INSERT INTO "_mocha_migrations" ("number","up_sql","down_sql","applied_at") VALUES(13,replace('\nINSERT INTO novels (title, slug, author_id, author_name, cover_image_url, synopsis, genre, tags, status, is_featured, total_chapters, total_reads, rating, created_at, updated_at) VALUES\n(''Daughters of the Delta'', ''daughters-of-the-delta'', NULL, ''Amara Okonkwo'', ''https://images.unsplash.com/photo-1516914589923-f105f1535f88?w=800&h=1200&fit=crop&q=80'', ''Three sisters navigate love, betrayal, and ancient family secrets in the oil-rich Niger Delta. When their grandmother''''s death reveals a hidden inheritance, they must confront the ghosts of the past.'', ''Drama'', ''Family Saga,Mystery,Nigerian'', ''ongoing'', 1, 47, 125000, 4.8, CURRENT_TIMESTAMP, CURRENT_TIMESTAMP),\n(''The Lagos Hustle'', ''the-lagos-hustle'', NULL, ''Chidi Mensah'', ''https://images.unsplash.com/photo-1611348586804-61bf6c080437?w=800&h=1200&fit=crop&q=80'', ''A street-smart tech genius from Mushin builds a fintech empire while dodging corrupt politicians and dangerous rivals. But success comes at a price he never expected.'', ''Thriller'', ''Tech,Crime,Urban'', ''ongoing'', 0, 32, 89000, 4.6, CURRENT_TIMESTAMP, CURRENT_TIMESTAMP),\n(''Kingdom of Whispers'', ''kingdom-of-whispers'', NULL, ''Zainab Adeyemi'', ''https://images.unsplash.com/photo-1518709268805-4e9042af9f23?w=800&h=1200&fit=crop&q=80'', ''In a magical kingdom inspired by the Benin Empire, a young priestess discovers she can speak to the dead—a gift that makes her both revered and hunted.'', ''Fantasy'', ''Magic,African Mythology,Adventure'', ''completed'', 1, 78, 234000, 4.9, CURRENT_TIMESTAMP, CURRENT_TIMESTAMP),\n(''Second Chance in Accra'', ''second-chance-in-accra'', NULL, ''Kwame Asante'', ''https://images.unsplash.com/photo-1516026672322-bc52d61a55d5?w=800&h=1200&fit=crop&q=80'', ''A divorced doctor returns to Ghana after 15 years in London. When she crosses paths with her university sweetheart, old flames reignite—but they''''ve both changed.'', ''Romance'', ''Second Chance,Diaspora,Ghanaian'', ''ongoing'', 0, 28, 156000, 4.7, CURRENT_TIMESTAMP, CURRENT_TIMESTAMP),\n(''The Night Market'', ''the-night-market'', NULL, ''Folake Balogun'', ''https://images.unsplash.com/photo-1518709268805-4e9042af9f23?w=800&h=1200&fit=crop&q=80'', ''Every full moon, a secret market appears in the heart of Ibadan where spirits trade in memories and desires. One woman will risk everything to buy back what she lost.'', ''Horror'', ''Supernatural,Yoruba Folklore,Dark'', ''ongoing'', 0, 8, 23000, 4.5, CURRENT_TIMESTAMP, CURRENT_TIMESTAMP),\n(''Nairobi After Dark'', ''nairobi-after-dark'', NULL, ''Grace Wanjiku'', ''https://images.unsplash.com/photo-1489749798305-4fea3ae63d43?w=800&h=1200&fit=crop&q=80'', ''An investigative journalist uncovers a web of corruption that reaches the highest levels of Kenyan politics. As she digs deeper, she realizes someone is always watching.'', ''Thriller'', ''Political,Suspense,Kenyan'', ''ongoing'', 0, 41, 98000, 4.6, CURRENT_TIMESTAMP, CURRENT_TIMESTAMP),\n(''The Empress of Timbuktu'', ''the-empress-of-timbuktu'', NULL, ''Mariama Diallo'', ''https://images.unsplash.com/photo-1547471080-7cc2caa01a7e?w=800&h=1200&fit=crop&q=80'', ''Set in the golden age of the Mali Empire, a merchant''''s daughter rises to become the most powerful woman in West Africa through wit, diplomacy, and carefully guarded secrets.'', ''Historical'', ''Empire,Power,Malian'', ''completed'', 0, 92, 187000, 4.8, CURRENT_TIMESTAMP, CURRENT_TIMESTAMP),\n(''Love & Jollof'', ''love-and-jollof'', NULL, ''Temi Adebayo'', ''https://images.unsplash.com/photo-1504674900247-0877df9cc836?w=800&h=1200&fit=crop&q=80'', ''A Nigerian food blogger and a Ghanaian chef compete on a reality cooking show. Their rivalry is fierce—until it turns into something neither of them expected.'', ''Comedy'', ''Romantic Comedy,Food,Rivalry'', ''ongoing'', 0, 19, 112000, 4.7, CURRENT_TIMESTAMP, CURRENT_TIMESTAMP),\n(''The Quantum Griot'', ''the-quantum-griot'', NULL, ''Olumide Bankole'', ''https://images.unsplash.com/photo-1451187580459-43490279c0fa?w=800&h=1200&fit=crop&q=80'', ''In 2157, a quantum physicist discovers that African oral histories contain encoded messages from the future. The revelation could save humanity—or destroy it.'', ''Sci-Fi'', ''Afrofuturism,Time Travel,Science'', ''ongoing'', 0, 12, 34000, 4.4, CURRENT_TIMESTAMP, CURRENT_TIMESTAMP),\n(''Bound by Blood'', ''bound-by-blood'', NULL, ''Adaeze Eze'', ''https://images.unsplash.com/photo-1509281373149-e957c6296406?w=800&h=1200&fit=crop&q=80'', ''Twins separated at birth—one raised in royalty, the other in poverty—discover their connection when a prophecy threatens to tear apart the kingdom.'', ''Fantasy'', ''Twins,Prophecy,Royal'', ''ongoing'', 0, 55, 145000, 4.7, CURRENT_TIMESTAMP, CURRENT_TIMESTAMP),\n(''The Pretender''''s Wife'', ''the-pretenders-wife'', NULL, ''Ngozi Obi'', ''https://images.unsplash.com/photo-1529232356377-57971f020a94?w=800&h=1200&fit=crop&q=80'', ''She married a billionaire for his money. He married her for revenge. Neither expected to fall in love—or uncover each other''''s darkest secrets.'', ''Romance'', ''Billionaire,Marriage of Convenience,Secrets'', ''completed'', 0, 65, 298000, 4.9, CURRENT_TIMESTAMP, CURRENT_TIMESTAMP),\n(''Echoes of the Ancestors'', ''echoes-of-the-ancestors'', NULL, ''Thabo Molefe'', ''https://images.unsplash.com/photo-1506905925346-21bda4d32df4?w=800&h=1200&fit=crop&q=80'', ''A South African sangoma inherits powers that have passed through her bloodline for centuries. But an ancient evil has awakened, and she''''s the only one who can stop it.'', ''Horror'', ''Supernatural,South African,Sangoma'', ''ongoing'', 0, 15, 41000, 4.6, CURRENT_TIMESTAMP, CURRENT_TIMESTAMP);\n','\n',char(10)),replace('\nDELETE FROM novels WHERE slug IN (\n  ''daughters-of-the-delta'',\n  ''the-lagos-hustle'',\n  ''kingdom-of-whispers'',\n  ''second-chance-in-accra'',\n  ''the-night-market'',\n  ''nairobi-after-dark'',\n  ''the-empress-of-timbuktu'',\n  ''love-and-jollof'',\n  ''the-quantum-griot'',\n  ''bound-by-blood'',\n  ''the-pretenders-wife'',\n  ''echoes-of-the-ancestors''\n);\n','\n',char(10)),'2026-03-16 07:53:04');
INSERT INTO "_mocha_migrations" ("number","up_sql","down_sql","applied_at") VALUES(14,replace('CREATE TABLE competition_submissions (\n  id INTEGER PRIMARY KEY AUTOINCREMENT,\n  user_id TEXT NOT NULL,\n  full_name TEXT,\n  email TEXT,\n  phone TEXT,\n  school_name TEXT,\n  class_year TEXT,\n  age INTEGER,\n  story_title TEXT,\n  genre TEXT,\n  synopsis TEXT,\n  story_content TEXT,\n  word_count INTEGER,\n  is_original_work INTEGER,\n  referral_source TEXT,\n  has_written_before INTEGER,\n  status TEXT DEFAULT ''pending'',\n  admin_notes TEXT,\n  created_at DATETIME DEFAULT CURRENT_TIMESTAMP,\n  updated_at DATETIME DEFAULT CURRENT_TIMESTAMP\n);','\n',char(10)),'DROP TABLE competition_submissions;','2026-03-16 21:56:57');
INSERT INTO "_mocha_migrations" ("number","up_sql","down_sql","applied_at") VALUES(15,replace('CREATE TABLE submission_scores (\n  id INTEGER PRIMARY KEY AUTOINCREMENT,\n  submission_id INTEGER NOT NULL,\n  judge_user_id TEXT NOT NULL,\n  originality_score INTEGER,\n  plot_structure_score INTEGER,\n  character_development_score INTEGER,\n  writing_quality_score INTEGER,\n  voice_style_score INTEGER,\n  theme_impact_score INTEGER,\n  total_score INTEGER,\n  judge_notes TEXT,\n  created_at DATETIME DEFAULT CURRENT_TIMESTAMP,\n  updated_at DATETIME DEFAULT CURRENT_TIMESTAMP\n);','\n',char(10)),'DROP TABLE submission_scores;','2026-03-17 18:41:35');
INSERT INTO "_mocha_migrations" ("number","up_sql","down_sql","applied_at") VALUES(16,replace('INSERT INTO competition_submissions (user_id, full_name, email, phone, school_name, class_year, age, story_title, genre, synopsis, story_content, word_count, is_original_work, referral_source, has_written_before, status, created_at, updated_at) VALUES \n(''sample-user-1'', ''Adaeze Okonkwo'', ''adaeze@example.com'', ''+234 801 234 5678'', ''University of Lagos'', ''Year 3'', 21, ''The Last Masquerade'', ''Cultural Fantasy'', ''A young woman discovers she is the last in a line of masquerade dancers who can communicate with ancestral spirits.'', ''The drums began at midnight, as they always did during the festival of the ancestors. Chidinma pressed her palms against the red earth, feeling the vibrations travel through her bones like whispered secrets from the other side...'', 2847, 1, ''Instagram'', 1, ''pending'', ''2025-01-15 10:30:00'', ''2025-01-15 10:30:00''),\n(''sample-user-2'', ''Kwame Asante'', ''kwame@example.com'', ''+233 24 567 8901'', ''University of Ghana'', ''Year 4'', 23, ''Golden Coast Dreams'', ''Contemporary Drama'', ''A fisherman''''s son in Accra must choose between his father''''s trade and a scholarship to study abroad.'', ''The nets were heavy with the night''''s catch, but Kofi''''s heart was heavier still. The letter from the university lay folded in his pocket, its words burning against his chest like the morning sun on the Atlantic waves...'', 3215, 1, ''Friend'', 1, ''reviewing'', ''2025-01-14 14:22:00'', ''2025-01-16 09:00:00''),\n(''sample-user-3'', ''Fatima Ibrahim'', ''fatima@example.com'', ''+234 802 345 6789'', ''Ahmadu Bello University'', ''Year 2'', 20, ''Threads of Silk and Sand'', ''Historical Fiction'', ''During the ancient trans-Saharan trade routes, a young merchant''''s daughter uncovers a conspiracy that could topple kingdoms.'', ''The caravan stretched across the dunes like a serpent made of gold and spices. Amina adjusted her veil against the biting sand, her eyes fixed on the distant city of Timbuktu, where secrets older than the desert itself awaited...'', 4102, 1, ''Twitter'', 0, ''shortlisted'', ''2025-01-12 08:15:00'', ''2025-01-17 11:30:00''),\n(''sample-user-4'', ''Oluwaseun Adeyemi'', ''seun@example.com'', ''+234 803 456 7890'', ''Obafemi Awolowo University'', ''Year 3'', 22, ''Lagos Nights'', ''Thriller'', ''A cyber security expert gets pulled into a dangerous game when she accidentally intercepts a message meant for a criminal syndicate.'', ''The screen flickered in the darkness of her Lekki apartment. Tolu should have been asleep hours ago, but the code wouldn''''t let her rest. When the encrypted message appeared on her monitor, she knew her quiet life was over...'', 3567, 1, ''School announcement'', 1, ''pending'', ''2025-01-16 19:45:00'', ''2025-01-16 19:45:00''),\n(''sample-user-5'', ''Blessing Eze'', ''blessing@example.com'', ''+234 805 678 9012'', ''University of Nigeria Nsukka'', ''Year 1'', 19, ''When the Harmattan Sings'', ''Romance'', ''Two rival families in a rural Igbo village must set aside generations of conflict when their children fall in love.'', ''The harmattan wind carried dust and memories across the valley that separated the Eze compound from the Okafor lands. For three generations, not a single word of kindness had crossed that divide—until Chukwuemeka smiled at Adanna...'', 2503, 1, ''TikTok'', 0, ''reviewing'', ''2025-01-13 16:00:00'', ''2025-01-15 14:20:00''),\n(''sample-user-6'', ''Tendai Moyo'', ''tendai@example.com'', ''+263 77 234 5678'', ''University of Zimbabwe'', ''Year 4'', 24, ''Stone Kingdom'', ''Historical Fantasy'', ''In the shadow of Great Zimbabwe, a young stonemason discovers he can see the spirits that built the ancient walls.'', ''The stones spoke to Tendai in voices older than memory. Each granite block in the great wall hummed with the energy of those who had placed it there, centuries before the white men came with their questions and their cameras...'', 3890, 1, ''Online search'', 1, ''shortlisted'', ''2025-01-11 12:30:00'', ''2025-01-17 16:45:00'');\n\nINSERT INTO submission_scores (submission_id, judge_user_id, originality_score, plot_structure_score, character_development_score, writing_quality_score, voice_style_score, theme_impact_score, total_score, judge_notes, created_at, updated_at) VALUES \n(3, ''sample-judge-1'', 9, 8, 8, 9, 9, 8, 51, ''Exceptional historical research and vivid world-building. The protagonist is compelling and the conspiracy plot is well-paced.'', ''2025-01-17 14:00:00'', ''2025-01-17 14:00:00''),\n(3, ''sample-judge-2'', 8, 9, 7, 8, 8, 9, 49, ''Strong narrative voice. The historical setting is immersive. Could use deeper character development for the antagonist.'', ''2025-01-17 16:30:00'', ''2025-01-17 16:30:00''),\n(6, ''sample-judge-1'', 9, 8, 9, 8, 9, 9, 52, ''Beautiful prose and a unique take on African mythology. The spiritual elements are handled with sensitivity and depth.'', ''2025-01-17 15:00:00'', ''2025-01-17 15:00:00''),\n(2, ''sample-judge-2'', 7, 8, 8, 7, 7, 8, 45, ''Relatable contemporary themes. The father-son relationship is well drawn. Some pacing issues in the middle section.'', ''2025-01-16 10:00:00'', ''2025-01-16 10:00:00'');','\n',char(10)),replace('DELETE FROM submission_scores WHERE judge_user_id IN (''sample-judge-1'', ''sample-judge-2'');\nDELETE FROM competition_submissions WHERE user_id IN (''sample-user-1'', ''sample-user-2'', ''sample-user-3'', ''sample-user-4'', ''sample-user-5'', ''sample-user-6'');','\n',char(10)),'2026-03-17 19:20:12');
