Y KEY AUTOINCREMENT,\n  owner_user_id TEXT NOT NULL UNIQUE,\n  plan_type TEXT NOT NULL,\n  max_members INTEGER DEFAULT 5,\n  amount INTEGER NOT NULL,\n  currency TEXT DEFAULT ''NGN'',\n  payment_reference TEXT,\n  starts_at DATETIME NOT NULL,\n  expires_at DATETIME NOT NULL,\n  is_active INTEGER DEFAULT 1,\n  created_at DATETIME DEFAULT CURRENT_TIMESTAMP,\n  updated_at DATETIME DEFAULT CURRENT_TIMESTAMP\n);\n\nCREATE INDEX idx_family_plans_owner ON family_plans(owner_user_id);\n\nCREATE TABLE family_plan_members (\n  id INTEGER PRIMARY KEY AUTOINCREMENT,\n  family_plan_id INTEGER NOT NULL,\n  user_id TEXT NOT NULL,\n  email TEXT NOT NULL,\n  status TEXT DEFAULT ''pending'',\n  joined_at DATETIME,\n  created_at DATETIME DEFAULT CURRENT_TIMESTAMP,\n  updated_at DATETIME DEFAULT CURRENT_TIMESTAMP\n);\n\nCREATE INDEX idx_family_members_plan ON family_plan_members(family_plan_id);\nCREATE INDEX idx_family_members_user ON family_plan_members(user_id);\nCREATE UNIQUE INDEX idx_family_members_unique ON family_plan_members(user_id);\n\n-- Add referral_code to user_profiles\nALTER TABLE user_profiles ADD COLUMN referral_code TEXT;\nALTER TABLE user_profiles ADD COLUMN referred_by_code TEXT;','\n',char(10)),replace('ALTER TABLE user_profiles DROP COLUMN referred_by_code;\nALTER TABLE user_profiles DROP COLUMN referral_code;\n\nDROP INDEX idx_family_members_unique;\nDROP INDEX idx_family_members_user;\nDROP INDEX idx_family_members_plan;\nDROP TABLE family_plan_members;\n\nDROP INDEX idx_family_plans_owner;\nDROP TABLE family_plans;\n\nDROP INDEX idx_gift_subs_code;\nDROP INDEX idx_gift_subs_recipient;\nDROP INDEX idx_gift_subs_purchaser;\nDROP TABLE gift_subscriptions;\n\nDROP INDEX idx_referral_rewards_user;\nDROP TABLE referral_rewards;\n\nDROP INDEX idx_referrals_unique;\nDROP INDEX idx_referrals_referred;\nDROP INDEX idx_referrals_referrer;\nDROP TABLE referrals;','\n',char(10)),'2026-03-23 23:16:12');
