INSERT INTO "_mocha_migrations" ("number","up_sql","down_sql","applied_at") VALUES(32,replace('\n-- User coin balances\nCREATE TABLE user_coins (\n  id INTEGER PRIMARY KEY AUTOINCREMENT,\n  user_id TEXT NOT NULL,\n  balance INTEGER NOT NULL DEFAULT 0,\n  created_at DATETIME DEFAULT CURRENT_TIMESTAMP,\n  updated_at DATETIME DEFAULT CURRENT_TIMESTAMP\n);\n\nCREATE UNIQUE INDEX idx_user_coins_user_id ON user_coins(user_id);\n\n-- Coin purchase/spend transactions\nCREATE TABLE coin_transactions (\n  id INTEGER PRIMARY KEY AUTOINCREMENT,\n  user_id TEXT NOT NULL,\n  amount INTEGER NOT NULL,\n  transaction_type TEXT NOT NULL,\n  description TEXT,\n  reference TEXT,\n  created_at DATETIME DEFAULT CURRENT_TIMESTAMP,\n  updated_at DATETIME DEFAULT CURRENT_TIMESTAMP\n);\n\nCREATE INDEX idx_coin_transactions_user_id ON coin_transactions(user_id);\n\n-- Track which chapters users have unlocked with coins\nCREATE TABLE chapter_unlocks (\n  id INTEGER PRIMARY KEY AUTOINCREMENT,\n  user_id TEXT NOT NULL,\n  chapter_id INTEGER NOT NULL,\n  coins_spent INTEGER NOT NULL,\n  created_at DATETIME DEFAULT CURRENT_TIMESTAMP,\n  updated_at DATETIME DEFAULT CURRENT_TIMESTAMP\n);\n\nCREATE UNIQUE INDEX idx_chapter_unlocks_user_chapter ON chapter_unlocks(user_id, chapter_id);\n','\n',char(10)),replace('\nDROP INDEX idx_chapter_unlocks_user_chapter;\nDROP TABLE chapter_unlocks;\nDROP INDEX idx_coin_transactions_user_id;\nDROP TABLE coin_transactions;\nDROP INDEX idx_user_coins_user_id;\nDROP TABLE user_coins;\n','\n',char(10)),'2026-04-02 20:56:44');
