INSERT INTO "_mocha_migrations" ("number","up_sql","down_sql","applied_at") VALUES(35,replace('-- Delete all demo novels and their related data\nDELETE FROM chapter_reactions WHERE chapter_id IN (SELECT id FROM chapters WHERE novel_id IN (SELECT id FROM novels WHERE title IN (''Daughters of the Delta'', ''The Lagos Hustle'', ''Kingdom of Whispers'', ''Second Chance in Accra'', ''The Night Market'', ''Campus Confessions'', ''Blood of the Ancestors'', ''Love & Jollof'', ''The Quantum Griot'', ''Mama''''s Kitchen'', ''The Pretender''''s Wife'', ''Shadows of the Sahel'')));\n\nDELETE FROM chapter_comments WHERE chapter_id IN (SELECT id FROM chapters WHERE novel_id IN (SELECT id FROM novels WHERE title IN (''Daughters of the Delta'', ''The Lagos Hustle'', ''Kingdom of Whispers'', ''Second Chance in Accra'', ''The Night Market'', ''Campus Confessions'', ''Blood of the Ancestors'', ''Love & Jollof'', ''The Quantum Griot'', ''Mama''''s Kitchen'', ''The Pretender''''s Wife'', ''Shadows of the Sahel'')));\n\nDELETE FROM chapter_unlocks WHERE chapter_id IN (SELECT id FROM chapters WHERE novel_id IN (SELECT id FROM novels WHERE title IN (''Daughters of the Delta'', ''The Lagos Hustle'', ''Kingdom of Whispers'', ''Second Chance in Accra'', ''The Night Market'', ''Campus Confessions'', ''Blood of the Ancestors'', ''Love & Jollof'', ''The Quantum Griot'', ''Mama''''s Kitchen'', ''The Pretender''''s Wife'', ''Shadows of the Sahel'')));\n\nDELETE FROM chapters_read WHERE chapter_id IN (SELECT id FROM chapters WHERE novel_id IN (SELECT id FROM novels WHERE title IN (''Daughters of the Delta'', ''The Lagos Hustle'', ''Kingdom of Whispers'', ''Second Chance in Accra'', ''The Night Market'', ''Campus Confessions'', ''Blood of the Ancestors'', ''Love & Jollof'', ''The Quantum Griot'', ''Mama''''s Kitchen'', ''The Pretender''''s Wife'', ''Shadows of the Sahel'')));\n\nDELETE FROM chapters WHERE novel_id IN (SELECT id FROM novels WHERE title IN (''Daughters of the Delta'', ''The Lagos Hustle'', ''Kingdom of Whispers'', ''Second Chance in Accra'', ''The Night Market'', ''Campus Confessions'', ''Blood of the Ancestors'', ''Love & Jollof'', ''The Quantum Griot'', ''Mama''''s Kitchen'', ''The Pretender''''s Wife'', ''Shadows of the Sahel''));\n\nDELETE FROM seasons WHERE novel_id IN (SELECT id FROM novels WHERE title IN (''Daughters of the Delta'', ''The Lagos Hustle'', ''Kingdom of Whispers'', ''Second Chance in Accra'', ''The Night Market'', ''Campus Confessions'', ''Blood of the Ancestors'', ''Love & Jollof'', ''The Quantum Griot'', ''Mama''''s Kitchen'', ''The Pretender''''s Wife'', ''Shadows of the Sahel''));\n\nDELETE FROM user_libraries WHERE novel_id IN (SELECT id FROM novels WHERE title IN (''Daughters of the Delta'', ''The Lagos Hustle'', ''Kingdom of Whispers'', ''Second Chance in Accra'', ''The Night Market'', ''Campus Confessions'', ''Blood of the Ancestors'', ''Love & Jollof'', ''The Quantum Griot'', ''Mama''''s Kitchen'', ''The Pretender''''s Wife'', ''Shadows of the Sahel''));\n\nDELETE FROM novels WHERE title IN (''Daughters of the Delta'', ''The Lagos Hustle'', ''Kingdom of Whispers'', ''Second Chance in Accra'', ''The Night Market'', ''Campus Confessions'', ''Blood of the Ancestors'', ''Love & Jollof'', ''The Quantum Griot'', ''Mama''''s Kitchen'', ''The Pretender''''s Wife'', ''Shadows of the Sahel'');','\n',char(10)),replace('-- Cannot restore deleted demo novels - they would need to be re-inserted manually\nSELECT 1;','\n',char(10)),'2026-04-06 08:16:37');
