INSERT INTO "_mocha_migrations" ("number","up_sql","down_sql","applied_at") VALUES(38,replace('\n-- Community discussions table\nCREATE TABLE community_discussions (\n  id INTEGER PRIMARY KEY AUTOINCREMENT,\n  user_id INTEGER NOT NULL,\n  novel_id INTEGER,\n  chapter_number INTEGER,\n  content TEXT NOT NULL,\n  is_spoiler INTEGER DEFAULT 0,\n  likes_count INTEGER DEFAULT 0,\n  replies_count INTEGER DEFAULT 0,\n  created_at DATETIME DEFAULT CURRENT_TIMESTAMP,\n  updated_at DATETIME DEFAULT CURRENT_TIMESTAMP\n);\n\n-- Discussion likes table\nCREATE TABLE discussion_likes (\n  id INTEGER PRIMARY KEY AUTOINCREMENT,\n  discussion_id INTEGER NOT NULL,\n  user_id TEXT NOT NULL,\n  created_at DATETIME DEFAULT CURRENT_TIMESTAMP,\n  updated_at DATETIME DEFAULT CURRENT_TIMESTAMP\n);\n\nCREATE UNIQUE INDEX idx_discussion_likes_unique ON discussion_likes(discussion_id, user_id);\n\n-- Discussion replies table\nCREATE TABLE discussion_replies (\n  id INTEGER PRIMARY KEY AUTOINCREMENT,\n  discussion_id INTEGER NOT NULL,\n  user_id INTEGER NOT NULL,\n  content TEXT NOT NULL,\n  likes_count INTEGER DEFAULT 0,\n  created_at DATETIME DEFAULT CURRENT_TIMESTAMP,\n  updated_at DATETIME DEFAULT CURRENT_TIMESTAMP\n);\n\nCREATE INDEX idx_discussions_novel ON community_discussions(novel_id);\nCREATE INDEX idx_discussions_created ON community_discussions(created_at DESC);\nCREATE INDEX idx_replies_discussion ON discussion_replies(discussion_id);\n','\n',char(10)),replace('\nDROP INDEX IF EXISTS idx_replies_discussion;\nDROP INDEX IF EXISTS idx_discussions_created;\nDROP INDEX IF EXISTS idx_discussions_novel;\nDROP INDEX IF EXISTS idx_discussion_likes_unique;\nDROP TABLE IF EXISTS discussion_replies;\nDROP TABLE IF EXISTS discussion_likes;\nDROP TABLE IF EXISTS community_discussions;\n','\n',char(10)),'2026-04-08 01:16:57');
