INSERT INTO "_mocha_migrations" ("number","up_sql","down_sql","applied_at") VALUES(40,replace('-- Add referral tracking columns to referrals table\nALTER TABLE referrals ADD COLUMN is_trial_activated BOOLEAN DEFAULT 0;\nALTER TABLE referrals ADD COLUMN fraud_flagged_at DATETIME;\nALTER TABLE referrals ADD COLUMN reward_revoked BOOLEAN DEFAULT 0;\nALTER TABLE referrals ADD COLUMN reward_days_given INTEGER DEFAULT 0;\n\n-- Add referral bonus tracking to user_profiles\nALTER TABLE user_profiles ADD COLUMN referral_bonus_days INTEGER DEFAULT 0;\nALTER TABLE user_profiles ADD COLUMN has_early_access BOOLEAN DEFAULT 0;\nALTER TABLE user_profiles ADD COLUMN total_referral_days_earned INTEGER DEFAULT 0;\nALTER TABLE user_profiles ADD COLUMN successful_referrals_count INTEGER DEFAULT 0;\n\n-- Track referral link clicks for conversion rate\nCREATE TABLE referral_clicks (\n  id INTEGER PRIMARY KEY AUTOINCREMENT,\n  referral_code TEXT NOT NULL,\n  referrer_user_id TEXT NOT NULL,\n  ip_hash TEXT,\n  user_agent TEXT,\n  clicked_at DATETIME DEFAULT CURRENT_TIMESTAMP,\n  created_at DATETIME DEFAULT CURRENT_TIMESTAMP,\n  updated_at DATETIME DEFAULT CURRENT_TIMESTAMP\n);\n\nCREATE INDEX idx_referral_clicks_code ON referral_clicks(referral_code);\nCREATE INDEX idx_referral_clicks_referrer ON referral_clicks(referrer_user_id);','\n',char(10)),replace('DROP INDEX IF EXISTS idx_referral_clicks_referrer;\nDROP INDEX IF EXISTS idx_referral_clicks_code;\nDROP TABLE IF EXISTS referral_clicks;\n\nALTER TABLE user_profiles DROP COLUMN successful_referrals_count;\nALTER TABLE user_profiles DROP COLUMN total_referral_days_earned;\nALTER TABLE user_profiles DROP COLUMN has_early_access;\nALTER TABLE user_profiles DROP COLUMN referral_bonus_days;\n\nALTER TABLE referrals DROP COLUMN reward_days_given;\nALTER TABLE referrals DROP COLUMN reward_revoked;\nALTER TABLE referrals DROP COLUMN fraud_flagged_at;\nALTER TABLE referrals DROP COLUMN is_trial_activated;','\n',char(10)),'2026-05-11 10:32:06');
INSERT INTO "_mocha_migrations" ("number","up_sql","down_sql","applied_at") VALUES(41,replace('CREATE TABLE polls (\n  id INTEGER PRIMARY KEY AUTOINCREMENT,\n  novel_id INTEGER,\n  question TEXT NOT NULL,\n  context TEXT,\n  is_spoiler BOOLEAN DEFAULT 0,\n  is_active BOOLEAN DEFAULT 1,\n  ends_at DATETIME,\n  total_votes INTEGER DEFAULT 0,\n  created_at DATETIME DEFAULT CURRENT_TIMESTAMP,\n  updated_at DATETIME DEFAULT CURRENT_TIMESTAMP\n);\n\nCREATE TABLE poll_options (\n  id INTEGER PRIMARY KEY AUTOINCREMENT,\n  poll_id INTEGER NOT NULL,\n  option_text TEXT NOT NULL,\n  votes INTEGER DEFAULT 0,\n  created_at DATETIME DEFAULT CURRENT_TIMESTAMP,\n  updated_at DATETIME DEFAULT CURRENT_TIMESTAMP\n);\n\nCREATE TABLE poll_votes (\n  id INTEGER PRIMARY KEY AUTOINCREMENT,\n  poll_id INTEGER NOT NULL,\n  option_id INTEGER NOT NULL,\n  user_id TEXT NOT NULL,\n  created_at DATETIME DEFAULT CURRENT_TIMESTAMP,\n  updated_at DATETIME DEFAULT CURRENT_TIMESTAMP\n);','\n',char(10)),replace('DROP TABLE poll_votes;\nDROP TABLE poll_options;\nDROP TABLE polls;','\n',char(10)),'2026-05-13 13:56:03');
