INSERT INTO "_mocha_migrations" ("number","up_sql","down_sql","applied_at") VALUES(43,replace('CREATE TABLE app_settings (\n  id INTEGER PRIMARY KEY AUTOINCREMENT,\n  setting_key TEXT NOT NULL UNIQUE,\n  setting_value TEXT,\n  created_at DATETIME DEFAULT CURRENT_TIMESTAMP,\n  updated_at DATETIME DEFAULT CURRENT_TIMESTAMP\n);\n\nINSERT INTO app_settings (setting_key, setting_value) VALUES (''maintenance_mode'', ''false'');\nINSERT INTO app_settings (setting_key, setting_value) VALUES (''maintenance_message'', ''We are updating Inkseries to bring you new features. Check back soon!'');','\n',char(10)),replace('DELETE FROM app_settings WHERE setting_key IN (''maintenance_mode'', ''maintenance_message'');\nDROP TABLE app_settings;','\n',char(10)),'2026-05-14 01:10:44');
INSERT INTO "_mocha_migrations" ("number","up_sql","down_sql","applied_at") VALUES(44,replace('-- Table to track subscription cancellations\nCREATE TABLE subscription_cancellations (\n  id INTEGER PRIMARY KEY AUTOINCREMENT,\n  user_id TEXT NOT NULL,\n  plan_type TEXT NOT NULL,\n  amount INTEGER NOT NULL,\n  cancellation_reason TEXT,\n  access_expires_at DATETIME NOT NULL,\n  flutterwave_subscription_id TEXT,\n  save_offer_shown BOOLEAN DEFAULT 0,\n  save_offer_accepted BOOLEAN DEFAULT 0,\n  created_at DATETIME DEFAULT CURRENT_TIMESTAMP,\n  updated_at DATETIME DEFAULT CURRENT_TIMESTAMP\n);\n\n-- Add columns to subscriptions table for tracking recurring state and cancellation\nALTER TABLE subscriptions ADD COLUMN is_recurring BOOLEAN DEFAULT 0;\nALTER TABLE subscriptions ADD COLUMN flutterwave_subscription_id TEXT;\nALTER TABLE subscriptions ADD COLUMN is_cancelled BOOLEAN DEFAULT 0;\nALTER TABLE subscriptions ADD COLUMN cancelled_at DATETIME;','\n',char(10)),replace('ALTER TABLE subscriptions DROP COLUMN cancelled_at;\nALTER TABLE subscriptions DROP COLUMN is_cancelled;\nALTER TABLE subscriptions DROP COLUMN flutterwave_subscription_id;\nALTER TABLE subscriptions DROP COLUMN is_recurring;\n\nDROP TABLE subscription_cancellations;','\n',char(10)),'2026-05-15 08:45:45');
