INSERT INTO "_mocha_migrations" ("number","up_sql","down_sql","applied_at") VALUES(46,replace('-- Refunds table to track all refund requests and automatic refunds\nCREATE TABLE refunds (\n  id INTEGER PRIMARY KEY AUTOINCREMENT,\n  user_id TEXT NOT NULL,\n  subscription_id INTEGER,\n  payment_reference TEXT,\n  amount INTEGER NOT NULL,\n  currency TEXT DEFAULT ''NGN'',\n  refund_type TEXT NOT NULL,\n  refund_reason TEXT,\n  status TEXT DEFAULT ''pending'',\n  flutterwave_refund_id TEXT,\n  processed_at DATETIME,\n  created_at DATETIME DEFAULT CURRENT_TIMESTAMP,\n  updated_at DATETIME DEFAULT CURRENT_TIMESTAMP\n);\n\n-- Track payment history to detect duplicates\nCREATE TABLE payment_charges (\n  id INTEGER PRIMARY KEY AUTOINCREMENT,\n  user_id TEXT NOT NULL,\n  subscription_id INTEGER,\n  payment_reference TEXT NOT NULL,\n  flutterwave_transaction_id TEXT,\n  amount INTEGER NOT NULL,\n  currency TEXT DEFAULT ''NGN'',\n  billing_period_start DATE,\n  billing_period_end DATE,\n  is_first_charge BOOLEAN DEFAULT 0,\n  charged_at DATETIME DEFAULT CURRENT_TIMESTAMP,\n  created_at DATETIME DEFAULT CURRENT_TIMESTAMP,\n  updated_at DATETIME DEFAULT CURRENT_TIMESTAMP\n);\n\n-- Add first charge tracking to subscriptions\nALTER TABLE subscriptions ADD COLUMN first_charge_at DATETIME;\nALTER TABLE subscriptions ADD COLUMN episodes_read_at_first_charge INTEGER DEFAULT 0;','\n',char(10)),replace('DROP TABLE refunds;\nDROP TABLE payment_charges;\nALTER TABLE subscriptions DROP COLUMN first_charge_at;\nALTER TABLE subscriptions DROP COLUMN episodes_read_at_first_charge;','\n',char(10)),'2026-05-15 10:13:11');
