INSERT INTO "novels" ("id","title","slug","author_id","cover_image_url","synopsis","genre","tags","status","is_featured","total_chapters","total_reads","total_likes","rating","published_at","created_at","updated_at","author_name","chapter_format") VALUES(1,'THE LAUNDRY BOY','the-laundry-boy',1,'/api/covers/1778023443783-fmsx1f.jpg',replace('Izunna runs laundry across Owerri to keep his family afloat and sit his WAEC. He is good at the work, better at the silence.\nBut silence costs. Over one season, he faces something he has no language to name: clients who mistake his professionalism for permission, a trap designed to compromise him, and a false accusation that wipes his name from a whole estate.\nWhen he meets a girl who listens without flinching, Izunna begins the work of finding his voice.\nThe Laundry Boy is about what boys carry, and what happens when they set it down.','\n',char(10)),'Street and Hustle','["Inkseries Original","Trending in Nigeria","Free Episodes Available"]','completed',0,15,132,0,4.7,NULL,'2026-03-13 17:47:20','2026-05-20 21:48:09','Inkseries Team ','seasons_episodes');
INSERT INTO "novels" ("id","title","slug","author_id","cover_image_url","synopsis","genre","tags","status","is_featured","total_chapters","total_reads","total_likes","rating","published_at","created_at","updated_at","author_name","chapter_format") VALUES(16,'ONE PRIZE - SEASON 1','one-prize-season-1',4,'/api/covers/1779864751722-do3dl7.jpg','Adaeze arrives last at Queen''s Hallmark College, takes the third bed, and quietly becomes the smartest girl in her set. When a university scholarship is announced, the friendship she built with her wealthy roommates fractures under ambition, secrets, and the weight of wanting something desperately enough to reveal exactly who you are.','School Life and Friendships','["Secret Identity","Boarding School","Self Discovery","Survival","Power","Identity Crisis","Class Divide","Lighthearted","Wholesome","Emotional","Action-Packed","Suspenseful","Heartwarming","Strong Female Lead","Good Girl","Smart Protagonist"]','completed',0,8,57,0,0,NULL,'2026-04-01 07:42:46','2026-05-27 06:52:38','Inkseries Team ','season_episode');
INSERT INTO "novels" ("id","title","slug","author_id","cover_image_url","synopsis","genre","tags","status","is_featured","total_chapters","total_reads","total_likes","rating","published_at","created_at","updated_at","author_name","chapter_format") VALUES(20,'ONE PRIZE - SEASON 2','one-prize-season-2',4,'/api/covers/1779864776250-hnh1wj.jpg','Adaeze arrives last at Queen''s Hallmark College, takes the third bed, and quietly becomes the smartest girl in her set. When a university scholarship is announced, the friendship she built with her wealthy roommates fractures under ambition, secrets, and the weight of wanting something desperately enough to reveal exactly who you are.','School Life and Friendships','[]','completed',0,10,32,0,0,NULL,'2026-04-01 11:56:03','2026-05-27 06:53:02','Inkseries Team ','seasons_episodes');
INSERT INTO "novels" ("id","title","slug","author_id","cover_image_url","synopsis","genre","tags","status","is_featured","total_chapters","total_reads","total_likes","rating","published_at","created_at","updated_at","author_name","chapter_format") VALUES(21,'SAME UNIFORM ','same-uniform',4,'/api/covers/1779865009821-c7fynr.jpg','Kemi and Tobenna have shared a classroom in Abuja for three years and never spoken. Then a power cut traps them alone in the school library with one phone torch and three hours of honesty, and everything changes. The problem is the timing: she is leaving for Toronto at the end of term. He is moving to Kano. They have twelve weeks. What follows is the story of two teenagers learning each other with the clock already running, discovering that the hardest thing about first love is not finding it but refusing to be careful with it once you do.','Romance and First Love','["Slow Burn","Friends to Lovers","Love Triangle","Opposites Attract","Royalty","Coming of Age"]','completed',0,12,28,0,0,NULL,'2026-04-04 12:44:38','2026-05-27 06:56:56','Inkseries Team ','seasons_episodes');
INSERT INTO "novels" ("id","title","slug","author_id","cover_image_url","synopsis","genre","tags","status","is_featured","total_chapters","total_reads","total_likes","rating","published_at","created_at","updated_at","author_name","chapter_format") VALUES(25,'THE BOY THE RIVER KNOWS - SEASON 1','the-boy-the-river-knows-season-1',4,'/api/covers/1775514833702-3jqwhy.jpg','When a flood takes his grandmother and leaves behind a clay pot sealed with a message in a dead language, sixteen-year-old Nnamdi follows the only thread he has into unmapped riverine Nigeria. What he finds there will not destroy his scientific certainty. It will complete it.','African Fantasy and Mythology','[]','completed',0,8,0,0,0,NULL,'2026-04-06 12:57:35','2026-04-20 07:12:11','Inkseries Team ','seasons_episodes');
