INSERT INTO "novels" ("id","title","slug","author_id","cover_image_url","synopsis","genre","tags","status","is_featured","total_chapters","total_reads","total_likes","rating","published_at","created_at","updated_at","author_name","chapter_format") VALUES(28,'CHILDREN OF OPPOSITE SKIES - SEASON 1','children-of-opposite-skies-season-1',4,'/api/covers/1779865205143-ipu7xg.jpg','In a world where the Yoruba sky kingdom and the Igbo earth kingdom have been at war for three hundred years, Adaora arrives at the sky court as a diplomat''s aide with orders to observe and report. Soren is the king''s youngest son, politically irrelevant, fluent in a language everyone else has forgotten. They should never speak. They speak anyway, in a dead tongue that belongs only to them, while the war they were born into burns closer and demands they choose what they are willing to become.','Romance and First Love','[]','completed',0,12,0,0,0,NULL,'2026-04-07 05:24:26','2026-05-27 07:00:11','Inkseries Team ','seasons_episodes');
INSERT INTO "novels" ("id","title","slug","author_id","cover_image_url","synopsis","genre","tags","status","is_featured","total_chapters","total_reads","total_likes","rating","published_at","created_at","updated_at","author_name","chapter_format") VALUES(29,'CHILDREN OF OPPOSITE SKIES - SEASON 2','children-of-opposite-skies-season-2',4,'/api/covers/1779865228862-79budt.jpg','In a world where the Yoruba sky kingdom and the Igbo earth kingdom have been at war for three hundred years, Adaora arrives at the sky court as a diplomat''s aide with orders to observe and report. Soren is the king''s youngest son, politically irrelevant, fluent in a language everyone else has forgotten. They should never speak. They speak anyway, in a dead tongue that belongs only to them, while the war they were born into burns closer and demands they choose what they are willing to become.','Romance and First Love','[]','completed',0,12,0,0,0,NULL,'2026-04-07 05:45:55','2026-05-27 07:00:34','Inkseries Team ','seasons_episodes');
INSERT INTO "novels" ("id","title","slug","author_id","cover_image_url","synopsis","genre","tags","status","is_featured","total_chapters","total_reads","total_likes","rating","published_at","created_at","updated_at","author_name","chapter_format") VALUES(30,'THE FARE','the-fare',4,'/api/covers/1779865514566-us4ugk.jpg',replace('Seun is the sharpest bus conductor on the Oshodi to Ojota route, quietly saving for school fees and a transport business planned to the last naira.\nWhen a union boss moves to control his route, Seun has no levy and nowhere to turn. Then he learns the conductor sent to displace him is Olamide, his closest childhood friend.\nWhat follows is not just a fight about a bus route. It is about loyalty, ambition, and what it costs a boy to become a man in a city that does not slow down for either.','\n',char(10)),'Street and Hustle','["Inkseries Original","Trending in Nigeria","Free Episodes Available"]','completed',0,6,2,0,0,NULL,'2026-04-08 01:24:35','2026-05-27 07:05:19','Inkseries Team ','seasons_episodes');
INSERT INTO "novels" ("id","title","slug","author_id","cover_image_url","synopsis","genre","tags","status","is_featured","total_chapters","total_reads","total_likes","rating","published_at","created_at","updated_at","author_name","chapter_format") VALUES(32,'THE TRANSFER STUDENT ','the-transfer-student',4,'/api/covers/1777179907947-mrwybc.jpg',replace('When Ibrahim Suleiman transfers to Federal Government College Abuja midterm, three incidents follow like clockwork: a hacked database, a vandalized car, an anonymous letter.\nStudent journalist Damilola notices the pattern first and targets Ibrahim. But the evidence refuses to hold still.\nSomeone built this trail before Ibrahim arrived and placed Damilola at the center of it. The truth reaches beyond the school gates into the federal education ministry itself. And the person who aimed her like a weapon is the woman she trusted most.\nDamilola has the story. She cannot print it yet. And someone already knows.','\n',char(10)),'Thriller and Mystery','["Trending in Nigeria","Inkseries Original","Free Episodes Available"]','completed',0,0,2,0,0,NULL,'2026-04-08 12:32:24','2026-05-20 21:55:50','Inkseries Team ','seasons_episodes');
INSERT INTO "novels" ("id","title","slug","author_id","cover_image_url","synopsis","genre","tags","status","is_featured","total_chapters","total_reads","total_likes","rating","published_at","created_at","updated_at","author_name","chapter_format") VALUES(36,'TWO FATHERS  - SEASON 1','two-fathers-season-1',4,'/api/covers/1776485736432-62evfa.jpg',replace('Emeka Obi finds a name in his birth certificate that does not belong to the man who raised him. His parents will not speak.\nBut a family funeral forces a reunion. Across the room, Emeka sees a stranger''s face that looks exactly like his own.\nWhat follows is a quiet, relentless search through family secrets, old photographs, and silences nobody will break. It leads him to a man who left, a mother who stayed, and a father who chose.\nBy the end, there is only one question: who are you when the story you were given was never the whole one?','\n',char(10)),'Family and Identity','["Identity","Family Secrets","Inkseries Original","Trending in Nigeria","Enugu","Lagos"]','completed',0,10,5,0,0,NULL,'2026-04-08 23:55:58','2026-05-20 21:58:07','Inkseries Team ','seasons_episodes');
INSERT INTO "novels" ("id","title","slug","author_id","cover_image_url","synopsis","genre","tags","status","is_featured","total_chapters","total_reads","total_likes","rating","published_at","created_at","updated_at","author_name","chapter_format") VALUES(37,'TWO FATHERS  - SEASON 2','two-fathers-season-2',4,'/api/covers/1776485764273-bdi3ye.jpg',replace('Emeka Obi finds a name in his birth certificate that does not belong to the man who raised him. His parents will not speak.\nBut a family funeral forces a reunion. Across the room, Emeka sees a stranger''s face that looks exactly like his own.\nWhat follows is a quiet, relentless search through family secrets, old photographs, and silences nobody will break. It leads him to a man who left, a mother who stayed, and a father who chose.\nBy the end, there is only one question: who are you when the story you were given was never the whole one?','\n',char(10)),'Family and Identity','["Father and Son","Inkseries Original","Trending in Nigeria","Forgiveness"]','completed',0,10,0,0,0,NULL,'2026-04-09 00:01:15','2026-05-20 21:58:52','Inkseries Team ','seasons_episodes');
INSERT INTO "novels" ("id","title","slug","author_id","cover_image_url","synopsis","genre","tags","status","is_featured","total_chapters","total_reads","total_likes","rating","published_at","created_at","updated_at","author_name","chapter_format") VALUES(38,'THE WEIGHT OF JULY','the-weight-of-july',4,'/api/covers/1778023993629-ew3wd9.jpg',replace('Abena arrives at Horizon Academy on a government scholarship from a fishing village, expecting the hardest part to be fitting in. She does not expect Serwa Boateng.\nOld Accra money. Quiet certainty. A family name that means everything in the right circles.\nTheir friendship builds slowly, cautiously, until a history project forces them to trace their families'' roots in Ghana''s 1966 coup. What they find in an archive folder destroys the careful distance they have been keeping.\nOne document. Two columns. One family''s foundation built on another family''s loss.\nNow the friendship must decide what it is made of.','\n',char(10)),'School Life and Friendships','["Inkseries Original","Trending in Nigeria","Boarding School","School Life"]','completed',0,12,5,0,0,NULL,'2026-04-09 04:48:10','2026-05-20 22:03:46','Inkseries Team ','seasons_episodes');
INSERT INTO "novels" ("id","title","slug","author_id","cover_image_url","synopsis","genre","tags","status","is_featured","total_chapters","total_reads","total_likes","rating","published_at","created_at","updated_at","author_name","chapter_format") VALUES(39,'OUTRANKED - SEASON 1','outranked-season-1',4,'/api/covers/1778023682656-g131kp.jpg',replace('Chukwuemeka Obi has spent three years building himself into the most feared senior prefect FGC Lokoja has ever seen. Then a new principal arrives from Abuja with one idea that dismantles everything he is.\nWhen her student council hands real authority to Chinazaekpere Hauwa, a JS3 girl Emeka once publicly humiliated, he must survive something worse than losing power: discovering he was never who he thought he was.\nWhat begins as a clash between two kinds of authority becomes something neither of them planned.\nA story about who you become when everything you built yourself around is taken away.','\n',char(10)),'School Life and Friendships','["Inkseries Original","Trending in Nigeria","Free Episodes Available"]','completed',0,8,4,0,0,NULL,'2026-04-09 12:24:50','2026-05-24 17:53:28','Inkseries Team ','seasons_episodes');
INSERT INTO "novels" ("id","title","slug","author_id","cover_image_url","synopsis","genre","tags","status","is_featured","total_chapters","total_reads","total_likes","rating","published_at","created_at","updated_at","author_name","chapter_format") VALUES(41,'OUTRANKED - SEASON 2 ','outranked-season-2',4,'/api/covers/1778023706713-jfxyal.jpg',replace('Chukwuemeka Obi has spent three years building himself into the most feared senior prefect FGC Lokoja has ever seen. Then a new principal arrives from Abuja with one idea that dismantles everything he is.\nWhen her student council hands real authority to Chinazaekpere Hauwa, a JS3 girl Emeka once publicly humiliated, he must survive something worse than losing power: discovering he was never who he thought he was.\nWhat begins as a clash between two kinds of authority becomes something neither of them planned.\nA story about who you become when everything you built yourself around is taken away.','\n',char(10)),'School Life and Friendships','["Inkseries Original","Trending in Nigeria","Free Episodes Available"]','completed',0,0,0,0,0,NULL,'2026-04-09 21:24:28','2026-05-20 22:06:55','Inkseries Team ','seasons_episodes');
