INSERT INTO "novels" ("id","title","slug","author_id","cover_image_url","synopsis","genre","tags","status","is_featured","total_chapters","total_reads","total_likes","rating","published_at","created_at","updated_at","author_name","chapter_format") VALUES(44,'AKWA ROAD ','akwa-road',4,'/api/covers/1780136397246-cogv16.jpg',replace('Six teenagers. Teacher Obiora''s lesson parlour, Awka Road, Onitsha. Every weekday, four to six. WAEC.\nDifferent schools, different homes, different secrets.\nNgozi retakes her exam hoping no one notices. Chidi hides real pain behind jokes that almost always land. Emeka has a bruise he won''t explain. Precious disappears Thursdays. Ada writes stories her father can never read. Tobe says almost nothing, sees everything, carries the heaviest thing of all.\nNone of them chose each other. The room chose them.\nAkwa Road is about six strangers who became each other''s people because they were too tired to pretend they hadn''t.','\n',char(10)),'School Life and Friendships','["Inkseries Original","Trending in Nigeria","Free Episodes Available"]','completed',0,12,0,0,0,NULL,'2026-04-10 15:23:24','2026-05-30 10:20:04','Inkseries Team ','seasons_episodes');
INSERT INTO "novels" ("id","title","slug","author_id","cover_image_url","synopsis","genre","tags","status","is_featured","total_chapters","total_reads","total_likes","rating","published_at","created_at","updated_at","author_name","chapter_format") VALUES(45,'BORROWED HAPPINESS - SEASON 1 ','borrowed-happiness-season-1',4,'/api/covers/1780136603081-bwdoje.jpg',replace('Teniola has spent her whole life working the edges of other people''s joy. Every weekend, a new Ibadan wedding. Every weekend, invisible.\nWhen she meets Kayode at an April reception, something shifts. His father plays the talking drum. He is laboring in someone else''s celebration too, and he sees her anyway.\nAcross five weddings and one summer, they find each other in back corridors and generator sheds, falling into something neither can name.\nBut being seen is dangerous when you''ve spent a lifetime learning to disappear.\nBorrowed Happiness is about choosing your own joy before someone teaches you not to.','\n',char(10)),'Romance and First Love','["Inkseries Original","Trending in Nigeria","Free Episodes Available"]','completed',0,7,4,0,0,NULL,'2026-04-10 15:47:36','2026-05-30 10:23:26','Inkseries Team ','seasons_episodes');
INSERT INTO "novels" ("id","title","slug","author_id","cover_image_url","synopsis","genre","tags","status","is_featured","total_chapters","total_reads","total_likes","rating","published_at","created_at","updated_at","author_name","chapter_format") VALUES(47,'BORROWED HAPPINESS - SEASON 2 ','borrowed-happiness-season-2',4,'/api/covers/1780136624376-ohbhmx.jpg',replace('Teniola has spent her whole life working the edges of other people''s joy. Every weekend, a new Ibadan wedding. Every weekend, invisible.\nWhen she meets Kayode at an April reception, something shifts. His father plays the talking drum. He is laboring in someone else''s celebration too, and he sees her anyway.\nAcross five weddings and one summer, they find each other in back corridors and generator sheds, falling into something neither can name.\nBut being seen is dangerous when you''ve spent a lifetime learning to disappear.\nBorrowed Happiness is about choosing your own joy before someone teaches you not to.','\n',char(10)),'Romance and First Love','["Inkseries Original","Trending in Nigeria","Free Episodes Available"]','completed',0,6,0,0,0,NULL,'2026-04-10 20:23:06','2026-05-30 10:23:47','Inkseries Team ','seasons_episodes');
INSERT INTO "novels" ("id","title","slug","author_id","cover_image_url","synopsis","genre","tags","status","is_featured","total_chapters","total_reads","total_likes","rating","published_at","created_at","updated_at","author_name","chapter_format") VALUES(49,'DARK KITCHEN - SEASON 1','dark-kitchen-season-1',4,'/api/covers/1776485134938-97vs1i.jpg',replace('Emem borrows her sister''s husband''s phone in a dark kitchen and sees a notification she was never meant to read. Convinced she has uncovered an affair, she takes screenshots and says nothing.\nThen she says everything too late and to the wrong person.\nWhat follows is a quiet catastrophe: a marriage dismantled, a sister lost, a truth that arrives only after the damage is done.\nSet in Calabar, Nigeria, Dark Kitchen is a devastating story about silence, assumption, and the unbearable cost of a single moment of incomplete information.','\n',char(10)),'Family and Identity','["Inkseries Original","Trending in Nigeria","Free Episodes Available","Family Drama","Big City","Secret Revealed","Complicated Family","Heartbreaking"]','completed',0,12,0,0,0,NULL,'2026-04-12 13:52:44','2026-05-20 22:14:58','Inkseries Team ','seasons_episodes');
