INSERT INTO "novels" ("id","title","slug","author_id","cover_image_url","synopsis","genre","tags","status","is_featured","total_chapters","total_reads","total_likes","rating","published_at","created_at","updated_at","author_name","chapter_format") VALUES(51,'THE KING''S OTHER HAND - SEASON 1','the-king''s-other-hand-season-1',4,'/api/covers/1776441889439-d8jpqz.jpg',replace('Amaechi of Oke is taken from his mother and delivered to the palace of Zara as a political pledge. He is six years old.\nInside those walls he finds his greatest friendship, suffers for it, and loses it too soon. He rises to the king''s inner circle, survives alone in a foreign city, and races home too late.\nWhen the palace discards him, he returns to a homeland that has moved on, carrying nothing but a promise made at six.\nThe King''s Other Hand is about a boy who belonged fully to no world and gave everything to both.','\n',char(10)),'African Fantasy and Mythology','["Inkseries Original","Trending in Nigeria","Free Episodes Available"]','completed',0,9,0,0,0,NULL,'2026-04-14 16:16:05','2026-05-20 22:17:54','Inkseries Team ','seasons_episodes');
