INSERT INTO "novels" ("id","title","slug","author_id","cover_image_url","synopsis","genre","tags","status","is_featured","total_chapters","total_reads","total_likes","rating","published_at","created_at","updated_at","author_name","chapter_format") VALUES(54,'UNBROKEN - SEASON 1','unbroken-season-1',4,'/api/covers/1776459405548-5wafjp.jpg',replace('Ivie Osagie leaves Ovia with seven WAEC distinctions, a passport, and a plan to break her family''s cycle of poverty. Her father''s cousin promises a life in Italy.\nWhat she finds is a debt she never agreed to and a system built to make her believe there is no way out.\nUnbroken follows Ivie across three seasons: a courtyard where she understands everything, two years of psychological war, and the harder work of building a life on her own terms.\nThis is not a story about what was done to her. It is a story about what she did anyway.','\n',char(10)),'Family and Identity','["Inkseries Original","Trending in Nigeria","Free Episodes Available"]','completed',0,8,0,0,0,NULL,'2026-04-15 07:02:39','2026-05-30 12:01:57','Inkseries Team ','seasons_episodes');
