INSERT INTO "novels" ("id","title","slug","author_id","cover_image_url","synopsis","genre","tags","status","is_featured","total_chapters","total_reads","total_likes","rating","published_at","created_at","updated_at","author_name","chapter_format") VALUES(56,'UNBROKEN - SEASON 3','unbroken-season-3',4,'/api/covers/1776459545725-k4q4s4.jpg',replace('Ivie Osagie leaves Ovia with seven WAEC distinctions, a passport, and a plan to break her family''s cycle of poverty. Her father''s cousin promises a life in Italy.\nWhat she finds is a debt she never agreed to and a system built to make her believe there is no way out.\nUnbroken follows Ivie across three seasons: a courtyard where she understands everything, two years of psychological war, and the harder work of building a life on her own terms.\nThis is not a story about what was done to her. It is a story about what she did anyway.','\n',char(10)),'Family and Identity','["Inkseries Original","Trending in Nigeria","Free Episodes Available"]','completed',0,7,1,0,0,NULL,'2026-04-15 07:30:15','2026-05-20 22:26:20','Inkseries Team ','seasons_episodes');
INSERT INTO "novels" ("id","title","slug","author_id","cover_image_url","synopsis","genre","tags","status","is_featured","total_chapters","total_reads","total_likes","rating","published_at","created_at","updated_at","author_name","chapter_format") VALUES(57,'THE QUIET NEXT DOOR ','the-quiet-next-door',4,'/api/covers/1776400928962-3zhhao.png',replace('Ngozi wants one thing: to be seen. From her Lagos rooftop, she builds a following nobody is watching yet. When Uloma in Flat 6 takes her in, she finally feels like someone.\nThen Uloma posts an accusation at midnight. A neighbor. A crime. One suspect.\nNgozi shares it before sunrise. What follows is fast, loud, and intoxicating.\nBut the story cracks. A timestamp. A sister at a gate nobody opened. And a young man in Flat 9, quietly dismantled by a crowd that moved on.\nThe Quiet Next Door is about what we destroy when we choose reach over truth.','\n',char(10)),'Thriller and Mystery','["Inkseries Original","Trending in Nigeria","Free Episodes Available"]','completed',0,12,7,0,0,NULL,'2026-04-17 04:38:20','2026-05-20 22:28:55','Inkseries Team ','seasons_episodes');
INSERT INTO "novels" ("id","title","slug","author_id","cover_image_url","synopsis","genre","tags","status","is_featured","total_chapters","total_reads","total_likes","rating","published_at","created_at","updated_at","author_name","chapter_format") VALUES(58,'THE RIDERS - SEASON 1','the-riders-season-1',4,'/api/covers/1776492551232-jfrmnj.png',replace('In Benin City, Osaro and his older cousin Idemudia run their uncle''s last two motorcycles as the government okada crackdown swallows their routes one by one. When a quiet man with a briefcase offers triple the usual rate, one cousin sees survival and the other sees a trap.\nWhat begins as a single job becomes a deepening entanglement that tests everything they believe about money, loyalty, and what it means to build a future in a city that has never made it easy.\nTwo boys. One road. Completely different destinations.','\n',char(10)),'Street and Hustle','["Inkseries Original","Trending in Nigeria","Episode Everyone is Talking About","Free Episodes Available"]','completed',0,0,1,0,0,NULL,'2026-04-18 06:10:31','2026-05-21 16:40:02','Inkseries Team ','seasons_episodes');
INSERT INTO "novels" ("id","title","slug","author_id","cover_image_url","synopsis","genre","tags","status","is_featured","total_chapters","total_reads","total_likes","rating","published_at","created_at","updated_at","author_name","chapter_format") VALUES(59,'THE RIDERS - SEASON 2 ','the-riders-season-2',4,'/api/covers/1776492727380-97l2bh.png',replace('In Benin City, Osaro and his older cousin Idemudia run their uncle''s last two motorcycles as the government okada crackdown swallows their routes one by one. When a quiet man with a briefcase offers triple the usual rate, one cousin sees survival and the other sees a trap.\nWhat begins as a single job becomes a deepening entanglement that tests everything they believe about money, loyalty, and what it means to build a future in a city that has never made it easy.\nTwo boys. One road. Completely different destinations.','\n',char(10)),'Street and Hustle','["Inkseries Original","Trending in Nigeria","Episode Everyone is Talking About","Free Episodes Available"]','completed',0,0,1,0,0,NULL,'2026-04-18 06:12:23','2026-05-21 16:40:22','Inkseries Team ','seasons_episodes');
INSERT INTO "novels" ("id","title","slug","author_id","cover_image_url","synopsis","genre","tags","status","is_featured","total_chapters","total_reads","total_likes","rating","published_at","created_at","updated_at","author_name","chapter_format") VALUES(60,'THE BACK ROW','the-back-row',4,'/api/covers/1776539449255-tjc5by.jpg',replace('A stolen exam paper. Five SS2 suspects from the back row. Goldcrest Academy, Umuahia. Nobody believes any of them.\nOnyekachi is hiding what he saw. Emeka is hiding what he sells. Adun is hiding who her uncle is. Yewa is hiding where she was that night. Nasiru is hiding who he has been talking to.\nTen days before a board hearing that could end their futures. Five teenagers who would never have chosen each other.\nBut someone built this frame before they ever met.\nThe Back Row is about truth in a room that has already decided not to listen.','\n',char(10)),'School Life and Friendships','["Inkseries Original","Trending in Nigeria","Free Episodes Available"]','completed',0,0,1,0,0,NULL,'2026-04-18 19:11:36','2026-05-21 21:07:41','Inkseries Team ','seasons_episodes');
INSERT INTO "novels" ("id","title","slug","author_id","cover_image_url","synopsis","genre","tags","status","is_featured","total_chapters","total_reads","total_likes","rating","published_at","created_at","updated_at","author_name","chapter_format") VALUES(61,'HER SIDE - SEASON 1','her-side-season-1',4,'/api/covers/1776689535575-r6eol9.jpg',replace('Chiamaka Obi arrives at a boarding school in Ibadan midterm with two bags, a monogrammed trunk, and a life she is not ready to let go of.\nShe gets the bottom bunk, a hostile bunkmate, an unfamiliar curriculum, dwindling money, and the slow collapse of everything she once used to define herself.\nHer Side of the Hostel tracks one school term: a sharp, often painful journey from performance to honesty, from isolation to belonging.\nAbout what we carry into rooms, what we put down, and what we find when pride stops being the loudest thing in the space.','\n',char(10)),'School Life and Friendships','["Inkseries Original","Trending in Nigeria"]','completed',0,12,2,0,0,NULL,'2026-04-19 05:05:28','2026-05-21 21:11:26','Inkseries Team ','seasons_episodes');
INSERT INTO "novels" ("id","title","slug","author_id","cover_image_url","synopsis","genre","tags","status","is_featured","total_chapters","total_reads","total_likes","rating","published_at","created_at","updated_at","author_name","chapter_format") VALUES(62,'HER SIDE - SEASON 2','her-side-season-2',4,'/api/covers/1776689559874-ekb67o.jpg',replace('Chiamaka Obi arrives at a boarding school in Ibadan midterm with two bags, a monogrammed trunk, and a life she is not ready to let go of.\nShe gets the bottom bunk, a hostile bunkmate, an unfamiliar curriculum, dwindling money, and the slow collapse of everything she once used to define herself.\nHer Side of the Hostel tracks one school term: a sharp, often painful journey from performance to honesty, from isolation to belonging.\nAbout what we carry into rooms, what we put down, and what we find when pride stops being the loudest thing in the space.','\n',char(10)),'School Life and Friendships','["Inkseries Original","Trending in Nigeria","Free Episodes Available"]','completed',0,12,1,0,0,NULL,'2026-04-19 06:19:56','2026-05-21 21:11:55','Inkseries Team','seasons_episodes');
INSERT INTO "novels" ("id","title","slug","author_id","cover_image_url","synopsis","genre","tags","status","is_featured","total_chapters","total_reads","total_likes","rating","published_at","created_at","updated_at","author_name","chapter_format") VALUES(64,'NEVER SAID','never-said',4,'/api/covers/1776610459870-3p4ldm.jpg',replace('Chukwudi is quietly smarter than everyone around him and has learned to hide it. When his mother hires a home lesson teacher, an NYSC corper named Amanda arrives and changes everything without meaning to.\nShe is the first adult who asks what he thinks and actually waits. She tells him his Ogoniland essay is the best she has read from someone his age.\nHe does not know what to do with being seen this fully.\nWhen Amanda leaves without warning, he begins to write. The page is where he understands what she gave him and what he will never lose.','\n',char(10)),'Romance and First Love','["Inkseries Original","Trending in Nigeria","Free Episodes Available"]','completed',0,7,1,0,0,NULL,'2026-04-19 14:46:17','2026-05-21 21:15:29','Inkseries Team ','seasons_episodes');
INSERT INTO "novels" ("id","title","slug","author_id","cover_image_url","synopsis","genre","tags","status","is_featured","total_chapters","total_reads","total_likes","rating","published_at","created_at","updated_at","author_name","chapter_format") VALUES(65,'PREP NIGHT ','prep-night',4,'/api/covers/1776930215508-j6jvn1.jpg',replace('When Temi Adeyinka transfers midsession to Federal Government College Lokoja, she expects to reclaim first position. What she does not expect is Dayo Okonkwo, quiet, immovable, three terms in first and never needed a single direct word to prove it.\nTheir rivalry becomes SS1B''s favourite spectator sport. Then the generator dies during prep. Forty minutes in the dark. Something shifts that neither knows how to name.\nWhat follows is two self aware teenagers using every available tool to avoid admitting what their class knows.\nPrep night is about the precise moment vulnerability begins, which is where performance ends.','\n',char(10)),'Romance and First Love','["Inkseries Original","Trending in Nigeria","Free Episodes Available"]','completed',0,12,2,0,0,NULL,'2026-04-20 02:19:24','2026-05-21 21:19:02','Inkseries Team ','seasons_episodes');
INSERT INTO "novels" ("id","title","slug","author_id","cover_image_url","synopsis","genre","tags","status","is_featured","total_chapters","total_reads","total_likes","rating","published_at","created_at","updated_at","author_name","chapter_format") VALUES(66,'AFTER THE CRASH - SEASON 1 ','after-the-crash-season-1',4,'/api/covers/1776681276116-06d0yb.jpg',replace('When her father''s empire collapses overnight, Adanna Obi loses everything she was built from: the school, the compound on Lagos Island, the friends who vanish as quietly as they came.\nRelocated to Mushin, enrolled in a school where no one knows her name, she begins learning what holds value in a person.\nChinedu, the boy assigned to show her around, is patient in a way that irritates, then disarms, then quietly dismantles her.\nTheir love does not arrive with drama. It arrives after grief, after honesty, after she learns to put down everything she was carrying that was never hers.','\n',char(10)),'Romance and First Love','["Inkseries Original","Trending in Nigeria","Free Episodes Available"]','completed',0,6,1,0,0,NULL,'2026-04-20 10:37:02','2026-05-21 22:00:59','Inkseries Team ','seasons_episodes');
INSERT INTO "novels" ("id","title","slug","author_id","cover_image_url","synopsis","genre","tags","status","is_featured","total_chapters","total_reads","total_likes","rating","published_at","created_at","updated_at","author_name","chapter_format") VALUES(67,'AFTER THE CRASH - SEASON 2','after-the-crash-season-2',4,'/api/covers/1776681474882-khhz76.jpg',replace('When her father''s empire collapses overnight, Adanna Obi loses everything she was built from: the school, the compound on Lagos Island, the friends who vanish as quietly as they came.\nRelocated to Mushin, enrolled in a school where no one knows her name, she begins learning what holds value in a person.\nChinedu, the boy assigned to show her around, is patient in a way that irritates, then disarms, then quietly dismantles her.\nTheir love does not arrive with drama. It arrives after grief, after honesty, after she learns to put down everything she was carrying that was never hers.','\n',char(10)),'Romance and First Love','["Inkseries Original","Trending in Nigeria","Free Episodes Available"]','completed',0,10,2,0,0,NULL,'2026-04-20 10:38:47','2026-05-21 22:01:20','Inkseries Team ','seasons_episodes');
INSERT INTO "novels" ("id","title","slug","author_id","cover_image_url","synopsis","genre","tags","status","is_featured","total_chapters","total_reads","total_likes","rating","published_at","created_at","updated_at","author_name","chapter_format") VALUES(68,'VOICE NOTES - SEASON 1 ','voice-notes-season-1',4,'/api/covers/1776705998766-vs8d9u.jpg','When Chisom, a seventeen-year-old girl from Enugu who talks best when no one is watching her face, is paired with Khalil from Abuja in an inter-school voice note exchange, she expects polite formality and nothing more. What builds instead is a private world — their own grammar, their own language, a connection assembled entirely from voice and honesty and the specific texture of a laugh heard through a phone. When a physical visit is announced, both of them panic. Because what they have was built in specific conditions. And now it must survive a room. Voice Notes is a story about what true intimacy costs, what it survives, and what it becomes when it finally has to prove itself real.','Romance and First Love','["Inkseries Original","Trending in Nigeria","Free Episodes Available"]','completed',0,10,3,0,0,NULL,'2026-04-20 17:28:42','2026-05-30 10:03:21','Inkseries Team ','seasons_episodes');
INSERT INTO "novels" ("id","title","slug","author_id","cover_image_url","synopsis","genre","tags","status","is_featured","total_chapters","total_reads","total_likes","rating","published_at","created_at","updated_at","author_name","chapter_format") VALUES(69,'VOICE NOTES - SEASON 2','voice-notes-season-2',4,'/api/covers/1776706172002-10zun5.jpg','When Chisom, a seventeen-year-old girl from Enugu who talks best when no one is watching her face, is paired with Khalil from Abuja in an inter-school voice note exchange, she expects polite formality and nothing more. What builds instead is a private world — their own grammar, their own language, a connection assembled entirely from voice and honesty and the specific texture of a laugh heard through a phone. When a physical visit is announced, both of them panic. Because what they have was built in specific conditions. And now it must survive a room. Voice Notes is a story about what true intimacy costs, what it survives, and what it becomes when it finally has to prove itself real.','Romance and First Love','["Inkseries Original","Trending in Nigeria","Free Episodes Available"]','completed',0,8,0,0,0,NULL,'2026-04-20 17:29:50','2026-05-30 10:03:04','Inkseries Team ','seasons_episodes');
INSERT INTO "novels" ("id","title","slug","author_id","cover_image_url","synopsis","genre","tags","status","is_featured","total_chapters","total_reads","total_likes","rating","published_at","created_at","updated_at","author_name","chapter_format") VALUES(70,'THE KEEPER''S INHERITANCE - SEASON 1','the-keeper''s-inheritance-season-1',4,'/api/covers/1776715678635-n4byjt.jpg',replace('Obiageli has lived beside Agulu Lake her whole life and never feared it. When a construction company arrives to drain part of it for a road, she begins dreaming in a voice that is not hers.\nShe wakes knowing things no living person told her: about the lake, her bloodline, and seven ancient stones at the deepest point, the only thing holding something catastrophic in place.\nWith the machines already moving, she must race against a legal system built on colonial lies, a fractured community, and her own fear to become what Agulu Lake has always been waiting for.','\n',char(10)),'African Fantasy and Mythology','["Inkseries Original","Trending in Nigeria","Free Episodes Available"]','coming_soon',0,0,0,0,0,NULL,'2026-04-20 20:08:58','2026-05-21 22:07:57','Inkseries Team ','seasons_episodes');
