INSERT INTO "novels" ("id","title","slug","author_id","cover_image_url","synopsis","genre","tags","status","is_featured","total_chapters","total_reads","total_likes","rating","published_at","created_at","updated_at","author_name","chapter_format") VALUES(72,'THE KEEPER''S INHERITANCE - SEASON 3','the-keeper''s-inheritance-season-3',4,'/api/covers/1776715935198-u9sdge.jpg',replace('Obiageli has lived beside Agulu Lake her whole life and never feared it. When a construction company arrives to drain part of it for a road, she begins dreaming in a voice that is not hers.\nShe wakes knowing things no living person told her: about the lake, her bloodline, and seven ancient stones at the deepest point, the only thing holding something catastrophic in place.\nWith the machines already moving, she must race against a legal system built on colonial lies, a fractured community, and her own fear to become what Agulu Lake has always been waiting for.','\n',char(10)),'African Fantasy and Mythology','["Inkseries Original","Trending in Nigeria","Free Episodes Available"]','coming_soon',0,0,0,0,0,NULL,'2026-04-20 20:12:30','2026-05-21 22:08:57','Inkseries Team ','seasons_episodes');
INSERT INTO "novels" ("id","title","slug","author_id","cover_image_url","synopsis","genre","tags","status","is_featured","total_chapters","total_reads","total_likes","rating","published_at","created_at","updated_at","author_name","chapter_format") VALUES(73,'THE CORNER BOY ','the-corner-boy',4,'/api/covers/1780136907226-uk9ccb.jpg',replace('Jidenna runs a data business from an Oshodi underpass: one itel phone, a mental ledger, two years of street intelligence. When a corporate kiosk sets up twenty metres from his corner, undercutting his margin, he faces a choice no Commerce textbook has prepared him for.\nWhat follows is not defeat. It is about a boy who studies his competition until it becomes his teacher, builds credit systems agents cannot match, and discovers that the difference between a hustle and a business is documentation.\nThe Corner Boy is about what happens when survival intelligence is given room to become vision.','\n',char(10)),'Street and Hustle','["Inkseries Original","Trending in Nigeria","Free Episodes Available"]','completed',0,10,20,0,0,NULL,'2026-04-21 12:48:15','2026-05-30 10:28:32','Inkseries Team ','seasons_episodes');
INSERT INTO "novels" ("id","title","slug","author_id","cover_image_url","synopsis","genre","tags","status","is_featured","total_chapters","total_reads","total_likes","rating","published_at","created_at","updated_at","author_name","chapter_format") VALUES(74,'MADAM''S GIRL ','madam''s-girl',4,'/api/covers/1780138191635-h9c20b.jpg',replace('Folake has worked Madam Bisi''s pepper stall in Bodija Market since JS1, not out of desperation but out of discipline. Between weighing tatashe and reading customers, she has been building: blended pepper sachets for working women who cannot afford another evening at a grinding machine.\nThe plan needs kitchen access, capital, and Madam Bisi herself. When Madam Bisi makes an offer fair by every business measure and complicated by every human one, Folake must decide what her idea is worth.\nA story about ambition, mentorship, and the hardest negotiation: the one with the person who first believed in you.','\n',char(10)),'Street and Hustle','["Inkseries Original","Trending in Nigeria","Free Episodes Available"]','completed',0,12,1,0,0,NULL,'2026-04-22 06:38:31','2026-05-30 10:49:57','Inkseries Team','seasons_episodes');
INSERT INTO "novels" ("id","title","slug","author_id","cover_image_url","synopsis","genre","tags","status","is_featured","total_chapters","total_reads","total_likes","rating","published_at","created_at","updated_at","author_name","chapter_format") VALUES(75,'BOTH HANDS','both-hands',4,'/api/covers/1780137078356-5oi2sz.jpg',replace('Jideofor is the best electrical hand under Carter Bridge and the only one secretly sitting JAMB. He has convinced himself that wanting both things is the same as betraying one of them.\nWhen a European car defeats every mechanic under the bridge, Jideofor diagnoses it alone. The owner is a UNILAG lecturer who returns not to save but to sharpen him.\nWhat does a boy owe the man who built him? And is honoring that debt the same as staying?\nBoth Hands is about inheritance, silence, and the kind of loyalty that looks like leaving but never actually does.','\n',char(10)),'Street and Hustle','["Inkseries Original","Trending in Nigeria","Free Episodes Available"]','completed',0,12,2,0,0,NULL,'2026-04-22 07:28:14','2026-05-30 10:31:24','Inkseries Team ','seasons_episodes');
INSERT INTO "novels" ("id","title","slug","author_id","cover_image_url","synopsis","genre","tags","status","is_featured","total_chapters","total_reads","total_likes","rating","published_at","created_at","updated_at","author_name","chapter_format") VALUES(76,'MOUTHING THE WORDS - SEASON 1 ','mouthing-the-words-season-1',4,'/api/covers/1778024217226-k6hhah.jpg',replace('Simi has spent four months on the same Lagos danfo as a boy she has never spoken to. She knows his shoe size, his reading habits, the lyrics he mouths. She did not plan on him finding out.\nWhen the bus breaks down on Carter Bridge and they end up late, his name is Femi. Being caught becomes the most honest conversation of her year.\nWhat follows is slow, specific, inevitable: the difference between watching someone and letting them watch you back.\nMouthing the Words is a Lagos love story about the moment you stop being a stranger to yourself.','\n',char(10)),'Romance and First Love','["Inkseries Original","Trending in Nigeria","Free Episodes Available"]','completed',0,8,5,0,0,NULL,'2026-04-28 16:25:34','2026-05-22 05:24:03','Inkseries Team ','seasons_episodes');
INSERT INTO "novels" ("id","title","slug","author_id","cover_image_url","synopsis","genre","tags","status","is_featured","total_chapters","total_reads","total_likes","rating","published_at","created_at","updated_at","author_name","chapter_format") VALUES(77,'MOUTHING THE WORDS - SEASON 2','mouthing-the-words-season-2',4,'/api/covers/1778024238747-c8vinl.jpg',replace('Simi has spent four months on the same Lagos danfo as a boy she has never spoken to. She knows his shoe size, his reading habits, the lyrics he mouths. She did not plan on him finding out.\nWhen the bus breaks down on Carter Bridge and they end up late, his name is Femi. Being caught becomes the most honest conversation of her year.\nWhat follows is slow, specific, inevitable: the difference between watching someone and letting them watch you back.\nMouthing the Words is a Lagos love story about the moment you stop being a stranger to yourself.','\n',char(10)),'Romance and First Love','["Inkseries Original","Trending in Nigeria","Free Episodes Available"]','completed',0,0,0,0,0,NULL,'2026-04-28 16:26:45','2026-05-22 05:29:59','Inkseries Team ','seasons_episodes');
INSERT INTO "chapters" ("id","novel_id","chapter_number","title","content","word_count","is_premium","is_published","audio_url","published_at","created_at","updated_at","scheduled_release_at","part_number","season_id") VALUES(125,1,1,'The Round',replace('Izunna had a system, and the system was the reason everything held together. Without it, bags got mixed, clients received the wrong clothes back, and the money meant for Adaeze''s second term fees dissolved into the kind of afternoon nobody could account for.\nHe was up by five thirty. His mother had stopped waking him in SS1, the year he started the business and proved he could hold a schedule better than any alarm. He arranged the morning across the parlor floor before sunlight reached the curtains: twelve laundry bags tagged by client name and zone, his notebook open to Tuesday''s route, and the delivery map he had drawn the night before on the back of a used exercise book page. World Bank first. Then Orji. Then MCC Road if there was a confirmed pickup. Back through Works Layout before the afternoon went flat. The keke driver near their compound had not needed directions in months.\nHis mother came out of the bedroom while he was crouching over the last two bags. She wore her market wrapper knotted at the waist, carry bag on her shoulder, head tied. She looked at him from the doorway the way she sometimes did in the early morning, with something he could not name, part pride and part a tiredness she worked to keep off her face.\n"Don''t forget to eat before you go out," she said.\n"Yes, Ma."\nShe crossed the room and touched the top of his head once, the way she did when he was much smaller. Then she was out the front door and the parlor held the kind of quiet that comes after someone leaves in a hurry.\nHe did not eat before he went.\nThe keke to World Bank cost one hundred and fifty naira. He had worked out in SS2 that consolidating his first three stops and walking the shorter connectors between them saved him four hundred naira a week. He never thought of it as savings. He thought of it as Adaeze''s notebook money, her second set of textbooks, the buffer that kept the school fees conversation from happening again.\nAlhaji Musa''s gate was the easiest stop on any route. The man himself was never visible at the gate, and the exchange never changed: one press of the bell, the gateman coming out with a tied black nylon bag, a nod, the clean bag passed over, the gate pulling shut. Nothing extra requested. Izunna valued transactions that stayed what they were supposed to be.\nMrs. Chidinma in Orji was the opposite in every way.\nHer compound sat behind the filling station, in a row of houses that always had activity in the yard. She was around fifty and had the kind of energy that made everyone within reach feel like her personal business. Every Tuesday she came to her own door. Every Tuesday she talked. Her daughter''s posting in Abuja. The road outside her gate the council had been promising to grade since the year before last.\nThat Tuesday she met him at the veranda with a covered cooler already in both hands.\n"Ofada rice. Too much for one person."\n"Ma, I still have stops to make."\n"Sit. Eat fast. Then go." She said it the way a teacher ends a discussion.\nHe sat on her veranda steps. The rice had the right oil ratio with a fried egg on top. She stood in the doorway and continued her update on the road while he ate. When he finished he covered the cooler and thanked her.\n"Next week, whiter whites," she said.\n"They''ll come back whiter."\n"That is always what you say."\n"And it always keeps being true."\nShe laughed at that, a full chest laugh, and waved him off like he was an argument she had decided not to push.\nThe Works Layout handoff was last. A woman whose name he had never learned counted out the full payment from a folded note and went back inside before he closed his notebook. She never disputed the surcharge. He appreciated that.\nThe business had started in SS1 first term. He had watched his mother sit at the kitchen table with the school fees notice open in front of her for longer than it should take to read one page. She folded it. She said she would sort it. The way her face went while she said it told him what sorting would cost them, and what they were already going without.\nThe next morning he knocked on three doors at their church and asked if anyone needed laundry collected. Two women said yes. One gave him her neighbor''s number. Within a month he had eight clients. By first term''s end, the fees were paid and the kitchen table scene did not repeat.\nHe was in SS3 now. Twelve steady clients. A notebook that had never failed him. WAEC sitting four months ahead, an exam he had already decided he was going to pass. He had structured his schedule around it carefully. Pickups on Tuesdays and Saturdays. Mornings for reading. No exceptions made for either.\nHe was at the bus stop near the MCC Road junction, checking his notebook to confirm he had nothing remaining in this part of town, when his phone buzzed.\nNew booking notification.\nHe opened it. MCC Road address. The kind of street with high freshly painted gates and compounds that stayed quiet through the afternoons. Those clients paid above his standard rate and never disputed the soap surcharge. He had been working toward that zone for months.\nHe read the name once. Then again.\nMrs. Ngozi Dike.\nHe saved the number, marked the booking confirmed, and wrote the address in his notebook under next Tuesday. Then he raised his hand for a keke back toward Wetheral Road.\nTwelve bags moved. One new client on MCC Road. Enough cleared after costs to put something toward Adaeze''s pile.\nHe told himself it had been a good day the whole ride home.','\n',char(10)),997,0,1,NULL,'2026-04-22 06:24:50','2026-03-16 04:02:44','2026-04-22 06:24:50',NULL,1,NULL);
INSERT INTO "chapters" ("id","novel_id","chapter_number","title","content","word_count","is_premium","is_published","audio_url","published_at","created_at","updated_at","scheduled_release_at","part_number","season_id") VALUES(126,1,2,'MCC Road',replace('\nThe gate was freshly painted and the bell worked on the first press, which told Izunna something about the kind of house this was going to be before he had even stepped through it.\nHe had arrived four minutes early, which was his habit for first-time clients. New clients formed their impression of a business in the first three minutes. He had learned that in SS2, after losing a Works Layout contact because he showed up looking rushed with chalk dust still on his sleeve from school. Since then, first visits were planned differently: neat shirt, notebook out before he knocked, a tone that said he had been doing this long enough to be trusted with someone''s property.\nThe gateman was a man in his fifties with a slow walk and no expression. He looked at Izunna without speaking, pulled the gate wider, and pointed toward the main house.\nIzunna noted the compound as he crossed it. New interlocking tiles. A car under a shade cover on the left side. Flower beds that were watered regularly, the soil still dark at the roots. The house itself was two storeys, cream and rust, with a wide veranda that had not been converted to storage the way many houses in that range eventually were. Whoever lived here maintained things. That was usually a good sign for a laundry client. It meant they cared about fabric.\nHe rang the house bell and waited.\nMrs. Ngozi Dike came to the door herself. She was in her mid-thirties, or somewhere close to it, and she wore a light-coloured wrapper that she had tied at the chest in the way that suggested she had been in the middle of something when the bell rang. Her hair was pinned loosely. She looked at him with the unhurried ease of someone who had not been interrupted at all, but had simply chosen this pace.\n"You must be the laundry boy." Her voice was level. Not unkind, just efficient.\n"Good afternoon, Ma. Izunna. I confirmed the pickup for two."\n"I know." She stepped back from the door. "Come and wait inside. The bag is almost ready."\nHe had waited in client homes before. It was normal, especially when something needed to be added at the last minute or a garment was still being untied from a hanger. He stepped in.\nThe sitting room was cool and dim. The curtains were drawn across the far window, the kind of heavy fabric that held out afternoon sun entirely. The settee set was cream leather. The centre table had a glass vase on it with nothing inside. He stood near the entrance, notebook in hand, and did not sit.\nShe moved toward the inner corridor and called back, "The bag is in the room. Let me bring it."\nHe waited.\nTwo minutes passed. He could hear movement from deeper in the house. A door. A sliding sound.\nThen she came back through the corridor entrance, and the wrapper from the door was gone.\nShe had changed, or started to. What she was wearing now was shorter and did not hold at the sides when she moved. She walked with the same unhurried ease, crossing toward the far end of the room to open a cabinet drawer, as though looking for something, though she had said the bag was in the room.\nIzunna looked at the wall on his right. It had a framed photograph mounted at eye level, a coastal landscape, somewhere with water and pale sand that was not Nigerian. He studied the frame. The frame had a thin black border. The photograph was printed large and the colours had stayed true, which meant the framing had been done properly, the way you seal a print to keep sunlight from pulling the saturation out over time.\nHe knew none of this about photography. But it gave his eyes somewhere to be.\n"I can''t find the second part," she said from across the room. She opened another drawer. She moved to the bookshelf beside the cabinet and checked behind a decorative box. She moved without hurry and without appearing to notice what she was not covered by. "The inner bag. I pack separately."\n"Take your time, Ma." His voice came out steady. He was proud of that.\n"I''m sure it''s in the bedroom." She turned and went back through the corridor.\nHe counted the tiles from where he stood to the front door. Twelve. He read the title text on the spines of four books on the bottom shelf. He checked his notebook as though there was something there to check, running his pen down the client column without reading any of it.\nShe came back five minutes later with a proper laundry bag, tied and labelled the way he asked all new clients to label their bags, name and phone number in marker on the white tag. She held it out.\n"Everything''s there now. I found it under the chair."\nHe took the bag and entered it in his notebook. Standard pickup weight. Nothing unusual in the bag''s shape. He quoted her the rate, she paid without negotiating, and he thanked her.\n"I''ll have it back to you clean by Friday, Ma."\n"Good." She was already moving back toward the interior of the house.\nThe gateman let him out without speaking.\nOn the keke back toward Wetheral Road, he held the bag on his lap and watched the MCC Road houses thin out as they turned. His hands were fully steady. He had done his job. He had collected. He had kept his eyes where they were supposed to be.\nHis phone buzzed against his thigh.\nHe opened it at the next traffic pause. A service notification from her contact card. She had rated the pickup. Five stars. And below the stars, a typed note:\nVery professional.\nHe read it once. The keke moved. He read it again.\nHe put his phone back in his pocket and looked out at the road ahead, not quite sure what he was supposed to feel about being graded for not looking.','\n',char(10)),1017,0,1,NULL,'2026-04-30 03:59:07','2026-03-16 04:04:05','2026-04-30 03:59:07',NULL,1,NULL);
INSERT INTO "chapters" ("id","novel_id","chapter_number","title","content","word_count","is_premium","is_published","audio_url","published_at","created_at","updated_at","scheduled_release_at","part_number","season_id") VALUES(127,1,3,'The Count',replace('Dr. Onyeka had not missed a Tuesday pickup in seven months, and in all that time he had never once answered his own door.\nThe bag was always on the veranda rail by one o''clock, tied shut, tag filled out in the same small handwriting, payment folded inside an envelope clipped to the outside strap. Sometimes a househelp appeared at the window to confirm the exchange. Mostly there was no one. Just the bag, the envelope, and the sound of a television on somewhere deeper in the house. Izunna would collect, sign the receipt, slide his copy under the door, and leave. The whole exchange lasted under two minutes.\nHe valued it more than he used to.\nHe did not examine that thought too closely. He moved on.\nEngr. Fashola worked at Civil Defence, which meant his pickup days were dictated by shift rotations rather than a fixed schedule. He texted ahead, always. That Tuesday he was standing just inside the Civil Defence compound gate in full uniform, bag already over his shoulder, finishing a call on his other phone. He held up one finger when he saw Izunna. Izunna waited. The call ended, the bag exchanged hands, the payment came from a chest pocket, counted out correctly and without a production made of it. Fashola nodded and went back through the compound entrance.\nTwo stops. Clean. Forward.\nMiss Adaora was on PH Road in a rented room in a block of flats that always had laundry drying on the external rails of every floor. She was twenty-four and serving her NYSC year in Owerri. She had found him through a church WhatsApp group and had been a client since September. She paid on time, tipped during festive periods, and treated him like a person with a schedule worth respecting.\nShe met him at the bottom of the stairwell with her bag already in hand.\n"I''m almost convinced I packed too many whites," she said.\n"Whites are never a problem."\n"That''s what my mother said about my wardrobe choices." She handed over the bag. "Are you eating? You look thin."\n"I''m the same size I was last week."\n"That''s not what I asked."\nHe almost smiled at that. "I''m eating."\n"Good. How is WAEC preparation going?"\nHe told her the truth, which he rarely did when people asked: Chemistry was holding, but Further Maths was a wall he kept running into from the same direction. She had studied science, he remembered from an earlier visit, and she said she still had her WAEC notebooks boxed up somewhere. She offered to leave them at the bottom of the stairs on Thursday if he wanted to look through them.\nHe said yes. He meant it.\nHe was three streets away, heading toward the main road, when the afternoon''s easy rhythm began to pull apart.\nIt was nothing visible. The street was ordinary, a row of shops with their awnings down against the sun, a woman selling groundnuts from a tray, two boys on a bench outside a phone repair stand arguing about something small. Nothing on PH Road had anything to do with MCC Road.\nThe memory surfaced anyway.\nHer moving through the room as though he were not standing there, or as though his standing there were inconsequential. The wrapper gone. The drawer opened, searched, and closed without anything found in it. The way she had said I can''t find the second part in the tone of someone reporting ordinary news.\nHe had done everything correctly. He had kept his eyes on the wall. He had collected the bag and left. He had been Very professional according to the five stars she had given him later.\nBut he had not decided any of it. That was the thing pressing at him now, on a street that had nothing to do with her. He had not chosen to stand in that room while she moved through it. He had not agreed to it. He had simply arrived for a professional transaction and the terms of the room had changed without his consent, and then he had been graded on how well he managed something he had not asked to be put through.\nHe stopped at the junction and waited for a break in the traffic.\nThe tally came the way it always did when he let the memory run long enough to pull at something older. A thread, and then what the thread was attached to.\nThere had been the woman in the compound when he was in JSS2, a relative of someone three houses down, who had sat beside him on a low stool during a naming ceremony and placed his hand somewhere and said things he had not understood at the time but had understood later, much later, alone at night in the way that understanding sometimes arrives when you are not asking for it.\nThere had been the woman in SS1, a client from his first month, who had come to the door in a way that he now recognized as deliberate, who had said things that his fifteen-year-old self had filed away under something strange happened today because he had not had a better category.\nThere had been smaller things between those. Looks that held too long. Comments shaped like compliments that landed differently. The two words he heard more than once, from more than one direction, when he stepped back or went quiet or did not respond the way they wanted: Are you not a man?\nHe crossed the road.\nHe had never said any of it aloud to anyone. Not his mother. Not Dayo. Not even to himself, in his own head, in the direct plain language that the things deserved.\nAt the bus stop, while he waited for a keke going toward their compound, he took out his phone. He opened the voice memo application. He held the phone up. The record button sat there, red circle, ready.\nHe stood with his thumb near it for a long time.\nThen he closed the application and put the phone back in his pocket. The phone buzzed immediately in his palm. A new message, from the MCC Road number, and the preview line sat on his screen in the keke''s half-light before he could decide whether he was ready to read it.','\n',char(10)),1055,0,1,NULL,'2026-04-28 13:06:15','2026-03-16 04:04:44','2026-04-28 13:06:15',NULL,1,NULL);
INSERT INTO "chapters" ("id","novel_id","chapter_number","title","content","word_count","is_premium","is_published","audio_url","published_at","created_at","updated_at","scheduled_release_at","part_number","season_id") VALUES(128,1,4,'Are You Not a Man?',replace('She opened the gate herself this time, which was the first thing different about that Tuesday.\nThe gateman had always been the one to let him in. Mrs. Dike at the gate, in a short housedress that stopped at the upper thigh, barefoot on the interlocking tiles, meant the gateman was either elsewhere in the compound or had been sent elsewhere. Izunna registered that detail the way he had learned to register things that were slightly off from the established pattern of a client visit. He noted it. He kept his face even.\n"You''re early," she said.\n"Two minutes, Ma. I can wait outside if the bag isn''t ready."\n"Come in." She turned and walked back toward the house ahead of him.\nHe followed at a distance that kept the transaction professional. The compound looked different from this angle in the afternoon, the shade cover on the car casting a long shadow across the tiles, the flower beds on the right side showing new growth since last week. He kept his eyes on things at ground level and moved steadily.\nInside, the curtains in the sitting room were open today. Light came through fully, reaching the far wall and the lower shelves of the bookcase. He could see the room properly for the first time: the ceiling had ornate plaster cornicing that someone had painted over in the same cream as the walls, a detail that would have been worth keeping. Two framed pieces on the right wall that he had not noticed in the dimness of the first visit. Abstract shapes in terracotta and ochre, the kind of work sold at hotel lobbies and upscale gift shops.\nHe stood where he had stood the first time, near the entrance.\n"The bag is upstairs," she said. "I''ll bring it down."\nHe nodded and waited.\nShe went up the staircase to his left. Her footsteps crossed the ceiling above him. He heard a wardrobe. Then nothing for a while. Then the footsteps returning.\nShe came down with the bag in one hand, the other hand trailing the rail loosely. She had not changed. The bag was half the weight of the first one. She set it on the centre table and stood behind it.\n"I''ve been thinking," she said, "that I should upgrade to weekly. Tuesday and Saturday both."\n"I can check the Saturday schedule and confirm by tomorrow."\n"Come closer. I want to show you something in the bag before I tie it."\nHe crossed to the centre table. She opened the top of the bag and pointed to a fabric folded at the top, a blouse with a faint pattern of beading around the collar. "This one needs hand wash only. Not machine. Can you do that?"\n"Yes, Ma. I''ll mark it separately."\n"Good." She did not step back. The table was between them but the table was narrow, and she was standing close enough to the edge that stepping back was either behind him or sideways. He moved to the right and lifted his notebook.\n"I''ll note that now. Any other items that need special handling?"\n"You''re very careful," she said. "Always so careful." Her voice had shifted register, the efficient tone from the door replaced with something slower.\n"It''s what the job needs."\n"The job." She tilted her head. "Is that really all you think about when you''re here?"\nHe looked at the bag. "If I can just confirm the count, Ma, I''ll get out of your time."\nShe came around the edge of the table.\nHe stepped back once, a full step, until the settee was behind his knees.\n"You don''t have to be so stiff," she said. She said it the way a teacher corrects a student''s posture, almost helpful in tone, as though she were doing him a service.\n"Ma, I''m here for the pickup."\nShe took one more step. The distance between them was now less than the width of a notebook page and she was not moving with the randomness of someone simply crossing a room. Her eyes were steady and certain and she was watching his face the way someone watches a door they expect to open.\nHe moved left, around the end of the settee, putting its full length between them.\nSomething shifted in her expression. It was not embarrassment. It was closer to displeasure, the particular displeasure of someone whose plan has been interrupted by a variable they had not considered.\n"Are you not a man?" she said.\nThe words were not loud. They were almost conversational. But they landed with the weight of something that had been held ready.\nHe looked at her once, directly, for the first time since entering the house. Then he picked the bag up from the centre table, entered the count in his notebook without stopping to double-check it, and walked to the front door.\nShe did not follow.\nHe let himself out, crossed the compound without hurrying, and nodded once at the gateman who had returned to the gate. He did not look back at the house.\nOn the keke going toward Wetheral Road, he held the bag between his feet and pressed both hands flat against his thighs.\nThey were not steady.\nHe pressed harder, as though pressure could solve for it. The keke moved through an intersection. A woman on the roadside balanced a tray of sachet water on her head and called out to a passing car. The Owerri afternoon continued doing what it did, the same market sounds and generator hum and okada horns, entirely indifferent to what had just happened inside a quiet compound on MCC Road.\nAt the compound gate he paid the fare and stood with his notebook open on the page where he logged client addresses. He found her row. Mrs. Ngozi Dike. MCC Road. He drew a clean line through it, pressed the pen hard enough that it indented the page beneath.\nHe told himself it was fine. He had handled it. He had walked out. That was the right thing.\nThe keke driver pulled away without asking anything.\nIzunna opened his notebook to her page. Mrs. Ngozi Dike. MCC Road. He put the pen to it and drew the line through her name slowly, pressing harder than the action required, until the ink grooved the page beneath.\nHe stared at what he had done.\nThe line was clean and the name was still completely readable underneath it.','\n',char(10)),1075,1,1,NULL,'2026-04-30 08:24:46','2026-03-16 04:05:59','2026-04-30 08:24:46',NULL,1,NULL);
INSERT INTO "chapters" ("id","novel_id","chapter_number","title","content","word_count","is_premium","is_published","audio_url","published_at","created_at","updated_at","scheduled_release_at","part_number","season_id") VALUES(129,1,5,' The Offer',replace('Mrs. Amina Okafor had never once made him wait.\nIn eight months of Tuesday pickups, she had been at her door before he reached the veranda steps every single time. Bag ready, payment counted, a question about his studies offered the way some adults offered it, not as performance but as genuine interest. She had given him a five hundred naira tip at Christmas without ceremony, folding it into his hand while saying she hoped the new year would be lighter. He had used it to buy three past question booklets for WAEC. He had not told her that, but he had thought about it during the exam preparations whenever he opened them.\nShe was one of four clients he had acquired through her husband''s referral, which was why Chief Biodun Okafor occupied a line in his notebook under a column headed Contact Source and a saved name in his phone that read: World Bank — Referral.\nHe pressed the bell at twelve fifty-eight.\nThe World Bank estate was the kind of neighbourhood where generators came on automatically when NEPA went, where the streets had speed bumps installed by the residents themselves rather than the council, and where the security at the main gate recorded your name and the number of whoever you were visiting before they would raise the barrier. He had noticed on his first visit that the houses here were set further back from the road than in Orji or Works Layout, each behind its own fence and vegetation, the kind of spacing that made neighbourhoods quiet in ways that had nothing to do with the time of day.\nMrs. Amina''s house had a garden strip running along the fence line on the inside, recently edged. The interlocking was an older pattern, slightly raised at the corners where the ground had shifted with the rains, which gave the compound a settled feeling, as though it had been here long enough to earn some imperfection.\nShe came to the door.\nFor a moment the visit looked exactly like every other one. She was dressed well, a silk blouse with matching trousers, hair set, the kind of put-together that was clearly habitual rather than prepared. She had the bag in one hand.\nThen she did not hand it over.\n"Come and sit for a moment," she said, and stepped back from the door.\nHe had sat in Mrs. Chidinma''s home. Eating on a veranda was different from being invited to sit inside. He stood at the entrance.\n"I have two more stops before the afternoon, Ma. I don''t want to keep you."\n"It''s just a minute." She set the bag down on the table inside the entrance hallway and turned to face him with the composed expression of a woman who was used to conversations going the direction she intended. "I want to talk to you about something."\nHe stayed in the doorway. His notebook was in his hand. He kept it there.\n"I''ve been watching how you work," she said. "Eight months, and you haven''t made one mistake. Never mixed up a bag, never damaged a fabric, always on time." She paused. "You are a smart boy."\n"Thank you, Ma."\n"But smart boys shouldn''t be carrying other people''s laundry in the Owerri sun." She said it without cruelty, the way someone states a fact they feel has been overlooked long enough. "This work will not take you where you''re meant to go."\nHe did not respond to that. He had learned in two years of running a business that silence, when applied correctly, was not the same as agreement.\n"I have connections," she continued. "My husband''s company, my own contacts. A boy like you, presentable, reliable, I can place you somewhere before you even finish school. Something with a future in it." She let the sentence sit for a moment. Then: "Come and be my boy. Let me change your life."\nThe room was quiet.\nOutside, somewhere on the street, a car reversed out of a compound and its horn sounded once.\nIzunna looked at a point just past her left shoulder, the wall where a family portrait hung in a broad wooden frame. Chief Okafor was seated in the centre of the portrait in a dark agbada. Two children on either side of him. Mrs. Amina standing, hand resting on her husband''s shoulder, wearing the same composed expression she was wearing now.\n"I''m grateful, Ma," Izunna said. His voice was the voice he used when clients tried to negotiate his rate downward, pleasant and immovable in equal measure. "My focus right now is WAEC. After that, I''ll be looking at my options properly."\n"I''m one of your options," she said. "A good one."\n"I hear you, Ma." He picked up her bag from the hallway table and entered it in his notebook. "I''ll have everything back by Friday. The beaded blouse and the linen — hand wash only, I have it noted from last week."\nShe watched him write. The composed expression had not moved. He could not tell whether she was satisfied with his answer or simply storing it for later. Either possibility was equally careful.\nHe thanked her, confirmed Friday''s delivery, and left.\nAt the estate gate the security officer crossed his name off the visitor register without looking up. The barrier rose. The street outside was ordinary with afternoon noise.\nHe walked to the junction and found a keke. In the back seat he opened his phone to update his log and the contact list was still on the screen from when he had dialled her to confirm the pickup that morning.\nMrs. Amina Okafor World Bank.\nHe scrolled two names down.\nWorld Bank Referral.\nChief Okafor. Both of them in the same list, four lines apart, carrying the same address in different directions.\nHe sat with the phone in his hand as the keke moved into traffic and did not put it away for a long time.','\n',char(10)),994,1,1,NULL,'2026-04-22 09:22:51','2026-03-16 04:06:53','2026-04-22 09:22:51',NULL,1,NULL);
INSERT INTO "chapters" ("id","novel_id","chapter_number","title","content","word_count","is_premium","is_published","audio_url","published_at","created_at","updated_at","scheduled_release_at","part_number","season_id") VALUES(130,1,6,'Orji Evening',replace('By the time he reached Mrs. Chidinma''s compound, his bag was empty and his feet had made the decision to rest before the rest of him agreed to it.\nIt had been a long day in the specific way that long days in Owerri accumulated weight, not from any single thing but from the compound effect of heat and distance and the particular effort of being professional across seven different stops with seven different people. Dr. Onyeka''s veranda. The Oguta Road delivery that had added forty minutes to his route because the address turned out to be a floor deeper in a building than the client had described. A redelivery in Works Layout because the first attempt had met a locked gate and an unanswered bell. By the time he turned into Mrs. Chidinma''s street the afternoon had gone orange at the edges and the generators in the neighbourhood were starting up one after another in the familiar early evening sequence.\nShe was in the yard when he arrived, talking to a woman over the low fence that separated her compound from the next. She saw him at the gate and broke off mid-sentence.\n"You look like someone who has been walking since morning," she said.\n"Close to it, Ma."\n"Come." She was already moving toward the kitchen entrance. "Sit down first. The bag is on the parlour chair."\nHe knew better than to argue. He collected the bag, noted it in his notebook, and sat on the low bench she kept on the covered back veranda. The bench was old, its wood gone smooth from years of use, with a crack along the left leg that had been stabilised with a loop of wire. He had sat on it three times before. There was something about its particular solidity that he always noticed.\nShe came out with a covered enamel plate and a cup of water. Egwusi soup and garri, the soup thick with uziza leaf and stockfish.\n"I made extra," she said, in the tone that did not invite discussion.\nHe ate. The food was the kind of food that required full attention, not because it was difficult but because it deserved it. Mrs. Chidinma sat in the cane chair across from him and asked about WAEC the way she always did when he visited, not with the anxiety that some adults brought to the subject but with the straightforward curiosity of someone who genuinely wanted to know the shape of a person''s days.\nHe told her about Further Maths. The specific problem was a coordinate geometry section that kept reversing itself in his understanding the moment he moved from one approach to another. She listened without interrupting. When he finished she said her own son had failed Further Maths twice before passing it on the third attempt and was now an engineer in Port Harcourt.\n"The subject doesn''t care how many times you try," she said. "It only cares that you understand it before the day."\nHe thought about that. It was a useful way to hold the thing.\nShe asked about his mother. He said she was well, busy with the market. She nodded and said his mother was a strong woman, had always been. She said it plainly, without performance, the way people said things they had held as true for a long time.\nFor the duration of the bench, the plate, and the conversation, the weight that had been settling on him since MCC Road lifted enough that he could breathe at the full depth of his lungs.\nHe thanked her, confirmed the return delivery for Friday, and left through the compound gate as the evening settled properly into the streets.\nThe way home from Orji took him past the edge of a street he had grown up walking. The road had been resurfaced at some point in the last two years, which made it unfamiliar for a moment until the buildings on either side reassembled into recognisable shapes. The provisions shop on the corner that had changed hands twice. The concrete block wall of the primary school with the faded painting of children holding hands, a mural that had been there since before he started attending.\nHe was not planning to think about anything. He was planning to walk home.\nThe memory did not ask permission.\nIt arrived the way it always arrived when he came near this part of Orji: as a physical thing first, a sensation of smallness, the specific smallness of being eight years old in a space controlled entirely by someone older. Then the rest of it assembled around that centre.\nShe was not a madam. She was not a client. She was someone who belonged to the fabric of those years, a relative of a neighbour, a woman who had been a regular presence in the compound during the long school holiday of his primary five year. She had treated him with a particular warmth that he had understood at eight as affection and understood now, at seventeen, with a different vocabulary entirely.\nHe had been alone with her in a room. He had been told things, and moved, and told that this was what care looked like between people who trusted each other. He had been eight years old. He had not had the language then, and the language he had now, standing on a resurfaced road in Orji in the early evening, was still not adequate for what it needed to describe.\nHe had never said it aloud. Not to his mother. Not to Dayo. Not even in the voice note he had nearly recorded and then closed three days ago. The thing lived in the part of him that did not have a door, only walls.\nHe walked the rest of the way home without stopping.\nAt the compound he sat on the front step and took out his phone. He called his mother. She picked up on the third ring, her voice carrying the particular warmth it carried when she heard it was him.\n"Izunna. Are you home?"\n"Just reached the compound."\n"Did you eat?"\n"Mrs. Chidinma fed me."\n"Good woman." A pause. The sound of the market behind her voice, beginning to wind down. "How was the day?"\nHe looked at the darkening street. A child somewhere in the compound was being called in for the night by a voice that carried through the wall.\n"Fine," he said. "It was fine."\nShe said she would be home by eight. She said to check if his brother had done his homework.\n"Izunna." Her voice shifted register, the way it did when she was saying something outside the practical list. "You sound like someone carrying something."\nHe looked at the primary school wall across the street. The painted children holding hands.\n"I''m okay, Ma," he said.\nShe was quiet for a moment in the way that meant she did not fully believe him and had decided not to push. Then she said goodnight.\nHe stayed on the front step after the call ended, in the dark, with all the words he had not said sitting exactly where they had always sat.','\n',char(10)),1196,1,1,NULL,'2026-04-30 08:25:42','2026-03-16 04:07:55','2026-04-30 08:25:42',NULL,1,NULL);
INSERT INTO "chapters" ("id","novel_id","chapter_number","title","content","word_count","is_premium","is_published","audio_url","published_at","created_at","updated_at","scheduled_release_at","part_number","season_id") VALUES(131,1,7,'The Accusation',replace('\nThe call came on a Thursday evening while he was doing Further Maths.\nHe had the past question booklet open to the coordinate geometry section, the one that had been reversing itself in his understanding for two weeks, and he had finally found an entry point into it through a method his physics teacher had mentioned offhandedly during a lesson on vectors. He was twenty minutes into the clearest session he had managed all term, three problems solved in sequence without backtracking, when the phone lit up on the desk beside his notebook.\nThe saved name read: World Bank — Referral.\nHe looked at it for one full ring cycle. Chief Biodun Okafor had never called him directly. Bookings came through Mrs. Amina''s number. Confirmations, schedule changes, payment queries, everything ran through her line. In eight months, the husband''s contact had been saved in his phone the way some contacts were saved, as a record rather than an expectation.\nHe picked up.\n"Hello?"\n"Izunna." The voice was deep and even, the voice of a man who had spent years in rooms where tone carried authority without requiring volume. "This is Chief Okafor. Am I disturbing you?"\n"No, sir. Good evening, sir."\n"Good evening, my son." A pause, brief and deliberate. "I want to speak to you about something. I need you to hear me clearly because I want to be fair to you."\nThe Further Maths page was still open in front of him. The problem he had been working on sat half finished, the arc of its logic interrupted. He closed the booklet without marking his page.\n"I''m listening, sir."\n"My wife has a gold wristwatch. A gift, from our tenth anniversary. She has had it for six years and she knows where she keeps it the way she knows her own name." Another pause. "It is not where she keeps it."\nThe room in Izunna''s chest went very still.\n"She has looked everywhere," Chief Okafor continued. "She last saw it, she is certain of this, on the morning of your last pickup. On the table beside the hallway. The same table where she set your bag down while she went to confirm the count."\nIzunna''s eyes moved without direction around his room. The desk. The window louvers with one blade sitting crooked since the harmattan winds. The school bag hung on the nail behind the door. None of it gave him anything useful.\n"Sir," he said. His voice was steady, which surprised him. "I didn''t take anything from your house."\n"I am not accusing you, my son." The voice remained level, and the levelness of it was somehow harder to hold against than anger would have been. Anger had edges you could orient yourself around. This voice was a smooth surface with nothing to grip. "I want to be very clear about that. I am not saying you took it. I am saying the timing is there, and I am a man who believes in settling things directly and privately rather than allowing things to grow into something worse for everyone."\n"I understand, sir."\n"Good." A sound in the background, a door somewhere in the house, and then quiet again. "My wife is not a careless woman. She does not misplace things of that kind. So I need us to talk properly, face to face, not over a phone line."\nIzunna said nothing. In the training he had given himself over two years of running a business, silence was a tool. Right now it was the only one available.\n"Is there anything you want to tell me now?" Chief Okafor asked. "Before tomorrow. If there is something to say, this is the moment to say it, my son, and I will hear you fairly."\nThere were things to say. There was a hallway table and a bag set down and a woman who had positioned herself in a room in a particular way on a previous Tuesday with a particular intention that her husband''s steady voice was not accounting for. There was a history in that house that had a shape to it, and the shape had not been made by Izunna.\nBut the phone was not a room. A phone call was not evidence. And the word of a seventeen year old laundry boy against the word of a woman in a World Bank estate house carried a weight distribution that he understood without needing to be told.\n"I didn''t take anything from your house, sir," he said again. "I have never taken anything from any client''s home."\nA silence on the line. Longer this time.\n"Come to the house tomorrow," Chief Okafor said. "We will talk properly."\nThe line went quiet.\nIzunna sat at his desk for a moment with the phone face down in front of him. Then he stood up and his legs took him to the space between the desk and the bed and he sat down on the floor there, back against the bed frame, knees up, phone still in his hand.\nThe Further Maths booklet was on the desk above him, closed on the page he had not marked.\nHe had been twenty minutes into the clearest session he had managed all term.\nHe sat on the floor of his room and did not move for a long time.','\n',char(10)),888,1,1,NULL,'2026-04-22 09:24:46','2026-03-16 04:08:45','2026-04-22 09:24:46',NULL,1,NULL);
INSERT INTO "chapters" ("id","novel_id","chapter_number","title","content","word_count","is_premium","is_published","audio_url","published_at","created_at","updated_at","scheduled_release_at","part_number","season_id") VALUES(132,1,8,' No Evidence',replace('He had rehearsed it on the keke, not a speech but a sequence. The facts in the order they happened, clean and direct, without anything that could be read as defensive.\nThe pickup date. The time he arrived. The hallway table. The bag Mrs. Amina had placed on it herself. The count he had completed while standing at the entrance. The front door he had walked out of without entering anywhere else in the house.\nHe had the facts. He had the sequence. He arrived at the World Bank estate gate at ten in the morning and gave his name to the security officer, who found it on a list rather than asking him to sign in fresh. Chief Okafor had added him to an expected visitors record. That detail settled something cold in his chest before he was through the barrier.\nThe compound looked the same. Of course it did. The garden strip, the edged flower beds, the older interlocking tiles with their settled imperfection. He noticed today that one section near the compound wall had been patched with a newer tile that did not quite match in colour, a small rectangle of brighter orange sitting among the weathered terracotta. Someone had tried to repair it seamlessly and had not fully succeeded.\nMrs. Amina answered the door.\nShe was composed in the way she had always been composed, silk and posture, nothing out of place. She looked at him the way a person looks at a matter they have already resolved internally and are now processing for the record.\n"Come in," she said.\nChief Okafor was in the sitting room. He was a large man with a full face and the kind of stillness that came from decades of being the most important person in most rooms he entered. He sat in the far chair, the one that faced the door directly, and gestured toward the settee without standing.\n"Sit down, my son."\nIzunna sat. Mrs. Amina took the chair beside her husband. The three of them formed a shape in the room and Izunna understood, looking at that shape, what kind of meeting this had always been going to be.\nChief Okafor opened with the same measured tone from the phone call. He said he appreciated Izunna coming. He said again that he wanted to be fair. Then he turned to his wife and said, simply, "Tell him what you told me."\nMrs. Amina told him.\nShe spoke without hesitation and without performance. The watch had been on the hallway table since Sunday. She was certain because she had worn it to a church programme and returned it to that exact spot when she changed after. She had not touched it again until Wednesday, two days after the Tuesday pickup, and found it gone. In the intervening time, she said, looking directly at Izunna with the steady gaze of someone recounting only what was true, just two people had been inside the house. The househelp, who had worked for them for eleven years and whose character she would not question. And the laundry boy.\nShe said the laundry boy without unkindness, which was almost worse than if she had said it with unkindness. It was simply the category he occupied in the room.\nIzunna waited until she finished.\n"The bag was on the hallway table," he said. "You put it there yourself. I collected it from where it was and I left. I didn''t go anywhere else in the house."\n"The front room is part of the house," she said. Not accusatory. Just precise.\n"I didn''t take the watch."\n"I didn''t say you did," she said, and her voice was so level that anyone listening would believe her entirely.\nChief Okafor looked at him with the expression of a man genuinely trying to be just in a situation his wife had already settled before he arrived in it. "Is there anything else, my son? Any way you can help me understand this?"\nThere was. There was a Tuesday three weeks before this one when Mrs. Amina had stood in this same sitting room in a way that had nothing to do with a missing watch and everything to do with the particular power a grown woman held over a teenage boy who depended on her account for part of his family''s income. There was a hallway table that had been used as an excuse to position him inside the room. There was a version of events preceding this one that gave this one its shape and its timing.\nHe looked at Chief Okafor''s face and understood that version was not sayable in this room. Not without evidence. Not with only his word against hers. The watch was not here. His word was the only thing he had brought into this house, and it was already lighter than hers before he had opened his mouth.\n"I didn''t take it," he said again.\nChief Okafor nodded slowly. He said he hoped the matter would resolve itself. He said he would be in touch if anything changed. He stood, which closed the conversation, and extended his hand. Izunna shook it because there was nothing else available to do.\nMrs. Amina walked him to the door. At the threshold she said, "I''ll have my sister collect the laundry going forward. It''s more convenient." Her voice was pleasant and entirely final.\nHe walked out.\nThe security officer at the gate crossed his name off the list with a single stroke.\nBy two in the afternoon, two cancellation messages had arrived from Works Layout numbers, both polite, both using the phrase other arrangements. By four, a third client from the same circle sent a message asking him to pause the arrangement until further notice. The reach of one phone call across an estate moved faster than he had understood it could.\nHe sat at the kitchen table that evening unable to account for how he had gotten from the keke stop to the chair. The table had a long scratch along its left edge from a repair job he and Dayo had attempted two years ago with the wrong tool. The overhead bulb had a flicker it had been developing for weeks that no one had gotten around to fixing. His delivery book sat on the table in front of him and he did not open it.\nAdaeze came out of the back room. She was fourteen and read rooms the way some people read text, quickly and without announcing what she had found. She went to the stove. She served a plate. She carried it to the table and set it in front of him with the spoon placed beside it carefully, then turned and went back to the room without asking a single question.\nHe sat in front of the food and did not eat.','\n',char(10)),1143,1,1,NULL,'2026-04-22 09:25:43','2026-03-16 04:09:36','2026-04-22 09:25:43',NULL,1,NULL);
INSERT INTO "chapters" ("id","novel_id","chapter_number","title","content","word_count","is_premium","is_published","audio_url","published_at","created_at","updated_at","scheduled_release_at","part_number","season_id") VALUES(133,1,9,'Zara',replace('He needed a new notebook.\nThe delivery book he had been using since the start of the second term had four pages left, which was not enough to carry him through the next three weeks of pickups and returns. He had tried to ration the pages by reducing his margin width and compressing the client columns but the result was entries he could not read back accurately, which defeated the purpose of keeping them. He needed a new notebook, and he had taken the MCC Road route deliberately this time, because he had decided two days ago that he was not going to start walking different streets because of what had happened on one of them. The road belonged to his route and his route was his livelihood and she did not get to take the road from him as well.\nThe stationery shop on the street just off MCC Road was one he had passed many times without entering. It occupied the ground floor of a two storey building whose upper level appeared to be a residential flat, with a window that had its curtains drawn in a way that suggested no one had opened them in some time. The shop''s exterior was a pale blue that had faded unevenly, darker in the corners where the sun did not reach and almost white across the middle section of the wall. A handwritten sign above the doorway listed the categories of stock inside in capital letters, each category underlined twice.\nHe went in.\nThe interior was narrow and better stocked than the exterior suggested. Shelves ran along both walls from floor to ceiling, organised in a system that required familiarity to navigate. Notebooks on the left, mid-shelf. Above them, examination stationery in sealed packets. Below, loose leaf paper in stacks sorted by line spacing. The right wall held art supplies, office materials, and a section at the back that appeared to be religious stationery, cards and bookmarks with printed text in English and Igbo.\nA girl was standing at the notebook section when he came in.\nShe was reading the back cover of a spiral bound notebook the way people read the backs of paperback novels, with the genuine evaluative concentration of someone who intended to use what they purchased. She was in a school uniform with the tie loosened, which meant she was either on her way home or had stopped here during a free period. Her school bag was on the floor beside her feet and she had stacked two items on the shelf edge beside her, a packet of drawing pens and a correction fluid, while she continued examining the notebook.\nHe moved to the section and looked for his usual brand. The shop carried it one shelf below where she was standing.\nHe checked the page count on two versions and chose the one with the ruled lines spaced at the width he used for client entries.\n"That one has thinner pages," she said.\nHe looked up.\nShe was not looking at him. She was still examining her own notebook. "The other version. The pages bleed through if you press at all."\nHe looked at the notebook in his hand and then at the alternative version beside it. The alternative had a slightly heavier cover and a different binding.\n"I use a ballpoint," he said.\n"Still bleeds." She turned the page of her own notebook and examined the paper''s texture with her thumb. "I learned by ruining two before I switched."\nHe put the lighter one back and took the heavier version. The price difference was twenty naira. He could work with twenty naira.\nShe brought her selections to the counter and paid while he was still deciding whether to add a second notebook to his purchase. He decided yes and brought both to the counter after her.\nOutside, the street had the specific mid-morning activity of a road that served both residential and light commercial purposes. A woman was arranging tomatoes on a table in front of the building next to the shop. A generator repair stand on the opposite side of the road had two machines open on its work surface. A man in an office shirt was walking with the direction of someone who knew exactly where he was going and had no interest in the route itself.\nAnd a boy, maybe fifteen, maybe sixteen, in a secondary school uniform, was walking in the opposite direction along the same side of the road when a woman leaning out of a first floor window above a provision store said something down to him in the particular register that was not a greeting.\nThe boy looked up. He laughed. The laugh was the kind that arrived on a face before the face had decided to put it there, a reflex, a social instrument for filling a space where any other response felt unavailable. He shook his head and kept walking.\nThe look on his face as he turned away from the window was something Izunna knew the exact weight of.\n"You saw that," said a voice beside him.\nHe turned. The girl from the stationery shop was standing two steps to his right, her bag repositioned on her shoulder, watching the boy continue down the road.\n"Yes," Izunna said.\n"He''s been laughing off that window for two weeks," she said. "I''ve seen it." She looked at Izunna with the direct attention of someone who noticed things and had decided to be honest about what they noticed. "You didn''t look like it was funny."\n"It wasn''t."\nShe held his gaze for a moment, measuring something. Not unkindly. The way a person looks when they are deciding whether the next sentence is worth saying.\n"There''s a drop-in space near Works Layout," she said. "Youth programme. Thursday evenings, six to eight." She was already opening the small front pocket of her bag. "They talk about things. Real things. It''s not a counselling session, it''s just a room where people actually listen." She found a small notepad and wrote quickly, tore the page, held it out. "Mr. Adeniyi runs it. He''s good people."\nHe took the paper. An address. A phone number. The name she had said written in clear capital letters below both.\nShe picked up her drawing pens package from where she had shifted it under her arm, adjusted her bag strap, and walked in the direction of the main road without adding anything else to it.\nHe looked at the paper. The address was three streets from the Works Layout junction, which he passed every Tuesday. The handwriting was even and had been written with the kind of ballpoint that did not bleed through.\nHe folded the paper in half. Then in half again. He put it in his pocket.\nHe did not throw it away.','\n',char(10)),1140,1,1,NULL,'2026-04-30 08:32:18','2026-03-16 04:10:29','2026-04-30 08:32:18',NULL,1,NULL);
INSERT INTO "chapters" ("id","novel_id","chapter_number","title","content","word_count","is_premium","is_published","audio_url","published_at","created_at","updated_at","scheduled_release_at","part_number","season_id") VALUES(134,1,10,'The Drop-In',replace('\nHe stood outside the address for four minutes before going in.\nThe building was set back from the Works Layout road behind a short concrete fence that had been painted light green at some point and was now mostly the colour of concrete again with a memory of green in the sheltered corners. A hand-painted sign had been mounted beside the entrance gate: LIVING WELL YOUTH SPACE. Below the name, in smaller letters, the operating hours and a phone number. The sign had been painted with care, the letters even and properly spaced, the kind of sign made by someone who wanted the place to be taken seriously.\nThrough the gate he could see the entrance of the building itself, a converted bungalow with a wide front room visible through a screen door that had been propped open with a concrete block. The lights inside were on, which meant people were already there. The sound coming out was the sound of a room settling into itself, low voices, a chair moving, the particular atmospheric noise of a gathering that has not yet formally started.\nHe went in.\nThe front room had been arranged with plastic chairs in a rough oval, not a perfect shape, more the shape you get when people set chairs without instruction and then adjust until it felt right. Twelve chairs. Seven of them occupied. A ceiling fan turned at medium speed above the centre of the oval, pushing the warm air without doing much to cool it but creating the small mercy of movement. On the wall to the right, someone had mounted a corkboard with papers pinned to it, notes and printed pages and two hand-drawn posters, one of which read YOUR STORY IS NOT STRANGE and one that had been partially covered by a newer notice about the following week''s session.\nA man was stacking extra chairs against the far wall. He turned when Izunna entered.\n"Welcome." He was perhaps mid-thirties, compact in build, wearing a plain ankara shirt tucked into dark trousers. His face had the kind of settled patience that was not performed ease but actual ease, the kind that came from running the same room for long enough to stop needing anything from it except what it was. "Find a seat. We start in five minutes."\nThis was Mr. Adeniyi.\nIzunna chose a chair that was not directly across from the door and not in the section of the oval that faced the corkboard, a position that felt like middle distance, present but not centred. The boy to his left was around his age and was examining his own phone screen with the absorbed focus of someone who was actually quite aware of the room and using the phone as a way to manage that awareness. The two boys on the far side of the oval were talking quietly, one of them with a notebook open on his knee. A girl in a blue hijab sat with her arms folded and her eyes on the door with the expression of someone who had decided before arriving that this had better be worth the commute.\nMr. Adeniyi pulled a chair into the oval and sat.\n"We''ll start with whatever is present," he said. His voice had the same quality as his face, unhurried. "Nobody has to speak. If you''re here and listening, that is enough for tonight."\nIt was not a counselling session in the way Izunna had been half expecting, the kind he had seen depicted in films, where a facilitator with a clipboard moved through a checklist of feelings. Mr. Adeniyi asked one opening question and then let the room decide what to do with it.\nThe question was: what does it cost to stay quiet about something?\nTwo people spoke in the first thirty minutes. A girl described being dismissed every time she raised a complaint at home, the way her family had developed a collective habit of receiving her concerns and setting them aside the way you set aside a plate you intend to return to but never do. A boy talked about a situation at school involving a senior student, careful with his details, his eyes on his own hands. Mr. Adeniyi listened to both of them with the same quality of attention, the kind that did not rush toward reassurance or solution but stayed in the room with what was being said for long enough to honour its weight.\nHe did not once ask: are you sure?\nHe did not say: but did you consider.\nHe said: that sounds like it required a lot of you. And then he let the room be quiet for a moment before it moved again.\nIzunna said nothing. He sat and listened and felt the particular strangeness of being in a room where the things being said were being received without the air immediately reshaping itself into something more comfortable.\nThen the boy spoke.\nHe was on the far side of the oval, slight in frame, wearing a school uniform that still had the collar button fastened even at six in the evening. He was perhaps fifteen, perhaps younger. He had said nothing for the first forty minutes. When he began speaking he did so without raising his hand or signalling in any way, just began at a pause in the room''s rhythm, his voice quiet and direct.\nHe said there was a woman in his compound. He said she was older, a relative of one of the tenants. He described what she had done in the language of someone who had chosen each word individually, carefully, the way you carry something fragile, not because the words were hard to find but because he was making sure each one landed where he meant it to.\nThe room did not laugh.\nIzunna watched the faces across the oval. The girl in the blue hijab had uncrossed her arms. The boy with the notebook was not writing. The boy who had been on his phone had put it face down on his knee and was looking at the speaker with the honest attention of someone who recognised something.\nMr. Adeniyi waited until the boy had reached the end of what he had brought with him that evening. Then he said: "Thank you for trusting this room with that."\nNothing more than that. No unpacking. No procedures. Just the acknowledgment that what had been said had been heard, and that the hearing was not conditional.\nIzunna walked home the long way.\nPast PH Road, where the streetlights were working on the left side of the road and dark on the right, and the food sellers at the junction were beginning to pack up their tables. Through the edge of Orji, past the primary school wall with its faded mural, past Mrs. Chidinma''s street without turning into it. The long route added twenty minutes and he did not mind. He needed the Owerri night to move around him for a while.\nHe was not lighter. He was not resolved. But he kept walking the long route home, and somewhere past the Orji junction he took out his phone and opened the voice memo application for the third time since the tally had begun.\nThis time he did not close it.\nHe held it at his side, the red circle recording the sound of his footsteps on the road, and said nothing, and did not stop walking.','\n',char(10)),1242,1,1,NULL,'2026-04-30 08:27:49','2026-03-16 04:11:17','2026-04-30 08:27:49',NULL,1,NULL);
INSERT INTO "chapters" ("id","novel_id","chapter_number","title","content","word_count","is_premium","is_published","audio_url","published_at","created_at","updated_at","scheduled_release_at","part_number","season_id") VALUES(135,1,11,'Counting Out Loud',replace('He texted her on a Wednesday morning, which was the first decision he had made in two weeks that did not come from the delivery book.\nThe number was on the folded paper she had given him outside the stationery shop. He had transferred it to his contacts under the name Zara Works Layout, which was how he organised new contacts until he knew them well enough for the entry to carry just a name. He wrote the text three times before sending it. The first version was too long. The second asked too specific a question before earning the right to ask it. The third said: I came to the drop-in last Thursday. I think I need to talk to someone before I go back. Are you free this week?\nShe replied in eleven minutes. Saturday morning. A suya spot near the Owerri Club road she knew. Ten o''clock.\nThe suya spot was a permanent structure rather than a roadside setup, a low zinc-roofed building with a concrete forecourt and four plastic tables arranged under a stretch of shade netting that had been patched in three places with a different coloured netting, the repairs creating an uneven grid of shadow on the ground below. At ten in the morning it was between its purposes, too late for the previous night''s business and too early for the afternoon crowd. The man inside was restocking the spice rack on the rear wall. Two chairs at the far table were occupied by an older man reading a newspaper with the pages folded back to a quarter of their width. The smoke from the suya stand at the back of the building moved sideways in the light wind and vanished before it reached the shade netting.\nZara was already there when he arrived, sitting with a bottle of Fanta and a notebook open in front of her. She was writing when he came in, finished the sentence she was on, and looked up.\n"You came to the drop-in," she said.\n"Yes."\n"Good." She said it plainly, without making a production of it. She closed the notebook and pushed it aside. "Sit down. Tell me what happened."\nHe had thought on the keke ride over about how to begin. He had decided on the same approach he used when he needed to explain a delivery complication to a client: the facts, the sequence, no interpretation offered before the information had been fully given.\nHe told her about Mrs. Dike first. The compound on MCC Road. The first visit and what the room became on the second. Stepping back until the settee was behind his knees. The words she had said when he did not respond the way she expected. He told it without reaching for language that would soften it or sharpen it. He kept it at the level of what happened and in what order.\nZara listened without interrupting. She did not shift her weight or change her expression in the way people sometimes did when they were hearing something uncomfortable, the small adjustments that told a speaker their information was becoming a problem for the listener. She stayed still and present in a way that was itself a kind of answer.\nHe told her about Mrs. Amina. The offer. The two contacts on the same phone screen. The Thursday phone call from Chief Okafor and the measured voice that was worse than anger because it had no edges. The sitting room the following morning, the three chairs arranged in a shape that had already reached its conclusion before he opened his mouth. The way Mrs. Amina had said the laundry boy without cruelty, simply as a category.\nThe four cancellations.\nThe kitchen table.\nWhen he finished there was a pause the length of a breath.\n"I believe you," Zara said.\nShe said it without hesitating. Without the qualifier that turned belief into a negotiation, the I''m sure it felt that way or the I''m not saying you''re lying but. Three words placed down like something solid and without condition.\nHe looked at the table surface. The plastic was a faded red with a manufacturer''s logo embossed near the edge, worn down to the point where only the outline of the letters remained. He traced the edge of the logo with his thumb without meaning to.\n"Thank you," he said.\n"You should tell Mr. Adeniyi," she said. "Not the full thing if you don''t want. But enough. He''s seen this before. He''ll know what to do with it."\nHe went to the drop-in that Thursday and stayed after the session ended, when the chairs were being stacked and the other attendees had filtered out through the screen door in twos and threes into the Works Layout evening. Mr. Adeniyi was unpinning an outdated notice from the corkboard when Izunna told him he had something to say.\nThey sat in two of the remaining chairs and Izunna gave Mr. Adeniyi the shape of it. Not every detail. The outline. The pattern across the months. The accusation and what it cost. The childhood memory he did not name directly but indicated with enough honesty that Mr. Adeniyi received it correctly.\nMr. Adeniyi listened the same way he listened during sessions: fully, without directing the account toward a conclusion he had already prepared. When Izunna finished, he asked two questions. Neither of them was are you sure. One was about safety. One was about who else in his life knew any part of this.\nThe answer to the second question was now: one person.\nMr. Adeniyi told him about a documentation process, informal but useful, a way of recording incidents with dates and details in the event that any future situation required a record. He told him the drop-in space was available outside session hours if he needed to talk further. He said what he had carried for this long had not made him weak. He said it had made him precise.\nIzunna walked to the bus stop on Works Layout road and stood under the yellow light of a functioning streetlamp, one of the three on that stretch that had not been dark for the past month.\nZara''s three words were still in his chest where they had landed on Saturday morning.\nNo one had ever said that to him about this. Not one person, in all the years the weight had been accumulating, had placed those three words down in that order without condition or hesitation.\nHe stood under the streetlamp and could not determine whether what was moving through him was the beginning of freedom or the particular terror of a silence that had held things in place for so long that ending it felt like removing a wall.\nHe was not sure the two feelings were different.','\n',char(10)),1135,1,1,NULL,'2026-04-22 13:14:01','2026-03-16 04:12:26','2026-04-22 13:14:01',NULL,1,NULL);
INSERT INTO "chapters" ("id","novel_id","chapter_number","title","content","word_count","is_premium","is_published","audio_url","published_at","created_at","updated_at","scheduled_release_at","part_number","season_id") VALUES(136,1,12,' Dayo''s Reaction',replace('Dayo had known him since primary four, which meant he had known him before the business, before their fathers'' various disappearances from the picture, before either of them had developed the particular armour that adolescence required in Owerri or anywhere else.\nThis was the reason Izunna had chosen him. Not because it would be easy, but because if the telling could not survive Dayo, it could not survive anything, and he needed to know that before he decided what came next.\nThey met on a Sunday afternoon at the concrete table behind the community library on Akachi Road, a spot they had used since JSS1 when it served as their base for the kind of long unstructured conversations that young boys have when the afternoon is too hot for movement and there is nothing specific required of them. The library itself was closed on Sundays, which meant the compound was empty except for a watchman who stayed inside the entrance kiosk and had never in six years asked them to leave. A neem tree on the left side of the compound dropped shade across the table from about two in the afternoon onward. The shade was useful. The privacy was the point.\nDayo arrived eight minutes late, which was early by his standard, wearing a faded red polo and carrying a sachet of water he had clearly just bought from the kiosk at the road entrance. He sat across from Izunna, bit the corner off the sachet, and said, "You sounded strange in the text."\n"I have something to tell you."\n"Okay." Dayo drank and set the sachet down. He gave Izunna the particular kind of attention that old friendship produced, not formal listening but the relaxed receptivity of someone who had heard this person say many things over many years and was ready for the next one.\nIzunna told him.\nHe used the same structure he had used with Zara and Mr. Adeniyi: the facts, the sequence, the MCC Road visits first, then Mrs. Amina, then the accusation. He kept his voice at the level of someone reporting rather than appealing. He had decided before arriving that he would not perform distress and would not perform composure either. He would simply say what had happened and let Dayo decide what to do with it.\nHe was three sentences into the MCC Road account when Dayo laughed.\nIt was not a cruel laugh. It was the laugh that arrived before thought, the reflex that certain words produced in certain people when the sentence they were hearing did not match the category their mind had prepared for it. A grown woman. A boy. A room. The laughter came from the gap between those things and what Dayo''s understanding said was possible.\nIzunna stopped talking.\nThe laugh lasted perhaps two seconds. Then Dayo looked at Izunna''s face.\nHe saw whatever was on it and the laugh went out the way a generator goes out when it runs dry, not gradually but all at once, the silence that followed almost louder than the sound had been.\n"Wait," Dayo said. "Wait, I''m not, I wasn''t laughing at you."\n"I know what kind of laugh it was."\n"I''m sorry." He said it quickly, which meant he had not fully arrived at what he was apologising for yet. The apology was genuine but it was the apology for the laugh, the social reflex, not for the understanding that had produced it. "Keep going. Tell me the rest."\nIzunna told him the rest. Dayo did not laugh again. He sat with his elbows on the concrete table and his brow pulled together, listening with the concentration of someone genuinely trying to place what they were hearing into a framework that could hold it.\nWhen Izunna finished, Dayo was quiet for a moment.\n"That accusation thing," he said. "With the watch. That was wrong. That was genuinely wrong, and I''m angry about that."\n"I know."\n"She set you up." He said it with the clean certainty of someone who could recognise injustice in the form most familiar to him. "Used you and then covered herself. That''s a bad person."\n"Yes."\n"And you lost four clients."\n"Yes."\nDayo picked up the empty sachet and folded it between his fingers, a habit he had when thinking, folding and unfolding the same piece of material until whatever he needed to say had assembled itself. "But the other thing," he said. "The women. The MCC Road woman. Mrs. Amina and the offer." He paused. "I don''t know, Izunna. That one I''m finding it hard to see the same way."\nIzunna looked at him.\n"I''m not saying you''re lying," Dayo said quickly. "I''m not saying that. But a woman making an offer, walking around her own house, that''s not the same thing. That''s her house."\n"She was my client. I was there to work."\n"I hear you. But men deal with worse every day and we just move. It''s not the same thing as what happens to women. It can''t be."\nHe said it without raising his voice. He said it the way someone stated a law of physics, not with cruelty, just with the settled certainty of a belief that had never been seriously examined because it had never needed to be.\n"Women can''t harass men," Dayo said. "That''s just not how it goes."\nThe neem tree above them shifted in a brief wind, its shadow moving across the concrete table and back. Somewhere on the Akachi Road side of the fence a bus horn sounded and faded.\nIzunna stood and picked up his delivery book from the table.\n"I''ll see you at school," he said.\nHe walked out of the compound and turned toward home, carrying the weight of Dayo''s certainty alongside the other things he had been carrying. What settled on him during that walk was not anger. It was something closer to a precise and exhausted understanding. Dayo was not a bad person. Dayo had laughed the reflex laugh and then stopped and then listened for the full duration and then said the wrong thing not with malice but with the fluency of someone repeating what the world had taught him so consistently that it no longer felt like a lesson. It felt like truth.\nThat was the problem that was larger than Dayo. That was the problem that had a face in every compound and every classroom and every keke conversation in every city in this country, wearing the expression of reasonable certainty, not knowing, not needing to know, how many people it was wrong about.','\n',char(10)),1098,1,1,NULL,'2026-04-22 13:15:27','2026-03-16 04:13:11','2026-04-22 13:15:27',NULL,1,NULL);
INSERT INTO "chapters" ("id","novel_id","chapter_number","title","content","word_count","is_premium","is_published","audio_url","published_at","created_at","updated_at","scheduled_release_at","part_number","season_id") VALUES(137,1,13,'The Article',replace('Zara sent the message on a Tuesday evening with the directness that had become her established mode of communication.\nA blogger I know is collecting anonymous testimonies. Men who have experienced sexual harassment. No names, no identifying details. Just the account, plainly written. She''s putting together something that matters. I thought of you. Only if you want.\nBelow the text, a contact name and a submission email address.\nHe read it twice, put his phone face down on the desk, and went to check on his brother''s homework. His brother was in JSS1 and was having the specific difficulty with English comprehension that came from treating the questions as obstacles rather than as guides toward meaning already present in the passage. Izunna sat with him for twenty minutes and walked him through two questions without giving the answers, the way their mother did when she had the time. By the time he returned to his room the compound outside his window had gone through its evening transition, the children''s voices replaced by the lower register of adult conversation from the flat across the yard and the sound of a television through a wall that did not fully contain it.\nHe picked up his phone. He reread the message.\nThen he opened the email application and typed the submission address into the recipient field and sat looking at the blank body of the email for a long time.\nThe room was warm. The reading lamp on his desk threw a circle of yellow light that reached the edge of the desk and dropped off into the darker rest of the room. On the wall beside the desk, a calendar from the previous year that he had kept because the back of it was blank and useful for working out calculations, had developed a slight curl at the bottom corner from the humidity of the rainy months. He had been meaning to retape it for weeks. In the yellow circle of the lamp, the curl threw a small shadow shaped like a question mark against the wall.\nHe began to type.\nHe did not start with the beginning. He started with the thing that was most solid in his body and worked outward from there. The room on MCC Road. The wrapper that was not there on the second visit when it had been there on the first. The way the space had been arranged so that stepping back placed furniture behind his knees. The words that had been said when he declined to respond the way she expected. He wrote it in plain sentences, the kind with one subject and one action and enough detail to be real without enough detail to identify anyone. He named nothing. He described everything.\nThen Mrs. Amina. The offer and its structure, the performance of concern for his future wrapped around something that was not concern. He wrote that the offer had been made in a house where the husband''s photograph was visible from the chair he had been directed to sit in. He did not explain why that detail mattered. He trusted the writing to carry it.\nHe wrote about the accusation and what it cost. Four clients. A name moved through an estate phone network before he had the chance to defend it. He wrote: There was no evidence I could point to. There was also no evidence she was required to provide. That asymmetry is the whole story.\nHe stopped there and read back what he had written. The screen light was the only other light in the room beside the lamp. It was past ten. His mother had gone to bed an hour ago. The compound outside was quiet except for the television through the wall, which had moved from whatever it had been showing to the familiar pattern of a night news programme.\nHe had not written about the childhood memory. He had opened a space near the end of the account, a single paragraph that said: this was not the beginning. The beginning was earlier and had a different face and I am not ready to write that part yet. But it belongs to the same story. He read that paragraph three times and left it in.\nHe wrote a final section about the silence and what it had required of him, the specific ongoing labor of managing other people''s comfort with information they were not prepared to receive. He wrote: I am not writing this because I want sympathy. I am writing this because the boy who laughed it off on a street in Owerri last week has this same story, and so does the one two streets from him, and so does the one who never becomes the delivery boy because what happened to him in a room when he was eight years old made him stop trusting rooms.\nHe read the full account from the beginning. He changed four sentences. He left the rest.\nHe typed a covering note to the blogger, three sentences, and sent the email before the part of him that had been negotiating against it could organise a sufficient argument.\nThen he sat in the lamp circle and listened to the television through the wall.\nThe article went live on Thursday. Zara sent the link at noon during school break. He opened it at the gate of the school compound, standing with his back to the fence, and found his account third in a collection of seven testimonies under a header that read: They Were Never Asked If They Were Okay.\nHis words were there in the plain sequence he had written them, anonymous, real, solid in a way they had not been inside his chest where they had lived for years without edges or weight, only the formless pressure of things that had never been said.\nThe comments loaded below the article. He scrolled without intending to stop.\nThis is every delivery boy''s story.\nTwo lines below it:\nMen will say anything.\nHe read both. He held them at equal distance and let them sit where they were, one recognising him and one refusing to, both of them now existing in the same world as the account he had written, which was also now existing in that world, permanent and plain and no longer only his to carry alone.\nHe read both comments one more time.\nThen he scrolled back up to the top of the article, past the other testimonies, to the line where his account began. It was there, in clean plain text, exactly as he had written it. And below where the account ended, in the place the submission form had asked for a name, the word the blogger had typed on his behalf:\nAnonymous.\nHe looked at that word for a long time.\nThen he closed the tab and picked up his delivery book.','\n',char(10)),1147,1,1,NULL,'2026-04-30 08:28:48','2026-03-16 04:13:58','2026-04-30 08:28:48',NULL,1,NULL);
INSERT INTO "chapters" ("id","novel_id","chapter_number","title","content","word_count","is_premium","is_published","audio_url","published_at","created_at","updated_at","scheduled_release_at","part_number","season_id") VALUES(138,1,14,' Mrs. Amina Calls',replace('He was at the tailor''s on Douglas Road when the call came.\nThe tailor, Mr. Emeka, occupied a narrow shop wedged between a phone accessories store and a provision outlet in a block of commercial units that had been built in phases over several decades, each section slightly different in height and facing from the one beside it, giving the whole block the appearance of something assembled from memory rather than a plan. Mr. Emeka had been repairing a zipper on one of Dr. Onyeka''s suit jackets, a task that had come in as an add-on to the standard laundry order, and Izunna had taken it on because the extra charge was reasonable and the tailor charged him a discounted rate in exchange for the steady referral of clients who needed small repairs alongside their cleaning.\nHe was waiting for the jacket, sitting on the low bench beside the door with his delivery book open, updating the week''s completed entries, when his phone buzzed against the bench wood with the particular vibration of a call rather than a message.\nHe looked at the screen.\nMrs. Amina Okafor — World Bank.\nThe shop around him continued at its own pace. Mr. Emeka''s sewing machine ran in its rhythmic cycle at the back of the narrow space. Outside, a woman''s voice from the provision store next door called a price to someone on the street. A motorcycle passed close to the block''s entrance and its engine note changed as it moved away.\nHe picked up.\n"Izunna." Her voice was exactly as he remembered it. Level, composed, carrying the particular warmth she applied to his name the way you applied a setting on a machine, reliably and without variation. "How are you, my dear?"\n"Good afternoon, Ma."\n"I''m calling with good news." A small pause, shaped like the pause before good news rather than the pause before anything requiring effort. "The watch. We found it."\nHe said nothing.\n"It was in my wardrobe the whole time. In the inner pocket of a travel bag I hadn''t opened since our anniversary trip. I feel so foolish." She produced a small laugh, the kind that acknowledged a minor domestic comedy, the keys you searched the whole house for before finding them in your own hand. "I wanted to call you personally and let you know."\nHe was looking at the far wall of the tailor''s shop. A length of ankara fabric in deep blue and copper was pinned across the upper section of the wall as a display piece, its pattern a repeating sequence of interlocked geometric shapes that resolved into a different shape depending on how much of it you looked at at once. Below it, on a shelf, a collection of thread spools in thirty different colours had been arranged not by colour family but by some other logic he could not immediately decode.\n"Thank you for letting me know, Ma," he said.\n"Of course." Another small pause. "I hope there are no hard feelings. These things happen, you know how it is."\nThese things happen.\nHe held the phrase at arm''s length in his mind and looked at it carefully. These things. A watch mislaid in a travel bag. A boy''s name moved through an estate network before she had confirmed a single fact. Four clients cancelled in one afternoon. Two weeks of a rebuilt schedule. The sitting room where Chief Okafor''s photograph had watched from the wall while her version of events occupied all the available air. A seventeen year old who had stood in a hallway with nothing to point to and nowhere to put his hands.\nThese things.\n"No hard feelings, Ma," he said.\n"Good boy." The warmth in her voice was complete and genuine and applied the same way it had always been applied, with the ease of someone who had never been required to examine the cost of their ease. "I''ll have Chief speak to the estate contacts. I''m sure we can sort out the account situation."\nHe noted that sort out the account situation was doing the work of twelve other sentences she had decided not to say. He noted it and said nothing.\n"I''ll let you get on with your day," she said. "You''re a good, hardworking boy, Izunna. I''ve always said so."\n"Thank you, Ma."\n"Take care of yourself."\nThe line went quiet.\nMr. Emeka appeared from the back of the shop with the jacket over one arm, the zipper repair complete and invisible at the seam. He held it up for inspection with the satisfaction of someone who had done a thing properly. Izunna stood and checked the zipper, confirmed the stitching, folded the jacket with the care its fabric required, and paid the repair fee. He thanked Mr. Emeka. He put the jacket into his delivery bag with the tissue paper layer between it and the other garments.\nOutside on Douglas Road the afternoon was at full volume. The provision store woman was still calling prices. A queue had formed at the POS stand two units down from the tailor''s, four people in it, patient with the specific patience of people who had factored the wait into their afternoon. Across the road a schoolboy was arguing with a bus conductor over change with the confidence of someone who knew exactly what he was owed.\nIzunna opened his delivery book to the client page.\nMrs. Amina Okafor. World Bank. The address beneath it in his regular ballpoint, the entry neat and unmodified since the month he had first added her to his route.\nHe took his pen and drew a clean line through it. He pressed firmly, the way he had pressed through Mrs. Dike''s entry on the MCC Road page, and this time he did not tell himself it was fine. He did not tell himself anything. He simply drew the line and closed the book.\nHe did not cry. There was nothing available in him shaped like tears for this particular thing. What was there instead was something more precise, a clear-edged understanding of the distance between what she had cost him and what her call had asked him to absorb without accounting.\nHe stood on Douglas Road with the delivery bag on his shoulder and took out his phone. He opened a blank document. Not the anonymous submission form, not the voice memo application he had closed twice. A blank document, white and empty, with the cursor sitting in the upper left corner waiting.\nHe began to type his name.','\n',char(10)),1090,1,1,NULL,'2026-04-22 13:17:32','2026-03-16 04:14:52','2026-04-22 13:17:32',NULL,1,NULL);
INSERT INTO "chapters" ("id","novel_id","chapter_number","title","content","word_count","is_premium","is_published","audio_url","published_at","created_at","updated_at","scheduled_release_at","part_number","season_id") VALUES(139,1,15,'The Laundry Boy Speaks',replace('He finished writing it on a Friday night after his mother had gone to bed.\nIt had taken eleven days from the blank document on Douglas Road to the version now open on his phone screen. Not because he had struggled to find the words, but because he had wanted each word to be the right one. Not dramatic. Not angled toward sympathy or anger or the performance of either. He had read it back each night before sleeping and removed every sentence that was doing something other than telling the truth plainly, and what remained when he could not remove anything further without removing truth itself was four paragraphs and his full name at the top.\nIzunna Obiora. Owerri. Seventeen.\nHe read it one final time.\nHe wrote about being a laundry boy who moved through the homes of strangers with the professional neutrality the job required, and about discovering that professional neutrality was not a protection, only a posture. He wrote about the specific geometry of being in a room where someone had rearranged the terms of the transaction without asking. He wrote about the words that had been said to him when he declined to participate, and about the understanding those words carried, that his reluctance was the anomaly requiring explanation rather than the behaviour that had produced it. He wrote about an accusation and a sitting room and a watch found in a travel bag on the day it was no longer useful to keep it missing.\nHe wrote one paragraph about being eight years old and understanding something now that he had not had the language for then. He kept it short. It was enough.\nThe final paragraph was not a conclusion. It was a question directed outward, at no one specific and therefore at everyone. He asked how many boys were currently managing something they had filed under strange thing that happened because no available category had been wide enough to hold it correctly. He asked what it cost a person to carry a thing without a name for the full length of their growing up. He asked what it might cost less if someone had simply, at the right moment, said: I believe you.\nHe posted it to his personal page at eleven forty-three on a Friday night and put the phone face down on his desk.\nHe did not sleep easily but he slept.\nBy Saturday morning it had been shared nineteen times. By Saturday afternoon, forty-one. Three clients sent cancellation messages before noon, brief and without explanation, the kind of messages that communicated everything through what they did not say. He entered the cancellations in his book without ceremony. He had known some would come. He had written the post knowing some would come.\nAt two in the afternoon his phone buzzed with a WhatsApp message from a number saved as Chief Biodun Afolabi GRA.\nHe opened it.\nBrave boy. I''m keeping your number.\nHe read it twice, put the phone down, and stood at the window of his room for a moment looking at the compound yard where his younger brother was kicking a deflated ball against the fence with the patient persistence of someone who had not yet accepted that the ball needed air. The afternoon light came across the yard at the low angle that meant the day was past its midpoint, throwing the shadow of the mango tree in the yard''s corner long across the ground.\nHis phone rang at four. Mrs. Chidinma.\nHe picked up.\nShe said nothing for a moment after he greeted her. Not the silence of someone who had not yet arrived at their words, but the silence of someone holding something carefully before they set it down.\nThen: "I''m proud of you."\nShe said it the way she said things she had decided were simply true. No preamble. No performance. The same register she used when she said his mother was a strong woman, the register of long-held facts.\nHe thanked her. She told him his whites would always be the whitest in Orji and ended the call.\nAdaeze found him in the evening at the kitchen table, where he was reviewing the week''s delivery schedule and making adjustments for the lost accounts. She sat across from him with her school reading in front of her and he thought she had come simply to share the table, the way she sometimes did, until she put her hand flat on the page she had been reading and looked at him directly.\n"I read it," she said.\nHe looked up.\n"I didn''t know, Izunna." Her voice was fourteen years old and also much older than that, the way the voices of girls who grew up watching their mothers hold things together sometimes were. "I''m sorry."\nTwo words from Zara. Two words from his sister. The same words doing different work, arriving from different directions, landing in the same place inside him with the weight of things that had been true the whole time and were only now being said.\n"It''s okay," he said.\n"It''s not," she said. "But I''m here."\nThat was enough for now.\nHe was up at five thirty the next morning. The parlor floor held the first six bags of the Tuesday route, tagged and arranged in zone order, the notebook open beside them. His mother had already left for the market. The compound was in its early quiet.\nHe checked the route. He confirmed the counts. He tagged the last two bags with the clean labels he had printed from the business center on Wetheral Road, the ones with the Laundry Boy logo Zara had helped him sketch on a page of her notebook three weeks ago, a simple design, a shirt on a line with the sun behind it.\nHe loaded the delivery bag.\nHe stepped out into the Owerri morning, where the street was doing what it always did at this hour: the first generators starting up, a woman somewhere nearby beginning a song she did not finish, the light coming in low and amber over the rooftops from the direction of the east.\nHe walked. Not lighter exactly, but straighter. Like a boy who had decided his story belonged to him.','\n',char(10)),1044,1,1,NULL,'2026-04-22 20:07:27','2026-03-16 04:15:44','2026-04-22 20:07:27',NULL,1,NULL);
INSERT INTO "chapters" ("id","novel_id","chapter_number","title","content","word_count","is_premium","is_published","audio_url","published_at","created_at","updated_at","scheduled_release_at","part_number","season_id") VALUES(141,16,1,'New Linen',replace('\nThe room smelled like someone else''s money fabric softener and the faint sweetness of body lotion that came in glass bottles, not plastic sachets. Adaeze stood in the doorway with her Ghana-must-go bag and understood, without anyone saying a word, that she was late to something that had already started without her.\n\nThe school had sent a letter in July. Queen''s Hallmark College for Girls, Enugu. Dorm assignment: Hibiscus House, Room 7. Three occupants. Adaeze had read it four times at the kitchen table while her mother stood behind her, one hand pressed flat against the wall, breathing carefully the way she did when she was trying not to cry from happiness.\nThat was July. This was September, and the letter had not prepared her for any of this.\nThe two beds closest to the window were already made. Not just made arranged. One had a peach duvet printed with small gold flowers, and a matching pillow that had no business being in a school dorm. The other had a grey fitted sheet so smooth it looked ironed, with a small stuffed bear sitting against the headboard as if it had been placed there by someone who knew exactly what they were doing. Both bedside tables had things on them: a water bottle, a reading lamp, a book face down.\nThe third bed, against the back wall, had the school-issued linens still folded on the bare mattress. White. Thin. Waiting.\nAdaeze walked to it and set her bag down.\nShe had known, before she arrived, that she would not have what these girls had. She had spent three weeks trying to prepare for that knowledge the way you prepare for cold water you tell yourself it will be cold, you brace your body, and you step in anyway. But knowing and standing inside it were different things, and for exactly four seconds she let herself feel the difference.\nThen she began to make her bed.\nShe was tucking in the second corner when the door opened and two girls came in together, mid-sentence, carrying ice cream from the school tuck shop. They stopped when they saw her.\nThe taller one, fine-boned with relaxed hair pulled into a low pony, looked at Adaeze the way people look at a painting they aren''t sure they understand. Not unkind. Just assessing.\nThe other one, shorter, with natural hair twisted up and a friendship bracelet on each wrist, recovered first. "Oh! You''re here. I''m Amara." She pointed at the taller girl. "That''s Chisom. We were wondering when the third person would come."\n"Adaeze," she said.\n"Adaeze," Chisom repeated, as if testing the name. "Which state?"\n"Anambra."\n"Same as me." Something in Chisom''s face eased slightly. "Good. Amara is Rivers. I was afraid I''d be outnumbered."\nAmara rolled her eyes with the ease of someone who had done it ten thousand times. "As if Enugu is your territory." She turned to Adaeze. "Don''t mind her. She thinks being Igbo makes her royalty."\n"I am royalty," Chisom said pleasantly, settling onto her bed. "My grandfather has a title and everything."\nAdaeze almost smiled. She finished tucking in her sheet and sat on the edge of the mattress. The springs gave a small complaint beneath her.\nShe watched Amara open a small cooler box a personal cooler box, the kind with a USB cable and drop her ice cream inside. Chisom was already lying back against her pillows, scrolling her phone with one thumb. The room arranged itself around them like it already knew their shapes.\nAdaeze''s bag held: three sets of school uniforms, two plain blouses, one church dress, a container of Vaseline, a bar of Geisha soap, her textbooks all second-hand, all covered in brown paper a small torch in case of night reading, and an envelope from her mother with three thousand naira inside that was supposed to last her the whole first term.\nShe did not unpack yet. She sat with her hands in her lap and looked at the window. Outside, the school compound was the kind of green that came from money trimmed hedges, a sprinkler running in the late afternoon heat, a paved path that curved toward the assembly hall. Girls in the same uniform she was wearing moved in pairs and clusters, easy and loud with each other.\n"Is this your first time at a boarding school?" Amara asked. She was not being unkind either. She had the manner of someone who was simply curious about most things.\n"Yes," Adaeze said.\n"It''s not as bad as people say. The food is terrible on Tuesdays and the water goes off every Thursday morning without fail. Other than that, fine."\n"The seniors in our block are harmless," Chisom added without looking up. "SS2 girls mostly. One SS3 who thinks she runs everything but doesn''t. Just agree with whatever she says and she''ll leave you alone."\nThey were being helpful, she realised. In the matter-of-fact way of girls who had no reason to be threatened by her, who were simply covering the basics. Adaeze accepted the information with a nod and stored it carefully.\nThat night, after lights-out, she lay on her thin school mattress and listened to Chisom and Amara talk in the dark the way people talk when they''ve already decided they trust each other. Quiet voices. A story about a cousin''s wedding. Amara''s laugh, which was bigger than you expected from someone her size.\nAdaeze stared at the ceiling.\nShe was the smartest girl in her set. She had the test scores to prove it, the teachers'' comments in every report card going back to JSS1. She was here on a scholarship that fifty-three girls had competed for and she had won, and she intended to remain here. She would sit in every class and take every note and earn every mark. She would not be sent home. She would not give anyone a reason.\nShe just had to figure out how to do all of that while being in a room with two girls whose duvets probably cost more than her school fees.\nAt some point, Amara''s voice trailed off mid-sentence. Then there was the soft, steady sound of sleep from both sides of the room.\nAdaeze turned onto her side and faced the wall.\nTomorrow she would find the ironing room.\n\nShe didn''t know yet what she would do when they found out not about the scholarship, everyone would know that soon enough but about the other things. The things you didn''t say out loud in a room that smelled like glass bottle lotion and someone else''s certainty. She pulled the thin school blanket to her chin, and in the dark of Hibiscus House, Room 7, told herself what she always told herself before sleep. You are here. That is enough. You are here.\nShe almost believed it.','\n',char(10)),1141,0,1,NULL,'2026-04-01 08:03:31','2026-04-01 07:58:39','2026-04-01 08:03:31',NULL,1,3);
INSERT INTO "chapters" ("id","novel_id","chapter_number","title","content","word_count","is_premium","is_published","audio_url","published_at","created_at","updated_at","scheduled_release_at","part_number","season_id") VALUES(142,16,2,'Night Snacks',replace('The first thing Adaeze learned about 10 p.m. in Hibiscus House was that the dark did not mean everyone was sleeping. The second thing she learned was that hunger had a sound, and it was the crinkle of a chin chin bag being opened very, very carefully.\n\nIt started on the third night.\nAdaeze had been lying still for twenty minutes, watching the ceiling and calculating. She did this before sleep sometimes, running numbers the way other people counted sheep. How many weeks left in the term. How much was in the envelope. Whether three thousand naira could stretch to cover the one textbook she still needed for chemistry if she skipped buying writing pads and asked to borrow Amara''s instead.\nShe was on the second calculation when she heard it.\nThe soft unzipping of Chisom''s locker. The precise, unhurried rustle of someone who had done this enough times to know exactly how much noise was acceptable. Then the familiar scent of fried dough and sugar drifted across the room, and Adaeze''s stomach responded before her mind could tell it not to.\nShe kept her eyes on the ceiling. She kept her breathing even.\n"I know you''re awake," Amara said from across the room. Not to Adaeze. To Chisom.\n"I know you want some," Chisom replied.\nThe rustle of Amara climbing out of bed. The small creak of the mattress springs. Then the sound of two people eating in the dark with the comfortable ease of a routine already formed in only three days.\nAdaeze''s stomach made a sound she was almost certain they could hear.\nShe turned over and faced the wall.\nShe had eaten dinner. The school food was heavy and starchy and the portions were not small. She was not starving. She told herself this with the quiet firmness she used for most things and focused on the wall in front of her, which was pale yellow in the daytime and grey now, and had a small scuff mark near the baseboard that looked like it had been made by the corner of a box.\n"Adaeze." Amara''s voice was low, easy. "We know you''re not asleep."\nShe considered pretending anyway. It would have been simpler.\n"I''m resting," she said.\nChisom made a sound that might have been a laugh. "Come and rest over here then. Amara''s mother sent puff puff from a woman in Port Harcourt who apparently is the only person in Nigeria who knows what she''s doing."\n"The only one," Amara confirmed, very seriously.\nAdaeze sat up.\nShe could not see their faces clearly but she could see their shapes, two girls sitting cross-legged on Chisom''s bed with a container between them. Amara was holding it out in her direction.\nShe got up and crossed the room and sat on the edge of Chisom''s mattress, close to the foot, and took one piece of puff puff. It was soft and still faintly warm from whatever charm Amara''s mother had packed it with, and it was the best thing Adaeze had eaten since the jollof rice her own mother had cooked the morning she left home.\nShe ate it in three bites and said nothing.\n"Good, yes?" Amara said.\n"Very good," Adaeze said honestly.\nChisom passed her the chin chin. It came in a clear zip bag and there was a lot of it. The good kind, not too hard, with a faint sweetness. Adaeze took a small handful.\nThey sat in the dark and ate. Outside, somewhere down the corridor, a tap was running. The night was cooler than the day had been, the kind of September cool that felt like a reward after the heat.\n"My mother sent enough for an army," Amara said. "She does this every term. She says the school food will kill me slowly."\n"She''s not wrong about the Tuesday soup," Chisom said.\n"What does your mother send?" Amara asked. It took Adaeze a second to realise the question was directed at her.\n"She doesn''t really send things," Adaeze said. She kept her voice level, conversational. "It''s not easy for her to, where we are."\nThe silence that followed was the careful kind. The kind where people are deciding how to step.\n"My father sends a package every two weeks," Chisom said, after a moment, in a tone that was lighter than the subject. "He feels guilty about the divorce so now we eat well." She said it like a fact she had already made peace with, but Adaeze stored it quietly. Chisom volunteering something real was not nothing.\nAmara laughed softly. "Mine sends things because she doesn''t trust anyone else to feed me. She asked the kitchen matron for the weekly menu and she read it over the phone to my aunt and apparently they both cried."\nAdaeze laughed at that. A real laugh, not the polite kind. Amara looked pleased.\nThey finished the chin chin in a comfortable quiet, passing the bag among the three of them until it was done. Then Chisom folded it neatly and dropped it in her locker to put in the bin tomorrow, because even at 10 p.m., Chisom was the kind of person who folded things.\nAdaeze stood to go back to her bed.\n"We do this every night," Amara said. "Ten o''clock. You don''t have to pretend anymore."\nAdaeze looked at her. In the dark, Amara''s face was open and unguarded. No agenda in it.\n"Okay," Adaeze said.\nShe went back to the third bed and lay down. The ceiling was the same. The numbers were still waiting. But something in the room had shifted in some small way, and Adaeze, who noticed everything, noticed that too.\nShe did not know if it was the beginning of something or just one warm night. She had learned not to decide too quickly about things that felt good. Good things had a way of proving you wrong.\nBut the puff puff had been real. The laugh had been real. And Amara had called her by name without being asked to.\nShe held those three things carefully in the dark and let herself fall asleep.\n\nWhat she did not know, lying there in the easy quiet of the room, was that Chisom had watched her walk back to the third bed, and had sat very still for a long moment after, thinking about something she did not say. When Amara whispered "goodnight" across the dark, Chisom whispered it back. But her eyes stayed open a little longer, fixed on the shape of Adaeze under the thin school blanket, her expression carrying something between recognition and guilt.\nThen she turned over, and closed her eyes, and whatever it was went with her into sleep.','\n',char(10)),1119,0,1,NULL,'2026-04-01T08:42:52.899Z','2026-04-01 08:42:52','2026-04-01 08:42:52',NULL,1,3);
INSERT INTO "chapters" ("id","novel_id","chapter_number","title","content","word_count","is_premium","is_published","audio_url","published_at","created_at","updated_at","scheduled_release_at","part_number","season_id") VALUES(143,16,3,'Press',replace('The iron was old. Not broken, just old, the kind that had been used long enough to carry the memory of every fabric it had ever touched. Adaeze had found it in the utility room at the end of the corridor, on a shelf between a mop bucket and a tin of Vim, and she had carried it back to the room at half past four in the morning like something precious.\nShe set up on the small table near the door, the one nobody had claimed for anything important yet. She had wet her uniform the night before, folded it damp into her locker, and now she spread the white blouse across the table''s surface and pressed the iron down with the particular care of someone who had been doing this since she was old enough to hold a handle.\nThe room was breathing. That was how she thought of it when both of them were asleep, the room breathing around her, steady and low. Chisom slept on her side with one hand tucked under her cheek. Amara slept flat on her back like someone who had been told to lie still and simply never stopped.\nAdaeze worked in silence.\nThe blouse first, collar to cuff, the iron moving in long deliberate strokes. Then the skirt, which needed the most attention at the pleats. She had a routine and she followed it without thinking, the way her fingers knew the buttons of her own school bag without needing her eyes. This was something her mother had taught her: that the things you could control deserved your full attention, because they were standing in for all the things you could not.\nShe was finishing the second pleat when Amara moved.\nNot awake yet, just shifting, the way people do when sleep is getting shallow. Adaeze kept her eyes on the skirt. A minute passed. Then she heard the soft sound of someone sitting up, the slow processing of a person returning to the world.\nShe did not look up.\nShe heard Amara''s feet find the floor. Heard her stand, pick up her water bottle, drink from it. The small sounds of early morning. Then nothing for a moment, and Adaeze knew without looking that Amara was watching her.\nShe kept pressing.\n"What time is it?" Amara''s voice was thick with sleep, not unfriendly.\n"Four fifty," Adaeze said.\nA pause. "Why?"\n"I like to be ready before the rush."\nThis was true, as far as it went. The fuller truth was that the ironing room opened at six and had a queue by six fifteen, and the junior girls always waited for the senior girls to go first, and by the time Adaeze got her turn the iron would be too hot and the cord would be loose from overuse. She had done the calculation on the first day. It was simpler to bring the iron here and be done before anyone else woke up.\nShe did not explain all of this. She never explained more than the first layer of a thing.\nAmara sat down on the edge of her bed, water bottle in both hands, watching. She did not ask anything else. Adaeze worked through the skirt, turned it over, ran the iron along the inside of the waistband.\n"You''re good at that," Amara said.\n"I''ve had practice."\n"How long have you been awake?"\n"A while."\nAmara was quiet for a moment. Then: "Do you do this every week?"\n"When I need to."\nThe room was still. Outside, the sky through the curtain was beginning to change, the particular dark blue that came just before the first grey, the colour of something about to become something else. Adaeze hung the finished skirt on the back of her chair and spread the second blouse flat.\n"Can I watch?" Amara asked. Then immediately: "That''s a strange thing to say. Forget it."\n"You''re already watching," Adaeze said.\nAmara laughed once, quietly, and settled back on her hands. There was nothing performing about her at this hour. No bracelets, no easy social confidence. Just a girl in a t-shirt and wrapper, her hair loose from its twists, sitting with the uncomplicated curiosity of someone who found the world interesting at face value.\n"My grandmother irons like that," she said after a while. "Same slow way. She says fast ironing is how you ruin good fabric."\n"She''s right," Adaeze said.\n"I''ve never ironed anything in my life." She said it without pride or embarrassment, just as information. "We have someone who does it."\nAdaeze pressed down on the collar. "I know."\nAmara looked at her. "Is that a problem?"\n"Why would it be?"\n"I don''t know. Sometimes people make it one."\nAdaeze turned the blouse and pressed the back yoke flat. "It''s not a problem," she said. "It''s just different."\nAmara nodded slowly, as if she was deciding whether to accept that answer or dig further. She decided to accept it. That was something Adaeze noticed about her: she knew when not to push. It was a more sophisticated quality than it appeared, and it did not fit easily with the image of a girl who had never needed to think about the cost of things.\nAdaeze was beginning to understand that Amara did not fit easily into anything.\nShe finished the second blouse, held it up to check the collar in the thin early light, then folded it over the chair beside the first. Her uniforms hung there looking clean and firm, the way uniforms looked when they were new, the way they would continue to look as long as she had an iron and enough time before the world woke up.\nShe unplugged the iron and wrapped the cord around the handle.\n"Adaeze," Amara said.\nShe looked up.\nAmara was looking at the uniforms, not at her, and something in her expression had gone quiet and honest in the way faces went when they were thinking something they hadn''t fully turned into words yet.\n"Nothing," Amara said. "Good morning."\n"Good morning," Adaeze said.\nShe carried the iron back to the utility room and returned to the room to find Amara already lying back down, one arm over her eyes. Chisom had not moved. The sky outside was fully grey now, on its way to light.\nAdaeze sat on the edge of the third bed and looked at her uniforms hanging on the chair. Crisp and white and ready for whatever the day required.\nShe had earned this. She earned it every week.\nShe lay down and closed her eyes, and when the bell rang forty minutes later, she was the first one dressed.','\n',char(10)),1111,0,1,NULL,'2026-04-01 08:46:08','2026-04-01 08:44:08','2026-04-01 08:46:08',NULL,1,3);
INSERT INTO "chapters" ("id","novel_id","chapter_number","title","content","word_count","is_premium","is_published","audio_url","published_at","created_at","updated_at","scheduled_release_at","part_number","season_id") VALUES(144,16,4,'The Enemy of My Enemy',replace('Her name was Ngozi Eze-Okoro and she was in SS3 and she had decided, for reasons that were never fully explained to anyone, that the corridor outside Hibiscus Room 7 was her personal property.\nShe announced this on a Thursday.\nShe did not knock. She simply opened the door the way people open doors when they have never had to consider whether they were allowed to, stepped inside, looked at all three of them in turn, and said: "Your side of the corridor is a mess. I want it clean by six o''clock or I''ll report you to the dorm mistress for a sanitation violation."\nThen she left.\nThe three of them looked at each other across the room.\n"The corridor is not messy," Amara said, after a moment.\n"I know," Chisom said.\n"There are two pairs of slippers outside the door. That''s all."\n"I know."\n"So what is she actually saying?"\nChisom lay back against her pillow with the expression of someone who had been expecting this. "She''s saying she noticed us. That''s all it is. She did the same thing to the room at the end of last term. She picks a room of junior girls and makes herself a problem for them until something more interesting comes along."\n"How long does that take?" Adaeze asked.\nChisom considered this. "Depends on how interesting you are."\n\nBy Friday, Ngozi had walked past their room four times, paused at the door twice, and on one occasion stopped to inform Amara that her water bottle left a ring on the corridor windowsill, which was unacceptable. Amara had picked up the water bottle without a word, waited until Ngozi''s footsteps had faded down the corridor, and then turned to the other two with an expression of pure disbelief.\n"The windowsill," she said.\n"She measured it," Chisom said. "I saw her look at it for thirty seconds before she spoke."\n"She was rehearsing," Adaeze said.\nBoth girls looked at her. It was the first time she had offered an opinion about Ngozi and she said it without thinking, the same way she said things in class when the answer was simply obvious.\n"Rehearsing," Amara repeated.\n"She came to say something. She needed a reason. She looked until she found one."\nAmara stared at her for a moment and then started laughing, the big laugh, the one that was too large for her frame. Chisom pressed her lips together in the way she did when she was trying not to join in and failing. Adaeze watched them both and felt something warm move through her chest that she did not immediately name.\n\nThe real problem came on Saturday morning.\nAdaeze was in the corridor filling her bucket from the tap when she heard the footsteps and knew before she turned around that it was Ngozi, and she knew from the sound of them, purposeful and unhurried, that today was going to be different from the water bottle and the slippers.\nNgozi stopped beside her and looked at the bucket.\n"Junior girls collect water between five and five forty-five," she said.\nAdaeze looked at her. "It''s five forty."\n"It''s five forty-three."\nThe tap was still running. The bucket was not yet full.\nAdaeze held Ngozi''s gaze for exactly as long as was safe, which she calculated in the space of two seconds, and then she reached down and turned off the tap. The bucket was three quarters full. She picked it up.\n"Thank you," Ngozi said, with the particular sweetness of someone who knew she had won, and walked away down the corridor.\nAdaeze carried the bucket back to the room and set it down and sat on her bed. Her jaw was tight. She breathed out through her nose slowly and opened her chemistry textbook and stared at a diagram of atomic bonding that she could not see properly because her eyes were doing something she refused to allow.\nShe was still staring at it when Chisom came back from the bathroom and took one look at her face and said: "What did she do?"\nAdaeze told her. Briefly, without drama.\nChisom''s expression did a thing Adaeze had not seen it do before. The easy surface of her face went somewhere and what was underneath came through, focused and cold and very certain.\n"Okay," she said. She did not say it loudly. She said it the way people said it when they had already decided something.\n\nWhat Chisom knew, and Adaeze and Amara did not, was that Ngozi Eze-Okoro had a rival. Her name was Tochi, also SS3, also powerful, and the two of them had been in a cold war since the beginning of the previous term over something involving a school prefect position that Tochi believed she deserved and Ngozi had received.\nWhat Chisom also knew was that Tochi''s younger sister was in JS1, new to the school, and desperate for an older friend.\n"We''re not doing anything wrong," Chisom explained, sitting cross-legged on her bed while Amara listened from her own, and Adaeze sat at the table with her chemistry textbook still open. "We''re just going to be very kind to Tochi''s sister. In front of Ngozi."\nAmara looked at her for a long moment. "That''s actually wicked."\n"It''s strategic."\n"Same thing sometimes."\n"Adaeze?" Chisom turned to her. "You don''t have to be part of it if you don''t want."\nAdaeze thought about the tap. The bucket three quarters full. The sweetness in Ngozi''s voice.\n"What''s the sister''s name?" she asked.\n\nHer name was Precious and she was twelve years old and she was homesick in the visible, total way of a child who had not yet learned to hide it. They found her sitting alone on the bench outside the dining hall on Saturday afternoon, in full uniform even though it was a free period, her hands folded in her lap.\nAmara sat down beside her first, because Amara was the kind of person who could sit beside a stranger with no gap between them and make it feel like they had always known each other.\n"You''re Tochi''s sister, yes? I''m Amara. These are my roommates."\nPrecious looked up at them with enormous uncertain eyes. "How did you know?"\n"You look like her around the forehead," Amara said, which was not entirely true but was the right thing to say.\nWhat happened next was not part of Chisom''s strategy, or at least it did not stay within it. Precious, given the opening of a few kind words, began to talk, and once she started she could not easily stop. She talked about her mother, about her school in Awka, about how the food here tasted different and the water in the shower was sometimes cold without warning, and how she had not made a single friend yet and the girls in her room were all from Lagos and seemed to already know each other. She talked the way a child talked when they had been holding everything inside because they had decided showing it would make things worse.\nAdaeze listened to all of it.\nWhen Precious finally slowed down, face slightly pink, Adaeze said: "The first two weeks are the hardest. After that you find your rhythm."\nPrecious looked at her. "Did you find yours?"\nAdaeze thought about 4:50 a.m. and a borrowed iron and a room that still smelled like other people''s things. "I''m finding it," she said honestly.\nPrecious nodded, as if that was actually more reassuring than a confident yes.\nThey stayed on that bench for forty minutes. Amara made Precious laugh three times. Chisom gave her a packet of digestive biscuits from her bag with the casual generosity of someone who always had extra. And somewhere in the middle of it, the strategy became secondary, and they were simply three girls sitting with a lonely twelve-year-old on a Saturday afternoon because it was the decent thing.\n\nNgozi walked past once.\nShe saw them. She saw Precious. Her pace did not change but her eyes moved over the scene and held for just a moment, and then she was gone down the path toward the hostel.\nOn Sunday morning there was no knock on their door. On Monday, she walked past Room 7 without pausing.\nOn Tuesday, Amara came back from the bathroom and announced: "She''s gone. I don''t know what happened but she''s done with us."\n"Tochi happened," Chisom said simply.\nAmara dropped onto her bed and looked at the ceiling. "I cannot believe that worked."\n"I can," Adaeze said, not looking up from her textbook.\nAmara threw a pillow at her. Adaeze caught it without looking up, which made Amara burst out laughing, and Chisom, who was trying very hard to maintain her composure, finally gave up and laughed too, and for a little while Room 7 was loud enough that someone knocked on the wall from next door.\nNone of them apologized.','\n',char(10)),1488,1,1,NULL,'2026-04-01 12:28:51','2026-04-01 08:45:32','2026-04-01 12:28:51',NULL,1,3);
INSERT INTO "chapters" ("id","novel_id","chapter_number","title","content","word_count","is_premium","is_published","audio_url","published_at","created_at","updated_at","scheduled_release_at","part_number","season_id") VALUES(145,16,5,'What Chisom''s Father Sends',replace('The package arrived on a Wednesday, which was two days later than it was supposed to.\nAdaeze noticed because Chisom had been checking with the dorm mistress every morning since Monday, always with the same careful casualness, the kind that was designed to look like she was asking about something unimportant. She would stop at the office door on her way to breakfast and say, "Any packages?" in a voice that implied she barely cared either way, and then come back to the room and sit at her desk and open her textbook to whatever page it fell on.\nAmara noticed too. They did not discuss it.\nOn Wednesday evening, after prep, the dorm mistress called Chisom''s name at the common room door and Chisom stood up from the table and walked out with her shoulders straight and her face composed. When she came back through the door ten minutes later, she was carrying a brown cardboard box the size of a small television, and for exactly two seconds, before she arranged her expression back into its usual order, she looked like a child.\n\nShe unpacked it on her bed.\nAdaeze was doing her reading assignment at the table. Amara was writing a letter home, the old-fashioned kind, because her mother had requested it at the beginning of term: Not text messages. Real letters. I want to hold your handwriting. Neither of them said anything, but both of them were watching in the way you watched something without turning your head.\nThe box was packed with a thoroughness that suggested someone had been paid to do it. Indomie in three flavours. A tin of Milo. Two packs of digestive biscuits. A jar of Skippy peanut butter. Chin chin in the clear bag, same brand as usual. Chocolate, the imported kind in gold foil. A fresh pack of white hair ties. Body lotion in a glass bottle, new, the same brand that already sat on Chisom''s bedside table.\nChisom arranged each item in a line on her duvet. She did this methodically, which was her way with most things. Then she reached back into the box and found an envelope at the bottom.\nShe opened it.\nAdaeze was looking at her book but she was not reading. She saw Chisom unfold the paper inside, saw her eyes move across it, saw the movement stop. It lasted only a moment. Then Chisom folded the paper back along its original creases and put it under her pillow and said, without turning around: "There''s enough here for everyone. Take what you want."\nAmara looked up from her letter. "Are you sure?"\n"I always send back what I don''t finish at the end of term," Chisom said. "Take it."\nShe stood up from the bed and went to the window and stood there with her arms folded, looking out at the dark compound.\nAmara met Adaeze''s eyes across the room. Adaeze looked back at her and said nothing, and Amara, who knew when not to push, picked up her pen and returned to her letter.\n\nAt ten o''clock, the food came out as usual. But that night it was different because it was all from the box, and Chisom was the one distributing it, handing things across with a kind of focused generosity that had an edge underneath it Adaeze could not name precisely. Like she was giving the food away because keeping it near her had become the problem.\nThey ate chocolate and sat in the dark.\n"My father has a PA now," Chisom said eventually. She said it at the ceiling. "Her name is Ifeoma. She is twenty-six."\nNeither of them responded. Adaeze pulled her blanket around her shoulders.\n"He dictated the note," Chisom continued. "I can always tell because he spells my name right but the sentences don''t sound like him. He says I hope this finds you in good health. He has never said that to me in my life. His actual voice says things like Chisom, oya, come and eat. Not I hope this finds you in good health."\nThe chocolate was very good. Adaeze ate a small square slowly and let it dissolve on her tongue.\n"Maybe Ifeoma packed the box too," Amara said. Carefully, not unkindly.\n"Definitely," Chisom said. "She got the brand of lotion right but my father would never remember to send hair ties. He doesn''t notice that kind of thing. She noticed." She paused. "Which means she''s been paying attention. To what kind of girl I am. Which means she''s been in my house going through my things."\nThe room was quiet for a moment with the weight of that.\n"Not necessarily through your things," Adaeze said. "She could have asked your father."\n"My father doesn''t know what hair ties I use."\n"He might."\n"He doesn''t." Chisom said it without bitterness, which made it worse somehow. Just a fact she had filed in the correct drawer. "He''s not that kind of father. He''s the other kind. The one who shows up very large for the big things, birthdays, graduations, anything that requires a speech, and is mostly absent for everything else. I spent thirteen years watching my mother decide whether that was enough." She stopped. "She decided it wasn''t."\nAmara was very still on her bed.\nAdaeze looked at the window. Outside, the security light made a small yellow circle on the path below, and a moth was going around and around it in the same loop.\n"My parents fight about money," Adaeze said.\nShe had not planned to say it. It came out the way things came out at ten o''clock in the dark, in the particular looseness that came from chocolate and a room that had slowly stopped feeling like a stranger''s space.\n"Not about not having it," she added. "About how to use what little there is. My father wants to expand his shop. My mother wants to save. They have had this exact argument my whole life. Different words every time, same argument."\n"Who usually wins?" Amara asked.\n"Nobody wins that argument," Adaeze said. "You just have it until you''re tired and then you go to sleep and it waits for you in the morning."\nChisom turned from the window and came back to sit on her bed. She pulled her knees to her chest and looked at the space between them all with an expression Adaeze had not seen on her before, something open and a little tired.\n"My mother cried for three days after he left," she said. "Then on the fourth day she woke up and rearranged all the furniture in the sitting room and made me egusi soup and told me we were going to be fine. And I believed her." She rested her chin on her knees. "I still believe her. I just also wish that note had sounded like my father."\nNobody said anything to that, because there was nothing to say to it that would not make it smaller.\nAfter a while Amara leaned across and put the tin of Milo in the middle of the floor between the three beds.\n"For tomorrow morning," she said. "All of us."\nChisom looked at it. Something in her face shifted, not much, just the small rearrangement of a person deciding to accept something.\n"Okay," she said.\nThey finished the last of the chocolate and went to sleep, and the Milo tin sat in the middle of the floor in the dark like a small agreement between three girls who were learning, slowly and without ceremony, how to occupy the same room.','\n',char(10)),1265,1,1,NULL,'2026-04-01 12:29:07','2026-04-01 08:47:11','2026-04-01 12:29:07',NULL,1,3);
INSERT INTO "chapters" ("id","novel_id","chapter_number","title","content","word_count","is_premium","is_published","audio_url","published_at","created_at","updated_at","scheduled_release_at","part_number","season_id") VALUES(146,16,6,'First Term Results',replace('The results went up on a Friday.\nThey were printed on a single sheet of A4 and pinned to the noticeboard outside the admin block, and by the time Adaeze got there after morning assembly the crowd around it was three girls deep. She waited. She was good at waiting. She stood at the edge of the cluster with her hands in her skirt pockets and watched the faces of the girls coming away from the board, reading them the way she read most things, looking for information before she committed to a reaction.\nWhat she saw was a mixed report. Some girls walking away satisfied. One in SS1 who turned from the board and immediately found something urgent to study in the middle distance. A group of four who had clearly all done well, squeezing each other''s arms and speaking too fast to follow.\nThe crowd thinned. Adaeze moved forward.\nShe found her name.\nShe read the number beside it. She read it again. Then she took one step back from the board and stood very still and breathed out through her nose and looked at the sky for exactly three seconds before she looked back down at the paper.\nFirst. Out of sixty-one girls. By eight marks.\nShe did not allow herself to feel it fully, not there, not in front of the noticeboard with girls still moving past her on both sides. She pressed it down into the place where she kept things that were too large for public, the same place she kept the memory of her mother''s face when the scholarship letter came, the same place she kept the morning she had sat in her father''s shop and read the acceptance letter out loud and her father had looked at the ceiling for a long time before he spoke.\nShe put it there, carefully, to be taken out later.\nThen she walked back to the hostel to find Chisom and Amara.\n\nAmara was sitting on her bed eating an orange when Adaeze came in, and she looked up and read Adaeze''s face immediately.\n"First?" she said.\nAdaeze sat down on the third bed. "First."\nAmara threw a piece of orange across the room. Adaeze caught it. "I knew," Amara said, with the satisfied air of someone whose prediction had come through. "I told Chisom last week. I said Adaeze will top this set and Chisom said she wasn''t sure, and I said I was completely sure."\n"What did Chisom say she wasn''t sure about?"\nAmara paused, the smallest pause. "Whether anyone could beat Nneka Okonkwo. She came first last term."\n"Nneka Okonkwo was second," Adaeze said.\n"By eight marks," Amara said, "yes, I can see the board from here."\nAdaeze looked at her. Amara had her phone up already and was typing, and it took Adaeze a moment to understand she was sending a message, and another moment to understand she was sending it to someone about Adaeze''s result, with the easy pride of a person reporting good news about a friend.\nIt was a strange thing to receive. Adaeze sat with it and did not say anything.\n"Where''s Chisom?" she asked.\nAmara''s expression shifted, just slightly. "Coming. She went to check with some girls from her prep class."\n\nChisom came back twenty minutes later.\nShe came in and set her bag on her chair and sat on her bed and was quiet for a moment, and Adaeze, who had been watching the door since Amara''s small pause, watched her now.\nChisom''s face was arranged the way it was when she was managing something. The surface pleasant and still. Whatever was underneath it moving at its own pace below the waterline.\n"First term results," she said. It was not quite a statement and not quite a question.\n"First," Amara said, nodding at Adaeze.\nChisom looked at Adaeze. Something passed across her face too quickly to name and then it was gone. "Congratulations," she said, and she meant it, Adaeze could hear that she meant it, but underneath the meaning was something else, something that sat alongside the genuine thing rather than replacing it.\n"Thank you," Adaeze said.\n"Where did you place?" Amara asked Chisom.\n"Third," Chisom said.\n"Third is good."\n"Third is fine." She opened her locker and took out her timetable and studied it. "It''s not where I planned to be."\n"Where did you plan to be?" Adaeze asked.\nChisom looked at her timetable. "First." She said it simply, without apology. "I don''t do things I don''t intend to do well."\nThe room held that for a moment.\n"So did I," Adaeze said.\nChisom looked at her then, a direct look, and for a second something in the room sharpened. Not hostility. Something more interesting than hostility. Recognition, maybe, of the kind that happened when you looked at someone and understood for the first time that they were built from similar materials, even if the house they lived in was entirely different.\n"Yes," Chisom said slowly. "I''m beginning to see that."\n\nAmara''s result came up in conversation the way things came up when Amara wanted them to, which was sideways and without ceremony.\nShe mentioned it that evening, at the table, while she was peeling another orange, three words folded into the middle of a sentence about something else entirely.\n"Twenty-first, by the way."\nChisom looked up. "Twenty-first?"\n"Out of sixty-one." She separated a segment cleanly. "Thirty-six percent."\n"Amara."\n"I passed."\n"That is not passing in any meaningful sense."\nAmara put a segment in her mouth. "It is the technical definition of passing. I checked."\nAdaeze looked at her carefully. Amara was doing the thing she sometimes did where she performed lightness over something that was not entirely light, and Adaeze had noticed it in other moments, small ones, whenever the conversation got close to something that required effort or expectation. She deflected not with sadness but with humour, which was a more sophisticated way of deflecting and therefore harder to address directly.\n"Do you care?" Adaeze asked. Not accusingly. Just asking.\nAmara looked at her. The easy surface of her expression held for a moment and then she looked back at her orange.\n"I don''t know," she said, with the honesty she sometimes produced when you asked her something directly and without preamble. "I care that my mother will be upset. I don''t know if I care about the number itself."\n"Why not?" Chisom asked.\nAmara was quiet for a moment. "Because I don''t know what the number is for yet. Back home I always knew what studying was for. School, then my parents'' expectations, then whatever was next. But being here, all of this," she gestured vaguely at the room, at the school beyond it, "I''m still figuring out what I''m actually doing. Studying feels like practicing for something but I don''t know what the thing is."\nThe room was quiet.\n"The thing is your life," Chisom said, not unkindly, but firmly, in the manner of someone who had never had the luxury of not knowing what things were for.\nAmara nodded slowly. "Maybe." She put another segment in her mouth. "But I need to understand it for myself. Not because someone told me."\nAdaeze thought about that for a long time after lights out. She lay in the dark and turned it over, this idea of needing to find your own reason, and it felt like something that came from a different world than the one she lived in. She had always known what things were for. Her mother''s face at the kitchen table had told her. The envelope with the three thousand naira had told her. The scholarship letter had told her. She had never once needed to go looking for her reason because her reason had never stopped being visible.\nShe wasn''t sure if that was fortunate or its own kind of poverty.\nOutside the window, the security light made its small yellow circle on the path below. The moth was there again, or a different moth, going around and around the same loop.\nChisom''s breathing had gone slow and even. Amara''s too.\nAdaeze stared at the ceiling and let herself, finally, in the full privacy of 1 a.m., feel the thing she had been pressing down since the noticeboard.\nFirst. Out of sixty-one.\nShe pressed the back of her hand against her mouth. Her eyes were doing the thing she never allowed in public. In the dark of the third bed, with no one watching, she let them.\nShe had earned this. Every 4:50 a.m. Every brown-paper-covered textbook. Every dinner that was all she had while the night filled with the smell of other people''s food.\nShe had earned this.\n','\n',char(10)),1452,1,1,NULL,'2026-04-01 12:29:38','2026-04-01 08:48:08','2026-04-01 12:29:38',NULL,1,3);
INSERT INTO "chapters" ("id","novel_id","chapter_number","title","content","word_count","is_premium","is_published","audio_url","published_at","created_at","updated_at","scheduled_release_at","part_number","season_id") VALUES(147,16,7,'What Amara Keeps',replace('The box first appeared on a Sunday.\nAdaeze would not have noticed it at all if she had not been at the table doing her reading while Chisom was at fellowship and the room was quiet enough that small things became visible. Amara came in from the bathroom with her towel over her shoulder, went directly to her locker, and reached past her folded clothes to the back of the shelf where she kept nothing, or where Adaeze had assumed she kept nothing. She pulled something out. Adaeze did not look up from her textbook.\nShe heard the soft click of a lock. The quiet sort, the kind with a small key.\nThen the sound of something being moved, papers maybe, or the shifting of small objects. Then the lock again. Then Amara pushed the locker shut and went to sit on her bed and opened her phone as if none of it had happened.\nAdaeze read the same paragraph four times and understood none of it.\n\nThe box was the colour of dark wood and small enough to be carried in both hands, the kind that was sold in the Aba market for keeping jewellery or letters or the things people wanted near them but out of sight. Adaeze saw it properly two days later when Amara forgot to push it fully to the back of the shelf and the locker door swung open in the afternoon heat. The brass lock on the front was small and neat and very deliberate.\nShe noted it and said nothing, the way she noted most things.\nWhat she could not note and say nothing about was the phone call.\n\nIt happened on a Tuesday night, three days before the end of term, when the school was loud with the particular energy of girls who could smell the holidays and could not contain themselves. Adaeze had gone to the corridor tap to wash out her water bottle at half past nine, just before lights out, and she was coming back around the corner of the corridor when she heard Amara''s voice from the alcove near the fire door, the small recessed space where the older girls sometimes went to make calls in private.\nShe stopped.\nShe was not trying to listen. She simply stopped because there was something in the texture of Amara''s voice that she had never heard before and it held her in place the way an unfamiliar sound held you in place before your brain caught up with your body.\nAmara was speaking in a low, careful voice, not the voice she used in the room or at the dining table or when she was performing ease for the world. This was a stripped version, the voice underneath the voice.\n"I know, Mama. I know what Dr. Eze said."\nA pause. Adaeze did not breathe.\n"I''m eating well. I''m sleeping. I''m not doing anything stupid." A short silence while the other end of the line spoke. "I brought everything. It''s here. I take it every morning, I promise you."\nAnother pause, longer.\n"Mama." Something in Amara''s voice went soft and tight at the same time, the particular tension of someone trying not to cry in a way that the other person could hear. "I''m fine. I need you to believe I''m fine. If you don''t believe it, I can''t believe it either."\nA long silence.\nThen: "Okay. Tell Daddy I said hello. Tell him I''m eating his soup in my dreams." A small almost-laugh, the kind that was covering other things. "Goodnight."\nThe call ended.\nAdaeze pressed herself against the corridor wall and waited. She heard Amara breathe. Heard her do it again, slowly. Heard the small sounds of someone putting themselves back together the way you put a thing back in its proper shape before anyone could see it had been crumpled.\nThen footsteps, away from the alcove, toward the bathroom, not back toward the room.\nAdaeze stood in the corridor for a long moment. Her water bottle was in her hand. The corridor tap was dripping. Somewhere down the hall someone was laughing at something on their phone.\nShe walked back to the room and got into bed and lay on her back and looked at the ceiling and did not move.\n\nChisom came in at quarter to ten, smelling of the fruity soap she used, and climbed directly into bed. She looked at Adaeze''s face in the low light and said, "What happened?"\n"Nothing," Adaeze said.\nChisom looked at her for a moment longer. "You have your something face."\n"I don''t have a something face."\n"You have approximately four faces. This is the something one." She arranged her pillow. "You don''t have to tell me."\nAdaeze was quiet. "Have you ever noticed that Amara has a box in her locker? Small, wooden. Locked."\nChisom was still for a moment. "I''ve seen it."\n"Do you know what''s in it?"\n"No." A pause. "I assumed it was something personal. I didn''t ask."\n"Me too," Adaeze said.\nThey lay in silence. Amara came in five minutes later, damp from the bathroom, smelling of her shampoo, and she moved through the room with the same easy presence she always had, dropping her towel on her chair, checking her phone, humming something low and tuneless under her breath. She was so completely herself that Adaeze, watching, felt the dissonance of it like a physical thing. The girl in the corridor and the girl moving around this room were the same person and also somehow not, and the distance between the two versions was the space where the secret lived.\nAmara caught her looking.\n"Why are you staring at me?" she asked. Not suspicious. Just curious.\n"You''re humming," Adaeze said, which was true but not the reason.\n"I always hum."\n"I know. I was listening."\nAmara smiled and turned off her bedside lamp and got into bed. "Goodnight, Adaeze."\n"Goodnight."\nThe room went dark. Chisom''s breathing went slow. Amara''s followed not long after, or what sounded like sleep, and Adaeze lay in the middle of everything she now knew and everything she still didn''t, and felt the particular discomfort of carrying a piece of someone else''s private weight without their permission.\nShe had not meant to hear it. But she had heard it, and now it was hers to carry carefully, the way you carried something borrowed, something that was not yours to use or set down, only to hold until the person it belonged to was ready to take it back.\nShe thought about the box. The brass lock. I take it every morning, I promise you.\nShe thought about Amara eating her orange in twenty-first place, saying I don''t know what the number is for yet, and she thought about how that sentence had sounded like lightness at the time, like Amara''s particular brand of unbothered, and she understood now that she had been reading it wrong.\nIt was not unbothered.\nIt was someone who had other things that were more urgent than a ranking on a noticeboard, someone who had learned to hold them alone and still show up warm and present and generous, still put the Milo tin in the middle of the floor, still pass the puff puff across the dark.\nAdaeze stared at the ceiling.\nShe had spent this whole term watching these two girls from a careful distance, measuring what she had against what they had, tallying the deficits of the third bed against the advantages of the other two, and it had seemed like a simple enough equation. Money and the lack of it. Ease and the lack of it.\nShe was beginning to understand that the equation was not simple, and that what people kept in locked boxes was rarely about money at all.\n\nOn the last day of term, while Chisom was in the bathroom and Adaeze was packing her bag, Amara took the box out of her locker.\nShe held it for a moment without opening it. Then she put it in her travel bag, underneath her folded clothes, and zipped the bag shut.\nShe turned and found Adaeze looking at her.\nNeither of them said anything. The moment stretched between them, not uncomfortable, not quite comfortable either. Something in the middle. The particular quality of two people standing on opposite sides of a thing that had not yet been named.\nThen Amara smiled, and it was a real smile, not the performing kind.\n"Safe journey home," she said.\n"You too," Adaeze said.','\n',char(10)),1421,1,1,NULL,'2026-04-01 12:29:27','2026-04-01 08:49:44','2026-04-01 12:29:27',NULL,1,3);
INSERT INTO "chapters" ("id","novel_id","chapter_number","title","content","word_count","is_premium","is_published","audio_url","published_at","created_at","updated_at","scheduled_release_at","part_number","season_id") VALUES(148,16,8,'The Announcement',replace('The new principal had been at Queen''s Hallmark for exactly six weeks and nobody had figured her out yet.\nThis was unusual. Principals, in Adaeze''s experience, were readable within the first few days. They were either the kind who led with fear, whose names you learned to say quietly in corridors, or the kind who led with warmth, who remembered your name and asked about your family and made you feel, briefly, like the school belonged to you too. Most fell somewhere between the two, predictable in their unpredictability, following patterns that older girls had already mapped and passed down like inherited knowledge.\nMrs. Okafor followed none of the patterns.\nShe was small and unhurried and she wore her grey hair in a low bun and she had a way of pausing before she spoke, not to think, it seemed, but to ensure she had your complete attention before she used your time. She had walked into the first assembly of second term, stood at the podium without any notes, and said: "I have been a principal for twenty-two years. I have watched girls leave this school and do extraordinary things, and I have watched girls leave this school and do ordinary things, and I have never once been able to predict, at the time of their leaving, which girl would do which. That uncertainty is what I find most interesting about this work."\nShe had paused, looked out at three hundred silent girls, and said: "I hope to be surprised by you."\nThen she had stepped down from the podium and the assembly had ended and nobody had spoken for almost a full minute afterward.\n\nSecond term settled over the school the way second terms always did, heavier than first, the novelty gone and the work remaining. Adaeze moved back into the third bed with the ease of someone returning to a place that had become, against all early expectation, hers. Her uniforms were freshly ironed. Her textbooks were stacked in the order of the timetable. She had used the holiday to read ahead in mathematics and chemistry and she carried this knowledge quietly, the way she carried most of her advantages, close and private.\nChisom arrived back with a new duvet. Cream coloured, thick, the kind of fabric that looked warm just to look at. She unpacked with the same methodical care she brought to everything and did not mention the holiday and nobody asked. Amara arrived last, one day after the others, carrying more bags than usual and moving with a slight deliberateness that Adaeze noticed and stored without comment.\nThe first night back, at ten o''clock, the three of them sat on Chisom''s bed and finished a bag of plantain chips and talked about nothing important, and something in the room settled back into the shape it had found by the end of last term, easy and unforced, three girls in a shared space who had become, without planning it, each other''s people.\nAdaeze sat cross-legged on the edge of the bed and listened to Amara imitate the voice of the woman at her family''s church who had asked her three times over Christmas whether she was eating enough, and she laughed, and it felt like the most uncomplicated thing in the world.\nShe did not know it was the last uncomplicated evening for a very long time.\n\nThe announcement came on a Thursday.\nIt came in the middle of morning assembly, slotted between the reading of the week''s notices and the closing prayer, which was where Mrs. Okafor put the things she wanted everyone to hear while they were still paying attention. She stepped to the podium in her unhurried way and the hall went quiet without anyone asking it to.\n"Queen''s Hallmark will this term launch its first academic competition," she said. "Open to every student, JS1 through SS3, across all subjects and disciplines. The format will be announced in full next week. The competition will run across six weeks, with the final held before the end of term."\nShe paused.\nThe hall held its breath.\n"The prize is a full university scholarship. Fees, accommodation, and a stipend for four years, offered by the Hallmark Foundation in partnership with three federal universities."\nThe silence lasted three more seconds and then broke completely, three hundred girls erupting into the kind of noise that moved through a space like weather. Adaeze did not join it. She sat straight in her row and felt the information move through her, not like excitement, more like recognition, the way you felt when something you had not known you were waiting for finally arrived.\nA full scholarship. Four years. Fees and accommodation and a stipend.\nShe looked at her hands in her lap and breathed carefully.\nMrs. Okafor waited for the noise to subside with the patience of someone who had waited out three hundred girls before and would again. When the hall quieted she said: "This competition is not for decoration. It is not a prize for the girl who has already been told she is exceptional. It is for the girl who has not yet had the chance to prove it. I hope every one of you will consider entering."\nShe stepped back. The closing prayer was said. The hall emptied.\n\nAdaeze walked back to the hostel alone.\nNot because Chisom and Amara were not there, they were, she could see them ahead in the crowd, Amara''s natural hair visible above the heads of the girls around her. She walked alone because she needed the three minutes between the assembly hall and Hibiscus House to put her face in order.\nShe was going to enter.\nThat was not a decision she made walking across the compound. It was a recognition of something that had already been decided somewhere deeper than conscious thought, the way you recognised hunger or cold, the body knowing before the mind caught up. The scholarship would cover university. All of it. Her parents would not have to do the calculation she had watched them do about her secondary school fees, sitting at the kitchen table with a notepad, adding and subtracting in silence. She would not have to watch her mother''s face do the thing it did when money was being stretched past its limit.\nShe would not have to ask for anything.\nShe crossed the compound and went up the stairs and pushed open the door of Room 7 and sat on the third bed and looked at the window and stayed very still.\nShe was still sitting there when Chisom came in.\nChisom entered without speaking. She set her bag on her chair with a precision that was slightly too careful and sat on her own bed and folded her hands and looked at nothing in particular. Her face was doing the managed thing, the surface composed, the waterline working hard.\nThey sat in silence for almost two minutes.\nThen Amara came in.\nShe closed the door behind her. She stood with her back against it for a moment and looked at both of them, at Chisom sitting with her folded hands and Adaeze sitting with her still face, and her expression moved through several things too quickly to follow.\nShe crossed the room and sat on the edge of her bed.\nThree girls. One room. The afternoon light coming through the curtain the way it always did, falling in a slanted line across the floor between the second bed and the third.\nThe silence was different from every silence that had come before it in this room. It was not the silence of early morning or of lights out or of ten o''clock and food and ease. It was the silence of three people who had just heard the same thing and were each now alone inside what it meant to them, and the room that had spent an entire term becoming a shared space had quietly, in the space of five minutes, become three separate spaces again.\nAmara opened her mouth.\nThen she closed it.\nChisom looked at the window.\nAdaeze looked at the floor.\nThe line of light between the second bed and the third was the same as always. Same angle, same width, same slow movement toward evening. It crossed the floor between them like a border that had not existed that morning.\nNobody said anything.\nNobody had to.','\n',char(10)),1401,1,1,NULL,'2026-04-06 12:48:56','2026-04-01 08:50:44','2026-04-06 12:48:56',NULL,1,3);
INSERT INTO "chapters" ("id","novel_id","chapter_number","title","content","word_count","is_premium","is_published","audio_url","published_at","created_at","updated_at","scheduled_release_at","part_number","season_id") VALUES(153,20,1,'Three Applications',replace('The application forms were available from the admin block starting Monday morning.\nAdaeze knew this because she had gone to check on Friday afternoon, after the last lesson, walking past the admin block on her way back from the library in a route that was slightly out of her way and that she did not acknowledge was deliberate. The notice on the door said: Hallmark Academic Competition. Application forms available from Monday 7th. Submission deadline Friday 11th. One entry per student.\nShe read it once and walked back to the hostel at her normal pace.\nShe did not mention it at dinner. She did not mention it at ten o''clock. She lay in the dark and listened to Chisom and Amara breathe and said nothing, and the nothing sat in the room alongside all the other nothings that had accumulated since Thursday''s assembly, three days of careful ordinary conversation about lessons and food and the new JS1 girl who had started crying in the dining hall and been comforted by the entire table around her, three days of ten o''clock snacks and easy laughter and nobody saying the word competition or scholarship or application, not once, as if by collective agreement, as if the silence were a courtesy they were all extending to each other while they worked out separately what they were going to do.\nAdaeze already knew what she was going to do.\nShe suspected the others did too.\n\nMonday morning she was at the admin block at six fifty-five.\nThe door opened at seven. The school secretary, a compact woman named Mrs. Agu who had been at Queen''s Hallmark since before most of the students were born, set a stack of forms on the counter without ceremony and went back to her desk. Adaeze took one form and folded it in half and put it in her textbook and walked to breakfast.\nShe sat with Chisom and Amara at their usual table. Amara was eating akara with the focused appreciation she brought to food she actually liked. Chisom was drinking tea and reading something on her phone. Neither of them had a form visible.\nAdaeze put her textbook on the bench beside her and ate her breakfast.\n\nShe filled out the form during free period, at the table in the back corner of the library where she did her best thinking. The form asked for name, class, subject specialisation, and a short statement of no more than two hundred words on why she was entering the competition.\nShe wrote the statement three times.\nThe first version was too honest. She read it back and it sounded like a letter from someone who needed something, which was true but was not the same as being useful. Need was not an argument. Need was everywhere. She tore it into small pieces.\nThe second version was too careful, the language arranged in the way she had learned to arrange things when she wanted to seem less than she was, which was a habit so old she sometimes did not notice when she was doing it. She read it back and recognised the habit immediately and tore that one too.\nThe third version was plain and accurate and did not apologise for itself.\nI am entering because I am the best student in my set and I intend to prove it in a format that cannot be adjusted or overlooked. I am entering because a full university scholarship will change the course of my life in ways I do not have the space to explain in two hundred words. I am entering because Mrs. Okafor said this competition is not for the girl who has already been told she is exceptional, and I have never once been told that, and I am tired of knowing something about myself that no one else has yet confirmed.\nShe read it back. It was one hundred and eighty words. She counted them twice.\nThen she put the form in the envelope the secretary had included, wrote her name on the front, and held it in both hands for a moment.\nShe submitted it on Wednesday morning before assembly. Mrs. Agu took the envelope without looking up and placed it in the tray on the left side of her desk.\nAdaeze walked to assembly and sat in her row and looked straight ahead and felt, for the first time since Thursday, something that was not anxiety. It was smaller than confidence and larger than hope. She did not have a precise name for it. She let it sit in her chest and did not examine it too closely.\n\nWhat she did not know, sitting in that assembly hall, was that Chisom''s envelope was already in the same tray.\nChisom had submitted hers on Tuesday afternoon, between the end of lessons and the beginning of prep, walking to the admin block alone in the ten-minute window when the corridors were emptying and there was very little chance of running into anyone from Room 7. She had filled out her form the night before, at her desk after lights out with her small torch, bent close to the paper in the way she did when she did not want to be seen working.\nHer two hundred words had taken forty minutes to write. Not because she did not know what to say. Because she knew too well, and the knowing was complicated.\nHer father''s latest letter, the real one, handwritten this time, not dictated, had arrived the previous week. It was shorter than his dictated letters and more painful. He was restructuring his business. There were delays. The terms of the arrangement he had made with her mother about school fees were going to need revisiting. He was sorry. He was working on it. He hoped she understood.\nShe had read it sitting on her bed on a Saturday morning while Adaeze was at the library and Amara was in the bathroom, and she had folded it back into its envelope and put it under her pillow and gone to breakfast and eaten everything on her plate.\nShe wrote in her application statement that she was entering because she was capable of winning and winning deserved to mean something. She did not write the rest of it. The rest of it was hers.\nMrs. Agu had taken her envelope and placed it in the tray without looking up.\n\nAmara submitted on Friday.\nThe deadline was five o''clock. She arrived at the admin block at four forty-seven, which was not her usual relationship with deadlines, which was typically to approach them as suggestions. She stood outside the admin block door for a moment before going in, her envelope in both hands, looking at nothing in particular.\nInside, Mrs. Agu was packing up her desk for the weekend with the deliberate efficiency of a woman whose relationship with five o''clock was sacred. She looked up when Amara came in and looked at the clock on the wall and said nothing, just held out her hand.\nAmara gave her the envelope.\nShe walked back to the hostel slowly, taking the long path around the sports field, the one that added seven minutes to the journey and that she sometimes took when she needed to think without being inside four walls. The late afternoon light was the particular gold of February in Enugu, heavy and warm, lying across the field in long flat sheets.\nHer application statement had not been about the scholarship money. Her family had money. She knew this and it sat uncomfortably alongside wanting something that her roommate needed in a way that was entirely different from wanting. She had written her two hundred words and deleted them and written them again four times before arriving at something she could live with.\nShe had written that she was entering because she had spent the whole of first term not knowing what she was working toward, and she had decided that was no longer acceptable, and this was the first concrete thing she had found that felt like a reason.\nShe had not written about the box. About what was in it. About what Dr. Eze had said, or what her mother''s voice sounded like at half past nine in a school corridor when she thought no one could hear her.\nShe folded her arms and walked the long path back to the hostel and went upstairs and opened the door of Room 7.\nChisom was at her desk. Adaeze was on her bed with a textbook.\nNobody had a form visible. Nobody had an envelope. The room looked exactly the way it always looked on a Friday evening, familiar and settled, the curtain moving slightly in the breeze from the louvres, the smell of Amara''s shampoo still in the air from the morning.\nAmara dropped her bag on her chair and sat on her bed and looked at her two roommates.\nChisom turned a page.\nAdaeze underlined something.\nThe room was quiet in the way it was always quiet on Friday evenings and it was also the loudest room Amara had ever been in.\nShe opened her mouth to say something. She looked at Adaeze''s bent head and Chisom''s straight back and she closed it again.\nShe lay back on her bed and stared at the ceiling.\nThree envelopes. One tray. Five o''clock on a Friday.\nThey would find out soon enough.','\n',char(10)),1574,0,1,NULL,'2026-04-01T12:07:10.547Z','2026-04-01 12:07:10','2026-04-01 12:07:10',NULL,2,6);
INSERT INTO "chapters" ("id","novel_id","chapter_number","title","content","word_count","is_premium","is_published","audio_url","published_at","created_at","updated_at","scheduled_release_at","part_number","season_id") VALUES(154,20,2,'Study Wars',replace('The list went up on Monday.\nMrs. Okafor had promised the full competition format the week after the announcement and she delivered it with the punctuality that was becoming her signature, a single typed sheet on the noticeboard outside the admin block, precise and unhurried, the way she was herself.\nThe competition would run in three stages. Stage one was a written examination, individual, covering English, mathematics, and general reasoning, to be held in week three. The top twenty scores across the whole school would advance to stage two, which was a research and presentation round, topic to be announced at the time. The top five from stage two would go to the final in week eight, a live panel examination in front of judges that included two university professors and one representative from the Hallmark Foundation.\nOne winner. Full scholarship.\nAdaeze read the format twice, slowly, and walked away from the board with everything already rearranging itself in her head. The written examination was the gateway. She needed to be in the top twenty. Given the school''s population and her first term results, that was achievable. The presentation round was the variable, it depended on topic and on a kind of intelligence that was different from examination performance, the ability to construct an argument and hold it in front of people while they looked for the places it could break. She was less certain about that round. She needed to think about it.\nShe was thinking about it all the way back to the hostel and up the stairs and through the door of Room 7 before she realised that Chisom was already at her desk, and the desk had been rearranged.\nIt was a small rearrangement. The kind that could be explained as tidying. Chisom''s textbooks, previously stacked to the right of the desk in a loose pile, were now arranged in a careful row along the back edge. Her notebooks were open. Her stationery was sorted. The desk lamp had been angled forward. The whole surface had the deliberate organisation of someone who had decided to take something seriously.\nAdaeze sat on her bed and opened her own textbook.\nNeither of them spoke.\n\nIt happened incrementally, which was why it was hard to name precisely when it began.\nThe first thing was the desk. Then it was the library. Adaeze had a standing arrangement with the corner table at the back, the quiet one with the good light, the one she had used since the beginning of first term. She arrived on Tuesday after lessons to find Chisom already there, spread across half the table with her notes and her colour-coded pens and the particular focused expression she wore when she was not to be interrupted.\nAdaeze took a table near the window. It had a slight wobble and the light was not as good.\nShe said nothing.\nOn Wednesday she got to the library first and took her corner table and Chisom came in twenty minutes later, saw her, and took the table on the opposite side without any change in expression, and they sat in the same room for two hours and studied in absolute silence and left at different times.\nIt was not hostile. That was the difficult thing about it. Hostility would have been easier to address, easier to name and push against. This was something else entirely. It was courtesy stretched so thin you could see through it, two people performing consideration for each other so carefully that the performance itself became the problem.\n\nAmara noticed on Thursday.\nShe came back from the bathroom to find both of them at their respective desks, Chisom with her colour-coded notes and Adaeze with her second-hand textbook open to a chapter she had already covered twice, and the room was so quiet that Amara''s footsteps on the floor felt intrusive.\nShe sat on her bed and looked from one to the other.\n"What is happening in here?" she asked.\n"Studying," Chisom said, without turning around.\n"Reading," Adaeze said, also without turning.\nAmara looked at the back of Chisom''s head and then at the back of Adaeze''s head and then at the ceiling, which had no useful information to offer.\n"It feels like a library in here," she said. "We have a library. It''s across the compound. This is our room."\n"People study in their rooms," Chisom said.\n"People also talk in their rooms," Amara said. "People who live together and eat chin chin together at ten o''clock and have laughed together enough times that I know both of your laugh sounds with my eyes closed."\nA short silence.\n"I have a lot to cover," Adaeze said.\n"We all have a lot to cover," Chisom said, which was the first time either of them had said anything that acknowledged what was actually happening, and the acknowledgment sat in the room for a moment, bright and uncomfortable, before Chisom turned a page and it was gone.\nAmara lay back on her bed and looked at the ceiling for a long time.\n\nThe ten o''clock ritual changed that week without anyone deciding it would.\nIt did not end. That was important. Nobody said, we are not doing this anymore. The food still came out. They still moved to whoever''s bed had the most space. But something inside the ritual had shifted its weight, the way a familiar piece of furniture felt different after it had been moved slightly from its original position, still the same object, still functional, but your body knew something had changed before your mind could confirm it.\nOn Thursday night Chisom shared plantain crisps and they ate them and the conversation was about the Thursday soup, which had reached a new level of inexplicability, and about a girl in SS2 who had reportedly brought a portable gas cooker into her room and been caught when the smell of jollof rice drifted into the corridor during night prep. It was easy conversation. It produced real laughter. Amara did the voice of the girl explaining herself to the dorm mistress and it was very good and both Adaeze and Chisom laughed without reservation.\nAnd yet.\nWhen the food was finished and they went back to their beds, Adaeze lay in the dark and felt the difference between this ten o''clock and the ten o''clocks of first term the way you felt the difference between a room with a window open and the same room with the window closed. The temperature was almost the same. The air was almost the same. Almost.\nThe competition was in the room with them now. It had taken its place among their things as quietly as Adaeze had taken the third bed on the first day of term, and it had begun to rearrange the furniture.\n\nThe study schedule appeared on Friday morning, written on a small piece of paper that Chisom had stuck to the inside of the room door with a strip of tape.\nIt was not addressed to anyone. It was a general timetable she had drawn up for herself, the kind of thing Chisom did when she was taking something seriously, the hours divided and allocated with the precision of someone who understood that time was the only resource she could fully control. Mathematics from five to six-thirty. English from six-thirty to eight. Chemistry from eight to nine.\nAdaeze read it standing at the door with her water bottle in her hand.\nShe went to her desk, took out a piece of paper, and wrote her own schedule. She did not put it on the door. She folded it in half and put it under the corner of her textbooks where she would see it first thing every morning.\nHer mathematics block started at four-thirty.\nShe did not do this because she needed an hour more than Chisom needed. She did it because she had always started earlier than everyone else, long before there was a competition to prepare for, and she was not about to let anyone else set the terms of her own habits. She had learned that much from the ironing board.\n\nAmara''s desk remained the way it had always been, which was to say it had a textbook on it and also a half-eaten packet of biscuits and a lip balm and a phone charger and a photograph her mother had sent of the family dog, a fat and tremendously self-important looking thing named Governor.\nShe studied in a way that was difficult to see as studying from the outside. She read lying on her stomach across her bed, or sitting sideways in her chair with her legs over the armrest, or on the floor with her back against the bedframe and her knees up. She took notes in a small book she kept in her pillowcase for reasons she had not explained. She was not doing what Chisom was doing or what Adaeze was doing and yet Adaeze, who had begun watching her more carefully since the corridor, had noticed that Amara''s casual reading was not casual at all, that the pages turned at a rate that suggested genuine comprehension, that the small book came out more often than it appeared to, that Amara simply did her most serious things in ways that did not look serious.\nIt was, Adaeze thought, its own kind of strategy. To be underestimated was a resource, if you knew how to use it.\nShe was not sure yet whether Amara knew this consciously or whether it was simply who she was. The distinction mattered.\n\nSaturday afternoon, the three of them were in the room at the same time, each doing their own thing, the air between them comfortable enough on the surface and complicated underneath, when Amara looked up from her floor position and said, without preamble: "Are we going to talk about it?"\nChisom did not look up from her notes. "Talk about what?"\n"Chisom."\nA pause. Chisom''s pen moved across the page.\n"We''re all entering the same competition," Amara said. "We know that. We all know that we know that. We''re walking around it like it''s a bucket on the floor that we''ve all agreed not to acknowledge, and one of us is going to trip over it."\n"I haven''t tripped over anything," Chisom said.\n"Not yet."\nAdaeze closed her textbook and rested her hands on the cover. She looked at the window. The compound below was quiet, the particular Saturday quiet of a school that had briefly released its grip on everyone''s time.\n"What is there to say?" she asked. Not dismissively. Genuinely.\n"I don''t know," Amara said. "Something true, maybe. Something that means when we sit here next week and the week after we''re not pretending to be fine while being something else."\nThe room held that.\nChisom put her pen down. She was quiet for a moment, looking at her notes, and then she turned around in her chair to face the room properly for the first time all week.\n"I am going to try to win," she said. Her voice was even and direct, the tone she used for things she had thought about and decided. "I don''t know what your reasons are. Mine are mine. But I am going to try as hard as I know how to try, and I cannot do that and also spend energy making sure nobody''s feelings are managed in the process."\nShe looked at Adaeze when she finished.\nAdaeze met her eyes. "I am going to try to win too," she said. "My reasons are also mine."\nThey looked at each other for a moment, the two of them, across the room, with the particular quality of two people who respected each other enough to be honest and cared about each other enough for the honesty to cost something.\nAmara sat up from the floor and crossed her legs. She looked at both of them.\n"Okay," she said. "Okay, then that''s what it is." She reached under her pillow for the small notebook and put it on her knee. "Can someone explain to me what the general reasoning section of a written examination actually tests, because I have been staring at the words for three days and I need a human being to explain it to me in a normal way."\nA small silence.\nThen Adaeze opened her textbook back to the relevant chapter and said: "Come here."\nAmara moved from the floor to the end of Adaeze''s bed and leaned in over the page, and Chisom, after a moment, stood from her chair and came and sat on the other side.\nThree girls. One textbook. The afternoon light crossing the floor in its usual slanted line.\nThe competition was still in the room. It had not moved and it would not move. But for this one hour, on a Saturday afternoon, they sat together on the same side of it, and that was something, even if neither of them knew yet how long it would last.','\n',char(10)),2174,0,1,NULL,'2026-04-01T12:09:44.255Z','2026-04-01 12:09:44','2026-04-01 12:09:44',NULL,2,6);
INSERT INTO "chapters" ("id","novel_id","chapter_number","title","content","word_count","is_premium","is_published","audio_url","published_at","created_at","updated_at","scheduled_release_at","part_number","season_id") VALUES(155,20,3,'Chisom''s Crack',replace('It was Amara who found her.\nNot in a dramatic way, not the way things happened in the stories they read for English literature where someone was always discovering someone else in the middle of a moment too private for witnesses. It was ordinary and accidental and it happened on a Tuesday evening when Amara came back from the bathroom early because she had forgotten her towel and pushed open the door of Room 7 and found Chisom sitting on the floor beside her bed with her back against the mattress and a letter in both hands, reading it the way you read something you had already read many times and were hoping would say something different.\nChisom looked up.\nAmara stood in the doorway with no towel and the two of them looked at each other for a moment that was too long for either of them to pretend nothing was happening.\n"I forgot my towel," Amara said.\n"It''s on your chair," Chisom said.\nAmara came in and picked up her towel and stood there, holding it, and looked at Chisom on the floor with the letter and the face that had stopped being managed.\n"Do you want me to go?" she asked.\nChisom looked at the letter. Then she folded it along its creases and held it in her lap and said: "Close the door."\n\nAmara sat on the edge of her bed. She did not say anything. This was one of the things Adaeze had noticed about her and that Chisom had noticed too, separately and without comparing notes, that Amara had a quality of stillness available to her that her general manner did not advertise. She could sit in a silence and not fill it, and the silence she offered was the kind a person could actually rest in.\nChisom stayed on the floor. She was still in her school uniform, which was unusual for this hour.\n"My father''s business is failing," she said.\nShe said it the way she said most difficult things, plainly, with no ornamentation, as if the plainness were its own form of protection.\n"Not slowly failing. It has been failing for two years and I did not know because nobody told me, and now I know because the letters changed and I am not a child and I can read the change even when the words are still polite." She smoothed the folded letter on her knee. "He had three pharmacies. Two are closed. The third one he is running with a loan that my uncle gave him, and my uncle is not a generous man, and the terms of the loan are the kind that make my father write letters that sound like someone who is afraid."\nThe room was very quiet.\n"My school fees for this term were paid," she continued, "but he said in this letter that he cannot guarantee the next term''s fees without knowing how the next quarter goes for the pharmacy. He said my mother should be prepared for the possibility of a conversation." She paused. "My mother has been working. She went back to work last year. She is a pharmacist too, that is how they met, but she left when she married him because he asked her to, and now she is back at it and there is a cost to that, not money, other costs. She is tired in a way I can hear over the phone."\nAmara was still. Listening.\n"The package," Chisom said. "The care package. His PA packed it. I said that. I was annoyed about the hair ties and the handwriting and the PA who noticed what kind of girl I am." She stopped. "But I have been thinking about it since. He still sent it. Whatever is happening with the money and the pharmacy and the loan from my uncle, he sat down and told someone what to buy for me and he sent it. He sent the chocolate and the peanut butter and the Milo." Something in her voice changed, not broke, Chisom''s voice did not break, but shifted register, went somewhere more internal. "It cost money he may not have comfortably and he sent it because he did not want me to know yet."\nShe looked at the letter.\n"I know now," she said.\n\nAdaeze came back from the library at eight fifteen to find Amara sitting on her own bed and Chisom at her desk, back in her usual posture, notes open, pen moving. The room looked the way it always looked at this hour.\nBut Amara looked at Adaeze when she came in and her eyes said something, a small precise communication between two people who had been learning each other''s silent language all term.\nAdaeze put her bag down and sat on the third bed and opened her textbook and did not ask anything.\n\nLater she would piece it together. Not because Amara told her directly but because Amara was not built for sustained secrecy and pieces of it came out over the following days in the natural way that things came out at ten o''clock, or in the early mornings, or on the long walk to the dining hall when it was just the two of them and the conversation went where conversations went when the ordinary topics had been used up.\nWhat she understood, assembled from the pieces: the fees were uncertain. The family wealth that Chisom wore so naturally, that had furnished her half of the room with its peach duvet and glass-bottle lotion and personal cooler box, was more fragile than its surface suggested. It was not gone. But the ground beneath it had shifted and the shift had been invisible to everyone including Chisom until the letters changed.\nThe scholarship, Adaeze understood now, was not about prestige for Chisom. It was not even primarily about the university education, though that was part of it. It was about not having to watch her mother''s tired face get more tired. It was about removing one large and looming item from the list of things her parents were currently trying to carry. It was about a girl who had been performing ease for so long that the performance had become identity, suddenly finding a reason to drop it, briefly, on a Tuesday evening on the floor beside her bed, because the cost of continuing had finally exceeded what she was able to pay.\n\nOn Friday, three days after Amara found her, Chisom came back from morning lessons and instead of going directly to her desk she sat on her bed and looked at Room 7 the way you looked at a place you were trying to memorise.\nAdaeze was the only other person in the room. She put her pen down.\n"My mother called this morning," Chisom said. "During first break. She wanted to tell me before I heard it another way."\nAdaeze waited.\n"My father is closing the third pharmacy. He sold the equipment to settle part of my uncle''s loan. He is going to work for a pharmaceutical distributor in Onitsha." She said this last part with the particular precision of someone reporting facts about a stranger. "My mother says it is a good company and the salary is stable and this is actually better for the family long term than the uncertainty of running a business."\n"She may be right," Adaeze said carefully.\n"She is trying to be right," Chisom said. "She is working very hard to be right about it." She was quiet for a moment. "My father had those pharmacies for eleven years. He opened the first one the year I was born. He named it Chisom Pharmacy." She stopped. "It''s closed now. It has been closed for eight months. I went past it in the holidays and the sign was still up but the inside was empty."\nAdaeze looked at her.\n"I stood outside it for a while," Chisom said. "On the street. I don''t know what I was doing. Looking at my own name on a closed building, I suppose." She folded her hands in her lap. "My name means ''God is with me'' in Igbo. Isn''t that something."\nThe words arrived quietly, without self-pity, which made them heavier than self-pity would have been.\nAdaeze thought about what to say and found that nothing she could construct was equal to the moment. She thought about what Amara would do and understood that Amara would not try to construct anything, she would simply be present, and sometimes being present was the entire response.\nSo she said: "I''m sorry about the pharmacy."\nChisom looked at her. Something in her face moved, very slightly, the way ice moved when it was just beginning to change state.\n"Thank you," she said. Quietly. Meaning it.\nThey sat for a moment in the room that had held all of their private things, the locked box and the ironing board and the letter under the pillow, the 4:50 a.m. and the corridor phone call and now this, a closed pharmacy with a name on the sign and an empty inside.\n"I need to win this competition, Adaeze," Chisom said. Not as a challenge. Not as a warning. Just as the true thing, said plainly to the one person in the room who would understand both the need and the cost of admitting it.\nAdaeze looked at her. Across the room that had spent all term teaching them who the other was.\n"I know," she said.\nShe picked up her pen.\nChisom opened her notes.\nOutside, the afternoon moved across the compound in its usual way, indifferent and unhurried, and in Room 7 two girls sat with the knowledge of each other''s need laid between them like something irreversible, and studied in a silence that was no longer the silence of courtesy or competition but of two people who had seen each other clearly and chosen to remain in the same room anyway','\n',char(10)),1662,0,1,NULL,'2026-04-01T12:11:06.852Z','2026-04-01 12:11:06','2026-04-01 12:11:06',NULL,2,6);
INSERT INTO "chapters" ("id","novel_id","chapter_number","title","content","word_count","is_premium","is_published","audio_url","published_at","created_at","updated_at","scheduled_release_at","part_number","season_id") VALUES(156,20,4,'The Leak',replace('The written examination was in four days when Chisom came back from the prep room on a Wednesday night and closed the door of Room 7 behind her with the particular quietness that was louder than slamming.\nAdaeze was at the table. Amara was on her bed with her small notebook. Both of them looked up.\nChisom stood at the door for a moment, and the expression on her face was one neither of them had seen before. Not the managed surface, not the waterline working underneath it. Something had gotten through both layers and was sitting on top of everything now, visible and unguarded and not entirely cold.\nShe went to her desk and stood in front of it without sitting down.\n"My notes are gone," she said.\nAdaeze put her pen down. "Which notes?"\n"My stage two notes." She said it without turning around. "I had a folder. Blue, inside my second textbook from the left. Research I have been doing for three weeks on how to approach the presentation round. Arguments, angles, sources. Three weeks of work." A pause. "It is not here."\nThe room was very still.\n"Maybe you left it in the prep room," Amara said. "Or the library."\n"I have not taken it out of this room," Chisom said. "I have been careful not to take it out of this room because I did not want anyone to see what I was preparing." She turned around then and looked at them both, and the look was not an accusation in its shape but it was an accusation in its weight, the particular heaviness of someone looking at the only two people who could have done a thing.\nAdaeze looked back at her steadily. "I have not touched your notes."\n"I didn''t say you did."\n"You looked at me when you said it."\n"I looked at both of you."\nAmara was sitting up now, her notebook closed in her lap. Her face had gone careful. "Chisom, I haven''t been near your desk. I don''t even sit on that side of the room."\n"My notes are gone," Chisom said again. The repetition had a quality of someone returning to the one fact they were certain of because the facts around it were too complicated.\n"Then they are somewhere in this room," Adaeze said. "Look properly."\n"I have looked."\n"Look again."\nSomething flashed in Chisom''s expression. "I know how to look for something in my own space, Adaeze. I am not careless with my things. You know that."\n"I know that," Adaeze said. "I also know I have not touched them."\n\nThey looked. All three of them, in the particular uncomfortable way of people searching a space while also being suspected within it, Adaeze going through her own side of the room to demonstrate its absence from her belongings, Amara lifting her mattress and checking under her bed with the thorough cooperation of someone who had nothing to hide. Chisom went through her own locker twice, her desk drawers, the pocket of every bag she owned.\nThe blue folder was not in Room 7.\nThey sat down on their respective beds afterward and the room had a different quality than it had ever had before. Not the almost-comfortable tension of the past two weeks. Something rawer.\n"Someone from the prep room," Amara said. "You said you didn''t take it out but is it possible you brought it once without thinking? Two weeks ago, one week ago?"\nChisom was looking at her hands. "It''s possible," she said slowly. "I had it here on Sunday. I am certain of Sunday."\n"Then between Sunday and now," Amara said.\n"Four days," Adaeze said. "How do you know someone else has it? Maybe it''s still in the prep room. Maybe it fell behind something."\nChisom looked up. The expression on her face settled into something specific that Adaeze read and understood one second before she spoke.\n"Nneka Okonkwo told Bisi that someone had been circulating research notes with a particular angle on historical African development frameworks," she said. "Bisi told me tonight. She thought I should know because it sounded like my approach." She paused. "My exact approach. The one I developed myself, that I have told nobody about, that I have been working on in here for three weeks."\nThe room absorbed that.\n"How many people are working on that angle?" Amara asked carefully.\n"It is not a common angle," Chisom said. "It requires a specific line of reading that most people here would not think to follow. I thought of it myself. I did not find it in a textbook." Another pause. "Someone has my notes or has seen my notes and they have shared them."\nShe looked at Adaeze.\nAdaeze felt it land. The look, and what was underneath the look, and she felt something move in her chest that was not quite anger and not quite hurt but was made of both things.\n"Say it," she said.\n"I haven''t said anything."\n"You keep looking at me and not saying it. Say it."\nThe room went very quiet. Amara had gone still on her bed, her eyes moving between them with the expression of someone watching a bridge and calculating whether it would hold.\n"You are the most prepared person in this competition," Chisom said. Her voice was even. Almost. "You have been working harder than anyone in this school and I think we both know that, and I respect it, I do. But you are also the person with the most to gain from knowing what I am planning. And you are in this room. And my notes are gone."\nThe words went in cleanly, the way things went in when they were delivered with precision.\nAdaeze stood up.\nNot violently, not with any drama, she simply stood up from the third bed the way she had sat down on it on the very first day of term, with the particular straightness of someone who had spent their whole life holding themselves upright in rooms where the ground was uncertain.\n"I have never in my life taken something that did not belong to me," she said. "Not a thing, not a mark, not a single advantage that I did not earn with my own hands. You have been in this room with me for two terms. You have watched me work. You have watched me iron my uniforms at five o''clock in the morning because I cannot buy new ones and I refuse to look like I cannot. You have eaten food at ten o''clock that I could not contribute to and I said nothing, not once, because I was not going to make my lack everyone else''s problem." Her voice was steady and it cost her something to keep it that way. "And you are standing there telling me with your eyes that I would steal from you."\nChisom''s jaw was tight.\n"I did not use the word steal."\n"You did not need to."\n"Adaeze." Amara''s voice was low.\n"I am fine," Adaeze said, which was not entirely true.\n"I am not accusing you," Chisom said, and the genuineness of this was visible and also insufficient because the look had already happened and the words had already happened and in Room 7 where everything small was eventually known, genuineness and insufficiency were not mutually exclusive.\n"Then stop looking at me like you are," Adaeze said.\n\nThe silence that followed was the kind that left a mark.\nAmara got up from her bed and went to Chisom''s desk and crouched down in front of it and looked at the space between the desk and the wall, the narrow gap that collected dust and forgotten things, and she reached into it with her arm and felt around and after a moment pulled out a blue folder that had slipped behind the left leg of the desk and lain flat against the skirting board, invisible from above, catchable only if you were looking at floor level from the right angle.\nShe stood up and held it out.\nChisom took it. She stood with it in both hands for a long moment, looking at it with an expression that moved through several things in quick succession.\n"It was behind the desk," Amara said. Quietly. No emphasis on any word. Just the fact.\nThe room was very, very still.\nChisom opened the folder. Her notes were all there, three weeks of work in her handwriting, the arguments and angles and sources. She turned through the pages slowly and then she closed it and held it against her chest and closed her eyes for a moment.\n"What Nneka told Bisi," Adaeze said. Her voice had come down but the steadiness was still there, the kind that came from holding something tightly rather than from ease. "The similar approach. That was a coincidence."\n"Yes," Chisom said. The word came out small.\n"Someone arrived at the same angle independently," Adaeze said. "It happens. Two people reading similar materials will sometimes think similar things."\n"Yes."\nThe room was quiet.\nChisom looked at Adaeze. Her expression had none of its management left in it. What was there instead was harder to look at, the face of someone who had shown a version of themselves they had not intended to show, who had been afraid and let the fear think for them, and who was now standing on the other side of it with their own behaviour in their hands.\n"I should not have looked at you like that," she said.\nAdaeze was quiet for a moment. The things she had said were still in the room, the true things said in a voice that had been fighting itself, the things about the uniforms and the ten o''clock food and the lack she had never made anyone else''s problem. She had not planned to say them. They had come out the way things came out when the container was finally too full.\nShe could not take them back. She was not certain she wanted to.\n"No," she said. "You should not have."\nShe sat back down on the third bed and picked up her pen and looked at her textbook and the words on the page were blurred for a moment before they settled back into sense.\nAmara returned to her own bed without saying anything, which was the right thing. She sat with her notebook in her lap and looked at nothing in particular, and her expression had the quality of someone who was sitting with their own private accounting, something that had nothing to do with the folder or the desk or Nneka Okonkwo''s secondhand information, something interior and unfinished that she had pushed aside to manage the immediate crisis and that was now waiting for her with patient insistence.\nChisom put her blue folder in her locker. She locked it this time. Then she sat at her desk and opened her notes and the scratch of her pen began again in the room that had gone quiet in a new way, not the almost-comfortable tension of the past two weeks, not the ease of first term, but something unsettled and real and specific to three people who had said and not said too many things and were now all sitting separately inside the cost of it.\nOutside, the night prep bell rang down the corridor.\nNobody moved.\n\nWhat nobody said that night, and what would not be said for several days, was that the real damage was not the accusation and not the found folder and not the things Adaeze had said in response. The real damage was simpler and more permanent than any of those things.\nIt was that in the moment of her fear, in the unmanaged two minutes before Amara found the folder behind the desk, Chisom had looked at Adaeze and the look had contained a question that should never have been formed about a person you had shared a room with for two terms. That you had eaten food with at ten o''clock. That you had watched iron her uniforms at five in the morning and understood, without being told, what the ironing meant.\nThe question had been answered. The folder was found. The accusation had never technically been made.\nBut Room 7 was a small space, and Adaeze had spent her whole life noticing things, and the look was in the room now, sitting between the second bed and the third like something that had taken up residence and intended to stay.','\n',char(10)),2093,1,1,NULL,'2026-04-01 12:31:20','2026-04-01 12:12:33','2026-04-01 12:31:20',NULL,2,6);
INSERT INTO "chapters" ("id","novel_id","chapter_number","title","content","word_count","is_premium","is_published","audio_url","published_at","created_at","updated_at","scheduled_release_at","part_number","season_id") VALUES(157,20,5,'Visiting Sunday',replace('Visiting Sunday came on the third weekend of term, which meant it arrived four days after the folder, four days after the things Adaeze had said and the look Chisom had given and the particular quality of silence that had settled over Room 7 like weather that had not yet decided what it wanted to become.\nThe school sent letters home in January notifying parents of the date. Adaeze had told her mother in a phone call from the common room, standing in the queue for the shared handset the way the scholarship girls did, waiting her turn while the girls with personal phones made their calls from their rooms. Her mother had said she would come. She had said it the way she said things she had already decided, without qualification or condition, simply: I will be there.\nAdaeze had not told Chisom or Amara that her mother was coming, not because it was a secret but because the telling would have required a conversation she was not ready to have. There were things about her mother, about the way her mother moved through the world, that Adaeze had spent two terms carefully managing the distance between. Not from shame. She had examined that possibility honestly, in the way she examined most things about herself, and what she found was not shame but something more complicated, a kind of protectiveness that went in both directions at once, toward her mother and toward herself, two people she loved guarding each other from a world that assessed them constantly and always found something insufficient.\nShe put on her second blouse on Sunday morning, the plain one she kept for church and good occasions, and ironed it at five o''clock and was ready before the bell.\n\nThe visiting area was the school''s lower garden, a stretch of lawn between the main building and the junior hostel with benches arranged in clusters and a temporary canopy that the school erected on visiting days to provide shade. By ten o''clock it was full of the particular noise of families reassembling themselves after weeks apart, the sound of mothers exclaiming over their daughters'' appearance, fathers sitting with the slightly uncertain posture of men in a space that was not designed for them, younger siblings running in the grass with the energy of children who had been in a car for several hours and needed to discharge it.\nAdaeze stood at the garden entrance and looked for her mother.\nShe found her near the far bench, standing rather than sitting, wearing her good dress, the one she wore for weddings and special occasions, blue and white with a pattern of small geometric shapes. She had her good bag over one arm and she was looking around the garden with the attentive stillness of a woman who was taking in information and making no judgments visible, and when she saw Adaeze her whole face did something that Adaeze could not look at directly without her throat tightening, so she looked at the grass instead as she walked across it.\nHer mother held her for a moment. She smelled of the lavender oil she kept in a small bottle on the kitchen windowsill at home, the same bottle she had kept there for as long as Adaeze could remember.\n"Let me look at you," her mother said, and held her by the shoulders and looked.\n"I''m fine, Mama."\n"You''re thinner."\n"I''m the same."\n"A mother knows thinner." But she was smiling, and the smile was the one that meant she was satisfied, that what she was seeing confirmed something she had needed to see with her own eyes. She cupped Adaeze''s face in both hands briefly, the way she had done since Adaeze was small, and then she released her and straightened the collar of her blouse and said: "Show me where you live."\n\nThey were coming back from the hostel, Adaeze having shown her mother the building and the corridor and stopped outside the door of Room 7, not taking her inside because Chisom and Amara were both in there and Adaeze had not planned this part, when Amara opened the door from the inside.\nShe was on her way to the visiting garden, her own mother expected at eleven, and she pulled the door open and found Adaeze and a woman standing in the corridor and stopped.\nFor one second, before anyone spoke, Amara looked at Adaeze''s mother.\nLater Adaeze would think about that second. What Amara''s face did in it was not calculation or assessment, it was recognition, the particular quality of a perceptive person encountering something true. Adaeze''s mother was a small woman with a direct gaze and good posture and the kind of face that had been shaped by years of solving problems with limited resources, and there was nothing in the corridor that morning to obscure any of that.\n"You must be Adaeze''s mother," Amara said, and her voice was warm without effort. "I am Amara. Her roommate."\nHer mother looked at her with the same attentive stillness she had used in the garden. "Amara. I have heard your name."\nAmara glanced at Adaeze with something delighted in her expression. "Good things, I hope."\n"Mostly good," Adaeze''s mother said, and the dryness in it was so precisely her own that Adaeze almost laughed.\nChisom appeared behind Amara in the doorway. She was dressed for visiting day, which meant she was immaculate, and she took in the scene with the social fluency she had been raised to and stepped forward and extended her hand.\n"Chisom," she said. "Good morning, ma."\nAdaeze''s mother shook her hand and looked at her for a moment. "You are the Anambra girl," she said. "My daughter told me."\n"Yes, ma." Something in Chisom''s expression adjusted slightly, a small surprise, quickly managed. That she had been mentioned. That she was known.\nThey stood in the corridor for a few minutes, the five of them, and Adaeze watched her mother talk to her roommates with the quiet competence she brought to everything, asking Amara about her journey and asking Chisom about her studies, nothing probing, nothing that required more than comfortable answers, and yet by the end of it Adaeze understood that her mother had seen both of them, properly, in the way she saw things, and had filed what she found.\nThen Amara went to meet her mother and Chisom went back inside, and Adaeze and her mother went to find a bench in the garden.\n\nThey sat in the lower garden with a container of jollof rice and fried plantain that her mother had carried from Anambra in a covered pot wrapped in a kitchen towel to keep the heat, and Adaeze ate it with the specific hunger of someone who had been eating school food for two months, and her mother watched her eat with the satisfaction of someone whose primary argument had been proven.\n"Tell me the real things," her mother said. "Not the things you say on the phone."\nAdaeze ate a piece of plantain. "The real things."\n"The phone things are fine. You are fine, studying is going well, you are eating, you are sleeping. I know the phone things. Tell me the other ones."\nAdaeze was quiet for a moment. Around them the garden was its usual Sunday noise, families and food and the particular frequency of people catching up on weeks of withheld living.\n"There is a competition," she said.\nHer mother listened without interrupting while Adaeze told her the shape of it. The format, the stages, the prize. When she finished, her mother was quiet for a moment, looking at the garden.\n"And your roommates," she said. "They are also entering."\n"Yes."\n"Both of them."\n"Yes."\nHer mother looked at the container between them. "This is the thing you have not been saying on the phone."\n"It is complicated."\n"Complicated how?"\nAdaeze thought about the folder. About Chisom''s face in that moment, before the folder was found. About the things she had said in response, the words that had come from somewhere deep and old and pressurised, the things about the uniforms and the ten o''clock food and the lack she had never made anyone else''s problem.\n"We were becoming friends," she said. "The three of us. Properly. And now this competition is inside it and the friendship is trying to survive around it but it is not the same shape anymore."\nHer mother nodded slowly. Not in a hurry to speak.\n"And Chisom," Adaeze said, because she had started now and the real things had their own momentum once you let them begin. "Chisom is the kind of person who is always composed. Always managed. She makes it look easy and it is not easy, I know that now, and I respect her for it." She paused. "But four days ago she looked at me and the look said she thought I had stolen from her. She did not say it. But the look said it."\nThe garden moved around them. A child ran past chasing a smaller child.\n"And did you?" her mother asked.\nAdaeze looked at her. "Mama."\n"I know you did not. I am asking if she had a reason."\n"The reason was that she was afraid and I was the person in the room."\n"And you are also the scholarship girl," her mother said. Not cruelly. Precisely.\nAdaeze was quiet.\n"People are afraid," her mother said, "and fear makes people see what they are afraid of, not what is true. That girl is afraid of losing something. You happen to be in the room." She picked a piece of plantain from the container. "That is not about you, even when it feels entirely about you."\n"It felt entirely about me."\n"I know."\n"I said things."\n"What things?"\nAdaeze told her. The exact words, as close as she could remember them. Her mother listened with the stillness she brought to important things.\nWhen she finished, her mother was quiet for a long moment.\n"Were they true?" she asked.\n"Yes."\n"Did they need to be said?"\nAdaeze thought about it honestly. "Some of them."\n"And the others?"\nShe was quiet. The others had come from the place where she kept the things that were too large for public. The container had been too full and the moment had opened it, and not all of what came out had been meant for Chisom. Some of it had been meant for every room she had ever stood in where she was the one who had less and was expected to perform ease about it.\n"The others were mine," she said.\nHer mother nodded. She did not say anything to this, which was its own form of confirmation.\n\nAt half past twelve Adaeze saw Amara across the garden with her mother, a tall woman in a yellow wrapper who moved with Amara''s same quality of taking up space without apology. They were sitting close together on a bench and Amara was talking with her hands the way she did when she was telling a story she cared about, and her mother was listening with her chin resting on her hand and her eyes on her daughter''s face with an expression that Adaeze could read even from this distance.\nShe looked away.\nShe did not see Chisom in the garden. Chisom''s mother had not come. She did not know this for certain but she had been in the garden since ten and she had not seen Chisom with anyone and it was now half twelve. She thought about the phone call, the restructured business, the tired voice, and she thought about Chisom in the room right now, the immaculate dress worn for a visitor who had not arrived, and she felt something move in her chest that had nothing to do with the competition.\nHer mother was watching her.\n"The Chisom girl," her mother said. "Her people are not here today."\n"No."\nHer mother looked at the garden for a moment. "When you go back to that room," she said, "remember that you are not the only one carrying something heavy."\n"I know that."\n"I know you know it." She looked at her. "I am telling you to remember it when it is inconvenient to remember it. When you are tired and the competition is close and you want to be angry at the look she gave you and the words you said. Remember it then."\nAdaeze looked at her hands.\n"You are going to win this competition," her mother said. Not loudly. Not with performance. The same tone she used for facts. "You have been winning things your whole life with tools that most of these girls would not recognise as tools. You do not need to become someone else to win it."\nThe garden was bright and warm and full of noise.\n"But winning is not the only thing that will stay with you from this place," her mother continued. "What you were becoming with those girls, before the competition got inside it, that will also stay with you. Do not throw it away because it became complicated. Everything real is complicated."\nAdaeze looked at the garden. At the families on the benches. At Amara''s mother listening to her daughter with that expression from across the lawn.\n"How did you get so wise?" she said.\nHer mother made a sound that was almost a laugh. "I have been poor and I have been afraid and I have sat in rooms where I was the third bed," she said, simply. "It teaches you things."\nAdaeze looked at her.\nHer mother picked up the container and offered it to her. "Finish the plantain," she said. "I carried it from Anambra."\n\nAt three o''clock, when the visiting hours ended and the garden began to empty, Adaeze walked her mother to the school gate and they stood there for a moment in the particular way of people who have said the real things and are now finding their way back to the ordinary.\nHer mother straightened her collar again, the same gesture as the morning, unnecessary now but done anyway.\n"Study hard," she said. "Eat. Sleep."\n"The phone things," Adaeze said.\n"The phone things keep me from worrying," her mother said. "Let me have them."\nShe walked through the gate and down the road to where she had arranged to be picked up, her good dress and her good bag and her lavender oil going back to Anambra, and Adaeze stood at the gate until she could not see her anymore and then she stood there a moment longer.\nThen she turned and walked back up the path to Hibiscus House.\n\nShe pushed open the door of Room 7 to find Chisom sitting on her bed in her visiting day dress, a book open in her lap that she was not reading. The room had the specific quality of a space that had been very quiet for a long time.\nChisom looked up.\nAdaeze looked at her. The immaculate dress. The closed gate. The book that was not being read.\nShe went to the table and picked up the tin of Milo that had been sitting there since Amara put it down in the middle of the floor all those months ago, a different tin now but the same gesture carried forward, and she set it on the small clear space at the edge of Chisom''s desk.\nShe did not say anything. She sat down on the third bed and opened her textbook.\nChisom looked at the Milo tin for a moment.\n"Thank you," she said.\n"Amara brought biscuits," Adaeze said. "From her mother."\nChisom nodded. She closed the book in her lap and put it on her bedside table and reached for her notes, and the scratch of her pen began again, and outside the visiting day garden emptied, and Room 7 filled with the particular quality of two people who had not resolved everything but had decided, for now, to remain.','\n',char(10)),2679,1,1,NULL,'2026-04-01 12:31:10','2026-04-01 12:14:04','2026-04-01 12:31:10',NULL,2,6);
INSERT INTO "chapters" ("id","novel_id","chapter_number","title","content","word_count","is_premium","is_published","audio_url","published_at","created_at","updated_at","scheduled_release_at","part_number","season_id") VALUES(158,20,6,'What We Don''t Say',replace('The written examination was on Thursday and by Wednesday night the room had reached a kind of pressure that had no name but that all three of them could feel, the way you felt a change in weather before it arrived, in your joints and your chest and the quality of the air around you.\nAdaeze had been awake since four. Not studying, just awake, lying on the third bed with the ceiling above her and everything she knew arranged and rearranged in her mind, the mathematics and the reasoning and the English comprehension techniques she had been drilling for two weeks until they lived in her hands rather than her head. She was as prepared as she knew how to be. That was both the comfort and the terror of it. There was nothing left to add. She would walk into that examination room tomorrow with everything she had, and everything she had would either be enough or it would not.\nShe had never in her life considered the possibility that everything she had would not be enough.\nShe considered it now, at four in the morning, in the specific vulnerability of the hours before a thing you cannot take back.\n\nThe day went the way days went before examinations, elongated and slightly unreal, lessons that nobody was fully present for, girls moving through the corridors with the distracted energy of people whose minds were already in a room that did not yet exist. Adaeze ate breakfast and lunch with the methodical attention of someone fuelling a machine. She reviewed her notes once in the morning and put them away and did not take them out again, because she had learned long ago that the last-minute review was not for learning, it was for anxiety, and anxiety was a tax she could not afford to pay the day before something that mattered.\nShe came back to the room at four to find it empty.\nShe sat at the table and looked at the wall and let herself be still for twenty minutes, which was the closest she came to rest on days like this. Then Amara came in, and then Chisom, and the room reassembled itself around all three of them and the pressure that had been building all week came with them.\n\nIt started over nothing. That was the thing about fractures under pressure: they did not need a significant event. They needed only a small one, the right small one, applied to the right place.\nThe small thing was a chair.\nAdaeze had moved her chair slightly to the left in the afternoon to catch the better angle of the window light, and when Chisom came to the table to get her calculator from where she had left it charging, she caught her hip on the corner of the moved chair and the calculator slid from her hand and hit the floor.\nShe picked it up. She looked at the chair. She looked at Adaeze.\n"Can you not move things without saying?" she said.\nHer voice was even. Just a request. The kind of thing you said when you were tired and preparing for something important and a small inconvenience arrived at the wrong time.\nAdaeze looked at her. "It is a shared table," she said. Also even.\n"I know it is a shared table. I am asking you to say when you move things on it so I know where they are."\n"I will try to remember," Adaeze said, and went back to her notes.\nThere were four seconds of silence.\n"You will try to remember," Chisom said.\nSomething in her tone had changed. Not much. Enough.\nAdaeze put her pen down.\n"What does that mean?" she asked.\n"It means I am asking you a simple thing and your answer is that you will try."\n"It is a chair, Chisom."\n"I know what it is."\n"Then what are we talking about?"\nChisom set her calculator down on the table with a precision that was the opposite of calm. "We are talking about the fact that you do what you want in this room and you have always done what you want in this room and I have not said anything because I understand your situation and I have tried to be considerate of it."\nThe room went very still.\nAdaeze stood up slowly. "My situation."\n"I did not mean it like that."\n"How did you mean it?"\n"I meant that I know things are different for you here and I have tried to be aware of that."\n"You have tried to be aware of my situation," Adaeze said. Her voice was quiet and even and extremely dangerous in the way voices were when they were working very hard to remain quiet and even. "So every kindness you have shown me this year has been consideration of my situation. The ten o''clock food. The talking in the dark. The puff puff. That was you being considerate of the poor girl in the third bed."\n"That is not what I said."\n"It is what you meant."\n"Adaeze, I am tired, the examination is tomorrow, I caught my hip on a chair and I asked you a simple thing."\n"You asked me to remember my place," Adaeze said. "That is what you asked."\nChisom''s jaw tightened. "Nobody said anything about your place."\n"Nobody had to."\nAmara, who had been sitting motionless on her bed since the calculator hit the floor, said: "Both of you."\nNeither of them looked at her.\n"You want to say something to me," Adaeze said. "You have wanted to say it since the folder. Say it."\nChisom looked at her. The management was gone completely now, the surface and the waterline both, and what was underneath was not cold, it was something that had been heated by weeks of pressure and four days of careful silence and a hip catching a moved chair at four o''clock the afternoon before the most important examination of both their lives.\n"Fine," she said. "You want the true thing. Here is the true thing. You are the smartest person in this school and you know it and I know it and you have known it since you arrived and you have sat in this room all year being quietly, perfectly self-sufficient and letting Amara and me believe we were letting you in when the whole time you were simply allowing us to think we were needed." Her voice was controlled and precise and each word was placed deliberately. "You don''t need us. You have never needed us. You needed a room and we happened to be in it. The friendship was real for us. For you it was something you accepted because refusing it would have cost you energy you needed for other things."\nThe room was absolutely silent.\nAdaeze stood with those words in her and felt each one of them go in at its specific angle, and the reason they went in so cleanly was not that they were true. It was that they were close enough to something true that she could not immediately locate where they broke from it.\nShe was still standing there when Amara spoke.\n"That was a terrible thing to say," Amara said. Her voice was very quiet and entirely steady. She was looking at Chisom with an expression that Adaeze had never seen on her before, not angry, something beyond angry, the face of someone who had absorbed something and was deciding what to do with it.\nChisom looked at her.\n"She has been in this room with us for two terms," Amara said. "You know her. You know who she is. You have sat on her bed at ten o''clock and told her things about your father that you have told nobody else at this school and now you are standing there telling her the friendship was not real for her." She paused. "You are afraid. I understand. We are all afraid. But you are using your fear to say cruel things, and the cruelty does not become truth just because you are afraid when you say it."\nChisom said nothing.\nAmara looked at Adaeze. "Are you okay?"\n"I am fine," Adaeze said, which was what she always said, which was a reflex so old it had preceded consciousness.\nShe sat down on the third bed.\nShe looked at the wall, at the pale yellow that had been grey on the first night and that she had watched change colour in every quality of light that moved through this room over two terms, and she sat with what Chisom had said and turned it over and looked at its underside and found there what she had suspected she would find.\nFear dressed as observation. Real things mixed in with false ones, the way good lies were always built, from the materials of truth.\nShe was self-sufficient. That was true. It was not a flaw. It was what she had needed to be her entire life and she had built it as carefully as she built everything, with her own hands, out of what was available.\nHad she let them in? That was the question Chisom''s words had placed in front of her, and she sat with it now and answered it the way she answered things when she was alone, without the cushion of self-protection.\nShe had let Amara in. That she was certain of. The thing between her and Amara was real and she had not engineered it, it had arrived without her planning it, on a night with puff puff and a laugh that was too big for Amara''s frame.\nChisom was the harder question. She thought about the floor beside the bed with the letter. About the closed pharmacy with the name on the sign. About the tin of Milo she had placed on the desk after visiting day without knowing exactly why. She thought about whether those things were the acts of someone who was simply being strategically warm or whether they were something else, something that had grown in her without her permission the way things sometimes grew in the places you were not watching.\nShe thought they were something else.\nBut she could not say it now, not in this room, not with the examination tomorrow and the pressure of the past weeks still in the air. Whatever she said now would come out wrong, would come from the wrong place, would be received badly. She knew this about herself, that she needed time and quiet to find the true thing, that she did not have access to it when she was standing inside the feeling.\nShe would need to come back to it.\n\nChisom sat at her desk with her back to the room for a long time.\nWhen she finally turned around her face had the quality of someone who had been somewhere difficult and come back changed by it. She looked at Adaeze on the third bed and she looked at Amara sitting with her closed expression on her own bed and she was quiet for a moment.\n"I should not have said it," she said.\nAdaeze looked at the wall.\n"I should not have said it the way I said it. Most of it is not what I believe. Some of it is what I am afraid of." She paused. "I am afraid that it is too late. That whatever happened with the folder happened and now something between us is different and will stay different and we will all leave this school having had something and then lost it." She looked at her hands. "I am afraid that I made it happen. With the look and now with this." A pause. "I am afraid that I am more like my father than I want to be. That when I am afraid I do the thing that makes the worst outcome happen faster."\nThe room absorbed that.\nAmara exhaled. It was not quite a sigh and not quite a release, it was the sound of someone who had been holding something and was deciding to set it down for now.\n"Tomorrow is the examination," she said. "Whatever this is, it will wait one day."\nChisom nodded.\nAmara looked at Adaeze. "Adaeze."\nAdaeze looked at her.\n"Tomorrow," Amara said. Gently. Not as avoidance. As a genuinely offered pause.\nAdaeze looked at Chisom. Chisom was watching her with the open, unmanaged face she showed only in the moments when she had nothing left to defend herself with.\nAdaeze thought about what her mother had said in the garden. About remembering the heavy things other people were carrying when it was inconvenient to remember. About not becoming someone else to win.\nShe thought about the pharmacy with the name on the sign.\nShe thought about the girl on the floor beside her bed reading a letter she had hoped would say something different.\nShe picked up her pen.\n"Tomorrow," she said.\n\nAt ten o''clock nobody moved for the food.\nThey lay in their beds in the dark, all three of them awake, and the room was quiet in a new way, not hostile, not easy, something in between that did not yet have a shape. Outside the window the security light made its circle and the night moved at its own pace, indifferent to examinations and friendships and the words that sat in rooms long after the people who said them had gone to sleep.\nAmara spoke first, into the ceiling.\n"I am terrified of tomorrow," she said.\nA pause.\n"Me too," Chisom said.\nAnother pause.\n"Me too," Adaeze said.\nThree voices in the dark. Small and honest and pointed at nothing in particular.\nNobody said anything else. But the nothing that followed was different from the nothing that had come before it, and in Room 7, where small differences had always been the only kind available, different was enough.','\n',char(10)),2327,1,1,NULL,'2026-04-01 12:30:58','2026-04-01 12:15:03','2026-04-01 12:30:58',NULL,2,6);
INSERT INTO "chapters" ("id","novel_id","chapter_number","title","content","word_count","is_premium","is_published","audio_url","published_at","created_at","updated_at","scheduled_release_at","part_number","season_id") VALUES(159,20,7,'Amara Steps Back',replace('The results of the written examination went up on a Monday.\nAdaeze was in the top twenty. She was third overall, behind a girl from SS3 named Obiageli who was widely understood to be the most analytically precise student in the school, and a girl from SS2 named Hadiza who had transferred from Abuja mid-last-year and who nobody had thought to watch until now. Adaeze was third and she read the number and stood at the noticeboard and felt the particular calibration of a person who had expected to be first and was rearranging themselves around a different reality without losing their footing.\nThird was in the top twenty. Third advanced to the presentation round. Third was not the end of anything.\nShe walked back to the hostel with this knowledge held carefully.\nChisom was twelfth. She received this information with the expression of someone who had prepared for disappointment and found it slightly better than feared, which produced not relief but a new and specific determination, the look of a person who had identified exactly how much ground they needed to recover and had already begun calculating how.\nAmara was seventeenth.\n\nSeventeenth surprised all of them, including Amara.\nShe came back from the noticeboard on Monday afternoon and sat on her bed and looked at nothing for a moment, and Adaeze, who had been watching her since the corridor phone call with the particular attention of someone carrying a piece of borrowed weight, watched the expression move across her face, surprise first, then something more complicated, and then a stillness that was not the easy surface stillness Amara used for the world but something deeper and more interior.\n"Seventeen," Amara said.\n"Top twenty," Chisom said, carefully.\n"I know." Amara looked at her hands in her lap. "I didn''t expect it."\n"I did," Adaeze said.\nAmara looked at her. The complicated expression moved again.\n"You study more than you show," Adaeze said. "I have been watching since first term."\n"You have been watching me study."\n"I watch everything," Adaeze said. "You know that."\nAmara was quiet for a moment and then she almost smiled, not quite, something close. "Seventeenth," she said again, to herself, as if she were placing the number somewhere inside her and checking whether it fit.\n\nThe presentation round topic was announced on Wednesday.\nThe role of African innovation in solving African problems: argue a case, propose a solution, defend your position.\nTwenty girls. Five spots in the final. They had three weeks.\nAdaeze read the topic and understood immediately what it required. Not just research and argument but conviction, the kind that came from knowing why you were saying something and not just what you were saying. She had the what. She had always had the what. The why was the part that would either carry her into the final or expose the limit of everything she had built.\nShe went back to the room and began.\n\nWhat happened with Amara happened on a Thursday, eight days into the presentation round preparation, in the way significant things sometimes happened, without announcement or drama, quietly and then completely.\nAdaeze came back from the bathroom at six in the morning to find Amara already awake and sitting on her bed, which was unusual, and the wooden box open in her lap, which was something Adaeze had never seen.\nShe stopped in the doorway.\nAmara looked up. She did not close the box. She looked at Adaeze with the expression she wore when she had made a decision and was sitting with it, the specific quality of someone on the other side of something they had been working toward for a while.\n"Come in," she said. "Close the door."\nAdaeze came in. She sat on the third bed. Chisom was still asleep, her breathing slow and even.\nAmara looked at the box in her lap. From where she sat, Adaeze could see the inside of it now for the first time. There was a small orange prescription bottle. A folded piece of paper that looked like it had been opened and refolded many times. A photograph, small, the size that came from a printed strip, of Amara and a woman who must have been her mother, both of them laughing at something outside the frame. And a bracelet, different from the friendship bracelets Amara wore on her wrists, a plain medical alert bracelet in silver with an engraving Adaeze could not read from this distance.\n"I heard you that night," Adaeze said. Before she could stop herself. "In the corridor. After lights out. I was at the tap and I heard you on the phone with your mother."\nAmara looked at her. She did not look surprised.\n"How much did you hear?" she asked.\n"Enough." A pause. "I have not said anything."\n"I know you haven''t." She looked at the box. "I have been trying to find the right time to say it myself. There is no right time for this kind of thing. You wait for it and it doesn''t come and eventually you understand that you have to make it rather than find it."\nShe picked up the prescription bottle and held it in her palm.\n"I have a condition called lupus," she said. "Systemic lupus erythematosus. It is an autoimmune condition. My immune system attacks my own tissues." She said this with the flatness of someone who had said it enough times that the words had been worn smooth. "It is manageable. Dr. Eze is my specialist in Port Harcourt. I have been managing it since I was eleven."\nThe room was very quiet.\n"Managing means medication every day. The bottle in this box is my hydroxychloroquine. I take it every morning before anything else." She turned the bottle in her fingers. "It also means rest matters. Stress matters. Sleep matters. Eating properly matters. My body does not give me the same margin for error that other people have. When I push past what my body can carry, it tells me. Not subtly."\nAdaeze looked at her. She thought about twenty-first place first term. About I don''t know what the number is for yet. About the lightness that was not lightness. About Amara studying on the floor and on her side and upside down, which she had thought was personality and now understood was also management, that Amara had learned to work inside her body''s requirements so naturally that it looked like preference.\n"Does the school know?" she asked.\n"The school nurse has my file. Mrs. Okafor knows." She paused. "My mother made sure before I came."\n"Chisom?"\nAmara shook her head.\n"Why not?"\nAmara looked at the photograph in the box. Her mother''s face, laughing. "Because Chisom looks at people and sees what they are capable of," she said. "It is one of the things I respect about her. But I did not want to be looked at and have the first calculation be about what I could not do." She paused. "I wanted to be Amara first. The condition is part of me. It is not the whole introduction."\nAdaeze thought about this. About all the ways a person arranged themselves for a room, what they led with and what they kept back, what they protected not from shame but from the particular exhaustion of being known for your limitation before you were known for yourself.\nShe thought about ironing uniforms at 4:50 in the morning so that nobody would see her as the girl who could not afford new ones before they saw her as the girl who topped the set.\n"I understand," she said.\nAmara looked at her and the look confirmed something between them that did not need more words.\n\nShe told Chisom that evening.\nShe did it simply, sitting cross-legged on her bed after dinner with the box open beside her and Chisom at her desk, and she told it the same way she had told Adaeze, plainly and without performance, the facts in the order they needed to be in.\nChisom turned around in her chair when Amara began and she did not look away once. She sat with her hands folded in her lap and her face went through its movements, surprise and adjustment and understanding arriving in sequence, and she was quiet for a long moment after Amara finished.\n"How long have you been managing this here?" she asked. "This term, last term."\n"Both terms."\n"Alone."\n"With my mother on the phone."\nChisom looked at the box. At the prescription bottle and the folded letter and the photograph. She looked for a long time without speaking.\n"You were sick in December," she said. "The week before the end of term. You said it was malaria."\n"It was a flare," Amara said. "It can look like other things. Fatigue, joint pain, fever."\n"You were in the sickbay for two days."\n"Yes."\n"I brought you malt and you said you were fine and I believed you." Chisom said this as if she were recounting something she had made a mistake about and was now correcting the record. "You were not fine."\n"I was managing," Amara said. "There is a difference."\nChisom was quiet again. Then she uncrossed her legs from the chair and stood up and came and sat beside Amara on the bed, not at the foot the way they sometimes sat, but alongside her, close, the way you sat next to someone when proximity was the clearest thing you had to offer.\nShe looked at the box.\n"The bracelet," she said.\nAmara picked it up. Turned it so Chisom could read the engraving. Amara C. Dike. Lupus SLE. Emergency contact: 08033.\nChisom looked at it for a moment. Then she looked at Amara.\n"You should wear it," she said.\n"I know." Amara turned it in her fingers. "I wear it at home. Here I have been putting it in the box."\n"Why?"\n"Because it is a question I am not always ready to answer."\nChisom looked at her. "You are ready now," she said. Not as a command. As an observation.\nAmara looked at the bracelet. She turned it once more, and then she fastened it on her wrist beside the friendship bracelets, where it sat quietly alongside them as if it had always been there.\n\nShe withdrew from the competition the following morning.\nShe went to the admin block before breakfast and asked to speak with Mrs. Okafor and was shown in and came out fifteen minutes later. She told Adaeze and Chisom over breakfast, setting down her tray and sitting with the same ease she brought to most difficult things, as if she were reporting something that had been decided and was now simply being communicated.\n"I withdrew," she said.\nChisom put down her fork.\n"I went to see Mrs. Okafor this morning," Amara said. "I told her that I was withdrawing from the competition. She asked if I was certain. I said yes."\n"Amara," Chisom said.\n"I am seventeenth," Amara said. "In the top twenty. I could go to the presentation round and I could prepare for three weeks and I could stand in front of those judges and I might make the final five." She said this without false modesty, simply assessing the actual probability. "But I have been pushing this term at a pace that my body has been quietly protesting for two weeks, and I have been ignoring it the way I sometimes ignore it when I want something badly enough, and I know what comes after ignoring it, and what comes after is three days in the sickbay during the most important round of the competition."\nShe picked up her fork.\n"I would rather step back on my own terms than be forced back on my body''s terms," she said. "The first one is a decision. The second one is a loss."\nThe dining hall moved around them, plates and voices and the particular morning noise of three hundred girls.\n"You wanted to win," Chisom said. Her voice was careful.\n"Yes," Amara said.\n"You have been preparing."\n"Yes."\n"And you are stepping back."\n"Yes." She looked at Chisom. "I know what the prize means to you. I know what it means to Adaeze. I am not stepping back as a gift to either of you. I am stepping back because my body is where I live and I have to live there after this competition is finished, and it is telling me something I have learned not to ignore." She paused. "That is the whole reason."\nChisom looked at her for a long moment.\n"I believe you," she said.\n"Good," Amara said. "Because it is true and I have no energy for convincing people."\nAdaeze had been quiet through all of it, eating her breakfast with the steady attention she brought to things she was absorbing rather than reacting to. She looked at Amara now, at the medical bracelet on her wrist beside the others, at the open face across the table.\n"Are you okay?" she asked.\nIt was the question nobody had asked Amara yet in all of this. Not Mrs. Okafor. Not Chisom. The one that was not about the competition or the decision or the reasoning but simply about her.\nAmara looked at her. Something in her expression shifted, just slightly, the small rearrangement of a person who has been holding something and has been offered a place to set it down.\n"I will be," she said. "I need to rest properly and eat properly and stop pretending that seventeenth place was the most significant thing happening in my body this month." She looked at her food. "I will be."\n"Okay," Adaeze said.\nAmara nodded. She ate a piece of akara.\n"Now," she said, after a moment, with the quality of someone turning a page, "the two of you have a presentation to build. I have three weeks and no competition to prepare for and I am an excellent researcher and I have opinions about African innovation that would fill a library." She looked between them. "Tell me what you need."\nChisom blinked. "You want to help us."\n"I want to be useful," Amara said. "I was not built for sitting still. If I cannot compete I will assist. I will assist both of you equally, before you ask, because I am not going to spend three weeks managing who gets more of my help. You are both going to the presentation round and you are both going to be prepared and whatever happens after that is between you and the judges."\nChisom looked at Adaeze.\nAdaeze looked at Chisom.\nSomething passed between them across the breakfast table, quick and unspoken, the first thing that had moved between them freely since the folder and the chair and the words that could not be unsaid. It was not resolution. It was not forgiveness, which took longer and required more than a shared look. But it was something, a small precise recognition that they were still here, all three of them, on the same side of something even if the competition put them on opposite sides of everything else.\n"Research on East African tech innovation," Adaeze said. "I need sources from the last five years."\nAmara pointed her fork at her. "Done."\n"Agricultural financing models in West Africa," Chisom said. "Academic sources if possible."\nAmara pointed at her too. "Also done." She looked between them. "You are going to owe me enormously."\n"We know," they said, at almost exactly the same time, and the almost of it, the slight mismatch, made all three of them look at each other across the table in the bright morning noise of the dining hall, and Amara laughed first, the big one, the one too large for her frame, and Chisom''s composed expression did its losing battle, and Adaeze felt something loosen in her chest that had been tight for longer than she could precisely remember.\nOutside the dining hall windows the February morning was already warm, the compound green and bright, and the day was opening around them with its usual indifference to everything that happened inside the lives it contained.\n\nThat evening, Adaeze sat on the third bed and looked at the room they had been living in for two terms and thought about what Amara had said at breakfast. I would rather step back on my own terms than be forced back on my body''s terms. The first one is a decision. The second one is a loss.\nShe thought about her own body''s terms, which were the terms of a girl who had built endurance into every part of herself, who had learned so early and so thoroughly to push past what was hard that she had sometimes confused the pushing with the living.\nShe thought about Chisom across the room, bent over her notes with the lamp angled forward, preparing for a presentation round that she needed to win in a way that had nothing to do with pride and everything to do with a closed pharmacy and a tired mother and the particular love that expressed itself as not wanting to add to someone else''s weight.\nShe thought about the look. About the words. About what her mother had said in the garden, that what they had been becoming with each other would stay with her too, alongside whatever else happened.\nShe did not know yet whether what had cracked between her and Chisom could be repaired. She did not know whether the friendship had the kind of structure that held after a fracture or whether it would hold its shape only until you pressed on it and then show you what it was really made of.\nShe knew one thing. She was still in the room. Chisom was still in the room. Amara had the medical bracelet on her wrist and had laughed her big laugh at breakfast and was already, somewhere, pulling research on East African tech innovation because that was who she was, a person who found a way to be useful even when the original plan had changed.\nThree girls. One room. Everything complicated and some things, underneath the complication, still intact.\nShe opened her notebook and began to work.','\n',char(10)),3047,1,1,NULL,'2026-04-01 12:30:43','2026-04-01 12:16:23','2026-04-01 12:30:43',NULL,2,6);
INSERT INTO "chapters" ("id","novel_id","chapter_number","title","content","word_count","is_premium","is_published","audio_url","published_at","created_at","updated_at","scheduled_release_at","part_number","season_id") VALUES(160,20,8,'The Night Before',replace('The night before the final, nobody pretended to sleep.\nThey tried. Lights went out at the usual time, ten thirty, because the routine had become the kind of thing that held even when everything around it was shifting, and there was something in the keeping of it that felt necessary, like insisting on breakfast before a long journey. The room went dark. Three bodies settled into their beds. The compound outside was quiet in the specific way of a school that had reached the end of its term and was holding its breath.\nTwenty minutes passed.\nThen Amara said, to the ceiling: "Are either of you asleep?"\n"No," Chisom said.\n"No," Adaeze said.\nA pause.\n"Okay," Amara said. And nothing else, as if the confirmation were enough, as if knowing that all three of them were awake in the same dark was its own kind of comfort.\n\nThe final was tomorrow at ten.\nFive girls. A panel of four judges. One scholarship. It had arrived the way large things always arrived, preceded by so much anticipation that when it was finally one day away it felt both enormous and strangely ordinary, the way a door looked the same the morning you walked through it for the last time as it had looked every other morning.\nAdaeze had made the final five. Chisom had made the final five. They had learned this on the same afternoon two weeks ago, standing at the noticeboard with the controlled expressions of people who had trained themselves not to react in public, and they had walked back to the hostel without speaking and come through the door of Room 7 to find Amara already there with two cups of Milo and a packet of digestive biscuits on the floor between the beds and an expression that said she had known before they did.\nShe had not said congratulations. She had looked at both of them and said: "Sit down. Drink this. Everything else later."\nThey had sat down. They had drunk the Milo. Everything else had come later, and slowly, in the way things came in a room that had learned to hold complexity without demanding it resolve faster than it was ready to.\nThe other three finalists were Obiageli, who remained the most analytically precise person in the school, a SS3 girl named Temi who had prepared with the focused intensity of someone for whom this was also not abstract, and Hadiza, the transfer student from Abuja, who had been quiet all term and whose presentation in the second round had made the entire room go still.\nFive girls. Adaeze knew their strengths the way she knew her own, because she had watched and assessed and calculated since the noticeboard, because that was what she did, and because knowing what she was walking into was the only preparation that felt complete.\nShe lay in the dark and went through it one last time and then she stopped herself, because she had gone through it enough and going through it again was no longer preparation, it was the anxiety tax, and she had already decided she could not afford it.\nShe looked at the ceiling and tried to find the stillness she found at 4:50 in the morning before the school woke up.\nIt came, eventually. Partial, but enough.\n\n"Can I ask you something?" Chisom said. Into the dark.\nNobody answered immediately, but nobody said no.\n"When you walk in tomorrow," Chisom said, "what are you thinking about? What is the thing in your head when you stand in front of the judges?"\nA silence.\n"My mother," Adaeze said. The answer arrived before she examined it, which meant it was true. "Not because I am doing it for her. But because she is the reason I know what any of this is for. When I stand there I will know what the answer is and I will know why the answer matters and that knowing came from her."\nThe room was quiet.\n"I think about the pharmacy," Chisom said. She said it simply, the way she had learned to say the difficult things over two terms, plainly, without the management. "The sign with my name on it. The empty inside. I think about what it felt like to stand on that street and look at it." A pause. "Not to make myself sad. Because it reminds me that things that look permanent can change, and things that look lost are not always gone, and if I win tomorrow my mother has one less weight to carry and that is a permanent thing that I will have done."\nThe dark held that.\n"I think about the bracelet," Amara said.\nHer voice was different from her usual voice. Not the performing ease, not the warm social fluency, something underneath those things, the voice she had used in the corridor outside the alcove on a Tuesday night three months ago that Adaeze had not been meant to hear.\n"I think about the fact that I am in this room," Amara continued. "That I came to this school with a condition that my mother was afraid would limit everything, and I am here and I have been here and I have made it to the end of a term that included a written examination and a presentation round and a friendship that almost broke and did not quite." She paused. "I am not in the final tomorrow. But I was seventeenth. I was in the top twenty. I did that." Another pause. "I think that is the thing I will be thinking about tomorrow. While you two are in there. I will be sitting somewhere thinking about seventeenth place and what it means."\nAdaeze turned her head toward Amara''s bed in the dark.\n"It means a great deal," she said.\n"I know," Amara said. "I am starting to."\n\nThe silence that followed was the good kind, the kind that Room 7 had been learning to make since the first term, full of three different people breathing at three different rhythms, each of them inside their own version of the dark.\nThen Chisom said: "I need to say something."\nThe room waited.\n"I need to say it before tomorrow because tomorrow it will either be too early or too late and I do not want to carry it in." She was quiet for a moment. "Adaeze."\n"I am here," Adaeze said.\n"What I said. In this room, before the written examination. About the friendship not being real for you." A pause. "I have thought about it every day since I said it. I have turned it over and looked at it from every angle and every time I look at it I find the same thing."\n"Which is?" Adaeze said.\n"That I said it because I was afraid of exactly the opposite," Chisom said. "That the friendship was real for me and I could not tell if it was real for you and I did not know how to hold that uncertainty so I made it into an accusation instead. Because if I accused you of not caring then I did not have to admit how much I did." She stopped. "That is a cowardly thing. I was cowardly. And I said it to a person who has given me no reason to doubt her since the first week of first term, and I said it on the night before the most important examination of her life, and I have not said this clearly until now: I am sorry. Plainly. Without qualification."\nThe room was very still.\nAdaeze looked at the ceiling. She had been waiting for this without knowing she was waiting, and now that it was here she found that the feeling it produced was not relief exactly, more like the release of something that had been held at a particular tension, the way a muscle felt when it finally stopped working.\nShe thought about what she had said in return. The true things and the other things, the ones that had been hers and not Chisom''s to receive. The ones that had come from the pressurised container of a lifetime of standing in rooms as the third bed and being asked, implicitly and explicitly, to perform ease about it.\nShe thought about what her mother had said. You do not need to become someone else to win.\nShe thought about whether she was still becoming, in this room, the person she wanted to be. Whether the two terms had added to her or only pressurised her. Whether she had let anything in or only let it accumulate.\nShe thought about Chisom on the floor beside her bed with a letter she had hoped would say something different. About a tin of Milo placed on a desk without explanation. About the way some things did not need language because they had already been said in the register that was older than language.\n"I said things too," Adaeze said. "Things that were mine and not yours. About the uniforms and the food and the lack. Those things were true. They did not all belong in that room at that moment."\nA pause.\n"They belonged somewhere," Chisom said.\n"Yes," Adaeze said. "They did. But not at you."\nAnother pause.\n"I know that now," Chisom said.\n"I know you do," Adaeze said.\nThe dark was very quiet.\n"Are we going to be okay?" Chisom asked. She asked it without the management, without the composure, just the question, direct and a little unguarded in the way she was only in this room, in this dark, with these two people.\nAdaeze thought about it. The honest answer was that she did not know exactly what okay would look like on the other side of tomorrow, whether the friendship would hold its weight in the new configuration that the competition result would produce, whether being in the same room with someone you had come to know this deeply was easier or harder when one of you had won the thing and the other had not.\nShe thought the honest answer was also that she wanted to find out. That she was not finished with this room or with these people, that whatever she was becoming she was still becoming it, and that this place and these two people were part of the materials.\n"I think we are going to find out," she said.\nA small silence.\n"That is good enough," Chisom said.\n"It is honest," Adaeze said.\n"Same thing," Amara said, from her side of the room, and her voice had the quality of someone who had been listening to two people find their way back to each other and was glad, privately and completely, that they had managed it.\n\nAt some point Amara got up.\nAdaeze heard her cross the room in the dark, heard the soft sounds of the locker opening, and then Amara came back and sat on the floor between the three beds in the small space that had been the Milo tin''s place at the beginning of the year, and she set something down on the floor between them.\n"What is that?" Chisom asked.\n"The last of my mother''s puff puff," Amara said. "I have been saving it. I do not know why, I think I was waiting for a night that deserved it."\nThe dark was quiet.\n"It is going to be stale," Chisom said.\n"Probably," Amara agreed.\nA pause.\n"Pass it," Adaeze said.\nThey ate stale puff puff in the dark at eleven o''clock on the night before the final, sitting in their beds and on the floor between them, passing the container without being able to see it, finding it by sound and reach and the particular knowledge of a shared space learned over two terms. It was stale. It was also, somehow, still the taste of a Port Harcourt woman who was the only person in Nigeria who knew what she was doing, and it was the taste of the first night they had been in this room together and the last night they would be in it before everything changed, and Adaeze ate her piece slowly and let it mean all of those things at once.\nWhen the container was empty Amara put it aside and stayed where she was on the floor, her back against the end of her bed, her knees up, the medical bracelet on her wrist catching the faint light from the window.\n"I have been thinking about something," she said.\n"Tell us," Chisom said.\n"Whatever happens tomorrow," Amara said, "I want you both to know that this year has been the thing I did not know I needed. Coming to this school. This room." She paused. "I came here because my mother thought the structure would be good for me and because my father said it was the best school in the region and because I had run out of arguments against it. I did not want to be here." A pause. "I want to have been here. When I look back at this year from wherever I am next year and the year after, I want to have been in this room, with the two of you, doing this specific difficult thing." She stopped. "That is what I wanted to say."\nThe room absorbed it.\nChisom was quiet for a moment. When she spoke her voice was careful in the way it was when she was being precise about something that mattered. "I did not want a third roommate," she said. "When I arrived and saw two beds already taken I was relieved. I thought a third person was a complication. An unknown variable." She paused. "I was right. You are both the most complicated thing that has happened to me this year." Another pause. "I would not reduce the complication by a single day."\nAdaeze listened to them and felt the thing she sometimes felt in this room, that something was happening that was larger than any of the individual moments inside it, that the year had been building toward something that was not the competition, that the competition was only the pressure the year had used to reveal it.\n"First term," she said. "When I arrived and the room already smelled like someone else''s money. I stood in the doorway and I understood that I was late to something that had started without me." She looked at the dark where Amara was sitting on the floor. "I am glad I came through the door anyway."\nA small silence.\n"So are we," Amara said.\n\nSleep came eventually, the way it always came in this room, one of them first and then another, the breathing changing from the rhythm of wakefulness to the rhythm of something deeper, the room settling into the quiet that belonged to it alone.\nAdaeze was the last awake.\nShe lay on the third bed in the dark and listened to Chisom and Amara sleep and she thought about tomorrow and then she thought about all the days that had produced tomorrow, the ironing board and the borrowed iron and the first night and the puff puff and the corridor phone call and the folder behind the desk and the pharmacy with the name on the sign and the mother who had come from Anambra in her good dress and said you do not need to become someone else to win.\nShe thought about who she was walking into that room with tomorrow morning. Not the girl who had arrived with a Ghana-must-go bag and three thousand naira and the knowledge that she was the smartest girl in her set and the most invisible. That girl was still here, she would always be here, she was the foundation and Adaeze would not pour concrete over her for anyone.\nBut there was more now. The more was in the room with her, breathing in the dark. Two people who knew about the ironing board and the thin blanket and the things she kept in the pressurised container, who had seen her in the moments she had not planned to be seen and had remained.\nShe was not invisible in this room.\nShe had not been for a long time.\nShe closed her eyes.\nTomorrow she would walk into that hall and she would stand in front of four judges and she would say what she believed with the full weight of who she was and what she knew and why it mattered, and it would either be enough or it would not, and either way she would come back to this room afterward and Amara would have researched something and Chisom would be sitting with her notes and the room would smell like itself and she would sit on the third bed which was her bed, which had always been her bed from the moment she put her bag down on it and began to make it in a room that smelled like someone else''s certainty.\nShe held that image until it became something warm and certain and her own.\nThen she let it carry her to sleep.','\n',char(10)),2863,1,1,NULL,'2026-04-01 12:30:32','2026-04-01 12:18:04','2026-04-01 12:30:32',NULL,2,6);
INSERT INTO "chapters" ("id","novel_id","chapter_number","title","content","word_count","is_premium","is_published","audio_url","published_at","created_at","updated_at","scheduled_release_at","part_number","season_id") VALUES(161,20,9,'The Competition',replace('The hall was smaller than Adaeze had expected.\nShe did not know why she had expected something larger. She had been in this hall before, for assemblies and end of term events, and it was the same dimensions it had always been, the same rows of chairs, the same high windows that let in the flat morning light in long even strips. But she had built it in her mind over weeks of preparation into something cavernous and weighted, and standing at the door on a Thursday morning in her ironed uniform with her name on the finalists'' list, it was just the school hall, pale walls and wooden floor and four judges sitting behind a long table at the far end.\nShe went in.\nThe other four finalists were already seated in the chairs arranged in a short row to the left of the judges'' table, facing the small raised platform that would be each girl''s ground for the next three hours. Obiageli was in the first seat, straight-backed, her notes on her knee in a folder that she was not consulting because she did not need to. Temi was in the third seat with her eyes closed and her hands flat on her thighs, which Adaeze recognised as a breathing technique. Hadiza was looking at the judges'' table with the measured attention of someone conducting a final assessment. Chisom was in the second seat.\nShe looked up when Adaeze came in.\nThey looked at each other across the hall in the way they had been looking at each other since the night before, the look that had something new in it, not the managed assessment of competitors and not the fractured careful thing of the past weeks, but something that had been cleared of most of its debris by the dark and the stale puff puff and the things said plainly before sleep.\nAdaeze took the fifth seat.\n\nThe format was simple.\nEach finalist would take the platform for twenty minutes. Ten minutes of prepared presentation on the topic, which they had submitted in outline form two weeks ago. Ten minutes of questioning from the judges, who had the outline and had prepared their own interrogations of it. The judges would deliberate after all five presentations and the result would be announced before the end of the school day.\nMrs. Okafor sat in a chair against the wall, not at the judges'' table, watching the room with the unhurried attention she brought to everything. She had greeted the girls when they came in with the simple warmth of someone who had already decided to be proud of them before the results. She had said: "Whatever you prepared, trust it." Then she had sat down and become part of the watching.\nThe hall filled quietly. Staff members. Prefects. A small group of senior girls who had been given permission to observe. Adaeze heard them come in without turning around.\nThe first judge introduced the panel. Two university professors, one from UNN and one from Nsukka, both with the particular attention of academics who had agreed to sit on a panel because the question interested them genuinely. The third was the Hallmark Foundation representative, a woman in her forties with reading glasses and a yellow blazer, who looked at the finalists with the expression of someone who had been doing this long enough to know what she was looking for and was curious whether she would find it today. The fourth was Mrs. Okafor''s predecessor, the retiring principal, a small man named Mr. Emeka who had the eyes of someone who had watched thousands of girls become themselves and was still interested in the process.\nObiageli went first.\nShe was, as she had always been, precise. Her argument was structured with the kind of rigour that came from a mind that organised information the way other minds breathed, automatically and without visible effort. Her ten minutes were the ten minutes of someone who had earned her place at the front of the room and knew it, not arrogantly, simply factually. The judges questioned her for ten minutes and she answered with the same rigour, finding the weak points in their challenges before they had fully articulated them and addressing them without being asked to.\nShe sat down to the kind of quiet that was a form of applause.\nChisom went second.\nShe walked to the platform with her notes in her hand and set them on the small lectern and did not look at them once. Adaeze watched her stand in front of the judges with the particular stillness that had been Chisom''s signature since the first week of first term, and she understood that she was watching Chisom do the thing she had been built to do, the thing that all the managing and composing had been in service of, bringing her full self to a room that required it.\nHer argument was about agricultural innovation across the Sahel, specifically about small-scale water harvesting techniques developed by communities in northern Nigeria and Niger that had been overlooked by institutional funders because the scale was too small to fit standard development frameworks. She argued that the innovation cycle in Africa was not broken, it was simply invisible to the people with the power to fund it, and that the solution was not to change the innovation but to change the lens.\nIt was the best argument Adaeze had heard her make. It had Chisom''s signature precision but it also had something underneath it that her classroom work sometimes lacked, a groundedness, a sense of the person behind the argument caring about it for reasons that went past intellectual interest. The judges felt it. Adaeze could see them sit forward slightly, the particular posture of people who are being reached.\nThe questioning was sharp. One of the professors challenged her framework directly, suggesting her evidence base was too narrow for the claims she was making. Chisom did not retreat. She expanded, pulling in examples she had not included in the presentation with the ease of someone who had prepared far more than she had shown, and the professor nodded once, the specific nod of someone who has received a satisfying answer, and moved to the next question.\nChisom sat down and looked straight ahead and her face was its usual managed surface and underneath the waterline Adaeze could see everything.\nTemi went third. Hadiza went fourth. Both were strong. Temi had a fire in her presentation that the judges responded to even when they challenged it. Hadiza was perhaps the quietest of all of them but her argument about pan-African renewable energy infrastructure had a structural elegance that was its own form of force.\nThen Adaeze stood up.\n\nShe had known her argument for three weeks. She had tested it against Amara''s research and Amara''s questions and against the particular quality of pushback that Amara applied when she thought something was not quite right, the honest skepticism of a person who was not competing but was helping and therefore had no reason to be gentle. The argument was solid. She was certain of it.\nShe walked to the platform and stood behind the lectern and looked at the four judges.\nThe hall was very quiet.\nShe began.\nHer argument was about educational innovation specifically, the gap between the solutions African governments proposed for educational access and the solutions that the communities who needed access were already generating themselves. She had examples from Lagos, from rural Zambia, from a community in eastern Uganda that had built a functional secondary school curriculum entirely from locally available materials and WhatsApp voice notes after the nearest government school closed. Her argument was that the most sophisticated educational innovations on the continent were not happening in institutions but in the spaces between them, in the places where official solutions had not arrived and so people had built their own, and that the failure was not imagination but visibility, and the question was not how to generate innovation but how to make what already existed legible to the people with resources to scale it.\nShe made the argument cleanly, with the evidence stacked in the order she had determined weeks ago, and she felt herself moving through it with the ease of someone covering familiar ground, and she was in the eighth minute when one of the professors raised his hand.\nShe paused.\n"Before your time is up," he said, "I want to ask you something not in your outline." He looked at her over his glasses. "Your argument centres on visibility. On making local innovation legible to external institutions. You argue this as an abstract policy question." He paused. "Is it abstract for you?"\nThe hall was still.\nAdaeze looked at him.\nShe understood the question completely. She understood what he was offering her, which was a choice. She could continue in the register she had established, precise and well-sourced and intellectually rigorous, and give him an answer that was true but managed, the way she had been giving managed answers her whole life to rooms that she was not certain were safe enough for the unmanaged ones.\nOr she could say the actual thing.\nShe thought about what her mother had said in the garden. You do not need to become someone else to win.\nShe thought about the third bed. About being the most invisible girl in her set. About ironing her uniforms at 4:50 in the morning so that the first thing anyone saw when they looked at her was not her lack but her work.\nShe thought about Amara saying, I would rather step back on my own terms than be forced back on my body''s terms.\nShe thought about Chisom''s argument, which had been strong not just because the framework was rigorous but because the person making it cared about it for reasons that were real and visible.\nShe thought about eight months of making herself invisible and what it had cost and what it had protected and whether the protection had always been worth the cost.\nThe hall waited.\n"No," she said. "It is not abstract."\nShe looked at the professor and then she looked at the other judges and then she looked at the room, and she understood that what she was about to do was the thing she had been practicing for without knowing it, not in the library or at the ironing board or at the table with her second-hand textbooks, but in Room 7, across two terms, with two girls who had seen her in the unmanaged moments and had not left.\n"I am a scholarship student," she said. "The scholarship that brought me to this school is the reason I am standing here. My family could not have afforded the fees." She said it evenly, without performance in either direction, not making it small and not making it large, just placing it in the room as what it was. "I have spent this year in a school that was not built for someone with my economic background, and I have learned many things this year, but one of the things I have learned is that I came in carrying innovations my institution did not have a framework for seeing."\nThe hall was very quiet.\n"I knew how to study without electricity," she said. "I knew how to maintain a uniform on no budget for an entire academic year. I knew how to learn from teachers I respected and from teachers I did not, because I had not had the option of selecting only the ones who served me well. I knew how to be productive inside scarcity in ways that my peers who had not experienced scarcity did not yet know." She paused. "These are not deficits. They are capabilities that my institution registered as absence and not as presence, because the framework for seeing them did not exist here." Another pause. "That is precisely the problem my argument addresses. Not as an abstraction. As my own life."\nThe silence held.\nThen the woman in the yellow blazer leaned forward and said: "What would the framework for seeing those capabilities look like, if you were to design it?"\nAnd Adaeze, who had spent her entire life preparing for questions like this without knowing they were coming, answered.\n\nShe answered for six minutes. The judges asked three follow-up questions. She answered all of them from the same place she had found when she decided to say the actual thing, the place where the argument and the person making it were the same rather than the argument being held in front of the person as a shield.\nWhen she sat down the hall was quiet in a way that was different from Obiageli''s quiet, which had been the quiet of impressed respect. This was something else. She did not try to name it. She sat in her chair and looked straight ahead and breathed and felt the full cost and the full rightness of what she had just done moving through her simultaneously.\nChisom was looking at her.\nAdaeze looked back.\nChisom''s expression was the open, unmanaged one. The one that appeared only in the dark of Room 7 and in the moments when she had nothing left to arrange her face around. It held, briefly, something that was not competition and not admiration and not quite either of the things Adaeze had a word for.\nThen Chisom looked away and they both looked at the judges'' table and waited.\n\nThe deliberation took forty-five minutes.\nThe five of them sat in the hall while the judges went into the adjoining room and the staff members talked quietly among themselves and the senior girls in the back rows whispered with the particular urgency of people processing something. Mrs. Okafor sat against the wall and looked at nothing and her expression was the expression she had worn since the beginning of this, the one that said she had already found what she came looking for and the result was a separate matter.\nNobody spoke among the five finalists. They had passed beyond the point where small conversation was available. They sat in their row with their individual silences and the hall held them, and outside the high windows the late morning was bright and ordinary.\nAdaeze sat with her hands in her lap.\nShe had said the true thing. Whatever came next, that was done and it was hers, not a performance of herself for the benefit of the room but an actual offering of the thing she was, brought to the precise place it was most relevant and given without apology.\nShe thought about her mother ironing at the kitchen table back in Anambra. About the lavender oil on the windowsill.\nShe thought about Amara sitting somewhere on the compound right now, not in this hall, resting the way she had been resting all week with the particular discipline of someone who had learned to take their body''s requirements seriously, and probably reading something, and probably taking notes in the small book from her pillowcase.\nShe thought about Chisom sitting two seats to her left, still and composed, and about the pharmacy with the name on the sign, and about what it meant to want something for someone else''s sake as much as for your own.\nShe sat with all of it and she waited.\n\nThe judges came back.\nThey took their seats. The room went completely silent.\nThe woman in the yellow blazer looked at the five girls and she did not build toward it. She said the name directly, the way significant things sometimes arrived after all the preparation, simply and without ceremony.\n"Adaeze Obi."\nThe hall exhaled.\nAdaeze sat completely still for one second. Two. The name sat in the room and she let it be there, in the room, in front of everyone, visible.\nThen she stood up.\nShe walked to the judges'' table the way she walked to the ironing board at 4:50 in the morning, without hurry, with the uprightness that was hers and had always been hers, across the wooden floor and the strips of morning light, and she shook the woman''s hand and she shook each judge''s hand and she turned around and faced the room.\nShe did not look for Chisom immediately. She looked at the room, at the staff members and the senior girls and Mrs. Okafor against the wall, at the hall that was the same dimensions it had always been and had still managed to be the largest room she had ever stood in.\nThen she looked at Chisom.\nChisom was sitting very straight in her chair. Her expression was the managed surface, the careful composure, and underneath it the waterline was moving. She looked at Adaeze and something passed across her face, complicated and real, the whole weight of it, what this moment cost her and what she felt about the person standing at the front of the room, both things present and neither of them cancelling the other out.\nThen she nodded.\nOnce. Small. Direct.\nThe kind of nod that meant something specific between two people who had been in the same room long enough to know each other''s language.\nAdaeze held it for a moment.\nThen she nodded back.','\n',char(10)),2896,1,1,NULL,'2026-04-01 12:30:15','2026-04-01 12:19:22','2026-04-01 12:30:15',NULL,2,6);
INSERT INTO "chapters" ("id","novel_id","chapter_number","title","content","word_count","is_premium","is_published","audio_url","published_at","created_at","updated_at","scheduled_release_at","part_number","season_id") VALUES(162,20,10,'The Third Bed',replace('The room smelled like itself now.\nThat was the first thing Adaeze noticed when she came back to it alone, in the hour between the announcement and the evening meal, needing the particular quiet of a space that had held her all year before the rest of the day required her to be present in the way that winning required you to be present. Not the fabric softener and glass-bottle lotion of the first day, not someone else''s certainty arranged on shelves that had not yet learned her shape. Something that had accumulated over two terms from the combination of three girls living inside it, Amara''s shampoo and Chisom''s body lotion and the particular smell of ironed cotton that lived in the air near Adaeze''s side of the room and that she had stopped noticing months ago and was noticing now because she was paying the kind of attention you paid to things you were about to lose.\nShe sat on the third bed.\nThe springs gave their small familiar complaint.\nShe sat with her hands in her lap and looked at the room the way you looked at something you wanted to keep exactly as it was, knowing you could not, knowing the keeping was not in the looking but in something that had already happened, something laid down in the past months that no ending could reach back and revise.\nShe had won.\nShe sat with that too, the way she had learned over two terms to sit with things that were too large for immediate processing, letting them be present without demanding that she feel them in any particular way. The scholarship was real. The four years were real. The fees and the accommodation and the stipend that meant her mother would not have to sit at the kitchen table with a notepad and add and subtract in silence, that was real, it had happened, it was now a fact about her life that could not be taken back.\nShe pressed the back of her hand against her mouth the way she had done on the night of the first term results, and in the empty room she let her eyes do what they needed to do, briefly and privately, before the world outside the door required her again.\n\nAmara arrived first.\nShe came in without knocking, which was how they all entered this room now, and she sat down beside Adaeze on the third bed without saying anything, and the two of them sat there together in the afternoon light and Amara put her head briefly on Adaeze''s shoulder and Adaeze let her, and they stayed like that for a moment in the particular silence of two people who had said most of the important things and did not need to say them again.\n"How do you feel?" Amara asked.\n"I don''t know yet," Adaeze said. "I keep finding out in pieces."\n"That''s how it is with the big things," Amara said. "You think you''ll feel one clear thing and instead it''s ten things at the same time and most of them contradict each other."\n"Yes," Adaeze said. "That is exactly what it is."\nAmara lifted her head and looked at the room. At Chisom''s side, the cream duvet and the organised desk and the family photograph that had appeared on the bedside table sometime in the second term, Chisom''s mother and Chisom at what looked like a graduation, both of them with the same fine-boned quality, the same particular way of occupying space.\n"She''s at the field," Amara said. "I saw her on the way here. She needed to walk."\nAdaeze nodded.\n"She will come back," Amara said. Not as reassurance. As information.\n"I know," Adaeze said.\n\nShe came back at half past four.\nThe door opened and Chisom came in and she had been walking long enough that her composure had returned, not the managed surface kind but the real kind, the composure that came from having moved through something and arrived at the other side of it still standing. She looked at Adaeze on the third bed and at Amara who had moved to her own bed and was reading with her feet up, and she set her bag on her chair and sat on her own bed and faced the room.\n"I walked to the bottom field and back three times," she said.\n"We know," Amara said, without looking up. "The JS1 girls think you are training for the athletics team."\nSomething moved in Chisom''s face. Not quite a smile. The architecture of one.\n"Adaeze," she said.\n"Chisom," Adaeze said.\nThey looked at each other across the room that had held all of their private things and all of their difficult things and all of the things that had surprised them about themselves and each other.\n"You won," Chisom said.\n"Yes."\n"You said the true thing in there," Chisom said. "In front of everyone. The thing about the scholarship and the capabilities that looked like absence." She paused. "I watched you decide to say it. I saw the moment you made the choice."\nAdaeze was quiet.\n"That was not a small thing," Chisom said. "I need you to know that I saw it."\nAdaeze looked at her. "I know you saw it. You were the person I knew could see it."\nSomething in Chisom''s expression shifted, the particular movement of a person receiving something they had not known they were waiting for.\n"You deserved to win," she said. Not easily. The way honest things were said, with the weight of what they cost still visible on them. "You have deserved it since before the competition existed. I want you to know that I know that."\nAdaeze sat with that for a moment. The cost of it on Chisom''s face. The reality of what it had taken to say it.\n"Your argument was the best framework in that room," Adaeze said. "The agricultural water harvesting. The way you argued visibility over innovation. I listened to it and I thought: she understands the real problem." She paused. "You understand the real problem because you have learned this year what it is to see something you cannot afford to lose."\nChisom looked at her. Her jaw worked briefly. The waterline was working hard.\n"I am not going to stop," she said, after a moment. "I am going to find another way to do what the scholarship would have done. I don''t know what it is yet. But I am not the kind of person who stops."\n"I know that," Adaeze said.\n"I know you know it," Chisom said.\nAmara turned a page without looking up. "I am sitting right here," she said, "and I want it noted that I am being very restrained about how much I am crying."\nThey both looked at her.\nHer face was entirely dry. Her expression was the performing-ease one, almost.\n"Amara," Chisom said.\n"I said restrained," Amara said. "I did not say successfully."\n\nThey called their parents that evening from the common room, taking turns at the shared phone, standing in the queue in the ordinary way of scholarship girls while the others used their personal phones from their rooms. Adaeze went last because she wanted the conversation to be unhurried and she knew from the queue how long the other calls were taking and she calculated accordingly.\nHer mother answered on the second ring.\n"Adaeze."\n"Mama."\nA silence of two seconds in which her mother was doing something, Adaeze knew the sound of it, the particular quality of someone who was controlling their breathing in the way her mother controlled it when she was trying not to cry from happiness.\n"Tell me," her mother said.\n"I won," Adaeze said.\nThe silence that followed was not empty. It was the fullest silence Adaeze had heard in a long time, her mother on the other end of a phone line in Anambra in the kitchen with the lavender oil on the windowsill, and Adaeze in a school corridor in Enugu that had become, improbably and permanently, part of the landscape of her life.\n"I knew," her mother said finally. Her voice had done the thing Adaeze rarely heard it do, it had lost its precise management, it was simply a voice, her mother''s voice, speaking without the layer of composure it usually wore.\n"I said the true thing, Mama," Adaeze said. "In front of everyone. About the scholarship and the school and what I came in knowing."\nA pause.\n"Good," her mother said. Simple, absolute. "Good."\n"I thought about you when I said it," Adaeze said. "About what you said in the garden. About not becoming someone else."\n"You have never needed to become someone else," her mother said. "You needed to understand that what you already were was enough. That is a different lesson and it takes longer and it costs more." A pause. "You learned it."\n"I am still learning it," Adaeze said.\n"Yes," her mother said. "You will be learning it for the rest of your life. That is not a failure. That is just what it is to know something true."\nThey talked for eleven minutes, which was longer than the standard queue allowed but nobody behind her said anything, which she understood only later was because the common room had gone quiet in the way rooms went quiet when something private was happening in them that the people inside recognised as something they should not interrupt.\n\nThat night, at ten o''clock, they sat on Chisom''s bed.\nAll three of them, the way they had sat on the first night of second term before the competition was inside the room, before the folder and the chair and the words that could not be unsaid. Chisom''s duvet was under them and the room was dark except for the small light from Amara''s phone screen that she had turned face-down after a minute because she did not need it.\nChisom''s package had arrived that afternoon. The regular one, packed by Ifeoma, the chocolate and the chin chin and the peanut butter. She had opened it when they came back from calling their parents and she had set it in the middle of the bed with the particular gesture of someone who had understood by now that the gesture itself was a form of language.\nThey ate in the dark.\n"My father called," Chisom said. Not to either of them specifically. To the room. "He heard from my mother. He said he was proud." She paused. "He called himself. Not through Ifeoma. He called from his personal number and he said Chisom, your mother told me. I am proud of you." Another pause. "That is the first time he has called me from his personal number this term."\nThe room was quiet.\n"That is something," Amara said.\n"It is small," Chisom said.\n"Small things are still things," Adaeze said.\nChisom was quiet for a moment. "Yes," she said. "They are."\nAmara ate a piece of chocolate. "My mother cried," she said. "When I told her I had withdrawn. Not sad crying. She said, Amara, you listened to your body and I have been trying to teach you that for three years. And then she cried." She paused. "She is going to cook the whole Port Harcourt woman puff puff recipe herself at home this holiday. She said she is going to learn it properly."\n"Tell her to send some," Chisom said.\n"I have already told her," Amara said.\nOutside, the compound was doing its usual quiet, the security light making its circle on the path below, a moth or several months going around and around the same loop. The corridor was settled, the school breathing in its night rhythm, three hundred girls in their beds or near them.\nIn Room 7 three girls sat on one bed and ate in the dark and let the evening move at its own pace around them.\n\nAdaeze thought about the beginning.\nThe doorway. The room that had smelled like someone else''s money. The two beds already made, the peach duvet and the grey fitted sheet, the stuffed bear placed with the certainty of someone who knew exactly what they were doing. The third bed with the school-issued linens still folded on the bare mattress.\nShe had stood in the doorway and understood, without anyone saying a word, that she was late to something that had started without her.\nShe thought about what had happened after that. The ironing board and the borrowed iron. The puff puff in the dark. The first real laugh. Chisom''s father''s letter and the pharmacy with the name on the sign. Amara''s voice in the corridor at half past nine, stripped to its underneath. The folder behind the desk. The look. The chair. The words that had come from the pressurised container of a lifetime of standing in rooms as the third bed.\nThe visiting garden and her mother in the good dress. The Milo tin on the desk.\nThe stale puff puff on the last night before everything changed.\nShe thought about all of it and understood that this was what her mother meant when she said something would stay with her from this place alongside whatever else happened. Not the scholarship, though the scholarship was real and significant and would change the course of her life in ways she would be discovering for years. Not the competition result and not the examination scores and not the first place at the end of first term.\nThis. The room. What had been built in it by three girls who had not planned to build anything, who had simply been put in the same small space and left to figure out who they were to each other, and had found, through all the fracturing and the silence and the hard honest things, that they were something.\n\nAmara fell asleep first.\nShe listed sideways on the bed, her head finding Chisom''s shoulder the way heads found things when sleep arrived before propriety could intervene, and Chisom looked down at her with an expression that had nothing managed about it, just Chisom looking at someone she had come to know and finding it unremarkable and essential in equal measure, and she did not move.\nAdaeze watched this and felt the warmth of it without needing to name it precisely.\n"Go to your bed," Chisom said softly, not unkindly. "Before you fall asleep here too."\n"I am awake," Adaeze said.\n"You are almost awake," Chisom said. "There is a difference."\nAdaeze almost smiled. She climbed off the bed carefully, not waking Amara, and crossed the room to the third bed and sat down on it and the springs gave their complaint and it sounded, in the quiet, like something she had heard so many times it had become part of the room''s voice.\nShe looked at her uniforms on the chair. Freshly ironed, same as always, ready for tomorrow. The last day of term. She would pack her bag after breakfast and her mother would send someone to collect her and she would leave this school for the holidays and come back next term to a room that might be this one or might be different and to two people who would be in their own rooms wherever those were, and the thing they had built this year would exist in a different form, distributed rather than contained, carried rather than shared.\nShe did not know yet what shape that would take. She was learning to hold that uncertainty the way she was learning to hold most things, without demanding that it resolve into certainty before she was ready.\nShe lay down.\nThe ceiling was the same pale yellow it had been on the first night. The security light made its circle on the path below. Chisom''s breathing went slow and even from across the room, Amara''s already there alongside it.\nAdaeze looked at the ceiling and let herself feel all ten of the contradictory things at once, the way Amara had said the big things arrived, and she did not try to arrange them into a single clean feeling because they were not a single clean feeling, they were a year, and a year was not one thing.\nShe thought about the girl who had stood in the doorway with a Ghana-must-go bag and understood she was late to something that had started without her.\nShe had not been late. She understood that now. She had arrived exactly when she arrived, and what she had found was not a room that had started without her but a room that had been waiting, in the way rooms waited, for the full set of people who would make it what it was supposed to be.\nShe had taken the third bed.\nShe had made it.\nShe had made it hers.\n\nTomorrow she would pack her bag. Her textbooks, second-hand, brown-paper covered, filled now with her own handwriting in the margins. Her uniforms, ironed, each one maintained across a whole year into something that looked new because she had decided they would. The torch. The Vaseline. The container of Geisha soap.\nAnd the things that had no physical form, that could not be packed because they had already been stored somewhere more permanent. Her mother''s voice saying you do not need to become someone else. The corridor phone call that had taught her that strength and secrecy were not the same thing. The look Chisom had given her from two seats away in the competition hall, the nod that meant something specific, the language of people who had lived close enough to build one.\nShe would carry all of it.\nNot as weight. As material. The kind you built things from.\nShe closed her eyes and the room breathed around her, the room that smelled like itself now, and she let it carry her the way she had let it carry her across two terms, into the particular darkness that came before morning, into the sleep that waited on the other side of everything the day had been.\nShe was here.\nShe had always been here.\nIt had always been enough.','\n',char(10)),3037,1,1,NULL,'2026-04-01 12:30:06','2026-04-01 12:20:45','2026-04-01 12:30:06',NULL,2,6);
INSERT INTO "chapters" ("id","novel_id","chapter_number","title","content","word_count","is_premium","is_published","audio_url","published_at","created_at","updated_at","scheduled_release_at","part_number","season_id") VALUES(163,21,1,' Three Hours',replace('The lights went out at 7:43 p.m., and Kemi heard herself say a word she would never say in front of her mother.\nThe library dropped into blackness so complete she couldn''t see her hand when she raised it. Somewhere to her left, a chair scraped. A phone torch blinked on, and in its thin white beam, she saw him.\nTobenna Okafor. Three rows across for two years, and about as familiar to her as a piece of furniture.\n"Sorry," he said, swinging the light away from her face. "I didn''t know anyone else was here."\n"I didn''t either."\nThey both looked toward the library door. Through the frosted glass panel, the corridor was dark. The generator usually kicked in within minutes. St. Helena''s had two of them; the school newsletter mentioned this with the pride of someone listing military assets.\nFive minutes passed. Then ten. The generator did not kick in.\nKemi pulled out her own phone. Dead. She had meant to charge it during afternoon break and had spent the break arguing with Adaeze about something she could no longer remember. She stared at the black screen and felt the specific misery of a problem entirely of her own making.\n"Mine is at twelve percent," Tobenna said. He was still three rows over. She could see him now that her eyes had adjusted, a shape more than a person, his phone face-down on the table to preserve it. "We could share if you need light."\n"Share how?"\n"Put it in the middle. We both move closer."\nIt was a practical suggestion. That was the thing she remembered afterward, that it was practical first, and that was why she said yes.\nShe gathered her notes and her textbook and her pencil case and moved to the table between them. He moved to the same table from the other side. They set his phone torch pointing upward in the middle and it threw a pale cone of light toward the ceiling, enough for reading if you leaned in.\n"I''m Tobenna," he said.\n"I know." She opened her textbook. "Kemi."\n"I know."\nFor a while they studied. Or attempted to. Kemi''s Economics notes kept sliding off her lap and she kept catching them, and the silence between them had a texture she didn''t like, dense and self-conscious, the silence of two people who are very aware of being in a silence.\n"How are you finding the Macro section?" he asked, not looking up.\n"Like it was designed by someone who has never needed money."\nHe looked up then. He had a face that did things in layers, like his reactions needed a second to clear immigration before they reached the surface. Then he laughed, quiet and sudden.\n"I''ve been staring at the same paragraph for forty minutes," he said. "The one about fiscal policy."\n"Which one? They are all the same paragraph written in slightly different font."\nHe laughed again, longer this time, and Kemi felt something loosen between them, some taut invisible thing going slack. She pulled her notes closer and they began to talk the way you only talk when you cannot go anywhere, when the door is locked and the lights are out and there is nothing to do but be present.\nHe told her he found schoolwork easy but found the idea of it pointless, which she understood in a way she had never said aloud to anyone. She told him she found the idea of school useful but the work exhausting, and he said that was almost the opposite problem, and they were both quiet for a moment considering that.\nShe told him about Canada. It came out quickly, without drama, the way things come out when you have been holding them long enough that they stop feeling heavy.\n"End of term," she said. "My mum got a residency position. We''ve known since January."\nTobenna was quiet. In the phone light his expression moved through something she couldn''t name.\n"Does it feel real?" he asked.\n"Sometimes. When I think about the cold, mostly."\n"Not when you think about leaving school? Your friends?"\nShe looked at him. "Not really. Is that bad?"\n"I don''t know. Maybe it means you were already half gone."\nIt was not a cruel thing to say. It was an accurate thing to say, and Kemi felt the accuracy of it land in her chest, the particular ache of being correctly seen by someone who had no reason to know her.\nShe asked why he was in the library this late. Students were allowed to stay until eight on revision nights, but most didn''t because the AC on the upper floor was broken and the library felt like revising inside a pot of egusi soup.\n"I needed somewhere quiet," he said. Then, after a pause: "My family is moving to Kano."\n"When?"\n"End of term."\nThey looked at each other.\nIt should have been a strange moment, maybe even funny. Two people discovering they were both about to disappear from the same place at the same time. But it was not strange and it was not funny. It settled between them with the weight of something that mattered, quiet and specific and impossible to explain to anyone who had not been sitting in that exact darkness.\nThe lights came back at 10:19.\nThe fluorescent tubes stuttered and then blazed and the library was suddenly enormous again, full of corners and space and the distance between tables. Kemi blinked. She could see him properly now: the shape of his collar, the pen ink along the side of his hand, the way he looked at her the moment the light returned, quickly, like he was confirming something.\nShe packed her books. He packed his. At the door they paused in the way of people who have shared something they did not plan to share and do not yet know what to do with it.\n"Same time tomorrow?" he said. "For revision."\nKemi looked at him and understood that he did not mean revision.\n"Same time," she said.\nShe walked out first. In the corridor, the lights were cold and steady and completely ordinary. She kept her face neutral all the way to the school gate, and she let herself feel it only after.','\n',char(10)),1048,0,1,NULL,'2026-04-23 10:55:34','2026-04-04 12:58:24','2026-04-23 10:55:34',NULL,1,NULL);
INSERT INTO "chapters" ("id","novel_id","chapter_number","title","content","word_count","is_premium","is_published","audio_url","published_at","created_at","updated_at","scheduled_release_at","part_number","season_id") VALUES(164,21,2,'Daylight',replace('Kemi had rehearsed three different ways to behave by the time she reached the classroom door, and she walked in and immediately forgot all of them.\nTobenna was already seated. He was in the second row near the window, which she had always known without ever letting herself admit she knew it, and now that knowledge sat differently, like something that had shifted two inches overnight and was pretending it had always been there. He was reading. Or holding a book open while staring at a fixed point slightly above the page. She watched long enough to confirm the page had not turned, and then she looked away, and the looking away took more effort than it should have.\nAround her, the classroom was filling. Chairs scraped. Bags dropped. Two boys near the back were deep in an argument that had clearly carried over from yesterday, and a girl near the window was sharing earphones with her neighbour. None of it registered.\nShe sat down and arranged her books with more precision than they required. Adaeze landed in the seat beside her, already speaking.\n"You heard about the generator?" Adaeze said. "The new maintenance man forgot to fuel both of them. Three hours, Kemi. Three full hours. Mr. Coker is apparently threatening to dock his entire salary."\n"I heard something about it."\n"Were you still in school? I left at six, thank God. I would have been stranded in that corridor crying."\n"I left before it happened," Kemi said.\nAdaeze looked at her with the particular expression she reserved for situations she suspected were more interesting than they appeared: chin dropped, eyes doing the actual work. Kemi had known Adaeze since JS2. The correct response was to offer nothing additional and let the suspicion die for lack of evidence.\n"You look tired," Adaeze said finally, and turned to greet someone near the door.\nKemi exhaled and opened her Government textbook.\nMr. Adisa arrived nine minutes late with a damp cardboard box of past papers. The papers were wavy at the edges, translucent at the corners. The ceiling fan above the window turned with the slow reluctant motion of something that had not been serviced since the last administration. Half the class made noise about the state of the papers. Kemi used the distraction to look up.\nTobenna was not looking at her. He was writing in the margin of his textbook with the focused expression of someone who was either genuinely engaged or working very hard to appear that way. She looked back at her past paper. Question one was a twelve marker on the structure of Nigeria''s federal system. She read it three times and absorbed nothing.\nShe established a rule somewhere in second lesson: eyes on the teacher, pen moving, no glancing toward the window row. The rule held through Biology. It held through the first half of Further Maths. It collapsed entirely during Economics, the last lesson before break, which required the class to rearrange into discussion groups of four.\nThe rearrangement was the specific kind of chaos that Nigerian classrooms produced when nobody wanted to move without first negotiating. When it settled, Kemi looked up from her bag and found Tobenna two seats away. Chisom had assembled the nearest cluster without seeking permission, which was how Chisom moved through the world, and now there were four of them around two pushed together desks: Kemi, Adaeze, Chisom, and Tobenna.\n"Aggregate demand," Chisom said. She always opened group work whether or not she had been appointed. "Who actually did the reading?"\nSilence.\n"Tobenna. You''re good at this. Start."\nHe explained it without performance, the way someone explains a thing they understood long ago and have since made entirely their own. He said demand was not simply wanting, that it required purchasing power behind the desire, which meant most of what people wanted technically did not count. He talked about the distance between planned spending and actual spending, and then he said, "The intention is never the same thing as the outcome," and looked directly across the desk at her. Not at the group. At her. For the length of one sentence only.\nKemi wrote the line down in her notes. She didn''t need to. She wrote it anyway.\nThe bell rang. She stood and gathered her things with the efficient speed she had built over three years of St. Helena''s transitions. She walked with Adaeze toward the door and she was almost through it when she heard her name.\nShe wasn''t entirely certain she had heard it. She slowed anyway.\n"Kemi."\nShe turned. Adaeze had dissolved into the corridor. Tobenna was standing at the window, the one that faced the assembly courtyard, and the morning light came in flat across the left side of his face.\n"I wasn''t sure," he said, "if yesterday was just yesterday."\nShe understood the question. Whether the library was an event that ended when the lights came back on, or something that had followed them both into the ordinary morning without either of them choosing it. The difference was not small. She had not yet let herself decide which answer she wanted.\nShe stood in the doorway. She thought about Canada, and Kano, and twelve weeks, and every reasonable argument for nodding once and walking away cleanly. She did not move.\n"I still owe you three percent of your battery," she said.\nShe didn''t wait to see what his face did with that.\nShe turned and walked into the corridor, into the heat and the noise of break time, the hallway suddenly full of movement and raised voices, and the smell of meat pies rising from the tuck shop two floors below. She did not look back.\nShe heard him laugh anyway. Short and quiet, the sound of someone who had not needed the last word and had gotten something better without trying. She carried it all the way to the stairwell before she let herself fully register that it was there.','\n',char(10)),999,0,1,NULL,'2026-04-23 10:56:40','2026-04-05 05:01:07','2026-04-23 10:56:40',NULL,1,NULL);
INSERT INTO "chapters" ("id","novel_id","chapter_number","title","content","word_count","is_premium","is_published","audio_url","published_at","created_at","updated_at","scheduled_release_at","part_number","season_id") VALUES(165,21,3,' First Move',replace('\nThree people asked Kemi if she was alright between first and third lesson, which told her more than she wanted to know about her own face.\nShe was alright. She was also spending significant mental energy on a question she kept refusing to name directly: whether she was going to the library that evening. She had said same time. He had said same time first, and at the time it had felt less like a decision and more like gravity, something she moved toward because it was simply the direction of everything. In the ordinary light of Tuesday it felt like something she had agreed to before she had finished thinking.\nAdaeze noticed nothing, which was either relief or evidence that Kemi had improved overnight. They ate lunch on the corridor bench outside the arts block, the one strip of the building that caught real breeze, and Adaeze was describing a boy from the opposing set named Faruk who had apparently looked at her with clear intent during morning assembly. Kemi made the right sounds in the right places. This was not difficult. Adaeze''s narratives were thorough and required mostly listening.\n"You''re distracted," Adaeze said, and stopped.\n"I have a lot on my mind."\n"Canada."\n"Yes," Kemi said. "Canada."\nIt was not a lie. Canada was always somewhere in her mind, ambient and ongoing, the way background noise becomes invisible until someone switches it off. But it was not what she was thinking about while Adaeze spoke, and she did not correct the assumption.\nAfter school she walked to the library.\nShe made this sound simple by keeping her thoughts thin and practical: she had revision to do, the library had the best light after hours, and the generator was confirmed fuelled because three teachers had formed a committee following yesterday''s incident. She climbed the stairs with these reasons held out in front of her. They lasted until she reached the landing and saw light under the door.\nShe pushed it open.\nTobenna was at a different table from yesterday, closer to the window, his Economics notebook open and a second textbook pressed flat beside it. He looked up when she entered.\n"You came," he said.\n"I said I would."\nShe chose a seat across from him rather than beside him. There was still a table of distance between them, but not three rows. Two feet of wood and whatever this was. She set her bag down, unpacked her books, and neither of them spoke for a while. But it was not the same silence as the night before. Yesterday''s silence had been dense and aware of itself. This one had a different quality. More settled. Like something that had already agreed to exist.\n"I wasn''t sure you''d come," he said, still writing.\n"You were here anyway."\n"I said I would be."\nShe looked across at him. He was writing steadily, but something in his stillness suggested he was aware of every small thing she did. She thought about the twelve weeks, turning the number over in her mind the way you check a thing from different angles to see if it feels the same in each one. It did not.\n"Can I ask you something?" she said.\n"Yes."\n"What are you getting out of this?"\nShe meant it genuinely but heard it land sharper than she intended. She kept going. "We both leave at the end of term. We both know it. So what do you think this actually is?"\nHe set his pen down. Through the window behind him, the sky had gone the deep orange of Lagos at six, the colour that made the zinc roof on the opposite building look briefly expensive.\n"I think it''s two people who had an honest conversation and don''t want to stop having it," he said. "I don''t have a plan past that."\n"I''m going to be a stranger to this place in twelve weeks," she said. "To everything in it."\n"So will I." He picked his pen back up. "Maybe that''s exactly the right condition for this."\nShe did not ask him to explain it. She thought she understood, and she thought asking him to say it more plainly would cost something she could not afford to lose. Some meanings were better held at the level at which they arrived.\nThey worked. Real work this time, or close enough. They talked between questions: a film she had watched twice that he had never heard of, the particular injustice of Further Maths being compulsory regardless of interest or mercy, a teacher whose end of term marking they agreed operated as creative fiction. He said he was thinking about studying Economics at university despite finding most of it unconvincing. She said she had not yet decided what to study because she had not yet decided who she was going to be in Canada. He looked at her when she said that and was quiet for a moment in a way that felt considered rather than empty.\nSomewhere in the second hour she moved her bag off the chair beside her to create more table space, and then shifted sideways to reach a textbook he was referencing, and by the time she registered the geometry of it she was sitting beside him rather than across.\nNeither of them mentioned it.\nThe library had filled slightly, then emptied. Two girls from SS3 left at half past seven, a boy near the door packed quietly and went. Now it was only them, and the window light had dropped to blue, and the overhead fluorescents held everything in the flat particular brightness that made revision rooms feel outside of time.\nShe found the paragraph she needed and read with her pen ready. He wrote in the narrow margin of his notebook in small, precise script. She read to the bottom of the page and turned it. He reached past her to retrieve his textbook from the far edge of the table, close enough that she felt the warmth of his arm before he pulled back.\nNeither of them mentioned that either.\nShe pressed her pen to the page and began to write.','\n',char(10)),1026,0,1,NULL,'2026-04-23 10:57:52','2026-04-05 05:03:25','2026-04-23 10:57:52',NULL,1,NULL);
INSERT INTO "chapters" ("id","novel_id","chapter_number","title","content","word_count","is_premium","is_published","audio_url","published_at","created_at","updated_at","scheduled_release_at","part_number","season_id") VALUES(166,21,4,'The Numbers',replace('Tobenna wrote the date in the top corner of his notebook and then stared at it long enough that Kemi noticed.\n"What?" she said.\nHe turned the notebook so she could see. He had written the date, and below it, in the neat precise figures he used for everything: 83 days.\nShe looked at the number. She had not counted. She had known end of term the way you know a fact without letting it become arithmetic, held at a comfortable distance where it remained a concept rather than a quantity. Eighty-three days was not a concept. It sat on the page and took up space and she felt the weight of it press somewhere below her sternum.\n"I did mine last night," he said. "Couldn''t sleep."\n"And you decided to bring it here."\n"I thought you should know the actual number."\nThey were on the back stairwell, which was technically not a place students were permitted after school hours, but the rule existed mainly to discourage the kind of noise that carried to the staff room, and they were not making noise. The stairwell was on the east side of the building, away from the evening traffic of the library and the prep classrooms, and it had a window on the landing that caught the last of the day''s light before it left entirely. The paint on the wall beside the window had bubbled and peeled in one long strip, revealing the grey primer beneath, and someone had drawn a small sun in the exposed patch with a blue biro.\nKemi looked at the number again. "Eighty-three days to what, exactly?"\n"My family leaves the twenty-second of July. My father already found a school in Kano. Already enrolled me."\n"He enrolled you before telling you?"\n"He told me and enrolled me on the same day." Tobenna said it without bitterness, but without warmth. It was a factual sentence about a factual man. "He operates with efficiency."\nShe thought about her own mother, who had broken the Canada news over jollof rice on a Sunday evening, setting down her fork first as if what followed required two free hands. Her mother operated with care and still the news had landed like a dropped object. She could not imagine finding out and being already registered in the same conversation.\n"When do you leave?" he asked.\n"July twenty-fifth." She paused. "Three days after you."\nHe absorbed this. "So we actually have the same deadline."\n"More or less."\nMore or less meant three days, and three days meant nothing in the arithmetic of what came after. She understood that without needing to say it, and she understood that he understood it too. This was the thing about Tobenna that had been true since the library and remained true now: the conversations they had operated at two levels simultaneously, what was being said and what was simply known between them, and the second level was often louder.\n"What is it actually going to be like?" he said. "Canada."\n"Cold." She had given this answer before and she gave it again because it was the truest thing, the detail that always arrived first. "My mum says we''ll adjust. I believe her about most things."\n"Not this?"\n"I believe her. I just don''t know what adjusting looks like from here. It''s like trying to imagine a colour you''ve never seen."\nHe considered this. Below them, somewhere on the ground floor, a door opened and closed. Footsteps crossed a corridor and faded. The school was emptying its last people.\n"What do you actually know about Kano?" she asked.\n"Harmattan is worse. The food is good. My father has been there twice for work and described it the way he describes work trips, without adjectives." He looked at the window. "I''ve been looking it up. It''s a real place, obviously. But knowing a place on a screen and knowing a place when it''s the place you live are not the same thing."\n"No," she said. "They are not."\n"I had plans for SS3," he said. It was the first time he had said something that carried audible feeling beneath the surface. "I know that sounds small."\n"It doesn''t sound small."\n"I was going to run for senior prefect. I''d already spoken to Mr. Adisa about it." He paused. "I''m not telling you that because it matters more than everything else. I''m telling you because it''s the kind of plan you make when you believe you know what the next twelve months look like. And then you stop knowing."\nKemi thought about the secondary school WhatsApp group she had already quietly muted. About the graduation preparations Adaeze kept raising that Kemi could not make herself engage with. About the way she walked through the school now sometimes, noting things she had not noticed before: the particular slant of light through the Biology block windows, the way the floor near the tuck shop had a soft spot that gave slightly underfoot, details she had stored without filing for four years and was apparently now cataloguing.\n"I keep memorising things," she said. "Without meaning to. Like my brain decided to start archiving before I did."\n"Like you''re already saying goodbye."\n"Without knowing who to say it to."\nThe light through the stairwell window had gone from gold to grey in the time they had been sitting. Tobenna closed his notebook, which meant closing the number too, folding it back into a cover.\n"Eighty-three days," she said, not to him specifically. Testing how it sounded outside her head.\n"Eighty-three days," he repeated. And then, in the same tone, without shifting the register: "I want to use them."\nShe looked at him in the flat grey light of the stairwell, the peeling paint and the small biro sun and the last of Tuesday dissolving through the window.\nShe said, "I know."','\n',char(10)),978,1,1,NULL,'2026-04-23 18:08:58','2026-04-05 05:05:06','2026-04-23 18:08:58',NULL,1,NULL);
INSERT INTO "chapters" ("id","novel_id","chapter_number","title","content","word_count","is_premium","is_published","audio_url","published_at","created_at","updated_at","scheduled_release_at","part_number","season_id") VALUES(167,21,5,'Anyway',replace('He was waiting at the school gate on Wednesday when she came out, which was not something they had arranged.\nHe had his bag over one shoulder and was looking at his phone with the focused blankness of someone not actually reading anything. She stopped walking when she saw him. Behind her, the end of day crowd pushed through the gate the way it always did: groups of girls in twos and threes, boys in loose clusters moving without apparent destination, a junior student being marched somewhere by a prefect with the weary authority of someone doing it twice that week. Adaeze was somewhere in the middle of all of it and Kemi did not move quickly enough.\n"That''s Tobenna Okafor," Adaeze said beside her, arriving without announcement in the way she always did. "Why is he standing at the gate looking at nothing?"\n"I don''t know," Kemi said.\nAdaeze looked at her with the expression she reserved for situations she had already correctly assessed and was giving one polite window of time for the other person to volunteer the truth. Kemi held her expression completely still.\n"Call me later," Adaeze said. She paused with her bag strap in both hands, deciding something. Then: "He has been watching you since February, you know." She did not stay to see Kemi''s face.\nShe moved off toward the bus stop and Kemi stood for a moment in the dispersing crowd, turning those five words over, before she crossed to the gate.\nTobenna looked up. He had the same controlled expression from the stairwell two days ago, the one that suggested he had decided exactly how to hold himself in this moment before she arrived.\n"I thought we could walk," he said. "Somewhere that''s not school."\nThe road outside St. Helena''s ran along a stretch of Surulere that was neither quiet nor busy at this hour. A woman sat at the junction beside a tray of groundnuts, fanning herself with a folded newspaper. Past her, compound walls ran along both sides of a side road to the left, their surfaces weathered to various stages of surrender, one gate padlocked with a lock bigger than a fist, another with a number painted in red that had been there long enough to blur into the plaster. The road behind it was shaded and unhurried, the kind that existed for people with nowhere specific to be.\nThey turned down it without discussing it.\n"I want to say something," Tobenna said, when the school noise had dropped behind them.\n"Go ahead."\n"I''ve been running an argument since Monday. The practical one. Both of us are leaving, both of us know it, and building something against that calendar is not rational." He paused. "It''s actually a very thorough argument."\n"I know that argument," she said. "I''ve been running it too."\n"And?"\n"And I''ve stopped finding it convincing."\nShe kept walking. The compound wall to their right had a long crack running from the ground to near the top, painted over once but already cracking again along the same line, as though the wall remembered exactly where it had broken before. She noted this without deciding to.\n"I''ve been calculating like that for five months," she said. "Every plan, every decision, measured against July. Whether it''s worth starting. Whether it will just make the leaving harder." She paused. "I think I have been doing it wrong."\n"How so?"\nShe stopped walking. He stopped a beat after her. They were standing in the shade of a neem tree whose roots had split the path beneath it, the concrete plates lifting away from each other at uneven angles. At the far end of the road, a man on a bicycle navigated the gap between two parked buses without slowing, and then the road was quiet.\n"Because calculating against the ending means you never actually start anything," she said. "And I think I''m more tired of not starting things than I am afraid of how they end."\nHe looked at her with a stillness she had begun to understand was not emptiness but its opposite, the way he went quiet when he was paying complete attention, like a question that had stopped asking and started listening.\n"I''m not pretending it''s simple," he said. "I know what 81 days looks like. I''m not asking you to pretend otherwise."\n"I''m not pretending anything," she said. "I want this anyway. Not despite the number. With it. The number is part of what it is."\nSomething shifted in his expression then, not dramatically, the way the quality of light changes when a cloud moves on: the same scene, a different texture.\n"Okay," he said.\n"Okay?"\n"Okay," he said again, and there was something in the repetition, the quiet certainty of it, that settled her more than any longer answer would have.\nShe looked at him for a moment in the neem tree shade. He was standing with his weight even, hands loose at his sides, not waiting for her to add anything, not performing patience, just present. The expression of someone who had said the thing he came to say and was ready now for whatever followed.\nThen she started walking again, because she needed motion to absorb what had been decided, and he fell into step beside her without comment.\nHe was beside her in the open afternoon, in the ordinary heat with the school already behind them. Not across a darkened library table, not two seats away in a reshuffled classroom, not on the other side of a stairwell landing. Beside. The geometry of it was a small adjustment. Everything else about it was not.\nAt the junction, the traffic moved without consulting pedestrians, operating on its own Lagos logic with no obligation to anyone standing at the kerb. They stopped. Beside her, his arm was close enough that the warmth of it was specific. She did not adjust away from it.\nA gap opened and they stepped into it together, crossing into the noise and heat on the other side.','\n',char(10)),1007,1,1,NULL,'2026-04-23 18:09:59','2026-04-05 05:06:15','2026-04-23 18:09:59',NULL,1,NULL);
INSERT INTO "chapters" ("id","novel_id","chapter_number","title","content","word_count","is_premium","is_published","audio_url","published_at","created_at","updated_at","scheduled_release_at","part_number","season_id") VALUES(168,21,6,'Still Here',replace('Tobenna was three minutes late and arrived with a wet umbrella, which was notable because the sky had been completely clear when Kemi left her house.\n"It rained in Yaba," he said.\n"The whole sky is blue."\n"One street in Yaba," he said. "Very specifically."\nShe looked at him and he looked back with the particular expression she was beginning to learn, the one that said he had already decided whether the thing he''d just said was funny and was leaving that work to her. She took the umbrella, collapsed it, and handed it back. He accepted this without comment and they started walking.\nIt was Saturday, which meant the stretch of Adeleke Street near the bus depot had its full complement of humanity. A man was selling raw cashews from a wheelbarrow, calling out to no one in particular with the focused persistence of someone who had done it long enough to stop caring who was actually listening. Two women in matching ankara were deep in an argument that had clearly been ongoing for some time and showed no signs of resolution. A group of boys were clustered around a phone propped against a generator on the ground, watching a video with the concentrated silence of a congregation.\nThey had not named what they were doing. She liked that. She had been calling it Saturday in her head, which was accurate enough.\n"I want to show you something," he said.\nShe followed him past the cashew man and the arguing women and turned left onto a smaller road she had passed but never entered. It was quieter here, the kind of quiet you only found in Lagos when a street happened to face the wrong direction for traffic. The buildings on both sides were low, painted in colours that had been optimistic once. Between two of them, so narrow she almost missed it, was a gap in the wall that opened into a small courtyard. Inside were four plastic tables and a woman at a charcoal grill that had clearly been there longer than the furniture.\n"Best suya in Surulere," Tobenna said.\n"People always say that about somewhere."\n"People are usually wrong. In this case, correct."\nThe woman at the grill did not look up when they entered. She turned a skewer with the efficient unhurried motion of expertise, a thing done ten thousand times and available for ten thousand more without requiring her full attention. The smoke rose straight up in the still courtyard air. Above the wall, the Lagos sky was completely clear and without apology.\nKemi sat and the plastic chair immediately found the uneven ground the way all plastic chairs did, rocking in the specific way that suggested it was somebody''s fault without clarifying whose. She adjusted. Tobenna sat across from her, the wet umbrella propped against the table leg.\nHe ordered for both of them, explaining as he spoke: this cut was better than that one, the suya here was peppery without being vengeful, and the woman would bring tomato and onion on a separate saucer because she had views about premature combinations.\nKemi watched him talk. He was different outside of school. Not unrecognizable, but slightly unlocked, like a word you had only ever read and then one day heard spoken aloud.\nThe suya arrived on newspaper, the tomato and onion on the side, a Fanta each without being asked. The bottle was cold enough that water had gathered on the outside. She lifted it and drank.\n"What are you going to miss?" he said.\n"Of Lagos?"\n"Of anything."\nShe looked at the edge of a headline visible near the fold of the newspaper, at the charcoal smoke rising into still air. She took the question seriously, which she suspected was what he had intended.\n"The way time moves here," she said. "I know people complain about it. The go-slows, the waiting, everything running on a schedule different from the one it promised. But there''s something inside all of that. You learn to find things while you''re waiting. You learn to exist inside the delay." She paused. "I think time will move differently in Canada. More accountable. I''ll probably be grateful for it and miss this simultaneously."\nHe was quiet in the way that meant he was actually thinking rather than preparing to respond.\n"I''m going to miss the noise," he said. "Which is strange because I complain about it daily. Lagos noise is a specific thing. It has layers. You can hear everything at once and somehow the total is something comfortable." He picked up his Fanta. "Kano will have its own noise. I know that. But it won''t be the one I grew up inside."\nThey ate. The suya was exactly what he had promised, the pepper direct and purposeful without cruelty. The afternoon sat around them without urgency. Then a cat appeared at the gap in the wall, surveyed the courtyard with professional suspicion, and left without resolving its verdict.\nKemi watched it go and laughed before she could decide to.\n"What?" Tobenna said.\n"Nothing. The cat."\nHe turned to look at the empty gap. He turned back. And then he smiled. Not the short quiet laugh from the corridor, not the controlled expression from the stairwell. A full, genuine, unmanaged smile that moved across his whole face before he could arrange it into anything more careful.\nShe looked down at the suya newspaper so he would not see what that did to her face.\n"We should do this again," he said. "Next Saturday."\nShe reached for another piece of suya. "You''ll be on time next Saturday."\n"That depends entirely on Yaba."\nShe looked up, and he was still smiling, and the afternoon held everything easily, as though it had room for all of it without needing to be asked.','\n',char(10)),970,1,1,NULL,'2026-04-24 02:59:26','2026-04-05 05:07:34','2026-04-24 02:59:26',NULL,1,NULL);
INSERT INTO "chapters" ("id","novel_id","chapter_number","title","content","word_count","is_premium","is_published","audio_url","published_at","created_at","updated_at","scheduled_release_at","part_number","season_id") VALUES(177,25,1,'The Last Story',replace('His grandmother was in the middle of a story about a river that swallowed a king when the lights went out, and Nnamdi thought: here we go again.\n\nThe candle she produced from somewhere inside her wrapper smelled like palm oil and old wood. She set it on the table between them without breaking the story, as if the darkness had always been part of the plan.\n"The king thought he was powerful," she said. "He had soldiers. He had horses. He had a title so long that children fell asleep before it ended."\n"Mama Chioma." Nnamdi did not look up from his physics textbook. "I have an exam tomorrow."\n"The river did not care about his exam either."\nHe turned a page. Outside, the Niger moved in the dark the way it always did steady, brown, older than everything he could name. Their compound sat close enough to the bank that he had fallen asleep to the sound of it his whole life. He had stopped hearing it years ago, the way you stop hearing your own heartbeat.\n"The king rode to the riverbank to prove something to his chiefs," his grandmother continued. She was seventy-three, or seventy-seven, or eighty-one she had given different answers in different years and seemed to find the question unserious. Her real age was written somewhere in the lines of her palms, not anywhere he could read. "He wanted everyone watching to know that water was just water."\n"And it wasn''t," Nnamdi said. "I know. It never is, in your stories."\n"In my stories." She repeated the phrase the way she repeated things she found interesting rather than true. "Nnamdi, look at me."\nHe looked up. The candle made her face look carved from something older than wood.\n"There are things I should have told you before now," she said. "I was waiting for the right time. The right time was always going to be next year, and then next year again, and now I think next year is not coming the way I planned."\nHe felt something shift in his chest. He pressed it flat. "You''re being dramatic."\n"I am being truthful, which is not the same thing." She reached under her chair and produced a clay pot, small enough to hold in two cupped hands, sealed at the top with something dark and waxy. He had never seen it before, which was strange. He had lived in this house since he was four. He had catalogued it the way he catalogued everything thoroughly, without meaning to.\n"What is that?"\n"Something for you." She set it on the table beside the candle. "But not tonight. Tonight I need you to listen to me."\n"I am listening."\n"You are hearing. That is different." She folded her hands in her lap. The candle flame leaned sideways without any wind, without any reason. "The river knows your name, Nnamdi. It has known it longer than I have."\nHe opened his mouth.\n"I know what you want to say," she said. "You want to tell me that rivers do not know things. That rivers are water and silt and minerals and motion. You want to cite something at me."\nHe closed his mouth.\n"I read your school reports," she said, and the corner of her lips moved. "Your biology teacher called you ''rigorously empirical.'' She meant it as a compliment. I was not sure."\n"It is a compliment."\n"It is a description. Like saying a door is solid. True, but it tells you nothing about what the door is keeping in." She looked at the clay pot. Then at him. Then past both of them, out the window where the Niger was a black sound in the dark. "There are things underneath this river that have been there since before your people had a name for themselves. Not creatures. Not gods do not make that face. Something older than those words. Something that remembers everything that has ever touched it."\nThe rain started then. Not the slow kind. Not the kind that gave you the courtesy of a warning. It arrived all at once, like a hand coming down flat on a table.\nNnamdi looked at the window. The drops hit the glass sideways, almost horizontally, which was not how rain worked.\n"That''s strange," he said.\nHis grandmother said nothing.\nHe checked his phone. The weather app showed a cheerful sun icon and a 0% chance of precipitation, the kind of confident wrongness that only algorithms could manage. He held the screen toward her.\nShe looked at it the way she looked at most of his technology not with dismissal, but with a patience that suggested the technology was the one missing the point.\n"NIMET says clear skies until Wednesday."\n"Put the phone down, my son."\nSomething in her voice made the words go through him in a way that had nothing to do with their meaning. He put it down.\n"If something happens tonight," she said, "you will know what to do."\n"Nothing is going to happen."\n"You will know what to do because I have spent sixteen years making sure you are the kind of boy who knows." She reached across the table and covered his hand with hers, briefly, the way she used to when he was small and the thunder was too close. Her hand was dry and warm and very certain. "The pot is yours. Whatever is inside it belongs to you. Do you understand?"\n"I understand that you are frightening me and I have to be up by five."\nShe smiled at that. A full smile, one that started in her eyes and took its time reaching her mouth, and it did something to him he could not have named with any word from any textbook he owned.\n"Go to bed," she said. "I will watch the water."\nHe went to bed. He told himself the rain was just rain. He told himself the sound of the river rising was the same sound it had always been, only louder, only the season. He lay in the dark and ran equations through his head until his brain finally stopped producing images of candlelight on his grandmother''s face and let him sleep.\nHe did not hear when the water came.\nHe did not hear it climb the compound walls or fill the yard or take the lower rooms. He did not hear whatever sound his grandmother made or did not make. By the time he woke to cold water around his ankles and the grey confusion of early morning, the river had swallowed half the compound.\nBy the time he had made it downstairs, soaked to the knee and shouting her name into every room, she was already gone.\nBy the time he had stood in the wreckage of their sitting room, surrounded by everything the flood had overturned and ruined and scattered, the only thing still sitting upright, dry, and completely untouched in the exact centre of the table, was the clay pot.\nHe picked it up with shaking hands. The wax seal was unbroken, the pot still sealed tight as a secret as if the water had moved around it on purpose, as if the flood had known exactly what it was allowed to take and what it was not.','\n',char(10)),1219,0,1,NULL,'2026-04-06T13:06:44.722Z','2026-04-06 13:06:44','2026-04-06 13:06:44',NULL,1,10);
INSERT INTO "chapters" ("id","novel_id","chapter_number","title","content","word_count","is_premium","is_published","audio_url","published_at","created_at","updated_at","scheduled_release_at","part_number","season_id") VALUES(178,25,2,'What the Water Took',replace('\nThe flood took the refrigerator, both plastic chairs from the yard, his grandmother''s bible, and three years of his secondary school certificates but it left the clay pot sitting in the centre of the table as if someone had placed it there deliberately, as if the water had instructions.\nNnamdi stood in the wreckage and understood, for the first time in his life, that he did not understand anything at all.\n\nThe water had dropped by morning. Not all the way the yard was still a shallow brown lake and the compound wall on the river side had a crack running top to bottom that had not been there the day before but enough to walk through in rubber boots, which he did not own, so he walked through it in his school shoes instead.\nHe moved through every room with the clay pot tucked under his arm.\nThe kitchen: her wrapper hanging on the door hook, dry above the waterline, smelling like the ogiri she had been cooking two days ago. The pepper grinder still on the counter. The fire unlit.\nHer bedroom: the mattress swollen with water. Her Bible on the floor, pages splayed open like a broken wing. The photograph of his parents on their wedding day his mother laughing at something outside the frame, his father looking at his mother instead of the camera floating face-up near the door. He picked it up. Set it on top of the wardrobe.\nSitting room: overturned. The stool, both cushion chairs, the small television his uncle had brought from Lagos three Christmases ago. All of it rearranged by water into something that looked like a question.\nThe table was the only thing still standing upright.\nHe set the pot down on it and looked at it. Then he looked at the door, open to the yard, and the brown water stretching from there to the wall, and the Niger beyond the wall, brown and risen and entirely calm, as if it had done nothing, as if it had simply sat there all night being a river.\nHe called her name into the yard. He called it twice, the way she had always said he should call voice down, not up, because the things you love are never above you.\nNothing answered. The river did not even ripple.\nHe called his uncle in Onitsha. The phone rang eight times and went to voicemail. He called again. Voicemail. He sent a text in all capitals and then stood there watching the screen, as if it might respond faster if he watched it.\nThen he called NEMA, the emergency management number he found after three tries on a search engine that kept suggesting flood insurance instead. The line connected, dropped, connected again. He spoke to a woman with a tired voice who took down his grandmother''s name and age seventy-three, he said, then corrected himself, seventy-seven, then said he wasn''t certain and the compound address, and she told him that the river had risen in seventeen communities overnight, that search teams were deployed, that he should stay where he was and not enter the water, and she said all of this in the tone of someone reading from a sheet of paper they had already read from many times today.\n"Was it a surge?" he asked. "The weather service showed nothing. There was no warning."\nA pause. "The river can do things we don''t always anticipate."\n"That is not an answer."\n"Sir, I''m asking you to remain calm and"\nHe ended the call.\nHe sat down on the only chair still upright and looked at the clay pot for a long time.\nIt was not remarkable to look at. Red-brown clay, the surface slightly uneven the way handmade things are, small enough to hold in two cupped palms. The seal at the top was made from something dark and waxy, pressed down smooth. No markings on the outside. No indication of what it was or who had made it.\nHe was a scientist. He reasoned through it.\nThe pot had been dry when he found it, which was improbable given that everything within three feet of the table had been submerged. The seal was intact. His grandmother had produced it the night before and told him it was for him. Therefore: it had been prepared in advance. Whatever was inside had been placed there deliberately, by her, for him.\nAnd she was gone.\nHe worked the wax seal with his thumbnail, carefully, the way he handled anything he did not want to damage. It came away in a clean ring, which surprised him — old wax tended to crack and crumble, but this came off almost like it was designed to. He set the ring of wax on the table and tilted the pot.\nA roll of material slid into his palm. Not paper. Something thinner, smoother, with a texture like dried river reeds pressed flat. He unrolled it slowly.\nIt was covered in writing.\nHe held it toward the window for better light. The script ran right to left across the material in thin, precise lines, each character formed with a care that suggested whoever had written this had taken a very long time over each one. The characters were not Igbo. Not Yoruba. Not any version of Arabic script he had seen in his history textbook. Not anything he could place from any direction.\nHe photographed it with his phone. He ran the image through Google Lens. The app spun, searched, and returned: No results found.\nHe tried a reverse image search. He tried a translation app. He tried typing what the characters looked like into a search bar circular base with three rising strokes, a horizontal bar with a diagonal descender and read through twelve pages of results that had nothing to do with what he was holding.\nHe sat back.\nOutside, a neighbour''s voice carried across the water, calling for someone. A child answered from somewhere far off. The ordinary sounds of a community doing the ordinary work of damage and survival, shovelling mud, calling names, counting what the water had taken and what it had left.\nHis grandmother had left him a message in a language that did not exist.\nOr a language that had stopped existing, which was not the same thing.\nHe rolled the material carefully and placed it back in the pot. He replaced the wax ring as best he could, pressing it flat with his thumb. He held the pot in both hands and looked at the river through the cracked compound wall, just the top of it visible, brown and wide and moving.\nThe river knows your name, Nnamdi.\nHe had told himself last night that this was an old woman''s poetry. The kind of thing you say when you are old enough to make mysteries out of ordinary things, when the world has lived inside you long enough to feel mythological.\nHe had believed that, fully, completely, with all the confidence of someone who had never been wrong about the things he was certain of.\nHe sat in the ruins of his grandmother''s sitting room, holding a clay pot that the flood had chosen not to touch, and felt his certainty do something he had no word for.\nNot break. Not vanish.\nBend.\n\nHe looked at the river one more time, and this time this one time, standing in the mud and the wreckage with the pot pressed against his chest he had the distinct and unscientific and completely irrational feeling that the river was looking back.','\n',char(10)),1266,0,1,NULL,'2026-04-06T13:09:59.827Z','2026-04-06 13:09:59','2026-04-06 13:09:59',NULL,1,10);
INSERT INTO "chapters" ("id","novel_id","chapter_number","title","content","word_count","is_premium","is_published","audio_url","published_at","created_at","updated_at","scheduled_release_at","part_number","season_id") VALUES(179,25,3,'The Language That Stopped',replace('By the fourth day after the flood, Nnamdi had contacted eleven linguists, two university archaeology departments, one very confused curator at the National Museum in Lagos, and a man on a linguistics forum who claimed to have decoded an ancient Sumerian trade route and who, after seeing the photograph, went quiet for six hours and then replied: where did you get this.\nNone of them had an answer. The man on the forum had only more questions.\n\nHis uncle arrived on the second day.\nUncle Femi was his mother''s younger brother, a civil engineer who wore ironed shirts even on weekends and approached every problem as if it were a structural one something to be assessed, reinforced, or demolished depending on what the assessment revealed. He walked through the compound with his hands clasped behind his back, nodding slowly at the damage the way engineers nod at things, like the flood had done something technically interesting.\n"We''ll get the wall fixed before the next rain," he said. "The floor can be dried out. The furniture" He looked at the swollen sitting room. "Some of it."\n"She''s not here," Nnamdi said. He was sitting on the repaired chair, the clay pot on the table in front of him. "They haven''t found her."\n"The search teams are still—"\n"Four communities. They''ve covered four communities." He had been tracking the NEMA updates obsessively, refreshing the page every forty minutes. "Seventeen were affected. They''re moving slowly."\nUncle Femi sat down across from him and looked at the pot. "What is that?"\n"Something she left me."\nHis uncle reached for it. Nnamdi moved it to his side of the table without thinking, the way you move something that belongs to you.\nUncle Femi looked at his hands, then at Nnamdi, then at the river through the cracked wall. "She was always full of things," he said quietly. Not unkindly. "Your grandmother. Always full of things she didn''t explain."\n"Did she ever show you anything like this? Any writing she kept? Any"\n"Nnamdi." He said the name the way adults say names when they want you to stop asking the question you''re asking. "Let the search teams do their work. When they find her, you can ask her yourself."\nHe did not say if. Nnamdi noticed, and said nothing.\nHis uncle made calls and arranged a temporary generator and bought new food to replace what the flood had ruined. He was efficient and present and doing everything correct, and by the third day Nnamdi was grateful for him and desperate for him to leave, because Uncle Femi''s competence was filling up the compound and leaving no space for the thing Nnamdi actually needed to do.\nOn the morning of the fourth day, Uncle Femi drove back to Onitsha for work. Nnamdi walked him to the car and waved and went back inside and opened his laptop.\nHe had already run the photograph through every automated tool available. Now he went further.\nHe posted on three academic linguistics forums African languages, historical scripts, and one general one called Undeciphered Writing Systems that had four thousand members and a pinned post that said no, we still haven''t cracked Linear A, please stop asking. He wrote a careful, neutral post: found in a sealed container, possible heirloom, any identification would be appreciated, attached image.\nWhile he waited, he made a list of everything he could observe about the script itself, the way his physics teacher had taught him to approach any unknown describe first, theorise second, conclude last.\nRuns right to left. Approximately 23 distinct characters visible, though some may be variants of the same base form. Characters appear to combine a root shape with additional strokes possibly an abugida or syllabic system rather than an alphabet. Some shapes share structural similarities with Nsibidi, but the match is incomplete. Material appears to be dried plant fibre, possibly papyrus-adjacent. Ink is dark brown, possibly made from organic compounds.\nHe photographed the Nsibidi comparison in his school''s cultural history textbook and put them side by side on his screen. Close. Related, maybe. But not the same. Like a word spoken by a mouth that shaped sounds slightly differently, in a slightly different time.\nThe forum responses came in over the next two days.\nMost were useless people guessing confidently with no basis, people asking him to post clearer images, one person who said it looked like a "fantasy font" and recommended a website. He ignored those.\nThree responses were worth reading.\nA PhD student in Ibadan said the structural logic resembled proto-Igbo script traditions that predated colonial disruption, but that she had never seen these specific characters and her supervisor had looked at the image and said the same.\nA retired professor of West African linguistics at the University of Birmingham said and he read this sentence four times this script pattern suggests a system that may predate the documented Niger Delta writing traditions by several centuries. I would very much like to know its provenance. If this is authentic, it should not exist.\nThe man who had gone quiet for six hours was named Adaeze, which surprised him. Her follow-up message said: I study undeciphered scripts. I have a database of over three hundred writing systems, extinct and active, across sub-Saharan Africa. I ran your image against all of them. Nothing matched. Not partial matches. Not structural echoes. Nothing. This is either a forgery or something that was never recorded. I don''t think it''s a forgery. I think it was never recorded because the people who used it did not want it recorded.\nHe sat with that for a long time.\nHe called the National Museum in Lagos directly after that, not the general line but a number he found buried in a departmental staff page. A Dr. Obiora answered, sounding as though he had expected a different caller. Nnamdi explained what he had, carefully, without mentioning the flood or his grandmother.\nThere was a long pause on the line.\n"Where exactly did you find this?" Dr. Obiora asked.\n"Riverine area. Niger Delta."\n"How old is the material?"\n"I don''t know. I don''t have equipment to test it."\nAnother pause. "Send me high resolution images. Both sides of the material, if there''s writing on the reverse."\nNnamdi checked. There was writing on the reverse. He had not noticed before because he had been reading only one side.\nHe photographed both sides under the best light he could arrange his phone torch angled at 45 degrees, the way photography tutorials said to do it and sent the images to Dr. Obiora''s email address.\nThree days passed.\nOn the third day, Nnamdi sent a follow-up.\nDr. Obiora''s reply came within the hour, which told him the man had been thinking about it.\nI have shared your images with three colleagues, including a specialist in pre-colonial Delta writing traditions. We are in agreement that the script is not currently in any database we can access. I want to be precise: we are not saying the script is unknown. We are saying it is unknown to us, and to the tools we have access to. That is a meaningful distinction. Languages do not disappear. They go underground. Someone, somewhere, will know this. But that someone is unlikely to be in a university.\nNnamdi read the last sentence twice.\nUnlikely to be in a university.\nHe looked up from his screen at the clay pot on the table. The compound was quiet around him. The river made its sound through the cracked wall, the same sound it always made, unhurried and completely indifferent to what he needed from it.\nHis grandmother had grown up on this river. She had spent her whole life here, on this bank, in this compound, telling stories to a boy who kept informing her, with great scientific confidence, that her stories were not real.\nShe had not gone to a university. She had not needed to. She had known things that his laptop and his forums and his professors and his databases could not locate, and she had written one of those things down in a language that the entire modern world had agreed, somewhere along the way, to forget.\nHe closed the laptop.\nHe picked up the clay pot and went and stood at the cracked wall and looked at the river. Brown, wide, carrying everything downstream the way it always did silt, debris, the ordinary wreckage of a world that kept moving.\nSomeone, somewhere, will know this.\nHe had been thinking about this wrong. He had been treating it like a research problem, like something solvable with enough databases and enough experts and enough modern tools. But the message was not modern. The woman who wrote it was not modern, not in any way that actually mattered.\nIf the answer was not in a university, then he needed to think about where old things went when the modern world stopped paying attention to them.\nHe needed to think about the river.\n\nHe had spent four days asking people who studied dead languages. It had not occurred to him, until this moment, to ask someone who still spoke one.','\n',char(10)),1530,0,1,NULL,'2026-04-06T13:13:38.796Z','2026-04-06 13:13:38','2026-04-06 13:13:38',NULL,1,10);
INSERT INTO "chapters" ("id","novel_id","chapter_number","title","content","word_count","is_premium","is_published","audio_url","published_at","created_at","updated_at","scheduled_release_at","part_number","season_id") VALUES(180,25,4,'The Fisherman Who Doesn''t Age',replace('\nThe old men of the river did not advertise themselves.\nNnamdi had lived on this bank for sixteen years and had learned, without being taught, that there was a category of person who existed at the edge of the water the way reeds existed — always there, never quite noticed, part of the background texture of a life lived near the Niger. He had never paid them serious attention. He paid attention now.\nHe started the morning after he closed his laptop. He walked the bank in both directions from the compound, past the women washing clothes on flat rocks, past the boys dragging a pirogue through shallow water, past the point where the bank curved and the town thinned out and the trees came close to the water''s edge. He walked until the sounds of the town were more suggestion than fact.\nThere was a man there.\nHe was sitting at the end of a narrow dock that jutted into the river at a slight angle, as if it had been built straight and the river had slowly persuaded it otherwise. He was fishing with a hand line rather than a rod, the line running from his fingers into the water without a float, which meant he was reading the pull directly through his skin. He was wearing a faded blue agbada, river-worn at the hem, and a hat that had once had a brim.\nHow old he was, Nnamdi could not say. Old in the way that certain trees were old, where the age had stopped being a number and become a quality, something you felt rather than calculated. His face was a landscape of lines but his hands on the fishing line were still, completely still, the way only very young or very old hands could be.\nNnamdi stood at the shore end of the dock and said good morning.\nThe man did not turn. "I know your grandmother," he said.\nThe sentence landed without warning. Nnamdi''s next words dissolved before he could form them.\n"Sit down," the man said. "You are making the fish nervous, standing there like a question mark."\nNnamdi walked the dock and sat beside him, the wood creaking under him in a way it did not creak under the old man, as if the dock knew the difference. The river was very close from here. It smelled like wet earth and something older than wet earth, something mineral and deep.\n"Her name is Chioma Okafor," Nnamdi said. "She''s been missing since the flood. Six days now."\n"I know how long," the man said.\n"Did you see her that night?"\n"I saw her many nights. I have seen her for longer than you have been alive." He adjusted the line between his fingers. A small tension, then stillness again. "What do you want from me, son of Chukwuemeka?"\nNnamdi''s father''s name. His father who was in Abuja. His father who had been notified and had said he was coming and had not yet come.\n"How do you know my father''s name?"\n"I know your grandfather''s name also. And the name before that." He said it simply, the way you say things that are just facts. "Your family has lived on this water for a very long time. I have been here for most of it."\nThe rational part of Nnamdi''s brain, which had been running continuously since the flood like a generator that did not know how to switch off, tried to produce an explanation for this. Old community. Long memory. Small riverine town. Possible.\nHe reached into the bag he had brought and took out the clay pot. He removed the rolled material carefully and held it toward the man.\n"Can you read this?"\nThe fisherman did not look at it immediately. He looked at the river. He adjusted his line. Then he turned, slowly, and looked at what Nnamdi was holding.\nThe stillness that came over him was different from his ordinary stillness. His ordinary stillness was the practiced quiet of a man who spent his days waiting for fish. This was something that moved through him from outside, like a cold current through warm water. His eyes, which had been the calm eyes of an old man who had seen most things, became something Nnamdi did not have a name for.\nHe looked at the material for a long time without speaking.\nThen he looked at Nnamdi.\nThen he looked at the river.\nHe reeled in his line, slowly, hand over hand, and set it on the dock beside him. He folded his hands in his lap. He breathed in through his nose and out through his mouth and the breath was longer than a normal breath.\n"Where did you get this?"\n"My grandmother left it for me. Sealed in a clay pot. It survived the flood."\n"Of course it did," the man said, very quietly, to no one in particular.\n"You recognise it."\nIt was not a question. The recognition had been in his face, total and immediate, before he had any time to arrange his expression into something less revealing.\nThe fisherman was quiet for long enough that Nnamdi thought he might simply refuse to answer. The river moved below them. Something jumped, far out, and landed back in the water with a sound like a door closing.\n"What is your name?" Nnamdi asked. "I have lived here my whole life and I do not know your name."\n"Ikenna," the man said.\n"How long have you been fishing this part of the river, Ikenna?"\nThe man almost smiled. "Longer than the dock has been here."\n"The dock looks like it is about forty years old."\n"Yes," Ikenna said.\nNnamdi looked at him properly. The lines of his face. The absolute stillness of his body. The way the dock did not creak under him. The way he had known his father''s name, his grandfather''s name, the name before that.\n"How old are you?" Nnamdi asked.\nIkenna picked up his line and looked at it, then at the water. "That is a question for another day."\n"My grandmother is missing. I have a message I cannot read. I have been to linguists and professors and museums and nobody can place this script. You looked at it for four seconds and went completely silent." Nnamdi kept his voice even, the way he kept his voice even in arguments he intended to win. "I am not asking for a story. I am asking for information."\nIkenna turned and looked at him for a long moment. Really looked, the way adults looked at you when they were updating their assessment of who you were.\n"Your grandmother," he said slowly, "would be very proud of that speech."\n"Is she alive?"\nThe question came out before he had decided to ask it. It sat between them in the river air, raw and unguarded, nothing like his careful even voice.\nIkenna was quiet. Then: "Yes."\nThe word went through Nnamdi like the shock of cold water. He had been holding something very tightly for six days without knowing he was holding it, and now it released all at once, and he had to breathe carefully for a moment before he could speak.\n"Where is she?"\n"Somewhere the river keeps the things it needs."\n"That is not an answer."\n"It is the most answer I can give you today." Ikenna looked at the material still in Nnamdi''s hands. "That writing is very old. Older than this dock. Older than the town behind us. Older than the name we gave this river, and we gave it a name a very long time ago." He paused. "There are people who still know it. Not many. They do not live in places with addresses."\nNnamdi looked at him. "Where do they live?"\nThe line twitched in Ikenna''s hands. He let it run, feeling it, then stilled it. He looked at Nnamdi with the eyes that had gone strange when they first saw the writing, and Nnamdi understood, with a certainty that had nothing to do with science and everything to do with something older than science, that whatever this man was about to say would change the direction of his life.\n"Come back tomorrow," Ikenna said. "At first light. Bring the pot."\nHe turned back to the river and that was the end of it.\n\nNnamdi walked home in the late afternoon with the material re-rolled and the pot under his arm, and he thought about the word yes, and the way Ikenna had said it, steady and certain, the way you confirm things you have known for a very long time.\nShe was alive.\nShe was somewhere the river kept.\nHe did not know what that meant. He was not sure it was the kind of thing that meant anything in the language he currently spoke. But it was a direction, which was more than he had yesterday, and a direction was enough to move.','\n',char(10)),1496,1,1,NULL,'2026-04-06T13:18:43.874Z','2026-04-06 13:18:43','2026-04-06 13:18:43',NULL,1,10);
INSERT INTO "chapters" ("id","novel_id","chapter_number","title","content","word_count","is_premium","is_published","audio_url","published_at","created_at","updated_at","scheduled_release_at","part_number","season_id") VALUES(181,25,5,'What the Fisherman Remembers',replace('He did not sleep well.\nHe lay on his back in the dark and stared at the ceiling and thought about the word yes and the phrase somewhere the river keeps and the way Ikenna''s face had changed when he saw the writing, that cold current moving through still water. He thought about his grandmother sitting across from him by candlelight, saying the river knows your name in a voice that was not performing mystery but reporting fact.\nAt some point the night shifted from black to grey and he got up, dressed, filled a flask with water, put the clay pot in his bag, and left the compound before the town was fully awake.\nIkenna was already on the dock.\nHe was not fishing. He was sitting with his hands on his knees, looking at the river, and he did not turn when Nnamdi walked the dock but said, "You are two minutes early," which meant he had known exactly when Nnamdi would arrive.\nNnamdi sat beside him. The river was silver in the early light, wide and quiet, carrying a thin mist just above the surface. A kingfisher sat on a post thirty meters downstream, orange and blue, absolutely still.\n"You said come at first light," Nnamdi said. "I came at first light."\n"I know. I was not complaining." Ikenna looked at him sideways. "Did you eat?"\n"I will eat when I get back."\n"Eat before you hear difficult things. It helps." He reached into the folds of his agbada and produced something wrapped in plantain leaf and held it toward Nnamdi. Fried akara, still warm. Nnamdi took it because refusing felt wrong, and because he was, he realised, actually hungry.\nHe ate. Ikenna watched the river.\nWhen the akara was finished Ikenna said, "Ask your questions. All of them. Ask everything that kept you awake last night and I will tell you what I can."\nNnamdi took out his phone. "Can I record this?"\nIkenna looked at the phone for a moment. "No."\nHe put the phone away. He had known Ikenna would say no. He had asked anyway because he was sixteen and had been trained by every science class he had ever attended to document everything.\n"Who wrote the message in the pot?"\n"Your grandmother."\n"In a language she never learned formally."\n"In a language she was born knowing," Ikenna said. "The same way you were born knowing how to cry before anyone taught you. Some things do not require learning. They require remembering."\n"That is not how language acquisition works."\n"No," Ikenna agreed. "It is not. Which is why what I am about to tell you will be difficult for you." He said it without impatience, without the faint condescension adults usually applied to teenagers they expected to argue. He said it as a neutral fact, the way you note that a road ahead is unpaved before you drive it.\nNnamdi waited.\nIkenna looked at the river and began.\n"Before the names we use now. Before the colonial maps and the missionary records and the university departments that study us from the outside and the inside both. Before any of that, the Niger was not just a river." He paused. "Every child in school learns that rivers are water systems. Drainage basins. Ecosystems. All of this is true. But the people who lived on this water before the world agreed on those words knew something else that was also true. That the river is inhabited. Not by fish. Not by the things you can catch and measure. By something older than the categories we use to explain what we mean by inhabited."\n"Water spirits," Nnamdi said. He kept his voice careful and neutral.\n"That is the short word, yes. Your grandmother used it. Her grandmother used it. Every person who has lived on this bank for the past thousand years has used it because there is no better word in any language we currently speak." Ikenna turned to look at him. "I can see what you are doing with your face."\n"I am not doing anything with my face."\n"You are being very polite about not believing me."\nNnamdi said nothing.\n"That is fine," Ikenna said. "Belief is not required. Continue listening."\nHe turned back to the river. The mist was lifting now, the silver surface warming toward brown as the sun climbed.\n"These presences, whatever you want to call them, they and the people on the bank had a relationship. Not worship. Not the simple thing the missionaries later wrote it was, where ignorant people bowed to things they did not understand. A relationship. Like the relationship between this bank and the water that shapes it. Each one changes the other. Each one needs what the other provides." He pulled at a loose thread on his agbada, then stopped. "There were people whose job was to maintain that relationship. To stand in the middle of it. To carry messages in both directions."\n"Bridge keepers," Nnamdi said, before he knew he was going to say it.\nIkenna looked at him sharply. "Where did you hear that word?"\n"I did not. It came to me."\nIkenna was quiet for a moment. Then: "Yes. Bridge keepers. People who could move between what the river knew and what the people on the bank needed to know. Who could hear what the water said and translate it into something that could be used. They were not priests. They were not kings. They were something with no modern equivalent, which is one of the reasons the history of this work was so easily buried."\n"Buried how?"\n"The same way everything inconvenient gets buried. First the missionaries decided it was devil worship and the converts stopped speaking of it publicly. Then the colonial administrators decided it was superstition and the educated class stopped speaking of it at all. Then the educated class taught their children that their grandparents had been primitive, and the children believed it because children believe what their schools tell them, and after two or three generations the thing that had been known for a thousand years became the thing that nobody admitted to knowing." He said it without bitterness, just the flatness of someone recounting a long, familiar loss. "The knowledge did not disappear. It went underground. The people who carried it kept carrying it, quietly, among themselves."\n"People like my grandmother," Nnamdi said.\n"People like your grandmother."\n"And people like you."\nIkenna said nothing. Which was an answer.\nNnamdi looked at the river. He was doing the thing he did when he was processing something that challenged his framework, which was to go very quiet and very still and let his mind run through it from multiple angles simultaneously. He was aware that Ikenna was watching him do this and was letting him.\nThe story was internally consistent, he would give it that. The buried history part was historically plausible, actually. He knew enough about colonial documentation of African religious and cultural practices to know that deliberate suppression was not mythology. That had happened. That was in the academic record. The part about presences in the river, about something older than categories, about people who could communicate in both directions across that boundary, that was the part where his certainty strained.\n"I believe the history," he said. "The suppression of knowledge. The breaking of the transmission chain. That is documented. I do not believe—"\n"That the river is inhabited."\n"I do not have any evidence for that."\n"No," Ikenna said. "You do not. Yet." He reached over and tapped the bag where the clay pot was. "Your grandmother left you a message in a language that no database contains. The flood that took her was not predicted by any weather system. She told you the river knew your name, and you are here, and the message is in your bag, and you came to first light on a dock talking to an old man you do not understand." He looked at Nnamdi calmly. "At what point does the absence of your kind of evidence become evidence of a different kind?"\nThe kingfisher downstream dropped from its post and hit the water and came up with something silver in its beak, gone before the ripple fully formed.\nNnamdi had no immediate answer. He looked for one and did not find it.\n"My grandmother walked into the flood," he said. The thing he had been circling for six days, not quite landing on it. "She didn''t get swept away. She went in."\n"Yes."\n"Because of me. That is what the village told me at the time." He stopped. "What did they mean?"\nIkenna was quiet for a long time. Long enough that the mist finished burning off and the river turned fully brown and a woman''s voice carried from somewhere upstream, calling a name in the morning air.\n"That," he said finally, "is not something I can tell you today."\n"Why not?"\n"Because you are not ready for it. Not because I am withholding it from you as a game, or because I enjoy watching you be frustrated, but because there are things that need to be built before they can hold what I would put inside them. You are still building." He stood, with the ease of a man whose joints had never considered stiffness, and picked up his hand line. "Come back tomorrow."\n"You keep saying come back tomorrow."\n"And you keep coming back," Ikenna said. "Which tells us both something."\nHe walked off the dock and along the bank without looking back, moving with the unhurried certainty of someone who had never once in his life needed to hurry, and Nnamdi sat on the dock alone with the river moving below him and the clay pot in his bag and the beginning of a feeling he did not have a scientific word for.\nNot belief. He was not there yet.\nBut the space where his certainty used to be solid was wider this morning than it had been yesterday, and growing.','\n',char(10)),1677,1,1,NULL,'2026-04-06T13:20:05.199Z','2026-04-06 13:20:05','2026-04-06 13:20:05',NULL,1,10);
INSERT INTO "chapters" ("id","novel_id","chapter_number","title","content","word_count","is_premium","is_published","audio_url","published_at","created_at","updated_at","scheduled_release_at","part_number","season_id") VALUES(182,25,6,'The Village Not on the Map',replace('On the seventh morning Ikenna did not give him words. He gave him directions.\nHe recited them the way you recite something you memorised so long ago that it has become part of your body rather than your memory, the way you know where your own hands are without looking. Follow the bank north past the point where the silk-cotton tree split into three trunks. Take the narrow channel where the water runs green rather than brown. When the channel forks, take neither fork but go straight, through the reeds, even where there is no visible path. Walk until you hear something that sounds like singing but is not singing. Stop there.\nNnamdi wrote it all down in his phone''s notes app. Ikenna watched him do this with an expression of mild amusement and said nothing.\n"How far?" Nnamdi asked.\n"Distances work differently in that direction."\n"That is not useful information."\n"No," Ikenna agreed. "It is not. Bring water. Wear shoes you do not mind losing."\nHe left at seven in the morning, after eating properly this time, after leaving a note for his uncle who called every evening and expected accounting of his days. The note said he was visiting a community elder about his grandmother. This was true enough.\nThe silk-cotton tree was easy to find. He had passed it a hundred times without registering it properly, the way you failed to register landmarks you had no reason to navigate by. It split into three trunks about four metres from the ground, each trunk going in a slightly different direction, as if the tree had once made a decision and could not settle on it.\nHe turned north from there and followed the bank.\nThe town fell away faster than it should have. He had not walked more than twenty minutes before the sounds behind him thinned to nothing, which was wrong, because the town extended further along the bank than this. He checked his phone. The GPS showed him moving along the bank correctly, a blue dot on a familiar line, and then, between one step and the next, the blue dot stopped updating. Not no signal. The signal bars were fine. The dot simply stopped moving while he kept walking, as if the map had decided he wasn''t going anywhere it recognised.\nHe kept walking.\nThe narrow channel announced itself by colour before he saw the fork. The water running off from the main river here was genuinely green, not the murky greenish-brown of algae-heavy water but a clear, still green, the colour of deep glass. He stood at the edge of it and looked down. He could see the bottom, which he could not do anywhere else on this river. The bottom was clean sand with dark stones arranged in patterns that were either natural or were not.\nHe took the channel.\nThe reeds came up on both sides as the channel narrowed, tall enough to close overhead in places, and the light went gold and filtered, the way light went in photographs of places that had been left alone long enough to become themselves. His shoes went into the water when the channel shallowed and he felt the soft pull of the current against his ankles, gentle but directional, like a hand at his back.\nThe fork appeared. Two clear paths diverging left and right. Between them, where no path was, the reeds grew dense and unbroken.\nNnamdi stood at the fork and looked at the space between and thought about everything he knew about navigation, about paths, about the physics of moving through dense vegetation, and then he thought about Ikenna''s face when he said go straight and he walked forward into the reeds.\nThey parted.\nNot dramatically, not all at once, but each step produced just enough give for the next step, the way a crowd made room for someone moving through it with sufficient certainty. The ground under him was firm. The reeds were thick on both sides but the forward path kept opening, barely, just enough, and he kept moving, and after a time that he could not accurately measure he heard something.\nIt did sound like singing. The same way rain on a roof sounded like applause, or the way wind through particular trees sounded like breathing. It had the shape of singing, the rise and fall, the sense of repeated pattern, but underneath it was something that had no relationship to human vocal cords. It was coming from ahead and from below simultaneously, as if the ground itself was producing it.\nHe stopped.\nThe reeds ended.\nHe stepped out of them and stood at the edge of a village.\nIt was not a large village. Perhaps thirty structures arranged in a loose curve around a central space, the structures built from wood and clay in a style he did not recognise from any architectural reference he had, walls curved rather than cornered, roofs layered with something dark and woven. A fire burned in the central space though it was full morning and the air was warm. Chickens moved between the buildings with the unhurried confidence of chickens everywhere. A child sat outside one of the structures drawing in the dirt with a stick, making shapes that Nnamdi recognised with a lurch in his stomach as the same shapes that were on the material in his bag.\nThe child looked up at him. She was perhaps eight years old with her hair in four sections and eyes that were absolutely unsurprised by his arrival.\n"We said you were coming," she told him, in Igbo.\n"Who said?"\nShe pointed at the river. Which was here, somehow, the Niger running along the far edge of the village in a curve that his map showed no tributary making, no branch of the river reaching this far from the main channel. He was either more turned around than he thought or the river had moved.\nHe chose not to examine that option directly.\nAn old woman came out of the nearest structure and walked toward him. She was tall, taller than he expected from someone her age, with white hair cut close to her head and the particular posture of someone who had never once in her life been uncertain of where she was going. She looked at him the way Ikenna had looked at him, which was to say she looked at all of him, not just his face, as if reading something written across his whole body.\n"Nnamdi Okafor," she said. Not a question.\n"Yes."\n"You look like your grandmother." She tilted her head. "Also like your great-grandfather, but that is a longer story." She turned and walked back toward the structures. "Come. You will want to sit down for this."\nHe followed her into the village and the sounds of the world he had come from closed behind him like water.\nInside the structure she led him to, three other elders were already seated on low stools around the fire that should not have been necessary in the morning heat but whose warmth was a different kind of warmth, the kind you felt in your chest rather than on your skin. Two men and one woman, all of an age that Nnamdi''s brain quietly refused to estimate. They looked at him with the same expression the tall woman wore, reading something in him he could not read in himself.\nHe sat on the stool they indicated.\nThe tall woman sat across from him. She reached out her hand and he understood, without being told, that she wanted the clay pot.\nHe took it from his bag and placed it in her hands.\nShe held it for a moment with her eyes closed. Then she opened them and looked at him with an expression that was made of several things at once, recognition and grief and something that sat underneath both of them, something that felt like relief.\n"She prepared you well," the old woman said. "Given how little time she had."\n"I need to find her," Nnamdi said. "Ikenna told me she is alive. That the river is keeping her somewhere. I need to know where that is and how to get to her."\nThe elders looked at each other. Something passed between them in a silence that was as legible to them as speech.\n"We will tell you where she is," the tall woman said. "But first you need to understand why she went. Because the where will mean nothing without the why, and the why will change everything you think you know about yourself."\nThe fire shifted between them. Outside, the child was still drawing in the dirt, the old script moving under her small hands with the ease of a language she had always known.\nNnamdi looked at the clay pot in the old woman''s hands, at his grandmother''s message written in the language that the whole modern world had forgotten, and felt the last of his carefully constructed certainty do what it had been doing, slowly and honestly, since the night of the flood.\nIt did not break. It opened.','\n',char(10)),1524,1,1,NULL,'2026-04-06 13:21:59','2026-04-06 13:21:40','2026-04-06 13:21:59',NULL,1,10);
INSERT INTO "chapters" ("id","novel_id","chapter_number","title","content","word_count","is_premium","is_published","audio_url","published_at","created_at","updated_at","scheduled_release_at","part_number","season_id") VALUES(183,25,7,'The Price of Knowing',replace('\n\nThe tall woman''s name was Lolo Adaeze, and she had been waiting for him for eleven years.\nShe told him this the way you told someone the time, plainly, without decoration, and watched his face process it with the patience of someone who had said difficult things to unprepared people many times before.\n"Eleven years," Nnamdi said.\n"Since before you started secondary school. Since before you decided that the world was only what you could measure." A small pause. "Your grandmother told us about that phase."\n"It is not a phase."\n"No," Lolo Adaeze said. "It is not. It is who you are. We are not asking you to stop being who you are. We are asking you to make room for what you do not yet know beside what you do." She poured water from a clay vessel into a cup and set it in front of him. "Drink. You walked far."\nHe drank. The water tasted like the river but cleaner, the river without sediment, without the history of everything the river had carried. He drank the whole cup before he realised he had.\nThe other three elders had not spoken yet. They sat on their stools with the stillness of people who had long ago made peace with silence and were in no hurry to disturb it. The fire between them produced no smoke, which Nnamdi noticed and filed away in the part of his mind that was still collecting observations even while the rest of him was barely keeping pace with what was happening.\n"You said you would tell me where she is," he said. "You said the where needs the why first."\n"Yes."\n"Then tell me the why."\nLolo Adaeze looked at the other elders. The older of the two men, who had a face like a dried riverbed, all lines running in the same direction, nodded once.\nShe began.\n"Your grandmother was a bridge keeper. You have heard this word from Ikenna, I think."\n"Yes."\n"She did not choose this role the way you choose a profession. She was born into it, as her mother was born into it, as the women of her line have carried it for longer than this village has had its current name. A bridge keeper maintains the relationship between what lives in the river and what lives on the bank. She carries messages. She keeps the terms of an agreement that was made so long ago that nobody alive remembers the making of it, only the keeping." She paused. "Are you following?"\n"I am following."\n"Your grandmother kept this role her entire life. She did it quietly because the world outside this river had decided the role was not real, and she was practical enough to know that announcing herself would cost her more than it gained. She kept it in the way she kept everything important, close to the chest, offered only to those who had already earned the offering." Lolo Adaeze looked at the clay pot, which sat on the ground between them. "But a bridge keeper cannot keep the role forever. At some point the role must pass. And the passing requires a choice."\nSomething tightened in Nnamdi''s chest. "She chose me."\n"She did not choose you. You were chosen before she was born. Before your father was born. The river made this choice a very long time ago and your grandmother spent her whole life preparing the boy the river had named." She said it gently but without softening it. "You are not here by accident, Nnamdi. The flood was not an accident. The pot was not an accident. Ikenna was not an accident. We are not an accident."\nHe sat with that. The fire shifted. One of the silent elders, the woman, adjusted her wrapper and looked at the middle distance with an expression of someone listening to something just outside the range of normal hearing.\n"She went into the river," Nnamdi said. "Because of me."\n"She went into the river because the time came for the handover and the handover requires the current keeper to step fully into the river''s world so that the next keeper can step fully into the role. It is not death. It is not punishment. It is the mechanism. She cannot come back until you have accepted what she is passing to you."\nThe silence after that was very complete.\nNnamdi counted his own breaths. Four in. Four out. His physics teacher''s advice for examinations, for moments when the problem on the page stopped making sense and you needed your brain to restart cleanly.\n"She is being held there," he said. "Until I agree."\n"She is waiting there. There is a difference."\n"Is there."\nLolo Adaeze looked at him steadily. "Your grandmother is not a prisoner, Nnamdi. She knows what she agreed to. She agreed to it a very long time ago. The waiting is not suffering. But yes, she cannot return until the thing is done."\nHe stood up. He did not mean to, his body made the decision before his mind caught up, and he walked to the doorway and stood looking out at the village, at the child still marking the dirt, at the river running along the far edge, brown and patient and entirely aware of him in a way that he could feel against his skin like a change in air pressure.\nHis grandmother had gone into the river for him. Had left him a message he could not read, in a language the whole world had buried, pointing him toward a village that did not appear on any map, so that a woman who had been waiting for eleven years could tell him that everything he thought was random had been arranged.\nHe turned back.\n"What are you asking me to agree to?"\nLolo Adaeze looked at him for a long moment. Then she said, "Sit down."\nHe sat.\n"We are asking you to accept the role. To begin learning what a bridge keeper needs to know. To allow us to teach you the language your grandmother used in that message and the hundred other things that go with it." She paused. "We are not asking you to give up your life on the other side of the reeds. Your school. Your family. Your science. We are not asking you to become a different person. We are asking you to become a larger one."\n"And if I say no?"\nThe dried-riverbed elder spoke for the first time. His voice was deep and slow, carrying the weight of someone who chose each word the way you chose a stone to build with. "If you say no, your grandmother will wait. The role will wait. The river will wait. It has waited before." He looked at Nnamdi without judgment. "But you will spend the rest of your life knowing that you said no, and knowing what you said no to, and that knowledge will not be comfortable to carry."\n"That sounds like a threat."\n"It is a description," the old woman beside him said, speaking for the first time, and Nnamdi heard, with a start, an echo of his grandmother''s voice in the rhythm of her words. Not the same voice. The same cadence, the same precision. "The same way a doctor describes what happens to an untreated wound. Not a threat. Just what is true."\nNnamdi looked at the clay pot on the ground. At his grandmother''s handwriting in a language she was born knowing. At the sealed message she had prepared before the flood, before he was ready, trusting that when the time came he would be exactly the kind of boy who came to first light on a dock and walked through reeds where no path was and sat in a village the maps had never heard of and listened to very old people tell him difficult things.\n"What exactly am I agreeing to?" he said. "Not in general. Specifically. What are the terms?"\nLolo Adaeze looked at him with something that was almost a smile. "Your grandmother said you would ask that."\n"What did she say when she said it?"\n"She said: good."\nShe reached into the folds of her cloth and produced a small bowl containing dark liquid, the same dark brown as the ink in the clay pot. She set it on the ground between them.\n"You will touch this," she said. "That is the agreement. One gesture, freely made. The terms unfold from there, as you are ready for them. We will not give you everything at once because everything at once would break you, and we need you whole."\n"I don''t know what I''m agreeing to," he said. "Not fully. Not specifically."\n"No," Lolo Adaeze said. "You do not."\nHe looked at the bowl. He looked at the river through the doorway. He thought about his grandmother''s hand over his in the candlelight, dry and warm and completely certain. He thought about the way she had said go to bed as if she was confident, absolutely confident, in the kind of boy who would come back from whatever came next.\nHe reached out and touched the surface of the liquid with two fingers.\nIt was warm. Warmer than the air, warmer than the fire, warm the way living things were warm. Under his fingers the liquid held still for a moment, and then, slowly, it moved toward him, not spilling, not flowing, just orienting, the way a compass needle oriented, as if it recognised something.\nThe elder woman exhaled softly. The dried-riverbed man nodded once.\nLolo Adaeze looked at him with eleven years of waiting in her face, finally, quietly, at rest.\n"Welcome," she said. "Now we begin."\nOutside, the child stopped drawing and looked at the river, and the river, wide and brown and older than everything around it, moved on.','\n',char(10)),1647,1,1,NULL,'2026-04-06T13:22:53.871Z','2026-04-06 13:22:53','2026-04-06 13:22:53',NULL,1,10);
INSERT INTO "chapters" ("id","novel_id","chapter_number","title","content","word_count","is_premium","is_published","audio_url","published_at","created_at","updated_at","scheduled_release_at","part_number","season_id") VALUES(184,25,8,'She Didn''t Fall In',replace('They did not begin that day.\nLolo Adaeze poured water over his fingers where he had touched the dark liquid, said something in the old language under her breath, and told him to go home and sleep and come back in three days. He had questions stacked up behind his teeth and she looked at each of them, unhurried, and said: three days.\nHe went home.\nHe ate. He called his uncle and gave an accounting of his day that was technically accurate and entirely incomplete. He lay on his back in the dark and stared at the ceiling and did not sleep, not properly, only the shallow half-sleep of a person whose mind had too much to do to fully let go of consciousness. He dreamed in a language he did not yet speak and woke with the grammar of it dissolving before he could hold it.\nTwo days he spent in the compound, moving through the rooms his grandmother had filled for sixteen years, picking things up and setting them down. Her pepper grinder. The photograph of his parents. The wrapper still on the door hook in the kitchen, dry above the waterline, still carrying the smell of a woman who had cooked in this kitchen every day of his life and who had packed that smell into the fabric so thoroughly that he thought it might outlast everything else.\nHe did not allow himself to think about the thing Lolo Adaeze had told him, not directly. He thought around it, the way you thought around a bright light, approaching it sideways, in pieces, never looking straight at the full shape of it.\nShe went into the river because the time came for the handover.\nShe cannot come back until you have accepted what she is passing to you.\nOn the morning of the third day he put on his shoes and walked to the silk-cotton tree and north along the bank and into the green channel and through the reeds, and this time the reeds parted even faster, as if they had been expecting him.\nThe village was the same. The fire in the central space, the curved buildings, the chickens. The child was not in the yard today. The village had the particular quiet of a place that did not need noise to feel inhabited, the same quality as the river, present and full without announcement.\nLolo Adaeze was waiting outside her structure. She looked at him the way she had looked at him the first day, reading the whole of him, and whatever she read seemed to satisfy her.\n"You did not sleep," she said.\n"Not well."\n"That will change." She went inside and he followed.\nThe three elders were there again. Same stools. Same positions. The fire between them, no smoke. He sat and looked at Lolo Adaeze and said, "Tell me everything. From the beginning. All of it."\nShe nodded. She had been waiting for him to say exactly that.\nShe began with the agreement itself, the one made so long ago that even she knew only the shape of it, not the moment of its making. The river and the people on the bank. The terms of the relationship. The bridge keepers who maintained it across generations, each one passing the role to the next, each handover requiring the same thing: the outgoing keeper stepping fully into the river''s world, so that the threshold was clear, so that the new keeper had no one to lean on but themselves.\nHe listened. He did not interrupt.\n"Your grandmother knew for most of her adult life that the handover was coming," Lolo Adaeze said. "The river tells the keeper when the time is approaching. Not a date. A feeling. A drawing in, the way the tide draws in before it turns." She paused. "She told us, some years ago, that the drawing had begun."\n"How many years?"\n"You were perhaps eleven."\nHe thought about himself at eleven. Serious, already certain, already building the framework of logic that he had carried into every classroom and conversation since. Already telling his grandmother, probably, that her stories were not real.\n"She did not go into the flood," Lolo Adaeze said. "She went into the river. The flood was the river''s way of providing a moment where the going would look like something else."\n"So that I would think she was taken," Nnamdi said. "Not that she left."\n"So that the world would think that. The world does not need to know the true mechanism. It does not have the framework for it and it would only cause your grandmother difficulty that would not serve anyone." She looked at him steadily. "But you needed to know. She always intended you to know. That is what the pot was for, what this village was for, what Ikenna was for. She built a path from her going to your knowing, and she built it carefully, because she knew you would only follow it if each step made sense before you took the next one."\nNnamdi was quiet.\nThe full shape of it was visible now and he was looking straight at it.\nHis grandmother had stood in the sitting room by candlelight and given him the pot and told him the river knew his name. She had done it on the night she had chosen, the night the river had agreed to provide the flood that would explain her absence to the world. She had sent him to bed. She had waited until he was sleeping. And then she had walked, on her own two feet, with full knowledge of what she was doing and why, into the water.\n"She sat across from me," he said. "She held my hand. She said she had things she should have told me, and that next year was not coming the way she planned." His voice was level. He was keeping it level the way you kept a vessel level when it was very full. "She knew. She knew exactly what was happening that night."\n"Yes."\n"She looked at me and she knew she was looking at me for the last time. From this side."\n"Yes."\nHe breathed in. Out. The fire shifted between them.\n"She could have told me," he said, and the levelness of his voice did not quite hold on the last word, the smallest fracture in it, almost nothing.\nLolo Adaeze was quiet for a moment. Then she said: "If she had told you, what would you have done?"\nHe opened his mouth.\n"You would have argued," she said. Not unkindly. "You would have sat across from her with all of your rigorously empirical certainty and you would have told her that none of it was real. You would have been frightened and you would have expressed it as logic, and she would have had to choose between her going and your comfort, and she had already carried that choice for eleven years and she knew which one had to win." A pause. "She chose to let you grieve an accident rather than argue with a decision she could not unmake. She chose to leave you a path rather than an explanation, because she knew you would follow a path and she was not sure you would accept an explanation."\nThe child he had been at eleven looked back at him from somewhere inside his chest. The boy who had told his grandmother, with the complete confidence of someone who had never been wrong about anything, that her stories were not real. He looked at that boy and felt something move through him that was made of several feelings at once, grief and love and a guilt he would have to learn to carry at the right weight.\n"She was not wrong," he said finally. "About what I would have done."\n"No," Lolo Adaeze said. "She was not."\nHe looked at the clay pot sitting between them. At the message inside it, still unread, in a language he was just beginning to be taught. His grandmother had written it to him. Had pressed the words into the material with care, character by careful character, and sealed it, and left it in the path of a flood, trusting that the river would leave it standing.\n"The message," he said. "In the pot. What does it say?"\nLolo Adaeze looked at him for a moment. "You will read it yourself. When you have enough of the language to read it, you will have enough of yourself to receive it. Those two things will happen at the same time."\nHe accepted this. It was the kind of answer he was learning to accept, not because he had stopped wanting immediacy but because he was beginning to understand that some things arrived only when you were built enough to hold them.\n"What happens now?" he asked.\n"Now we teach you. The language first, then the deeper things. It will take time. It will require you to hold two worlds at once, the one you know and the one you are entering, without dropping either of them." She looked at him with the full weight of her waiting, all eleven years of it, finally in motion. "This is not a small thing we are asking."\n"I know."\n"Your grandmother knew you would say that too." The elder woman''s voice, quiet from her stool. "She said: he will say I know, and he will mean it, because he is the kind of boy who does not say things he does not mean."\nNnamdi looked at the fire. He thought about his grandmother in the river''s world, in whatever form that took, waiting with the patience of someone who had spent a lifetime being patient. Waiting for the boy she had prepared across sixteen years to become large enough to come and find her.\nHe was not large enough yet. He knew that plainly. But he was larger than he had been the night of the flood, larger than the boy who had put his phone on the table when she asked and told himself the rain was just rain and gone to sleep while she said goodbye.\nHe was going to learn the language. He was going to read her message. He was going to find out what the river kept and what it asked and what it meant that his name had been known here longer than he had been alive.\nAnd at the end of all that, he was going to find the place where the river held the things it needed, and he was going to stand at the edge of it, and he was going to bring his grandmother home.\nHe picked up the clay pot and held it in both hands, the weight of it familiar now, the weight of everything it carried pressed against his palms.\nOutside the village, the Niger moved in the afternoon light, wide and brown and full of everything it had ever been given to keep. It had known his name before he was born. It had arranged the flood and the pot and the fisherman and the green channel and the child drawing the old script in the dirt, had arranged all of it across years and generations, had waited with the absolute patience of something that did not experience time the way he did.\nHe was beginning, just beginning, to understand what it meant that the river had chosen him.\nIt did not mean he was special.\nIt meant he was responsible.\n\nEnd of Season 1: The Language Before Words\nSeason 2: What the Water Keeps','\n',char(10)),1943,1,1,NULL,'2026-04-06T13:25:22.693Z','2026-04-06 13:25:22','2026-04-06 13:25:22',NULL,1,10);
INSERT INTO "chapters" ("id","novel_id","chapter_number","title","content","word_count","is_premium","is_published","audio_url","published_at","created_at","updated_at","scheduled_release_at","part_number","season_id") VALUES(185,26,1,'The Bridge Keeper''s Apprentice',replace('The language had forty-three characters.\nNnamdi knew this by the end of his second week in the village because he had counted them the way he counted everything, methodically, cross-referencing each new character Lolo Adaeze introduced against the ones he had already catalogued, building a table in the back of his notebook that his secondary school teachers would have recognised as the work of a boy who could not encounter a system without immediately trying to map it.\nLolo Adaeze watched him build the table and said nothing for three days. On the fourth day she sat beside him, looked at the table, and said: "Forty-seven."\nHe looked up.\n"You have counted forty-three," she said. "There are forty-seven. The last four are not written. They are felt. When you are ready for them you will know, not because I tell you but because they will arrive." She tapped the table with one finger. "But this is good work. Your grandmother kept a table like this when she was learning. Hers had forty-one before she found the rest."\nHe beat his grandmother''s record by two characters, and he was not proud of this exactly, but he held it quietly in the place where he kept the things that mattered.\nHe was coming to the village every day now.\nThe rhythm of it had established itself with a naturalness that surprised him. He rose early, ate, left a note for his uncle on the days his uncle was in the compound, walked the bank north past the silk-cotton tree and through the green channel and into the reeds. The reeds parted. The village received him. He sat with Lolo Adaeze or one of the other elders and learned. In the late afternoon he walked back through the reeds and the channel and along the bank and into the life he had always known, which was still there, still running, still making its ordinary demands. He ate dinner. He did his schoolwork. He called his uncle. He slept.\nHe was holding two worlds. It was not seamless. There were moments, sitting in his school classroom with the ceiling fan turning overhead and his chemistry textbook open on the desk, when the village felt like something he had imagined. And there were moments in the village when his school, his uncle, the compound on the bank, felt like the dream. He had not yet found the place in himself where both could be fully real simultaneously. He was looking for it.\nOn the fourteenth day Lolo Adaeze said: "Today you do not come to me."\nHe was sitting on his stool with his notebook open. He looked at her.\n"Today someone else begins your education." She stood. "Come."\nShe led him across the village to a structure he had not entered before, set slightly apart from the others at the village''s edge nearest the river. It was built differently from the rest, lower to the ground, the walls thicker, the roof layered in the same dark woven material but more of it, as if whoever lived here needed more weight between themselves and the sky. A garden of sorts surrounded it, though garden was not quite the right word. Plants he could not name grew in careful rows, some with leaves the colour of river water, some with roots that ran along the surface of the ground rather than beneath it, visible and exposed, as if they needed to be seen.\nLolo Adaeze stopped at the entrance and did not go in.\n"She is expecting you," she said.\n"Who is she?"\n"Her name is Mama Eze. She was your grandmother''s teacher." A pause, the weight of it deliberate. "She has been teaching bridge keepers on this river for a very long time."\nHe looked at Lolo Adaeze. She looked back at him with the expression she wore when she had told him everything she intended to tell him for now.\nHe went in.\nThe interior was one room. Dark, cool in the way of thick walls and deep shade, the light entering through a single high window in a column that fell on the centre of the floor and lit nothing useful. It took his eyes a moment to adjust and when they did he found the room full of things. Not cluttered. Arranged. Pots of varying sizes on every surface, some sealed, some open, some containing liquids and some containing materials he could not identify from across the room. Bundles of dried plants hanging from the low ceiling. Lengths of the same reed material he had found in his grandmother''s clay pot, rolled and stacked with the precision of a library. And in the far corner, on a low stool that seemed designed to be as close to the ground as possible while still being technically a seat, an old woman.\nShe was the oldest person he had ever seen.\nHe knew this immediately and completely, not from counting the lines on her face, which were beyond counting, but from the quality of the stillness around her. Ikenna was old in a way that had stopped being a number. This woman was old in a way that made Ikenna seem young. She sat with her hands in her lap and her eyes closed and her breathing so slow and so complete that each breath seemed to be doing the work of several.\nThen she opened her eyes.\nThey were clear. Not clouded the way he expected, not the diminished eyes of extreme age. Clear and very direct and moving over him with an attention so thorough that he felt, briefly, like something being read.\n"Sit," she said. Her voice was small but not weak. The smallness was economy, nothing wasted.\nHe sat on the floor, since there was no other stool. She looked at him sitting on the floor and something in her face shifted, the smallest movement.\n"Your grandmother always sat on the floor too," she said. "The first time. She said the stool felt presumptuous." She reached beside her and produced a stool from somewhere behind her that he had not seen. She set it in front of her with a steadiness of hand that his brain quietly refused to reconcile with her age. "Take the stool, Nnamdi."\nHe took the stool.\nShe looked at him for a long time. He let her look.\n"How much has Lolo told you?" she said.\n"The agreement between the river and the people on the bank. The bridge keeper''s role. The mechanism of handover. The language, forty-three characters and four more I cannot access yet." He paused. "My grandmother. Why she went."\nMama Eze nodded slowly. "And what do you understand about what a bridge keeper actually does? Not the history of it. The work itself."\nHe opened his mouth and then closed it. He had the information about the role. He could describe it, the carrying of messages, the maintenance of the relationship. But she had said understand, and he was honest enough to know those were different things.\n"Not enough," he said.\n"Good answer." She reached into the folds of her cloth and produced a length of the reed material, blank, unwritten. She held it toward him. "Take this."\nHe took it.\n"Hold it flat on your palms. Both hands. Like you are offering it to someone."\nHe did. The material was lighter than it looked, lighter than it had any reason to be, and warm in a way that was not his hands warming it.\n"A bridge keeper does not simply carry messages," Mama Eze said. "A bridge keeper translates. Not language to language. World to world. What the river knows and what the people on the bank can receive are not the same things. The river does not speak in human terms. It speaks in water. In current and depth and the memory of everything that has ever entered it." She looked at his hands, at the material lying across his palms. "Your grandmother''s job was to take what the river said and find the closest human equivalent. And to take what the people on the bank needed and find a way to bring it to the river''s attention."\n"How?" he asked.\n"By being both," she said. "By standing with one foot in each world long enough that your body learns to carry both. It changes you. Not in ways that are visible to people who are not looking. But in ways that are real." She paused. "Your grandmother had a piece of the river in her. You will have felt it. In her water. In the way she knew things before they arrived. In the way she was never quite surprised by anything."\nHe thought about his grandmother and the weather app and her patience with his technology and the way she had looked at the cracked compound wall the night before the flood as if she already knew what the river was planning.\n"Yes," he said quietly.\n"That is what you are building toward. But it is a long building." She looked at him with eyes that had watched his grandmother learn the same things from the same stool. "Your grandmother was a good keeper. One of the best I have taught in many years. Patient, precise, honest with the river and honest with the people she served." A pause. "She was also stubborn in ways that caused difficulty, and she underestimated how quickly things could move when the river decided to move them." She said this without criticism, just fact, a teacher''s complete assessment of a student she had loved. "I expect you have her stubbornness."\n"I have been told I am rigorously empirical."\nMama Eze''s face moved again, that small interior shift. "Yes. She told me about that." She reached over and touched the material in his hands, lightly, one finger tracing a character he recognised from his table, and then another, and then one he did not recognise, one of the four he had not yet reached. Under her finger the character seemed to sit differently on the surface, as if it had been waiting to be pointed out.\nHe looked at it and felt something he could not name move through the center of his chest.\n"What does that one mean?" he asked.\n"You tell me," she said. "You felt something when you saw it. What was it?"\nHe looked at the character. The feeling had been brief and he chased it now, trying to hold the shape of it before it dissolved. It had been like recognition but not of something he had seen. Recognition of something he had always known and simply never had a name for. The feeling of a word arriving for a feeling you have carried wordlessly your entire life.\n"Coming home," he said. "But not to a place. To a version of yourself."\nMama Eze was quiet. Then she said: "Your grandmother took three weeks to reach that character. You are here in fourteen days." She took the material from his hands gently and rolled it and set it aside. "Rest now. Eat something from the garden, the plants with the flat leaves near the door, they are safe. Come back tomorrow at first light."\n"What are we doing tomorrow?"\n"Tomorrow," she said, "you begin to learn how to listen to the river." She closed her eyes, which was clearly the end of the conversation. "It will be the hardest thing you have ever done. Harder than the language. Harder than the walking through the reeds. Because you have spent sixteen years learning to trust only what you can verify, and the river does not verify. It simply speaks." Her breathing slowed back to its extraordinary depth. "You will need to learn to hear it before you decide whether to believe it."\nHe stood. He looked at the room, at the rolled lengths of material stacked with the precision of a library that had been assembled over an unthinkable amount of time. He looked at Mama Eze on her low stool, eyes closed, already somewhere he could not follow yet.\nHe ate a leaf from the flat-leafed plant near the door. It tasted like clean water and something underneath clean water, something mineral and old.\nHe went home through the reeds and the green channel, and that night he sat at his desk and opened his chemistry textbook and stared at it for a long time, and then he closed it and opened his notebook instead and sat with the character Mama Eze had traced, drawing it over and over in the margin until his hand knew its shape by heart.\nComing home to a version of yourself.\nHe was beginning to understand that this was not a journey to somewhere else.\nIt was a journey to something in him that had always been there, waiting with the patience of a river, waiting for the boy who needed to be built before he could receive it.','\n',char(10)),2168,0,1,NULL,'2026-04-06T13:30:53.679Z','2026-04-06 13:30:53','2026-04-06 13:30:53',NULL,2,11);
INSERT INTO "chapters" ("id","novel_id","chapter_number","title","content","word_count","is_premium","is_published","audio_url","published_at","created_at","updated_at","scheduled_release_at","part_number","season_id") VALUES(186,26,2,'The Ones Who Stayed',replace('He smelled the food before he cleared the reeds.\nSomething frying in hot oil, onions and something spiced underneath, carrying across the morning air with the confidence of a smell that knew it had nowhere better to be. His stomach responded before his brain did, loud enough that the reeds seemed to hear it, and he came out into the village already embarrassed.\nThree people his age were sitting around the fire in the central space.\nNot elders. Not children. Three teenagers, his age or near enough, sitting on the low stools with the ease of people who had been sitting on those stools long enough that the stools had learned their shapes. A girl was tending a clay pot over the fire with the focused attention of someone who took cooking seriously as a discipline. A boy across from her was doing something with a length of the reed material, marking it with a small tool, not writing exactly, more like correcting, the way you corrected a document you had read before. A second girl sat slightly apart from both of them with her knees pulled to her chest and her eyes on the river, and she turned when Nnamdi came through the reeds with the precise timing of someone who had heard him coming for longer than was acoustically reasonable.\nShe looked at him. He looked at her.\n"You are late," she said, in Igbo.\n"I was not told there was a time."\n"Mama Eze said first light."\n"It is first light."\nShe looked at the sky with an expression that said she disagreed about this but would not press it, and turned back to the river.\nThe girl at the fire looked up. She was round-faced with close-cut hair and the kind of steady, appraising eyes that reminded him of a teacher taking attendance. "Sit down," she said. "You look like you are trying to decide whether we are real."\nHe sat. "I am not."\n"You are." She lifted the pot from the fire and set it on a flat stone. "Everyone does it the first time they see us. You think you are the only one and then you find out you are not and your face does the thing." She gestured at her own face without specifying what the thing was. "I am Adaora. The one correcting his script for the third time this week is Emeka, and the one watching the river like it owes her an apology is Simi."\nEmeka looked up briefly, nodded, and returned to his correction with the focus of someone who did not consider introductions worth interrupting real work for. Simi did not turn around.\n"Nnamdi," he said.\n"We know," Adaora said. "Mama Eze told us you were coming." She served food into a bowl and held it toward him. Akara again, and something else, a stew he did not recognise with a smell that was extraordinary, dark and layered and deeply serious. "Eat. We have been waiting to meet you."\nHe ate. The stew was as serious as it smelled. He did not ask what was in it because he had learned in the past two weeks that some questions in this village were answered with more than he was ready for before breakfast.\n"How long have you been coming here?" he asked.\n"I have been here three years," Adaora said. "My mother brought me the first time. Her mother brought her. My family has ties to the river going back further than any of us have managed to trace." She said it without performance, just fact, the way she said everything, clean and direct. "Emeka is two years. His grandfather was a keeper on a different part of the river, the lower delta, before the oil companies changed the water chemistry and the connection broke. He came here to find the closest thing left."\nEmeka made a sound without looking up that was either confirmation or disagreement.\n"Simi," Adaora said, and paused. "Simi''s situation is different."\n"Different how?" Nnamdi said.\nSimi turned from the river then. She was tall even sitting, with a long face and the particular quality of stillness he had come to associate with the village and everyone in it, except on her it sat differently, less like peace and more like something held very tightly in check.\n"My grandmother did not make it," she said. "The handover was not completed. She went in and I was not ready and she waited and I was still not ready and after a certain amount of time the river makes a decision without you." She looked at him with eyes that had something old in them, not old the way Mama Eze''s eyes were old but old the way grief was old, the kind that had been carried long enough to become part of the person carrying it. "She is still in there. But the window for the handover is closed. The role passed to someone else in another line."\nThe fire moved between them. Nnamdi did not offer condolences because Simi''s face was not asking for them.\n"Why are you still here then?" he said.\nAdaora made a small sound. Emeka looked up for the first time properly.\nSimi looked at him for a moment with an expression he could not read. Then something in it shifted, not quite a smile but the shape a smile made before it decided whether to arrive. "Because I am not finished learning. The role passed but the knowledge does not disappear just because the window closed. I am still my grandmother''s grandchild. The river still knows my name, just differently now." She turned back to the water. "I stay because this is the truest place I have found. Everything else I have tried to do with my life has felt like a translation of this."\nHe thought about his school classroom and the ceiling fan and the chemistry textbook and the feeling of the village dissolving into something imagined.\n"I know that feeling," he said.\nSimi looked at him again, properly this time. "Yes," she said. "I can see that you do."\nEmeka set down his reed material and stretched his arms above his head and looked at Nnamdi with the direct, assessing look of someone who had been paying attention while pretending not to. "How far are you in the language?"\n"Forty-three characters confirmed. Working toward the remaining four."\n"Forty-three in two weeks." Emeka looked at Adaora. She raised her eyebrows in a way that communicated something between them. He looked back at Nnamdi. "I was at thirty-one at two weeks. Adaora was at thirty-eight."\n"Adaora is not a fair comparison," Adaora said. "I grew up hearing fragments of the language from my mother. I had a head start."\n"What is the forty-fourth character?" Emeka asked. Not testing him, genuinely asking, with the interest of a peer comparing notes.\n"I have not accessed it yet."\n"It comes as a sound before it comes as a shape," Emeka said. "You will hear it first, probably in the river, and then you will know the character. At least that is how it came to me." He picked up his work again. "Mama Eze will not tell you this. She believes in finding your own path to each one. I do not see the point in suffering when there is someone right here who has walked the path before you."\nAdaora made the sound again, the small one. "This is also why Emeka''s corrections are still ongoing after two years."\n"My corrections are refinements."\n"Your corrections are because you rushed."\n"I refined quickly," Emeka said with the serenity of someone who had lost this argument many times and had made peace with losing it.\nNnamdi watched them and felt something settle in his chest that he had not known was unsettled. He had been carrying the strangeness of this place alone for two weeks, the green channel and the village and Lolo Adaeze and Mama Eze and the forty-three characters and the four he had not reached, carrying all of it inside the ordinary container of his daily life with no one to carry any of it with him.\nHere were three people who knew the weight of it. Who had found their own ways to hold it and who sat around a fire in a village that did not appear on any map and argued about the pace of learning with the ease of people who had argued about it enough times that the argument had become a kind of affection.\n"Mama Eze is expecting me," he said.\n"She is always expecting you," Adaora said. "She has been expecting you for longer than you have been alive. Another ten minutes will not disturb the timeline." She refilled his bowl without asking. "Finish eating first. Whatever she is going to teach you today will require all of you, and half of you is currently hungry."\nHe finished eating.\nThe river moved along the far edge of the village, carrying its ordinary extraordinary business, and for the first time since the flood Nnamdi did not sit beside it feeling like a person on the outside of something looking in.\nHe sat inside it, among people who understood, and let the morning do what mornings did.','\n',char(10)),1554,0,1,NULL,'2026-04-06T13:32:13.362Z','2026-04-06 13:32:13','2026-04-06 13:32:13',NULL,2,11);
INSERT INTO "chapters" ("id","novel_id","chapter_number","title","content","word_count","is_premium","is_published","audio_url","published_at","created_at","updated_at","scheduled_release_at","part_number","season_id") VALUES(187,26,3,'A Memory That Isn''t His',replace('Mama Eze told him to sit at the river''s edge and listen.\nNot for anything specific. Not with any tool or method. Just sit, she said, the way you sat with a person you were still learning, without agenda, without the pressure of needing them to be anything other than what they were. She said this and went back inside her structure and left him there, which he was beginning to understand was her primary teaching method. She pointed him at things and walked away, and the walking away was the lesson.\nHe sat.\nThe bank at the village''s edge was different from the bank behind his compound. The same river, technically, the same brown water moving in the same direction toward the same sea, but the feeling of it here was different in a way he had stopped trying to explain scientifically and started simply noting as fact. The water here moved with more intention. Not faster. More deliberate, the way a person moved through a room they knew well versus a room they were navigating for the first time.\nHe sat with his feet near the waterline, not in it, and tried to do what she said.\nHe lasted four minutes before his mind produced a list of things he should be doing instead. Schoolwork. The unanswered messages from his uncle. The NEMA updates he had been tracking less obsessively now, their language of search and recovery feeling increasingly beside the point. He pressed the list flat and returned to the river.\nSeven minutes. Eight. Ten.\nAt some point he stopped counting.\nThe river had a sound underneath its surface sound. He had noticed this before but explained it as water moving over different densities of riverbed, varying resistance producing varying frequencies. This was still probably true. But the sound underneath the surface sound had something else in it today, a quality he could not reduce to riverbed density, a quality that sat at the edge of pattern the way the old language sat at the edge of language he already knew. Almost. Almost.\nHe leaned toward it, not physically, something else leaning, something inside him that did not have a name yet.\nAnd the riverbank disappeared.\nNot gradually. Between one breath and the next he was somewhere else, fully, completely, with no sense of transition. No dissolving of one scene into another the way dreams dissolved. Simply: he was no longer at the river''s edge in the village. He was standing in a market.\nThe market was loud and packed and entirely real. Not a vision, not a dream-image, not the thin constructed feeling of imagination. Real in the way the village was real, in the way Mama Eze''s room was real, the full sensory weight of an actual place. He could feel the ground under his feet, hard-packed earth worn smooth by years of traffic. He could feel the heat, thick and physical, pressing on his neck and shoulders. He could smell roasting corn, palm oil, the iron smell of fresh meat, unwashed bodies, cloth, dust.\nBut the market was wrong.\nThe stalls were built from materials he did not recognise, dark wood and woven reed, no plastic, no metal frames, no printed signage. The cloth on sale was hand-dyed in patterns he had never seen, deep indigo and ochre and black in geometries that reminded him of something he could not place. The people around him were dressed in wrappers and tunics that had no relationship to anything in his experience, not traditional dress as he knew it, something older, something that preceded the version of tradition he had grown up understanding as traditional.\nAnd he was not himself.\nHe understood this slowly and then all at once. He was standing upright in a body that was not his body, taller than him, broader, with hands that were a man''s hands and not a sixteen-year-old''s. He looked down at these hands, dark-skinned and calloused, carrying something, a clay vessel sealed with dark wax, smaller than his grandmother''s pot, and the feeling of the vessel in these hands was so familiar that it moved through him like a current.\nHe was a man. He was in a market that did not exist anymore. And he knew, with a certainty that came from inside the memory rather than from any observation he was making, that he was on his way to the river.\nHe walked. Not because he decided to. The body knew where it was going and went, and he went with it the way water went with a current, present but not directing. Through the market, past stalls and voices and the ordinary commerce of a day in a time he had no name for. People nodded at the man whose body he was wearing. One woman touched her chest briefly as he passed, a gesture of acknowledgment that was more than acknowledgment, the kind of gesture you made at someone who carried a particular weight.\nBridge keeper.\nHe felt the knowledge arrive fully formed, not as thought but as fact embedded in the body he was occupying. This man was a bridge keeper. Had been a keeper for twenty years. Was on his way to the river to complete a task that was urgent, that had been building for weeks, that the river had been signalling about in ways that had been keeping him awake.\nThe market thinned. The river appeared ahead, wide and brown and exactly the same river, unchanged across whatever centuries separated this moment from his own. He walked to the bank and crouched at the waterline and placed the clay vessel on the surface of the water.\nIt floated.\nHe said something. Words in the old language, the language of forty-three characters and four more he had not reached, and he understood every word of it, heard it in his own voice coming from the man''s throat, felt the shapes of it as naturally as breathing. The river received it. Not metaphorically. The water around the vessel moved in a pattern that was not current, not wind, not any fluid dynamic he had studied. It moved in response.\nAnd the river spoke back.\nNot in sound. In knowing. The knowing arrived in the man''s chest and therefore in his chest, direct and complete, bypassing language entirely, and what the river said was something he felt rather than heard, a feeling that translated, imperfectly, into: we see it. we are moving. trust the current.\nThe man exhaled.\nAnd Nnamdi was back.\nHe was sitting at the bank at the village''s edge with his feet near the waterline and his hands pressed flat against the ground and the afternoon light low and golden around him, which meant hours had passed, which meant he had been gone for hours, which was impossible because it had felt like twenty minutes at most.\nHe sat very still and did not move for a long time.\nThe memory was not dissolving the way dreams dissolved. It was sitting in him with full weight, full colour, every sensory detail intact and solid. The sound of the market. The heat. The feeling of the clay vessel in hands that were not his hands. The words in the old language arriving in his mouth like something he had always known. The river''s answer moving through the man''s chest like a current.\nHe looked at his own hands. Sixteen years old, familiar, entirely his own.\nHe was shaking slightly. He pressed his hands flat against the earth until the shaking stopped.\nMama Eze was sitting behind him. He did not know when she had come out. She was on a low stool several feet back from the bank, watching him with her clear old eyes.\n"How long ago did he live?" Nnamdi asked. His voice came out steady. He was grateful for that.\n"Four generations before your grandmother," she said. "His name was Obiora. He was considered the finest keeper of his time."\n"I spoke the language. In the memory. I understood all of it."\n"Yes."\n"I understood all forty-seven characters." He paused. "I understood the four I had not reached yet."\n"Yes," she said again.\nHe sat with that. The implication of it was enormous and he was approaching it carefully, the way you approached something structural that you were not certain would hold your weight.\n"He is in me somewhere," Nnamdi said. "That memory came from inside me, not from outside."\n"The line carries more than blood," Mama Eze said. "This is something your biology classes did not cover." She stood with her usual impossible ease. "Come inside. Drink water. What you experienced takes something from the body and it needs to be replaced."\nHe stood. His legs were unsteady for a moment and then were not.\n"Mama Eze," he said. "The man in the memory. Obiora. He was going to the river because something was wrong. The river told him it was moving, that he should trust the current." He looked at her. "What was wrong?"\nMama Eze looked at him for a long moment with an expression that sat between a teacher''s satisfaction and something heavier, something that knew where this question eventually led.\n"Come inside," she said. "That is a conversation for when you are sitting down."','\n',char(10)),1552,0,1,NULL,'2026-04-06T13:33:20.117Z','2026-04-06 13:33:20','2026-04-06 13:33:20',NULL,2,11);
INSERT INTO "chapters" ("id","novel_id","chapter_number","title","content","word_count","is_premium","is_published","audio_url","published_at","created_at","updated_at","scheduled_release_at","part_number","season_id") VALUES(188,26,4,'What His Name Means',replace('The conversation Mama Eze had promised him did not happen that day.\nShe gave him water and a bowl of something warm and sat across from him in her dim room and watched him drink and eat and slowly return to the full weight of himself, and when he opened his mouth to ask about Obiora and the thing that had been wrong she held up one finger and shook her head. Not yet. He swallowed the question and finished the bowl and walked home through the reeds in the golden late-afternoon light feeling like a house that had been rearranged while the owner was out, everything in the right place but nothing quite where he remembered leaving it.\nHe did not sleep well again. This was becoming a pattern.\nHe lay in the dark and visited the memory, which was still there, still fully intact, the market sounds and the heat and the familiar weight of the clay vessel in hands that were not his. He tested each detail the way he tested data, pressing on it to see if it would hold. It held. Every sensory particular, solid and consistent, the way real memory was solid and consistent rather than the shifting, logic-resistant texture of dreams.\nObiora. Four generations before his grandmother. The finest keeper of his time. On his way to a river that was signalling something wrong.\nHe fell asleep somewhere near three in the morning and dreamed in the old language and woke knowing two things he had not known the day before, small things, the name of the plant nearest Mama Eze''s door and the specific character in the old script that meant the place where the current changes direction. He wrote them both down before they could dissolve.\nIn the morning he went to the village and found Simi at the river''s edge.\nShe was standing in the water to her ankles, which he had not seen anyone do before, the elders always remained on the bank. Her eyes were open but not focused on anything he could see. He sat on the bank nearby and waited and after a few minutes she came back from wherever she had been and stepped out of the water and sat beside him.\n"You went under yesterday," she said.\nHe looked at her. "You knew?"\n"Adaora felt it. The water changes quality slightly when someone receives a memory. We have all experienced it." She looked at the river. "Who did you get?"\n"A man named Obiora. Four generations before my grandmother."\nSimi was quiet for a moment. "Mama Eze''s face when she heard that name. What did it do?"\nHe thought about it. "She said it was a conversation for when I was sitting down."\n"Then it is a significant name." She pulled her wrapper tighter. "That is how this works. The memories that come first are not random. The river sends what you are ready for, and also what you need, and those two things are not always the same."\nHe sat with that and then said, "She is going to tell me something today that I will not like."\n"Probably," Simi said. "Most of the true things are uncomfortable at first." She stood. "Go. Do not make Mama Eze wait. She is patient but she is also very old and I think she feels the weight of time more than she lets on."\nHe found Mama Eze inside, already on her stool, already waiting, as if she had been sitting in the specific posture of a woman about to say a difficult thing since before he arrived.\n"Sit," she said.\nHe sat.\nShe looked at him for a moment with her clear, reading eyes. "What is your name?"\nHe almost smiled. "You know my name."\n"Say it."\n"Nnamdi."\n"What does it mean?"\nHe had known the meaning his whole life the way you knew the meanings of things that had been told to you so early they became furniture, present and unremarkable. "My father is alive," he said.\n"In the river''s language," Mama Eze said, "the name means something larger than that. The word we translate as father in your name does not refer only to the man who raised you or the man who made you. It refers to the line. Everything behind you that is still living in you. Every keeper who carried what you are now being asked to carry." She paused. "Your name, in the language of this river, means: the line is not broken."\nHe was quiet.\n"You were not named carelessly," she said. "Your grandmother chose it, which your father does not know and would not understand, and she chose it because names in the river''s world are not decoration. They are function. They describe what a thing is and what it is for. Your name was a statement. She was telling the river, at the moment of your birth, that she had heard its claim on you and that she was confirming it."\n"She named me as a promise," he said.\n"She named you as a confirmation of a promise already made." Mama Eze reached beside her and produced a length of the reed material, this one covered in writing he could now read with some fluency, and held it toward him. "Your name appears in this record. Do you see it?"\nHe took the material and found it quickly, his eyes moving through the characters with the ease that had been building over weeks. His name, in the old script, in a line of text that he read slowly, his lips moving slightly as he worked through it.\nHe looked up. "This is a list."\n"It is a record of the river''s claims. Every person whose name the river has known before their birth. Every keeper named before they could speak." She looked at him steadily. "Your name is not at the bottom of that list."\nHe looked at the material again. His name was not at the bottom. It was not near the bottom. It sat in the middle of a list that extended a long way in both directions, generations above him, and below his name, only a few more entries, and then blankness.\n"How old is this record?"\n"Old," she said. "The entries above your name represent approximately four hundred years of keepers on this river."\nHe counted the entries below his name. Seven. Seven names between his and the end of the written record.\n"What happens after the last entry?" he asked.\nMama Eze was quiet for a moment. "That is what Obiora was walking to the river about," she said. "In the memory you received."\nSomething shifted in the room. The fire between them did not move but the quality of the air around it changed, the way air changed before a storm, pressure building in the invisible parts of the atmosphere.\n"Tell me," he said.\n"The river is not simply a presence," Mama Eze said. "It is a living record. It holds everything that has ever been given to it, every memory, every agreement, every name, every act of keeping across the four hundred years in that document and longer before it. But a record requires keepers to remain legible. Without the bridge keeper relationship, without someone translating in both directions, the river''s memory becomes inaccessible. It does not disappear. It becomes unreachable. Sealed." She looked at the document in his hands. "The entries are thinning because the keepers are thinning. Each generation there are fewer people willing or able to take the role. The colonial disruption that buried the knowledge took more than Lolo Adaeze told you. It did not just bury the tradition. It severed connections that had been running continuously for centuries."\n"And if the list ends," Nnamdi said. "If the last keeper is the last keeper and there is no one after."\n"The river does not die," Mama Eze said. "But the agreement ends. What the river has been keeping, all of it, the memories, the names, the four hundred years of accumulated knowing, it returns to the water. Untranslatable. Gone from human access forever." She paused. "Your grandmother was protecting you from knowing the full weight of what you were being asked to carry. She wanted you to come to it in pieces, as you were built to receive it."\nHe looked at his name in the old script on the material in his hands. Not decoration. Function. A statement made at his birth by a woman who had known, even then, what the river needed from the boy she was bringing into the world.\nThe line is not broken.\nShe had named him that as a promise. And she had spent sixteen years quietly, carefully, building the kind of boy who could keep it.\n"The seven names below mine," he said. "Are they alive?"\nMama Eze looked at him with her full attention. "Six are. They are young. Younger than you. The line continues beyond you, if you hold your part of it."\nHe set the material down on the ground between them.\nHe thought about Simi, sitting in the water to her ankles, returning from somewhere he could not follow, staying in the village because it was the truest place she had found even after the window closed. He thought about what it meant to be the name in the middle of a list that the world had agreed to forget.\nHe looked at Mama Eze.\n"What happened to Obiora?" he said. "The thing that was wrong when he went to the river. What was it?"\nMama Eze looked at him for a long moment with eyes that had been looking at this river for longer than he had any framework to hold.\n"That," she said quietly, "is what is happening again now."','\n',char(10)),1640,1,1,NULL,'2026-04-06 13:35:16','2026-04-06 13:35:00','2026-04-06 13:35:16',NULL,2,11);
INSERT INTO "chapters" ("id","novel_id","chapter_number","title","content","word_count","is_premium","is_published","audio_url","published_at","created_at","updated_at","scheduled_release_at","part_number","season_id") VALUES(189,26,5,'The Bargain His Grandmother Made',replace('\nHe did not ask Mama Eze to continue that day.\nHe could see in her face that she had given him the last thing she intended to give him for now, the door closed behind her final sentence with the quiet finality of a door that knew its own weight. He thanked her and gathered his things and walked home through the reeds and spent the evening sitting at his desk staring at his notebook without writing anything in it.\nThat is what is happening again now.\nHe wrote the sentence down, finally, at the bottom of a page, and stared at it.\nWhatever Obiora had walked to the river about four hundred years ago, whatever had been wrong enough to keep a keeper awake and moving urgently through a market with a sealed clay vessel, it was happening again. In his time. On his watch. With him at the middle of a list that was running out of names.\nHe slept badly and rose early and was in the village before Adaora had finished making the morning fire.\nShe looked at him across the flames with her steady, appraising eyes. "You have the face," she said.\n"What face."\n"The one where you have just understood how serious things are and you are deciding whether to be frightened or useful." She handed him a cup of water. "Be useful. It is less exhausting."\n"I need to speak to Lolo Adaeze."\nAdaora looked at him for a moment. "Not Mama Eze?"\n"Mama Eze tells me what I am ready for. Lolo Adaeze told me on the first day that she would tell me everything." He drank the water. "I need everything now."\nHe found Lolo Adaeze at the far end of the village, standing at the river''s edge with her arms at her sides and her white hair bright in the early light, looking at the water with the focused attention of someone reading a document. She did not turn when he approached but said, "I was wondering when you would come to me directly."\n"I should have come sooner."\n"You came when you were ready. This is the correct time." She turned then and looked at him with her full height and her full attention. "Walk with me."\nThey walked along the bank, away from the village, into the quieter stretch where the trees grew close to the water and the light came through in pieces. She walked with her hands behind her back and did not speak until the village sounds had thinned completely.\n"Your grandmother came to me when she was twenty-two," Lolo Adaeze said. "She had been a keeper for four years, inherited the role early because her mother became ill and the handover was accelerated. She was skilled and she knew it and she was also frightened in ways she would not admit, which is a dangerous combination." She paused. "The river was already showing signs of strain. The keeper network was thinner than it had been in living memory. The colonial disruption had done its work and the generation that should have replenished the network had not. Your grandmother understood what this meant. The implications of it."\n"The list ending," Nnamdi said.\n"More than the list. The river had been holding its record for centuries, carrying it in trust, in the expectation that the bridge keeper relationship would continue. When it became clear that the relationship was fracturing, the river began to do what any keeper of a record does when the record is under threat." She looked at the water. "It began to consolidate. To pull its most critical holdings closer to its center. Away from the banks. Away from the places where human access was still possible."\n"It was protecting the record," he said.\n"Yes. But protection at that depth comes with consequences. The river pulling inward means less exchange. Less translation. The things that the bridge keeper relationship had always maintained, the balance between what the water took and what it returned, flood patterns, fish migrations, the fertility of the bank soil, all of it begins to drift without someone managing the relationship actively."\nHe thought about the floods in recent years, the ones on the news that the weather services kept calling unprecedented. The fish yields his uncle had mentioned once, dropping annually. The bank erosion that had been quietly widening for as long as he could remember.\n"Your grandmother saw all of this," Lolo Adaeze continued. "And she went to the river and she made a bargain."\nThey stopped walking. The water moved beside them, unhurried, carrying its freight of silt and memory.\n"She asked the river to hold its record intact," Lolo Adaeze said. "Not to pull it further inward. To maintain the terms of the original agreement as if the keeper network were still at full strength, to keep the balance, to keep the exchange, even as the human side of the relationship was failing." She looked at him. "This was not a small thing to ask. The river had been contracting for good reason. She was asking it to remain open and exposed on the strength of a promise."\n"What promise?"\nLolo Adaeze turned to face him fully.\n"She promised the river a keeper," she said. "Not herself. She was already its keeper. She promised the river the next generation. A keeper born into full knowledge, prepared from birth, brought to the role with the kind of intention and completeness that the network had not seen in two generations." She paused. "She made this promise thirteen years before you were born."\nThe morning light came through the trees in pieces and lay on the water in pieces and Nnamdi stood very still inside all of it.\n"She promised him before I existed," he said.\n"She promised the river a keeper who would come. The river accepted the terms. It stopped contracting. It held the record. It maintained the balance, imperfectly, at cost to itself, for thirteen years while your grandmother prepared herself to receive and raise and prepare the child the river had agreed to wait for."\n"And then I was born," he said.\n"And then you were born, and she named you, and she began."\nHe thought about sixteen years of her stories, her patience, her careful precision about the things she told him and the things she waited to tell him. The way she had never pushed, never forced, had let him build his frameworks and his certainty and his rigorous empiricism and had watched all of it with the equanimity of someone who knew that the building was necessary, that the wall had to be solid before it could be asked to open.\n"She gave the river me," he said. Not with bitterness. Just with the plainness of a thing that needed to be said plainly.\n"She gave the river the possibility of you," Lolo Adaeze said carefully. "There is a difference. The bargain was not a transaction. She did not sell you or assign you. She promised that if the river held, she would bring forward the best-prepared keeper she could. What you do with that preparation is still your choice. It has always been your choice." She looked at him steadily. "Your grandmother understood the difference between preparing someone and deciding for them. She prepared you completely. She decided nothing."\nHe thought about the bowl of dark liquid and his two fingers touching its surface and the warmth of it orienting toward him like a compass needle.\nHe had made his own choice. She had trusted that he would.\n"The thing that is happening again," he said. "The thing Obiora walked to the river about. The thing Mama Eze said is happening now."\n"Yes."\n"The river is contracting again."\nLolo Adaeze was quiet for a moment. "Your grandmother''s bargain bought time. She held her end for over thirty years. But a bargain sustained by one keeper, alone, aging, with no network behind her, with the weight of the whole relationship resting on one set of hands, that is a bargain under enormous strain." She looked at the water. "When she stepped into the river, the active human side of the bargain went with her. The river has been holding since then on the strength of what you touched in that bowl. The promise of what you are becoming."\n"How long do I have."\n"Not a precise question for an imprecise situation. But I will tell you this." She turned and began walking back toward the village. "The memory you received. Obiora at the market, walking to the river with his sealed vessel. Do you know what was in the vessel?"\nHe had not thought to wonder. He thought now.\n"A message," he said.\n"A message and an offering. The two things a bridge keeper brings when the river is in crisis. The message says: I am here. I am holding. The offering says: here is proof." She paused. "You will need to bring both, Nnamdi. Soon. Before the river decides that the promise in that bowl is not enough to sustain the wait."\nHe looked at the river moving beside him, wide and brown and full of four hundred years of everything that had ever been given to it. Full of his grandmother, somewhere in its depths, waiting with the patience she had spent a lifetime building into the boy now walking on its bank.\nHe was the bargain his grandmother had made.\nHe intended to be worth it.','\n',char(10)),1587,1,1,NULL,'2026-04-06T13:36:13.681Z','2026-04-06 13:36:13','2026-04-06 13:36:13',NULL,2,11);
INSERT INTO "chapters" ("id","novel_id","chapter_number","title","content","word_count","is_premium","is_published","audio_url","published_at","created_at","updated_at","scheduled_release_at","part_number","season_id") VALUES(190,26,6,'The Spirit That Follows Him',replace('It had been in the corner of his eye since the night of the flood.\nHe understood this only in retrospect, the way you understood things that had always been present once you finally had the framework to see them. A quality of attention in certain moments, a feeling of being observed from a direction that had nothing to do with compass points, something that was not behind him or beside him but adjacent to him in a way that had no spatial word. He had filed it, in the weeks before the village, under grief and stress and the psychological texture of loss. Reasonable explanations for an unreasonable feeling.\nHe was running out of reasonable explanations.\nIt was clearest near water. At the river''s edge in the village, when he sat listening and the surface of his attention thinned enough for other things to come through, he felt it most sharply. A presence slightly outside the frame of whatever he was looking at. Patient in a way that suggested it had been patient for a long time before he started noticing and intended to be patient for a long time after.\nHe mentioned it to Adaora on a Tuesday morning while they were sitting with the fire between them and she looked at him with an expression he could not immediately read.\n"How long?" she said.\n"Since the flood. Maybe before." He looked at his hands. "I thought it was grief doing something to my perception."\n"What does it feel like?"\nHe considered this seriously, the way Mama Eze had taught him to consider the river, without rushing toward a conclusion. "Like being known," he said finally. "Not watched. Known. The way it feels when someone in a room understands what you are about to say before you say it."\nAdaora set down her cup. "Tell Mama Eze today."\n"You know what it is."\n"I have a strong idea," she said. "But it is not my thing to tell. Tell Mama Eze."\nHe told Mama Eze.\nShe listened with her eyes closed, which was how she listened when she was giving something her full attention rather than just her ears. When he finished she was quiet for long enough that he thought she might have fallen asleep, which had happened once before and which he had learned not to take personally.\nThen she opened her eyes and looked at him with an expression that was made of several things at once, satisfaction and gravity and something underneath both of them that he thought, reading her face with the fluency he had been building, might be relief.\n"Go to the river," she said. "Now, while the light is this way." She meant the afternoon light, low and golden and particular, the light that seemed to reach further into the water than midday light did. "Sit at the edge. Do not go in. Do not lean toward it or invite anything. Simply sit and allow your attention to go where the light goes."\n"And the thing I have been feeling will show itself?"\n"It has been waiting for you to stop explaining it away," she said. "That is all it has ever been waiting for."\nHe went to the bank.\nThe light was doing what she said, reaching down into the water at a low angle, illuminating the first few feet below the surface in a way that made the river briefly transparent. He could see the sandy bed, the dark stones in their patterns, the occasional movement of something alive passing through the lit column and out the other side.\nHe sat. He let his attention go where the light went.\nFor a long time nothing happened except the river being the river, which he had learned was not nothing. Then the quality of the air to his left changed. Not temperature, not wind. Something else, the quality he had been filing under grief and stress for weeks, but here at the water''s edge with his attention fully open and no explanation ready to hand, he felt it without any buffer between himself and the feeling.\nHe turned his head slowly.\nIt was in the water. Not beneath the surface but at it, the boundary between water and air, occupying the membrane between the two the way oil occupied the surface of water, present in the threshold itself. He could not have said what it looked like because looking was not the right instrument for it. It was not invisible. It was not visible in any way that his eyes were designed to process. It registered in him the way the old language had registered before he had its characters, as something he almost had the vocabulary for, something one layer below the surface of what his senses could fully receive.\nBut he felt its shape.\nOld. Older than the village, older than the record with its four hundred years of names, old in the way the river itself was old, which meant old in a way that preceded the human frameworks he had for measuring age. And attentive, fully and entirely attentive, its attention on him with the quality he had described to Adaora, not surveillance but recognition, the feeling of being known by something that had been knowing him for a long time.\nHe breathed slowly. He did not lean toward it or invite it. He simply sat and allowed.\nThe presence moved. Not toward him. Beside him, taking a position at the water''s edge parallel to his own, as if it were sitting with him rather than appearing to him, a gesture so ordinary in its structure that it briefly made him want to laugh, this ancient incomprehensible thing arranging itself companionably on the bank.\nThen it communicated.\nNot in words. Not in the direct knowing-transfer of the Obiora memory. Something softer than either, a feeling with a direction, the way music could carry an emotion too specific for language. What arrived in his chest was something he translated, carefully, as: I have been here since before you were born. I am not a danger to you. I was assigned.\nHe sat very still inside this.\nAssigned by what?\nThe response came the same way, feeling with direction: by the same thing that put your name in the record before you existed.\nHe looked at the water where the presence sat at its surface, and for a moment, only a moment, in the particular angle of the afternoon light, he saw something. Not a form. A quality of the light itself in that spot, a slight deepening, a density, the way water deepened in color over greater depth. It was there and then it was the ordinary river again.\nHe walked back to Mama Eze.\nShe looked at him when he entered and read whatever his face was doing and nodded once, a small decisive nod.\n"Sit," she said.\nHe sat. "It communicated with me. It said it was assigned."\n"Yes."\n"By the river."\n"By the agreement," Mama Eze said. "When your grandmother made her bargain, the river accepted the terms and assigned a guardian to the promise. Something to remain near the child who had been promised, to know him across his growing, to be present at the threshold when the time came for him to cross." She looked at him. "It has been with you since before the flood. Since before you were old enough to feel it."\nHe thought about sixteen years of his grandmother''s stories, of growing up on the bank, of the feeling he had never had a name for of the river being specifically aware of him in a way it was not aware of everyone. He had always explained it as the narcissism of a child who had been told too many stories about himself.\n"It is not a danger," he said.\n"No. It is closer to what the old language would call a witness. Something that holds the record of who you have been across the time of your growing, so that the river knows exactly what it is receiving when you come fully into the role." She paused. "Every keeper has had one. Obiora had one. Your grandmother had one. They are not sent to protect or to guide. Only to know."\n"Only to know," he repeated. He sat with the weight of that. Something had been knowing him since before his birth. Had sat in the corner of his perception for sixteen years, patient and quiet, waiting for the moment he stopped explaining it away.\n"Is it always at the water?"\n"It is always where the threshold is," Mama Eze said. "Anywhere that the boundary between worlds is thin. The river is the thinnest place near you. But not the only one." She looked at him steadily. "You will feel it in the village now that you have seen it clearly. And eventually you will feel it everywhere, because a keeper who is fully in the role carries the threshold with them."\nHe looked at his hands. The hands that were clearly his own, sixteen years old, familiar, and yet which had spent those sixteen years being known by something older than the river''s name.\n"What do I do with it?" he asked.\n"Nothing yet," Mama Eze said. "Knowing it is there is enough for now. It has been patient this long." She almost smiled, the interior shift he had learned to read. "It can wait a little longer."','\n',char(10)),1582,1,1,NULL,'2026-04-06T13:37:32.321Z','2026-04-06 13:37:32','2026-04-06 13:37:32',NULL,2,11);
INSERT INTO "chapters" ("id","novel_id","chapter_number","title","content","word_count","is_premium","is_published","audio_url","published_at","created_at","updated_at","scheduled_release_at","part_number","season_id") VALUES(191,26,7,'Drowning in Two Worlds',replace('His father called on a Wednesday.\nNot a check-in call, not the brief, guilty ten minutes his father had been offering every two weeks since the flood, apologising with his voice for an absence his schedule had made necessary. This was different. His father''s voice came through the phone with the particular weight of a man who had been carrying a decision for some time and had finally put it down.\n"I am coming next weekend," he said. "I have taken the time. I want to see the compound, assess the repairs, and I want to see you." A pause. "I should have come sooner."\n"Yes," Nnamdi said. "You should have."\nHis father absorbed this without deflecting it, which was how Nnamdi knew he was serious. "I will be there Saturday morning."\nHe put the phone down and sat for a while at his grandmother''s table with the clay pot in front of him and thought about his father arriving at a compound whose owner had walked into a river, asking questions about a son who had spent the past weeks in a village that did not appear on any map learning a language that had not been spoken publicly in centuries.\nHe thought about how that conversation would go.\nThen he opened his school bag and took out his chemistry textbook and looked at it and felt the two worlds pull in opposite directions inside his chest like a current splitting around an obstacle.\nHe had three weeks of schoolwork to catch up on. His chemistry teacher had called twice. His form teacher had sent a letter, formal and careful, expressing condolences about his grandmother and noting with equal care that his attendance and submission record had fallen below the threshold that required a conversation. His WAEC examinations were in four months. He had not thought about them in three weeks and the not-thinking felt, suddenly, like a very loud sound.\nHe went to school on Thursday.\nIt was his first full day back since the flood and he walked through the gates with the feeling of someone re-entering a place that should be familiar and finding all the familiar things slightly wrong in scale, not smaller exactly, but differently proportioned, the way places looked when you had been away long enough for your internal map of them to drift from the reality.\nHis classmates were kind in the distracted way of teenagers who had been told something difficult had happened and were doing their best with it. Condolences that lasted thirty seconds and then dissolved into the ordinary business of the day, which was actually what he wanted, the ordinariness of it, the relief of being in a room full of people to whom the Niger was simply a river.\nHe sat through chemistry and made notes and the notes were good, his hand remembering the shorthand his brain had developed over years of this particular classroom. He sat through mathematics and felt the clean satisfaction of problems with definite solutions, numbers behaving according to rules that did not change based on which side of a reed bank you were standing on.\nBy lunch he thought: I can do this. Both things. Mama Eze said both things. This is just the other side of the river and I know this side, I have always known this side.\nThen Chukwudi sat across from him at the lunch table and said, "You look different. Something happened to you that is not about your grandmother."\nChukwudi had been his closest friend since JSS1. He was perceptive in the specific, inconvenient way of people who paid attention without announcing that they were paying attention.\n"I am fine," Nnamdi said.\n"I did not say you were not fine. I said something happened." He looked at him with patient, level eyes. "You do not have to tell me. But do not tell me nothing happened when I can see that something did."\nNnamdi looked at his food. He thought about saying it. He constructed the sentence in his mind, took it apart, reconstructed it, and each version of it sounded, in this lunch hall with its ceiling fan and its smell of rice and stew and forty teenagers talking at once, like something that belonged to a different world entirely.\nHe said nothing. The silence between them stretched into something uncomfortable, and then Chukwudi nodded once and picked up his fork and talked about football instead, and Nnamdi responded in the right places and ate his food and felt the distance between his two worlds widen by a measurement he could not name.\nSaturday came.\nHis father arrived in a clean car with a pressed shirt and the expression of a man practicing being present. He was tall and broad-shouldered with Nnamdi''s forehead and an energy that filled a room without meaning to, the energy of someone accustomed to being the authority in every space he entered. He stood in the sitting room that Nnamdi had cleaned and reorganised and looked at the repaired wall and the replaced furniture and the grandmother''s wrapper still on the kitchen door, which Nnamdi had not been able to bring himself to move.\nThey sat across from each other at the table where the clay pot no longer sat, because Nnamdi had moved it to his room three days ago without fully examining why.\nHis father talked about the repairs. About the insurance. About the search, which NEMA had officially reclassified from active search to periodic monitoring, the language of agencies that had moved a case from urgent to permanent. His father''s voice doing the work of a man who was holding grief at a functional distance because the alternative was not functional.\n"She is not dead," Nnamdi said.\nHis father looked at him.\n"I know that sounds like denial. I know what it looks like from the outside." He kept his voice careful and level. "But I have information that NEMA does not have, and I am telling you she is alive."\n"What information."\nHe looked at his father across the table. This man who had grown up in this compound, who had heard his mother''s stories the same way Nnamdi had heard them, who had gone to university and become an engineer and built a modern, logical, functional life in Abuja and called home every two weeks from inside it.\n"The elders in the community," Nnamdi said, which was true. "They have knowledge of the river that the search teams do not. There are things about how the flood moved that night that are not consistent with a drowning."\nHis father looked at him for a long time. "The elders," he said.\n"Yes."\n"Which elders. Who specifically."\n"People who have lived on this river for a very long time." He held his father''s gaze. "I know it sounds vague. I am telling you it is real."\nHis father sat back in his chair. He looked at the kitchen door with his mother''s wrapper on it. He looked at his son, and Nnamdi could see him doing the thing intelligent people did when they encountered something they did not want to examine closely, building distance from it using reason as the building material.\n"You have been spending time with people from the community," his father said. "People who have given you comfort by framing this in terms of local belief." His voice was measured, careful, kind in the way of someone who was trying very hard not to be unkind. "I understand that. It can help, in grief, to have a framework that keeps things open. But Nnamdi, I need you to also be talking to a school counsellor. I need you to be attending your classes. I need you to be preparing for your examinations, because your grandmother wanted that for you more than she wanted anything."\nEach sentence landed with a small, precise weight.\nNnamdi sat inside them and felt the two worlds pull again, harder this time, and felt for the first time, with frightening clarity, what it would cost to lose hold of either one.\nHe could not explain the village to his father. He had tried to construct the explanation in his head and it collapsed every time under the weight of its own impossibility. He could not explain Mama Eze or the forty-seven characters or Obiora''s memory or the presence at the water''s surface that had been sitting beside him all his life.\nAnd he could not simply nod and agree that his grandmother was dead and file this whole thing under grief and community support and return to being the rigorously empirical boy his chemistry teacher had praised in his school report.\nHe was both of those boys. He had been told he could be both. But sitting across from his father in the compound that had belonged to a woman who was neither dead nor findable by any modern method, he felt the seam between them straining in a way it had not strained before.\n"I will talk to the counsellor," he said. "I will sort out my attendance. I will prepare for the examinations."\nHis father nodded, relieved.\n"But she is not dead," Nnamdi said quietly. "And I am going to find her."\nHis father looked at him with an expression that was made of love and worry in equal measure, and said nothing, because there was nothing in his world that usefully answered that.\nAfter his father left on Sunday evening Nnamdi sat at the table alone and thought about Simi standing in the water to her ankles, returning from somewhere unreachable. Staying because the village was the truest place she had found.\nHe understood her better now than he had the morning they met.\nThe truest place could be the loneliest one if you could not bring the people you loved inside it.\nHe picked up his chemistry textbook and opened it and studied for two hours, thoroughly, with full attention, because Mama Eze had said hold both worlds and he intended to, and because his grandmother had wanted this for him, and because being the bridge meant standing in the middle, and the middle was not comfortable, but it was his.\n','\n',char(10)),1706,1,1,NULL,'2026-04-06T13:38:44.359Z','2026-04-06 13:38:44','2026-04-06 13:38:44',NULL,2,11);
INSERT INTO "chapters" ("id","novel_id","chapter_number","title","content","word_count","is_premium","is_published","audio_url","published_at","created_at","updated_at","scheduled_release_at","part_number","season_id") VALUES(192,26,8,'The River Makes Its Claim',replace('Mama Eze did not greet him when he arrived on Monday morning.\nShe was standing outside her structure facing the river with her back to the village, and the quality of her stillness was different from her ordinary stillness in a way he could now read as clearly as he read the old script. Not the stillness of a woman at rest. The stillness of a woman who had been standing in one place receiving something difficult and had been standing there long enough that her body had simply organised itself around the receiving.\nHe stopped beside her and looked at the river.\nIt was different.\nNot visibly, not in any way that a photograph would have captured. The water was the same brown, moving in the same direction, the same width between the banks. But the feeling of it had changed the way the feeling of a room changed when something significant had happened in it before you arrived. The river had weight this morning that it had not had yesterday, a pressure against his awareness, and the presence he had learned to recognise at the water''s surface was not in its usual place at the threshold. It was gone.\n"Where is it?" he asked.\n"Inside," Mama Eze said. "It went in last night."\n"What does that mean?"\nShe turned and looked at him. "It means the river has called it back. When the witness withdraws it is because the watching period is over." She looked at him steadily. "One way or another."\nHe stood with the full meaning of that settling through him.\n"Come," she said. "Everyone is inside."\nEveryone was Lolo Adaeze, the three other village elders, Adaora, Emeka, and Simi. They were arranged around the central fire in the main structure, the large one he had not entered before, its walls hung with lengths of the old script and its floor marked with patterns he recognised from the child''s drawings in the dirt, the same characters, larger, older, worn into the clay floor by years of use. The fire was higher than usual. The room had the quality of a room in which something formal was about to happen.\nSimi looked at him when he entered with an expression that told him she already knew what this was and that she was sorry for the weight of it.\nHe sat.\nLolo Adaeze began without preamble.\n"The river communicated last night," she said. "Not through the keeper channel, which has been inactive since your grandmother went in. Through the direct channel, which it has not used in living memory, which tells you something about the degree of urgency." She looked at him across the fire. "The message was simple. The river has been holding the terms of your grandmother''s bargain for over two months now on the strength of your agreement with the bowl. It considers your preparation sufficient for the initial crossing. It is asking you to come."\n"To come where?"\n"To the threshold. To present yourself formally as the incoming keeper. To make the offering Lolo described to you, the message and the gift together, the way Obiora did in your ancestor memory." She paused. "If you do this, the river acknowledges you as keeper and the handover is initiated properly. Your grandmother can begin her return from the interior."\nThe fire moved between them. He waited.\n"And if I do not," he said.\n"If you do not come by the next full moon, the river will begin contracting again. The bargain will be considered void. The record it has been holding will begin its withdrawal from human access." Her voice was level, clear, no softening. "And your grandmother will remain where she is. Indefinitely."\nThe room was very quiet.\nHe looked at the floor patterns, the old characters worn into clay by feet that had stood in this room across generations, carrying variations of this same weight. He looked at Simi, whose window had closed, whose grandmother was still in the interior, permanently now, because the timing had not aligned and the choice had not been made.\nHe looked at Adaora, who met his eyes with her steady, appraising calm, and Emeka, who was looking at the fire with the focused expression of someone who understood exactly what was being asked and the cost of it.\n"The full moon is in nine days," Nnamdi said.\n"Yes."\n"What does the formal presentation require?"\nLolo Adaeze looked at Mama Eze. Mama Eze looked at Nnamdi with her clear, old eyes and said: "You go to the river at the threshold point, which I will show you. You carry an offering of your own making, something that demonstrates your understanding of the role and your intention to hold it. You speak the formal address in the old language. You cross the waterline."\n"Cross it."\n"Step in," she said. "Not far. To the knee. Enough to be on both sides of the boundary simultaneously. Enough for the river to read you the way it reads all things that enter it." A pause. "It will take something from you. A small thing. A keeper''s first crossing always costs something. You will not know what until it is taken."\nHe absorbed this. The unknown cost, the thing he could not prepare for. He turned it over and found that it did not frighten him the way it would have frightened the boy who had sat half-listening to his grandmother''s stories two months ago. That boy had been afraid of what he could not quantify. He was still that boy in many ways, would always be that boy, but he had more room in him now, room for the things that arrived without a unit of measurement.\n"Nine days," he said. "I need to do something first."\nLolo Adaeze looked at him. "What."\n"My father is in Abuja. My school is expecting me. I have an examination preparation schedule and a form teacher who has written me a letter and a friend who knows that something happened to me and is waiting for me to be able to say what it is." He looked around the room, at all of them, at the people who had spent weeks teaching him that holding both worlds was the work. "I need to go and be in the other world for a few days. Not to escape this one. To make sure I am coming to the threshold with both hands full."\nMama Eze looked at him for a long moment.\nThen she said: "Your grandmother went to her threshold with both hands full. She made sure of it." She paused. "Do not be gone long."\nHe was at school by Tuesday.\nHe sat through his classes with full attention and submitted three weeks of overdue work and stayed after chemistry to speak to his teacher, who looked at his submission and then at him with the slightly startled expression of teachers whose expectations had just been exceeded without warning. He spoke to the school counsellor, who was a kind, careful woman named Mrs. Eze, who shared a name with his teacher in the village and who asked him good questions that he answered honestly at the level he could reach without crossing into things she had no framework for. He told her about grief and the difficulty of holding loss while preparing for examinations and the feeling of being between two versions of himself. All of this was true.\nHe sat with Chukwudi at lunch on Wednesday and said: "Something happened to me that I cannot fully explain. I went somewhere I cannot fully describe. I am still the same person but I am also not, and one day I will be able to tell you more than this."\nChukwudi looked at him for a long moment. "Is it dangerous?"\n"It might become dangerous. I am managing it."\n"Are you managing it well?"\nHe thought about the nine days and the threshold and the unknown cost and his grandmother in the river''s interior, patient as she had always been patient.\n"I am managing it as well as I can," he said.\nChukwudi nodded slowly. "Okay," he said. "I am here when you can say more." He picked up his fork. "Eat your food."\nHe called his father on Thursday evening. They talked for thirty minutes about ordinary things, school, the compound repairs, the upcoming examinations. At the end his father said, "You sound more settled," with the careful relief of a man who had been worrying.\n"I am working through it," Nnamdi said.\n"Good. That is all anyone can do."\nHe returned to the village on Friday morning.\nHe walked through the green channel and the reeds and into the village with five days remaining and the river pressing against his awareness the way it had been pressing since Monday, heavier now, more directional, a current pulling toward something he was almost ready to face.\nMama Eze was at her door when he came through the reeds, as if she had known his footstep in the distance, which he had stopped being surprised by.\n"You came back," she said.\n"I said I would."\nShe looked at him, reading him the way she had read him on the first day, the whole of him, and whatever she found seemed to satisfy her more than the first reading had.\n"Then we have five days," she said. "And much to prepare."\nShe went inside. He followed.\nBehind him the river moved on, carrying everything it had ever been given to keep, waiting with the patience of something that did not measure time the way he did, but which had, in its long and particular way, been waiting for exactly this boy, in exactly this moment, for a very long time.\n\nEnd of Season 2: What the Water Keeps\nSeason 3: The Source','\n',char(10)),1646,1,1,NULL,'2026-04-06T13:40:17.695Z','2026-04-06 13:40:17','2026-04-06 13:40:17',NULL,2,11);
INSERT INTO "chapters" ("id","novel_id","chapter_number","title","content","word_count","is_premium","is_published","audio_url","published_at","created_at","updated_at","scheduled_release_at","part_number","season_id") VALUES(193,27,1,'The Choice the River Offers',replace('\n\nOn the first of the five days he did not go to the village.\nHe told no one. He woke before the compound was fully light, dressed, made tea he did not drink, and sat at his grandmother''s table with the clay pot in front of him and the old script open in his notebook and thought for a very long time.\nHe had been moving since the flood. He understood this now with the clarity of someone who had briefly stopped. Two months of forward motion, one revelation pulling him to the next, one teacher handing him to another, the language and the memories and the bargain and the witness and the contracting record, each piece arriving before he had fully digested the last. The motion had felt like progress, and it had been progress, but it had also been a way of not standing still long enough to feel the full weight of the thing he was walking toward.\nHe felt it now.\nThe choice the river was offering was not complicated in its structure. Come to the threshold and cross it, or do not come. Say yes with your whole body or say nothing and let the silence be its own answer. In its structure it was the simplest thing he had been asked since the flood.\nIn its weight it was the heaviest.\nHe opened his notebook to a blank page and did what he did with every problem that was too large to hold in his head: he built a table. Two columns. He headed the left one what I keep and the right one what I become and then sat with his pen over the page and found that the columns were not filling the way he expected.\nIn the left column he wrote: examinations. university. his father''s expectations. Chukwudi. the life he had been building with the assumption that it would look like the lives of the boys he sat beside in chemistry class, some version of the trajectory that started in this compound and went through WAEC and JAMB and a university in Lagos or Nsukka or possibly abroad and arrived somewhere with a salary and a title and the satisfied feeling of a person who had built exactly what they planned.\nHe looked at what he had written.\nNone of it was wrong. None of it was small. He had wanted these things genuinely and still wanted them and the wanting was not shameful or inconsistent, it was simply his, built from years of being the kind of boy who worked hard and expected the work to lead somewhere visible and mappable.\nHe moved to the right column.\nHe wrote: bridge keeper. He wrote it and then sat with the pen unmoving because the column was not filling the way the left one had. He knew the role intellectually, had been taught its history and mechanism and weight. But the right column was not asking him for the role''s definition. It was asking him what his life actually looked like if he crossed that threshold. What a Tuesday afternoon looked like. What his father''s face looked like when he tried to explain where he had been and what he had been doing. What the examinations looked like through the eyes of a boy who had also stood in the river and been read by something four hundred years older than the examination board.\nHe could not fill the right column. Not because there was nothing there but because he did not yet have language for it. It was the forty-seventh character, the ones that were felt before they were known.\nHe closed the notebook.\nHe went and stood at the cracked compound wall and looked at the river.\nIt was a Tuesday morning in November and the Niger was doing what it always did, carrying its brown weight toward the sea, indifferent to the weather service and the examination schedule and the father in Abuja and the boy on the bank who was trying to decide something. It had been doing this since before there was a word for river. It would be doing it long after the last keeper''s grandchildren had forgotten what a keeper was.\nHe had spent a significant portion of his life standing at this wall looking at this water. He had looked at it as a child and found it large and brown and ordinary. He had looked at it as a thirteen-year-old who had decided that large and brown and ordinary was not a diminishment but simply accuracy. He had looked at it the night of the flood and found it changed in a way he had not yet had the framework to understand.\nHe looked at it now and found that the river he was seeing was not the river he had seen before, and the difference was not in the river.\nHe knew what was in there. Not all of it, not the depths of it, but enough. The record of four hundred years of keepers and their work and the names the river had known before their bearers were born. His grandmother somewhere in its interior, not suffering, not trapped, waiting with the patience she had spent a lifetime building into the boy she had chosen him to be. The memory of Obiora walking through a market that no longer existed, on his way to a threshold Nnamdi was five days from standing at himself. The six young people whose names sat below his in the record, the continuing line, the future of the relationship if the relationship had a future.\nHe thought about Simi standing in the water to her ankles every morning, going as close as she could to the world she could not fully enter, staying in the village because it was the truest place she had found. Simi, whose grandmother was permanently in the interior because the window had closed, who had held that grief long enough that it had become the shape of her daily life, who had looked at Nnamdi on the morning they met and seen something in him she recognized.\nHe did not want to become the answer to the question Simi''s life was asking.\nHe went back inside and sat at the table and looked at the clay pot.\nHis grandmother had pressed those forty-seven characters into that material with a tool he had never seen, in a room he had not been in, sometime in the years before the flood when she had known the drawing was beginning and the time was approaching. She had written a message she trusted he would eventually be able to read, in a language she trusted he would eventually learn to carry.\nShe had done all of it without telling him. Had raised him toward a threshold she could not describe to him without losing him, had trusted the river and trusted herself and trusted the specific boy she had spent sixteen years building.\nHe had told Lolo Adaeze that his grandmother was not wrong about what he would have done if she had told him early. He had said this honestly. The boy he had been at eleven, at thirteen, at fifteen, that boy would have argued. Would have explained. Would have built a wall of rigorously empirical certainty between himself and the thing his grandmother was asking him to face and would have believed, completely, that the wall was wisdom.\nHe was not that boy anymore.\nHe was not not that boy either. The table in the notebook was still there. The examinations were in four months. His father was in Abuja believing his son was working through grief in a healthy and manageable direction. Chukwudi was waiting for a conversation that would require more words than Nnamdi currently had for it.\nHe was both boys. The one who had built the wall and the one who had watched it open. And the choice the river was offering was not asking him to be one and abandon the other. Lolo Adaeze had said it on the first day. Not a different person. A larger one.\nHe understood that sentence now in a way he had not understood it then. The left column and the right column were not in opposition. They were the same river seen from different banks, and the keeper''s job, the whole and entire point of the keeper''s job, was to stand in the middle, where the water was, and hold both banks in sight simultaneously.\nHe closed the clay pot''s notes in his mind and opened his chemistry textbook and studied for two hours. Thoroughly. With full attention.\nThen he packed his bag and walked to the silk-cotton tree and north along the bank, and the reeds parted, and the village received him, and he sat with Mama Eze and said: tell me everything I need to know before the fifth day.\nShe looked at him with eleven years of Lolo Adaeze''s waiting and all her own long years underneath that and said: good.\nShe began.','\n',char(10)),1516,0,1,NULL,'2026-04-06T13:44:48.116Z','2026-04-06 13:44:48','2026-04-06 13:44:48',NULL,3,12);
INSERT INTO "chapters" ("id","novel_id","chapter_number","title","content","word_count","is_premium","is_published","audio_url","published_at","created_at","updated_at","scheduled_release_at","part_number","season_id") VALUES(194,27,2,'What Science Cannot Map',replace('\n\nMama Eze gave him an assignment on the second day.\nShe did not call it an assignment. She said: take your science and bring it here, to this place, and see what it can reach and what it cannot. She said it the way she said most things, plainly and without instruction on method, and went back inside her structure and left him with it.\nHe sat with the assignment for the walk home and through dinner and into the early hours of the morning and arrived at an approach the way he arrived at most approaches, by building it from the simplest available materials.\nHe would test what he knew against what he had experienced. Not to disprove one or validate the other. To find the actual boundary between them, if one existed, which he was no longer certain it did.\nHe opened a fresh page in his notebook.\nHe started with the flood.\nThe weather service had shown clear skies. He had held the phone toward his grandmother and she had looked at it with patience. The flood had arrived without atmospheric warning, without the pressure drop that preceded weather events, without the cloud formation that any basic meteorology could have predicted. He had checked the weather data retrospectively, three times, from two different services. Nothing. The sky had been clear until the water arrived.\nUnexplained by standard meteorology. He wrote this in the margin.\nBut not unexplained. The river had moved with intention. The river had needed a mechanism for his grandmother''s going. He now knew this, had been told it, had built enough relationship with the actual facts of the situation to receive it as information rather than mythology.\nHe wrote: intentional variation in water flow, driven by a non-atmospheric agency, producing meteorological effects without meteorological cause. He looked at this sentence. It was not satisfying to the part of him that had written cleanly structured chemistry notes for three years. But it was accurate. It described what had actually happened without requiring him to choose between the river''s version and the weather service''s version. Both were describing the same event from instruments calibrated for different registers of reality.\nHe moved to the clay pot.\nThe material inside was not paper. He knew this. The texture, the flexibility, the weight of it were not consistent with any paper-making tradition he could identify. He had looked it up, had read about pre-colonial West African writing materials, about the use of dried plant fibres and treated bark and materials derived from river reeds. The closest analogue in the literature was a material described by a nineteenth-century missionary as found among certain Niger Delta communities, which he had quoted as evidence of primitive record-keeping and which Nnamdi had read with the specific frustration of someone who understood what the missionary had not.\nThe material had survived the flood in a sealed pot. The pot had survived the flood untouched. He wrote: selective hydrodynamic displacement. The flood had moved around the pot. He had seen this with his own eyes and it remained, in purely physical terms, an anomaly. Water did not selectively displace around objects based on their contents. Water moved according to pressure and gradient and the physical properties of surfaces.\nUnless something was altering those properties from within the system.\nHe sat with that.\nThis was the part where his scientific framework strained, not because the phenomenon was impossible but because the mechanism was outside the vocabulary of the framework. Physics described how water moved. Physics did not currently have a description for a system in which water movement was modified by a non-physical agency operating from within the system itself. This was not a failure of physics. It was a boundary condition, the edge of the map, the place where the instruments ran out of calibration.\nHe wrote: boundary condition. framework insufficient, not incorrect.\nHe kept going.\nHe wrote about the village and its unmappable location, which his GPS had consistently failed to track. He framed it carefully. The GPS was accurate to a specific number of metres and operated by triangulating signals from satellites orbiting at a known altitude. If the village existed in a space that was in some way orthogonal to the plane those satellites were mapping, the signal would not fail. It would simply not reach. Not a malfunction. A gap in the instrument''s range, the way a thermometer did not malfunction when it encountered colour because colour was not in its range.\nHe wrote about Obiora''s memory. This one he spent the longest time with.\nThe memory had arrived with full sensory weight, undissolvable, internally consistent in every detail including details he had not known and had subsequently verified. The market''s physical description matched the archaeological record of pre-colonial Niger Delta settlements he had found in a university research paper. The cloth-dyeing patterns he had seen were consistent with indigo-dyeing traditions documented in that region from the fourteenth century. The seal on Obiora''s clay vessel matched the dark waxy seal on his grandmother''s pot.\nHe had not known any of this when he was inside the memory.\nHe had known it afterward, when he looked it up, which meant the memory had contained accurate historical information he had not possessed. Which meant it had come from somewhere outside his own recall. The only candidates were: an elaborate hallucination constructed from subconscious processing of material he had absorbed and forgotten, or an actual transmission of stored information from a source outside himself.\nHe was a scientist. He weighed both options against the evidence.\nThe hallucination theory required him to have unconsciously absorbed and stored detailed knowledge of fourteenth-century cloth-dyeing patterns, pre-colonial settlement architecture, and specific seal-making traditions, without any recollection of the source material. He had looked for source material that could account for this level of specific historical accuracy in anything he had read. He had not found it.\nHe wrote: external transmission more consistent with evidence than confabulation.\nHe put the pen down and looked at the page.\nHe had been doing science for the past two hours. He had observed, described, hypothesised, tested against evidence, and arrived at conclusions. The conclusions were not the conclusions his chemistry teacher would have recognised. They did not resolve into tidy formulas or peer-reviewable findings. But the method had been the method, rigorous and honest and unwilling to reach past the evidence, and the evidence had led him, step by step, to the same place the river had been trying to bring him since the night of the flood.\nThe two things were not in opposition.\nScience was a method for reading reality. The old knowledge was a different method for reading a different register of the same reality. Neither one could fully replace the other because neither one could fully reach what the other reached. A thermometer and a compass were not in conflict. They were measuring different properties of the same world.\nHe looked at the character in the old script that meant the place where the current changes direction. He thought about the fact that every river had these points, hydrologically documented, physically explicable, the result of bank curvature and gradient shift and the fluid dynamics of turbulent flow. And also the fact that in the river''s language these points were considered the places where communication between the river''s world and the human one was clearest, the places where the keeper''s work was most effective.\nSame phenomenon. Two descriptions. Both true.\nHe took the notebook to Mama Eze the next morning.\nShe took it and looked at each page without hurrying, reading slowly in the way she read everything, as if the reading were also a kind of listening. When she reached the last page she closed the notebook and held it on her knee and was quiet for a moment.\n"Your grandmother argued with me for a month about whether the old knowledge was in conflict with what she had been taught in school," she said. "She did not have your framework. But she had the same instinct." She looked at him. "She eventually said: it is all water. Science and the old knowing. It is all water moving, and I am learning to read the current."\nHe thought about his grandmother at twenty-two, sitting on this same stool, finding her own language for the thing he had spent last night finding his language for.\n"She was right," he said.\n"She was nearly always right," Mama Eze said. "Which was part of what made her difficult." She handed the notebook back to him. "Keep this. What you have written here is not just for you. One day it will be for the six names below yours in the record."\nHe looked at the notebook in his hands. The notes of a sixteen-year-old who had spent a night applying rigorous empiricism to the unmappable and found that the map did not end, it only changed its language at the boundary.\nOutside, the Niger moved in the morning light, and he thought: three days.\nThree days to the threshold.\nHe was ready. Not completely. Not in every way. But ready in the way a river was ready when it had gathered enough current to move what was in front of it, not forcing, not stopping, simply moving with the weight of everything it had collected on the way.','\n',char(10)),1567,0,1,NULL,'2026-04-06T16:04:18.663Z','2026-04-06 16:04:18','2026-04-06 16:04:18',NULL,3,12);
INSERT INTO "chapters" ("id","novel_id","chapter_number","title","content","word_count","is_premium","is_published","audio_url","published_at","created_at","updated_at","scheduled_release_at","part_number","season_id") VALUES(195,27,3,'The Old Men''s Last Council',replace('They came on the third day.\nHe did not know they were coming. He arrived at the village in the early morning to find it changed in a way he felt before he saw, the same pressure shift he had learned to read as the river paying attention, but larger this time, the attention of more than one source, a gathering quality in the air that reminded him of the moment before a storm when every living thing went quiet.\nThere were eleven people seated in the large structure around the central fire.\nHe knew Lolo Adaeze and Mama Eze and the three village elders. The other six he had never seen. Five of them were old, old in the specific way of the village''s elders, age as quality rather than number, each of them carrying the particular stillness he had come to understand as the accumulated weight of a life spent in relationship with the river. The sixth was a woman who was perhaps sixty, younger than the others by a generation, and she sat with her hands folded tightly in her lap in the posture of someone who was holding something in rather than projecting something out.\nAdaora, Emeka, and Simi were seated to one side, not in the circle but near it, present as witnesses.\nLolo Adaeze looked at him when he entered and said, "Sit," and indicated a stool that had been placed in the circle with the specificity of something prepared.\nHe sat.\nLolo Adaeze looked around the circle. "We are here," she said, in the old language, and the formality of it, the script of it, told him this was a thing with a shape, a proceeding that had happened before in other circles in other villages across the long history of the river.\nEach elder in turn said something brief. He caught most of it, his comprehension of the spoken language still building, still finding its footing. Each one gave their name and their river, the specific stretch of the Niger or its tributaries that they were attached to, the way you stated your credentials before speaking on a matter of shared concern. He heard the names of rivers he knew from his geography classes and rivers he had never heard of, smaller tributaries with names the maps had not bothered to record.\nThen they looked at him.\nHe understood he was expected to do the same.\nHe said his name and the name of his stretch of river, his grandmother''s stretch, the bank behind the compound with the cracked wall and the silk-cotton tree, and when he said it in the old language the circle received it with a stillness that was also an acknowledgment.\nThe eldest of the visiting elders spoke first. He was a man so old that Nnamdi had initially taken him for one of the village''s permanent inhabitants, which given what he now knew about those inhabitants was a significant misreading of age. He spoke slowly, in the old language, and Nnamdi understood perhaps two thirds of it and filled the remaining third from context.\nThe man''s name was Dikeoru. He was from the lower delta, the oldest active keeper on the river, the last of his generation and aware of this fact. He spoke about what the river had looked like from his stretch in the past decade, the withdrawal he had been watching with the helplessness of someone watching an ocean tide go out from very far up a beach. The fish. The bank. The increasing unintelligibility of what the river sent, as if the signal was weakening at the source. He described it with the flat precision of a man who had long ago finished grieving it and was now simply reporting.\nThe woman with the folded hands spoke next. Her name was Ngozi. She was not a keeper, had never been a keeper, but was the last living student of a keeper from the western tributaries who had died two years ago without completing a handover. She had come because Lolo Adaeze had asked her to come and because she was carrying knowledge the dead keeper had given her in fragments over many years, incomplete, not enough to constitute a transfer of the role, but enough to want somewhere for it to go before she too was gone.\nShe looked at Nnamdi when she said this last part.\nHe looked back at her and did not look away.\nThe other four elders spoke in turn. Each story was a variation of the same story. A stretch of river. A dwindling connection. A keeper at the end of their generation with no clear successor, or a successor who had not been ready in time, or a community that had moved far enough from the old knowledge that even the language of readiness had been lost. Each account was specific and particular and together they built something in the room that was not despair exactly but was the thing that lived next to despair, the clear-eyed facing of a loss that was real and in motion and required looking at directly.\nNnamdi listened to all of it.\nWhen the last elder finished Lolo Adaeze looked at him and said, "You may speak."\nHe had not prepared to speak. He sat for a moment with the weight of the circle and the fire between them and the eleven people who had gathered, some of them traveling distances he had not asked about, to sit in this room on the day before the day before his threshold crossing.\nHe said: "I want to understand what you need from me."\nDikeoru looked at him with ancient, clear eyes. "Not from you specifically," he said, slowly enough that Nnamdi caught every word. "We are not here to add to your burden. You are carrying enough." He paused. "We are here because a keeper crossing a threshold is a significant event and when such a thing happens the remaining keepers of the river come if they are able. To witness. To add the weight of their presence to the moment." A pause. "And to ask one thing."\n"What thing?"\n"That you hold what we know also," Dikeoru said. "Not all of it. We are not asking you to become eleven keepers in one body. But the knowledge we carry, the specific teachings of our specific stretches of river, when we are gone it goes with us unless someone receives it. We have spent our lives hoping for successors on our own stretches and some of us are still hoping and some of us know the hoping is finished." He looked around the circle at the other elders, who were looking back at him with the expressions of people who had discussed this and arrived at a position and were now behind it fully. "We are asking you to be a repository. To take what we carry and hold it until the river finds its next generation of keepers and the knowledge can be passed properly to the ones it belongs to."\nNnamdi sat with this.\nIt was not what he had expected. He had expected the council to be for him, about him, the threshold and the crossing and the final preparations. Instead it was these eleven people giving him something, trusting him with the accumulated knowledge of dying lines, asking him to carry it forward into a future they would not see.\nHe thought about the record with its four hundred years of names. He thought about his chemistry notebook and the boundaries of different instruments measuring the same world. He thought about Ngozi''s folded hands and what it meant to carry fragments of something that had no complete home.\n"I am seventeen days past being someone who would have told you none of this was real," he said.\nDikeoru almost smiled. "We know. Lolo Adaeze has kept us informed of your progress."\n"I do not know if I am large enough to hold what you are asking me to hold."\n"You are not yet," Dikeoru said. "But a keeper who crosses the threshold tomorrow, or the day after, grows into their holding. The river makes room." He looked at Nnamdi with the steadiness of someone who had been on his stretch of river for sixty years and knew what rivers did with the things they were given. "We are not asking you to hold it fully formed and complete. We are asking you to hold the thread until the thread can find its proper owner. You are a bridge keeper. Holding threads between worlds is precisely the work."\nNgozi unfolded her hands. She reached into her wrapper and produced a small sealed pot, smaller than his grandmother''s, dark clay with a dark seal.\nAround the circle, five of the other elders did the same.\nSix pots set on the floor of the circle in the firelight.\n"Not today," Lolo Adaeze said. "After the crossing. When you are standing on the other side of the threshold you will be able to receive them. Before would be too much weight for the crossing itself."\nHe looked at the six pots.\nSix rivers. Six dying lines. Six lives of accumulated knowing, each sealed in clay, waiting for a boy from the Niger Delta who seventeen days ago had been certain the world was exactly what it looked like.\nHe looked at Mama Eze, who had been silent through the whole council. She was looking at him with her clear, old eyes, and in them he read something he had not seen there before. Not assessment. Not the patient reading of a teacher measuring her student.\nPride.\nHe looked back at the circle.\n"After the crossing," he said. "I will receive them."\nOutside, the river moved through the afternoon and said nothing, which was how it said everything it had already said and was willing to wait for him to be ready to fully carry.','\n',char(10)),1662,1,1,NULL,'2026-04-06T16:19:32.260Z','2026-04-06 16:19:32','2026-04-06 16:19:32',NULL,3,12);
INSERT INTO "chapters" ("id","novel_id","chapter_number","title","content","word_count","is_premium","is_published","audio_url","published_at","created_at","updated_at","scheduled_release_at","part_number","season_id") VALUES(196,27,4,'Against the Current',replace('\nHe did not go to the village on the fourth day.\nHe woke before light with the weight of the council sitting on his chest and lay in the dark and felt, for the first time since he had touched the bowl and started moving, the full force of what he was two days away from. Not the threshold. Not the crossing. The after. The long, unmappable after, the Tuesday afternoons and the chemistry classes and his father''s voice on the phone and Chukwudi at the lunch table, all of it continuing on one side while on the other side there were six sealed pots and a river contracting and a grandmother waiting and six names below his in a record that needed him to hold.\nHe got up and made tea and sat at the table and thought: what if I do not go.\nHe sat with the question honestly, the way Mama Eze had taught him to sit with the river, without rushing toward a conclusion. He spread the question out and looked at its full shape.\nIf he did not cross the threshold the river would begin to contract. The record would withdraw. His grandmother would stay in the interior. The six pots would eventually become the property of the earth, their contents inaccessible to anyone. Dikeoru would finish his years on his stretch of river without anyone to pass the thread to. Ngozi would carry her fragments until she could not carry them and then they would dissolve into the ordinary silence of things the world had stopped knowing.\nAll of this was true.\nAlso true: he was sixteen years old. Also true: his WAEC examinations were in four months. Also true: his father was in Abuja constructing a mental image of a son who was grieving normally and progressing academically and would emerge from this difficult year into the bright, mappable future that had always been the plan.\nHe sat with both truths and did not move for a long time.\nThen he did something he had not done in two months. He opened his laptop and looked at university admission requirements. Not idly. Specifically, with the focused attention he applied to problems he was serious about. He looked at engineering programmes and medicine and the sciences, the fields he had been oriented toward since JSS2, the fields that matched the framework he had built his identity inside of. He read requirements and looked at cut-off scores and found his own predicted grades sitting comfortably above the thresholds and felt the clean satisfaction of a person whose path was clear and achievable and completely within their own power to walk.\nHe stayed on the laptop for two hours.\nAt some point he noticed that his hands were cold.\nHe looked at them. His hands were never cold. The air in the compound was warm, November harmattan beginning to dry the air but not yet cooling it. He pressed his palms together and the cold was internal, not a temperature but a quality, the same quality as the river''s pressure against his awareness but inverted, turned inward, as if something that had been flowing outward had reversed direction.\nHe ignored it.\nHe closed the laptop and opened his chemistry textbook and studied for an hour and the cold in his hands did not leave. He made more tea and held the cup and the warmth of it did not reach whatever the cold was coming from. He went outside and stood in the morning sun and felt the harmattan air on his face and watched the river and the cold sat in him, patient and present, neither worsening nor leaving.\nBy midday he could not read.\nThis had never happened to him. He was a person who could always read. Reading was the one reliable tool in every version of his life, the thing that worked regardless of what else was not working. He sat with his chemistry textbook open and his eyes moved across the sentences and the sentences did not enter him. They sat on the page and he sat on his side of the gap between them and nothing crossed.\nHe tried his notebook. The old script. He looked at the characters he had spent weeks learning and they were there, present, recognisable, but the feeling that usually came with them, the sense of them landing in a part of him that had been waiting for this exact language, was absent. The characters were shapes on a page and nothing more.\nHe sat very still.\nHe was not being punished. He understood this clearly and immediately, before fear could construct a different explanation. The river did not punish. Mama Eze had said this and he had absorbed it and it was true in a way he could feel against the texture of what was happening, which was not hostile, not threatening, not the quality of a thing that wished him harm.\nIt was the quality of a current meeting resistance.\nHe thought about rivers and what happened when rivers met resistance. Not what happened to the obstacle. What happened to the river itself. The flow backed up behind the point of resistance. The water that should have been moving forward stalled. The energy of the current, which needed somewhere to go, folded back on itself and created turbulence at the point of blockage, not violent, not destructive, simply the physical consequence of a flow that had nowhere to go.\nHe was the point of resistance.\nThe cold in his hands, the inability to read, the strange inversion of the river''s presence, none of it was punishment. It was what happened to him when he tried to stand in the middle of a current and refuse to move with it. He was not being pushed. He was experiencing the natural consequence of his own resistance, the water backing up, the energy with nowhere to go folding back into the container that was trying to block it.\nHe went to the bank.\nHe stood at the cracked wall and looked at the river and the cold in his hands intensified briefly, sharply, and then steadied. The pressure of the river''s attention was very clear from here, directional, the way it had been directional since he came back from his father''s visit, pointing toward the threshold with the patient insistence of something that was not forcing him but was also not willing to pretend the direction did not exist.\nHe thought about what Lolo Adaeze had said. The river would not choose for him. But if he did not choose, the river would begin moving without him, the contraction, the withdrawal, the record pulling inward, not as punishment but simply as the physics of a situation that required a flow and was not receiving one.\nHe thought about the boy in the chemistry classroom who had been certain the world was exactly what it looked like. He thought about the two months that had happened to that boy and what those two months had built in him and whether the building was for something or simply for itself.\nHe went inside and sat at the table and put his hands flat on the surface the way he had put them flat on the riverbank on the morning after the flood, pressing down until the thing inside him steadied.\nHe looked at the clay pot.\nHe said aloud, to no one, to the compound, to the river through the cracked wall: "I know."\nThe cold in his hands eased. Slowly, the way cold eased when the source of it was removed rather than suppressed. Not gone immediately but moving in the direction of gone, the current finding its way around the resistance, the flow resuming.\nHe picked up his chemistry textbook and opened it and the sentences entered him as they always had.\nHe studied for an hour. Thoroughly. With full attention.\nThen he packed his bag and put on his shoes and walked to the silk-cotton tree.\nHe did not go to the village. He sat at the base of the tree where the three trunks diverged and he sat with his back against the wood and watched the river and stayed there until the light went low and golden and the cold in his hands was completely gone and what replaced it was something he had no prior word for, something between certainty and readiness, something that felt like the moment a current found its channel and understood that this was the direction it had always been travelling in.\nHe went home. He ate. He laid out what he would wear tomorrow.\nOne more day before the threshold.\nHe was not ready in every way. He accepted this without negotiating with it. He would never be ready in every way, because the every-way version of ready was the horizon, and the horizon moved when you moved, and the river was not asking for the horizon. It was asking for the boy on the bank, with his cold hands and his chemistry textbook and his two months of building, to take one step into the water.\nHe could do that.','\n',char(10)),1534,1,1,NULL,'2026-04-06T16:21:39.479Z','2026-04-06 16:21:39','2026-04-06 16:21:39',NULL,3,12);
INSERT INTO "chapters" ("id","novel_id","chapter_number","title","content","word_count","is_premium","is_published","audio_url","published_at","created_at","updated_at","scheduled_release_at","part_number","season_id") VALUES(197,27,5,' The Language He Was Born Speaking',replace('On the last day before the threshold he did not go to the village and he did not go to the river.\nHe sat at his grandmother''s table in the early morning light with the clay pot open in front of him and the material unrolled flat on the surface and his notebook open beside it and he read.\nHe had been building toward this. He understood that now. Every character Lolo Adaeze had introduced, every session with Mama Eze, every ancestor memory and river-listening and cold-handed morning of resistance, all of it had been building him toward sufficient size to receive what was written here. Mama Eze had told him this on the day he had asked what the message said. When you have enough of the language to read it, you will have enough of yourself to receive it. Those two things will happen at the same time.\nHe had forty-seven characters. He had the spoken rhythms from Obiora''s memory. He had two months of sitting with the river until the river''s way of meaning things had become a second grammar running alongside his first one.\nHe began.\nThe first line was a salutation, formal in the way the old language was formal, not stiff but precise, each word doing the exact work of its meaning with nothing decorative. It translated, as close as he could bring it across the boundary between languages, as: to the one who carries my name forward into the water.\nHe stopped on this for a moment. Not his name. Her name. Okafor. The family name, the line name, the name that connected him to the record and to every keeper before him who had stood at a river''s edge with a sealed pot and an offering and the full weight of what the relationship required.\nHe kept reading.\nThe second section was written in a register he had not encountered before in any of his lessons, something between the formal address of a keeper''s communication and the intimate directness of a person speaking to someone they knew completely. It took him a while to find his footing in it and then it opened.\nI am writing this before you exist. The river has told me you are coming and I believe it because the river has never told me anything untrue, even when I wished it would. I do not know your face yet. I do not know if you will have your father''s forehead or your grandfather''s hands or something entirely your own that none of us could have predicted. I know only what the river knows, which is your name, and your name is enough.\nHe read this paragraph three times. The third time he noticed that his hands were very still on the table.\nHe kept reading.\nYou will have grown up hearing my stories. This is not an accident. I have told them deliberately, every one, because a keeper''s first language is not the old script and it is not the language of the river. It is story. The stories were your first lessons. You did not know this. That is how lessons work when they are given to someone who is not yet ready to know they are being taught.\nHe thought about himself at seven, at nine, at twelve, sitting across from her in this room with the lights on or the candle between them, half-listening or fully listening depending on whether his textbooks had been more demanding that day. He thought about the quality of her telling, the precision of it, each story going exactly as long as it needed and no further, each one leaving something in him that he had not known at the time was being left.\nHe had thought she was telling him stories.\nShe had been teaching him to receive a world.\nI know what you will become before you do. I know the way you will sit with difficult things, turning them over from every angle, refusing to reach past what the evidence allows. I know this because I built it. Not alone. You built it also, as you grew, but I gave you the conditions for it, the space for rigour and the permission for certainty and the library that your father thought was only about keeping you occupied on rainy afternoons. I built the boy who would one day need to be rigorously empirical about things that had no empirical framework, and I have never been more deliberately anything in my life.\nHe stopped.\nHe put the material down and looked at the ceiling and breathed carefully for a moment.\nHis grandmother had built him. Not controlled him. Not decided for him. Had looked at what the river needed from its next keeper and had constructed, patiently, over years, the conditions in which that keeper could grow into himself. Had given him science because a keeper needed precision. Had given him stories because a keeper needed the grammar of the unseen. Had given him certainty because a keeper needed something solid to stand on when the water rose.\nHe picked up the material and kept reading.\nThere will be a night when you sit across from me and I will try to tell you. I will not say it directly, because you are not ready and I have learned, slowly and at some cost, that you cannot hand a person their readiness, you can only build the conditions for it. I will give you the pot. I will tell you the river knows your name. You will tell me that rivers do not know things, and I will think: good. A boy who argues clearly has a mind that is working. A mind that is working can be trusted with what comes next.\nHe smiled. He could not help it. A full smile, starting in his eyes, which was exactly how his grandmother''s smiles had started, and he registered this small inheritance with something that was not quite grief and not quite joy but sat in the exact warm space between them.\nBy the time you read this you will have met Ikenna, who has been on that bank longer than either of us has been alive. You will have found the village and you will have sat with Lolo Adaeze and Mama Eze, who taught me everything I am passing to you plus everything they have learned in the years since. You will have read the record and found your name and understood the weight of it. You will have had at least one morning of cold hands.\nHe laughed. A short, real, involuntary sound in the empty compound.\nI am sorry about the cold hands. That is the current meeting resistance and it is uncomfortable. It passes. Everything that is not the river passes, and everything that is the river remains, and learning to tell the difference is most of the work.\nHe read on.\nThe letter moved through things he had experienced and things he had not yet experienced, written by a woman who had known the approximate shape of the next two years of his life before he had taken his first breath. She wrote about the threshold and what to expect from the crossing in terms that were neither frightening nor falsely reassuring, practical and precise in the way she had been practical and precise about everything that mattered. She wrote about the six pots and what they would require of him and the six names below his in the record and what they would eventually become. She wrote about his father, carefully, with a love for her son underneath the words that he felt rather than read, and told Nnamdi things about his father''s childhood on this same bank that he had never known and that explained, quietly, certain distances between them that he had always felt but never understood.\nThen the register changed again, back to the intimate directness, and he felt the change before he fully processed it.\nI need to tell you something that none of the others will tell you because it is not their thing to tell. The river asked much of me. I gave it everything it asked, freely, without regret, because I believed in the work and I believe still. But the thing I gave most freely and with the most complete love was not a language or a knowledge or a thirty-year bargain. It was you. Not to the river. Not as sacrifice or transaction. I gave you to yourself. I spent sixteen years building the conditions for you to become exactly who you needed to become and I handed that boy to the world and I would do it again without changing a single morning of it.\nHe stopped reading.\nHe sat at his grandmother''s table in the compound she had filled for sixteen years and looked at the material in his hands and felt the weight of what she had written settle through him slowly, the way silt settled in still water, finding its level.\nShe had known him before he was born. Had prepared herself to receive him and prepared the world to receive him and prepared him, across sixteen years of stories and precision and the particular quality of her attention, to receive himself. Had gone into the river for him, had waited for him, had written him this letter in a language he had spent two months learning to be large enough to read.\nHe sat with it for a long time.\nThen he read the final lines.\nTomorrow you will go to the threshold. You will take the offering you have made and you will speak the address and you will step into the water. The river will read you, all of you, everything you are and everything I built and everything you built yourself. It will take something small from you. Do not be afraid of the taking. What the river takes it keeps in the record. You will be in there with us, with Obiora and all the others, and you will never be alone in the water.\nGo well, my son. The river knows your name. I have always known your name.\nCome and find me when you are ready.\nHe set the material down.\nThe compound was quiet around him. The harmattan moved through the yard, dry and particular, carrying the smell of the river over the cracked wall, the river that held his grandmother and Obiora and four hundred years of keepers and was waiting, two days from now, to hold him too.\nHe rolled the material carefully and placed it back in the pot.\nHe sat at the table for a while longer, not reading, not thinking in the organised way that was his habit. Simply sitting. Letting the letter be in him the way the river was in him, settled, permanent, not requiring anything from him in this moment except his presence.\nThen he opened his chemistry notebook and studied for an hour.\nHe made his offering in the evening. He did not need to be told what it should be. He knew, the knowing arriving the way the forty-seventh character had arrived, fully formed, from somewhere that was his and not only his. He made it carefully and sealed it and set it beside the clay pot and looked at both of them in the lamplight.\nTomorrow.','\n',char(10)),1908,1,1,NULL,'2026-04-06T16:29:33.451Z','2026-04-06 16:29:33','2026-04-06 16:29:33',NULL,3,12);
INSERT INTO "chapters" ("id","novel_id","chapter_number","title","content","word_count","is_premium","is_published","audio_url","published_at","created_at","updated_at","scheduled_release_at","part_number","season_id") VALUES(198,27,6,'The Flood That Heals',replace('LHe felt the rain coming three hours before it arrived.\nNot in the sky. The sky on the morning of the threshold was clear and dry, harmattan blue from edge to edge, the kind of sky that the weather service would look at and call settled. He felt it in the river, in the pressure of its attention against his awareness, which had been building since he woke, not the steady directional pull of recent weeks but something larger, the feeling of a current gathering upstream, collecting itself for something.\nHe dressed carefully. He ate. He picked up the clay pot and the offering he had made the evening before, wrapped in the flat-leafed material from Mama Eze''s garden, sealed with a wax he had prepared from instructions in the old script. He looked around his grandmother''s compound, at the repaired wall and the kitchen with her wrapper still on the door and the table where he had sat two months ago holding a pot the flood had not touched.\nHe left the compound and walked north.\nLolo Adaeze met him at the silk-cotton tree.\nShe was alone, which surprised him. She looked at him and at the pot and the offering and nodded once with the expression of someone whose long waiting had arrived at its final morning. She fell into step beside him and they walked in silence along the bank, past the green channel, and he understood without asking that today the path was different.\nShe led him further north than he had been, past the point where the village track diverged, along a stretch of bank where the trees grew old and enormous and their roots went into the water in long reaching arches, and the river here was quieter than elsewhere, the surface very still, the kind of stillness that was not absence of movement but concentration of it, all the energy pulled inward and down.\nThe threshold point was a place where the bank curved gently inward and the river came close, very close, the water lapping at a shelf of packed earth that was neither fully bank nor fully riverbed. The surface of the water here held a quality he recognised, the same quality as the presence he had felt at his side for two months, the threshold membrane, the place where the two worlds were thinnest against each other.\nThe eleven elders were there.\nAll of them, the village elders and the six who had come for the council, arranged along the bank in a loose arc behind the threshold point. Adaora and Emeka stood together at one end of the arc. Simi stood at the other end, slightly apart, watching the water with the expression she wore when she was closest to the place she could not fully enter. Mama Eze was nearest the water, standing with her feet at the very edge of the shelf, and she turned when he arrived and looked at him with her clear old eyes and he held her gaze for a moment and understood that this was the last thing she had to teach him and that the teaching was simply this: she had brought him here and the rest was his.\nHe walked to the threshold point.\nThe river''s pressure against him was very strong now, not uncomfortable, not threatening, the way a strong current was not threatening if you understood how to move with it. He set the pot down on the shelf beside him and held the offering in both hands and looked at the water.\nHe spoke the formal address in the old language.\nHe had practiced it until the words lived in his mouth rather than his memory, until the shapes of them were as natural as breathing. He spoke clearly, at a normal register, not performing, not projecting, the way you spoke to someone close enough to hear you without effort. He gave his name and his river and his line, Nnamdi Okafor of the middle Niger, grandson of Chioma Okafor who had held this role for thirty years and waited in the interior for this morning. He stated his intention and his understanding of what the role required. He spoke the phrase that Mama Eze had given him for last, the formal acceptance, the old language equivalent of the bowl he had touched in the village two months ago, but larger, binding in a way the bowl had only gestured toward.\nThe river received it. He felt the receiving the way he had felt the river''s communication in Obiora''s memory, as knowing rather than hearing, direct and complete, the river reading the address and reading him simultaneously, all of him, everything he was and everything two months of building had made him.\nHe placed the offering on the surface of the water.\nIt floated. It moved toward the center of the river with a steadiness that had nothing to do with the current, purposeful and direct, and then it was gone beneath the surface without sinking, which was not how objects behaved in water and which he noted with the part of him that was always noting things and set aside without argument.\nHe looked at the water in front of him.\nHe stepped in.\nThe cold was immediate and total, not the cold of the harmattan or the cold of resistance he had felt in his hands four days ago, the cold of the river itself, living and specific, the cold of something that had been moving since before he had a name for cold. It took him to the knee in two steps and he stopped there, on both sides of the boundary simultaneously, bank behind him and open water before him, his feet on the riverbed and his hands at his sides and the full presence of the river around his legs like a current that was also an attention.\nIt read him.\nHe felt it the way Mama Eze had said he would feel it, not as intrusion but as encounter, the river moving through his awareness the way his awareness had been moving through the river for two months, both of them finally in the same medium, finally able to receive each other directly. He felt the record in it, the four hundred years, and he felt his grandmother somewhere in its depth, not a location he could point to but a presence he recognised the way you recognised a voice in a crowded room, distinct and familiar and completely itself.\nThen the river took something.\nHe did not know what until it was gone. A small thing, as Mama Eze had promised. Something from the part of him that had needed proof before belief, the very last layer of it, the residual holding-out that he had carried so long it had become structural. It went cleanly, without pain, the way a thorn came out of skin that had healed enough to release it. He stood in the water and felt the space where it had been and found that the space was not empty. The river had left something in the place of what it took. A quality he could not name yet, something that would need time to become legible, the way the forty-seventh character had needed time.\nThen the rain came.\nNot the violent arrival of the flood two months ago. This was different, a rain with intention rather than urgency, beginning at the river''s surface and moving outward, the river calling its water back from the sky in a slow, deliberate rhythm. It fell warm and it fell specifically, not random distribution but a pattern, and where it fell on the bank the earth received it without the panic of flood, the ground opening for it the way ground opened for water that was meant for it.\nBehind him he heard Adaora make a sound. He looked over his shoulder.\nThe bank downstream was blooming.\nNot flowers, not grass, something underneath the visible, a quality of the bank itself changing, the colour of the earth deepening from flood-stripped grey to the rich dark brown of well-watered soil, the roots of the old trees visibly fed, the waterline settling into the bank with the specific purposefulness of a river that knew where its edges were. The cracking and the erosion that had been advancing along this stretch for years, quietly, unremarked, was reversing in real time, the earth knitting itself back at the waterline with a patience that was also a speed.\nNnamdi stood in the water to his knees and watched it and felt the river moving through him and out of him and back into itself, the circuit complete, the bridge between the two worlds carrying current in both directions for the first time in longer than anyone standing on the bank could measure.\nHe was the variable.\nNot the observer, not the analyst, not the boy on the bank watching the water with careful, rigorous eyes.\nThe bridge.\nThe rain fell warm around him and the bank healed downstream and the elders stood in silence behind him and the river moved through its keeper and its keeper stood in the river and the two of them, boy and water, did the ancient ordinary work of holding the world together at its seam.','\n',char(10)),1556,1,1,NULL,'2026-04-06T16:31:03.985Z','2026-04-06 16:31:04','2026-04-06 16:31:04',NULL,3,12);
INSERT INTO "chapters" ("id","novel_id","chapter_number","title","content","word_count","is_premium","is_published","audio_url","published_at","created_at","updated_at","scheduled_release_at","part_number","season_id") VALUES(199,27,7,'The River Remembers His Name',replace('He did not step out of the river immediately.\nHe stood in it for a long time after the rain stopped and the elders had moved and the bank downstream had finished its quiet work of healing. The water around his legs had changed quality since the crossing, the way the air in a room changed after something significant had been said in it, the same room, the same air, but carrying something new in its arrangement. He could feel the record now the way he had felt the forty-seven characters once they were in him, not as external information but as a second knowledge running alongside his first one, present and accessible, the river''s four hundred years of accumulated keeping sitting in him like a library he had not yet had time to read but whose contents he could feel the shape of.\nHe stepped out of the water.\nMama Eze was the closest to him. She looked at his face and then at the river and then back at his face and said nothing, which was the most complete thing she could have said.\nLolo Adaeze put her hand briefly on his shoulder, the same gesture his grandmother had made across the table by candlelight, hand over hand, dry and warm and certain. Then she stepped back.\nSimi was looking at the river with an expression he did not examine directly because it was too private for looking at directly. He stood beside her for a moment and she said, very quietly, "She is close now. Can you feel it?"\nHe could feel it.\nHis grandmother was not in the depths. She was near the surface, near the threshold point, the interior releasing her the way a held breath was released, slowly, with the specific relief of something that had been held the correct length of time and no longer.\nHe said, "I need to go back in."\nMama Eze said, "I know."\n"Alone."\n"Yes."\nHe walked back to the threshold point and waded in, deeper this time, to his waist, and the cold was different on this side of the crossing, not the cold of the river reading him but the cold of the river receiving him, a distinction he felt rather than understood, and he stood in the waist-deep water and waited.\nShe came from the direction of the current.\nNot walking. Not swimming. Moving the way things moved in the river''s world, without friction, without the resistance that movement required in the world on the bank. She came from the direction of the current and she was exactly herself, exactly the woman who had sat across from him by candlelight and put her hand over his and said go to bed with the absolute confidence of someone who knew precisely what morning was coming.\nShe stopped in the water in front of him.\nShe looked at him for a long time with the reading expression, the one he had spent two months learning to recognise in Mama Eze and Lolo Adaeze and had never understood until now was his grandmother''s expression first, the one they had all learned from her, the full-body reading of a person you needed to know completely.\nWhatever she read seemed to satisfy her entirely.\n"You are taller," she said.\nHis throat closed. He opened it carefully. "It has been two months."\n"And several lifetimes," she said. "You have been carrying a great deal."\n"You left me a great deal to carry."\n"Yes." She said it without apology and without guilt, the way she said everything true, plainly and with full ownership of it. "I did."\nHe looked at her in the river''s light, which was different from the light on the bank, softer and more present, the light of a place that held things rather than moving them. She was the same. He had not known what to expect, had constructed no image of what she would look like in the river''s interior, and she was simply the same woman, unchanged, the same white wrapper and the same lines in her face and the same eyes that had been reading him since before he could read himself.\n"I read the letter," he said.\n"I know."\n"You knew everything. Before I was born."\n"The river told me the shape of what was coming," she said. "The specifics were yours. The way you would argue, the particular quality of your certainty, the cold hands." The corner of her mouth moved. "Those were yours."\n"You built me for this."\n"I built the conditions," she said. "You built yourself. There is a difference and I need you to understand it fully before I say the next thing."\nHe waited.\n"What you have become in these two months, the keeper you are beginning to be, the largeness of you, the two worlds you are holding, none of that came from me or from the river or from Mama Eze or from any of the things we arranged. Those things gave you the materials." She looked at him with complete directness. "You are the builder. You have always been the builder. I needed you to know that before I came back, because a keeper who thinks the river made them will always be smaller than a keeper who knows they made themselves."\nHe stood in the river and felt this settle through him the way the letter had settled, slowly and permanently, finding its level.\n"The six pots," he said.\n"I know about them."\n"And the six names below mine in the record."\n"I know about those too." She looked at him. "You are not doing this alone, Nnamdi. You were never meant to. The bridge is not a single plank. It is a structure, and structures are built by more than one person." She paused. "Adaora and Emeka and Simi. Dikeoru''s knowledge in the pots. The six names below yours, who will find their way to the river in their own time, as you found yours." A pause. "And me. I am not done. The role has passed but the knowledge does not pass with it. I will be on this river for the rest of my life, which is a long life yet, and I intend to be useful in it."\nSomething released in his chest that he had not known he was holding.\nNot the worry about the record or the contracting or the six pots, those were still there, still real, still requiring him. Something smaller and more personal than that. The thing that had been sitting underneath all of it since the morning he had stood in the flood-wrecked sitting room holding a dry clay pot and understood that she was gone.\nShe was not gone.\nShe was standing in a river wearing a white wrapper looking at him with eyes that had known his name before he was born.\n"Come home," he said.\nShe looked at the river around them, at the water she had lived inside for two months, at the threshold point and the bank beyond it and the world on the other side that had continued without her. She looked at it with the expression of someone taking full account of something before they left it.\n"The compound needs the wrapper taken off the kitchen door," she said. "It has been there long enough."\n"I will leave it until you take it yourself."\nShe looked at him. Then she moved past him toward the bank, toward the threshold, and he turned and walked beside her through the deepening shallows, and where they walked the current moved with them rather than against them, the river releasing what it had held long enough, the terms of the old bargain fulfilled.\nShe stepped out of the water onto the bank.\nThe elders were there, all of them, the village and the visiting both, and they received her the way the circle had received his name on the day of the council, with a stillness that was also an acknowledgment. Mama Eze looked at her with the eyes of a teacher whose finest student had come home and said nothing because nothing was necessary.\nSimi looked at her and looked away, quickly, and he watched Simi''s face do something private and then settle, and he understood what it cost her to watch this homecoming and he made a note of it in the place in himself where he was beginning to keep the things a keeper needed to remember.\nHis grandmother looked at the bank, at the healed earth downstream, at the quality of the water at the threshold point, and he watched her read it the way she had always read the river, completely and without hurry, and then she looked at him.\n"You did this," she said.\n"We did this," he said. "You built sixteen years of conditions."\nShe looked at him for a moment with the full-body reading expression, everything he was, the chemistry textbook and the old script and the two worlds held simultaneously in the one boy she had spent her whole life preparing to release into his own.\n"Rigorously empirical," she said.\n"It is not a phase," he said.\nShe smiled at that. The full smile, starting in her eyes, taking its time reaching her mouth.\nHe smiled back.\nThey walked home along the bank together, past the threshold point and the old trees and the green channel, past the silk-cotton tree splitting into its three directions, back through the town that was waking into its ordinary morning, the river moving beside them the whole way, wide and brown and carrying everything it had ever been given to keep, including now the boy it had known before he was born, the boy it had waited for, the boy who had walked into it and come out the other side holding both worlds at once and finding that this, precisely this, was the point.\n\nEnd of Season 3: The Source\nEnd of The Boy the River Knows','\n',char(10)),1671,1,1,NULL,'2026-04-06T22:01:46.512Z','2026-04-06 22:01:46','2026-04-06 22:01:46',NULL,3,12);
INSERT INTO "chapters" ("id","novel_id","chapter_number","title","content","word_count","is_premium","is_published","audio_url","published_at","created_at","updated_at","scheduled_release_at","part_number","season_id") VALUES(200,28,1,'The Weight of Sky',replace('The clouds did not part for her. They simply moved aside, the way guards move for someone they have been told to tolerate.\n\nAdaora had prepared for hostility. She had not prepared for beauty.\nThe sky court rose out of nothing or rather, out of everything, because the sky was everything up here, endless and pale gold, the kind of gold that had no warmth in it. The structures were built from condensed light and old bone-white stone, towers that tapered like fingers pointing upward into more sky. There were bridges between them, narrow and arching, and people moved across those bridges in long robes the color of early morning, not looking down. They never looked down.\nShe understood immediately why they were arrogant.\n"Close your mouth," said Councillor Ekene from beside her, his voice low and dry. He was her father''s man, forty years in diplomatic service, and he had briefed her for three months on sky court protocol. He had not briefed her on this.\nShe closed her mouth.\nTheir escort four sky soldiers in pale armor with that gold sun emblem stitched at the shoulder led them across the main bridge without ceremony. No welcome. No acknowledgment beyond the minimum. She was a diplomat''s aide, barely a title, barely worth the ceremony they had already decided she wasn''t worth. She kept her face still and watched everything.\nThe people of the sky court were tall. That was the first thing. Not unnaturally so, but tall the way trees were tall when they had grown without anything competing for their light. Their skin ranged from deep brown to rich amber and their hair was elaborate, braided and coiled in structures that must have taken hours, all of it threaded with gold wire and small white stones. Beautiful and deliberate. Beauty as a kind of armor.\nThey looked at Adaora''s delegation the way you looked at a crack in a wall you had learned to live with. Familiar. Unpleasant. Not worth fixing yet.\nShe counted guards, exits, the angle of the sun, the direction of wind. Her mother had taught her that. When you are somewhere that does not want you, the first thing you do is learn how to leave.\nThey were taken to the delegation quarters a set of rooms carved into the interior of one of the towers, cool and spare, with windows that looked out on nothing but more sky. The escort left without instructions. Ekene began immediately reviewing his notes. The two junior aides began unpacking. Adaora stood at the window.\nThree hundred years. The war between the earth kingdom and the sky court was three hundred years old, older than her grandmother''s grandmother, older than the treaties that had failed and the truces that had collapsed and the children on both sides who had grown up knowing the other side as the enemy before they had learned to read. Her father had sent her here because she was sharp and careful and because she spoke three languages and because, she suspected, he did not entirely believe this diplomatic mission would work and wanted someone present who could think when things went wrong.\nShe was seventeen. She thought about that sometimes.\nThe first afternoon they were not required anywhere, which was itself a message. She used the time to walk. Ekene disapproved but he did not stop her. She stayed close to the delegation tower and learned the immediate geography the courtyard below, the smaller bridges that connected to what looked like a library or archive, a garden carved into the stone of an adjacent tower where things with silver leaves grew in rows.\nIt was at the edge of that garden that she heard it.\nShe stopped walking.\nThe sound was a voice, low and male, coming from somewhere inside the archive building. Not singing. Not praying. Reciting. The words were steady and careful, like someone working through something difficult, and it took her three full seconds to understand what she was hearing because understanding it was impossible and yet.\nThe language was Mmo.\nShe knew Mmo the way she knew her grandmother''s hands in pieces, in sensation, in the particular shape of certain words that did not exist anywhere else. Her grandmother had spoken it in the kitchen and in sleep, sometimes, in the last months. It was a language so old that the scholars of the earth kingdom called it dead, called it pre-war, called it something that had dissolved when the two kingdoms had severed themselves from each other and refused even shared speech. She had never heard another living person use it. She had thought she was the only one left who remembered even the fragments her grandmother had given her.\nThe voice inside the archive did not sound like fragments.\nIt sounded like fluency.\nShe stood very still. The voice continued, unhurried, the cadence of it rising slightly at the end of each line in a way she recognized as the old formal style, recitation meant to be memorized. She understood perhaps one word in five. Her grandmother had given her the kitchen words, the bedtime words, the words for ordinary love. Whoever was speaking in there was using the formal register, the words built for ceremony and record.\nShe should go back. She knew that. She was three days in a foreign court, enemy court, and she was standing outside a building she had no access to, listening to something that was probably not meant for her, that was almost certainly part of something she did not yet understand.\nShe took three steps toward the archive entrance.\nThe voice stopped.\nShe froze.\nSilence. Then, from inside, the sound of something being set down, the soft drag of a chair. Then nothing. She waited. Thirty seconds. A minute. The silence held.\nShe made herself walk back toward the delegation tower. Slowly, so it didn''t look like retreat. She kept her breathing even and her hands loose at her sides.\nInside, Ekene was still reviewing his notes.\n"The archive building," she said. "Who has access?"\nHe looked up. "Court scholars. Senior staff. Members of the royal family." He returned to his notes. "Not us."\nShe sat down. Outside the window the sky had shifted, less gold now, going toward a deep coral as whatever passed for evening arrived. The tower across from theirs had lights beginning to show in its windows, small and steady.\nHer grandmother had died when Adaora was eleven. In the last weeks, she had started speaking Mmo in longer stretches, like someone returning to a place they had left for too long. Adaora had sat beside her and listened and held the sounds in her memory because she had understood, even at eleven, that she was being given something.\nShe had never once imagined that somewhere in the sky, another person was holding the same sounds.\nShe pressed her hand flat against the cool stone wall of the delegation tower and breathed.\n\nTomorrow there would be briefings, protocols, the careful choreography of diplomacy between people who hated each other. Tonight she had one question, and it sat in her chest like a coal: whose voice was that, and how do they know a dead language better than I do','\n',char(10)),1214,0,1,NULL,'2026-04-07 05:30:01','2026-04-07 05:27:08','2026-04-07 05:30:01',NULL,1,13);
INSERT INTO "chapters" ("id","novel_id","chapter_number","title","content","word_count","is_premium","is_published","audio_url","published_at","created_at","updated_at","scheduled_release_at","part_number","season_id") VALUES(201,28,2,'First Word',replace('She went back the next morning before anyone was awake.\nThe archive entrance had no guard just a heavy door of pale wood banded in gold, and a small carved symbol above the frame that she recognized from Ekene''s briefings as a court scholar''s seal. Restricted. She pressed her palm flat against the wood and pushed anyway.\nThe door opened.\nInside was cool and dim, the smell of something between dust and metal, the particular silence of a room full of old paper. Shelves rose from floor to ceiling on every wall, packed with scrolls and bound texts and loose documents weighted at the corners with small stones. A narrow staircase in the far corner wound upward. Light came from strips of luminescent crystal set into the ceiling, low and steady.\nShe stood at the entrance and listened.\nNothing.\nShe moved to the nearest shelf and looked without touching. The texts were labeled in the formal sky script she had studied the angular, precise lettering that looked nothing like the round earth script she had grown up reading. She could read it, slowly. History records. Sky court law. Astronomical mapping. A whole section on weather documentation going back two hundred years.\nShe was reaching for one of the weather records it seemed the least suspicious thing to hold when she heard the stairs.\nFootsteps, unhurried, coming down.\nShe did not run. Running would be worse. She stepped back toward the shelves and kept her face neutral and her breathing even and waited.\nHe was younger than she expected.\nThe sky court princes she had seen in the official briefings were formal portraits, stiff and deliberately intimidating. This was a boy young man in plain clothes, no gold wire in his hair, no ceremony anywhere on him. Tall, like all of them, brown-skinned, with the kind of face that was still deciding what it was going to be. He was carrying a scroll loosely in one hand and his eyes, when he saw her, did not go to hostility first.\nThey went to surprise.\nThen to something more careful.\n"This section is restricted to court scholars and family," he said. His earth-language was accented but correct.\n"I know," she said. "The door was unlocked."\n"I left it unlocked for myself."\n"I didn''t know that."\nA pause. He looked at her the way someone looked at a problem they hadn''t been assigned. His eyes moved to the weather record still in her hand. She set it back on the shelf.\n"You''re from the earth delegation," he said.\n"Adaora. Aide to Councillor Ekene."\nHe didn''t give his name. She already knew it she had placed him in the first three seconds, the youngest prince, Soren, the one the briefings described as politically irrelevant. She waited to see what he would do with her presence.\nHe crossed to one of the reading tables and sat down and unrolled his scroll. Like she wasn''t there.\nShe should leave. She knew she should leave. She turned toward the door.\nAnd then, because she had spent one entire night not sleeping over a question she could not put down, she stopped.\nShe said, in Mmo, the only formal phrase she knew, the one her grandmother had used to open every important conversation: I come with open hands.\nThe silence that followed was the loudest thing she had ever heard.\nSoren looked up from his scroll.\nHis expression had changed entirely. Every piece of the careful neutral face was gone, and what was underneath it was something unguarded and almost young shock, and then something that looked like the specific pain of someone hearing a sound they had given up on hearing.\nHe said, in Mmo, slow and precise: Your accent is earth-southern. Old coastal dialect. Where did you learn it?\nHer grandmother''s hands. The kitchen. The last months. "My grandmother," she said, in the same language, and her voice came out steadier than she felt. "She died when I was eleven."\nHow much do you have?\n"Kitchen words. Bedtime words. Maybe forty phrases."\nSomething shifted in his face. Not pity she would have closed the conversation for pity. It was more like recognition. I have the formal register, he said. The ceremonial texts. I have been reading it for four years and I have never once spoken it to another person.\n"Neither have I," she said.\nThirty seconds. That was all. Because then a door opened somewhere above them and they both heard it and the living moment cracked down the middle, and she walked out of the archive without looking back, the pale wood door swinging shut behind her.\nShe crossed the courtyard in the early sky-morning light and went back to the delegation tower and sat on the edge of her sleeping mat and stared at the wall.\nI come with open hands. Her grandmother''s phrase, from a dead language, spoken to the sky king''s son in a restricted archive on her second morning in the enemy court.\nDown the hall Ekene was already awake, already reviewing documents, already preparing for the briefing that would begin in two hours. The war was three hundred years old. People were dying in it right now, today, in the valley provinces, in the coastal settlements. She was here to assist a diplomatic effort that had failed four times before this and would probably fail again.\nShe lay back on the sleeping mat and looked at the ceiling.\nAcross the courtyard, in the archive, she was fairly certain Soren was also not sleeping.\nShe was right.','\n',char(10)),927,0,1,NULL,'2026-04-07T05:32:50.885Z','2026-04-07 05:32:50','2026-04-07 05:32:50',NULL,1,13);
INSERT INTO "chapters" ("id","novel_id","chapter_number","title","content","word_count","is_premium","is_published","audio_url","published_at","created_at","updated_at","scheduled_release_at","part_number","season_id") VALUES(202,28,3,'Rules We Make',replace('She made herself a list.\nNot on paper because paper could be found but in her head, the way she had been trained. Ordered, numbered, revisited each morning like a prayer.\nOne: she was here to assist Councillor Ekene. To observe, to record, to relay information to her father''s office with accuracy and without personal interference.\nTwo: she had no business in the archive. She had no business with any member of the royal family, and specifically no business with the youngest prince, who was politically irrelevant and therefore irrelevant to the mission entirely.\nThree: what had happened in the archive was a moment of weakness. It was understandable. It would not happen again.\nShe held the list in her head through the morning briefing, through the formal introduction ceremony in the great hall where she stood three rows back and watched Ekene exchange ritual phrases with the sky court''s senior councillors, through the afternoon review session where she transcribed notes in her careful earth-script. She held it through dinner, where the delegation ate separately, and through the evening, when the sky outside the windows went from coral to a deep bruised purple she had no name for.\nShe was doing very well.\nThen on the fourth morning she went to the garden.\nShe had a reason. The silver-leafed plants were mentioned in a trade document she was cross-referencing and she needed to confirm the variety for an annotation. This was a legitimate work task. She wrote it down in her duty log before she left.\nHe was already there.\nNot reciting this time. Just sitting on the low stone bench at the garden''s edge, a small book open in his lap, not reading it. Looking at the sky the way someone looked at something that belonged to them and also exhausted them.\nHe saw her at the same moment she saw him.\nNeither of them left.\nShe crossed to the opposite end of the garden and crouched beside the silver-leafed plants and looked at them with the focus of someone who was absolutely here for the plants. She heard him close the book. She did not look up.\n"There are twelve varieties," he said, in earth-language. "The one you''re looking at is the coastal strain. Your people brought it, originally. Three hundred years ago, before."\nShe looked up then.\nHe was watching her without any particular expression. Informational. Like he was completing a record.\n"Thank you," she said, in earth-language.\nSilence. She looked back at the plant.\n"I''ve been thinking," he said, "about how this is going to go."\nShe waited.\n"You can''t come to the archive. If someone sees you there it becomes a problem for your delegation and a problem for me." He said it the way someone stated weather. Not unkindly. "And we can''t speak in public. In any language."\n"I know that," she said.\n"There is a maintenance corridor behind the archive. It connects to the east tower. It''s used twice a week by the cleaning staff, early mornings, Tuesdays and Fridays. The rest of the time it is empty." He paused. "I''m not suggesting anything. I''m telling you the information exists."\nShe stood up. Brushed the stone dust from her knees.\n"You want to keep meeting," she said.\n"I want access to a native speaker of an old coastal dialect," he said. "That is a scholarly interest. I have had it for four years."\n"And I''m just a convenient resource."\n"You''re the only living person I''ve been able to speak Mmo with." He said it plainly. The plainness of it was worse than if he had been dramatic. "I am aware that is not a small thing."\nShe looked at him for a moment. The sky behind him was its usual pale gold, the towers rising in the distance, everything clean and cold and magnificent. He looked out of place against it somehow. Too plain. Too still.\n"If we do this," she said, slowly, "there are conditions."\nHe waited.\n"Nothing I hear from you goes into my official reports. Nothing you hear from me goes to the court." She kept her voice low and even. "Whatever this is, it lives only here."\n"Agreed."\n"And if either of us decides to stop, we stop. No questions."\n"Agreed."\nShe nodded once. Then she said, in Mmo, her grandmother''s phrase for sealing a thing: It is witnessed by what we both remember.\nHe repeated it back to her. His formal register against her coastal dialect, the same words wearing different clothes, and underneath both versions the same language, the same three hundred years of it surviving in two people who had no reason to be standing in the same garden.\nShe picked a leaf from the coastal plant, tucked it into her notes for the annotation, and left without another word.\nWalking back across the bridge to the delegation tower she kept her face neutral and her hands loose and her breathing even.\nShe revised her list that night. She did not throw it away. She told herself that was the important part, that the list still existed, that she was still the person who had made it.\nBut she noted the maintenance corridor in the back of her memory, filed it carefully, and lay awake in the dark for a long time thinking about a dead language that had survived in two people on opposite sides of a three-hundred-year war.\nShe did not examine what that meant.\nNot yet.','\n',char(10)),913,0,1,NULL,'2026-04-07T05:35:16.433Z','2026-04-07 05:35:16','2026-04-07 05:35:16',NULL,1,13);
INSERT INTO "chapters" ("id","novel_id","chapter_number","title","content","word_count","is_premium","is_published","audio_url","published_at","created_at","updated_at","scheduled_release_at","part_number","season_id") VALUES(203,28,4,'The Banquet',replace('Ekene told her three times to stay behind him and slightly to the left.\n"Not beside me," he said, adjusting his ceremonial collar in the small bronze mirror above the washstand. "Beside me implies equal rank. Left and behind implies support. You are support."\n"I understand," Adaora said.\n"And do not speak unless directly addressed. And if directly addressed, answer briefly. And do not look at the royal family."\n"I understand."\n"And do not eat until I eat."\n"Ekene."\n"Yes."\n"I understand."\nHe looked at her in the mirror. "You have never been to a sky court banquet."\n"Neither have you."\nA pause. He straightened his collar one final time. "Left and behind," he said, and walked out.\n\nThe great hall was the largest room she had ever stood in.\nIt was built into the top of the central tower, open on all sides to the sky through tall arched windows, the ceiling so high above them it had its own weather — a faint mist gathered at the apex, lit gold from below by the hundreds of candles burning in iron fixtures along every wall. The tables were arranged in a strict hierarchy she had memorized from the briefing documents: the royal table on its raised platform at the far end, the senior court tables fanning outward by rank, and at the far left edge, closest to the doors and furthest from the center, the delegation table. Correctly placed. Deliberately peripheral.\nShe stood left and behind Ekene and looked at nothing directly and saw everything.\nThe sky court dressed for ceremony the way they built their towers — with the intention of being overwhelming. Every robe was layered, every head elaborately braided, gold wire catching the candlelight so the room seemed to flicker even when no one moved. There were perhaps two hundred people and they filled the hall with a low, controlled noise that was not quite conversation and not quite silence.\nShe found him without meaning to.\nHe was at the royal table, three seats from the center, between an older court official and a young woman whose braids were the most elaborate in the room. He wore ceremony better than he wore plainness — the layered robe, the gold at his collar — but she could see from across the hall that he wore it the way someone wore borrowed clothes. Present. Not comfortable.\nHe was not looking at her.\nShe looked away.\n\nThree hours.\nShe learned them by their edges.\nThe first hour was ritual — call and response phrases between the sky king and his senior councillors, the kind of formal speech that meant nothing except its own performance. She stood and sat when Ekene stood and sat and kept her face arranged in the expression of respectful attention she had practiced.\nThe second hour was food, served in courses she did not recognize, some of it good and some of it aggressively strange. She ate what Ekene ate and noted the dishes for her report and did not look at the royal table.\nShe looked at the royal table.\nHe was listening to the court official beside him with the patient expression of someone who had been listening to that official for a long time. His hands were flat on the table. Once he said something that made the young woman beside him laugh, brief and genuine, and then he looked down at his plate and she could not read whatever was on his face from this distance.\nShe looked away again.\nThe third hour was the part that required the most from her. It was the open reception, the room loosening into movement, people crossing between tables, the careful social machinery of the court in motion. Ekene entered it immediately, moving toward the senior councillors with the practiced ease of a man who had been doing this for forty years. She was supposed to follow and observe.\nShe followed and observed.\nShe was standing at the edge of a conversation between Ekene and a sky court official about river trade agreements, holding a cup of something warm and spiced that she was not drinking, when she became aware of someone stopping beside her.\nNot beside her. Near her. At the correct diplomatic distance of two people who had no reason to speak.\nShe did not turn her head.\nIn her peripheral vision: plain ceremony clothes, hands loose at his sides, attention directed toward the river trade conversation with the polite blankness of someone fulfilling an obligation.\nShe looked at the middle distance and breathed.\nHe was close enough that she could have spoken to him in Mmo at half a whisper and he would have heard her. She did not do this. The hall had two hundred people in it and every one of them was practicing the sky court''s particular skill of looking elsewhere while seeing everything.\nHe stood there for perhaps four minutes. She was not counting. She counted.\nThe river trade conversation moved to port access and she made a note in the small book she carried for Ekene''s use and did not once turn her head.\nThen he moved on.\nShe watched him cross the hall toward the royal table, unhurried, and resume his seat, and pick up his cup, and look out at the room with the same patient blankness.\nFrom across the hall he was just the youngest prince, politically irrelevant, fulfilling his ceremonial obligation. Nothing about his posture or his expression told any story.\nShe looked down at her notepad.\nIn the margin, without deciding to, she had written one word.\nNot in earth script. Not in sky script.\nIn Mmo.\nThe word her grandmother used for the particular feeling of wanting something you could not name yet. A word that had no translation in any living language because it was too specific, too old, too precisely describing something people apparently felt often enough to need a word for but not often enough to carry it forward into the languages that survived.\nShe looked at it for one second. Then she drew a clean line through it and returned to the notes.\nLeft and behind Ekene, she followed him out when the banquet ended, through the great hall''s tall doors and back across the bridge under the sky''s deep purple night.\nShe was across the bridge and nearly at the tower door when she realized she had been counting. Four minutes. She had counted every second he stood beside her without knowing she was doing it, and that number was sitting in her chest now like evidence of something she had not yet been charged with.','\n',char(10)),1111,1,1,NULL,'2026-04-30 13:54:14','2026-04-07 05:36:34','2026-04-30 13:54:14',NULL,1,13);
INSERT INTO "chapters" ("id","novel_id","chapter_number","title","content","word_count","is_premium","is_published","audio_url","published_at","created_at","updated_at","scheduled_release_at","part_number","season_id") VALUES(204,28,5,'What He Overheard',replace('Adaora had seen him twice since the corridor. Once crossing the archive bridge and once at the edge of the garden, both times at a distance, both times without acknowledgment. She was doing well with the list. She was keeping the rules. She went to sleep on Wednesday with her notes organized and her conscience clear.\nShe woke up at the sky court''s dawn hour thinking about the formal register, specifically the verb form they had not yet worked through, and whether he had attempted it alone.\nShe told herself that was an academic interest.\nSoren had a gift for being ignored.\nIt was not something he had cultivated deliberately. It had simply developed over years of being the youngest, the least significant, the one whose seat at the royal table existed out of obligation rather than necessity. People stopped adjusting their conversations when he entered rooms. They forgot to lower their voices. After a while he had understood that this was useful, and he had stopped announcing himself.\nHe was not announcing himself the evening he came through the side passage behind the war council chamber, the one that connected to the upper archive, the one that nobody used because it was narrow and badly lit and there was a more convenient route on the other side of the tower. He was carrying three texts he had borrowed from the lower stacks and thinking about verb conjugations and not thinking about anything else.\nHe heard his father''s voice through the wall and stopped.\nNot because of the voice. Because of the word that followed it.\nOminala.\nHe knew Ominala from the maps. A river settlement in the earth kingdom''s southern territory, three thousand people, mostly fishing families, positioned at the junction of two tributaries that fed into the larger valley river system. He knew it from the maps because he knew all the contested territories from the maps. He had been studying them since he was twelve, not for strategy but for language, tracing the old place names back to their Mmo roots.\nHe stood very still in the narrow passage and listened.\nHis father was not alone. Two voices he recognized as senior war council: General Adio, who had been running the eastern campaigns for six years, and Councillor Femi, who handled supply chains and never attended anything unless it was operational. A third voice he did not immediately place.\nThey were discussing a supply interruption. The sky court had been funding a network of informants in the southern earth territories for eleven years, positioning them along the river routes. The plan, as he understood it from the fragments coming through the wall, was to activate those informants next month. Not for information gathering. For disruption. Bridges. Supply lines. The food routes that fed three settlements through the dry season, of which Ominala was the largest.\nThe third voice said something about timing. His father said the diplomatic mission complicated nothing, that it was theatre and everyone present understood it as theatre. Councillor Femi said the dry season window was six weeks and they could not afford to wait past it.\nGeneral Adio said Ominala would be manageable within a month.\nSoren put his hand flat against the passage wall.\nManageable. He knew what that word carried in a war council context. He had grown up in this court. He knew the vocabulary of decisions made in rooms where the people being decided about were not present.\nThree thousand people.\nHe made himself move. Quietly, the way he had learned to move through this court his entire life, he continued down the passage and up to the archive and set the three texts on the reading table and sat down.\nThe archive was empty. It was always empty at this hour.\nHe looked at the texts without seeing them.\nThe rules they had made in the garden were clear. Nothing he heard went to her. Nothing she heard came to him. Whatever existed between them lived only there, between them, separate from everything that was also true about who they were and where they stood.\nHe had agreed to those rules. He had suggested them, partly. They were sensible. They were the only thing that made any of this even remotely survivable.\nThree thousand people in Ominala, most of them fishing families, none of them war council, none of them the reason this conflict had started or the reason it continued. The dry season in six weeks. Supply routes cut. He knew what that looked like in practice because he had read the after-reports from previous campaigns, filed in this same archive, written in the precise flat language of military record that did not say people starved but communicated it clearly enough if you read carefully.\nHe pulled a blank sheet toward him and then did not write anything on it.\nShe was in the delegation tower right now, probably. Working on Ekene''s documents, probably. Doing the careful, necessary work of a diplomatic mission that his father had just described, in a private council meeting, as theatre.\nHe thought about the word she had used to seal their agreement in the garden. The old Mmo phrase, witnessed by what we both remember. He had recognized it as a formal sealing phrase from the ceremonial texts but he had not known, until she said it, that it was still used. That it had survived in actual mouths, not just in records.\nHe sat in the archive for a long time.\nThen he took the blank sheet and wrote on it in Mmo. Not a message. Just the name: Ominala. The old form, the way it appeared in the pre-war texts, before the sky court''s maps had flattened it into something unrecognizable.\nHe looked at it. Then he folded the sheet once and held it and thought about what he was and what she was and the three hundred years sitting between both of those things.\nOutside, the sky went dark in the way it went dark up here, fast and complete, the stars appearing all at once like they had been waiting.\nHe was still holding the folded sheet when the archive''s crystal lights shifted to their night setting, low and amber, and the tower around him went quiet.\nHe had not decided anything yet.\nHe told himself that. He had not decided anything yet.','\n',char(10)),1066,1,1,NULL,'2026-04-29 08:42:45','2026-04-07 05:37:21','2026-04-29 08:42:45',NULL,1,13);
INSERT INTO "chapters" ("id","novel_id","chapter_number","title","content","word_count","is_premium","is_published","audio_url","published_at","created_at","updated_at","scheduled_release_at","part_number","season_id") VALUES(205,28,6,'The Archive Hours',replace('The maintenance corridor smelled like stone and old water and something faintly metallic that she never identified. It was narrow enough that two people could not pass each other without turning sideways. The light came from a single crystal strip near the ceiling that flickered every few minutes for no reason anyone had apparently bothered to fix.\nIt was, genuinely, the least romantic place in the sky court.\nThey met there on Tuesdays and Thursdays, not Fridays as he had originally said, because Fridays the cleaning staff ran late. Thirty minutes, sometimes forty. Long enough to work through a passage of text, trade vocabulary, correct each other''s pronunciation. She brought her grandmother''s phrases. He brought the formal register. They built a shared grammar out of both.\nThat was how it started. That was what she told herself it was, for the first two weeks.\nThen one Tuesday he arrived with a text about coastal fishing routes and she looked at the old Mmo word for the specific net used in deep water and said, without planning to, "My uncle makes these. By hand. It takes him three weeks per net."\nSoren looked up from the text. "Does he sell them?"\n"He gives them to whoever needs them." She paused. "He says the sea doesn''t care who paid for the net, only whether it holds."\nHe was quiet for a moment. "My father would not understand a logic like that."\n"Neither would mine," she said. "But my uncle is not interested in what kings understand."\nThat was the first time they talked about something other than language.\nAfter that it happened naturally, the way a river found its level. They would start with the texts and end somewhere else entirely, following the thread of a word into a memory into a question into an answer that had nothing to do with grammar. She learned that he had taught himself Mmo at fourteen after finding a single damaged text in the archive''s lower stacks, that he had spent a year reconstructing enough of it to read the damaged portions, that he had told nobody because nobody would have found it useful or interesting. He learned that she had almost not come on this mission, that she had argued with her father for two weeks about it, that she had lost the argument not because her father was more persuasive but because she had eventually understood he was also frightened and could not say so.\n"He sent you because he trusts you," Soren said.\n"He sent me because he needed someone he could trust and I was available." She looked at the corridor wall. "Those are different things."\n"Are they?"\nShe considered it honestly. "I don''t know. Maybe not."\nHe had a habit, she noticed, of going very still when he was actually thinking, as opposed to the performed attention he wore in public spaces. In the corridor he was often still. She had started to read the quality of his stillness the way she read weather.\nShe noticed other things she did not examine too carefully.\nThe Thursday of the third week he arrived late and sat down with the distracted energy of someone who had come from something difficult. She waited. After a few minutes he said, in Mmo, "My father held a review of the eastern campaign today. I was required to attend."\nShe kept her voice even. "And?"\n"And I sat in a room for two hours and listened to a war described in the language of logistics." He looked at the corridor floor. "I have always known, in an abstract way. Today it was not abstract."\nShe thought about the valley provinces. About the casualty reports her father''s office received, written in the same flat logistics language, the numbers that were people. "It is never abstract for the people in the settlements," she said.\n"I know that."\n"I don''t mean it as an accusation."\n"I know that too." He was quiet. Then: "I want to ask you something and I need you to answer honestly."\n"All right."\n"Do you believe this diplomatic mission is going to work?"\nShe should not answer that. It was exactly the kind of question their rules existed to prevent, the kind of answer that crossed from personal into political, that could not be unspoken. She looked at him in the flickering corridor light and he was watching her with the particular stillness that meant he was actually asking, not performing a question.\n"No," she said.\nHe nodded slowly, like she had confirmed something.\n"My father describes it as theatre," he said. "In private. He is not preparing for peace. He is preparing for the next campaign phase and using the diplomatic window to complete the preparation."\nThe corridor felt smaller suddenly. She breathed through it. "Soren."\n"I know what I just said."\n"Why are you telling me this?"\nHe looked at her directly. In Mmo, he said, because you are the only person I speak truthfully to. The formal register made it sound ceremonial, almost impersonal, but the formal register was just the clothes the language wore. Underneath it the meaning was plain.\nShe looked back at him for a long moment.\nThe thing she had been not examining chose this moment to become impossible to ignore. It sat in the corridor with them, patient, taking up the space she had been carefully not giving it. She was aware of the exact distance between where she was sitting and where he was. She was aware that she had been aware of that distance for several meetings now.\nShe looked down at the open text between them.\n"We should finish the passage," she said.\n"Yes," he said.\nThey finished the passage. Their voices in the narrow corridor, his formal register and her coastal dialect, the dead language alive between them for thirty more minutes while the crystal light flickered overhead and the sky court moved through its routines on the other side of the wall.\nWhen she left she walked back to the delegation tower at her usual pace and sat at her work table and opened Ekene''s documents and stared at them.\nShe was keeping records for her father''s office. She was here to observe and report. She was a diplomat''s aide, seventeen years old, in the enemy court, with a list in her head that still existed, that she still revised each morning.\nShe opened the report and wrote three lines about the afternoon session and stopped. What Soren had said was still there, sitting exactly where he had left it. My father describes it as theatre and it was the most operationally important thing anyone had said to her since she arrived, and it was going into no report, and she knew precisely why, and that knowing was the thing she could not write anywhere.','\n',char(10)),1144,1,1,NULL,'2026-04-30 13:56:02','2026-04-07 05:38:15','2026-04-30 13:56:02',NULL,1,13);
INSERT INTO "chapters" ("id","novel_id","chapter_number","title","content","word_count","is_premium","is_published","audio_url","published_at","created_at","updated_at","scheduled_release_at","part_number","season_id") VALUES(206,28,7,'Casualty Report',replace('\nThe dispatch arrived on a Wednesday, which meant she had one day before she would see him again.\nShe did not know, at first, that it concerned her village. Dispatch documents came through Ekene and were summarized for her in the portions relevant to her work. She transcribed, annotated, filed. It was the third item in the morning''s documents, labeled under southern territory updates, and she was halfway through transcribing it before the settlement name registered.\nUghelli.\nShe stopped writing.\nUghelli was not large. It sat at the edge of the coastal territory, a fishing and farming settlement, the kind of place that appeared on military maps only as a supply node, a number, a strategic position. It had a market that ran on Saturdays. It had a school with two rooms and one teacher. It had her mother''s sister and four cousins and a stretch of red earth road she had walked every dry season of her childhood.\nThe dispatch described an engagement in the southern coastal zone. Sky court forces and earth kingdom militia. Casualties on both sides, numbers listed cleanly in two columns. Under earth kingdom casualties, a note: significant civilian impact in proximate settlement, Ughelli district.\nSignificant civilian impact.\nShe finished transcribing the document in her careful, even handwriting. She checked her work once. She set the page in the correct file. Then she folded her hands on the table and sat very still for a moment.\nEkene came through the adjoining room and looked at her. "The afternoon session begins at the second bell," he said.\n"I know," she said.\nHe looked at her for a moment longer with the expression of a man who had been in diplomatic service for forty years and knew the difference between fine and not fine. He did not ask. He went back through the door.\nShe sat at the table until the first bell. Then she gathered her materials and followed him to the afternoon session.\n\nShe was quiet at dinner. The junior aides filled the silence with conversation about the afternoon session, about a sky court official who had made a pointed remark about earth kingdom river management, about the food, which had been better today, somebody thought. She ate what was in front of her and contributed nothing and nobody pushed her because she had a reputation in the delegation for being contained, and contained people were left alone.\nAfter dinner she went to the window.\nThe sky at night up here was different from earth sky. Too open, too present, nothing on the horizon to interrupt it. She had stopped finding it cold. She did not examine when that had happened.\nShe thought about her aunt, who made pepper soup with too much pepper and was proud of it. Her cousin Nkechi, who was twelve now, who had been learning to braid. The Saturday market. The red earth road.\nSignificant civilian impact.\nShe did not cry. She pressed her hand flat against the window''s cool surface and breathed through the tightness in her chest and did not cry because crying required a certainty she did not have yet. Significant civilian impact was not a name. It was not a confirmation. It was the flat logistics language of military record that communicated things clearly enough if you read carefully.\nShe had read carefully.\n\nThursday came.\nShe went to the corridor at the usual time and sat in the usual spot and when he arrived and settled across from her and opened the text he had brought, she said, "Not today."\nHe looked up.\n"I don''t want to work today," she said. Her voice came out level. "Can we just sit."\nHe looked at her for a moment. Something had shifted in her face and he could see it — she watched him see it — but he did not know what it was yet. She was not going to tell him yet. She did not know how to hold both things at the same time, this corridor and what the corridor was built inside, who she was here and who his people were in Ughelli.\n"All right," he said. He closed the text.\nThey sat.\nThe corridor light flickered in its usual way. Somewhere in the archive on the other side of the wall something settled, the old building sound. She looked at the floor and he looked at the floor and neither of them spoke for a long time.\nHe said, eventually, in Mmo, not the formal register, the quieter register she had taught him from her grandmother''s kitchen words: you are carrying something.\nShe looked at him.\nHis face was careful and open and genuinely asking. He had learned, in the archive hours, to ask without pushing. She did not know when she had started to value that specifically.\n"Yes," she said. In Mmo. The simplest answer.\nDo you want to put it down for a while.\nShe thought about that. The dispatch was in the file. The file was in her work folder. The work folder was in the delegation tower, sitting on the table where she had transcribed it in careful even handwriting and checked her work once.\n"I don''t know if I can," she said.\nHe nodded slowly. He did not ask what it was. She had said not today and he was honoring that and she felt the honoring of it somewhere specific in her chest, in the same place where the tightness lived.\nThey sat for the rest of the thirty minutes in silence. Not uncomfortable. The corridor held them and the light flickered and she breathed through the tightness one breath at a time.\nWhen she left she said, in Mmo, her grandmother''s phrase for something that needed no response: it is witnessed.\nHe repeated it back quietly as she went.\nWalking back across the courtyard she thought about the fact that she had just spent thirty minutes sitting in silence with the sky king''s son, finding it easier than sitting alone in her room, and that somewhere underneath that fact was a question she was not ready to ask herself.\nShe walked past it.\nShe had enough to carry.','\n',char(10)),1032,1,1,NULL,'2026-04-29 08:41:36','2026-04-07 05:39:05','2026-04-29 08:41:36',NULL,1,13);
INSERT INTO "chapters" ("id","novel_id","chapter_number","title","content","word_count","is_premium","is_published","audio_url","published_at","created_at","updated_at","scheduled_release_at","part_number","season_id") VALUES(207,28,8,'What the Language Holds',replace('\nShe had spent four days deciding how to say it.\nNot whether. She had passed whether somewhere between the dispatch and the Saturday that came after it, when she had sat with the knowledge of Ughelli like a stone in still water, feeling the ripples move outward into everything. Whether was finished. The question was only how, and how had no clean answer, so she arrived at the corridor on Tuesday with nothing prepared and sat down and waited for him to settle and then said it plainly.\n"Your people killed people from my village."\nHe went still.\nNot the thinking stillness she had learned to read. Something different. The stillness of someone who had been waiting for a wall to arrive and had just felt it.\n"Ughelli," she said. "Southern coastal territory. The dispatch came last Wednesday."\n"I know about Ughelli," he said quietly.\n"How many?"\nA pause. "The report I saw said fourteen confirmed. Civilian."\nFourteen. She had not had a number before. The dispatch had said significant civilian impact and she had read carefully and understood it but fourteen was different from significant. Fourteen had a specific weight. She sat with it for a moment.\n"Were any of them yours," he asked. "Specifically."\n"I don''t know yet. I haven''t been able to get word out." She looked at her hands. "My aunt lives there. Four cousins. The youngest is twelve."\nHe said nothing. She did not want him to say nothing and she also did not know what she wanted him to say. She was not sure language had the right shape for this specific moment, which was perhaps why she had come here to say it, to this corridor, in this language that nobody else spoke.\n"Your father ordered it," she said. Not an accusation. A fact, laid flat between them.\n"Yes."\n"And you knew. Before it happened. You knew something was coming for the southern settlements."\nThe pause that followed was long enough that she looked up at him. He was watching her with an expression she had not seen on him before. Not guilt exactly. Something older and more specific than guilt.\n"Yes," he said.\nThe word landed.\nShe had known, sitting in her room with the dispatch, that there was a version of this conversation where she was furious. She had rehearsed that version. It had felt clean and necessary and she had understood exactly who she was in it. Sitting in the corridor now with the actual answer she found that the fury was present but it was not alone. Underneath it was something more complicated and she hated that it was complicated.\n"Why didn''t you tell me," she said.\n"Our rules."\n"Fourteen people, Soren."\n"I know." His voice was quiet and without defense. "I sat in the archive with the information for three days. I wrote your settlement''s name on a piece of paper in Mmo and held it and told myself I had not decided anything." He paused. "I had decided. I just was not ready to say so."\n"You chose the court."\n"I chose the rules we made." He looked at her directly. "I told myself they were the same thing."\n"Are they."\n"No," he said. "I know they are not."\nThe corridor light flickered. She breathed through the tightness that had lived in her chest since Wednesday, the tightness that had a number now, fourteen, that had a name now, the specific name of his choosing.\nIn Mmo she said, I need to ask you something and I need the true answer.\nHe straightened slightly. The formal register was the register for serious things. She had never initiated it before. He said, I will give it.\nIf it happens again, she said. If you hear something. Will you tell me.\nHe was quiet for a long time.\nThe honest answer was not simple and they both knew it. Telling her meant breaking with the court. It meant choosing her side over his, or at least choosing something that existed outside the clean lines of sides, something that had no political category and no safe place to live. It meant the rules they had made were not the outermost boundary of what this was.\nYes, he said finally. I will tell you.\nShe looked at him. The formal register made everything sound like ceremony but she had learned, over weeks in this corridor, that the formal register was also where he put the things he meant most completely. The kitchen words she had inherited were for ordinary love. His ceremonial language was for the things that cost something to say.\n"I don''t forgive you," she said, in earth language. Plain and direct. "For Ughelli. I want to say that clearly."\n"I know."\n"But I believe you."\nHe nodded once.\nShe opened the text he had brought, the one sitting untouched between them since the beginning, and smoothed the page. Her hands were steady. She was not sure when she had become someone whose hands stayed steady through things like this, or whether it was steadiness at all or just the particular discipline of someone who had learned early to carry things without showing the weight.\n"The third passage," she said. "You had a question about the verb form last week."\nHe looked at her for a moment, reading her the way she had learned to read him. Then he found the passage and read it aloud, the formal register filling the narrow corridor, and she listened and corrected his conjugation and explained the coastal variant and he repeated it back until he had it right.\nThey worked for thirty minutes. The language held them the way it always held them, that specific and fragile shelter of words that belonged to both of them and nobody else.\nWhen she left she did not say her grandmother''s closing phrase.\nShe said instead, in Mmo, something she had not planned: I am still here.\nIt was a kitchen phrase. Ordinary. Her grandmother had said it coming through the door, a simple announcement of presence. She had not thought about why she chose it until she was halfway across the courtyard and felt what it meant in this specific corridor, after this specific conversation.\nShe kept walking.\nBehind her the corridor was quiet and the archive was quiet and the sky court moved through its day on all sides, enormous and indifferent.\nFourteen people.\nShe was still here.','\n',char(10)),1075,1,1,NULL,'2026-04-07T05:40:07.247Z','2026-04-07 05:40:07','2026-04-07 05:40:07',NULL,1,13);
INSERT INTO "chapters" ("id","novel_id","chapter_number","title","content","word_count","is_premium","is_published","audio_url","published_at","created_at","updated_at","scheduled_release_at","part_number","season_id") VALUES(208,28,9,'Someone Is Watching',replace('\n\nThe elder''s name was Councillor Yetunde and she had been managing the sky court''s internal affairs for twenty-three years.\nAdaora knew this from the briefing documents. She knew Yetunde by sight — a tall woman, silver-haired, with the particular economy of movement that belonged to people who had spent decades in rooms where every gesture was read. She sat two seats from the sky king at formal events. She spoke rarely. When she did, people adjusted.\nAdaora had noted her as significant and filed her accordingly and had not thought about her specifically until the morning Yetunde looked at her across the eastern courtyard with an expression that was not hostile, not curious, but precise. The expression of someone completing a count.\nAdaora looked away first.\nShe told herself it was nothing. The sky court watched the earth delegation as a matter of routine. Being observed was not the same as being seen.\nShe believed this for two days.\n\nOn Thursday she arrived at the corridor entrance and stopped.\nNothing was visibly wrong. The door was as she had left it on Tuesday, the corridor beyond it dim and quiet. She stood at the entrance and listened for thirty seconds and heard nothing. She went in.\nSoren arrived four minutes later and she knew from the way he moved that something had already reached him.\nHe sat down and said, without preamble, "My brother spoke to me this morning."\nShe waited.\n"Darian. The second son. He manages court security as a secondary function." He looked at the corridor floor. "He asked me, casually, how I had been spending my Tuesday and Thursday mornings."\nThe tightness arrived in her chest, different from the Ughelli tightness, sharper and more immediate.\n"What did you say," she said.\n"Archive work. Which is true."\n"And?"\n"He said that was what he had assumed." Soren paused. "He said it in the way that meant he was not assuming."\nShe thought about Yetunde''s eyes in the eastern courtyard. The precise expression. The completed count.\n"How long do you think they have been watching," she said.\n"I don''t know. Darian is careful. He would not move until he had enough." He looked at her. "Enough is different depending on what he has actually seen."\nWhat they had seen, if they had been thorough, was a pattern. The corridor meetings were invisible from the main courtyard but the entry door was not. She used the garden route. He used the archive route. Separately, each route had a legitimate explanation. Together, on a Tuesday and Thursday rhythm, they built a shape that someone patient and trained would eventually recognize.\nYetunde was patient and trained.\n"We should stop," Adaora said.\nThe words came out before she had fully decided them, but once they were in the corridor they were true and she knew it. She watched Soren receive them. He did not argue. He looked at the floor for a moment with the particular stillness of someone doing an honest calculation.\n"Yes," he said.\nThe agreement sat between them and she felt the specific shape of it, how it was the right answer and also the hardest and how those two things were not in conflict, just simultaneously true.\n"For how long," he said.\n"I don''t know. Until the pattern breaks. Until there''s nothing to confirm." She thought through it practically, the way her mother had taught her. "You stop the archive visits. I go back to the garden once more for the plant annotation and then I don''t go back. We don''t pass each other in corridors. We don''t adjust our behavior if we''re in the same room."\n"Especially if we''re in the same room," he said.\n"Yes."\nHe nodded. She could see him filing it, the same way she filed things, ordered and numbered and revisited. He was better at this than she had initially given him credit for. The youngest prince, irrelevant, overlooked. He had survived this court for twenty years by being good at exactly this kind of cold management of exposure.\nShe thought about what it must have cost him to be that person for twenty years and pushed the thought away because it was not useful.\n"Soren." She said his name the way she rarely said it, directly, without approach. "If Darian finds something. If this becomes an official matter. You protect yourself first."\nHe looked at her.\n"I mean it," she said. "I am a diplomat''s aide. I have a delegation and a councillor and my father''s office. I have cover. You have less."\n"I am a member of the royal family."\n"You are the youngest son that nobody is watching for political reasons," she said. "Which means if you become a political problem the solution is simple and fast." She held his gaze. "Protect yourself first."\nSomething moved through his expression that she did not have a word for in any language, dead or living.\nIn Mmo he said, you are asking me to do the thing that would cost me the most and calling it protection.\nShe said nothing. Because he was right, and she had no answer for that, and the corridor was very small and the danger had stopped being abstract and was now sitting with them in the flickering light like a fourth person.\n"The texts," he said quietly. "The ones we worked through. I''ll move them to the lower stacks. Different section. Nothing traceable."\n"Good."\n"And the archive entry logs. I can adjust the record for the last two weeks."\nShe looked at him. "Can you do that without drawing attention."\n"I''ve been doing archive work since I was fourteen. Nobody questions my access." He paused. "I should have done it earlier. I didn''t think."\n"Neither did I."\nA silence.\nShe became aware that this was possibly the last time they would be in this corridor. She did not say that. Saying it would give it a weight she was not prepared to manage, not here, not now, not with the danger this immediate.\nShe gathered the text they had not opened today and stood.\nIn Mmo she said her grandmother''s closing phrase, the witnessing one, the one they had used since the garden. She said it at the normal register, quietly, the way she would have said it on any other Thursday.\nHe repeated it back.\nShe left the corridor and crossed the courtyard at her usual pace and went directly to Ekene''s office and sat down and opened the afternoon''s documents and began working.\nTwo hours later, from the window, she saw Councillor Yetunde cross the eastern courtyard below. The elder did not look up.\nBut she paused, briefly, at the point where the garden path met the archive route.\nAnd looked at both of them.\nThen continued walking.','\n',char(10)),1133,1,1,NULL,'2026-04-07T05:40:50.344Z','2026-04-07 05:40:50','2026-04-07 05:40:50',NULL,1,13);
INSERT INTO "chapters" ("id","novel_id","chapter_number","title","content","word_count","is_premium","is_published","audio_url","published_at","created_at","updated_at","scheduled_release_at","part_number","season_id") VALUES(209,28,10,'The Choice She Makes',replace('The treaty session lasted four hours and failed in the third.\nShe watched it happen from her position left and behind Ekene, the way she had watched everything in this court for two months now, with the particular attention of someone whose job was to see clearly and record accurately. The sky court''s senior councillors sat across the table from the earth delegation with the patient expressions of people who had already decided the outcome and were fulfilling a procedural obligation. Ekene presented the earth kingdom''s proposed terms with forty years of diplomatic precision. The sky court''s lead councillor, a broad man named Adio who also ran the eastern campaigns, listened without interruption and then declined each point in order, methodically, like someone clearing a table.\nThe earth delegation''s proposed boundary revision. Declined.\nThe proposed trade route reopening. Declined with a counter that gave the sky court three additional access points and the earth kingdom none.\nThe proposed civilian settlement protections. Declined on the grounds of military necessity, a phrase Adio used three times.\nEkene kept his face neutral through all of it. She kept hers neutral. The junior aides kept theirs neutral. On the other side of the table Adio kept his neutral and the session ended with both sides agreeing to reconvene in two weeks, which everyone present understood as the formal language for nothing will change.\nOutside, crossing back to the delegation tower, Ekene said nothing. She said nothing. They walked in the silence of people processing the same information at different depths.\n\nThat night she opened her report folder.\nHer father''s office required a summary after each significant session. She had a template, a structure, a set of required fields. She filled them in order.\nSession date. Attendees. Earth kingdom positions presented. Sky court responses. Assessment of opposing delegation''s posture. Recommended next steps.\nShe wrote cleanly through each field until she reached assessment.\nShe sat with her pen above the page.\nWhat she knew, officially, from today''s session: the sky court had declined every substantive point with no genuine counter. The diplomatic mission was not progressing. The sky court was managing the process rather than engaging it.\nWhat she knew unofficially, from Soren, six weeks ago in the archive corridor: his father had described this mission as theatre. The court was using the diplomatic window to complete preparation for the next campaign phase.\nWhat she knew unofficially, from Soren, in the weeks after Ughelli: he had confirmed that the southern territory actions were coordinated and intentional. Not field decisions. Policy.\nNone of the unofficial information existed in any of her reports. She had made that choice week by week, small omission by small omission, each one feeling manageable in isolation. Together they had built something she was only now seeing the full shape of.\nShe put her pen down.\nThe report she was supposed to write was the one that included everything. That was her function. That was what her father had sent her here to do, why he had trusted her specifically, why she was seventeen years old in the enemy court instead of home. She was his eyes. She was supposed to see clearly and report accurately.\nThe report that included everything would have Soren in it, not by name, but by implication. An intelligence source within the royal family. A pattern of information that could only have come from inside the court. Her father''s office would extract the implications with or without her naming them. They were thorough people.\nShe thought about Darian, the second son, asking about Tuesday and Thursday mornings. About Yetunde pausing at the junction of the garden path and the archive route. About Soren saying protect yourself first back to her like a translation of something she had not said in any language.\nShe picked up her pen.\nShe wrote the assessment section from what she had observed directly in the session. The sky court''s posture was obstructive and indicated no genuine intent toward resolution. The counter-proposals suggested a court operating from a position of strategic confidence. The earth delegation should not expect substantive progress in the reconvened session.\nShe wrote recommended next steps. Escalate to senior diplomatic level. Request direct engagement with the sky king''s office rather than the councillors. Prepare contingency positioning for mission failure.\nShe did not write what she knew about why the court was confident. She did not write the intelligence about the next campaign phase. She did not write anything that had come from a source in the sky court.\nShe closed the folder.\nShe sat at the table for a long time after that, in the specific silence of someone who had just done something they could not undo. The report existed now. It was the version she had chosen. Every other version had ceased to exist the moment she set down her pen.\nShe thought about the word on her list, the one she revised each morning. Accurate. She was supposed to report with accuracy. She had reported accurately from her direct observations. She told herself that.\nShe told herself that twice.\nFrom down the hall she could hear Ekene moving through his own post-session work, the quiet sounds of a man who had spent forty years in diplomatic service and had probably watched this specific failure coming for weeks. He had not told her what he thought privately. She had not told him what she knew privately. They were both carrying things in the silence between them, and the delegation tower was full of the weight of what was not being said.\nShe opened the folder one more time.\nShe added one line to the assessment section, carefully worded, attributed to nothing and nobody: intelligence suggests the sky court''s position is not subject to revision at the councillor level. Direct royal engagement is not optional. It is the only remaining route.\nShe closed it again.\nIt was the most she could give her father''s office without giving him Soren. She did not know if it was enough. She did not know if she was still the person her father had sent here, or whether that person had been replaced gradually by someone who made different calculations, who weighed different things, who sat in a corridor on Tuesdays and Thursdays and called it something other than what it was.\nShe put the report in the outgoing folder and went to the window.\nThe sky outside was deep and black and full of stars.\nSomewhere in the court, the next campaign phase was being prepared. She had the shape of it and had put it in a drawer and locked the drawer and she would have to live with that, with what it meant, with what it might cost.\nShe pressed her hand to the cool glass.\nShe had written herself into a version of events her father could read and her conscience could survive. Somewhere in the valley provinces the next campaign phase was moving toward people who did not know the shape of the decision she had just made on their behalf. She did not know their names. That was the part she could not put down.','\n',char(10)),1197,1,1,NULL,'2026-04-30 13:57:01','2026-04-07 05:42:11','2026-04-30 13:57:01',NULL,1,13);
INSERT INTO "chapters" ("id","novel_id","chapter_number","title","content","word_count","is_premium","is_published","audio_url","published_at","created_at","updated_at","scheduled_release_at","part_number","season_id") VALUES(210,28,11,'The Shape of Betrayal',replace('\nEkene submitted the request for royal engagement on a Monday morning, three days after she had recommended it in her report.\nShe watched him draft it at the work table, his careful sky-script moving across the page, forty years of diplomatic precision in every line. He had read her assessment and agreed with it and acted on it without hesitation because she was his eyes and he trusted her eyes and that was the arrangement between them, the foundation of everything the delegation ran on.\nShe said nothing.\nThe request went through official channels to the sky king''s senior secretary. The correct route. Properly formatted. She had watched Ekene send dozens of communications through this court''s channels over two months and each one had been received and processed without incident.\nThis one was different and she did not know why until it was too late to matter.\n\nCouncillor Yetunde came to the delegation tower on Wednesday morning.\nNot Adio, who handled official sessions. Not the secretary who managed correspondence. Yetunde, who managed internal affairs, who had paused at the junction of the garden path and the archive route three weeks ago and looked at both of them.\nShe arrived with two court officials and the specific calm of someone who had been building toward a moment for a long time and had arrived at it.\nAdaora was at her work table when she heard the voices in Ekene''s room. She set down her pen and did not move and listened to the shape of the exchange through the wall without being able to hear the words. Yetunde''s voice was low and even. Ekene''s responses were measured, then careful, then very still in the way that meant something had shifted.\nAfter twenty minutes Yetunde left. Her footsteps were unhurried down the corridor, down the stairs, out.\nAdaora waited.\nEkene appeared in the doorway. He looked at her with an expression she had never seen on him in two months of this mission. Not anger. Something older. The face of someone reassembling.\n"They have revoked our direct communication access," he said. "All future correspondence goes through a review process. Three day delay minimum." He paused. "The request for royal engagement has been declined. Formally. With a notation that the earth delegation has demonstrated conduct inconsistent with the terms of the diplomatic arrangement."\nShe heard the notation land. Felt its specific shape.\n"What conduct," she said.\n"Intelligence gathering beyond the scope of the diplomatic mandate." His eyes were on her, calm and precise. "They believe someone in this delegation has been accessing restricted information through an unofficial channel."\nThe corridor. The archive. The maintenance passage that smelled like stone and old water.\n"Yetunde has recommended our mission be formally suspended," Ekene said. "We have four days to complete our current documentation and prepare for departure."\nThe word departure moved through her like cold water.\n"Ekene."\n"I need you to tell me," he said quietly, "whether this notation has a basis."\nShe looked at him across the room. Forty years of diplomatic service. Her father''s man. The person who had trusted her eyes without question, who had acted on her recommendation without hesitation, who was now standing in a doorway with the face of someone who had walked into something blind because the person who was supposed to see clearly had chosen instead to see selectively.\n"Yes," she said.\nHe was quiet for a long time.\n"How much," he said.\n"Enough that your request triggered a recognition. They saw the shape of what I knew and traced it back."\n"And the source."\nShe said nothing.\nHe looked at her. He was not a man who needed things explained twice. She watched him work through it, the archive, the restricted access, the youngest prince who spent his mornings among old texts. She watched the understanding arrive and settle and become something he would carry quietly for the rest of this mission and probably longer.\nHe did not say the name. She was grateful for that.\n"The southern campaign intelligence," he said instead. "You had it."\n"The shape of it."\n"And you held it."\n"Yes."\nAnother silence, longer. Outside the window the sky court moved through its morning routines. The gold light fell across the stone towers the way it always fell, clean and cold and magnificent and entirely indifferent to the two people standing in a delegation tower room having a conversation that could not be undone.\n"There is a settlement in the western approach," Ekene said finally, his voice flat. "Oguta. Your report''s recommendation moved my thinking toward direct engagement, which moved our positioning documents, which my office relayed to your father''s military liaison last week." He stopped. "The liaison redistributed border resources based on those documents. Oguta''s militia support was reduced by a third."\nShe felt it arriving before he finished.\n"The sky court''s campaign," he said. "The next phase. When does it move."\nShe knew the answer. She had known it since Soren had told her in the corridor, six weeks ago, his voice quiet and without defense. The dry season window. Six weeks from that conversation.\nWhich was now.\n"Ekene," she said, and her voice came out wrong, too small, not equal to the size of what was happening.\n"How many people in Oguta," he said, not asking her, asking the wall behind her, asking the sky outside. "Roughly."\nShe knew from the maps. She had studied all the contested territories. "Four thousand," she said. "Approximately."\nHe nodded once. The nod of a man absorbing a number. Then he turned back into his room and she heard him sit down and begin writing, fast and urgent, the scratch of his pen already moving before the door was fully closed.\nSending the warning.\nWhether it would arrive in time was a calculation she could not make from inside this tower, in this court, four days from departure. She stood at her work table and felt the shape of what she had made through a series of choices that had each seemed manageable in isolation, each one justified, each one protecting something she had decided was worth protecting.\nFourteen people in Ughelli.\nSoren''s name, protected in every report she had filed.\nFour thousand people in Oguta who had not been part of any calculation she had made.\nShe sat down. She picked up her pen. She put it down again.\nThis was the shape of it, she understood now. Betrayal did not always announce itself loudly. Sometimes it built itself quietly out of omissions, out of choices made in narrow corridors by someone who was still telling themselves their list existed, that they were still the person who had made it. By the time you saw the shape clearly it had already become a thing you were inside of rather than something you were deciding.\nhe pressed both hands flat on the table. There were four thousand people in Oguta inside a consequence she had built one omission at a time, and she had not asked a single one of them whether they wanted to be there. She sat with that until it had the weight it deserved. It took a long time.','\n',char(10)),1200,1,1,NULL,'2026-04-30 13:57:56','2026-04-07 05:42:56','2026-04-30 13:57:56',NULL,1,13);
INSERT INTO "chapters" ("id","novel_id","chapter_number","title","content","word_count","is_premium","is_published","audio_url","published_at","created_at","updated_at","scheduled_release_at","part_number","season_id") VALUES(211,28,12,'Last Word, For Now',replace('\nThe four days moved the way difficult things moved — slowly and then all at once.\nShe packed her documentation on the first day, organized her files on the second, completed her final annotations on the third. Ekene worked in his room with the sustained focus of a man managing consequences from a distance, sending and receiving communications through the new review process, waiting the three-day delays, his pen moving at all hours. He did not speak to her about Oguta again. He did not need to. They were past the place where speaking about it would change anything.\nShe did not see Soren.\nShe had not seen him since before the corridor went quiet, since before Yetunde, since before the shape of everything had become visible. She did not know what he knew about the suspension. She did not know if Darian had spoken to him again, or whether Yetunde had, or whether he was sitting in the archive right now working through a formal text with nobody to correct his conjugation and nobody who knew what the kitchen register sounded like.\nShe told herself not knowing was cleaner.\nShe almost believed it.\n\nThe morning of departure she rose before the bells and stood at the window for the last time. The sky was doing the thing it did at this hour, the pale gold arriving slowly from the east, the towers emerging from the dark one by one. She had stopped finding it cold somewhere around the fifth week. She could not remember the exact day.\nShe finished dressing and carried her bag to the main corridor and set it with the delegation''s luggage and went back to check the room one final time.\nThe room was empty and clean and already indifferent. Rooms in this court were good at that. They held nothing, retained nothing, went back to their original state without effort.\nShe stood in the doorway for a moment. Then she turned and walked toward the stairs.\nHe was at the bottom of them.\nNot waiting, exactly. Standing at the edge of the entrance hall with the look of someone who had arrived somewhere and had not yet committed to the next step. He was in plain clothes, no ceremony. His hands were loose at his sides. He looked the way he had looked that first morning in the archive, before she had known his name, before any of it.\nThe entrance hall was not empty. Two of the junior aides were moving luggage near the main door. A sky court official she didn''t know was crossing the far end. Not a safe place. Not a place for anything.\nShe came down the last three steps and crossed toward the door and felt him fall into step beside her, not close, the correct diplomatic distance, two people moving in the same direction who had no particular reason to be doing so.\nOutside, the courtyard. The delegation''s transport was being prepared at the far end. Ekene was already there, speaking with the escort. Thirty seconds of open courtyard between the tower door and the point where she would reach the delegation and there would be nothing more.\nHe spoke first.\nIn Mmo, pitched low, the formal register, walking beside her without looking at her: I heard about the suspension. I know the shape of why.\nShe said nothing.\nDarian showed me the internal record, he said. I saw what they had built. I understood what you had been protecting.\nFour thousand people in Oguta. The warning Ekene had sent. Whether it had arrived in time she still did not know, would not know until they were back in the earth kingdom and the information reached her father''s office and even then she might not know the specific number, only the flat logistics language of the after-report.\nShe had been protecting Soren.\nShe had also been protecting something in herself, the version of herself that existed in the corridor, that was simpler and more honest than the version that wrote reports and kept lists and was her father''s eyes. She had been protecting that too. She had not examined which one she was protecting more.\nI want to ask you something, he said. The formal register, the register for serious things.\nShe waited.\nDo you know who you are. After all of this.\nShe felt the question land in the specific place where it had been heading since Ughelli, since the report she had chosen, since Ekene''s face in the doorway, since the shape of four thousand people entering her calculations too late.\nThe delegation''s transport was fifteen steps away. Ekene had seen her and was watching her approach with the patient expression of a man who had decided to let her have whatever this was.\nShe said, in Mmo, the kitchen register, her grandmother''s words wearing ordinary clothes: I know what I chose. I am still learning what I am.\nHe was quiet for two steps.\nThen he said, in the formal register, slowly, like someone setting something down in a place where it would keep: I will remember every word you taught me. Every coastal phrase. Everything your grandmother gave you. A pause. It does not die with distance.\nShe stopped at the edge of the delegation''s position.\nHe stopped with her, the correct two steps behind, the diplomatic distance, nothing readable in his posture for anyone watching. The sky court official from the entrance hall had crossed to the other side of the courtyard. The junior aides were occupied. Ekene looked briefly away.\nShe said, in Mmo, the closing phrase, the witnessing one, the one they had used since the garden: It is witnessed by what we both remember.\nHe said it back.\nThen she walked to the delegation and took her place left and behind Ekene and did not look back.\nThe transport lifted from the courtyard in the way sky court vessels lifted, smooth and final, the stone towers falling away below. She watched them go through the transport window, the bridges and the gold light and the silver-leafed garden and the archive building with its pale wood door. All of it shrinking. All of it becoming distance.\nThe war was still three hundred years old. It was also, in the valley provinces and the coastal territories and possibly in Oguta right now, very new. She was going home changed, carrying things she had not carried when she arrived, some of them worth carrying and some of them not and some of them impossible to categorize yet.\nShe faced forward.\nThe sky was everywhere, and then it wasn''t, and then the earth kingdom rose up below them, red and green and immediate, the land that had made her, coming back to claim whatever was left.\n\nEnd of Season 1 — "The Dead Language"','\n',char(10)),1141,1,1,NULL,'2026-04-07T05:44:22.941Z','2026-04-07 05:44:23','2026-04-07 05:44:23',NULL,1,13);
INSERT INTO "chapters" ("id","novel_id","chapter_number","title","content","word_count","is_premium","is_published","audio_url","published_at","created_at","updated_at","scheduled_release_at","part_number","season_id") VALUES(212,29,1,'After the Last Word',replace('\n\nShe was home for eleven days before she stopped reaching for the Mmo texts.\nNot consciously. She would be at her work table in the evening, the familiar red earth light coming through the window, her father''s documents spread in front of her, and her hand would move toward the corner of the table where she had kept the small collection of phrases she was building, the coastal vocabulary cross-referenced against the formal register. Then she would remember that those notes were in a folder she had not unpacked, in a bag in the corner of her room, and she would return her hand to the documents and continue working.\nShe was fine.\nThe earth kingdom received her the way it always received her, with the specific texture of home, the smell of red earth after rain, the round script on every signpost and document, the food that tasted like itself instead of like something she was learning. Her mother held her for a long time at the door and did not ask questions immediately, which meant she had already spoken to Adaora''s father and understood enough. Her father asked questions over dinner, measured and specific, and she answered them fully and accurately and watched him receive the information with the expression of a man recalibrating.\nShe did not tell him everything.\nShe told herself the parts she withheld were no longer operationally relevant. The mission was over. The diplomatic window had closed. Whatever she had held back during the mission had no report to be missing from now.\nShe was fine.\n\nHer body had a different position on the matter.\nShe slept badly, which she attributed to readjustment. The sky court''s day rhythms were different from the earth kingdom''s and her body was finding its way back, that was all. She woke at the sky court''s dawn hour for two weeks, the pale gold light hour that didn''t exist here, and lay in the dark of her room while the earth kingdom slept and looked at the ceiling and did not think about anything specific.\nShe ate less than usual, which her mother noted without comment by the second week, the portions on Adaora''s plate quietly increasing at each meal. She appreciated this and said nothing about it.\nShe went for walks in the morning, long ones, through the settlement''s outer paths where the farming plots began and the red earth road stretched toward the coast. She had walked this road every dry season of her childhood. It knew her. She put her feet on it and breathed and told herself this was what she needed, familiar ground, familiar sky, the right sky, close and warm and hers.\nOn the eighth day she walked past the junction for the coast road and kept going until she reached the ridge overlooking the valley and stood there looking out at the earth kingdom''s landscape, the green and red and brown of it, and felt, for the first time since the transport had lifted from the sky court courtyard, something other than the specific flatness she had been living inside.\nShe felt how far away everything was.\nNot geographically. The sky court was distance, yes, weeks of travel, a world built on a different foundation from this one. But the flatness she had been carrying was not about distance. It was about the corridor, the flickering light, the thirty minutes on Tuesdays and Thursdays that had been, for several weeks, the most honest place she had access to. That place was gone now and she had not found anything to put in its location and the absence had a shape she was only beginning to trace.\nShe stood on the ridge for a long time.\nThen she went back down.\n\nThe official briefing with her father''s senior staff happened on the twelfth day.\nShe presented her observations from the mission with the precision she had been trained for, the session summaries, the assessment of the sky court''s diplomatic posture, the failed treaty attempt, the suspension. She had organized her documentation carefully. She answered every question fully.\nAt the end, her father''s military liaison, a compact woman named Brigadier Eze who had been running the southern border assessment for three years, placed a map on the table. She pointed to a settlement in the western approach.\n"Oguta," she said. "The warning your councillor sent arrived thirty-six hours before the sky court''s campaign moved into the western corridor. We had enough time to move civilian populations in the northern quarter. Not enough for the southern."\nAdaora looked at the map.\n"How many," she said.\n"Southern quarter civilian casualties. Sixty-three confirmed." Eze''s voice was flat and professional. "Without the warning it would have been significantly higher. The northern evacuation held."\nSixty-three.\nShe looked at the map. Oguta sat at the western approach the way Ughelli sat at the coast, the way all these settlements sat, as nodes on military maps, as numbers in after-reports, as the flat logistics language of decisions made in rooms where they were not present.\nHer father was watching her.\n"The warning was late," she said.\n"Yes," Eze said.\n"But it arrived."\n"Yes."\nShe nodded once. The nod of someone absorbing a number. She recognized it as Ekene''s nod, from the delegation tower doorway, and felt the recognition like a hand pressing on a bruise.\nAfter the briefing she went to her room and sat on the edge of her sleeping mat and looked at the bag in the corner, the one she had not unpacked. After a moment she crossed to it and opened it and found the folder with the Mmo notes inside.\nShe set it on the table.\nShe did not open it. She just set it there, in the corner of the work table where it had lived in the sky court, and sat down and looked at it for a while.\nSixty-three people.\nA warning that had arrived thirty-six hours early because Ekene had moved fast, because she had finally written the one line that pointed her father''s liaison in the right direction, because the northern quarter had held.\nShe was home. She was fine.\nOutside her window the earth kingdom was loud and warm and present, the sounds of the settlement moving through its evening, cooking smells and voices and the particular music of a place that knew itself completely. She had grown up inside that music. It had made her.\nShe looked at the folder.\nThen she opened it.\nShe did not read it. She just looked at her own handwriting, the coastal phrases and their formal register equivalents, the small notes in the margins where she had worked through a conjugation or marked a word her grandmother had used but she had not been sure of until Soren confirmed it.\nThe war had a new shape now. Wider, uglier, the western corridor open, Oguta''s southern quarter in the after-reports. It was going to get worse before anyone made it better.\nShe closed the folder.\nShe was home.\nShe was not fine.\nShe was beginning, finally, to stop pretending those were the same thing.','\n',char(10)),1190,0,1,NULL,'2026-04-07T05:48:18.922Z','2026-04-07 05:48:18','2026-04-07 05:48:18',NULL,2,14);
INSERT INTO "chapters" ("id","novel_id","chapter_number","title","content","word_count","is_premium","is_published","audio_url","published_at","created_at","updated_at","scheduled_release_at","part_number","season_id") VALUES(213,29,2,'What Soren Became',replace('\n\nThe archive felt different after she left.\nHe noticed it the first Tuesday. Not her absence specifically, or not only that. The quality of the silence had changed. Before, the archive''s quiet had been the quiet of a place he had to himself, comfortable and complete. After, it was the quiet of a place missing something it had briefly held, and those two silences were nothing alike.\nHe worked through it. He was good at working through things. He had been doing it his entire life.\n\nHe went to Darian three weeks after the earth delegation departed.\nNot because Darian summoned him. He went himself, on a Thursday morning, to his brother''s offices in the eastern tower, and sat across from him at the heavy work table and said, "I want to be useful."\nDarian looked at him for a long moment. They had their mother''s eyes, both of them, and Darian used his the way their mother had used hers, as instruments of assessment rather than warmth.\n"Useful," Darian said.\n"To the court. To the campaign. In a capacity that makes actual use of what I know." Soren kept his voice even. "I have been sitting in the archive for six years. I know every contested territory by its original name, its water sources, its pre-war trade routes, its population centers. I know the linguistic history of the border regions going back four hundred years." He paused. "I am twenty years old and I have been treated as decoration. I am telling you I am not decoration."\nDarian was quiet.\n"This is about the earth girl," he said.\n"This is about me," Soren said. "She has nothing to do with it."\nIt was mostly true. He had examined that carefully before walking to his brother''s offices, the question of motivation, the question of whether this was grief disguised as ambition or something that had existed before her and had simply needed a pressure point to surface. He had concluded it was both and that both could be true simultaneously and that what mattered was what he did with it.\nDarian looked at him for a long time. Then he opened a drawer and placed a document on the table.\n"The western corridor," he said. "We need someone who can work with the intelligence teams on territorial mapping. The old records are incomplete and the field teams are making errors because of it." He watched Soren''s face. "It is not a military role. It is a research and advisory role."\n"I know," Soren said.\n"People will die based on the maps you produce."\n"I know that too."\nDarian slid the document across the table. "Father will need to approve it."\n"I know."\nHis father approved it in two days, which told Soren something about how his father had always seen him, that the moment he made himself useful in a legible way the approval was immediate, no deliberation required. He filed that away and reported to the intelligence offices on a Monday morning and began work.\n\nHe was good at it.\nBetter than he had expected, which itself told him something. The archive years had built a particular kind of mind in him, methodical and lateral, able to hold large amounts of spatial information and find the connections that weren''t immediately visible. The intelligence teams had field data and tactical knowledge. He had historical depth and linguistic precision. Together they produced maps that were more accurate than anything the court had been working from.\nHe did not think about what the maps were for. He thought about accuracy. He thought about the old Mmo place names and what they told you about water access and elevation and the seasonal movement of people. He thought about the work.\nOn some days this was enough.\nOn other days he would be working through a territorial record and a word would appear in the old script, a coastal word, a kitchen word, and he would hear it in her voice without meaning to. The particular cadence of her coastal dialect against his formal register, the way she had corrected his conjugation without making him feel corrected. He would sit with the word for a moment and then continue working.\nHe did not write to her. There was no channel that would have been appropriate or safe. The diplomatic suspension had closed the official routes and there were no unofficial ones he could use without creating exactly the kind of record that Darian would find and trace.\nHe thought about the last thing she had said in the courtyard. The witnessing phrase, ordinary and final. He had repeated it back and watched her walk to the delegation and not look at him and he had stood in the courtyard for a moment after the transport lifted, looking at the sky it had gone into, before turning back toward the tower.\nHe had not let himself stand still for long after that.\n\nSix weeks into his intelligence role, Darian came to his offices.\nHe sat down across from Soren''s work table the way Soren had sat across from his, and looked at the maps spread between them, and said, "The western campaign performed well."\nSoren looked at his maps. Oguta was on the westernmost edge, a small settlement mark, a population notation in the old script that he had included because precision required it.\n"The southern quarter took casualties," he said.\n"War has casualties," Darian said. Not unkindly. Factually.\n"I know."\n"The northern evacuation held. Brigadier Adio said the mapping accuracy made the difference in the approach corridor. Your work." Darian paused. "Father has noticed."\nSoren looked at the map for a moment longer. He thought about a number he did not know and could not find through any channel available to him, the specific number from Oguta''s southern quarter, written somewhere in an earth kingdom after-report in the flat logistics language of military record. He thought about who might have read that report. Who might have sat with that number the way he was sitting with the absence of it.\n"Good," he said.\nHe said it the way someone said something they had decided to mean, fully and without revision, because the alternative was to not mean it and he had made a choice and choices required their own maintenance.\nDarian left.\nSoren sat with the maps.\nHe was useful now. He was no longer decoration. His father had noticed. The court had a version of him that it could categorize and value and he had built that version himself, deliberately, out of what he actually knew, and it was real and it functioned and he wore it the way he had always worn ceremony, present and not entirely comfortable.\nHe pulled a fresh sheet toward him and began the next territorial record.\nIn the margin, without deciding to, he wrote one word in Mmo.\nThe kitchen register. The word for presence, for continuing, for the simple fact of still being somewhere.\nHe looked at it for a long time. Then he folded the map so the margin was hidden and pushed it to the edge of the table, just outside his line of sight. He did not throw it away. That was the part he noticed.','\n',char(10)),1213,0,1,NULL,'2026-04-30 13:59:02','2026-04-07 05:49:11','2026-04-30 13:59:02',NULL,2,14);
INSERT INTO "chapters" ("id","novel_id","chapter_number","title","content","word_count","is_premium","is_published","audio_url","published_at","created_at","updated_at","scheduled_release_at","part_number","season_id") VALUES(214,29,3,'The Diplomat''s Daughter',replace('\n\nHer father called her into his study on a Tuesday morning, which meant it was not a conversation. It was a briefing.\nShe had grown up understanding the difference. Conversations happened at the dinner table, in the kitchen, on the red earth road during evening walks. The study was where her father became the man her father also was, the one who had built a diplomatic career on the particular skill of making difficult things sound like reasonable ones. The study had maps on the walls and a heavy wooden desk and two chairs positioned across from each other that were not the same height, a detail she had noticed at twelve and never mentioned.\nShe sat in the lower chair and folded her hands and waited.\nHe opened a folder on the desk between them. "The Osa Accord," he said.\nShe knew the name. Everyone in the earth kingdom''s diplomatic offices knew it, the way you knew the name of something that had been attempted and failed so many times it had become a kind of mythology. A framework for a permanent ceasefire, proposed originally a hundred and forty years ago, revised eleven times, never ratified. The most recent version had been the basis for the failed treaty session she had watched collapse in the sky court''s great council chamber four months ago.\n"There is a new proposal," her father said. "A modified framework. The sky court has agreed to a second round of formal sessions." He paused. "Ekene will lead the delegation again."\n"All right," she said carefully.\n"He has requested you specifically."\nShe looked at her father.\n"He filed the request last week," he said. "I want to understand before I respond to it that you are aware of what returning means. The suspension was lifted as part of the new session agreement but the sky court will have conditions. You will be operating under closer observation than last time."\n"I understand."\n"Do you." He said it without particular emphasis, which meant it was the most important thing he had said so far. He looked at her across the desk with the expression she recognized as his honest face, not the diplomatic face, not the briefing face. The face of her father looking at his daughter. "Adaora. What happened in that court."\nShe held his gaze. "I did my job and I made errors in my job and I have already accounted for them in my debrief."\n"That is not what I asked."\nThe study was quiet. Outside, the settlement moved through its morning, familiar and close. She had been home for four months. She had unpacked the folder of Mmo notes and placed it on her shelf and looked at it every day and not opened it again. She had gone on her morning walks and eaten her mother''s food and attended her father''s briefings and been, by every external measure, the person she was supposed to be.\n"It was complicated," she said.\n"Complicated in a way that will affect your judgment if you return."\nShe thought about that honestly, the way the corridor had felt in the last weeks, the flickering light and the thirty minutes and the particular quality of honesty that had lived there and nowhere else. She thought about Soren''s face when she had told him about Ughelli. About the Oguta map that had come out of his intelligence work, somewhere in the sky court''s western campaign planning, a map she would never see but that had been built partly from the same archive years that had taught him Mmo.\nComplicated was not large enough a word. She knew that. She was using it because her father''s study was not the corridor and she did not have a language here for the full shape of it.\n"It will not affect my judgment," she said.\nHe looked at her for a long moment.\n"Ekene believes you are the best person available for this assignment," he said. "He was not unaffected by the suspension. It cost him. He is requesting you anyway." He closed the folder. "That tells me something about what he saw in you that I should take seriously."\nShe thought about Ekene in the delegation tower doorway. His face when she had said yes, there is a basis for this. The way he had not said the name. The way he had sat down and immediately begun writing the warning, fast and urgent, not waiting, not assigning blame, just moving to limit what could still be limited.\nShe had not spoken to him since their return. She had written him a formal note of acknowledgment after the debrief, careful and correct. He had not responded, which was its own kind of response.\n"When do they need an answer," she said.\n"Friday."\nShe nodded. Then she said, "Can I ask you something."\n"Yes."\n"Do you think it will work this time. The accord."\nHer father was quiet for a moment in the specific way of someone choosing between the answer they had and the answer they were willing to give. "I think," he said slowly, "that the war has reached a cost that is making both sides look for a door. I think the Osa Accord exists because someone, a hundred and forty years ago, understood that this was always going to be necessary. I think the door is closer now than it has been." He paused. "Whether anyone walks through it depends on the people in the room."\nShe looked at the maps on his walls. The contested territories, the valley provinces, the coastal settlements, Ughelli and Oguta and all the other names that appeared as nodes and numbers and supply route markers. Three hundred years of a war that had been necessary to nobody born into it and inherited by everyone.\nShe thought about what Soren had said in the courtyard, the formal register, slow and deliberate: it does not die with distance.\nHe had meant the language. She had understood at the time that he meant only the language.\nShe was less sure now what he had meant.\n"Tell Ekene yes," she said.\nHer father looked at her. Not the briefing face. The other one.\n"Adaora," he said. "Whatever is complicated. You resolve it or you set it down before you walk back into that court. Those are the only two options that keep you safe."\nShe met his eyes. "I know, Baba."\nHe held her gaze for a moment longer. Then he nodded and closed the folder and the briefing was over and he was her father again, standing up from behind the desk, asking if she had eaten this morning in the voice that was only ever just her father.\nShe said yes and walked out of the study and down the hall and out through the front door into the red earth morning.\nShe stood on the path outside the house and looked at the sky.\nIt was the wrong color. It was always the wrong color here, too close, too warm, not the pale cold gold of the sky court''s permanent morning light. She had never minded that before. She had grown up under this sky. It was hers.\nShe breathed it in and told herself it was enough and began walking toward the road.\nShe had told her father the truth and she had not told him all of it and the space between those two things had a shape she recognized. She was going back to the sky court to find out whether that shape would hold or break. She was not sure which outcome she was more afraid of.','\n',char(10)),1277,0,1,NULL,'2026-04-30 14:00:45','2026-04-07 05:49:58','2026-04-30 14:00:45',NULL,2,14);
INSERT INTO "chapters" ("id","novel_id","chapter_number","title","content","word_count","is_premium","is_published","audio_url","published_at","created_at","updated_at","scheduled_release_at","part_number","season_id") VALUES(215,29,4,'Same Room, Different People',replace('\n\nThe sky court received her the way it received all returning things.\nWithout acknowledgment.\nThe clouds moved aside, the escort met them at the landing point, the pale towers rose in the cold gold light exactly as they had risen the first time. She had prepared herself for the familiarity of it, the specific texture of a place she had left changed and was now re-entering, but preparation and arrival were different things and she felt the difference in her chest as the transport settled and the doors opened and the sky court''s air came in, cool and metallic and entirely itself.\nEkene had not spoken to her directly since the departure four months ago. On the transport he had been correct and professional, reviewing documents, conducting his preparations, including her in the working sessions with the precise neutrality of a man who had made a decision about how to carry something and was carrying it. She had matched his register exactly. They had rebuilt a functional working relationship out of deliberate mutual silence about everything underneath it, and it held, and she was grateful for it and sorry for it simultaneously.\nThe delegation quarters were in the same tower. Different rooms, she noted. Someone in the court''s logistics had made that adjustment. She filed it and unpacked and went to the window.\nThe archive building was visible from this side. The pale wood door. The garden path beside it, the silver-leafed plants in their rows, the stone bench at the garden''s edge where he had sat that second morning with an unopened book and the look of someone who owned the sky and was tired of it.\nShe looked at the archive building for ten seconds. Then she turned away and opened her work folder.\n\nThe first formal session was the following morning.\nShe took her position left and behind Ekene and looked at the room and its arrangement, the sky court''s councillors across the table, Adio at the center, two others she recognized from the previous mission. New faces at the edges. New documents. The modified Osa Accord framework in a fresh binding at each seat.\nShe was reviewing the attendee positions against her briefing notes when the side door opened.\nShe knew before she looked up. Something shifted in the room''s air, or in her awareness of the room''s air, and she looked up because not looking would have been its own kind of telling.\nHe was not the same.\nThat was the first thing, arriving before she had time to prepare for it. He had been plain before, deliberately plain, the youngest prince wearing ceremony like borrowed clothes. What crossed to the table''s edge and took a seat at the outer advisory position was not plain. Not decorated either. Something in between that she did not have an immediate word for. He moved differently. The archive stillness was still there but it was sitting inside something else now, something that had weight and direction. He looked like someone who had decided something and was living inside that decision.\nHe sat down and opened the document in front of him and did not look at her.\nShe returned to her briefing notes.\nHer handwriting was even. Her hands were steady. She was her father''s eyes.\n\nThe session ran two hours.\nShe watched him work from her peripheral vision, which she was not doing deliberately and could not entirely stop. He was in an advisory capacity, not speaking unless addressed, passing notes to Adio twice on points of territorial record. When he spoke, briefly, on a boundary notation in the accord''s third section, his voice was the same and also not the same, carrying something it had not carried before. Confidence was not the right word. Certainty was closer. The certainty of someone who had found the thing they were for and was using it.\nShe wrote her session notes and did not look at him directly and the three hundred years of the war sat in the room with all of them, in the documents and the careful language of the accord and the faces of the people across the table from each other who were trying, again, to find a door.\nWhen the session ended she gathered her materials and followed Ekene toward the corridor.\n"Adaora."\nShe stopped.\nNot because he had said her name. Because of the register. Not the formal Mmo register, not the kitchen register. Just her name, in earth language, said by someone who knew exactly what they were doing by saying it.\nEkene was three steps ahead and had not paused. The other delegates were filing out around them. She turned.\nHe was standing at the correct diplomatic distance. His expression was the careful neutral of the sky court, readable only if you had spent weeks learning to read it. His document folder was under his arm. Anyone watching would see two diplomatic representatives completing a standard post-session acknowledgment.\nShe waited.\nHe said, in a voice low enough that it reached only her, "You look well."\nShe looked at him. The person standing across from her had his face and his stillness and the particular quality of attention she had spent weeks in a narrow corridor learning to read. He also had something else now, something she was still identifying, sitting in the edges of his posture and his certainty.\n"You''ve changed," she said.\n"Yes."\n"The intelligence work."\nSomething moved through his expression. Not surprise that she knew. Something more considered. "Darian told you."\n"The briefing documents mention a new territorial mapping advisor. I know your archive work. It was not difficult to place."\nHe was quiet for a moment. Around them the room was emptying, the last delegates moving through the door. She had perhaps thirty seconds.\n"Have you decided who you are," she said. His own question, from the courtyard, the last morning. Do you know who you are after all of this.\nHe looked at her directly. The careful neutral was still there but underneath it, in the specific quality of his stillness, was the answer she recognized as the one he meant completely.\n"I am still working on it," he said. "Same as you."\nShe held his gaze for one more second.\nThen she turned and walked through the door and caught up to Ekene in the corridor without adjusting her pace and took her position left and behind him and did not look back.\nIn the corridor, Ekene said nothing. He was very good at that.\nShe matched his silence and carried hers alongside it and walked back toward the delegation tower through the cold gold morning of the sky court, the towers rising on all sides, the bridges arching overhead, the familiar magnificent hostility of a place that did not want her and that she knew, now, better than she had wanted to.\nShe was back.\nHe was different.\nShe was different.\nThe three hundred years had not moved at all.\nSomewhere in the space between those things was either the beginning of something or the end of it and she did not know yet which one and would not know until they were further inside it than she was now, standing in a corridor after a session, her hands steady and her notes complete and her chest doing something she recognized and was not going to name.\nNot yet.','\n',char(10)),1235,1,1,NULL,'2026-04-07 05:51:31','2026-04-07 05:50:49','2026-04-07 05:51:31',NULL,2,14);
INSERT INTO "chapters" ("id","novel_id","chapter_number","title","content","word_count","is_premium","is_published","audio_url","published_at","created_at","updated_at","scheduled_release_at","part_number","season_id") VALUES(216,29,5,'What the Language Costs Now',replace('\n\nShe found the maintenance corridor on her fourth day back.\nNot deliberately. She had been mapping the tower layout for her security assessment, the standard first-week task she had not completed properly last time because she had been seventeen and new and had not yet understood what kind of place she was inside. She was not seventeen anymore. She completed the assessment properly, room by room, passage by passage, and when she turned the corner behind the archive building the corridor door was there, the same as she had left it, the same single crystal strip flickering in the same irregular way.\nShe stood at the entrance for a moment.\nThen she went in and sat down in her old position and waited.\nShe did not know if he would come. She had not sent word, had no channel to send word through. She was operating on the logic of pattern, that he knew this corridor the way she knew it, that it had lived in him through the four months the same way it had lived in her.\nAfter twelve minutes she heard the other entrance.\nHe came in and sat across from her and they looked at each other in the flickering light and the corridor held them the way it had always held them, that specific and fragile shelter.\n"I didn''t know if you''d come," she said.\n"I didn''t know either," he said. "Until I was here."\nA silence. Not the comfortable working silence of the archive hours. Something with more texture.\nShe opened the question directly because she had not come here to move around it. "The western corridor maps. The Oguta campaign. Was that your work."\nHe was quiet for a moment. "The territorial mapping, yes. The campaign application was Adio''s."\n"The maps made the corridor approach accurate."\n"That was the purpose of the maps."\n"Sixty-three people in Oguta''s southern quarter."\nHe held her gaze. "I know the number."\n"How long have you known it."\n"Six weeks after you left. Darian showed me the after-report." He said it without deflection, without the layer of careful distance she might have expected. "I sat with it. I am still sitting with it."\nShe looked at him. He looked back. The corridor light flickered between them.\nThis was the thing she had carried on the transport back, in the briefing documents, in the four months of morning walks on the red earth road. Not his absence. Not even the number from Oguta specifically. The thing she had carried was this: that they had both been changed by the same sequence of events and the changes had not moved them toward each other. They had moved them into versions of themselves that were harder and more useful and not entirely recognizable and she did not know what that meant for the corridor, for the language, for the thirty minutes on Tuesdays and Thursdays that had been, briefly, the most honest place she had access to.\nShe said, in Mmo, the formal register, because the formal register was for serious things: something is different.\nHe said, also formal: yes.\nTell me where you feel it.\nHe was quiet for a moment. When he spoke it was slowly, choosing each word with the precision of someone working in a language they had built from fragments and archive years and a dead grandmother''s kitchen phrases.\nI feel it, he said, in the place where I used to come here without calculating whether I should. I calculated today. I calculated for four days before today. A pause. That is new.\nShe understood that exactly. She said: I feel it in the language itself. It used to cost nothing to begin. Today I sat at the entrance for three minutes before I came in.\nBecause of Oguta.\nBecause of everything after the corridor, she said. Oguta is part of it. The report I chose not to write is part of it. The version of you that made the maps is part of it. She looked at her hands. We are not the same people who made the rules in the garden.\nNo, he said.\nI don''t know if the rules still hold.\nHe was still for a long moment. The thinking stillness, the one she had learned to read, the one that meant he was actually inside the question rather than performing his way around it.\nThe rules were made, he said finally, by two people who needed to protect something new and fragile. What we are now is not new and not fragile. He paused. I think the rules held as long as they needed to. I think what we need now is different.\n"What do we need now," she said, in earth language, because some things needed to be said in a language that was not ceremonial, that had no formal register to hide inside.\nHe looked at her. The careful neutral was gone. She was looking at the unguarded face, the one from the first morning in the archive, the one that appeared only when the door was shut and the court was on the other side of a wall.\n"Honesty," he said. "Without the rules as a boundary. Without the corridor as the only place it''s allowed to live."\nShe felt the weight of that. What he was describing was not the maintenance corridor on Tuesdays and Thursdays. It was something that would have to exist inside the actual shape of their lives, the war and the court and the accord sessions and Darian and Yetunde and sixty-three people in Oguta and the next thing after Oguta, whatever that was going to be.\n"That is more dangerous than the rules," she said.\n"I know."\n"The rules gave us a container. Without them we are just two people on opposite sides of a three-hundred-year war who keep finding each other in corridors."\nHe almost smiled. Not quite. The almost of it was enough. "Is that not what we have always been."\nShe looked at him. In Mmo, the kitchen register, ordinary and unprotected: I missed the language.\nA pause. Then, also kitchen register, the words wearing their simplest clothes: I missed the person who taught it to me.\nThe corridor held that for a moment, the flickering light steady for once, the archive quiet on the other side of the wall.\nShe breathed through what it cost to be in this specific place with this specific person and know that the corridor was not enough anymore and that what was outside the corridor was not safe and that those two things were both completely true and could not be resolved by any rule she was capable of making.\n"The accord sessions," she said, returning to earth language. "We work. We do what we came here to do."\n"Yes."\n"And outside the sessions."\n"Outside the sessions," he said carefully, "we figure out who we are now. Together. Honestly." He paused. "No rules this time. Just truth."\nShe stood up.\nIn Mmo, the formal register, the sealing phrase from the garden: it is witnessed by what we both remember.\nHe said it back. Then added, in the kitchen register, quiet and direct: and by what we have not yet said.\nShe left the corridor and walked back through the courtyard in the cold gold light and felt the specific weight of standing at the beginning of something that had no safe terms and no container and no list that would make it manageable.\nShe left the corridor carrying something that had no container now, no rules, no thirty-minute boundary, and the cold gold air of the sky court pressed in on all sides and she did not know yet whether what she had just agreed to was honesty or just danger with the door taken off its hinges.','\n',char(10)),1305,1,1,NULL,'2026-04-30 14:01:55','2026-04-07 05:52:34','2026-04-30 14:01:55',NULL,2,14);
INSERT INTO "chapters" ("id","novel_id","chapter_number","title","content","word_count","is_premium","is_published","audio_url","published_at","created_at","updated_at","scheduled_release_at","part_number","season_id") VALUES(217,29,6,'The Other Woman / The Other Soldier',replace('\n\nHis name was Chike and he was exactly what the mission needed.\nAdaora understood this within the first hour of his arrival. He was her father''s new liaison, sent to support the delegation''s documentation work, twenty-two years old, earth kingdom military intelligence, with the kind of competence that announced itself quietly and the kind of face that was easy to trust. He spoke four languages. He had been in three diplomatic postings before this one. He sat down at the work table on his first morning and began contributing immediately, no adjustment period, no friction.\nEkene approved of him visibly, which for Ekene meant a slight relaxation around the eyes and the absence of the particular silence he used when something concerned him.\nAdaora approved of him too. That was the uncomplicated part.\nBy the end of the first week Chike had established a working rhythm with the delegation that made everything run more smoothly, and in the evenings when the session documents were filed and the tower went quiet he would bring two cups of the earth-spiced tea he had packed from home and set one on her table without asking and they would work in a companionable silence that required nothing from her.\nIt was the easiest thing in the sky court.\nOn the eighth evening he said, without looking up from his documents, "You know this place already. You move through it differently from how I move through it."\n"I was here before," she said. "Four months."\n"It shows." He glanced up. "It also shows that it cost you something."\nShe looked at him. He was not asking. He was observing, the way intelligence training built observers, but there was something underneath the observation that was personal and careful and not entirely professional.\n"Most things worth doing cost something," she said.\nHe smiled. It was a straightforward smile, nothing hidden in it. "Fair," he said, and returned to his documents.\nShe returned to hers.\nShe did not examine why the straightforwardness of the smile sat in her chest with the specific weight of a thing that was asking her a question.\n\nHer name was Isadora and she was a sky court scholar attached to the accord sessions as a linguistic consultant.\nSoren became aware of her the way he became aware of most things in this court, gradually and then completely. She appeared at the second session''s advisory table, three seats from him, with the focused stillness of someone genuinely engaged in the work rather than performing engagement. After the session she asked him a precise question about a boundary notation in the accord''s fifth section, something about the original Mmo place name and whether it implied a different territorial reading than the current sky script version.\nHe answered her. She pushed back intelligently. They worked through it standing at the edge of the council chamber for twenty minutes after everyone else had left, and when they reached a conclusion she wrote it in her notes with the satisfaction of someone who had been trying to solve something and had solved it.\n"I have been arguing that point for three weeks," she said. "Nobody in the court''s linguistics office would engage with it seriously."\n"It is a serious point," he said.\nShe looked at him with an expression that was direct and uncalculating. "You are better at this than your advisory position suggests."\n"I know," he said.\nShe almost smiled. "Not modest."\n"Accurate," he said, and something in the exchange made her actually smile, open and genuine, and he recognized in that smile the specific quality of someone who was not performing anything, who did not have a corridor and a dead language and a three-hundred-year war running underneath every interaction.\nIt was, he realized, genuinely restful.\nHe thought about that on the walk back to his offices. The restfulness of someone uncomplicated. Someone whose loyalty was clear and whose intentions were surface-level and who smiled without anything hidden in it.\nHe sat at his work table and looked at the territorial maps.\nHe thought about Adaora in the corridor five days ago. We figure out who we are now. Together. Honestly. Her face when she had said it, the unguarded one, the one that cost her something to show. The formal register and then the kitchen register and then the sealing phrase and the addition he had made to it, by what we have not yet said, which had been true and which he had said because they were past the point of saving things.\nHe thought about Isadora''s uncomplicated smile.\nThe theme of the thing he was inside arrived, fully formed, and he sat with it.\n\nChike asked her to walk with him on the eleventh evening.\nNot the garden, he said, he had heard the courtyard paths were better in the evening light, would she show him. She looked at him across the work table and saw the question underneath the question and felt its specific weight.\nHe was good. He was uncomplicated. He was on the right side of a three-hundred-year war and he was looking at her with an expression that had nothing hidden in it and required nothing from her except a yes.\nShe said, "I don''t think that''s a good idea."\nHe held her gaze for a moment. He was not a man who needed things explained twice. "All right," he said, without adjustment, without pressure, and returned to his documents.\nShe looked at the side of his face for a moment. The straightforwardness of him. The ease. She thought about what it would mean to choose ease, to be someone whose most honest place was not a narrow corridor with a flickering light but an open table with a cup of tea and a person who wanted nothing complicated from her.\nShe thought about who she would have to not be to have that.\nShe returned to her documents.\nAcross the courtyard, she did not know, Soren was sitting at his work table looking at territorial maps and thinking about a smile that required nothing from him, and arriving at his own version of the same question.\nThe question the theme had always been building toward.\nNot who do you love. That part had been decided, quietly and without announcement, somewhere in a dead language between a coastal dialect and a formal register, in a corridor that smelled like stone and old water.\nThe question was what are you willing to stop being in order to have it.\nChike said goodnight and left. His footsteps were even and unhurried down the corridor.\nShe sat at the table after he left and felt the specific shape of the road not taken, the uncomplicated life that had stood in her room for eleven days with a cup of tea and a straightforward smile and asked nothing of her.\nShe had said no to it.\nShe understood, sitting alone in the sky court tower with the cold gold dark outside her window, that she had said no to it completely, not as a temporary position but as a permanent one, and that the permanent no had a cost she was only beginning to calculate.\nShe opened the Mmo folder.\nShe began working on a conjugation she had not been able to resolve since she was eleven years old, sitting beside her grandmother in a kitchen that smelled like pepper soup, learning a language she had not known she was going to need.','\n',char(10)),1250,1,1,NULL,'2026-04-07 13:17:35','2026-04-07 05:53:19','2026-04-07 13:17:35',NULL,2,14);
INSERT INTO "chapters" ("id","novel_id","chapter_number","title","content","word_count","is_premium","is_published","audio_url","published_at","created_at","updated_at","scheduled_release_at","part_number","season_id") VALUES(218,29,7,'Intelligence',replace('\n\nShe found it in the accord''s supplementary documents.\nNot hidden exactly. Filed in the territorial reference section, cross-indexed under boundary notations, the kind of placement that was either careless or deliberate and she could not tell which from the document alone. It was a single page, no header, no attribution, written in the old Mmo formal script that only two people in this court could read fluently.\nShe read it twice. Then she sat very still for a long time.\n\nThe document was a complete operational outline.\nNot a summary. Not a fragment. A full strategic map of the sky court''s next campaign phase, the one that would follow the accord sessions regardless of their outcome, the contingency the court had been building while the diplomatic process ran its course. It covered three territories, four settlement corridors, the specific dry season timing, the supply chain vulnerabilities the sky court intended to exploit.\nIf the earth kingdom''s military had this document, they could pre-position. Not just evacuate civilians. Pre-position. Intercept. Change the outcome of a campaign phase that would otherwise move through the valley provinces the way the western corridor had moved through Oguta, except three times the scale.\nIf the sky court discovered the earth delegation had this document, the accord sessions ended immediately. The diplomatic suspension became permanent. The war moved from its current shape into something uglier and faster with no door left in it.\nShe held both of those things and looked at the page.\nThe Mmo script was Soren''s. She knew his handwriting from the archive hours, the formal register''s angular precision, the way he formed the third-person plural, the specific shape of his coastal corrections in the margins where she had taught him her grandmother''s vocabulary. This was his hand, absolutely, no question.\nWhat she did not know was whether he had put it in the supplementary file for her to find.\n\nShe requested a working session with him the following morning, formal channels, properly filed, a territorial notation query from the earth delegation''s documentation team. It was the correct procedure. Chike raised an eyebrow slightly when she submitted it and said nothing, which was its own kind of statement.\nSoren arrived at the small working room the session administrators assigned, alone, on time. He sat across from her and placed his document folder on the table and looked at her with the expression she now knew as his actual face, the unguarded one, the one that appeared when the court was on the other side of a door.\nShe placed the single page on the table between them.\nHe looked at it.\nShe watched his face with everything she had. She was her father''s eyes. She had spent a year learning to read this specific face. She needed to know, before she decided anything else, whether this was deliberate or whether she had found something she was not supposed to find and the situation was different from what she was hoping it was.\nHis face told her nothing definitive.\nThat was, itself, information.\n"Soren," she said quietly.\nHe looked up from the page.\n"Did you put this where I would find it."\nA silence. The working room was small and without windows and the door was closed and they were two people who had agreed to honesty and she needed him to be that now, precisely and completely.\n"I filed it in the supplementary section," he said carefully, "because it belonged there by subject matter."\n"That is not an answer."\nHe was quiet.\n"I need to know," she said. "Not for the report. Not for my father''s office. For me. Before I decide what to do with this I need to know whether you put it there for me or whether I found something I was not meant to find, because those are two completely different situations and I cannot navigate either one correctly without knowing which I am inside."\nHe looked at the page for a long moment.\nThen he said, in Mmo, the kitchen register, the register for ordinary truth: I knew you would be reviewing the supplementary documents. I knew you were the only person in this court who could read that script. I told myself I filed it where it belonged.\n"And."\nAnd I have known about this campaign phase for six weeks. I have been sitting with it the way I sat with Ominala. He paused. I told myself I had not decided anything.\nShe felt the shape of that arrive.\n"You decided," she said.\n"I filed a document where it belonged," he said, in earth language now, plain and direct. "What you do with it is not my decision. I have no control over what a diplomat''s aide finds in the course of her documentation work."\nShe looked at him.\nHe had built her a door and left it open and given himself sufficient distance from the opening of it that he could survive the discovery. It was careful and it was intelligent and it was also the most honest thing he could have done, giving her the information while keeping the choice entirely hers. The risk lived on her side of the table. He had arranged it that way deliberately.\nShe thought about the Oguta maps. Sixty-three people in the southern quarter. The cartography that had made the corridor approach accurate. The choice he had made after she left, to become useful, to become the person the court needed him to be.\nShe thought about what it must have cost him to build those maps and then file this page.\n"If I use this," she said, "and the court traces it back to the supplementary file, they trace it to you."\n"The file has multiple contributors. The attribution is not direct."\n"Darian is thorough."\n"Yes." He held her gaze. "I know that."\nShe looked at the page between them. The full operational outline. Three territories. Four settlement corridors. The valley provinces at the scale of three Ogutas. The information that could pre-position an earth kingdom response and change what the campaign phase looked like from the ground.\nShe thought about significant civilian impact, the flat logistics language of after-reports, written in the same precise hand as the page in front of her.\nShe thought about who she was.\nNot the question she had been carrying since the first mission. She knew the answer to that one now, or the beginning of it. The question she was sitting with was different. It was whether the person she was becoming was one she could look at clearly, whether the choices accumulating in her file — the reports she had shaped, the information she had held, the information she was now holding again — whether those choices added up to something she could name honestly.\nShe picked up the page.\n"I need to think," she said.\n"I know."\n"This cannot leave this room in any form until I have decided."\n"Agreed."\nShe looked at him one more time. He was watching her with the full weight of his attention, the stillness that meant he was completely inside the moment. She thought about what it had cost him to get here, to this small windowless room, to this page on this table, to the version of himself that had filed a document where it belonged and then sat across from her and told the truth about it.\nIn Mmo, the formal register: this is witnessed.\nHe said it back, quietly.\nShe folded the page and placed it inside her document folder and stood up and left the room.\nIn the corridor she walked at her usual pace, her hands steady, her face neutral, her folder under her arm. She passed two sky court officials and Councillor Adio''s secretary and a cleaning staff member polishing the bridge railing in the cold gold morning.\nShe was the diplomat''s daughter. She was her father''s eyes. She was seventeen months inside a three-hundred-year war that had been making people into different versions of themselves long before she arrived.\nShe was also the person who had come back to this court when she should have said no, who had sat in a corridor and agreed to honesty without rules, who was now carrying a folded page that could change the shape of a campaign phase or destroy the last door left in this conflict depending entirely on what she decided next.\nShe walked back toward the delegation tower.\nShe walked back to the delegation tower with the folded page against her ribs and thought about the northern quarter of Oguta, the one that had held. She thought about the valley provinces. She thought about whether the version of herself who had sent the last transmission would recognize what she was considering doing with this one. She thought she would. That was the part that was not simple.','\n',char(10)),1481,1,1,NULL,'2026-04-30 14:02:51','2026-04-07 05:54:16','2026-04-30 14:02:51',NULL,2,14);
INSERT INTO "chapters" ("id","novel_id","chapter_number","title","content","word_count","is_premium","is_published","audio_url","published_at","created_at","updated_at","scheduled_release_at","part_number","season_id") VALUES(219,29,8,'Who He Is at Home',replace('\n\nThe sky king held a family gathering on the third Sunday of every month.\nShe knew this from the briefing documents, listed under court social calendar, flagged as internally significant and diplomatically irrelevant. She had read it and filed it and not thought about it again until the Sunday she came back from her morning walk through the eastern courtyard and found herself at the wrong end of the bridge at the wrong time.\nThey were in the garden.\nNot a formal event. That was the first thing that caught her. No ceremony clothes, no gold wire, no performance. The sky king was seated on the low bench in plain robes, older up close than in the formal portraits, with the particular stillness of a man who had been powerful for a long time and had settled into it. Beside him a woman she placed as the queen''s sister, two older men who carried the family resemblance in their height and their cheekbones. A younger woman, perhaps fifteen, sitting cross-legged on the garden stones with a text open in her lap.\nDarian, standing at the garden''s edge, speaking to one of the older men with the focused efficiency he brought to everything.\nAnd Soren, crouched beside the fifteen-year-old, looking at whatever was in her text, saying something that made her argue back immediately, both of them going back and forth over the page with the ease of people who had been arguing about texts together for years.\nAdaora stopped at the bridge''s edge.\nShe was far enough that she was not intruding. Close enough to see clearly. She should turn around. She was already turning around when the fifteen-year-old looked up from the text, directly across the courtyard, and said something to Soren, and he looked up too.\nHe saw her.\nShe did not move. Neither did he. The fifteen-year-old looked between them with the frank assessment of a teenager who missed nothing, and then returned pointedly to her text.\nThe sky king said something. Soren answered without looking away from Adaora, brief and even, and then stood up and crossed the garden toward the bridge.\nShe waited.\nHe reached the bridge''s edge and stopped at the correct diplomatic distance, the family gathering visible behind him, Darian already watching from his position at the garden''s edge.\n"My sister," he said quietly, meaning the fifteen-year-old. "Lara. She is working through a pre-war trade text and refusing to accept that her translation of the third section is incorrect."\n"Is it incorrect."\n"Significantly." A pause. "She is also correct that I am being difficult about it."\nShe almost smiled. "How long has she been studying the old texts."\n"Two years. She found the same damaged document I found at fourteen and decided it was a puzzle." Something moved through his expression, the unguarded face, the one that appeared only when the court was on the other side of something. "I did not know she had found it until six months ago. She had been working through it alone."\nAdaora looked at Lara, still bent over her text, chin set with the specific stubbornness of someone who was going to solve the thing even if it took all morning.\n"She is like you," she said.\n"Worse," he said. "She is more stubborn and more precise and she will be better at it than I am within two years." He said it without any edge, just fact, and the pride in it was so unperformed that it landed differently than anything she had heard from him in a formal context.\nBehind him the sky king said something to the queen''s sister and they both laughed, low and private. The older men had settled into conversation. Darian was still watching, his assessment face in full operation, but he had not moved.\nShe looked at the sky king. Up close, without the formal portrait distance, without the war council chamber, he was a man in his sixties in plain robes in a garden with his family on a Sunday morning. He had ordered Ughelli. He had described the diplomatic mission as theatre. He was also, right now, the man whose laugh had just been low and private and directed at someone he loved.\nShe understood, looking at him, something she had known abstractly and now knew in her body. That the people who made the decisions that appeared in after-reports were not the decisions and nothing else. They were complete people with Sunday mornings and daughters who translated old texts incorrectly and stubbornly, and that made nothing better and nothing simpler but it made it true.\n"Your father," she said quietly. "Does he know what you filed."\n"No."\n"Does Darian."\n"Not yet." He paused. "Darian suspects I am doing something. He is watching the shape of my behavior the way he always watches. He has not found a specific thing to point at."\n"He will."\n"Probably." He looked at her directly. "I know that."\nShe looked back at the family in the garden. Lara had given up on the text temporarily and was now pulling leaves off the silver-leafed plant nearest her bench, methodically, which was presumably not allowed and which nobody was stopping her from doing.\n"What was it like," she said. "Growing up here."\nHe was quiet for a moment, the thinking stillness. "Quiet," he said finally. "In the way that large loud things are quiet at their center. Everything moved around the court and the war and my father and Darian and I was in the archive. Nobody disturbed the archive." A pause. "Lara was young enough when I found the texts that I could give her something I did not have. Someone to work through it with."\nShe thought about her grandmother''s kitchen. The pepper soup smell and the coastal phrases, the specific texture of being given something by someone who understood it was worth giving.\n"You did not have anyone," she said.\n"I had the texts."\n"That is not the same thing."\nHe looked at her. "No," he said. "It is not."\nThe Sunday morning held them for a moment, the cold gold light on the garden stones, the family behind him, the three-hundred-year war present everywhere and invisible in the way large things were invisible when you were standing inside them.\nDarian moved.\nNot toward them, just a repositioning, the practiced casual drift of someone closing a distance without appearing to. Soren registered it without looking.\n"You should go," he said.\n"I know."\nShe did not go immediately. She looked at the garden one more time. Lara had abandoned the silver leaves and picked up her text again, arguing already with whatever she had found on the new page, her face carrying the specific focus of someone who did not know yet that the thing she was building in the archive would one day have to live inside the world outside it.\nShe looked like her brother.\nAdaora looked at Soren. At his face in the Sunday morning light, without ceremony, without the careful neutral, without the archive and the corridor and the intelligence work and the Oguta maps and all the things they had both become. Just his face, which was still deciding what it was going to be, which she had watched deciding for almost a year now.\nIn Mmo, the kitchen register, the simplest phrase: I see you.\nNot the ceremonial seeing. The ordinary one. The one her grandmother had used in the morning, coming into the kitchen, greeting the day and the person in it.\nHe received it like something he had not expected to be given.\nThen, quietly, in the same register: I see you too.\nShe turned and walked back across the bridge.\nBehind her, Darian reached his brother and said something low and direct. She did not hear the words. She did not look back.\nShe walked through the cold gold morning with the weight of the folded page in her document folder and the weight of a Sunday morning in a garden and the weight of who he was at home, which was not simpler than who he was in a corridor but was more complete, and the more complete version of him was harder to hold at the necessary distance than the incomplete one had been.\nShe walked back through the cold gold morning carrying the more complete version of him, which was harder than the incomplete one had been, and the document was still in her folder, and she had made the Oguta decision alone. She was not going to make this one alone. She did not know yet what that was going to cost both of them.','\n',char(10)),1447,1,1,NULL,'2026-04-30 14:05:57','2026-04-07 05:55:03','2026-04-30 14:05:57',NULL,2,14);
INSERT INTO "chapters" ("id","novel_id","chapter_number","title","content","word_count","is_premium","is_published","audio_url","published_at","created_at","updated_at","scheduled_release_at","part_number","season_id") VALUES(220,29,9,'The Version She Doesn''t Recognize',replace('\n\nShe sent it on a Wednesday.\nNot impulsively. She had carried the folded page for eleven days, through three accord sessions and two corridor meetings and a Sunday morning in a garden that had made everything harder. She had thought through every version of the decision with the precision her father had trained into her, every outcome mapped, every consequence followed to its end.\nThe valley provinces. Three territories. Four settlement corridors. The campaign phase that was coming regardless of the accord''s outcome, that was being prepared in rooms she would never enter, by people who had already decided the diplomatic window was theatre.\nSixty-three people in Oguta''s southern quarter.\nShe encoded the document using the delegation''s secure transmission protocol, attached it to her weekly intelligence summary, and marked it for her father''s military liaison with a single line of annotation: act on this before the dry season window.\nShe submitted it through the review channel, three day delay, standard procedure.\nThen she sat at her table and looked at the wall.\nShe had not told Soren.\nShe had thought about telling him. In the corridor on Tuesday she had almost said it, the decision she had made, the thing she was about to do, and she had stopped because telling him was asking him to absorb a consequence he had not agreed to absorb when he filed the document where it belonged. He had given her the choice. She had made it. That was the arrangement.\nShe told herself that.\nShe looked at the wall for a long time.\n\nDarian came to Soren''s offices on Thursday morning.\nHe arrived without announcement, which was standard for Darian, and sat across the work table with the expression that meant he had finished building something and was ready to show it. He placed a single document on the table.\nA log. Corridor access records, maintenance passage, spanning two periods. The first period corresponded exactly to the previous mission''s Tuesday and Thursday rhythm. The second period, three entries, corresponded to the current mission.\nSoren looked at it.\n"The earth delegation''s aide," Darian said. "Adaora. Her access pattern in the archive garden matches both periods."\nSoren said nothing.\n"The supplementary file," Darian said. "The operational outline in the old script. I had it reviewed by the court''s linguistics office. They cannot read the script but they identified it as pre-war Mmo. The only person in this court with fluency in that register is you." He paused. "The only person in the earth delegation with any Mmo knowledge is her."\nThe offices were quiet. Outside, the sky court moved through its morning.\n"I am not here as an accusation," Darian said. His voice was the voice of someone who had decided how to handle a situation and was executing the decision. "I am here because the accord sessions have four weeks remaining and Father has been informed there may be an intelligence exposure. He wants it managed before the peace talks."\n"Managed," Soren said.\n"The earth delegation''s aide is the exposure point. If she is removed from the delegation on procedural grounds before the information she carries can be confirmed and acted on, the damage is contained." He looked at Soren steadily. "I need to know if that is the right move."\nSoren understood what Darian was asking. Not whether she had the document. He already knew she had it. He was asking whether Soren would confirm the exposure, give Darian the specific shape of it, hand him the information he needed to build the procedural case that would remove her from the court before the transmission reached her father''s liaison.\nThe transmission she had probably already sent.\nHe looked at the access log on the table.\nHe thought about what she had said in the working room. If I use this and the court traces it back, they trace it to you. And he had said he knew that. He had said it knowing that the tracing would arrive here, at this table, with Darian''s face across it.\nHe had told himself he was prepared for it.\nHe looked at the access log and felt the distance between prepared and actual.\n"The aide approached me in the first mission," he said. His voice came out even. "She had identified my archive work and was attempting to build an intelligence relationship. I managed the interaction to limit exposure." He paused. "The supplementary file was an error in my document organization. I have corrected it."\nDarian looked at him for a long moment.\n"That is your account," he said.\n"That is what happened," Soren said.\nAnother silence. Darian was reading him the way he always read him, with the instruments of assessment their mother had given both of them, looking for the place where the account did not hold. Soren held the account still and steady and looked back at his brother with the face he had been building in this court for twenty years, the face that showed nothing it was not choosing to show.\nDarian picked up the access log. "I will need a written statement."\n"I will have it to you this afternoon."\nDarian stood. At the door he paused. "The transmission," he said. "If it has already moved through the review channel, the written statement controls the narrative. The court''s position is that the document was not what it appeared to be. Incomplete. Outdated. Not operationally current." He looked at Soren. "That is the position."\n"I understand."\nDarian left.\nSoren sat at his work table in the offices that had made him useful, surrounded by the maps that had made him legible to a court that had previously treated him as decoration. He had just handed Darian a version of events that was technically supportable and specifically designed to absorb the exposure onto himself and away from her.\nHe had also, in the same breath, described her as an intelligence operative who had approached him with intent.\nBoth things could not be simultaneously true in the way he had presented them. He had built an account that protected her from removal and protected himself from consequence and in doing so had made her something she was not and made himself something he was not and filed both versions where they belonged and told himself he had not decided anything.\nHe pulled a fresh sheet toward him.\nHe began writing the statement.\nHis handwriting was even. The formal register''s angular precision, each character correct. He was the person who had learned this script from a damaged archive text at fourteen and spent six years in a room alone with it before a girl from the earth kingdom had walked in and said I come with open hands and changed the quality of every silence that came after.\nHe kept writing.\n\nShe found out about the statement on Friday.\nChike brought it to her without comment, a copy flagged in the court''s official record, her name in the sky script she read slowly but correctly. She read the account twice. She read the part where she had approached him with intelligence intent. She read the part where the document was an organizational error, not operationally current.\nShe sat with it.\nShe thought about the working room. His face across the table. I knew you would be reviewing the supplementary documents. I told myself I filed it where it belonged. The kitchen register. The truth wearing its ordinary clothes.\nHe had told the truth to her and built a lie for the record and the lie protected her from removal and also made her into something she had not been and he had done all of it without asking her first.\nThe same way she had sent the document without asking him first.\nShe looked at Chike. He was watching her with the expression of someone who had assembled a picture and was waiting to be told how much of it he was allowed to see.\n"Thank you," she said. Her voice came out steady.\nHe nodded and left.\nShe sat alone in the tower room and felt the full shape of what they had both become in the space of forty-eight hours. She had sent the intelligence without warning him. He had built a record that protected her without telling her. They had each made a unilateral decision that could not be unmade and each one had cost something it was not theirs alone to spend.\nShe thought about the theme, the question the story had been asking since the garden, since the rules they had made, since the dead language had come alive between two people who had no business speaking to each other.\nIs love worth the risk of becoming someone you do not recognize.\nShe looked at her hands.\nShe recognized them.\nShe was not sure she recognized what they had done.','\n',char(10)),1481,1,1,NULL,'2026-04-07T05:55:52.242Z','2026-04-07 05:55:52','2026-04-07 05:55:52',NULL,2,14);
INSERT INTO "chapters" ("id","novel_id","chapter_number","title","content","word_count","is_premium","is_published","audio_url","published_at","created_at","updated_at","scheduled_release_at","part_number","season_id") VALUES(221,29,10,'Peace Talks',replace('\n\nThe summit had been three hundred years in the making and it showed.\nEvery detail of it was weighted, from the chamber selected, a neutral hall in the court''s oldest tower, neither the sky king''s formal council room nor the earth delegation''s working space, to the table itself, round, which had required three weeks of negotiation to agree on because a rectangular table had two heads and a round one had none. The seating arrangement had been the subject of its own document, four pages, distributed to both delegations the morning of.\nAdaora read it at breakfast and noted her position and Soren''s position and the eleven seats between them and the specific geometry of a round table that meant eleven seats was not actually far.\nShe ate what was in front of her and went to get ready.\n\nThe chamber filled slowly, with the particular formality of people who understood that the way they entered a room was itself a statement.\nThe earth delegation arrived as a unit. Ekene at the center, the senior aides flanking him, Adaora and Chike and the junior staff completing the formation. They crossed to their designated positions and stood. Across the chamber the sky court''s delegation was already seated, Adio at the center, the senior councillors arranged outward in order of rank.\nThe sky king entered from the side door.\nShe had seen him in the garden on a Sunday morning in plain robes, laughing privately with someone he loved. She filed that version away and looked at the version that entered the chamber now, the one in full ceremony dress, the gold at his collar and the elaborate arrangement of his silver-streaked hair, the walk of a man who had been the largest presence in every room he had entered for thirty years. He took his seat and the room settled around him the way rooms settled around people who had learned to require it.\nHer own king entered two minutes later.\nShe had never been in the same room as her father''s king before. He was shorter than the portraits suggested and older, with the specific tiredness of someone who had been making decisions with large consequences for a long time. He sat down and looked across the table at the sky king and something passed between them that was not warmth and not hostility but the specific recognition of two people who had been each other''s problem for decades and were now, finally, in the same room to address it.\nSoren came in with the advisory staff.\nHe took his position at the outer ring, two seats from Darian, his document folder open, his face in the careful neutral. He did not look at her. She did not look at him. They were, in this chamber, what they had always been on paper. Diplomat''s aide. Territorial advisor. Two people with no particular reason to know each other.\nShe looked at her notes.\n\nThe summit opened with ritual phrases, the formal language of acknowledgment that both sides were present and that the session was official and that what was said here carried the weight of both courts. The earth kingdom''s senior secretary read the Osa Accord''s modified preamble. The sky court''s secretary read the response.\nThen the actual work began.\nShe had attended enough sessions to know the rhythm of them, the way the opening hour was careful and exploratory, each side testing the other''s positions without committing, like two people walking onto uncertain ice. This session had the same rhythm but underneath it something different, a current she could feel from her position at the outer ring. The two kings were in the room. That changed the weight of every word.\nShe watched the sky king. He was listening to Ekene''s opening position with the expression of a man doing genuine assessment, which was not the expression he had worn in the failed treaty session four months ago. Something had shifted in the court''s posture and she thought she understood what had shifted. The intelligence she had sent. The military liaison''s response. The earth kingdom had positioned itself, quietly and without announcement, in the three territories the campaign phase intended to move through.\nThe sky court knew the campaign''s element of surprise was gone.\nShe watched this understanding move through the session without being stated. It lived in the specific way Adio chose his words when he responded to Ekene''s boundary proposals, in the fractional pause before the sky king''s nod at two separate points. The ground had changed and everyone in the room knew the ground had changed and nobody was going to say how.\nShe kept her face neutral and her notes even and felt the specific weight of being one of the reasons the ground had changed.\nAcross the table, Darian was watching her.\nNot continuously. He was too skilled for that. But in the pattern of his attention, the intervals of it, she could trace the shape of what he was still building, the account Soren had given him and the parts of it that did not fully hold and the conclusion he was moving toward with the patience of someone who had decided that the summit was not the moment but that the moment was coming.\nShe returned to her notes.\n\nThe session broke at midday for a recess.\nShe was crossing toward the side corridor when she heard Lara''s voice.\nNot in the chamber. In the anteroom adjoining it, the door half-open, the unmistakable argumentative precision of a fifteen-year-old who had found someone willing to engage. She paused at the door.\nLara was sitting on the bench inside, text open, talking to one of the earth delegation''s junior aides who had apparently made the mistake of asking what she was reading. She was explaining the third-section translation problem with the full force of someone who had been working on it for two years and was not going to summarize.\nThe junior aide looked slightly overwhelmed.\nAdaora almost smiled.\nShe felt him before she heard him. The particular quality of his presence, the way the air in a space adjusted around someone who had learned to move quietly through difficult places.\nSoren stopped beside her at the door, looking at his sister.\n"She found someone to argue with," he said quietly.\n"Your junior aide is losing," she said.\n"He always loses. Lara does not argue to convince. She argues to be completely understood." A pause. "My father is the same. I never noticed until recently."\nShe looked at him carefully. He was watching Lara with the unguarded face, the one that appeared when the court was on the other side of something. He also looked tired in a way she had not seen before, the specific tiredness of someone maintaining something that was costing them.\n"Darian is close," she said quietly.\n"I know."\n"The statement won''t hold past the summit."\n"I know that too."\nShe looked at him. "When it breaks. What happens to you."\nHe was quiet for a moment. Around them the recess moved, people crossing the corridor, voices from the chamber, the ordinary machinery of a summit that might actually be the last one.\n"I have been thinking about that," he said. "What happens to me." He looked at Lara, who had won whatever point she was making and was now explaining the next one. "I think I have been the wrong person in this court for a long time. I think I became more wrong recently and some of that was my choice and some of it I do not regret." He paused. "What happens to me after the summit is less important than what happens in it."\nShe looked at the chamber door.\nInside, her king and his king were sitting at a round table that had taken three weeks to agree on, working through a framework that had been attempted eleven times and had never held because the people in the room had not been ready for it to hold.\nShe thought about what ready meant. Whether it required clean hands or only honest ones.\n"The fifth section," she said. "The boundary notation Isadora raised. Your reading of the original Mmo text changes the territorial implication significantly."\n"Yes."\n"If you present that reading in the afternoon session, formally, it gives both sides a way to accept the revised boundary without either one appearing to concede."\nHe looked at her.\n"It is the right reading," she said. "I have checked it against my grandmother''s coastal dialect twice. The original text supports it."\n"I know," he said. "I have known since the second session."\n"Then present it."\nHe was quiet.\n"Soren." She said his name the way she said it only in corridors, direct and without approach. "You filed a document where it belonged. I sent what needed to be sent. We are both inside the consequences of those choices and we cannot change the shape of them." She looked at him. "But this session is happening right now. The fifth section is right now. Use what you know."\nHe looked at Lara one more time.\nThen he straightened, closed his document folder, and walked back toward the chamber.\nShe waited thirty seconds. Then she followed.\nInside, the recess was ending, the delegations returning to their positions around the round table that had no head. She took her seat and opened her notes and looked at the chamber, the two kings and the three-hundred-year war and the modified Osa Accord in its fresh binding at every seat.\nAcross the table Darian was watching her.\nShe looked back at him, steadily, and then returned to her notes.\nShe opened her notes. Across the chamber Darian had stopped watching her and turned to his brother, and she knew that posture, the angle of a man who had finished counting and moved to timing. Whatever he had found, he had enough of it. The afternoon session opened with the sky king''s voice and the forty-seventh clause, and the chamber did not know it was also a clock, already running.','\n',char(10)),1685,1,1,NULL,'2026-04-30 14:08:39','2026-04-07 05:56:35','2026-04-30 14:08:39',NULL,2,14);
INSERT INTO "chapters" ("id","novel_id","chapter_number","title","content","word_count","is_premium","is_published","audio_url","published_at","created_at","updated_at","scheduled_release_at","part_number","season_id") VALUES(222,29,11,'The Cost',replace('\n\nThe fifth section passed.\nNot easily. Soren presented the Mmo territorial reading in the afternoon session with the precision of someone who had been sitting on it for weeks and had decided that sitting on it any longer was its own kind of choice. The sky court''s linguistics consultant, Isadora, confirmed the reading independently. The earth delegation''s senior aide, who had studied pre-war boundary texts for eleven years, confirmed it a third time.\nThe sky king looked at the reading for a long moment. Then he looked at his son.\nSomething passed between them that the chamber absorbed without comment.\nThe fifth section passed.\nBy evening the accord had cleared its three remaining contested clauses. The ratification session was scheduled for Friday, two days away. Both delegations returned to their towers and Adaora sat at her work table and looked at the modified Osa Accord in its fresh binding and felt the specific exhaustion of something that had been almost impossible becoming almost real.\nThen Chike came in and set a document on her table without speaking.\nShe looked at it.\nA formal court notice, sky script, her name in the third line. A request for a closed session with the court''s internal affairs office. Councillor Yetunde. Tomorrow morning. Attendance mandatory for all members of the earth delegation.\nNot just her. All of them.\nDarian had moved.\n\nShe went to Ekene that night.\nNot the managed version. Not the account she had been maintaining since the first mission, the careful omissions and the shaped reports and the one line she had added to the assessment section. She sat across from him in his room with his forty years of diplomatic service between them and told him everything.\nThe archive corridor. The maintenance passage. The dead language. The rules they had made. Ominala, which she had not known about in time. Ughelli, which she had known about too late. The report she had chosen not to write. The intelligence she had withheld to protect a source she was not supposed to have. The document filed where it belonged. The transmission she had sent without warning him.\nSoren''s name.\nAll of it, in order, without omission, wearing its actual shape.\nEkene listened without interrupting. When she finished the room was very quiet. He looked at his hands on the table for a long moment.\n"The transmission," he said finally. "The pre-positioning in the three territories. That came from your source."\n"Yes."\n"And the valley province casualties. The ones we did not take. That also came from your source, indirectly."\n"Yes."\nHe was quiet again. She sat inside the quiet and let it be what it was.\n"How many people do you think did not die," he said, "because of what you chose to do."\nShe had thought about that. She had thought about it alongside the sixty-three from Oguta''s southern quarter and the fourteen from Ughelli and she had found that the accounting was not clean and was never going to be clean and she was going to have to carry the full column, both sides of it, for the rest of her life.\n"I don''t know the exact number," she said. "The valley provinces. The three territories. The pre-positioning changed what the campaign phase could do." She paused. "More than sixty-three."\nHe nodded. The same nod. Absorbing a number.\n"Adaora." He looked at her directly. "Yetunde''s session tomorrow. She has Darian''s material. She is going to use it to challenge the delegation''s standing before the ratification."\n"I know."\n"If the delegation''s standing is successfully challenged, the ratification does not happen on Friday. It goes back to the accord committee. It may not come back."\nShe looked at him. "I know."\n"Then you understand what tomorrow''s session requires from you."\nShe understood. Tomorrow''s session required the account she had just given him, delivered formally, attributed fully, her name on every part of it. It required her to stand in front of Yetunde and give the sky court''s internal affairs office the complete picture before they could use the incomplete picture as a weapon. It removed the leverage. It also ended her diplomatic career and possibly her freedom depending on how the court chose to categorize what she had done.\nIt was the thing she could not get back.\n"Yes," she said.\nEkene looked at her for a long moment. Then he said, in a voice she had not heard from him before, not the forty-year diplomat, something underneath that, "You are the best person I have brought to a posting in twenty years. I want you to know that before tomorrow."\nShe felt that land in the specific place where it needed to land.\n"Thank you," she said.\nHe nodded once. Then he picked up his pen and returned to his documents, and the conversation was over, and she went back to her room and sat on the edge of her sleeping mat and looked at the Mmo folder on the corner of her table.\n\nSoren went to his father at the same hour.\nNot Darian. He had thought about going to Darian, the managed approach, the shaped account. He had sat with that option for three days and had understood, by the end of the third day, that the managed approach was the approach of a person who was still trying to be useful to the court, still trying to fit inside the category it had made for him, still the person who had walked into his brother''s office and said I want to be useful and meant it as a kind of survival.\nHe did not want to survive that way anymore.\nThe sky king received him without ceremony, which meant he had been expecting something. They sat across from each other in his private study, the same configuration as always, the father and the youngest son who had been decoration and then briefly useful and was now standing on the edge of something that would make him neither.\nHe told his father everything.\nThe archive. The corridor. The language. Every meeting, its content, its cost. The Ominala decision and what it had cost him to make it. The Oguta maps and what he had understood, sitting with the after-report, about what he had built and what it had been used for. The supplementary file and why he had put it where he had put it. The statement he had given Darian, which was technically supportable and specifically designed to limit exposure, which was the kind of thinking his father had taught him without intending to and which he no longer wanted to be fluent in.\nHis father listened.\nWhen he finished the study was quiet in the way of a place where something irrevocable had just been said. The sky king looked at his hands and then at his son and his expression was not the formal portrait face, not the summit face. It was the garden face, the Sunday morning face, old and tired and more honest than ceremony allowed.\n"The accord," his father said.\n"The fifth section reading is correct," Soren said. "Independent of everything else I have told you, the linguistic analysis stands. The ratification is the right outcome."\nHis father was quiet for a long time.\n"You understand what you have just given me," he said.\n"Yes."\n"Your position in the intelligence office. Your access. The work you have built." He paused. "Darian."\n"I understand."\n"And you came anyway."\nSoren looked at his father. At the face that had ordered Ughelli and laughed privately in a garden on Sunday morning, that had approved his intelligence posting in two days and barely looked at him for twenty years before that. The complete person, not the symbol, not the war''s architect. His father.\n"I came," he said, "because the accord ratifies on Friday and I will not let Darian use what he knows to stop it. And because I am tired of building things that cost other people prices I do not pay."\nHe paused.\n"And because you deserved the truth from me before someone else gave you a version of it."\nHis father looked at him for a long time.\nThen he said, "Leave Darian to me."\n"And the earth delegation''s aide."\nA pause. "That is more complicated."\n"She does not deserve to be the cost of this," Soren said. "Whatever consequence I carry, I carry it. Her standing before the ratification should not be affected."\nHis father''s expression moved through something she could not have read from across a summit chamber but that Soren, twenty years of learning this face, read clearly. Not agreement. Not refusal. The specific expression of a man calculating what he owed his son against what his court required.\n"Go to your rooms," his father said finally. "Tomorrow morning I will speak to Yetunde."\nSoren stood.\nAt the door his father said, "The girl. The earth kingdom aide."\nHe stopped.\n"She taught you the language," his father said. Not a question.\n"The coastal register," Soren said. "I had the formal. She had the kitchen words."\nHis father looked at the wall for a moment. "Your grandmother spoke something like it," he said quietly. "Before the war. I was very young. I had forgotten." He paused. "I had chosen to forget."\nSoren held that for a moment.\nThen he said, in Mmo, the kitchen register, the ordinary greeting, the one for presence and continuation: I am still here.\nHis father looked at him.\nHe did not repeat it back. He did not know the words. But something in his face received them, the specific quality of a man hearing a sound he had given up on hearing, which was an expression Soren recognized because he had worn it himself, once, in an archive, when a girl from the earth kingdom had said I come with open hands.\nHe left the study and walked back through the sky court''s nighttime corridors, past the archive, past the garden, past the bridge where she had stopped on a Sunday morning and looked at his family and said I see you.\nIn his room he sat at his work table.\nHe had offered everything he had built after she left. The usefulness and the intelligence work and the position and the maps and the version of himself the court had finally had a category for. He had put it on the table in his father''s study and left it there and walked out and he was not going to get it back.\nHe pulled a sheet toward him.\nIn Mmo, the formal register, he wrote the closing phrase, the witnessing one, the one they had used since the garden.\nHe looked at it.\nThen he added, underneath it in the kitchen register, the small and ordinary words: it cost something. it was worth it.\nHe folded the sheet and held it and looked at the wall of his room, the sky court pressing in on all sides, cold and gold and magnificent and three hundred years old.\nHe had laid everything he had built on his father''s table and walked out. She was going to walk into Yetunde''s office tomorrow and put her name on every part of it. They had each made a decision that would cost them the version of themselves this court had been building, and neither had asked the other first, and somehow that was the most honest thing they had done since the garden. Two days. Whatever came after Friday was not going to look like anything either of them had planned for.','\n',char(10)),1932,1,1,NULL,'2026-04-30 14:09:43','2026-04-07 05:57:27','2026-04-30 14:09:43',NULL,2,14);
INSERT INTO "chapters" ("id","novel_id","chapter_number","title","content","word_count","is_premium","is_published","audio_url","published_at","created_at","updated_at","scheduled_release_at","part_number","season_id") VALUES(223,29,12,'Children of Opposite Skies',replace('\nYetunde''s session lasted forty minutes.\nAdaora arrived with her full account prepared, everything in order, her name on all of it. She sat across from Yetunde in the internal affairs office and waited for the questions to begin.\nYetunde looked at her for a moment. Then she placed a single document on the table. A formal notice of session closure. Already signed.\n"The matter has been reviewed at the senior level," Yetunde said. Her voice was the same as always, precise and without excess. "The delegation''s standing before the ratification is not affected."\nAdaora looked at the closure notice.\n"Councillor," she said carefully. "I came prepared to give a full account."\n"I know," Yetunde said. "That preparation is noted." She looked at Adaora with the expression that had always been precise and was now something slightly different. Not warmth. Recognition. "The session is closed. You have a ratification to attend."\nAdaora looked at her for one more moment. Then she picked up her bag and left.\nIn the corridor she stood still for a moment and breathed and understood that someone had made a decision in a room she had not been in, that the decision had protected her standing, and that the cost of it had been paid by someone else at a table she would never sit at.\nShe walked toward the ratification chamber.\nThe room was the same round table.\nSame geometry, same careful seating arrangement, same cold gold light through the high windows. Both kings. Both delegations. The modified Osa Accord in its fresh binding, three hundred years of war compressed into forty-seven clauses and one round table that had taken three weeks to agree on.\nShe took her position. Left and behind Ekene, as always.\nSoren was at the outer advisory ring, two seats from Darian. He looked the same and not the same, the way he had looked on her return, carrying something that had weight and direction. She noticed, from across the chamber, that his position in the advisory ring was slightly different from the summit. Further from Darian. Further from the court''s inner formation.\nShe did not know what his father had done with what he had given him. She did not know what it had cost. She looked at his face from across the room and could not read it at this distance and returned to her documents.\nThe ratification moved through its ritual phases.\nThe preamble read aloud. The forty-seven clauses confirmed in order. The fifth section, with its revised boundary notation, passing without objection, Isadora''s confirmation already in the official record from the summit session.\nShe watched the sky king''s face as each clause cleared. The assessment expression, genuine and continuous, the face of a man who had come into this room having made a decision she could not see the full shape of but whose edges she could trace. He had come to ratify. Whatever his reasons, whatever calculation had brought him here, he had come to ratify.\nHer own king''s face was the face of someone who had been carrying the weight of a three-hundred-year war and was beginning, slowly, to feel the weight redistribute.\nClause forty-seven.\nBoth secretaries confirmed.\nThe sky king picked up the pen.\nThe room held its breath in the specific way of people who had been inside a long and costly thing and were watching it become, finally, something else.\nHe signed.\nHer king signed.\nThe Osa Accord. Ratified. On a Friday morning in the sky court''s oldest tower, at a round table that had no head, in the presence of people who had spent their lives on opposite sides of something that had just, irrevocably, changed shape.\nThe chamber released its breath.\nProtocol required a formal closing exchange between the two kings. Brief, ritual, the language of acknowledgment and transition. She had the script in her briefing documents. She knew the phrases.\nWhat she did not have in her briefing documents was what the sky king did after the ritual exchange was complete.\nHe looked at his son.\nAcross the chamber, a direct look, the kind that carried a conversation inside it. Soren received it with the stillness she knew completely, the thinking stillness, and then something shifted in it, something released, and he stood up from the advisory ring.\nHe crossed the chamber.\nNot toward the earth delegation. Toward the center of the room, the round table, the open space between both kings where the accord now sat in its binding with two signatures on it. He stopped there and looked at the room, the full chamber, both delegations, both kings, Darian and Yetunde and Ekene and Chike and Isadora and all the people who had built and survived and been built and broken by three hundred years of a war that had ended forty seconds ago.\nHe said, in Mmo, the formal register, in a voice pitched to carry:\nI come with open hands.\nThe chamber went very still.\nNot everyone understood the words. Most of them did not. But the language itself, the sound of it, the pre-war script that had survived in an archive and a kitchen and two people who had no business knowing it, moved through the room with the specific weight of something very old becoming present.\nAdaora felt it arrive in her chest before she had decided anything.\nShe stepped forward from her position left and behind Ekene.\nShe was aware of Ekene not stopping her. She was aware of the room, the two kings, Darian''s assessment face, Yetunde''s precise attention. She was aware that she was crossing the chamber in full view of everyone who had spent this mission watching the shape of her movements and drawing conclusions from them.\nShe stopped beside him at the center of the room.\nIn Mmo, the coastal register, her grandmother''s words in their ordinary clothes, she said:\nIt is witnessed by what we both remember.\nThe formal register and the coastal dialect. The archive and the kitchen. The two halves of a dead language spoken together in the same room for the first time, probably, in three hundred years.\nShe did not know who in the chamber understood the words.\nShe knew that everyone understood the fact of them.\nThe sky king looked at the two of them standing at the center of his ratification chamber, this earth kingdom girl and his youngest son, speaking a language that had died with the war and had apparently refused to stay dead. His expression moved through something she could not fully read.\nThen he said, in sky court formal language, to the room: "The session is closed."\nPeople began to move. The careful machinery of post-ratification protocol, documents gathered, delegations reforming, the business of two kingdoms beginning to figure out what peace required of them in practical terms.\nShe stood at the center of the room with Soren beside her and felt the specific quality of a moment that had finished becoming itself.\n"Your position," she said quietly. "What did it cost."\n"The intelligence office," he said. "The advisory role. For now." A pause. "My father has suggested a different kind of usefulness. Linguistic and cultural consultation on the accord''s implementation. It has no precedent in the court." He looked at her. "He said it was time to make one."\nShe absorbed that.\n"The earth kingdom will need equivalent expertise," she said carefully.\n"I imagine they will."\nShe looked at him. He looked back. Darian was crossing the chamber toward them, his face doing its assessment work, and beyond him Ekene was watching with the expression of a man who had decided to let something be what it was. Chike was near the door, gathering documents, not looking at her in the specific way of someone who had understood something and made their peace with it.\nThe three-hundred-year war had ended eleven minutes ago.\nThey were standing at the center of a room full of people who were beginning to figure out what came next, which was going to be long and difficult and full of things that could not be resolved by a single accord and a round table, because three hundred years did not become something else in forty-seven clauses, it just agreed to become something else and then the actual work began.\nShe thought about who she was.\nNot the question she had been carrying. She knew the answer now, or enough of it to walk forward on. She was the diplomat''s daughter who had come into a hostile court at seventeen and made errors and paid for them and kept going. She was the girl her grandmother had given a dead language to, who had found another person holding the other half of it. She was the woman who had sent the transmission and written the report and stood in the internal affairs office ready to put her name on all of it.\nShe was still becoming. That was the honest answer. She was going to be still becoming for a long time.\nShe thought that was all right.\nIn Mmo, the kitchen register, the smallest and most ordinary phrase, the one for presence and continuation and the simple fact of still being somewhere:\nI am still here.\nHe said it back.\nThe room moved around them, the two kingdoms beginning their long complicated work of learning to be something other than enemies, and they stood at the center of it speaking a dead language in plain voices, witnessed by everyone, hidden from no one, the archive and the kitchen finally in the same place at the same time.\nOutside, through the high windows, the sky was its usual pale cold gold.\nIt had never looked, to her, like the wrong color.\nEnd of Season 2 — "The Breaking Point"\nEnd of Children of Opposite Skies','\n',char(10)),1643,1,1,NULL,'2026-04-07T13:16:30.083Z','2026-04-07 13:16:30','2026-04-07 13:16:30',NULL,2,14);
INSERT INTO "chapters" ("id","novel_id","chapter_number","title","content","word_count","is_premium","is_published","audio_url","published_at","created_at","updated_at","scheduled_release_at","part_number","season_id") VALUES(224,30,1,' King of Oshodi',replace('\n\nThe danfo hadn''t fully stopped when Seun swung out from the open door, one hand on the frame, his voice already cutting through the noise of Oshodi motor park like a blade through soft bread.\n"Ojota! Ojota direct! Enter with your change o!"\nHe was sixteen and small for it, but his voice had never gotten that message. It carried the way his driver Uncle Femi''s didn''t, past the hawkers and the other conductors and the women balancing trays of pure water sachets on their heads, past the smell of exhaust and frying akara and the distant sound of someone''s Afrobeats leaking from a phone. People heard Seun. They always did.\nThree passengers peeled away from the crowd and moved toward the yellow bus. Seun counted them before they reached him. A woman with a nylon bag of tomatoes pressed against her chest, a young man in a pressed shirt trying not to look like he was in a hurry, and old Baba Sikiru, who took this route every Tuesday and Thursday and always tried to pay with a five-hundred naira note for a two-hundred naira fare.\n"Baba, I told you last week," Seun said, already holding out his hand as the old man climbed in.\nBaba Sikiru laughed, low and wheezy, and produced exact change from somewhere in his agbada. "Sharp boy."\n"Na you teach me." Seun swung back onto the door frame as Uncle Femi eased the danfo into the crawling traffic. He knew this road the way he knew his own heartbeat. The wide pothole just before the Ikorodu Road junction that Uncle Femi always forgot about. The stretch near Ketu where traffic knotted into a fist every morning between seven-fifteen and eight. The police checkpoint that appeared on Mondays and Wednesdays but never on Fridays, for reasons nobody questioned out loud.\nHe knew which passengers to watch. The ones who would quietly slide toward the door as the bus slowed, hoping the chaos of disembarking would swallow their fare. He knew which ones tipped, never much, but enough. He knew which regular passengers needed to be called by name because it made them feel seen, and people who felt seen came back.\nThis was not luck. This was study.\nBy the time they reached the Ketu bus stop, Seun had collected fares from nine passengers, settled an argument between the woman with the tomatoes and the young man in the pressed shirt who had accidentally elbowed her, and spotted a fare-dodger three stops early. He blocked the door with his body, said nothing except "Bros," and held out his palm. The man paid.\nUncle Femi caught Seun''s eye in the rearview mirror and shook his head slowly, the way he always did. Not disapproval. Something closer to admiration that he was too old to say plainly.\nThe return trip was smoother. It always was. Morning traffic moved one direction, so coming back from Ojota to Oshodi before the afternoon rush was almost pleasant, if you could call anything about a yellow danfo with a cracked windshield and a door that didn''t fully close pleasant. Seun didn''t mind it. There was something clean about the motion, about having a thing you were good at and doing it over and over until the doing felt like breathing.\nHe ate during the brief stop at Oshodi. Rice and stew from Mama Titi''s spot, the kind of food that cost three hundred naira and tasted like it cost more. He ate standing up, counting the morning''s collection in his head. After Uncle Femi''s cut and the bus running costs, Seun''s share for a full day came to roughly two thousand five hundred naira on a good day. Today was shaping up to be good.\nHis notebook was in his back pocket, small and battered, the cover soft from handling. He didn''t take it out here. He knew the numbers already.\nEleven thousand, two hundred. That was what sat in the envelope under the floorboard in his room. That was six weeks of careful work, of choosing rice over fried chicken, of saying no when the other conductors pooled together for beer on Saturday evenings. His school resumption fees were fourteen thousand. He had been out for one term, told his mother it was a short break, told himself it was a strategy.\nHis mother believed it was laziness dressed up in excuses. She had said so, clearly, the way she said everything, standing in the kitchen doorway with her wrapper tied tight around her waist and her face doing that thing where disappointment and love occupied the exact same expression.\n"Seun. You have a head. Use it for something that will last."\nHe had not argued. Arguing with his mother about the route was like arguing with Oshodi itself. You did not win. You survived it and kept moving.\nWhat she didn''t understand, what he hadn''t found the words to explain, was that the route was the plan. Not the end of it. The beginning. He had worked it out, the whole thing, in the notebook. Conductor for eight more months. Save enough to cover school fees and have something left. Finish secondary school. Then spend two years building capital. A partnership with Uncle Femi or someone like him. One bus. Then two. A small fleet running a reliable route. Not scrambling. Not ducking. Something with his name on it that nobody could take.\nIt was a plan built from the street up and it was working.\nThe afternoon sun came down hard on the motor park. Seun finished the last of his rice and crushed the nylon carefully, dropped it in the gutter because there was nowhere else, and felt the small familiar guilt of it. He pushed the notebook deeper into his pocket and watched Uncle Femi navigate the danfo back into position for the next run.\nA group of conductors nearby were loud about something, laughing the kind of laughter that was really just noise. One of them, Razor, a wiry twenty-year-old who wore the same red cap every day, called out to Seun.\n"Oshodi king! You hear the news?"\nSeun shook his head, already moving toward the bus.\n"Union meeting tomorrow," Razor said, still grinning. "Alhaji Ruka is reorganizing the routes. Sharing things out fresh."\nSeun paused. Just for a second.\n"What routes?"\nRazor shrugged, the grin not moving. "All of them, they say. We go see tomorrow."\nSeun climbed back onto the danfo door as Uncle Femi pulled out into traffic, the familiar noise of the park folding behind them. He told himself it was nothing. Route reorganizations happened. They talked about it and nothing changed. The plan was solid. The numbers were close.\nHe told himself that all the way to Ojota and most of the way back.','\n',char(10)),1134,0,1,NULL,'2026-04-08 13:20:17','2026-04-08 01:29:32','2026-04-08 13:20:17',NULL,1,NULL);
INSERT INTO "chapters" ("id","novel_id","chapter_number","title","content","word_count","is_premium","is_published","audio_url","published_at","created_at","updated_at","scheduled_release_at","part_number","season_id") VALUES(225,30,2,'Union Notice',replace('\n\nAlhaji Ruka did not look like someone who could end your life without raising his voice. That was the thing about him that nobody warned you about until it was too late.\nHe was short and wide, with a face that had settled into a permanent expression of mild boredom, the kind of face that had seen enough of the world''s drama to stop being impressed by it. He wore a kaftan the color of weak tea and sat in a white plastic chair outside the union office like a man waiting for nothing in particular. But every conductor who passed him slowed down. Even the ones who pretended not to notice him moved differently, shoulders shifting, eyes finding somewhere else to be.\nSeun noticed all of this from across the park. He noticed it the way he noticed everything, catalogued it, filed it. But he did not slow down.\nThe union meeting had pulled most of the Oshodi conductors into a loose crowd near the corrugated iron office. Uncle Femi was already there, standing at the back with his arms folded and his face closed in that way that meant he was calculating something privately. Seun slid into the crowd beside him.\n"What did I miss?"\n"Nothing yet," Uncle Femi said, without looking at him. "He hasn''t spoken."\nThe crowd was doing the thing crowds did before something official happened. Men talked too loudly about unrelated things. Someone laughed at a joke that wasn''t funny. A hawker moved through offering bottled water and everyone ignored him.\nThen Alhaji Ruka stood.\nHe didn''t raise his hand or call for quiet. He simply stood and the noise fell away from him like water.\n"I will not waste your time," he said. His voice was ordinary. That was also unsettling. "The National Road Transport Workers Union has reviewed route allocations for this corridor. Some routes are being reassigned. Some fees are being restructured. The full list is on the board." He gestured toward the office door. "Every conductor working a registered route will pay a monthly union levy starting from next week. The levy covers your protection, your legal standing, and your right to operate. Those who do not pay cannot work. That is all."\nHe sat back down.\nThe crowd exhaled and then immediately began talking, loud and overlapping, the way people talk when they''re deciding how afraid to be. Seun moved through them toward the board on the office door. It was a single sheet of paper, printed badly, some words slightly smeared. He found his route quickly.\nOshodi — Ojota corridor. Registered conductors: see new allocations.\nHe found the levy amount three lines down.\nFive thousand naira. Monthly.\nHe read it again. Then he stepped back from the board and stood there a moment with the motor park noise moving around him.\nFive thousand naira monthly was five thousand naira he did not have the architecture for. His savings plan had no slot for five thousand naira monthly. He had built the numbers carefully and this was not in them.\nUncle Femi appeared at his shoulder, read the board, and said nothing for a long moment.\n"It''s not the first time they''ve tried this," Seun said.\n"No."\n"Last time nothing came of it."\nUncle Femi made a sound that was not quite agreement.\n"This time is different?" Seun asked.\nThe older man looked at him the way adults looked at you when they thought you already knew the answer and were just hoping to be told otherwise. "Ruka is not the man from last time."\nSeun looked back at the board. Five thousand naira. The number sat in his chest like a stone he had swallowed accidentally.\n"I''ll figure it out," he said.\nUncle Femi said nothing.\nHe worked two more runs that afternoon, which was one more than usual, because the numbers needed to be looked at from a different angle and physical motion helped him think. His voice was rougher by the third trip, and the afternoon crowd was the impatient kind, the kind that treated conductors like furniture that should move faster.\nBy the time he ate in the evening it was suya from a man near the park entrance, the smoke from the grill cutting through the usual exhaust smell, and Seun sat on a low concrete block and opened his notebook.\nHe worked through it three times. The numbers did not change on the third attempt the way he had quietly hoped they might. Five thousand naira monthly was money that would extend his savings timeline by at least four months. Four months became a full term at school still unpaid for. The plan was not broken but it had a new crack running through it.\nStill. There was time before next week. He could find an angle.\nRazor appeared from somewhere and sat beside him uninvited, chewing on a stick of suya and looking at the notebook without actually reading it.\n"You see the levy?" Razor asked.\n"I saw it."\n"Five thousand." Razor shook his head with something that was almost enjoyment. "My brother they are not joking this time."\n"You''re paying it?"\nRazor laughed, sharp and short. "What choice? You don''t pay, you don''t work. You don''t work, you don''t eat. That''s the whole calculation."\n"There might be other options."\nRazor looked at him with the specific pity of someone who had already moved past the stage of looking for other options. "This is Alhaji Ruka, Seun. The man did not come to negotiate." He stood, brushed suya crumbs off his shirt, and pointed vaguely in the direction of the union office. "Just pay. Find the money somewhere and pay. This kind of wahala you don''t want to be the last person still standing in."\nHe left, and Seun looked back at his notebook.\nThe numbers still hadn''t changed.\nHe closed it, tucked it into his pocket, and told himself what he had been telling himself all afternoon. It was a demand, not a verdict. There were always angles. The route was his, the passengers were his, the plan was his, and one short wide man in a tea-colored kaftan was not going to rewrite it.\nHe believed this.\nHe almost entirely believed this.\nOn the danfo ride home, crushed between a woman with a baby tied to her back and a man who smelled of sawdust, Seun stared out the window and watched Oshodi slide past. The yellow buses. The yellow light. The same streets that had always been his.\nHe would figure it out by tomorrow, he decided.\nTomorrow came and went without a solution.','\n',char(10)),1105,0,1,NULL,'2026-04-08 13:22:37','2026-04-08 01:31:20','2026-04-08 13:22:37',NULL,1,NULL);
INSERT INTO "chapters" ("id","novel_id","chapter_number","title","content","word_count","is_premium","is_published","audio_url","published_at","created_at","updated_at","scheduled_release_at","part_number","season_id") VALUES(226,30,3,'The New Conductor',replace('\nHe heard the voice before he saw the face, and his body knew before his mind caught up, the way your body always knows the things you are not ready to know.\n"Ojota! Ojota direct! Correct change only o!"\nSeun stopped walking.\nThe morning park was full and loud, the usual Tuesday chaos of bodies and engines and hawkers, and for a second he thought he had imagined it. The voice was wrong for this place, wrong for this route, wrong for every calculation he had made since yesterday when he woke up and decided today was the day he found his angle. He moved through the crowd until he had a clean line of sight to the Ojota bay and then he stood there and looked.\nThe danfo was yellow, the way they all were. It was not Uncle Femi''s bus. It was a newer one, the windshield uncracked, the paneling still holding its paint in most places. And hanging off the open door with one hand on the frame, body angled out toward the crowd, working the morning rush with the ease of someone who had done this a thousand times, was Olamide.\nSeun did not move.\nOlamide was taller than he had been at thirteen, which was the last time they had been in the same place long enough to really see each other. He had grown into his height without growing out of that particular way he had of holding himself, loose and easy, like the world had not yet given him a reason to tighten up. His voice was deeper but the rhythm of it was exactly the same, that slight upward pull at the end of each call, the way he stretched the last word like he was offering something worth considering.\nThey had grown up on the same street in Mushin. Played the same games, attended the same school, shared the kind of friendship that forms in childhood before you know enough to be selective about who you let close. Olamide had been the one who laughed first at everything and made it safe for everyone else to follow. He had been the one who, at twelve, convinced Seun they could fix the landlord''s generator and split the money, a plan that had failed completely but had not felt like failure because Olamide kept laughing through the whole disaster.\nThen Olamide''s mother moved them to his uncle''s compound in Bariga after the second rent trouble, and the distance did what distance does. Not a fight. Nothing clean enough to be a fight. Just the slow loosening of something that had once been tight. A friendship that ended not with a door slamming but with a door left open until the breeze from somewhere else quietly closed it.\nThat was three years ago.\nNow Olamide was standing on Seun''s route, on a bus that wasn''t Uncle Femi''s, calling the same fares in the same bay, wearing a red conductor''s vest that Seun had never seen before but recognized immediately, because he recognized the union''s colours.\nA hand landed on Seun''s shoulder.\nHe turned. It was Uncle Femi, which meant the old man had been watching him stand here and stare long enough to come find him.\n"You know him?" Uncle Femi asked.\n"Yes." The word came out flat.\n"He was here when I arrived this morning. His driver has papers. Union papers. Signed this week." Uncle Femi paused. "They moved him onto our bay."\nSeun looked at the bay. There was room for two buses, there had always been room for two, but the flow of passengers had already begun to reorganize itself toward the newer bus the way passengers always moved toward what looked newer and cleaner. He watched three people he recognized, a woman who took his route every Tuesday, a secondary school boy who always stood near the door, walk past and climb into Olamide''s bus.\n"This is how they do it," Uncle Femi said, not unkindly. "They don''t push you off the route directly. They put someone else on it and let the passengers decide."\n"And if I keep working the route?"\nThe old man was quiet for a moment. "Then you are working without union papers on a route that now has union coverage. They can stop you. Not just ask you. Stop you."\nSeun watched Olamide swing back onto the door frame as the bus prepared to move. Olamide had not looked in his direction. Either he hadn''t noticed Seun in the crowd or he was working very hard at not noticing.\nSeun knew which one it was.\nHe walked to Uncle Femi''s bus without saying anything else. He climbed in. He called the fares. His voice came out steady, which surprised him, because there was something happening in his chest that was not quite anger and not quite grief and was worse than both of them separately.\nThe morning run was the longest he had worked in months.\nHe counted passengers and made change and said the things conductors say and all of it happened in some separate part of him while the rest of him turned the same thing over and over. Not the route. Not the levy. Not Alhaji Ruka in his tea-colored kaftan.\nOlamide.\nOf all the conductors in Lagos, in Oshodi, on this corridor, the union had put Olamide on his route. Maybe it was coincidence. Lagos was large but the transport world was not, and it was possible their paths had simply crossed by accident at the worst possible time. He tried to believe this for the length of one full trip.\nHe stopped believing it somewhere near Ketu on the return run.\nOlamide had known this was Seun''s route. He had grown up hearing Seun talk about the plan, about Uncle Femi, about the Oshodi to Ojota corridor. He had known, and he had come anyway, which meant one of two things. Either Olamide had needed the work badly enough that it overrode everything else, or someone had specifically put him here.\nSeun thought about Alhaji Ruka''s face. That permanent boredom. The way he had announced the levies like a man reading a shopping list. A man like that did not leave things to coincidence. A man like that knew exactly what tools he was using and what they were for.\nThe danfo stopped at a junction and in the window Seun caught his own reflection, brief and unclear in the dirty glass. He looked older than sixteen. He had been told that before and had always taken it as a compliment.\nRight now it didn''t feel like one.\nHe thought about his notebook. Eleven thousand, two hundred naira. Fourteen thousand needed. Three weeks of good days still between him and the number. He thought about his mother in the kitchen doorway and the particular shape of her disappointment. He thought about the plan, all of it, the careful architecture of it, and how it had been built to survive most things but not this. Not the specific weight of a friend''s face appearing in the place where his future was supposed to be.\nThe junction cleared. Uncle Femi pressed the accelerator and the danfo moved.\nSeun turned away from the window.','\n',char(10)),1211,0,1,NULL,'2026-04-08 20:19:18','2026-04-08 01:32:42','2026-04-08 20:19:18',NULL,1,NULL);
INSERT INTO "chapters" ("id","novel_id","chapter_number","title","content","word_count","is_premium","is_published","audio_url","published_at","created_at","updated_at","scheduled_release_at","part_number","season_id") VALUES(227,30,4,'Same Sky, Different Road',replace('\n\nSeun waited until the afternoon lull, when the park emptied of its morning urgency and settled into the slower rhythm of drivers eating and conductors arguing and hawkers resting their trays on their knees. It was the one hour of the day when Oshodi motor park felt almost human.\nHe found Olamide sitting on a low wall beside the newer bus, eating eba and egusi from a small container, the kind you bought from the food women near the park entrance. He was eating with the focused attention of someone who had been hungry since morning. He looked up when Seun''s shadow reached him and something moved across his face too quickly for Seun to name it before it was gone.\n"Seun." His voice was level. Not warm, not cold. Carefully in the middle.\n"Olamide."\nThey looked at each other. Three years of distance sat between them like a third person who hadn''t been invited but had shown up anyway and expected to be fed.\nSeun sat on the wall without asking. Olamide moved his container slightly to make room, which was not a welcome exactly but was not the opposite of one either.\n"When did you start on this route?" Seun asked.\n"Monday."\n"Monday." Seun nodded slowly. "And you were going to say something when?"\nOlamide took another scoop of eba and chewed it before answering. "I knew you''d find out."\n"That''s not the same thing."\n"I know."\nA hawker passed them calling out gala and Lacasera and neither of them responded. Somewhere behind them a driver was cursing at his engine, a long steady stream of Yoruba that had the resigned quality of a man who had had this same argument with this same engine many times before.\n"Did you know it was my route?" Seun asked.\nOlamide set the container down on the wall between them. He wiped his hand on his trousers. He did not look away, which Seun noted and was not sure what to do with.\n"Yes," Olamide said.\nThe word landed cleanly. No dressing around it. Seun had expected deflection, or a complicated explanation, and the plain honesty of it was almost worse than lying would have been.\n"So you came anyway."\n"I needed the work, Seun."\n"There are other routes."\n"I was offered this one."\nSeun turned to look at him directly. "By who?"\nSomething in Olamide''s face shifted. Not guilt exactly. Something older and more tired than guilt. "A man connected to the union. He said there was a spot open on the Oshodi to Ojota corridor. He had a driver already. He just needed a conductor."\n"A spot open," Seun repeated. "My spot."\n"He didn''t say whose spot it was."\n"But you knew."\nOlamide picked the container back up. He stared into it like the egusi had something to tell him. "I thought maybe you''d moved on. Got another route. I hadn''t heard from you in three years, I didn''t know where you were working."\n"You could have asked."\n"I didn''t have your number."\n"You knew where Uncle Femi parks."\nThe silence that followed was the kind that had weight. Seun could feel it pressing against the side of his face. Across the park, someone''s danfo backfired and a group of conductors shouted in mock alarm and then laughed.\nThey had had only one real argument in all the years of their friendship. Seun was twelve, Olamide thirteen. It had been about something small, a borrowed football that came back with a slow puncture, but it had grown into something else entirely, the way small arguments between close friends sometimes revealed the bigger ones they had been avoiding. They had not spoken for eleven days. On the twelfth day Olamide had appeared at Seun''s door with a sachet of pure water and a look on his face like a man submitting paperwork he found embarrassing. They had not discussed the argument after that. They had simply resumed.\nThere was no sachet of pure water now. And this was not a borrowed football.\n"I need you to ask to be moved," Seun said. "Tell them you want a different route. Tell them anything. I don''t care what reason you give."\nOlamide was quiet for a long moment. When he spoke his voice was still level but something underneath it had changed. "I can''t do that."\n"Why not?"\n"Because I need this route." He paused. "The money is good here, Seun. The passenger volume is high. I''ve been struggling for eight months. Eight months of bad routes and drivers who cheat their conductors and days I come home with less than five hundred naira. This is the first solid placement I''ve had."\n"It''s my placement."\n"The union doesn''t see it that way."\n"I don''t care how the union sees it." Seun heard his own voice go tight and made himself slow it down. "I have a plan, Olamide. School fees. A business. I''ve been building toward it for two years on this route. This route specifically. You know what I''m trying to do."\n"I know what you were trying to do at thirteen," Olamide said, and there was something in his voice that was not unkindness but sat close to it. "People''s plans change."\n"Mine hasn''t."\nOlamide looked at him then, a long look, and Seun saw something in it he didn''t fully understand, something that mixed recognition with something sadder. Like looking at a version of yourself you had already decided you couldn''t afford to be.\n"I''m not your enemy," Olamide said.\n"You''re on my route."\n"I''m trying to survive."\n"So am I," Seun said. "The difference is I''m not doing it on top of someone else."\nThe words came out harder than he had shaped them in his head. He watched them land on Olamide''s face and watched Olamide absorb them the way you absorb something you had already prepared yourself to hear. Which meant he had thought about this. Had known this conversation was coming and had rehearsed his response to it.\nThat was the thing that made Seun stand up.\nNot the route. Not even the union. The fact that Olamide had sat with this knowledge and made his peace with it before Seun had even found out.\n"I''m not asking you to be poor for me," Seun said, standing. "I''m asking you to find another route."\n"And if I can''t?"\n"Then I''ll work the route anyway."\nOlamide looked up at him from the wall. "Seun. If you work without union papers they will stop you. Not just Ruka''s people. The drivers, the other conductors, all of them will move against you because that''s how the system protects itself. You know how this works."\n"I know how everything works," Seun said. "That''s never been my problem."\nHe walked away before Olamide could respond. He moved through the park with his hands loose at his sides and his face arranged into the expression he wore when he needed the world to think nothing was wrong. Past the food women. Past the engine-cursing driver. Past a group of conductors who nodded at him and got a nod back.\nHe did not look back at the wall.\nBut he could feel Olamide watching him go, and the feeling sat on his back the whole walk to Uncle Femi''s bus, heavy and specific, the weight of someone who knew you well enough to know exactly how much damage they were doing.','\n',char(10)),1239,1,1,NULL,'2026-04-08 20:19:31','2026-04-08 01:34:04','2026-04-08 20:19:31',NULL,1,NULL);
INSERT INTO "chapters" ("id","novel_id","chapter_number","title","content","word_count","is_premium","is_published","audio_url","published_at","created_at","updated_at","scheduled_release_at","part_number","season_id") VALUES(228,30,5,'Small Chop, Big Hunger',replace('\n\nThe first name on Seun''s list was Mallam Sule.\nEveryone in Oshodi knew Mallam Sule. He ran three buses on the Oshodi to Mile 12 corridor and had a reputation for being the kind of man who gave young conductors a chance when the bigger operators wouldn''t look at them. He had given Razor his first real placement two years ago. He had given a boy called Tunde a job the same week Tunde got out of a police cell. He was, by the motor park''s standards, a reasonable man.\nSeun found him at his usual spot behind the union office, a strip of shade where Mallam Sule sat every afternoon with a radio and a glass of Zobo, listening to news that he then ignored completely.\nHe heard Seun out without interrupting. Seun kept it short and practical. He was a conductor with two years of solid experience on the Oshodi to Ojota corridor. He knew the route. He knew the passengers. He was looking for a new placement. He did not mention Olamide. He did not mention the levy.\nMallam Sule looked at him over the rim of his Zobo glass for a long moment.\n"You''re Femi''s boy," he said.\n"Yes sir."\n"Good conductor. I''ve heard." He set the glass down. "You have union papers?"\nThere it was. Sitting in the question like a stone at the bottom of a clear stream, visible from the surface, impossible to pretend away.\n"Not currently," Seun said.\nMallam Sule picked his glass back up. "Come back when you do."\nThe second name on the list was a woman called Aunty Bisi who operated a bus on the Oshodi to Agege route and was known to run her operation slightly outside the union''s direct oversight, in the way that certain small businesses existed in the gap between the rules and the enforcement of them. Seun had heard about her from a conductor named Chukwu who had worked for her briefly before moving on.\nHe found Aunty Bisi through three separate conversations and a twenty-minute walk to a side street near the old Agege motor park. She was a broad woman with a direct manner and reading glasses pushed up on her forehead that she never actually used for reading.\nShe listened to Seun with her arms folded and her head tilted slightly, the way people listened when they were already forming an answer.\n"No union papers," she repeated.\n"No."\n"You know Ruka extended his coverage last month. Agege corridor is inside his territory now."\nSeun had not known this.\n"Three months ago I could have used you," Aunty Bisi said, not unkindly. "Today I can''t put a conductor on any bus without papers. He has people watching. Not every day but enough days." She unfolded her arms and looked at him with something that was almost apology. "Sort your papers and come back. I mean that. You have a good face for this work. Serious."\nSeun thanked her and left.\nHe spent two hundred naira on transport getting to those two conversations and got nothing from either of them but the same wall with a different face on it.\nHe sat in a danfo going back toward Oshodi and thought about the shape of the problem. The union was not just a levy. The levy was the visible part, the number on the board, the thing that looked like it could be negotiated or worked around or outlasted. But underneath the levy was something structural. Ruka had built coverage so wide that the entire corridor, every route, every operator, every driver and conductor who wanted to work without harassment existed inside his permission. You did not go around him. There was no around. There was only through him, which meant through his terms, which meant five thousand naira monthly that Seun did not have.\nHe got off two stops early and walked, because walking was cheaper than sitting still and he needed the motion.\nAt the edge of the park he found Chukwu eating groundnuts from a cone of newspaper. Chukwu was twenty-two and had been conducting since he was fifteen and had the kind of institutional knowledge that came from years of watching how things actually worked as opposed to how people said they worked.\n"I need a way around the levy," Seun said, sitting beside him without preamble.\nChukwu offered the groundnuts. Seun took a small handful.\n"Around it how?"\n"Any way. Defer it. Reduce it. Trade something for it."\nChukwu chewed thoughtfully. "You know what I tried last year? I went to one of Ruka''s coordinators. Not Ruka himself. The man below him, Coordinator Dayo. I figured maybe there was a junior rate for new conductors. An introductory thing."\n"And?"\n"Dayo told me the levy was the levy. But." Chukwu held up a finger. "He said if I brought in two new conductors who registered with the union, he would waive my first month. Like a referral thing."\nSeun turned this over. "So you find him people to tax and he lets you off once."\n"Exactly. And then next month you''re still paying full rate plus you''ve brought two more people into the system." Chukwu shook the groundnut cone and a few more fell into his palm. "That''s the whole thing, Seun. Every angle they give you leads back inside the system. There is no outside."\n"There has to be something."\nChukwu looked at him with the patience of someone who had already spent the energy Seun was currently spending and arrived somewhere quieter. "You know what the outside looks like? You work a route with no union backing and for a few days nothing happens. Then one morning a group of boys you''ve never seen before tell you to step off the bus. Not Ruka. Not his coordinators. Just boys. And you step off because the alternative is worse than stepping off." He folded the top of the groundnut cone carefully. "That''s the outside."\nSeun stared at the ground. The motor park moved around them, the usual afternoon noise of it, and it struck him for the first time as a sound that could turn hostile. The same voices. The same engines. But pointed in a different direction.\n"What about a loan?" Seun said. "Five thousand naira. If I could borrow it somewhere I could pay the first month and buy time to figure out the rest."\n"From who?"\nSeun thought about this. His mother, which was immediately impossible, not just because she didn''t have it but because borrowing it from her meant explaining why he needed it, which meant the route, which meant the conversation he had been managing the shape of since he started working. Uncle Femi, who was already absorbing his own levy costs and had said nothing about it because Uncle Femi was the kind of man who absorbed things quietly until he stopped. Razor, who spent money the same day he made it and was proud of this as though it were a philosophy.\nThere was nobody.\nHe had built the plan to be self-sufficient. Every number in the notebook was a number he was generating himself, because depending on other people''s money was a variable he hadn''t wanted in the equation. It had felt like discipline. Now it felt like a wall he had built around himself without realizing which side he was on.\nHe took another small handful of groundnuts.\n"The levy deadline is in three days," Chukwu said. "After that Ruka starts enforcing."\n"I know."\n"You have the money?"\nSeun looked out at the park. Two yellow danfos nosed past each other near the Ojota bay. His bay. He could see the newer bus from here, already loaded for an afternoon run, and though he couldn''t see Olamide from this distance he knew exactly where Olamide was standing because he knew that door frame the way he knew the back of his own hand.\n"Not yet," he said.\nChukwu nodded and said nothing, which was the most honest response available. The groundnut cone was almost empty. Somewhere in the park a conductor was shouting fares and for a moment the voice sounded like Seun''s own, the same rhythm, the same upward pull, and then it didn''t.\nHe had three days.\nThe notebook had eleven thousand, two hundred naira in it and every single one of those naira was already spoken for.\nHe stood up, straightened his shirt, and went back to work.','\n',char(10)),1412,1,1,NULL,'2026-04-08 20:19:45','2026-04-08 01:35:49','2026-04-08 20:19:45',NULL,1,NULL);
INSERT INTO "chapters" ("id","novel_id","chapter_number","title","content","word_count","is_premium","is_published","audio_url","published_at","created_at","updated_at","scheduled_release_at","part_number","season_id") VALUES(229,30,6,'The Offer',replace('\n\nSeun was counting the day''s earnings behind Uncle Femi''s bus when Olamide found him.\nIt was that hour when the park thinned out, the rush traffic done, the evening crowd not yet arrived, and the light over Oshodi turned the colour of old copper. Most of the conductors had drifted toward food or conversation or both. The bay was quiet. Seun had chosen it deliberately. He needed to run the numbers one more time because running them again was the only thing left that felt like doing something.\nOlamide came around the back of the bus without announcing himself and stood there with his hands in his pockets, which was something he had always done when he was working up to saying something he didn''t want to say. Seun remembered this the way you remembered things about people you had once known in a different version of your life.\nHe kept counting.\n"I heard you went to Mallam Sule," Olamide said.\n"Word travels fast."\n"It''s a small park."\nSeun finished counting and folded the notes. He looked up. Olamide had changed out of his conductor''s vest and was wearing a plain blue shirt, which made him look younger, closer to the thirteen-year-old who had once stood in a broken-generator yard laughing at a plan gone wrong. Seun set that thought aside.\n"What do you want, Olamide?"\nOlamide pulled his hands from his pockets and sat on the rear bumper of the bus, uninvited, the way he had sat on the wall four days ago, and the day before that he had been on Seun''s route calling Seun''s fares, and before that he had been a boy on another street who did not know any of this was coming.\n"I want to tell you something that I was told not to tell you," Olamide said.\nSeun said nothing.\n"Ruka chose this route specifically. Not because of the passenger volume, though that''s part of it. Because of you." Olamide looked at him steadily. "Someone told him you were operating independently. No union backing, no levy, no registration. Just a sharp boy running a clean route with a loyal passenger base and no attachment to anyone he could pressure. That kind of conductor bothers men like Ruka. You were always going to be a target. The timing is just now."\nThe copper light shifted. A bus somewhere in the park turned its engine over and the sound rolled across the tarmac.\n"Who told him?" Seun asked.\nOlamide looked at the ground briefly. "I don''t know for certain."\n"But you have a thought."\n"A thought isn''t a fact."\nSeun let this go for now because pulling at it would unravel things he needed to stay whole for the next few minutes. "Why are you telling me this?"\n"Because you deserve to know the shape of what you''re dealing with." Olamide leaned forward, elbows on knees. "And because Ruka has a proposal."\nThe word sat between them. Seun watched Olamide''s face for signs of what to do with it and found nothing comfortable.\n"He sent you."\n"He doesn''t know I''m here. This is me telling you separately so you can think about it before it becomes official." Olamide paused. "His proposal is this. You come under his registration. Not as an independent conductor but as part of his network. The bus you work, the route you work, everything stays the same. But the bus belongs to one of his fleet operators and your earnings go through his system. You get a cut. Fixed percentage."\n"How much?"\n"Forty percent of daily collection."\nSeun did the arithmetic without reaching for the notebook because he didn''t need to. Forty percent of his best days was roughly the same as his worst days now. And on the bad days, forty percent of nothing was nothing. He had been taking home sixty, sometimes seventy percent of collections after Uncle Femi''s costs. Forty percent was not survival money. Forty percent was the wage of someone who had lost.\n"He wants me to work my own route for less than I''m making now," Seun said.\n"He wants you inside the system," Olamide said. "The percentage is the starting point. It moves upward if your numbers are consistent. That''s how it works for everyone who comes in."\n"That''s how it works for everyone he''s already caught." Seun stood up straight. "This is not a proposal. This is a trap with a number attached to it."\n"It''s a way to keep working."\n"It''s a way to keep working for him."\nOlamide stood up from the bumper. He was an inch taller than Seun and the inch felt more significant than it had when they were younger. "I know what it looks like. I know what it costs. But Seun," he stopped, and something in his voice lost its careful levelness for the first time since these conversations had started, "the deadline is tomorrow. After tomorrow he stops asking. And the version of this that comes after asking is not something I can help you with."\nThere it was. Under the offer, under the concern, under the honesty about the route being targeted. A wall. The same wall every door in the last three days had been made of, just closer now, close enough to feel the temperature of it.\n"You said you can''t help me," Seun said slowly. "That means you have been helping me. Coming here. This conversation."\nOlamide said nothing.\n"Did you volunteer for this route or did someone choose you for it?"\nThe silence lasted long enough to be an answer.\n"They put you here because you know me," Seun said. It was not a question. The understanding arrived fully formed, the way understanding sometimes did when you had been holding pieces without realizing they connected. "Because they thought if it was you on my route I would either back down or negotiate. Because they knew I wouldn''t just fight a friend the way I would fight a stranger."\nOlamide''s jaw tightened. "It''s more complicated than that."\n"Is it?"\n"I needed the work, Seun. That part was true. I told you that."\n"And the rest?"\nOlamide looked at him, and in the copper evening light his face was difficult to read, layered with things that may have been shame or may have been the practiced expression of someone who had decided shame was a cost of doing business and had paid it early to get it over with.\n"I''m still your friend," Olamide said quietly.\nSeun looked at him for a long moment. He thought about the football with the slow puncture, and eleven days of silence, and a sachet of pure water held out like a peace offering. He thought about the two of them at twelve and thirteen, making plans on a street in Mushin that neither of them had the language yet to know were plans, just dreaming out loud the way boys did before the world taught them that dreaming out loud was expensive.\nHe thought about eleven thousand, two hundred naira under a floorboard. Fourteen thousand needed. A deadline that was now tomorrow. A mother who did not know the shape of the thing her son was trying to survive.\n"Go home, Olamide," he said.\nOlamide stayed a moment longer, like he was waiting for something else, some version of this conversation that ended differently. Then he pushed off the bumper, straightened his shirt, and walked away into the thinning park without looking back.\nSeun stood behind the bus alone. The copper light was going now, bleeding out of the sky the way it did every evening, turning everything gray and then darker than gray. He could hear the park settling into its nighttime sounds, different from the daytime ones, lower and slower. Around him the yellow buses sat in their rows like patient animals.\nTomorrow the deadline passed. After tomorrow Ruka stopped asking.\nHe had the notebook. He had the numbers. He had a plan that had made sense for two years and was now standing in a space the plan had never been designed to occupy.\nHe did not know what he was going to do.\nHe stood there for a long time, not deciding, just standing, while the last of the light went out of the sky over Oshodi and the park filled up with dark.','\n',char(10)),1393,1,1,NULL,'2026-04-08 20:19:54','2026-04-08 01:36:51','2026-04-08 20:19:54',NULL,1,NULL);
INSERT INTO "chapters" ("id","novel_id","chapter_number","title","content","word_count","is_premium","is_published","audio_url","published_at","created_at","updated_at","scheduled_release_at","part_number","season_id") VALUES(249,36,1,'The Thing Nobody Said',replace('\n\nThe crack in a family secret never announces itself. It arrived the way Emeka''s did: on a Tuesday afternoon, inside a government office that smelled of old paper and someone else''s jollof.\nHe was there for his WAEC attestation form. Routine. His mother had handed him a folder that morning without looking up from her phone birth certificate, passport photograph, school ID and told him to take a danfo because she needed the car. Emeka had not thought anything of it. Not until the woman behind the counter held his birth certificate up to the light, the way you do when you are checking something, and then looked at Emeka, and then looked at the certificate again.\n"Your father''s name," the woman said.\n"Chukwuemeka Obi." Emeka pointed at the top line. "That''s me."\n"Your father''s name," she said again, and turned the form around.\nHe looked. He had seen his birth certificate before, the way you look at a thing you have never needed to study. But he looked now, properly, and the name printed in the Father column was not Obiora Chidi Obi, which was his father''s name. It was not any name he recognized at all.\nHis mother''s signature was there on the Mother line he knew her handwriting the way he knew the sound of her voice, slightly slanted, the loop on the A always too wide. That was real. That was solid.\nThe name beside Father was typed, not handwritten, and it belonged to nobody he had ever heard spoken inside his house.\nIkenna Duru.\nThe woman behind the counter had already moved on, stamping something, sliding his certificate back into the folder with the boredom of someone who had seen ten thousand documents that morning. Emeka took it. He thanked her because his mother had raised him to thank people. He walked out of the office and stood in the car park and read the name again in the white afternoon light.\nIkenna Duru.\nHe said it quietly, barely a breath, the way you test the weight of a thing before deciding whether to lift it.\nHis father Obiora Obi, who had driven three hours in the rain once because Emeka called from a friend''s house sounding miserable, who still showed up to every school prize-giving even when Emeka stopped winning prizes, who burned omelets every Saturday morning and refused to admit it that man''s name was not on this certificate.\nA motorcycle horn shrieked behind him. A woman walked past with a baby tied to her back, the baby watching Emeka with large, expressionless eyes, as if it already knew things he was only beginning to learn.\nHe put the certificate back in the folder. He put the folder in his bag. He texted his mother: Done. Coming home. Two blue ticks appeared almost immediately. She did not reply.\nOn the bus, he sat by the window and watched Lagos move past him. The yellow danfos cutting into lanes without apology. A hawker balancing a tray of cold drinks on her head with the ease of someone who had never heard of gravity. A boy his age selling phone chargers at a standstill in traffic, meeting Emeka''s eye through the glass and then looking away, already on to the next window.\nHe thought about things he had not thought about in years.\nThe way his parents sometimes stopped talking when he entered the parlour. He had always read that as adult business, the kind that did not involve him. The way his mother''s relatives looked at his father at family gatherings, a look that was polite but never fully warm. He had chalked that up to in-law tension, ordinary and forgettable.\nHe thought about his own face.\nHe had his mother''s nose, everyone said so without being asked. But his jaw, his height, the shape of his hands long fingers, wide knuckles, a geography that belonged to nobody in any photograph on any wall in their house. Whenever he had raised it, his parents had shrugged and said these things skipped generations. Genes were unpredictable. You could not account for everything.\nHe had believed them because there was no reason not to.\nThe bus lurched to a stop. The conductor leaned out and shouted a street name into the heat. Emeka did not move, even though it was his stop.\nIkenna Duru.\nHe knew what he was sitting with. He was not stupid, and he was not a child, and seventeen years of living with two people who loved him had not prepared him for this particular kind of knowing. He would go home. He would eat whatever was on the stove. He would greet his father when he came back from the office. He would do his homework and say goodnight and none of it would feel the same because he would be doing all of it with a name folded inside his chest like a second heartbeat.\nThe conductor shouted again. Emeka stood, squeezed past a woman with shopping bags, and stepped off the bus into the noise and heat of his neighbourhood. Children chased a ball near the gutter. A generator hummed from somewhere above. The smell of pepper soup drifted from the buka at the end of the street.\nEverything looked exactly the same.\nHe walked home slowly, and the name walked with him, and he did not yet know what it wanted.','\n',char(10)),903,0,1,NULL,'2026-04-09T00:06:41.564Z','2026-04-09 00:06:41','2026-04-09 00:06:41',NULL,1,20);
INSERT INTO "chapters" ("id","novel_id","chapter_number","title","content","word_count","is_premium","is_published","audio_url","published_at","created_at","updated_at","scheduled_release_at","part_number","season_id") VALUES(250,36,2,' Other People''s Fathers',replace('\n\nHe did not ask. That was the thing that surprised him most about himself how easily he carried it.\nThree days had passed since the government office, since the name on the certificate, since he had stepped off the bus into a neighbourhood that looked the same but wasn''t. Three days of eating dinner across from his parents, watching his father argue with the television during the news, watching his mother refill everyone''s water without being asked. Three days of waiting to feel something simple. Anger, maybe. Or the clean, clarifying kind of grief. Instead what he felt was a low, persistent attention, the way you notice a sound in the wall you cannot place and start listening for it in everything.\nHe was listening now.\nFriday afternoon, and Emeka was at Tunde''s house because Tunde had a generator and a new PlayStation and no patience for why either of those things should be elsewhere. They were in the parlour, controllers in hand, a bag of chin-chin between them on the cushion, and Tunde was losing badly and pretending he wasn''t.\nTunde''s father came in from work at half past four.\nEmeka had seen this a hundred times. Uncle Femi thick through the shoulders, always in a senator, always smelling faintly of the inside of a nice car dropped his briefcase by the door and said, "Tunde, did you fix that light in your room like I asked?"\nTunde paused the game. "I forgot."\n"You forgot." His father looked at the ceiling, the way fathers did, asking God for patience. Then he looked at Emeka. "How are you, Emeka? Your people are well?"\n"Yes sir, we''re fine sir."\nUncle Femi nodded, picked up his briefcase, ruffled Tunde''s hair on the way past Tunde batted his hand away, annoyed, the way sons were annoyed by fathers and disappeared into the back of the house.\nTunde unpaused the game.\nEmeka held his controller and did not play.\nHe was looking at the empty doorway where Uncle Femi had just been. There was nothing to see there. Only the hallway, the family photographs on the wall, a pair of dress shoes lined up neatly near the entrance.\n"Your ball," Tunde said.\nEmeka turned back to the screen.\nThe thing about watching other people''s fathers was that you had to be subtle about it. If you stared, they noticed, and then they asked questions, and Emeka was not ready for questions from anyone, least of all himself.\nBut he was watching. He had been watching all week.\nAt school, he watched Mr. Okafor drop off his son in the blue Toyota every morning, the same car, the same time, and how his son climbed out without saying goodbye but Mr. Okafor always waited until he was inside the gate before he drove away.\nHe watched his classmate Akin on the phone at break time, half-laughing, half-complaining, saying, "Dad, I''m serious, that''s not how it works," and then laughing properly at whatever the response was.\nHe watched a man on his street lift a small girl onto his shoulders without warning, the girl shrieking with surprise then delight, the man steadying her ankles with both hands, both of them laughing at nothing in particular.\nHe was cataloguing something. He understood that even if he could not name it precisely. He was building a case, gathering evidence of what it looked like when a thing was real. When it was simply, straightforwardly real.\nAnd then he would think about his own father Obiora Obi, who showed up and burned omelets and drove three hours in the rain and the case would fall apart, because what he had was also real. The evidence was twenty years of lived mornings, not just the biology behind them. He knew that. Knowing it did not stop the listening.\nSaturday, and his father knocked on his bedroom door after breakfast.\n"Come out. I want to show you something."\nHis father''s car was in the compound, the bonnet up, and his father was in old clothes the way he only got on weekends, the kind of old that meant real comfort. He handed Emeka a rag and pointed at the engine.\n"Your uncle taught me this," his father said, his hands moving over parts Emeka couldn''t name. "His own father taught him. That''s how these things go."\nEmeka held the rag. He looked at his father''s hands. Wide knuckles, long fingers.\nHe looked at his own.\n"What are you looking at?" his father asked, without turning.\n"Nothing." Emeka crouched beside him. "Show me again."\nHis father showed him. He explained each thing patiently, without condescension, the way he always did, as if Emeka''s understanding mattered personally to him. The sun came down into the compound and a neighbour''s radio played something old and Yoruba from over the fence, and for a few minutes Emeka forgot the name in the folder and only felt the concrete under his feet and the warmth of the engine and his father''s voice moving through the still morning air.\nThen his father said, "You''ve been quiet this week."\nEmeka kept his eyes on the engine. "School stress."\nA pause. One beat too long.\n"Okay," his father said.\nOne word. Okay. But the pause before it had lived somewhere specific, the way a pause only lives when a person is deciding not to say the thing that actually fits. Emeka knew that pause now. He was beginning to understand the whole grammar of what wasn''t being said in this house, and the lesson was coming fast.\nHis father handed him a wrench. "Hold this."\nEmeka held it. He did not look up.\nAbove them, the sky was enormous and indifferent, the kind of blue that had nothing to say about the small human business happening beneath it. Somewhere over the fence the radio was still playing. The song was something about home, and missing it, and how you couldn''t always go back to the place that made you.\nEmeka turned the wrench in his hands and said nothing, and neither did his father, and the silence between them was the most honest conversation they had managed all week.','\n',char(10)),1030,0,1,NULL,'2026-04-09T00:09:00.216Z','2026-04-09 00:09:00','2026-04-09 00:09:00',NULL,1,20);
INSERT INTO "chapters" ("id","novel_id","chapter_number","title","content","word_count","is_premium","is_published","audio_url","published_at","created_at","updated_at","scheduled_release_at","part_number","season_id") VALUES(251,36,3,' What the Death Brought In',replace('The call came on a Wednesday night, and it rearranged everything.\nEmeka was in his room when he heard his mother''s voice change in the parlour not louder, just different, the way a person''s voice goes when the news is the kind you sit down to receive. He came to the doorway and she was already sitting, phone pressed to her ear, her free hand flat on her knee the way she held herself when she was keeping something in.\nHis father was watching her from the other chair.\nShe hung up and said, "Mama Ifeoma is gone."\nHis father closed his eyes briefly. Opened them. "When?"\n"This evening. They''re saying next Saturday for the burial."\nEmeka leaned against the doorframe. He knew Mama Ifeoma the way you knew very old relatives from photographs and occasional visits where they held your face in both hands and called you by the wrong name, or the right name said in a voice so full of something you couldn''t quite receive it. She was his mother''s aunt. Or his mother''s mother''s cousin. The exact line had never been made clear to him, and he had never pushed, because in his family the extended network was large and tangled and everyone simply belonged to everyone else in ways that did not require explanation.\n"We''ll all go," his mother said. It was not a question.\nHis father nodded.\nHis mother looked at Emeka then, just for a moment, and something passed across her face that was too quick to catch. Then she stood up and went to the kitchen, and the sound of her moving pots around came through the wall, and his father picked up the remote and lowered the television volume and stared at the screen without watching it.\nEmeka went back to his room.\nHe lay on his bed and looked at the ceiling and thought about the word all.\nThe drive to Enugu took six hours because his father refused to fly for anything under eight hours of travel time, a principle he held with the conviction of a man who had decided it once and never revisited the decision. They left before five in the morning, his mother in the front seat with a bag of snacks she had packed the night before, Emeka in the back with his headphones and the particular loneliness of highway travel before sunrise.\nThe roads changed as they left Lagos. The air changed. The landscape opened up, and the green that came with it was a different green from the city, deeper and less apologetic.\nHis mother passed chin-chin to the back seat without turning around. He took it. She turned the radio to a station playing highlife and his father made a sound that was almost contentment. This was the version of his family Emeka had always known the travelling version, easy in small ways, the tight domestic arrangements loosened slightly by motion and distance.\nHe watched the back of their heads and felt, for no reason he could defend, a sudden and terrible tenderness for both of them.\nHe put his headphones in and looked out the window and did not sleep.\nThe compound in Enugu was already full when they arrived.\nThis was how it worked in his mother''s family the dead had not yet been buried and the living had already gathered from six states, cars parked on both sides of the road, children running between legs, the smell of cooking coming from three different directions, aunties in matching aso-ebi fabric moving with the coordinated efficiency of people who had done this before.\nHis mother was absorbed within minutes. An aunt took her arm. Two women pulled her aside for the kind of conversation that happened in low voices near doorways. His father found the men gathered under the canopy in the compound, accepted a handshake and a seat, and became part of that circle with the ease of a man who understood the choreography.\nEmeka stood with his overnight bag and watched all of it and knew nobody''s name.\nA boy about twelve appeared at his elbow. "You''re Aunty Ngozi''s son."\n"Yes."\n"I''m Chidi. My mum is Aunty Adaeze."\nEmeka shook the boy''s hand because the boy had offered it with the seriousness of an adult, and it deserved a serious response. "I''m Emeka."\n"I know," Chidi said. "Everyone knows who you are."\nBefore Emeka could ask what that meant, Chidi had spotted something across the compound and sprinted toward it, leaving Emeka with the statement sitting in the air between him and nobody.\nEveryone knows who you are.\nHe told himself it meant nothing. He was Aunty Ngozi''s son, which made him known by default. That was how these things worked.\nHe told himself that.\nHe went to find a place to put his bag.\nThe evening gathered the family into the main parlour for prayers, then food, then the slow comfortable collapse of people who had been travelling and had now stopped. Emeka sat with his plate and ate and listened to conversations he was not part of. His Igbo was functional but not fast enough for the way people spoke at full speed when they were comfortable, so he caught words and edges and let the meaning wash past him.\nHe was watching the room the way he had been watching things all week cataloguing, paying attention.\nThat was how he saw the woman notice him.\nShe was older, sixties maybe, with the upright posture of someone who had once been formidable and still remembered it. She was looking at him from across the room with an expression he could not immediately read. Not hostility. Not the generic warmth of a relative who had forgotten his name. Something more deliberate than either.\nWhen she saw him looking back, she turned to the woman beside her and said something quietly. The other woman looked at Emeka too, then away.\nHis mother was two seats down from him. Emeka watched her face for the rest of the evening the way you watched a road for potholes carefully, without wanting to find any.\nHe found one.\nAt the moment the older woman stood to leave the room, his mother''s eyes followed her. Just for a second. And in that second his mother''s expression did the thing it had done on the phone the night of the news it held something in, tightened briefly, then released back into the face she showed the world.\nEmeka ate the rest of his food.\nThe generator hummed outside. Someone''s child was crying in another room. A man near the door was telling a story that kept making people laugh, and the laughter was the warm, unguarded kind that came from people who had known each other long enough to mean it.\nEmeka sat inside all of it and felt the distance between himself and everyone in the room, and could not tell whether the distance was new or whether he was only now measuring it.\nTomorrow was the burial. The compound would be even fuller. There would be more people, more eyes, more rooms he didn''t know the history of.\nHe thought about the older woman and the look she had given him.\nHe thought about what Chidi had said.\nHe cleaned his plate, excused himself from nobody in particular, and went to find the room where they had put his bag.\nOutside his window, the night was thick and dark and full of insect sound, and the compound lights threw long shadows across the yard. He lay on the narrow mattress they had set up for him and stared at the ceiling.\nHe had the feeling, specific and unignorable, that this house knew something about him.','\n',char(10)),1294,0,1,NULL,'2026-04-09T00:11:25.993Z','2026-04-09 00:11:26','2026-04-09 00:11:26',NULL,1,20);
INSERT INTO "chapters" ("id","novel_id","chapter_number","title","content","word_count","is_premium","is_published","audio_url","published_at","created_at","updated_at","scheduled_release_at","part_number","season_id") VALUES(252,36,4,'The Man Who Looked Away',replace('The burial was loud in the way that Igbo funerals were loud not with grief, exactly, but with the full weight of a life being accounted for in public.\nMama Ifeoma had lived eighty-one years and the crowd reflected every one of them. The canopy in the compound had been extended overnight and still wasn''t enough, so chairs spilled out past the gate and down the road, and the women in the family''s aso-ebi filled the space with colour so dense it was almost sound. A live band set up near the entrance played songs Emeka didn''t know the words to but whose feeling he understood something between celebration and mourning, the way the two things became the same thing when a person had lived long enough.\nEmeka sat in the third row with his parents and kept his eyes moving.\nHe had learned in three days that this family gathered in layers. The innermost ring was blood his mother''s generation and above, the ones who had grown up in this compound or near enough to it. Then came the married-ins, the ones who belonged by attachment and had earned their place over years. Then the outer ring, the extended and the associated, people connected by business or geography or the long memory of a debt repaid. Everyone understood which ring they occupied. The ceremony made it visible.\nHis father was in the second ring. Emeka watched him navigate it without complaint greeting the right people, deferring in the right moments, accepting the role of husband-of without making it smaller than it was. He was good at this. He had always been good at this.\nEmeka was thinking about that about what it cost a man to be good at belonging to a family that had never fully opened the door when the man arrived.\nHe came in from the side entrance, the one that led from the back of the compound, which meant he was family enough to know it existed. He was tall, somewhere in his late forties, with the kind of lean that suggested he had once been heavier and the weight had left without announcement. He wore a plain black agbada, no embroidery, no accessories, and he moved through the crowd with the specific quietness of someone who did not want to be the story of the day.\nEmeka noticed him the way you noticed a change in temperature. Not dramatic. Just present.\nThe man found a seat at the edge of the canopy, three rows back and to the left, slightly apart from the people nearest to him. He greeted the woman beside him with a nod. He did not talk. He folded his hands in his lap and watched the ceremony with an expression that was respectful but interior, the kind of face a person wore when they were somewhere they felt they had complicated right to be.\nEmeka looked away. The pastor was speaking. His mother''s head was bowed.\nHe looked back.\nThe man was looking at him.\nNot the way people looked when they were scanning a crowd. Not the polite recognition of a relative who thought they should probably know your name. This was direct and full and lasted one second longer than accidental the kind of look that arrived from somewhere it had been waiting.\nThen the man looked away.\nEmeka''s chest did something he had no word for. Not quite pain. Not quite recognition. Something that lived between the two.\nHe stared at the man''s profile. Late forties. Lean. The black agbada. Hands folded in his lap. He was not looking at Emeka now. He was watching the pastor with careful attention, giving the ceremony his full and deliberate face, and the deliberateness of it was its own kind of information.\nEmeka looked down at his own hands.\nHe did not look up for a long time.\nThe reception after was the louder, longer thing. Food came out in quantities that suggested the family had been cooking for two days, which they had. Music started. The older women danced first, the formal dance of women who had earned the right to take up space, and then the floor opened and the formality dissolved.\nEmeka moved through it carefully, plate in hand, trying to triangulate without being obvious about it. He lost the man twice in the crowd before finding him again near the far end of the canopy, standing now, talking to an elderly uncle whose name Emeka didn''t know.\nHe was close enough, twenty feet maybe, to see the man''s face properly in the afternoon light.\nHe stopped moving.\nThe jaw. The particular line of it, the way it sat slightly forward. The shape of the hands long fingers, wide knuckles. He had been looking at those hands his whole life. He saw them every time he looked at his own.\nThis was not resemblance the way people said you had your mother''s nose or your grandfather''s ears, the soft genetic echo that families passed around like a shared recipe. This was a mirror with twenty years in between. This was structural. This was bone.\nEmeka stood with his plate and the noise of the funeral carried on around him and he felt the ground do something it had never done before, a kind of subtle unreliability, as if the compound floor was still solid but the idea of it was no longer guaranteed.\nThe man finished his conversation with the uncle. He turned. His eyes moved across the compound in the way eyes moved when you were looking for the nearest exit, and they passed over Emeka once, and then they stopped, and the two of them stood twenty feet apart in the middle of a crowded funeral and saw each other.\nOne second.\nTwo.\nThe man looked away first.\nHe set down his drink on the nearest table, said something brief to the person beside him, and walked back toward the side entrance, the one that led to the back of the compound, moving with the calm of a man who was not running but had decided it was time to be somewhere else.\nEmeka watched him go.\nHis plate was still in his hands. The food on it had gone cold. Somewhere behind him his mother was laughing at something, the full unguarded laugh she only produced around her own people, and the sound of it reached him like a transmission from another country.\nHe stood where he was until the man was gone.\nThen he stood there a little longer.','\n',char(10)),1096,1,1,NULL,'2026-04-09T00:14:22.703Z','2026-04-09 00:14:22','2026-04-09 00:14:22',NULL,1,20);
INSERT INTO "chapters" ("id","novel_id","chapter_number","title","content","word_count","is_premium","is_published","audio_url","published_at","created_at","updated_at","scheduled_release_at","part_number","season_id") VALUES(253,36,5,' Blood Type',replace('He had a name and a face. What he did not have was a single person he could ask.\nThat was the shape of the problem as Emeka understood it on the drive back to Lagos, watching the highway unroll behind a smeared window while his parents talked softly in the front about the funeral, about who had aged, about the food, about the drive home taking longer than expected because of roadworks near Ore. Normal conversation. The kind that filled a car without asking anything of anyone.\nHe had his phone in his lap and his headphones in and the music turned low enough that he could still hear them, and he sat like that for four hours, turning the man''s face over in his mind the way you turned a coin, looking for the inscription.\nBack in Lagos, back in his room, he opened his laptop.\nHe started where anyone started. He typed Ikenna Duru into the search bar and pressed enter and waited.\nThere were results. There were always results. The problem was that Ikenna Duru was not a rare name, and the internet did not know which one he meant. There was a lawyer in Abuja with the name. A footballer from the nineties with a brief Wikipedia page and no photograph. A memorial post from 2019 for someone who had died at forty-three. A business registration in Anambra. Three Facebook profiles, one with a locked privacy setting, one that had not been updated since 2016, one that belonged to a man who was clearly too young.\nHe refined the search. Ikenna Duru Enugu. Then Ikenna Duru Nigeria. Then, with the specific feeling of a person crossing a line they had decided to cross, Ikenna Duru Ngozi.\nNothing that meant anything.\nHe sat back and looked at the ceiling.\nThe problem with digging into a secret was that the people who had buried it were usually careful. His mother was a careful woman. He had always understood that about her, the way she thought three moves ahead in every situation, the way she kept her feelings in a place that required effort to access. That quality had always seemed like strength to him. He was revising the inventory of what it could mean.\nAt school the next day he found Tunde at their usual spot under the staircase at break time and said, without preamble, "If you wanted to find out if someone was related to you, how would you do it?"\nTunde looked up from his phone. "What kind of question is that?"\n"A hypothetical one."\n"Is it a hypothetical one or is it a you one?"\nEmeka said nothing. Tunde looked at him for a moment, then sat up straighter, which was his version of paying attention.\n"DNA test," Tunde said. "My cousin did one. One of those online ones. You spit in a tube and they tell you everything."\n"What kind of everything?"\n"Like your ancestry. And if other people on the platform match your DNA they show up as relatives. Cousins and that. Close family shows up stronger." He shrugged. "She found out she had a half-sibling in London she didn''t know about. Her dad had a whole situation before he married her mum."\nEmeka absorbed this.\n"How much does it cost?"\nTunde told him. Emeka did the conversion in his head and felt the number sit heavily against what he had saved from three months of managing his transport money.\n"You can get them cheaper on Jumia sometimes," Tunde said, watching him with the careful non-intrusiveness of a good friend who had decided not to ask. "Delivery takes a while though."\n"Okay."\n"Emeka."\n"I''m fine."\nTunde picked his phone back up. "Okay," he said, in the tone of someone filing something away for later.\nThat evening Emeka went looking in the house.\nHe did not know exactly what he was looking for. Documents, maybe. The kind of thing parents kept in the steel cabinet in his father''s study, the one that was never locked because his father believed that a locked cabinet in your own house was an insult to your own family. Emeka had been in that cabinet before for school forms, vaccination records, the car papers. He knew what lived in there.\nHe went in while his father was at evening prayers at the parish and his mother was on the phone in the bedroom, her voice low and continuous, the cadence of a long conversation.\nHe went through the files carefully, touching nothing out of order.\nHis own documents were there — immunisation booklet, his primary school leaving certificate, his WAEC registration. Underneath those, his parents'' marriage certificate, dated twenty-three years ago, which he already knew. His father''s business papers. His mother''s international passport and an old Nigerian one expired since 2009. Vehicle documents. Property papers for the house in the village his father had been building for ten years without finishing.\nHe almost missed it.\nIt was in an envelope at the back of the cabinet, unsealed, slightly thicker than the others. No label. He hesitated, then opened it.\nInside were two things. A printed email, old enough that the paper had gone slightly yellow at the edges, and a photograph he had never seen before.\nHe looked at the photograph first.\nHis mother, younger, standing outside a building he didn''t recognise. She was laughing at something outside the frame. She was visibly pregnant.\nStanding beside her, not touching her but close, was a man.\nA tall man. Lean. A jaw that sat slightly forward. Long fingers wrapped around a bottle of malt.\nEmeka knew the face. He had been looking at a version of it in the mirror his whole life.\nHe put the photograph back. He put the envelope back. He closed the cabinet and stood in his father''s study and listened to his mother''s voice coming through the wall, still talking, the words indistinct, the tone the one she used with people she trusted.\nHis hands were not shaking. He noticed that with a kind of distant surprise. He had expected them to shake.\nHe left the study and went to his room and sat on the edge of his bed and looked at his hands and thought about a DNA test he could not afford and a photograph he was not supposed to have seen and a man at a funeral who had looked at him and then walked away.\nThe face in the photograph and the face at the funeral were the same face.\nHe had known that before he opened the envelope. He had walked into his father''s study already knowing it.\nWhat he had needed was for it to stop being something he could talk himself out of.\nIt had stopped.','\n',char(10)),1131,1,1,NULL,'2026-04-09T00:15:57.752Z','2026-04-09 00:15:57','2026-04-09 00:15:57',NULL,1,20);
INSERT INTO "chapters" ("id","novel_id","chapter_number","title","content","word_count","is_premium","is_published","audio_url","published_at","created_at","updated_at","scheduled_release_at","part_number","season_id") VALUES(254,36,6,'His Mother''s Hands',replace('He waited four days. Not because he wasn''t ready but because he needed to find the right version of ready.\nThere was a version where he came in hot, the photograph metaphorically on the table, demanding the full story in one sitting. He had rehearsed that version twice in the shower and both times it had ended badly in his head, his mother closing like a door and him standing on the wrong side of it with nothing new. There was a version where he was calm and surgical, one precise question, no emotion. That version felt dishonest in a way he couldn''t fully explain. He had emotion. Pretending otherwise was just another kind of silence, and this family had enough of those.\nHe waited until Saturday morning when his father left for the hardware store, a trip that always took two hours because his father treated hardware stores the way other men treated barbershops, as places of unhurried social transaction.\nHis mother was in the kitchen, standing at the counter with her back to the door, shelling ede into a bowl. The late morning light came through the window above the sink and sat on her shoulders and the back of her head and made everything look calm in the way that things looked calm right before they weren''t.\nEmeka sat down at the kitchen table.\nShe did not turn around. "There''s bread on the counter."\n"I''m not hungry."\nShe kept shelling. The sound of it was rhythmic and specific, a small dry percussion that filled the kitchen.\n"Mum."\n"Mm."\n"Who is Ikenna Duru?"\nHer hands stopped.\nNot for long. One breath, maybe two, and then they started again, the same rhythm, the same steady work, but something in the room had shifted the way air shifted before rain and they both knew it.\n"Where did you hear that name?" Her voice was level. She did not turn around.\n"My birth certificate. At the government office. His name is in the Father column."\nThe shelling stopped again. This time it did not resume.\nShe put both hands flat on the counter and stood there with her back still to him, and he watched her shoulders and the particular way she was holding herself, braced, the posture of someone absorbing an impact they had been waiting for.\n"Mum."\n"Emeka." Her voice had something in it now. A weight that hadn''t been there before.\n"Please just tell me."\nShe turned around. Her face was composed in the way that faces were composed when the composure was costing something. She looked at him for a long moment and he looked back and neither of them pretended the question was not in the room.\n"That was a long time ago," she said.\n"That''s not an answer."\n"I know it''s not." She pulled out the chair across from him and sat down and folded her hands on the table, and Emeka recognised the gesture because he did the same thing when he was trying to hold himself together from the outside in. He had never known where he got it from until this moment.\n"You were born," she said carefully, "in a complicated time."\n"Complicated how?"\nShe looked at her hands. "There are things I need to speak to your father about before I can speak to you. This is not something I can do alone."\n"He''s not my father." The words came out before he had decided to say them, flat and precise, and he watched them land on her face.\nShe did not flinch. She absorbed them the same way she had absorbed everything in this conversation, with a steadiness that was either strength or practice or both.\n"Obiora Obi," she said quietly, "has been your father every day of your life."\n"I know that."\n"Do you? Because the way you just said that suggests you have decided it means less than it does."\n"I haven''t decided anything. That''s the problem. I don''t have enough information to decide anything because nobody will tell me anything."\nShe was quiet.\nOutside, a neighbour''s child was crying about something, the sharp ordinary crying of a child who wanted something and hadn''t got it. A okada passed on the street. The refrigerator hummed. All the normal sounds of a Saturday morning continuing without permission.\n"How long have you known?" she asked.\n"Since the government office. Three weeks."\nSomething moved across her face at that. The realisation that he had been sitting with it alone, carrying it through dinners and school days and car repairs in the compound, and had said nothing. He watched her understand that and watched it cost her.\n"You should not have had to carry that alone," she said.\n"No," Emeka said. "I shouldn''t have."\nShe looked away. Outside the window the neighbour''s child had stopped crying. The sudden absence of the sound made the kitchen feel larger.\n"I will talk to your father," she said. "We will sit down together, the three of us, and we will talk properly. I need you to give me that. A few days."\n"You''ve had seventeen years."\nThe words sat between them, not cruel exactly, but exact, and his mother received them with her eyes closed briefly, a gesture so small he almost missed it.\n"Yes," she said. "I have." She opened her eyes and looked at him directly, and for a moment the composure fell away just enough that he could see underneath it, something tired and old and genuinely sorry. "I have, and I know that. And I am asking you for a few more days. Not to hide. To do this the right way."\nEmeka looked at her hands on the table. His hands. The same fold, the same knuckle geography, the same instinct to hold yourself together from the outside in.\nHe thought about the photograph in the envelope. The man beside her, not touching her but close. Her face turned away toward something outside the frame, laughing at something he would never know the content of, in a version of her life that had existed before he did.\n"A few days," he said.\nShe nodded.\nHe pushed back from the table and stood up and she watched him the way she had watched him his whole life, with a specific attention that he had always read as love and still read as love and now understood was also something else. Something that had been waiting for this kitchen and this Saturday and this particular quality of morning light to finally say what it was.\nHe left the kitchen without the bread and went to his room and sat on his bed and stared at the wall.\nShe had not denied it.\nThat was the thing he turned over for the rest of the day, the single clear fact he could hold: she had not denied it. She had deflected and composed and asked for time, but she had not once looked him in the eye and said the name on the certificate was a mistake.\nThe silence was its own kind of answer.\nHe had known that for weeks. Now she knew he knew.\nSomething had shifted, quietly and permanently, and there was no version of the next few days in which they went back to the way things were before he sat down at that kitchen table on a Saturday morning and said a name out loud.','\n',char(10)),1237,1,1,NULL,'2026-04-09T00:17:00.911Z','2026-04-09 00:17:00','2026-04-09 00:17:00',NULL,1,20);
INSERT INTO "chapters" ("id","novel_id","chapter_number","title","content","word_count","is_premium","is_published","audio_url","published_at","created_at","updated_at","scheduled_release_at","part_number","season_id") VALUES(255,36,7,' What Dad Doesn''t Say',replace('His father came back from the hardware store that Saturday with a bag of rawl plugs he didn''t need and a story about running into an old colleague near the paint section, and Emeka sat through the telling of it at lunch and watched his father''s face with the new attention he had been developing for weeks, the kind that looked for what wasn''t there.\nHis mother was quiet through the meal. Not unusually quiet, not the kind that announced itself. Just a few degrees below her normal temperature, enough that you would not notice unless you were already watching. His father either didn''t notice or was performing not noticing, and Emeka could no longer tell the difference.\nHe ate his rice and listened to his father talk and catalogued what he saw.\nThe conversation his mother had promised did not happen that weekend. Monday came and then Tuesday and each evening the three of them moved through the house in their established patterns and nobody sat anybody down and the silence on the subject continued, layered now, thicker, with the new weight of his mother knowing that he knew.\nHe was not exactly waiting. He was watching.\nHe watched his father come home from the office each evening, loosen his tie in the doorway, ask what was for dinner with the same intonation every single day, the rhythm of a man whose domestic life was a thing he trusted completely. He watched him grade papers at the dining table on Wednesday nights because he still took marking home even though he had been head of department for four years and didn''t have to. He watched him fall asleep in the armchair during the nine o''clock news and wake up ten minutes later and insist he had not been sleeping.\nThese were not new observations. Emeka had grown up inside them. What was new was the question running underneath: how much of this man''s life had been built on something he had agreed to carry?\nBecause he had agreed. Emeka was certain of that. His father was not a man who stumbled into things. He made decisions with the full weight of himself and then stood behind them without complaint. Whatever had happened before Emeka was born, whatever the story was that his mother had not yet told, his father had walked into it with both eyes open and had stayed for seventeen years.\nThe question was what that cost a man.\nAnd whether the man would ever say.\nThursday evening his father knocked on his bedroom door and came in without waiting, which was his habit, and sat on the edge of the desk chair while Emeka was at his bed with a textbook.\n"Your mother tells me you''ve been stressed," his father said.\nEmeka looked at him. "She said that."\n"She said school stress. But she said it the way she says things when she means something else."\nHis father''s face was open in the way it only got when they were alone, away from the social performances of gatherings and offices, the version of him that had driven three hours in the rain because his son had called from a friend''s house sounding miserable. He was looking at Emeka with the particular attention of a man who had been paying attention since the beginning.\nEmeka put the textbook down.\nHe wanted to ask. The question was right there, dressed and ready, and he was so tired of holding it inside the house where it lived. He wanted to look his father in the eye and ask him directly: do you know that I know? Did Mum tell you? How long have you known that I was not yours and what did it feel like to decide to stay?\nHe said none of it.\nBecause his father''s face was open and unguarded and sitting in that openness was something Emeka had no other word for but love, not the performed kind, not the kind that wanted credit, the ordinary working kind that showed up on Thursday evenings and knocked on doors and sat on desk chairs because it had noticed something was wrong.\nAnd Emeka understood, with a clarity that surprised him, that some questions could not be asked gently. That some truths, once spoken in a room, rearranged the furniture permanently and you could not put anything back. The conversation his mother had promised had not happened yet and until it did, this room and this man and this Thursday evening were the last of the before.\nHe was not ready to be in the after without warning.\n"I''m okay," Emeka said. "Just exam pressure."\nHis father nodded slowly. He did not look entirely convinced but he did not push, which was also his habit, the respect for a door not fully opened.\n"You know," his father said, looking at the wall, "when I was your age I wrote every worried thought in an exercise book. Just to get it out of my head. Terrible handwriting. Complete nonsense sometimes. But it helped."\n"Did it work?"\n"Sometimes. Sometimes it just looked worse written down." He smiled slightly. "The point is you wrote it. You owned it."\nHe stood up and straightened the desk chair.\n"Food will be ready soon," he said.\nHe was almost at the door when Emeka said, "Dad."\nHis father turned.\nEmeka looked at him. The loose tie. The slightly tired eyes. The face of a man who had been exactly where he said he would be, every single day, for seventeen years.\n"Nothing," Emeka said. "Just. Thank you. For checking."\nSomething moved through his father''s expression, brief and full, gone before it fully arrived.\n"That''s what I''m here for," he said.\nHe pulled the door behind him, not quite closed, the way he always did, the small habit of a man who wanted his son to know the house was still available.\nEmeka sat in the not-quite-closed room and thought about what it meant to choose something. To look at a complicated truth and decide to build a life on top of it anyway. To knock on a door on a Thursday evening and sit on a desk chair and love someone who did not share your blood and never once make them feel the difference.\nHe thought about the name on the certificate and the man at the funeral and the photograph in the envelope and none of it touched what he felt right now, which was the specific grief of someone who was about to understand their father for the first time and wasn''t sure they were ready for what understanding would cost both of them.\nHe picked up the textbook.\nHe could not read a word of it.','\n',char(10)),1127,1,1,NULL,'2026-04-09T00:18:37.484Z','2026-04-09 00:18:37','2026-04-09 00:18:37',NULL,1,20);
INSERT INTO "chapters" ("id","novel_id","chapter_number","title","content","word_count","is_premium","is_published","audio_url","published_at","created_at","updated_at","scheduled_release_at","part_number","season_id") VALUES(256,36,8,' Cousins Know Things',replace('The three days his mother had asked for became ten, and then the ten became two weeks, and no one sat anyone down.\nEmeka stopped waiting for it. Not because he had given up but because he had begun to understand that this was also information. The way a family postponed a thing told you as much about the thing as the conversation itself would. Whatever his parents were circling around, it was large enough that even his mother, who handled difficult things with her hands flat on the table and her voice level, was not ready to stand in the same room as it.\nHe would find another way in.\nHis mother''s cousin Adaeze came to Lagos on a Thursday with her children for a medical appointment, and because she was family she stayed the weekend, and because she was staying the weekend she brought Chidi, the twelve-year-old from the funeral who had shaken Emeka''s hand with the gravity of a diplomat and said everyone knows who you are.\nChidi arrived with a small bag and very large opinions about everything, and within two hours had reorganised Emeka''s bedroom on the grounds that the layout was inefficient, and was now sitting cross-legged on the floor with Emeka''s old PlayStation controller explaining to Emeka how to play a game Emeka had owned for three years.\n"You''re holding it wrong," Chidi said.\n"It''s my controller."\n"And you''re holding it wrong."\nEmeka let him talk. There was something restful about Chidi, the way children who had not yet learned to edit themselves were restful. Everything was on the surface. Nothing required translation.\nThey played for an hour. Chidi won twice and was gracious about neither victory.\nAt the second win he dropped the controller and fell back on the floor dramatically and said, "That one was for Uncle Emeka."\nEmeka looked at him. "What?"\nChidi turned his head. "You don''t know Uncle Emeka?"\n"I''m Emeka."\n"The other one." Chidi sat back up, cross-legged, straightening as if for a proper explanation. "Your mum''s uncle. Her father''s brother. He died before I was born but my mum talks about him sometimes. She said your mum named you after him." He picked up the controller again. "They were close when they were young. That''s what she says."\nEmeka said nothing. He filed this away with the careful quietness he had developed for information that arrived without announcing its importance.\n"Your mum said that?" he asked. Casual. Eyes on the screen.\n"She and Aunty Ngozi were talking at the funeral. I was there but they didn''t notice because I was under the table." He said this without guilt. "My mum said it was sad that you didn''t grow up knowing that side of the family properly."\n"Which side?"\nChidi looked at him with the directness of a child who had not yet learned that some questions were a different shape than they appeared. "Your dad''s family. The other one."\nThe room went very still.\nEmeka kept his face exactly where it was. He was looking at the television screen but he had stopped seeing it. Somewhere in the house his mother and Adaeze were talking in the parlour, their voices low and warm, the cadence of women who had known each other since childhood.\n"What other one," Emeka said.\nChidi had already moved on, his attention back on the game. "I don''t know his name. I just heard them talking. My mum said it was a whole thing." He pressed buttons on the controller. "Are we playing or not?"\n"Yeah," Emeka said. "We''re playing."\nHe picked up his controller and his hands were steady and he played the next round without registering a single moment of it.\nAfter dinner Emeka helped clear the table, which he did not usually do with the level of thoroughness he did it that night, carrying plates to the kitchen in two trips when one would have done, taking his time rinsing, positioning himself close enough to the kitchen doorway that he could hear the parlour without being visible in it.\nHis mother and Adaeze were on the couch. The television was on but neither of them was watching it. They were talking with the easy familiarity of people who had run out of small things to say and moved to the real ones.\nHe caught fragments. That was all. His mother''s voice was lower than Adaeze''s, which made it harder.\nHe heard Adaeze say: you can''t protect him from it forever.\nHe heard his mother say something he couldn''t catch, two or three sentences, her voice going briefly sharp and then settling.\nHe heard Adaeze say: he looks so much like him now, Ngozi. Anyone who knew him will see it.\nThen the television volume went up slightly. Not obviously. Just enough.\nEmeka put the last plate on the rack and dried his hands on the kitchen cloth and went to his room.\nHe sat on the bed.\nHe was building a picture from pieces that were not meant for him and the picture was getting clearer whether anyone wanted it to or not. A man. His mother''s history. A family he had not grown up knowing. A resemblance visible enough that a woman at a funeral had stared at him from across a room, and a twelve-year-old under a table had absorbed more than the adults above him intended.\nHe opened the Notes app on his phone and typed what he had:\nIkenna Duru. Photo in cabinet. Same face at funeral. Mum''s uncle was named Emeka. She named me after him. There''s a family I don''t know. Dad''s family. The other one.\nHe read it back.\nThen he typed one more line.\nAdaeze said: anyone who knew him will see it.\nHe locked his phone and looked at the ceiling.\nThe thing about building a picture from pieces was that at some point you had enough pieces and the image resolved, whether you were ready for it or not. He wasn''t there yet but he was close, and the closer he got the more he felt the thing that waited on the other side of knowing fully, not relief, not resolution, but a door, and behind the door was a question he had been circling for weeks without naming directly.\nNot who is this man.\nNot what happened.\nWhat do I do with it once I know?\nDown the hall the parlour conversation had resumed, quieter now. Chidi was in the bathroom brushing his teeth with the aggressive enthusiasm of a child who had been told twice. His father was watching the news with the volume low.\nThe house moved through its evening.\nEmeka lay back on his bed and looked at the ceiling and turned the door over in his mind and did not yet try to open it.','\n',char(10)),1141,1,1,NULL,'2026-04-09T00:19:55.720Z','2026-04-09 00:19:55','2026-04-09 00:19:55',NULL,1,20);
INSERT INTO "chapters" ("id","novel_id","chapter_number","title","content","word_count","is_premium","is_published","audio_url","published_at","created_at","updated_at","scheduled_release_at","part_number","season_id") VALUES(257,36,9,'The Photograph',replace('He had left something behind in his father''s study.\nHe had known it since Episode Five, since the evening he had opened the envelope and looked at the photograph and put everything back and walked out because the photograph alone had been enough, more than enough, and he had needed to breathe. But there had been two things in the envelope. He had only looked at one.\nThe printed email had been underneath the photograph. He had seen it, registered it, and chosen not to read it because part of him understood that the photograph was already changing everything and the email might finish the job entirely, and he had not been ready for the job to be finished.\nThree weeks later, alone in the house on a Friday afternoon, he went back.\nHis mother was at the market. His father was at school for a staff development session that ran until five. Emeka knew the schedule the way he had always known the schedule, the natural domestic knowledge of a child who had grown up in a house and absorbed its rhythms. He was not proud of using it this way. He went to the study anyway.\nThe cabinet was exactly as he had left it. He found the envelope at the back, behind the property papers, undisturbed.\nHe sat on the floor with his back against the desk and took out both items.\nHe looked at the photograph first. He had earned that much. His mother, young and laughing, her stomach round beneath a loose blouse. The man beside her with his long fingers and his forward jaw, the face that Emeka had spent seventeen years looking at from the inside. They were standing outside what looked like a teaching hospital, the kind with the long corridor and the blue signage you saw in every major city. Neither of them was looking at the camera. They were looking at each other.\nHe turned the photograph over.\nSomeone had written on the back in blue biro, faded but legible. The handwriting was not his mother''s.\nNgozi at seven months. March 1998. God is faithful.\nEmeka was born in May 1998.\nHe had always known his own birthday. He had simply never done the arithmetic while holding a photograph of a man who was not his father standing beside his mother and counting backwards.\nHe put the photograph down carefully, face up, and picked up the email.\nIt was two pages, printed on paper that had once been white, folded twice. The print was small, the kind that came from an early inkjet printer, slightly uneven in places. He unfolded it and read.\nThe address at the top was his mother''s old email, the one she no longer used, the one he had seen on old school documents from his primary years. The name in the From field was one he recognised.\nIkenna Duru.\nThe date in the header was June 2001. Emeka would have been three years old.\nHe read slowly.\nThe email was not dramatic. That was the first thing that struck him. It did not read like a confrontation or an accusation or the kind of correspondence that ended things. It read like a man trying to be careful with language because he understood the weight of what he was handling.\nIkenna Duru wrote that he had heard she was settled now. He wrote that he was glad for her and that he meant that without bitterness. He wrote that he understood the decision she had made and that he had not understood it at the time but had come to understand it since. He asked, in one careful sentence near the middle of the second page, whether the child was well.\nHe did not use Emeka''s name. He wrote the child the way you wrote around something you had decided not to hold directly.\nHe wrote that he was not asking for anything. He wrote that he wanted her to know that he had not forgotten and would not forget, but that he respected the life she had built and would not complicate it. He wrote that if she chose never to reply to this email he would understand and would not write again.\nHis mother had not replied.\nEmeka knew this the way he knew everything in this envelope. She had not replied, and Ikenna Duru had not written again, and the email had been printed and put in an envelope at the back of a cabinet and kept for twenty-three years, and he did not know whether she had kept it as evidence or as penance or simply because she could not make herself throw away the last written proof that the thing had been real.\nHe sat on the floor of his father''s study for a long time.\nThe afternoon light moved across the wall. Somewhere outside a hawker passed calling something unintelligible. A dog barked twice and stopped.\nHe read the email again. The second time he was calmer. He was reading for information now, the way he had learned to read for information over the past month, the way this whole search had trained him to separate feeling from fact and take the facts first and let the feeling find him later.\nThe facts were these.\nIkenna Duru had known about him. Had referred to him as the child in June 2001, which meant the knowledge predated any discovery. Had written to his mother not to claim anything but simply to ask if he was well, and had received no reply, and had kept his word and not written again.\nHe folded the email back into its original creases and placed it under the photograph and put both back in the envelope and returned the envelope to its place at the back of the cabinet behind the property papers.\nHe closed the cabinet and stood up and looked at the room. His father''s certificates on the wall. The desk with its neat arrangement of pens and the stapler his father had owned since before Emeka was born. The small framed verse from Proverbs above the door that had been there as long as the wall itself.\nThis was the room of a man who had stayed.\nA man who had taken a phone call or a conversation or a piece of information sometime in 1998 and had looked at the full complicated weight of it and had decided that he was going to be somebody''s father and had spent seventeen years being exactly that without ever once making his son feel the seam.\nEmeka stood in the room and let the feeling find him.\nIt arrived not as one thing but as several things at once, and they did not cancel each other out. They sat together in his chest with the uncomfortable intimacy of truths that had no interest in being tidy.\nHe turned off the study light and went to his room to wait for his parents to come home.','\n',char(10)),1171,1,1,NULL,'2026-04-09T00:21:04.094Z','2026-04-09 00:21:04','2026-04-09 00:21:04',NULL,1,20);
INSERT INTO "chapters" ("id","novel_id","chapter_number","title","content","word_count","is_premium","is_published","audio_url","published_at","created_at","updated_at","scheduled_release_at","part_number","season_id") VALUES(258,36,10,' A Name That Isn''t His',replace('\nHis mother came to his room on a Sunday evening and stood in the doorway and said, "Your father is in the parlour. Come."\nNot a question. Not exactly a command. The voice of a woman who had made a decision and was not going to revisit it.\nEmeka closed his textbook and followed her.\nHis father was on the couch. Not in his usual armchair, which meant he had chosen this seat deliberately, leaving room on either side. The television was off. The room had the particular quality of a space that had been prepared, the way a room felt when someone had sat in it alone for a few minutes before calling others in, making peace with what was about to happen there.\nEmeka sat on the opposite couch. His mother sat beside his father.\nNobody spoke for a moment.\nThen his father said, "Your mother wants to tell you something. I am here because what affects you affects me and I am not going to be absent from a hard thing." He said it simply, the way he said most things, and then he was quiet, and he looked at Emeka''s mother.\nShe had her hands in her lap. Not folded on the table this time. In her lap, slightly open, the posture of someone who had put down the thing they had been holding.\nShe began.\nShe did not begin at the beginning. She began in the middle, the way people began when the beginning was too far back and the middle was where the weight actually lived. She was twenty-three, she said. She was in her final year at university in Enugu. She had met a man in her second year who was completing a postgraduate programme in engineering. His name was Ikenna Duru.\nShe said the name without ceremony. It arrived in the room and settled.\nThey were together for two years, she said. He was brilliant and serious and she had loved him with the full unguarded confidence of someone who had not yet learned that love required more than itself to survive. When she became pregnant in her final year it was not planned and the world they were in, her family and his, closed around the fact of it with a weight neither of them had anticipated.\nHis family wanted him to marry her. Her family was complicated in ways she did not explain yet, ways that had to do with names and land and an old disagreement that had nothing to do with Emeka''s mother and Ikenna Duru specifically, and everything to do with what it meant to bring their names together formally. She said the word complicated and did not unpack it and Emeka noted the door left closed and did not push it.\nThere had been a point, she said, where it might still have worked. But Ikenna Duru had been offered a fellowship abroad, a two-year programme that would have changed his career entirely, and she had been eight months pregnant, and the decision had not been cruel but it had been what it was, and she had understood in the month before Emeka was born that she was going to be doing the hardest part alone.\nShe met Obiora Obi at a church programme in Lagos three months after Emeka was born. He was thirty, steady, attentive, and he had known about the baby before the third conversation and had not flinched.\nShe looked at Emeka''s father when she said this. A look that was its own language, seventeen years of shared sentences in a single glance.\nThey had married when Emeka was eight months old. His father had registered him. Had given him the name.\nHis father, who had been quiet through all of this, said now, looking at Emeka directly: "You have always been my son. Nothing in this conversation changes that. I want you to hear that from me, not as a consolation. As a fact."\nEmeka looked at him. The honest eyes. The slightly tired face. The man who had stayed.\n"I know," Emeka said. And he meant it, more fully than he had ever meant two words in his life.\nHis mother was watching him. He turned back to her.\n"The man at the funeral," he said.\nShe went still.\n"He was there. At Mama Ifeoma''s burial. He came through the side entrance. He sat at the edge of the canopy." He kept his voice even. "He looked at me."\nHis mother''s eyes closed briefly.\n"He still has family in that line," she said quietly. "Mama Ifeoma was connected to his mother''s people. I did not know he would be there. I saw him arrive and I did not know how to —" She stopped. "I should have told you then."\n"Who is he?" Emeka asked. Even though he already knew. He needed her to say it.\nShe looked at him.\n"That was Ikenna Duru," she said.\nThe room was very quiet.\nEmeka sat with the confirmation and felt it move through him, not like a shock but like the last piece of a structure finally bearing weight. The face at the funeral. The jaw. The hands. The man who had looked at him with a recognition so complete it had lasted one second longer than accidental and then had looked away and walked to the side entrance and left.\nHe had known. He had known since that afternoon under the canopy with his cold plate and the noise of the funeral around him.\nBut knowing alone and having it confirmed were two different rooms, and he was standing in the second one now and the door behind him was closed and the one in front was open.\nHis parents were watching him. His mother with her hands open in her lap. His father with the steady, patient face of a man who had decided a long time ago that presence was the thing he could offer and had been offering it without interruption ever since.\nEmeka looked at the open door.\nThe man at the funeral had seen him. Had stood twenty feet away in a crowd of mourners and had seen him and had known exactly who he was. Had looked away and walked out through the side entrance and said nothing, and somewhere out in the city, or the country, or wherever a man went when he walked away from a thing, Ikenna Duru was existing right now, living the life he had built in the years since a printed email had gone unanswered.\nHe had looked away.\nBut he had looked.','\n',char(10)),1104,1,1,NULL,'2026-04-09T00:22:05.864Z','2026-04-09 00:22:05','2026-04-09 00:22:05',NULL,1,20);
INSERT INTO "chapters" ("id","novel_id","chapter_number","title","content","word_count","is_premium","is_published","audio_url","published_at","created_at","updated_at","scheduled_release_at","part_number","season_id") VALUES(259,37,1,'The First Message',replace('\nThe problem was not finding him. The problem was what to say.\nEmeka had found Ikenna Duru in eleven minutes on a Tuesday night two weeks after the parlour conversation, which told him the man had not been hiding. A LinkedIn profile, a faculty page at a private university in Abuja, a brief bio that said he was a professor of civil engineering with research interests in flood management and infrastructure in the Niger Delta. A small photograph in the corner of the faculty page, formal, taken against a plain background.\nEmeka had looked at the photograph for a long time.\nThe face was older than the one in the envelope, older than the one at the funeral seen from twenty feet away. Up close and still, in the flat light of a faculty photograph, it was simply a man in his late forties who did not know he was being looked at. He had the forward jaw. He had the long fingers, one hand visible at the edge of the frame. He looked like someone who thought carefully before he spoke.\nEmeka had closed the laptop and not opened it again for two weeks.\nThe two weeks were not empty. He went to school. He came home. He ate dinner with his parents and the three of them had achieved, since the Sunday parlour conversation, a new kind of quiet that was different from the old kind. The old quiet had been sealed. This one had air in it. His mother asked him, twice, how he was doing with it all, and both times he had said he was fine and both times she had looked at him with the eyes of a woman who knew fine from its many impostors and had chosen, for now, to accept the word at face value.\nHis father had said nothing more on the subject. He did not need to. The fact of his presence was the statement, the same statement it had always been, consistent and without footnote.\nEmeka appreciated it in a way he did not have words for yet.\nHe opened the laptop again on a Wednesday night when the house was asleep.\nHe found the faculty page and looked at the photograph and then looked away from it and opened a new email window.\nHe sat with the cursor in the To field.\nThere was a contact email on the faculty page. An institutional address, the kind that went to a department inbox and sometimes did not get read for weeks. There was also, on the LinkedIn profile, a message function. He had looked at both options for two weeks. The email felt formal in a way that might make it easier to dismiss. The LinkedIn message felt too casual for what it was, the wrong register for the most significant thing he had ever tried to say.\nHe had written seven drafts in his Notes app over the past fourteen days. He opened them now and read them in order.\nThe first was three paragraphs long and explained everything and felt like a legal document. The second was one sentence and felt like a threat. The third tried to be casual and sounded nothing like him. The fourth was the best of the seven and still wrong, too eager in the middle, the need showing in a way that embarrassed him even alone at midnight.\nHe closed the Notes app.\nHe opened the email window and put the institutional address in the To field and put his cursor in the body and typed without a draft, the way he sometimes answered exam questions he had been thinking about for so long that the thinking was done and the writing was just the deposit.\nGood evening Professor Duru,\nMy name is Emeka Obi. I am seventeen years old and I live in Lagos. I believe you may know who I am.\nI am not writing to cause any problem or complication in your life. I only want to talk, if you are willing.\nYou can reach me on this email address or on this number.\nHe typed his number.\nHe read it back twice.\nIt was sixty-one words. It said what it needed to say and nothing it didn''t, and the nothing it didn''t was an entire continent of things, the photograph and the cabinet and the funeral and the parlour and seventeen years and a name that had been in a government document his whole life and a face that looked back at him every morning, all of it compressed into sixty-one words on a Wednesday night while his parents slept down the hall.\nHe moved his cursor to Send.\nHe sat there.\nOutside, the neighbourhood generator cut out and came back on, the brief darkness replaced by the low hum of electricity resuming. A dog barked somewhere on the next street and was answered by another further away and then they both stopped. The city at this hour was not silent but it was reduced, a quieter version of itself, the daytime aggression gone and something more honest underneath.\nHe pressed Send.\nThe email disappeared into the white space of the sent folder.\nHe closed the laptop and sat in the dark for a moment before he turned his bedside lamp back on. His room looked the same as it always looked. His textbooks on the shelf, the old poster of a footballer he no longer cared about on the wall, the school bag on the chair, the glass of water on the bedside table that he had put there and not drunk.\nHe had done the thing. It was done.\nHe picked up the glass and drank the water and turned off the lamp and lay in the dark and felt his heartbeat, which had been elevated since the moment he put the address in the To field and had not yet come back down. He breathed through it. He made himself breathe through it.\nHe did not know if Ikenna Duru would read the email tonight or in three days or at all. He did not know what a man did when he opened his institutional inbox and found sixty-one words from a seventeen-year-old in Lagos who believed he knew who he was. He did not know whether the man who had looked and then looked away at a funeral in Enugu was the kind of man who would reply.\nWhat he knew was that the message existed now in the world.\nIt had left him.\nAnd whatever happened next was no longer a thing he was only carrying alone in the dark.','\n',char(10)),1109,0,1,NULL,'2026-04-09T00:28:53.889Z','2026-04-09 00:28:53','2026-04-09 00:28:53',NULL,2,21);
INSERT INTO "chapters" ("id","novel_id","chapter_number","title","content","word_count","is_premium","is_published","audio_url","published_at","created_at","updated_at","scheduled_release_at","part_number","season_id") VALUES(260,37,2,'Two Men at a Table',replace('\nThe reply came on a Friday morning while Emeka was in Further Maths.\nHe felt his phone vibrate in his pocket and ignored it because Mr. Adeyinka moved through the classroom during lessons the way a man moved through a room he owned, and confiscating phones was his preferred evidence of ownership. Emeka kept his eyes on the board and his hand on his pen and let the vibration sit against his thigh like a second heartbeat for the remaining forty minutes of the class.\nHe read it in the bathroom during break, door latched, back against the wall.\nThe reply was shorter than his message. Four sentences.\nEmeka. Yes, I know who you are. I have thought about this moment for a long time. I would very much like to talk.\nNo greeting. No sign-off. Just the four sentences and below them, a phone number with an Abuja area code.\nEmeka read it three times. Then he locked his phone and put it in his pocket and went back to class and sat through the rest of the school day with the four sentences living inside him, very still and very loud, the way a sound was loud in a quiet room.\nHe had not told his mother he was going to write. He had not told her the reply had come. He had told no one, and the keeping of it was a different kind of weight from all the other secrets this year had handed him, because this one was his. He had made it. He was choosing what to do with it.\nWhat he had not planned for was his father.\nSaturday morning and his father was at the dining table with the newspaper and a cup of tea that had gone cold because he always forgot to drink it while he was reading. Emeka came out for breakfast and they were alone, his mother at the market, the house holding its weekend quiet.\nHe made himself toast and sat down across from his father and they existed in the comfortable silence that had always been available between them, the kind that required nothing.\nThen his father folded the newspaper.\nHe did not put it down and pick up his tea. He folded it with the deliberateness of a man who had been waiting for a particular moment and had decided this was it.\nHe looked at Emeka.\n"Did you write to him?" his father asked.\nEmeka went still.\nHis father''s face was not angry. It was not hurt in the performed way of someone who wanted you to see the hurt. It was simply open and direct and waiting, the face of a man who had decided that whatever the answer was, he was going to receive it standing up.\n"Yes," Emeka said.\nHis father nodded once. He picked up his cold tea and looked at it and put it down again.\n"Did he reply?"\n"Yes."\nThe kitchen clock marked seconds. Outside the compound gate a car passed playing music too loud for morning, the bass fading as it moved down the street.\n"What did he say?"\n"That he wants to talk."\nHis father was quiet for a moment. Not the collapsed quiet of a man absorbing a blow. The considered quiet of a man deciding how to be what the moment needed.\n"How did you find his contact?" he asked.\n"Faculty page. He teaches at a university in Abuja."\n"Engineering," his father said. Not a question. Which meant he knew. Which meant some portion of what Emeka had been quietly excavating for months was a geography his father had always had the map to.\nSomething shifted between them at the table. Not broken. Shifted, the way weight shifted when two people adjusted their grip on the same thing.\n"How long have you known?" Emeka asked. "About the certificate. That I knew."\nHis father considered the question honestly. "Your mother told me the evening you asked her in the kitchen. But I had seen it before that. You came back from the government office a different way than you left."\nEmeka looked at him. "You didn''t say anything."\n"Neither did you."\nHe could not argue with that.\n"I was waiting," his father said, "for you to come to me. And then when you didn''t I understood that you needed to find it yourself first. That is not a criticism. I would have done the same." He paused. "I did do the same, once. There were things about this situation I had to find myself before I could be in a room with them."\nThis was the most his father had said about his own interior in seventeen years of Emeka''s memory. He received it carefully.\n"Are you angry?" Emeka asked. "That I wrote to him without telling you."\nHis father thought about this with the sincerity the question deserved.\n"No," he said. "You are seventeen and you are trying to understand who you are and I will not be the thing that stands between you and that. I would not know how to live with myself." He looked at Emeka directly. "What I want, and what I am asking you for, is that you do not shut me out of this. Not because I have rights over it. Because I am your father and I want to be useful to you if I can."\nEmeka looked at the man across the table. The newspaper folded to one side. The cold tea. The slightly tired eyes of a man who had been holding something heavy for a long time and was, for the first time, setting it down in a way they could both see.\n"He wants to talk," Emeka said again. "I don''t know what that means yet. I don''t know what I want it to mean."\n"That''s okay."\n"I''m not trying to replace anything."\nHis father''s expression did the brief full thing it had done in the doorway of his bedroom weeks ago, there and gone.\n"I know that," he said quietly. "I have never been afraid of that."\nEmeka believed him. He believed him the way you believed things that had been demonstrated rather than declared, the evidence too long and too consistent to be performance.\nHe ate his toast. His father refolded the newspaper and found his page and read, or held the paper in the position of reading, and the morning continued around them.\nThe conversation had not resolved anything. Nothing was cleaner than it had been before. But it had happened, and both of them were still at the table, and outside the city was going about its Saturday business, and the distance between them was smaller than it had been in months.\nThat felt, for now, like enough.','\n',char(10)),1129,0,1,NULL,'2026-04-09T00:30:25.837Z','2026-04-09 00:30:25','2026-04-09 00:30:25',NULL,2,21);
INSERT INTO "chapters" ("id","novel_id","chapter_number","title","content","word_count","is_premium","is_published","audio_url","published_at","created_at","updated_at","scheduled_release_at","part_number","season_id") VALUES(261,37,3,'Her Side of It',replace('\nShe came to his room on a Sunday afternoon with no preamble, just two cups of tea on a tray and the look of a woman who had rehearsed something long enough that the rehearsal was beginning to cost more than the saying.\nShe put the tray on his desk and sat in his desk chair and wrapped both hands around her cup and looked at him on the bed and said, "I want to tell you properly. From the beginning."\nEmeka put his phone face down. "Okay."\n"Not as an explanation," she said. "I am not trying to explain it away. I want you to know what it actually was."\nHe nodded.\nShe began.\nShe grew up in Enugu in a house with four sisters and a father who was a secondary school principal and a mother who taught primary two for thirty years. Not wealthy, she said, but stable, the kind of stability that came from two people who understood the value of a thing before they spent it. Her father was particular about names and about family standing and about the way the world was allowed to see them, not out of pride exactly, more out of a belief that a family''s reputation was a structure you lived inside, and structures required maintenance.\nShe went to university in Enugu and it was the first time she had been genuinely free, she said, in the way that only people who had grown up inside other people''s careful management understood freedom. She was not reckless with it. But she was open in a way she had not been able to be before.\nShe met Ikenna Duru in her second year at a faculty event she had attended only because her roommate had insisted. He was doing his master''s in civil engineering. He was from Imo State, which was the first complication, because her father had an old grievance with a man from Imo State that had calcified over years into a general suspicion of that geography, the kind of inherited position that families maintained long after the original injury had been forgotten. She had thought it was foolish. She had thought many of her father''s positions were foolish, as children did.\nShe had not thought about how much power foolish positions retained when they were held by people who loved you.\nShe and Ikenna were together for two years. She said it without romanticising it and without diminishing it. He was serious and he was kind and he had a quality of attention, she said, that made you feel that what you said mattered to him personally. She had not met many people with that quality. She had not met it before.\nWhen she became pregnant in her final year she had been frightened in a way that had no bottom, she said, because she was twenty-three and finishing her degree and unmarried and her father had a position about family standing and she was carrying the child of a man from Imo State.\nIkenna wanted to marry her. She said this plainly, without performance. He had wanted it. They had had the conversation more than once, and she had believed he meant it, and she had also understood with the specific intelligence of someone who had grown up watching a family negotiate the world, that want and ability were not the same thing. His family had reservations of their own. The fellowship abroad appeared at the worst possible time, the kind of opportunity that arrived once in a career, and she had been eight months pregnant, and she had watched him hold the two things in his hands and try to find a way to keep both and not be able to.\nShe was not bitter about it, she said. She had been. She was not anymore.\nWhat she had been, at twenty-three with a new baby in her mother''s house, was alone in the way that was particular to women, the kind of alone where everyone was present and available and none of them were carrying the specific weight.\nShe met Obiora Obi at a church event in Lagos when Emeka was three months old and she had not been looking for anyone, she said, which was the only context in which she could have been found by the kind of man he was. He had known about the baby before she told him. A mutual friend had said something. She had expected it to end there.\nIt had not ended there.\nShe paused. She drank from her cup. Outside the window the afternoon was softening toward evening, the light losing its hard edge.\nShe looked at Emeka.\n"The decision to not tell you," she said carefully, "was not made once. It was made many times. Every year you got older and every year the telling seemed more complicated and every year your father was so fully your father that the other thing seemed like a story that belonged to a different life." She stopped. "That was wrong. I know that. I am not asking you to tell me it was not wrong. I just want you to know it was not cold. It was not that I did not think about you."\n"I know," Emeka said.\nShe looked at him, checking the words for what lived underneath them.\n"I named you after my father''s brother," she said. "His name was Emeka. He died when I was eleven and I loved him the way you loved the person in your family who saw you most clearly. Your father agreed to the name without hesitation." She paused. "Ikenna never knew I did that. That the name came from my family and not from him. I do not know if that matters."\nEmeka thought about it. A name given from grief and love, from a woman at twenty-three building something new from the materials the previous thing had left her. He thought about Chidi under the table at the funeral, absorbing more than the adults intended.\n"It matters," he said. "But not the way you think. It means you gave me something of yours. Not something you owed him."\nHis mother looked at him for a long time.\nThe look was not the composed one, the face she showed the world. It was the underneath one, the tired and genuine one he had glimpsed in the kitchen on a Saturday morning weeks ago, and this time it stayed.\n"You are more generous than I deserve," she said quietly.\n"I''m not being generous," Emeka said. "I''m just trying to understand it."\nShe nodded. She wrapped both hands around her cup again and looked out the window and they sat together in the room while the light continued its slow change outside, neither of them needing to fill what was left.\nIt was the most honest the room had ever been.','\n',char(10)),1150,0,1,NULL,'2026-04-09T00:31:38.934Z','2026-04-09 00:31:38','2026-04-09 00:31:38',NULL,2,21);
INSERT INTO "chapters" ("id","novel_id","chapter_number","title","content","word_count","is_premium","is_published","audio_url","published_at","created_at","updated_at","scheduled_release_at","part_number","season_id") VALUES(262,37,4,'The Man Himself',replace('\nIkenna Duru had suggested a café in Victoria Island, which told Emeka two things: the man was in Lagos, and he had thought about neutral ground.\nThey had exchanged four more emails over two weeks, short careful messages that established the practical things without touching the real ones. Emeka had told his mother. She had gone very still and then nodded and said she thought it was right, and the effort that cost her was visible and she made no attempt to hide it, which Emeka respected. His father had said only: tell me how it goes.\nHe took a bus to VI on a Saturday morning and arrived fifteen minutes early because he could not help it and sat at a corner table and ordered a Coke he did not want and watched the door.\nIkenna Duru arrived at exactly the agreed time, which also told Emeka something.\nHe was taller than he had seemed at the funeral, or perhaps the space at the funeral had swallowed his height and this room returned it. He wore a plain shirt the colour of charcoal, no tie, and he carried nothing, no bag, no folder, the deliberate lightness of a man who had decided to bring only himself. He stood in the entrance and looked across the café and found Emeka and for a moment neither of them moved.\nThen he walked over.\nHe stopped at the table and looked down at Emeka and Emeka looked up at him and the resemblance in full daylight, at this distance, was simply a fact, as plain and unargumentative as a weather report. The jaw. The hands. The geography of the face that Emeka had spent seventeen years looking at from inside.\n"Emeka," Ikenna Duru said.\n"Yes sir."\nHe sat down across the table.\nThe first ten minutes were the most difficult ten minutes of Emeka''s life, which was saying something given the year he had had. They ordered, the waiter came and went, and they sat across from each other with the weight of everything between them pressing down on the ordinary furniture of café conversation. Ikenna Duru asked about his journey. Emeka answered. Emeka asked if he had come from Abuja. He said he had been in Lagos since Thursday for a conference.\nThen the small talk ran out, as small talk always did, and what was underneath it came to the surface.\nIkenna Duru looked at him directly. He had the quality his mother had described, the attention that made you feel what you said mattered to him personally. Emeka felt it and noted it and kept himself level.\n"I owe you an explanation," Ikenna Duru said. "Before anything else. I understand that."\n"You don''t have to start there," Emeka said.\n"I want to. Because if I don''t say it first it will sit between us the whole time and make everything else dishonest."\nEmeka said nothing. He waited.\n"I was twenty-six," Ikenna Duru said. "That is not an excuse. It is a context. I was twenty-six and I had worked toward that fellowship for three years and your mother and I had run out of road in a way I did not handle well." He paused. "I told myself I would go for two years and come back and find a way to make it right. That was what I told myself. But the two years became four and the four became a life and at a certain point a man understands that the story he told himself at twenty-six was the story of a coward dressed as a pragmatist."\nThe word coward sat on the table between them. He had placed it there himself, without prompting, and he did not move to take it back.\n"I wrote to your mother in 2001," he said.\n"I know," Emeka said.\nIkenna Duru looked at him. "She told you?"\n"I found the email. It was printed and kept."\nSomething moved through the man''s face at that. He absorbed it and was quiet for a moment.\n"She never replied," he said.\n"No."\n"I understood why." He looked at the table. "She had built something real and I was a disruption she had not asked for. I had forfeited the right to press." He looked back up. "But I want you to know that you were not forgotten. I want you to know that clearly."\nEmeka looked at him. The honest face. The forward jaw that was his own jaw. The long fingers wrapped around a coffee cup.\nHe had rehearsed this meeting many times in his head and in none of the rehearsals had he known what he would feel when the man was actually in front of him. He had expected anger, or the relief of finally, or some collision of the two. What he felt instead was something quieter and stranger, the feeling of looking at an answer to a question and discovering the answer did not automatically resolve the question.\n"Can I ask you something?" Emeka said.\n"Yes. Anything."\n"At the funeral. You looked at me and then you walked away." He kept his voice even. "Why did you walk away?"\nIkenna Duru was quiet for a long moment.\n"Because you were with your parents," he said finally. "Because you were in the middle of a family event at a burial and you were seventeen and I had no right to walk across that compound and introduce myself to your life without your knowledge or your permission." He paused. "And because I was afraid."\n"Of what?"\n"Of what your face would do when you understood who I was."\nEmeka sat with this.\nOutside the café window Victoria Island moved through its Saturday business, cars and pedestrians and the particular energy of money and motion. Inside the café the other tables held their own separate worlds, couples and colleagues and friends, none of them paying any attention to a man and a boy sitting across from each other in the corner over drinks they had largely forgotten to consume.\n"I don''t know what I want from this," Emeka said. It was the most honest thing he had said since he sat down. "I''m not looking for a new father. I have a father."\n"I know that," Ikenna Duru said. "I am not here to be that."\n"Then what are you here to be?"\nThe man looked at him with the full attention his mother had described, the kind that did not look away from hard questions.\n"Whatever you will allow," he said. "Nothing more than that. Nothing you have not decided."\nThe answer was careful and it was genuine and it was not enough and it was also all there was.\nEmeka picked up his Coke. It had gone warm.\nHe drank it anyway.','\n',char(10)),1133,1,1,NULL,'2026-04-09T00:32:36.067Z','2026-04-09 00:32:36','2026-04-09 00:32:36',NULL,2,21);
INSERT INTO "chapters" ("id","novel_id","chapter_number","title","content","word_count","is_premium","is_published","audio_url","published_at","created_at","updated_at","scheduled_release_at","part_number","season_id") VALUES(263,37,5,'What He Wanted',replace('\nThey met again the following Saturday. Same café, same corner table, as if they had agreed to it without saying so, the geography of their first meeting already becoming a habit before they had decided what they were building.\nThis time Emeka arrived without the fifteen minutes early. He had worked on that during the week, the deliberate practice of not over-preparing, of letting a thing be what it was rather than what he had rehearsed. He got there at the agreed time and Ikenna Duru was already seated, coffee in front of him, looking out the window with the expression of a man deep inside his own thinking.\nHe looked up when Emeka sat down. Something in his face settled.\n"I was not sure you would come back," he said.\n"I said I would."\n"Yes." A pause. "I have learned not to assume that saying a thing and doing it are the same."\nEmeka looked at him. It was a strange thing to say and they both knew it and neither of them named it.\nHe had come with questions this time. Not written down, not rehearsed in the shower, but present in him in a way that had accumulated over the week, the residue of seven nights lying in the dark thinking about a man in a charcoal shirt who had used the word coward about himself without flinching.\nHe started with the one that had been sitting longest.\n"The fellowship," Emeka said. "When you went abroad. Did you know my mother was going to be alone?"\nIkenna Duru looked at him steadily. "Yes."\n"And you went anyway."\n"Yes."\nThe honesty of it was not comfortable. Emeka had expected deflection, the careful repositioning of facts that adults performed when they wanted to be understood without being judged. There was none of that. The man simply answered, and the answer was what it was, and he made no move to dress it.\n"Why?" Emeka asked.\nIkenna Duru wrapped both hands around his coffee cup. He looked at the table and then back up.\n"I wanted it more than I was afraid of what it would cost," he said. "I have spent many years finding more sophisticated ways to say that, but that is the truth of it. I was twenty-six and I had worked toward that opportunity since my second year of university, and your mother was complicated, and our families were complicated, and the fellowship was clean and clear and entirely mine." He paused. "I told myself the situation with your mother was unresolvable regardless. That I was not leaving something that was going to work. I was very good at believing the things that made the choice I had already made easier."\nEmeka thought about this. "Did you love her?"\nThe question arrived before he had decided to ask it and he did not take it back.\nIkenna Duru was quiet for a moment.\n"Yes," he said. "In the way you loved things at twenty-six, which was fully but without the understanding that love was not a feeling that managed itself. It required decisions. Consistent ones. I was not yet a person who understood that."\n"Are you now?"\nThe man looked at him with something that was not quite a smile and not quite grief but lived between the two.\n"I am fifty-one years old," he said. "I have had a long education."\nEmeka nodded slowly. He turned his glass on the table, a slow rotation, thinking.\n"Did you ever come back? After the fellowship?"\n"I came back to Nigeria in 2005. I have been here since. I took the position in Abuja in 2009."\n"You''ve been in the country for twenty years."\n"Yes."\n"And you never tried to find us. After the email."\nIkenna Duru received this without defence. "Your mother made her position clear by her silence. I had told her I would respect it and I did." He paused. "I also knew that your father, the man who raised you, was a good man. That was not nothing. Knowing you were with someone who was genuinely your father made the staying away easier to live with."\n"Easier," Emeka said.\n"Easier. Not easy."\nThe café was filling up around them, the Saturday mid-morning crowd arriving with their laptops and their weekend energy, and the noise of other people''s ordinary lives made a useful border around the edges of this conversation.\n"I want to ask you something difficult," Ikenna Duru said.\nEmeka looked at him. "Go ahead."\n"When you found me. When you wrote to me. What were you hoping for?"\nEmeka had asked himself this question many times in the weeks since the email. He had not found a clean answer, which was itself an answer.\n"I don''t know," he said. "I think I wanted the full picture. I had all these pieces and they made a shape but not a complete one. I wanted to see you as a whole person and not just as the thing that was missing from the story." He looked at the table. "I also think I wanted to know whether I mattered to you. Even a small amount."\nSilence.\n"You mattered," Ikenna Duru said. "You have mattered since before you were born. I want to be careful with that claim because I understand I have not behaved as though it were true and a man who says a thing mattered while demonstrating otherwise is asking to be believed on the cheap." He looked at Emeka directly. "But it is true. And I have carried the weight of how I managed it for a long time."\nEmeka looked at him.\nThe man across the table was not a villain. He had understood that before he sat down, but sitting down had confirmed it in the way only proximity could. He was a person who had made a large and consequential choice at twenty-six from a combination of ambition and fear and the ordinary human talent for believing what was convenient, and who had spent twenty-five years being the person left on the other side of that choice. He was complicated. He was human. He was sitting in a café in Victoria Island on a Saturday morning with his long fingers around a coffee cup, telling a seventeen-year-old the truth because the seventeen-year-old had asked for it, and the truth was insufficient.\nThat was the thing Emeka was understanding in his body, not just his head.\nThe truth was insufficient. Not because it was incomplete but because some debts were not cleared by honesty alone. You could explain a thing perfectly and it still would not give back what it had taken. The explanation and the loss sat beside each other and neither one cancelled the other out.\nHe looked at Ikenna Duru.\nHe was not done with him. He knew that. There was still a next Saturday, still more questions, still the slow construction of whatever this was or could be. But he was also, for the first time since the government office and the name in the Father column, clear-eyed about what he was working with.\nA man who had chosen wrong and knew it.\nA truth that was real but not enough.\nAnd a question that was still his to answer.','\n',char(10)),1214,1,1,NULL,'2026-04-09T00:33:40.502Z','2026-04-09 00:33:40','2026-04-09 00:33:40',NULL,2,21);
INSERT INTO "chapters" ("id","novel_id","chapter_number","title","content","word_count","is_premium","is_published","audio_url","published_at","created_at","updated_at","scheduled_release_at","part_number","season_id") VALUES(264,37,6,'The Name',replace('\nHis mother had told him the name came from her father''s brother. He had believed her because it was true, and because the way she said it carried the specific weight of something that had cost her to give.\nWhat she had not told him was that Ikenna Duru had a brother named Emeka.\nHe found this out on their third Saturday not from Ikenna Duru but from something Ikenna Duru said without meaning to, a sentence that arrived sideways in the middle of a conversation about something else and lodged itself in the room before either of them could account for it.\nThey had been talking about Abuja, about the university, about what civil engineering actually meant as a daily practice rather than a title on a faculty page. Emeka had been asking because he was genuinely curious and because genuine curiosity was the one tool he had found that made these Saturdays feel less like negotiations and more like two people trying to know each other honestly. Ikenna Duru was a good talker when the subject moved away from the weight of their history. He became precise and alive and the quality of his attention turned outward rather than inward.\nHe was explaining a flood management project in the Niger Delta, something about embankments and soil saturation and the specific stubbornness of delta terrain, when he said: "My brother used to say I talked about soil the way other men talked about football."\nHe stopped.\nNot dramatically. He simply stopped, the way a person stopped when they had said something that opened a room they had not meant to open.\nEmeka looked at him. "You have a brother."\n"Yes."\n"What is his name?"\nThe pause before the answer was not long. It was exactly long enough.\n"Chukwuemeka," Ikenna Duru said. "We called him Emeka."\nThe café held its noise around them. Someone at the next table laughed at something. The waiter passed with a tray.\nEmeka sat very still.\nHe was thinking about his mother at twenty-three. He was thinking about a name she had told him came from her father''s brother, which was true, and about whether a name could come from two places at once, whether a woman could choose a name that was both a tribute to the uncle she had lost at eleven and a private acknowledgement of the man who had not stayed, a word that held both things without having to explain itself to anyone.\nHe was thinking about how a secret inside a secret worked, the layers of it, the way his mother had managed the truth for seventeen years not just in the large shape of it but in the small specific decisions that accumulated into a life.\n"Tell me about him," Emeka said.\nIkenna Duru looked at him carefully, reading the request.\n"He is three years younger than me," he said. "He lives in Port Harcourt. He works in logistics, has four children, laughs too loudly in restaurants." Something softened in his face. "He is the better man of the two of us. He will tell you that himself if you ever meet him."\n"Did he know about me?"\n"Not at first. I told him in 2003, when I came back for our father''s burial. He was the first person I told." He paused. "He was not kind about how I had handled it. He has never been kind about how I handled it. He asks about you still, occasionally."\nEmeka absorbed this. A man in Port Harcourt who asked about him occasionally. Another branch of a tree he had not known was his.\n"Is that where my name came from?" Emeka asked. "Not just my mother''s uncle. You as well."\nIkenna Duru was quiet.\n"I cannot tell you what your mother intended," he said slowly. "That is hers to tell." He looked at the table and then back up. "What I can tell you is that when I heard your name, years later, when I found out through the family network what she had named you, I thought about my brother. I did not know whether she had intended it. I have never known. But I thought about it."\n"Did you ask her?"\n"We have not spoken since 2001."\nEmeka nodded.\nHe was going to have to ask his mother. He understood that. He was going to have to sit across from her again and say the name Chukwuemeka and watch her face and ask her directly, and whatever she said would be the thing he would have to hold. He was not afraid of that conversation. He was aware of it the way you were aware of a door you were not yet standing in front of.\nHe looked at Ikenna Duru.\n"What does it mean?" he asked. "The full name."\nIkenna Duru looked slightly surprised, as if this was not the direction he had expected.\n"Chukwuemeka," he said. "God has done great things."\nThe name sat in the air between them.\nEmeka had known the meaning in the abstract way you knew things you had never been given a reason to examine. He had seen it on forms, heard it at prize-giving when the full name was read and it had always felt ceremonial rather than personal, the formal version of him that existed on documents and in the mouths of teachers.\nSitting in this café on this Saturday morning, hearing it said by the man whose brother carried the same name, it felt for the first time like something that had been chosen with intention.\nGod has done great things.\nHis mother at twenty-three, alone in her mother''s house with a new baby, naming him something that was a tribute and a grief and possibly also a thread connecting her to a man she had loved and was learning to stop waiting for. His father at thirty, meeting a woman and a baby and deciding without hesitation to be what was needed, pouring seventeen years of ordinary love into a name someone else had given.\nHis own face in the mirror every morning, carrying features that had come from a man he was only now sitting across from.\nAll of it held in two words. Four syllables. An inheritance he had not known was layered.\n"My father wanted to name my brother Emmanuel," Ikenna Duru said quietly, still on the name, still turning it over in the way Emeka understood because he was doing the same thing. "My mother insisted on Chukwuemeka. She said Emmanuel was borrowed and Chukwuemeka was theirs." He looked at Emeka. "My mother was a woman who felt strongly about owning what was yours."\nEmeka thought about his mother''s hands flat on the kitchen counter. The way she held herself when she was keeping something in.\nHe thought about how a person could carry a thing for seventeen years and keep carrying it and never put it down without being asked.\n"I''m going to ask her," Emeka said. "About the name."\n"Good," Ikenna Duru said simply.\nThe word was not relieved or anxious or loaded with anything other than what it said. Good. As if the thing that mattered was that Emeka kept moving through the questions rather than which answer arrived at the end of them.\nOutside the window the afternoon had started its slow advance on the morning. The light through the glass had shifted. They had been here longer than either of them had tracked.\nEmeka looked at his own hands on the table. Long fingers. Wide knuckles. The geography that had always been his and now had a history attached to it, a story, two branches of a family meeting in the specific architecture of a seventeen-year-old''s hands.\nHe did not know yet what to do with all of it.\nBut he was beginning to understand that the not knowing was not a failure. It was just the next part.','\n',char(10)),1323,1,1,NULL,'2026-04-09T00:35:04.074Z','2026-04-09 00:35:04','2026-04-09 00:35:04',NULL,2,21);
INSERT INTO "chapters" ("id","novel_id","chapter_number","title","content","word_count","is_premium","is_published","audio_url","published_at","created_at","updated_at","scheduled_release_at","part_number","season_id") VALUES(265,37,7,'Fracture',replace('\nThe breaking did not come from where he expected.\nHe had been watching his parents for weeks with the careful attention he had developed since January, and what he had seen was two people navigating a hard stretch with the discipline of long practice. His mother was quieter than usual in the particular way that meant she was processing rather than withdrawing. His father maintained his routines with the steadiness that was simply his nature, the man who showed up being the same man regardless of weather. They were not without strain. But they were holding.\nWhat he had not been watching was his mother''s family.\nIt started with a phone call on a Tuesday evening that his mother took in the bedroom with the door closed, which she only did when the conversation required privacy she did not want to negotiate around. Emeka was at the dining table with his textbooks and he heard the tone of it through the wall without hearing the words, the specific register of a woman being asked to account for something.\nThe call lasted forty minutes.\nShe came out with her face composed in the over-composed way, the composure that was itself a signal.\nHis father looked up from his newspaper.\n"Aunty Chioma," his mother said. It was both an explanation and the end of one.\nHis father folded the newspaper.\nAunty Chioma was his mother''s oldest sister, fourteen years her senior, a woman Emeka had met perhaps six times in his life. She had the family''s posture and her father''s precision and an opinion about every matter she encountered that she delivered without waiting to be asked. She had been at the burial in Enugu. Emeka understood, without being told, that someone at that burial had said something, or that the ripple of Emeka''s meeting with Ikenna Duru had moved through the family network the way things moved through family networks, without permission and without a clear point of origin.\n"What did she say?" his father asked.\nHis mother sat down. "She says it is a family embarrassment. That I have allowed Emeka to make contact with that man and that it reflects on everyone." Her voice was level but Emeka knew the underside of level. "She wants me to stop it."\nThe room was quiet.\nEmeka looked at his textbook and did not look up.\n"And what did you say?" his father asked.\n"I told her my son''s life was not a matter she had standing in." A pause. "She disagreed."\nHis father made a sound that was not quite a word.\n"She is calling Mama," his mother said. Which meant her mother, the retired primary two teacher in Enugu, who was seventy-three and unwell and whose peace his mother protected with the ferocity of someone who understood it was finite.\nHis father stood up. He went to the kitchen. The sound of him filling a kettle came through the wall.\nEmeka closed his textbook.\n"Mum," he said.\nShe looked at him.\n"I''m sorry this is causing problems."\n"You have nothing to apologise for," she said immediately, firmly, the voice she used when a thing was not up for negotiation. "This is not your doing. This is the consequence of decisions that were made before you were old enough to make any."\nHe believed her. He also knew that belief did not remove the weight she was carrying, only clarified where it had come from.\nThree days later his father came home from school with a tightness around his jaw that was not his natural expression and said, at dinner, that a colleague had mentioned something. The colleague had a wife who was connected to the extended family network. The information about Emeka and Ikenna Duru had moved further than any of them had managed.\nHis mother put down her fork.\n"Who," she said.\n"It does not matter who," his father said. "What matters is that it is moving."\nEmeka looked at his plate. He was the centre of this. He understood that with the specific discomfort of someone who had pulled a thread and was now watching the fabric respond. He had not pulled the thread carelessly. He had done it because he needed to and he stood behind the need. But standing behind a decision did not mean you were exempt from what it cost.\n"I''ll stop," he said. "The meetings. I''ll stop them."\nBoth his parents looked at him.\n"You will not," his father said. The voice was quiet and absolute.\n"People are talking. Mum is getting calls. You''re coming home with your jaw like that. I did this."\n"You asked a legitimate question about your own life," his father said. "The talking is not your fault. The talking is what people did before you were born and what they are doing now because some families prefer a managed truth to a real one." He looked at Emeka directly. "I will not have you make yourself small to fit inside someone else''s comfort. Do you understand me?"\nEmeka looked at him.\nThe man who had stayed. The man who had built seventeen years on a decision no one had required of him. Sitting at his own dining table telling his son that the story of his life was his to know, regardless of who found the knowing inconvenient.\n"Yes," Emeka said.\nHis mother reached across and put her hand briefly over his on the table, a gesture so quick he almost missed it.\nThen she picked up her fork and said, "I am going to call Mama myself before Chioma does. She should hear it from me."\n"I''ll come with you," his father said. "If you want."\nShe looked at him. The seventeen-year language between them, the look that held whole conversations.\n"Yes," she said. "Come."\nThat night Emeka lay in his room and looked at the ceiling and thought about fracture. How things broke. How sometimes what looked like breaking was actually a structure finding its true shape under pressure, the weak joints failing and the real ones holding.\nHis parents were in the parlour with the television on low, his mother on the phone with her mother in Enugu, his father beside her. Not talking. Present.\nThe family was not breaking.\nIt was under pressure and the pressure was finding the places that were not as solid as they had appeared. But the things that mattered, the things built deliberately from real decisions, those were holding.\nHe understood something new in the dark.\nThe people trying to manage this story had never been inside it. They knew its shape from the outside and the shape offended them. But a story looked different from inside it, where you could feel the weight of every decision and the cost of every silence and the specific quality of love that showed up without requiring anything in return.\nFrom inside it, the story was not an embarrassment.\nIt was just his.','\n',char(10)),1161,1,1,NULL,'2026-04-09T00:36:21.823Z','2026-04-09 00:36:21','2026-04-09 00:36:21',NULL,2,21);
INSERT INTO "chapters" ("id","novel_id","chapter_number","title","content","word_count","is_premium","is_published","audio_url","published_at","created_at","updated_at","scheduled_release_at","part_number","season_id") VALUES(266,37,8,' What You Keep',replace('\nHe went to the café alone that Saturday.\nNot to meet Ikenna Duru. He had texted to say he needed to skip the week, and the reply had come back in two words: Of course. No pressure, no negotiation, no performance of understanding. Just the two words, and Emeka had held his phone and thought that this was perhaps the most accurate thing the man had given him yet, the willingness to be absent when absence was what was needed.\nHe ordered tea he did not particularly want and sat in the corner table that had become theirs and looked out the window at Victoria Island on a Saturday morning and let himself think without direction for the first time in months.\nThe thinking was not comfortable. He had not expected it to be.\nHe thought about the government office in January, the woman holding his birth certificate up to the light. He thought about the name in the Father column and the bus ride home and the way Lagos had looked exactly the same through a smeared window while everything that gave it context was quietly rearranging itself. He thought about the cabinet in his father''s study, the envelope, the photograph, the printed email with its four careful paragraphs. The funeral in Enugu and the man who had looked and looked away. His mother''s hands flat on the kitchen counter. His father on a Saturday morning with the newspaper folded, asking: did you write to him.\nHe thought about Ikenna Duru in a charcoal shirt sitting across a corner table using the word coward about himself without apology. He thought about the name, the four syllables, the meaning held inside them. God has done great things. His mother at twenty-three building something from the wreckage of an unchosen alone, naming her son twice over without telling anyone.\nHe thought about what he had wanted when he started.\nHe had wanted the full picture. He had said that in the café and it had been true. He had wanted to see the shape of the thing that had been kept from him, to hold it in his hands and know it for what it was rather than for the space its absence had made. He had wanted to stop being the last person in the room to know something about himself.\nHe had that now.\nThe question was what to do with having it.\nHe took out his phone and opened the Notes app and found the list he had made in his room months ago, the fragments he had been gathering.\nIkenna Duru. Photo in cabinet. Same face at funeral. Mum''s uncle was named Emeka. There''s a family I don''t know. Adaeze said: anyone who knew him will see it.\nHe read it. Then he scrolled down past it to a blank space and typed slowly, the way you typed when you were thinking and writing at the same time and the writing was how the thinking got done.\nWhat I know: Ikenna Duru is my biological father. He chose a fellowship over my mother when she was eight months pregnant. He wrote one email in 2001 and kept his word and did not write again. He is a professor in Abuja who talks about soil the way other men talk about football. He has a brother in Port Harcourt who has four children and asks about me occasionally. He is not a villain. He is not what I was looking for.\nWhat I know: Obiora Obi registered my name and has been my father every day of my life. He burns omelets and drives three hours in rain and folds newspapers and asks questions by not asking them. He told me my life was not something I should make small to fit inside someone else''s comfort. He is what the word father has meant in practice for seventeen years.\nWhat I know: My mother named me twice over. She gave me a name that held a grief and a love and possibly a thread she was not ready to cut and never told anyone. She carried a story for seventeen years because she was trying to protect the thing she had built and the cost of that protection was mine to pay without knowing I was paying it. She was wrong. She also did the best she could. Both of those things are true and neither cancels the other.\nHe read it back.\nThen he typed one more thing.\nNone of this changes who I am. It changes what I know about how I got here. Those are not the same thing.\nHe put the phone down and looked out the window.\nA woman was walking past on the pavement outside with a child on her hand, the child stopping every few feet to look at something on the ground, a stone or an insect or the particular quality of a shadow, and the woman waiting each time with the patient attention of someone who had learned that a child''s pace was its own kind of information. They were not in a hurry. The morning had room for what the child needed to examine.\nEmeka watched them until they moved out of frame.\nHe thought about what you kept and what you put down. He thought about how he had spent months carrying the shape of a question that had felt like a missing piece, as if the answer, once found, would fill a hole and make the structure complete. The answer had arrived and the structure was not incomplete. It had been whole the entire time. He had simply not known what it was made of.\nHe was made of his mother''s stubbornness and her careful hands and the name she had chosen twice over. He was made of his father''s steadiness, the dailiness of a love that did not require acknowledgement. He was made of a man he was still learning, a tall professor with long fingers who had made a large wrong choice at twenty-six and had been living inside the consequences ever since and was trying now, in corner cafés on Saturday mornings, to be honest about it.\nHe was made of Lagos traffic and Enugu funerals and a birth certificate at the back of a cabinet and a printed email with its paper gone yellow at the edges.\nHe was made of more than he had known.\nThat was not loss. It was not resolution either, not the clean kind, not the kind that tied itself off and required nothing further. It was just the truth of it, large and untidy and entirely his.\nHe finished his tea.\nHe left the café and stepped into the Saturday morning and the city received him the way it always did, without ceremony, without pause, with the full indifferent noise of a place that had been going about its business long before he arrived and would continue long after.\nHe walked into it.','\n',char(10)),1167,1,1,NULL,'2026-04-09T00:37:45.866Z','2026-04-09 00:37:45','2026-04-09 00:37:45',NULL,2,21);
INSERT INTO "chapters" ("id","novel_id","chapter_number","title","content","word_count","is_premium","is_published","audio_url","published_at","created_at","updated_at","scheduled_release_at","part_number","season_id") VALUES(267,37,9,'The Conversation They Never Had',replace('\nHis father was in the compound on a Sunday afternoon doing the thing he did when he needed to think, which was finding something physical to occupy his hands. Today it was the side gate, which had been sticking for three months and which he had been meaning to fix and which had now, apparently, become urgent.\nEmeka watched him from the doorway for a moment. The old clothes. The toolbox open on the ground. The focused, unhurried way he worked, the same way he did everything, as if the quality of the attention was the point rather than the speed of the result.\nHe went inside and made two cups of tea and brought them out.\nHis father looked up. He looked at the two cups. He set down his screwdriver and accepted one without comment and they stood in the compound in the afternoon light and drank, and the gate stood between them with its old complaint, and neither of them spoke for a while.\nThen Emeka said, "Can I ask you something properly?"\nHis father looked at him over the rim of his cup. "When have I ever said no to a question?"\n"You haven''t. That''s why I''m asking."\nHis father lowered the cup. He leaned against the wall and crossed one ankle over the other and gave Emeka the full version of his attention, the one that meant he had put everything else down.\n"Ask," he said.\n"When you met her," Emeka said. "When you found out about me. What did you actually think?"\nHis father was quiet for a moment. Not avoiding the question. Locating the honest answer rather than the available one.\n"I thought she was remarkable," he said. "Not because of the situation. In spite of it, or alongside it. She was twenty-three with a three-month-old and she was not looking for rescue and she was not performing strength. She was simply getting on with it, and that quality in a person, the getting on with it without making a theatre of the difficulty, I had not seen it up close before." He paused. "And I thought the child must be something, to be carried by someone who moved through hard things like that."\nEmeka held his cup.\n"Were you afraid?" he asked. "Of what you were getting into?"\n"Terrified," his father said simply. "I was thirty years old and I had lived alone since twenty-four and I did not know anything about children except that they were loud and expensive and required a consistency I was not sure I had." He looked at the gate, then back. "I remember sitting in my car after the third time I visited her and asking myself very directly: is this a decision or a feeling? Because feelings pass and decisions hold, and I needed to know which one I was operating from before I went any further."\n"Which was it?"\n"Both," his father said. "But the decision was larger. The feeling was the beginning. The decision was what I built on top of it."\nEmeka nodded slowly.\n"Did you ever resent it?" he asked. "Any of it. The situation you walked into."\nHis father thought about this with the seriousness the question deserved.\n"There were moments," he said, "early on, when I felt the weight of something I had not originated. That is honest. A man is allowed to feel the weight of things." He looked at Emeka directly. "But resentment requires a victim, and I was not a victim. I made a choice with full information. Nobody misled me. Nobody pressured me. I chose this with open eyes and I would choose it again without hesitation." He paused. "You are not a burden I bore. You are a person I raised. Those are not even close to the same thing."\nThe compound was quiet around them. A bird moved through the guava tree in the corner. The afternoon held its warmth without aggression, the kind of Sunday light that asked nothing.\nEmeka looked at his father.\n"I need to tell you something," he said. "And I need you to hear it as what it actually is, not as a consolation."\nHis father waited.\n"Meeting him has not moved anything," Emeka said. "Not the way you might think. I went looking for a missing piece and what I found was that the piece was not missing. I just didn''t know what it was." He kept his eyes on his father''s face. "You are my father. Not by default. Not because you were there and he wasn''t. Because of every single ordinary thing, every Saturday omelet and every prize-giving and every time you knocked on my door on a Thursday evening because you noticed something was wrong. That is what a father is. I know that now in a way I didn''t know how to say before."\nHis father looked at him.\nThe expression that moved through his face was not relief, exactly, because relief implied he had been uncertain, and Emeka did not think he had been uncertain, not about the fundamental thing. It was something different. Recognition, maybe. The feeling of a thing you had known being said out loud and becoming, in the saying, more fully real.\nHe did not make a performance of it. He was not that kind of man.\nHe picked up his screwdriver.\n"Help me with this gate," he said.\nEmeka set down his cup and crouched beside the toolbox.\nHis father talked him through it the same way he had talked him through the car engine in the compound months ago, patiently and without condescension, and Emeka held things and passed things and paid attention, and the gate gradually yielded to the work, the old complaint giving way under steady effort.\nThey did not talk about the big things again. They talked about the gate and whether the whole frame needed replacing and whether the hardware store on the main road stocked the right hinges, and his father had an opinion about the hardware store on the main road that he expressed at some length, and Emeka listened and responded and the afternoon moved through itself.\nThe gate opened cleanly when they tested it. His father swung it back and forth twice with the satisfaction of a man for whom a thing working properly was its own reward.\nEmeka watched him and felt the specific, unglamorous solidity of the life they had built together, the seventeen years of knocked doors and burnt omelets and newspapers folded at the right moment, the architecture of ordinary love that had been holding him up since before he was old enough to know he was standing on something.\nIt had never needed the full story to be real.\nIt had always been real.\nHe handed his father back the screwdriver and they went inside for dinner and the evening came down around the house and everything was not resolved and everything was not simple and the question of who Emeka was would keep asking itself in new forms for years to come.\nBut tonight, inside this house, with these people, he was exactly where he was supposed to be.','\n',char(10)),1197,1,1,NULL,'2026-04-09T00:38:56.873Z','2026-04-09 00:38:56','2026-04-09 00:38:56',NULL,2,21);
INSERT INTO "chapters" ("id","novel_id","chapter_number","title","content","word_count","is_premium","is_published","audio_url","published_at","created_at","updated_at","scheduled_release_at","part_number","season_id") VALUES(268,37,10,' The Name He Gave Me',replace('\nHe met Ikenna Duru one last time before the school term ended.\nNot at the café. Ikenna Duru was returning to Abuja the following morning and had asked, in a message that took its time arriving at the point, whether Emeka would be willing to meet somewhere more open. A park, he had suggested. Somewhere without the feeling of a corner table and the weight of interior space.\nEmeka had said yes.\nThe park was in Ikoyi, the kind that existed in quiet negotiation with the city around it, trees old enough to have opinions, the noise of Lagos present but softened by distance and leaf. They walked rather than sat, which turned out to be the right decision, conversation easier when it did not require two people to look directly at each other for its entire duration.\nThey talked for an hour and a half.\nIkenna Duru talked about his work, a project near Warri that was testing new approaches to erosion management, and the talk was alive in him the way it had been alive in the café the day he mentioned his brother, the precision and the enthusiasm of a man who had found the thing he was genuinely good at and had spent his life inside it. Emeka listened and asked questions and the questions were real questions, not performance, because the curiosity was real regardless of everything else.\nHe talked about his brother in Port Harcourt. He talked about their mother, who had died in 2015, who had been formidable and exact and had insisted on the right names for everything. He talked about Nigeria in a way that was neither romantic nor despairing, the way people talked about a place they had decided to stay in with full knowledge of its difficulty.\nEmeka talked about school, about the exams coming in six weeks, about Tunde and the PlayStation and the chin-chin on the cushion between them that had been a constant since primary school. He talked about wanting to study architecture, which he had not said out loud to anyone yet, the idea too new and too personal to survive other people''s opinions before it had fully formed. He said it to Ikenna Duru, who listened and said: you have the mind for it. The structural thinking. I noticed that in how you approach questions.\nEmeka received the observation and stored it in the place where he was building his understanding of this man.\nNear the end of the walk, on a bench at the edge of a slow-moving stretch of water, they sat.\nIkenna Duru looked at the water. He had the look of a man approaching something he had been moving toward the entire walk and had arrived at finally.\n"I want to ask you something," he said. "And I want you to know before I ask it that there is no wrong answer and I mean that without qualification."\nEmeka waited.\n"What do you want this to be? Going forward. Whatever shape you need it to take, I will take that shape. If you need distance, I will hold distance. If you want to keep talking, I am here. If you need years before you know, I have years." He paused. "I am not asking because I need an answer for myself. I am asking because it is your question and you should be the one who answers it."\nEmeka looked at the water.\nHe had thought about this. He had been thinking about it since the café in Episode Eighteen, since the Saturday alone with the tea he did not want and the Notes app and the untidy truth of everything he was made of. He had not arrived at certainty because certainty was not available for questions this shape. What he had arrived at was something more durable than certainty.\nClarity about what he actually wanted rather than what he thought he was supposed to want.\n"I don''t need a father," he said. "I have a father. I am not looking to replace what I have or build something that mirrors it." He looked at Ikenna Duru. "But I am not done with you either. You are part of the story of how I exist and I think I want to know you. Slowly. In the way you know someone who is not obligated to be anything except honest." He paused. "I think I can do that if you can."\nIkenna Duru looked at him.\nThe relief in his face was not the relief of a man who had been forgiven, because Emeka was not offering forgiveness today, not the formal kind, not the kind that cleared accounts. It was the relief of a man who had been seen as what he actually was, complicated and insufficient and trying, and had been offered a real thing rather than a managed one.\n"I can do that," he said quietly.\nThey sat for a while longer. The water moved at its own pace. A bird crossed the open space above them without particular urgency. Somewhere behind them a child was running and laughing and the sound of it came through the trees clean and uncomplicated.\nThen Emeka said: "My mother named me after her father''s brother."\n"Yes," Ikenna Duru said.\n"And your brother''s name is Emeka."\nA pause. "Yes."\n"Did she know that when she named me?"\nIkenna Duru was quiet for a long moment.\n"I think," he said carefully, "that your mother is a woman who does nothing without knowing what she is doing." He looked at the water. "I think she chose a name that was true in more than one direction at once. That is what I think. But that story belongs to her."\nEmeka nodded.\nHe was going to ask her. He had decided that on the Saturday in the café and the decision had not changed. He was going to sit across from his mother and say the name and watch her face and whatever she said would become part of what he knew. It would not be the last conversation. These conversations, he understood now, did not end. They evolved. The questions changed shape as you grew into them, the answers deepened as you became more capable of holding them.\nThat was not a problem. That was just what it meant to be a person with a history.\nHe took the bus home in the late afternoon with the city coming alive around him in the specific way of Lagos heading into evening, the velocity increasing, the noise sharpening, the particular electricity of five million people moving toward the end of their days.\nHe looked out the window.\nHe thought about a name. Four syllables. God has done great things.\nHe had been given it by a woman who was alone and twenty-three and building something real from difficult materials. It had been registered by a man who had chosen, with full information and open eyes, to stand behind it for the rest of his life. It carried inside it a dead uncle and a living one and a grief and a love and the unspoken thread between two people who had been young and complicated and had not found a way through.\nThe name was not simple. It had never been simple. He had just not known what it was holding.\nHe knew now.\nAnd the knowing did not lighten it. It did not make the carrying easier in the way he had imagined, months ago in a government office that smelled of old paper, that understanding a thing would make it easier to carry. The weight was the same. What had changed was that he knew what the weight was, and knowing what you were carrying was its own kind of strength, not the absence of difficulty but the ability to hold it with your eyes open.\nHe was Emeka Obi. His father had given him that name. Not the man whose blood he carried, but the man who had shown up every day and knocked on doors and burned omelets and driven three hours in the rain because his son had called from a friend''s house sounding miserable. The man who had stood in a compound on a Sunday afternoon and said: you are not a burden I bore. You are a person I raised.\nThat was the name he had been given.\nNot the syllables. The seventeen years inside them.\nThe bus moved through the city and the city moved around the bus and Emeka sat in the window seat and watched Lagos be itself, loud and ungovernable and entirely alive, and felt, for the first time since January, the ground under him as something reliable.\nNot certain. Not simple.\nReliable.\nHe was going home.\n','\n',char(10)),1464,1,1,NULL,'2026-04-09T00:40:41.185Z','2026-04-09 00:40:41','2026-04-09 00:40:41',NULL,2,21);
INSERT INTO "chapters" ("id","novel_id","chapter_number","title","content","word_count","is_premium","is_published","audio_url","published_at","created_at","updated_at","scheduled_release_at","part_number","season_id") VALUES(269,38,1,'Scholarship Girl',replace('\n\nThe school smelled like floor wax and other people''s money, and Abena Mensah stood at the entrance of Akosua House with her trunk, her bucket, and the specific stillness of someone who had decided, somewhere on the four-hour bus ride from Abandze, that she would not be impressed by anything.\nShe had been wrong about the gate.\nShe had imagined it smaller a school gate, an ordinary thing but the iron arch of Horizon Academy rose above the tarmac road like it was making a point. The name was forged into the metal in letters that had been there longer than her mother had been alive. Girls in pressed uniforms streamed past her on both sides, pulling wheeled suitcases, laughing at things that had already happened, resuming friendships that had only been interrupted by the six-week holiday. Nobody stopped. Nobody looked.\nAbena picked up her trunk by one handle and her bucket by the other and walked in.\nThe admin block woman checked her name against a printed list with the patience of someone who did this four times a year and felt nothing about it.\n"Mensah, Abena. Central Region. Government scholarship." A pause. Not long. Just long enough. "Room fourteen. Akosua House."\nAbena took the paper slip, folded it twice, and put it in her uniform pocket.\nRoom fourteen was on the second floor. The staircase was wide, the banister worn smooth by ten thousand hands. Abena counted the steps without meaning to. Seventeen.\nThe door was already open.\nHer roommate was sitting on the bed nearest the window the better bed, the one with the afternoon light surrounded by a controlled arrangement of things. A small wooden jewelry box. A stack of novels with unbroken spines. Skincare in a clear toiletry bag, all the same brand. The girl had her back to the door, writing in a notebook, and her handwriting, even from the doorway, looked like it had been taught rather than developed.\n"You must be my roommate," the girl said, without turning.\nAbena set down her trunk. "I must be."\nThe girl turned then. She was pretty the way some girls were pretty at sixteen not trying, just arranged correctly. Her uniform was the same as Abena''s except somehow it wasn''t. Same fabric, same cut, but hers sat differently. Ironed to a certainty.\n"Serwa Boateng." She didn''t stand. She said her name the way you give someone directions useful information, neutrally delivered.\n"Abena Mensah."\n"Where are you from?"\n"Abandze. Central Region."\nSerwa nodded once, as if this confirmed something she hadn''t said aloud, and turned back to her notebook.\nAbena took the remaining bed. Left side, away from the window. The mattress was firm, the pillow flat, and the whole room smelled of industrial detergent. She pressed her palm against the pillow once, then began to unpack only what she needed for tonight. Soap, towel, tomorrow''s books, and the photograph of her grandmother she always placed on whatever surface was available in whatever room she was sleeping in.\nShe set the photograph against the wall where the windowsill would have been if she''d had a window. Her grandmother in the photograph was maybe forty, standing in front of a fishing boat with her arms crossed and her chin up, looking at the camera like she had agreed to this photograph but had not agreed to smile about it.\n"Who''s that?" Serwa asked.\nAbena looked up. Serwa was still facing her notebook, but her eyes had moved.\n"My grandmother."\n"Is she"\n"She''s alive. She''s fine."\nSerwa nodded again. The room went quiet in the way rooms go quiet when two people are deciding how much to offer each other. Not unfriendly. Not yet. Something more careful than that.\nDinner was at six. Two hundred girls at long tables, the noise rising to the ceiling and coming back down rearranged. Abena sat where there was space next to a Form Two girl named Efua who had strong opinions about the jollof, and a girl from Kumasi named Patience who was on the same scholarship and ate with the focused energy of someone making sure to get her money''s worth.\nThey did not become friends that night. They became something earlier than that. People who knew each other''s names.\nSerwa sat at a corner table. Four girls, all with the same quality of stillness around them, the same way of making the cafeteria look like it was happening to someone else.\nAbena watched her for only a moment. Then looked back at her food.\nLater, in the room, Serwa turned off her lamp at exactly ten o''clock. Abena turned off hers too, though she hadn''t finished her chapter. She lay in the dark and listened to the school at night slippers on corridor tiles, a burst of laughter quickly hushed, the low cough of a distant generator.\nShe thought about the bus ride. The gate. The floor wax.\nShe thought about her grandmother''s face in the photograph. The raised chin. The crossed arms. The look that said: I agreed to be here. I did not agree to be small.\nAbena closed her eyes.\nShe would not be small either.\nAcross the room, in the dark, Serwa Boateng was also still awake and she had not decided yet what she thought about her roommate, which meant, without her quite knowing it, that she had already started thinking.','\n',char(10)),897,0,1,NULL,'2026-04-09 05:13:17','2026-04-09 04:52:21','2026-04-09 05:13:17',NULL,1,NULL);
INSERT INTO "chapters" ("id","novel_id","chapter_number","title","content","word_count","is_premium","is_published","audio_url","published_at","created_at","updated_at","scheduled_release_at","part_number","season_id") VALUES(270,38,2,'Old Money Smells Like Leather and Lavender',replace('\n\nThe smell hit Abena first thing Monday morning no, let me rewrite without dashes.\nThe smell reached Abena before she was fully awake. Leather and something floral, expensive in the way that things are expensive when they have never needed to announce it. She opened her eyes to find Serwa already dressed, standing at the small mirror above the shared desk, pressing her collar flat with two fingers like the uniform had personally offended her.\nSix fourteen. Abena checked the wall clock and looked back at the ceiling.\nShe had never shared a room with anyone except her younger sister, and her younger sister smelled like shea butter and sleep. This was different. This was a room that had already decided whose it was.\nShe sat up, reached for her towel, and headed for the bathroom without a word.\nBy the time she returned, Serwa had opened the window and was sitting at the desk reading, her back straight, one leg crossed over the other. She did not look up. Abena dressed, pulled her braids into a bun, and began packing her school bag. The silence was not comfortable. It was the silence of two people choosing, very deliberately, not to begin.\nIt was Serwa who broke it.\n"Your soap."\nAbena looked up. Serwa was still reading.\n"Your soap," Serwa said again. "It''s very strong. Could you keep it in the bucket rather than on the sink?"\nAbena looked at her bar of Rexona on the bathroom shelf, then back at Serwa. "There are two of us using that sink."\n"I know that."\n"So the shelf is for both of us."\nSerwa turned a page. "I''m asking nicely."\n"You''re not asking. You''re instructing."\nThat made Serwa look up. Something moved behind her eyes, quick and controlled, like a door opening and closing in the same breath. She looked at Abena for a long moment, then back at her book.\n"Fine," she said.\nAbena left the soap on the shelf.\nThe morning went the way mornings go when something small has been decided but not yet settled. They walked to breakfast separately without planning to. They sat at different tables without acknowledging it. In their first class, Government, they ended up two seats apart and neither moved closer.\nIt was Efua who told Abena about Serwa at break time, leaning in with the particular energy of a girl who has been waiting for someone to ask.\n"Boateng family. You know Boateng Consolidated? The logistics company? Her grandfather started it. They have a house in East Legon and another one somewhere in England. Serwa has been at this school since Form One. She was made a prefect last term and then she resigned. Nobody knows why. She mostly keeps to herself but not in a sad way. In a choosing way."\nAbena ate her bread roll and said nothing.\n"She''s not mean," Efua added. "She''s just very certain."\nCertain. Abena turned the word over. It was the right word. Serwa moved through the school the way someone moves through a house they own. Not unkind to the furniture. Simply unbothered by it.\nThat afternoon, they were in the room together again, and the space between them had the texture of something unfinished. Abena was doing her reading when Serwa opened her wooden jewelry box, took out a bracelet, held it up to the light from the window, then put it back.\n"Your grandmother," Serwa said, without looking at the photograph. "Is she the one who raised you?"\nAbena did not look up from her textbook. "Why?"\n"I''m making conversation."\n"Earlier you were instructing. Now you''re making conversation."\nSerwa made a small sound. Not quite a laugh. Something adjacent to one. "Yes. My grandfather raised me mostly. My parents travel for work."\nAbena looked up now. Serwa was not looking at her. She was looking at the jewelry box, fingers resting on its lid.\n"My grandmother raised me," Abena said. "My mother is in Accra. She works at a salon in Osu."\nSerwa nodded. She closed the jewelry box.\n"The bracelet," Abena said. "Was that your grandfather''s?"\n"He gave it to me the first time I got a good report card. I was eight." A pause. "I don''t wear it because I''m afraid I''ll lose it."\nAbena looked at the photograph of her own grandmother on the wall. The raised chin. The fishing boat.\n"My grandmother gave me that photograph. She said, whenever I feel like I don''t belong somewhere, I should look at it and remember she felt that way her whole life and showed up anyway."\nThe room was quiet.\nSerwa looked at the photograph for the first time since Abena had placed it there. She looked at it properly, the way you look at something when you have decided it deserves the attention.\n"She sounds difficult," Serwa said.\n"She''s the most difficult person I''ve ever met," Abena said. "I want to be exactly like her."\nThis time the sound Serwa made was closer to a laugh. Small, almost reluctant, like it had escaped without permission. She picked up her book again. Abena looked back at her own.\nThe soap stayed on the shelf.\nNeither of them mentioned it again.','\n',char(10)),869,0,1,NULL,'2026-04-09T04:54:31.184Z','2026-04-09 04:54:31','2026-04-09 04:54:31',NULL,1,NULL);
INSERT INTO "chapters" ("id","novel_id","chapter_number","title","content","word_count","is_premium","is_published","audio_url","published_at","created_at","updated_at","scheduled_release_at","part_number","season_id") VALUES(271,38,3,' The Project',replace('\nMr. Asante wrote four words on the board and the entire class went quiet in the way a class goes quiet when it understands, collectively, that something is about to become a problem.\nWHO MADE GHANA FREE?\nHe underlined it twice, put the chalk down, and turned to face them with the expression of a man who had been teaching history for twenty years and still found it funny that people thought they already knew the answer.\n"Your end of term project," he said. "Twenty percent of your final grade. You will work in pairs. You will not choose your pairs. I will."\nA ripple moved through the room. Abena felt it pass through her own chest, something between dread and the particular exhaustion of already knowing how certain things go. She had done well in every class so far. History was the one subject she had walked into feeling certain, the way you feel certain about something that was handed to you before you were old enough to question it. Her grandmother had opinions about Ghana''s independence. Strong ones. Delivered at the dinner table with the same authority she delivered everything.\nShe was not sure she wanted those opinions graded.\nMr. Asante read the pairs from a printed list. Abena heard her name paired with Serwa Boateng and wrote it down in her notebook without reacting, because she had already known, the way you know things in the ten seconds before they happen, that this was exactly what the term had been building toward.\nAcross the room, Serwa wrote something in her own notebook. Her face gave nothing away.\nThe project brief was detailed. Each pair would research the independence movement and present findings on one specific aspect: the politicians, the protests, the colonial response, or what Mr. Asante called, in a voice that suggested this was the most interesting option, "the people history forgot to name." Each pair would also write a personal reflection connecting their own family histories to the period.\nThat last part was the part Abena heard most clearly.\nTheir own family histories.\nShe thought about her grandmother. About the way Nana talked about certain years like they were weather, like they were things that had happened to the body rather than the country. She had never thought to ask for specifics. She had only ever received the feeling.\nAfter class, Serwa appeared at her elbow in the corridor with the naturalness of someone who had decided to stop pretending they were not going to have to talk to each other.\n"Library. Five o''clock," Serwa said. "I want to start the outline tonight."\n"I have prep."\n"Prep ends at four thirty."\nAbena looked at her. "You already know the prep schedule."\n"I''ve been here since Form One."\nThere was no argument to make against that. Abena said five o''clock and kept walking.\nThe library at Horizon Academy smelled like old paper and the specific cold of a room with air conditioning that had been running since before anyone alive could remember. Abena arrived at four fifty eight. Serwa was already there, at a corner table, two chairs pulled out, a notebook open to a fresh page. She had also, Abena noticed, brought a plate of biscuits from somewhere, which sat between the two chairs like a small, uncertain peace offering.\nThey did not discuss the biscuits.\n"I think we should do the politicians," Serwa said, uncapping her pen. "Most documented. Easiest to source."\n"Mr. Asante said the people history forgot to name was the most interesting option."\n"Mr. Asante doesn''t have to write the paper."\nAbena sat down. "The people history forgot to name is also the most relevant to the personal reflection component. For most of us, our families weren''t the politicians."\nSerwa looked up from her notebook. Something shifted in her expression, not offense exactly, but a kind of alertness. Like a word had been used that required careful handling.\n"My family," she said, measured, "was involved in the independence movement."\n"So was mine." Abena met her eyes. "That''s kind of the problem."\nA pause. The air conditioning hummed.\n"What does that mean?" Serwa asked.\nAbena picked up a biscuit, looked at it, put it down. How to explain the feeling she had carried since Mr. Asante read their names together. It wasn''t a fact yet. It was the shape of a fact, the outline of something she couldn''t see clearly but could feel the edges of, the way you feel the shape of a stone in dark water before your hand closes around it.\n"It means," she said carefully, "that I don''t know yet what my family''s story is. And I think I need to find out before we decide what angle we''re taking."\nSerwa looked at her for a long moment. Then she wrote something in her notebook and turned it so Abena could read it. Two columns. Abena''s family research. Serwa''s family research. Below each column, a row of empty lines.\n"Then we find out," Serwa said. "Both of us. Then we decide."\nIt was the most reasonable thing she had ever said to Abena. It was also, somehow, the thing that made Abena most uneasy, because reasonable was only useful if what you found was something you could reason with.\nShe pulled the notebook toward her and wrote her grandmother''s full name at the top of her column.\nAbena Ama Mensah. Born Abandze. Central Region. 1946.\nShe stared at it for a moment.\nThen she picked up her pen and added one more line.\nWhat happened to her in 1966?\nWord count: 891\nReady for Episode 4 when you are.','\n',char(10)),941,0,1,NULL,'2026-04-09T04:55:51.913Z','2026-04-09 04:55:51','2026-04-09 04:55:51',NULL,1,NULL);
INSERT INTO "chapters" ("id","novel_id","chapter_number","title","content","word_count","is_premium","is_published","audio_url","published_at","created_at","updated_at","scheduled_release_at","part_number","season_id") VALUES(272,38,4,'What My Grandmother Sang',replace('\n\nThe phone rang seven times before her grandmother picked up, which meant Nana had been outside and had walked back in slowly, the way she did everything slowly now, not from weakness but from a lifelong suspicion that hurrying was for people who had not yet learned that things arrive when they arrive.\n"Abena."\nNot a question. Her grandmother never answered the phone with a question. She always knew.\n"Nana." Abena pressed the phone closer to her ear. She was sitting on the bottom step of the Akosua House staircase, the only place in the building where the signal held without argument. Two other girls had walked past and she had turned her face toward the wall both times. Some calls were not for an audience.\n"You are eating?" Nana said.\n"I am eating."\n"You are sleeping?"\n"I am sleeping."\n"You are reading your Bible?"\nA pause. "I am reading my textbooks."\nNana made the sound she always made at that answer, a low note in the back of her throat that managed to be both disapproval and acceptance at the same time. Abena heard the familiar creak of the wooden chair in the corner of the sitting room, the one with the armrest that had been broken and re-tied with cloth so many times the cloth had become part of the chair.\n"Tell me about the school," Nana said.\nAbena told her. Not everything, but the shape of things. The gate. The library. Mr. Asante''s history class. She left out Serwa entirely, not from any plan but because some things needed more space than a staircase phone call.\n"History," Nana said, when she mentioned the project. "What history?"\n"Independence. The movement. We have to research the period and connect it to our family histories."\nSilence.\nNot the silence of someone thinking. The silence of someone deciding.\n"Nana."\n"I heard you."\nAbena waited. Down the corridor, someone''s Afrobeats leaked under a closed door, tinny and cheerful. The generator hummed outside.\n"Your great-uncle Kofi was a Nkrumahist," Nana said finally, in the tone she used for facts that were also warnings. "From before you were born. From before your mother was born. He believed in that man the way some people believe in God. With their whole body."\nAbena had heard the name Kofi her whole life, attached to the vague shape of a man who had existed before her and mattered in some way she had never been given the full details of. "What happened to him?"\nThe wooden chair creaked.\n"What happened to many people," Nana said. "In 1966, when they took Nkrumah out, the men who took him out had lists. Names. People who had been useful to the old government. People who owned things that the new government wanted to own. Your great-uncle Kofi was on one of those lists."\nAbena''s hand tightened around the phone. "What kind of list?"\n"The kind where, afterward, you do not own what you owned before."\nOutside the window at the end of the corridor, the evening was going orange and slow. Abena watched it and said nothing, because there was a shape forming in her chest that she needed to let settle before she put words to it.\n"The land," she said.\n"The fishing land. His cooperative. Six other families were part of it, all from Abandze, all registered under his name because he was the one with the education to do the paperwork. When they came for him, they came for the registration too." Nana''s voice was steady, the way her grandmother''s voice was always steady, built from decades of saying hard things without flinching. "Some of it was redistributed. Some of it was sold to people who knew the right people. That is how those things work."\nAbena stared at the floor tiles. White with small grey flecks, worn pale at the centre from all the feet that had passed over them.\n"Why didn''t you ever tell me this?"\n"You never asked."\n"Nana."\n"You are asking now." Not unkind. Simply exact. "I am telling you now."\nAbena thought about her column in Serwa''s notebook. The empty lines below her grandmother''s name. The question she had written at the bottom and not yet answered. She thought about Serwa at the library table, two columns, the reasonable architecture of someone who believed that finding things out was the same as being able to handle them.\n"Did we get any of it back? The land?"\nA long pause. Longer than the others.\n"Some questions," Nana said, "have answers that take longer than a phone call."\nIt was not a no. It was also not a yes. It was the shape of something her grandmother had been carrying for fifty years, and Abena felt the weight of it pass through the phone line and settle somewhere between her ribs.\nThey talked for a few more minutes about smaller things. Her mother''s health. The cousin''s new baby. The price of fish at the Abandze market, which Nana reported with the gravity of someone delivering war news. When they said goodnight, her grandmother added, as she always did, the same Fante phrase she had been saying since Abena was small enough to be carried.\nHwe wo ho. Hwe wo ho.\nWatch yourself. Watch yourself.\nAbena sat on the step for a long time after the call ended, the phone warm in her hand, the generator still humming, the Afrobeats still leaking under the door.\nThen she went upstairs, opened her notebook, and beneath her great-uncle Kofi''s name, she wrote one word.\nLand.','\n',char(10)),928,1,1,NULL,'2026-04-09T04:57:17.628Z','2026-04-09 04:57:17','2026-04-09 04:57:17',NULL,1,NULL);
INSERT INTO "chapters" ("id","novel_id","chapter_number","title","content","word_count","is_premium","is_published","audio_url","published_at","created_at","updated_at","scheduled_release_at","part_number","season_id") VALUES(273,38,5,' The Boateng Name',replace('\n\nSerwa had a system for research the way she had a system for everything: start with the largest container and work inward. General to specific. Broad to narrow. Emotion nowhere in the process until the process was complete.\nIt had always worked.\nShe started with the school library''s archive shelf, a row of green-spined volumes that smelled of decades and had not been touched recently enough to be free of dust. She found three books covering Ghana''s post-independence period, signed them out at the desk, carried them to the corner table she had already begun to think of as theirs, and opened the first one.\nAbena had not arrived yet. It was Saturday morning, eight fifteen. Most of the school was still in bed or moving toward breakfast with the specific slowness of girls who had nowhere to be. Serwa had eaten at seven, alone, which was how she preferred mornings.\nShe read for forty minutes before she found the first useful thing.\nIt was a chapter on what the book called "administrative restructuring" following the 1966 coup. The language was careful, academic, written by someone who had clearly decided that bureaucratic phrasing was a kind of protection. What it described, beneath all the careful language, was the process by which property, land, and businesses associated with the Nkrumah government had been reviewed, seized, or redistributed by the new military administration.\nSerwa took notes in her precise, taught handwriting. She was not yet looking for her family. She was building context the way you build a foundation, first, before anything else goes on top of it.\nShe was on her second book when Abena arrived, set her bag down, poured herself a glass of water from the library''s side table, and sat without greeting. They had an arrangement now that neither had spoken aloud. Silence at the start. Work first. Talking when there was something worth saying.\nIt was, Serwa thought, the most functional relationship she had at this school.\n"Anything?" Abena asked, after a few minutes.\n"Context. Nothing personal yet." Serwa turned a page. "You?"\n"I called home." Abena opened her own notebook. "I have a name. My great-uncle. He was part of a fishing cooperative. Land registered in his name." A pause. "1966 was not good for him."\nSerwa looked up briefly, then back at her book. She filed the information without responding to it, not from indifference, but because she understood that some things were offered as facts and not yet as conversations.\nShe found her grandfather''s name forty minutes later.\nIt was in a supplementary index at the back of the third volume, a record of business registrations filed in the six months following the coup. New companies. New land transfers. New contracts issued by the transitional government to private citizens deemed, in the language of the index, "aligned with national development priorities."\nBoateng, Emmanuel K. Accra. Registered: July 1966. Transport and Logistics. Government contract awarded.\nShe read it twice.\nThen she sat up straighter, the way she always did when something confirmed what she had quietly believed.\nHer grandfather had built Boateng Consolidated from nothing, or so the family story went. He had seen an opportunity, taken it, worked without sleeping for fifteen years, and turned one truck and one government contract into a company that now had thirty vehicles, a warehouse in Tema, and offices in two cities. Her father told that story at every family gathering with the specific pride of a man who believed that inheritance was not what you received but what you built on.\nHere was the contract. Here was the beginning. July 1966.\nShe wrote it in her notebook under the heading Boateng Family, documented.\nEmmanuel K. Boateng. Transport contract. Post-coup administration. July 1966.\nShe underlined his name once. It looked the way she had always imagined it would look in a book: solid, earned, permanent.\n"I found something," she said.\nAbena looked up.\n"My grandfather. His first government contract. It''s in the post-coup business registry." Serwa turned the book so Abena could see the index page. "July 1966. This is where Boateng Consolidated starts."\nAbena looked at the page. Her eyes moved across the index, not just to Serwa''s grandfather''s entry but across the whole column, the way someone reads when they are looking for more than what they were shown. Serwa noticed but said nothing.\n"That''s significant," Abena said, carefully.\n"It is." Serwa took the book back. "My father always said my grandfather built the company on instinct and timing. He had the right idea at the right moment." She looked at the entry again. "Here''s the moment."\nAbena was quiet for a few seconds, her pen resting against her notebook without writing. Then she said, "What does the contract cover? Does it say?"\n"Transport and logistics. Government routes." Serwa scanned the entry. "There''s a reference code. We might be able to find the full contract record in the national archive section."\n"We should look for it," Abena said. Her voice was even, but there was something underneath it, some frequency that Serwa''s ear caught without being able to name.\n"We will," Serwa said.\nShe wrote the reference code in her notebook, neat and exact, and circled it once. Her grandfather''s name sat at the top of her column, underlined and certain, the beginning of everything her family had become.\nShe did not yet know what Abena had written at the top of hers.\nShe did not yet know that two columns in the same notebook could point, like two rivers, toward the same water.','\n',char(10)),928,1,1,NULL,'2026-04-09T04:58:32.388Z','2026-04-09 04:58:32','2026-04-09 04:58:32',NULL,1,NULL);
INSERT INTO "chapters" ("id","novel_id","chapter_number","title","content","word_count","is_premium","is_published","audio_url","published_at","created_at","updated_at","scheduled_release_at","part_number","season_id") VALUES(274,38,6,'The Same Year',replace('\nThe photograph was not supposed to be there.\nAbena found it on a Thursday evening, inside the back cover of a library book she had requested from the archive shelf, a slim volume on coastal communities and land use in post-colonial Ghana. It must have been used as a bookmark decades ago and forgotten, the way things get forgotten inside books, quietly, without ceremony, until someone opens the right page.\nShe almost set it aside. Then she turned it over.\nIt was a formal photograph, the kind taken at an official event, black and white and slightly overexposed the way photographs were in that era when the light was stronger than the film expected. A group of men stood in two rows in front of a government building. They were dressed in suits and kente cloth, serious-faced, the occasion written into their posture. Someone had written on the back in faded pencil, the handwriting careful and old.\nLand Registration Ceremony, Accra. Central Region Cooperative Transfer. 1966.\nAbena sat very still.\nShe read the caption again. Then she turned the photograph over and looked at the faces. Eight men. She did not know any of them. She looked at the building behind them, at the sign above the entrance, at the way the men in the front row stood slightly apart from the men in the back row, not in the way of strangers but in the way of people on different sides of a table who have been asked to stand together for a photograph.\nShe turned it over again.\nCentral Region Cooperative Transfer. 1966.\nHer great-uncle Kofi had run a cooperative in the Central Region. Her grandmother had told her. Land registered in his name. Six families. Gone after the coup.\nShe looked at the photograph a third time. She did not know which face was his. She did not know if he was in this photograph at all, or if this was a different cooperative, a different transfer, a different story that only rhymed with hers. But the year sat on the back of the photograph like a stone, and she could not make it lighter by looking at it harder.\nShe put the photograph in her notebook between two pages and kept reading.\nSerwa arrived at six, the time they had agreed on, with her own stack of books and a container of chin chin her mother had sent in a weekend package. She set the container between them, an act Abena had come to understand was Serwa''s version of warmth, practical, shareable, requiring no acknowledgment.\nThey worked in silence for twenty minutes.\n"I requested the contract record from the reference code," Serwa said, without looking up. "The librarian says it will take a week to locate. It''s in the older physical files."\n"Okay."\n"I also found a newspaper archive. The Ghanaian Times, 1966. There are issues from the months after the coup. I''ve been reading through them."\nAbena looked up. "Anything useful?"\n"A lot of announcements. Government appointments. Business registrations." Serwa turned a page. "Property notices."\nThe word landed between them softly, but it landed.\n"Property notices," Abena repeated.\n"Standard for the period, apparently. When land changed hands through the new administration, they published notices in the paper. Public record." Serwa''s voice was even, informational, the tone she used when she was reporting rather than interpreting. "I''ve been compiling a list of the ones from the Central Region."\nAbena opened her notebook to the page where the photograph was pressed. She took it out and placed it on the table between them.\nSerwa looked at it. Then she picked it up and read the back.\nNothing in her face moved. But she held the photograph for three seconds longer than necessary before she set it down again.\n"Where did you find this?"\n"Inside a library book. Back cover."\nSerwa looked at it again, at the faces, at the building, at the caption. "Central Region Cooperative Transfer," she read aloud, quietly, as if saying it at low volume changed what it said.\n"My great-uncle ran a cooperative in the Central Region," Abena said. "Land. Fishing rights. Six families."\nSerwa put the photograph down carefully, as if it were something that could break. She did not say anything for a moment. Outside the library window, the last of the evening had gone dark and the compound lights had come on, casting the room in a yellow warmth that felt, to Abena, slightly wrong for the conversation they were not yet having.\n"The property notices I found," Serwa said finally. "Some of them are transfers to private buyers. Not government redistribution. Private sales, at prices the newspaper did not print." She paused. "My grandfather''s contract covered government transport routes. But I want to check whether he also acquired land in that period."\nAbena heard what Serwa was doing. She was following the logic. The same logic Abena had been following since her grandmother said the words redistributed and sold to people who knew the right people. Serwa was a person who followed logic wherever it went, even when it went somewhere uncomfortable.\nIt was the thing about her that Abena respected most and feared most in equal measure.\n"We''re reading the same event," Abena said. "From different sides."\nSerwa looked at her. In the yellow light her expression was careful and open in a way Abena had not seen on her before, not guarded certainty, but something that had not yet decided what it was.\n"I know," she said.\nThe chin chin sat between them, untouched.','\n',char(10)),927,1,1,NULL,'2026-04-09T05:02:10.766Z','2026-04-09 05:02:10','2026-04-09 05:02:10',NULL,1,NULL);
INSERT INTO "chapters" ("id","novel_id","chapter_number","title","content","word_count","is_premium","is_published","audio_url","published_at","created_at","updated_at","scheduled_release_at","part_number","season_id") VALUES(275,38,7,' A Name in the Ledger',replace('\n\nThe physical files smelled like they had been waiting for someone to be sorry.\nThe librarian, Mrs. Dadzie, brought the folder out from the archive room on Friday afternoon with the careful movements of someone handling something that was not fragile but deserved to be treated as if it were. It was a brown cardboard folder, tied with string that had once been red and was now the colour of old brick, and on the front tab, in typed letters that had faded to the colour of weak tea: Government Transport Contracts and Land Acquisitions, Accra Region, 1966 to 1968.\n"Sign here," Mrs. Dadzie said, sliding a register across the counter. "You may use it at the table only. No removing pages. No photographs." She paused and looked at them both over her glasses. "Whatever you find in there, it stays in this library until it goes back in that folder."\nAbena signed her name. Serwa signed hers beneath it.\nThey carried the folder to the corner table. Neither of them opened it immediately. It sat between them for a moment, the string still tied, while the library went about its quiet business around them.\nSerwa untied the string.\nThe documents inside were ordered by date, the oldest at the bottom, and they worked through them systematically the way they had learned to work together over the past weeks, Serwa cataloguing, Abena cross-referencing against her own notes. Transport contracts first. Serwa found her grandfather''s original contract on the fourth page, two typed sheets, government letterhead, Emmanuel K. Boateng named as the awarded contractor for three Central Region routes. The language was formal and exact. The payment terms were listed. The routes were listed.\nOne of the routes ran from Accra through the Central Region to the coast.\nAbena wrote it in her notebook without comment.\nThey kept reading.\nThe land acquisition documents began halfway through the folder. These were different in character from the transport contracts, less clean, the language more layered, more careful in the way that language is careful when it is covering the distance between what happened and what was written down about what happened. Transfers of title. Changes of registration. Properties described by plot number and region with the original owners listed in a column on the left and the new owners in a column on the right, and between those two columns, a third column that said only: Basis of Transfer.\nMost of the entries in that third column said: Government acquisition, NLC Decree.\nSome of them said: Private purchase, verified.\nAbena moved down the list slowly. Her great-uncle''s cooperative had been registered under the name Mensah-Annan Coastal Cooperative, Abandze. She had that from her grandmother. She kept her finger on the left column and moved it down the page one entry at a time, reading each name, each plot number, each region.\nShe found it on the fourteenth entry.\nMensah-Annan Coastal Cooperative. Abandze, Central Region. Plots 7, 8, 9, and coastal access right, Ref. CR-044. Original registrant: Kofi Mensah-Annan.\nShe stopped breathing for exactly one second.\nIn the right column, under New Registration:\nBoateng, Emmanuel K. Accra.\nIn the middle column, under Basis of Transfer:\nPrivate purchase, verified. July 1966.\nThe library was very quiet.\nAbena looked at the entry for a long time. Long enough that the words stopped being words and became shapes, and then became words again. She was aware of Serwa beside her, reading the same page, and she knew from the quality of the silence that Serwa had reached the same entry.\nNeither of them spoke.\nAbena looked at the plot numbers. Three plots and a coastal access right. In Abandze, coastal access was not a convenience. It was the difference between a fishing cooperative that could function and one that could not. Without access to the water, the land above it was decorative.\nHer grandmother had said: some of it was sold to people who knew the right people.\nHere was the person. Here was the sale. Here was the month.\nJuly 1966. The same month Emmanuel Boateng received his government transport contract. Two transactions. One man. One month. And somewhere in the Central Region, six families who had built something together and then watched it transfer, in the language of a typed document, to a column on the right.\n"Serwa," Abena said.\n"I see it."\n"Your grandfather bought the land."\n"I see it," Serwa said again. Her voice had not changed in volume or tone, but something inside it had, the way the sound of water changes when the depth beneath it changes.\nAbena looked at her. Serwa was staring at the document with the expression of someone doing a very large calculation, not refusing the answer, not yet, but needing every step of the working to be visible before she would accept where it was going.\n"Private purchase, verified," Abena read aloud. "That means he chose to buy it. It wasn''t assigned to him."\n"I know what it means."\n"I need you to know that I know what it means too." Abena kept her voice even. "I''m not accusing you of anything. I''m saying that this document exists and we have both read it."\nSerwa closed the folder. Not with anger, with the care of someone who needed to do something with her hands. She retied the string, slowly, looping it the same way it had been looped before.\n"My grandfather was a good man," she said. The sentence came out like something she had always known and was now, for the first time, holding up to a different light.\nAbena looked at the photograph still pressed inside her notebook. Eight men in front of a government building. The year on the back.\n"I know," she said. And she meant it, or meant the part of it that was true, which was that good men were capable of transactions, and transactions were capable of lasting longer than the men who made them.\nSerwa stood up. "I need to think."\n"Okay."\n"I''ll be at breakfast tomorrow."\n"Okay."\nShe picked up her bag and left the library without looking back. Abena sat alone at the corner table with the folder between her palms, the string retied, the documents inside it exactly as they had been, unchanged by being read, the way history is always unchanged by being discovered.\nOnly the people change.','\n',char(10)),1064,1,1,NULL,'2026-04-09T05:03:21.201Z','2026-04-09 05:03:21','2026-04-09 05:03:21',NULL,1,NULL);
INSERT INTO "chapters" ("id","novel_id","chapter_number","title","content","word_count","is_premium","is_published","audio_url","published_at","created_at","updated_at","scheduled_release_at","part_number","season_id") VALUES(276,38,8,' What Nana Didn''t Say',replace('\nShe waited until Sunday.\nNot because Sunday was the right day for hard conversations but because Saturday she had spent walking, which was what she did when something was too large for a room. She had walked the school compound three times after breakfast, past the science block, past the small garden someone had planted beside the chapel that nobody attended anymore, past the back fence where the noise of the road outside came through in waves. She had walked until the thing in her chest stopped feeling like panic and started feeling like a question she could hold steadily enough to ask.\nSunday morning, after chapel, she sat on the step with her phone.\nSeven rings. Then the creak of the chair.\n"Abena."\n"Nana."\nThey did the usual round. Eating, sleeping, reading her Bible. She said yes to all three this time because she needed her grandmother in a good mood, or at least a patient one, before she said the next thing.\n"Nana, I need to ask you something and I need you to tell me the truth."\nA pause. "When have I ever told you anything else?"\n"You told me things take longer than a phone call."\n"Some things do."\n"This one can''t." Abena pressed her back against the wall of the staircase. Above her, the building went about its Sunday business, footsteps and music and the distant percussion of someone''s bucket in the bathroom. "I found a document, Nana. A land acquisition record from 1966. Plots seven, eight, and nine. Coastal access right CR-044. Abandze, Central Region. Original registrant, Kofi Mensah-Annan."\nSilence.\nNot the thinking silence or the deciding silence. A different silence. The silence of someone who has been waiting, without knowing they were waiting, to hear a set of words said out loud, and now that they have been said, does not know what to do with her hands.\n"Nana."\n"Where did you find this document?"\n"The school library archive. We requested it for the history project." A breath. "My project partner''s grandfather is listed as the buyer. Private purchase. July 1966."\nThe chair creaked. Abena imagined her grandmother shifting, setting down whatever was in her hands, looking at the window the way she always looked at the window when a conversation required the outside world as a witness.\n"His name," Nana said. "This grandfather."\n"Emmanuel Boateng."\nThe silence that followed was the longest one yet. It had a texture to it, dense and old, the silence of a name that had lived in someone''s memory for fifty years without being spoken into a telephone.\n"You know that name," Abena said.\n"Yes."\n"Did you always know?"\n"Abena."\n"Nana, did you always know whose name was in the right column?"\nHer grandmother exhaled. It was not a sigh exactly. It was the sound of something being set down that had been carried a very long time.\n"Your great-uncle Kofi knew the man," Nana said. "Not well. The way men knew each other in those days when business crossed paths. Boateng had trucks. Kofi''s cooperative needed things moved, fish, supplies, sometimes equipment. They had an arrangement." She paused. "When the coup came and the soldiers started going through the lists, Kofi was on one of them. We did not know, at first, how he got there. Later we understood. Someone had given his name."\nAbena stared at the floor tiles. "Who gave his name?"\n"We were never certain." Her grandmother''s voice was careful now, careful in the specific way of someone who has spent decades being fair to a story that never treated them fairly. "We had our beliefs. We never had proof."\n"But you believed it was Boateng."\n"We believed it was someone who then benefited very quickly from Kofi''s misfortune. The land sold within the same month. Private purchase. His cooperative, the registration, everything Kofi had spent eight years building. Gone." The wooden chair creaked again. "In those days you did not go to court. You did not put it in the newspaper. You kept your family safe and you remembered and you kept living."\nAbena thought about the document. The two columns. The third column in between. Basis of Transfer: Private purchase, verified.\n"Why didn''t you tell me?"\n"Tell you what, exactly? That we believed a man we could not prove anything against had taken what was ours? That your great-uncle spent the rest of his life fishing from a boat he had to rent because the land the boat should have launched from belonged to someone else?" Her grandmother''s voice did not break. It was the voice of someone who had already done their breaking, privately, years before Abena was born. "I told you what I knew. The land was gone. That was the truth."\n"The whole truth is bigger than that."\n"The whole truth is always bigger than what we give children." A pause. "You are not a child anymore. You found the document yourself. That is how I always imagined it would happen, when it happened."\nAbena sat with that. The idea of her grandmother imagining this moment, not engineering it, not preventing it, simply knowing it would come and waiting with the patience of someone who trusted the water to carry things to shore eventually.\n"My project partner," Abena said. "Serwa Boateng. Emmanuel Boateng''s granddaughter. She is my roommate."\nThe silence this time was so complete that Abena checked the screen to make sure the call was still connected.\n"Nana."\n"I heard you."\n"She didn''t know. She found her grandfather''s name in the registry and she was proud. She didn''t know what it was connected to."\nHer grandmother said nothing.\n"She read the document with me. She saw it. She left without saying much, but she wasn''t pretending." Abena pressed her palm flat against the cool wall beside her. "She''s not him, Nana."\nMore silence. Then, quietly, in Fante:\n"No. She is not him."\nIt was the most her grandmother would give. Abena understood it was enough, that it was not absolution or resolution or the closing of anything, but it was her grandmother''s voice saying the truest thing it could manage across fifty years and a telephone line.\nThey said goodnight.\nAbena sat on the step with the phone in both hands and thought about what had not been said. The name her grandmother had believed for fifty years without proof. The arrangement between two men that had turned, in one month, into something else entirely. The fact that her grandmother had packed all of it into silence and handed Abena a photograph instead, and said: watch yourself, watch yourself.\nShe had been watching.\nShe just had not known, until now, exactly what she was watching for.','\n',char(10)),1119,1,1,NULL,'2026-04-09T05:04:36.789Z','2026-04-09 05:04:36','2026-04-09 05:04:36',NULL,1,NULL);
INSERT INTO "chapters" ("id","novel_id","chapter_number","title","content","word_count","is_premium","is_published","audio_url","published_at","created_at","updated_at","scheduled_release_at","part_number","season_id") VALUES(277,38,9,'What Your Grandfather Built',replace('\n\nSerwa did not call home on Sunday.\nShe had picked up her phone twice and put it down twice, which was two more times than she was accustomed to hesitating over anything. She was not, by nature, someone who circled a thing. She was someone who walked directly at it, assessed it, and decided. Hesitation, in her experience, only gave a problem more room than it deserved.\nBut this was not a problem. It was something older and heavier than that.\nShe called on Monday evening, after prep, from the far end of the corridor where the window looked out over the back fence and the road beyond it. She could hear the traffic. She found it useful, the noise of things continuing normally while other things stopped.\nHer mother answered on the second ring.\n"Serwa. We were just talking about you."\n"Who is we?"\n"Your father and I. Dinner." The sound of cutlery, a chair, her mother settling into the particular posture she took when Serwa called, half present, half still inside whatever conversation had just been interrupted. "How is school?"\n"Fine." Serwa looked at the road. A trotro moved past, painted yellow and black, packed full. "I need to ask you something about Grandpa Emmanuel."\nA half second pause. The cutlery sound stopped.\n"What about him?"\n"His first government contract. 1966. Transport routes through the Central Region." Serwa kept her voice even, the way she kept everything even when she needed the other person to stay in the conversation. "I found it in a library archive. I''m doing a history project."\n"Yes, that was his beginning. Your father has told that story many times."\n"I know the story." Serwa pressed her shoulder against the wall. "I also found the land acquisition records from the same period. July 1966. Three plots and a coastal access right in Abandze. Original registrant, a man named Kofi Mensah-Annan." She paused. "New registrant, Emmanuel Boateng."\nSilence.\nNot her mother''s usual silence, the efficient kind that meant she was thinking or redirecting. This was a held silence, the kind that required effort.\n"Mama."\n"Where exactly did you find these records?"\n"School archive. It''s a physical file. Government document." Serwa watched the road. "His name is in both columns. The transport contract and the land purchase. Same month."\n"Serwa." Her mother''s voice had changed register. Still controlled, but the control was doing more work now. "These are historical documents. The period after the coup was complicated. Many transactions happened that were standard practice at the time."\n"I''m not asking about standard practice. I''m asking about this specific transaction."\n"I don''t see why —"\n"Mama." Serwa closed her eyes briefly. "The man whose land Grandpa bought was reported to the NLC. Someone gave his name to the soldiers. He lost his cooperative, his land registration, everything. Within the same month, Grandpa had the land and a government contract." She opened her eyes. "I am asking you if our family knows how Kofi Mensah-Annan''s name got onto that list."\nThe traffic moved outside. Someone on the road was selling something, his voice rising above the engines in a rhythmic call.\nHer mother exhaled. It was not the exhale of someone who did not know. It was the exhale of someone who had hoped, for a long time, not to be in this particular conversation.\n"Your grandfather," her mother said slowly, "was a man of his time. The coup created opportunities for people who were positioned correctly. He was positioned correctly."\n"That is not an answer."\n"It is the answer that was given to me."\n"By who?"\nA pause. "By your grandmother. Before she died." Her mother''s voice had gone careful in a way Serwa had never heard before, careful and tired, the voice of someone carrying a piece of furniture that was too heavy to put down in a doorway. "She told me that Emmanuel had known the Mensah-Annan man. That there had been a dispute between them, money owed, a misunderstanding about a shipment. That after the coup, Emmanuel had reported him as a Nkrumahist." A breath. "She said he had done it to protect the family. That everyone was reporting someone in those days. That Kofi Mensah-Annan would have lost everything regardless."\nSerwa stood very still.\n"She believed that?"\n"She chose to believe it. There is a difference." Her mother''s voice was quiet now. "And once she told me, I chose to believe it too, because the alternative was to spend my life inside a guilt that was not mine to carry and could not be returned to anyone."\nSerwa thought about her grandfather''s name in the ledger. The pride she had felt, reading it. The clean, uncomplicated pride of a girl who believed that what her family had built had been built from nothing. Instinct and timing, her father always said. The right idea at the right moment.\nThe right idea. The right man reported. The right month to buy.\n"The land," Serwa said. "Does it still generate income for the family?"\nA long pause. "The Tema warehouse is partly built on a parcel that came from that original Central Region acquisition."\nSerwa did not say anything.\n"Serwa."\n"I''m here."\n"What are you going to do with this?"\nIt was, she realised, the wrong question. Not because her mother was wrong to ask it, but because it assumed the thing that had to be decided was what to do with the information rather than what to do with herself, which was the only question that had ever actually mattered.\n"I don''t know yet," she said.\n"Be careful," her mother said. "Not for our sake. For yours. History is something you can look at without climbing inside it."\nSerwa almost said: but some of us never had the choice to stay outside. She did not say it because it was not her sentence to say. It belonged to someone else. Someone sleeping six feet away from her in room fourteen who had been climbing inside this particular history since before she knew there was a document to find.\n"Goodnight, Mama."\nShe stood at the window for a long time after the call ended. The road had quieted. The trotro was gone. The man selling things had moved further down and his voice was faint now, just the rhythm of it, the call without the words.\nShe thought about the bracelet in the wooden box. Given to her at eight years old for a good report card. She had always kept it safe because she was afraid to lose it.\nShe understood now that she had been afraid of the wrong thing.','\n',char(10)),1106,1,1,NULL,'2026-04-09T05:05:48.188Z','2026-04-09 05:05:48','2026-04-09 05:05:48',NULL,1,NULL);
INSERT INTO "chapters" ("id","novel_id","chapter_number","title","content","word_count","is_premium","is_published","audio_url","published_at","created_at","updated_at","scheduled_release_at","part_number","season_id") VALUES(278,38,10,' The Fight',replace('\nIt started over the project outline, which was not what it was about.\nAbena had drafted the personal reflection section over the weekend, three paragraphs, careful and factual, naming the cooperative, the land, the year, the transfer. She had not named Emmanuel Boateng. She had written a private buyer and left the space between those words deliberately empty, because she had not yet decided how much truth a school project was required to hold.\nShe slid it across the library table on Tuesday evening without comment.\nSerwa read it. Her face did not move. She read it a second time, then set it down and looked at Abena.\n"You wrote a private buyer."\n"Yes."\n"You know who the buyer was."\n"Yes."\n"Then why —"\n"Because I was trying," Abena said, and her voice came out with more edge than she intended, "to protect you."\nSomething shifted in Serwa''s expression. Not gratitude. Something more complicated, something that looked almost like offense.\n"I don''t need protecting."\n"I know you don''t. I was doing it anyway."\n"By leaving my grandfather out of a document that is supposed to be honest."\nAbena looked at her. "Your grandfather who bought land from a man whose name he had just given to soldiers."\nThe sentence sat on the table between them like something spilled.\nSerwa''s jaw tightened. "We don''t know that he gave the name."\n"Your mother told you he did."\n"My mother told me what your grandmother believed. That is not the same as proof."\n"It is the same as pattern," Abena said. "Same month. Same man. Same family that ended up with everything and the other family that ended up with nothing."\n"People lost things in 1966 for many reasons. The coup was not one man''s doing."\n"I know that. I also know that your grandfather had a specific arrangement with my great-uncle and then specifically bought his specific land in the specific month after he specifically lost it." Abena heard her own voice rising and did not stop it. "That is not a coincidence, Serwa. That is a sequence."\nSerwa stood up. It was not dramatic, it was the movement of someone who needed to be vertical for what came next.\n"My grandfather built something," she said. "He worked for thirty years. He built a company that employs people. My father went to university because of what he built. I am at this school because of what he built." Her voice was controlled, precise, each word placed like a foot on uncertain ground. "I am not going to sit here and reduce him to one transaction in one month in one document."\n"I am not reducing him." Abena stood too, because the table felt wrong now, felt like a surface that required them to be equal and seated and reasonable, and she was done being reasonable. "I am saying that one transaction in one month cost my great-uncle everything. Six families. Coastal access they never got back. My grandmother''s brother spent the rest of his life renting a boat to fish water that used to be registered in his name." Her voice cracked on the last word, not from weakness, from the specific pressure of a truth that had been compressed for too long. "He died renting it. Your grandfather died owning a warehouse."\nSerwa looked at her. Her eyes were bright, not with tears exactly, but with the effort of holding something in.\n"What do you want me to do?" she said. "Tell me. What is it that you want from me?"\n"I don''t want anything from you."\n"You want me to apologise for my family."\n"I want you to stop defending a man who does not need defending from the truth."\n"He is my grandfather."\n"And Kofi Mensah-Annan was my family." Abena''s voice dropped. Quieter was worse. "He was my grandmother''s brother and she has never said his name to me without her voice changing and I was sixteen years old before I understood why, and now I understand why, and you are asking me to write private buyer in a school project so that your feelings are comfortable."\nThe library was empty except for them. Mrs. Dadzie had gone home an hour ago. The fluorescent light above them hummed its indifferent hum.\nSerwa looked away first. She looked at the window, at the dark compound outside, at her own reflection in the glass, and Abena watched her do it and felt, underneath the anger, something that was almost grief. Because Serwa''s face in that moment was not the face of someone who disbelieved her. It was the face of someone who believed her completely and had not yet found a place to put it.\n"I did not do this," Serwa said, quietly, to the window. "I was not there. I was not born."\n"I know that."\n"Then why does it feel like you are looking at me like I was?"\nAbena opened her mouth. Then she closed it.\nBecause sometimes, she thought but did not say, the person in front of you is the only place the history has a face. Because the warehouse exists and the rented boat existed and the document with two columns exists and her grandmother''s changed voice exists, and none of those things care about who was born when.\nBut she did not say it. Because it was true and also not fair and she was tired and so was Serwa, and some truths needed more than a Tuesday evening to be said correctly.\n"I think we should stop for tonight," Abena said.\nSerwa picked up her bag. She did not say goodnight. She walked to the door, stopped with her hand on the frame, and stood there for a moment with her back to Abena.\n"I''ll write my section of the reflection myself," she said. "You write yours. We don''t have to agree on what happened. We just have to hand something in."\nShe left.\nAbena stood alone in the library with the draft between them on the table, the words private buyer looking up at her like a question she had already answered wrong.','\n',char(10)),1021,1,1,NULL,'2026-04-09T05:07:15.780Z','2026-04-09 05:07:15','2026-04-09 05:07:15',NULL,1,NULL);
INSERT INTO "chapters" ("id","novel_id","chapter_number","title","content","word_count","is_premium","is_published","audio_url","published_at","created_at","updated_at","scheduled_release_at","part_number","season_id") VALUES(279,38,11,' 1966 Wasn''t Our Year',replace('\n\nAbena woke at four in the morning and did not go back to sleep.\nShe lay on her back in the dark and listened to Serwa''s breathing across the room, slow and even, the breathing of someone who had either found peace or was very good at performing it. She could not tell which. Three weeks ago she would have said she could not read Serwa at all. Now she could read most of her. This, she could not read.\nShe turned onto her side and looked at her grandmother''s photograph, invisible in the dark, present anyway.\nShe had been thinking, since the library, about the word sequence. She had used it in the fight and it had been the right word and also a brutal one, because a sequence implied intention, and intention implied a man who had looked at another man''s misfortune and decided to profit from it deliberately. Maybe that was true. Her grandmother believed it was true. Her grandmother was not a woman who believed things carelessly.\nBut she had also been thinking about Serwa''s face at the window. The reflection in the glass. The way she had said: I did not do this. Not as an excuse. As a fact that was also a wound.\nBoth things were true. The sequence was real. Serwa was not responsible for it. Abena knew how to hold one true thing. She was still learning how to hold two.\nShe thought about Kofi Mensah-Annan, a man she had never met, dead before her mother was grown, reduced in her imagination to a name and a boat and a cooperative and a document. She tried to make him fuller than that. She gave him a face like her grandmother''s, the same chin, the same direct gaze. She gave him the eight years of work her grandmother had mentioned, eight years of organising six families and doing the paperwork and registering the land and building something that was supposed to outlast him.\nIt had outlasted him. Just not for his family.\nAt five thirty the compound lights came on outside the window and the room went from black to grey. Serwa''s breathing changed. Not awake, but closer to it. Abena closed her eyes and kept them closed until the alarm went off at six.\nSerwa skipped breakfast.\nShe sat on the chapel steps, which nobody used in the mornings, with her notebook open to a blank page and her pen uncapped and nothing written. The air was cool and smelled of cut grass and the bread rolls from the dining hall drifting across the compound.\nShe was thinking about the bracelet.\nHer grandfather had given it to her for a good report card. She had been eight. He was a tall man with a careful way of speaking and hands that were always warm, and he had said: this is for a girl who understands that the mind is the only thing nobody can take from you. She had not understood what he meant at eight. She had understood that the bracelet was gold and that he was proud of her and that pride from him felt like being handed something solid.\nShe still believed he had been a good grandfather. She was finding that this was possible to believe at the same time as believing that he had done a thing that was not good. People were not one thing. She knew this. She had always known this.\nWhat she had not known was that knowing it in theory and needing it in practice were entirely different weights.\nHer mother had said: history is something you can look at without climbing inside it. Serwa had almost said: some people never had the choice to stay outside. She thought about why she hadn''t said it. She had stopped herself because she thought it would sound like she was taking Abena''s side against her own family.\nBut it was simply true.\nHer family had always been on the outside of 1966, looking in at it as a good year, a beginning, a foundation. Abena''s family had been inside it, in the cold part, in the part where things were lost. Neither of them had chosen their position. They had both been handed it at birth, wrapped up in family stories and photographs and bracelets and names not spoken at dinner tables.\nShe opened her notebook and wrote a single line.\nWhat does it mean to benefit from something you didn''t do?\nShe looked at it for a long time. Then she wrote underneath it:\nWhat does it mean to keep benefiting?\nShe did not write an answer because she did not have one yet. But she thought about the Tema warehouse. Her grandfather''s route through the Central Region. The coastal access right that had passed from Kofi Mensah-Annan''s cooperative into her family''s holdings and stayed there, quietly, for fifty years while the Mensah-Annan family rented boats.\nShe thought about Abena''s face when she said: he died renting it.\nNot anger in the face. Something underneath anger. Something that had been living in her family''s body for two generations before Abena was old enough to understand what it was.\nSerwa capped her pen.\nShe was not responsible for 1966. She understood this clearly and without the need to argue it. She was also, and this was the part she had been circling for three days, not separate from it. The school she sat in front of. The uniform she wore. The bracelet in the wooden box. All of it had, somewhere in its roots, a month in 1966 and a document with two columns and a man who had known exactly what he was buying.\nShe could not unknow that.\nThe question was what a person did with a truth they could not unknow, when the person who deserved an answer from her family was sleeping six feet away from her every night.\nShe did not have the answer yet.\nBut she thought, for the first time, that she might be ready to look for it.\n','\n',char(10)),1013,1,1,NULL,'2026-04-09 05:13:36','2026-04-09 05:08:19','2026-04-09 05:13:36',NULL,1,NULL);
INSERT INTO "chapters" ("id","novel_id","chapter_number","title","content","word_count","is_premium","is_published","audio_url","published_at","created_at","updated_at","scheduled_release_at","part_number","season_id") VALUES(280,38,12,' The Gap Between Us',replace('\n\nThe history project was due on Friday.\nOn Thursday evening Serwa came back to the room after prep, set her bag down, and placed a folded piece of paper on Abena''s desk without a word. Then she sat on her bed and opened a book and read, or performed reading, which Abena had learned to distinguish by the rate at which pages turned.\nAbena looked at the paper. Then she unfolded it.\nIt was Serwa''s section of the personal reflection. Two paragraphs, the handwriting precise as always, but something different in it, some quality of pressure in the pen strokes that suggested it had not been written quickly.\nShe read it.\nMy grandfather, Emmanuel Kofi Boateng, registered his first government contract in July 1966, one month after the coup that removed Kwame Nkrumah from power. He built a transport company from that contract, and that company became the foundation of my family''s life. I was taught this story as one of vision and hard work, and I do not believe those things were absent from it.\nI also now know that in the same month, a man named Kofi Mensah-Annan lost the registration of his fishing cooperative in Abandze, Central Region, and that my grandfather purchased that land through private transaction. I do not know every detail of how that transaction came to be possible. I know that it should not have been possible in the way that it was, and that what my family gained and what the Mensah-Annan family lost are not separate events. They are the same event, seen from two directions. I am writing this because a history project that does not tell the truth is not a history project. It is just a story someone preferred.\nAbena read it twice. Then she folded it carefully, the same folds as before, and held it in both hands for a moment.\n"Serwa."\n"It needs to go in the project," Serwa said, from behind her book. "Whatever you think of it."\n"I think it''s honest."\nThe page-turning stopped.\n"I think it''s the most honest thing either of us has written for this project," Abena said. "And I think Mr. Asante is going to have a lot of feelings about it."\nSomething moved at the corner of Serwa''s mouth. Not quite a smile. The outline of one.\nAbena put the paper down and looked at the ceiling. The room was quiet the way it had been quiet on the first night, two girls deciding how much to offer each other. Except now the deciding was different. Now they knew what the offering cost.\n"I''m not going to pretend the gap isn''t there," Abena said. "Between us. What our families are. What happened."\n"I know."\n"I don''t want to pretend it."\n"I''m not asking you to." Serwa set her book down finally, and looked across the room with the directness she gave everything, not comfortable exactly, but present. "I''m asking you something different."\n"What?"\n"I don''t know yet how to say it." A pause. Long enough to be real. "I''ve been trying to find the words since Tuesday and I can''t find the right ones so I''m going to use the approximate ones." She looked at her hands. "I can''t give back what my family took. I can''t undo a document. I can''t make your great-uncle''s cooperative exist again or give your grandmother her brother''s land back or fix the fifty years in between." She looked up. "But I don''t want to be someone who knows the truth and does nothing with it for the rest of her life just because the doing is complicated. I don''t know what the doing looks like yet. But I know I don''t want to be that person."\nAbena listened to all of it. She did not rush to answer because the answer needed to come from the right place and she needed a moment to find it.\n"My grandmother told me something once," she said. "She said the water doesn''t forget. It carries everything. Silt, bones, the memory of every boat that ever crossed it. She wasn''t talking about forgiveness. She wasn''t saying the water is kind. She was saying it holds what happened and keeps moving." Abena looked at the photograph on the wall, the raised chin, the crossed arms. "I think that''s what we''re supposed to do. Hold what happened. Keep moving."\nThe room was still.\n"That sounds like something that''s easier to say than to do," Serwa said.\n"Yes," Abena said. "It is."\nThey sat with that honesty for a moment, and it was not comfortable, but it was real, which was better than comfortable, which was the thing they had both learned this term without a class or a grade for it.\nSerwa stood up, went to her desk, and came back with the chin chin tin she kept in her drawer, nearly empty now, the last few pieces rattling at the bottom. She set it between them on Abena''s desk.\n"For the project," she said. "We should put both reflections in. Mine and yours. Side by side. Two columns."\nAbena looked at her. "Like the ledger."\n"Yes. Except this time both sides get to speak."\nAbena reached into the tin and took the last piece. She held it for a moment, this small thing, this ordinary thing that had been offered and accepted so many times across the gap between their two beds that it had become its own kind of language.\n"Okay," she said. "Two columns."\nThey worked until midnight. The project was twelve pages by the time they finished, documented and sourced and honest in the way that things are honest when the people writing them have decided that the truth is worth more than the comfort of its absence. Abena wrote her section and Serwa wrote hers and they placed them side by side in the final pages without softening either one.\nWhen they turned off the lights, Serwa said, in the dark, in the same direction as the ceiling:\n"Abena."\n"Yes."\n"Thank you for not writing private buyer."\nAbena looked at the dark space where her grandmother''s photograph was.\n"Thank you for not needing me to."\nThe room went quiet. Outside, the compound lights cast their usual yellow through the curtain. Somewhere down the corridor, music played softly under a door.\nNeither of them slept immediately. But it was a different kind of awake than the first night, not two girls deciding whether to begin, but two girls who had already begun, and knew it, and were simply resting inside that knowledge before morning came and the world asked them to keep going.\nThey would keep going.\nNot because the gap had closed. But because they had both looked down into it, seen exactly how deep it was, and chosen each other anyway.\nThat was not nothing.\nThat was, in fact, everything.\n\n\nSEASON 1: "What the Water Remembers" — COMPLETE\n','\n',char(10)),1156,1,1,NULL,'2026-04-09T05:10:00.101Z','2026-04-09 05:10:00','2026-04-09 05:10:00',NULL,1,NULL);
INSERT INTO "chapters" ("id","novel_id","chapter_number","title","content","word_count","is_premium","is_published","audio_url","published_at","created_at","updated_at","scheduled_release_at","part_number","season_id") VALUES(281,39,1,' Corridor King',replace('The corridor on the first floor of Ahmadu block went silent before Chukwuemeka Obi appeared. That was the rule nobody made and everybody kept.\nHe walked the way a person walks when they have never once had to hurry. Slow. Precise. His white shirt pressed to a crease so sharp it looked like a warning. The senior prefect badge on his chest caught the afternoon light and threw it back at whoever was watching. The badge was not the power. Emeka was the power. The badge just confirmed it.\nStudents flattened themselves against the wall as he passed. A JS1 boy juggling textbooks froze mid step, arms locked, eyes straight ahead, waiting to be dismissed. Emeka gave him the look the slow scan from shoes to face and moved on without a word. The silence he left behind was louder than anything he could have said.\nThis was Federal Government College Lokoja, and in this corridor, Chukwuemeka Obi was the law.\nHe had worked for it. Four years of watching the prefects before him, studying what made students fear some and merely tolerate others. Fear was not cruelty. Emeka understood that early. Fear was certainty. It was the knowledge settled in the chest of every student who saw you coming, that you would not be moved. That the rules you carried were not suggestions. That you had no off days.\nSS2 had been his rehearsal. SS3 was his stage.\nHe turned the corner toward the stairwell and heard it before he saw it: the slap of rubber soles against tile, fast and careless, the particular rhythm of someone who did not believe anyone important was watching.\nHe stopped.\nShe came around the corner at speed, a JS3 girl with a notebook pressed to her chest and her plaited hair coming loose on the left side. She was looking back over her shoulder at something a friend, a joke, a dare and she nearly ran straight into him.\nShe stopped so fast her shoes squealed against the tile.\nThe notebook dropped.\nNeither of them moved. Emeka looked at the notebook on the floor, then up at her face. She was breathing hard from the run, and her expression was doing the slow, dawning work of someone calculating the size of the mistake they had just made.\n"Pick it up," he said.\nShe bent and picked up the notebook.\n"Your name."\nHer chin came up slightly before she answered, and he noticed that. Not defiance exactly. More like a reflex. Like her body had tried to protect her before her mind could catch up.\n"Chinazaekpere," she said. "Hauwa. JS3B."\n"Chinazaekpere Hauwa." He let the name sit in the corridor. "You were running."\n"I was"\n"In the corridor." He said it simply, the way you state something that requires no argument because it already won.\nHer jaw tightened. "Yes."\nThree other students had frozen nearby, practising the particular stillness of people trying not to exist. Emeka was aware of them. He was always aware of the audience. Not because he performed for them, but because the lesson was for them as much as it was for her.\n"Fifty lines," he said. "Clean sheet. I will not run in the corridor. Prefects room, six o''clock today."\nSomething moved behind her eyes. Quick and sharp, and then gone. She pressed her lips together.\n"Yes, sir," she said.\nCorrect. Exactly what should have been said. But the pause before it that half second of held breath stayed in the air between them like a question she had chosen, very deliberately, not to ask out loud.\nEmeka held her gaze a moment longer than was strictly necessary, then looked away.\n"Dismissed."\nShe walked. Not slowly enough to be insolent, not quickly enough to look afraid. She walked at a speed that said absolutely nothing, and somehow that bothered him more than if she had stormed off.\nHe watched her turn the corner and disappear.\nBehind him, the three frozen students exhaled as one and found their feet. He could already hear the story forming you heard what happened in Ahmadu block? Oga Prefect and some JS3 girl. Good. Stories like that were maintenance. They kept the machine running without him having to rebuild it every morning.\nEmeka adjusted his badge, squared his shoulders and continued down the corridor.\nEverything was in order. Junior students moved with care. Senior students gave him the nod of recognition. Two teachers passed him near the stairwell and acknowledged him with the particular nod usually reserved for colleagues rather than students. He had not asked for this. He had simply made himself unavoidable.\nAt the far end of the corridor he stopped at the window facing the football field. The sun was going down behind the Kogi hills, painting the grass the colour of old bronze. Boys below chased the ball with the loose, careless joy of people who believed they were unobserved.\nEmeka watched them for a moment longer than he needed to.\nThen he turned and walked back into the school.','\n',char(10)),841,0,1,NULL,'2026-04-26 16:56:12','2026-04-09 12:35:50','2026-04-26 16:56:12','2026-04-26T17:15:00.000Z',1,23);
INSERT INTO "chapters" ("id","novel_id","chapter_number","title","content","word_count","is_premium","is_published","audio_url","published_at","created_at","updated_at","scheduled_release_at","part_number","season_id") VALUES(282,39,2,'The New Madam',replace('The news arrived the way most important things arrived at FGC Lokoja through the kitchen staff, three days before it was official.\nA new principal. A woman. Coming from Abuja.\nBy the time the school assembled on Monday morning, the rumour had grown a full body and several contradictory details. She was strict. She was lenient. She had shut down a whole hostel in her last school. She let students use phones. Nobody agreed on anything except that change was coming, and change in a school like this moved through the student body the way weather moved through the Lokoja valley sudden, total, and not interested in your plans.\nEmeka stood at the far right of the assembly ground with the other prefects, hands behind his back, watching the new principal cross from the administrative block toward the podium. She was not tall. She wore a navy blue skirt suit and flat shoes, and she walked with the unhurried confidence of someone who did not need height to fill a room. A manila folder sat under one arm. She did not look around at the assembled students the way new teachers often did, scanning faces to establish presence. She looked straight ahead, at the podium, as if the four hundred students standing in neat rows were already handled.\nEmeka filed that away.\n"Good morning, Federal Government College Lokoja."\nHer voice came through the microphone clean and measured. No performance in it. No attempt to charm.\n"My name is Mrs. Okafor. I am your new principal. I will not tell you that I look forward to a long and happy relationship with this school because I do not believe in starting with a sentence that carries no meaning."\nBeside Emeka, Prefect Biodun shifted his weight. Emeka did not move.\n"What I will tell you," Mrs. Okafor continued, "is that I read every report on this school before I accepted this posting. Academic records, disciplinary records, staff evaluations, and something else." She opened the folder. "Student feedback from the last three terms. Anonymous. Collected by the ministry."\nA ripple moved through the assembly. Not sound exactly. More like a collective adjustment of posture.\n"What I found was a school with strong examination results and a significant problem of order maintained through intimidation rather than structure." She looked up from the folder. "That will change."\nEmeka''s jaw did not move. He kept his eyes forward and his expression arranged in the particular blankness he had perfected over three years. Inside, something registered the sentence and filed it under: does not apply to me.\n"Effective from next week," Mrs. Okafor said, "this school will establish a student council. An elected body of student representatives, one from each arm of each class, with an elected president at the top. This council will hold formal authority over student affairs, including the functions currently handled exclusively by the prefect body."\nShe let that sentence land.\n"Prefects will retain their traditional ceremonial and support roles. But disciplinary authority, student welfare decisions, and direct communication with school administration will flow through the council."\nEmeka breathed in slowly through his nose.\nCeremonial.\nHe turned the word over in his mind the way you turn over a coin to see if both sides are what you were told they were. Ceremonial. The word they used for things that still existed but had been quietly emptied of anything that mattered. The flag in the corner of a classroom. The prayer before an examination. Things that were present so that nobody had to say they were gone.\nHe almost smiled.\nThis was what happened when administrators from Abuja arrived with folders full of feedback forms and the vocabulary of school reform. They built new structures on top of old ones and called it progress. In two terms the student council would be a notice board committee arguing about whether to paint the common room, and the prefect body would still be running this school the only way a school like this could actually be run.\nMrs. Okafor was still speaking, details about election timelines and nomination processes. Emeka let the words pass over him.\nAround the assembly ground, juniors were exchanging glances. He could see the excitement moving through the JS rows the way light moved across water, quick and shallow. They did not understand yet that excitement was not the same as power.\nA few rows ahead, near the JS3 section, he noticed a girl with her notebook already open, writing something down. Her plaited hair was done differently today, neater, both sides even. It took him a moment to place her.\nThe girl from the corridor.\nChinazaekpere Hauwa.\nShe was writing quickly, head down, capturing something from the announcement with the focused efficiency of someone who was not simply listening but already thinking about what came next.\nEmeka watched her for three seconds, then looked back at the podium.\n"Elections will be held in two weeks," Mrs. Okafor said. "I expect every student to take this process seriously. This council will have real work to do."\nShe closed the folder.\n"That is all."\nShe stepped away from the podium without waiting for applause and walked back toward the administrative block the same way she had arrived. Straight line. Flat shoes. Not looking around.\nThe teachers began moving students back to classes. The ground filled with noise.\nEmeka turned to Biodun. "She''ll adjust," he said simply.\nBiodun nodded with the quick agreement of someone who had learned not to disagree with Emeka in open spaces.\nThe assembly dispersed. Emeka straightened his badge, tucked his hands behind his back and joined the flow toward the classrooms. Around him, students were already debating nominations and council positions with a brightness that would fade the moment they understood how institutions actually worked.\nLet them have their election.\nHe had built something in this school that no folder from Abuja could disassemble in a Monday morning assembly. He had four years in these walls and a certainty that sat in his chest like a stone.\nTwo weeks, he thought.\nHe would still be standing after two weeks.','\n',char(10)),1021,0,1,NULL,'2026-04-26 16:56:31','2026-04-09 12:37:37','2026-04-26 16:56:31','2026-04-26T17:15:00.000Z',1,23);
INSERT INTO "chapters" ("id","novel_id","chapter_number","title","content","word_count","is_premium","is_published","audio_url","published_at","created_at","updated_at","scheduled_release_at","part_number","season_id") VALUES(283,39,3,'The Notice Board',replace('The notice went up on a Tuesday, between second and third period, while most of the school was still moving between classrooms.\nEmeka saw the small crowd before he saw the board.\nA cluster of JS and SS students had gathered near the administrative corridor, pressed close enough that the ones at the back were rising on their toes. That kind of crowd meant one of three things: a fight, a result, or something new from Mrs. Okafor. He had learned in two weeks that the third option was becoming the most common.\nHe moved toward the board with the unhurried stride that parted crowds without requiring him to say anything. Students noticed him coming and stepped aside by instinct, creating a path that closed behind him like water. He reached the front and read.\nFEDERAL GOVERNMENT COLLEGE LOKOJA\nSTUDENT COUNCIL ELECTIONS\nOFFICIAL GUIDELINES AND ELIGIBILITY REQUIREMENTS\nThe notice was typed. Two full pages, printed clean, pinned at four corners with fresh tacks. Mrs. Okafor, he had observed, did not do things halfway.\nHe read it from the top.\nNomination period: one week. Voting day: the following Monday. One candidate per class arm per position. The Student Council President must be from JS3 or SS1, to allow for at least one full year of service before leaving the school.\nHe read the next section.\nEligibility: All students in good academic and disciplinary standing are encouraged to participate. Members of the current prefect body are not eligible to run for any student council position, in order to ensure a clear separation of the two structures.\nEmeka read that paragraph again.\nThen he read it a third time.\nThe words did not change.\nHe was aware of the students still gathered around him, aware of the particular quality of silence that had settled in his immediate area, the way it always did when people were watching him process something and waiting to see what his face would do.\nHis face did nothing.\nHe stepped back from the board, straightened, and walked toward the stairwell. Behind him the crowd filled back in and the noise resumed, speculation and argument tumbling over itself in the way of people who had no idea what the thing they were discussing actually meant.\nHe took the stairs to the second floor and stood at the window at the end of the corridor. Below, the compound was moving through its ordinary Tuesday rhythms. The groundskeeper was trimming the hedge near the gate. Two SS1 girls were crossing toward the library with textbooks balanced on their heads for reasons known only to them. A junior teacher was marking something on a clipboard outside the science block.\nNot eligible.\nHe said it inside his head without heat, the way you repeat a phrase in a language you are trying to learn. Turning it over. Testing the weight of it.\nHe had not wanted to run. That was the first thing he told himself, and it was true enough. The student council was a new structure built by a new principal on top of something that already worked. Emeka had not been looking at the election as an opportunity because he had not thought of it as something that could affect him. He was not a candidate. He was the structure itself.\nExcept that was precisely what the notice had removed.\nIt had not just excluded him from running. It had drawn a line between what he was and what the council would be, and named his side of the line the old side. The side that needed to be separated from the new thing. The prefect body existed now as a distinct category, defined not by what it did but by what it was no longer permitted to touch.\nHe pressed one hand flat against the wall beside the window.\nDown the corridor, a group of JS3 students came around the corner walking quickly, talking over each other. One of them broke from the group and walked ahead, faster, as if she had somewhere to be before the others. She was carrying a notebook and a folded sheet of paper, and she moved with a directness that Emeka had noticed before, the particular kind of purpose that did not announce itself.\nChinazaekpere Hauwa.\nShe had not seen him. She passed within four metres of where he stood without looking up, turned the corner toward the JSS administrative office, and disappeared.\nThe folded sheet of paper could have been anything.\nHe told himself it was anything.\nHe turned back to the window and made himself look at the compound until the stiffness in his shoulders released by one degree. He had been senior prefect for two terms. In that time he had resolved three hostel crises, two examination malpractice incidents, and one situation involving a class teacher that he had handled with a discretion the school administration had never formally acknowledged but had clearly noted. He knew how this school ran. He knew which rules were written on boards and which ones were written into the actual bones of the place.\nNo notice changed bones.\nThe bell rang for third period.\nEmeka straightened his badge, the same small gesture he performed every time he needed to return to himself. He turned from the window and walked back toward the stairwell, nodding briefly at a group of SS2 boys who scattered with slightly too much speed.\nHe thought about the notice one more time before he let it go.\nNot eligible.\nFine.\nHe did not need a title from a ballot box. His name was already written into the walls of this school in a language elections could not print and Mrs. Okafor''s folder could not collect. You did not build four years of order in a place like this and then get removed by a typed sheet with four tacks.\nHe descended the stairs. Third period was Further Mathematics, and Emeka had not missed a class in two terms. Some things you kept steady on principle. But at the bottom of the stairwell he stopped, without entirely meaning to, and looked toward the JSS administrative office. The corridor was empty. Whatever Chinazaekpere Hauwa had been carrying, she had already delivered it. He did not know why that felt like something he should have paid more attention to.','\n',char(10)),1056,0,1,NULL,'2026-04-27 15:03:03','2026-04-09 12:38:46','2026-04-27 15:03:03','2026-04-26T16:15:00.000Z',1,23);
INSERT INTO "chapters" ("id","novel_id","chapter_number","title","content","word_count","is_premium","is_published","audio_url","published_at","created_at","updated_at","scheduled_release_at","part_number","season_id") VALUES(284,39,4,' Campaign Season',replace('They appeared overnight, the way things that matter always do.\nHand-lettered on sheets of cardboard, taped to the walls outside the dining hall, the library, the entrance to every hostel block. Some were neat, ruler-lined lettering in blue and green marker. Some were rougher, done in haste or by someone whose confidence outran their handwriting. By Tuesday morning the school had the particular charged atmosphere of a place that had remembered it had opinions.\nVOTE CHUKWUDI OSEI FOR CHANGE\nADAEZE OBIORA: A VOICE FOR EVERY STUDENT\nFOR A FAIR COUNCIL: ELECT RASHEED ABDULLAHI SS1C\nEmeka read them as he walked his morning rounds. Not slowly. Not with the close attention he might once have given a disciplinary notice. He read them the way you read something you have already understood, just confirming that it says what you expected.\nThe school was enjoying itself. That was the accurate word. Even the SS3 students who should have been past the age of this kind of enthusiasm were gathered in clusters outside classrooms, debating candidates with the energy of people who had been given something to want. Teachers supervised from doorways with expressions that suggested cautious optimism. Two JS1 boys had fashioned rosettes from exercise book paper in the colours of their preferred candidate and were wearing them openly, which would ordinarily have been a uniform violation Emeka would have addressed before breakfast.\nHe walked past them.\nBy the second day, walls he had already passed had new additions. The campaign was moving. He could feel the school tilting toward something, the way a table tilts when enough weight shifts to one side, slowly and then all at once.\nIt was on the wall outside the female hostel block, near the water point, that he saw it for the first time.\nThe lettering was careful. Each character shaped with the kind of attention that came from deciding, before the pen touched paper, that this would be done properly. The cardboard was white, not the recycled brown of most of the others, and the border was done in two colours, green and gold, alternating.\nCHINAZAEKPERE HAUWA. JS3B.\nYOUR COUNCIL PRESIDENT.\nBelow the name, in smaller letters: Because the school belongs to all of us.\nEmeka stood in front of it for a moment. Around him, two girls from JS2 paused to look at the poster, then at him, then moved on quickly.\nHe looked at the name.\nHe had pronounced it in full exactly once, in the corridor on the day she ran. He remembered the way she had given it without shortening it, both names, as if she had decided before he asked that she would not offer him a smaller version of herself to work with. Chinazaekpere. Hauwa. Igbo and Hausa sitting side by side in a single person, which in Lokoja was not unusual, but there was something in the way she had said it that had made it feel deliberate.\nHe remembered the notebook that had dropped. The chin that had come up before the answer. The walk afterward, that middle speed that said nothing and somehow said everything.\nHe looked at the poster one more time and then walked on.\nThe campaign built through the rest of the week with a momentum that Mrs. Okafor had clearly anticipated and quietly encouraged. A notice went up granting candidates thirty minutes during the Wednesday lunch break to speak to their class arms. A second notice confirmed that teachers would not discuss candidates'' relative merits with students, which Emeka found professionally correct and personally unnecessary, since he had no intention of discussing candidates with anyone.\nHe was watching, not participating. There was a distinction.\nOn Thursday, Prefect Biodun fell into step beside him near the administrative block and spoke with the careful indirection of someone building up to a point.\n"That JS3 girl," Biodun said. "The one with the two names."\nEmeka said nothing.\n"She is everywhere," Biodun continued. "You go to the dining hall, she is talking to people. You go to the library corridor, she has been there and left already. My junior sister says she came to the SS1 girls hostel common room and spent forty minutes answering questions." He paused. "Nobody asked her to come to SS1."\nEmeka looked ahead.\n"She is JS3," Biodun said, with the tone of a person noting an anomaly they find both impressive and slightly unacceptable.\n"I know what she is," Emeka said.\nBiodun nodded and stopped building toward his point, which was the sensible response.\nThat evening, Emeka stood at the window of the second-floor corridor again, the one that looked out over the compound. The sky over the Kogi hills was doing the thing it did at this time of year, purple at the edges and a deep burning orange near the horizon, the kind of sky Lokoja produced as casually as other places produced clouds.\nBelow, near the JS classroom block, a small group of students was gathered in the fading light. Naza stood in the centre of them, not like someone performing, but like someone who had simply started talking and the people had gathered because the talking was worth stopping for. She was not holding a poster or a placard. She had her notebook, and she was gesturing with it occasionally, the same notebook that had fallen in the corridor that first day, and the students around her were nodding, asking things, nodding again.\nEmeka watched for longer than he had intended.\nThere was a specific kind of person who built their authority through the force of their certainty, through the knowledge that they would not be moved. He knew that kind of person well because he was one. But there was another kind, rarer in his experience, who built something different. Not the certainty that they would not be moved. The certainty that the people around them were worth moving for.\nHe could see it from the second floor window in the gathering dark.\nHe did not name what he saw. He simply turned from the window, straightened his badge, and walked back toward the prefects'' room.\nThe election was on Monday.\nWhatever the school was building toward, he would still be here when it was done.','\n',char(10)),1040,1,1,NULL,'2026-04-26 16:57:02','2026-04-09 12:40:25','2026-04-26 16:57:02','2026-04-26T17:15:00.000Z',1,23);
INSERT INTO "chapters" ("id","novel_id","chapter_number","title","content","word_count","is_premium","is_published","audio_url","published_at","created_at","updated_at","scheduled_release_at","part_number","season_id") VALUES(285,39,5,' The Count',replace('The rain came in the night and left the compound smelling of wet earth and something older, the particular Lokoja smell that rose from the ground after rain, mineral and deep, like the river was reminding the city it was still there.\nElection day arrived clean and cool.\nBy seven-thirty the voting table was set up under the shade of the big neem tree beside the administrative block, two teachers seated behind it with a ballot box and a register, both wearing the expressions of people who had been told this was important and had decided to believe it. Students filed past in the morning calm, collected their ballots, moved to the cardboard booth that had been constructed overnight from three chairs and a cloth screen, and returned. The whole process had the careful solemnity of something Mrs. Okafor had designed to feel real because she intended it to be real.\nEmeka watched from the corridor above.\nHe had a legitimate reason to be there. Morning rounds did not stop for elections, and someone had to ensure that the foot traffic moving between the voting table and the classrooms did not become disorder. He told himself this as he stood at the window, and it was true enough to hold.\nBelow, the line moved steadily. He recognised students from the way they carried themselves, even from above, the particular slope of a JSS student''s shoulders under a too-large uniform, the different quality of stillness an SS2 student had learned. He had spent three years reading this school from the outside in. It was not a habit he could simply stop.\nNaza arrived at the table at eight-fifteen.\nShe joined the line without ceremony, the same notebook under her arm, her uniform pressed, her hair plaited back neatly. She did not look around the compound in the way that candidates sometimes did, checking for witnesses to their own importance. She waited her turn, collected her ballot, went behind the screen, came out again. She handed the folded paper to the teacher at the box, watched it drop in, and walked back toward the JS classroom block.\nShe did not look up at the corridor window.\nEmeka turned away.\nThe results were read at noon, in the same assembly ground where Mrs. Okafor had made her first announcement. The principal stood at the podium with a sheet of paper and the patient expression of someone who had done this before in other schools and understood that the moment required weight.\nThe student body stood in the sun, which had burned off the morning coolness and reasserted itself fully. The air smelled of lunch being prepared in the kitchen block behind the hostel. Somewhere near the back, a junior student was coughing with the repetitive dedication of someone who had either a cold or a serious need for attention.\nEmeka stood with the prefects at the side of the assembly. Badge straight. Hands behind his back. Face arranged.\nMrs. Okafor read the council positions from the bottom up, class representatives first, working toward the top. Each name was followed by a vote count and then the specific sound a secondary school crowd makes when a result lands, not quite cheers, not quite applause, something in between, shaped by whether the name was popular or merely correct.\nThe compound was paying attention. Even the students usually most resistant to institutional events had the alert stillness of people waiting for something specific.\nThen Mrs. Okafor looked up from her sheet.\n"Student Council President."\nThe compound went fully quiet. Even the coughing stopped.\n"Total votes cast: three hundred and eighty-one." She looked back at the paper. "Rasheed Abdullahi, SS1C. Forty-four votes."\nA pocket of noise from the SS1 area.\n"Adaeze Obiora, SS2A. Sixty-one votes."\nSlightly larger noise. The SS2 girls section found each other''s eyes.\n"Chinazaekpere Hauwa, JS3B."\nThe pause before the number was half a second, no longer. But Emeka felt it.\n"Two hundred and forty-seven votes."\nThe sound that came up from the student body was not the polite compound noise that had followed the other names. It was full and sudden, the released energy of an outcome that confirmed what enough people had already believed to make it feel like a collective truth rather than a surprise. JS students were louder than the SSS section but the SS students were not quiet either, and even some of the teachers at the edges of the assembly ground permitted themselves an expression that was not quite neutral.\nTwo hundred and forty-seven out of three hundred and eighty-one.\nEmeka did the arithmetic without trying to.\nSixty-four percent.\nHe looked at the numbers and then he looked at her.\nNaza was standing in the JS3 row, and she was not jumping, not grabbing the girls beside her, not performing the victory the way the moment seemed to invite. She was very still. Her notebook was pressed against her chest with both hands and she was looking at the podium with the expression of someone receiving not a prize but a weight, and understanding the difference.\nA teacher near the JS section touched her shoulder and pointed her forward. She began walking toward the podium.\nThe compound noise continued.\nEmeka did not move.\nHe watched her climb the two steps to the podium level and stand beside Mrs. Okafor, who shook her hand with the firm grip of someone passing something real from one set of hands to another. Naza said something to the principal that Emeka could not hear from where he stood. Mrs. Okafor nodded.\nThen Naza turned and faced the school.\nShe looked out over the assembly ground and for a moment she simply looked, taking in the full shape of the thing that had just happened. Her chin was up. Not the reflex chin of that first day in the corridor, not the instinctive self-protection of a student braced for a consequence. This was different. This was a person measuring the size of something and deciding they were ready for it.\nHer eyes moved across the assembly and stopped, briefly, at the prefect section.\nAt him.\nThe moment lasted no longer than a breath. Then it was over, and she was looking elsewhere, and Mrs. Okafor was speaking again about next steps and the council''s inaugural meeting.\nEmeka looked straight ahead.\nAround him the prefects were still, each of them processing the number in their own way. Beside him, Biodun let out a breath that was not quite a word but had the shape of several.\nTwo hundred and forty-seven votes.\nThe school had not hedged. It had not given a cautious mandate to a safe candidate. It had chosen a JS3 girl, two years from her WAEC, and handed her the thing by two-thirds majority.\nThe assembly began to disperse. Students moved toward the classroom blocks in the buzzing, overlapping conversation of a community that had just done something together and was still warm from it.\nEmeka turned and walked back toward Ahmadu block.\nHis badge was straight. His shirt was pressed. His face held its arrangement perfectly.\nBut sixty-four percent was a very specific number, and it stayed with him the whole way up the stairs.','\n',char(10)),1204,1,1,NULL,'2026-04-26 16:57:16','2026-04-09 12:42:38','2026-04-26 16:57:16','2026-04-26T17:15:00.000Z',1,23);
INSERT INTO "chapters" ("id","novel_id","chapter_number","title","content","word_count","is_premium","is_published","audio_url","published_at","created_at","updated_at","scheduled_release_at","part_number","season_id") VALUES(286,39,6,' First Order',replace('The inaugural student council notice went up on Friday morning and by Friday afternoon Emeka had read it four times.\nNot because the language was unclear. The language was precise, which was the problem. Vague notices could be navigated. Vague notices had edges you could find and press. This one had been written by someone who understood that precision was a form of authority, and who had decided, at fifteen, to use it.\nSTUDENT COUNCIL NOTICE — NO. 001\nRE: JUNIOR STUDENT MOVEMENT AFTER LIGHTS OUT\nEffective immediately, no junior student (JS1 to JS3) is to be summoned to the senior hostel block for any reason after 9PM. Any senior student requiring a junior student''s assistance with laundry, provisions, or personal errands must make such requests before the evening bell. Junior students found in the senior hostel after 9PM will be referred directly to the council for review. Senior students who summon them will be referred to the principal.\nSigned: Chinazaekpere Hauwa, Student Council President.\nEmeka set the notice down on the table in the prefects'' room.\nThe system the notice had just addressed was older than any current student in the school. It was not written anywhere, not in the school handbook, not in any official document. It existed the way most real systems existed, in the understanding passed from one set of seniors to the next, in the particular education a JS1 student received in their first week about how things worked. Senior students had things done for them by junior students. That was the texture of boarding school life. In return, seniors provided a kind of informal protection, a navigation guide for a disorienting new world. The system had problems. Emeka knew it had problems. But it had structure, and structure in a school like this was not nothing.\nAnd it had been one of the things the prefect body enforced informally, which meant that Naza had just, in her first official act, removed something from their hands without consulting them, without a meeting, without even a courtesy conversation.\nHe folded the notice once and put it in his pocket.\nHe found her on Saturday morning outside the council''s designated room, a small office near the library that had previously been used for storing examination materials. She was with two council members, a girl from SS1 and a boy from JS3, and they were arranging the furniture inside with the focused efficiency of people who had been planning this moment for longer than they let on.\n"A word," Emeka said from the doorway.\nNaza looked at him the way you look at something you expected to arrive and chose the time and location for accordingly.\n"Emeka," she said. Not sir. Not the careful deference junior students had spent three years giving him in corridors. Just his name, spoken cleanly, the way you address someone who is exactly level with you.\nThe two council members looked between them and found somewhere else to be.\nEmeka stepped into the room. "The notice."\n"Which one?" she said, turning back to the desk she was straightening.\n"You know which one."\nShe set down the stack of files she was holding and faced him. She was almost a full head shorter than him. It did not appear to register with her as relevant information. "Notice 001. Junior student movement after lights out."\n"You changed a system that the prefect body manages."\n"The prefect body managed it informally," she said. "Which means it was never a system. It was a habit. There is a difference."\n"It worked."\n"For who?" She said it without aggression, the way you ask a question you genuinely want answered, which was somehow more difficult to respond to than an argument. She picked up her files again. "I talked to eleven JS1 students before I wrote that notice. Eleven. Do you know what they told me?"\nEmeka said nothing.\n"They were afraid to say no," Naza said. "Not because of school rules. Because there were no school rules. Because the only rule was whatever the senior who sent for them decided it was." She set a file on the desk. "That is not structure. That is something else."\n"You should have brought it to a joint meeting first," Emeka said. "Prefects and council, together. That is the correct process."\n"There is no established process yet for joint meetings," she said. "That is something we should build together. I agree with you." She paused. "But I was not going to leave eleven JS1 students unprotected while we built the process."\nThe room was quiet. Through the window, the Saturday compound was going about its weekend self, the loose, louder version of the school that appeared when the formal week structure relaxed.\nEmeka looked at her.\nShe looked back.\nHe had expected pushback delivered as performance. He had expected her to use the room, the title, the weight of the election result as armour. What she had done instead was more difficult. She had given him the argument that made her correct, plainly, without theatre, and then stood in it without moving.\n"You should have informed the prefect body before posting," he said. It was the only ground he had left that was still solid.\n"You are right," she said.\nHe had not expected that.\n"I should have informed you first," she continued. "That was a gap. I will close it going forward." She said it the way a person says something they mean, without softening it into an apology or hardening it into a concession. "But the notice stands."\nEmeka held her gaze for a moment. Then he turned and walked to the door.\n"Joint meeting," he said, without looking back. "Next week. We establish the process."\n"Tuesday," she said. "Five o''clock. I will put it in writing."\nHe walked out of the room and back into the corridor.\nThe notice would stand. He had walked in expecting to dismantle it and had walked out having confirmed it. He replayed the conversation as he moved and found, with a precision that irritated him, that she had not been wrong about a single thing she said. Not the substance, not the process gap she had acknowledged, not the way she had acknowledged it.\nHe turned the corner toward Ahmadu block.\nThe badge on his chest felt the same weight it always had.\nBut for the first time in three years he was not entirely certain it was enough.','\n',char(10)),1077,1,1,NULL,'2026-04-26 16:57:29','2026-04-09 12:43:39','2026-04-26 16:57:29','2026-04-26T17:15:00.000Z',1,23);
INSERT INTO "chapters" ("id","novel_id","chapter_number","title","content","word_count","is_premium","is_published","audio_url","published_at","created_at","updated_at","scheduled_release_at","part_number","season_id") VALUES(287,39,7,'The Mistake',replace('\nIt started with a sound.\nThe particular sound of furniture being dragged across a concrete floor, loud and careless, coming from the JS2 common room on a Wednesday evening when the floor was supposed to be in prep. Emeka heard it from the corridor and turned toward it before he had made any decision to turn. Three years of corridors had made certain responses automatic.\nHe pushed the door open.\nFourteen JS2 students looked up at him from various positions of disorder. Three desks had been pushed against the wall. Two boys were in the middle of what was clearly a wrestling match that had been dressed up, not very convincingly, as a handshake dispute. A girl near the window had her reading lamp angled toward a small mirror and was doing her hair with the focused calm of someone who had decided prep hour was personal time.\n"Who is the prep supervisor?" Emeka said.\nSilence. The wrestling match became two boys standing very straight. The girl with the mirror did not put it down immediately, which Emeka noted.\n"Mr. Fadipe," someone said from the back. "He went to the staffroom."\n"How long ago."\n"Since four o''clock, sir."\nIt was now six forty-five.\nEmeka looked at the room. Desks out of position. A mirror. The wrestling. In a different month, in a different term, this would have resolved in four minutes. He knew exactly how it would have gone: names taken, desks repositioned, lines assigned, the particular quality of silence that followed when a room understood it had made an error restored within the hour. He had done it dozens of times.\nHe looked at the girl with the mirror. "Put that away and return to your desk."\nShe put the mirror in her bag. But she did it with a slowness that was not quite insolence but lived in the same neighbourhood, and the two boys near her exchanged a glance that lasted less than a second and said something he did not like.\n"Names," he said. "Everyone who was not seated at their desk when I came in."\nA JS2 boy near the front opened his mouth. "Sir, we were told by the student council that prep supervision disputes should be reported to—"\n"I did not ask what the student council told you," Emeka said. "I asked for names."\nThe room went quiet in a different way. Not the clean, immediate quiet of a room that respected the authority asking for it. The quiet of a room that was deciding something.\n"Sir." The boy again. Slowly. "The council notice said that disciplinary matters during prep should go through the class representative first."\nEmeka looked at him.\nThe boy was perhaps thirteen. He had the round face of someone who had not yet grown into his ears, and he was gripping his pen with both hands, and he was not looking away.\nEmeka had been looked at by junior students for three years and he knew every variation of the look. Fear dressed as composure. Composure dressed as courage. This boy was frightened. But he was holding his ground on something he had been told he was allowed to hold.\n"Stand up," Emeka said.\nThe boy stood.\n"Your name."\n"Tobenna Eze, sir."\n"Do you understand that I am the senior prefect of this school, Tobenna?"\n"Yes, sir."\n"Then you understand that my authority in this corridor does not require the student council''s framework to be valid."\nA pause. "Sir, Council Notice 003 says—"\n"I do not need you to quote notices at me."\nHe said it sharply. More sharply than he had intended. He heard it the moment it left his mouth, the edge in it, the particular sound of a person who has just lost an argument and has raised their voice instead of finding better ground.\nThe room heard it too.\nSomething shifted in the fourteen faces watching him. Not fear. Something closer to recognition, the expression of people recalibrating something they had held as fixed.\nThen the door behind him opened.\nMrs. Okafor walked in.\nShe was still in her work clothes, which meant she had come from the administrative block, which meant someone had sent word, which meant this had been heard outside the room before it was finished inside it.\nShe looked at the room. She looked at Emeka. Her expression did not change.\n"Emeka," she said.\n"Ma."\n"What is the issue here?"\nThe room was now the specific quiet of a place in which nobody wanted to answer that question.\n"Prep supervision was absent," he said. "I came in to restore order."\nMrs. Okafor looked at the desks, two of which were still pushed against the wall. She looked at Tobenna Eze, who was still standing.\n"Sit down, please," she said to the boy.\nTobenna sat.\nMrs. Okafor looked at Emeka and moved her eyes toward the door. He followed her into the corridor and she pulled the door closed behind them.\nShe did not speak immediately. The corridor held the thin noise of the school at evening prep, distant and ordinary.\n"Council Notice 003," she said, "gives class representatives first response in prep supervision disputes."\n"I am aware of the notice."\n"Then you understand what you walked into."\nHe kept his voice level. "The room was in disorder. A student was openly defiant."\n"A student cited a notice he had been given and was entitled to cite." She looked at him with the direct, unornamented attention that was her default mode. "There is a difference between defiance and procedure, Emeka. I think you know that."\nHe said nothing.\n"What happened in that room tonight," she said, "will be in twelve different conversations before lights out. Not because the students are wrong to talk about it. Because something worth discussing happened." She paused. "I am not disciplining you. I am telling you what is true."\nShe opened the door and went back into the common room. Emeka heard her voice through the door, measured and clear, telling the room that desks needed returning to position and that she would be speaking with Mr. Fadipe about his supervision record.\nEmeka stood in the corridor.\nDown the hall, a group of SS2 boys were approaching from the stairwell. They saw him. They did not flatten against the wall. They moved to the side, the ordinary courtesy one person gave another in a narrow corridor, and walked past.\nHe stood there after they were gone.\nHe had raised his voice at a thirteen-year-old boy who was quoting a notice.\nThat was what had happened.\nHe could dress it in every available justification and the centre of it would stay the same.\nHe walked back toward the prefects'' room with his badge straight and his face arranged and the sound of his own voice still sitting in his chest like something he could not put down.','\n',char(10)),1149,1,1,NULL,'2026-04-26 16:57:44','2026-04-09 12:44:56','2026-04-26 16:57:44','2026-04-26T17:15:00.000Z',1,23);
INSERT INTO "chapters" ("id","novel_id","chapter_number","title","content","word_count","is_premium","is_published","audio_url","published_at","created_at","updated_at","scheduled_release_at","part_number","season_id") VALUES(288,39,8,'Empty Title',replace('The last day of term always had a specific sound. Boxes dragged across hostel floors. The metallic complaint of locker doors opened and shut for the final time. Voices at a pitch the school did not permit during term, unregulated, spilling out of windows and across the compound with the loose energy of a population that had stopped performing for three weeks.\nEmeka packed his box methodically. Textbooks first, stacked by subject and size. Then clothes, folded the way his father had taught him, flat and tight, no wasted space. Then the smaller things. A torch. A tin of Milo. The notebook he used for prefect records, half filled, which he placed on top of everything else and then moved to the side.\nThe prefects'' room was emptying around him.\nBiodun had left an hour ago, already dressed in his own-clothes with the visible relief of someone removing a costume. Two other prefects, Seun and Danladi, had packed together and gone without much ceremony, the particular quiet of people who had stopped being certain what to say around him since the common room incident. He had not made it easier for them. He was aware of that.\nHe closed his box and sat on the edge of the bed.\nThe room was almost bare now. Six beds, six mattresses stripped to ticking, six lockers standing open. The window above his bed let in the afternoon light at an angle that showed every scratch on the concrete floor, every scuff mark left by three years of boxes dragged in and out by boys who believed this room was important because of what it meant to be inside it.\nHe looked at the notice board above the door.\nIt was mostly cleared, but one sheet had been left behind, pinned at a single corner and hanging slightly crooked. A duty roster from the beginning of term, his own handwriting at the top in the clean block letters he used for official documents. SENIOR PREFECT DUTY SCHEDULE. WEEK ONE. Names beneath it in columns. Times. Locations. The whole architecture of a week he had organised before the week happened.\nHe had built this room into something.\nThat was the fact he kept returning to, in the particular circular way that thoughts moved when they had nowhere else to go. He had sat in this room as a newly appointed SS3 prefect and looked at the seniors before him and decided that the prefect body under his watch would be different. More disciplined. More consistent. He had called meetings with structure. He had kept records. He had held the line on things other prefects let slide, not from cruelty, he told himself, and mostly believed, but because the alternative was a school that ran on whoever happened to be watching.\nHe picked up the badge from the bed beside him.\nIt was heavier than it looked, or at least it always had been. A metal circle with the school crest and the words SENIOR PREFECT in raised lettering around the edge. He had pinned it to his shirt every morning of this term with the same small movement and the same small knowledge that it meant something.\nHe turned it over in his hand.\nNaza''s council had issued eleven notices before the end of term. He had counted them, not because he was compiling a record but because the number kept presenting itself to him. Eleven notices in eight weeks. Junior student movement. Dining hall queuing procedure. A framework for reporting teacher absenteeism without victimisation. A noise curfew for the hostel common rooms that was, he had to acknowledge, better designed than the one the prefects had been enforcing informally for two years. Each notice had gone to the principal''s office, come back with a stamp, and been posted on every board in the school within twenty-four hours.\nHe had been consulted on two of them. The joint meeting process they had agreed to was real, and Naza had kept to it where she could, which he had not expected and had not known how to respond to cleanly.\nBut eleven notices.\nHe thought about the common room. Tobenna Eze with his pen held in both hands, citing Notice 003 at a senior prefect in a voice that shook but did not stop. The look on the faces of fourteen JS2 students recalibrating something in real time.\nHe thought about the way Mrs. Okafor had said his name in the corridor after. Not with anger. With the careful pronunciation of someone being precise about what they were addressing.\nHe thought about Naza''s face when he had walked into the council room that first Saturday morning. The absence of deference in it. Not disrespect. Something more difficult than disrespect. The simple assumption that they were level, delivered as a fact so obvious it did not need stating.\nHe set the badge down on the mattress.\nOutside the window, the compound was at its end-of-term pitch. A car horn from the gate, parents arriving in the particular mix of relief and anxiety that school collection always produced. Someone called a name in a voice that carried the whole length of the compound. Somewhere in the JS hostel block, someone was playing music from a phone, the kind of music that had been strictly managed all term and was now available in the open, briefly and completely.\nHe was going home to Onitsha tomorrow morning. He would sit in the back of his uncle''s car and watch the Niger bridge approach and think, the way he always thought on that bridge, about the city on the other side and what returning to it meant. He would eat his mother''s food. He would sleep in his own bed. He would be, for three weeks, simply Chukwuemeka Obi, who was a boy from Onitsha completing his final year of secondary school.\nAnd then he would come back.\nHe looked at the badge on the mattress.\nHe had walked into this school at thirteen as a boy who needed to know exactly where he stood in order to feel safe. He had built the answer to that need into a title, and built the title into a presence, and built the presence into something the school organised itself around. He had been certain that the thing he had built was the same as the thing he was.\nHe was less certain now.\nHe picked up the badge and pinned it to his shirt. Old habit. The morning reflex extended into the afternoon without thinking.\nThen he stopped.\nHis hand stayed at his chest, badge secured, and he sat with the knowledge that the weight he felt when he put it on was not the weight of the badge.\nHe did not remove it. He left it where it was and stood and picked up his box and carried it to the door. He looked back once at the stripped room, the bare lockers, the hanging roster in his own handwriting.\nHe turned off the light and walked into the corridor.\nThree weeks.\nWhen he came back, something would have to be different.\nHe did not yet know what, or how, or whether he was capable of it.\nHe walked down the stairs and out into the end-of-term light.','\n',char(10)),1218,1,1,NULL,'2026-04-26 16:58:01','2026-04-09 12:46:03','2026-04-26 16:58:01','2026-04-26T17:15:00.000Z',1,23);
INSERT INTO "chapters" ("id","novel_id","chapter_number","title","content","word_count","is_premium","is_published","audio_url","published_at","created_at","updated_at","scheduled_release_at","part_number","season_id") VALUES(314,41,1,'New Term Protocol',replace('The Niger bridge looked the same as it always did, wide and grey and indifferent to whatever you brought onto it, and Emeka sat in the back of his uncle''s car and watched the river below and said almost nothing for the full crossing.\nHis uncle, who was a practical man, did not ask about the silence.\nLokoja received them in the particular January heat that felt different from December heat, drier, more direct, as if the harmattan had decided to stop pretending it was anything other than what it was. The school gate was open when they arrived, and the compound already had its new-term quality, half-populated, uncertain, the way a stage looks before the full cast arrives.\nEmeka carried his box to the hostel without stopping to read the notice boards.\nHe had decided this on the bridge. He would not begin the term by checking what had changed. He would unpack, he would sleep, and in the morning he would resume his duties with the same consistency he had always brought to them and without the mistake he had made in December. He had had three weeks to examine the common room incident from every angle and he had arrived at a conclusion that was uncomfortable but clear: he had been wrong in method, if not entirely in principle, and being wrong in method in front of an audience was a specific kind of damage he could not afford again.\nCold compliance. That was the resolution. He would work within the new structure with the professional correctness of someone who had accepted a framework without endorsing it. He would attend joint meetings. He would respect the council''s notices. He would do his job with the same precision he had always used and he would not give Naza, the school, or Mrs. Okafor anything to point to.\nHe unpacked his textbooks first, the same order as always, and told himself the decision felt steady.\nHe saw her on the second morning.\nThe council had a new notice board, a dedicated one, installed beside the principal''s office over the break. It was painted green, which was either a coincidence or a statement, and it already had three notices on it when Emeka passed it on his way to the administrative block. He read them without stopping, the way you read something peripheral, gathering information without granting it the dignity of your full attention.\nNotice 012: Council meeting schedule for the new term. Tuesdays, five o''clock.\nNotice 013: Updated joint protocol for prefect-council coordination, co-signed by Student Council President and Senior Prefect.\nHe stopped.\nHis own name was on the notice. His own title beneath it. He had not signed this document. He had agreed in December to the joint meeting process, verbally, but this was a printed notice on a green board with his name on it, and he had not seen it before it was posted.\nHe was still reading it when Naza came out of the principal''s office.\nShe was carrying a brown envelope and a council file, and she was already in full school uniform, pressed and correct, at seven forty-five in the morning of the second day of term. She saw him at the board and stopped.\n"Emeka."\n"My name is on this notice," he said. "I did not sign it."\nShe looked at the board, then back at him. "We agreed to the joint protocol in December. The notice formalises what we agreed."\n"Formalising something requires the agreement of the people named in it."\n"You are right." She held the envelope against her chest and looked at him with the same level attention he had been trying to organise his thoughts around since December. "I should have sent it to you before posting. I will pull it and repost with your sign-off."\nHe had expected resistance. The directness of the concession landed in a way he had not prepared for and he kept his face still while he recalibrated.\n"I want to see it before it goes up again," he said.\n"I will bring it to you this afternoon."\n"Fine."\nA pause. The administrative corridor was beginning to fill with early arrivals, students and two teachers moving around them without appearing to notice the particular quality of the stillness between them.\n"There is a council meeting Tuesday," she said. "I would like you there."\n"I will be there."\n"Good." She shifted the envelope under her arm. "I also want to propose something at the meeting. A formal prefect liaison role, one prefect who attends council sessions as an observer with speaking rights. I think it helps both structures."\nHe looked at her.\n"Or we can discuss it Tuesday," she said.\n"We will discuss it Tuesday."\nShe nodded once and walked past him toward the JS classroom block, the flat purposeful walk that he had catalogued without intending to. She did not look back.\nEmeka turned to the notice board.\nHis name was still on Notice 013, co-signed and official, formalising something he had agreed to in December in a corridor conversation after an incident he would rather not be reminded of. He looked at his own title in printed letters: Senior Prefect, Chukwuemeka Obi.\nIt was still there.\nThat was the thing he needed to hold onto. The badge was still on his chest. His name was still on the board. The framework had changed, and he had not designed the change, and he was going to comply with it coldly and professionally and without giving an inch he did not have to give.\nHe straightened his badge and walked toward the stairwell.\nTuesday was four days away.\nHe would be ready.\nThree doors down from the notice board, inside the principal''s office, Mrs. Okafor was reading the new term report and making notes in the margin. She had a view of the administrative corridor from her window, and she had watched the exchange at the notice board with the careful attention of someone who had arranged several things over the holiday break and was now checking whether they were landing as intended.\nShe turned back to her report.\nShe made a small mark beside a name.\nThen she turned the page.','\n',char(10)),1038,0,1,NULL,'2026-04-26 16:58:51','2026-04-10 07:25:53','2026-04-26 16:58:51','2026-04-26T17:15:00.000Z',2,25);
INSERT INTO "chapters" ("id","novel_id","chapter_number","title","content","word_count","is_premium","is_published","audio_url","published_at","created_at","updated_at","scheduled_release_at","part_number","season_id") VALUES(315,41,2,'Common Problem',replace('The smell reached the dining hall before the complaints did.\nIt arrived on a Wednesday, the sour, unmistakable smell of rice that had been stored wrong, or cooked from a bad batch, or both. By the time the lunch bell rang and four hundred students filed in from classes, it was already sitting in the air above the serving counter with the settled confidence of something that had been there for hours.\nThe first complaint came from a JS2 table. Then an SS1 boy pushed his plate back and stood up. Then three girls at the far end of the female section put down their spoons within thirty seconds of each other, which was either coincidence or communication, and in a girls'' hostel it was never coincidence.\nBy the time Emeka arrived at the dining hall door, twelve students had left their food untouched and the serving staff were arguing in low voices behind the counter.\nHe stood at the entrance and assessed.\nThe kitchen supervisor, Mr. Bello, was a compact man who had been managing school food since before most of the current students were born, and he was standing at the counter with the expression of a person defending territory he had held for decades and did not intend to surrender to a smell. "It is the water," he was telling the SS2 boy in front of him. "The water in Lokoja this week. It affects the taste. It is not the rice."\n"Sir, the rice smells like it has been sitting since last term," the boy said.\n"It does not smell like anything."\n"Sir."\nEmeka moved through the dining hall to the counter. "Mr. Bello."\nThe supervisor looked at him with the particular relief of a man who has spotted a familiar kind of authority. "Emeka. Tell them the rice is fine."\n"I have not tasted it," Emeka said.\nHe looked at the rice in the serving tray. It had the colour of food that had been reheated once too many times, pale and slightly translucent at the edges. He picked up a spoon from the counter and tasted a small amount.\nIt was not fine.\nIt was not dangerous, probably. But it was the kind of food that asked something of the person eating it, a willingness to continue that a boarding school student, already far from home and eating from a tray, should not have to find.\n"When did this batch come in?" he said.\nMr. Bello''s relief shifted into wariness. "Last week."\n"Storage conditions?"\n"The usual store."\n"Has anyone checked the store this week? The back section?"\nA pause.\nEmeka looked at him.\n"I will check," Mr. Bello said.\n"Do it now, please."\nHe turned from the counter and found Naza standing four feet behind him.\nShe had her council file and she was looking at him with the expression she wore when she was collecting information, the careful, non-committal attention of someone not yet ready to show their hand.\n"When did you get here?" he said.\n"Two minutes after you." She looked at the serving trays. "How bad is it?"\n"Not dangerous. But not acceptable."\nShe nodded. She turned to the SS2 boy who had been arguing with Mr. Bello. "Go and sit down. Don''t eat the rice." Then to the room, louder: "Everyone, please sit and wait. We will have an update in ten minutes."\nThe dining hall settled into the restless quiet of four hundred hungry students exercising patience they had not agreed to exercise.\nNaza turned back to Emeka. "What do we have instead of the rice?"\n"That is a question for the kitchen."\n"I know. I am asking if you know, because you have been dealing with this kitchen longer than I have and it is faster than finding Mr. Bello again."\nHe held her gaze for a moment. "There is usually a bread reserve. Loaves from the bakery van that comes Tuesdays. If this week''s delivery came in, there should be enough for a supplementary meal."\n"Where is it stored?"\n"Side room off the kitchen. Left of the stove."\nShe wrote something in her file and walked toward the kitchen.\nEmeka watched her go and then followed, because the alternative was standing in the dining hall while a situation he had identified continued without him, which was not something he was built for.\nThe kitchen was warm and smelled of the rice more strongly here. Two cooks were at the back, looking at a large pot with the guilty body language of people who had known about the problem before the students did. Naza was already at the side room door, which she opened, and looked in.\n"There is bread," she said.\n"How many loaves?"\nShe counted. "Thirty-one."\n"Not enough for the full school."\n"No." She turned. "We divide it. JS students get bread now. SS students get priority tomorrow morning for a supplementary breakfast before their morning classes. I will put it in writing tonight."\nEmeka looked at the two cooks. "The remaining rice from this batch. Is there more in storage?"\nOne of the cooks, a thin woman named Mama Ngozi who had been in this kitchen for eleven years, met his eyes with the resignation of someone who had been waiting for this question. "Two bags," she said quietly. "In the back store."\n"Take them out. They go back to the supplier."\n"Mr. Bello will—"\n"I will speak to Mr. Bello," he said.\nMama Ngozi nodded and moved toward the store.\nNaza was watching him.\n"The supplier is Hajiya Laraba''s company," he said, before she could ask. "The school has used her for three years. She has a direct line to the bursar. If you want this escalated formally, that is the route."\n"And if I escalate it formally, what happens?"\n"There will be a review. It will take two weeks and end with a letter of caution that changes nothing."\n"What happened the last time there was a food problem?"\nHe paused. "Nothing."\nShe wrote in her file again. He looked at the notepad over her shoulder, not intrusively, just enough to see that she was not writing notes. She was drafting. Full sentences, structured. A council report.\n"You are writing this up tonight," he said.\n"I am writing it up now," she said. "This goes to Mrs. Okafor before six o''clock. With the supplier name, the storage conditions, and the response." She looked up from the file. "And your name alongside mine on the report. If you are agreeable."\nHe was quiet for a moment.\nA joint report meant a shared record. It meant that whatever the administration did with the problem, the solution belonged to both structures, the council and the prefect body together. It was a different kind of formalisation than the notice board incident at the start of term, not his name attached to something he had not seen, but his name attached to something he had been present for, had contributed to, had helped solve.\nIt was also, and he was honest with himself about this, a reasonable thing to agree to.\n"Agreeable," he said.\nShe wrote his name at the bottom of the draft.\nThey walked back into the dining hall together and stood at the front while Naza addressed the room. She explained the bread distribution clearly, the JS priority now, the SS breakfast arrangement, the report going to the principal. She spoke without notes and without the performing-confidence of someone who had prepared a speech. She spoke the way a person speaks when they know what they are talking about and respect the people listening enough to tell them the truth.\nEmeka stood beside her and said nothing.\nHe did not need to add anything. That was what he understood by the time she finished. She had covered it. The room was settled, the problem was documented, the solution was in motion.\nWhen she stepped back from the front, she glanced at him briefly, the quick checking glance of someone confirming a thing they expected to be true.\nHe gave her a small nod.\nShe turned toward the door.\nHe stood in the dining hall for another minute after she left, watching the bread distribution begin, JS students rising table by table in the order Naza had specified, the whole process running with a cleanliness that required no additional management.\nHe had not designed this solution.\nHe had contributed to it.\nHe was still deciding how he felt about the difference.','\n',char(10)),1415,0,1,NULL,'2026-04-26 16:59:04','2026-04-10 07:27:07','2026-04-26 16:59:04','2026-04-26T17:15:00.000Z',2,25);
INSERT INTO "chapters" ("id","novel_id","chapter_number","title","content","word_count","is_premium","is_published","audio_url","published_at","created_at","updated_at","scheduled_release_at","part_number","season_id") VALUES(316,41,3,'The Long Table',replace('The power went at seven forty-three.\nOne moment the council room was lit by the single fluorescent tube that had been flickering since the start of term, and the next moment the whole block went dark and the fluorescent tube gave up its last argument and went quiet. Outside, the generator had not yet kicked in, which meant someone in the maintenance block was either asleep or unbothered, and the school settled into the particular intimacy of an unplanned blackout.\nEmeka had been in the council room for eleven minutes, waiting.\nThe joint meeting had run long, longer than either of them had planned, and the other council members and the two prefects who attended as observers had left when the agenda was finished and the light was still on. Naza had stayed to write up the minutes. Emeka had stayed because there was an item they had not resolved, the hostel noise curfew overlap, where the prefect body''s existing framework and the council''s Notice 007 contradicted each other in the thirty-minute window between nine and nine-thirty, and someone needed to decide which document governed.\nNow they were sitting in the dark.\nHe heard her open a drawer, heard the click of a small torch, and a thin beam of light appeared across the table. She set the torch upright so it threw light at the ceiling and became a lamp of sorts. Functional. Not bright enough for writing but enough to see by.\n"I have a candle somewhere," she said.\n"The torch is fine."\nShe sat back down. The table between them was covered in files and loose papers and two empty sachets of water, the ordinary debris of a meeting that had gone three hours. Her council file was open to the minutes page, half filled in her careful handwriting.\n"Nine to nine-thirty," he said.\n"Nine to nine-thirty," she agreed. She looked at her file. "My notice says lights off, common rooms closed. Your framework says supervised wind-down, prefect present."\n"They are not incompatible."\n"They are if the prefect on duty decides wind-down means the common room stays open."\nHe conceded this with a slight tilt of his head. "Amend the notice to specify that supervised wind-down takes place in the hostel corridors, not the common rooms. The common rooms close at nine. The prefect manages corridor movement until nine-thirty."\nShe wrote it without responding for a moment. He watched her handwriting move across the page, the same careful lettering she had used on her campaign posters.\n"That works," she said.\nOutside, the generator came on with its familiar diesel cough and the lights returned. The fluorescent tube above them flickered twice and resumed its argument with itself. Naza switched off the torch and put it in the drawer.\nThey looked at each other briefly in the restored light, and something in the dynamic of the room had shifted without either of them engineering it. The dark had done something to the formal distance that joint meetings required. Not removed it. Just loosened it slightly, the way a collar loosens when you have been wearing it for a long time.\nNaza closed her file. "Can I ask you something."\nIt was not phrased as a question requiring permission, so he waited.\n"The school voted you senior prefect by staff appointment, not election," she said. "Did you want it that way? Or would you have run, if they had let you?"\nHe looked at her.\n"I am asking because I want to understand something," she said. "Not to start an argument."\nHe considered the question with the honesty it deserved. "I would have run," he said. "And I think I would have won."\n"I think so too," she said, without any particular colour in it.\n"But I wanted the appointment," he continued. "An election is a popularity contest dressed in procedure. An appointment means someone who has watched you decided you were the right person. I preferred being decided on."\nShe was quiet for a moment. "I am the opposite," she said. "The election mattered to me specifically because it was an election. Two hundred and forty-seven people chose this. Not one person in authority looking at a list." She paused. "The number still sits with me. I look at the school differently because of it."\nHe had not expected her to tell him the number sat with her. He had thought about that number more than he would admit to anyone, and to hear her say it plainly, without performance, rearranged something small in the way he had been carrying the term.\n"Two hundred and forty-seven is a mandate," he said.\n"It is a responsibility," she said. "Which is heavier."\nThe fluorescent tube flickered once and they both looked up at it with the involuntary reflex of people who have been in enough blackouts to distrust restored power.\nIt held.\nNaza gathered her files and stacked them with the neat efficiency that was her default mode in this room. Emeka collected the meeting agenda sheets and aligned them against the edge of the table.\n"The curfew amendment," he said. "You will update the notice?"\n"By tomorrow morning." She stood. "I will send it to you before it goes up."\n"I know," he said.\nShe picked up her files and her torch and her empty water sachets, which she deposited in the bin by the door with the instinctive tidiness of someone who did not leave rooms the way she found them.\nAt the door she stopped.\n"You said you preferred being decided on," she said. "By one person who watched you." She looked at him with the level attention he had stopped trying to decode and simply accepted as her default. "Do you think they saw the right things?"\nHe did not answer immediately.\n"I used to think so," he said.\nShe held his gaze for a moment, the way she held things she intended to remember, and then she nodded once and walked out into the corridor.\nEmeka sat at the long table for another minute.\nThe fluorescent tube flickered above him.\nHe did not look up at it this time.','\n',char(10)),1024,0,1,NULL,'2026-04-26 16:59:17','2026-04-10 07:28:29','2026-04-26 16:59:17','2026-04-26T17:15:00.000Z',2,25);
INSERT INTO "chapters" ("id","novel_id","chapter_number","title","content","word_count","is_premium","is_published","audio_url","published_at","created_at","updated_at","scheduled_release_at","part_number","season_id") VALUES(317,41,4,'Decent, Once',replace('The argument was already three minutes old when Emeka turned the corner.\nHe heard Mr. Adeyinka''s voice first, which was not unusual. Mr. Adeyinka taught SS2 Economics and had a voice calibrated for a room larger than any room he was ever actually in. It carried through walls and around corners and arrived before he did, which gave most students enough warning to adjust themselves into whatever shape the moment required.\nThe boy in the corridor had not had enough warning.\nHe was JS2, small even for his year, standing against the wall outside the Geography room with his exercise book held out in front of him like a document being presented for inspection. Mr. Adeyinka was reading it with the theatrical dissatisfaction of a man who had already decided what he thought before he read it.\n"This is what you submitted," Mr. Adeyinka said. "This."\n"Sir, I—"\n"You wrote four lines. Four lines for a full classwork assignment. Four lines, Chidi."\n"Sir, I was sick on Thursday. I told the class teacher."\n"You told the class teacher." Mr. Adeyinka lowered the book and looked at the boy with the expression of a man for whom this explanation had not improved the situation. "You told the class teacher. And I am asking you why you submitted four lines."\n"Because I was sick, sir. I did not finish."\n"You did not finish." He held the book out. "Take it. Write it again. Full assignment. On my desk by seven AM tomorrow, or I am entering zero in the record."\n"Sir, tomorrow is Saturday."\nA pause.\n"I am aware of what tomorrow is."\nEmeka had stopped at the corner.\nHe watched the boy take the book with both hands, the particular two-handed receipt of a student taking something from a teacher, automatic and trained in. The boy''s face was doing the complicated work of holding together, the jaw tight, the eyes fixed at a point below Mr. Adeyinka''s chin, the posture of someone absorbing an outcome they do not have the standing to dispute.\nEmeka knew that posture. He had produced it in students himself and had filed it, when he noticed it, under: necessary. Under: the cost of maintaining order.\nHe looked at it now and felt something he could not file anywhere cleanly.\nHe walked around the corner.\n"Mr. Adeyinka."\nThe teacher turned. His expression arranged itself into the version it used for senior students, not quite the authority he deployed on juniors, not quite the collegiality he used with other staff. Something in between.\n"Emeka."\nEmeka looked at the boy briefly, then at the teacher. "I could not help overhearing. The student was absent Thursday with the class teacher''s knowledge?"\nMr. Adeyinka''s eyes moved. "That is between me and my student."\n"I am asking because if the absence was documented, the school''s missed-work policy gives the student the number of days they were absent to complete outstanding work. Not a fixed deadline."\nA silence.\nMr. Adeyinka looked at him with the specific expression of a person recalculating what kind of conversation they were having. "You are quoting school policy at me."\n"I am confirming what I understand the policy to be," Emeka said. "In case it is useful."\nThe teacher looked at the boy, then back at Emeka. The corridor held the stillness of a moment finding its shape.\n"He can submit Monday," Mr. Adeyinka said. He said it the way a person makes a concession that they intend to reframe as a decision. "Monday morning. Seven AM."\n"Thank you, sir," Emeka said.\nMr. Adeyinka walked away with the brisk movement of a man who had other places to be that were more comfortable than this one.\nEmeka looked at the boy.\nChidi was staring at him with the open, slightly stunned expression of someone whose falling had been interrupted before they hit the ground and who had not yet decided what to do with the solid surface beneath their feet.\n"Monday," Emeka said. "Do not make it late."\n"Yes, sir." A pause. "Thank you, sir."\nEmeka walked on.\nHe did not think about it after.\nThat was the honest account. He walked to the prefects'' room and reviewed the duty roster for the weekend and ate his dinner and went to bed at his usual time, and the corridor incident did not present itself to him as something requiring reflection. It had been a policy clarification. It had been correct procedure, applied to a situation where someone had not applied it. That was all.\nHe did not know that Chidi had a senior sister in SS1 who had been standing at the far end of the corridor and had seen everything.\nHe did not know that she had told three people by evening.\nHe did not know any of this until Tuesday.\nNaza arrived at the joint meeting four minutes early, which was her habit, and she was arranging the agenda sheets when Emeka came in. She looked up and then back at the papers.\n"I heard about the corridor," she said.\nHe pulled out his chair. "Which corridor."\n"Chidi Mbah. Mr. Adeyinka. Friday."\nHe sat down. "It was a policy matter."\n"I know what it was." She set a sheet in front of his seat. "I am just telling you I heard about it."\nHe looked at the agenda. "Is it on the agenda?"\n"No."\nHe picked up the sheet and read it.\nNaza uncapped her pen and wrote the date at the top of her minutes page. The council room had its usual early-meeting quiet, chairs still being found, papers still being settled.\n"Chidi is in the same class as my hostel neighbour''s junior sister," Naza said, without looking up. "Apparently he told his whole class."\nEmeka said nothing.\n"I am not making a point," she said. "I am just telling you what is being said."\nShe finished writing the date and looked up at him with the level attention that had stopped unsettling him sometime in the last three weeks without him noticing the exact moment it stopped.\n"What is being said?" he said.\nShe held his gaze for a moment.\n"That Oga Prefect defended somebody," she said. "That he did not have to, and he did."\nShe looked back at her minutes page.\nEmeka looked at the agenda.\nOutside, the other council members were coming down the corridor. He could hear their voices approaching, the ordinary noise of people who had not been sitting in a room with a sentence that had just landed quietly and completely and changed the temperature of the air.\nHe kept his eyes on the agenda.\nHe did not say anything.\nHe did not need to.','\n',char(10)),1117,1,1,NULL,'2026-04-26 16:59:52','2026-04-10 07:29:33','2026-04-26 16:59:52','2026-04-26T17:15:00.000Z',2,25);
INSERT INTO "chapters" ("id","novel_id","chapter_number","title","content","word_count","is_premium","is_published","audio_url","published_at","created_at","updated_at","scheduled_release_at","part_number","season_id") VALUES(318,41,5,'Mr. Adeyinka',replace('The first sign was small enough to miss.\nA council notice, Number 016, had been posted on a Monday regarding the library period. Junior students were to be given dedicated access on Wednesday afternoons, unsupervised, on the basis that the previous system of requiring a senior student escort had reduced JS library usage by more than half. Naza had presented the data at a joint meeting. Emeka had reviewed it and raised no objection. The notice had gone to Mrs. Okafor, come back stamped, and gone up on the boards.\nBy Wednesday, Mr. Adeyinka had taken it down from the board outside his classroom.\nNot all the boards. Just the one outside his classroom, which was the one JS students passed on their way to the library. When the JS2 class arrived for their Wednesday library period and found no notice confirming the arrangement, half of them turned back, uncertain, and spent the period in the common room instead.\nNaza brought it to Emeka on Thursday morning.\nShe showed him the gap on the board, the four tack holes where the notice had been, and said nothing. She did not need to say anything. The four holes said it.\n"It could have fallen," Emeka said.\nShe looked at him.\n"I am noting the possibility," he said. "Not arguing for it."\n"The tacks are gone," she said. "Fallen notices keep their tacks."\nHe looked at the board a moment longer. "Who do you think took it?"\n"I do not think," she said. "I know. Mama Ngozi saw him."\nEmeka was quiet.\nMr. Adeyinka had been, if not a friend exactly, then a consistent point of support. He was the kind of teacher who understood that a school ran better when its senior prefect had enough informal authority to handle situations before they required staff intervention. He had nodded at Emeka in corridors with the nod of a person who approved of the way things were. He had backed three of Emeka''s disciplinary calls last term by declining to contradict them when junior students appealed to him. Their relationship had never been stated. It had simply operated, like most real arrangements in institutions, beneath the level of documentation.\nThat relationship was what made the removed notice legible as a message rather than a mistake.\n"He is testing it," Emeka said.\n"He has been testing it since January," Naza said. "This is the third incident. The first two I could not prove. This one I can."\nHe looked at her. "What were the first two?"\nShe opened her file. She had documentation. Of course she had documentation. A note from the JS1 class representative about a council welfare meeting that had been rescheduled twice because the room they had been allocated was suddenly unavailable both times. A written account from a SS1 girl who had been told by Mr. Adeyinka, during a class session, that the student council was a federal government experiment that would be gone by next year and was not worth any serious student''s attention.\nEmeka read both accounts.\nHe set the file down.\n"He said this in a class session?" he said.\n"To thirty-two students."\nHe looked at the board again. The four holes. The missing notice.\nHe had known Adeyinka was uncomfortable with the new structure. Most of the older teachers were, to varying degrees, uncomfortable with the idea that a JS3 girl had formal authority over student affairs that they had previously navigated informally, through seniors they had selected and could manage. But discomfort was one thing. Removing a posted, principal-stamped notice from a school board and telling a classroom full of students that the council was temporary and insignificant was something else.\nIt was the kind of behaviour that, if Emeka had seen it directed at the prefect body, he would have addressed before the week was out.\nHe understood, standing at the board with Naza''s file in his hand, that this was the choice. Not a complicated one in principle. Complicated only because of what it cost.\n"I will speak to him," he said.\nNaza looked at him steadily. "I am taking it to Mrs. Okafor."\n"I know. I am saying I will speak to him before you do." He returned her file. "Not to protect him. To give him the opportunity to correct it himself before it becomes a formal record. That is the right sequence."\nShe considered this. "How long do you need?"\n"One day."\n"You have until Friday morning," she said. "If the notice is not back on that board by Friday, and if I do not have his written confirmation that the class statement will be retracted, it goes to the principal with Mama Ngozi''s account attached."\n"Understood."\nHe found Mr. Adeyinka in the staffroom after school, grading papers at the table near the window he preferred. The staffroom was mostly empty at this hour, one other teacher at the far end on a phone call, the ceiling fan going at full speed and doing almost nothing about the heat.\nEmeka sat down across from him without being invited.\nMr. Adeyinka looked up and then back at his papers. "Emeka."\n"Sir."\nA pause. The pen moved across a page.\n"Notice 016," Emeka said. "The board outside your classroom."\nThe pen stopped. Adeyinka set it down with the deliberateness of a man choosing his response before he delivered it. "Notices fall," he said.\n"The tacks were removed."\nA silence.\n"Sir," Emeka said. He kept his voice at the register he used for things that required steadiness. "You told your SS2 class the council is temporary."\nMr. Adeyinka leaned back in his chair and looked at him with the expression of a man who had decided to be honest because the alternative was more effort than it was worth. "What I told my class is my business."\n"It is the school''s business when you tell thirty-two students that a principal-authorised structure is not worth their attention."\n"I am a teacher of sixteen years in this school," Mr. Adeyinka said. "I have watched structures come and go. I am allowed to have a perspective."\n"In your own time," Emeka said. "Not in a classroom. Not about a structure the principal has approved and the school is building." He held the teacher''s gaze. "And not by removing posted notices."\nMr. Adeyinka looked at him for a long moment, and inside that moment Emeka could see the man recalculating something. What he had expected, perhaps, versus what had arrived. An ally. A boy whose authority he had quietly supported. Now sitting across from him and placing the prefect body, without ambiguity, on the other side of the table.\n"You are defending that girl''s council," Adeyinka said.\n"I am defending the school''s structure," Emeka said. "Which now includes the council. Sir."\nThe sir came out clean and without softness.\nAdeyinka picked up his pen. He looked at his papers. He was quiet long enough that the ceiling fan completed several full rotations.\n"The notice will go back up," he said. "Tomorrow morning."\n"And the class statement?"\nA pause. "I will address my class."\n"Thank you, sir."\nEmeka stood and pushed his chair in neatly and walked out of the staffroom. The corridor outside was cooling into evening, the light coming in flat and orange through the western windows, the school settling into its after-prep quiet.\nHe walked back toward the hostel block without hurrying.\nHe thought about the nod Adeyinka had given him in corridors last term. The quiet backing. The understanding that had operated beneath documentation because it did not need documentation.\nHe thought about Naza''s file. The four tack holes. Thirty-two students told that something real was not worth their attention.\nHe thought about what it had cost him to sit across that table and spend that particular currency.\nHe decided it had been the correct expenditure.\nHe straightened his badge and kept walking.','\n',char(10)),1319,1,1,NULL,'2026-04-26 17:00:06','2026-04-10 07:30:29','2026-04-26 17:00:06','2026-04-26T17:15:00.000Z',2,25);
INSERT INTO "chapters" ("id","novel_id","chapter_number","title","content","word_count","is_premium","is_published","audio_url","published_at","created_at","updated_at","scheduled_release_at","part_number","season_id") VALUES(319,41,6,'Temporary Alliance',replace('Mr. Adeyinka did not put the notice back up.\nThursday came and went. The board outside his classroom held a duty roster and a mathematics reminder and the four tack holes from Notice 016, unchanged. Emeka walked past it on his morning rounds and said nothing to anyone. He walked past it again in the afternoon and said nothing to anyone. He returned to the prefects'' room that evening and sat with the duty roster and the knowledge that he had given his word to Naza on a timeline that was now expiring.\nFriday morning she was at the board at seven-fifteen with her file.\nHe arrived at seven-twenty.\nShe looked at the board, then at him, with the expression of a person who had expected exactly this outcome and had prepared accordingly. "I am going to the principal."\n"I know," he said. "I am coming with you."\nShe looked at him for a moment. "You do not have to."\n"I gave you a timeline," he said. "He did not meet it. I will not tell the principal something different from what happened."\nShe held his gaze, and something moved briefly behind her eyes, not surprise exactly, more like the quiet confirmation of a thing she had been uncertain about. Then she turned toward the administrative block. He fell into step beside her.\nThey walked the length of the compound together in the early morning light, past the neem tree and the green council board and the JS students starting to move toward the dining hall for breakfast. Two SS2 girls watched them with the open curiosity of people filing something away for later discussion. Emeka kept his eyes forward.\nMrs. Okafor was already at her desk.\nShe looked up when they came in together and her expression did not change, but she set down her pen. "Sit."\nThey sat. Naza placed her file on the desk and opened it to the documentation. Mrs. Okafor read without being guided through it. She read Mama Ngozi''s account, the class statement record, the note about the unavailable rooms. She looked at the photograph Naza had taken of the board with the four holes.\nShe read everything twice.\nThen she closed the file and looked at Emeka. "You spoke to him Thursday."\n"Yes, ma."\n"And he agreed to replace the notice."\n"He said it would go back up Friday morning."\nShe looked at the wall clock. It was seven thirty-one. "It is Friday morning."\n"Yes, ma."\nMrs. Okafor was quiet for a long moment. Outside her window the compound was building toward its morning rhythm, the breakfast movement, the approaching bell. She picked up a pen and wrote something at the top of a sheet of paper.\n"I will speak with Mr. Adeyinka today," she said. "This will go into his formal record. If there is a fourth incident of any kind, it will go to the ministry." She looked at both of them. "The council''s library arrangement stands. I will post a replacement notice myself this morning."\n"Thank you, ma," Naza said.\nMrs. Okafor looked at Emeka. "You backed the council''s position."\n"I backed the school''s structure," he said. It came out the same way it had in the staffroom, clean and without softness.\nThe principal looked at him with the careful, unornamented attention of a person reading something more than the words being said. She nodded once.\nThey stood to leave.\n"One more thing," Mrs. Okafor said.\nThey stopped.\n"Working together looks like what you just did." She looked at them both, briefly. "Not a meeting agenda. Not a signed notice. This. Remember it."\nShe picked up her pen and returned to her desk.\nThey came out of the administrative block into the full morning light and stood for a moment on the step. The compound was in its breakfast motion now, students crossing in loose groups, the dining hall doors open and releasing the smell of tea and bread.\nNaza closed her file. She did not say anything immediately. He did not either.\nIt was strange, was the accurate word for it. Three terms ago he had stood in a corridor and given this girl fifty lines for running. He had used her full name as a piece of authority, a weight to press with. She had taken her lines to the prefects'' room at six o''clock and set them on the table without a word, and he had collected them without looking at her face, and that had been the complete transaction.\nNow they had sat on the same side of a principal''s desk and said the same thing and walked out the same door.\n"He will not take it well," Naza said. "Adeyinka."\n"He will manage it."\n"He will make it uncomfortable for the council members in his classes."\nEmeka looked at her. "If he does, document it. Immediately. Do not wait for a pattern. One incident, one record."\nShe was already writing something in her file. He watched her handwriting move across the page and thought about the first time he had seen it, on a white cardboard poster with a green and gold border, outside the female hostel block.\nBecause the school belongs to all of us.\nHe had read that line and filed it under: campaign language. The kind of sentence a candidate wrote because it sounded right, not because it had content.\nHe was less certain about that filing now.\n"The council members in his classes," he said. "Who are they?"\nShe looked up. "Blessing Osei, SS2A. And Dayo Fashola, SS2C."\n"I will check on them informally. Through the prefect rounds. If Adeyinka makes it uncomfortable, there will be something visible before they have to document it themselves."\nShe looked at him with the level attention that had become, somewhere in the last two months, simply a thing he expected rather than something he braced for. "You would do that."\nIt was not a question, but it had the shape of one.\n"I said I would," he said.\nShe nodded slowly, the particular nod of someone adjusting a position they had been holding for a long time. Not a large adjustment. But real.\nThe bell rang for first period.\nAround them the compound redirected itself from dining hall to classrooms, the shift happening in the quick, total way it happened in boarding schools, one collective purpose exchanging itself for another.\n"Tuesday meeting," Naza said, moving toward the JS block.\n"Tuesday," he agreed.\nShe walked away in the flat, purposeful stride he had been watching since the corridor in his first term, and he stood on the administrative step a moment longer before turning toward Ahmadu block.\nThe morning felt different from the inside than it looked from outside it.\nHe had gone into that office with the council''s case and his own word and nothing else, and it had been enough, and the difference between today and the common room in December was not small. He could measure it cleanly.\nHe did not know what to call the thing that had happened on the step.\nHe walked toward his first class and decided it did not need a name yet.','\n',char(10)),1196,1,1,NULL,'2026-04-26 17:00:37','2026-04-10 07:31:30','2026-04-26 17:00:37','2026-04-26T17:15:00.000Z',2,25);
INSERT INTO "chapters" ("id","novel_id","chapter_number","title","content","word_count","is_premium","is_published","audio_url","published_at","created_at","updated_at","scheduled_release_at","part_number","season_id") VALUES(320,41,7,'What Made Him',replace('It came out on a Wednesday, which was not a day Emeka would have chosen.\nThe inter-house sports preparation had run into a problem with the SS3 boys who were supposed to anchor the relay team but had, in the way of SS3 boys in their final term, developed a collective indifference to schedules that did not directly concern their WAEC preparation. Emeka had spent forty minutes on the field trying to assemble a full practice and had managed three quarters of one. He came off the field in the low afternoon heat with red dust on his shoes and a frustration he was not entirely managing.\nNaza was sitting on the low wall outside the sports store, waiting.\nShe had a council matter, something about the inter-house scorekeeping arrangement and whether the council''s welfare monitors should have access to the first aid station independently or through the sports prefect. It was a reasonable question that required a direct answer and on another afternoon he would have given it cleanly and moved on.\nInstead he sat down on the wall beside her, which he had not planned to do, and said: "Ask me."\nShe asked. He answered. She wrote it in her file.\nThen she said, without looking up from the writing: "You are tired."\n"I am fine."\n"You have been on the field since four. The relay boys did not show." She capped her pen. "You are tired and you are also angry, which is a combination you do not usually let out together."\nHe looked at her.\n"I notice things," she said simply.\nHe looked away, at the field, where the groundskeeper was beginning his evening sweep of the track. The sun was going down behind the Kogi hills in the usual way, unhurried and total.\n"My father was a headmaster," he said.\nHe had not decided to say it. It arrived the way things arrived when you were tired and someone was sitting close enough to receive them.\nNaza did not respond immediately. She let the sentence settle.\n"Community secondary school in Onitsha," he continued. "He ran it for nineteen years. The way he ran it, everything was structure. Morning assembly ran to the minute. Teachers who were late were addressed publicly. Students who broke rules were corrected in front of the school because he believed correction was also instruction, that the watching students learned as much as the one being corrected."\nHe paused.\n"You grew up watching that," Naza said.\n"I grew up inside it." He looked at his shoes, the red dust on the white canvas. "He ran our house the same way. My mother used to say he could not find the door between the school and the sitting room. That he carried the headmaster in with him every evening and forgot to leave it on the step."\nThe groundskeeper reached the far end of the track and turned.\n"He was not cruel," Emeka said. "I want to be clear about that. He was not a cruel man. He was a man who believed that the most important thing you could give a person was the certainty of consequences. That if a person knew exactly what would happen when they stepped out of line, they were safer. More contained. He believed containment was a form of love."\nNaza was very still beside him.\n"When I came here at thirteen I was the son of a headmaster in a school full of boys who had nobody watching. Boys who had taken off whatever their homes had put on them the moment the gate closed. And I understood something in the first week." He stopped.\n"What did you understand?" she said.\n"That the school was afraid of the wrong things. It was afraid of noise and uniform violations and running in corridors, but it was not afraid of the things that actually hurt people. The senior boys who took things from juniors. The classrooms where the weak students got their work taken and had no language to report it in because the language of the school said seniors were authority and authority was not questioned." He paused. "My father would have called that disorder. I called it the same thing. I decided I was going to be the thing that corrected it."\n"And the corridor became your assembly ground," Naza said quietly.\nHe turned to look at her.\nShe was not looking at him with softness. She was looking at him with the careful attention of someone recording something precisely because it mattered, not because it was comfortable. Her expression had not changed into sympathy. It had changed into something more honest than sympathy.\n"Yes," he said.\n"And the junior students who were afraid of you," she said. "The ones who flattened against walls. You counted that as the school being safer."\nIt was not an attack. It was a question with a weight she was handing him directly, without padding.\n"I did," he said. "For a long time."\n"And now?"\nHe was quiet for a moment. Below them on the field the groundskeeper had almost finished his sweep, the track clean and dark red in the evening light.\n"Now I think my father had one thing right," he said. "Certainty matters. People need to know where they stand." He looked at the field. "But I think he had one thing wrong. He thought the structure was the safety. That if the rules were clear enough and the consequences certain enough, nothing bad could get through." He paused. "The structure is not the safety. The people inside it are the safety. If the people are wrong, the structure just gives them better organisation."\nNaza looked at him for a long moment.\nShe did not say: I am sorry about your father. She did not say: that explains so much. She did not soften the conversation into comfort or harden it into verdict.\nShe picked up her file and opened it again and wrote something at the bottom of the page.\n"The first aid station," she said. "The welfare monitors will coordinate through the sports prefect for access. But if the sports prefect is unavailable they have independent authority. I will write it that way."\n"That is correct," he said.\nShe finished writing.\nThe sun had gone fully behind the hills now and the compound lights were coming on one by one, the slow illumination of an institution settling into its evening self.\n"My full name," she said, without looking up. "Chinazaekpere. It means God answers my prayers. My mother is Igbo from Enugu. She chose it." She closed the file. "Hauwa is my father''s mother''s name. She was from Kano. She died before I was born." She stood from the wall. "I carry both of them. I do not always know how to do that cleanly."\nShe picked up her things.\n"I am telling you that," she said, "because you told me something."\nShe walked away toward the JS hostel block.\nEmeka sat on the wall until the compound lights had all come on and the field was dark and the groundskeeper had long since gone inside.\nHe sat with what she had given him in return.\nSomething that had been sitting locked in his chest for three years had been looked at directly and not flinched from, and the person who had looked at it had not used it to soften him or to win anything.\nShe had simply filed it.\nHe found, unexpectedly, that this was exactly what he had needed.\nWord count: 1,069','\n',char(10)),1260,1,1,NULL,'2026-04-26 17:01:01','2026-04-10 07:32:26','2026-04-26 17:01:01','2026-04-26T17:15:00.000Z',2,25);
INSERT INTO "chapters" ("id","novel_id","chapter_number","title","content","word_count","is_premium","is_published","audio_url","published_at","created_at","updated_at","scheduled_release_at","part_number","season_id") VALUES(321,41,8,' The Almost',replace('It started with rain and a borrowed umbrella and a decision that seemed reasonable at the time.\nThe third-term inter-house cultural night had been Naza''s project from the beginning, a council initiative to give each house thirty minutes of performance time, music and spoken word and a short drama piece, with the dining hall rearranged into something that resembled, with effort and goodwill, a proper venue. Emeka had been involved in the logistics, crowd management and seating and the particular problem of four hundred students in an enclosed space after dark, which required a prefect presence that could be firm without flattening the occasion.\nIt had gone well. Better than expected. The drama piece from Confluence House had made three teachers laugh out loud, which was the kind of outcome that changed the temperature of a school for days.\nBy nine-fifteen, the hall was cleared and the compound was wet.\nThe rain had come in during the last performance, the way Lokoja rain arrived in March, without the slow build of warning, just a sudden total commitment. By the time the event ended and students began moving back to hostels, the paths between the buildings were running shallow and the air smelled of wet laterite and the particular greenness that came up from the ground when Lokoja finally decided to rain.\nEmeka was at the dining hall door coordinating the hostel movement when he noticed Naza at the far side of the compound, standing at the edge of the overhang with her council file pressed against her chest and no umbrella, looking at the gap between the dining hall and the JS hostel block. The gap was forty metres of open ground with no covered walkway and rain coming down in the earnest way it came down when it intended to stay a while.\nHe had an umbrella.\nHe told himself it was logistical. She was the council president and it was a school event she had organised and it was reasonable for the senior prefect to ensure she got back to her hostel without her files being destroyed by rain. This was the account he gave himself as he crossed the covered walkway to where she stood.\nShe looked at him when he arrived, and then at the umbrella.\n"Come on," he said.\nShe fell into step beside him and he opened the umbrella as they moved off the overhang and into the rain. It was a standard umbrella, not large, and the rain was specific in its intentions, which meant they were closer together than their usual council room distance, her shoulder near his arm, his hand above both of them holding the umbrella at the angle that kept most of the rain off.\nThey walked.\nThe compound was still moving around them, students in groups making quick runs for their hostels, some with umbrellas, some without and apparently reconciled to this. The groundskeeper''s cat had taken up position on the windowsill of the science block and was watching the rain with the philosophical calm of an animal that had made its decision.\nHalfway across the compound Naza said: "The drama piece."\n"Confluence House."\n"The part where the principal character realises he has been arguing with himself the whole time." She was looking ahead at the hostel block. "I wrote that scene."\nHe looked at her. "You wrote it."\n"I gave it to the drama students three weeks ago. I told them they could change whatever they needed." She paused. "They kept most of it."\nHe thought about the scene. The principal character, a market trader who had been conducting a long argument with a rival, discovering in the final minutes that the rival was a version of himself from an earlier point, stubborn and frightened and certain. The audience had laughed, but it was the kind of laughter that had something else underneath it.\n"It was the best piece of the night," he said.\nShe was quiet for a moment. "I know what it was about," she said. "You can say it."\nHe looked at her.\nShe was not looking at him. She was watching where she was stepping, navigating a shallow run of water across the path. But her chin was at the particular angle it took when she was saying something she had decided to say without decorating it.\n"I will not say it," he said.\n"Why not?"\n"Because you already know. And because saying it changes the size of it."\nShe looked at him then, briefly, quickly, the rain making a light sound on the umbrella above them. Her face in the compound lights was very close and very clear and she was looking at him with something he had not seen in her before, something that was not the level assessment she used in the council room and was not the careful attention she had given him on the wall outside the sports store.\nIt was something without a procedure for it.\nHe held her gaze.\nThe JS hostel block was five metres away.\n"Emeka." Her voice was quieter than the rain.\n"Naza."\nHe did not know what would have come next. He would think about this afterward, turning it over the way you turn over something you found in an unexpected place, trying to understand what it was before you decide what to do with it. He did not know what would have come next because what came next was the hostel door opening and Naza''s hostel neighbour, a loud SS1 girl named Priye, appearing in the light of the doorway with an expression of total delight.\n"Naza! I have been waiting. You have to see what happened in the SS2 common room, somebody''s provision box is missing and Mama Titi is—" She stopped. She looked at Emeka. She looked at the umbrella. She looked at the distance between them, which was not a large distance, and her expression completed a calculation that took approximately one second.\n"Good evening, sir," she said, in a voice completely failing to be neutral.\nNaza stepped out from under the umbrella and onto the hostel step. "I am coming," she said to Priye, in a voice that was entirely neutral because she had chosen it. She turned back to Emeka.\nShe held out her hand for her council file, which he had been holding without realising it.\nHe gave it to her.\nTheir fingers did not touch. He was certain of this. There was a clean transfer and a clean space between and the file moved from his hand to hers without contact.\nAnd yet.\n"Thank you," she said. "For the umbrella."\n"Good night," he said.\nShe went inside.\nThe door closed.\nEmeka stood in the rain with the umbrella above him and the compound emptying around him and the cat still watching from the science block windowsill.\nHe walked back to the senior hostel.\nThe rain came down steady and complete.\nHe did not try to name what had almost happened.\nHe simply walked, and breathed, and let the rain say whatever it was saying.','\n',char(10)),1180,1,1,NULL,'2026-04-26 17:01:26','2026-04-10 07:33:38','2026-04-26 17:01:26','2026-04-26T17:15:00.000Z',2,25);
INSERT INTO "chapters" ("id","novel_id","chapter_number","title","content","word_count","is_premium","is_published","audio_url","published_at","created_at","updated_at","scheduled_release_at","part_number","season_id") VALUES(322,41,9,'Old Habits',replace('The pressure had been building since Monday.\nWAEC mock examinations were two weeks out and the school had the specific tension of an institution that had staked its reputation on results and was now counting the days until it found out if the stake had held. Teachers were running extra lessons that ran into each other''s extra lessons. The timetable had become a suggestion. The hostels were louder at night with the low, persistent noise of students studying past lights out, which the prefects were supposed to manage and the council''s curfew notice governed and neither structure was managing cleanly because the students doing it were SS3 students and SS3 students three weeks from WAEC existed in a category of their own.\nEmeka had slept five hours on Monday and four on Tuesday and on Wednesday he had handled three separate hostel disputes before breakfast, one of which involved a missing textbook that turned out not to be missing but borrowed without asking, which was the kind of dispute that took forty minutes to resolve and left everyone involved in a worse position than the missing textbook had.\nHe was on the second floor of Ahmadu block on Wednesday afternoon when he heard the noise from the stairwell.\nLaughter, first. The kind that had an edge in it, louder than laughter needed to be, which meant it was performing for someone. Then a voice, high and frightened, trying to make itself smaller.\nHe pushed the stairwell door open.\nThree SS2 boys were on the landing between floors. They had a JS1 student pressed against the wall, not physically, they were not touching him, but they had arranged themselves around him in the way that did not require touching. The JS1 boy was holding a textbook against his chest and his eyes were moving between the three older boys with the rapid calculation of someone trying to find the exit in a room that had closed.\n"Give it," one of the SS2 boys was saying. He was a broad boy named Tunji, who Emeka knew as someone who operated at the outer edge of what could be documented.\n"It is my textbook," the JS1 boy said. His voice was doing the thing voices did when they were trying to hold still.\n"We know it is your textbook. We are borrowing it."\nMore laughter.\nEmeka came through the door and the laughter stopped with the clean finality of a switch.\nThe three SS2 boys arranged themselves into innocence.\n"Tunji," Emeka said.\n"Sir." Smooth. Practised.\nEmeka looked at the JS1 boy. "Go."\nThe boy went, down the stairs and fast, the textbook still pressed to his chest.\nEmeka looked at the three boys. The fatigue was sitting behind his eyes in a way he had been managing all week and he was tired of managing it. He was tired of the extra lessons overrunning and the hostel disputes and the mock timetable and the specific quality of this term which had required more from him than any previous term and given less back.\n"All three of you," he said. "My room. Now."\nThey followed him upstairs.\nIn the prefects'' room he stood at the window and they stood near the door and he told them what they had done in the terms he used to use for things like this, direct and without softening, the language of consequence delivered with the certainty of someone who was not interested in their account of it.\n"Sir, we were not—"\n"I did not ask for your account."\nA pause.\n"A hundred lines each. I will not intimidate junior students. Clean sheet. Here by six o''clock."\nTunji''s jaw moved slightly. "Sir, the mock timetable—"\n"Six o''clock," Emeka said.\nThey left.\nHe stood at the window for a moment, the compound below going about its afternoon self, and he felt the tension in his chest loosen by one degree, the release that came from handling something with the certainty that it was handled.\nHe did not know Naza was in the corridor until he came out of the room.\nShe was three doors down, coming from the direction of the SS prefect liaison''s room where the council kept a secondary file cabinet. She had her file. She had clearly been there long enough.\nTheir eyes met.\nHe knew what she had heard. He could see it in the quality of her stillness.\n"It was handled," he said.\nShe looked at him. Not with the level assessment of the council room or the careful attention of the wall outside the sports store. Something older. Something that reminded him, with an accuracy that was uncomfortable, of the expression on Tobenna Eze''s face in the common room in December. The expression of someone recalibrating something they had held as changed.\n"A hundred lines," she said.\n"They were intimidating a JS1 student."\n"I know what they were doing." She held her file against her chest, both hands, the same way she had held her notebook on election day. "I heard what you said in there. The way you said it."\n"They needed to hear it clearly."\n"They did not need lines, Emeka. They needed to understand what they did and why it was wrong." She looked at him with something that was not anger. Anger would have been easier than this. "Lines are not understanding. You know that. You have known that since December."\nHe held her gaze. "The situation required authority."\n"The situation required correction." She said it carefully, the way she said things she had decided deserved precision. "You were tired and you were certain and you walked into that room the way you used to walk through every corridor in this school. You did not correct them. You pressed them."\nHe felt something tighten in his chest.\n"You are not that prefect anymore," she said. "I thought you were not that prefect anymore."\nThe corridor held the quiet of an after-lesson building, distant and ordinary.\n"You thought," he said.\nShe looked at him for a long moment.\nThen she looked away, at the wall, at nothing specific. She let out a breath that was not quite a sigh and not quite a word but had the weight of both.\n"I will see you at the Tuesday meeting," she said.\nShe walked toward the stairwell.\nHe did not call her back. He had no ground to call her back on, which he understood before she had taken three steps, and the understanding sat in his chest like the rain had sat on the umbrella two weeks ago, insistent and patient.\nHe listened to her footsteps on the stairs.\nThen silence.\nHe went back into the prefects'' room and sat on the edge of his bed and looked at the duty roster on the wall above the door, his own handwriting in clean block letters, and he thought about the three boys walking in with the smoothness of practised innocence and the JS1 boy''s eyes moving between them trying to find the exit.\nHe had walked into the room tired and certain.\nHe had not asked the three boys to explain themselves. He had not given them the thing he had given Chidi Mbah in the corridor outside the Geography room, the thing Naza had heard about secondhand and reported back to him with a quietness that had changed the temperature of a meeting room. He had given them lines and a time and the door.\nHe pressed both hands against his knees.\nOutside, the mock timetable was running. Somewhere in the school thirty-one council notices were posted on boards, three co-signed with his name, eleven attended by him in their drafting. Somewhere on the first floor there was a stairwell landing where a JS1 boy had gone home free because Emeka had arrived before the situation became something else.\nThese were also true.\nBut Naza had been in the corridor and she had heard it and her face had done the thing it did when something failed to be what she had believed it was, and the season was ending with the distance between them larger than it had been since January, and this time he could not locate the error in her reading of the situation.\nThat was the part that stayed.\nHe was not entirely the boy from the corridor anymore.\nBut he was not entirely free of him either.\nHe sat with that until the six o''clock bell rang, and then he got up and straightened his badge and waited for three SS2 boys to bring him a hundred lines each, because he had said six o''clock, and some habits were the right ones to keep.','\n',char(10)),1449,1,1,NULL,'2026-04-26 17:01:43','2026-04-10 07:34:41','2026-04-26 17:01:43','2026-04-26T17:15:00.000Z',2,25);
INSERT INTO "chapters" ("id","novel_id","chapter_number","title","content","word_count","is_premium","is_published","audio_url","published_at","created_at","updated_at","scheduled_release_at","part_number","season_id") VALUES(323,43,1,'After the Break',replace('The third term began on a Thursday, which felt wrong in the way that things feel wrong when the calendar refuses to cooperate with the weight of what you are carrying.\nEmeka arrived a day early, the way he always did, and unpacked in the same order as always, textbooks first, clothes flat and tight, the prefect record notebook on top of everything. He pinned his badge to his shirt on the first morning and stood at the window of the prefects'' room and looked at the compound receiving its new-term population and told himself the distance was professional and appropriate and not a problem he needed to solve.\nHe had told himself this for three weeks at home in Onitsha, and it had not become more convincing with repetition, but he was committed to the attempt.\nThey saw each other on the second day.\nIt was not an encounter. That was the precise word for what it was not. An encounter required something to happen. This was two people crossing the administrative corridor from opposite directions at the same time and adjusting their trajectories by a degree each and continuing without stopping.\n"Emeka."\n"Naza."\nFour syllables total, and then the corridor returned to its ordinary business.\nHe continued to the notice board. She continued to the principal''s office. The students nearby absorbed this exchange with the quick, peripheral attention of a school population that had been watching these two people occupy the same spaces for two terms and understood that something in the texture of it had changed.\nBy afternoon the understanding had moved, the way understanding always moved in a boarding school, without a single identifiable carrier.\nThe Tuesday meeting was the first real test.\nEmeka arrived at five o''clock, as agreed. The council members were already seated, Blessing Osei and Dayo Fashola side by side, two JS representatives across from them, the SS1 liaison in the corner with her notebook. Naza was at the head of the table with the agenda already distributed.\nShe did not look up when he came in.\nHe sat in his usual chair, the one to her left where the prefect liaison always sat, and picked up the agenda sheet and read it.\nThe meeting ran for fifty-five minutes.\nNaza chaired it with the same precision she always brought, clear on agenda items, firm on timing, fair in the way she managed the room. She addressed him three times, twice for prefect body input on logistics and once to confirm the weekend duty roster. Each time she spoke to him it was with the professional correctness of someone who had decided that correctness was the available register and was going to use it fully.\nHe matched it exactly.\nIt was, technically, the most efficient meeting they had run all year.\nIt was also the worst.\nBlessing Osei caught his eye as the meeting ended, briefly, with the expression of a person watching a bridge that used to be there and is now not there, trying to understand when it left. He looked away before she could say anything.\nThe school felt different in the fracture.\nThat was the thing he had not anticipated. He had expected the distance to be between them and to stay between them, a contained thing with clean edges. Instead it moved. It was in the dining hall when they sat at their respective tables, the SS senior table and the council table, and both tables faced the same direction and the gap between them was twelve feet of dining hall floor and also something larger. It was in the corridor when junior students, who had absorbed the change by now, adjusted their requests, going to one or the other of them based on the type of issue rather than going to both the way they had begun doing in the second term, that careful navigation of two people who had been, for a period, worth approaching together.\nPrefect Biodun, who had the instincts of a person who survived institutions by reading them accurately, said nothing for four days and then said, carefully, on Friday evening: "The meeting was quiet this week."\n"Meetings are supposed to be quiet," Emeka said.\n"Not that kind of quiet," Biodun said.\nEmeka did not respond and Biodun, correctly, did not continue.\nOn Saturday he took his morning rounds later than usual, when the compound was in its weekend looseness and there was less that required managing. He walked the full perimeter, Ahmadu block to the science wing to the library corridor to the JS classrooms, the route he had walked three times a week for two years until it was less a route than a rhythm.\nOutside the library, he stopped.\nThere was a new notice on the council board, posted since Friday. He read it.\nCouncil Notice 031: Inter-house sports welfare arrangement, final version. The document was clean and thorough. First aid access, water station locations, welfare monitor assignments. At the bottom, under implementation notes, a single line: Prefect liaison to confirm duty assignments by Wednesday. Contact Senior Prefect directly.\nHe stood in front of it for a moment.\nShe had written contact Senior Prefect directly. Not the council office. Not the liaison system they had built in January with the careful architecture of two people constructing something neither had wanted to need. Directly.\nHe did not know what it meant. It could have been efficiency. It could have been a door left open by someone who was not ready to close it completely, left open in the only language currently available, which was the professional language of council notices and implementation notes.\nHe took a photograph of the notice with the careful attention of someone preserving evidence.\nThen he walked on.\nHe completed his rounds and returned to the prefects'' room and sat at the desk and opened his record notebook and wrote the date at the top of the page in his clean block letters. He wrote the duty assignments for the week. He wrote the inter-house sports logistics, the prefect names, the locations, the times.\nAt the bottom of the page he wrote: Contact re: Notice 031 — Wednesday.\nHe looked at the words.\nOutside, the compound was doing its Saturday things, the loose voices and the football and the particular quality of light that Lokoja produced in the late morning of the dry season, flat and bright and honest about what it was.\nHe closed the notebook.\nWednesday was four days away.\nHe would hold the professional distance for four days and on Wednesday he would make contact as the notice specified and they would handle the inter-house logistics with the correctness they had both committed to.\nAnd perhaps somewhere in that correctness there would be a margin. Small and unannounced.\nHe did not count on it.\nBut he did not rule it out.','\n',char(10)),1147,0,1,NULL,'2026-04-26 17:02:15','2026-04-10 07:41:18','2026-04-26 17:02:15','2026-04-26T17:15:00.000Z',3,27);
INSERT INTO "chapters" ("id","novel_id","chapter_number","title","content","word_count","is_premium","is_published","audio_url","published_at","created_at","updated_at","scheduled_release_at","part_number","season_id") VALUES(324,43,2,' What She Carries',replace('The letter from home arrived on a Tuesday inside a brown envelope with her father''s handwriting on the front, the careful Hausa-inflected cursive he had used on every letter since JS1, and Naza sat on her hostel bed and held it for a full minute before opening it.\nHer father wrote the way he talked, in the long, looping sentences of a man who believed that the shortest distance between two points was not always the most honest one. He asked about her health and her studies and her food. He asked whether the harmattan had broken yet in Lokoja. He said her grandmother in Kano was asking after her. He said her mother sent her love and also a reminder about her Mathematics, which needed attention.\nAt the bottom, in the particular handwriting shift that meant he had returned to the letter after putting it down: Your mother tells me the school principal called. She says you are doing well. We are proud. But Naza, remember that you are fifteen. You do not have to carry the whole school.\nShe folded the letter and put it back in the envelope.\nShe sat with it in her lap for a while.\nThe weight had arrived gradually, which was the thing nobody warned you about. In the election week it had felt like possibility, all of it, the campaign and the votes and Mrs. Okafor''s handshake and the compound noise that had come up from three hundred and eighty-one students in the sun. She had stood at the podium and looked out at the school and felt the size of what had just been handed to her and decided, in the same breath, that she was ready.\nShe had been ready for some of it.\nThe council meetings, she could run. The notices, she could write. The logistics and the documentation and the careful architecture of building a new structure inside an old institution, she had found that she had the patience and the precision for those things in a way that surprised even herself.\nIt was the other part.\nTiwa was the first one. A JS2 girl who had come to the council office in February with a complaint about a class teacher who was marking her work unfairly, lower than her classmates on identical answers, and had sat across the table from Naza with the careful posture of someone who had rehearsed the request and was still not certain it would be received. Naza had taken the complaint. She had followed the process. She had documented and reported and Mrs. Okafor had reviewed the marking and the teacher had been spoken to.\nThe teacher had not been disciplined. He had been spoken to.\nTiwa''s marks had not changed retroactively.\nNaza had sat in her own office afterward and understood something about the distance between structure and outcome that no council notice could fully close.\nThere was Emeka. She had put him in a category in September and the category had kept needing revision, which was its own kind of cost. You could not revise a category without admitting the original had been wrong, and she had not been entirely wrong, which made the revision more complicated than if she had been. He had been exactly what she thought he was and then consistently more than that and then, in the stairwell corridor after the mock revision week, exactly what she thought he was again, and she had walked away from that corridor with the particular exhaustion of someone who had invested attention in a thing and found it returned incompletely.\nShe was still not certain what she had walked away from.\nShe was not certain she wanted to be certain.\nOn Wednesday she was in the council office when Blessing Osei knocked and came in with a face that meant something specific had happened.\n"The JS1 girls," Blessing said.\nNaza set down her pen.\n"Three of them came to me this morning. They have been giving their provisions to an SS3 girl since the beginning of term." Blessing sat down. "Not giving. She comes to their room on Friday nights."\n"Who is the SS3 girl?"\nBlessing told her.\nNaza wrote the name and looked at it on the page.\nThe SS3 girl was a school daughter of the senior female prefect. Which meant the path this complaint needed to travel went directly through the existing social architecture of the female hostel, the school mother and daughter system that predated the council, predated any current student, predated possibly any teacher currently on staff. It was not written anywhere. It operated the way most real things operated, below documentation, in the understanding passed from one year group to the next.\nShe could report it to the senior female prefect and watch it disappear into that architecture.\nShe could take it directly to Mrs. Okafor and spend the next two weeks managing the fallout in the female hostel, where the council''s authority was newer and more fragile than it appeared from outside.\nShe could document it and hold it and wait for a third incident that gave her more ground.\nNone of the options were clean.\nShe sat with all three of them and thought about her father''s letter. You do not have to carry the whole school. She thought about what carrying it actually meant from the inside, the specific weight of knowing about a thing and being responsible for what happened to the knowledge.\nYou did not have to carry it.\nBut if you did not, someone else did. Or no one did. And the JS1 girls kept giving their provisions on Friday nights because the structure that was supposed to protect them had looked at the architecture and decided it was complicated.\n"I will take it to the principal," she said.\nBlessing looked at her with the careful expression of a person measuring the cost being accepted. "The hostel will be difficult after."\n"I know."\n"The SS3 girls will make it difficult. And they only have eight weeks left, so they will not be cautious about it."\n"I know," Naza said again.\nShe wrote the incident report in the careful handwriting she used for things that needed to last. She named the SS3 girl. She named the three JS1 girls with their permission. She wrote the dates and the items and the process by which it had reached the council.\nShe signed it at the bottom with her full name, both parts, Igbo and Hausa, the way she had given it to Emeka in the corridor in September when she had decided she would not offer him a smaller version of herself to work with.\nShe had not stopped making that decision every day since.\nThis was what nobody saw from the outside. Not the meetings or the notices or the election number. This daily decision to sign your full name to things that would make the week harder, because the alternative was signing less.\nShe put the report in its envelope.\nOutside, the dry season light was doing its flat, honest thing to the compound.\nShe picked up her father''s letter and read the last line one more time.\nYou do not have to carry the whole school.\nShe put the letter in her drawer.\nShe picked up the envelope and walked to the principal''s office.','\n',char(10)),1228,0,1,NULL,'2026-04-26 17:02:36','2026-04-10 07:42:29','2026-04-26 17:02:36','2026-04-26T17:15:00.000Z',3,27);
INSERT INTO "chapters" ("id","novel_id","chapter_number","title","content","word_count","is_premium","is_published","audio_url","published_at","created_at","updated_at","scheduled_release_at","part_number","season_id") VALUES(325,43,3,'The Prefect Nobody Sees',replace('The thing about being watched for three years was that you forgot how to stop.\nEmeka noticed this on a Sunday morning in March when he woke at five forty-five, which was twenty minutes before the bell, which was his habit, and lay in the half-dark of the prefects'' room listening to the breathing of two other prefects still asleep and understood that he had been performing even in here. In the room where no junior student ever came. In the room where the badge sat on the locker instead of the chest.\nHe lay still and asked himself what he would do differently if nobody was going to see it.\nHe did not have an immediate answer, which told him something.\nThe WAEC preparation period had collapsed the school''s usual structure into a single tunnel with examination dates at the end of it. Extra lessons had replaced free periods. The library ran a double shift. Even the compound''s social life, the football and the evening conversations and the loose Saturday freedoms, had contracted into something quieter and more purposeful.\nIn this compression, Emeka found himself with something he had not had in three years of senior school.\nUnscheduled time.\nNot free periods. Not the deliberate gaps in a structured day that a senior prefect used for record-keeping or duty planning. Actual unaccounted time, on a Wednesday afternoon, when the extra lesson he was supposed to attend was cancelled because the teacher had a ministry visit and the prefect duty roster had a two-hour gap he had not filled and there was nothing, for two hours, that the school required from him.\nHe stood in the prefects'' room holding the duty roster and looked at the gap and felt something he could not immediately name.\nHe went to the library.\nNot for WAEC preparation. He had done his preparation. He went because the library was the one place in the school where presence required no explanation, where you could sit with a book and have the book be the complete account of what you were doing.\nHe signed in at the desk and went to the back section, the shelves of fiction and general reading that got less traffic than the reference shelves and smelled of the particular dust of books that were used by people who chose them rather than needed them. He ran his hand along the spines and pulled out a novel he had started in JS2 and never finished, a worn copy of a Chinua Achebe he had read the first sixty pages of and set aside because examination preparation had arrived and he had not gone back.\nHe sat in the corner chair, the one with the cracked plastic armrest that nobody preferred, and he read.\nHe read for an hour and forty minutes.\nNobody needed anything from him. Nobody walked past and adjusted their posture. Nobody gave him a nod of acknowledgement or stepped out of his path. He was simply a boy in a chair with a book, and the library around him went about its own quiet business, pages turning and pencils moving and the ceiling fan completing its slow rotations above the study tables.\nSomewhere in the second hour he realised he had not thought about the badge once.\nHe came back on Thursday. And Friday.\nOn Friday he brought his own book, a mathematics textbook he had finished using for WAEC preparation and kept because there were problems at the back he had not solved, not because they were on any syllabus but because they were difficult and he had not been able to leave them alone since December.\nHe worked through two of them.\nThe first took twenty minutes and yielded cleanly. The second refused. He worked at it for forty minutes from three angles, filling half a page with approaches that arrived at wrong answers, and sat back and looked at it with the particular frustration of a problem that was not unclear but was simply beyond his current reach.\nHe was still looking at it when a JS3 boy appeared at the end of his shelf, looking for a reference book, and stopped when he saw Emeka.\nThe boy''s face did the calculation. Senior prefect. Sitting alone in the back of the library on a Friday afternoon working through unsolicited mathematics with a page full of wrong answers visible.\n"Sir," the boy said carefully.\n"The reference books are the next shelf," Emeka said.\nThe boy went to the next shelf.\nEmeka looked at the wrong answers on his page.\nHe was used to being seen in competence. Three years of corridors had trained him to present the finished version, the badge straight, the back upright, the decision already made before anyone could watch him make it. He had made certainty into a costume so well fitted that he had stopped knowing where the costume ended.\nBut the wrong answers were there on the page and the JS3 boy had seen them and nothing had collapsed.\nHe picked up his pencil and tried the problem from a fourth angle.\nOn Saturday evening he sat in the common room after dinner.\nNot to supervise it. Not with a duty reason. He sat in the SS common room because it was where the other boys were, and being where the other boys were without a purpose was something he could not remember doing since the first week of JS1, before he understood the kind of boy he was going to become in this school.\nBiodun was there, and Seun, and four other SS3 boys in various positions of WAEC anxiety, and someone had tuned a radio to a station playing old music, the kind of music that made no academic demands and asked only to be heard.\nBiodun looked at him when he came in, the look of a person recalibrating. He moved his bag from the empty chair beside him.\nEmeka sat.\nThey sat for an hour. The music played. Someone produced a packet of biscuits and it moved around the room. Conversation happened, not about examinations, but about after, about university choices and cities and what the world outside this school looked like from the inside of the school looking out.\nEmeka talked. Not extensively. But he talked.\nHe said he wanted to study law. He had not said this out loud to anyone in this school before because it had not been relevant information. His identity here was the badge, not the plan behind the badge.\n"Law," Biodun said. "I can see that."\n"Why?" Emeka asked.\nBiodun looked at him with the careful honesty of someone who had spent two years watching him from close range. "Because you have always cared about what is correct," he said. "You just spent a long time thinking correct meant the same thing as certain."\nThe room was quiet for a moment.\n"That is true," Emeka said.\nBiodun nodded, the nod of a person satisfied to have said a thing and had it received.\nThe music played.\nOutside, the dry season dark had settled over the Kogi hills, and the compound was in its Saturday-evening self, and somewhere in the JS hostel block a girl with two names was carrying the weight of a school that she had chosen, daily, not to put down.\nEmeka did not know this specifically.\nBut he sat in the common room with his name not on any duty roster and the badge on his locker and the wrong answers on a page in the library, and he was, for the first time in three years, simply present in a room without managing it.\nIt was unfamiliar.\nIt was not as frightening as he had expected.','\n',char(10)),1290,0,1,NULL,'2026-04-26 17:02:58','2026-04-10 07:43:44','2026-04-26 17:02:58','2026-04-26T17:15:00.000Z',3,27);
INSERT INTO "chapters" ("id","novel_id","chapter_number","title","content","word_count","is_premium","is_published","audio_url","published_at","created_at","updated_at","scheduled_release_at","part_number","season_id") VALUES(326,43,4,'Final Term Crisis',replace('The list appeared on a Monday and by Tuesday it was the only conversation in the school.\nIt was not posted officially. It circulated the way damaging things circulated in boarding schools, person to person, a photograph of a document that should not have been photographed, moving through the student body faster than any notice Mrs. Okafor had ever stamped and posted on a green board.\nEmeka saw it in Biodun''s hand at breakfast.\nA printed register. Forty-one SS3 names. Beside each name, a column for WAEC registration confirmation. Thirty-seven names had a tick. Four did not.\nBiodun''s name was among the four.\nEmeka looked at the list and then at Biodun, who was looking at his tray with the particular stillness of someone who had been awake with a thing for longer than one night.\n"All four paid," Emeka said. Not a question.\n"Before the January deadline," Biodun said quietly. "You collected my receipt yourself."\nEmeka had. He had run the payment confirmation exercise personally, collected forty-one receipts, compiled the register, submitted the folder to the vice principal''s office in January with a cover sheet in his own block letters. He had been thorough because he was always thorough.\nForty-one names. Forty-one ticks should exist somewhere.\n"Who else knows?" he said.\nBiodun looked up. "Everyone who has seen this photograph. Which is most of the school."\nHe found Naza before first period.\nShe was outside the council office already holding her own copy of the photograph, and she looked at him with the expression of someone who had been waiting for this conversation since she woke up.\nHe told her what he knew. She told him what she had found. The examination board''s submission deadline was Friday. Four unconfirmed names by Friday meant four SS3 students who could not sit WAEC this year.\n"The folder went to Mr. Idowu''s office," she said.\nThey looked at each other.\nMr. Idowu had been vice principal for eleven years. He had never been openly hostile to the council. He had been, more precisely, absent from it, signing what required signing and contributing nothing that was not strictly necessary. Emeka had always read this as professional neutrality.\nHe was reading it differently this morning.\n"Nine o''clock," Naza said. "His office. Together."\nMr. Idowu received them across his organised desk with the measured expression of a man who had decided before they sat down how this conversation was going.\nEmeka presented the issue plainly. Four names. Unconfirmed. Friday deadline. The folder submitted to this office in January.\n"Registration processes have technical delays," Mr. Idowu said. "These things resolve."\n"The deadline is Friday," Naza said. "We need to know what happened to the four names between January and now."\nMr. Idowu looked at her with the specific expression of a man who had a category for student council presidents. "The examination board communicates with school administration," he said. "Not the student council."\n"We are not asking the examination board," Naza said. "We are asking you."\nA silence.\n"I will look into it."\n"We would like to see the submission acknowledgement," Emeka said. "The document confirming the board received all forty-one names."\nThe vice principal opened the wrong drawer first. Then the correct one.\nHe produced a document.\nEmeka read it. Examination board acknowledgement, dated January. Thirty-eight names.\nThirty-eight.\nHe looked at the document. Then at Mr. Idowu. "The folder I submitted had forty-one names."\n"Technical—"\n"Three names are missing from a document that left this office," Naza said, her voice level and precise. "That is not technical. That has a Friday deadline. We need the resolution process."\nMr. Idowu straightened a file on his desk that did not need straightening.\n"I will contact the examination board today."\n"We would like to be copied on that communication through Mrs. Okafor''s office," Naza said. "So the affected students have confirmation before Friday."\nThey were in Mrs. Okafor''s office by eleven.\nShe read the acknowledgement, looked at the number thirty-eight, and picked up her phone without a word. The second call lasted eleven minutes and her voice carried the particular quality of a person who had decided to be very clear and was not going to decide otherwise.\nShe put the phone down.\n"The examination board will accept a supplementary submission for the three missing names by Wednesday." She looked at Emeka. "Your original folder. Do you have a copy?"\n"With the receipts. In the prefects'' room."\n"This afternoon." She looked at them both. "The four students will sit their examinations."\nShe said it with the finality of a sentence that had already decided its own outcome. "Go to class."\nIn the corridor outside, Naza walked beside him in the direction of their classrooms.\n"Biodun''s issue is different," Emeka said. "Outstanding school fees. The bursary flagged it and the board was notified." He paused. "He has been managing it quietly."\nNaza wrote something in her file. "How much?"\nHe told her.\n"The council welfare reserve covers it," she said. "With your agreement as prefect liaison. Joint decision."\nHe looked at her. The welfare reserve she had argued for in January, that he had attended the drafting of without fully committing to its purpose, was about to do exactly what she had said it would do.\n"Agreed," he said.\nThey reached the junction where their classrooms diverged.\n"Emeka," she said.\nHe stopped.\n"The receipts. Bring two copies to Mrs. Okafor. Leave one with me." She held his gaze. "You submitted forty-one names in January and the record shows thirty-eight and we do not yet know exactly where the three went. The person with a copy of the original submission is the person who can account for it." She paused. "I want to be that person alongside you."\nHe was quiet for a moment.\n"Two copies," he said.\nShe turned and walked to her class.\nHe walked to his, and thought about forty-one names in his own block letters, and three that had not arrived where they were supposed to, and the girl walking in the other direction who had decided, without being asked, to hold the record with him.\nHe thought: this is what page three means. This is what the document is actually about.\nHe went to class.','\n',char(10)),1040,1,1,NULL,'2026-04-26 17:03:20','2026-04-10 15:13:28','2026-04-26 17:03:20','2026-04-26T17:15:00.000Z',3,27);
INSERT INTO "chapters" ("id","novel_id","chapter_number","title","content","word_count","is_premium","is_published","audio_url","published_at","created_at","updated_at","scheduled_release_at","part_number","season_id") VALUES(327,43,5,'The Apology That Isn''t Easy',replace('The inter-house sports crisis took three days to fully surface and arrived, as these things tended to, at the worst possible time.\nIt began with a disqualification.\nConfluence House had won the relay on Saturday by a margin wide enough to feel decisive, and the compound had received the result with the particular noise of a school that had watched something settle cleanly. But on Monday morning Mr. Bisi, the sports coordinator, posted a review notice outside the staffroom. A timing irregularity in the third leg. The result was under review pending confirmation from the second timekeeper''s record.\nBy Monday afternoon it was clear what the review would find.\nThe second timekeeper was Rotimi, an SS2 boy from Emeka''s house, Niger House, which had finished second. And Rotimi''s record showed a time in the third leg that, if accepted, would push Confluence out of first place and move Niger House to the top.\nEmeka had assigned Rotimi to the timekeeper position himself.\nHe had not asked Rotimi to do anything. He needed to be clear about this in his own account. He had given Rotimi the role through the standard logistics process, the same way he assigned every position. He had not discussed the result with him. He had not suggested anything.\nBut he knew Rotimi.\nHe had known since Monday afternoon, looking at the discrepancy between the two timekeeping records, that Rotimi had done this for Niger House because Rotimi was exactly the kind of boy who would do this for Niger House, and Emeka had put him in the position, and that connection was not clean.\nHe sat with this knowledge through Monday evening and Tuesday morning.\nThe council was involved because Naza had been the welfare coordinator for the event, which meant she had co-signed the sports logistics notice that included the timekeeper assignments. Her name was beside his on the document. The review affected her record as much as his.\nShe came to him on Tuesday afternoon.\nShe knocked on the prefects'' room door, which she had never done before, always catching him in corridors or the council office. He opened it and she stood in the doorway with her file and the particular quality of stillness that meant she had thought carefully about what she was going to say before she arrived.\n"Rotimi," she said.\n"Yes."\nShe looked at him. "Did you know?"\n"No." He held her gaze. "I did not ask him to do anything. I did not know he would."\nShe accepted this. "But you knew what kind of boy he was when you assigned him."\nHe was quiet.\n"I am not accusing you," she said. "I am asking what you knew."\n"I knew he was house-loyal," Emeka said. "I did not think that far ahead. I should have."\nNaza looked at the floor for a moment, then back at him. "Mr. Bisi is going to give Niger House the result if no one challenges the process. The review is a formality. The second timekeeper''s record supersedes the first. That is the written rule."\n"I know the written rule."\n"The written rule is going to give your house the win on a record that is most likely false." She looked at him steadily. "I cannot challenge it without your support. My challenge alone reads as council politics. But if you bring it forward, it is the senior prefect himself flagging the integrity of his own house''s result."\nHe understood exactly what she was asking.\nIt was not a small thing. Niger House had not won inter-house sports in four years. The boys in his house had trained for this term with a seriousness he had watched and respected. His own housemaster, Mr. Eze, had spoken about the result in Monday morning assembly with a warmth that was the closest Emeka had seen the man come to open pride. And the WAEC period meant this was the last inter-house sports of his school career.\nHe was also, in eight weeks, going to leave this school and go into a world that would take the measure of him by different tools than a prefect badge.\n"I will go to Mr. Bisi," he said.\nNaza looked at him.\n"Today," he said. "Before the review closes."\nMr. Bisi''s office was a small room attached to the sports store that smelled of linseed oil and old leather and the specific history of school athletics. The sports coordinator was a lean, unhurried man who had been timing school races for twenty-two years and who looked at Emeka across his desk with the expression of someone who had a reasonable idea of why he had come.\nEmeka stated it plainly.\nHe said that he had assigned Rotimi to the timekeeper position. He said that Rotimi was a Niger House boy who was house-loyal to a degree that, in retrospect, made his assignment to that position a conflict of interest. He said he could not confirm the discrepancy was deliberate but could not confirm it was not. He said the integrity of the result required the discrepancy to be investigated rather than resolved by the written rule alone.\nHe said all of this in the register he used for things that required steadiness.\nMr. Bisi listened without interrupting. When Emeka finished, the sports coordinator looked at his desk for a long moment. He picked up a pen and set it down.\n"You understand what this means for Niger House," he said.\n"Yes, sir."\n"Your housemaster already told the boys."\n"I know, sir."\nMr. Bisi looked at him with the careful attention of a man who had been in schools long enough to understand that what was happening in this chair in front of him was not common. "Why are you here, Emeka?"\nHe had not prepared an answer for this because it was not a question he had expected. He sat with it for a moment.\n"Because Confluence House ran the relay," he said. "And the result should belong to who ran it."\nThe sports coordinator nodded slowly.\n"I will reopen the review," he said. "Formally. Both timekeepers will be interviewed separately. The result will be determined by the full investigation, not the written hierarchy." He paused. "This will take three days."\n"Understood, sir."\n"And Niger House will know who initiated it."\n"I know, sir."\nHe walked out of the sports office into the afternoon light.\nThe Niger House boys knew by dinner.\nHe could feel it when he walked into the dining hall, the particular quality of a room that has been discussing you and has not finished. Rotimi was at the end of the Niger House table and looked at his tray when Emeka sat down. Two other boys shifted. His housemaster, Mr. Eze, was at the staff table and did not catch Emeka''s eye, which was its own kind of statement.\nBiodun sat beside him and opened his dinner and said nothing.\nAfter a while Biodun said: "You went to Bisi."\n"Yes."\nBiodun ate. "The boys are not happy."\n"I know."\n"Rotimi is not speaking."\n"That is his right."\nBiodun looked at his tray. "Was it worth it?"\nEmeka looked at the dining hall, the tables and the trays and the four hundred students eating in the noise of an ordinary Tuesday evening.\n"Yes," he said.\nHe said it without the weight of someone convincing themselves. He said it the way you say something that is simply true, that was true before you said it, that will be true after.\nBiodun nodded.\nThey ate dinner.\nAt the council table across the hall, Naza was listening to something Blessing Osei was saying. She did not look across the room.\nBut when she stood to leave, she did, briefly, and she held his gaze for exactly long enough to say something that had no words in the only language currently available between them.\nHe looked back.\nThen she was gone, and the dining hall was the dining hall again, and the result of Niger House''s last inter-house sports was uncertain and three days away, and Emeka was sitting with the cost of a thing he had done right.\nIt did not feel the way he expected it to feel.\nIt felt solid.','\n',char(10)),1372,1,1,NULL,'2026-04-26 17:03:35','2026-04-10 15:15:17','2026-04-26 17:03:35','2026-04-26T17:15:00.000Z',3,27);
INSERT INTO "chapters" ("id","novel_id","chapter_number","title","content","word_count","is_premium","is_published","audio_url","published_at","created_at","updated_at","scheduled_release_at","part_number","season_id") VALUES(328,43,6,'Chinazaekpere',replace('The investigation gave Confluence House the relay.\nThe finding came on Friday morning, three days after Emeka had walked into Mr. Bisi''s office, posted on the sports notice board in the same clean typed format as every other official result. Rotimi''s record was found inconsistent with the electronic backup timing device that had been running as a secondary measure and had not been considered until the formal review required it. Confluence House won by a margin of one point nine seconds.\nNiger House''s final inter-house sports ended in second place.\nEmeka read the notice on his morning rounds. He stood in front of it for a moment and then continued walking.\nIn the hostel that evening, two Niger House boys passed him in the corridor without speaking. This had been the texture of the last three days, not hostility exactly, more like a rearrangement, the way a room rearranges itself around a piece of furniture that has been moved, everyone adjusting their paths without announcing the adjustment. Rotimi had returned to speaking but spoke around him, the way you speak around a thing you are not ready to address directly.\nBiodun remained Biodun, which Emeka was more grateful for than he had said.\nHe sat at his desk that evening and opened his record notebook and wrote the date and the confirmed result and closed the notebook and looked at the wall.\nHe had done the right thing.\nHe knew this cleanly, without the need to argue himself into it. But right things had costs and the costs were real and he was sitting with both, the rightness and the cost, in the same chest, and they did not cancel each other.\nIt was Mrs. Okafor who created the occasion.\nShe called them both to her office on Saturday morning, the last Saturday before the final examination week, which meant the last weekend of any relative freedom the school would have before WAEC descended and reorganised everything into urgency. She was writing when they came in and gestured for them to sit without looking up.\nShe finished what she was writing, set down her pen, and looked at them both.\n"End of year review," she said. "I do this with the student leaders every third term. I am going to tell you what I observed this year and you are going to tell me what you think needs to happen differently next year."\nShe talked for fifteen minutes. Emeka listened.\nShe talked about the council structure and what it had achieved and where it had gaps. She talked about the prefect body and how its role had evolved over the year, not always smoothly but honestly. She talked about the food crisis and the Adeyinka situation and the inter-house sports review, and she spoke about each of them with the direct, unornamented assessment that was her consistent mode, naming what had worked and what had cost and what had been learned.\nShe looked at Emeka when she spoke about the sports review. "That was not easy," she said.\n"No, ma."\n"It was correct."\n"Yes, ma."\nShe turned to Naza. "The provisions incident. You had pushback from the female hostel."\n"Yes, ma."\n"You held the position."\n"Yes, ma."\nMrs. Okafor looked at them both. "You built something this year," she said. "Not the council. Not the prefect framework. Something between the two that I did not design and did not ask for and that turned out to be the most functional part of the school''s student structure." She paused. "I want it documented. A written framework that the incoming leadership can use. Not a set of rules. A set of principles. How you made decisions together. What you referred upward and what you resolved directly and how you knew the difference."\nShe picked up her pen. "I need it before your last examination. That gives you ten days."\nThey came out of the principal''s office into the Saturday morning light.\nThe compound was in its last weekend looseness, the particular freedom of students who could see the end of the tunnel and had not yet entered the final dark of it. Someone was playing music from the JS hostel. The neem tree threw its shade across the entrance path in the clean geometry of a late morning sun.\nThey stood on the administrative step.\n"Ten days," Naza said.\n"We can do it."\nShe looked at the compound. She was in her weekend clothes, a yellow blouse and dark trousers, which was the first time he had spoken to her in this year outside of school uniform, and there was something disorienting about it in a way he did not examine closely. She looked younger and more particular, more specifically herself, than the council president in the pressed uniform.\n"The principles," she said. "We will need to sit together properly. Not a meeting. Something longer."\n"Sunday evening," he said. "The council room."\nShe nodded.\nA pause settled between them, the particular quality of a pause between people who have more to say than the current moment has given them language for.\nHe had been thinking about the corridor since December of last year. Not constantly. But with the returning frequency of something that had not been resolved. The fifty lines. Her full name used as a weight. The notebook on the floor and the chin that came up before the answer. He had thought about it during the holiday and during the second term and in the third term while the distance was loud between them and he was looking for a margin in council notices.\nHe had been thinking about how to say it.\nHe understood now that there was no correct method. There was only the moment and the name and the decision to mean it.\n"Chinazaekpere," he said.\nShe turned and looked at him.\nNot the council president look. Not the level assessment. She looked at him the way you look at something that has arrived unexpectedly and correctly, the look of someone whose name has been said the full way, both syllables of the Igbo part landing with the care of someone who has learned the weight of them.\nHe had called her Naza for two terms. Everyone called her Naza. It was easier and she answered to it without appearing to mind. But her mother had chosen Chinazaekpere, and the choice meant something, and he had used the name as a weapon once and it had sat in him since then as an unresolved account.\n"I want to say something," he said. "Not for the framework. Not for the principal."\nShe waited.\n"The corridor," he said. "September. The fifty lines." He held her gaze. "You were running. That part was correct. The lines were correct by the rules I was operating under." He paused. "But I used your name the way I used everything that year. As a tool. As something to press with." He looked at her steadily. "That was not the correct use of your name."\nNaza was very still.\n"I cannot go back to that corridor," he said. "But I can say it plainly. I used what you gave me as a weight, and I should not have, and I am sorry for it."\nHe said the last sentence without decoration, without the softening that would have made it easier to deliver and less than it needed to be.\nShe looked at him for a long moment.\nThe compound moved around them in its Saturday way, ordinary and indifferent to the particular nature of what was happening on the administrative step.\n"I know you know," she said. "That I wrote about it."\n"The drama piece."\n"Not just that." She looked at the neem tree. "In my council notebook, in September, the week after the corridor. I wrote about it. What it felt like to have your own name used as the thing that pressed you down." She looked back at him. "I write things to understand them. I wrote that to understand why authority felt different from power." She paused. "You became the answer to that question over the course of this year. Not a comfortable answer."\nHe received this.\n"Chinazaekpere," he said again, more quietly. "God answers prayers."\n"My mother''s faith," she said. "Not always mine." Something shifted in her expression, small and honest. "But sometimes."\nThe music from the JS hostel had changed to something slower, drifting across the compound with the unhurried quality of a Saturday that did not know it was the last real one.\n"Sunday evening," he said. "The council room. Six o''clock."\n"Six o''clock," she said.\nShe walked toward the JS hostel block.\nHe stood on the step until she had crossed the compound and gone inside, and then he turned and walked back toward Ahmadu block, and the morning was the morning, flat and honest and bright, and his name for her was different now and her name in his mouth was different and neither of them had said anything about what that meant.\nThey had ten days and a document to write.\nIt was enough to begin with.','\n',char(10)),1522,1,1,NULL,'2026-04-26 17:03:48','2026-04-10 15:16:38','2026-04-26 17:03:48','2026-04-26T17:15:00.000Z',3,27);
INSERT INTO "chapters" ("id","novel_id","chapter_number","title","content","word_count","is_premium","is_published","audio_url","published_at","created_at","updated_at","scheduled_release_at","part_number","season_id") VALUES(329,43,7,'Who We Are Now',replace('The document took nine days.\nThey met in the council room on Sunday evening and three evenings after that, and what began as a framework for incoming student leaders became something neither of them had anticipated writing. Not a set of rules. Mrs. Okafor had been clear about that. But the principles kept arriving with the specific gravity of things that had been learned at cost, and cost gave them a weight that neither of them wanted to flatten into administrative language.\nOn the fourth evening Naza looked at the draft and said: "This reads like a record of everything we did wrong."\n"It reads like a record of everything we learned," he said.\nShe looked at it again. "Same document."\n"Yes," he said. "That is the point."\nShe wrote that down, not as a principle but as a note to herself, in the margin, the small handwriting she used for things that were not yet finished becoming.\nThey submitted the document to Mrs. Okafor on the ninth day, four pages, clean and direct, with a title they had argued about for twenty minutes and settled on without entirely agreeing: On Running a School Together: Notes for the People Who Come After.\nMrs. Okafor read it in front of them.\nShe read it the way she read everything, completely and without performance, and when she finished she set it on her desk and looked at them both.\n"This is better than what I asked for," she said.\nShe did not say anything else about it. She did not need to.\nThe last examination was on a Thursday.\nLiterature in English, which was the paper Emeka had been least anxious about and which arrived with the particular mercy of a final examination that asked for things he genuinely had. He wrote for two hours and fifteen minutes in the examination hall, which smelled of anxiety and ceiling fan oil and the specific dusty solemnity of a room where results were being made, and when the bell rang and the papers were collected he sat for a moment with his hands flat on the empty desk.\nDone.\nHe walked out of the examination hall into the afternoon light and stood on the steps and looked at the compound, which was already converting itself into its end-of-year version, students emerging from halls with the released energy of people who had been contained by a purpose and were now free of it.\nSomeone shouted. Someone else shouted back. An SS3 boy from Kogi House threw his examination booklet into the air and watched it fall with the expression of a person who had just completed a sentence he had been constructing for three years.\nEmeka looked at the compound for a long time.\nThe leaving began that evening.\nBoxes appeared at doorways. The hostel corridors took on their end-of-term sounds, the dragging and the metallic complaint of lockers. But this was different from end-of-term. This was the particular leaving of people who were not coming back to this version of the place, and the school knew it, in the way that institutions know things, in the texture of its sounds and the quality of its light.\nHe was in the middle of packing when Biodun appeared at the door.\n"People are gathering at the neem tree," Biodun said. "The SS3s."\nEmeka set down the stack of textbooks he was holding.\nHe had not planned to go. Gatherings of this kind, informal, unscheduled, existing outside the structure of official end-of-term activities, were things he had supervised in the past two years rather than joined. But he was not supervising anything tonight. He was an SS3 student who had written his last paper and had a box half-packed and eight weeks of secondary school behind him.\nHe went.\nThirty-one SS3 students under the neem tree in the warm evening dark.\nSomeone had produced candles, the thick short ones used during power cuts, and they sat in a loose circle with the candles on the ground between them, which gave the gathering the quality of something that had decided, without planning to, to be serious about itself.\nPeople talked. About the examinations, about after, about the particular grammar of what it meant to leave a place that had been the whole world for five years and walk into a larger one that had no idea you existed yet.\nEmeka listened more than he talked.\nRotimi was there. They had not spoken directly since the sports review, the three days of corridor adjustment still present between them, but Rotimi sat two people down from him and when their eyes met, briefly, across the candlelight, Rotimi gave him the nod of someone who had processed something and arrived, not at full agreement, but at the recognition that it was over.\nEmeka returned the nod.\nBiodun, who saw everything, saw this and said nothing, which was the correct response.\nNaza found him at the edge of the group, an hour later, when the gathering had thinned to twelve people and the candles had burned to shorter versions of themselves.\nShe was in her own-clothes, a blue ankara blouse and dark jeans, her hair out of the usual plaits, and she looked at him with the expression she had arrived at somewhere in the third term, the one that had no procedure in it, that was simply her looking at him the way you look at something you have decided to see clearly.\n"You did not come to say goodbye to me," she said.\n"I did not know it was goodbye," he said.\nShe sat beside him on the low wall at the edge of the neem tree''s shadow. Not close enough to be a statement. Close enough to be honest.\n"I am coming back next year," she said. "SS1. I have one more year."\n"I know."\n"And you are going."\n"Yes."\nShe looked at the remaining gathering, the candles and the SS3 boys and girls doing the particular work of ending. "What happens to the council when you leave?"\n"It continues," he said. "That is the point of building a structure."\n"I know the point," she said. "I am asking what happens to this part of it. The prefect liaison. The joint meetings. The notices we co-signed." She paused. "It requires someone who will do it the way we did it. And that is not a small requirement."\nHe looked at her. "You will train them."\n"I will try."\n"You will succeed," he said. "Because you understand what it is supposed to be, which means you can teach it even to people who start from the wrong place."\nShe was quiet for a moment. "Like you started from the wrong place."\n"Like I started from the wrong place."\nA candle guttered in the small evening breeze and steadied itself.\n"Onitsha," she said. "University there?"\n"Abuja, probably. Law."\nShe nodded. "I thought law."\n"Why?"\nShe looked at him with the slight lift at the corner of her mouth that was the closest she came to a smile in serious conversations. "Because you have always needed the argument to be correct before you could rest inside it." She paused. "Law will give you the correct arguments. You will be very precise about them."\nHe was quiet for a moment. "You will study what?"\n"Medicine," she said. "Enugu, if the admission comes." She looked at her hands. "My mother''s city. She would like that."\nHe looked at her profile in the candlelight, the careful features and the chin that had come up in a corridor in September of last year before she gave him her full name and had never fully come down since.\nHe thought about everything that had happened between that corridor and this wall. The fifty lines and the election number and the food crisis and the Adeyinka staffroom and the rain and the umbrella and the common room fracture and the sports review and the document in Mrs. Okafor''s office and the administrative step on a Saturday morning when he had said her full name and meant it differently from the first time.\nHe thought about what she had said on the wall outside the sports store. I carry both of them. I do not always know how to do that cleanly.\nHe thought about what he had said to Biodun in the common room. Correct meant the same as certain. Past tense. He had used the past tense without planning to.\n"I would not have found this without you," he said. "Whatever this is. Who I am at the end of this year."\nShe looked at him directly.\n"You would have," she said. "Eventually. It was already in you." She held his gaze. "I just made it happen faster by making it necessary."\nHe considered this. "Is that what you did."\n"That is what we did to each other," she said. "You made it necessary for me too. Not the same way. But necessary."\nThe last of the candles had burned low. The gathering around them had reduced to six people talking in the quiet way of people who are in no hurry to let a night end. Above the Kogi hills the sky was doing its deep, unhurried thing, the stars specific and unambiguous in the dry season dark.\nHe was leaving tomorrow. His uncle''s car would arrive at eight. The box in the prefects'' room was half-packed and he had a badge on the locker that had meant everything and then less and then something different again.\n"When you come back next year," he said.\n"Yes."\n"The document. If the new prefect does not read it properly, there is a section on page three about joint decision-making that will tell you everything you need to know about whether they are approaching it the right way."\nShe looked at him. "Page three."\n"The third principle. Authority that cannot account for itself is not authority. It is habit. That one took us four drafts."\n"I wrote that one," she said.\n"I know. I pushed back on it twice."\n"You were wrong both times."\n"I was wrong both times," he said.\nThe slight lift returned to her mouth. Stayed this time.\nHe looked at it and looked away.\n"Chinazaekpere," he said.\nShe let the name land the way she always did when he said it now, with the particular stillness of someone receiving something that was theirs.\n"Go and finish packing," she said. "Your uncle comes at eight."\n"I know."\nHe stood.\nShe stayed on the wall, in the blue ankara and the candlelight, looking at the dark hills.\nHe walked back toward Ahmadu block.\nHe did not look back. Not because he was being studied in it, not because he was performing the exit. He did not look back because he understood that looking back was not the right direction anymore.\nAhead was Onitsha and the bridge and his mother''s food and a university application with the word law on it and a version of himself that had been built in this school and was about to find out if it held in a larger world.\nBehind him, on a wall under a neem tree, was a girl with two names who had made him necessary to himself by refusing to be less than herself.\nHe would carry that.\nNot as a romantic conclusion.\nAs a fact.\nAs the truest account of what a school year could do when two people stopped managing each other and started, without meaning to, becoming.\n\n\n\nTHE PREFECT — END','\n',char(10)),1927,1,1,NULL,'2026-04-26 17:04:09','2026-04-10 15:17:52','2026-04-26 17:04:09','2026-04-26T17:15:00.000Z',3,27);
INSERT INTO "chapters" ("id","novel_id","chapter_number","title","content","word_count","is_premium","is_published","audio_url","published_at","created_at","updated_at","scheduled_release_at","part_number","season_id") VALUES(330,44,1,'SeStrangers in a Zinc Room',replace('The chair Ngozi chose was the one closest to the exit, which was not a door but a curtain, which meant that if things went badly she could leave without making noise. She had learned to always find the exit first.\nNobody else was there yet. It was three fifty-two.\nShe looked at the room. Six plastic chairs in a semicircle. A blackboard with old chalk dust ground into its surface the way age grinds into a face. A wooden table at the front with a stack of papers and a tin cup holding three markers and one cane. The cane was thin and was leaning against the table like it had nothing to prove. A single bulb hung from the ceiling. The generator outside was already running.\nShe thought: thirty sessions in this room. Then she thought about her mother''s shop on Bridge Head and how the rent was two months behind and she did not think anything else.\nThe boy who came in at three fifty-five was the problem from the start. Not because he did anything wrong. Because of his shoes. White sneakers, the kind with the thick sole that Nike only made in that colourway last December, and they were clean. Genuinely clean. In Onitsha. In July. He sat down two seats from Ngozi, put his phone on his knee, and looked at the screen without looking at the room. The phone was a Samsung Ultra. She knew the price. Her cousin had priced one at Slot in Enugu and walked out quietly.\nThe next one was a boy who came in loud and lightweight, like he had decided before arriving that he was going to enjoy himself. He said, "So this is where suffering happens," dropped his bag on the floor, and took the chair closest to the board. Nobody responded, which did not seem to bother him at all.\nA girl in a Holy Rosary uniform after him. Oxford notebook held against her chest with both arms, like someone might try to take it. She sat down, opened it, and began writing before she had even properly settled into the chair.\nThen a girl who sat at the far end of the semicircle and folded her hands in her lap with the practiced stillness of someone performing calm. Her school uniform had a Lagos cut to it, the collar a slightly different shape from every other uniform in the room. Small difference. The kind only someone who had been the different one would notice.\nThe last was a boy who arrived exactly at four, sat in the remaining chair, placed his textbook on his knee, and became the quietest person in the room so completely that Ngozi almost forgot he had just walked in.\nTeacher Obiora did not wait.\nHe was already at the board, chalk moving. He wrote without greeting them, without turning around, without acknowledging that six teenagers had just arranged themselves in a semicircle behind him and were waiting. By the time he put the chalk down, there were four equations, two grammar rules, and a Bible verse on the board. Proverbs 4:7. Wisdom is the principal thing; therefore get wisdom.\nHe faced them.\nHe was not tall but the room did not seem to know that. He had a short-sleeved shirt the colour of weak tea, a red biro behind his ear, and the expression of a man who had watched too many students waste their own potential and had run out of grief about it.\n"My name is Mr. Obiora. You will call me Teacher Obiora. Not sir. Not uncle. Teacher Obiora." He waited. "Again."\n"Teacher Obiora," most of them said. Not quite together.\nHe accepted this. "You are here because WAEC is coming and what your schools have given you is not enough." He picked up the chalk and underlined the verse. "I am not here to motivate you. Motivation is your own business. I am here to make sure that when you sit in that examination hall, there is no question that catches you without an answer."\nHe passed a stack of papers to the girl nearest him, which was the girl from Holy Rosary, who passed them along without looking up from her notebook.\nTimetable. Thirty sessions. English, Mathematics, Chemistry, Biology, Economics, Literature laid out in a grid that pressed down on Ngozi the moment she read it.\n"Four o''clock to six o''clock," Teacher Obiora said. "Monday to Friday. You will not come late. You will not leave early. If you choose not to come, I do not follow you. I simply continue without you."\nHe picked up the cane from where it leaned against the table, looked at it briefly, then put it back. It felt like a decision.\n"Questions?"\nThe loud boy raised his hand. "Teacher Obiora, can we bring food?"\nSomething in the room relaxed without anyone saying anything. Even Teacher Obiora''s face shifted one millimeter.\n"You can bring food," he said. "You cannot make noise while eating it."\nHe turned back to the board.\nOutside, the generator coughed and steadied. Awka Road pushed its evening sounds through the zinc walls. The six of them looked at their timetables or at the board or at the curtain and said nothing, and in that silence they were still strangers, still separate, still fully themselves.\nThen the sneakers boy''s phone buzzed against his knee.\nHe looked at it. One second, two. His jaw shifted like something had moved inside it. He turned the screen face down and looked at the board with an expression that had not been there before, something pressed down and careful, and Ngozi who had been watching without meaning to looked away before he could catch her.\nTeacher Obiora began the first session.\nNobody was ready for what the next thirty would cost them.','\n',char(10)),973,0,1,NULL,'2026-04-10T15:28:01.290Z','2026-04-10 15:28:01','2026-04-10 15:28:01',NULL,1,NULL);
INSERT INTO "chapters" ("id","novel_id","chapter_number","title","content","word_count","is_premium","is_published","audio_url","published_at","created_at","updated_at","scheduled_release_at","part_number","season_id") VALUES(331,44,2,' The Phone Goes Around',replace('Teacher Obiora left the room at four forty-three to take a phone call, and the six of them watched him go through the curtain and then looked at each other for the first time.\nNot the polite, sideways looking they had been doing since Monday. Real looking. The kind that happens when the adult in the room removes himself and everyone suddenly has to decide who they are without him.\nChidi decided first. He always decided first.\n"Okay, but that timetable is a punishment from God," he said. "Who is doing Economics and Chemistry in the same week? Who planned this?"\n"Teacher Obiora planned it," Precious said, from the far end of the semicircle.\n"I know Teacher Obiora planned it. That is what I''m saying. That man sat down and looked at this timetable and felt nothing." Chidi shook his head slowly. "No emotion. Nothing. Just suffering, neatly arranged."\nNgozi laughed before she could stop herself. Tobe looked up from his textbook briefly, then looked back down. Ada kept writing.\nEmeka, who had said almost nothing across two sessions, looked up from his phone. "Does anybody actually understand the Economics syllabus?"\nIt was such a plain question, with no performance in it, that it landed differently than anything Chidi had said. Precious turned toward him slightly. Ngozi looked over.\n"Which part?" Ngozi asked.\n"National income. The calculations." He turned the phone so she could see the screen. He had a past question paper pulled up, photographed and loaded into his gallery. "I''ve done this one three times and I keep getting a different answer."\n"Pass it," Ngozi said.\nHe hesitated. One second, not long, just enough to notice. Then he leaned across the empty chair between them and held the phone out to her.\nShe took it.\nThe phone was heavier than it looked, and the screen was very bright, and her own reflection looked back at her from the dark edge of it for a moment before she focused on the question. She worked through it in her head. Gross national product. Transfer payments. The calculation was not the problem. The setup was.\n"You''re including transfer payments in the national income," she said. "You shouldn''t. They''re not factor incomes."\nHe looked at her. "You''re sure?"\n"I''ve done this exact question." She did not say when. She did not say why she had done past questions from four years back. "The answer is the second option."\nShe passed the phone back. He checked it against something, and something on his face settled.\n"She''s right," he said, to the room more than to her.\n"Of course she''s right," Chidi said. "She said it like she was sure. People who are sure are usually right." He paused. "Or very dangerously wrong. But in this case, right."\nPrecious almost smiled. She turned back to her own notes, but the angle of her shoulders had changed.\nTobe passed the phone to Chidi without being asked, because Chidi had been holding his hand out for two minutes. Chidi took it with the energy of someone who had been waiting for exactly this, opened the gallery without asking, and began scrolling past questions like he owned it.\n"Chidi," Emeka said.\n"I''m not touching anything. I''m just looking." He held the phone up. "Is this all past questions or do you have other things on here?"\n"Past questions."\n"Nothing else?"\n"Past questions," Emeka said again, in a way that closed the conversation.\nChidi passed it to Ada.\nShe accepted it without looking up from her notebook, which meant she had been paying attention the whole time despite giving every appearance of not being present. She held the phone in one hand and her pen in the other and looked at the Literature questions with the focused stillness of someone reading something she already knew.\n"These ones are easy," she said quietly.\n"Easy," Chidi repeated.\n"The comprehension ones. The prescribed texts are the harder part. It depends which texts your school is doing."\n"Which texts are you doing?" Precious asked. It was the most she had said directly to Ada across two days.\n"Chike and the River. An Inspector Calls. Things Fall Apart." Ada looked up briefly. "You?"\n"Same. Minus Chike." She held out her hand.\nAda passed the phone across the semicircle.\nPrecious scrolled to the Literature questions and read them with her chin slightly raised, the way someone reads something they are making themselves not be intimidated by. Ngozi watched her and thought about the way she had walked in on Monday, that practiced quietness, and wondered what it cost.\n"Pass it to Tobe," Chidi said.\nPrecious passed it to Tobe, who was at the end.\nTobe held it the way you hold something borrowed. Carefully. He looked at the screen and then, instead of scrolling, he said, "Which subject do you each actually need the most help with?"\nNobody had asked that. Two sessions in and nobody had thought to ask it.\nThe room was quiet enough that they could hear the generator cycling outside and someone selling pure water on the road.\n"Maths," Ngozi said.\n"Chemistry," said Chidi, with the weight of someone admitting something larger.\n"Economics," Emeka said, already knowing they had established this.\nPrecious said, "All of it," and did not look embarrassed about it.\n"Literature," Ada said. Which was surprising, because she had just called the questions easy.\nTobe nodded. He passed the phone back to Emeka without saying what his own answer was.\nTeacher Obiora''s voice came from just outside the curtain. They all straightened without deciding to.\nHe came back in, looked at the board, looked at them, picked up the chalk.\n"Economics," he said. "Open your notebooks."\nAda reached for hers on the floor beside her chair, and in the reaching her grip slipped. The notebook hit the ground and fell open, pages fanning against the concrete.\nEmeka was closest. He reached down before she could and picked it up.\nOne page faced him. Not a single equation. Not a date or a definition or a diagram. Handwriting, small and dense and tilted slightly to the left, in the way of someone writing fast because they are afraid of losing the thought. A story, or the middle of one.\nAda''s hand was already out.\nHe placed the notebook in it without expression. But his eyes moved to her face for just a moment, a question forming in them that he did not ask.\nShe closed the notebook and held it against her chest.','\n',char(10)),1085,0,1,NULL,'2026-04-10T15:28:55.417Z','2026-04-10 15:28:55','2026-04-10 15:28:55',NULL,1,NULL);
INSERT INTO "chapters" ("id","novel_id","chapter_number","title","content","word_count","is_premium","is_published","audio_url","published_at","created_at","updated_at","scheduled_release_at","part_number","season_id") VALUES(332,44,3,' What Chidi Started',replace('It began, as most things with Chidi began, as a joke.\nWednesday. Third session. Teacher Obiora had written a comprehension passage on the board about a fisherman from the Niger Delta and asked them to identify three literary devices in the second paragraph. They had their heads down. The room had that particular silence of people working, the scratch of pens, the occasional sound of someone turning a page.\nPrecious was reading the passage aloud under her breath, the way she did when she was concentrating, her lips moving slightly. Her accent came out when she did that. The Lagos curve she usually kept flattened surfaced in the way she rounded certain vowels, the way her o sounds sat higher in her mouth than everyone else''s.\nChidi heard it.\nHe did not think before he spoke. This was not new.\n"Precious," he said, in a Lagos accent that was not cruel but was not careful either, "wetin you dey find inside that paragraph?"\nNgozi looked up.\nAda''s pen stopped.\nPrecious finished the sentence she was reading before she responded. She set her pen down, turned to look at Chidi, and her voice when it came was very level. "Say that again."\n"I was just playing," Chidi said, already reading the room, already understanding he had miscalculated. "It was a joke."\n"I know it was a joke." She picked her pen back up. "I''m asking you to say it again."\nHe didn''t.\nTeacher Obiora was at the board and had either not heard or had chosen not to involve himself. The generator filled the silence outside.\n"My mother is from Nnewi," Precious said, to her notebook rather than to Chidi. "My father is from Ibadan. I grew up in Lagos. I moved here two years ago. So yes, I sound like this. This is what I sound like." She underlined something. "Next time you want to make that joke, just keep it."\n"I said I was playing," Chidi said, and there was something defensive in it now.\n"I heard you the first time."\nThe temperature in the room had changed. Emeka had gone very still with his phone face down on his knee. Tobe was looking at the board. Ngozi was looking at Precious.\n"Chidi," Ngozi said.\n"What?"\nShe just looked at him.\nHe sucked in a breath and let it out. "Precious, I''m sorry. That was stupid."\nPrecious did not respond immediately. She finished writing a sentence, then she said, "Okay," in the particular way that meant she had accepted the apology but had also filed the information somewhere.\nTeacher Obiora turned from the board. "Three devices. Who has them?"\nAda''s hand went up. It always went up first, which Ngozi had noticed was something Ada herself did not seem aware of.\n"Simile," Ada said. "In the line about the river moving like a tired old man. Personification in the third sentence, where the waves are described as arguing. And repetition. The word nothing appears four times."\nTeacher Obiora looked at her for a moment. "Correct." He turned back to the board. "The rest of you should be disturbed that she finished before you."\nThe session moved forward.\nBut at five fifteen when Teacher Obiora called a ten minute break and stepped out again, the room split.\nNot physically. They were all still in the same six chairs. But Ngozi turned toward Precious and said, quietly, "He does that. He doesn''t always know when the line is."\nPrecious looked at her. "Does he do it to everyone?"\nNgozi paused. "He did an impression of Tobe''s voice last week."\nBoth of them looked at Tobe, who was reading and had not offered anything to the conversation.\n"What did Tobe do?" Precious asked.\n"Nothing," Ngozi said. "Tobe does nothing."\nOn the other side of the room, Emeka had shifted his chair slightly closer to Chidi''s, not enough to be obvious, just enough to be beside him. He was not defending him. He was just present in the particular way that male friendship sometimes communicates: I''m not agreeing with what you did, but I''m still here.\nChidi, for his part, was not performing unbothered. He was sitting with his elbows on his knees, looking at the floor between his shoes. He was doing what he did when he had said something he actually regretted, which was different from the times he apologized because the room required it. This time the regret was on his face without his permission.\nAda was writing. Ngozi had given up trying to figure out whether Ada was ever not writing.\n"She''s good," Emeka said to Chidi, quietly, meaning Precious and the way she had handled it.\n"I know," Chidi said. "That''s what makes it worse."\nEmeka almost smiled.\nThe ten minutes passed. Ngozi looked at the curtain.\nPrecious had gone out five minutes into the break, the way she sometimes did, stepping onto Awka Road for air. It was something she did and always came back from within two or three minutes, just enough time to stand outside the noise of the generator and breathe.\nThe ten minutes ended.\nTeacher Obiora came back in, picked up the chalk, and looked at the semicircle.\nFive chairs.\nHe looked at the curtain. He looked back at the five of them. He said nothing, which was its own kind of comment, and turned to the board.\nFive minutes passed.\nNgozi counted them. She was not the only one. She could tell by the way Emeka''s eyes moved to the curtain every forty seconds and the way Tobe had stopped turning pages.\nTen minutes.\nPrecious''s bag was still there. Her notebook was still open on her chair, pen resting in the spine of it. Whatever she had gone outside to do, she had not planned to stay.\nThe curtain did not move.\nChidi stared at the floor between his shoes and said nothing at all.','\n',char(10)),983,0,1,NULL,'2026-04-10T15:29:57.068Z','2026-04-10 15:29:57','2026-04-10 15:29:57',NULL,1,NULL);
INSERT INTO "chapters" ("id","novel_id","chapter_number","title","content","word_count","is_premium","is_published","audio_url","published_at","created_at","updated_at","scheduled_release_at","part_number","season_id") VALUES(333,44,4,'Thursday',replace('Precious''s chair was the first thing Ngozi saw when she walked in.\nEmpty. Bag gone. No notebook left open in the seat the way it had been on Wednesday, when Precious had finally come back through the curtain eleven minutes late and sat down without explanation and Teacher Obiora had looked at her once and continued writing. Today there was nothing. Just a plastic chair in a semicircle, angled slightly toward the board from the last person who had sat in it.\nNgozi put her bag down and looked at the chair for a moment, then looked at the board.\nThe others arrived in their usual order. Chidi, then Emeka, then Tobe, then Ada, and at each arrival Ngozi watched their eyes go to the empty chair and then away, the way you look at something and then pretend you weren''t looking.\nTeacher Obiora came in at exactly four and registered the chair the same way he registered everything, with his eyes and nothing else. He picked up the chalk. He did not call Precious''s name.\n"English Language. Lexis and structure." He turned to the board. "These are the marks most of you are throwing away because you think reading is enough. It is not enough."\nThe session began.\nIt was harder to concentrate with five of them. Ngozi could not explain the logic of this, because Precious was quiet on most days and wrote in her notebook and kept herself to herself. But her absence was loud in a way her presence never was. The semicircle felt lopsided. The room felt like a sentence with a word missing.\nAt four thirty-eight, Chidi leaned toward Emeka and said, barely above a whisper, "You think she''s still vexing?"\nEmeka cut his eyes at him.\n"I''m serious. After Wednesday, maybe she just."\n"She''s not vexing," Emeka said.\n"How do you know?"\n"Because she left her bag on Wednesday and came back. If she was done she would have taken the bag."\nThis was more than Emeka usually said at one stretch and it quieted Chidi for a while. Ngozi, who had heard all of it, kept her eyes on the board and thought that Emeka was right. Precious wasn''t the type to make her exit without her bag. Whatever Wednesday was, it was not the reason she wasn''t here today.\nTeacher Obiora asked a question about synonyms. Tobe answered it. Teacher Obiora moved on.\nBy five o''clock, Chidi had a theory. Ngozi could tell because he had been quiet for twenty minutes, which was only ever because he was thinking, and when he finally spoke again he said, "She has extra lesson somewhere else. She signed up for two places and today she''s at the other one."\nNobody confirmed or rejected this.\n"Or," he continued, keeping his voice below Teacher Obiora''s register, "she had something at her school. Function or something. FGC people always have functions."\n"Chidi," Ngozi said.\n"I''m just saying."\n"You''re guessing."\n"We''re all guessing. We literally know nothing about her. What do we actually know?" He looked around the semicircle. "She''s from Lagos. Her Igbo sounds different. She reads her passages aloud when she thinks nobody''s listening. That''s all I have."\nHe was right, which was the uncomfortable part. Four sessions in and what they had was the surface of each other, the things people could not help showing. The shape of how they sat. The frequency with which they looked up from their work. The things they reached for when they were nervous.\nEmeka was looking at the chair again.\nTobe had not said anything on the subject, which was usual. But Ngozi had noticed that every time someone offered a theory about Precious, Tobe''s pen stopped moving for just a moment, the way it moved when he was listening carefully to something and processing it somewhere deeper than the surface.\n"She''ll come back," Ngozi said. To the room, not to anyone specific.\nBreak came at five fifteen.\nTeacher Obiora went out. The room settled into itself.\nAda was writing. She had been writing with unusual speed for the last twenty minutes, the pen moving in a way that was different from note-taking, no pauses to look at the board, no pulling from anything external. Just the pen and whatever was in her head finding its way out.\nTobe was reading his textbook, or holding it in front of him, which was not always the same thing.\nNgozi watched Ada write and thought about the notebook page that Emeka had seen on Tuesday. The handwriting tilted to the left, small and fast and urgent. She had not mentioned it since and neither had Emeka, but it sat in the room with them the way things do when they have been seen but not discussed.\nAda stopped writing. She looked at what she had written. She read it back slowly, her lips not moving this time, just her eyes tracking left to right down the page.\nThen she did something Ngozi had not seen her do before.\nShe took the page between her fingers and tore it out. Clean and careful, close to the spine. She folded it once, not in half, in thirds, the way you fold something you mean to pass to someone. She looked at it in her hand.\nShe looked at Tobe.\nTobe was looking back at her, which meant he had been watching too.\nAda slid the folded page across the space between them. It crossed two chairs and stopped at Tobe''s knee.\nHe looked down at it. He looked at Ada.\nShe had already turned back to her notebook, pen moving again, as if she had not just done something.\nTobe picked up the paper. He held it without opening it.\nOutside on Awka Road, a bus horn sounded twice and faded. The generator kept its rhythm.\nHe opened the page.','\n',char(10)),978,1,1,NULL,'2026-04-10T15:31:09.225Z','2026-04-10 15:31:09','2026-04-10 15:31:09',NULL,1,NULL);
INSERT INTO "chapters" ("id","novel_id","chapter_number","title","content","word_count","is_premium","is_published","audio_url","published_at","created_at","updated_at","scheduled_release_at","part_number","season_id") VALUES(334,44,5,'What the Generator Knows',replace('The light went at four fifty-one.\nNot gradually. One moment the bulb above them was doing its usual buzzing work, and the next it was gone, and the generator outside made a sound like a man who had been holding his breath too long and then went silent too. The room dropped into the kind of dark that a Onitsha evening produces when both NEPA and your generator fail at once. Not total, the curtain let in the last grey light from the street, but close enough.\nNobody moved.\nTeacher Obiora said, from somewhere near the board, "Don''t panic."\nNobody had been panicking. But the instruction helped.\n"I have fuel," he said. "The container is in the back. Give me ten minutes."\nHe moved through the dark with the comfort of a man who knew every corner of his own room. The curtain swayed and he was gone.\nThe six of them sat in the half-dark and listened to Awka Road, which did not stop for NEPA. Okadas. A woman selling something. Two men arguing about something they would still be arguing about by the time the street slept. Life at its regular volume while the lesson room held its breath.\n"Ten minutes," Chidi said.\n"He said ten minutes," Ngozi agreed.\n"I know. I''m just saying it."\nPrecious had come back that Thursday evening, no explanation given and none asked for, and had taken her seat and opened her notebook as if the empty chair had never happened. It was now Monday, a new week, and the room had quietly accepted her return the way it accepted most things: by moving forward and filing it away.\nThe dark, though, was doing something to the room. Ngozi could feel it. Without the light and the board and Teacher Obiora''s presence anchoring them to the work, they were just six people in a small space, and the usual rules of the room, the bent heads, the careful distances, the performance of being fine, felt harder to maintain.\n"Can I use your phone for light?" Precious asked. The question was directed at Emeka.\n"Battery is at nine percent," he said.\n"Nine percent and you didn''t bring a cable?"\n"The cable is in my bag. The bag is at home."\n"Why is your bag at home?"\nA pause. "I forgot it."\nSomething in the way he said it landed in the room without anyone commenting on it. Emeka did not forget things. He was the most physically prepared person among them, phone charged, pen always working, sneakers clean as if the dust of Awka Road did not apply to him. Forgetting his bag was not nothing.\nTobe took out his phone, an older Tecno with a cracked screen, and turned on the torch. He set it face up on his knee so it threw light at the ceiling and distributed it evenly around the room. It was a practical, generous thing to do and he did it without making anything of it.\n"Thank you," Ada said.\nTobe nodded.\nIn the upward light, their faces looked different. Softer and stranger at the same time. The shadows went the wrong way and it made them look like a different set of people, or maybe more like themselves, the version that the fluorescent bulb and the formality of the session usually covered.\n"What did the paper say," Chidi said to Tobe. Not a question. More like something he had been holding since Thursday.\n"Chidi," Ngozi said.\n"I just want to know."\n"It wasn''t for you," Ada said from across the semicircle. Her voice was flat, not angry, just factual.\n"I know it wasn''t for me. That''s why I''m asking Tobe."\nTobe looked at Chidi. "She gave me a piece of a story she was writing," he said. "That''s all."\nChidi looked at Ada. Ada looked at the torchlight.\n"Was it good?" he asked.\nAda turned to look at him then, a direct look, assessing.\n"It was good," Tobe said.\nSomething shifted in Ada''s posture, barely, the way a door shifts in a breeze, not opening, just acknowledging the air.\nThe minutes moved. Outside, Teacher Obiora could be heard doing something that involved metal and mild frustration. The generator did not start.\n"My mother had a lesson teacher," Precious said, into the dark. "In Nnewi. She always talked about him. How he was the one who made her believe she would pass."\nNobody asked her to continue but nobody didn''t, and in the middle of that she continued.\n"She keeps saying Onitsha has the best lesson teachers in the South East. That''s one of the reasons we stayed." She paused. "One of the reasons."\nThe other reasons sat unasked in the room.\nNgozi was thinking about her own mother. The provision store. The way her mother had not said anything when Ngozi registered for WAEC again, just handed her the registration form and the money and touched her shoulder once in the particular way that meant: I know. We don''t have to say it.\n"My father used to say that school is the only thing nobody can take from you," Ngozi said. "Once you have it, it''s yours."\n"Your father sounds like a serious man," Chidi said.\n"He was." The word was out before she decided to say it. Past tense. Sitting in the room now with all its weight and its wrong shape, because she had never said that to anyone here, had never intended to, had spent four sessions in this room being the warm one, the one who laughed first, the one who had suya to share and enough energy to fill the space, and now the past tense was just sitting there and everyone had heard it.\nThe generator caught, turned over twice, and roared back to life.\nThe bulb above them buzzed on.\nThe light returned everything to where it had been. Board. Chairs. The distance between them.\nNgozi looked at the board.\nNobody looked at her, which was either kindness or its own kind of silence. She could not decide which was worse.','\n',char(10)),1011,1,1,NULL,'2026-04-10T15:32:15.815Z','2026-04-10 15:32:15','2026-04-10 15:32:15',NULL,1,NULL);
INSERT INTO "chapters" ("id","novel_id","chapter_number","title","content","word_count","is_premium","is_published","audio_url","published_at","created_at","updated_at","scheduled_release_at","part_number","season_id") VALUES(335,44,6,' The Suya Evening',replace('Ngozi brought it in a black nylon bag that had been sweating since Ochanja Market, and the moment she set it on Teacher Obiora''s table, before she had even opened it, before anyone could see what was inside, Chidi sat up straight.\n"Is that suya," he said.\n"It might be suya."\n"Ngozi." He put his pen down. "Is that suya."\nShe opened the bag.\nIt was suya. Six sticks wrapped in old newspaper, the paper already translucent with groundnut oil, and a small sachet of sliced onions and tomatoes folded into the corner of the bag. She had bought it on the way from Bridge Head, from the mallam whose fire she could see from the bus window, whose suya had a pepper balance she had never found anywhere else in Onitsha.\nTeacher Obiora looked at the bag. He looked at Ngozi. He looked at the class, which had collectively stopped pretending to read.\n"You have fifteen minutes," he said, and went outside with his phone.\nFor a moment after he left, nobody moved.\nThen Chidi was out of his chair.\nNgozi unwrapped the newspaper on the table and they gathered around it in a way that had nothing planned about it, Chidi first, then Emeka, then Precious who had stood up slowly as if she wasn''t sure she was invited, then Ada who brought her notebook with her by habit and then looked at it in her hand and set it on her chair instead. Tobe was the last to stand. He came to the edge of the group and Ngozi passed him a stick before he could decide whether to reach for one.\nThey stood around Teacher Obiora''s table and ate suya in the particular silence of people eating something good.\n"This is the best thing that has happened in this room," Chidi said.\n"We''ve only had five sessions," Precious said.\n"I know. This is still the best thing."\nPrecious took a piece of onion from the sachet. "Where did you get it?"\n"Ochanja. The mallam near the second junction."\n"My mother buys from there," Precious said. Something in her voice when she said my mother was different from her usual register. Softer. Less managed.\n"Your mum likes suya?" Ngozi asked.\n"She likes everything with pepper." Precious looked at her stick. "She says pepper is the only honest ingredient. It never pretends to be mild."\nChidi laughed, a real one. "I want to meet your mother."\nPrecious smiled. It was the fullest smile any of them had seen from her and it changed her face the way sunlight changes a room, suddenly and completely.\nEmeka was eating with the careful enjoyment of someone who had been taught not to eat with his hands in company and was actively ignoring that teaching. He had groundnut oil on two fingers and was not doing anything about it. This was the most relaxed Ngozi had ever seen him. The sneakers were still clean but something else about him had come undone slightly, the collar of his shirt, the set of his shoulders.\nAda had eaten half her stick and was looking out through the curtain at the early evening on Awka Road. The light at six o''clock in Onitsha was the particular gold that came before dusk, the kind that made everything look like a memory while it was still happening.\n"Why did you do it?" Emeka asked Ngozi. "The suya."\nNgozi considered performing a light answer. She had several ready. She chose not to use any of them.\n"Last Monday," she said, "when the light went. I said something I hadn''t planned to say." She did not look at anyone specifically. "I didn''t sleep well that night. I kept thinking about how I just dropped it in the room and then the generator came back and we all just moved on." She pulled a piece of meat from her stick. "I don''t know. I just wanted to do something that felt good. For the room."\nNobody said anything for a moment.\n"It does feel good," Tobe said.\nIt was such a simple thing to say, and he said it so plainly, that it landed in the room like a hand on a shoulder.\nThey finished the suya. Ngozi folded the newspaper and put it back in the bag. The oil had soaked through completely now. She would throw it away on Awka Road on her way home.\nThey were still standing around the table when Teacher Obiora came back in. He looked at the six of them standing there together, which was different from six people sitting in a semicircle, and he looked at the table and then he picked up the chalk without comment.\nThey went back to their chairs.\nSomething had changed and all of them knew it, not dramatically, not in a way anyone would have been able to point to or explain to someone outside the room. But the distance between the chairs felt different. The semicircle felt like a choice now, rather than an arrangement.\nTeacher Obiora was writing a Mathematics problem on the board when Chidi said, quietly, to nobody in particular, "This is my third year doing WAEC prep."\nHe said it the way you say something you have been carrying alone for so long that you stop caring who hears it.\nAda''s pen slowed.\nEmeka looked at him.\nChidi was looking at the board, jaw set, waiting for whatever came next. Not performing bravery. Just done. Done with holding it in a room that had just, without ceremony, become something else.\nThe generator hummed. The chalk moved. Outside, Onitsha was doing what it always did, loud and alive and indifferent.\nNobody laughed.','\n',char(10)),950,1,1,NULL,'2026-04-10T15:33:13.655Z','2026-04-10 15:33:13','2026-04-10 15:33:13',NULL,1,NULL);
INSERT INTO "chapters" ("id","novel_id","chapter_number","title","content","word_count","is_premium","is_published","audio_url","published_at","created_at","updated_at","scheduled_release_at","part_number","season_id") VALUES(336,44,7,'After the Suya',replace('Tuesday came the way Tuesdays do after something has shifted, ordinary on the surface, asking you to pretend that whatever happened last week was not the size it actually was.\nNgozi arrived first, as usual. She set her bag down, looked at the semicircle, and noticed immediately that the chairs were slightly closer together than Teacher Obiora normally arranged them. Not dramatically. Three, maybe four inches. Enough that someone would have had to move them. She did not know when it had happened or who had done it, whether it was Teacher Obiora or the cleaning person or one of them yesterday, but she sat down and did not move her chair back.\nChidi came in, dropped his bag, and sat. He had the face of someone who had spent the weekend deciding whether to regret what he had said on Friday and had landed somewhere between no and not quite. He pulled out his textbook. He did not make a joke.\nPrecious arrived carrying a container, a small flask with a rubber-sealed lid, and she set it on Teacher Obiora''s table without explanation and sat down. Ngozi looked at the flask.\n"Zobo," Precious said, without being asked. "My mother made too much."\nNgozi felt something warm move through her chest.\nAda came in and sat and opened her notebook. Today she had two pens, one blue and one red, and she arranged them in parallel on the desk beside the notebook in a way that suggested ritual.\nTobe arrived at three fifty-eight and took his seat and there was something slightly different about the way he looked at the room when he walked in, something that had not been there in the first week. Not comfort exactly. Recognition.\nFour o''clock came.\nEmeka did not.\nTeacher Obiora began the session anyway. He was not the type to hold a class for an absent person, and they all knew it, but every two or three minutes Ngozi''s eyes moved to the curtain. Chidi''s did too. Precious was pouring zobo into the flask''s cap for whoever wanted it, passing it around like a small ceremony, and she paused each time she passed it to look at the empty chair.\nThe curtain moved at four twenty-two.\nEmeka came in.\nHe did not announce himself. He moved to his chair the way someone moves when they are trying to take up as little space as possible, which was so opposite to the way Emeka usually occupied a room that it pulled Ngozi''s attention completely. His sneakers were not clean today. There was a scuff along the left toe, pale against the white leather. She noticed the scuff first because it was the easier thing to notice.\nThe bruise was above his right cheekbone. Not large. Not dramatic. The deep kind, the kind that sits under the skin in a colour between purple and yellow that means it was not fresh and was not yet old. He had not tried to cover it.\nHe sat down, put his phone on his knee, opened his textbook.\nTeacher Obiora looked at him. One second, two. He turned back to the board.\n"As I was saying. Quadratic equations. The method most of you are using is taking three times longer than it needs to."\nThe session continued.\nNgozi looked at her notebook. She wrote the date at the top of a new page. She did not look at the bruise again, because looking again would make it a thing, and she could feel without checking that nobody else was looking either. Not Chidi, who she would have expected to say something, who was characteristically and deliberately reading his textbook with total focus. Not Precious, who had quietly passed the flask cap of zobo to Emeka''s side of the semicircle and left it on the empty chair between them without saying anything. Not Ada, who was writing with her blue pen and had not switched to the red one yet.\nNot Tobe, who was looking at the board, but whose pen had not moved since Emeka sat down.\nThe zobo sat on the empty chair.\nEmeka looked at it. He looked at Precious, who was not looking at him. He picked up the cap and drank from it and set it back on the chair.\nAt five fifteen Teacher Obiora called the break.\nHe went out. The room exhaled.\nChidi lasted forty-five seconds. "Okay so what happened to Obiora''s favourite quadratic method because I completely lost him after the second step." He was looking at the board, not at Emeka. His voice was the exact temperature of normal.\n"You substitute into the formula before you simplify," Tobe said.\n"Show me."\nTobe leaned over and showed him in his notebook, working through it, and Chidi studied it with a focus that had nothing to do with quadratic equations. He was giving Emeka the room. They all were. The conversation about Mathematics was a way of filling the space around Emeka with something ordinary, something that asked nothing of him.\nEmeka was looking at his phone. His jaw was set. He was reading something or pretending to, and his thumb moved on the screen without scrolling far enough to have actually read anything.\n"Thank you for the zobo," he said to Precious, without looking up.\n"My mother will make more," Precious said. "She always makes more than we need."\nShe said it simply, without weight, but Ngozi caught the gentleness underneath it, the specific kindness of offering a mother''s presence to someone who might need the idea of it right now.\nEmeka nodded. He put the phone face down.\nTeacher Obiora came back. The session resumed.\nFor the rest of the hour Emeka answered every question Teacher Obiora asked. Every one. With the controlled precision of someone who needed, more than anything, to be competent at something today. Teacher Obiora did not remark on it. He simply moved to the next question and the next, as if this were ordinary, as if a boy with a bruise above his eye answering everything correctly was the most natural thing in the room.\nMaybe, Ngozi thought, for Teacher Obiora, it was.\nShe wrote the last equation in her notebook and underlined it.\nThe bruise did not come up. Not once.','\n',char(10)),1047,1,1,NULL,'2026-04-10T15:34:12.622Z','2026-04-10 15:34:12','2026-04-10 15:34:12',NULL,1,NULL);
INSERT INTO "chapters" ("id","novel_id","chapter_number","title","content","word_count","is_premium","is_published","audio_url","published_at","created_at","updated_at","scheduled_release_at","part_number","season_id") VALUES(337,44,8,'Ada''s Notebook',replace('It was Chidi who found it, which was the worst possible way for it to happen.\nTeacher Obiora had stepped out to receive a parent who had come to pay fees, and Chidi, who could not exist in an unstructured ten minutes without investigating something, had gone to the table at the front to look at the stack of past question papers Teacher Obiora kept there. He was flipping through them with one hand, eating the last of a chin-chin he had produced from his bag, when Ada''s notebook slid off her chair.\nShe had gone outside to use the toilet. Her bag was there, her two pens parallel on the seat, and the notebook on the floor, open.\nChidi looked at it.\nNgozi said, "Leave it."\nHe crouched down and picked it up, and before Ngozi could say anything else he was reading, not the quick accidental glance that Emeka had taken three weeks ago, but reading, standing there with chin-chin in one hand and Ada''s notebook in the other, his eyes moving down the page.\n"Chidi," Precious said.\n"Just a second."\n"That is not yours."\n"I know." He turned the page. "I know, just." He read a little more. He closed the notebook. He stood up.\nHis face had changed.\nHe put the notebook on Ada''s chair, on top of the two pens, and went back to his seat. He finished the chin-chin. He brushed the crumbs from his knee.\n"What?" Emeka said, reading his face.\nChidi shook his head.\nAda came back in and sat down and immediately registered the notebook''s position, on the seat rather than the floor where she had left it. She looked at it. She looked at the room. Her eyes moved to Chidi.\nHe met her gaze without flinching. "You''re a good writer," he said.\nAda went very still.\n"I shouldn''t have read it," he said. "I know. But you''re good."\nThe room did what the room did when something true entered it unexpectedly. It went quiet and everyone pretended they were looking at something else and nobody was.\n"What are you writing?" Precious asked. Her voice was careful, the way you are careful with something that might startle.\nAda looked at her hands in her lap. Then she looked up, not at Precious, at the notebook. "Stories," she said. "I''ve been writing them in here since the second session." She paused. "I have notes in the back. For WAEC. But the front is stories."\nNobody said anything.\n"My father has already paid my UNIMED acceptance fee," she said. "Medicine. I have a place waiting." She said it the way you state a fact you have made your peace with, except that her hands in her lap were not at peace. They were pressed flat against each other, fingers interlocked, the knuckles slightly pale. "He paid it in February. He told everyone. His colleagues, our pastor, my grandmother. Everyone knows Ada is going to be a doctor."\nTobe was watching her with a stillness that was different from his usual stillness. Concentrated. Present.\n"Does he know?" Ngozi asked. "About the writing?"\nAda looked at her. "He knows I read a lot."\nThe distinction sat in the room like a held breath.\n"Writing and reading are not the same thing," Precious said quietly.\n"No," Ada said. "They are not the same thing."\nChidi opened his mouth.\n"Don''t," Emeka said.\n"I was going to say something good."\n"Say it carefully."\nChidi leaned forward in his chair. "Ada. I read two pages of what you were writing. I don''t know the full story. But those two pages, the part where the girl is on the bus and she''s watching the road and thinking about her mother." He stopped. "I forgot I was in this room. I forgot about Teacher Obiora and WAEC and everything. I was just there, on the bus with her." He sat back. "That''s what good writing does. It takes you somewhere."\nAda looked at him for a long moment.\n"My father would say it''s a hobby," she said. "He would say you can write on weekends. After work. After your real life."\n"Is that what you think?" Precious asked.\nAda did not answer that.\n"There are people who write for a living," Tobe said. It was quiet and direct and he said it the way he said things when he had been turning them over for a while. "Real people. Not just abroad. Here too."\n"I know," Ada said.\n"Then you know it''s possible."\n"Knowing something is possible and knowing how to make it happen are different things." She looked at her notebook. "Knowing something is possible and being someone whose father has told everyone his daughter is going to be a doctor are also different things."\nEmeka, who had said nothing, said, "What do you want?"\nAda looked at him.\n"Not what''s possible. Not what your father has paid for. What do you want?"\nThe generator outside ran its steady rhythm. Awka Road was doing its evening things. The single bulb above them held its light over all six of them and the question that Emeka had just put in the middle of the room.\nAda picked up her notebook. She held it the way she always held it, against her chest, both arms across it.\n"I want to write," she said. "That is the only answer I have."\nTeacher Obiora came back in. Ada set the notebook on her knee. Teacher Obiora looked at the board, looked at his class, picked up the chalk.\nThe session resumed.\nAda took notes in the back of the notebook, as she always did. Her eyes were dry. Her handwriting was steady.\nShe did not look up at any of them for the rest of the session.\nThe next morning Ngozi looked for the notebook when Ada came in and sat down.\nAda''s hands were empty. Her two pens were in her breast pocket. She sat, placed her hands on her knees, and looked at the board.\nThe notebook was not there.','\n',char(10)),1009,1,1,NULL,'2026-04-10T15:35:08.152Z','2026-04-10 15:35:08','2026-04-10 15:35:08',NULL,1,NULL);
INSERT INTO "chapters" ("id","novel_id","chapter_number","title","content","word_count","is_premium","is_published","audio_url","published_at","created_at","updated_at","scheduled_release_at","part_number","season_id") VALUES(338,44,9,'What Precious Carries',replace('The second Thursday Precious missed, nobody offered theories.\nThe first time she had been absent, Chidi had filled the silence with guesses, extra lesson elsewhere, a school function, something with FGC. The room had let him do it because it was better than sitting with the not knowing. But she had come back the following Monday without explanation and they had accepted it and moved on, and now here was another Thursday with her chair empty and her bag gone and none of them said a word about it.\nTeacher Obiora taught the session. They took notes. Tobe answered the questions that hung unanswered long enough to become uncomfortable. Chidi ate his chin-chin. Emeka''s bruise had faded to a shadow above his cheekbone, almost gone, something you would miss if you hadn''t been watching.\nNgozi wrote the date at the top of her page and then looked at it for a moment before writing anything else.\nTwo Thursdays.\nPrecious came back on Friday.\nShe arrived at three fifty-eight, which was two minutes earlier than she usually arrived, and she sat down and arranged her things the way she always did, notebook, pen, her phone in her bag turned face down so the notifications wouldn''t pull her. She said good afternoon to Teacher Obiora when he came in and he nodded and went to the board.\nEverything on the surface was the same.\nBut Ngozi had spent two weeks learning the surfaces of people in this room, the specific way Emeka held his phone when something was wrong, the way Ada''s handwriting changed when she was unsettled, smaller and more compressed, the way Chidi went quiet instead of loud when something was sitting on him. She knew surfaces now. She knew when a surface was working hard.\nPrecious was working hard.\nAt five fifteen Teacher Obiora went out and the room shifted into break. Chidi and Emeka leaned over a Mathematics problem in Emeka''s notebook. Ada had her notebook open at the front, not the back, which was new. She had started bringing it again three days after she had come in without it, without comment, as if it had never been gone. Tobe was reading.\nPrecious stood and said, "I''m getting air," and went through the curtain.\nNgozi counted to fifteen before she followed.\nAwka Road in the five o''clock light was all motion. Buses and okadas and traders beginning to pack up and children released from whatever had held them all day running in ways that looked less like play and more like relief. The mallam''s suya fire was already going at the junction, the smoke rising thin and straight in the windless evening air.\nPrecious was standing to the side of the building, her back against the zinc wall, looking at the road without watching it.\nNgozi stood beside her.\nNeither of them spoke for a moment. On Awka Road a bus conductor was shouting destinations. Fegge. Inland Town. Upper Iweka. The sound of a city that did not stop for anything.\n"You don''t have to tell me anything," Ngozi said.\nPrecious looked at her.\n"I just didn''t want you to be outside alone."\nPrecious turned back to the road. She was quiet long enough that Ngozi thought she was going to stay quiet, which was fine, which was also why Ngozi had come out, so that the silence had company.\n"She has kidney disease," Precious said. "My mother."\nNgozi was still.\n"They told us in February. I''ve known since February and I haven''t." Precious stopped. She pressed her lips together briefly. "I haven''t told anyone. Not anyone at my school. Not my cousins. My father knows, but my father is in Lagos, so knowing and being present are." She paused. "Different things."\n"Thursdays," Ngozi said.\n"Thursdays we go to St. Charles for her dialysis. I take her because she doesn''t like taking okada alone and the treatments make her tired after." Precious looked at her hands. "She didn''t want to move back to Lagos. She said Onitsha has better air. I don''t know if that''s true or if she just didn''t want to admit that moving here was a mistake." Something crossed her face briefly, sharp and then contained. "She''s stubborn in the way that looks like strength until you''re the one watching her walk to the treatment room."\nNgozi thought about her own mother at Bridge Head, standing behind the provision counter at seven in the morning and still there at nine at night, the particular set of her back that was determination and exhaustion wearing each other''s clothes.\n"Does she know you come here?" Ngozi asked. "To lesson."\n"She insisted on it." Precious almost smiled. "She told the hospital scheduler specifically not to book Fridays because I have lesson on Fridays. She negotiated my WAEC prep into her dialysis schedule."\n"That''s your mother," Ngozi said.\n"That''s my mother," Precious agreed.\nThey stood in the five o''clock noise for another moment.\n"I keep thinking," Precious said, "that if I pass everything, if I do well, if I get the results and the admission and all of it, it will mean something. Like I''m building something for her to see." She looked at the suya smoke rising above the junction. "But then I think about what Emeka''s face looked like the day he forgot his bag. Or what Chidi said about his third year. And I think everyone in that room is building something for someone to see." She paused. "Or trying to."\nNgozi said nothing. She did not think it needed a response.\n"Thank you for coming out," Precious said.\n"I told you. I didn''t want you to be alone."\nPrecious nodded. She pushed off the zinc wall. "We should go back in."\nThey went back through the curtain together.\nFive faces looked up and then, reading something in the way Ngozi held herself, looked back down. Ngozi sat and picked up her pen. Precious sat and opened her notebook.\nTeacher Obiora came back in thirty seconds later and looked at all six of them in the room and picked up the chalk.\nThe session resumed.\nNgozi did not say anything.\nWhat Precious had given her out there on Awka Road was not Ngozi''s to pass around the room like Emeka''s phone. It was Precious''s. It would stay where it had been given until Precious decided otherwise, if she ever did.\nNgozi dated a new page and began to write.','\n',char(10)),1074,1,1,NULL,'2026-04-10 15:36:17','2026-04-10 15:36:02','2026-04-10 15:36:17',NULL,1,NULL);
INSERT INTO "chapters" ("id","novel_id","chapter_number","title","content","word_count","is_premium","is_published","audio_url","published_at","created_at","updated_at","scheduled_release_at","part_number","season_id") VALUES(339,44,10,' The Third Week of May',replace('Ten days.\nTeacher Obiora wrote it on the board before he wrote anything else, the way a doctor writes a number you have to sit with before the rest of the conversation can happen. He underlined it once. He put the chalk down.\n"Ten days," he said. "After today, nine. After tomorrow, eight." He looked at them. "The students who fail WAEC do not fail because they are not intelligent. They fail because they panic in the last ten days and they stop doing the thing that was already working. I am telling you this now so that when the panic comes, because it will come, you will remember that I warned you and you will sit down and continue working."\nHe turned back to the board and began writing Chemistry equations.\nNgozi looked at the number. Ten. She wrote it in the margin of her notebook and then crossed it out because looking at it was not helping.\nThe room had a different quality this week. Something tighter in it. The spaces between them, which had been closing since the suya evening, since the dark, since Ada''s notebook and Precious on Awka Road and Emeka''s bruise, felt compressed now by something external. WAEC was ten days away and it was pressing on all six of them in the way that a deadline presses, not just on the work but on the person doing the work, on everything they had been carrying alongside it.\nEmeka had both his textbook and his phone on his knee, which he had not done since the first week. He was flipping between a past question paper and something on his screen, and the focused, careful quality he usually had was frayed slightly at the edges.\nAda was writing in the front of her notebook. She no longer tried to hide it. She wrote in the front and took notes in the back and if Teacher Obiora had noticed he had not said anything, and if the others noticed they had accepted it the way they had accepted most things about each other by now, as a fact of the room rather than a question.\nIt came from nowhere, the way the worst ones do.\nThey were on Literature. Teacher Obiora had asked about the central conflict in Things Fall Apart and the discussion had moved the way discussions in the room had learned to move, not the stiff question-and-answer of the first week but something more like actual thinking done out loud.\n"Okonkwo''s problem is pride," Chidi said. "Everything comes from pride. He couldn''t bend."\n"It''s more than pride," Precious said. "It''s fear. He was terrified of becoming his father, so he went as far in the other direction as he could and he overcorrected."\n"That''s the same as pride."\n"It is not the same as pride. Pride is about yourself. Fear is about who you don''t want to be. They produce the same behavior but they come from different places."\nChidi turned toward her. "With respect, Precious, I don''t think you''re reading the same Okonkwo I''m reading."\n"With respect," she said, in a tone that held the phrase at arm''s length, "I''ve read this book three times."\n"Reading it three times doesn''t mean your interpretation is right."\n"It doesn''t mean it''s wrong either."\n"Children," Teacher Obiora said, without particular urgency.\n"I''m not saying it''s wrong," Chidi said, and there was something in his voice now that had edges. "I''m saying Okonkwo knew exactly who he was. He made choices based on who he was. That''s pride. Not fear."\n"He beat his wife during the Week of Peace because he was afraid of looking weak," Precious said. "He disowned Nwoye because he was afraid of having a son like his father. Every act of cruelty in that book comes from terror, not pride. Chinua Achebe wrote a man who was afraid and could not say it."\nThe room was paying full attention now. Teacher Obiora had his chalk and had not turned to the board.\n"You know what your problem is," Chidi said.\n"Chidi," Emeka said.\n"No, let me say it. Your problem is that you always want to be the most correct person in the room. Since day one. You walk in here with your Lagos accent that you practice flattening and your FGC uniform and you always have to have the deepest reading, the most complicated answer."\nThe silence that followed was a different kind from any that had been in the room before.\nPrecious did not move. Her pen was in her hand and her notebook was open and she sat with a straightness that was not composure, it was the thing that holds the place where composure was before something knocks it loose.\n"Chidi," Ngozi said. Her voice was low and serious.\n"I''m just saying what''s true."\n"You are not saying what''s true," Precious said. Her voice was very controlled and very quiet. "You are saying what you see from where you are sitting. And from where you are sitting you cannot see very much."\n"Then tell me what I''m missing."\n"You''ve been missing it since the third session." She looked at him directly. "I don''t perform. I think. Those are not the same thing."\nThe generator outside ran its unchanging rhythm. Awka Road continued. The number ten was still on the board.\nTobe stood up.\nNot suddenly, not dramatically. He just stood, the way you stand when you have been sitting too long and your body has decided it is finished being still. He was not tall but standing made him present in the room differently.\n"I have something to say," he said.\nEveryone looked at him. Teacher Obiora looked at him.\n"I have been in this room since the first session." His voice was steady and unhurried. "I have watched all of you every day. Chidi, you are one of the most generous people I have met. You were the first person to say something kind about Ada''s writing. You checked on Emeka without making it about Emeka." He paused. "But when you are afraid, you attack. You have been afraid for ten sessions and most of the time you turn it into jokes. Right now you turned it into that." He looked at Precious. "And Precious. You carry things alone because you have learned that rooms are not safe. This room is not the rooms that taught you that." He stopped. He looked at both of them and then at all of them. "WAEC is in ten days. We found each other in this room and in ten days the room is going to be gone. I don''t want to spend what''s left of it watching two people who actually respect each other pretend they don''t."\nHe sat back down.\nHe picked up his pen.\nThe room was so still that the chalk dust on the board seemed afraid to fall.','\n',char(10)),1154,1,1,NULL,'2026-04-10T15:37:28.290Z','2026-04-10 15:37:28','2026-04-10 15:37:28',NULL,1,NULL);
INSERT INTO "chapters" ("id","novel_id","chapter_number","title","content","word_count","is_premium","is_published","audio_url","published_at","created_at","updated_at","scheduled_release_at","part_number","season_id") VALUES(340,44,11,'Last Session',replace('Teacher Obiora ended the session at five nineteen.\nNot at six. Not after the full two hours. He put the chalk down in the middle of a sentence about essay structure, looked at what he had written on the board, and then looked at the six of them in a way he had not looked at them before. Not the assessing look of the first session, the one that measured and filed and moved on. Something else. Something that took longer.\n"That''s enough," he said.\nChidi looked up from his notebook. "We still have forty minutes."\n"I know how long we have." Teacher Obiora set the chalk on the table. "I said that''s enough."\nHe picked up the stack of past question papers from the table, tapped them against the surface to align them, and set them back down. He looked at the board once more. He uncapped the board eraser and cleaned it, the equations and the essay points and everything else disappearing under the felt in long horizontal strokes until the board was empty.\n"You know what you need to know," he said. "The rest is between you and the examination room." He looked at them one final time. The red biro was behind his ear. His short-sleeved shirt was the same pale colour it had always been. "Go home. Sleep. Eat well before each paper." He paused at the curtain. "All of you have worked hard. I am not a man who says that easily."\nHe went out.\nThey heard his footsteps on the concrete outside, the specific sound of his walk, unhurried and deliberate, fading down toward the gate. Then the sound of the gate. Then Awka Road absorbing him.\nThe six of them sat in the semicircle with the empty board in front of them and the single bulb above them and the generator running outside and nobody moved.\nChidi''s notebook was open on his knee. He looked at it and then closed it slowly, like a door at the end of a long day.\nEmeka put his phone in his pocket. Not face down on his knee. In his pocket, fully away, which Ngozi had not seen him do voluntarily in thirty sessions.\nAda''s pen was in her hand. She set it down beside her notebook, parallel to the edge, and looked at the empty board.\nIt was Precious who spoke first, not with words, just the small sound of someone exhaling something they had been holding for a long time. She sat back in her chair and tilted her head slightly toward the ceiling and breathed.\nTobe was looking at the curtain where Teacher Obiora had gone through. His textbook was closed on his knee, his pen on top of it, the same way he had arrived on the very first day. Except that the first day he had come in and become still in the particular way of someone trying not to be seen. The stillness now was different. It was the stillness of someone who had been seen and had survived it.\n"I keep thinking about something," Ngozi said.\nNobody asked what. They had learned by now that with Ngozi you waited.\n"The first day. I got here early and I sat in this chair and I looked at the room and I thought, thirty sessions. I just have to survive thirty sessions and then WAEC will come and it will either work or it won''t." She looked at the chair legs, the concrete floor, the chalk dust that had settled into the cracks. "I wasn''t thinking about any of you. I was just thinking about surviving the room."\n"Same," Chidi said. No joke attached to it.\n"I didn''t even want to come," Emeka said. "My mother found Teacher Obiora''s number on a flyer. She put the timetable on the fridge and told me I was going." He looked at the empty board. "I came the first day planning to sit at the back and do nothing for two hours."\n"There is no back," Precious said. "It''s a semicircle."\n"I know that now."\nAda picked up her pen and put it down again. "I told my father the lessons were four to seven," she said. "I bought myself an extra hour."\nEveryone looked at her.\n"For writing." She did not look apologetic. "I sit in Mr. Biggs on Oguta Road for an hour after and I write. Then I go home." She paused. "He thinks I''m here until seven."\n"Ada," Ngozi said.\n"I know."\n"That''s actually genius," Chidi said.\n"It''s not genius. It''s survival."\nThe generator outside shifted rhythm briefly, a stutter, and then steadied. The light held. Outside on Awka Road the evening was doing its usual things, loud and indifferent and alive, but in the room it was quiet in a way that felt chosen rather than empty.\nNgozi looked at the six chairs. She thought about how they had been arranged on the first day, six plastic chairs in a semicircle, and how they had all chosen where to sit based on instinct, the exit, the board, the distance from other people. She thought about how the distance had changed. How nobody had announced it. How it had happened the way most true things happen, without ceremony, in the middle of other things.\n"I''m going to miss this room," Tobe said.\nIt was the simplest true thing anyone had said, which made it the most difficult to sit with.\n"It''s a zinc room on Awka Road," Chidi said. But his voice when he said it had none of the lightness he usually used to deflect. He said it and looked at the zinc roof above them and did not follow it with anything else.\nThey sat with it.\nThe minutes moved the way minutes do when you are aware of them, slowly and then suddenly.\nPrecious looked at her hands in her lap. She looked at the curtain. She looked at Ngozi beside her and then at each of them in turn, all the way around the semicircle to Tobe at the end.\n"What happens to us after?" she said.\nNot dramatically. Just the question, placed in the room the way you place something fragile on a surface, carefully, because you know it cannot take much weight.\nThe generator ran.\nThe bulb held its light over all of them.\nNobody answered.','\n',char(10)),1063,1,1,NULL,'2026-04-10T15:38:31.325Z','2026-04-10 15:38:31','2026-04-10 15:38:31',NULL,1,NULL);
INSERT INTO "chapters" ("id","novel_id","chapter_number","title","content","word_count","is_premium","is_published","audio_url","published_at","created_at","updated_at","scheduled_release_at","part_number","season_id") VALUES(341,44,12,' 4–6pm',replace('The morning of the first paper, Ngozi woke at five.\nNot because her alarm went off. Because her body had been keeping a different clock for five weeks and it knew, before she opened her eyes, that today was the day the thirty sessions had been pointing toward. She lay on her mat in the room she shared with her younger sister and looked at the ceiling and thought about nothing specific, which was itself a kind of thinking.\nShe dressed slowly. Ate the rice her mother had kept covered on the stove the night before with a note beside it that said only: Chew well. She picked up her pencil case, her admission letter, her ID card. She stood in the doorway of the kitchen for a moment, looking at the note in her mother''s handwriting.\nShe folded it and put it in her pocket.\nThe examination centre was Saint Mary''s Secondary School off Modebe Avenue, fifteen minutes from Awka Road on a danfo that smelled like engine oil and early morning. Ngozi got down at the junction and was walking toward the gate when she heard her name.\nChidi was sitting on the low concrete fence outside the centre with his admission letter folded in his hand and his shoe untied and the expression of a man who had made peace with something difficult and was now simply waiting on the other side of it.\n"You''re early," she said.\n"Couldn''t sleep." He looked at her. "You?"\n"Five o''clock."\nHe nodded. He looked at the gate. "Third time," he said. Not the way he had said it in the suya evening, as a confession dropped into the room. This was quieter. A fact he had decided to carry differently.\n"Third time," she said back, not as a reminder, as an acknowledgment.\nThey stood there together and then Precious came around the corner with her bag on one shoulder and her admission letter in her hand and when she saw them something in her face settled, the specific relief of finding familiar ground in an unfamiliar morning.\n"Is this our centre?" she said.\n"Same centre," Ngozi said.\nPrecious stood beside them. She looked at the gate, at the students moving through it in their white shirts and dark trousers, the invigilators with their clipboards, the general organised tension of an examination morning.\n"My mother was awake before me," Precious said. "She made akamu. She stood in the kitchen in her wrapper and made akamu at four-thirty in the morning and told me to eat all of it." She paused. "She said to tell WAEC that her daughter says hello."\nChidi laughed. A real one.\nEmeka arrived at seven forty, which was earlier than any of them expected. He was in his white shirt and his sneakers were clean again, fully clean, and he walked toward them with his hands in his pockets and his admission letter tucked under his arm.\nNobody asked about the sneakers. They understood.\n"Where are the others?" he said.\n"Not here yet," Ngozi said.\nHe stood with them and they waited, the four of them in a loose arrangement outside Saint Mary''s gate, and the morning moved around them.\nTobe came at seven fifty. He came alone, the way he always came, and he saw them from the road and walked to where they were standing without hurrying. He had his pencil case in one hand and nothing else, no bag, just what he needed, which was exactly how he had always been.\n"Ada," Ngozi said, when he reached them.\n"I know," Tobe said. He looked at the gate. "She''ll come."\nShe came at seven fifty-eight.\nShe was running, slightly, not the panicked run of someone who was late but the quick walk that becomes a run when you see people you know. She had her admission letter and her pencil case and her Oxford notebook tucked under her arm, which made Chidi smile in a way he didn''t try to hide.\n"Why do you have the notebook?" Emeka asked.\n"Habit," she said, slightly breathless. She looked at all of them. "We''re all here."\nThey were all here.\nSix students in white shirts outside an examination gate on a Tuesday morning in the third week of May. The danfos were moving on the road behind them. Somewhere on Awka Road, Teacher Obiora was probably already at his table, already waiting for the next six. The zinc roof was there. The chairs were there, arranged in their semicircle. The kerosene lamp that Teacher Obiora kept in the corner for when NEPA took light was there, the glass still warm from a morning that did not know it was supposed to mean something.\nThe bell inside Saint Mary''s rang once.\n"Okay," Chidi said. He looked at the gate, then at each of them. He tied his shoe. He stood up. "Okay."\nNobody made a speech. Nobody needed to. They had already said the things that needed saying, some of them in the room, some in the dark, some on Awka Road in the five o''clock light, some in the particular silence of people who had learned each other''s weight.\nThey went through the gate together and then the crowd of students pulled them in different directions, different exam halls, different rows, different seats.\nNgozi found her seat and put her pencil case on the desk and looked at the blank answer booklet in front of her. Outside the louvred window, the Onitsha morning was at full volume. Inside, the room was the particular silence of thirty people about to begin.\nShe thought about six plastic chairs in a semicircle.\nShe picked up her pen.','\n',char(10)),946,1,1,NULL,'2026-04-10T15:40:09.287Z','2026-04-10 15:40:09','2026-04-10 15:40:09',NULL,1,NULL);
INSERT INTO "chapters" ("id","novel_id","chapter_number","title","content","word_count","is_premium","is_published","audio_url","published_at","created_at","updated_at","scheduled_release_at","part_number","season_id") VALUES(342,45,1,' Asoebi Season',replace('\n\nBy ten o''clock, Teniola had rearranged seventeen chairs, untangled two sets of fairy lights, and accepted zero thanks. The wedding was not hers, and neither was the work, but her hands knew the job before her brain caught up.\nThe venue was a compound off Agodi Gate Road, the kind with a gate painted the bride''s color two days before the ceremony and repainted white two days after. Today the gate was coral. Teni had seen that color across so many weddings she could no longer see it as beautiful. She saw it as inventory.\nHer mother was somewhere near the entrance, directing three young men with the particular authority of a woman who had not sat down since six a.m. Mama Teni moved through events like a general through contested ground: phone at her ear, waist beads clicking, a folded list in her left hand that she consulted and updated and consulted again. She was extraordinary at her job. Teni had spent sixteen years watching her be extraordinary and had learned, among other things, that extraordinary came at a cost.\nThe cost was weekends. All of them.\nEvery owambe from April through December, spread across Bodija, Jericho, Agodi, Ring Road. Teni had been to more weddings than most women twice her age. She knew how to spot a venue that had overbooked its chairs. She could read an asoebi color arrangement from across a compound. She knew which caterers served small portions when the oga was not watching, and which photographers disappeared before the cutting of the cake.\nWhat she did not know, at sixteen, was what it felt like to attend a party for herself.\nShe carried a stack of programs to the reception tables and placed them with the flat efficiency of someone who had done this for years. The compound was filling now. Aunties in coordinated aso-oke, their gele tied high and proud. Men in agbada trailing their wives like elegant shadows. Children running the perimeter of everything, already sticky with Fanta.\nTeni watched them arrive with the practiced detachment of a security camera. Her uniform today was black: black blouse, black trousers, flat sandals. Her mother''s staff dressed in black so they could move through events without being mistaken for guests. It worked. No one ever mistook Teni for a guest.\n"Teni!" Her mother''s voice cut through the music from near the gate. "Come and count the small chops. Tell Emmanuel the prawn ones are short."\nShe went. She counted. They were short. She told Emmanuel, who kissed his teeth and said "are you sure?" as if she had counted wrong on purpose. She said "yes, I''m sure" in a voice that had learned not to rise.\nBy noon the ceremony had moved inside a church three streets away, and the compound belonged to caterers and decorators and her mother''s team running final checks. Teni had a thirty minute window where nothing was required of her. She found a low concrete ledge near the back of the compound, behind a column of plastic chairs still wrapped in cellophane, and she sat down.\nShe pulled out her phone. Her best friend Simi was at home sending memes since eight a.m. Teni scrolled through them without fully laughing. Simi thought the weddings sounded glamorous: all that food and music and fine fabric. Teni had stopped trying to explain that standing inside a celebration was not the same as belonging to one.\nOutside the back gate, a generator coughed to life. Then a second one joined it from somewhere further away, and the afternoon filled with that particular Ibadan layering: generator hum under talking drums under the distant swell of a praise singer warming up her voice.\nThe band was arriving.\nTeni watched them through the gap in the back gate, not because she was interested, but because there was nothing else to look at. Men unloading equipment from a rusted bus. Drums wrapped in old cloth. Speakers with scuff marks that told their history without words.\nThen a boy her age jumped down from the back of the bus holding a water bottle and a small backpack, and stood in the compound dust looking at the venue the same way Teni looked at all venues: not admiring it, assessing it. Taking inventory.\nHe looked up once, toward the back of the compound where she was sitting.\nShe looked away first.\n"Teni!" Her mother''s voice, closer now. "They are back from church. Stand by the entrance and direct the overflow chairs to the left side."\nShe stood. She smoothed her blouse. She became useful again.\nBut she looked once more toward the back gate before she moved, and the boy with the water bottle was still there, writing something in a notebook with the focused stillness of a person doing a private calculation.\nShe filed it somewhere that was not yet important.\nThe guests came through the gate now, coral and gold and jubilant. Teni walked toward the entrance to do what she always did. She made herself useful. She made herself small. She made herself invisible enough that the celebration could arrange itself around her like she was part of the structure, like she had never once wanted to be somewhere else.\nThe talking drum started. The compound answered with noise.\nTeni directed the overflow chairs to the left side.','\n',char(10)),893,0,1,NULL,'2026-04-10T20:06:34.174Z','2026-04-10 20:06:34','2026-04-10 20:06:34',NULL,1,29);
INSERT INTO "chapters" ("id","novel_id","chapter_number","title","content","word_count","is_premium","is_published","audio_url","published_at","created_at","updated_at","scheduled_release_at","part_number","season_id") VALUES(343,45,2,'Boys'' Quarters',replace('The bride had been crying for eleven minutes and nobody was doing anything useful about it.\nTeni stood outside the changing room with a packet of facial blotting sheets her mother had handed her twenty minutes earlier with instructions to "stay close and be ready." The maid of honour was on the phone. The mother of the bride was fanning herself and making it worse. Two aunties were offering conflicting advice at the same time, and the bride, a pretty woman in white lace and panic, was crying anyway, carefully, the way someone cries when they know their makeup is expensive.\nTeni knocked gently, entered, held out the blotting sheets, and said nothing. The bride took them. Their eyes met. Teni gave her a small nod that meant you are fine, this is fine, all of this is survivable. She had learned the nod from her mother, who deployed it at approximately four events per month.\nThe bride exhaled. Dabbed. Steadied.\nTeni slipped back out.\nHer mother was passing in the corridor and caught her eye and gave a single approving nod, the mirror of the one Teni had just used, and then she was gone again around the corner, already talking into her phone about the generator fuel situation.\nThe reception was in full noise now. The praise singer had found her full register and was using all of it. Teni moved through the back corridor of the main hall, past pyramids of soft drinks, past a teenager in a catering apron eating small chops behind a pillar without guilt, past the rear exit door that someone had propped open with a brick.\nShe went through it.\nOutside was a narrow stretch of compound that separated the main venue from the boys'' quarters, a flat-roofed structure at the back used for storage and overflow. The difference between inside and outside was immediate and physical. The generator was back here, and it was loud, but after five hours inside a celebration, loud and sourceable was better than loud and everywhere.\nShe sat on the concrete step at the boys'' quarters entrance and put her back against the door frame.\nThirty seconds later, footsteps.\nThe boy from the bus came around the corner of the building holding a Styrofoam plate and stopped when he saw her.\nThey looked at each other.\n"Sorry," he said. "I thought this area was empty."\n"It is," Teni said. "I am not a person right now. I am on break."\nSomething in his face shifted. Not quite a smile. More like recognition. He looked at his plate, then at the concrete step, then at her.\n"Can the step fit two non-persons?"\nShe moved sideways. He sat.\nHis name was Kayode. She offered hers. He was seventeen, she was sixteen. His father played the gangan and had been playing it at events across Ibadan since before Kayode was born. He had grown up in the back areas of other people''s celebrations the same way she had: aware of the music without owning it, present without being acknowledged.\n"You get used to it," he said, and then immediately: "Actually that is a lie. You just get better at pretending."\nTeni looked at him. "Yes."\nThat single word landed between them like something with weight. He heard it.\nThey ate. He had rice and fried meat and was willing to share; she had not eaten since eight a.m. and accepted without pretending she was not hungry. From inside the venue, the praise singer was calling the groom''s family to the dance floor. The groom''s family was responding with the energy of people who had been waiting all day to be called.\n"Do you go to school here?" he asked.\n"Queens College. But I''m home for the long weekend." She paused. "You?"\n"Government secondary, Agodi. Final year."\n"WAEC year?"\n"WAEC year." He said it the way people say the name of a thing that is both important and exhausting. Then: "You like any subject or you are just surviving?"\n"Literature. You?"\n"Physics and Maths. Anything with a fixed answer."\n"That is the most engineer thing to say."\nHe turned to look at her, and this time it was a real smile, unguarded and quick. "Am I obvious?"\n"Only because I was guessing." She tilted her head. "Is that what you want to do? Engineering?"\nThe smile stayed but something behind it shifted. "That is the plan." He said it in a way that carried more information than the words contained. Teni heard the weight under it without being able to name it yet. She filed it. Not her business.\n"I want to study Communications," she said. "Or Journalism. Something where I get to ask questions and people are supposed to answer."\n"You like asking questions?"\n"I like getting answers. There is a difference."\nHe looked at her for a moment. "That is actually a distinction."\n"I know."\nFrom the back gate, one of the band''s assistants poked his head into the narrow compound and called: "Kayode! Your father is looking for you, they want the gangan for the cutting."\nKayode stood. Brushed rice off his trousers. Picked up his plate. Then he stopped and looked down at her.\n"How many more weddings does your mother have this season?"\nTeni almost laughed. She had never been asked that question as though the answer mattered to anyone but her mother''s clients. "Four more. All before end of August."\nHe nodded once, thoughtful. "My father also has four." He paused one beat. "Probably the same ones."\nThen he walked back through the narrow compound toward the gate and disappeared around the corner.\nTeni sat with her back against the doorframe and the generator humming beside her, and she noticed, for the first time in what felt like years, that the inside of her chest was doing something she had not asked it to do.\nShe pressed her palms flat against the warm concrete step.\nInside the venue, the talking drum started.\nIt sounded, now, entirely different.','\n',char(10)),1003,0,1,NULL,'2026-04-10T20:07:41.096Z','2026-04-10 20:07:41','2026-04-10 20:07:41',NULL,1,29);
INSERT INTO "chapters" ("id","novel_id","chapter_number","title","content","word_count","is_premium","is_published","audio_url","published_at","created_at","updated_at","scheduled_release_at","part_number","season_id") VALUES(344,45,3,'After the Aso',replace('The asoebi fabric was still on the dining table Tuesday morning, coral and gold in a shaft of window light, and Teni walked past it three times before her mother finally folded it into a bag.\n"Stop looking at it," her mother said, not looking up.\n"I was not looking at it."\n"You have been walking past it since yesterday. Fold something or go and read."\nTeni went to read. She sat at the desk in her room with her Literature textbook open to a page about narrative voice and read the same paragraph four times without retaining a single sentence.\nThe issue was not the fabric. The issue was that her brain had developed a new habit since Saturday and the habit was Kayode. Not Kayode in any dramatic sense. Just small replays, arriving without permission. The quick smile. Probably the same ones. The way he said engineering like a door he was not sure was still open. The way he had asked how many weddings remained as if the answer was data he intended to use.\nShe closed the textbook.\nHer phone was face-down on the desk because she had learned that face-up phones destroyed reading sessions. She turned it over. Simi had sent six messages since morning about a boy in their class named Tobenna who had apparently said something in a group chat that required analysis. Teni scrolled through the thread and typed appropriate responses and felt, the entire time, like she was operating at a slight distance from the conversation.\nShe put the phone down.\nThe thing was, she did not have his number. They had not exchanged numbers. They had not made plans. He had said probably the same ones and walked away and she had sat on that concrete step for another four minutes before her mother''s voice pulled her back inside. And now here she was in her room on a Tuesday in Ibadan, reading the same paragraph about narrative voice, understanding nothing.\nShe picked up the phone again and opened a new note.\nThings I know about Kayode:\nFather plays gangan. Government secondary, Agodi. Final year. Physics and Maths. Wants to do Engineering. Has four more weddings this season. Shares food without being asked.\nShe stared at the list.\nThen she typed one more line:\nSaid "that is actually a distinction" like he meant it.\nShe closed the note and put the phone down and went to find her mother.\nMama Teni was in the parlour with her event binder, which was a thick thing of laminated pages and color-coded tabs that represented her entire professional life. She was on a call but gestured with two fingers toward the kitchen — there was food on the stove. Teni served herself jollof rice and stood in the kitchen doorway eating and listening to her mother negotiate chair rentals with the focused aggression of a woman who knew exactly what things cost.\nWhen the call ended, Teni said: "Mama, the next one is which weekend?"\nHer mother looked up. "Why?"\n"I want to know if I need to cancel anything with Simi."\nThis was a reasonable cover. Her mother consulted the binder without suspicion. "Third Saturday. Eleyele. Big one. Chief Salami''s daughter, you remember the engagement we did in February?"\nTeni remembered. A garden event, fairy lights in jacaranda trees, a caterer from Lagos who had charged double and delivered exactly as promised. "The one with the white flowers."\n"Tuberose. Yes. The wedding will be bigger. Your uncle Biodun is coming from Abuja, the aso-ebi has already sold out twice." She was already writing something in the margin of the binder. "I need you sharp for that one. No phone. No wandering."\n"Okay."\n"Okay meaning what?"\n"Okay meaning yes, Mama. I will be sharp."\nHer mother looked at her for one moment with the precise attention of a woman who had watched this particular child since birth. "You are quiet this week."\n"I am always quiet."\n"Quiet and elsewhere are different."\nTeni ate a spoonful of rice. "I am here."\nHer mother held the look one second longer, then returned to the binder.\nShe texted Simi that night.\nIf you met someone at an event and you didn''t take their number and they said something that implied they would see you at the next event, is it reasonable to think they actually meant it or are people just polite?\nSimi''s response took forty seconds.\nWHO\nTeni typed: No one you know.\nThat''s not an answer. Is he fine?\nTeni looked at the ceiling of her room. She typed: That is not the relevant detail.\nIt is always the relevant detail. How did you meet him? At one of your mum''s weddings?\nHe was working the event too. His father is in the band.\nA pause. Then: So he understands the life.\nTeni had not framed it that way but the moment Simi said it, something in her chest confirmed it like a key turning. She typed: Yes.\nTeni. A pause. Take his number at the next one.\nWhat if he doesn''t come?\nHe said he would be there.\nHe said probably.\nTeni. Take his number.\nShe put the phone down and looked at the ceiling again. Outside, a neighbor''s generator started up and the street settled into the familiar Ibadan evening frequency: generators, a distance television, a child being called indoors in Yoruba.\nShe thought about what he had said. Anything with a fixed answer. The logic of a person who had learned to trust what could be proven. And she had said I like getting answers like someone who did not yet know that the questions she was forming had no fixed ones.\nShe picked up her phone one more time and opened the note.\nShe read the list.\nThen she added: Eleyele. Third Saturday.\nShe closed it. She turned off her lamp. She lay in the dark listening to the generators and tried to approach sleep from a reasonable direction.\nThe coral gate was probably already white again.\nShe thought about this for a while: how fast things were repainted. How a venue could hold one kind of light on a Saturday and by Tuesday be entirely itself again, indifferent to what had happened inside it.\nShe thought about concrete steps and Styrofoam plates and the particular sound of a talking drum when you were not, for once, thinking about the chairs.\nSleep came eventually.\nIt came slowly, but it came.','\n',char(10)),1080,0,1,NULL,'2026-04-10T20:08:53.101Z','2026-04-10 20:08:53','2026-04-10 20:08:53',NULL,1,29);
INSERT INTO "chapters" ("id","novel_id","chapter_number","title","content","word_count","is_premium","is_published","audio_url","published_at","created_at","updated_at","scheduled_release_at","part_number","season_id") VALUES(345,45,4,'The Talking Drum''s Son',replace('Teni spotted the band''s bus before she spotted him, and the relief that moved through her body was so immediate she had to pretend she was looking at something else.\nThe bus was parked at the side gate of the Eleyele venue, same rust along the wheel arches, same scuff on the rear bumper. The equipment was already being unloaded. Teni was carrying a box of centrepiece candles toward the main hall and she slowed her pace without meaning to, scanning the figures moving around the bus until she found the one with the backpack.\nKayode was lifting a wrapped drum with both arms, talking to an older man beside him, the kind of talking that was really just listening with occasional nods. His father, probably. Same jaw. Same quality of stillness, even while moving.\nShe did not stop walking. She kept her face neutral and carried the candles inside and set them down on the correct table and then stood very still for three seconds, arranging nothing, just standing.\nThen she went back outside.\nThe venue was a private estate hall in Eleyele with a garden section attached, and it was, as her mother had promised, a big one. Three hundred guests minimum. Aso-ebi in deep burgundy with gold trim, already visible on every woman who had arrived early to secure good seats. A Lagos caterer. A live band and a DJ running alternating sets.\nTeni''s mother was in four places at once, which was her standard operating mode at large events. She had given Teni a task list on a folded paper before they left the house: centrepieces, gift table arrangement, back hall chairs, coordinator support during the reception entry march. Enough to keep her moving all afternoon.\nShe moved. She worked. She kept one frequency of her attention on the back areas of the compound.\nAt twelve-forty, she was crossing from the storage room to the main hall when she heard: "You slowed down when you saw the bus."\nShe turned.\nKayode was leaning against the outer wall of the storage room with his arms folded, and he was not smiling but his eyes were doing something that served the same function.\n"I was checking the parking arrangement," Teni said.\n"There is no parking arrangement on that side. It is just the bus."\n"Then I was checking the bus."\n"For what?"\nShe looked at him. "Rust levels."\nHe laughed. It was a real one, short and unguarded, and it did something to the afternoon. He pushed off the wall and fell into step beside her without asking, which she noted but did not comment on.\n"How long have you been here?" she asked.\n"Since nine. We set up early for big ones." He glanced sideways at her. "You?"\n"Seven-thirty."\nHe made a face that acknowledged the weight of seven-thirty without overstating it. They walked together toward the back of the hall and stopped at the edge of the garden section where the guests had not yet spread.\n"I looked up the season schedule," he said. "My father''s bookings."\nShe kept her expression even. "And?"\n"We have three more in common. After today." He said it plainly, as if reporting the results of a calculation. "Agodi in July. Bodija in August. New Bodija end of August."\n"I know," Teni said. "I checked ours too."\nA pause. They were both looking at the garden, at the tuberose arrangements her mother''s team had built along the low fence. Teni had helped source those flowers. She knew their exact cost per bunch.\n"Why did you check?" Kayode asked.\nIt was a direct question. She respected direct questions in principle. In practice this one required a second.\n"Same reason you did," she said.\nHe nodded slowly, and the subject moved on without being closed, the way some subjects did when both people understood the answer and neither needed it spoken.\nThey found twenty minutes together at the back of the estate garden during the period when the ceremony photographs were happening inside and the back areas were briefly quiet. They sat on a low retaining wall with their backs to the main hall, facing a row of pawpaw trees that belonged to whoever lived behind the venue.\nHe had his notebook. She noticed it again.\n"What do you write in there?" she asked.\n"Calculations mostly. Some notes."\n"What kind of notes?"\nHe considered the question. "The kind that help me think."\nShe waited. He opened the notebook to a page near the middle and turned it toward her. It was a grid of numbers with labels beside them: tuition, hostel, books, transport, feeding. A budget broken into academic sessions, projected across four years.\nShe looked at it for a long moment. Then she looked at him.\n"You planned it all out," she said.\n"Planning it does not pay it," he said. Not bitterly. Just accurately.\nShe did not say anything immediately because she was thinking about what to say, which was not the same as having nothing to say. He did not rush her.\n"My mother planned everything too," she said finally. "Every event, every season, every chair. She can tell you the cost of tuberose per bunch at four different vendors. She built her whole business from nothing."\n"That is real."\n"It is. But I have never once seen her sit down at one of these things and just be there." Teni looked at the pawpaw trees. "I do not want to be so good at arranging things that I forget to be inside them."\nKayode was quiet for a moment.\n"I wrote those numbers," he said, "because if I do not write them nobody else will. My father does not plan past the next booking." A pause. "I am not angry at him. He does the work. He just does not see the math underneath it."\n"You see it for both of you."\n"Somebody has to."\nShe looked at him. He was looking at the numbers. The afternoon light was flat and honest and it showed his face without flattery, and what it showed was someone carrying something he had not put down in a very long time.\n"Kayode," she said.\nHe looked up.\n"You will go," she said. "To UI. You will find a way."\nHe held her gaze for one beat, two, and she could not fully read what moved across his face because it was too layered. Then he closed the notebook.\n"You do not know that," he said.\n"No," she agreed. "But I said it anyway."\nFrom inside the hall, the MC''s voice rose suddenly over the speakers, announcing the entrance of the wedding party. The band responded. The talking drum started its familiar cascade and she felt it, as always, in her sternum.\nKayode stood. Picked up his bag.\n"I have to go in," he said. "My father needs me for the entrance set."\nShe nodded.\nHe took two steps, then stopped without turning around.\n"Thank you," he said. "For the thing you said."\nThen he walked back toward the hall, and Teni stayed on the low wall with the pawpaw trees in front of her, and the drum growing louder behind her, and something warm and slightly frightening opening up quietly in the center of her chest.\nShe did not press her palms to the concrete this time.\nShe let it stay.','\n',char(10)),1228,1,1,NULL,'2026-04-10T20:09:58.129Z','2026-04-10 20:09:58','2026-04-10 20:09:58',NULL,1,29);
INSERT INTO "chapters" ("id","novel_id","chapter_number","title","content","word_count","is_premium","is_published","audio_url","published_at","created_at","updated_at","scheduled_release_at","part_number","season_id") VALUES(346,45,5,'Outside the Generator Hum',replace('The MC said the bride''s name wrong twice before someone corrected him, and the whole hall laughed the second time in the warm easy way of people who had eaten well and were now prepared to be generous about everything.\nTeni was standing at the back left wall, her task list done, her mother occupied with a vendor dispute near the kitchen entrance. She had approximately no assigned function for the next thirty minutes and she was using that time to be a body against a wall, watching people enjoy a party.\nIt was not a bad view. The burgundy asoebi moved across the dance floor in coordinated waves every time the MC called a family group. The groom''s mother was a dancer, the real kind, not the kind that danced to be watched. The flower girls had abandoned their baskets somewhere and were now running between tables with the pure purposeful energy of children who had discovered freedom inside a crowd.\nThe talking drum was doing what talking drums do at the peak of a Yoruba reception, which was to make the air feel inhabited. Teni had grown up with that sound as background frequency, as furniture, as something that happened to spaces rather than to her. She was listening to it now with different attention and she was not fully sure when that had changed.\nShe found him with her eyes without deciding to look.\nHe was at the edge of the band section, not playing, watching his father the way you watched something that was also a lesson. His father was deep in the music, gangan strapped across his body, call and response with the praise singer moving between them like a live current. He was brilliant. You could see it even from the back wall.\nKayode watched him with an expression she was still learning to read.\nHe found her at the side exit twenty minutes later.\nShe was outside before he arrived, standing in the narrow corridor between the hall and the generator shed, where a single fluorescent tube threw yellow light over the concrete. She had come out for air and stayed because the air was better than the alternative.\n"Your father is good," she said when he appeared.\n"He is the best," Kayode said. No hesitation. No qualification.\n"I could hear it from the back."\n"You can hear him from anywhere." He leaned against the opposite wall and looked at his shoes for a second. "He played at the governor''s son''s wedding in 2019. Three newspapers covered it. He was the only one they did not name."\nTeni was quiet.\n"I am not saying it to complain," Kayode said quickly.\n"I know," she said. "You are saying it because it is true and true things need somewhere to go."\nHe looked at her.\nShe looked back at him without moving her eyes away, which was something she had been practising without realising it, the small courage of holding a look until it had finished saying what it came to say.\n"When did you become a person who says things like that?" he asked.\n"I have always been this person," she said. "You are only just meeting me."\nHe smiled. The unguarded one, the short bright one that arrived before he could decide whether to allow it. She was cataloguing his smiles now without intending to and that fact alone told her something about where she was.\n"I want to ask you something," she said.\n"Ask."\n"What does it feel like? When he plays and you are watching."\nHe took a breath. Not a performative one, a real one, the kind that meant the answer required some assembly.\n"Proud," he said. "First. Always proud." A pause. "Then something else underneath the proud. Something I do not have a clean word for."\n"Try an unclean one."\nHe looked at the fluorescent tube above them, thinking. "Like watching a road that is very beautiful and also very long and also the only road available." He stopped. "That is not clean."\n"It is honest," she said. "Which is better."\nHe nodded slowly. Then: "Your turn."\n"I did not agree to a turn."\n"You asked me something real. That creates a balance."\nShe considered arguing this on principle and decided against it. "Fine. What is the question?"\n"When you are at these events," he said, "doing all the work, watching everyone else celebrate. Is any part of you angry?"\nThe question arrived with an accuracy that made her chest tighten. She looked at the generator shed across the narrow corridor, the padlock on its door, the rust at the base of the casing.\n"Not at my mother," she said carefully.\n"I did not ask about your mother."\nShe pulled a slow breath. "Yes," she said. "A small part. Not always. But sometimes I look at the dance floor and I think about all the work underneath it and I feel like a nail inside a wall. You cannot see me but the whole thing falls down without me." She paused. "And I do not know if that is something to be proud of or something to be sad about."\n"Both," Kayode said, without hesitation. "It is both."\nShe released the breath she had been holding.\nThey stood in the yellow light for a moment, two nails inside two walls, and the generator between them hummed its constant indifferent hum, and inside the hall the talking drum was running a cascade that fell and rose and fell again.\n"Can I ask one more?" she said.\n"You never agreed to limits."\n"The notebook," she said. "The budget you showed me. Does your father know it exists?"\nKayode was quiet for a count of four. "No."\n"Are you going to show him?"\n"When the number in the last column changes from red to black."\nShe understood that. The logic of it and the loneliness of it, both. She did not tell him what to do with it. She did not offer a solution. She just let it be what it was, which was the truth of his particular Tuesday inside a Saturday full of other people''s joy.\nFrom inside, the MC''s voice rose above everything: "Put your hands together as we call the couple for the first dance!"\nThe hall erupted.\nKayode pushed off the wall. Straightened his collar.\n"I actually have to go this time," he said.\n"You said that last time too."\n"Last time I meant it less."\nShe looked at him. He looked at her. The fluorescent tube buzzed faintly above them, yellow and faithful.\n"Teni," he said. Her name in his mouth was a slightly different object than it was anywhere else. She noted this with the calm of someone noting a thing they had already half expected.\n"Give me your number," he said. "So I do not have to hope you are checking the rust levels next time."\nShe took his phone. Typed her number. Handed it back.\nHe looked at the screen, then at her, then he walked back inside and the door swung shut behind him and the generator resumed its authority over the silence.\nShe stood in the yellow light a moment longer.\nThen she smiled at the generator shed, which did not smile back, which was fine.\nShe was getting used to joy in small and unwitnessed places.','\n',char(10)),1226,1,1,NULL,'2026-04-10T20:11:03.706Z','2026-04-10 20:11:03','2026-04-10 20:11:03',NULL,1,29);
INSERT INTO "chapters" ("id","novel_id","chapter_number","title","content","word_count","is_premium","is_published","audio_url","published_at","created_at","updated_at","scheduled_release_at","part_number","season_id") VALUES(347,45,6,'High Table, Low Chair',replace('He texted first. That was the fact she returned to most often in the two weeks between Eleyele and Agodi, not because it mattered in any large way but because it was data and she was collecting data now.\nGenerator check scheduled for July 12. Rust levels reportedly unchanged.\nShe had read it three times before responding and then typed back: I will bring my inspection kit and then put the phone face-down on her desk and sat very still for a moment, smiling at her Literature textbook.\nThey texted across those two weeks with the careful frequency of two people who were aware they were establishing a pattern and had silently agreed not to name it. He sent her things: a news article about a new engineering faculty at UI, a photo of a broken gangan skin his father was patching with that particular focused patience of a craftsman. She sent him things back: a paragraph from a Chimamanda essay she thought he would argue with, a picture of the Agodi venue flyer her mother had left on the dining table.\nHe texted back: Same venue my father played a burial at in March. There is a good wall behind the caretaker shed.\nShe had laughed out loud at that, alone in her room, the sound surprising her.\nThe Agodi wedding was a church wedding with a garden reception, the kind where the high table sat on a raised platform so the principal guests could look out over everyone else with the benevolent authority of people who had earned elevation. The family was old Ibadan money: measured voices, expensive fabric worn with the ease of people who had never needed to think about fabric. Three hundred chairs. A professional decorator who was not her mother but had hired her mother for logistics coordination, which placed Mama Teni in a supporting role she handled with the grace of a woman who knew her value regardless of title.\nTeni was wearing black as always, moving fast as always, carrying a clipboard her mother had handed her at the gate.\nShe did not see Kayode immediately because the band had set up on the far side of the garden and the garden was deep, and there were too many people already filling the space. She was cross-referencing the seating chart with the name cards when her phone buzzed.\nCaretaker shed is on your left past the frangipani tree. I am already here. There is a bench.\nShe looked left. Found the frangipani tree, its white flowers indifferent to the occasion. Looked at her clipboard. Looked at the tree again.\nShe finished the name cards first.\nHe had found an actual bench, wooden, behind the shed, angled away from the main garden in a way that made it invisible from the high table. Someone had left a plastic bag of groundnuts on it. He moved them aside when she arrived and she sat and the bench creaked once in acknowledgment.\n"You finished your tasks?" he asked.\n"For now," she said. "My mother has her coordinating face on. She will not surface for forty minutes."\n"My father is doing the band warm-up. Same window."\nThey looked at each other with the shared satisfaction of two people who had learned to read the event schedules around them like weather patterns.\nIt lasted about seven minutes.\nThe caretaker, an older man in a brown uniform, came around the shed with a bucket and stopped when he saw them. He looked at Teni. He looked at Kayode. He looked at the bench as if recalculating its ownership.\n"Una dey work the event?" he asked.\n"Yes sir," they said, with the identical reflex of people who had spent their lives answering that question.\nHe nodded once and went on around the shed. But he had looked at them the way adults looked at things they were deciding whether to report, and that look stayed in the air after he left.\n"We should move," Teni said.\n"Where?"\nShe thought. The garden was full now, the shed was compromised, the caretaker knew their faces. "There is an interior corridor in the main hall. Past the kitchen. It goes to the back offices."\n"How do you know?"\n"I know every venue''s back corridor," she said. "It is one of my less exciting skills."\nThe corridor was narrow and fluorescent-lit and smelled like disinfectant and old carpet, and it was empty except for a stack of plastic chairs that had not made the final count. They sat on the bottom two chairs and pulled them slightly apart from the stack and the corridor held them without comment.\n"You are good at this," Kayode said.\n"At what?"\n"Finding spaces."\nShe thought about this. "I have been invisible at these things long enough to learn where the invisible places are."\nHe was quiet for a moment. Then: "Someone saw us."\n"The caretaker."\n"Not only him." He looked at his hands. "When you were walking across the garden. One of the women at the high table."\nTeni felt something shift in her chest. "Which one?"\n"Older woman, burgundy gele. She was watching you cross the garden and then she looked at where you were going and then she looked back at you."\n"She probably thought I was a lost guest."\n"She probably did," Kayode said, in the tone of a person who thought the opposite.\nTeni straightened. "Does that worry you?"\nHe considered it honestly, which she appreciated. "Not worry," he said. "But I notice it."\nShe nodded. There was a difference and she knew the difference. Noticing was not fear but it was the entrance to several things that could become fear.\n"My mother cannot know yet," Teni said. Not dramatically. Just as a fact that required acknowledgment. "Not because of anything bad. Just because she will make it into a thing before I have had time to know what the thing is."\n"Same," Kayode said.\nThey sat with that mutual agreement in the corridor''s fluorescent hum.\nThen he said, quietly: "I got a letter."\nShe turned to look at him.\n"From UI." He was looking at the stack of plastic chairs. "Formal admission letter. It came Monday."\nThe corridor was very still.\n"Kayode," she said. The word came out soft, almost private.\n"I have not told my father yet." His jaw was set but his voice was even. "The fees are in the letter. All of them. First semester, second semester, breakdown of everything." A pause. "The number in the last column is still red."\nShe sat with him inside that sentence.\nThe letter existed. The place was real. The money was not yet.\nShe wanted to say something that would help and she was searching for it, feeling along the edges of what she knew about him and his father and the notebook and the four years of calculations, when the corridor door opened at the far end and her mother appeared with the velocity of a woman on her third task.\nShe stopped when she saw Teni.\nShe looked at Kayode.\nShe looked at the two chairs pulled apart from the stack.\n"Teni," she said, in the voice that had no temperature. "The florist needs a signature. Come."\nTeni stood. Smoothed her trousers. She did not look at Kayode but she felt the quality of his stillness beside her, the way he went very upright, very neutral, the posture of a boy who had learned to be invisible on demand.\nHer mother held the door.\nTeni walked toward it.\nShe did not look back. But at the last second, just before the door, she let her hand drop to her side with all four fingers open, a signal that meant nothing to anyone watching and possibly nothing to him either.\nShe heard the bench shift behind her.\nShe did not know if he had seen it.','\n',char(10)),1315,1,1,NULL,'2026-04-10T20:12:10.027Z','2026-04-10 20:12:10','2026-04-10 20:12:10',NULL,1,29);
INSERT INTO "chapters" ("id","novel_id","chapter_number","title","content","word_count","is_premium","is_published","audio_url","published_at","created_at","updated_at","scheduled_release_at","part_number","season_id") VALUES(348,45,7,' She Danced, Too',replace('Her mother was the one who told her to dance.\nIt happened the way rare things happened at events: sideways, without announcement. The praise singer had called out the decorators by name, which sometimes happened at big weddings when the family wanted to honor every vendor publicly, and Mama Teni had been summoned from behind her clipboard to the edge of the dance floor to receive her commendation in front of three hundred people.\nTeni watched her mother walk out there. Watched her accept the applause with a smile that was real but also practiced, the smile of a woman who had learned to receive recognition without fully letting it in. The praise singer said her name twice, called her the backbone of the celebration, and the MC echoed it, and the whole garden responded warmly.\nThen the praise singer looked past her mother and pointed directly at Teni and said: "And her daughter. Come."\nTeni did not move for one full second.\nHer mother turned and looked at her with an expression that had never appeared on her face at an event before. It was not the coordinator face or the logistics face or the no-temperature voice face. It was just her mother''s face, open and briefly young, and it said: come.\nTeni walked out onto the floor.\nThe music caught her before she had decided what to do with her body, and her body, it turned out, had been waiting. She moved without performance, without the self-consciousness of a girl who had spent sixteen years watching other people inhabit dance floors while she held clipboards. She just moved and the music held her and for ninety seconds she was not invisible and she was not logistics and she was not her mother''s shadow.\nShe was just there.\nThe garden applauded. Her mother put a hand briefly on her shoulder. The praise singer blessed them both and moved on to the next name.\nTeni walked back to the edge of the floor.\nHer heart was doing something extravagant.\nShe found Kayode behind the generator shed ten minutes later, which was not the plan but the plan had dissolved in the last hour and they were both operating without one.\nHe had seen her dance. She could tell from the way he looked at her when she appeared around the shed, something open in his expression that he did not immediately close.\n"The praise singer called you out," he said.\n"She called my mother."\n"She called both of you."\nTeni leaned against the shed wall. The generator hummed its constant hum. "It was ninety seconds."\n"It was the first time I have seen you on the inside of something," he said, and the simplicity of it landed squarely in the center of her chest.\nShe looked at him. He was not smiling. He was just saying what he saw, which was the thing about him that kept doing this to her, kept arriving with more accuracy than she was prepared for.\n"How do you know it was the first time?" she asked.\n"Because I have been watching," he said. "Since the first wedding. I watch you work and I watch you make yourself small and I watch the way you look at the dance floor from the edges." A pause. "Today was different."\nShe breathed. "It felt different."\n"Good different?"\n"I do not have a clean word for it," she said, and he heard the echo of his own phrase from Eleyele and something in his face softened.\nThey stood together in the generator''s hum and the afternoon light came through the gap in the fence in long flat lines and everything was very still and very full at the same time.\n"The letter," she said. "Have you decided what to do?"\nHis face changed. Not dramatically, just a small repositioning, the way a room changes when a window closes. "Not yet."\n"Have you told anyone besides me?"\n"No."\nShe thought about him carrying that letter for a week without anywhere to put it. "You should tell your father."\n"I know."\n"Sometimes," she said, and the words came from a genuine place, a warm and impulsive place that wanted to solve the thing because solving things was what she had been trained to do her whole life inside her mother''s operation, "sometimes it helps to have someone say it alongside you. I could come with you. We could talk to him together, explain the numbers, show him the breakdown."\nThe stillness that followed was immediate and total.\nKayode did not move. Did not speak. She watched something travel across his face that she could not intercept and it moved too fast for her to read and by the time it settled he was looking at the generator and not at her.\n"Kayode," she said.\n"You want to coordinate it," he said. His voice was even. That was the frightening part. It was completely even.\n"I just meant—"\n"I know what you meant." He picked up his bag from the ground beside the shed and straightened. "You meant well."\nThose two words arrived with an exact and terrible weight. She opened her mouth and closed it again.\n"I have to help with the equipment," he said.\nShe knew that sentence. She had been waiting for it since the moment she heard her own words come out wrong, and knowing it was coming did not soften it when it arrived.\nHe walked back toward the band tent without looking back.\nShe stayed against the generator shed with a cold Coke in her hand that she did not remember picking up, and she watched his back disappear into the noise of the reception, and she stood there for a long time, listening to the talking drum running its cascade, and she understood with the slow precision of someone assembling an answer from scattered pieces exactly what she had done.\nShe had looked at the most private thing he owned and offered to manage it.\nShe had turned his wound into logistics.\nThe generator hummed. Someone inside was laughing very loudly at someone else''s happiness.\nShe did not text him that night.\nNeither did he.','\n',char(10)),1031,1,1,NULL,'2026-04-10T20:13:14.538Z','2026-04-10 20:13:14','2026-04-10 20:13:14',NULL,1,29);
INSERT INTO "chapters" ("id","novel_id","chapter_number","title","content","word_count","is_premium","is_published","audio_url","published_at","created_at","updated_at","scheduled_release_at","part_number","season_id") VALUES(349,47,1,'August Ajebo',replace('Fourteen days of nothing and then: Hey.\nOne word. No punctuation. Arriving on a Thursday night at nine forty-three while Teni was lying on her bed staring at the ceiling fan making its slow indifferent rotations. She had read it four times before she accepted that it was real and not a rehearsal of a thing she had been imagining sending herself.\nShe put the phone face-down.\nShe picked it up.\nShe typed: Hey. Then deleted it. Typed: Hi. Deleted that. Typed: You good? and sent it before she could delete that too.\nThree minutes passed. The fan made its rotations. Outside, the street was doing its Thursday evening thing: a motorcycle, someone''s television, the neighbour''s daughter practicing piano badly through an open window, the same eight bars repeated with the patient stubbornness of a child who had been told not to stop until she got it right.\nFine. You?\nFine.\nTwo fines. A combined weight of nothing and everything. She stared at the word on her screen and understood that they were both standing on the same side of a door neither of them knew how to open from this angle.\nShe typed: I am sorry about what I said at Agodi.\nSent it. Put the phone on her chest. Stared at the ceiling.\nThe apology had been in her drafts folder, metaphorically, for all fourteen days.\nShe had written and deleted versions of it across two weeks with the precision of someone editing a piece of work that kept failing its own standard. Too long and it became a speech. Too short and it became a dismissal. She had shown one version to Simi, who had said this is good, send it, which made her immediately distrust it because good and right were not the same category.\nWhat she had finally sent was the plainest version. No explanation attached. Just the acknowledgment.\nHis response took nine minutes, which she did not time but knew anyway.\nI know you were trying to help.\nI know, she typed. That is not the same as it being okay.\nAnother pause. Then: No. It is not.\nShe read that and felt the specific relief of being disagreed with honestly, which was better than being let off a hook she deserved to stay on a little longer.\nCan I ask what it felt like? she typed. When I said it.\nThe three dots appeared. Disappeared. Appeared again. She watched them with the concentrated attention of a person watching a language being assembled in real time.\nLike you saw the most difficult part of my life and your first instinct was to put it on a task list.\nShe closed her eyes.\nYes, she typed. That is exactly what I did.\nYou do it because it is how you were trained, he wrote. I understand that. My father does the same thing with problems. Turn them into logistics. Manage them from the outside. A pause. I just did not want to be a problem.\nYou are not a problem.\nI know that too, he wrote. But I needed one day to feel it again after the thing you said.\nOne day turned into fourteen.\nI know. I am sorry about that part.\nShe lay in the dark with the phone on her chest and the ceiling fan making its rotations and the neighbour''s daughter still fighting the same eight bars, and she felt the conversation settling into something that was not fixed but was at least honest about where the crack was.\nHe called on Saturday morning, which surprised her.\nThey had not called before. Texts had been their medium, with its natural pressure release, its ability to be considered before sending. A call was something else. A call was immediate and unedited and she accepted it on the second ring because hesitating would have been a kind of lie.\n"I went to see my father," he said, without greeting.\nShe sat up. "About the letter?"\n"About the letter."\nShe waited. Outside her window, the street was early and quiet, just the generators starting their morning shifts.\n"He already knew," Kayode said.\nShe went still. "What?"\n"He found the notebook. Two months ago. He did not say anything, he just found it and read it and put it back." A breath. "He has been setting aside money since March. He did not tell me because he did not want me to rearrange my expectations around an amount that might not be enough."\nTeni pressed her free hand flat against her knee.\n"Is it enough?" she asked.\n"Not all of it. But it is a start. He knows a man at the bank." Another breath, this one different, looser. "We talked for three hours. First time we have talked like that since my mother left."\nShe did not know about his mother leaving. He had not told her and she had not asked. She filed it the way she filed the things he was not ready to give yet, carefully, without pressure.\n"Kayode," she said.\n"It was good," he said quickly, and she understood he was not ready for the full response her chest wanted to send across the line. "It was hard and then it was good."\n"Okay," she said. "That is enough."\n"Yes." A pause. "Teni."\n"Yes."\n"The Bodija wedding. It is in eleven days."\nShe looked at the window. The morning was coming in flat and clean and the generators were finding their rhythm and somewhere down the street the same neighbour''s daughter was back at the piano, same eight bars, except this time she got through to the ninth.\n"I know," Teni said.\n"I will be there."\n"I know that too."\nThe call held for three more seconds without words, which was its own kind of sentence, and then he said goodbye and she said goodbye and she sat on the edge of her bed with the phone in her lap and the morning coming through the window and felt the thing between them, still fragile in the places where it had cracked but present, definitively present, like a bone that had broken and was now, slowly and imperfectly, deciding to heal.\nShe went to find her mother in the kitchen.\nMama Teni was at the stove, the radio on low, an event binder open on the counter beside her because her mother''s event binder was always open somewhere, it was a permanent feature of their home like the furniture.\n"The Bodija one," Teni said. "What do you need me to do?"\nHer mother turned from the stove with a measuring look that lasted one second and told Teni she had not forgotten the corridor at Agodi and had been waiting to see what shape that silence would take before deciding anything about it.\n"Everything," her mother said. "Same as always."\n"Okay," Teni said.\nShe sat at the kitchen table and pulled the binder toward her and opened it to the Bodija tab, and she began to read, and her mother turned back to the stove, and the radio played something old and Yoruba and the morning settled around them like a thing that had been waiting for everyone to be ready.','\n',char(10)),1201,0,1,NULL,'2026-04-10T20:25:29.381Z','2026-04-10 20:25:29','2026-04-10 20:25:29',NULL,2,30);
INSERT INTO "chapters" ("id","novel_id","chapter_number","title","content","word_count","is_premium","is_published","audio_url","published_at","created_at","updated_at","scheduled_release_at","part_number","season_id") VALUES(350,47,2,'Jericho Afternoon',replace('The Bodija wedding was supposed to be Wedding #4 but the family postponed it six days before and the Jericho one moved up without warning and Teni found out on a Wednesday evening when her mother dropped a new venue flyer on the dining table and said "Saturday" without looking up from her phone.\nTeni looked at the flyer. Looked at her phone. Texted Kayode: Bodija moved. Jericho is Saturday now. Oke-Ado road.\nHis response came fast: I know. My father got the call this afternoon. Same booking, different address.\nShe looked at that for a moment. Thought about how their lives ran on parallel tracks through someone else''s schedule, how a postponed wedding reshuffled them both without consultation.\nSame window, she typed. Different wall.\nHe sent back a single: Yes.\nThe Jericho venue was a newer hall, the kind built in the last five years with event photography in mind: high ceilings, a marble-effect floor, LED strip lighting along the cornices that could change color on instruction. The family was young money, tech and real estate, and the wedding had the particular energy of people who had planned it like a product launch.\nTeni arrived at seven and her mother arrived ahead of her, which was always the case because her mother did not travel to events so much as materialize inside them. The setup was already sixty percent done when Teni walked through the service entrance. She took her clipboard from the table near the kitchen, reviewed the morning tasks, and began.\nShe was arranging escort cards alphabetically at the reception table when she became aware of someone beside her.\nNot Kayode.\nA girl. Roughly her age, maybe a year older, in a pale yellow dress that said guest but carrying a walkie-talkie that said something else. She was pretty in a deliberate way and she moved through the hall with the proprietary ease of someone who knew the family personally.\n"You are the decorator''s daughter?" the girl said.\n"Coordinator''s," Teni said. "My mother handles logistics."\n"Same thing." The girl said it without malice, which almost made it worse. "I am Remi. The bride is my cousin. I am helping coordinate the bridal party side."\n"Teni."\nRemi glanced at the escort cards. "You know alphabetical by surname or first name?"\n"Surname," Teni said. "Standard for table seating."\n"My cousin wants first name."\n"Then your cousin should have put that in the brief." She paused. "I can redo them. It takes twenty minutes."\nRemi smiled, the smile of someone deciding whether to like you or not. "Leave it. I will tell her after the ceremony." She looked around the hall with the assessing gaze of someone who also knew how to read rooms. "Your mother is good. Everything looks correct."\n"She is the best," Teni said, and did not examine the echo until later.\nShe found Kayode at eleven, in the narrow stairwell at the back of the hall that led to a fire exit nobody was using. It was his find this time, not hers, and she noted the shift with quiet satisfaction. He was learning the vocabulary of venues, the grammar of back corridors and overlooked exits.\n"Remi," he said, when she sat down on the second step.\nShe looked at him. "You know her?"\n"She knows my father. She was talking to him during setup." Something careful in his face. "She asked him if the drummer''s son was helping today."\nTeni was still.\n"He pointed me out," Kayode said. "She looked over for a long time."\n"How long is a long time?"\n"Long enough."\nShe thought about the pale yellow dress and the walkie-talkie and the way Remi had appeared at exactly the escort card table. "She came to find me," Teni said. It was not a question.\n"I think so."\n"Why?"\nHe was quiet for a moment. Then: "I think she has seen us before. She was at Eleyele. I remember the dress, different color but same person."\nTeni felt something move through her that was not quite fear and not quite anger. Something more like the sensation of a private room whose door had been opened from the outside without knocking.\n"She does not know anything," Teni said. "She saw two people working an event."\n"She saw two people sitting on a wall behind the estate garden," Kayode said. "For twenty minutes. During the reception."\nThe stairwell was very quiet. Above them, the LED lights shifted from white to warm gold, the hall responding to some instruction from the DJ''s board.\n"Does that change anything?" she asked.\nHe thought about it seriously, which she had come to understand was his way: he did not answer questions with the first thing available, he answered with the considered thing, even when the considered thing took longer.\n"It changes the feeling of it," he said finally. "Not the thing itself. But the feeling."\nShe understood that completely. The thing between them had existed in back corridors and generator sheds and narrow stairwells, in spaces no one was paying attention to. The moment someone paid attention, it became a different kind of object. Still real. But newly exposed. Like a photograph developed from a negative that had only ever lived in the dark.\n"What do we do?" she asked.\n"Nothing," he said. "We are not doing anything wrong."\n"I know."\n"Then we do not act like we are."\nShe straightened. He was right and she knew he was right and the knowing sat beside a separate and inconvenient truth, which was that being seen changed things even when it changed nothing. Her mother had looked at her in that Agodi corridor with an expression that had not been repeated or referenced but had not disappeared either. It was somewhere in the house, that look, living in the space between them.\nFootsteps above them on the stairs. They separated without discussion, the instinct of people who had spent their lives reading the approach of adults in event venues. The fire exit door opened one floor up and a catering staff member came down carrying empty trays, looked at them both without interest, and continued past to the ground floor.\nNeither of them spoke for a moment.\nThen Kayode said, quietly: "I brought you something."\nShe looked at him. He reached into his backpack and produced a small takeaway container of puff puff, folded closed at the top.\nShe looked at the puff puff and then at him.\n"From the woman outside the gate," he said. "I saw you walk past her twice this morning without stopping and I thought you had probably not eaten."\nShe took the container. The puff puff was still faintly warm. She opened it and ate one and it was exactly what it was, simple and sufficient and bought with the particular attention of someone who had been watching her the way she had been watching him: carefully, quietly, across the distance of other people''s celebrations.\n"Thank you," she said.\n"Eleven days to Bodija," he said.\n"Ten now," she said. "It is past midnight somewhere."\nHe smiled. She smiled back. Above them the hall shifted from gold to a soft rose, the color of something beginning or ending, and the talking drum started from behind the main hall door, low and deliberate, feeling its way into the afternoon.','\n',char(10)),1223,0,1,NULL,'2026-04-10T20:27:15.083Z','2026-04-10 20:27:15','2026-04-10 20:27:15',NULL,2,30);
INSERT INTO "chapters" ("id","novel_id","chapter_number","title","content","word_count","is_premium","is_published","audio_url","published_at","created_at","updated_at","scheduled_release_at","part_number","season_id") VALUES(351,47,3,' Wetin You Want',replace('Remi found her at the gift table.\nTeni was logging envelopes into her mother''s ledger, the careful work of recording names and amounts that required enough concentration to justify not looking up. She heard the pale yellow dress before she saw it, the particular sound of someone approaching with direction and intention.\n"Your mother is looking for you," Remi said.\nTeni checked her phone. No message from her mother. She looked up. "She texted me?"\n"I told her I would find you." Remi set her walkie-talkie on the table with the ease of someone who owned surfaces. "I wanted to talk to you first."\nTeni put the pen down. She gave Remi her full attention, which was the thing she did when she wanted to understand the shape of something before deciding what to do with it.\nRemi was not hostile. That was the first thing. Her face was composed and direct and she had the look of someone who had decided to say a thing and was now simply executing the decision.\n"The boy," Remi said. "The drummer''s son."\n"Kayode," Teni said.\n"You are close."\nIt was not a question but it wore the shape of one. Teni recognised the construction. She used it herself sometimes. "We are friends," she said.\n"I have seen you," Remi said. "Eleyele. Agodi. Today." She paused. "I have a good memory for faces."\n"I know," Teni said. "You told me."\nRemi looked at her with something that recalibrated slightly, the recognition of a person meeting more precision than they anticipated. She picked up her walkie-talkie and held it without using it.\n"My aunt," she said. "The bride''s mother. She noticed you both at Agodi. In the corridor." Another pause. "She mentioned it to your mother."\nThe gift table was very still.\nTeni did not move her face. She was her mother''s daughter in at least this one way: she had learned to receive information without giving the information anything back until she was ready.\n"What did she say?" Teni asked.\n"That she saw a boy and a girl sitting together in the staff corridor. That the girl looked like the coordinator''s daughter." Remi''s voice was not cruel. It was careful, actually, in the way of someone delivering a thing they knew had weight. "I do not know what your mother did with that."\nTeni thought about the morning after Agodi. Her mother at the stove, the event binder open, the look that had lasted one second and said everything and nothing. The question she had not asked. The answer Teni had not given.\n"Why are you telling me?" Teni asked.\nRemi was quiet for a moment. She looked across the hall to where the reception was moving into its next phase, the MC warming up the crowd, the families being arranged for the money spray.\n"I was sixteen once," she said. "At my cousin''s first wedding. A boy from the caterer''s family. We talked in the back garden for an hour and someone told my mother before we even exchanged numbers." She looked back at Teni. "Nothing happened. But the telling made it into a thing it was not yet."\nTeni absorbed this.\n"I am not your enemy," Remi said. "I just thought you should know the timeline."\nShe picked up her walkie-talkie and walked back toward the bridal party section, pale yellow moving through the crowd with the ease of someone who had said what they came to say and had no further business.\nTeni found Kayode behind the hall near the drainage channel that ran along the back fence, where the caterers had set up the overflow gas burners and the air smelled like groundnut oil and hot metal. She pulled him three steps away from the nearest caterer and told him everything in a low fast voice, the way her mother briefed staff before a critical moment: no unnecessary words, sequence intact, tone level.\nHe listened without interrupting.\nWhen she finished, he was quiet for a count of six.\n"Your mother knows," he said.\n"She might have known since Agodi."\n"And she said nothing."\n"She said nothing," Teni confirmed.\nHe looked at the drainage channel, at the water moving slowly along the concrete. "What does that mean?"\n"I do not know yet." She paused. "It means she is deciding something. My mother does not react. She waits until she has the full picture and then she acts."\n"That is frightening."\n"Yes," Teni said. "She is very good at her job."\nSomething moved across his face, not quite a smile but related to one. It dissolved quickly. "What do we do?"\n"Remi said to know the timeline. I think what she meant was: do not let someone else define this before we do."\nHe looked at her. "Define it how?"\nAnd there it was, the question underneath the question, the one that had been building since a concrete step at a coral gate venue in April. She felt it arrive with the full weight of everything that had been accumulating across five months and four venues and a thousand small honest exchanges.\nShe looked at him. He looked at her.\nAround them the kitchen noise continued, the burners, the caterers moving, the distant sound of the hall building toward its climax.\n"Wetin you want, Teni," he said, soft and direct, the Pidgin dropping the formality the way Pidgin did, cutting to the real thing underneath the English.\nShe breathed.\n"I want this to be what it actually is," she said. "Not a secret we are managing. Not a thing in a corridor. I want to know what it is and I want it to have a name."\nHe was very still.\n"I have not had many things that were only mine," she said. "At these events. In this life. Everything I do is for someone else''s occasion. I do not want this to be that." She paused. "I want it to be mine."\nThe question of what he wanted sat between them without being asked because she could see him assembling it from the inside, the way he assembled everything: methodically, honestly, without rushing the answer to arrive before it was ready.\n"I want the same thing," he said. "I have wanted it since Eleyele." A pause. "I was afraid that wanting something for myself was not available to me right now. With UI, and my father, and everything." He looked at the drainage channel. "Then I realised I was using the difficult things as a reason not to ask for the good ones."\nShe felt something in her chest unlock quietly, the way a window opened when you had not realised the room was short of air.\n"Kayode," she said.\n"Yes."\n"I am not going to try to coordinate your life," she said. "I need you to know that. What I said at Agodi, I understand why it was wrong. I am not going to do it again."\n"I know," he said. "And I am not going to disappear for fourteen days again because I do not know how to say a hard thing."\n"Good."\n"Good."\nThe back door of the hall swung open and a junior caterer came out with a stack of empty trays and moved past them without interest, and the noise of the reception spilled out briefly and then was sealed away again.\nKayode looked at her with the full open attention that she had been collecting since April, cataloguing in notes she kept to herself, and said: "So."\n"So," she said back.\n"We should go back inside," he said. "Before your mother comes looking."\n"Yes."\nNeither of them moved for another ten seconds, standing in the groundnut oil air beside the drainage channel while the Jericho afternoon held them in its flat honest light.\nThen she turned and walked back toward the hall door.\nHe fell into step beside her, close enough that their arms were almost touching, and they walked that way, not holding anything, not announcing anything, just moving through the back of someone else''s wedding in the full quiet knowledge of what they had just become to each other.\nThe door swung open.\nThe music came out to meet them.','\n',char(10)),1368,0,1,NULL,'2026-04-10T20:28:22.872Z','2026-04-10 20:28:22','2026-04-10 20:28:22',NULL,2,30);
INSERT INTO "chapters" ("id","novel_id","chapter_number","title","content","word_count","is_premium","is_published","audio_url","published_at","created_at","updated_at","scheduled_release_at","part_number","season_id") VALUES(352,47,4,'Her Mother''s Daughter',replace('Her mother chose a Sunday.\nNot a wedding Sunday, which was the only reason Teni was home and present and without a clipboard to hide behind. It was the kind of Ibadan Sunday that arrived with full intention: rice on the stove by ten, the neighbor''s church audible through the window, the ceiling fan on its second speed. The kind of Sunday that had nowhere to be and therefore nowhere to escape to.\nTeni was at the dining table with her Literature notes when her mother came out of the kitchen, turned off the radio, and sat down across from her.\nShe did not bring the event binder.\nThat was the first sign.\nHer mother looked at her for a moment without speaking, which was a technique Teni recognised because she had inherited it. Let the silence do the first work. Let the other person feel the shape of what is coming before it arrives.\n"The Agodi corridor," her mother said.\nTeni put her pen down.\n"Mrs. Fashola told me," her mother continued. "The bride''s aunt. She was not unkind about it. She said she saw two young people sitting and talking and she thought I should know." A pause. "That was three weeks ago."\n"You waited," Teni said.\n"I needed to think." Her mother folded her hands on the table. "And I needed to watch."\n"Watch what?"\n"You." She said it plainly. "How you moved at Jericho. What your face did when the band arrived. Where your attention went when you thought I was not looking."\nTeni said nothing. The rice on the stove made its quiet sounds.\n"He is the gangan player''s son," her mother said. "Kayode."\nHearing his name in her mother''s mouth was a particular sensation, like a private object being picked up by someone else''s hands, handled carefully but still foreign.\n"Yes," Teni said.\n"How long?"\n"Since the first wedding. April."\nHer mother absorbed this without visible reaction. She was very good at that, receiving information before deciding what to do with it.\n"Teni," she said. "Talk to me."\nAnd there it was. Not a command. Not the coordinator voice or the logistics voice or the no-temperature voice. Just her mother, at a table with no binder, asking to be let in.\nTeni looked at her hands. Looked up.\n"He is the only person my age who understands this life without me having to explain it," she said. "The weddings. The working. The being present at everything and belonging to nothing." She paused. "When I am with him I am not invisible. I am not a nail inside a wall. I am just a person."\nHer mother was quiet for a long time.\n"Nail inside a wall," she said softly.\n"I did not mean—"\n"No." Her mother lifted a hand. "Say it. You meant it."\nTeni breathed. "I love what you built. I know what it cost. I know you did it alone and I know it is extraordinary." She looked at the table. "But I have been to two hundred weddings and never once danced until that praise singer called me out at Agodi. And even that was not mine. It was your commendation. I came with it."\nHer mother did not look away. She had the face now of a woman receiving a truth she had possibly known for a long time and had been waiting for the other person to find the words for.\n"I was twenty-two," her mother said, "when I started the business." She said it not as a defence but as a beginning. "Your father had just left and you were three years old and I had four hundred naira and a contact who needed someone to coordinate his sister''s wedding in Bodija." She looked at the window. "I was invisible at that wedding too. I was invisible at the next thirty." A pause. "But I was building something. That is what I told myself."\n"You did build something," Teni said. "That is real."\n"Yes. But you are asking me whether I got lost inside the building." Her mother looked at her directly, and her eyes had something in them that Teni had not seen there before, or had seen but never had the vocabulary for: the specific tiredness of a person who had been competent for so long that competence had become the only available identity. "I think sometimes I did."\nThe Sunday settled around them, the rice, the fan, the distant church.\n"I do not want you to stop," Teni said carefully. "The business. This life. I know it is us. I just want there to also be something that is me."\n"Kayode," her mother said.\n"Kayode," Teni confirmed. "And other things. Journalism. My own thoughts. A dance floor I walk onto because I chose it."\nHer mother looked at her for a long time with an expression that moved through several rooms before settling.\n"I want to meet him," she said finally.\nTeni blinked. "What?"\n"Properly. Not a corridor. Not me walking through a door and seeing what I am deciding not to see." Her mother unfolded her hands and placed them flat on the table. "If he is important to you then I want to know who he is."\n"He is good," Teni said, and the simplicity of it surprised even her, how much it covered, how accurately it landed.\n"I did not ask if he was good," her mother said. "Good is the beginning of the evaluation, not the conclusion." But there was something in her face when she said it, a loosening, slight and real.\nShe stood and went back to the kitchen to check the rice.\nTeni sat at the table with her Literature notes and her pen and the Sunday filling the room around her, and she felt something she did not immediately have a word for. Something that lived between relief and grief and gratitude. The particular feeling of a conversation that had been approaching for a long time finally arriving and being, against all expectation, survivable.\nShe picked up her phone. Texted Kayode.\nMy mother wants to meet you.\nShe put the phone face-up this time.\nHis response took four minutes.\nOkay, he wrote. Then: Is that good or should I be afraid.\nShe looked at the kitchen doorway, at her mother moving with her particular focused grace, one hand lifting the pot lid, the other already reaching for the spoon.\nBoth, she typed. She is very good at her job.\nShe heard him in the single character he sent back:\nHa.\nShe put the phone down. Picked up her pen. The Literature notes were still open to the same page about narrative voice, the same page she had been failing to read since August. She read it now, the whole page, and this time every word went in.','\n',char(10)),1140,1,1,NULL,'2026-04-10T20:29:48.070Z','2026-04-10 20:29:48','2026-04-10 20:29:48',NULL,2,30);
INSERT INTO "chapters" ("id","novel_id","chapter_number","title","content","word_count","is_premium","is_published","audio_url","published_at","created_at","updated_at","scheduled_release_at","part_number","season_id") VALUES(353,47,5,' The Last Reception',replace('The meeting happened on a Wednesday, six days before the New Bodija wedding, at a buka on Mokola roundabout that Teni had chosen because it was neutral ground and because the pepper soup was serious enough to occupy hands and mouths during difficult silences.\nKayode arrived seven minutes early, which she knew because she was already there and watched him come through the door in a clean white kaftan that told her he had thought about what to wear and landed on something that was respectful without being a performance. He saw her and came over and sat down and said "good afternoon" to her mother with the directness of someone who had decided that confidence was more honest than deference.\nHer mother looked at him for three full seconds before responding.\n"Good afternoon," she said. "You are early."\n"Yes ma." A pause. "I did not want to make you wait."\nHer mother nodded once, the nod of a woman filing information. She picked up the menu.\nTeni looked at her hands under the table and told herself to breathe.\nThe pepper soup arrived and with it a conversation that moved like her mother planned events: structured underneath, apparently casual on the surface. She asked about his school, his father, his plans. He answered without shrinking, without overselling, with the particular honesty of a person who had decided the truth was the only sustainable position.\nWhen he talked about UI he did not look at Teni for rescue. He looked at her mother and said: "The admission is confirmed. The fees are mostly arranged. My father and I are working the balance through a bank contact." A pause. "It will happen."\nHer mother held his gaze. "You are certain."\n"I am working to make the certainty true," he said. "That is the most honest answer I can give you."\nSomething in her mother''s face shifted, slight and real, the particular shift of a woman who valued precision and had just received it from an unexpected direction.\n"My daughter says you understand this life," her mother said. "The events. The working."\n"My father has played at events since before I was born," Kayode said. "I grew up in the back areas. Service entrances, generator sheds, back corridors." He glanced at Teni once, brief and warm. "That is where I met her."\n"I know where you met her," her mother said.\nA silence. The buka moved around them, other tables, other conversations, a television in the corner showing a news channel nobody was watching.\n"I am not asking you to stop," her mother said finally. "I am asking you to be careful with her." She said it without sentimentality, in the voice she used for important instructions. "She is not a back corridor person. She has never been. She has just been placed in back corridors her whole life and learned to make them work." Her eyes moved to Teni. "That stops being a skill and starts being a limitation if nobody names it."\nTeni felt the words arrive in her chest and stay there.\nKayode said: "I know that, ma. That is not how I see her."\n"How do you see her?"\nHe did not hesitate. "Like someone who should be at every table she has ever set."\nHer mother looked at him for a long moment. Then she picked up her pepper soup spoon and said: "Eat before it gets cold."\nThe New Bodija wedding was the largest of the season.\nTeni had known this since her mother first showed her the brief in June: five hundred guests, a venue that had hosted a senator''s daughter the previous year, a catering team of forty, a live band plus DJ plus a special appearance by an Ibadan musician whose name alone guaranteed attendance. The kind of wedding that required her mother''s full operational capacity and left no margin for anything else.\nThey arrived at six-fifteen in the morning.\nThe sky was the particular dark blue of very early Ibadan, before the generators fully committed to the day, before the heat remembered itself. Teni carried two bags from the car and stood outside the venue entrance for a moment, looking up at the building with its white facade and the soft lights already on inside.\nShe had stood outside venues like this her whole life and always felt the same thing: the before, the quiet before the event machine started, the moment when the space was still empty enough to be honest about what it was, just walls and chairs and borrowed light.\nHer mother appeared beside her.\nThey stood together for a moment, not saying anything.\n"Ready?" her mother said.\n"Yes," Teni said.\nThey went in.\nThe band arrived at eight.\nShe did not go to find him. She was carrying a full morning of tasks and her mother needed her properly present, and they had spoken the night before, a long call that had moved between practical and private the way their conversations did, and there was an understanding between them that today was different, that today required both of them to be what they were at events, workers first, themselves in the margins.\nShe saw him at ten-fifteen across the main hall, helping two band members position a speaker. He did not see her. She watched him for four seconds from the far side of the room: the careful attention he brought to the physical work, the notebook in his back pocket, the white kaftan exchanged now for a plain navy shirt that had been ironed carefully.\nHe looked up.\nFound her across the hall the way people found each other when they had been paying attention long enough.\nHe did not wave. Neither did she. But something passed between them across the noise and distance of the hall that was its own kind of language, the one they had been building since April in back corridors and on concrete steps.\nShe turned back to her work.\nAt two o''clock, the reception was at full height.\nThe musician had arrived and the hall had responded by becoming something close to collective joy: the music physical, the dance floor dissolving the boundary between family sections, the spray of naira creating its own choreography. Teni''s mother was at the coordinator''s table near the entrance, managing the second half of the event with the quiet authority of a woman in her exact right place.\nTeni was at the back of the hall near the service corridor door, tasks complete, watching.\nShe was watching the dance floor. Watching the way the families moved through the music without thinking about it, the way the joy was just available to them, all the way through.\nShe was watching and she was feeling the familiar edge of it, the almost, the glass wall between her and the thing she could see but never quite touch, when the service door opened behind her and Kayode came through and stood beside her.\nThey stood together at the back of the hall watching the dance floor.\n"Last one," he said.\n"Last one," she said.\nThe music built toward something, the musician reading the room and lifting it, and the hall answered.\nKayode turned to her.\n"Teni," he said. "Dance with me."\nShe looked at him. At the crowded hall. At the dance floor full of guests in asoebi.\n"We are working," she said.\n"Your mother''s tasks are done. My father does not need me for twenty minutes." He held out his hand, open, waiting. "One song. Inside it this time. Not watching from the edge."\nShe looked at his hand.\nShe looked at the dance floor.\nShe thought about ninety seconds at Agodi and how it had felt like a door opening inside her body. She thought about her mother that Sunday: I think sometimes I did get lost. She thought about Remi in the pale yellow dress and the caretaker''s shed and the boys'' quarters behind the first coral gate and Kayode''s notebook with its red numbers slowly turning black.\nShe thought about all the back corridors she had ever found and learned to call enough.\nShe took his hand.\nThey walked to the edge of the dance floor and then past the edge, past the almost, past the glass wall, and onto it, and the music received them the way music received everyone, without condition, and they danced, badly at first because being inside the thing you had only watched required an adjustment, but then better, and then good, and the hall moved around them with its full borrowed joy and for the first time in sixteen years of weekends Teni was not watching someone else''s celebration from a back corridor.\nShe was inside it.\nShe was a person inside a moment that was entirely hers.\nShe looked at Kayode and he was already looking at her, and the talking drum was doing what it did, and the naira was falling like approval from all directions, and her mother was somewhere behind her and was either watching or was not watching and either way the dance floor held.','\n',char(10)),1521,1,1,NULL,'2026-04-10T20:30:52.323Z','2026-04-10 20:30:52','2026-04-10 20:30:52',NULL,2,30);
INSERT INTO "chapters" ("id","novel_id","chapter_number","title","content","word_count","is_premium","is_published","audio_url","published_at","created_at","updated_at","scheduled_release_at","part_number","season_id") VALUES(354,47,6,'Own Joy',replace('Nobody stopped the world when they walked off the dance floor.\nThat was the thing Teni noticed first. She had half expected something: her mother''s voice, a vendor emergency, the specific interruption that events always produced at the wrong moment. But the hall continued exactly as it had been, five hundred people in full celebration, the musician still reading the room, the naira still falling, the joy still borrowing nothing from anyone.\nShe and Kayode came off the floor and stood at the edge, breathing.\n"You can dance," he said.\n"I told you. Agodi."\n"Agodi was ninety seconds. That was three songs."\nShe looked at the floor, then at him. "You counted."\n"I was paying attention." He was not quite smiling but the thing around his eyes was doing it for him.\nHer chest was still moving from the music, from the dancing, from the specific exertion of being fully present inside something for the first time in a long time. She felt it the way you felt a muscle you had not used in years: the proof of it, the mild pleasant ache.\n"Teni."\nShe turned.\nHer mother was standing two steps away.\nNot with a clipboard. Not with the coordinator face. Just standing, in her full event uniform, looking at her daughter the way she had looked at her on that Sunday at the dining table: open, present, without the logistics layer over it.\nShe looked at Kayode briefly. He straightened slightly, not from fear, from respect.\nHer mother looked back at Teni. "The bride is asking for the head coordinator''s daughter," she said. "She wants to say thank you. Personally."\nTeni blinked. "For what?"\n"The escort cards. She said they were the most organised she has seen at any event." Her mother paused. "Also she saw you dancing and said you looked like someone who deserved to be at the party."\nThe sentence arrived with more weight than its words. Teni held it.\n"Go," her mother said. "She is at the high table."\nThe bride''s name was Funke and she was twenty-eight and radiant in the particular way of people whose happiness was currently too large for their face to contain all at once. She took both of Teni''s hands when she arrived at the high table and said: "Your mother is the best in Ibadan and you are going to be better."\nTeni said: "Thank you ma."\n"Do not thank me. Hear it." Funke squeezed her hands once and released them. "What are you going to study?"\n"Communications. Journalism, hopefully."\n"Good." Funke nodded with the authority of someone who had learned that encouraging young women was also a form of event planning: you arranged the conditions and then you let the thing happen. "Tell your mother I will refer her to every family I know."\nShe turned back to her high table. The audience was over. Teni stood for a moment beside the high table, at the edge of the raised platform, and looked out over the reception hall from that particular elevation.\nShe had set every table she could see from here. She knew the cost of the centrepieces, the vendor who had delivered the chairs, the caterer''s name, the fault line in the seating chart that she had repaired at seven-thirty this morning. She knew the structure underneath the celebration the way you knew the bones underneath a person, invisibly, essentially.\nAnd now she was standing above it, looking down at it, and it was hers in a way it had never been before. Not because she owned it. Because she understood it. Because she had earned the view.\nShe came down from the platform and walked back through the hall.\nThe last hour of the event had the particular texture of endings: the caterers beginning their quiet dismantling, the older guests filtering out, children asleep across their mothers'' laps, the DJ bringing the music down from its peak toward something slower and survivable. The hall breathed out.\nTeni found Kayode at the service entrance helping load equipment onto the band''s bus. She stood at the door and watched him work for a moment, the easy competence of it, the way he moved with his father''s team as a natural part of the unit, talking and lifting and directing without drama.\nHis father noticed her first.\nHe was a tall man, same jaw as Kayode, same quality of stillness, with the particular physicality of someone who had been playing drums since before his body finished deciding what it was. He looked at her without expression and then looked at Kayode and back at her and said something to Kayode in a low voice.\nKayode turned. Saw her. Said something back to his father.\nHis father looked at her for one more second, then nodded, the nod of a man completing a calculation, and went back to the equipment.\nKayode came to the door.\n"He knows?" she asked.\n"He has known since Eleyele," Kayode said. "He said he was waiting to see if it was real or just summer."\nShe absorbed this. "What did you tell him?"\n"I told him it was real."\nThe service entrance held them in its plain fluorescent light. Behind him the bus was almost loaded, the season''s final equipment going home. Behind her the hall was coming down from its height, the last of the celebration finding its edges.\n"So," she said.\n"So," he said.\n"What happens now? After the last wedding."\nHe thought about it honestly, which was always his way. "School starts in six weeks. I will be in UI." He looked at her. "You are in Lagos."\n"Queens College is two more terms," she said. "Then JAMB. Then hopefully University of Lagos."\n"Hopefully," he said.\n"Likely," she corrected.\nHe smiled. The real one, unguarded and quick. "Likely."\nThey stood with the practicalities of it, not as obstacles but as facts to be arranged, the way two people arranged things when they had decided the thing was worth arranging for.\n"It does not end because the summer ends," he said.\n"No," she agreed. "It does not."\n"I will be in Ibadan for holidays. You will be here when Queens College breaks."\n"And we have phones."\n"We have phones," he confirmed.\nShe looked at him in the fluorescent light, at the notebook visible in his back pocket, at the navy shirt that had been ironed carefully, at his face that she had been reading since April and was still, pleasantly, not finished learning.\n"Kayode," she said.\n"Yes."\n"Your numbers. The last column."\nHe understood. "Still working on it. But getting there."\n"When it goes black," she said, "I want to be the first person you tell. Not because I am going to do anything with the information. Just because I want to know."\nHe looked at her for a long moment.\n"Okay," he said. It was a small word carrying a large and careful meaning.\nHer mother was at the coordinator''s table when Teni returned, writing in the event binder with the focused attention of someone closing out a season. Around her the venue crew moved, chairs being stacked, lights being taken down, the scaffold of the celebration being disassembled to reveal the plain hall underneath.\nTeni sat down beside her.\nHer mother did not look up but shifted the binder slightly in her direction, an old gesture, the one that meant: you can look.\nTeni looked. The season''s accounts, color-coded, final. Eight events. Every one profitable. Every one completed. Her mother''s name on every page in the small careful handwriting of a woman who had built something from four hundred naira and a contact in Bodija and had not stopped building since.\n"Mama," she said.\nHer mother looked up.\n"When I have my own thing," Teni said, "I want you to teach me how you did this."\nHer mother was quiet for a moment. Something moved across her face that was not quite any of the faces Teni knew, it was newer than all of them, softer at the edges.\n"You already know most of it," her mother said. "You have been learning it since you were six years old."\n"I know the logistics," Teni said. "I want to know the other part. The part where you decided it was yours."\nHer mother looked at her. The hall settled around them, quieter now, most of the guests gone, the lights coming down from event brightness to something plain and sufficient.\n"That part," her mother said, "took me longer than it should have." She closed the binder. "Do not wait as long as I did."\nShe stood, picked up the binder, and walked toward the exit to supervise the final equipment load. Teni watched her go, this woman who had built an entire world out of other people''s celebrations and who was, imperfectly and precisely and on a schedule entirely her own, learning to step back inside it.\nTeni sat alone at the coordinator''s table in the emptying hall.\nShe was sixteen. She had been to more weddings than most women twice her age. She knew how to spot a venue that had overbooked its chairs, how to read an asoebi color arrangement from across a compound, when to use the no-temperature voice and when to use the nod.\nShe also knew, now, what a dance floor felt like from the inside.\nShe knew what it felt like when someone looked at you across a crowded hall and found you before you had finished looking.\nShe knew that you could grow up invisible and still, if you were paying the right kind of attention, find someone who saw you exactly.\nShe picked up a leftover program from the table. The bride and groom smiled up at her from the cover, coral flowers around the border, their names in gold.\nShe put it back down.\nShe picked up her own pen.\nShe opened her notebook, the small one she had started keeping in July, not for logistics, not for task lists, for the other kind of notes, the ones her mother did not make and Kayode had been making all his life.\nShe wrote: Own joy is not the absence of someone else''s. It is just something you have to choose.\nShe read it back.\nThen she closed the notebook, put the pen in her pocket, and walked out of the hall into the late Ibadan evening, where the generators were winding down and the sky was doing what the Ibadan sky did at the end of long days: turning the specific orange of a place that had held a lot of heat and was finally, generously, letting it go.\nShe stood outside and breathed it in.\nIt was hers.\n\n\n\nEVERY TABLE I EVER SET— Season Two: Complete.\nFull series: Complete.','\n',char(10)),1801,1,1,NULL,'2026-04-10T20:33:57.573Z','2026-04-10 20:33:57','2026-04-10 20:33:57',NULL,2,30);
INSERT INTO "chapters" ("id","novel_id","chapter_number","title","content","word_count","is_premium","is_published","audio_url","published_at","created_at","updated_at","scheduled_release_at","part_number","season_id") VALUES(368,49,1,' Arrival',replace('The bus driver prayed out loud before he started the engine.\nEmem had not expected that. She shifted her bag to her lap, looked at her hands, and said nothing while the man at the front of the vehicle bowed his head and asked God to hold the road steady under their wheels. Half the passengers echoed his amen. She moved her lips without sound.\nThe bus pulled out of the Akpabuyo park just before eight in the morning and Emem watched her town let go of her through the window. Rooftops. A woman selling groundnut at a junction. The secondary school she had walked past a thousand times without ever really looking at. Then bush, and sky, and the long road to Calabar.\nShe was sixteen years old and this was the first time she was making this trip alone.\nAfiong had called three times the night before. Had she packed enough? Was she taking the correct bus? Did she have the address saved somewhere that was not just in her head? Emem had answered every question with yes and tried not to sound impatient. After the call ended she lay in the dark of her room and thought about what Afiong had said in a different conversation, months earlier.\nHe is not like the others, Emem. This one is different.\nShe had said it carefully. Like someone who had been wrong before and knew it, and was choosing to believe anyway.\nThe bus reached Calabar before noon.\nAfiong''s flat was on the third floor of a building just off IBB Way. Emem counted the stairs twice because the first time she lost count. She knocked and heard movement inside, quick footsteps, and then the door opened and her sister was standing there looking like a different version of herself.\nNot different in a way Emem could point to. Same face. Same voice when she said her name. But something in her posture had changed. She was standing like someone who was not bracing for anything.\n"You carried all this by yourself?" Afiong took the bag off her shoulder without asking and pulled her inside.\nThe flat was small but clean, the kind of clean that took effort. Curtains drawn halfway against the afternoon heat. A ceiling fan turning slowly overhead.\nEmem was still looking around when she heard the front door.\nA measured close. Footsteps. Then a voice.\n"Traffic on IBB was bad today."\nEdem walked in still loosening his tie, a nylon bag of groceries in his other hand. He was taller than Emem had imagined from photographs. His face was open, unhurried. He saw her and smiled the way people smiled when they had been told good things about someone and were glad to find them real.\n"Emem. You made it." He set the groceries down and extended his hand. "Afiong has been talking about this visit since last month."\n"Thank you for having me."\n"This is your house." He said it simply, the way people said things they actually meant.\nShe watched him cross to the kitchen and lift the pot cover. He said something under his breath. Approval. Then he turned to Afiong.\n"You made banga?"\n"You said you were craving it."\n"Three days ago."\n"I remembered."\nSomething passed between them. Not words. Just a look that lasted two seconds before Afiong turned back to the plates. But Emem was standing close enough to catch it.\nShe looked away.\nDinner was small and easy. Edem asked about her school, her friends, what she was reading. He listened when she answered. Not the way adults listened while waiting for her to finish, but actually listened. When she mentioned her Geography teacher dictated too fast, he laughed a real laugh and said his own teacher used to go so quickly that half the class just wrote rubbish to fill the page.\nAfiong watched him tell the story with a smile she probably did not know she was wearing.\nLater, Emem lay on the guest mattress with the fan turning above her and listened to the sound of her sister''s voice through the thin wall. Low and unhurried. She could not make out words. Just the sound of two people easy with each other before sleep.\nAfiong had once sat on their mother''s floor with her shoes still on and said she was tired of loving people who treated love like something they could set down whenever it suited them. She had said it quietly. Emem had been twelve and had not known what to do with it.\nShe turned onto her side.\nShe was happy for her sister. She was sure of it.\nBut there was something else underneath she had no name for yet. Small and unsettled. Like a sound she had heard once and could not place.\nShe closed her eyes.\nShe did not know that in four days she would be standing in the dark of this same flat, holding a phone that did not belong to her, reading something she was never meant to read.\nNot yet.','\n',char(10)),845,0,1,NULL,'2026-04-14 17:06:34','2026-04-12 13:56:18','2026-04-14 17:06:34',NULL,1,32);
INSERT INTO "chapters" ("id","novel_id","chapter_number","title","content","word_count","is_premium","is_published","audio_url","published_at","created_at","updated_at","scheduled_release_at","part_number","season_id") VALUES(369,49,2,'The Good Husband',replace('Emem woke to the sound of someone trying very hard not to make noise.\nShe lay still for a moment, listening. Careful footsteps in the corridor. The soft clink of a cup being set down rather than placed. A tap running briefly and then cut off. She turned onto her back and stared at the ceiling. The fan had been switched off at some point in the night and the morning was already warm.\nShe checked the time on her phone. Six forty-three.\nWhen she opened the bedroom door, she found Edem in the kitchen, still in his house clothes, cracking eggs into a bowl. He looked up.\n"Morning. Did I wake you?"\n"No," she said, which was not entirely true.\n"Sit. I''m making omelette."\nShe sat at the table and watched him work. He moved through the kitchen like someone who had spent real time there. Not performing. Not making a show of helping. Just cooking, the way a person cooked when it was simply part of their morning.\n"Afiong still sleeping?" Emem asked.\n"She had a hard week at the office." He cracked the last egg. "Saturday is the one day I don''t let her wake up before nine."\nHe said it without looking up. Matter of fact. Like it was a rule he had made for himself a long time ago and saw no reason to explain.\nEmem looked at the table.\nAfiong came out just before nine, wrapper tied loose, hair undone, the way she only looked when she felt safe. She saw the covered plate at her usual chair and looked at Edem.\n"You cooked."\n"Emem helped."\n"I did not," Emem said.\nAfiong laughed, a full laugh, the kind that reached her eyes. Emem had not heard that laugh in a long time.\nThey spent the morning indoors. Edem fixed a cabinet hinge that had been loose for weeks, the kind of small task that sat on a list until someone decided it was finally the day. Afiong sat nearby folding laundry and they talked about nothing in particular. A neighbor''s new car. Whether the rain would come early this year. A film Edem had fallen asleep watching twice and still had not finished.\nEmem sat close and pretended to look at her phone.\nIn the afternoon, Edem said he had to run an errand and asked if they needed anything from the market. Afiong gave him a list written on the back of a receipt. He read it, folded it, put it in his pocket.\nAt the door he turned back.\n"Afiong."\nShe looked up from the couch.\n"The one with the green wrapper or the yellow one? Because she only specified wrapper and I will come back with the wrong thing if you don''t tell me now."\nAfiong blinked. Then she pressed her mouth together, trying not to smile. "Green."\n"Thank you." He left.\nEmem waited until his footsteps faded on the stairs.\n"He reads your shopping lists."\n"He reads everything I write," Afiong said. "The first time I gave him a list he called me from the market four times."\n"Because he wanted to get it right?"\n"Because he wanted to get it right."\nAfiong said it plainly, the same way Edem had said things all morning. Without decoration. Like she was still slightly surprised by it herself and had decided the only way to carry it was quietly.\nEmem looked down at her phone.\nShe thought about the men who had come before Edem. She had been too young to understand most of it but she had understood enough. The way Afiong used to sound on phone calls in the next room, careful and small, like someone trying to take up less space. The way she came home for Christmas one year and smiled too much and laughed too fast and their mother had watched her without saying a word.\nEdem came back from the market with the green wrapper, a bunch of unripe plantain nobody had asked for, and a small bag of chin chin he held out to Emem when he walked in.\n"The woman said they''re fresh today."\nEmem took them.\nThat evening, she sat on the balcony while Afiong and Edem cooked together inside. She could hear them through the open window. His voice asking where the crayfish was kept. Afiong saying the same place it had always been. Him saying he was certain it had moved. Her saying nothing in the flat had moved. A brief silence. Then both of them laughing at something she had missed.\nThe street below was settling into its evening noise. Generators starting. Children called in for dinner. A hawker moving his cart slowly past the gate.\nEmem ate her chin chin one at a time.\nShe had spent the whole day watching Edem and she had not found a single crack. Not one moment where the warmth slipped and something colder came through. He was the same at six in the morning as he was at seven in the evening.\nHer sister deserved this. She was certain of it now in a way she had only suspected before.\nShe put the last piece of chin chin in her mouth and listened to them laughing inside.\nShe fell asleep to the sound of them laughing in the kitchen. She did not know it was the last time she would hear it.','\n',char(10)),900,0,1,NULL,'2026-04-30 14:23:04','2026-04-12 13:57:34','2026-04-30 14:23:04',NULL,1,32);
INSERT INTO "chapters" ("id","novel_id","chapter_number","title","content","word_count","is_premium","is_published","audio_url","published_at","created_at","updated_at","scheduled_release_at","part_number","season_id") VALUES(370,49,3,' No Light',replace('The lights went out at exactly the moment Emem was winning.\nShe had been beating Afiong at Whot for the third consecutive round, cards spread across the center cushion, when the ceiling fan slowed to a stop and the room dropped into full dark. Afiong made a sound of frustration that had nothing to do with the cards.\n"NEPA again."\n"It''s been four days," Emem said.\n"Five."\nThey sat in the sudden quiet. Outside, the street adjusted. Someone down the road started a generator. Another followed. The neighborhood filled with that familiar nighttime hum, everyone''s but theirs.\nEdem appeared from the bedroom doorway, phone torch already on. He pointed it at the ceiling so the light spread soft and wide across the room.\n"I''m not starting the generator tonight. The noise goes straight to my head after ten."\n"I told you to fix the exhaust pipe," Afiong said.\n"And I will fix it." He sat back down at the dining table where his laptop was open, screen still glowing on backup battery. "I just need to finish this report first."\nAfiong reached for her phone, turned on her own torch, and held it between her teeth while she gathered the scattered Whot cards from the cushion. Emem watched her and felt the laughter rise before she could stop it.\n"You look like a goat."\nAfiong removed the phone from her mouth. "Help me find the candles."\nThey found two in the kitchen drawer and set them on the table near Edem''s laptop. The light they gave was small and warm and flickering. Edem looked up from his screen, looked at the candles, looked at Afiong.\n"Thank you."\nAfiong touched his shoulder as she passed. Two seconds, no more. Then she disappeared into the bedroom.\nEmem stayed on the couch.\nShe was reading something on her phone when Edem looked over.\n"Emem. I need to get something from the kitchen but I don''t want to interrupt Afiong now that she''s settled. Can you get me the biscuits on the second shelf? And anything else you find up there."\n"Okay." She stood.\n"Take my phone," he said, already turning back to his screen. "The candles won''t reach that far."\nHe held it out without looking up.\nShe took it.\nThe kitchen was at the end of a short corridor, away from the candle light. She turned his phone torch on and moved down the hall. The second shelf had two packets of digestive biscuits, a tin of tuna, and a bag of groundnut. She tucked the biscuits under her arm.\nThe groundnut was at the back. She set the phone down on the counter, torch facing up, to free both hands.\nThat was when it happened.\nHer fingers found the groundnut. She picked it up. And because she was sixteen and her data had been slow all day and Edem''s phone was right there already unlocked, she did the thing she would spend the next two years wishing she had not done.\nShe turned on his hotspot.\nIt took four seconds to connect. She opened her messages and they loaded fast, faster than they had all day. She was reading a message from her friend Mfon when the notification dropped down from the top of the screen.\nShe did not mean to read it. It was simply there, in the space between her eyes and the phone, before she could look away.\nThe name she did not recognise. The platform she had never seen Afiong mention. And the words, brief and clear in the notification bar.\nMiss u so much. when r we seeing again?\nEmem went very still.\nThe groundnut bag was in one hand. The phone was in the other. The torch light pointed at the ceiling and threw long shadows across the kitchen walls.\nShe read it again.\nThe words did not change.\nHer chest did something she could not name, a slow drop, like a floor giving way one plank at a time. She thought about the green wrapper from the market. The shopping list folded into his pocket. The hand on Afiong''s shoulder two seconds ago in the candlelight.\nShe looked at the notification again.\nThen she opened his screenshots folder and took two pictures of the screen. Her hands were not shaking. That surprised her. She had expected them to shake.\nShe turned off his hotspot. Picked up the biscuits. Picked up the groundnut. Walked back down the corridor into the sitting room.\nEdem was typing, eyes on his laptop.\nShe set the snacks beside him and placed his phone face down on the table.\n"Thank you," he said, not looking up.\n"It''s fine," she said.\nShe went back to the couch and sat down. She picked up her own phone and looked at the screenshots. Then she locked the screen and set it face down on the cushion beside her.\nFrom the bedroom, she could hear Afiong moving around, the small sounds of someone getting ready for sleep. The candles flickered. Edem typed.\nEmem sat with both phones beside her and said nothing.','\n',char(10)),848,0,1,NULL,'2026-04-14 17:07:05','2026-04-12 14:00:47','2026-04-14 17:07:05',NULL,1,32);
INSERT INTO "chapters" ("id","novel_id","chapter_number","title","content","word_count","is_premium","is_published","audio_url","published_at","created_at","updated_at","scheduled_release_at","part_number","season_id") VALUES(371,49,4,' Evidence',replace('The candles burned down before Edem finished his report.\nEmem watched the first one go. A thin curl of smoke, then nothing. Edem reached over without looking and lit a new one from the second. He worked with the focus of someone who had trained himself not to notice time passing. His fingers moved on the keyboard in short bursts. Stop. Think. Type again.\nEmem had not looked at her phone since she sat back down.\nShe kept her eyes on the television screen, which was off, dark and slightly reflective. In it she could see the warped shapes of the room. Edem at the table. The candle flame. Herself on the couch, sitting straight, hands in her lap, looking exactly like a person who was pretending to be calm.\nShe looked calm. She was certain of it.\n"You can sleep if you want," Edem said. "You don''t have to wait up."\n"I''m not tired."\nHe glanced at her briefly, then back at the screen. "Okay."\nAfiong called from the bedroom. Something about a phone charger. Edem got up, went in, came back two minutes later. He paused at the kitchen, drank a glass of water, returned to his table.\nNormal. Everything was completely normal.\nEmem thought about the notification.\nMiss u so much. when r we seeing again?\nShe thought about the name she had not recognised. She tried to remember the exact letters. She had not looked long enough. She had looked at the words and the words had swallowed everything else. She unlocked her phone under the cover of her wrapper and opened the screenshots.\nThe images were clear. She had not expected them to be this clear.\nThe notification bar at the top of the screen. The platform icon she did not recognise. The name she could not fully make out, cut off at the edge. The message visible in full.\nShe locked her phone again.\nEdem was typing. His face in the candlelight was the same face it had been all day. Open. Unhurried. She looked at him for a long time and looked for something that did not fit and found nothing, which made it worse, because she knew that meant nothing.\nShe had heard Afiong say it once, about a different man, years ago.\nYou never see it until you see it. And then you cannot stop seeing it.\nAt half past ten, Edem closed his laptop and stretched.\n"I''m done. Finally." He blew out the candle and stood. "Good night, Emem."\n"Good night."\nShe listened to him move down the corridor. The bedroom door. The low murmur of voices, Afiong asking something, Edem answering. Then quiet.\nEmem lay down on the guest mattress without changing her clothes.\nShe stared at the ceiling. The room was fully dark now, the kind of dark that had weight to it. Outside, generators hummed and a dog barked twice at something and then stopped. She could hear her own breathing.\nShe opened the screenshots again.\nShe was not a suspicious person. She needed to say that to herself clearly. She was not someone who looked for problems. She had not gone into that kitchen planning anything. She had borrowed his hotspot for four seconds because her data was slow and she had a message from Mfon she had been waiting on all afternoon. That was all. That was the whole of it.\nBut the notification had come. She had not sent for it. It had simply arrived, the way bad things arrived, without asking.\nShe locked her phone.\nShe thought about Afiong folding laundry this morning with her hair undone. She thought about the way her sister laughed at lunch, the real laugh, the one that reached her eyes. She thought about what Afiong had said to her months ago, careful and quiet, like someone choosing to believe despite everything.\nHe is not like the others, Emem. This one is different.\nShe pressed the back of her hand against her mouth.\nShe unlocked the phone again. This time she looked at the screenshots longer. She looked at the timestamp. She looked at the name fragment. She looked at the message, word by word, as if reading it slowly enough would change what it said.\nIt said the same thing it had said in the kitchen.\nShe thought about going to Afiong''s room and knocking. She rehearsed it in her head. There is something I need to show you. Simple. Direct. The way she had always been told to handle difficult things. Don''t carry it. Say it.\nBut it was past eleven and Afiong was asleep and Edem was right there in the same room and what exactly would she say. She had two screenshots taken in the dark from a borrowed phone with a name she had not fully read. She did not know the platform. She did not know the person. She knew four seconds of information and she was lying here building a structure out of it.\nMaybe it was nothing.\nShe put the phone under her pillow.\nShe did not sleep.\nAt two in the morning she took it back out and looked at the screenshots again. At three she put it away and made herself close her eyes. At four-thirty she gave up.\nShe lay still and listened to the night outside and to the sound of her sister breathing peacefully in the next room and she did not know what she was going to do.\nShe only knew she had the screenshots. They were on her phone. They were real.\nAnd she had not said a word.','\n',char(10)),936,1,1,NULL,'2026-04-14 17:07:16','2026-04-12 14:02:30','2026-04-14 17:07:16',NULL,1,32);
INSERT INTO "chapters" ("id","novel_id","chapter_number","title","content","word_count","is_premium","is_published","audio_url","published_at","created_at","updated_at","scheduled_release_at","part_number","season_id") VALUES(372,49,5,'The Morning After',replace('She made the decision at five in the morning without making it.\nOne moment she was lying on her back staring at the ceiling. The next she was sitting up and reaching for her bag.\nShe did not ask herself why. She did not think the word leave. She simply began to move the way a person moved when staying had become a thing she could not figure out how to do. Clothes first. She had not unpacked properly so most of them were still folded the way she had put them in. She pressed them flat and layered them back in carefully, quietly, the way she had been taught to pack since she was small.\nHer charger was plugged into the wall beside the mattress. She wound the cable slowly around her hand.\nToiletries. Her novel. The small pouch her mother had tucked into the side pocket with two hundred naira inside and a folded piece of paper that said for biscuit on the bus. She had laughed at it when she found it. She did not laugh now.\nShe checked under the mattress. She checked the floor beside the door. She checked twice, because that was the kind of thing she did, and then she sat on the edge of the mattress with her bag closed in her lap.\nOutside, the street was in that particular early morning state between night and day. The generators had stopped. Birds had started. A motorcycle moved past below the window, its engine fading slowly down the street. The sky through the curtain gap was dark blue, not black.\nShe should write something. A note, at least. She found her notebook in the top of her bag and held her pen over a blank page for a long time. She wrote: I had to get back early. She looked at it. She tore the page out, folded it small, and put it in her pocket. Then she thought about where she would leave it and with whom and she took it out of her pocket and tore it again, smaller, and put the pieces at the bottom of the bag.\nShe would call Afiong from the bus. She would say something. She would figure out what to say by the time the call connected.\nShe lifted her bag and opened the bedroom door.\nThe corridor was dark and still. Afiong''s door was closed. She moved carefully, keeping to the side of the hallway where the floor did not shift under weight. The living room was grey in the early light, the couch cushions still slightly pressed from last night, the Whot cards Afiong had gathered sitting in a neat stack on the side table.\nShe was four steps from the front door when she heard the kitchen.\nA tap. The quiet sound of a kettle being filled. She stopped.\nShe should not have looked. She would think about that later, the way she thought about the hotspot, the way she thought about all of it. She should have kept walking the four steps to the door.\nShe looked.\nEdem was standing at the kitchen counter in his house clothes, his back to the corridor. He had not heard her. He was setting a cup out on the counter, the yellow one with the chipped handle that Afiong always picked. Not a mug from the front of the shelf. That specific cup. He was measuring tea leaves with the focus of someone who had done this many times and still took it seriously.\nHe did not know she was there.\nThere was nothing performed about it. No audience. He was alone in a quiet kitchen before sunrise making tea in his wife''s favourite cup the way people did things when no one was watching and the habit had become part of who they were.\nEmem stood in the corridor doorway for three seconds.\nThen she walked to the front door, unlatched it slowly, and stepped out.\nThe stairwell was cool. She went down fast, not running, just moving with her bag against her side and her eyes on the steps. Third floor. Second. First. The security man at the gate was asleep in his chair and she let herself out through the smaller side door and stepped onto the street.\nThe air outside was still and thin. A woman was already walking somewhere with a basket on her head, her wrapper bright against the grey morning. A boy on a bicycle moved silently past.\nEmem shifted her bag higher on her shoulder and started walking toward the bus park.\nShe told herself she was going home because there was no reason to stay longer. Holidays were flexible. Nobody had set a fixed return date.\nShe told herself the screenshots were probably nothing.\nShe told herself she would know what to say to Afiong by the time the bus reached Akpabuyo.\nShe walked and the street lightened slowly around her and she did not look back at the building.\nBut she saw the yellow cup. She kept seeing it.','\n',char(10)),845,1,1,NULL,'2026-04-14 17:07:26','2026-04-12 14:03:29','2026-04-14 17:07:26',NULL,1,32);
INSERT INTO "chapters" ("id","novel_id","chapter_number","title","content","word_count","is_premium","is_published","audio_url","published_at","created_at","updated_at","scheduled_release_at","part_number","season_id") VALUES(373,49,6,' The Weight of It',replace('She told Afiong she had come home early because of school.\nAfiong called the morning Emem left, while the bus was still on the road, and Emem watched the phone ring in her lap and let it go to voicemail. She called back twenty minutes later, when she had her voice ready, and said it calmly. Extra lessons starting soon. Teacher sent a message. She had not wanted to wake anyone.\nAfiong was quiet for a moment. Then she said okay, and asked if she had eaten, and that was that.\nEmem stared out the bus window and watched Calabar disappear behind her.\nSchool had not resumed. There were no extra lessons. Emem went home and put her bag in the corner of her room and sat on her bed and looked at the wall.\nThree days passed.\nShe woke in the mornings, ate what her mother put in front of her, answered questions with the right number of words. Her mother noticed nothing wrong, which meant Emem was performing well, which was not something she was proud of.\nAt night she took out her phone.\nShe had looked at the screenshots so many times the images had stopped feeling like evidence and started feeling like something that lived inside her. The notification bar. The unfamiliar platform. The name fragment at the edge. The message.\nMiss u so much. when r we seeing again?\nShe wrote messages to Afiong that she deleted before sending. Long ones first, explaining everything from the hotspot to the kitchen to the bus ride home. Then shorter ones. Then one that was just: I need to tell you something. She held her thumb over send for a long time before she deleted that one too.\nShe did not know what she was waiting for.\nShe told herself she needed to be sure. The name had been cut off. The platform was one she did not recognise. She had four seconds of information and a bad feeling and those were not the same thing as proof. Afiong was happy. She had seen it with her own eyes, real happiness, the kind her sister had spent years waiting for. To walk into that with a screenshot taken from a borrowed phone in a dark kitchen felt like something she could not take back.\nSo she waited.\nMfon came over on a Thursday afternoon and they sat on the veranda eating mango and talking about nothing. Mfon was easy company, the kind of person who filled silence naturally and did not require much in return. Emem was grateful for it.\n"You seem far," Mfon said at some point.\n"I''m right here."\n"You''re right here but you''re far." Mfon pointed her mango seed at her. "Something happened in Calabar."\n"Nothing happened."\n"Emem."\n"I said nothing happened."\nMfon looked at her for a moment, then dropped the mango seed into the bin and moved on to something else. She was a good friend. She knew when not to push.\nEmem watched a lizard cross the top of the fence and thought about the yellow cup.\nThree weeks after she came home, Afiong called on a Sunday evening, just to talk. She sounded the way she had sounded since the wedding, settled and easy, asking about Mama, about the neighbor''s new baby, about whether the mango tree in the compound had fruited yet.\nEmem answered everything.\nThen Afiong said: "Edem''s been asking about you. He said you left so quietly he didn''t even know you were gone until he saw your room."\nEmem looked at the wall.\n"I had to get back early," she said.\n"I know. I just thought you seemed off before you left. Like something was bothering you." A pause. "Was everything okay? With him? With us?"\nThe question sat there.\nEmem opened her mouth.\nShe closed it.\n"Everything was fine," she said.\nAfter the call she sat on her bed and looked at the screenshots for a long time. Then she put her phone face down and lay back and pressed both palms flat against her eyes.\nShe stayed like that until her mother called her for dinner.\nIt was a Tuesday, four weeks after the bus ride home, when she finally said it.\nAfiong had called to say goodnight. It was a habit they had kept since Afiong moved to Calabar, a short call, five minutes at most. Mama was already asleep. The house was quiet. Emem was sitting in the dark of her room with her phone warm in her hand.\n"Afiong."\n"Mm?"\nShe had no prepared version left. She had deleted all of them.\n"There is something I saw when I was with you. Before I left." She stopped. Started again. "On Edem''s phone. I need to send you something."\nThe line went quiet.\n"What kind of something?" Afiong''s voice was careful now, the way a person''s voice went careful when they already felt the shape of what was coming.\n"Screenshots." Emem closed her eyes. "I should have shown you before I left. I don''t know why I didn''t. I should have."\nA long silence.\n"Send them," Afiong said.\nEmem opened the photos. Her thumb hovered. Then she pressed send.\nShe listened to her sister breathe on the other end of the line and waited.','\n',char(10)),881,1,1,NULL,'2026-04-14 17:07:34','2026-04-12 14:04:31','2026-04-14 17:07:34',NULL,1,32);
INSERT INTO "chapters" ("id","novel_id","chapter_number","title","content","word_count","is_premium","is_published","audio_url","published_at","created_at","updated_at","scheduled_release_at","part_number","season_id") VALUES(374,49,7,' The Screenshots',replace('Afiong was in bed when her phone buzzed.\nEdem was in the bathroom. She could hear the tap running, the particular sound it made when he was brushing his teeth, a habit she had learned the way you learned all the small sounds of a person you lived with. She was lying on her side, phone to her ear, listening to Emem breathe in a way that meant she was about to say something difficult.\nShe had already felt it coming. The way the call had shifted register without warning. One moment Emem was just there, quiet, the way she was most evenings. Then her voice changed by a degree too small to name and Afiong felt her whole body go still the way it went still when something was approaching.\nSend them.\nThe screenshots came through as two images. She opened the first one.\nShe read it.\nShe read it again.\nThe bathroom tap was still running. Outside the window a generator hummed. The ceiling fan turned. Everything in the room was exactly where it had always been.\nShe looked at the second screenshot.\nMiss u so much. when r we seeing again?\nShe did not recognise the platform. She looked at the name and could not read all of it, the notification had cut it short. She looked at the timestamp. She looked at the message again.\n"Afiong." Emem''s voice from the phone, small and careful. "Are you there?"\n"I''m here."\nA long pause.\n"I''m sorry I didn''t tell you before I left. I kept thinking I should be sure first. I kept thinking maybe it was nothing and I didn''t want to—"\n"Emem."\n"Yes."\n"I''ll call you tomorrow."\nShe ended the call.\nShe put the phone face down on the mattress and lay on her back and looked at the ceiling.\nThe bathroom door opened. Edem came out in his house clothes, rubbing his face with a small towel. He dropped it on the chair by the door, his usual place for it, and climbed into bed. He reached for his phone on the nightstand, checked something briefly, set it back down.\n"You still on the phone?" he asked.\n"No. I''m done."\nHe settled beside her. The mattress adjusted. He turned onto his side, facing her, the way he always slept.\n"Long call."\n"It was Emem."\n"How is she?"\nAfiong looked at the ceiling. "She''s fine."\nA short silence. Then his breathing began to slow and deepen and she knew the rhythm of that too, knew exactly how many minutes it took him to fall asleep after his head hit the pillow.\nShe lay beside him and did not move.\nShe thought about the morning he came home from the market with the green wrapper. She thought about the yellow cup with the chipped handle, how she had come out for tea one morning months ago and found it already made, sitting at her place at the table, still warm. She thought about the evening she came home from work with a headache so bad she could not lift her eyes and he had sat on the floor beside the couch for twenty minutes with his hand on her back and not said anything.\nShe looked at the screenshots again.\nShe did not cry.\nShe had cried before. She knew how to cry over a man. She had done it in bathrooms and in cars and once on the floor of their mother''s room with her shoes still on. She knew exactly what that felt like, the way it moved through you and left you hollow and then slowly, over weeks, filled back in.\nThis was not that.\nThis was something that had no movement to it. It sat in the center of her chest like a stone that had always been there and she had simply not known it until now.\nShe turned her head and looked at Edem''s face in the dark.\nHe was asleep. His face was the same face it always was. Calm. Unhurried. The face she had looked at across a table on a third date and thought, without meaning to: this one is careful with things.\nShe turned back to the ceiling.\nShe thought about the years before him. The ones that had taken things from her she had not offered willingly. The way she had slowly learned to hold herself smaller so there was less of her to damage. The long quiet period after the last one, when she stopped answering calls from numbers she did not know and told her mother she was not ready and meant it.\nShe thought about the first time Edem reached for her hand in a bus and did not let go even when the traffic cleared.\nThe generator outside cut off. The room went quieter.\nShe lay in the dark beside her husband and looked at the screenshots one more time and then put the phone under her pillow.\nShe did not confront him. She did not shake him awake. She did not do any of the things she had done before, in other rooms, with other men, when she still believed that asking questions changed anything.\nShe closed her eyes.\nHe shifted in sleep and his arm moved near hers without touching and she did not move toward it the way she usually did.\nShe lay still.\nShe was still there in the morning. She made tea. She answered when he spoke to her. She smiled at the right moments. She was present in every way a person could be present and absent in the one way that mattered.\nShe lay beside him and felt the shape of what she was about to do. She had not decided it yet. But her phone was under her pillow and Okon''s name was still in her contacts and the distance between those two facts was shorter than it should have been.','\n',char(10)),987,1,1,NULL,'2026-04-30 14:23:51','2026-04-12 14:05:41','2026-04-30 14:23:51',NULL,1,32);
INSERT INTO "chapters" ("id","novel_id","chapter_number","title","content","word_count","is_premium","is_published","audio_url","published_at","created_at","updated_at","scheduled_release_at","part_number","season_id") VALUES(375,49,8,' Ceasefire',replace('It started with small things.\nEdem noticed the small things first because he was the kind of person who paid attention to small things. The way Afiong stopped leaving her book on his side of the bed when she finished reading it. The way she answered his questions fully but did not ask any back. The way she laughed at things on her phone but did not show him what was funny anymore.\nHe noticed. He said nothing. He waited for it to pass the way a reasonable man waited for a mood to pass.\nIt did not pass.\nThree weeks in, he came home to find dinner already made and covered and Afiong in the bedroom with the door not quite closed. He stood in the kitchen and looked at the covered pot and thought about it.\nHe changed out of his work clothes. He uncovered the pot. He served two plates and set them on the table and knocked on the bedroom door.\n"Food is ready."\nA pause. "I''ll come out."\nShe came out in five minutes, sat across from him, and ate. She asked about his day. He told her. She listened and nodded and asked the right follow-up questions and he sat across from her and felt the distance clearly, the way you felt a drop in temperature without being able to point at what changed.\n"Is everything okay?" he asked.\nShe looked up. "Yes. Why?"\nHe looked at her. "You seem far."\n"I''m right here." She picked up her cup.\nHe watched her drink.\n"Afiong."\n"Edem, I''m fine. I''m just tired. Work has been a lot."\nHe left it there. He did not want to push. He had never been a man who pushed and he was not going to become one now. But he lay awake that night and listened to her breathe beside him and knew that tired was not the right word for what was happening.\nHe tried things.\nThe yellow cup, made and waiting. She thanked him and drank it and washed it and put it back. A film she had mentioned wanting to see, found and downloaded and set up on the laptop on a Saturday evening. She watched it beside him without touching him once, which was not like her. Flowers once, not from a vendor but from the shop she had pointed at once and said she liked. She put them in water and said they were beautiful and touched his arm briefly and the touch felt measured, like something she had decided to give rather than something that had simply come.\nHe accepted all of it. He did not make her account for any of it.\nBut at night he lay beside her and felt the space between them in a way he had not felt since the early months when they were still learning each other''s edges.\nHer friend Ndidi came to visit on a Friday. Emem heard them from the kitchen, Afiong''s voice coming back to something looser, a laugh that was closer to the real one. He stood in the kitchen doorway for a moment and listened.\nWhen Ndidi left Afiong came into the kitchen to wash the cups and he was still there, leaning against the counter.\n"You were laughing," he said.\nShe glanced at him. "Is that strange?"\n"No." He paused. "I just haven''t heard it in a while."\nThe cup clinked against the sink. She kept washing.\n"I''ve been tired," she said again.\n"You keep saying that."\nShe turned off the tap. She dried her hands on the kitchen cloth and turned to face him and her expression was not unkind. It was careful. The way someone looked when they were deciding exactly how much of a thing to give.\n"I''m okay," she said. "I just need some time."\n"Time for what?"\nShe looked at him. Something moved behind her eyes that he could not read.\n"Just time," she said. She folded the kitchen cloth and set it down and walked past him.\nHe stood at the sink alone.\nAt night he reached for her hand under the blanket. She did not pull away. She lay still and let him hold it and that was almost worse than if she had pulled away, the stillness of it, the permission given from a distance.\nHe stared at the ceiling.\nHe thought back. He turned the last weeks over carefully, looking for the thing he had done, the word he had said wrong, the moment he had missed. He found nothing solid. Just the fact of her pulling back and his hands reaching and the gap between them neither growing nor closing.\nHe did not know about the screenshots.\nHe did not know about the dark kitchen or the borrowed phone or the sister who had packed a bag before sunrise and left without saying goodbye.\nHe only knew that the woman beside him had gone somewhere he could not follow, and that she was letting him hold her hand in the dark, and that it felt like standing outside a house where someone had turned off all the lights.\nHe held her hand anyway.\nTwo streets away in Akpabuyo, Emem opened the screenshots for the eleventh time that week, counted them as if the number might have changed, and put her phone face down on the mattress. She had been trying to write a message to Afiong for three days. The cursor blinked in the empty text field. She closed the app.','\n',char(10)),920,1,1,NULL,'2026-04-30 14:39:23','2026-04-12 14:06:34','2026-04-30 14:39:23',NULL,1,32);
INSERT INTO "chapters" ("id","novel_id","chapter_number","title","content","word_count","is_premium","is_published","audio_url","published_at","created_at","updated_at","scheduled_release_at","part_number","season_id") VALUES(376,49,9,'Old Names',replace('The message came on a Wednesday, which was not a special day.\nAfiong was at her desk at the office, eating groundnut from a small paper cone and reading through a contract that had already been read twice and still had three errors nobody had caught. Her phone screen lit up beside her keyboard. She glanced at it the way she glanced at everything these days, from a slight distance, as if she had learned not to expect much from anything that arrived.\nThe name on the screen stopped her hand halfway to her mouth.\nOkon Bassey.\nShe looked at it.\nThe message preview showed four words: Hope you''re doing well.\nShe put the groundnut down.\nShe did not open it. She let the screen go dark and turned back to the contract and read the same sentence four times without taking in a single word. Then she put her pen down and looked at the wall in front of her.\nOkon Bassey.\nShe had not heard that name in three years. She had not looked for it. She had not typed it into a search bar at midnight or found reasons to ask mutual friends how he was doing. She had simply set it down the way you set down something that had been too heavy for too long, and walked away from it, and not looked back.\nShe had met Edem eight months later.\nShe did not open the message that day.\nShe drove home in the evening traffic and cooked and ate dinner across from Edem and answered his questions and said goodnight and lay in the dark beside him and did not think about the message.\nShe opened it at eleven forty-seven, after his breathing had gone deep and slow.\nHope you''re doing well.\nThat was all. Four words and a full stop, the kind of message that gave nothing and required nothing and left the door at exactly the width the sender intended.\nShe locked the phone.\nShe unlocked it.\nShe looked at his contact name. She had never deleted it. She had told herself at the time that deleting a contact was a dramatic gesture and she was not a dramatic person and it did not mean anything that she had simply left it there.\nShe thought about what it meant that it was still there.\nShe put the phone under her pillow and lay still.\nShe did not reply that night or the next morning. She went to work and did her job and came home and sat across from Edem at dinner and looked at his face, which was the same face it always was, patient and present, watching her with that particular careful attention he had always given her.\nHe asked if she wanted to take a walk after dinner. They used to do that. Early in the marriage, before her work schedule thickened, they had walked to the waterfront some evenings and bought roasted corn from the woman by the gate and sat on the low wall watching the river.\n"Not tonight," she said.\nHe nodded. He did not ask again.\nAfter he slept she took the phone out.\nShe opened Okon''s message and this time she kept it open and thought about him in the way she had not allowed herself to think about him in three years. Not the ending, which had been the kind of ending that left marks. But before the ending. The beginning and the middle, when he had been the person who laughed at her jokes before she finished them and knew her food order without asking and called her by a name nobody else used, a small private name that meant nothing to anyone outside the two of them.\nShe thought about the version of herself that had existed inside that relationship. Younger. Less careful. Someone who had not yet learned to monitor her own warmth before giving it.\nShe had not been that person in a long time.\nShe looked at her husband sleeping beside her. She thought about the yellow cup. She thought about the hand reaching for hers under the blanket every night, without fail, even now, even in these weeks when she had given him nothing to reach for.\nShe looked at Okon''s message.\nShe did not reply.\nBut she did not delete it either.\nHe messaged again four days later.\nSaw your picture on Ndidi''s page. You look well.\nShort. Easy. The tone of someone who had rehearsed casualness.\nShe read it twice and put the phone down and picked it up and read it again.\nShe thought about Ndidi''s birthday post, the one from two Saturdays ago. She had worn the blue dress Edem liked. She remembered him saying so at the door before they left. She had smiled at the compliment and said thank you and moved past it the way she moved past most things he offered these days.\nYou look well.\nShe put the phone face down.\nShe stared at the ceiling for a long time.\nThen she picked it up and typed: Thank you. I''m well.\nShe pressed send before she thought about it too carefully.\nThen she lay back and listened to Edem breathing beside her in the dark and held the phone against her chest and closed her eyes.\nShe told herself it was nothing. Just a reply. Just courtesy.\nShe had said the same thing to herself about not deleting the contact.','\n',char(10)),912,1,1,NULL,'2026-04-14 17:08:06','2026-04-12 14:07:33','2026-04-14 17:08:06',NULL,1,32);
INSERT INTO "chapters" ("id","novel_id","chapter_number","title","content","word_count","is_premium","is_published","audio_url","published_at","created_at","updated_at","scheduled_release_at","part_number","season_id") VALUES(377,49,10,'What Happened',replace('It did not happen all at once.\nThat was the thing Afiong would not be able to explain later, not to anyone, not even to herself in the quiet of rooms she sat in alone. It had not been a decision made in a single moment. It had been a series of small steps, each one feeling like barely a step at all, until she looked up one day and did not recognise how far she had walked.\nThe messages had continued through October.\nCareful ones at first. The kind that could mean nothing if anyone saw them. How was work. Did she still like that restaurant on Marian Road. Did she remember the time they got lost driving to Obudu and argued for forty minutes about whose fault it was.\nShe remembered.\nShe told herself she was simply being civil. They were adults. They had a history and history did not have to mean damage. She could speak to a person from her past without it meaning anything about her present.\nShe replied to his messages in the evenings, after Edem slept. She told herself that detail meant nothing either.\nThey met for the first time in November, at the restaurant on Marian Road he had mentioned. She wore a plain dress and arrived five minutes late and told herself on the drive there that it was just lunch.\nHe was already seated when she arrived. He stood when he saw her, the way he always had, an old habit she had forgotten he had. He looked the same. Older in the jaw, a little steadier in the eyes, but the same.\n"Afiong," he said.\nJust her name. The way he had always said it, two syllables given equal weight.\nShe sat down.\nThey talked for two hours. About work, about Calabar, about the years between them. He did not ask about Edem directly. He asked once, carefully, if she was happy, and she looked at her glass and said she was fine, and he did not push, which was not like the Okon she remembered and which made her trust him more than she should have.\nShe drove home and made dinner and sat across from Edem and talked about her day and did not mention the restaurant on Marian Road.\nThey met three more times before December.\nEach time she told herself it was the last time. Each time the telling felt less convincing than the time before.\nOkon had learned patience somewhere in the three years between them. He did not rush anything. He listened when she talked, and she had things she wanted to say that she had not been able to say inside her own house, to the man who slept beside her and still reached for her hand every night and whose face she could no longer look at without feeling the weight of what she believed she knew.\nShe knew she was doing something wrong. She was not confused about that. She did not have a version of events in her head where what she was doing had a clean name.\nBut she was tired. She had been tired for months, carrying something she had not put down and could not show anyone and could not find the words for inside her own marriage, and Okon was familiar in the way that old things were familiar, worn into a shape that fit her hands without effort.\nThe last evening in December, she went to his flat.\nShe had not planned it. She told herself that all the way there and did not believe it by the time she arrived. She stood at his door for a moment with her hand raised to knock and felt the full weight of where she was standing.\nShe knocked anyway.\nHe opened the door.\nWhat she did not see, because she was not looking for it, was the phone on the shelf beside the television. Angled slightly. Screen down so the recording light did not show. Propped against a book with the unhurried care of someone who had prepared for this before she arrived.\nShe did not see it.\nShe stepped inside and he closed the door.\nShe drove home late. The streets were quiet. The bridge over the creek was empty and she slowed on it without meaning to and sat for a moment with the engine running and the window down, the night air coming off the water.\nShe did not feel what she expected to feel.\nShe had expected something. Relief, maybe. Or guilt in a form she could at least hold. Instead there was just a flatness, wide and without edges, the way the creek looked at this hour when there was no moon to break it up.\nShe thought about Edem.\nShe drove the rest of the way home.\nHe was awake when she came in, sitting at the table with a glass of water, laptop closed. He looked at her.\n"You were out late."\n"I was with Ndidi." She set her bag down. "I should have called."\nHe looked at her for a moment. Then he nodded.\n"It''s fine," he said. "Are you hungry?"\n"No."\nShe went to the bathroom. She stood at the sink and ran cold water over her wrists the way she did when her head felt too full and looked at herself in the mirror.\nBehind her the flat was quiet. Edem moved to the bedroom. She heard the mattress take his weight.\nShe turned off the tap.\nOn a shelf in a flat across the city, a phone lay screen down with its work already done.\nShe did not know.','\n',char(10)),945,1,1,NULL,'2026-04-30 14:38:40','2026-04-12 14:09:30','2026-04-30 14:38:40',NULL,1,32);
INSERT INTO "chapters" ("id","novel_id","chapter_number","title","content","word_count","is_premium","is_published","audio_url","published_at","created_at","updated_at","scheduled_release_at","part_number","season_id") VALUES(378,49,11,'Delivered',replace('It came on a Thursday afternoon.\nEdem was at his desk when his phone buzzed. A number he did not recognise. He finished the sentence he was typing, reached for the phone, and opened the message.\nThere was no text. Just a file.\nA video.\nHe looked at the number again. Nothing about it told him anything. He looked at the file. Small thumbnail, dark, nothing visible. The kind of thing a person might ignore if they were not already carrying a particular low unease that had lived in their chest for the past three months without ever finding a name.\nHe pressed play.\nHe watched eleven seconds before he put the phone face down on the desk.\nHe sat very still.\nOutside his office window, Calabar moved the way it always moved on a Thursday afternoon. Traffic. A hawker''s voice rising and falling. A bird on the wire across the street, rearranging its wings.\nHe picked the phone back up.\nHe watched the rest of it.\nWhen it ended he sat for a long time without moving. The phone was in his hand. The screen went dark from inactivity and he did not wake it.\nHe thought about the evening three weeks ago when she came home late and said she had been with Ndidi. He had looked at her face and found nothing that contradicted it and told himself he was looking for problems. He had asked if she was hungry. She had said no. He had listened to her run the tap in the bathroom and told himself he was a man who trusted his wife and that trust was not weakness.\nHe put the phone down again.\nHe breathed.\nA second message arrived from the same number.\nHe opened it.\nI took back what was mine.\nHe read it once. He put the phone in his drawer and closed the drawer. He stood up and walked to the window and stood there with his hands in his pockets looking at the street below without seeing any of it.\nSeven years. He had spent seven years being careful with people. Being the kind of man who read shopping lists and remembered which cup she liked and did not go to sleep before reaching for her hand. He had been that man not because anyone was watching but because it was the only kind of man he knew how to be.\nHe had watched her pull away for three months. He had left space. He had kept reaching. He had told himself it was a season and seasons passed and the only thing to do was stay.\nHe went back to his desk.\nHe opened his drawer and picked up his phone and watched the video one more time, not because he wanted to but because some part of him was still looking for something that would make it mean something other than what it meant.\nIt meant what it meant.\nHe put the phone in his pocket and picked up his keys.\nHe drove without deciding where he was going and ended up at the waterfront. He parked and sat in the car. The river was flat and brown in the afternoon light. A fishing boat moved slowly across the far side. A woman was washing something at the bank, her wrapper tied high, working with the focused patience of someone who had nowhere else to be.\nHe sat and watched the water.\nHe thought about the first evening he brought her here, early in the marriage. She had leaned against the low wall and looked at the river and said she liked the way water made everything quiet. He had stood beside her and not said anything because there was nothing to add to that.\nHe took his phone out and looked at the video notification again.\nThen he opened his gallery and found a photograph from that evening. Her at the wall, profile turned toward the water, the last light catching the side of her face. He had taken it without telling her. She had not known until he showed her later and she had looked at it for a long time and then looked at him.\nHe locked his phone.\nHe sat by the river for a long time.\nWhen he drove home she was in the kitchen. He heard her before he saw her, the sound of the tap, a pot on the burner. He stood in the corridor for a moment.\nThen he walked in.\nShe turned when she heard him. Her face opened the way it used to open and then something moved through it quickly, a reading of his face, and the opening stopped.\n"You''re home early," she said.\nHe looked at her.\nHe had prepared nothing. He had driven here with nothing prepared and now he was standing in his own kitchen and the pot was on and she was looking at him with that careful expression she had been wearing for months and he was holding a phone in his pocket with a video on it and a message that said I took back what was mine.\n"Afiong," he said.\nHis voice came out quiet. He had not expected it to be quiet.\nShe set the spoon down.\nShe already knew.','\n',char(10)),883,1,1,NULL,'2026-04-14 17:08:35','2026-04-12 14:10:41','2026-04-14 17:08:35',NULL,1,32);
INSERT INTO "chapters" ("id","novel_id","chapter_number","title","content","word_count","is_premium","is_published","audio_url","published_at","created_at","updated_at","scheduled_release_at","part_number","season_id") VALUES(379,49,12,'The Filing She did not lie.',replace('That was the thing Afiong held onto afterward, in the weeks that followed, when she sat with what remained of everything. She had not lied to him. When he stood in the kitchen doorway with that quiet on his face, the specific quiet of a man who already knew and was only waiting for her to confirm it, she had not constructed a story or reached for an excuse.\nShe had simply told him the truth.\nNot all of it. But the part that was hers to tell.\nHe showed her the video without speaking first.\nHe held the phone out and let it play and watched her face while it did. She watched three seconds of it and looked away and did not look back. The kitchen was still going, the pot on the burner, steam beginning to lift the lid slightly. Neither of them moved to turn it off.\nWhen it ended he put the phone in his pocket.\n"How long," he said.\nNot a question. A measurement. He was trying to locate the thing on a timeline, to find where it had started so he could understand the shape of it.\nShe told him. The messages. The lunch on Marian Road. The evenings she had said she was with Ndidi.\nHe stood and listened. His face did not collapse. That was what she had not expected. She had expected something to break open in him and instead he stood with his arms at his sides and listened to everything she said with the careful attention he gave everything, as if he was collecting the information and would decide later what to do with it.\nWhen she stopped talking the kitchen was quiet except for the pot.\nShe thought about the screenshots on her phone. She thought about Emem''s voice on that Sunday call weeks ago. There is something I saw. She opened her mouth.\nThen she closed it.\nShe did not know why. She would ask herself that question for a long time afterward and never find a clean answer. Maybe she thought it would sound like an excuse. Maybe she knew that an explanation was not the same as a justification and she did not want to watch him decide which one it was. Maybe she was not ready to say her sister''s name inside this moment.\nShe said nothing about the screenshots.\nShe said nothing about Emem.\nEdem turned and switched off the burner. He stood with his back to her for a moment, both hands on the counter.\n"I need you to let me be alone tonight," he said.\nShe went to the bedroom.\nHe did not sleep in the flat that night. She heard him leave around ten, the measured close of the front door, and she lay on the bed in the dark and listened to his car start below the window and pull away.\nShe did not call him.\nShe lay on her back and looked at the ceiling and thought about the thing she had not said, the screenshots, Emem, the dark kitchen, the notification that had started all of it. She picked up her phone twice and put it down twice.\nShe did not sleep until morning.\nHe came back three days later for his work things. He was polite. He asked if she needed anything before he left. She said no. He nodded and picked up his bag and stopped at the door.\n"I tried," he said. Not with anger. Just as a fact he needed to say out loud. "For three months I tried."\nShe looked at him. "I know."\n"I don''t think you do," he said. "Because if you did you would have talked to me."\nHe left.\nThe papers came through a lawyer two weeks later. Edem''s name at the top. The language formal and distant, the kind of language that made a marriage sound like a transaction being dissolved. She sat at the table with the envelope open in front of her and read every line.\nHer mother called that evening. Word had moved the way word moved in families, faster than anyone intended. She listened to her mother''s voice and gave short answers and got off the call as quickly as she could.\nNdidi came over. She sat with Afiong for three hours and did not ask too many questions and that was the kindest thing anyone did for her that week.\nShe did not call Emem.\nShe did not reply to Emem''s messages, which came first as questions and then as apologies and then stopped coming altogether. She read each one and set the phone down.\nShe was not ready. She did not know when she would be ready. She only knew that every time she saw her sister''s name on her screen she felt the shape of the dark kitchen and the borrowed phone and the message she had never confronted and never explained and she could not hold that and speak at the same time.\nShe did not tell anyone who had brought her the screenshots.\nNot her mother. Not Ndidi. Not the lawyer. Not Edem.\nShe carried it alone the way she had been carrying things alone her whole life, and she put it somewhere inside herself where she would not have to look at it directly, and she kept going.\nEmem saw the status at eleven on a Tuesday night.\nShe had been checking her phone the way she had been checking it for weeks, looking for a message from Afiong that had not come. She opened WhatsApp and went to her sister''s name and found a single line where Afiong''s statuses usually were.\nSome things can''t be fixed.\nShe stared at it.\nShe read it again.\nShe sat on the edge of her bed in the dark of her room and felt the full weight of every moment she had chosen silence. The kitchen. The bus ride home. The weeks of rehearsed messages she had deleted. The Sunday call she had waited too long to make.\nShe had told herself she was waiting until she was sure.\nShe had been sure enough to take the screenshots. She had simply not been brave enough to deliver them to the right person at the right time.\nShe locked her phone.\nOutside her window the night went on as it always did. Somewhere down the street a generator hummed. She sat in the dark and did not move.\nShe had set something in motion.\nShe understood that now with a clarity that had no comfort in it.\nAnd it was still moving.','\n',char(10)),1102,1,1,NULL,'2026-04-14 17:08:42','2026-04-12 14:11:46','2026-04-14 17:08:42',NULL,1,32);
INSERT INTO "chapters" ("id","novel_id","chapter_number","title","content","word_count","is_premium","is_published","audio_url","published_at","created_at","updated_at","scheduled_release_at","part_number","season_id") VALUES(380,50,1,'Summons',replace('The message came from her mother, not Afiong.\nThat was the first sign. In their family, Afiong was the one who called when something needed to be discussed. She was the older one, the one who organized, who set dates and times and made sure everyone arrived. A message from Mama meant Afiong was not able to, or not willing to, make this call herself.\nFamily meeting. Edem''s people and our people. Saturday. You must be there.\nEmem read it twice. She typed: What time? She deleted it. She typed: Is Afiong okay? She deleted that too. She sent: Okay Mama.\nShe put her phone face down on the desk and looked at her textbook and did not read a single word of it for the next twenty minutes.\nShe had not spoken to Afiong in six weeks.\nShe had sent eleven messages in that time. She knew the exact number because she had gone back and counted them one sleepless night, as if the number itself meant something. The messages had moved from questions to explanations to apologies, each one a different shape of the same thing: I am here. I am sorry. Please say something.\nAfiong had read every one of them. The double blue ticks were there, small and indifferent.\nShe had not replied to any of them.\nSaturday arrived the way dreaded things arrived, too quickly and with ordinary weather. Emem dressed carefully in a way that meant nothing except that she needed something to control. She plaited her hair back. She wore the blue dress her mother liked. She looked at herself in the mirror for a long time without seeing much.\nHer mother was waiting in the sitting room with her good wrapper on and her face arranged into the particular expression she wore when she had decided to hold herself together regardless of what happened. She looked at Emem when she came out.\n"You look fine," she said.\n"Mama, what exactly—"\n"In the car."\nIn the car her mother told her only what was necessary. The marriage was ending. Edem had filed. Both families were gathering to discuss what could still be discussed. Her voice was steady and flat, the voice of someone delivering a report on something they had already finished grieving privately.\nEmem looked out the window.\n"Will Afiong be there?" she asked.\n"It''s her marriage."\n"I mean—" She stopped. "Yes. Okay."\nThe drive from Akpabuyo into Calabar took forty minutes. Emem watched the road and counted things without meaning to. Electricity poles. Roadside stalls. The number of yellow buses heading in the opposite direction.\nShe thought about what she would say when she saw Afiong. She had been thinking about it for six weeks and had not found anything that felt like enough. Every version she rehearsed collapsed somewhere in the middle, under the weight of what she had actually done.\nShe had taken screenshots from a borrowed phone in a dark kitchen. She had carried them for weeks without saying a word. She had told her sister at the worst possible time, in the worst possible way, without sitting with her, without being present, without making sure the message landed somewhere that could hold it.\nShe had handed her sister a grenade and then gone home and waited.\nShe pressed her hand flat against her knee to keep it still.\nThe meeting was at Edem''s uncle''s house, a large compound off Eta Agbo Road with a gate that opened onto a wide yard. Two cars she did not recognise were already parked inside. Her mother straightened her wrapper when she stepped out.\nEmem stood by the car for a moment.\nThrough the open parlour window she could hear voices. Low, formal, the particular register of adults managing a difficult thing. She could hear Edem''s uncle''s voice, measured and slow. She could hear a woman she did not know. She could hear her own heartbeat, which was not something she usually heard.\nShe could not hear Afiong.\nHer mother touched her arm. "Come."\nThey walked across the yard and through the front door and into the parlour. The room was arranged the way rooms were arranged for these occasions. Two sides. Edem''s family on the right. Hers on the left. Aunties she recognised and ones she did not. An older man with a carved walking stick who appeared to be presiding.\nEdem was there. He was seated near his uncle, his back straight, his face the same closed-off version of itself she had last seen in Episode 11. He did not look at the door when they entered.\nAfiong was seated at the far end of the left side.\nShe looked up when Emem walked in.\nTheir eyes met for two seconds.\nAfiong looked away first. She looked down at her hands in her lap and did not look up again. She was wearing the green wrapper from the market trip. Emem did not know if that meant something or nothing.\nEmem sat down.\nThe older man with the walking stick cleared his throat and the room settled and the meeting began.\nEmem folded her hands in her lap and kept her eyes forward and breathed.\nShe had no idea what was about to happen.\nShe only knew that somewhere in this room, before this day ended, the truth was going to have to live somewhere outside of her.','\n',char(10)),899,0,1,NULL,'2026-04-14 17:18:34','2026-04-13 02:30:18','2026-04-14 17:18:34',NULL,2,33);
INSERT INTO "chapters" ("id","novel_id","chapter_number","title","content","word_count","is_premium","is_published","audio_url","published_at","created_at","updated_at","scheduled_release_at","part_number","season_id") VALUES(381,50,2,'The Table',replace('The older man with the walking stick was called Papa Okon Ekpo and he had presided over three family meetings this year alone. He had the manner of someone who had heard everything and was no longer surprised by any of it. He opened with a prayer, then a brief statement of why they were gathered, his voice unhurried, giving the room time to settle into what it was.\nNobody settled.\nEdem''s uncle spoke first on behalf of his side. He was a large man with reading glasses pushed up on his forehead that he never once brought down to his eyes. He spoke carefully, outlining what had happened from Edem''s position without raising his voice. The marriage had broken down. Trust had been destroyed. His nephew had made every effort to preserve what they had built and had been met with betrayal.\nHe used that word without softening it.\nOn Emem''s side of the room, one of the aunties shifted in her seat. Her mother sat with her hands folded and her face still.\nAfiong sat at the end of the row and looked at the floor.\nThen it was their side''s turn.\nAuntie Remi, the eldest on Afiong''s side and the one who had always spoken loudest in family matters, began with a defense that Emem recognised as the shape of love wearing the wrong clothes. She said Afiong was a good wife. She said every marriage had difficulties. She said filing for divorce was a drastic response to what could still be repaired.\nEdem''s uncle let her finish.\nThen he said, quietly, that his nephew had not come here to be counseled. He had come to conclude matters with respect.\nAuntie Remi''s mouth tightened.\nPapa Okon Ekpo raised one hand and both sides went quiet.\n"Let the husband speak," he said.\nEdem stood.\nHe did not look at Afiong when he began. He spoke to the room, to the center of it, the way someone spoke when they had made their decision long before they entered the building and were now simply here to complete a formality.\nHe said he had spent three months watching his marriage go cold and not knowing why. He said he had tried every way he knew to reach his wife and been met with distance he could not explain. He said he had not been a perfect man but he had been a present one, and presence was the one thing he had always promised her and kept.\nHe said the video arrived on a Thursday afternoon.\nThe room was very still.\nHe said the message that came with it told him everything he needed to know about the person who had been in contact with his wife. He said he had sat with what happened for weeks and had not found a single version of it he could build a future on.\nHe said he was not angry. He said it quietly and the room believed him.\nThen he sat down.\nAuntie Remi started again, her voice higher now, and one of Edem''s aunties on the other side responded, and for several minutes the room became the thing these rooms always became when grief had nowhere else to go. Accusations moving back and forth across the center. Words like responsibility and failure and what kind of woman landing and being returned.\nEmem sat with her hands in her lap and looked at Afiong.\nAfiong had not moved. She was still looking at the floor, her hands folded in her green wrapper, her face holding an expression Emem had never seen on her before. Not shame exactly. Something older than shame. The look of a person who had already judged themselves and was waiting for the room to finish.\nPapa Okon Ekpo raised his hand again.\n"The wife," he said. "Let her speak."\nAfiong stood slowly.\nShe was quiet for a moment. The room waited. Emem felt her own breathing go shallow.\nThen Afiong reached into the side of her wrapper and took out her phone.\nShe opened it. She found what she was looking for. She held it out toward the center of the room.\n"Before anything else," she said. "I want this to be seen."\nPapa Okon Ekpo leaned forward. Edem''s uncle took the phone and looked at it. He passed it to the man beside him. It moved along Edem''s side of the room, each person looking and passing it on.\n"These are screenshots," Afiong said. Her voice was steady. "From my husband''s phone. I received them months ago. Someone close to me sent them. A message from another woman. That is where it started. That is what broke something in me that I did not know how to repair."\nThe phone reached Edem.\nHe looked at it.\nHe looked at it for a long time.\nThe room was completely silent. Outside a car passed on the street. Someone''s wrapper rustled.\nEdem looked up from the phone and his eyes moved across the room slowly until they found Emem''s face.\nHe looked at her for two full seconds.\nThen he looked back at the phone.\n"This is not mine," he said.','\n',char(10)),863,0,1,NULL,'2026-04-14 17:18:42','2026-04-13 02:31:12','2026-04-14 17:18:42',NULL,2,33);
INSERT INTO "chapters" ("id","novel_id","chapter_number","title","content","word_count","is_premium","is_published","audio_url","published_at","created_at","updated_at","scheduled_release_at","part_number","season_id") VALUES(382,50,3,' The Wrong Name',replace('Nobody spoke.\nEdem was still looking at the phone. He held it the way a person held something they needed to understand completely before they said another word about it. The room waited. Outside, a generator started somewhere down the street and the sound of it came through the window and filled the silence briefly before everyone stopped noticing it.\n"This is not mine," he said again.\nAfiong looked at him for the first time since the meeting began. "It came from your phone."\n"I am telling you this is not my account."\nAuntie Remi made a sound on Emem''s side of the room. Edem''s uncle raised a hand in her direction without looking at her and she stopped.\nPapa Okon Ekpo leaned forward in his chair. "Explain what you mean, my son."\nEdem turned the phone toward the room. His voice was still quiet but there was something new underneath it, something moving fast below the surface.\n"This platform," he said. "I have never used this. Not once."\nAfiong''s hands were clasped in front of her. "The notification came through on your phone. I was shown it on your phone."\n"Shown by who?"\nThe question landed in the room and did not move.\nAfiong''s jaw tightened. She did not answer.\nEdem looked at her. Then he looked down at the phone again and scrolled slowly, examining both screenshots with the focus of someone reconstructing something from pieces.\n"The icon here," he said, pointing. "This application. I don''t have it. I have never downloaded it." He looked up. "Someone can check my phone right now. Today. You can go through every application I have ever installed."\nHe reached into his pocket and placed his phone on the center table.\nIt sat there between both sides of the room.\nNobody reached for it immediately. The offer itself had changed something in the air. Emem felt it. She felt her mother feel it beside her.\nEdem''s uncle picked up Afiong''s phone again and looked at the screenshots. He was quiet for a long moment.\n"The name on this account," he said slowly. "It is not fully visible. It is cut off here at the edge."\n"Yes," Edem said.\n"Can you read what is there?"\nEdem looked. He read the visible fragment aloud. Four letters. The beginning of a name.\nThe room was quiet.\nThen Edem went very still.\nHe sat down.\nHe sat down the way a person sat when their legs had made a decision before their mind caught up. He put both hands flat on his knees and stared at the center table and his face went through something nobody in the room could fully read.\nPapa Okon Ekpo watched him. "You recognise it."\nIt was not a question.\nEdem did not answer immediately. He picked up Afiong''s phone one more time and looked at the fragment of the name. Then he looked at the platform icon. Then he put the phone down carefully.\n"My brother," he said. "Etim."\nThe name dropped into the room like something falling from a height.\nAfiong''s head came up.\n"Etim was visiting us last year," Edem said. His voice was measured but the measurement was costing him something. "He forgot to sign out of his accounts on my phone. I noticed some applications I didn''t recognise and asked him about them. He signed out and I thought nothing more about it." He stopped. "He must not have signed out of everything."\nThe room sat with this.\nAuntie Remi''s mouth opened and closed.\nEdem''s uncle had both hands pressed together in front of his face, eyes closed, the posture of a man recalculating everything he had said in the last hour.\nPapa Okon Ekpo looked at Afiong. He did not speak. He simply looked at her with the patience of a man waiting for her to arrive at the same place the rest of the room was arriving.\nAfiong was staring at the phone on the table. Her face had gone to a place Emem had never seen it go before. Not shock exactly. Something more like a person watching a structure they had built carefully over months come apart in real time, and understanding with complete clarity that they had built it on the wrong ground.\nEmem had not moved.\nShe had been sitting in the same position since Edem said this is not mine and she had felt something shift in her chest then, a slow unlocking, like a door she had been leaning against from the wrong side finally swinging open.\nShe knew what was coming next.\nShe had known since the moment the screenshots crossed the room.\nShe looked at her mother beside her. Her mother was looking straight ahead, her face still, but her hands in her lap had tightened around each other.\nEdem looked across the room.\nHe was not looking at Afiong.\nHe was looking at the left side of the room slowly, person by person, until his eyes stopped.\nHe was looking at Emem.\n"Who took these screenshots?" he asked.\nHis voice was quiet. It was the same voice he had used all morning. But the question sat in the room differently from everything else that had been said.\nBecause it was the only question that had no answer yet.\nAnd everyone was looking at Emem now.','\n',char(10)),890,0,1,NULL,'2026-04-14 17:18:57','2026-04-13 02:32:28','2026-04-14 17:18:57',NULL,2,33);
INSERT INTO "chapters" ("id","novel_id","chapter_number","title","content","word_count","is_premium","is_published","audio_url","published_at","created_at","updated_at","scheduled_release_at","part_number","season_id") VALUES(383,50,4,'Etim',replace('Every eye in the room was on Emem.\nShe felt them the way you felt heat from a source you could not look at directly. Her mother beside her had gone completely still. Auntie Remi was looking at her. Edem''s uncle was looking at her. Papa Okon Ekpo was looking at her with the unhurried patience of a man who had learned long ago that silence was the most efficient tool in a room like this.\nAfiong was looking at the table.\nEmem opened her mouth.\n"I took them," she said.\nHer voice came out smaller than she intended but it came out clearly and it did not shake and she was grateful for that one thing.\nThe room received it.\nHer mother turned to look at her slowly, the way a person turned when they had suspected something for weeks and were now watching it confirmed. She said nothing. Her hands in her lap tightened once and then released.\nEdem looked at Emem for a long moment. Then he looked at Afiong.\nAfiong had still not lifted her eyes from the table.\nPapa Okon Ekpo spoke first.\n"Tell us what happened," he said to Emem. "From the beginning."\nShe told it. She kept her eyes on the center table and told the whole of it without stopping. The holiday visit. The blackout. The borrowed phone and the dark kitchen. The hotspot she had turned on for four seconds. The notification that arrived before she could look away.\nShe told them about the screenshots and the sleepless night and the morning she packed her bag and left before sunrise. She told them about the weeks at home with the images living in her phone. She told them about the Sunday call.\nShe did not leave anything out.\nThe room listened.\nWhen she finished, Auntie Remi made a sound that was not quite words. Edem''s uncle removed his reading glasses from his forehead, looked at them, and put them back. Papa Okon Ekpo nodded once, slowly, the nod of a man filing information into the correct place.\nEdem had not moved.\nEdem''s uncle picked up Afiong''s phone and looked at the screenshots again with the new information sitting in the room. He looked at the name fragment. He looked at the platform icon.\n"We need to be certain," he said.\nEdem took his own phone from the center table where it had been sitting untouched. He went into his settings and scrolled. He turned the screen toward his uncle.\n"No such application," his uncle said.\nEdem nodded.\n"Etim must be contacted," Papa Okon Ekpo said.\nEdem''s uncle already had his phone to his ear. The room waited. On the other side of the parlour a younger child appeared in the doorway, was spotted by an auntie, and was quietly redirected. The generator outside continued its indifferent hum.\nThe call connected.\nEdem''s uncle spoke briefly in Efik, his voice low and direct. A question. A pause. Another question. He listened for a long moment. Then he ended the call and looked at the room.\n"Etim confirms it," he said. "He used the phone during his visit and did not sign out of all his accounts. The platform is one he uses. He did not know the account was still accessible on his brother''s phone."\nHe set his own phone down.\nThe room went silent.\nIt was a particular kind of silence, the kind that came after the last piece of something landed and everyone present understood the full shape of what they were looking at.\nA notification on a borrowed phone in a dark kitchen. Four words from a young man who had simply forgotten to sign out of his account. A sixteen year old girl standing alone with a screen she had not been meant to see.\nAnd everything that had followed from it.\nAfiong had her hands pressed flat against her knees. Her eyes were still down. Her face was not doing anything visible but Emem knew her sister''s face and she knew that stillness, knew what it cost to hold yourself that still.\nEdem sat with his elbows on his knees and his hands loosely clasped and looked at the floor between his feet.\nHe looked like a man doing arithmetic he had not asked to do, adding and subtracting, finding the totals, finding them accurate and finding them devastating in equal measure.\nAuntie Remi said, quietly: "So it was nothing. The whole thing started from nothing."\nNobody responded to that.\nBecause it was true and it was also not the whole truth and everyone in the room was intelligent enough to hold both of those things at once.\nIt had started from nothing.\nAnd it had still happened.\nOkon was still real. The flat across the city was still real. The phone on the shelf was still real.\nEmem looked at her sister''s bowed head and thought about the yellow cup in the kitchen before sunrise. She thought about Edem''s face when he said I tried. She thought about eleven unanswered messages and double blue ticks and a WhatsApp status at eleven on a Tuesday night.\nShe thought about how a single moment of silence in a dark kitchen had become a room full of people sitting with the wreckage of a life.\nShe looked at her hands.\nShe lay beside him and felt the shape of what she was about to do. She had not decided it yet. But her phone was under her pillow and Okon''s name was still in her contacts and the distance between those two facts was shorter than it should have been.','\n',char(10)),940,1,1,NULL,'2026-04-30 14:25:02','2026-04-13 02:33:43','2026-04-30 14:25:02',NULL,2,33);
INSERT INTO "chapters" ("id","novel_id","chapter_number","title","content","word_count","is_premium","is_published","audio_url","published_at","created_at","updated_at","scheduled_release_at","part_number","season_id") VALUES(384,50,6,' Afiong''s Wall',replace('The divorce took forty-three days to finalise.\nEmem knew this because she counted them. Not intentionally. She simply found herself marking time the way a person marked time when they were waiting for something they could not name, checking dates without meaning to, watching the calendar move forward and feeling each day land.\nShe knew the number because she was watching for signs that it was over. She did not know what she would do when it was. She only knew she needed to know when.\nAfiong moved back to Akpabuyo three weeks after the family meeting.\nShe did not move into the family house. She rented a room in a compound two streets away, close enough that Mama could walk there in ten minutes, far enough that she did not have to explain herself daily. She came to the family house for meals sometimes. She sat with Mama and answered questions in the short careful way of someone managing how much of themselves they gave out at any one time.\nEmem was home.\nThey were two streets apart and they did not speak.\nIt was not that Afiong was cold when they were in the same room. That would have been easier. Cold had a temperature to it, something you could measure and respond to. What Afiong gave instead was something more precise than cold. She was simply absent. Present in body and absent in every other way that mattered. She answered if Emem spoke directly to her. She did not look for her in a room when she entered. She did not avoid her visibly enough for Mama to notice.\nShe had simply removed herself from Emem the way you removed a name from a list. Quietly, without announcement, with the finality of someone who had decided once and did not need to decide again.\nEmem sat across from her at dinner one evening in the third week and watched her talk to Mama about a woman at her office and thought: she is never going to bring this up herself. Not as an accusation. Just as a fact she was learning about her sister for the first time. Afiong would not confront. She would not shout. She would not send a message at midnight saying everything she had held back.\nShe would simply close.\nAnd she had.\nNdidi called Emem on a Thursday evening, which surprised her. She had not spoken to Ndidi since before the family meeting.\n"I''m not calling to take sides," Ndidi said, immediately, before anything else.\n"Okay," Emem said.\n"I just want you to know she''s not telling anyone. About you. About the screenshots. About any of it." A pause. "People are asking her questions and she''s not saying your name."\nEmem sat with that.\n"Why are you telling me this?" she asked.\n"Because I think you should know." Ndidi paused again. "She''s not okay. But she''s not doing what some people would do."\nThe call lasted four more minutes and covered nothing important. When it ended Emem held her phone and looked at the wall.\nShe thought about what it cost Afiong to keep that. All those aunties with their questions and their conclusions already forming, and Afiong sitting among them and saying nothing about the dark kitchen and the borrowed phone and her sister who had packed a bag before sunrise.\nShe was protecting her. Even now. Even like this.\nOr maybe she was protecting herself from having to say it out loud. Emem could not tell. She was not sure it mattered.\nThe papers were finalised on a Wednesday.\nEmem found out from her mother, who said it the way she said difficult things, plainly, as a piece of information that needed to be delivered and not a wound that needed tending. She said Afiong was fine. She said Edem had been decent about the process. She said these things happened and life continued.\nEmem nodded.\nShe went to her room and sat on her bed.\nShe opened her message thread with Afiong. The last message was hers, sent nineteen days ago. A single line. I''m here whenever you''re ready. Two blue ticks beneath it. Read and left.\nShe looked at the thread for a long time.\nShe did not type anything.\nShe understood something now that she had not understood during the weeks she was sending messages and waiting. Afiong''s silence was not temporary. It was not a season the way moods were seasons. It was a position her sister had taken up and furnished and intended to live in.\nThe door was not locked from the outside.\nIt was locked from the inside.\nAnd Afiong held the only key and had put it somewhere Emem could not reach.\nShe locked her phone.\nShe lay back on the bed and stared at the ceiling and listened to the house settle around her. Mama moving in the kitchen. The street outside. The fan turning overhead.\nForty-three days.\nA marriage. A sister. A family that would sit at the same table for years and carry this thing underneath every ordinary meal, every celebration, every ordinary Tuesday that looked like nothing from the outside.\nEmem closed her eyes.\nShe was still there.\nShe was the one who had started it and she was still here and Afiong was two streets away behind a locked door and Edem was somewhere in this city alone.\nAnd nobody outside this family knew her name in any of it.\nShe was still there. She was the one who had started it and she was still here and somewhere in this city Edem was alone and did not know she was coming.','\n',char(10)),945,1,1,NULL,'2026-04-30 14:27:47','2026-04-13 02:34:49','2026-04-30 14:27:47',NULL,2,33);
INSERT INTO "chapters" ("id","novel_id","chapter_number","title","content","word_count","is_premium","is_published","audio_url","published_at","created_at","updated_at","scheduled_release_at","part_number","season_id") VALUES(385,50,7,'The Girl Who Started It',replace('School resumed on a Monday.\nEmem put on her uniform and ate breakfast and walked through the gate with everyone else and took her seat in SS2B and opened her notebook and wrote the date at the top of a clean page. Around her the classroom filled with the noise of people who had spent six weeks doing other things and were now returning to this shared life with stories to tell and energy to spend.\nShe sat in the middle of it and said the right things at the right times and nobody noticed anything.\nMfon found her at break time under the mango tree where they always sat and dropped down beside her with a meat pie and a long story about her cousin''s wedding that had apparently involved a missing ring, a jealous ex, and a generator catching fire during the first dance. Emem listened and laughed in the right places and asked one follow up question and Mfon, satisfied, moved on to other things.\nThis was how it went.\nEmem had discovered in the weeks since the family meeting that she was better at this than she had known. The performance of normalcy. She had assumed guilt would show, the way a fever showed, something visible in the face or the eyes that people who knew her would catch and question. But it did not show. She walked through her days and ate her meals and answered her teachers and the world around her simply continued, indifferent to what she was carrying underneath.\nNobody knew.\nThat was the part she had not anticipated. She had imagined that when everything came out it would come out everywhere, that the knowledge of what she had done would move the way family news moved, fast and wide. But Afiong had kept her name out of it. Ndidi had said so and the weeks since had confirmed it. At school she was just Emem. Sixteen. SS2. The quiet one who sat in the middle and always had her notebook open.\nThe girl who had destroyed her sister''s marriage was not a visible thing.\nShe was just a girl.\nIn class she was present in the way that got you called on occasionally and not marked absent from the lesson. She took notes. She submitted assignments. Her Geography teacher said her map work had improved and she said thank you and walked back to her seat.\nAt night she lay in the dark and replayed things.\nNot in a useful way. Not the kind of replaying that arrived at conclusions or built toward decisions. Just the loop of it. The dark kitchen. The hotspot. The notification. The four seconds between seeing it and understanding what she was seeing. She had done the thing any person might have done in that moment, or so she told herself. She had been handed something that looked like evidence and she had responded to it the way a person responded to evidence.\nBut then she thought about what she had not done.\nShe had not asked. She had not waited. She had not sat with Afiong in person and shown her the screenshots with her own hands and been present for whatever happened next. She had sent them through a phone screen weeks later from a different town and then waited in the dark of her own room to see what they would do.\nShe had dropped something heavy into her sister''s life and stepped back to watch from a distance.\nThat was the part she could not find an excuse for. Not the taking of the screenshots. The leaving. The silence. The months of carrying them without saying a word, and then the way she had finally said the word, at night, over a call, without looking her sister in the face.\nShe pulled her blanket up.\nOutside a dog was barking at something it would never catch. She listened to it for a while and then it stopped.\nMfon asked her one afternoon, simply and without preamble, if she was okay.\nThey were walking home after school, the long way because Mfon liked the long way. The road was quiet at this hour, the afternoon heat beginning to pull back.\n"You''ve been here since resumption," Mfon said, "but you''ve also not been here. You know what I mean."\nEmem looked at the road.\n"Something happened in the holidays," she said.\n"I know." Mfon did not push. She walked beside her and waited.\nEmem thought about how much to say. She had been thinking about it for weeks. Whether to tell Mfon. Whether telling someone would make it lighter or just spread it to a new place without removing any of the weight.\n"I did something," she said. "I thought I was doing the right thing. It wasn''t the right thing."\nMfon was quiet for a moment. "Is it fixable?"\nEmem thought about Afiong two streets away behind a door that locked from the inside. She thought about Edem somewhere in this city alone. She thought about forty-three days and a WhatsApp status and eleven messages with blue ticks beneath them.\n"No," she said.\nMfon nodded.\nShe did not say she was sorry, which Emem appreciated. She did not say everything happened for a reason or that time healed things. She just nodded and kept walking beside her and let the road be the road.\nThey walked the rest of the way in silence.\nIt was the most honest conversation Emem had since the family meeting.\nIt did not make her feel better.\nIt made her feel less alone inside the not feeling better. She looked at the road ahead. Edem''s office address was still folded in her school bag. Had been there for eight days.','\n',char(10)),962,1,1,NULL,'2026-04-30 14:28:57','2026-04-13 02:35:58','2026-04-30 14:28:57',NULL,2,33);
INSERT INTO "chapters" ("id","novel_id","chapter_number","title","content","word_count","is_premium","is_published","audio_url","published_at","created_at","updated_at","scheduled_release_at","part_number","season_id") VALUES(386,50,8,' Finding Edem',replace('She found his office address the way she found most things she was not supposed to go looking for.\nNdidi had mentioned the company name once, months ago, in passing, the way people mentioned details that had no reason to become important. Emem had not written it down. She had simply heard it and it had gone somewhere in her and stayed there. She typed it into a search bar on a Saturday morning and found the address in four minutes.\nShe looked at it for a long time.\nThen she wrote it on a piece of paper, folded it, and put it in her uniform pocket and went to school and did not think about it for a week.\nShe thought about it every day for a week.\nShe thought about what she would say. She had been doing this for months now, rehearsing conversations that collapsed before she could finish them, and she knew by now that the rehearsals were not helping. Every version she prepared sounded like something she was saying to manage the situation rather than something true. She would get to a certain point in the script and hear herself and stop.\nShe did not want to manage it.\nShe wanted to say the actual thing.\nThe problem was she did not yet know what the actual thing was.\nShe went on a Tuesday afternoon, after school.\nShe did not tell Mfon. She did not tell her mother. She took a keke from the school gate and gave the address to the driver and sat in the back with her school bag on her lap and her hands folded on top of it and watched the city move past.\nThe building was on a quiet street off Etta Agbo Road, three floors, a small sign beside the entrance with the company name in blue lettering. A security man at the gate looked at her uniform and her bag and asked who she was there to see.\nShe said Edem''s full name.\nThe man looked at her for a moment. "He''s expecting you?"\n"No."\nAnother look. Then he picked up the phone on his desk and made a brief call. He listened. He looked at her once more.\n"Third floor," he said. "Ask for his secretary."\nThe secretary was a woman in her thirties with reading glasses on a chain around her neck and the manner of someone who managed her boss''s time the way a goalkeeper managed a net. She looked at Emem''s uniform and her school bag and her sixteen year old face and said Mr. Edem was in a meeting.\n"I can wait," Emem said.\n"It may be a long wait."\n"I can wait," she said again.\nThe secretary looked at her for a moment, then gestured to a row of chairs beside the window. Emem sat down and put her bag between her feet and looked at the city through the glass. Calabar from the third floor looked different. Quieter. The creek was visible at the far edge, brown and flat in the afternoon light.\nShe waited forty minutes.\nHe came out of the meeting room with two other men, talking, jacket over one arm. He saw her before she stood up. She watched him register who she was. Something moved across his face briefly and then settled back into stillness.\nThe other men left. He walked over.\nHe stopped in front of her and looked at her. He did not look unkind. He looked tired in a way that had nothing to do with the hour.\n"Emem."\n"I''m sorry to come here," she said. "I didn''t have another way to reach you that wasn''t through family."\nHe was quiet.\n"I just need ten minutes," she said. "If you don''t want to after that you don''t have to speak to me again."\nHe looked at her for a long moment. Then he glanced at his secretary, who was observing them with professional neutrality.\n"Five," he said. "I have another call at four."\nThere was a small seating area at the end of the corridor, two chairs and a low table by a window. He sat across from her and put his jacket over the arm of the chair and looked at her with the same careful attention he had given everything since she had known him.\nShe had prepared nothing. That had been the decision. No script. No managed version. Just the truth in whatever order it arrived.\n"I need you to know that I didn''t come to your house that holiday looking for anything wrong," she said. "I wasn''t suspicious of you. I didn''t go into that kitchen to find something. I turned on the hotspot because my data was slow and I had a message I was waiting for."\nHe said nothing.\n"When the notification came I didn''t know what to do with it. I was sixteen and alone in the dark and I made a decision I thought was protecting my sister." She stopped. "I didn''t think about what I didn''t know. I didn''t think about asking questions first or waiting or any of the things I should have thought about."\nShe looked at him directly.\n"And then I stayed silent for weeks and sent those screenshots the worst possible way and was not there when they landed." She paused. "I''m not telling you this to ask you to forgive me. I''m not here for that. I just needed you to know that you were never what I thought you were in that kitchen. That was never you."\nThe corridor was quiet around them.\nEdem looked at her for a long moment. His face was doing the thing it had always done, holding everything carefully, giving nothing away before he was ready.\nHe looked at the window.\nHe looked back at her.\n"Your five minutes are up," he said.\nHe stood and picked up his jacket and walked back down the corridor to his office.\nHe did not look back.\nEmem sat in the chair by the window for a moment. Outside the creek was still visible, flat and brown, moving slowly toward somewhere she could not see.\nShe picked up her bag and left. She was at the gate when her phone buzzed. She looked at the screen. A number she did not recognise. She stood at the gate and looked at it and did not open it.\n','\n',char(10)),1070,1,1,NULL,'2026-04-30 14:30:04','2026-04-13 02:37:06','2026-04-30 14:30:04',NULL,2,33);
INSERT INTO "chapters" ("id","novel_id","chapter_number","title","content","word_count","is_premium","is_published","audio_url","published_at","created_at","updated_at","scheduled_release_at","part_number","season_id") VALUES(387,50,10,'After Three weeks passed.',replace('Emem did not hear from Edem. She had not expected to. She had walked out of his office building and taken a keke back to Akpabuyo and sat at dinner that evening and answered her mother''s questions about school and gone to bed and told herself she had done the one thing she could still do and that it would have to be enough.\nShe was not sure it was enough.\nBut it was done. That was different from enough, and she was learning to tell the two apart.\nAfiong was still two streets away.\nStill present at Sunday dinners in the way she had been present since she moved back. Still answering when spoken to. Still carrying the careful, managed version of herself that she offered the family now in place of the real one. Emem watched her across the table and looked for a crack, not to enter it, just to know it was there.\nShe did not find one.\nAfiong had always been the stronger one. Emem had known that since she was small. Not louder. Not harder. Just more able to hold a position once she had taken it. She could respect that even when it was turned against her. She was learning to respect it even now.\nShe stopped sending messages.\nNot out of anger. Not because she had given up on her sister entirely. But because she understood finally that the messages were for herself, each one a small attempt to move the locked door by force, and the door was not going to move that way. If Afiong came back to her it would be in Afiong''s time and on Afiong''s terms and no number of messages would change that timeline by a single day.\nShe stopped and she waited and she carried the waiting.\nSchool continued. Mfon continued. Her Geography teacher continued giving too many notes and Emem continued writing them down and somewhere in the ordinariness of it she found that she was sleeping better. Not well. But better.\nShe was different in a way she could not fully explain and did not try to. Not healed, she knew the word healed was not the right word for what she was. But different. There was a before version of herself and an after version and the line between them was a dark kitchen in Calabar and everything that had followed from it.\nShe did not know yet what the after version of herself would become. She was still inside it.\nThe message arrived on a Thursday evening.\nShe was at her desk doing homework when her phone lit up beside her notebook. A number she had saved under his name. She looked at it for a moment before opening it.\nTwo words.\nI know.\nThat was all.\nNo punctuation after it. No follow up message. Just those two words sitting in the white space of the screen, small and complete.\nShe read it three times.\nShe did not know exactly what he meant by it. She thought perhaps that was deliberate. That he had chosen two words precise enough to mean several things at once and had left her to find her own place inside them.\nI know could mean: I know you told the truth.\nIt could mean: I know it started from a mistake.\nIt could mean: I know who you are and it is not the worst version of this story.\nShe sat with all three.\nShe did not reply. There was nothing to add to two words that had been chosen that carefully.\nShe picked up her phone a long time later.\nShe opened her photo gallery. She did not hesitate the way she had expected to hesitate. She found the folder where she had moved them months ago, away from her main camera roll, the two images she had taken in a dark kitchen on a borrowed phone in the first week of a holiday that had changed everything.\nShe looked at them once.\nThe notification bar. The platform she had not recognised. The name cut off at the edge. The four words that had started it all.\nShe selected both.\nShe deleted them.\nThe folder was empty.\nShe locked her phone and set it face down on the desk and looked at her open notebook. The homework was half done. Outside the window the street was doing what the street always did in the evening, generators starting, voices from the compound next door, a child being called in.\nShe was not healed. The marriage was still over. Afiong was still two streets away behind a door that locked from the inside. Edem was somewhere in this city carrying what he carried.\nNone of that had changed.\nBut she had told the truth when it cost her. She had stood in a corridor and given the true account of herself to the one person who deserved to hear it and she had not asked for anything in return. She had not managed it or softened it or made it easier to hold.\nShe had just told it.\nShe picked up her pen.\nShe found her place in the homework and continued.','\n',char(10)),865,1,1,NULL,'2026-04-14 17:20:01','2026-04-13 02:41:45','2026-04-14 17:20:01',NULL,2,33);
INSERT INTO "chapters" ("id","novel_id","chapter_number","title","content","word_count","is_premium","is_published","audio_url","published_at","created_at","updated_at","scheduled_release_at","part_number","season_id") VALUES(388,50,9,'What She Should Have Said',replace('The keke dropped her at the junction and she walked the rest of the way home.\nShe walked slowly, not because she was tired but because she was not ready to be inside four walls yet. The afternoon was cooling into evening, the light going amber and long across the road. She passed the compound where the twins from her primary school had grown up. She passed the buka where her mother bought pepper soup on Fridays. Familiar things, doing what familiar things did, holding their shape while everything else moved.\nShe had said it.\nShe had stood in a corridor on the third floor of a building off Etta Agbo Road and told the true account of herself to the one person who deserved to hear it. She had not managed it or softened it. She had just said it.\nShe had expected to feel lighter.\nShe did not feel lighter.\nShe sat on the front step of the house when she arrived, not ready to go in yet. The compound was quiet at this hour, the neighbours'' generator not yet started, the children called in for dinner. She put her school bag between her feet and looked at the street.\nShe thought about what Edem had said.\nHe had said nothing. That was what he had said. He had listened to every word she offered and looked at the window and looked back at her and said her five minutes were up. Then he had walked back down the corridor and she had sat in the chair by the window for a moment and then picked up her bag and left.\nShe had told herself on the keke ride home that it was enough. That the point had never been his response. That she had gone there to give him the truth and she had given it and what he did with it belonged to him.\nShe believed that.\nShe also knew it was not the whole of what she was feeling.\nThe whole of what she was feeling was this.\nShe had told the truth to the right person. But she had told it a year too late and in a corridor with five minutes on the clock and a secretary watching from across the room. She had told it after a family meeting and a divorce filing and forty-three days of finalisation. She had told it after Afiong had already moved two streets away and locked a door from the inside.\nShe had told it when it was the only thing she had left to give.\nAnd somewhere between giving it and walking out of that building she had understood for the first time the difference between two things she had been treating as the same.\nConfession was what she had done in Edem''s corridor. It was true and it was necessary and it had cost her something real. But it had been, underneath everything, still about herself. About what she needed to put down. About who she needed to become in her own accounting of this story.\nAccountability was something older and harder. It was not a corridor and five minutes and a practiced true account. It was a dark kitchen in Calabar a year ago. It was a sixteen year old girl standing alone with a phone that did not belong to her and a notification she had not been meant to see. It was that girl choosing, in that moment, to go back down the corridor and knock on a bedroom door and say: I need to show you something and I need to be here when you see it.\nThat was what she should have said.\nNot the message on the Sunday call. Not the corridor. That. Right there in the dark, before she took the screenshots, before she packed her bag, before any of it moved.\nShe should have knocked on the door.\nShe had not knocked on the door.\nHer mother''s voice came from inside the house, asking if she was back. She said yes. Her mother said food was on the table.\nShe stayed on the step a moment longer.\nShe thought about Afiong two streets away. She thought about whether the day would ever come when that door unlocked from the inside. She did not know. She had stopped pretending she could calculate it.\nShe thought about Edem''s two words, which had not arrived yet but would, three weeks from now, on a Thursday evening when she was not expecting them.\nShe did not know that yet.\nShe only knew that she had done what she could do from where she was standing now, a year after the kitchen, a year after the silence, a year after the bag packed before sunrise.\nShe could not go back to the dark kitchen.\nShe could only be the person who had finally, at a cost, chosen to tell the truth.\nShe picked up her bag.\nShe went inside. She sat at her desk and looked at her homework and did not open it. Then she picked up her phone and looked at the screenshots folder. Still there. Still waiting. She closed her phone and put it face down. Not yet. But soon.','\n',char(10)),872,1,1,NULL,'2026-04-30 14:30:54','2026-04-13 06:57:17','2026-04-30 14:30:54',NULL,2,33);
INSERT INTO "chapters" ("id","novel_id","chapter_number","title","content","word_count","is_premium","is_published","audio_url","published_at","created_at","updated_at","scheduled_release_at","part_number","season_id") VALUES(389,51,1,'The Day They Took Me',replace('The morning they came for Amaechi, his mother did not cry. That was the thing he could not stop thinking about as the horses pulled him away from everything he had ever known.\n\nShe had known they were coming. She must have known for weeks, maybe longer, because when the Zara soldiers arrived at their compound with their red-dyed robes and their long staffs and their faces arranged into the polite blankness of men doing something they would rather not explain, his mother was already dressed. Her wrapper was the good one, the deep indigo she wore to ceremonies and funerals. She had oiled her skin. She had wrapped her headtie with the kind of careful attention that meant she had been awake since before the sun.\n\nShe did not explain any of this to Amaechi. She simply called him to stand before her, pressed both hands to his face, and looked at him the way you look at something you are memorising.\n\nHe was six years old. He did not understand what was happening. He understood only that her hands were warm and that she smelled like shea butter and that something in her eyes was very far away even though she was looking directly at him.\n\n"You are the son of Dike of Oke," she said. "Whatever they call you in that place, whatever name they give you there, you remember the name I gave you. Amaechi. Do you know what it means?"\nHe nodded. He had known since he could speak. Who knows what tomorrow holds.\n\n"Then carry it like a shield." She pressed her forehead to his. She held it there for three long breaths. Then she stepped back and folded her hands in front of her and did not move again as the soldiers walked him to the road.\nHe turned back twice. The third time he told himself he would not turn again and he kept that promise, though it cost him something he did not have a name for yet.\n\nThe journey to Zara took four days.\n\nThey traveled on horseback through the forest roads of the eastern territory, Amaechi seated in front of one of the soldiers, held in place more by the man''s bulk behind him than by any intention of his own. The forest was dense and enormous in a way that made Oke feel suddenly small. Trees he had never seen crowded the road on both sides, their roots lifting out of the earth like the knuckles of buried giants. Birds called from places he could not see. The light came through in pieces.\n\nOn the second day, they crossed the Oma River on a wide flat boat poled by two men who worked in silence. The river was brown and slow and so wide that the other bank seemed like a rumour until they were nearly upon it. Amaechi sat at the front of the boat and watched the water and did not speak. The soldier behind him had stopped trying to make conversation somewhere around the first morning.\n\nOn the third night, they camped near a village whose name Amaechi did not catch. The women there looked at him with a sympathy they did not put into words. One of them pressed a piece of roasted yam into his hand as he walked past. He ate it in three bites and did not thank her because by then he was so hollow inside that even gratitude felt like too much effort to produce.\nHis mother''s voice kept returning to him in the quiet hours. Not her face. Her voice. The specific weight of it when she said carry it like a shield. He repeated the words to himself in the dark until they lost their meaning and then found it again.\n\nHe saw the palace on the morning of the fourth day.\n\nThey came out of the forest onto a wide red road and there it was, sitting at the end of a long approach lined with iroko trees so old their branches had grown into each other overhead. The palace of the Eze of Zara was not what Amaechi had imagined when adults in Oke spoke of it with lowered voices. He had expected something cold and sharp, the way danger usually presented itself in the stories his father told. What he saw instead was something vast and warm-coloured, its walls built from deep red earth and faced with carved panels that caught the morning light. Banners in yellow and green moved in the wind above the main gate. Figures moved along the walls in slow deliberate patterns, guards making their rounds.\nIt was the most beautiful thing he had ever seen.\n\nThat made it worse, somehow.\nThe soldier urged the horse forward and the gates opened before them and Amaechi felt the shadow of the outer wall fall across his face as they rode through. He looked up at the carved faces watching from the stone above the gate, old kings with steady eyes and mouths set into expressions that gave nothing away.\n\nHe was still looking up at them when he noticed the man standing at the far end of the entrance courtyard, waiting with the particular stillness of someone who had been there a long time and intended to be there much longer.\n\nThe man''s eyes found Amaechi immediately. He smiled.\nIt was the kind of smile that did not reach anywhere near his eyes.','\n',char(10)),912,0,1,NULL,'2026-04-14 17:22:45','2026-04-14 16:22:42','2026-04-14 17:22:45',NULL,1,34);
INSERT INTO "chapters" ("id","novel_id","chapter_number","title","content","word_count","is_premium","is_published","audio_url","published_at","created_at","updated_at","scheduled_release_at","part_number","season_id") VALUES(390,51,2,' The Weight of Oke',replace('Nobody told Amaechi the rules. They simply watched to see how long it would take him to break them.\n\nHis room was small but not unkind. A sleeping mat thicker than anything he had owned in Oke, a wooden chest for his things, a window that looked out onto an inner courtyard where palace boys his age moved in clusters he had not yet been invited to join. A girl named Adaeze brought him food twice a day and answered his questions with the shortest possible words, not out of cruelty, he decided, but out of a caution she had learned from somewhere.\n\nThe palace had a rhythm and Amaechi spent his first three days simply trying to hear it. Morning drums at first light meant the Eze was beginning his day and all movement in the inner corridors stopped until the second drumbeat released it.\n\nMeals were taken in a specific order that had nothing to do with hunger and everything to do with rank. The courtyard fountain was for palace children only, not for pledge boys. He learned that last one the hard way, from the flat stare of an older boy who said nothing but positioned himself between Amaechi and the water with the practiced ease of someone who had done it before.\nHe learned to watch more than he moved. He learned to stand near walls. He learned the difference between the guards who would answer a question and the ones who looked past you as though you were furniture. He carried his mother''s words in his chest like a coal wrapped in cloth, small and hot and needing careful handling.\n\nOn the fourth morning, Ogbonna sent for him.\n\nThe adviser''s office was on the second level of the administrative wing, at the end of a corridor where the carved panels were older and more elaborate than anywhere else Amaechi had yet seen. A boy no older than Amaechi stood outside the door with a wooden tray and the blank careful face of someone concentrating very hard on being invisible. He did not look up as Amaechi approached.\n\nAmaechi knocked. A voice said enter.\n\nOgbonna was seated behind a wide table covered in scrolls and small clay tablets and stacks of correspondence tied with cord. He did not look up immediately. He finished reading whatever was in his hand, set it down with a precision that felt deliberate, and then gave Amaechi the full weight of his attention.\n\nHe was not a large man. He was the kind of man whose size was irrelevant because the room reorganised itself around him anyway. His robes were the dark green of senior court officials, trimmed at the collar with narrow beadwork. His face was long and composed and gave the impression of someone who had long ago stopped being surprised by anything.\n\n"Sit," he said.\nAmaechi sat.\nOgbonna looked at him the way a man looks at a document he is about to file. Assessing, categorising, finding the correct place for it among things already known.\n"You are the son of Dike of Oke," Ogbonna said. It was not a question.\n"Yes."\n"Your father holds the eastern territory under the Eze''s authority. You are here because that arrangement requires a guarantee. You are the guarantee." He paused, letting the sentence finish its work. "Do you understand what that means?"\nAmaechi understood it the way a person understands cold water. The knowledge arrived all at once and lived in the body, not the mind. He said yes anyway.\n"It means," Ogbonna continued, as though Amaechi had said nothing, "that your comfort here depends entirely on your father''s continued loyalty. Your position here depends on your usefulness. And your usefulness depends on how well you learn to be what this court requires." He folded his hands on the table. "You are not a guest, boy. Guests leave when they please. You are not a servant. Servants have no value beyond their function. You are a pledge. That is a specific thing. It would be wise to understand it specifically."\nThe room was very quiet.\n\n"You will attend lessons with the prince. You will learn what he learns. You will behave according to palace standards at all times." Ogbonna reached for one of the scrolls, signaling that the important part was coming. "And you will understand this above everything else. If the prince errs, the correction falls to you. That is the pledge law. It has stood longer than either of us has been alive and it will stand long after we are gone."\nHe said it the way someone describes the weather. Matter of fact, impersonal, slightly bored.\nAmaechi kept his face still. His mother had taught him that too, without words, through the years of watching her manage his father''s moods and the village council''s decisions and the hundred small humiliations of living under Zara''s shadow. Keep the face still. Let nothing cross it that you have not chosen to put there.\n\n"Any questions?" Ogbonna asked.\n"No," Amaechi said.\nOgbonna looked at him for one moment longer than necessary. Then that smile appeared again, the same one from the courtyard, the one that lived only on the surface of his face.\n\n"Good," he said. "You may go."\nAmaechi stood, turned, and walked to the door. He did not hurry. He felt Ogbonna''s eyes on his back every step of the way, patient and precise and completely certain.\n\nOutside in the corridor, the boy with the tray was gone.\nAmaechi stood alone in the carved hallway and breathed slowly and thought about a cage and what it felt like before the door had fully closed.','\n',char(10)),945,0,1,NULL,'2026-04-14 17:22:51','2026-04-14 16:25:05','2026-04-14 17:22:51',NULL,1,34);
INSERT INTO "chapters" ("id","novel_id","chapter_number","title","content","word_count","is_premium","is_published","audio_url","published_at","created_at","updated_at","scheduled_release_at","part_number","season_id") VALUES(391,51,3,'The Price of a Prince',replace('The cane was thin and pale and cut from a specific tree that grew only in the palace garden. Amaechi would come to know this later. That morning, he did not know anything except that it was moving toward him and that he had done nothing wrong.\n\nThe lesson room sat at the heart of the palace''s eastern wing, a wide airy space with high windows that let in long blades of morning light. The walls were lined with wooden shelves holding scrolls and clay tablets and the kind of books that arrived from the northern traders wrapped in oilskin. Three low tables sat on woven mats in the centre of the room. Amaechi had been coming here for two weeks, seated always at the leftmost table, learning to read the formal script of Zara alongside two other palace boys whose names he was still learning to trust.\n\nAt the middle table sat Chizaram.\nAmaechi had seen the prince before, in the way you see weather before it reaches you. At a distance, surrounded by attendants, moving through the palace with the particular quality of stillness that was trained into royal children from birth. Up close, in the lesson room, Chiza was something else entirely. He was small for his age and serious-faced, with quick eyes that moved faster than he let on. He asked questions that made the tutor pause. He made small drawings in the margins of his tablets when he thought no one was watching. He had laughed once, two days ago, at something the other boy said, and the laugh had been so sudden and unguarded that Amaechi had looked up from his own work without meaning to.\nThe tutor was an old man named Nwosu, thin and deliberate, who taught with the patience of someone who had given the same lessons many times and had made peace with that fact. Today''s lesson was oral recitation, a long passage from the founding histories of Zara that all palace-born children were required to memorise and deliver without error.\nChiza stood at the front of the room.\n\nHe began well. His voice was steady and his memory was sharp and he moved through the first portion of the passage with the confidence of someone who had prepared. Then he reached the third stanza, the one describing the founding Eze''s crossing of the Oma River, and something in his recall slipped. He paused. He started the line again. He paused again. His eyes moved to the window in the brief involuntary way eyes move when a mind is searching empty shelves.\nNwosu said nothing. He waited.\nChiza attempted the line a third time and produced it incorrectly, transposing two names in a way that changed the meaning of the entire stanza.\n\nNwosu closed the scroll in his hands. He looked at Chiza with an expression that was not unkind and not forgiving. Then he looked at Amaechi.\n\nAmaechi understood before anyone said anything. He felt it move through him the way cold moves through thin cloth. Not surprise. Something worse than surprise. A confirmation of the thing Ogbonna had described in that precise, unhurried voice two weeks ago. If the prince errs, the correction falls to you.\n\nHe had told himself he understood it then. He had not understood it at all.\n"Stand," Nwosu said to him.\nAmaechi stood.\nHe walked to the front of the room because there was nothing else to do. Walking was the only decision left to him and he made it with his back straight and his jaw set and his mother''s voice in his ear saying carry it like a shield.\n\nOgbonna was already there. Amaechi did not know when he had entered the room or how long he had been standing to the side of the shelves, but there he was, dark green robes, composed face, the thin pale cane held loosely in one hand. He had the look of a man attending a routine administrative function.\n"Hold out your hands," Ogbonna said.\nAmaechi held them out.\n\nThe first stroke landed across both palms. It was precise and not especially hard, which somehow made it worse. There was a carefulness to it that felt like a message. Ogbonna was not angry. He was not hurrying. He was demonstrating a principle, and the demonstration required accuracy more than force.\nThe second stroke followed.\nThen the third.\n\nAmaechi did not make a sound. He fixed his eyes on the high window above Ogbonna''s shoulder and he breathed through his nose and he held his face the way his mother had taught him, still and closed and giving nothing away. His hands burned. His chest burned worse.\n\nOgbonna stepped back and examined him the way a craftsman examines finished work.\n\n"You may sit," he said.\nAmaechi returned to his table. He set his burning hands flat on the surface and looked at his work from before the lesson, the careful letters he had been practising, and he did not look at Chiza.\n\nBut Chiza looked at him.\nAmaechi could feel it, a gaze that had weight to it, heavy with something that was not pity exactly but lived very close to pity''s edge. He did not want it. He did not know yet that it was the beginning of the only real friendship his life would hold.\nHe just knew his hands hurt, and the morning was not yet finished.','\n',char(10)),905,0,1,NULL,'2026-04-30 13:51:24','2026-04-14 16:26:56','2026-04-30 13:51:24',NULL,1,34);
INSERT INTO "chapters" ("id","novel_id","chapter_number","title","content","word_count","is_premium","is_published","audio_url","published_at","created_at","updated_at","scheduled_release_at","part_number","season_id") VALUES(392,51,4,'The Boy Who Did Not Cry',replace('Sleep did not come. Amaechi lay on his mat in the dark and listened to the palace breathe around him and waited for the burning in his hands to decide what it wanted to be.\n\nThe room felt different at night. Smaller, somehow, even though nothing had changed. The window that looked onto the inner courtyard let in a thin rectangle of moonlight that moved slowly across the floor as the hours passed. Somewhere in the deeper part of the palace, a night drum sounded its slow count. One beat, then silence. One beat, then silence. Amaechi had learned that it marked the watch rotations of the palace guards, but lying here now it sounded less like timekeeping and more like a heart that had forgotten how to do anything but the minimum.\n\nHe turned his hands over in the dark and looked at them. The welts had settled into a dull insistent throbbing that spiked whenever he flexed his fingers. He flexed them anyway, three times, slowly, the way his father had taught him to test pain and not be ruled by it. His father had said a man who cannot look directly at his own wound will always overestimate its size.\nHis father had said many things. His father had also sent him here.\n\nHe turned onto his side and faced the wall and told himself to sleep and did not sleep.\nThe knock came so quietly that for a moment he thought he had imagined it. A single soft sound at the base of his door, more a brush of knuckle than a proper knock, the kind of sound made by someone who had not fully committed to being there.\nAmaechi did not move.\nThe sound came again.\nHe sat up, crossed to the door, and opened it.\nChizaram stood in the corridor in a sleeping robe two sizes too large for him, his feet bare on the cool stone floor. He was holding a small clay lamp that gave off just enough light to see his face by. His expression was the most complicated thing Amaechi had seen on a person who was not his mother. There was guilt in it, clearly, sitting right at the surface where anyone could read it. But underneath that was something else, something that looked like it had been there longer than tonight, something that had been waiting for an occasion to show itself.\nNeither of them spoke.\n\nAmaechi stepped back from the door. Chiza came in. Amaechi sat back on his mat. Chiza sat on the floor beside it, set the lamp between them, and pulled his knees to his chest. He looked at Amaechi''s hands and then looked away.\nThe lamp flame moved in the small currents of the room.\n"I knew the line," Chiza said finally. His voice was very quiet. "The third stanza. I knew it this morning before the lesson. I said it to myself on the way to the room and I knew every word."\nAmaechi waited.\n"I don''t know what happened. My mind just." He stopped. Started again. "I knew it."\n"I believe you," Amaechi said. He was surprised to find that he meant it.\n\nChiza looked at him then, quickly, as though checking whether there was cruelty hiding underneath the words. He seemed to find none because his shoulders dropped slightly.\n"Does it hurt very much?"\n"It is already better," Amaechi said. This was partially true. The throbbing had not stopped but it had moved from the front of his attention to somewhere just behind it, which felt like progress.\n\nChiza looked at the lamp. "I wanted to say something. In the room. After." He pulled at a loose thread on his robe. "I couldn''t find anything."\n"There wasn''t anything to say."\n"That made it worse."\nAmaechi considered this. He thought about the weight of Chiza''s gaze in the lesson room, the quality of it, the way it had pressed against the side of his face for the rest of the morning. He had resented it then. Sitting here now in the lamplight with the night drum sounding its slow count outside, he understood it differently. The guilt had had nowhere to go. It had simply gone where it could.\n"Why do you let them?" Chiza asked.\n"Let them?"\n"You could have cried. You could have made a sound. They cannot stop you from doing that."\nAmaechi was quiet for a moment. "I know."\n"So why didn''t you?"\nHe thought about his mother at the compound gate in her good wrapper with her hands folded and her eyes memorising his face. He thought about the word she had pressed into him like a thumbprint into soft clay. Amaechi. He thought about what it meant to carry something like a shield.\n\n"Because Ogbonna was watching," he said at last. "And I did not want to give him anything he could keep."\nChiza was quiet for a long time after that. Long enough that the lamp burned lower and the moonlight rectangle on the floor had moved nearly to the wall.\n"I will know the line next time," he said. "Every line."\nAmaechi lay back on his mat and looked at the ceiling. "I know you will."\n\nChiza did not leave immediately. He sat with the dying lamp between them and the night drum outside and the particular comfortable silence of two people who have just, without planning to, decided to trust each other.\nHe was still there when Amaechi finally fell asleep.','\n',char(10)),919,1,1,NULL,'2026-04-14 17:23:05','2026-04-14 16:28:46','2026-04-14 17:23:05',NULL,1,34);
INSERT INTO "chapters" ("id","novel_id","chapter_number","title","content","word_count","is_premium","is_published","audio_url","published_at","created_at","updated_at","scheduled_release_at","part_number","season_id") VALUES(393,51,5,' Bedfellows',replace('She made herself a list.\nNot on paper paper could be found but in her head, the way she had been trained. Ordered, numbered, revisited each morning like a prayer.\nOne: she was here to assist Councillor Ekene. To observe, to record, to relay information to her father''s office with accuracy and without personal interference.\nTwo: she had no business in the archive. She had no business with any member of the royal family, and specifically no business with the youngest prince, who was politically irrelevant and therefore irrelevant to the mission entirely.\nThree: what had happened in the archive was a moment of weakness. It was understandable. It would not happen again.\nShe held the list in her head through the morning briefing, through the formal introduction ceremony in the great hall where she stood three rows back and watched Ekene exchange ritual phrases with the sky court''s senior councillors, through the afternoon review session where she transcribed notes in her careful earth-script. She held it through dinner, where the delegation ate separately, and through the evening, when the sky outside the windows went from coral to a deep bruised purple she had no name for.\nShe was doing very well.\nThen on the fourth morning she went to the garden.\nShe had a reason. The silver-leafed plants were mentioned in a trade document she was cross-referencing and she needed to confirm the variety for an annotation. This was a legitimate work task. She wrote it down in her duty log before she left.\nHe was already there.\nNot reciting this time. Just sitting on the low stone bench at the garden''s edge, a small book open in his lap, not reading it. Looking at the sky the way someone looked at something that belonged to them and also exhausted them.\nHe saw her at the same moment she saw him.\nNeither of them left.\nShe crossed to the opposite end of the garden and crouched beside the silver-leafed plants and looked at them with the focus of someone who was absolutely here for the plants. She heard him close the book. She did not look up.\n"There are twelve varieties," he said, in earth-language. "The one you''re looking at is the coastal strain. Your people brought it, originally. Three hundred years ago, before."\nShe looked up then.\nHe was watching her without any particular expression. Informational. Like he was completing a record.\n"Thank you," she said, in earth-language.\nSilence. She looked back at the plant.\n"I''ve been thinking," he said, "about how this is going to go."\nShe waited.\n"You can''t come to the archive. If someone sees you there it becomes a problem for your delegation and a problem for me." He said it the way someone stated weather. Not unkindly. "And we can''t speak in public. In any language."\n"I know that," she said.\n"There is a maintenance corridor behind the archive. It connects to the east tower. It''s used twice a week by the cleaning staff, early mornings, Tuesdays and Fridays. The rest of the time it is empty." He paused. "I''m not suggesting anything. I''m telling you the information exists."\nShe stood up. Brushed the stone dust from her knees.\n"You want to keep meeting," she said.\n"I want access to a native speaker of an old coastal dialect," he said. "That is a scholarly interest. I have had it for four years."\n"And I''m just a convenient resource."\n"You''re the only living person I''ve been able to speak Mmo with." He said it plainly. The plainness of it was worse than if he had been dramatic. "I am aware that is not a small thing."\nShe looked at him for a moment. The sky behind him was its usual pale gold, the towers rising in the distance, everything clean and cold and magnificent. He looked out of place against it somehow. Too plain. Too still.\n"If we do this," she said, slowly, "there are conditions."\nHe waited.\n"Nothing I hear from you goes into my official reports. Nothing you hear from me goes to the court." She kept her voice low and even. "Whatever this is, it lives only here."\n"Agreed."\n"And if either of us decides to stop, we stop. No questions."\n"Agreed."\nShe nodded once. Then she said, in Mmo, her grandmother''s phrase for sealing a thing: It is witnessed by what we both remember.\nHe repeated it back to her. His formal register against her coastal dialect, the same words wearing different clothes, and underneath both versions the same language, the same three hundred years of it surviving in two people who had no reason to be standing in the same garden.\nShe picked a leaf from the coastal plant, tucked it into her notes for the annotation, and left without another word.\nWalking back across the bridge to the delegation tower she kept her face neutral and her hands loose and her breathing even.\nShe revised her list that night. She did not throw it away. She told herself that was the important part, that the list still existed, that she was still the person who had made it.\nBut she noted the maintenance corridor in the back of her memory, filed it carefully, and lay awake in the dark for a long time thinking about a dead language that had survived in two people on opposite sides of a three-hundred-year war.\nShe lay in the dark until she heard the archive bell strike the late hour. He would be in there now. She was certain of it the way she was certain of things she had no evidence for, and that certainty was itself the thing she should have been examining.','\n',char(10)),953,1,1,NULL,'2026-04-30 13:47:28','2026-04-14 16:36:07','2026-04-30 13:47:28',NULL,1,34);
INSERT INTO "chapters" ("id","novel_id","chapter_number","title","content","word_count","is_premium","is_published","audio_url","published_at","created_at","updated_at","scheduled_release_at","part_number","season_id") VALUES(394,51,6,' Roots and Thorns',replace('The letter arrived on a Friday, which was how Amaechi would always remember it afterward. Not the month, not the season, but Friday, because Friday was the day the palace messenger route came through from the eastern territories and he had been counting them for months without admitting to himself why.\nHe did not receive it directly.\nThat was the first thing. In Oke, a letter went from the hand that wrote it to the hand it was meant for, carried by someone trusted and delivered with whatever words the sender had attached to it verbally, the real message living in those spoken words as much as in the written ones. In the palace, letters from outside passed through the administrative office first. This was policy. Ogbonna had mentioned it in their first meeting with the same tone he used for everything, matter of fact, impersonal, a thing as settled as the architecture.\nAmaechi had not thought about it again until the morning Adaeze appeared at the door of the lesson room and told him Adviser Ogbonna wished to see him.\nHe knew before he arrived. Something in the quality of the summons, the timing of it, the particular way Adaeze had not met his eyes when she delivered it. He walked the corridor to the administrative wing with his face arranged carefully and his hands loose at his sides and the coal his mother had pressed into his chest burning at a frequency he had not felt since the morning they took him from Oke.\nOgbonna was standing when Amaechi entered, which was unusual. He stood at the window with his back to the room, looking out at the courtyard below with the contemplative posture of a man thinking about something pleasant. On the table behind him sat a folded piece of paper. Even from the doorway Amaechi could see the broken seal.\nOgbonna turned when he heard the door.\n"Amaechi." He said the name the way he said everything, precisely, without warmth, giving each syllable exactly its correct weight and no more. He crossed to the table, picked up the letter, and held it out.\nAmaechi walked forward and took it.\nThe paper was thin, the kind his mother had always used, purchased from the traders who came through Oke twice yearly from the northern routes. Her handwriting was on it, careful and slightly uneven, the letters of a woman who had taught herself to write past the age when learning is easy. He could see immediately that the fold was wrong, creased in a different place from how she always folded her letters, with the address side in rather than out.\nHe looked at Ogbonna.\nOgbonna looked back at him with that surface smile. "Correspondence from the eastern territories is reviewed as a matter of standard protocol. You understand."\n"I understand," Amaechi said.\nHe left before Ogbonna could say anything further. In the corridor, he found a corner between two carved panels and stood there and read.\nHis mother had been ill since the end of the dry season. A fever that came and went and came back stronger each time. The village healer had been twice. His father had sent for a specialist from the territory capital, a man who knew the fevers that came from the river lowlands. She was resting. She was being cared for. She wanted him to know but she did not want him to worry, and she knew these two wants were contradictory and she was sorry for that.\nShe asked him one question at the end of the letter. She asked if he was eating well.\nAmaechi read the letter three times standing in the corridor. Then he folded it the correct way, her way, address side out, and put it inside his robe against his chest and stood with his back against the carved panel and looked at the ceiling.\nHe could not leave. He had known this before he read a single word. Pledge boys did not travel home for illness. Pledge boys did not travel home at all unless the agreement between territories had broken down, and if it broke down it was not a homecoming but a crisis. His presence here was the condition of his father''s loyalty. His absence would signal something no one could afford.\nHe thought about his mother standing at the compound gate in her good indigo wrapper. The care with which she had been dressed. The three breaths she had held her forehead against his. She had known then. She had been memorising him then, not because mothers memorise their children at separations, which they do, but because she had understood, in a way he had not, what kind of separation this was.\nThe coal in his chest shifted and burned and he breathed through it steadily the way his father had taught him to breathe through pain.\nDown the corridor, a door opened and voices spilled out, two palace officials discussing something about grain allocation, moving past without noticing him in his corner. The palace continued its rhythms around him. The morning drums were already a long time ago. Lessons would be starting.\nHe thought about Ogbonna''s hands on this paper. His eyes moving across his mother''s uneven careful letters. Her private words sitting inside Ogbonna''s administrative mind, filed and noted and reduced to the category of information.\nHe thought about how a cage did not require iron bars. How sometimes all it needed was a set of rules stated pleasantly and a smile applied to the face at the correct moments.\nHe pushed off from the wall and walked back toward the lesson room. He kept his face still. He kept his hands loose. He carried the letter against his chest where it sat warm from his body and thought about a woman lying in a compound in Oke looking east from her sleeping mat, and he made her a promise he could not speak aloud.\nHe would come back. Whatever it cost. Whatever it took.\nHe would come back.','\n',char(10)),1011,1,1,NULL,'2026-04-14 17:23:33','2026-04-14 16:37:09','2026-04-14 17:23:33',NULL,1,34);
INSERT INTO "chapters" ("id","novel_id","chapter_number","title","content","word_count","is_premium","is_published","audio_url","published_at","created_at","updated_at","scheduled_release_at","part_number","season_id") VALUES(395,51,7,'What Brothers Do',replace('The boy''s name was Kolade and he had been at the palace three years longer than Amaechi, which he carried the way some people carry height, as though duration were a form of superiority and proximity to power were the same thing as possessing it.\nKolade was the son of a senior Zara chief, not a pledge boy but a ward, which was a different category entirely and one he ensured everyone understood. Wards had more freedom of movement, better placement at meals, and a future that included returning home with their dignity intact. He was fourteen, a year older than Amaechi, with a long face and quick clever eyes that were always measuring something. He had been friendly to Amaechi in the first weeks, the careful friendliness of someone taking inventory, and Amaechi had been polite in return without offering anything real.\nHe had learned early that Kolade''s friendliness was not about friendship. It was about positioning.\nThe opportunity Kolade had been building toward arrived on a Thursday during the open courtyard hour, when palace children mixed with less structure than the formal parts of the day allowed. A small group had gathered near the eastern fountain, the older boys mostly, the ones who had developed the habit of performing their conversations for each other. Chiza was there, which was unusual. He preferred the library during open hour but his attendant had guided him outside on the instructions of his physician, who had noted that the prince spent insufficient time in sunlight.\nKolade produced the game from inside his robe with the casualness of something he had not planned, which meant he had planned it carefully.\nIt was a riddle game, old and well known, where players recited proverbs and the group judged which carried the most wisdom. Harmless on its surface. Amaechi watched Kolade set it up and felt the shape of something underneath the surface but could not yet see it clearly.\nThree rounds passed cleanly. Then Kolade looked at Chiza with an expression of casual invitation.\n"The prince should give us one. His tutors say he has the sharpest mind in his year."\nCompliments directed at royalty in public were always traps. Chiza knew this and accepted the challenge anyway because refusing would have looked like the thing it was, an acknowledgment that the compliment was a trap, which was worse than the trap itself.\nChiza recited a proverb about a river that never reached the sea. It was good. The group murmured appreciatively.\nThen Kolade smiled and said, "Now the Oke boy. Let us hear what wisdom they carry in the eastern territories."\nThe way he said eastern territories landed in the group like a stone in water. Something in the phrasing made Oke sound remote and small and slightly absurd, the way you could make anywhere sound remote and small by saying its name with a specific quality of patience.\nEvery face turned to Amaechi.\nHe felt the geometry of it in an instant. Whatever he said next would be compared to what Chiza had said. If he said something stronger, Chiza was diminished in front of his peers by his own companion. If he said something weaker, Oke was diminished and Kolade''s implication confirmed. If he said nothing, he was a pledge boy without voice, which was what Kolade actually wanted the group to see.\nThe courtyard was very quiet.\nAmaechi looked at Kolade for one steady moment. Then he looked at Chiza, who was watching him with those quick eyes, and something passed between them, quick and wordless and completely clear.\n"My grandmother used to say," Amaechi began, his voice easy and unhurried, "that the river does not ask permission from the rock. It simply finds the way through." He paused. "But she also said that the rock and the river are both the river''s business. Neither one is the sea''s concern."\nA beat of silence.\nThen Chiza said, "That is the same river." His tone was thoughtful, as though working something out. "Your grandmother was speaking to mine."\nThe group laughed, genuinely this time, at the idea of two grandmothers from different territories arriving at the same river from different sides. The laughter moved through the circle and dissolved the tension Kolade had constructed, leaving nothing in its place except the mildly irritated face of a boy whose plan had arrived somewhere other than intended.\nKolade looked at Amaechi. Amaechi looked back at him with an expression that gave nothing away.\nLater, walking back to their quarters, Chiza said nothing about it for a long time. Then, quietly, "You could have let it land."\n"Let what land?"\n"The stronger proverb. You had one. I could see you choosing."\nAmaechi said nothing.\n"Why didn''t you use it?"\n"Because the game was not about proverbs."\nChiza was quiet. Then, "Thank you."\n"It was nothing."\n"It was not nothing."\nAmaechi did not answer. They walked the rest of the corridor in silence.\nThat night, lying on his mat while Chiza''s breathing deepened into sleep across the room, Amaechi looked at the ceiling and turned the day over slowly in his mind.\nHe had chosen without hesitating. That was the thing he kept returning to. Not the choice itself but the speed of it, the absence of any real internal debate. His first instinct had been to protect Chiza and he had followed it before he had examined it.\nIn Oke, your first instinct was your family. Then your people. Then your territory. That was the order of things, the order his parents had raised him inside, the order that had existed before he was born and would exist after.\nHe was not sure where Chiza sat in that order now. He was not sure the order still applied in the same way it had when he learned it.\nHe thought about his mother''s letter pressed between the pages of his lesson scroll. He thought about a woman lying sick in a compound in Oke while he stood in palace courtyards defending a prince''s dignity in riddle games.\nHe thought about who he was becoming and whether the boy who had left Oke would recognise the shape of him now.\nHe did not find an answer before sleep came.\nHe was not sure the answer existed yet.','\n',char(10)),1052,1,1,NULL,'2026-04-14 17:23:42','2026-04-14 16:38:54','2026-04-14 17:23:42',NULL,1,34);
INSERT INTO "chapters" ("id","novel_id","chapter_number","title","content","word_count","is_premium","is_published","audio_url","published_at","created_at","updated_at","scheduled_release_at","part_number","season_id") VALUES(396,51,8,'The King Falls',replace('The Eze of Zara collapsed on a Wednesday, in full court, in front of two hundred people who would all later claim they had seen it coming. None of them had seen it coming.\nAmaechi was not supposed to be in the assembly hall that morning. Pledge boys did not attend full court sessions. They sat in lessons while the palace''s formal business moved through its channels above them, distant and procedural, like weather happening on a different floor. But Nwosu had sent them to the records room to retrieve specific scrolls for the afternoon''s geography lesson, and the records room shared a wall with the assembly hall''s eastern corridor, and the door to that corridor had been left open by someone who had not expected anyone to be in the records room at that hour.\nHe heard it before he understood what he was hearing.\nA sound moved through the wall, through the corridor, through the open door, a sound he could not immediately name because it was made of several sounds layered together. A sharp collective intake of breath from two hundred people simultaneously. Then a crash, something heavy and wooden, a ceremonial staff perhaps, hitting stone. Then voices, all at once, in the particular register of people who are frightened and trying to sound like they are not.\nAmaechi set down the scroll he was holding and moved to the corridor door.\nThrough it he could see the side entrance to the assembly hall and through that entrance, at an angle, a portion of the hall itself. What he saw in that portion would stay with him for the rest of his life with the specific clarity that belongs to moments where the world reorganises itself permanently.\nEze Nwagu was on the floor.\nHe had not fallen the way ordinary men fell, sideways or forward, catching themselves partially on the way down. He had gone straight, the way a great tree goes when the root has already failed, a total surrender to gravity with no negotiation. His ceremonial robes were pooled around him. The chiefs nearest to him were crouching, hands reaching, faces stripped of the composure that court training spent years building. The throne sat empty above all of it, enormous and still and suddenly, terrifyingly, available.\nAmaechi pulled back from the doorway before anyone saw him.\nBy evening the palace was a different place.\nThe change was not loud. That was the thing that frightened Amaechi most about it. He had expected noise, the way crisis in Oke always came with noise, raised voices and running feet and the particular communal urgency of people who processed fear together. The palace processed fear privately, behind closed doors, in careful language, in the space between what was said and what was meant. The corridors looked the same. The guards stood at their posts. The meal drums sounded at their correct times.\nBut the conversations stopped when he walked past. Eyes moved in ways they had not moved before. Servants who had always operated with relaxed efficiency now moved with the taut deliberateness of people conscious of being watched.\nChiza was with his mother. He had been taken there immediately after the assembly and Amaechi had not seen him since. Their room felt enormous without him, the carved animals on the windowsill casting long shadows in the evening light.\nAmaechi sat on his mat and listened to the palace breathe its new, careful breath and thought about the empty throne.\nHe saw Ogbonna three times before the night was out.\nThe first time was at the physicians'' corridor, where Ogbonna stood with two senior chiefs in a conversation that stopped the moment Amaechi came into view and resumed the moment he passed. The second time was near the kitchen courtyard, where Ogbonna was speaking to a palace messenger, pressing something small and sealed into the man''s hand with a speed and discretion that belonged to a different register than the day''s official business. The messenger left through the servants'' gate, not the main road.\nThe third time was at the entrance to the wing where the senior chiefs had their quarters. Ogbonna was standing alone, doing nothing, which was the strangest sight of the three. He was simply standing in the corridor with his hands folded and his face turned slightly upward, the way a man stands when he is not waiting for anything specific but is very content to be exactly where he is.\nHe saw Amaechi and nodded once, a small precise inclination of his head, courteous and completely unreadable.\nAmaechi nodded back and kept walking.\nHe found Adaeze in the kitchen at the late hour, which was unusual for her, and asked her directly because he had learned that Adaeze responded better to directness than to careful approach.\n"How bad is it?"\nShe looked at the doorway before she answered. "The physicians say he is stable. The fever broke once already."\n"And the court?"\nShe looked at the doorway again. Then at him. "There are chiefs in this palace who have been waiting fifteen years for a throne they thought they deserved more than Nwagu." She picked up her tray. "Stable is not the same as safe. Not for the Eze. Not for anyone who stands near the throne."\nShe left before he could ask the next question.\nAmaechi stood in the empty kitchen and thought about Chiza sitting with his mother in the royal quarters, small and serious-faced, with those quick eyes that moved faster than he let on. He thought about a boy who described the weight of being the only son as standing on a bridge that everyone kept telling him was strong.\nThe bridge was moving now. Everyone could feel it.\nAnd somewhere in the palace''s eastern corridor, Ogbonna stood in the dark with his hands folded and his face turned up, patient as a man who has already worked out where every piece is going to land.','\n',char(10)),997,1,1,NULL,'2026-04-14 17:23:48','2026-04-14 16:41:25','2026-04-14 17:23:48',NULL,1,34);
INSERT INTO "chapters" ("id","novel_id","chapter_number","title","content","word_count","is_premium","is_published","audio_url","published_at","created_at","updated_at","scheduled_release_at","part_number","season_id") VALUES(397,51,9,' A Crown of Thorns',replace('Eze Nwagu died on a Sunday, nine days after he fell, in the deep hours before the morning drums. The palace learned of it not from an announcement but from a silence, the absence of the night drum''s slow count, which stopped between one beat and the next and did not resume.\nAmaechi woke to that silence and lay still in the dark and knew.\nAcross the room, Chiza''s mat was empty. He had been summoned to his mother''s quarters two days ago when the physicians stopped pretending the fever was retreating and had not returned since. Amaechi had spent those two nights alone in the room that felt too large, listening to the palace move through its quiet preparations with the efficiency of an institution that had always known this moment was coming and had been ready for it far longer than anyone would say aloud.\nHe dressed before the lamps were lit. He sat at the window and looked east into the dark and said his mother''s name once, quietly, the way you say the name of something you are holding onto.\nThe funeral lasted three days.\nThis was the custom for a ruling Eze, three days of ceremony that moved from private ritual to public procession to final rites, each day carrying its own specific weight and its own specific demands on the people nearest the throne. Amaechi had been told his role by the palace steward the morning after the Eze died, delivered in the same scroll-reading voice the man used for everything, as though the instructions were administrative rather than historic.\nHe would walk beside the king.\nNot behind. Not at a respectful distance with the other palace attendants. Beside. He would carry one of the royal banners in the procession, the amber and green one representing continuity of the royal line, and he would walk at Chiza''s left hand through every public portion of the ceremony.\nHe understood what this meant. Chiza had arranged it. Sometime in those two days in his mother''s quarters, sitting with grief and the approaching weight of the crown, the boy had thought of Amaechi and made sure he would be there. The thought of it pressed against Amaechi''s chest in a way he did not have clean language for.\nHe saw Chiza for the first time on the morning of the second day, at the assembly point for the procession.\nThe boy who emerged from the preparation chamber was Chiza and also not Chiza. The ceremonial robes added width to his shoulders that was not quite real. The coral beads at his neck caught the morning light and threw it back in small bursts. His face had been prepared by the ritual specialists, marked at the temples and forehead with the white clay of royal transition, and his expression had settled into something Amaechi had not seen there before. Not composure exactly. Something that had come through composure and out the other side into a place that was very still and very alone.\nThen Chiza found him in the crowd of attendants and something in that expression shifted, fractionally, the way a lamp flame shifts when a door opens in another room.\nAmaechi moved to his left side and took the amber banner from the attendant holding it and stood straight.\nChiza looked at him once. Then he looked forward.\nThe drums began.\nThe procession moved through the palace and out through the main gates and along the wide red road lined with iroko trees, the same road Amaechi had traveled four years ago on a horse with a soldier behind him, looking up at the carved faces above the gate with the wondering eyes of a boy who did not yet know what he had arrived into.\nThe crowd on either side of the road was enormous and very quiet. Thousands of faces, territory chiefs and village elders and ordinary people who had walked days to be present, all of them watching the boy-king move through the corridor of iroko trees with the amber banner at his left and the green one at his right and the weight of Zara on his eleven-year-old shoulders.\nAmaechi kept his eyes forward and the banner straight and his steps measured to match Chiza''s, and he thought about none of the things he was supposed to think about. Not his mother''s promise. Not Oke. Not Ogbonna. He thought only about the boy walking beside him, about a lamp burning low on a floor between two mats, about silence that was comfortable and trust that had been built in the specific dark of a room where nobody was watching.\nHe thought: I am here. Whatever this costs, I am here.\nThey passed the outer courtyard on the return through the palace gates, the wide paved space where the public witnesses to the ceremony had gathered in their hundreds, pressed close on all sides with their faces turned toward the procession.\nAmaechi saw Ogbonna at the moment Ogbonna saw him.\nThe adviser stood at the edge of the courtyard crowd, still and perfectly positioned, dark green robes immaculate, hands folded in front of him. He was not watching Chiza. He was watching Amaechi, with the steady focused attention of a man who has been watching for some time and intends to keep watching.\nThe look on his face was not anger. It was not surprise. It was not the surface smile he deployed in corridors and administrative offices. It was something underneath all of those things, something that had been waiting patiently through every previous expression for an occasion important enough to show itself.\nIt was certainty.\nNot the certainty of a man who has just decided something. The certainty of a man who decided long ago and has simply been waiting for the world to catch up to his conclusion. The look said: I see what you are becoming. I see what you think this moment means. I have seen further ahead than you have and I am not afraid of any distance between where you stand now and where you will eventually fall.\nThe procession carried Amaechi past him. The crowd closed behind them. The drums continued.\nAmaechi kept his eyes forward and the banner straight and his steps steady beside his king.\nBut the look stayed with him. It would stay with him for years, in corridors and lesson rooms and distant cities and the long roads of a life that was already in motion. It would become the thing he measured other dangers against, the cold certain patience of a man who had already decided the ending and was simply waiting, without urgency, for the story to arrive there.\nThat look. Patient and cold and absolutely certain.\nThe iroko trees closed overhead as they re-entered the palace, and the shadow of the gate fell across Amaechi''s face, and the first season of his life in Zara came to its end.','\n',char(10)),1161,1,1,NULL,'2026-04-14 17:24:01','2026-04-14 16:43:05','2026-04-14 17:24:01',NULL,1,34);
INSERT INTO "chapters" ("id","novel_id","chapter_number","title","content","word_count","is_premium","is_published","audio_url","published_at","created_at","updated_at","scheduled_release_at","part_number","season_id") VALUES(398,52,1,'The Inner Chamber',replace('The appointment was read aloud before the full council on a Tuesday morning, three months after the coronation, in the same assembly hall where Eze Nwagu had fallen. Amaechi stood at the back of the hall and listened to his own name in the mouth of the palace steward and felt the room change temperature.\nThe council of Zara was seventeen men arranged in a horseshoe around the throne, chiefs and advisers and senior officials who had served under Nwagu and now served under his son with the careful adaptability of men who understood that power was the constant and the person holding it was merely the current vessel. They were not cruel men, most of them. They were practical men, which in Amaechi''s experience was often more dangerous.\nChiza sat on the throne in his formal robes and received their business with the focused attention he brought to everything. He had grown in the three months since the coronation, not in height but in some quality of presence that was difficult to name precisely. He still made small drawings in the margins of documents when he thought no one was watching. He still woke before the drums and lay looking at the ceiling. But something had settled into his bearing that had not been there before, a stillness that was chosen rather than trained, and it made him look older than his years in a way that was not entirely comfortable to witness.\nThe steward finished reading the appointment terms. Amaechi, son of Dike of Oke, to be elevated from palace pledge to King''s personal attendant, with access to the inner chamber, the private meeting room, and the royal correspondence desk.\nSilence held for a moment.\nThen Ogbonna spoke.\nHe did not rise dramatically. He did not raise his voice. He simply straightened slightly in his council seat and began speaking in the measured, reasonable tone he used for everything, the tone that made his most damaging observations sound like he was doing everyone a favour by sharing them.\n"The council celebrates the King''s desire for trusted company," he said. "It is natural and correct for a young king to surround himself with familiar faces." A pause, precisely calibrated. "However, the position of personal attendant carries access to matters of state security. It has historically been held by individuals whose loyalty to Zara is unconditional and whose background has been fully examined." Another pause. "The son of an eastern vassal chief, however personally admirable, holds a loyalty that is by the nature of his position divided. This is not a question of character. It is a question of structure."\nHe sat back. He folded his hands. He looked at the throne with an expression of genuine, helpful concern.\nSeveral council members shifted in their seats. The shifting was not agreement exactly. It was the movement of men who found the argument inconvenient and structurally sound in equal measure, which meant they would not oppose it openly but would not defend against it either.\nAmaechi stood at the back of the hall and kept his face still and watched Chiza.\nChiza had not moved during Ogbonna''s speech. He sat with both hands on the armrests of the throne and listened to every word with the complete attention he gave to everything, and his face gave nothing away.\nWhen Ogbonna finished, Chiza waited.\nHe waited long enough that the silence became its own statement, long enough that two council members exchanged a brief glance, long enough that the room understood the pause was not hesitation.\nThen Chiza spoke.\n"The council''s caution is noted," he said. His voice was even and clear and carried to every corner of the hall without effort. "Amaechi of Oke has lived inside these walls for four years. He has studied what I have studied. He has stood beside me at the funeral of my father and carried the banner of this kingdom''s continuity before thousands of witnesses." He paused. "I am aware of what divided loyalty means. I am also aware of what undivided friendship looks like. They are not the same thing and the council would do well not to confuse them."\nHe looked at Ogbonna directly. "The appointment stands."\nThe steward made the notation. The council moved to its next item of business.\nAmaechi watched Ogbonna receive it.\nThat was the thing he would think about afterward, not Chiza''s words, which were clean and considered and exactly right, but the three seconds that followed them, the three seconds in which Ogbonna processed a public contradiction from a king before the full council of Zara.\nNothing moved in his face. Not the jaw. Not the eyes. Not the hands folded precisely in his lap. He absorbed the moment the way deep water absorbs a stone, completely, without displacement, the surface closing over it as though it had never arrived.\nThen he nodded once, the small precise nod he used to acknowledge administrative outcomes, and turned his attention to the next item on the council''s agenda.\nAmaechi had seen men receive bad news with anger and with grief and with the particular bitter resignation of people who had expected it. He had never seen anyone receive it with that quality of absolute stillness.\nIt was the most frightening thing he had witnessed in four years inside these walls.\nMore frightening than the cane. More frightening than the opened letter. More frightening, even, than the certainty he had seen on Ogbonna''s face in the funeral courtyard.\nA man who shouted when he lost had a ceiling to what he would do next. A man who went still had none.','\n',char(10)),942,0,1,NULL,'2026-04-14T17:29:43.467Z','2026-04-14 17:29:43','2026-04-14 17:29:43',NULL,2,35);
INSERT INTO "chapters" ("id","novel_id","chapter_number","title","content","word_count","is_premium","is_published","audio_url","published_at","created_at","updated_at","scheduled_release_at","part_number","season_id") VALUES(399,52,2,'What the Throne Costs',replace('The hardest thing about governing, Chiza told Amaechi once, was not the decisions. It was the faces of the men presenting the decisions to you, and the work of figuring out which part of each face was true.\nAmaechi had been in the inner chamber for six weeks and had already developed a system. He stood against the wall to Chiza''s left during council presentations, close enough to be useful and far enough to be overlooked, and he watched the faces. Not the words. Anyone could arrange words. Faces were harder to fully govern, and the inner chamber, with its smaller table and its absence of formal audience, loosened the governance slightly. A jaw that held perfectly in full council could tighten fractionally here. Eyes that stayed neutral in the assembly hall sometimes moved half a second too quickly to a colleague when a sensitive topic was raised.\nAmaechi catalogued these things and said nothing during the meetings and told Chiza what he had seen afterward, in the plain language Chiza had asked him early on to always use.\n"Plain," Chiza had said, the week Amaechi took up the post. "Whatever you see, tell me plainly. Everyone else in this palace speaks to me in a language with three meanings and I spend half my energy translating. I need one person who does not do that."\n"I can do that," Amaechi had said.\n"Even if what you see is something I will not want to hear?"\n"Especially then."\nChiza had looked at him steadily for a moment. "Good," he said. And that was the agreement.\nWhat Amaechi saw, in those six weeks, was a boy doing something genuinely difficult with considerably more skill than anyone outside the inner chamber would have credited him.\nChiza read every document himself. This was not as common among rulers as it should have been. He asked questions that cut past the prepared presentation to the actual situation underneath, and he asked them without embarrassing the presenter, which required a delicacy that was harder than the questioning itself. He made decisions at the pace that the decision required, quickly when quickness was called for and slowly when slowness was the correct tool, and he did not confuse the two.\nBut he was twelve years old and he was surrounded by men who had been in this palace since before he was born, men who carried twenty and thirty years of accumulated knowledge and accumulated interest and the very particular patience of people who know that a young king grows into either a strong ruler or a managed one, and who have already begun working toward the outcome they prefer.\nAmaechi watched them manage. He watched the way certain information arrived at the inner chamber pre-shaped, with the inconvenient edges already smoothed away. He watched the way Chiza''s genuine questions were answered thoroughly on their surface and incompletely at their core. He watched a senior chief named Adisa present a land redistribution proposal three weeks running, each time with minor adjustments that moved it fractionally closer to something that served Adisa''s territory and fractionally further from what Chiza had actually asked for.\nHe told Chiza all of it. Every session. In plain language, as agreed.\nChiza listened without interrupting and then sat quietly for a moment and then asked the question that addressed what Amaechi had identified. He never made it obvious where the question had come from. He had the instinctive political intelligence to protect his own source, and the source''s safety was something they had never needed to discuss.\nWhat Amaechi did not tell Chiza was what he was hearing in the corridors.\nNot because he was hiding it. Because he was still measuring it, still trying to separate what was real from what was performance, and with Ogbonna those two things were never easily separated.\nIt was Adaeze who first said it plainly, as Adaeze always said things.\n"He is asking questions about your father," she told him, without looking up from the lamp she was trimming. "About the tribute arrangements. About what Oke sends to the capital and what it keeps. About whether the amounts have changed since you came to the palace."\nAmaechi was quiet.\n"He has spoken to three council members privately in the last two weeks. I cannot tell you what was said. I can tell you that two of those three men looked at you differently in the corridor the next day."\n"Differently how?"\nShe set down the lamp. "The way people look at something they have been told to reconsider."\nHe thought about it that night, long after Chiza had fallen asleep.\nOgbonna was not spreading rumours. Rumours were crude instruments and Ogbonna did not use crude instruments. He was raising questions. Precise, reasonable, structurally sound questions about the nature of a pledge boy''s loyalty when that pledge boy had been elevated to the most trusted position in the kingdom. He was doing it quietly, one conversation at a time, in the patient thorough way he did everything.\nHe was not trying to remove Amaechi quickly. Quick removal would require evidence and confrontation and a public argument he might lose. He was doing something slower and more effective. He was making Amaechi''s presence in the inner chamber feel, to enough of the right people, like a question that had not yet been fully answered.\nQuestions, left to grow in the right conditions, became doubts.\nDoubts, tended carefully, became consensus.\nAmaechi lay in the dark and listened to the palace breathe and thought about a man with perfectly folded hands and the specific patience of someone who had never once in his life needed to hurry.\nOutside, the night drum sounded. One beat. Then silence.\nOne beat. Then silence.','\n',char(10)),961,0,1,NULL,'2026-04-14T17:30:41.187Z','2026-04-14 17:30:41','2026-04-14 17:30:41',NULL,2,35);
INSERT INTO "chapters" ("id","novel_id","chapter_number","title","content","word_count","is_premium","is_published","audio_url","published_at","created_at","updated_at","scheduled_release_at","part_number","season_id") VALUES(400,52,3,' The Decision',replace('Chiza told him on a Thursday evening, in the inner chamber after the last attendant had gone, in the direct way he had developed for conversations he had already finished arguing with himself about before beginning them with anyone else.\nThe lamps were low and the room smelled of the day''s business, ink and warm clay and the faint sourness of men who had been sitting in close conference since morning. Chiza was still at the table, one hand resting on a spread map of the northern territories, his finger tracing the road lines without quite touching them, the way he touched things he was thinking hard about.\nHe did not arrange an introduction. He simply looked up and said it.\n"I am sending you to Kara."\nAmaechi stood at his usual place beside the wall and kept his face still and waited for the rest.\n"The Kara king has requested a formal representative from Zara to sit at his court for a full season. Someone who will learn their diplomatic customs, build relationships with their senior officials, and return with the kind of knowledge that cannot be written in a report." Chiza looked at the map. "I want that person to be you."\n"Why me?"\n"Because I trust your eyes more than anyone else''s. Because you already read people better than men twice your age. Because Kara is the most important relationship in Zara''s north and right now we understand them through documents written by people who were there years ago and wanted to appear more informed than they were." He finally looked up fully. "And because you deserve more than a wall in my meeting room."\nThe last sentence landed differently from the others. Amaechi recognised it as the one Chiza had most carefully prepared and most genuinely meant.\n"It is an honour," Amaechi said.\n"It is the highest posting a non-titled official can receive. You will be received as my personal envoy. You will carry my seal." Chiza paused. "You will also, while you are there, begin the formal process for Oke''s tribute reassessment. Quietly, through the correct channels. I have not forgotten what I promised."\nHe had not promised in words. He had never promised in words. But three months ago, reading through the eastern territory accounts late at night, he had looked at the Oke tribute figures and then looked at Amaechi and said nothing, and the nothing had contained a complete sentence that both of them heard clearly.\nAmaechi looked at the map. Kara sat at the top of it, above the savanna line, connected to Zara by two major roads and a river route that became unreliable in the rainy season. A long way. A long time.\n"How long?"\n"One full season. Perhaps a little more."\nHe nodded slowly. "When do I leave?"\n"Ten days."\nThe preparation was practical and swift. A travel allocation, a formal letter of introduction bearing Chiza''s seal, a list of Kara court customs compiled by the palace''s senior correspondence clerk, a small guard of four soldiers for the road. Amaechi packed his wooden chest with the methodical care of someone who had learned that what you chose to carry revealed what you believed you were going back to.\nHe put his mother''s letters in first.\nOn the morning of the tenth day he rose before the drums as always and dressed in the new formal robes the palace tailor had made for the posting, deep blue with narrow bronze trim at the collar, the colours of a Zara envoy. He stood at the window and looked east for a longer time than usual.\nChiza was already awake, sitting on his mat with his knees drawn up, watching Amaechi pack the last items into the travel chest with the quiet attention he had always given to things he did not want to happen.\nNeither of them spoke for a long time.\n"The wooden animals," Amaechi said finally, nodding at the windowsill.\n"What about them?"\n"You never told me what the unidentifiable one is."\nChiza looked at it. A small carved figure, rounder than the others, with suggestions of limbs that could not quite commit to a species. "It is not any particular animal," he said. "It is whatever the story needs it to be."\nAmaechi picked up the travel chest. "Then it is the most important one."\nChiza stood and straightened his robes and looked at Amaechi with the expression he wore when he had already accepted something difficult and was now simply standing in it.\n"Come back smarter than you leave," he said.\n"That should not be difficult."\n"I meant it as a high standard."\n"I know."\nThey held each other''s gaze for one moment. Then Amaechi picked up his chest and walked to the door.\nThe road out of the palace ran through the main courtyard and past the administrative wing before reaching the outer gates. Amaechi had walked it hundreds of times in four years without particular thought. He walked it now with his travel chest under his arm and his four-man guard falling into step behind him and the morning light coming hard and golden through the iroko trees.\nOgbonna was standing at the edge of the administrative wing''s entrance.\nHe was not waiting in the way that announced itself as waiting. He was simply there, as he had been simply there in the entrance courtyard on the first day, four years ago, with that same quality of having been present for a long time and intending to remain so. His robes were immaculate. His hands were folded. His face carried its customary composure.\nWhen Amaechi drew level with him, Ogbonna bowed.\nIt was a correct bow, precise and full, the formal depth owed to a King''s personal envoy departing on official business. Every angle of it was exactly right. There was nothing in it that anyone watching could have identified as anything other than proper courtly respect.\nAmaechi stopped walking.\nHe looked at Ogbonna. Ogbonna straightened from the bow and met his gaze with an expression of complete, courteous blankness.\nNo surface smile. No cold certainty. Nothing readable at all.\nThat was what made it the most threatening thing that had ever happened to Amaechi. In four years he had learned to read Ogbonna through what showed on his surface, the calibrated smiles and the patient certainty and the stillness that followed public contradiction. He had built his understanding of the man from those signals.\nThis face gave him nothing. And a man who gave nothing was telling you that he no longer needed you to know what he was thinking. He had moved to a place beyond readable. He had moved to a place where the outcome was already settled and the signals no longer mattered.\nAmaechi walked on.\nHe did not look back. He passed through the outer gates and onto the wide red road lined with iroko trees, the same road he had arrived on as a boy of six with a soldier at his back and a promise still warm in his ear.\nHe walked north and did not look back.\nBut the bow stayed with him, correct and empty and absolute, all the way to the edge of the forest road where Zara''s walls finally disappeared behind the trees.','\n',char(10)),1220,0,1,NULL,'2026-04-14T17:31:36.365Z','2026-04-14 17:31:36','2026-04-14 17:31:36',NULL,2,35);
INSERT INTO "chapters" ("id","novel_id","chapter_number","title","content","word_count","is_premium","is_published","audio_url","published_at","created_at","updated_at","scheduled_release_at","part_number","season_id") VALUES(401,52,4,' The Road North',replace('The forest ended on the third day.\nAmaechi did not notice it happening gradually, the way he had expected. One hour the iroko trees were pressed close on both sides of the road, their canopy turning the light green and fractured, and then the road curved and rose slightly and he came over a low ridge and the trees simply stopped, and the world opened.\nHe had never seen the savanna before.\nHe had read about it in the palace geography scrolls, had studied the maps with Chiza on evenings when the lesson had drifted into curiosity, had heard the northern traders describe it in the market language of men trying to sell the idea of a place. None of that had prepared him for the actual experience of standing at its edge and feeling it look back at him.\nIt was enormous in a way that had nothing to do with size. The forest was also enormous but the forest held you inside itself, surrounded you with its noise and its green density, made you a part of its interior. The savanna did not hold you. It simply extended, in every direction, flat and gold and absolutely indifferent, the grass moving in long slow waves under a wind that had been traveling a very great distance before it reached you.\nThe sky above it was a different sky from the one over Zara. Wider. More serious.\nOne of the guards, a quiet older man named Tobenna who had made this road before, drew his horse level with Amaechi''s and looked out at the grass for a moment.\n"First time?" he said.\n"Yes."\nTobenna nodded as though this confirmed something he already knew. "It is larger every time," he said, which Amaechi did not fully understand until the days that followed made it clear.\nThe road north ran through the grass in a line that sometimes felt confident and sometimes felt like a suggestion. Villages appeared every day and a half, clusters of compound walls and thatched rooftops sitting in the landscape with the settled permanence of things that had decided their location carefully and intended to remain. The people here were lighter-built than Zara, with distinct clothing patterns, narrow-shouldered robes in dusty indigo and pale ochre, and a greeting custom that involved the right hand pressed flat to the chest before extending forward.\nAmaechi learned the greeting on the second day and used it at every village stop. Tobenna watched him do this without comment, which Amaechi had learned was Tobenna''s form of approval.\nThe food changed. The stews were thinner and spiced differently, with a heat that arrived late and lasted long. The bread was flat and charred at the edges and better than it looked. He ate everything offered and asked about what he could not identify and filed the information away with the same methodical attention he had developed for palace council meetings, the careful cataloguing of a person who has learned that everything is useful eventually.\nAt night he lay on his mat in whatever compound had offered them lodging and looked at the ceiling and thought about Chiza.\nNot with longing exactly. With something more like the awareness of an absence, the way you become conscious of a sound only when it stops. In four years he had spent no more than a handful of nights away from those shared quarters, and the habit of Chiza''s presence had embedded itself so deeply that its absence had a texture and a weight.\nHe thought about the face at the door. Not the formal farewell in the courtyard with the guards and the stewards and the palace''s ceremony arranged around them. The face in the room before that, sitting on the mat with his knees drawn up, watching Amaechi pack with the quiet attention of someone who had already accepted what was happening and was simply being present inside it.\nHe carried that face the way he carried his mother''s letters, close and with care.\nHe wrote the first letter on the sixth evening, before he had reached Kara, sitting outside a village compound with the last of the day''s light still in the western sky and the savanna going gold and then amber and then a deep reddish brown that reminded him of Zara''s walls.\nHe used the small writing board from his travel chest, the one he had packed without fully admitting to himself why.\nChiza,\nThe savanna is not what the maps suggest. Maps make it look like an absence, like the space between places. It is not an absence. It is its own complete thing. I think the men who made the maps had not actually stood inside it.\nThe road is good. Tobenna knows every village compound from here to the Kara border, which means we eat well and sleep without incident.\nI have been thinking about what you said, about needing one person who does not speak to you in a language with three meanings. I want you to know that works in both directions. Write to me plainly. Whatever is happening in that council room, write it to me as it actually is.\nI will be in Kara before the next full moon. I will write again from there.\nAmaechi\nHe read it back once. It was not quite everything he wanted to say, but it was true, which was the standard he had committed to and intended to keep.\nHe folded it, pressed Chiza''s seal impression into the soft wax from his travel kit, and gave it to the village courier Tobenna had arranged, a boy of about ten with serious eyes and a fast horse, who took it with both hands and tucked it into his satchel and rode south before the light finished leaving the sky.\nAmaechi watched him go until the grass swallowed him.\nThen he turned and looked north, where Kara sat at the top of everything, enormous and unknown, and the wind came across the savanna from that direction carrying the smell of distance and something else underneath it, something he could not name yet but that felt, in some way he did not entirely trust, like the future arriving early.\nHe went inside before the dark was complete.','\n',char(10)),1046,1,1,NULL,'2026-04-14T17:32:27.966Z','2026-04-14 17:32:28','2026-04-14 17:32:28',NULL,2,35);
INSERT INTO "chapters" ("id","novel_id","chapter_number","title","content","word_count","is_premium","is_published","audio_url","published_at","created_at","updated_at","scheduled_release_at","part_number","season_id") VALUES(402,52,5,' The City of Gold Dust',replace('Kara announced itself before it was visible. First the sound, a low continuous hum that had no single source, the compressed noise of a city that never fully quieted, not even at night. Then the dust, fine and gold-tinted, hanging in the air above the road in a permanent haze that caught the afternoon light and held it. Then the smell of roasting meat and animal hide and the sharp mineral bite of the gold-dust markets that gave the city its name among southern traders.\nThen the city itself, and Amaechi stopped his horse without meaning to.\nKara was built on a wide flat plain at the convergence of two rivers, and it sprawled across that plain with the undisciplined confidence of something that had been growing for centuries without anyone telling it where to stop. The buildings were different from Zara''s, taller and narrower, with flat rooftops where people sat in the evenings, their silhouettes visible against the sky from the approach road. Minarets rose at intervals above the roofline, slender and white, catching the sun. The markets were visible from outside the city walls, their noise preceding their sight, a dense layered sound of bargaining and movement and the particular music of commerce conducted at high volume across multiple languages simultaneously.\nThe gates were twice the height of Zara''s and guarded by soldiers in pale robes with long curved swords at their belts, who examined Chiza''s seal with the unhurried thoroughness of men who had seen many seals and been impressed by few of them.\nThen the seal was returned, a gate captain was summoned, and the quality of attention Amaechi received changed completely.\nThe formal welcome was conducted at the palace of Eze Tariq, ruler of Kara, in a receiving hall that made Zara''s assembly room look modest. Amaechi sat in the envoy''s chair, a specific seat positioned at a precise diplomatic distance from the throne, and received ceremonial greetings from a line of senior officials whose names and titles he committed to memory with the focused attention his years in Zara''s palace had made automatic.\nEze Tariq himself was a broad, slow-moving man in his late fifties with a face that gave the impression of having processed a very great deal of information over a very long period of time and having arrived at a state of general unsurprise. He received Amaechi''s formal address, Chiza''s letter of introduction, and the gifts from Zara''s treasury with the patient grace of a man performing a familiar ritual he still believed in.\n"The young king of Zara sends a young man," Tariq said, in the trade language they shared. His tone was not unkind. "Tell your king his instinct is correct. Youth reads youth more accurately than age reads youth. Tell him also that his envoy is welcome at our table for as long as the visit serves both kingdoms."\nAmaechi delivered his prepared response. It was well received.\nHe did not see the two princes until dinner.\nTheir names were Femi and Raji. Femi was the elder by four years, formally designated as heir, with his father''s broad build and a quality of coiled readiness that suggested he had been preparing for a specific moment for a long time. Raji was leaner, quicker-eyed, and possessed of the kind of charm that people with serious intentions sometimes deploy to ensure they are not taken seriously until it is too late.\nThey sat on opposite sides of the long dinner table and were courteous to each other with the specific elaborateness of people who had been told to be courteous and had decided to be so thoroughly that the courtesy itself became a form of hostility.\nThey were both, within the first hour, courteous to Amaechi.\nFemi asked him about Zara''s military arrangements along the eastern border, the kind of question that wore the clothing of polite interest and carried something else underneath.\nRaji asked him whether the young king of Zara was as capable as his correspondence suggested, which was also the kind of question that wore clothing.\nAmaechi answered both questions with the diplomatic middle language the palace had taught him, full of information that confirmed nothing and denied nothing, and smiled at both brothers with equal warmth.\nAfter dinner, the senior Kara official assigned to manage his visit, a careful man named Haruna, walked him back to his quarters through the palace''s inner courtyard. The night was warm and the sky above the flat rooftops was dense with stars.\n"You handled the princes well," Haruna said.\n"I said nothing of substance."\n"That is what handling them well looks like." He paused. "I am required to give you the official instruction. You are a guest of the Kara throne and as such you are expected to maintain a position of complete neutrality regarding the matter of succession."\n"I understand."\n"The instruction is genuine and also impossible," Haruna continued, in the same level tone. "Both princes will approach you in the coming days with versions of the same request. Femi will want Zara''s formal acknowledgment of his designated status. Raji will want Zara''s informal signal that his own claim would not be unwelcome." He stopped walking. "Neither will accept genuine neutrality. Neutrality, to a man fighting for a throne, looks exactly like support for his opponent."\nAmaechi stood in the courtyard and looked at the stars and thought about Ogbonna, who had spent four years demonstrating that the most dangerous positions were the ones that appeared simple.\n"What do you suggest?" he asked.\nHaruna considered this with the seriousness it deserved. "I suggest you write to your king quickly and ask for specific instruction. And I suggest you sleep well tonight, because both princes will have sent you invitations before morning."\nHe bowed with genuine courtesy and walked back toward the administrative wing.\nAmaechi stood alone in the Kara courtyard, under the wide northern sky, surrounded by the city''s endless hum, and understood with complete clarity that he was standing at the centre of something that had been in motion long before he arrived and that had no interest whatsoever in his neutrality.\nHe went inside and got out his writing board.','\n',char(10)),1033,1,1,NULL,'2026-04-14 17:33:44','2026-04-14 17:33:22','2026-04-14 17:33:44',NULL,2,35);
INSERT INTO "chapters" ("id","novel_id","chapter_number","title","content","word_count","is_premium","is_published","audio_url","published_at","created_at","updated_at","scheduled_release_at","part_number","season_id") VALUES(403,52,6,'Fire in Kara',replace('LThe accusation was made publicly, which was the point of it. A private accusation could be denied. A public one had to be survived.\nIt happened at the weekly court gathering, twelve days into Amaechi''s stay, in the great hall where Eze Tariq received his chiefs and senior officials every Thursday morning. Amaechi had attended the previous two gatherings without incident, seated in the envoy''s position, observing the business of Kara''s court with the quiet cataloguing attention he had developed over years of palace walls.\nHe had been careful. He had taken Raji''s dinner invitation and Femi''s separate invitation to a morning ride and managed both with the precise neutrality Haruna had correctly identified as impossible but which Amaechi had decided to attempt anyway, because the alternative was choosing a side and choosing a side was the one thing he absolutely could not do.\nHe had thought he was managing it.\nHe had not been managing it. He had been managing the surface of it while something else moved underneath.\nFemi''s senior adviser, a hard-faced man named Usman who wore his robes like armour, stood during the open address portion of the gathering and spoke in the formal Kara court language that Amaechi followed at about three quarters'' comprehension. He spoke for four minutes. The hall was completely silent for all four of them.\nHaruna, seated beside Amaechi, translated in a murmur so quiet it barely existed. Usman was stating that the envoy from Zara had been observed in three private meetings with the younger prince over the preceding week. That these meetings had not been disclosed to the court''s diplomatic office as protocol required. That the content of these meetings was unknown but their frequency and privacy suggested an arrangement that Zara''s official position of neutrality did not account for.\nAmaechi kept his face still and his hands loose in his lap and looked at the middle distance the way he had learned to look at things that required the appearance of calm.\nEze Tariq listened to Usman with his characteristic unsurprise and then looked at Amaechi with an expression that was not accusatory and not sympathetic and not anything that helped.\n"The envoy of Zara may respond," he said.\nEvery face in the hall turned.\nAmaechi stood.\nHe had three seconds between standing and speaking, which was not enough time to construct anything and was exactly enough time to remember everything the palace had taught him about the architecture of a response that could not afford to be wrong.\nHe spoke in the trade language, slowly and clearly, so that every person in the hall could follow without assistance.\n"The court''s concern is correct and the protocol failure is mine," he said. "The meetings with Prince Raji were not disclosed to the diplomatic office. That was an error of procedure and I take responsibility for it." He paused. "The meetings were initiated by the prince and their content concerned Kara''s existing trade arrangements with Zara''s eastern territories, matters relevant to my official brief. There was no arrangement discussed or implied regarding the succession. I am prepared to provide a full written account of every exchange to the court''s diplomatic office before this day''s end."\nHe sat down.\nUsman looked like a man who had brought a specific tool for a specific purpose and found the thing he had intended to use it on had shifted position.\nEze Tariq nodded once, accepted the offered account as satisfactory, and moved the gathering to its next item.\nThe soldiers came that night.\nNot many. Four men in Femi''s household colours, positioned at the corners of the guest quarters compound when Amaechi stepped outside after the lamps were lit, standing with the patient stillness of people who had been told to be present rather than to act. A message delivered through physical arrangement rather than words, the grammar of implied threat that powerful men used when they wanted you to understand something without giving you anything to formally respond to.\nAmaechi stood in the doorway and looked at the nearest soldier and measured the distance to the compound gate and calculated the geometry of the situation with the cold precision of a person who has understood that panic is only useful as information about what is happening and then must be set aside.\nZara was twenty-two days south. Tobenna and the three other guards were housed in the soldiers'' compound on the far side of the palace complex. Haruna''s jurisdiction extended to diplomatic protocol and not to this.\nHe was alone with this in the way that mattered.\nHe went back inside and sat on his mat and thought about every man he had watched in every council room and corridor for the past four years. He thought about the specific education of growing up in a palace, the understanding it built in you about how power communicated, how it signalled, what it wanted and what it feared.\nFemi did not want to harm a Zara envoy. Harming a Zara envoy would produce consequences that Femi, as a man positioning himself to inherit a kingdom, could not afford. What Femi wanted was for Amaechi to be frightened enough to do one of two things. Leave Kara early, which would read as a withdrawal of Zara''s interest and damage Raji''s position. Or send a communication to Zara that was intercepted and revealed a bias, which could be used to discredit whatever position Zara eventually took.\nBoth options required Amaechi to react.\nSo he would not react.\nHe spent the night on his mat, fully dressed, not sleeping, running through every conversation in every meeting since his arrival and extracting from it the specific information he had collected, about Kara''s grain surplus and the northern road conditions and the water agreements between Kara''s eastern villages and Zara''s tributary territories. Information that was genuinely useful, genuinely within his brief, genuinely neutral.\nBefore the morning drums he had a letter written to Haruna that was seven dense paragraphs of trade and agricultural detail and contained, in its third paragraph, a precise and undramatic account of the soldiers at his compound corners and a formal request that the diplomatic office note the incident for the record.\nFormal. Documented. Undramatic.\nNot a frightened man. An official doing his job.\nHe gave it to the compound boy for morning delivery and stepped outside into the early light.\nTwo of the four soldiers were still there. The other two had gone, which meant Femi had received some communication during the night that had reduced the message by half. Amaechi looked at the remaining two soldiers with the same expression he used for palace guards doing their ordinary rounds.\nThen he went back inside and got out his writing board again.\nHe had another letter to write. This one to Chiza. And he would write it plain, as agreed.','\n',char(10)),1148,1,1,NULL,'2026-04-14T17:34:41.212Z','2026-04-14 17:34:41','2026-04-14 17:34:41',NULL,2,35);
INSERT INTO "chapters" ("id","novel_id","chapter_number","title","content","word_count","is_premium","is_published","audio_url","published_at","created_at","updated_at","scheduled_release_at","part_number","season_id") VALUES(404,52,7,' Letters Written in Blood',replace('The first letter was measured. The second was urgent. The third was something he did not have a clean name for, somewhere between frightened and exhausted and too honest for his own comfort.\nHe wrote the first one the morning after the soldiers appeared at his compound corners, in the careful diplomatic prose the palace had trained into him, the kind of writing that conveyed information without conveying the condition of the person conveying it. He described the public accusation, his response, the overnight presence of Femi''s men, and his formal complaint to Haruna. He described the political geometry of the succession crisis with the detached precision of a man filing a report. He sealed it and sent it south with Tobenna''s fastest rider and told himself he had done the correct thing.\nChiza''s reply arrived nineteen days later.\nAmaechi. Your handling of the accusation was exactly right. Formal, documented, undramatic. Do not give Femi a reaction he can use. Continue your work on the trade arrangements and let the succession matter resolve itself around you. You are a river, not a rock. Find the way through.\nI am well. The council is manageable. Adisa tried the land proposal again. I asked him four questions and he withdrew it before I finished the third. I think you would have enjoyed watching.\nStay safe. Write when you can.\nAmaechi read it in his quarters with the afternoon light coming through the narrow window and felt, for a moment, the specific warmth of being known by someone who paid attention. Then he folded it and put it with his mother''s letters and went back to the situation, because the situation had not paused for the warmth.\nThe second letter was written three weeks later, after Raji summoned him to a private meeting and told him, with the direct honesty of a man who had decided pretense was no longer efficient, that Femi had been speaking to two of Eze Tariq''s senior generals. That the conversations concerned the succession timeline. That Raji believed his brother was preparing to move before their father died rather than after.\nAmaechi wrote to Chiza that night and the measured prose cracked slightly at the edges.\nThe situation here has changed. What began as a diplomatic positioning contest has the shape now of something more serious. I need to know whether Zara has a formal position on Kara''s succession and whether that position can be communicated to Eze Tariq directly, because my presence here as a neutral envoy is becoming a liability to the neutrality itself. Every day I remain without a declared position I am used as evidence of a position by whichever prince finds it useful that morning.\nI am managing. I want you to know that clearly. But I need instruction, not advice about rivers and rocks.\nHe sealed it and sent it and waited.\nChiza''s reply arrived twenty-two days later.\nI hear what you are saying between the words and I want you to know I am taking it seriously. I am consulting with the council on a formal position. These things move slowly here. I know that is not what you need to hear.\nI want to say something else and I want to say it as plainly as I know how. You are the most capable person I have ever watched in a difficult room. Not because you are fearless. Because you are afraid and you think clearly anyway. Whatever is happening in that city, you are equal to it. I believe that with everything I have.\nCome home when it is done. Come home whole.\nAmaechi read it sitting on his mat with his back against the wall and the walls of the room feeling closer than the architecture justified. He read it twice. The second time something in his chest moved in a way that was not entirely comfortable, the specific ache of being cared for by someone who was far away and could not help.\nHe did not write the third letter. He wrote toward it for two weeks and could not find the version that was honest without being alarming, so he put the writing board away and worked instead.\nHe went to Haruna with everything he had documented. Every meeting, every implication, every piece of the succession architecture he had assembled over seven weeks of careful observation. He laid it out without editorialising and asked Haruna what the diplomatic office needed to contain the situation.\nHaruna listened for a long time without interrupting, which was how Amaechi knew he was being genuinely useful.\nTogether they constructed the framework of a formal agreement, a trade and security accord between Kara and Zara that gave both princes a concrete reason to maintain stability, because instability during a formal accord negotiation would reflect badly on whichever side provoked it. It was not a resolution of the succession. It was a structure that made open conflict more costly than continued patience.\nFemi''s adviser Usman reviewed it and said nothing for three days and then agreed to it.\nRaji reviewed it and smiled his charming smile and agreed to it immediately, which meant he had found something in it that served him, which was fine. It served Amaechi''s purpose regardless.\nThe morning he left Kara, Haruna walked him to the city gates.\n"You are a good diplomat," Haruna said, at the gate. "Better than your years suggest you should be."\n"I had good training."\n"Training does not give a person that quality of steadiness in a room that is trying to move." He pressed his right hand flat to his chest in the Kara greeting. "Whatever you left behind here, it was worth what you built."\nAmaechi returned the gesture. He thought about what Haruna meant and did not ask for clarification, because he already knew.\nHe had left behind the part of himself that believed difficulty could be managed from a safe distance. That part was gone. What had grown in its place was harder and quieter and not entirely comfortable to carry.\nHe turned south and walked into the savanna.','\n',char(10)),1020,1,1,NULL,'2026-04-14T17:35:49.335Z','2026-04-14 17:35:49','2026-04-14 17:35:49',NULL,2,35);
INSERT INTO "chapters" ("id","novel_id","chapter_number","title","content","word_count","is_premium","is_published","audio_url","published_at","created_at","updated_at","scheduled_release_at","part_number","season_id") VALUES(405,52,8,'Bad News',replace('The last letter from Chiza arrived on a Tuesday, thirty-three days before the messenger came.\nAmaechi knew the exact count because he had been counting.\nIt was not unusual for letters to take three weeks crossing the savanna road. Weather, courier availability, the unpredictable business of distance, all of these could stretch the journey without meaning anything beyond themselves. He had told himself this on day twenty-two. He had told himself again on day twenty-six with slightly less conviction. By day thirty he had stopped telling himself and simply counted, the way you count something you are afraid to stop counting because the alternative is admitting what the number might mean.\nHe had not written to Chiza since returning from Kara. This was the thing that sat underneath the counting and would not be still. He had intended to write. He had sat with the writing board three times in three weeks and found that the honest version of what he wanted to say required a clarity about his own condition that he had not yet fully achieved. Kara had changed something in him and he was still taking the measure of the change, still finding its edges in the dark, and he had not wanted to send Chiza a letter that was more confusion than communication.\nHe had told himself he would write when he knew what to say.\nNow thirty-three days had passed without a letter from Zara and he sat with that silence and understood, in the way the body understands things before the mind has finished its argument, that he had waited too long.\nThe messenger arrived at dawn on a Wednesday.\nAmaechi heard the horse in the compound before the boy knocked, a hard irregular rhythm that meant the animal had been pushed past its comfortable pace for a significant portion of the road. He was already dressed, already at the window, already carrying the cold thing that had been growing in his chest for thirty-three days and was now very heavy and very still.\nThe knock came. He opened the door.\nThe messenger was young, perhaps sixteen, with the dust of three days'' hard riding on his face and in his robes and settled into the lines around his eyes in a way that made him look older than he was. He was from the palace. Amaechi recognised the messenger corps insignia on his collar, a detail so familiar it landed like a blow.\nThe boy held out the letter with both hands.\nHe was not meeting Amaechi''s eyes. That was the thing. In the palace, messengers were trained to meet the recipient''s eyes during delivery as a mark of the message''s official status. This boy was looking at the ground to the left of Amaechi''s feet with the focused attention of someone who has been told difficult news so many times in the past three days that he has found a specific patch of ground to look at while it is received.\nAmaechi took the letter.\nHe closed the door.\nHe stood in the centre of the room and looked at the folded paper in his hands. Chiza''s seal was on it, the official palace seal, the one used for formal correspondence, not the smaller personal one Chiza used on the letters he wrote himself late at night at the reading table. The handwriting on the outside was a clerk''s handwriting. Precise and impersonal and the wrong hand entirely.\nHe opened it and read it once.\nThe language was formal and correct and said what it had to say in the careful measured prose of official palace communication, the kind of writing designed to convey information without conveying the devastation of the information, as though the right arrangement of words could make the content more bearable.\nIt could not.\nAmaechi stood with the letter in his hands and read it once and did not read it again.\nHe had always known, in the abstract, distant way you know things that are true but feel permanent, that Chiza was ill. The letters over the past three months had mentioned fatigue, a persistent cough that the physicians were managing, a reduced schedule that the council had arranged with appropriate discretion. Managed. Monitored. Under control. The language of people who needed something to be under control and had decided that language was sufficient to make it so.\nThe letter in his hands was written in different language.\nHe stood with it for what felt like a long time and was probably less than a minute and felt the cold thing in his chest complete its work, settling into a weight that he understood instinctively was not temporary.\nThen he moved.\nThe wooden chest came out from under the sleeping mat. His hands were steady, which surprised some portion of him that was still observing from a distance. He folded his robes and placed them in the chest with the methodical care he brought to packing, the habit of a person who had learned that what you chose to carry revealed what you believed you were going back to.\nHe put the letters in first. His mother''s bundle, tied with cord, worn soft at the edges from years of handling. And underneath them, every letter from Chiza, twenty-one of them, in the order they had arrived, the first ones warm and slightly parental and full of the voice Amaechi had been hearing in his head since the savanna road and the last ones shorter, the handwriting slightly less even, the sentences ending sooner than they used to.\nHe had not let himself read that unevenness for what it was.\nHe read it now.\nThe chest closed. The buckle fastened. He lifted it and turned and the messenger was still outside, he could hear the boy''s feet on the compound stone, moving in the small uncertain pattern of someone who has not been told whether to wait or go.\nAmaechi opened the door.\n"Tell Tobenna to ready the horses," he said. "We leave within the hour."\nThe boy looked at him for the first time, quickly and then away. He nodded and went.\nAmaechi stepped into the compound and looked south, where the savanna road ran straight and gold into the distance, where Zara sat at the end of twenty-two days of hard riding if the weather held and the horses were strong and a man did not stop for anything that was not strictly necessary.\nTwenty-two days.\nHe stood in the dawn light and did the calculation and knew, in the same way the body knows things before the mind has finished its argument, that twenty-two days was the wrong number.\nHe picked up his chest and walked to the stables.','\n',char(10)),1124,1,1,NULL,'2026-04-14 17:37:10','2026-04-14 17:36:50','2026-04-14 17:37:10',NULL,2,35);
INSERT INTO "chapters" ("id","novel_id","chapter_number","title","content","word_count","is_premium","is_published","audio_url","published_at","created_at","updated_at","scheduled_release_at","part_number","season_id") VALUES(406,52,9,' The Closed Door',replace('He rode the last six hours in the dark because stopping was not something his body would agree to, and when the palace walls finally appeared against the night sky, pale and enormous and exactly as he had left them, he felt nothing he had a name for.\nThe road south had taken eighteen days.\nNot twenty-two. Eighteen. He had pushed the horses to the edge of what was responsible and slightly past it, sleeping four hours when he slept at all, eating in the saddle, speaking to Tobenna and the guards only when the road required it. The savanna had blurred past him in long gold stretches that he stopped seeing after the third day and simply moved through, his body on the horse and everything else fixed on a point somewhere ahead that kept receding as he approached.\nTobenna had not questioned the pace. On the fourth day, riding level with Amaechi in the early morning light, he had simply said, "We will make it in eighteen if the eastern river crossing is clear."\n"Make sure it is clear," Amaechi said.\nTobenna had made sure it was clear.\nHe did not let himself think about what he was riding toward. He allowed himself only the road, the next compound, the next water point, the next morning. He had discovered somewhere around the seventh day that hope and dread occupied the same space inside him and that the only way to carry both without being destroyed by either was to narrow his attention to the immediate and keep it there by force.\nHe thought about the road. He thought about the horses. He thought about nothing else.\nFor eighteen days.\nThe palace gate guards recognised him and opened the smaller entrance gate without ceremony, their faces carrying the particular careful blankness of people managing the gap between what they knew and what they had been told to say. One of them began a formal greeting and stopped himself in the middle of it.\nThat stopping was the first confirmation.\nAmaechi walked through the gate.\nThe palace at this hour was not empty but it was reduced, the night staff moving through their routines with the quiet efficiency of people working in a space that had recently changed and had not yet fully settled into its new shape. The lamps in the outer courtyard were lit at the standard intervals. The fountain caught the light and held it. Everything looked the same.\nNothing was the same. He could feel it in the air the way you feel weather before it arrives, a pressure change, a quality of atmosphere that the body registers before the mind has caught up.\nHe did not stop at his quarters. He did not stop anywhere. He walked the route he had walked a thousand times across four years, through the outer courtyard and the administrative corridor and the inner passage that curved left past the records room and straightened into the residential wing, and his feet knew every stone of it, every worn edge and uneven join, and the familiarity of it was the most painful thing he had experienced on this entire eighteen-day journey.\nHe turned the final corner.\nThe corridor outside the king''s chamber was lit by two wall lamps that threw long shadows toward the closed door at its end.\nThe door was closed.\nHe had known it would be. He had known since the messenger''s eyes found that patch of ground beside his feet in the Kara compound at dawn. He had known for eighteen days of hard riding through the gold and the dust and the long flat nothing of the savanna. His body had known before the letter. The thirty-three days of silence had known.\nKnowing did not prepare him for the door.\nHe stood at the entrance to the corridor and looked at it, the carved wood he had passed through every day for two years, the specific grain of it, the iron handle worn smooth at the place where hands had reached for it most often, and he stood very still and breathed the way his father had taught him to breathe through pain, steadily and from the bottom of the chest, and he did not move for a long time.\nThen he became aware of the figure standing to the right of the door.\nOgbonna.\nHe stood in the shadow between the two wall lamps with his hands folded and his robes immaculate and the new council seal at his neck catching the lamplight in small cold flashes. He was not doing anything. He was simply present, in the way he had always been simply present, with that quality of having been there a long time and intending to remain.\nHe looked at Amaechi without expression.\nNot the surface smile. Not the cold certainty from the funeral courtyard. Not the careful composure of a man receiving a public contradiction. Not even the empty courtesy of the bow at the gate. All of those had been performances for specific moments. This was none of those things. This was the face underneath all the performances, still and without feature, the face of a man who has arrived at the destination he set out for so long ago that the arriving itself requires no expression.\nHe did not speak.\nHe did not need to speak.\nThe corridor said everything. The closed door said everything. The seal at Ogbonna''s neck said everything. Twenty years of patience, of precise questions and careful whispers and perfectly administered punishments and courteous bows at gate, had arrived here, in this corridor, at this hour, with this door.\nAmaechi stood at the entrance to the corridor and looked at the man who had won and felt the full weight of eighteen days and four years and a childhood and a promise all pressing down at once.\nHe did not look away.\nNeither did Ogbonna.\nThe lamps held their light between them and the door stayed closed and the palace breathed its new, permanent breath around them both, and the second season of Amaechi''s life came to its end in that corridor, in that silence, in the space between a closed door and the man who had always known it would close.','\n',char(10)),1046,1,1,NULL,'2026-04-14T17:38:12.065Z','2026-04-14 17:38:12','2026-04-14 17:38:12',NULL,2,35);
INSERT INTO "chapters" ("id","novel_id","chapter_number","title","content","word_count","is_premium","is_published","audio_url","published_at","created_at","updated_at","scheduled_release_at","part_number","season_id") VALUES(407,53,1,' Going Home to a Stranger',replace('They did not expel him loudly. Loud expulsion would have required a charge, a hearing, a formal record, and formal records created the kind of documentation that could be contested. What they did was quieter and more complete.\nIt took eleven days.\nOn the first day, his access to the inner chamber was suspended pending a review of his official status under the new administration. The suspension was delivered in writing, in the correct format, with the correct seals, by a clerk who did not meet his eyes. On the third day, his quarters were reassigned, he was moved to the eastern guest wing, where visiting dignitaries from minor territories stayed, in a room that was comfortable and entirely without the specific character of a place that belonged to you. On the seventh day, his stipend allocation was reclassified from palace staff to transitional guest, a category he had not previously known existed and which carried, the documents explained, a standard duration of thirty days before formal conclusion.\nOn the eleventh day, Ogbonna sent him a letter.\nIt was the first direct communication between them in four years. It was three sentences. It noted that Amaechi''s status as pledge had formally concluded with the death of the king under whose authority it had been issued. It noted that the transitional arrangements would support his return to the territory of Oke at his convenience. It expressed, in the final sentence, the new administration''s gratitude for his years of service to Zara''s crown.\nGratitude. The word sat in his chest like a stone dropped in still water, spreading its rings outward through everything it touched.\nHe packed his wooden chest for the last time that afternoon.\nThe journey south took nine days and he made it largely in silence, with two palace horses he had been allocated for the road and no guard, which was itself a statement about what he was now and what he was not. He passed through the forest roads he had traveled as a child on a soldier''s horse with a bundle and a promise, and the roads were the same roads, the same red earth, the same canopy turning the light green and fractured overhead, the same birds calling from invisible places.\nHe was thirty-one years old.\nHe had left Oke at six and he was returning at thirty-one and the arithmetic of that sat with him through the nine days like a traveling companion he had not invited and could not dismiss.\nHe did not think about Chiza. He had made this decision somewhere in the corridor outside the closed door and had held it through the eleven days of careful administrative removal and held it still now. There would be time for that later, in some room in some future he had not yet reached, but not on this road, not yet. The grief was there, he could feel its mass and its permanence, but he had put a door between himself and it the way you put a door between yourself and a fire when the fire is too large to approach directly. Later. Not yet.\nHe thought instead about the road. He thought about what was at the end of it.\nHe smelled Oke before he saw it.\nCook smoke and wet earth and the specific green smell of the forest thinning into the hilly eastern scrubland that marked the beginning of his father''s territory. His body recognised it before his mind had processed the recognition, a physical response in the chest and the throat that had nothing to do with decision and everything to do with the twenty-five years of cellular memory that a place could press into you before you were old enough to know it was happening.\nHe stopped his horse on the rise above the village and looked down.\nThe compound walls were the same red earth, the same organic sprawl of a settlement that had grown by need rather than plan. The iroko at the compound''s eastern edge was larger than he remembered, its canopy spreading wide and unhurried above the roofline. Children moved between the compounds in the late afternoon light, their voices carrying up the rise in fragments, words he could not hear individually but whose texture was immediately and completely familiar.\nHe had dreamed this view. Not often, not with the frequency of genuine longing, but it had come to him in the deep hours of palace nights, this exact rise, this exact angle, the village sitting in its valley with the hills behind it and the sky doing what the sky did here, wider and more personal than the sky anywhere else he had been.\nThe dream had not included the feeling of being a stranger looking at it.\nHe rode down.\nThe first person to see him was a woman drawing water from the compound well, middle-aged, with a wrapper in a pattern he did not recognise from any family he remembered. She looked up at him on the horse with the measuring assessment that people in small settlements gave to unfamiliar arrivals, the quick cataloguing of threat and purpose and origin.\nShe did not recognise him.\nHe asked her for the Dike compound and she pointed without warmth and went back to her water.\nHe rode in the direction she pointed and passed three more people who looked at him with the same stranger''s assessment and he understood, with a completeness that the nine days of road had been preparing him for without his permission, that this was the condition he had arrived into.\nHe had left a boy and returned a man that nobody here had watched become. The shape of him, the bearing the palace had built into his posture and his face and the way he occupied space, was not the shape of anything Oke had produced or expected. He was made of a place he had just been removed from, and he was standing in the place that had made him before all of that, and neither place fully contained what he had become.\nHe was, in the most specific sense he had ever experienced the word, between.\nThe Dike compound gate appeared ahead of him.\nHe stopped his horse and sat for a moment and breathed, once, from the bottom of his chest, the way his father had taught him and his mother had reinforced and Zara had made automatic.\nThen he dismounted and went in.','\n',char(10)),1080,0,1,NULL,'2026-04-14T17:43:25.378Z','2026-04-14 17:43:25','2026-04-14 17:43:25',NULL,3,37);
INSERT INTO "chapters" ("id","novel_id","chapter_number","title","content","word_count","is_premium","is_published","audio_url","published_at","created_at","updated_at","scheduled_release_at","part_number","season_id") VALUES(408,53,2,'His Mother''s Promise',replace('Nobody told him where she was buried. He found it himself, the way you find things that your body has been navigating toward without consulting the part of you that makes decisions.\nThe grave was at the eastern edge of the compound, under the wide canopy of the old iroko tree he had looked down on from the rise the evening before. This made sense. His mother had loved that tree with the specific loyalty she gave to things that had been present for her entire life without demanding anything in return. She used to sit in its shade in the late afternoons when the compound work was done, not sleeping, not doing anything that had a name, just sitting with her back against the bark and her hands in her lap and her face turned slightly upward the way a person turns their face toward something they find reliable.\nHe had not known, as a child, that he was watching her rest. He had thought she was watching the tree. He understood now that she had been doing something harder and more necessary than either.\nThe grave was marked with a flat river stone, wider than a hand, with her name worked into it in the careful chisel strokes of someone who had taken their time. The stone was old. The earth around it had long settled and compacted and grown over with the short grass that covered the compound''s eastern section, the kind of growing over that took years and meant the grief of the people who tended it had moved from the acute to the permanent, which was its own kind of settling.\nAmaechi stood at the edge of the marked earth and looked at her name on the stone and the cold thing that had been living in his chest since the corridor outside Chiza''s door expanded quietly and made room for this new weight alongside the old one.\nHe sat down.\nHe sat for a long time. The compound moved around him at its afternoon pace, voices and footsteps and the domestic sounds of a household that had learned to operate without noticing this corner of the eastern yard. Nobody came to him. Either they did not know who he was yet or they understood that this particular patch of ground required a specific privacy and gave it to him without being asked.\nHe thought about the morning they took him.\nNot the soldiers or the horses or the long road through the forest. The moment before all of that. Her hands on his face, warm and deliberate, pressing in at the cheekbones the way she did when she wanted him to hold still and receive something fully. Her forehead against his. Three breaths, counted, unhurried, as though she had all the time she needed and intended to use it completely.\nHe had been six years old. He had not known what he was being given.\nWhat she had given him was everything she had. Not comfort, she was too honest for comfort that was not earned. Not reassurance, she had known where he was going and what it was likely to cost him and she was not willing to lie about that. What she had given him was herself, pressed into him in that three-breath moment, her particular quality of endurance, the specific strength of a woman who had spent her life under the weight of Zara''s shadow and had decided, without drama, that the weight would not determine the shape of her.\nHe had spent twenty-five years becoming the thing she pressed into him that morning and had not fully understood until this moment, sitting in the eastern yard with her name in a river stone in front of him, that this was what had actually happened.\nHe pressed his forehead to his knees and stayed there for a while and let the grief do what grief needed to do, without managing it or measuring it or finding the version of it that was acceptable to be seen. There was nobody watching. This corner of the yard was his and hers and the old iroko''s business and nothing else.\nWhen he lifted his head the light had moved. Late afternoon had become early evening and the iroko''s shadow had stretched long across the grass and the compound sounds had shifted to the lower register of a household winding toward its evening meal.\nHe looked at the stone.\nFree our people.\nShe had not said it exactly in those words. She had said come back. She had said remember your name and what it means. She had pressed her forehead to his and breathed three breaths and sent him into a life that was going to cost him more than either of them had fully calculated. But underneath all of it, underneath the shea butter and the indigo wrapper and the memorising eyes, was this. The thing that had made her dress carefully on the morning they came. The thing that had kept her hands steady at the gate.\nShe had sent him into Zara''s palace because there was no choice. She had sent him with a name that meant the future was unknown and a charge that meant the future was not without direction. She had understood, in the way she understood most things, that being taken could be survived but being taken for nothing could not.\nHe had been close to Chiza for fifteen years. He had stood at the boy''s left hand through a funeral and a coronation and a hundred council mornings. He had told him the truth in a palace full of careful lies. He had gone where he was sent and survived what the sending put him inside of and come back changed and been removed with three sentences and the word gratitude.\nAnd Oke was still a vassal territory. Still sending tribute along the eastern road twice yearly. Still watched from the capital with the patient proprietorial eye of an empire that considered the watching to be a form of generosity.\nHe had not freed anyone.\nHe put his hand flat on the grass above the settled earth and held it there, the way she had held her hands on his face, deliberately, with full attention.\n"I am back," he said. "I know it is late. I am back."\nThe iroko moved above him in the evening wind, its canopy shifting with the slow authority of something that had been rooted in this ground for a very long time and intended to remain.\nHe sat with her until the compound lamps were lit. Then he stood and brushed the grass from his robes and turned toward the main compound with the particular quality of resolution that does not announce itself because it has already moved past the announcing stage into the doing.\nHe had one thing left. One promise that had survived the palace and the savanna and the corridor and the eleven days of administrative removal and the nine days of road. One thing that was entirely his own, that Ogbonna had never touched and Zara had never owned and the years had not diminished.\nHe would spend whatever remained of his life making it true.\nHe walked back into the compound and went to find his brother.','\n',char(10)),1222,0,1,NULL,'2026-04-14T17:44:26.654Z','2026-04-14 17:44:26','2026-04-14 17:44:26',NULL,3,37);
INSERT INTO "chapters" ("id","novel_id","chapter_number","title","content","word_count","is_premium","is_published","audio_url","published_at","created_at","updated_at","scheduled_release_at","part_number","season_id") VALUES(409,53,3,' The Brother Who Stayed',replace('Emeka was in the compound''s main hall when Amaechi found him, sitting across a low table from two village elders with a land dispute document spread between them, speaking in the measured unhurried way of a man who had been the person people brought their problems to for long enough that the role had become indistinguishable from the person.\nHe looked up when Amaechi entered.\nThe resemblance was the first thing, sharper than Amaechi had expected. Emeka had their father''s jaw and their mother''s eyes and the particular combination of these produced a face that was familiar in a way that bypassed recognition entirely and arrived somewhere older and more physical, a response in the chest that had nothing to do with memory and everything to do with blood.\nEmeka was twenty-six. He had been one year old when Amaechi left.\nHe looked at Amaechi from across the table with an expression that moved through several things quickly, surprise, then something that was not quite relief but occupied its neighbourhood, then a careful settling, the face of a man who had been told his brother was returning and had prepared a response and was now discovering that preparation and arrival were entirely different experiences.\nHe said something brief to the elders. They rolled the document, offered Amaechi the respectful nod owed to a returned senior, and left with the practised discretion of people accustomed to reading rooms.\nThen it was just the two of them.\nEmeka stood. He was shorter than Amaechi by two fingers and broader across the shoulders, built for the compound''s physical work in a way that Amaechi''s palace years had not built him. He crossed to where Amaechi stood and they held each other briefly, the embrace of men who were not practiced at it with each other and were doing their best with a closeness they had not earned through time.\n"You look like father," Emeka said, stepping back.\n"You look like mother."\nSomething moved in Emeka''s face at that. Quickly, and then it was managed. "Come and eat," he said. "You have been on the road."\nThe meal was good and the conversation during it was careful.\nEmeka''s wife, a steady-eyed woman named Chisom who had clearly been told enough to know how to receive a stranger who was also family, served them and joined them and asked questions that were warm and not intrusive, questions about the road and the weather and whether Amaechi had stopped at the market town two days south, where her cousin''s family lived. It was generous of her, the engineering of an ordinary conversation in circumstances that were not ordinary, and Amaechi was grateful for it in the way you were grateful for a well-placed lamp in unfamiliar dark.\nEmeka''s two children, a girl of four and a boy of two, were put to bed before the meal was finished. Amaechi had watched them with a feeling he could not name cleanly, something between tenderness and the specific loneliness of witnessing a life that had continued and thickened and become fully itself in your absence.\nAfter Chisom went inside, the careful conversation ended.\nThey sat across the dying lamp with the compound quiet around them and the night insects filling the dark with their noise, and the thing that had been underneath the meal sat between them on the table as plainly as if someone had placed it there.\n"Father left the compound to both of us," Emeka said. Not aggressively. As a fact being placed in the correct position before anything else was placed near it.\n"I know."\n"The village elders have been coming to me for six years. The territory disputes, the tribute negotiations, the dry season council. Six years."\n"I know."\nEmeka looked at him steadily. "I am not saying this to argue. I am saying it so that we begin from a true place."\n"Then let me say my true place also." Amaechi set his cup down. "I did not come back to take what you have built. I came back for a specific thing. The tribute. The vassal arrangement. Mother made me a promise before they took me and I have been carrying it for twenty-five years and I intend to spend whatever time I have left making it true." He paused. "That work needs someone who knows this territory. Someone the village councils will listen to. Someone who has been here."\nEmeka was quiet.\n"I need you," Amaechi said. "Not your compound or your authority or your six years. You."\nThe lamp between them was very low now, burning at the end of its oil, the light contracting slowly toward the wick.\n"They told us things about you," Emeka said. "When we were growing up. Father mostly. About what you were doing in the palace, what you had become." He picked up his cup and held it without drinking. "He was proud. He said it in the way proud men said things, sideways, inside other sentences, so you had to know to listen for it." A pause. "But there were also nights when mother was still alive and she would sit under the iroko and I would ask her what she was thinking about and she would say your name. Just your name. And then go back to whatever she had been doing."\nAmaechi said nothing.\n"I grew up in the space your absence made," Emeka said. "That space had a shape. I filled it the best I could." He finally drank. "I am not angry about that. I need you to understand I am not angry. But I need you to understand what it was."\n"Tell me."\nEmeka looked at him across the lamp and for a moment the careful management left his face entirely and what was underneath was simpler and younger and much more honest, the face of a boy who had grown up with a famous absent brother and had loved him and resented him and been shaped by both without being asked.\n"It was lonely," he said. "Even full. Even with Chisom and the children and the elders coming with their documents. Underneath all of it, it was very lonely."\nThe lamp went out.\nThey sat in the dark for a moment without moving, the compound breathing around them, the night insects continuing their patient noise.\n"I am here now," Amaechi said. It was not an apology and it was not a solution and he knew it was not enough. But it was the truest thing he had.\nEmeka was quiet for long enough that Amaechi thought he might not answer.\nThen, "I know," he said. "I know you are."\nOutside, the iroko moved in the night wind, its canopy shifting above the compound wall, above the eastern yard, above the flat river stone with their mother''s name on it.\nBoth of them could hear it from where they sat.','\n',char(10)),1153,0,1,NULL,'2026-04-14T17:45:36.276Z','2026-04-14 17:45:36','2026-04-14 17:45:36',NULL,3,37);
INSERT INTO "chapters" ("id","novel_id","chapter_number","title","content","word_count","is_premium","is_published","audio_url","published_at","created_at","updated_at","scheduled_release_at","part_number","season_id") VALUES(410,53,4,'Ogbonna''s Long Arm',replace('The new tribute assessment arrived on a Thursday, which was how Amaechi would always remember it. Not because Thursday carried any particular weight in the calendar of Oke but because it was the day after he and Emeka had sat with the village council for the first time together, and the sitting had gone well, and he had allowed himself, briefly and against his better judgment, to feel something adjacent to hope.\nThe document came through the standard eastern territory courier, folded in the official Zara administrative wrapper with the correct seals in the correct positions. Emeka brought it to him in the compound''s main hall with the flat careful face of a man who had already read it and was managing what the reading had produced.\nAmaechi opened it and read it standing.\nThe tribute assessment for Oke territory had been reviewed and recalculated under the new administration''s eastern revenue framework. The quarterly grain allocation was increased by thirty percent. The dry season cattle contribution was increased by twenty. A new levy had been created, the eastern boundary maintenance fee, applied to all vassal territories sharing Zara''s eastern forest border. The fee was substantial. The justification was four sentences of administrative language that said nothing while appearing to say everything.\nEffective immediately. No appeal window specified.\nAmaechi folded the document and set it on the table.\n"There is more," Emeka said.\nHe produced a second document. Shorter. More direct. A land notification from the Zara noble estates office, informing the chief of Oke that a section of the eastern boundary territory, the flat fertile stretch along the lower Oma tributary where three of Oke''s farming families had worked the land for two generations, had been formally reclassified as a Zara crown estate and allocated to a noble of the new court.\nThe families had thirty days to vacate.\nAmaechi read it twice and put it beside the first document and stood with his hands flat on the table and breathed from the bottom of his chest.\n"The families," he said.\n"Nwofor''s people and the two Okeke households. Seven adults and eleven children."\n"Where will they go?"\n"There is room in the upper compound. Temporarily." Emeka paused. "Amaechi. Who is doing this?"\nHe looked at his brother. "The new administration."\n"You know what I am asking."\nHe did know. He picked up the land notification and looked at the authorising signatures at the bottom. Three names. A senior revenue officer. A noble estates clerk. And the third signature, at the bottom of the column, the one that sat below the others with the particular quality of a signature that did not need to be large to be the most important one in the room.\nOgbonna. Senior Adviser to the Zara Crown, Eastern Territories Division.\nAmaechi set the document down and looked at his brother''s face and saw in it the specific fear of a man watching something he has spent six years building being threatened by something too large and too patient for ordinary resistance.\n"I know what to do," Amaechi said.\nHe spent the next six weeks doing everything the palace had taught him.\nHe drafted the formal appeal against the tribute increase himself, in the correct administrative language, structured according to the exact protocols he had learned in years of inner chamber work. He cited three precedents from the eastern territory agreements that predated the new administration. He attached the original tribute calculation from the previous court, signed by officials whose authority the new administration was obligated by charter to respect. He was thorough and precise and completely correct.\nHe sent it through the official appeals channel to the Zara administrative council.\nThe rejection arrived in twelve days. Polite, formal, complete. The precedents he had cited were noted and found insufficient under the new revenue framework. The signature at the bottom was a revenue clerk''s. But above the clerk''s name, the reviewing authority line carried a different name.\nHe wrote a second appeal. Longer, more detailed, with additional documentation sourced from Emeka''s six years of territory records and three supporting letters from neighbouring vassal chiefs who faced the same increases and had agreed, after two evenings of careful conversation with Amaechi, to submit coordinated objections.\nHe sent it to the senior council chamber directly, bypassing the revenue office.\nThe rejection arrived in nine days. Equally polite. The coordinated nature of the submission was noted, in language that managed to make coordination sound like a form of presumption. The reviewing authority line carried the same name.\nHe drafted a third appeal. This one addressed the land seizure specifically, on the grounds that the farming families held documented occupancy rights that predated the current noble allocation by forty years. He attached the occupancy records, which Emeka had kept with the meticulous care of a man who had understood, without being told, that documentation was a form of protection.\nHe sent it to the land rights office in the capital.\nThe rejection arrived in eight days.\nSame language. Same careful courtesy. Same reviewing authority.\nHe sat in the compound hall on the evening of the third rejection with the three documents in front of him and looked at the name that appeared on each one and felt the full architecture of it settle into place with the cold completeness of something that had been under construction for a very long time.\nThis was not policy. Policy was impersonal, it applied broadly, it had the blunt indifferent edge of a system operating on its own logic. This was something else. The thirty percent increase applied to Oke specifically at a rate higher than comparable territories. The land seized was the most productive section of the eastern boundary, chosen with the knowledge of someone who had read enough eastern territory reports to know exactly what its loss would cost. The appeals process had been allowed to function correctly so that the rejections could be documented as legitimate.\nEvery instrument was clean. Every procedure was followed. Every rejection was unchallengeable through the channels that existed.\nOgbonna had spent twenty years in a palace learning what the tools of power could do in patient hands, and now those hands were on every document that connected Oke to Zara, and they were doing what they had always been going to do.\nAmaechi gathered the three rejections and put them in his wooden chest beside his mother''s letters.\nHe went to find Emeka.','\n',char(10)),1076,1,1,NULL,'2026-04-14T17:46:39.177Z','2026-04-14 17:46:39','2026-04-14 17:46:39',NULL,3,37);
INSERT INTO "chapters" ("id","novel_id","chapter_number","title","content","word_count","is_premium","is_published","audio_url","published_at","created_at","updated_at","scheduled_release_at","part_number","season_id") VALUES(411,53,5,'The Warrior He Became',replace('The thirty days the eviction notice gave the farming families passed and on the thirty-first morning Amaechi was standing in the eastern boundary field when the Zara land officials arrived, and he was not alone.\nThe decision to resist had not been dramatic. It had been a conversation in Emeka''s compound hall on a quiet evening, with four village elders seated around the low table and the three rejection letters spread between them and the lamp burning at the steady pace of a night that had enough time for what needed to be said.\nAmaechi had laid out the situation without softening it. The petitions had failed. The formal channels were closed. The land transfer would proceed unless it was physically interrupted, and physical interruption carried consequences that everyone in this room needed to understand clearly before committing to anything.\nHe had expected argument. He had expected the particular caution of men who had spent their lives as a vassal territory and had learned, through the accumulated experience of generations, that the cost of resistance was paid by the people who could least afford it.\nWhat he had not expected was the silence that followed his assessment, not the silence of reluctance but the silence of men who had already, privately and separately, arrived at the same conclusion and were simply waiting to hear it said aloud by someone who understood both the palace and the field.\nThe eldest of the four, a man named Okafor whose family had farmed the lower Oma tributary land for as long as anyone could trace, put his hand flat on the table.\n"Tell us what you need," he said.\nAmaechi spent eight days preparing.\nHe was precise about what he was building. Not an army. Not a rebellion. Both of those would give Ogbonna exactly the documentation he needed to escalate from administrative pressure to military authority, and military authority was a language Oke could not match. What Amaechi was building was a presence. Organised, visible, and entirely within the technical boundary of what vassal territories were permitted to do in defence of documented occupancy rights.\nHe wrote to every family in the eastern boundary settlements and explained what was happening and what he proposed. He went in person to the three compounds whose land was most directly threatened and sat with the men and women there and listened to what they needed to say before asking anything of them. He visited the two neighbouring vassal chiefs who had co-signed his second appeal and spoke to them plainly about what coordination could look like at the level of people rather than documents.\nEmeka moved through all of this beside him, not deferring but not competing, filling the spaces Amaechi''s palace manner could not reach. When Amaechi''s formal bearing created distance, Emeka''s six years of compound authority closed it. When the elders looked uncertain about the man who had returned from a world they did not fully understand, Emeka''s presence said: he is ours. He was always ours.\nBy the eighth evening Amaechi understood something he had not expected to find at thirty-one years old. He understood what it felt like to be doing the right work.\nThere were eleven of them on the morning the land officials arrived.\nNot armed men in the military sense. Farmers and elders and two of the neighbouring settlement''s senior men, standing in the lower Oma tributary field with the unhurried deliberateness of people who had decided where they were standing and had no immediate plans to stand anywhere else. Amaechi was at the front, dressed in no particular ceremony, with Emeka at his right and old Okafor at his left.\nThe land officials were four, with a Zara administrative seal and a document and the professional composure of men who expected their documents to do the work that presence was currently failing to do.\nTheir lead official was a young man, perhaps twenty-five, with the careful self-importance of someone recently elevated and not yet tested. He read the transfer order aloud. He noted that the occupancy period had concluded. He indicated that the families were required to vacate at their earliest convenience.\nAmaechi waited for him to finish.\nThen he produced his own document. The occupancy records Emeka had kept, the forty-year history of the farming families'' presence on this land, the specific clause in the eastern territory agreements that required a formal land tribunal hearing before any occupancy transfer could be enforced.\nHe had not cited this clause in his three appeals. He had found it two weeks ago in a document so old its edges had crumbled and he had copied it in his own hand and had said nothing to anyone about it until this morning because he had understood, from years of watching Ogbonna, that a tool kept hidden until the right moment was worth three tools displayed too early.\nHe read the clause aloud in the formal Zara administrative language, clearly and without emphasis, the way Ogbonna himself might have read it.\nThe young official looked at the document. He looked at his own document. He looked at the eleven people standing in the field with the patient permanence of rooted things.\nHe said he would need to refer the matter to the reviewing authority.\n"Please do," Amaechi said. "We will be here."\nThe officials withdrew.\nThe land tribunal clause delayed the transfer by four months. It did not stop it. Amaechi understood this from the moment the officials left the field. The clause created a process and Ogbonna''s administration would work through the process correctly and arrive at the same destination through a longer road. But four months was not nothing. Four months was time for the farming families to document their occupancy further, to build the formal record that would complicate every subsequent administrative step, to exist on their own land as people with a legal argument rather than people in the path of an inevitable outcome.\nFour months was also what happened when Oke gathered behind one man and held its ground and the ground held back.\nThe walk back to the compound that evening had a quality Amaechi had not felt in a long time. The eleven men and women moving through the boundary field in the late afternoon light, talking in the ordinary voices of people who had just done something and knew it mattered, even knowing the fight was not finished, even knowing what was waiting at the other end of the four months.\nEmeka fell into step beside him.\n"She would have liked this," he said.\nAmaechi looked at him.\n"Mother." Emeka kept his eyes on the path ahead. "She would have liked watching you do this."\nAmaechi said nothing. He walked and felt the field grass against his legs and the evening air coming down from the eastern hills and the specific weight of a man who has been carrying a promise for twenty-five years and has finally, in one small but completely real way, begun to make it true.\nIt was not enough. He knew it was not enough.\nBut it was real.','\n',char(10)),1190,1,1,NULL,'2026-04-14T17:47:57.811Z','2026-04-14 17:47:57','2026-04-14 17:47:57',NULL,3,37);
INSERT INTO "chapters" ("id","novel_id","chapter_number","title","content","word_count","is_premium","is_published","audio_url","published_at","created_at","updated_at","scheduled_release_at","part_number","season_id") VALUES(412,53,6,' Between Two Empires',replace('He had not been back to Zara''s capital in two years and the city received him the way cities received people who had once mattered inside them and no longer did, without acknowledgment, without hostility, with the complete indifference of a place that had continued its business without interruption and saw no reason to mark the return.\nThe journey had taken seven days. He had made it alone, which was a decision Emeka had argued against and Amaechi had held to, not out of stubbornness but out of a clear-eyed understanding of what the visit was and was not. It was not a delegation. A delegation implied collective authority and collective authority implied a level of formal standing that Oke did not currently possess and that Amaechi''s presence at the head of a group would not create. It was one man making an argument he had prepared carefully, in the language of the institution he was addressing, using the access that his years of palace service had not entirely revoked.\nOne man was either enough or it was not. More men would not change which.\nHe had arranged the council hearing through the correct channel, a formal petition for floor time submitted to the administrative office six weeks in advance, granted with the procedural efficiency of an institution that processed requests of this kind regularly and without particular interest in their outcome. He had a slot of forty minutes on a Wednesday morning, the third item on the council''s agenda for that day.\nHe arrived the evening before and stayed in a traveler''s compound near the market district, in a room that was clean and entirely without the specific quality of a place that had ever known him.\nThe council chamber was smaller than the assembly hall and more intimate in a way that was not comforting. Twelve men arranged around a wide table, senior officials of the new administration, some of whom Amaechi recognised from his years in the inner chamber and some of whom had arrived after him and knew him only as a name attached to a petition.\nHe was given the petitioner''s chair at the foot of the table.\nHe sat in it and looked at the chamber he had walked freely for two years and felt the specific quality of the distance between then and now, not nostalgia, something colder and more instructive. The carved panels on the walls were the same. The morning light came through the high windows at the same angle. The table was the same table. Everything that had changed was invisible to the room because the room did not track the things that had changed. It tracked authority and he had none and so the room simply arranged itself around that fact with the impersonal accuracy of spaces that reflected only what was formally true.\nHe noted Ogbonna''s chair, positioned at the table''s right side, traditionally the senior adviser''s seat. It was empty. There was no explanation offered for the absence and none was owed.\nAmaechi understood immediately. Ogbonna''s presence would have given the hearing a significance it was not intended to carry. An empty chair said: this matter does not require the attention of anyone who matters.\nHe took the measure of this and set it aside and began.\nHe spoke for thirty-eight of his forty minutes.\nHe presented the occupancy clause and its application to the land transfer. He presented the tribute increase against the historical rate documentation and the charter provisions that governed reassessment timelines. He presented the coordinated impact across three eastern vassal territories and the long-term revenue implications of destabilising established farming communities, an argument framed in the language of Zara''s own economic interest rather than Oke''s, because he understood this audience well enough to know which language they would hear.\nHe was precise. He was thorough. He was exactly as calm as the argument required and no calmer, because a man with no emotion was easy to dismiss and a man with too much was easier.\nHe watched their faces as he spoke.\nThis was the thing he had been doing since he was thirteen years old in a lesson room and a palace corridor and an inner chamber and a Kara court gathering. Reading faces. Finding the gap between the presented surface and the actual position underneath. He had become good at it in the way that people became good at skills that their survival had required.\nWhat he found in these twelve faces was not hostility. Hostility would have been something to work with, to redirect, to find the edge of and push against. What he found was something that had no useful edge. Three of the twelve were listening with genuine attention, the kind that meant they were following the argument and finding it sound. Four were listening with the courteous patience of men waiting for a procedure to conclude. The remaining five were present in the physical sense only, their attention distributed somewhere in the administrative middle distance, handling the interval between this item on the agenda and the next.\nHe was making a correct argument to a room that had already decided.\nHe had known this before he arrived. He had come anyway because the alternative was surrender without record and surrender without record left nothing for whoever came after him to build on. Every document he submitted today became part of Oke''s formal case. Every procedural step he completed correctly narrowed the space in which the administration could act without accountability.\nHe was not here to win today. He was here to make winning harder for them tomorrow.\nHe finished his presentation and sat back and waited.\nThe council chairman thanked him for the thorough submission. He noted that the matters raised would be reviewed by the relevant offices. He noted that the petitioner would receive a formal response within the standard timeframe. He moved to the next agenda item.\nAmaechi gathered his documents.\nHe walked out of the chamber through the same corridors he had spent two years walking freely and felt them receive him as they had received him since his return, as a man in a space he once inhabited and no longer did, tolerated, processed, moved through the correct channels and out the other side.\nIn the outer courtyard he stopped and stood in the morning light and breathed once, from the bottom of his chest, the way his father had taught him and his mother had reinforced.\nThen he picked up his document case and walked toward the city gate and began the seven-day road back to Oke.\nThe rejection arrived before he did.','\n',char(10)),1111,1,1,NULL,'2026-04-14T17:48:53.212Z','2026-04-14 17:48:53','2026-04-14 17:48:53',NULL,3,37);
INSERT INTO "chapters" ("id","novel_id","chapter_number","title","content","word_count","is_premium","is_published","audio_url","published_at","created_at","updated_at","scheduled_release_at","part_number","season_id") VALUES(413,53,7,'The Trap',replace('They came on a Tuesday, which meant the paperwork had been ready since at least Friday and someone had decided the weekend was too informal for an arrest of this particular kind.\nAmaechi was in the compound hall with Emeka and two of the village elders when he heard the horses. Not many. Four, perhaps five, moving at the deliberate pace of people who were not in a hurry because hurry implied uncertainty and this party had none. He knew the sound before he reached the window. He had been hearing it, in some interior register, for twenty years.\nHe turned from the window and looked at Emeka.\n"Go to Chisom," he said. "Take the children to Okafor''s compound."\nEmeka looked at him with the expression he wore when he was deciding whether to argue.\n"Emeka."\nHe went.\nThe two elders looked at Amaechi with the specific fear of men who had lived their entire lives in a vassal territory and understood, at a cellular level, what horses at this pace and this number meant at a compound gate.\n"You should leave also," Amaechi told them. "What happens next does not require witnesses and your presence will not change it."\nThey left. He straightened his robes and went to the gate himself.\nThe officer was young, perhaps thirty, in the formal uniform of Zara''s administrative enforcement division, which was a different corps from the military and carried a different category of authority, the authority of documented process rather than force. He had four soldiers behind him and a sealed document in his hand and the careful professional composure of a man who had been briefed thoroughly and intended to execute the briefing without deviation.\nHe read the charges aloud at the gate.\nIncitement of rebellion in a vassal territory. Organising unlawful resistance to a lawfully issued land transfer order. Coordinating seditious correspondence between vassal territories with the intent to undermine Zara''s administrative authority in the eastern region. Unauthorised representation of vassal interests before the crown council without documented standing.\nFour charges. Each one specific. Each one sourced from a real action Amaechi had taken, the field confrontation, the coordinated appeal letters, the council hearing, all of it present in the documentation the officer carried, assembled with the thoroughness of someone who had been collecting material for a long time and had waited until the collection was complete.\nAmaechi listened to all four charges without interrupting.\nThen he said, "May I see the authorising signature."\nThe officer turned the document and held it forward.\nAmaechi looked at the signature. He did not need to. He had known whose name was on it from the moment he heard the horses. But there was something necessary about seeing it directly, about giving the thing the full acknowledgment it had spent twenty years working toward. Ogbonna''s signature sat at the bottom of the document in the same precise hand that had signed every rejection letter and every tribute assessment and every piece of paper that had arrived from Zara''s capital since his return.\nHe handed the document back.\n"I will need to collect a few things from inside."\nThe officer nodded. He posted one soldier at the gate and walked with Amaechi to the main hall himself, which was procedure. Amaechi did not mind. He moved through his own compound with the unhurried pace of a man who had been in difficult rooms before and knew that the quality of your movement inside them was the only dignity entirely within your control.\nHe packed the wooden chest for the last time with the same methodical care he had always brought to it. The document case from the council hearing. Emeka''s occupancy records. His own copies of every petition and appeal, every rejection, every correspondence that constituted the formal record of Oke''s case.\nHe packed them not for himself. He packed them for whoever came after.\nHe found a piece of paper and wrote Emeka a note in plain language. Where the documents were. What they contained. Which clauses in the eastern territory charter still had unused applications. The name of the official in the land rights office who had, in their brief exchange during the council hearing, looked at him with the three-second attention of a man who found the argument genuinely sound.\nHe wrote: the work is not finished. It was never going to be finished by one person. That was never what it was for.\nHe folded the note and left it on the table where Emeka would find it.\nThen he picked up the chest, turned, and looked at the hall. The low table where he and Emeka had sat with the elders. The lamp that Chisom kept filled without being asked. The doorway through which the children ran in the mornings. He had been here eight months. It had taken him thirty-one years to arrive and he had been given eight months.\nHe thought about his mother''s grave in the eastern yard. He thought about the flat river stone and the old iroko and the evening he had sat with his hand pressed to the settled earth and made a new version of an old promise.\nHe had not freed anyone.\nHe had created a documented record. He had organised people who had not been organised. He had won four months that the farming families had used to build a case that would take Ogbonna''s administration two years to work through correctly. He had filed every petition and attended every hearing and written every letter in language clean enough that nothing could be dismissed on procedural grounds.\nIt was not freedom. It was not what his mother had asked him to carry.\nBut it was a foundation. And foundations were for building on, not for standing in.\nHe had always known this was coming. What he had not known, when he was thirteen in a lesson room or twenty in a corridor outside a closed door or thirty-one standing on a rise above a valley that no longer knew his face, was that knowing it was coming would not diminish its weight when it arrived. The chest was heavy and the hall was quiet and the officer was waiting at the gate and none of that knowledge helped with any of this.\nHe thought: I wanted more time. That is the only true thing left. I wanted more time.\nThen he picked up the chest and walked to the gate and went with the officer into the morning, past the iroko and the well and the compound entrance where a woman had once stood in her good wrapper with her hands folded and her eyes memorising a boy''s face.\nHe did not look back.\nHe had promised himself that once, on a road much longer ago than this, and he had kept it.\nHe kept it now.','\n',char(10)),1147,1,1,NULL,'2026-04-14T17:49:50.276Z','2026-04-14 17:49:50','2026-04-14 17:49:50',NULL,3,37);
INSERT INTO "chapters" ("id","novel_id","chapter_number","title","content","word_count","is_premium","is_published","audio_url","published_at","created_at","updated_at","scheduled_release_at","part_number","season_id") VALUES(414,53,8,' The Last Letter',replace('The room was small and it was honest. No carved panels. No high windows throwing morning light at ceremonial angles. One sleeping mat, one table, one lamp, walls of plain red earth that had nothing to prove. The kind of room that had held many people briefly and remembered none of them.\nAmaechi had been inside it for eleven days.\nThey had not put him in a cell. This was a distinction Ogbonna''s administration had been careful about, because a cell implied a criminal and a criminal implied a trial and a trial implied a public record of specific accusations tested against specific evidence, which was more exposure than a careful man required. What they had given him instead was a supervised residence, a small compound in the administrative quarter of the capital, with a guard at the outer gate and meals delivered twice daily and no formal schedule because there was nothing formal left for him to attend.\nHe was not charged with anything that required immediate adjudication. The charges existed in the documentation and the documentation would move through the correct processes at the pace the administration found convenient and arrive at whatever outcome had already been decided by the man whose signature was at the bottom of the authorising document.\nHe understood all of this clearly. He had spent twenty-five years inside the machinery of this institution and he could read its movements the way old farmers read weather, not with certainty but with the deep pattern recognition of someone who had watched it long enough to know what each configuration meant.\nHe was not leaving this room toward anything that resembled before.\nHe had made peace with this on the third day, sitting on the sleeping mat with his wooden chest against the wall and the compound''s small window showing him a rectangle of sky above the capital''s roofline. He had made peace with it the way his mother made peace with things, directly and without ceremony, looking at what was true until it stopped being a shock and became simply the condition inside which the remaining decisions had to be made.\nThere was one remaining decision. He had been building toward it for eleven days.\nOn the twelfth morning he asked the guard for paper and ink.\nThe guard, a young man who had been performing his function with the decency of someone who understood that the person in his supervision was not what the documentation made him sound like, brought both without comment. He also brought a second lamp without being asked, which was a small kindness Amaechi acknowledged with a nod and intended to remember.\nHe sat at the table and set the paper in front of him and dipped the pen and held it above the page for a long moment.\nHe thought about who needed this letter.\nNot the new king, who would not read it and could not be changed by it. Not Emeka, who had the note from the compound hall and the document case and the name of the land rights official and everything practical that could be passed forward. Not the village elders or the farming families or any of the people whose land and lives the work had been for.\nHe thought about a boy on a road.\nA boy six years old with a bundle on his back and a soldier''s horse ahead of him and a promise still warm in his ear, turning back twice at the compound gate before telling himself he would not turn again.\nHe had never written to that boy. He had become that boy''s consequence without ever speaking to him directly. It seemed, sitting in this small honest room at the end of everything, like an omission that needed correcting.\nHe put the pen to the paper and began.\nTo the boy on the road,\nYou do not know yet where you are going. I know. I have been there and come back and now I am sitting in a room that is the last room of the life that started on your road, and there are things I want to tell you before the circle closes.\nIt cost more than you will be able to imagine from where you are standing. The people you will love will be taken from you in ways that do not care how much you love them. The place you are walking toward will shape you into someone the place you are walking away from will not immediately recognise. You will stand in corridors outside closed doors. You will read letters that have already been opened. You will arrive too late for the most important moment of your life and you will carry that arriving for the rest of your years.\nHere is what it was worth.\nA boy sat on a floor in the dark because guilt had no language and so he chose silence and presence instead. You will learn that silence and presence are sometimes the fullest things a person can offer. You will learn this because he taught you and he will teach you because you let him in.\nYou will stand beside a king before thousands of people and carry the banner of continuity and the king will have arranged this because you are the only person in the palace he fully trusts and that trust will have been built in the dark over small lamps with no audience, which is the only way real trust is ever built.\nYou will ride eighteen days without stopping because someone''s life matters more than your body''s comfort. You will arrive too late. You will survive arriving too late. This will be the hardest thing. You will survive it anyway.\nYou will sit beside your mother''s grave and put your hand on the ground above her and make the promise again and mean it more than the first time because the first time you were six years old and the second time you will know exactly what it costs.\nYou will organise eleven people in a field and hold your ground and the ground will hold back and for a moment, one small clear moment, you will feel what it means to do the right work in the right place for the right reason. Hold that moment. It is real. It will remain real regardless of what comes after.\nI will not tell you it was enough. It was not enough. Our people are not yet free and I am in a small room and the man with the patient hands has had his way and the promise is only half kept at best. I will not make it something it was not.\nBut I will tell you this. Do not turn back at the gate. Not the second time. Keep the promise you make to yourself on that road because you will need to keep it again at the end, in a different road, and the practice will matter.\nGo. The road is long and it is yours and there is no version of it that does not begin with you walking away from the gate.\nI would do it again. Every day of it. Every cost.\nGo.\nHe set the pen down.\nOutside the window, above the capital''s roofline, the morning sky was doing what the sky did in Zara at this hour, going from the deep blue of early light to the warm gold of full morning, the transition happening so gradually and so completely that you could never identify the exact moment it became one thing instead of the other.\nHe folded the letter and held it in both hands and looked at the window for a long time.\nFar away, on a red road lined with iroko trees, in the long-ago morning of a day that had already decided everything, a small boy with a bundle on his back walked away from a compound gate. He had turned back twice. He had made himself a promise. He walked with the unsteady determined pace of a child carrying something heavy and invisible, his face forward, the forest road opening ahead of him through the trees.\nThe road was long.\nHe walked it anyway.\n\n\nTHE END\n\nTHE KING''S OTHER HAND is a work of fiction inspired by the true historical friendship between Barnaby Fitzpatrick and King Edward VI of England in the sixteenth century. The characters, kingdom, and cultural world of this novel are entirely original.\nAmaechi''s story is finished. The promise lives on.','\n',char(10)),1426,1,1,NULL,'2026-04-14 17:53:48','2026-04-14 17:51:29','2026-04-14 17:53:48',NULL,3,37);
INSERT INTO "chapters" ("id","novel_id","chapter_number","title","content","word_count","is_premium","is_published","audio_url","published_at","created_at","updated_at","scheduled_release_at","part_number","season_id") VALUES(415,54,1,'"The Girl Who Would Break It"',replace('The gravestone had no photograph. Just a name pressed into cheap concrete and a year that had taken everything with it.\nIvie Osagie was eight years old when they buried her father in the red soil of Ovia. She was sixteen now, standing at the same spot on a Tuesday afternoon, her school uniform still on her back, her shoes already coated in dust. Eight years. The grave had not changed. Neither had the house she walked home to every evening.\nShe did not cry. She had finished crying somewhere around age twelve.\n"I will not stay here," she said to the stone. Not a prayer. A statement of fact.\nBehind her, Ovia was doing what it always did at this hour. Women were arranging pepper on roadside trays, their voices cutting across each other in that particular rhythm that meant nothing was wrong and nothing was changing. Boys were playing football with a ball that had lost most of its air, their bare feet slapping the packed dirt like applause for a show nobody had asked to watch. It was the kind of town where everything felt temporary but nothing ever actually changed. The same dust. The same broken gutters. The same faces growing older without going anywhere.\nIvie''s father, Raymond Osagie, had died at thirty four. Stroke, the doctor said. Poverty, Ivie had decided since then. He worked himself into the ground for a salary that never stretched to the end of the month, for a house that leaked when it rained, for four children whose school fees arrived every term like a hard knock at the door. He had been a quiet man with a loud laugh, and she missed the laugh more than anything else. More than his face, even. The laugh was the part of him that had felt most alive.\nShe was the oldest. That meant something.\nAt home, Mama Florence was in the kitchen, stirring a pot that had more water than it needed. Eki and Ese, her younger sisters, were doing homework on the same wooden table they ate from, their pencils scratching against paper in competing rhythms. Ose, the youngest, eight years old and already carrying himself like someone who had been told he was special, was chasing a lizard around the compound with focused, scientific determination.\nIvie dropped her bag, changed out of her uniform, and sat beside Eki.\n"You went to the grave again," Eki said. Not a question.\n"Mind your business."\n"I am just saying. Staring at a stone will not bring money."\n"Neither will your mouth."\nEki went quiet. She was thirteen and had learned when to stop pushing.\nThe truth was that Ivie went to the grave because it was the only place she let herself think clearly. At home there was always noise, always something needing doing, always Mama''s tired face reminding her that the next school fee was coming and the money was not. The grave was quiet. And Raymond Osagie, whatever else he had failed to leave them, had left Ivie one thing she held like a lamp in both hands. He used to say that one person in a family could change the whole story. Just one person willing to go far enough.\nShe intended to be that person.\nThe question was how.\nOvia had one answer for girls like Ivie: marry someone doing slightly better than your father and hope the pattern did not repeat. Ivie had watched that answer play out in her aunties'' lives, her neighbours'' lives, the lives of girls two or three years ahead of her in school. It was not an answer. It was the same sentence continuing.\nThere was another answer. The one everyone whispered about but nobody said plainly: leave. Get out of Ovia, out of Midwest State, out of Nigeria entirely. Somewhere with real salaries and real futures that did not depend on who your father had been or how much he had left behind.\nSomewhere like where Aunty Osato lived.\nIvie had met her father''s cousin only a handful of times, but each visit had the quality of a film. Aunty Osato wore real perfume and carried bags that nobody in Ovia could name the price of. She spoke about Italy the way people spoke about heaven: carefully, with the weight of someone who had actually been there and knew it was real. She sent money home at Christmas. She laughed like a woman who had never once worried about school fees.\nThe last time she visited, two years ago, she had looked at Ivie for a long moment and said, "This one has sense. When she finishes secondary school, we will talk."\nMama had laughed it off. But Ivie had filed the sentence away and kept it somewhere dry, somewhere it would not spoil.\nShe pulled out her Literature textbook now and opened it across her knees. Her WAEC exams were seven months away. Seven months to prove she was exactly who she believed herself to be.\nOutside, Ose had abandoned the lizard and was now demanding Mama buy him biscuit. Mama was calling Ivie''s name.\nShe closed the book, stood, and went to do what the oldest child in a house like this always had to do.\nBut the sentence stayed with her.\nWhen she finishes secondary school, we will talk.\nIvie intended to give Aunty Osato nothing to complain about.','\n',char(10)),901,0,1,NULL,'2026-04-15T07:06:11.490Z','2026-04-15 07:06:11','2026-04-15 07:06:11',NULL,1,38);
INSERT INTO "chapters" ("id","novel_id","chapter_number","title","content","word_count","is_premium","is_published","audio_url","published_at","created_at","updated_at","scheduled_release_at","part_number","season_id") VALUES(416,54,2,'Aunty Osato''s House',replace('The bus to Oredo City left Ovia at six in the morning and arrived feeling like it had taken a year off everyone''s life. Ivie did not care. She pressed her face to the window the entire ride and watched the town she had grown up in slowly disappear behind her.\nIt was the December holiday, two weeks after her mock examinations, and Mama had agreed to let her visit Aunty Osato with the cautious energy of someone granting a wish they were not sure was wise. She had braided Ivie''s hair the night before, her fingers moving quickly, her mouth saying nothing, which was its own kind of language.\nOredo City arrived the way cities always did: all at once, and slightly too loud. Traffic that had no logic. Buildings stacked against each other like they were competing for the same square of sky. Hawkers moving between cars with the calm confidence of people who had long ago decided the road belonged to everyone equally. Ivie pulled her small bag onto her lap and felt something shift in her chest. She had been to Oredo City twice before, both times for medical reasons, both times too worried to actually look at anything. This time she looked at everything.\nAunty Osato''s flat was in a part of the city where the roads were tarred and stayed tarred. That was the first thing Ivie noticed. The second thing was the gate, which was metal and freshly painted and operated by a man in a uniform who nodded at Aunty Osato''s name like it meant something in this particular building.\nThe flat itself was on the third floor. Aunty Osato opened the door before Ivie finished knocking.\n"You look like your father," was the first thing she said. "Come inside before the cold runs out."\nThe flat had air conditioning. Not the window unit kind that Ivie had seen in her headmistress''s office, grinding and leaking and smelling of old water. This was the kind that lived in the ceiling and breathed cold air down so evenly and quietly that you only noticed it because your skin said thank you.\nIvie noticed everything.\nThe sofa was leather, the real kind, dark brown and deep enough to swallow you. There were framed photographs on the wall, Aunty Osato in places Ivie could not name: in front of a fountain, on a bridge, standing in a market where the buildings behind her were old in a way that Nigerian buildings were not. A flat screen television wider than Ivie''s entire mattress at home sat against one wall. On the kitchen counter, visible from where Ivie stood, were fruits she had only seen in the imported section of shops she had never bought anything from.\n"Sit," Aunty Osato said, already moving toward the kitchen. "I made soup."\nIvie sat on the edge of the sofa, then caught herself sitting on the edge and made herself sit fully back. She was not going to act like someone who had never seen a sofa.\nAunty Osato was forty something, though she carried it like a decision rather than a fact. Her hair was done in a style that cost more than Ose''s school fees. Her skin had the particular evenness that came not from genetics but from money and time and products Mama would not recognise. She moved through her kitchen the way wealthy people moved through all spaces: without checking to see if anything was in her way, because things arranged themselves for her.\nThey ate together at a dining table with matching chairs. Ivie had not sat at a dining table with matching chairs before.\n"Your mother says you are reading hard," Aunty Osato said.\n"Yes ma."\n"What subjects are you strong in?"\n"English. Literature. Biology."\nAunty Osato nodded slowly, like she was filing information. "And the others?"\n"I am working on them."\n"Work harder. When I take someone somewhere, I need to know they have a head on their shoulders." She said it simply, the way you said pass the salt. Then she picked up her phone and began scrolling, conversation apparently finished.\nIvie looked down at her soup.\nWhen I take someone somewhere.\nThe sentence landed in her stomach alongside the food, warm and enormous. She had not imagined it two years ago. She had not invented the promise. It was real and it was sitting across the table from her in a flat with air conditioning that breathed like a living thing.\nShe looked up at the photographs on the wall again. The bridge. The fountain. The old buildings in the background of that market shot. She did not know which country it was.\nShe was going to find out.\n"Aunty," she said carefully. "The place in that photograph. The one with the bridge. Where is that?"\nAunty Osato glanced up from her phone. Something moved across her face. It was quick, and Ivie did not know enough yet to name it.\n"Italy," Aunty Osato said. Then she smiled. "Finish your soup."','\n',char(10)),840,0,1,NULL,'2026-04-15T07:07:11.935Z','2026-04-15 07:07:12','2026-04-15 07:07:12',NULL,1,38);
INSERT INTO "chapters" ("id","novel_id","chapter_number","title","content","word_count","is_premium","is_published","audio_url","published_at","created_at","updated_at","scheduled_release_at","part_number","season_id") VALUES(417,54,3,'The Deal',replace('The second morning in Aunty Osato''s flat, Ivie woke up before anyone else and simply lay still, listening to the silence.\nThat was the thing about this place that she could not fully explain to herself. It was not just the things she could see. It was what was absent. No Ose kicking in his sleep beside her. No roof that ticked and shifted in the night wind. No sound of Mama rising at five to start water boiling on a stove that took three attempts to light. Just the cool, even breath of the air conditioning and the particular quiet of a building where everyone had enough.\nShe stared at the ceiling and made a decision: she was going to be very careful today. She was going to listen more than she talked, and she was going to remember everything.\nAunty Osato made tea at seven, real tea with a kettle that boiled on its own, and set a plate of sliced bread and eggs on the counter without asking if Ivie was hungry. That was another thing wealth did, Ivie was noticing. It assumed. It did not ask whether you needed something. It simply provided, the way weather provided rain, without negotiation.\nThey ate. Aunty Osato was on her phone again, typing with the focused energy of someone managing things that happened in time zones Ivie had never considered. After a while she set the phone face down and looked at Ivie with the full weight of her attention.\nIt was a different kind of being looked at. Not the way teachers looked at you to find what was wrong. More like the way a person looked at something they were considering buying.\n"Tell me about your school," she said.\nIvie told her. The classes, the teachers she respected, the ones she had learned to work around. She talked about her Literature teacher, Mr. Idehen, who read passages aloud like they were personal letters. She talked about how she had failed Mathematics in her first mock and sat with the textbook every night for three weeks after until it stopped feeling like a foreign language.\nAunty Osato listened without interrupting. That was unusual in Ivie''s experience. Most adults listened only until they found their entry point.\n"You are serious," Aunty Osato said when she finished. It was not a compliment exactly. More like a conclusion.\n"I have to be," Ivie said.\n"Why?"\nThe question surprised her. She thought the answer was obvious. But she gave it honestly. "Because nothing is going to change for my family if I am not. Eki and Ese are watching me. Even Ose, even if he does not know it yet. If I stay small, they will think small is the only option."\nAunty Osato was quiet for a moment. Outside, a car horn sounded three times and then gave up.\n"Your father used to say things like that," Aunty Osato said. "He was a man who believed in the idea of things more than the reality. It got him into trouble sometimes." She paused. "But you are not him. You have his words and your mother''s sense. That is a useful combination."\nIvie did not know whether that was a compliment either. She filed it away to examine later.\n"I want to ask you something," Ivie said. She kept her voice level. She had rehearsed this moment approximately forty times since the bus ride yesterday. "You said when I finish school we will talk. I want to know what that means. Exactly."\nAunty Osato leaned back in her chair and looked at her for a long moment.\n"It means what it means," she said. "You finish your WAEC. You pass well, not anyhow, I mean well. You bring me your results. Then I will process what needs to be processed and when I am returning after Christmas next year, you will come with me."\nThe words arrived one by one and Ivie received each of them like something fragile.\n"To Italy," Ivie said.\n"To Italy."\n"To do what?"\n"To work. To learn. To get your footing before you decide what life you want to build." Aunty Osato''s voice was even, almost bored, the way people described a route they had driven many times. "I have a setup there. Girls who come, work, save, move forward. You will not be starting from nothing. You will be starting from somewhere."\nIvie nodded slowly. Her heart was doing something complicated behind her ribs.\n"What kind of work?" she asked.\nAunty Osato smiled. It reached her eyes and stopped just before it reached anywhere deeper.\n"The kind that pays," she said. "Go and call your mother. Tell her you are fine."\nIvie got up, picked up the phone she had been lent for the visit, and walked to the window. Oredo City stretched out below her, rooftops and roads and all those lives going forward. She dialled Mama''s number. It rang four times before Mama picked up, and in those four rings Ivie stood at the window of Aunty Osato''s flat and watched Oredo City stretch below her and felt, for the first time, the specific weight of what she had just agreed to. She did not know yet what to call the feeling. She told herself it was excitement. It was easier to carry that way.','\n',char(10)),891,0,1,NULL,'2026-04-30 08:48:40','2026-04-15 07:08:16','2026-04-30 08:48:40',NULL,1,38);
INSERT INTO "chapters" ("id","novel_id","chapter_number","title","content","word_count","is_premium","is_published","audio_url","published_at","created_at","updated_at","scheduled_release_at","part_number","season_id") VALUES(418,54,4,'Kachi',replace('Onyekachi Obi had a way of appearing at the exact moment Ivie was trying to think, which was either a gift or a problem depending on the day.\nShe had known him for two years, since he moved to Ovia with his uncle''s family from Enugu. He was the kind of boy who did not announce himself loudly but ended up in the centre of every room anyway, not because he pushed his way there but because people shifted to make space without quite realising they had done it. He was funny without trying. He listened like he meant it. And he had decided somewhere in their second year of knowing each other that Ivie Osagie was the most interesting person in Ovia, a fact he communicated not through grand gestures but through consistent, stubborn presence.\nThey were sitting behind the compound wall of his uncle''s house, sharing a bottle of Fanta that was already warm because Ovia''s light had been out since morning. It was a Saturday, three days after Ivie returned from Oredo City, and she had been carrying Aunty Osato''s words around like something she had not yet found the right place to set down.\nShe told him everything.\nKachi listened without interrupting, which was one of the things she valued most about him. When she finished he was quiet for a moment, turning the Fanta bottle in his hands.\n"So she did not tell you what kind of work," he said.\n"She said the kind that pays."\n"That is not an answer."\n"I know." Ivie pulled her knees up. "But everything else she has is real. The flat, the things inside it. Those photographs. She has been to that place and come back with something to show for it. That is more than most people around here can say."\nKachi nodded slowly. Not in agreement. In the way people nodded when they were organising their words carefully.\n"I am not saying she is lying," he said. "I am saying you did not get a real answer to a real question and you decided to be satisfied with that."\n"I decided to be patient."\n"Those are different things, Ivie."\nShe looked at him. His face was doing the thing it did when he was genuinely worried, a slight tension around his jaw, his eyes more still than usual. Kachi''s face was a poor liar and she had learned to read it the way she read her Literature texts, not just for what was on the surface.\n"You do not want me to go," she said.\nHe did not answer immediately. A motorcycle passed on the road beyond the wall, its engine loud and then fading.\n"I want you to go somewhere," he said finally. "I want you to have everything you are talking about. I want your family to stop struggling. I want all of that for you." He paused. "I just have a feeling I cannot explain properly, about this specific thing, this specific woman."\n"She is family, Kachi."\n"Family is not a guarantee of anything."\nIvie opened her mouth and closed it again. She could not argue with that particular truth. Her father''s brother had borrowed money from Mama the year after the funeral and never mentioned it again. Family was not a guarantee. She knew that.\n"What would you have me do," she said. "Stay here? Marry someone from this town? Watch my mother get old in that house until the roof finally gives in completely?"\n"I would have you ask better questions before you get on a plane."\n"I am going to pass my WAEC first. Nothing is happening until after that."\n"And after that?"\n"After that I will have more information. I will have talked to her more. I will know more than I know now."\nKachi looked at her for a long moment. Then he handed her the Fanta even though there was barely any left. It was something he did, giving her the last of things without commentary, and it always landed somewhere in her chest that she did not have a name for yet.\n"I am not going to tell you not to go," he said. "You would not listen and I would waste my breath." The corner of his mouth moved, not quite a smile. "But promise me something."\n"What?"\n"That if anything feels wrong, you will not talk yourself out of that feeling. You are smart enough to build a case for almost anything. Do not use that against yourself."\nIvie took the bottle. The Fanta was flat and warm and tasted of plastic from sitting in the sun.\n"You sound like an old man," she said.\n"You sound like someone who has already decided and is telling me after the fact."\nShe did not deny it.\nThey sat there until the sun started going down. When she finally stood to go Kachi said, quietly, without looking at her, "If something goes wrong there, something real. Promise me you will find a way to say it." She looked at him. "Nothing is going to go wrong." He nodded, not like he agreed, like he had expected that answer. She walked home with the warmth of his shoulder still on her arm and told herself he was worried because he cared and not because he knew something she didn''t.','\n',char(10)),891,1,1,NULL,'2026-04-30 08:56:58','2026-04-15 07:11:43','2026-04-30 08:56:58',NULL,1,38);
INSERT INTO "chapters" ("id","novel_id","chapter_number","title","content","word_count","is_premium","is_published","audio_url","published_at","created_at","updated_at","scheduled_release_at","part_number","season_id") VALUES(419,54,5,'Last Paper',replace('The results were posted on a Wednesday morning, and by the time Ivie got to school the noticeboard already had a crowd around it three people deep.\nShe did not push. She stood at the back and watched faces come away from the board wearing their results before they could arrange their expressions. Chioma from her class walked away crying, whether from joy or the opposite Ivie could not tell. Two boys she barely knew were slapping each other on the back with the particular violence of male celebration. A girl named Precious was on her phone already, her voice climbing.\nIvie waited until the crowd thinned. She was good at waiting. She had been practicing it for a year.\nWhen she finally stepped up to the board her eyes found her name quickly, she had always been fast at finding herself in lists, some habit built from years of checking if her name was on scholarship notices, bursary lists, anything that might mean the next term''s fees were manageable.\nShe read it once.\nThen she read it again, more slowly, the way you reread something when your brain refuses to accept that the first reading was accurate.\nEight subjects. Seven distinctions. One credit, in Mathematics, which she had earned the hard way and was therefore more proud of than any of the distinctions.\nShe stood very still for a moment. Around her the schoolyard was all noise and movement and the specific chaos of two hundred teenagers receiving the verdicts on years of their lives. Ivie stood in the middle of it and felt something enormous and quiet moving through her, like a river running under a road.\nShe had done it.\nShe walked home instead of taking a bus. Forty minutes on foot in the afternoon heat, her bag on her back, her results sheet folded in her hand. She needed the time to get her face ready. She did not want to arrive home already crying because Mama would cry too and then Eki and Ese would cry and Ose would cry because everyone else was crying, and she wanted at least one clear moment before the house filled with noise.\nMama was in the kitchen when she walked in.\nIvie held out the results sheet without saying anything.\nMama wiped her hands on her wrapper and took it. She read it with the careful attention she gave to everything she considered important, receipts, letters from school, medical forms, moving her lips slightly. Then she looked up.\n"Raymond," she said softly. Not to Ivie. To something behind her, or before her, or somewhere that was not in the kitchen at all.\nThen she pulled Ivie into her arms and held on.\nThat was when Ivie cried.\nShe called Aunty Osato from a neighbor''s phone that evening, standing outside in the blue dark, the compound quiet behind her.\nAunty Osato picked up on the third ring.\n"I have my results," Ivie said.\nA pause. "And?"\n"Seven distinctions. One credit."\nAnother pause, longer this time. When Aunty Osato spoke again her voice had shifted slightly, the way a door shifted when someone on the other side leaned against it.\n"Good girl," she said. "Scan everything and send to this number. I will tell you what to do next."\nWhat came next arrived in stages over the following three weeks. A list of documents. A trip to Oredo City with Mama that Aunty Osato paid for, their first time in a government passport office, a building that smelled of old paper and new frustration. A man at a desk who looked at their documents with the slow deliberation of someone who understood that time was his only power. Forms. Photographs taken under a white light that made everyone look slightly alarmed. More forms.\nAunty Osato sent money for the processing fee, then more money for what the passport office man called facilitation, a word that meant something different here than in any dictionary. Mama held each transferred amount in her hand like a debt she was not sure how to carry. Ivie told her it would be repaid when she got there and settled. She said it with the confidence of someone who believed it completely.\nThe passport came on a Thursday. Navy blue, her photograph inside looking back at her like a stranger who shared her face. She turned it over in her hands, reading the words she had seen on government documents all her life, words that now carried different weight because they were attached to her name, to her face, to a future that had a direction.\nThat night she showed it to Kachi over the compound wall.\nHe held it carefully, like it was something that could be damaged.\n"That is real," he said quietly.\n"I know."\nHe handed it back. His eyes moved over her face, reading something she had not written there on purpose.\n"When?" he said.\n"She comes back at Christmas. I leave with her when she returns."\nKachi nodded. He looked down at his hands. The evening was warm and the street behind them was beginning to settle into its night sounds.\n"Okay," he said. Just that word. But the way he said it carried everything he was choosing not to.','\n',char(10)),879,1,1,NULL,'2026-04-15T07:12:48.431Z','2026-04-15 07:12:48','2026-04-15 07:12:48',NULL,1,38);
INSERT INTO "chapters" ("id","novel_id","chapter_number","title","content","word_count","is_premium","is_published","audio_url","published_at","created_at","updated_at","scheduled_release_at","part_number","season_id") VALUES(420,54,6,'The Night Before',replace('The bag had been packed for three days. Ivie kept unpacking it and repacking it, not because anything was wrong with how it was arranged but because it gave her hands something to do while her mind ran in every direction at once.\nIt was the night of December 28th. Aunty Osato''s flight back to Italy left the following afternoon from Lagos, a city Ivie had never been to, and they were taking a morning bus to make it in time. Everything was organised. Everything was confirmed. And yet Ivie found herself standing over the open bag at nine in the evening, refolding a blouse she had already folded twice.\n"You have folded that one before," Eki said from the doorway.\n"I know."\n"You are nervous."\n"I am not."\nEki came and sat on the edge of the bed anyway, watching her with the particular attention of a younger sibling who had spent years reading the room and surviving on the information. She was fourteen now and had developed opinions about everything that she delivered with a confidence Ivie secretly admired.\n"I will be the oldest when you leave," Eki said.\n"You will still be the second oldest."\n"It is the same thing when you are not here." A pause. "I know what to do. Do not worry about us."\nIvie looked at her. Sometimes Eki said exactly the right thing with such casual precision that it felt like being seen clearly in a mirror you did not know was there.\n"I am not worried," Ivie said. "I am coming back better. When I come back, things will be different."\nEki nodded with the patient expression of someone who hoped this was true and was not going to argue either way.\nMama called her into the bedroom at ten.\nThe room was dim, one small lamp on the dresser throwing warm light across the walls. Mama was sitting on the bed in her housedress, her Bible open on her lap, though she was not reading it. She was waiting.\nIvie sat beside her and Mama took both her hands and held them the way she used to when Ivie was small and sick and the night felt too large.\nShe prayed for a long time. Not the quick, efficient prayers Ivie had heard at family events, God bless the food, God bless this gathering. This was a different kind of prayer, the private kind, built slowly from the inside, the kind that came from a woman who had already lost the person she trusted most and was now releasing another person into a world that had already shown her what it was capable of.\nShe prayed for safety. For wisdom. For doors to open and the right ones to stay closed. She prayed Ivie would remember who she was when she was far from everyone who knew her. She prayed in English and then shifted into Esan without noticing, the words coming from somewhere older than either of them.\nWhen she finished she kept holding Ivie''s hands. The lamp flickered once and steadied.\n"You are my serious one," Mama said. "You have always been my serious one. Even when you were small, when other children were playing, you were watching. Taking everything in." She squeezed her hands. "That thing inside you, that serious thing, do not let anywhere take it from you. You hear me?"\n"Yes Mama."\n"Whatever you see, whatever happens, you are Raymond''s daughter and you are mine. That is not something a place or a person can remove. Do you understand what I am telling you?"\nIvie nodded. Her throat was doing something difficult.\n"I understand," she managed.\nMama pulled her in and held her, and Ivie pressed her face into her mother''s shoulder and breathed her in, the familiar warmth of her, the smell of shea butter and sleep and everything that had always meant safe.\nShe went to Kachi at eleven, when the house had gone quiet. He was already at the compound wall, like he had been waiting, which he probably had.\nThey stood in the dark without talking for a moment. The night was warm and still, Ovia settled around them, the kind of quiet that only existed this late when even the dogs had decided there was nothing left worth announcing.\n"I will write," she said. "When I have a way to."\n"I know."\n"It will not be forever. One year, maybe two. Then I will have money and a plan and I will come back or send for you or something. There is a way forward in this, Kachi. I can see it."\nHe looked at her the way he always did when she said things he was not sure he agreed with but had decided not to fight. Then he reached into his pocket and brought out a small folded piece of paper.\n"My uncle''s email," he said. "In case calling is hard. He will get the message to me."\nShe took it and held it tightly.\n"Kachi."\n"Go," he said quietly. "Before I say something that will not help either of us."\nShe went. At the gate she stopped. Not because she had decided to stop. Because something in her body paused without permission and stood in the dark of the compound entrance and looked back at the wall where he was still sitting, though she could not see him from here. The night was warm and entirely ordinary and tomorrow she was getting on a plane and Kachi was staying here and she had promised herself she would not make this into something large. She made herself walk. She did not look back again. She told herself that was the same as not wanting to.','\n',char(10)),957,1,1,NULL,'2026-04-30 08:58:23','2026-04-15 07:13:44','2026-04-30 08:58:23',NULL,1,38);
INSERT INTO "chapters" ("id","novel_id","chapter_number","title","content","word_count","is_premium","is_published","audio_url","published_at","created_at","updated_at","scheduled_release_at","part_number","season_id") VALUES(421,54,7,'Fiumicino',replace('The plane lifted off the Lagos runway and Ivie gripped the armrest with both hands and decided she was not going to be the kind of person who was afraid of flying.\nShe was not afraid. She was simply very aware that she was inside a machine the size of a building that had just left the ground and was now climbing through cloud cover at a speed her body had no reference for. That was not fear. That was information.\nAunty Osato was in the window seat, already asleep or performing sleep well enough that it made no difference. She had moved through the Lagos airport with the efficient calm of someone who had done this so many times it had become administrative, bags checked, boarding passes produced, security queues navigated without once looking uncertain. Ivie had stayed close and copied every move, handing over documents when documents were needed, stepping forward when it was time to step forward, keeping her face arranged into an expression she hoped communicated that she also did this regularly.\nShe had not. She had never been on a plane. She had never been to Lagos. Both of those things had happened in the same day.\nAt thirty thousand feet, when the seatbelt sign went off and the cabin crew began moving with trays, Ivie allowed herself to look out across Aunty Osato at the window. There was nothing outside but dark and the occasional scattered light far below, whole towns reduced to suggestions. She thought about Ovia down there somewhere, Mama in the bedroom with the small lamp, Eke and Ese sharing the bed, Ose sprawled across his own mat with the careless sleep of someone who did not yet know the world was large and mostly indifferent.\nShe was going to change what that world felt like for all of them.\nShe accepted the juice the cabin crew offered and drank it and watched a film on the small screen in the seat back in front of her, an action film with subtitles she did not need. When sleep came she did not fight it.\nFiumicino Airport arrived as light. That was the first thing. The terminal was washed in pale morning brightness that came from everywhere at once, from the high ceilings, from the glass walls, from surfaces that seemed designed to hold and distribute illumination. Everything was white and grey and moving. Signs in Italian and English. Voices in languages she could not separate from each other. A floor so clean and continuous it looked like it had been poured that morning.\nIvie walked through it and felt like a person inside a screen.\nCustoms took twenty minutes. A man in uniform looked at her passport, looked at her face, looked at her passport again with the specific attention of someone whose job was to find the gap between a document and a person. He stamped it and waved her through. She breathed again.\nOutside the secure area, Aunty Osato was already moving toward the exit, wheeling her large bag with purpose. Ivie pulled her own smaller bag and followed. The automatic doors opened and Italy came in through them, a January morning that was cold in a way Ivie had never felt cold before, a clean, pressing cold that found every gap in her clothing immediately and settled there.\nShe almost laughed. She had known Italy would be cold in January. She had read about it, thought about it, packed for it. And still the reality of it was something that reading had not fully prepared her for. That was interesting to her. The difference between knowing a thing and standing inside it.\nThe car was already waiting. A dark saloon with a driver who nodded at Aunty Osato without speaking and put the bags in the boot with the practiced ease of someone following a routine. Ivie got in and the car moved and Italy scrolled past the windows in the grey morning light, roads and buildings and bare trees and road signs she read carefully even though she did not know where they were going.\nShe would learn. She would learn everything.\nThey drove for forty minutes before the car stopped outside a building in an area that was quieter than the roads they had come through. Aunty Osato got out. Ivie followed.\nIn the small hallway inside, before they reached the stairs, Aunty Osato turned and held out her hand.\n"Your passport," she said. "I will keep documents safe. The system here, they sometimes check. It is better I hold everything together."\nIvie looked at the outstretched hand.\nSomething moved in her chest. Small and quick, like a bird startled from a branch. She thought of Kachi''s voice: if anything feels wrong, do not talk yourself out of that feeling.\nBut Aunty Osato was watching her with patient, familiar eyes, and outside was a country whose language Ivie did not speak, and the logic of the explanation was not unreasonable.\nShe placed her passport in Aunty Osato''s hand.\nAunty Osato put it in her bag without looking at it, turned, and started up the stairs.\nIvie stood in the hallway for one breath longer than was necessary.\nThen she followed.','\n',char(10)),874,1,1,NULL,'2026-04-17 13:06:04','2026-04-15 07:14:42','2026-04-17 13:06:04',NULL,1,38);
INSERT INTO "chapters" ("id","novel_id","chapter_number","title","content","word_count","is_premium","is_published","audio_url","published_at","created_at","updated_at","scheduled_release_at","part_number","season_id") VALUES(422,54,8,'Madam',replace('The room they gave her had a window the size of a textbook, and when Ivie woke up the first morning she lay still and listened to the building before she opened her eyes.\nVoices. Women''s voices, speaking in a mix of languages she could not separate, Italian threading through something that sounded like Yoruba, then Pidgin, then a language she did not recognise at all. Movement above and below her. A door opening and closing with the frequency of a building that was fully occupied and already awake. The cold she had felt at the airport had followed her inside and settled into the walls.\nAunty Osato had shown her to this room the night before, told her to sleep, told her they would talk in the morning. The room had a single bed, a plastic chair, and a small mirror nailed to the wall at a height that caught mostly forehead. Ivie had sat on the bed for a long time before she slept, telling herself the strangeness was just newness, that everything unfamiliar felt wrong at first, that this was the beginning of something and beginnings were supposed to be uncomfortable.\nShe had almost believed it.\nAunty Osato came for her at nine and told her to dress warmly and come.\nThey left the building and walked. The neighbourhood it sat in was not the part of Italy Ivie had seen in the photographs on Aunty Osato''s wall. There was no fountain, no old beautiful bridge, no market with golden light. These streets were narrow and tired, buildings with peeling paint pressed close together, laundry hanging from lines strung between windows, the pavement cracked and stained in patterns that suggested a long history of neglect. A group of men stood at a corner without apparent purpose. A shop with metal grilles sold things in packaging Ivie did not recognise.\nShe walked and looked and said nothing.\nThey arrived at a low building set back from the road, its entrance half hidden behind a rusted gate that had been left permanently open. Aunty Osato pushed through without slowing.\nInside, a courtyard. And in the courtyard, women.\nSeven or eight of them, young, Ivie''s age or a few years older, some Nigerian by the look of them, some not. They were sitting and standing in the loose arrangement of people who spent a lot of time together and had long since run out of things to perform for each other. They wore the expressions of people waiting for something they were not looking forward to.\nWhen Aunty Osato walked in, they changed.\nNot all at once. In a wave, starting from the ones closest to the gate. They straightened. They turned. And then they spoke.\n"Madam, welcome."\n"Good morning Madam."\n"Madam you are back."\nThe word landed on Ivie like cold water.\nMadam.\nShe looked at Aunty Osato''s face to find something that would explain this differently. An employer and her staff, perhaps. A community leader among her people. Something with a clean and ordinary explanation.\nAunty Osato''s face offered nothing. She was nodding at the greetings with the settled ease of a person receiving what they were owed, moving through the courtyard, exchanging a few words with one girl, touching another briefly on the shoulder in a way that was not warmth but assessment.\nIvie stood at the edge of the courtyard and looked at the girls.\nOne of them was looking back. A girl with a thin face and careful eyes, Ivie''s height, her hair tied back tight. Nigerian. She was watching Ivie with an expression that was not quite pity and not quite warning. It was the expression of someone watching another person walk toward something they have already walked toward themselves and cannot be stopped from reaching.\nIvie looked at her.\nThe girl looked back.\nAnd in the space of that silent exchange, something in Ivie''s chest that had been leaning away from understanding for the past twenty four hours stopped leaning.\nIt stood up straight.\nIt looked at the courtyard, at the building, at the absence of any school or office or workplace, at Aunty Osato moving through these girls like a woman moving through things she owned, at her own passport sitting in a bag that did not belong to her, at the window the size of a textbook in the room they had given her.\nThe girl with the careful eyes looked down first.\nAunty Osato turned from across the courtyard and found Ivie''s face with the particular ease of someone who knew exactly where she had left something.\n"Come," she said. "We have things to discuss."\nIvie''s feet moved. She did not decide to move them. They moved because standing still in a courtyard in a country whose language she did not speak, without a passport, without a phone, without a single person in the world who knew the name of this street, was not an option.\nShe walked toward Aunty Osato.\nThe girl with the careful eyes did not watch her go.\nShe already knew how this part ended.','\n',char(10)),849,1,1,NULL,'2026-04-15T07:15:45.833Z','2026-04-15 07:15:45','2026-04-15 07:15:45',NULL,1,38);
INSERT INTO "chapters" ("id","novel_id","chapter_number","title","content","word_count","is_premium","is_published","audio_url","published_at","created_at","updated_at","scheduled_release_at","part_number","season_id") VALUES(423,55,1,'The Number',replace('The room Aunty Osato used as an office had a desk, two chairs, and a single bare bulb that made everything look like evidence.\nIvie sat in the chair on the wrong side of the desk and kept her hands flat on her thighs. She had decided on the walk from the courtyard that she was going to listen to everything before she responded to anything. That was the clearest instruction she could give herself. Listen. Take it in. Do not react until you understand the full shape of what you are reacting to.\nAunty Osato sat down and opened a small notebook. She did not look at Ivie immediately. She paged through the notebook with the unhurried attention of someone reviewing figures they already knew, a performance of thoroughness rather than actual calculation. Ivie recognised it from her secondary school principal, who used to shuffle papers before difficult conversations to remind everyone in the room who held the time.\nShe kept her hands flat. She kept her face still.\n"You are a smart girl," Aunty Osato said, still looking at the notebook. "Smart enough to understand what I am going to explain without me repeating myself. So I will say everything once."\nShe looked up.\n"You are here because I brought you here. The flight, the documents, the processing fees, the facilitation in Lagos, the transport from the airport, the room you slept in last night. Everything has a number attached to it." She turned the notebook around and placed it on the desk facing Ivie. "That is what you owe me."\nIvie looked at the number.\nShe had prepared herself, in some distant practical corner of her mind, for a debt. That part she had assembled into a shape she could manage. Aunty Osato had spent money. There would be repayment terms. That was the framework she had been working with since the courtyard, since the passport, since the small cold room with the window the size of a textbook.\nThe number in the notebook dissolved that framework completely.\nIt was not the cost of a flight and some documents. It was the cost of a car and a flight and documents and what Aunty Osato called accommodation and what Aunty Osato called connection fees and what Aunty Osato called investment in Ivie''s future, each item listed in a column with a figure beside it, and at the bottom a total that sat on the page like something immovable.\nIvie looked at the number for a long time.\nShe thought about Mama''s voice on the phone the morning she left. She thought about the passport photograph, her own face looking back at her like a stranger. She thought about Kachi''s piece of paper folded in the bag in her room, his uncle''s email address in his careful handwriting.\nShe thought about what kind of work Aunty Osato had described as the kind that pays.\nThe floor did not disappear. That was not quite right. The floor stayed exactly where it was and Ivie stayed exactly where she was and the room stayed exactly where it was, but something shifted in the arrangement between them so that nothing she was sitting in felt like it meant what it had meant ten minutes ago.\n"I cannot pay this," she said. Her voice came out level. She was surprised and grateful.\n"You will not pay it in money," Aunty Osato said. "Not directly. You will work. The other girls will show you how things operate here. You will have a daily target. Everything you earn above your keep goes toward the number. When the number reaches zero you are free to go wherever you like."\nShe said it the way you described a bus route. Transfer here, alight there, the journey takes however long it takes.\nIvie looked at her. This woman who had sat across a dining table from her in Oredo City. Who had listened to her talk about Mr. Idehen and the Literature textbook. Who had held out her hand in the hallway and said I will keep documents safe in the voice of a reasonable person offering reasonable help.\n"What kind of work," Ivie said.\nAunty Osato closed the notebook.\n"The girls will explain," she said. "You will understand quickly. You are not the first and the ones who do well here are the ones who understand quickly and cause no trouble." She stood up, which meant the meeting was over. "I am not a wicked woman, Ivie. I am a businesswoman. You are not a prisoner. You are someone who owes a debt. There is a difference."\nIvie stood because there was nothing else to do.\nAt the door she stopped. She did not turn around.\n"My passport," she said.\n"Will be returned when the number reaches zero," Aunty Osato said. "That is also how it works."\nIvie walked out.\nThe girl with the careful eyes was in the corridor. She had been waiting, or perhaps she had simply been nearby, and the difference did not matter.\n"I am Sade," she said quietly.\nIvie looked at her.\n"How long have you been here," Ivie said.\nSade looked at the wall. Then back at Ivie.\n"Long enough," she said. "Come. I will show you."','\n',char(10)),877,0,1,NULL,'2026-04-15T07:19:54.107Z','2026-04-15 07:19:54','2026-04-15 07:19:54',NULL,2,39);
INSERT INTO "chapters" ("id","novel_id","chapter_number","title","content","word_count","is_premium","is_published","audio_url","published_at","created_at","updated_at","scheduled_release_at","part_number","season_id") VALUES(424,55,2,'Day One',replace('Sade had told her to count something.\nAnything, she said. The cracks in the ceiling. The seconds between cars on the road outside. Just find a number and follow it. Your mind needs somewhere to be that is not here. Give it somewhere to be.\nIvie had nodded like this was practical advice about a practical situation. She had kept nodding while Sade explained the rest of it, the street, the hours, the men, the amount per transaction that went into the envelope and what happened if the envelope was short at the end of the night. She had nodded and filed each piece of information away in the same part of her mind she used for WAEC revision, the part that received difficult material without judgment and simply held it until it was needed.\nThat part of her mind was working very hard this morning.\nThe street was twenty minutes from the building, which Ivie understood now to be one of three buildings Aunty Osato operated in this part of the city. Sade walked with her and three other girls in the grey morning cold, all of them dressed in the way Sade had described, in a way that felt to Ivie like wearing the wrong answer to a question, and she kept her eyes forward and her breathing steady and told herself that whatever this morning was, it was information. She was gathering information. She was learning the shape of the thing she had to dismantle.\nThe street itself was unremarkable in the way that all terrible things, up close, turned out to be unremarkable. It was a road. Cars passed. Buildings stood on either side doing what buildings did. Other girls from other buildings were already positioned along it, some talking to each other, some not, everyone performing a version of waiting that was specific and practiced and which Ivie catalogued with the careful attention she had always given to things she was seeing for the first time.\nShe thought about Ovia. Deliberately. She brought it up the way you brought up a song you needed to stay calm, her mother''s kitchen in the morning, the sound of Ose demanding something with the confidence of a last born who had never been told the word no. She held those images at the front of her mind and let the street exist behind them, at a slight remove, as something she was observing rather than something she was standing inside.\nShe counted cracks in the pavement. She got to eleven before the first car slowed.\nWhat Ivie discovered that day, in the specific and unasked for education of it, was that a person could be in two places at once.\nNot in the way people meant when they said they were distracted or daydreaming. In a more structural way. A way that felt almost architectural, like a house with two floors where the noise on the ground floor had nothing to do with what was happening in the room upstairs.\nUpstairs was where she kept herself.\nDownstairs was where she kept her body, which was also hers but which she had decided, with the cold deliberate precision of a girl who had passed seven WAEC subjects on willpower alone, she was going to treat as a separate matter. A practical matter. The kind that paid.\nShe counted. Ceiling tiles. Road sounds. Her own pulse when she could feel it. She thought about her father''s voice, which she could barely remember now but whose texture she still held, the low warmth of it, the way it used to read her name like it was something worth saying carefully. She thought about Kachi''s shoulder warm against hers in the Ovia evening. She thought about what the number in Aunty Osato''s notebook would look like when it reached zero.\nShe thought about zero constantly. Zero was the most beautiful number she had ever considered. Zero was a door.\nSade found her at the end of the day and walked back with her and did not say anything for a long time, which was exactly right. Some things needed the silence that came after them to be respected.\nWhen they were almost at the building Sade said, "You did well."\nIvie looked at her. "Do not say that to me."\nSade nodded slowly. "Okay."\n"I did what I had to do. I will do it again tomorrow and the day after. But do not make it into something it is not."\n"Okay," Sade said again, simply.\nInside, Ivie went to her room and sat on the edge of the bed. She pressed the heels of her hands against her eyes until she saw light. She stayed like that for a long time.\nThen she got up. She found the corner of the room where she had hidden a small piece of paper and a stub of pencil. She drew a line.\nOne day.\nShe looked at the line for a moment. One mark on a piece of paper. Barely visible.\nShe folded it and put it back in its hiding place.\nThe number in Aunty Osato''s notebook was large. But every large number was made entirely of ones.\nShe could count ones.','\n',char(10)),870,0,1,NULL,'2026-04-15 07:22:07','2026-04-15 07:20:49','2026-04-15 07:22:07',NULL,2,39);
INSERT INTO "chapters" ("id","novel_id","chapter_number","title","content","word_count","is_premium","is_published","audio_url","published_at","created_at","updated_at","scheduled_release_at","part_number","season_id") VALUES(425,55,3,'The Other Girls',replace('The kitchen was the only room in the building where nobody was required to be anything.\nIvie discovered this on her fourth day, when she woke before the others and went looking for water and found Sade already there, sitting on the counter eating bread with the uncomplicated focus of someone who had temporarily suspended all other concerns. Sade looked at her, offered the bread without speaking, and Ivie took a piece and ate it standing up, and for approximately four minutes nothing was required of either of them.\nThat was how she learned that the kitchen, between the hours of six and seven in the morning, belonged to whoever needed it most.\nThere were seven girls in the building. Ivie began to know them the way you learned a new neighbourhood, not all at once but in layers, one detail at a time until the map became reliable.\nSade was from Lagos, Surulere specifically, which she mentioned with the reflex pride of someone who had decided that where you came from was the last thing anyone could take. She had been in the building for fourteen months. She spoke about this the way a person spoke about a surgery they had recovered from, with the flat factual tone of someone who had processed the worst of it and arrived somewhere on the other side that was not quite fine but was at least stable. She was the one the other girls went to when something needed solving. Not because she had appointed herself but because she had simply been there longest and competence, in the absence of everything else, became its own kind of authority.\nPrecious was from Edo State, which she and Ivie discovered on Ivie''s fifth morning in the kitchen and which produced a moment of recognition so fierce it felt almost violent, two people finding their language in a place where language had been stripped away. Precious was twenty, small, with the careful economy of movement of someone who had learned not to take up more space than necessary. She had been in the building for eight months. She laughed at things that were not funny and Ivie understood this was not confusion but armour.\nRose was Ghanaian. Amara was from Côte d''Ivoire and spoke French and fragments of English she deployed with surgical precision, using few words to say exact things while everyone else was still assembling sentences. There were two others whose names Ivie learned slowly, girls who moved through the house at a remove, who had built their walls higher and were not yet ready to let anyone near enough to even knock.\nIvie did not push. She understood the walls.\nWhat she had not expected was the humour.\nIt arrived in small doses and strange moments, a comment from Sade about the particular expression of a man who had tried to negotiate a lower price, delivered so drily that three of them were laughing before they could stop themselves. Precious doing an impression of Aunty Osato''s walk, the slight forward lean of a woman who moved through spaces like she was perpetually arriving, that was so accurate it filled the kitchen with the complicated laughter of people laughing at something that was not funny and was also somehow, in this specific company, exactly funny.\nIvie laughed and felt guilty for laughing and then looked at the others and saw the same guilt moving through their faces and understood that the guilt was part of it, that the laughter and the guilt were not opposites but the same response to the same impossible thing.\nSurvival had a texture she had not read about in any book. It was not clean or linear. It did not progress steadily from broken to repaired. It moved sideways and backwards and occasionally sat completely still, and in the gaps between its movements, apparently, it sometimes produced bread eaten on a kitchen counter at six in the morning and laughter that hurt the chest on the way out.\nOn her ninth night, Ivie found Amara sitting outside the building''s back door in the cold, her arms around her knees, looking at nothing.\nIvie sat beside her without asking. They sat in silence for a while, the cold pressing in from all sides.\nThen Amara said something in French that Ivie did not understand. But the tone of it was clear enough, the specific exhaustion of a sentence that meant I did not think it would be this long.\n"I know," Ivie said.\nAmara looked at her sideways. Then she nodded, once, and looked back at the dark.\nThey sat there until the cold became unreasonable and went inside.\nIt was not friendship exactly. Ivie was not sure she had the capacity for friendship right now, not in the full, open-handed way she had been friends with Kachi, where you gave the real version of yourself and trusted it would be held carefully.\nThis was something else. Smaller and stronger than friendship. The specific bond of people who had looked at the same impossible thing and chosen, each in their own private way, to keep going anyway.\nIt did not have a name. She was lying in the narrow bed thinking about this when she heard, from the room next to hers, the sound of someone crying with the specific discipline of someone trying not to be heard. She lay still and listened and did not knock because knocking would make it real for both of them. But she pressed her hand against the wall between the rooms and kept it there for a long time.','\n',char(10)),937,0,1,NULL,'2026-04-30 08:59:40','2026-04-15 07:21:51','2026-04-30 08:59:40',NULL,2,39);
INSERT INTO "chapters" ("id","novel_id","chapter_number","title","content","word_count","is_premium","is_published","audio_url","published_at","created_at","updated_at","scheduled_release_at","part_number","season_id") VALUES(426,55,4,'The Rules',replace('Season 2, Episode 4 — "The Rules"\nShe learned the first rule by watching what happened to a girl named Cynthia.\nCynthia was from Warri, had been in the building for three months before Ivie arrived, and had the particular restlessness of someone who had not yet found the internal architecture that made endurance possible. She talked too much and too loudly and laughed in a way that filled rooms without reading whether rooms wanted filling. Ivie had not decided what she thought of her yet when the thing happened.\nIt was a Wednesday evening. A man had stopped his car on the street, a Nigerian man, older, well dressed, his window down. He had spoken to Cynthia in Urhobo, her language, and she had answered, and for approximately four minutes they had talked in the way two people talked when a shared language arrived unexpectedly in a foreign place, with the relief of something found.\nChidinma, the woman who managed the building''s daily operations, was across the street. She watched the conversation without moving. Her face did not change.\nThat night Aunty Osato called Cynthia into the office.\nWhat happened in the office Ivie did not witness. What she witnessed was Cynthia returning from it, sitting on the kitchen floor with her back against the cabinet because the chair was too far and her legs had apparently made a decision. Sade was already there, crouched beside her, saying nothing, which was the right thing.\nIvie stood in the doorway and understood the first rule not as a policy but as a cage inside the cage.\nNo African men. No Black men. Not because of morality or preference. Because a shared language was a shared possibility. Because the one thing Aunty Osato could not afford was a girl finding someone who could understand her without translation.\nShe assembled the others the way she assembled everything: patiently, from evidence rather than assumption.\nThe second rule she confirmed from Precious, who explained the pills with the flat economy of someone describing weather. Wednesday collection. Chidinma at the kitchen door with the foil strips, watching each girl take and swallow before moving to the next. No collection recorded without confirmation. No exceptions discussed because the exceptions were never raised.\nIvie took hers and thought about management. About a system that needed her body functional and unencumbered and available. That did not ask her body what it wanted because the body''s wants were not a variable anyone in this building had budgeted for.\nShe thought about Cynthia on the kitchen floor and the pills on Wednesday morning and the way both of these things shared the same logic: every rule in this building was designed to reduce the number of things she could become.\nShe noted this carefully. The rules were not arbitrary. They were architectural. Which meant they had been designed, and designed things had designers who had made choices, and choices meant there had been alternatives, and alternatives meant there were still gaps.\nThe third rule was the phone, which was not a rule so much as an absence so complete it had become structural.\nIvie had Kachi''s piece of paper in the bag lining, his uncle''s email address in careful handwriting. She had not unfolded it since the hallway in Italy. There was nothing to unfold it for. There was no phone, no internet, no public terminal within walking distance she was permitted to walk alone. The paper was real but access to what it represented was zero.\nShe thought about Mama not hearing from her and filed the thought immediately at the back, behind everything else. Some information was too heavy to carry at the front of your mind while you were trying to remain functional.\nThe fourth rule had no name because it named itself every hour without assistance.\nShe was in Italy. She did not speak Italian beyond the fragments she was accumulating. Her passport was in a desk drawer. Nobody in this building would call for help because calling for help required exposure and exposure was the one thing none of them could risk. The street outside was not a route to freedom. It was a place she went to work and returned from. Beyond it the city was enormous and entirely indifferent to her specific situation.\nThis was the rule that made the others unnecessary. If you could not leave you did not need to be told what you were not allowed to do. The walls managed themselves.\nIvie sat with the full weight of this.\nThen she thought about something her Mathematics teacher had said once, not about cages but about problems: the more walls a structure has, the more places two walls must meet. And where two walls meet, there is always a joint. And joints, under the right pressure, applied in the right direction, by someone patient enough to find the exact point, could be separated.\nShe was patient. She would find the point. The following morning Chidinma came to collect the Wednesday pills and when she handed Ivie''s strip across, Ivie looked at her, just for a moment, with the particular attention of someone filing information rather than receiving it. Chidinma looked back. Something moved across the older woman''s face, too quick to name, and she moved on to the next girl. Ivie took her pill. But she had seen what she had seen: Chidinma knew exactly what this system was and had chosen her place inside it. Which meant she could be read. And anything that could be read could, eventually, be used.','\n',char(10)),932,1,1,NULL,'2026-04-30 09:01:04','2026-04-15 07:23:03','2026-04-30 09:01:04',NULL,2,39);
INSERT INTO "chapters" ("id","novel_id","chapter_number","title","content","word_count","is_premium","is_published","audio_url","published_at","created_at","updated_at","scheduled_release_at","part_number","season_id") VALUES(427,55,5,'What the Body Learns',replace('The body was a practical thing. That was what Ivie decided somewhere around the third week, in the specific quiet that followed a long day when the mind was too tired for anything complicated and the truth arrived simply, without dressing.\nThe body learned. That was what it did. You taught it a new road and after enough repetitions it walked the road without you. You taught it to wake at a certain hour and it woke. You taught it to endure a certain cold and after a while it stopped reporting the cold as emergency information and filed it instead under conditions, simply the way things were in this place at this time of year.\nShe had not chosen this. But the body did not wait for choice. It adapted the way water adapted, taking the shape of whatever it was currently inside, not because it agreed with the shape but because adaptation was what kept water water.\nShe understood this now in a way she had not understood anything before, not from a book, not from instruction. From the inside.\n\nThe inner world had begun as an accident.\nSade had told her to count. She had counted, and in the counting she had found a door, and behind the door was a room, and the room had turned out to be the size of everything she had ever been before she arrived in this building.\nShe had furnished it carefully.\nHer father''s laugh, the low warm texture of it, went against the far wall where she could always find it. Mama''s hands braiding her hair the night before she left went in the centre, because that memory had a weight that wanted to be load bearing. The compound in Ovia at evening, the light going orange across the rooftops, the sound of the street settling into its night. Eki''s sharp mouth and the love underneath it. Ose chasing a lizard with scientific commitment. The Fanta bottle, flat and warm, Kachi''s shoulder warm against hers.\nThese things lived in the room. She visited them on a schedule she kept as strictly as Aunty Osato kept her notebook.\nWhat happened outside the room was outside the room. It was real and it was hers and she was not pretending otherwise, she had tried pretending otherwise in the first week and found it made things worse, like trying to convince yourself a wound did not hurt instead of simply cleaning and wrapping it. Better to know exactly what was happening and put it where it belonged.\nOutside the room: the street, the cold, the envelope, the daily reduction of the number in Aunty Osato''s notebook.\nInside the room: everything that was actually Ivie Osagie.\nThe two did not have to meet. That was the discovery. She had thought they would have to meet, that you could not keep things separated that completely without one contaminating the other. But she was finding, with the same surprised precision with which she had once discovered she could pass Mathematics, that the walls between the room and the street held if she maintained them deliberately. Not perfectly. There were days the walls thinned. There were nights she lay on the narrow bed and felt the two places pressing toward each other in a way that frightened her. But the walls held more than they failed and that was enough.\n\nPrecious noticed.\nShe did not say anything directly, because Precious communicated mostly in observation and indirection, but one afternoon in the kitchen she watched Ivie eat in the particular focused silence Ivie had developed, the silence of someone currently elsewhere, and said, "You found your place."\nIvie looked at her.\n"The place inside," Precious said. She tapped her own temple with one finger. "Some girls never find it. They stay on the surface of everything and the surface is too much to stay on." She picked up her cup. "You found yours fast. That is good."\nIvie considered this. "Does it stay? The longer you are here?"\nPrecious was quiet for a moment. "You have to keep building it," she said finally. "It does not maintain itself. You have to keep putting things in it. Keep making it somewhere worth going."\nIvie nodded slowly.\nThat evening she added something new to the room. Not a memory. Something forward facing, a picture she constructed from intention rather than recollection. A classroom. Herself inside it, older, sitting at a desk with a notebook that was entirely hers, full of things she had chosen to learn. She did not know yet what subject. It did not matter. The point was the choosing.\nShe placed it carefully.\nThen she examined the whole room, all of it, and confirmed that every wall was standing.\nOutside, the building was doing its evening things. Somewhere above her Sade''s footsteps crossed the floor. The cold pressed quietly against the window the size of a textbook.\nIvie sat in the room inside herself and stayed there until she was ready.\nThen she got up and went back to the surface, carrying herself with her. In the corridor she passed Cynthia''s door, which had been closed for three days now, since the office. She stopped outside it. Knocked twice, lightly. Silence. She put her forehead against the wood for a moment, not long, just long enough to say something without words across the door between them. Then she went downstairs. The room inside her was intact. But it had space for one more thing, and she knew now what she was going to put there next.','\n',char(10)),930,1,1,NULL,'2026-04-30 09:09:44','2026-04-15 07:23:55','2026-04-30 09:09:44',NULL,2,39);
INSERT INTO "chapters" ("id","novel_id","chapter_number","title","content","word_count","is_premium","is_published","audio_url","published_at","created_at","updated_at","scheduled_release_at","part_number","season_id") VALUES(428,55,6,'Eki''s Letter',replace('Sade brought it to her on a Tuesday morning, folded inside the waistband of her skirt, passed without ceremony or explanation, which was the only way things could be passed in a building where Aunty Osato moved through rooms without announcing herself.\nIvie looked at it in her hand. A piece of paper, folded four times, her name written on the outside in handwriting she recognised before she fully processed that she was recognising it.\nEki.\nShe did not open it immediately. She put it inside her pillowcase and went through the morning as though it was not there, which was one of the harder things she had done since arriving, and she had done many hard things. The letter sat inside the pillowcase like a coal, warm and present and requiring nothing from her yet, and she could feel it from across the room.\nShe opened it that evening, sitting on the floor with her back against the bed, the paper spread across her knees.\nEki''s handwriting was small and slanted and moved across the page with the urgent compression of someone who had been given limited paper and unlimited things to say.\nShe had written in the way Eki did everything, directly and without softening. She had found this way to send the letter through a woman in Oredo City who knew someone who knew Sade''s family, a chain of connections so unlikely it felt like something Ivie''s father would have called God''s arrangement if he were still alive to say things like that. The letter had taken six weeks to arrive.\nSix weeks.\nIvie sat with that fact for a moment before continuing.\nOse had started primary school. This information arrived in Eki''s letter with the particular pride of an older sibling reporting on a younger one, pride mixed with the slight exasperation of someone who had helped prepare him for it. He had cried on the first day and then made three friends by the second and had not mentioned crying since. He was already asking questions his teachers did not have answers for, which Eki wrote as a complaint but which Ivie read as a boast.\nEse had passed her Junior WAEC. She was reading for her senior classes and had decided she wanted to study nursing, a decision she had apparently delivered to the household with the finality of someone who had already graduated and was simply informing them of an established fact.\nIvie almost smiled at that.\nThen she read the next paragraph.\nMama was sick.\nNot emergency sick, Eki was careful to clarify, in the specific way of someone who understood that those two words arriving without context in a letter delivered six weeks late could constitute a cruelty. Not hospital sick. But tired in a way that went beyond tired, a fatigue that lived in her bones and showed in her face in the mornings and which the local chemist had given a name to that Eki could not fully spell but which involved the word blood. She was taking something for it. She was still working. She was not complaining because she never complained, but Eki was sixteen years old and had been reading her mother''s face since she was old enough to understand faces, and she was reporting what she saw.\nIvie put the letter down.\nShe pressed the heels of her hands against the floor, feeling the cold hard surface of it, anchoring herself to the room, to the building, to the city outside the window the size of a textbook. She had learned in the past months that certain pieces of information required an immediate physical response, something that told the body where it was before the mind began processing what it had just received.\nFloor. Building. Italy. Her name, Ivie Osagie, still intact.\nShe picked the letter up again.\nEki ended it the way Eki ended everything, without ceremony. She said they were managing. She said Ivie should not worry because worrying from that distance was useless. She said Ose had asked about Ivie last week and she had told him Ivie was working in a big city far away and he had accepted this with the confidence of someone who expected his sister to be exactly that, somewhere important, doing something that mattered.\nThen, in smaller writing at the very bottom, so close to the edge of the paper it was almost off it:\nI am not stupid, Ivie. I do not know exactly what is happening there but something is wrong. You do not have to tell me. Just come back. Come back as yourself. That is all any of us need from you.\nIvie folded the letter. She pressed it flat with her palm. She held it against her chest for a moment, both hands over it, the way Mama had held her hands the night before she left.\nThen she reached under the mattress and found her piece of paper with its rows of marks.\nShe had been counting days. Now she began counting with a different intensity, not as endurance but as calculation. Mama was sick. Ose was in school. Ese had plans. Eki was holding everything together with sixteen year old hands that were not built for the weight they were carrying.\nShe looked at the marks on the paper.\nNot fast enough.\nShe was going to have to find a way to move faster.','\n',char(10)),905,1,1,NULL,'2026-04-15T07:24:56.773Z','2026-04-15 07:24:56','2026-04-15 07:24:56',NULL,2,39);
INSERT INTO "chapters" ("id","novel_id","chapter_number","title","content","word_count","is_premium","is_published","audio_url","published_at","created_at","updated_at","scheduled_release_at","part_number","season_id") VALUES(429,55,7,'Her Own Math',replace('The idea did not arrive dramatically. It arrived the way most useful ideas arrived, quietly, in the middle of something else, while Ivie was watching Aunty Osato count the evening envelopes at the desk in her office, the door left partially open, which was either carelessness or a demonstration that she had nothing to fear from being seen.\nIvie was in the corridor. She was not supposed to be observing but she was observing, the way she had always observed things, with the still, patient attention that her mother called her serious thing and which had served her in every examination she had ever sat.\nAunty Osato counted with speed and satisfaction. One pile for the house. One pile for the notebook, the debt column, each girl''s payment reducing her number by whatever the night had produced. Aunty Osato''s hands moved between the piles with the practiced ease of someone who had been doing this arithmetic for years.\nIvie watched the piles and thought about what Sade had told her in the first week. That Madam counted everything that went into the envelope. That the count was accurate. That Madam had a system and the system had no gaps.\nBut systems built by human beings always had gaps.\nShe had been thinking about this since Episode 4, since she had mapped the rules and found the shape of the cage. And standing in the corridor watching those hands move between two piles, she found the gap she had been looking for.\nAunty Osato counted what went into the envelope. She had no way of counting what never reached the envelope.\nShe spent two weeks testing it before she touched a single coin.\nShe needed to understand the rhythm of the system completely before she moved inside it. How often did the envelopes get collected. Who collected them. Was there a count before the street and a count after, or only after. She watched and listened and asked Sade careful questions wrapped inside other questions, the way you hid important things inside ordinary containers.\nSade answered without asking why she was asking. Sade was perceptive enough to know and careful enough not to say.\nThe envelope was counted once. At the end of the night. By Aunty Osato or by Chidinma, the older woman who ran the building''s daily operations and who had the tired competence of someone serving a sentence they had long ago accepted.\nOnce.\nWhich meant that what happened before the envelope was sealed was outside the count.\nShe started with small amounts. Amounts so small that even if something went wrong, even if Aunty Osato somehow noticed an inconsistency, the number was explainable as rounding, as error, as the ordinary imprecision of a difficult night.\nShe kept the money in a place she had prepared in advance, a small tear in the inner lining of her bag, sealed with three stitches she had unpicked and repicked herself using a needle Precious had given her without comment. The lining was dark and the tear was at the bottom corner and you would have to be specifically looking for something hidden to find it.\nShe was not naive about the risk. She understood it clearly and completely. If Aunty Osato found the money the consequences would be the kind that redefined what consequences meant. She held this knowledge at full size and did not reduce it because reducing it would make her careless and carelessness was not something she could afford.\nBut Eki''s letter lived in the same pillowcase as the paper with its marks. And Mama was sick. And Ose was in school. And Ese had plans that required someone ahead of her to have cleared a road.\nThe risk of staying slow was also a risk. She was simply choosing which one to carry.\nShe kept her ledger in her head. Writing it down would have been a different category of dangerous. Instead she maintained it the way she maintained the inner room, through deliberate and regular attention, visiting the numbers every morning before anything else began, updating them, checking them, running the calculation of how far the hidden amount had grown against how far it needed to go.\nShe called it her second number. The first number was Aunty Osato''s, the debt in the notebook, moving toward zero at the pace the envelope set. The second number was hers, growing in the opposite direction, invisible, accumulating toward a figure she had decided on after long calculation.\nThe figure was what she would need to get from this building to somewhere she could begin.\nNot to Ovia. Not yet. She could not arrive home with nothing and give Mama a returned daughter instead of the changed circumstances that were the whole point of leaving. She needed enough to land somewhere, establish something, send money home before she came home herself.\nShe ran the numbers nightly. The first number going down. The second number going up. Two calculations running in parallel, one for Aunty Osato, one for herself, and the day they crossed each other would be the day everything changed.\nThe marks on her paper were no longer just endurance.\nThey were a countdown.','\n',char(10)),867,1,1,NULL,'2026-04-15T07:25:56.392Z','2026-04-15 07:25:56','2026-04-15 07:25:56',NULL,2,39);
INSERT INTO "chapters" ("id","novel_id","chapter_number","title","content","word_count","is_premium","is_published","audio_url","published_at","created_at","updated_at","scheduled_release_at","part_number","season_id") VALUES(430,55,8,'The Last Night',replace('She had known the day was coming for eleven weeks.\nThat was when the first number had crossed the threshold of what one final large envelope could clear, when the arithmetic she had been running every morning finally produced a result that meant something was ending. She had sat with that knowledge for eleven weeks without changing her face, without telling anyone except Sade, who had received the information with a long look and a single nod and had not mentioned it again.\nTonight was the night.\nShe had prepared the envelope herself, counting the notes with the same careful attention she had given everything in this building, every rule, every rhythm, every gap. The amount was exact. She had checked it four times. She had checked it a fifth time because this was not a moment for almost.\nSade sat on the edge of the bed and watched her count.\n"You are sure about the number," Sade said.\n"I have been sure about the number for eleven weeks."\n"She will not simply accept it and open the door."\nIvie folded the envelope. "I know."\n"She will say there are additional fees. Processing. Interest. Something she forgot to mention the first time." Sade''s voice was level, carrying the weight of someone who had watched this moment before with a different girl and a different outcome. "She has done it before."\nIvie looked at her. "What happened to that girl?"\nSade looked at the wall. "She believed the new number."\nIvie put the envelope in her pocket. "I will not believe a new number."\nAunty Osato''s office was lit by the same bare bulb that had been burning the night Ivie first sat across that desk and felt the floor disappear. The room had not changed. The desk, the two chairs, the notebook. Aunty Osato in her seat with the settled ease of a woman who had been in charge of this particular space for long enough that the room had taken her shape.\nIvie sat down and placed the envelope on the desk.\nAunty Osato looked at it without touching it.\n"You are counting," she said. It was not a question.\n"I have always been counting," Ivie said.\nAunty Osato picked up the envelope. She opened it and counted with her usual speed, her fingers moving through the notes with the practiced efficiency of someone for whom money was first a language and second everything else. When she finished she set the notes down and looked at them for a moment.\nThen she opened the notebook.\nShe paged to Ivie''s entry, found the column, ran her finger down the figures. The silence in the room had a texture. Ivie kept her hands flat on her thighs, a habit she had developed in this chair on the very first day, and she breathed slowly and waited.\nAunty Osato looked up.\n"There is the matter of interest," she said. "Money held over time accumulates interest. This is how financial arrangements work."\nIvie had been waiting for this sentence. She had rehearsed her response to it so many times that it arrived now without effort, clean and exact.\n"That was not part of the arrangement you described when you told me the number," she said. "You said the number. You said when it reached zero I would have my passport and I would be free to go. Those were your exact words."\n"Arrangements evolve."\n"This one does not."\nAunty Osato looked at her steadily. Ivie looked back. This was the moment Sade had warned her about and she was inside it now and the only navigable path through it was the one she had mapped in advance: stay on the original terms, do not accept a new number, do not let the silence pressure her into filling it with concession.\nShe waited.\nAunty Osato tapped the notebook with one finger. "You have become difficult."\n"I have become precise," Ivie said. "There is a difference."\nSomething moved across Aunty Osato''s face. Too quick to name. She looked down at the notebook again, at the column, at the figure at the bottom that was no longer what it had been when Ivie first saw it.\nThe silence stretched.\nThen Aunty Osato closed the notebook.\nShe opened the desk drawer and placed inside it the envelope and its contents. Then she reached into the same drawer and produced a navy blue document that she set on the desk between them.\nIvie looked at her own face looking back at her from the photograph.\nShe did not reach for it immediately. She looked at it for one full breath, this small document she had processed in a government office in Oredo City with Mama standing beside her, this thing that had been taken from her in a hallway while she was still believing in the version of the story that had brought her here.\nShe picked it up.\nIt was exactly as she remembered. Her name. Her photograph. The words she had read the night it arrived, standing in the Ovia dark.\n"You may go in the morning," Aunty Osato said. Her voice had returned to its usual register, even and administrative, as though the last five minutes had been a routine transaction now satisfactorily concluded.\nIvie stood.\nShe did not say thank you. She had thought about whether she would and had decided she would not, not because she was angry, though she was, but because thank you implied a debt of a different kind and she was finished with Aunty Osato''s debts entirely.\nShe walked to the door.\n"Ivie."\nShe stopped but did not turn.\n"You are a serious girl," Aunty Osato said. "You were always going to survive this."\nIvie walked out.','\n',char(10)),958,1,1,NULL,'2026-04-15T07:26:55.275Z','2026-04-15 07:26:55','2026-04-15 07:26:55',NULL,2,39);
INSERT INTO "chapters" ("id","novel_id","chapter_number","title","content","word_count","is_premium","is_published","audio_url","published_at","created_at","updated_at","scheduled_release_at","part_number","season_id") VALUES(431,55,9,'Out',replace('She left before the building woke up.\nNot because she was afraid of goodbyes exactly, but because she understood that goodbyes in a place like this had a weight that could slow your feet at the exact moment your feet needed to be moving. She had said what needed saying the night before, sitting in the kitchen with Sade and Precious and Amara, the four of them around the small table in the particular quiet of people who had run out of ordinary conversation and were simply choosing to be in the same room one last time.\nSade had given her the name of a Nigerian woman in a part of the city called Torpignattara, a woman who ran a legitimate hair braiding shop and who had helped other girls find their footing after leaving. She pressed the address into Ivie''s hand on a piece of paper torn from a magazine margin and said, "She will not turn you away. Tell her Sade sent you."\nPrecious had given her a scarf, thick and dark blue, without explanation.\nAmara had said something in French and then translated it herself, quietly: "The road knows the feet that are ready."\nIvie had held each of these things carefully and put them where they belonged.\nThe door of the building opened without resistance. That surprised her. She had half expected it to resist, to require some final negotiation, as though the building itself had become an extension of the system that had held her. But it opened like any door opened, simply, at the turn of a handle, and the cold came in immediately and completely.\nJanuary. Still. The street outside was the dark blue of four in the morning, that particular hour when night had not yet agreed to become day and the city was at its most honest, stripped of the performance it put on for daylight. The street lamps threw orange pools on the pavement. A cat crossed the road at the far end with the unhurried authority of something that owned the hour.\nIvie stepped outside and the door closed behind her.\nShe stood on the pavement and breathed.\nThe cold entered her lungs and she let it, feeling its clean specific reality, the fact of outside air that had nothing to do with that building or that desk or that notebook or that bare bulb. She was standing on a street in a city in a country whose language she had been learning in fragments for months and whose geography she had been mapping from a building she was no longer inside.\nShe turned left because left was the direction of the main road and the main road was the direction of the rest of the city and the rest of the city was the direction of everything that came next.\nShe was terrified.\nShe had known she would be and she was, in the specific way she had prepared for, a fear that was not paralysing but present, running alongside her like a second person matching her stride for stride. Her bag was on her back, everything she owned inside it, which was not much but was entirely hers. The passport was in the inside pocket, against her body, which was where it would remain until she was somewhere she had chosen to be.\nThe second number was in the bag lining. Weeks of careful accumulation, enough to begin with. Not enough for certainty, but she had learned in this city that certainty was not on offer and you moved anyway.\nShe walked.\nThe streets were not empty. A city this size was never empty, even at this hour. A man was rolling a cart of something along the opposite pavement. Two people were talking outside a building with their breath making clouds. A bus passed with a few passengers visible through its lit windows, ordinary people going somewhere at four in the morning for ordinary reasons.\nIvie walked among them and nobody looked at her with any particular attention and this was so different from the street she had been walking for months, where being looked at was the entire point and the entire transaction, that she felt something loosen in her chest. Just a pedestrian. Just a person going somewhere. Just a girl from Ovia with a bag on her back and an address in her hand and everything still to build.\nThe fear was real. She was alone in a foreign city in the dark with limited money and no confirmed plan beyond a name on a piece of torn paper. She held this reality at its full size and did not reduce it. She had learned that reducing things did not make them smaller, it only made you less prepared.\nBut underneath the fear, deeper and steadier, was something else. She had been searching for the word for it since the door closed behind her and she had finally found it.\nSpace. The feeling of space, of being outside a container, of moving in a direction she had chosen because she had chosen it and for no other reason.\nShe pulled the dark blue scarf tighter around her neck.\nThe sky ahead was beginning to suggest, very faintly, that it was considering becoming something other than night.\nIvie walked toward it.','\n',char(10)),887,1,1,NULL,'2026-04-15T07:27:58.552Z','2026-04-15 07:27:58','2026-04-15 07:27:58',NULL,2,39);
INSERT INTO "chapters" ("id","novel_id","chapter_number","title","content","word_count","is_premium","is_published","audio_url","published_at","created_at","updated_at","scheduled_release_at","part_number","season_id") VALUES(432,56,1,'New York, Alone',replace('The woman at the hair braiding shop in Torpignattara had looked at Ivie for a long moment when she arrived, taken in the bag on her back and the dark blue scarf and the specific exhaustion that was not tiredness but the aftermath of sustained endurance, and said simply, "Sade sent you."\n"Yes."\n"Sit down. You have eaten today?"\nThat was six months ago. The woman''s name was Mama Efe and she had given Ivie a cot in the back of the shop and work that was legal and paid and required nothing from her body except her hands and her time, which felt like extraordinary luxury. Ivie had braided hair and saved money and learned more Italian and sent the first wire transfer home, watching Mama Florence''s name on the receipt with a feeling she could not fully describe, the particular relief of a promise beginning to be kept.\nBut Italy still had Aunty Osato in it. In a different part of the city, behind a gate Ivie never had to approach again, but present. A fact in the atmosphere.\nMama Efe had a cousin in New York.\nThat was how it happened.\n\nJohn F. Kennedy Airport received her the way large American airports received everyone: with scale and noise and the immediate impression that the building had not been designed for human beings specifically but for the idea of human movement in the abstract. Ivie walked through it with her bag and her documents and the address of Mama Efe''s cousin written on a paper in her pocket and she kept moving because moving was still the clearest instruction she knew how to follow.\nOutside the terminal the cold was a different quality from Italy''s cold. Denser. More decided. The kind of cold that did not negotiate. The sky above the taxi rank was a low white that pressed down on everything with the impersonal authority of a city that had been enormous for so long it had forgotten what it was like to be anything else.\nA taxi. An address. A borough called the Bronx, which she had heard of only as a name.\nShe pressed her face to the window and watched New York arrive.\n\nMama Efe''s cousin was a woman named Auntie Bisi, Yoruba, fifty years old, direct in the manner of someone who had long ago decided that life was too short for the long way around anything. She had a two bedroom apartment on a street that was loud in a way that felt purposeful, as though the street had decided noise was its particular contribution and was committed to it.\nShe showed Ivie the small room, the bathroom, the kitchen, and the rules of the apartment in approximately ten minutes, and the rules were reasonable and the room had a window that was a real window, large enough to show a proper piece of sky.\nIvie stood at it for a while after Auntie Bisi left her to settle.\nNew York was outside it, going about its business with staggering indifference. Traffic. People. A bodega across the street with a light in its window that had probably been on for years without anyone deciding it was remarkable. Somewhere below, two people were arguing in Spanish and a child was laughing at something unrelated to the argument.\nOrdinary life. Just ordinary life, happening in all directions.\n\nThe first week she could not sleep past four in the morning.\nHer body had been calibrated to that hour, to rising and beginning the mathematics of the day, to the building''s sounds and rhythms and requirements. Now there were no requirements. The room was quiet and the apartment was quiet and New York was never quiet but its noise was outside and indifferent and not directed at her.\nShe would lie in the dark at four in the morning and feel the absence of the structure that had held her for two years, and the absence had a physical quality, like a bandage removed from a healed wound, the skin underneath tender and new and strange in the open air.\nDuring the days she helped Auntie Bisi, who sold food from a stall at a weekend market and needed someone who could count change quickly and manage a queue without losing composure. Both of these things Ivie could do. She did them and earned something and put it away and walked back to the apartment through Bronx streets that were slowly becoming familiar, one landmark at a time.\nShe called home on a Thursday from Auntie Bisi''s phone. Mama''s voice arrived across the distance sounding like itself, like the kitchen and the lamp and every morning she had woken up in that house, and Ivie held the phone with both hands and said she was fine, she was working, the money was coming, and did not say anything else because there was not a language yet for everything else.\n"Your voice sounds different," Mama said.\n"I am just tired," Ivie said. "Good tired."\nMama was quiet for a moment. "Come home soon," she said softly.\n"I will," Ivie said. "When I have something to bring with me."\nShe hung up and sat for a long time in the room with the real window, watching the sky outside go from afternoon to evening.\nShe was not broken. She had checked regularly and she was not broken.\nBut she was not yet whole either, and she was beginning to understand that whole was not something you returned to. It was something you built. From here. From this room. From this city that did not know her name and did not need to yet.\nShe had built things before under worse conditions.\nShe went to help Auntie Bisi with dinner. That night she lay in the dark of the room with the real window and waited for four o''clock to arrive, because four o''clock always arrived, her body had been set to it for two years like an alarm she had not asked for. It arrived and she was awake for it and outside New York was doing whatever New York did at four in the morning, which was apparently everything, and she lay there and thought about the fact that nobody in this city knew where she was. Not Aunty Osato. Not the building. Not the street. Not the envelope system, not Chidinma, not the rules. She was in a room that nobody with bad intentions could find her in and the city outside did not know her name and for reasons she could not fully explain both of those things were exactly the same relief.','\n',char(10)),1108,0,1,NULL,'2026-04-30 09:23:33','2026-04-15 07:32:26','2026-04-30 09:23:33',NULL,3,40);
INSERT INTO "chapters" ("id","novel_id","chapter_number","title","content","word_count","is_premium","is_published","audio_url","published_at","created_at","updated_at","scheduled_release_at","part_number","season_id") VALUES(433,56,2,'Small Work, Big Quiet',replace('Season 3, Episode 2 — "Small Work, Big Quiet"\nThe Saturday market arrived every week with the energy of something that had decided to exist fully or not at all.\nAuntie Bisi''s stall occupied the same twelve feet of pavement it had occupied for six years, between a Ghanaian man who sold fabric and a Puerto Rican woman named Carmen who sold jewellery and had strong opinions about everything, which she delivered in a combination of Spanish and English that somehow communicated precisely regardless of which language carried the sentence. Auntie Bisi sold jollof rice, moin moin, and puff puff, in quantities that required Ivie to start chopping at six in the morning if they were going to be ready for the first customers at ten.\nIvie learned to chop at the speed the market required. She learned to manage a queue with four people talking simultaneously, to give change without looking at her hands, to smile at the right moments and be efficient at the moments that required efficiency and read which was which from context alone. These were not small skills. She had learned harder things. But she was also discovering that competence in an ordinary task, freely offered and freely received, produced a satisfaction that had nothing to do with the size of the task.\nOn her third Saturday a boy of about eight stood in front of the stall and looked at the puff puff with the focused longing of someone conducting a negotiation with themselves about whether they could afford the thing they wanted.\nIvie put one in a napkin and handed it across.\nHe looked at her. She nodded once. He took it and left at speed, which was the correct response.\nAuntie Bisi, who had been watching, said nothing. But the look she gave Ivie had something in it that landed in the vicinity of approval.\nThe room at Miss Hyacinth''s house came through a woman at the market, a customer named Mrs. Okonkwo who ate Auntie Bisi''s jollof with the satisfaction of a person eating something they had been looking forward to all week and who talked while she ate in a way that produced a surprising amount of useful information.\nIvie went to see it on a Wednesday after the lunch shift. The house was two streets from the market, the room on the second floor overlooking a yard where someone had planted a garden that had partially succeeded and was apparently at peace with partial success. The window was large. The radiator worked. The curtain was slightly too short for the window.\nMiss Hyacinth showed her the room and the shared bathroom and the kitchen and looked at her at the front door with the frank evaluation of a woman who had rented to enough people to have developed instincts worth trusting.\n"You are a worker," she said. Not a question.\n"Yes," Ivie said.\n"You will not be trouble."\n"No."\nMiss Hyacinth stepped aside. "First month in advance. The curtain I will replace when I find the right length."\nIvie paid from the amount she had carried since Italy. She sat on the edge of the bed when Miss Hyacinth left and looked at the slightly too short curtain and the yard below and the particular quality of light coming through a window she had chosen to stand at.\nShe exhaled.\nIt was a long exhale. It had been building for approximately two years.\nWhat she had not budgeted for was the noise that safety made when it arrived.\nShe had imagined it as quiet, as the absence of the things that had pressed against her in Italy. And it was quiet in that way. But it was also something louder underneath the quiet, a constant low frequency that she eventually identified as the sound of her own life making decisions without first calculating the cost of the decision.\nShe was hungry, so she ate. She was tired, so she slept. She was cold, so she wore the coat. These were not calculations. They were just things she did because her body told her to and her body was speaking again in the honest uncomplicated language of a body that belonged to the person living inside it.\nShe lay in the narrow bed one night in the third week and listened to Miss Hyacinth''s house settling around her and the street outside offering its routine inventory of sounds and she understood that this, the radiator and the too short curtain and the jollof rice at six in the morning and the boy who took the puff puff at speed, this was not the waiting room for her life.\nThis was her life.\nShe called Mama on Sunday from a phone she had bought with her third week''s wages. She sat on the floor of the room with her back against the bed and dialled and listened to the ringing cross an ocean and a continent and all the distance she had put between herself and the house in Ovia.\nMama picked up on the fourth ring.\n"Ivie."\nJust her name. Just the way Mama said her name, with the specific weight of a woman saying the name of someone she had been holding in her chest for a long time.\n"Mama," Ivie said. "I am okay. I am properly okay." Mama was quiet for a moment. Then she said, "Eki wants to know if you are coming for Christmas." Ivie closed her eyes. The radiator clicked. The too short curtain moved slightly in the draft from the window. "Tell her I am working on it," she said. "Tell her I am working on everything." She hung up and sat on the floor of the room for a long time. She was okay. She was properly okay. And being okay was not the end of anything. It was the first requirement for what came next, and what came next was still the whole original thing: Mama''s house, Eki''s hands holding what was too heavy for them, Ose growing up with someone ahead of him who had cleared a road. She had been surviving. She had not yet started. She stood up. She had an early shift.','\n',char(10)),1035,0,1,NULL,'2026-04-30 09:14:29','2026-04-15 07:33:29','2026-04-30 09:14:29',NULL,3,40);
INSERT INTO "chapters" ("id","novel_id","chapter_number","title","content","word_count","is_premium","is_published","audio_url","published_at","created_at","updated_at","scheduled_release_at","part_number","season_id") VALUES(434,56,3,'Tunde',replace('He came into Mama''s Table on a Tuesday, which was the wrong day to come in if you wanted the full experience and the right day if you wanted to actually get a table and have someone pay attention to you.\nIvie was at the front of house, which she had by now inherited completely from Mr. Fashola, who had decided that his time was better spent arguing with suppliers than managing the dining room. She handed the man a menu without looking up from the reservation book.\n"We have the egusi and the pepper soup today," she said. "The ofe akwu is finished."\n"I have been coming here for two years," the man said pleasantly. "I know what you have."\nShe looked up.\nHe was tall, Yoruba by the look of him, her age or close to it, with the kind of face that was not immediately remarkable and then, a moment later, entirely was. He was smiling in the way of someone who found the situation genuinely amusing rather than someone performing amusement to be charming. There was a difference and she had become very good at identifying it.\n"Then you do not need the menu," she said, and took it back.\nHe laughed. A real laugh, surprised out of him. He sat down.\nHis name, she learned from the reservation he made the following Tuesday and the Tuesday after that, was Tunde Adewale. He was from Lagos originally, Surulere, and had been in New York for four years studying and then working in something involving urban planning that he explained once at length and which she had listened to with genuine interest and then retained only the shape of, which was that he cared about how cities were built and who they were built for.\nHe came in every Tuesday. He always sat in her section.\nShe noticed him noticing her and said nothing about it for six weeks.\nThis was not coyness. It was assessment. She had learned in the past two years to take the full measure of a situation before she moved inside it, to identify what was being offered and what was actually on the table and whether the distance between those two things was navigable. She had learned this in a building in Italy and she applied it everywhere now, not with fear but with the precision of someone who had paid a high price for carelessness and did not intend to pay it again.\nWhat she assessed over those six weeks: he was consistent without being persistent. He came on Tuesdays and was pleasant and left reasonable tips and did not push for anything beyond conversation when conversation was available. He asked her questions and listened to the answers and did not use the answers as launching pads for talking about himself. He told her about Lagos without nostalgia, clearly and with the perspective of someone who had left something he loved and was still in the process of understanding what it meant to love a place and live somewhere else.\nHe reminded her, occasionally, of Kachi.\nNot in his face or his manner exactly. In the quality of his attention. The way it was full without being pressuring.\nShe noted this and filed it and kept assessing.\nThe Tuesday she allowed the conversation to become something more was a Tuesday in March when the restaurant was quiet and she was tired in a way that had loosened something in her, the way fatigue sometimes removed the energy required to maintain distance.\nHe asked her where she was from and she said Midwest State and he said he did not know it well and she said most people did not and he said tell me about it.\nSo she told him about Ovia. Not everything. The shape of it, the red dust roads, the market on Saturday mornings, the way the town felt temporary without ever actually changing. She told him about her father''s laugh, which she still missed more than his face. She told him about her siblings, Eki and Ese and Ose, and the way she described them made him smile in the way of someone who recognised the particular love that could only exist between siblings who had shared a difficult house.\nHe listened without interrupting.\nWhen she finished he said, "You are the one who left to change things."\n"Yes."\n"That is a heavy thing to carry."\nNobody had said that to her before. Not in those words. She looked at him and he was not performing sympathy, he was just stating what he saw, clearly and without flinching.\n"It is," she said.\nThey sat with that for a moment.\nThen the kitchen bell rang and she stood and went to collect the order from the pass and when she came back he was still there and the conversation, without either of them deciding anything, had become the kind that did not fully end when you walked away from it.\nShe did not let him walk her home for another three weeks.\nShe allowed the walk because she had finished assessing and the assessment had produced the same result enough times in a row to be reliable. Not because she trusted him completely. Trust was not something she was capable of dispensing completely yet and she had accepted this about herself as a current condition rather than a permanent state.\nBut she trusted him enough. For a walk. For a conversation that continued outside the restaurant and along streets she now knew well enough to navigate without thinking.\nAt her door she said goodnight and he said goodnight and he did not ask for anything further, which was either natural decency or very good strategy, and she had decided it did not matter which one it was because the outcome was the same and the outcome was the only thing she was currently in a position to evaluate.\nShe went inside.\nAt the window with the slightly too short curtain she watched him walk back down the street until he turned the corner.\nShe stood there a moment longer.\nShe went inside. She sat at the small table in her room and looked at nothing for a while. Then she took out a piece of paper and wrote three things at the top: his name, the street she worked on, the name of Auntie Bisi''s building. She looked at these three things for a moment, then folded the paper and put it under the mattress, which was where she kept things she was not ready to do anything with yet but was not ready to stop holding either. She went to bed. She did not sleep for a long time. That was also information.','\n',char(10)),1127,0,1,NULL,'2026-04-30 09:16:10','2026-04-15 07:34:24','2026-04-30 09:16:10',NULL,3,40);
INSERT INTO "chapters" ("id","novel_id","chapter_number","title","content","word_count","is_premium","is_published","audio_url","published_at","created_at","updated_at","scheduled_release_at","part_number","season_id") VALUES(435,56,4,'What I Have to Tell You',replace('She had rehearsed it three times and abandoned the rehearsal each time because the rehearsed version kept coming out shaped wrong, too organized, too much like a presentation of a thing rather than the thing itself.\nIn the end she decided to simply begin and let it find its own shape.\nThey were in a park near her street, a Sunday in April when New York had finally agreed to become warm, sitting on a bench with the remains of the food they had bought from a jollof rice takeout place Tunde had strong opinions about. The afternoon was easy and unhurried. Children were somewhere nearby being loud about something that made them happy. The sky was the particular blue that only existed on the best days of late spring.\nShe had chosen today. She had known since Thursday that it would be today.\n"There are things about how I got here," she said, "that I have not told you."\nHe looked at her. He did not say you don''t have to or only if you want to or any of the other things people said when they were afraid of what was coming. He simply looked at her with his full attention, which was what she had needed him to do, and waited.\nSo she told him.\nShe told him about Ovia and her father''s grave and the promise she had made to the name in the concrete. She told him about Aunty Osato''s flat in Oredo City and the photographs on the wall and the leather sofa and the way wealth could look, from outside, like a door. She told him about the deal, the passport, the flight, the cold coming in through the airport doors.\nShe told him about the hallway where Aunty Osato held out her hand.\nShe told him about the courtyard and the girls calling her Madam and the number in the notebook and what the number meant and what the work was that would reduce it. She told him about Sade and Precious and Amara. She told him about the room inside herself that she had built and furnished and maintained like a structure that was keeping something alive.\nShe told him about Eki''s letter and Mama''s tiredness and the marks on the paper and the second number growing in the bag lining. She told him about the last night in the office and her passport returned across a desk and the door of the building opening at four in the morning onto a street that was entirely hers to walk.\nShe told him all of it. Not performing it, not compressing it into something more manageable than it was, not protecting him from the weight of it. He had asked, in his own way, by being the kind of person she had assessed for months and found consistently, reliably, honest. She gave him the honest version.\nShe did not look at him while she spoke. She looked at the park, at the children and the blue sky and the ordinary Sunday afternoon arranged around them like a setting for something that deserved a setting.\nWhen she finished she sat in the quiet for a moment.\nThen she looked at him.\nHis face was doing something she could not immediately name. Not pity. She had braced for pity and would have known how to manage it, would have straightened and told him she did not need it. Not shock exactly either, though he was not pretending the information had not landed. Something more precise than either of those things.\nHe was looking at her the way you looked at something you were trying to understand fully before you responded to it, taking the whole of it in, not reaching for the nearest available reaction.\nHe was quiet for long enough that a less steady version of herself might have filled the silence. She let it stand.\nThen he said, "How old were you when you walked out of that building."\n"Eighteen."\nHe nodded slowly. "And you managed the whole thing. Every part of it. Alone."\n"I had the other girls. Sade, mostly."\n"You were sixteen when you got on that plane," he said. "Sixteen and you had seven distinctions and a plan to change your family''s story and a woman you trusted to show you the way." He paused. "She used every true thing about you against you."\nIvie looked at him.\n"That is what I want you to hear," he said quietly. "Not what happened. But that it happened because you were exactly who you should have been. Ambitious and trusting and ready to sacrifice for the people you loved. She looked for those things specifically. You were not naive. You were targeted."\nThe afternoon kept going around them, entirely indifferent, children and sky and the distant noise of the city.\nIvie felt something shift. Not break. Not collapse. Shift, the way a load shifted when someone placed their hand under part of it, not removing it, just redistributing the weight so that the carrying became something your body could sustain.\nShe had known this, intellectually. She had assembled it herself in the quiet of the small room in Mama Efe''s shop, in the dark of four in the morning. But there was a difference between a truth you held alone and a truth that was spoken back to you by someone who had heard the whole story and arrived at it themselves.\nHer eyes filled. She did not stop them.\nHe did not move toward her immediately and she was grateful for that too, for the beat he gave her, the dignity of a moment to feel the thing without being rescued from it. Then he reached over and covered her hand with his. Just that. Steady and present and requiring nothing back.\n"Thank you for telling me," he said.\nShe looked down at his hand on hers.\n"I did not know if I could," she said.\n"I know." A pause. "I am not going anywhere, Ivie."\nShe did not answer. She did not need to. She turned her hand over and held his and they sat in the park while the afternoon went about its business around them, the city enormous and indifferent and occasionally, unexpectedly, capable of this.','\n',char(10)),1049,1,1,NULL,'2026-04-15T07:35:42.990Z','2026-04-15 07:35:43','2026-04-15 07:35:43',NULL,3,40);
INSERT INTO "chapters" ("id","novel_id","chapter_number","title","content","word_count","is_premium","is_published","audio_url","published_at","created_at","updated_at","scheduled_release_at","part_number","season_id") VALUES(436,56,5,'The Arrest',replace('She found out on a Wednesday morning from a WhatsApp group she had never joined intentionally.\nAuntie Bisi had added her to a group called Naija New York Connect sometime in her first month in the Bronx, a group that functioned primarily as a delivery system for food vendor announcements, church event flyers, and news from home that arrived in fragments, half verified, passed between people who knew someone who knew someone. Ivie kept the notifications off and checked it occasionally when she had the patience for it.\nThat Wednesday she opened it while the kettle was boiling and read seventeen messages before she understood what she was reading.\nA name. Her name. Aunty Osato Eguasa, Midwest State. Arrested. Italy. Trafficking. Jailed.\nShe put the phone down on the kitchen counter and stood very still.\nThe kettle finished boiling and clicked off and the kitchen went quiet.\nShe read the full story later, on a proper news website that a member of the group had posted, a Nigerian outlet that had picked up the Italian report. The details arrived one paragraph at a time and she absorbed each one with the careful attention she gave to things that required her full presence.\nAunty Osato had been operating for eleven years. Three buildings in the city. Forty three girls across that period, the number the investigators had confirmed, though the reporter noted the actual figure was likely higher. The arrest had come after a two year investigation involving Italian authorities and an international anti trafficking organisation. Two other women had been arrested alongside her, women whose names Ivie did not recognise, who had operated buildings she had never been inside.\nThe sentence was twelve years.\nIvie read the number and sat with it.\nTwelve years. Aunty Osato, who had moved through her own flat in Oredo City like a woman gravity had decided to accommodate rather than constrain. Who had listened to Ivie talk about her Literature teacher and her father''s cousin and her WAEC results. Who had held out her hand in a hallway in a voice so reasonable it had dismantled all available suspicion. Twelve years in a room she had not chosen, without a passport in her possession, which was the kind of detail that only meant something if you had lived its inversion.\nShe did not feel what she had expected to feel.\nShe had imagined this moment before, in the abstract, in the way you sometimes imagined the resolution of something while you were still inside it, as a way of maintaining the belief that resolution was possible. In those imaginings the feeling had been clean. Satisfaction, or relief, or the particular closure of a door being permanently shut.\nThe actual feeling was neither clean nor singular.\nThere was relief. She found it after a moment, real and solid underneath everything else. The knowledge that Aunty Osato was not in that building, not standing in that courtyard, not opening the desk drawer. That forty three confirmed girls, and the ones the number had not caught, would not be preceded by more. The relief was genuine and she gave it its full weight.\nBut underneath the relief, and alongside it, and woven through it in ways she could not fully separate, was something she had not budgeted for.\nGrief.\nNot for Aunty Osato. She examined this carefully and confirmed it was not for Aunty Osato. It was older than that. It was grief for the woman she had believed Aunty Osato to be, the woman she had constructed from a leather sofa and photographs on a wall and a sentence said across a dining table in Oredo City. That woman had not existed. But Ivie had loved her, in the way a sixteen year old loved the first person who looked at her and said this one has sense, and the grief was for the loving rather than the person who had received it.\nAnd underneath that grief, deeper still, was something she had no word for, the particular sorrow of being a person whose story included this chapter, who would carry the weight of those two years not as something that had happened to her but as something that was now part of the permanent architecture of who she was.\nShe sat with all of it without trying to reorganise it into something more manageable.\nShe called Sade that evening through a number she had held for a long time without using. Sade was in London now, had been for eight months. Her voice across the line was the same, direct and warm and carrying the specific knowledge of someone who had been in the same building and breathed the same impossible air.\n"I saw," Sade said, before Ivie finished her first sentence.\n"How do you feel," Ivie asked.\nA pause. "Like it is not enough and also like it is something. Both at the same time."\n"Yes," Ivie said. "That is exactly it."\nThey stayed on the line for a while without speaking, which was its own kind of conversation, two people holding the same complicated thing from different cities and finding that the distance between them did not diminish the holding.\n"Precious knows?" Ivie asked eventually.\n"I called her this morning. She cried and then she laughed and then she cried again."\nIvie nodded. "That sounds right."\n"Are you okay?" Sade asked.\nIvie looked around her room. The slightly too short curtain. The radiator. The window with its piece of New York sky, going dark now with the evening.\n"I am not not okay," she said carefully.\n"That is also something," Sade said. They were quiet again. Then Sade said, "There is a woman. A lawyer, here in London. She works with the organisation that brought the case. She has been calling girls who got out, asking if they will give statements. I said I would think about it." Ivie held the phone. The room around her was very still. "What kind of statement," she said. "Formal. For the record." A pause. "I know it is a lot to ask." Ivie looked at the window. The New York evening outside it. Everything she had built on this side of that building. "Give me her number," she said. "I am not promising anything. Just give me the number."','\n',char(10)),1053,1,1,NULL,'2026-04-30 09:21:10','2026-04-15 07:36:38','2026-04-30 09:21:10',NULL,3,40);
INSERT INTO "chapters" ("id","novel_id","chapter_number","title","content","word_count","is_premium","is_published","audio_url","published_at","created_at","updated_at","scheduled_release_at","part_number","season_id") VALUES(437,56,6,'School Again',replace('The enrollment form asked for a lot of things she had and one thing she had been afraid to want.\nName. Date of birth. Previous qualifications. Emergency contact. These she filled in with the careful handwriting she had maintained through everything, the same handwriting that had answered WAEC questions in an examination hall in Midwest State eight years ago while she was still a girl who believed that clearing her O-levels was the beginning of a straight road forward.\nThe last question was the one that had kept her sitting outside the admissions office of the community college for twenty minutes before she walked in. Intended area of study.\nShe had written: Public Health.\nThen she had looked at it for a moment, at those two words in her own handwriting, and felt something so large move through her that she had to press her feet flat against the floor to stay level.\nThe idea had arrived gradually, the way the best ideas arrived, not as a decision but as a recognition of something that had been true for longer than she had been paying attention.\nShe had spent two years in a building watching what happened to girls whose bodies were managed by someone else''s system. She had watched what happened when you had no information, no language for your rights, no access to the people or institutions that might have helped if you could have reached them. She had watched illness move through that building without proper treatment because treatment required exposure and exposure was the one thing none of them could risk.\nShe had thought about Mama''s sickness, the word the Ovia chemist had given it that Eki could not fully spell, the word that involved blood, the kind of tiredness that lived in bones. She had sent money home and the money had helped but she had also felt, in sending it, the limitation of money as the only tool available. What she wanted to understand was the system behind the illness, the prevention behind the cure.\nPublic health was the study of why people got sick and how communities could be built so that fewer of them did. She had read this in a leaflet at a clinic she had visited in her first year in New York and the sentence had stayed in her.\nIt sounded like something worth building a classroom around.\nShe was twenty four years old and she was the oldest person in her Introduction to Biology class by six years.\nShe had known this would be the case and had prepared a version of herself that could sit in a room full of eighteen year olds without feeling the distance too sharply. What she had not prepared for was how quickly the distance became irrelevant.\nThe moment the lecturer began, she stopped being twenty four and started being simply a person in a room where someone was explaining something worth understanding. Her pen moved across her notebook. She asked a question in the third week that made the lecturer pause and then nod slowly and say that was a very good question in a tone that meant it genuinely was. A girl beside her leaned over afterward and asked if she could look at Ivie''s notes.\nShe recognised this. The specific electricity of a classroom where the material was real. Mr. Idehen reading Literature passages like personal letters. Herself at a desk in Ovia, the textbook open, the world narrowed down to the problem in front of her and the tools she had to solve it.\nShe had thought that version of herself was a girl. She was discovering it was not a phase of her life but a feature of her character, permanent and portable, surviving everything that had tried to reduce her.\nTunde brought her a set of highlighters the evening before her first examination, holding them out with the straightforward practicality of someone who expressed care in useful objects rather than large declarations. She took them and he sat at the small table in her room and read while she revised, the two of them in the quiet of a weeknight with their separate materials and the radiator doing its clicking and the city outside going about its business.\nShe looked up at him once, midway through a chapter on epidemiology and disease prevention, and he was reading with the focused stillness she had come to know well, entirely present in whatever he was inside.\nShe looked back at her notes.\nThis was also something she had not known to expect. That ordinary evenings could feel like this, like a life assembled from chosen pieces fitting together in a way that was not dramatic or cinematic but was real and load bearing and quietly extraordinary.\nShe passed the examination with the highest mark in the class.\nShe did not tell anyone except Tunde and, in a phone call that Sunday, Mama, whose voice on hearing the news did something complicated that Ivie held carefully and did not rush past.\n"Raymond would have talked about this for a week," Mama said.\n"I know," Ivie said.\nShe was smiling. She felt it on her own face and recognised it as the real kind, the kind that came from somewhere internal rather than somewhere performed.\nShe was in school. She was twenty four years old and she was in school and outside the window of the classroom the city went about its enormous business and in Ovia her mother was still in a house with a roof that leaked when it rained. She wrote the last answer in the examination and put her pen down and looked at the paper, at her own handwriting covering it, and thought about all the years between the last examination she had sat in Midwest State and this one. Everything that had happened in those years. Everything she had paid to be sitting in this chair at this desk in this city on this afternoon. Then she stood up and handed in her paper. Whatever the mark was, she had sat the examination. Everything else was secondary.','\n',char(10)),1023,1,1,NULL,'2026-04-30 09:21:57','2026-04-15 20:27:14','2026-04-30 09:21:57',NULL,3,40);
INSERT INTO "chapters" ("id","novel_id","chapter_number","title","content","word_count","is_premium","is_published","audio_url","published_at","created_at","updated_at","scheduled_release_at","part_number","season_id") VALUES(438,56,7,'Everything She Built',replace('The apartment was on the fourth floor of a building in Brooklyn, and in the mornings the light came through the living room window at an angle that made everything it touched look considered, like someone had arranged it on purpose.\nIvie stood at the kitchen counter and listened to the building.\nThis was a habit she had carried from the room with the textbook window in Italy, from the small room in the Bronx, from every space she had occupied since the night she walked out of a building at four in the morning into a city that did not know her name. She had always listened to buildings before she began her day. It was a way of confirming where she was. A way of arriving, each morning, fully and deliberately.\nWhat she heard now: the radiator doing its mild commentary. Traffic four floors below making its reasonable case for itself. Tunde''s voice from the bedroom, low and unhurried, reading something aloud to the person who still found his voice the most interesting sound in any room she was placed in.\nShe poured two cups of tea and carried them back.\nAdaeze was three years old and had decided that mornings belonged to her father, a position she had taken up with the conviction of someone who had reviewed all available options and arrived at a firm conclusion. She was sitting in the middle of the bed with Tunde''s phone in her hands, scrolling through photographs with the focused authority of a small person conducting an audit.\n"Mama," she said, without looking up.\n"Good morning," Ivie said.\nAdaeze considered this greeting, found it satisfactory, and returned to the photographs.\nTunde took his tea and moved over so Ivie could sit. She sat beside him with her back against the headboard and her tea warm between her hands and watched her daughter work through the photographs with the serious attention of someone who had inherited, from somewhere in her particular combination of parents, the habit of examining things until she understood them.\nThe degree was framed on the wall in the living room. Public Health, summa cum laude, from a university whose name Ivie had written on an application form at twenty four with the specific terror of someone who had decided that the gap between where they were and where they were reaching was either a reason to stop or a reason to move faster, and had chosen.\nBeside it was a photograph taken in Ovia three years ago, the first time she had gone home. Mama in the centre, smaller than Ivie remembered but present with the full force of a woman who had decided that presence was its own kind of victory. Eki beside her with the expression of someone who had known all along that her sister would come back exactly as herself. Ese in her nursing scrubs, home for the occasion. Ose taller than all of them at seventeen, still loud, still asking questions nobody had answers to.\nShe had stood in her mother''s kitchen that first day home and put her hand on the counter that was the same counter and breathed the air that was the same air and felt the two versions of herself, the girl who had left and the woman who had returned, standing in the same body in the same room, and she had let them find each other without rushing it.\nIt had taken the whole trip.\nIt had been enough.\nShe worked at a public health organisation in lower Manhattan now, in a department that focused specifically on migrant women''s healthcare access. She had not planned this particular focus when she enrolled. It had found her, the way the truest work always found the person most fitted to do it, through a thesis supervisor who asked good questions and a research topic that arrived already feeling like something she owed rather than something she had chosen.\nShe knew things that the women in her caseload needed someone to know. Not from a textbook. From the specific and permanent education of having been in that building and made it out. She did not perform her history in her work. She did not wear it as a credential or a badge. But it was in the room when she was in the room, in the quality of her listening, in the questions she knew to ask because she had once needed someone to ask them of her and nobody had been there.\nSade knew this about her work. They spoke every few weeks across the distance between New York and London, where Sade had built her own particular life in her own particular way, and their conversations had the texture of something that had started in a building neither of them named aloud anymore but which had given them, against all its intentions, each other.\nAfter Tunde took Adaeze to the park she stood at the living room window for a while.\nThe Brooklyn street below was doing what streets did on a Saturday morning, unhurried and layered, people moving in the specific manner of people who had nowhere they had to be before noon. A woman was reading on a stoop. Two men were talking beside a car with the absorption of a conversation that had been going on since before she started watching. A child in a yellow coat was walking ahead of her parents with the purposeful stride of someone who had a destination in mind and intended to arrive there first.\nOrdinary life. Extraordinary ordinary life.\nIvie looked at it and felt the full weight of how much it had cost to be standing at this window in this apartment on this street on this particular Saturday morning, and she did not look away from the weight. She held it at its full size. She had learned that this was the only honest way to hold it.\nThen she said her name aloud.\nQuietly. Not for anyone, not for Tunde or Adaeze or Mama or Eki or any of the people she carried with her everywhere. For herself. The way you confirmed something you needed to stay certain of.\n"Ivie Osagie."\nThe girl from Ovia. Her father''s oldest. Her mother''s serious one. The one who went far enough. The one who mapped the maze and found the gap and walked out of the building at four in the morning with her passport against her chest and a city she did not yet know spread out in front of her.\nThe one who built everything after.\nThe light came through the window at its considered angle and touched everything in the room and Ivie stood inside it and did not flinch.\n\n\n\n\nEVERYTHING SHE BUILT\nA Serialized Novel in Three Seasons\nSeason 1: "The Promise" — 8 Episodes\nSeason 2: "The Cage" — 9 Episodes\nSeason 3: "New Ground" — 7 Episodes\nShe left Ovia with a name, a passport, and a promise someone else made and never intended to keep.\nShe arrived at the end of her own story with the same name, the same passport, and a life built entirely from promises she made to herself.\nTwenty four episodes. Three seasons. One girl who refused, at every point where refusal was the harder choice, to become less than what she had always been.\n\nThis novel is for every girl who was told the road forward required her to pay with herself.\nIt is for the ones who found the gap in the maze.\nIt is for the ones still looking.\nAnd it is for the ones who never made it out — whose names we do not know, whose counting nobody witnessed, whose story deserves to be told until the world finally decides to listen.\n\nEVERYTHING SHE BUILT\nis complete.\nEnd of Series.','\n',char(10)),1309,1,1,NULL,'2026-04-15 20:35:40','2026-04-15 20:33:28','2026-04-15 20:35:40',NULL,3,40);
INSERT INTO "chapters" ("id","novel_id","chapter_number","title","content","word_count","is_premium","is_published","audio_url","published_at","created_at","updated_at","scheduled_release_at","part_number","season_id") VALUES(440,57,1,'The Girl on the Rooftop',replace('The rooftop of Compound 14, Awolowo Close was not supposed to belong to anyone, but Ngozi had claimed it the way teenagers claim things gradually, quietly, without asking permission.\nShe sat on the low concrete ledge with her back against the water tank, phone tilted toward the last of the evening light, reading comments on a post she had shared three days ago. Forty-two likes. She had wanted four hundred.\nBelow, the compound moved through its usual evening rhythm. Pepper grinding somewhere near the back. A television arguing with itself through an open window. The gate man whistling the same five notes he had been whistling since January. Ngozi had lived here eleven months and knew every sound the way you know a song you never chose to learn.\nShe was seventeen and building something. She was not sure yet what it was exactly, but she posted every two days, studied what got attention and what did not, and kept a notes app full of ideas she had not yet been brave enough to try. Nothing she made was getting enough reach. Nothing was getting enough of anything.\nShe let her eyes drift to the courtyard below. That was when she noticed the window on the ground floor. Third door from the back stairwell. The one with curtains that never moved.\nFlat 9.\nShe had never seen the man who lived there leave before eight in the morning or come back before ten at night. When he did appear, he moved fast, head down, earphones locked in, like someone trying to cross a road before the light changed. He did not greet the gate man. He did not greet Mama Chidi, who sat outside every evening shelling groundnuts and ranking the business of everyone in the compound. He had not greeted Ngozi either, not even the afternoon she stood directly in his path carrying a full bag of groceries, giving him one full second to acknowledge she existed.\nHe had looked at the floor and kept walking.\nHis name was Tunde. She knew that only because she had heard the landlord say it once, from across the compound, in a tone that suggested something official.\nShe was still watching Flat 9 when the voice came from the floor above.\n"Hey. You. Rooftop girl."\nNgozi turned. A woman was leaning out of an upstairs window with the ease of someone who was comfortable in every room she entered. She was in her early twenties, wearing a yellow headwrap that sat slightly undone in a way that looked deliberate. A ring light glowed behind her, throwing warm gold into the evening air around her face.\n"Is it me?" Ngozi said.\n"Is there another rooftop girl up there?"\nNgozi looked left, then right. "No."\n"Then yes. It''s you. Come up. I have been meaning to meet the girl who sits up there thinking too hard."\nNgozi almost said she was not thinking too hard. She was barely thinking at all. But something about the woman''s voice settled the usual hesitation in her chest, so she got up and went.\nThe door to Flat 6 was open when she arrived. She stepped inside and felt the shift immediately. String lights along the top of one wall. A small desk with a laptop, a ring light, a phone on a tripod. Three succulents on the windowsill. The kind of room built by someone with a very clear idea of how they wanted the world to see them.\n"Uloma," the woman said, hand extended.\n"Ngozi."\n"I know. Mama Chidi told me your name two weeks ago. She told me the names and full history of everyone in this compound." Uloma opened a mini fridge and produced two cold bottles of Fanta. "Sit anywhere."\nNgozi chose the reading chair because the bed looked too comfortable and she did not know this woman yet. "You do content?" she asked, nodding toward the ring light.\n"Remote work first. Content on the side. But the content is growing, so." Uloma shrugged and sipped her Fanta. "You post."\n"You have seen my page?"\n"I searched you after the third time I spotted you up there." Uloma studied her the way people study something they are deciding the value of. "That photo you took of the street food woman last month. The framing. That was a real eye."\nNgozi looked at her bottle. "It did not get much reach."\n"Reach is a skill you can learn. The eye is something you either have or you do not."\nThey talked for close to an hour. Uloma explained algorithms the way someone talks about things they have tested personally and already won. Engagement windows. The difference between content that got saved and content that got shared. How a caption could carry a post the picture alone could not. Ngozi listened and asked questions and felt something she had not felt in a long time, the specific quiet of being in exactly the right room with exactly the right person.\nWhen she finally stood to leave, Uloma looked at her from across the room, unhurried.\n"You have a good eye," she said. "You notice things. That''s rare."','\n',char(10)),862,0,1,NULL,'2026-04-17 05:12:57','2026-04-17 04:50:33','2026-04-17 05:12:57','2026-04-17T04:00:00.000Z',1,NULL);
INSERT INTO "chapters" ("id","novel_id","chapter_number","title","content","word_count","is_premium","is_published","audio_url","published_at","created_at","updated_at","scheduled_release_at","part_number","season_id") VALUES(441,57,2,' How to Be Seen',replace('Uloma posted at 7pm every Tuesday and Thursday, and she treated both days the way some people treated church.\nNgozi had come to understand this by the third visit. There was a version of Uloma that existed in conversation, relaxed, laughing, generous with her Fanta and her opinions, and there was a version that appeared approximately forty minutes before a post went live. That version did not laugh. That version moved through the room with a focused quiet that made Ngozi feel like furniture.\nShe did not mind. She had started coming to Flat 6 the way you return to a place that is teaching you something, not because you were invited each time, but because the door was always open and the learning had not stopped.\n"Watch how I set this up," Uloma said one Tuesday evening, adjusting the ring light two degrees to the left. "People think content is about what you say. It is actually about what they see before you say anything."\nShe angled her phone on the tripod until the frame showed the string lights, one succulent, the warm painted wall, and her face in soft gold. Nothing in the shot looked arranged. Everything in the shot was arranged.\n"The background is a character," Uloma continued. "It tells your audience what kind of person you are before you open your mouth. Mine says: creative, calm, a little aesthetic, serious but not stiff." She glanced at Ngozi. "What does yours say?"\nNgozi thought about her own room. The desk buried under textbooks. The plastic chair with the broken armrest she kept meaning to replace. "Mine says I have not thought about it."\n"Correct. Fix that."\nNgozi wrote it down in her notes app. She had started a running document she had titled, privately, Uloma''s Rules, though she would not have admitted that to anyone.\nUloma''s actual work happened in the mornings, before Ngozi arrived. Remote data annotation for a European company, shift hours that meant she was done before noon most days. The content was the afternoon project, the evening project, the project that had taken her from four hundred followers eight months ago to just over eleven thousand now. She talked about the number the way a runner talks about a personal best, with satisfaction but no satisfaction, because the next number was already the one that mattered.\n"You want to know what actually moved my growth?" Uloma said, pulling up her analytics on her laptop and turning the screen so Ngozi could see. "Consistency plus proximity to things people already care about. I did not try to create a new conversation. I walked into conversations that were already happening."\nNgozi studied the graph. The climb was not sudden. It was a long, slow rise with two sharp peaks. "What happened at the peaks?"\n"First one, I posted a video the same night a big news story broke. Just my reaction, two minutes, no editing. Second one, a bigger creator shared my post about remote work struggles." Uloma closed the laptop. "Luck meets preparation. That is all growth ever is."\nNgozi turned this over in her mind. She had been approaching her page like a garden she was tending in private, patient and quiet. Uloma was describing something different. Not a garden. A market stall. You had to be where the crowd already was.\nThey were forty minutes into a recording session when it happened.\nUloma was mid-sentence, ring light glowing, phone on tripod, the practiced version of herself fully assembled, when the light flickered. Then the internet died. The recording app hung on a grey screen. Uloma sat completely still for three seconds in the specific way of a person deciding whether to be calm.\nShe was not calm.\n"Not today," she said, and the warmth was entirely gone from her voice. She opened her router app, saw the signal flatline, and turned to look at the wall shared with Flat 9.\nNgozi had heard it mentioned before. Twice last month, once the month before that. Tunde''s setup, whatever he was running in there, pulled from the compound''s shared electrical line at odd hours. The gate man said it was a big computer. Mama Chidi said it was probably something suspicious. Nobody had asked Tunde directly because nobody talked to Tunde.\nUloma stood, walked to her door, crossed the corridor, and knocked on the door of Flat 9.\nA long pause. Then from inside, a voice. Low, careful. "Yes?"\n"Your equipment is pulling power again. My internet just died in the middle of a recording."\nAnother pause. Longer this time.\n"I am sorry." The voice did not get louder. "I will restart the router."\n"Please do."\nShe stood there one more moment, as if expecting the door to open. It did not. She heard the faint sound of movement inside, and then the hum of something powering down and back up. On her phone, the internet signal blinked and returned.\nUloma came back into Flat 6 and sat down without speaking. She repositioned her phone. She checked the frame. She ran a hand over her headwrap and found the practiced expression again.\nBut before she pressed record, she looked back over her shoulder, through the open door, toward the corridor.\nToward the door that had not opened.\nShe looked at it the way you look at a thing that has already decided to be a problem.','\n',char(10)),902,0,1,NULL,'2026-04-17T04:51:42.207Z','2026-04-17 04:51:42','2026-04-17 04:51:42','2026-04-17T05:00:00.000Z',1,NULL);
INSERT INTO "chapters" ("id","novel_id","chapter_number","title","content","word_count","is_premium","is_published","audio_url","published_at","created_at","updated_at","scheduled_release_at","part_number","season_id") VALUES(442,57,3,' The Boy Nobody Knows',replace('Ngozi started asking questions about Tunde the way you start a thing you are pretending is casual.\nShe asked the gate man first, because the gate man saw everyone. His name was Baba Risi and he had worked Compound 14 for six years and could tell you the brand of noodles any tenant preferred. She caught him on a slow Thursday morning while he was oiling the gate hinges and asked the question sideways.\n"That guy on the ground floor. Flat 9. You know him well?"\nBaba Risi looked up. "Tunde."\n"Yes. What is his surname?"\nThe gate man squinted, genuinely searching. Then he shook his head. "He just signs the visitor book as Tunde. Never brought a visitor since he came."\n"How long has he been here?"\n"Eight months, maybe. Close to nine."\nEight months. Almost a year in a compound where Mama Chidi knew the preferred soap brand of every tenant, and the man had not given anyone his surname.\nNgozi wrote it in her notes app under a new heading she called Observations, then immediately felt strange about it and changed the heading to Nothing.\nShe tried Mama Chidi next, during the evening groundnut session. Mama Chidi was a small, deliberate woman who gathered information the way the earth gathers rain, naturally and without effort. She sat outside every evening in her plastic chair and if you positioned yourself close enough for long enough, she would eventually tell you everything about everyone.\n"Flat 9 boy," Ngozi said, keeping her voice easy.\nMama Chidi sucked her teeth. "That one. He is not from here. Yoruba boy, I think. Maybe Osun. But he does not speak Yoruba to anyone so I cannot confirm. Does not speak anything to anyone." She shelled a groundnut with practiced speed. "A young man who cannot greet his elders. Something is wrong with him."\n"Or he is just quiet."\nMama Chidi looked at her the way old women look at young people who have said something innocent and incorrect. "Quiet is one thing. That one is something else."\nNgozi did not push it. She had learned that arguing with Mama Chidi was like arguing with compound policy. You could disagree privately and nothing would change.\nThe accidental meeting happened on a Friday.\nNgozi was coming back from the pharmacy down the road, the kind of errand that made Lagos feel manageable, a ten minute walk with a clear purpose and a clear return. She was nearly at the gate when she heard footsteps behind her, quick and deliberate, and she turned to hold it open out of the simple habit of not letting heavy iron swing into the next person.\nThe next person was Tunde.\nHe stopped when he saw her holding it. Like he had not expected anyone to notice him, or had not expected the gate to be held open, or both. He looked at her directly for perhaps the first time since she had been in the compound, and she noticed his eyes were tired in a way that was not about sleep.\nHe nodded once and walked through.\n"You''re welcome," she said, before she could decide not to.\nHe paused for half a step, just barely. Then kept going.\nShe watched him cross the courtyard toward Flat 9. He was taller than she had registered from the rooftop. His backpack strap was fraying at the seam. His hands, she noticed, were not entirely still. Even walking, even with nowhere in particular to be, his fingers moved against his thigh in a light, irregular rhythm, like someone running through a problem they had not yet solved.\nShe thought about that rhythm for the rest of the evening.\nLater, she video-called Sade from her room. Sade was her oldest friend, currently three streets away and failing to study for an exam she was convinced would fail her first.\n"Tell me something interesting," Sade said, textbook propped at an angle behind her. "I cannot read another line of this."\n"There is this guy in my compound," Ngozi said. "He has been here almost a year and nobody knows his surname. He barely comes outside. Does not talk to anyone."\n"Sounds like my uncle after NEPA takes light."\n"I am serious. His hands were shaking when I held the gate for him."\nSade looked up properly. "Shaking how?"\n"Not sick shaking. Nervous shaking. Like he is always carrying something heavy and trying not to show it."\n"Maybe he just has anxiety."\n"Or maybe he is hiding from something."\nSade was quiet a moment. Then, in the patient voice she used when Ngozi was building entire houses out of single bricks, she said: "Or maybe he is just a person who finds people exhausting and wants to be left alone to live his life."\nNgozi did not have an answer for that. She said goodnight and set her phone face down on the mattress.\nShe lay in the dark and thought about the fraying strap and the tired eyes and the fingers moving against his thigh.\nShe thought about Uloma''s voice in the corridor. Your equipment is pulling power again.\nShe thought about a door that had not opened.\nWhat she did not see, and had no way of seeing, was Flat 9 at two in the morning.\nThe rest of Compound 14 was long asleep. The pepper grinder silent. The television dark. Even Baba Risi''s five-note whistle had gone quiet for the night.\nTunde sat at his desk in the blue light of his laptop screen, reading an email he had been waiting four days to receive. A small design project from a logistics company in Abuja. The kind of job that would not change his life but would cover two weeks of electricity and let him keep going.\nThe email said yes.\nHe read it twice. Leaned back in his chair. And in the full, unguarded privacy of a room where no one had ever watched him, a small smile crossed his face.\nHe cracked his knuckles, pulled up the project brief, and started work.','\n',char(10)),1012,0,1,NULL,'2026-04-17T04:52:54.869Z','2026-04-17 04:52:54','2026-04-17 04:52:54','2026-04-17T05:00:00.000Z',1,NULL);
INSERT INTO "chapters" ("id","novel_id","chapter_number","title","content","word_count","is_premium","is_published","audio_url","published_at","created_at","updated_at","scheduled_release_at","part_number","season_id") VALUES(443,57,4,' The Night She Posted',replace('Ngozi was still awake at midnight for no good reason.\nShe had told herself she was editing a caption. Then she was watching a video she had already watched. Then she was lying on her back with the phone held above her face, doing the thing she had promised herself she would stop doing, which was consuming other people''s content at midnight and feeling vaguely hollow about her own.\nThat was when Uloma''s post appeared.\nIt sat at the top of her feed the way important things sit. Quietly, waiting. The profile photo. The timestamp. 11:47pm.\nNgozi tapped it.\nShe read it once quickly. Then she sat up and read it again slowly.\nThe post was long, longer than Uloma usually wrote. It opened with an apology for the late hour, the kind of apology that signals what follows is serious. Then it described what Uloma said had happened three nights ago. Inside her room. Late. A neighbor with access to the building. Someone who did not interact with people, who used that invisibility the way certain people use darkness, as cover.\nThere was no name.\nThere did not need to be.\nThe compound had exactly one person who matched every word of that description, and Ngozi''s chest understood it before her mind finished the last sentence.\nShe sat very still. Outside, Awolowo Close was completely silent. A generator hummed somewhere two streets over. Inside her own chest, something was moving fast and she was not sure whether to call it certainty or fear.\nShe went to the comments. Already sixty deep, and the post had only been live for fifteen minutes. Women saying they believed her. Men saying this was why nowhere was safe. Strangers who had never heard of Uloma, never heard of the compound, never heard of Awolowo Close, who knew nothing except what those paragraphs had handed them, and they were furious, and they were ready, and they were growing by the minute.\nNgozi read until her eyes blurred. Then she looked at the share button.\nShe thought about Uloma''s ring light. The way Uloma had said you notice things, that''s rare. The way Uloma had explained reach and proximity and walking into conversations that were already happening. She thought about her own page. Two hundred and seventeen followers. Forty-two likes on her best post. The long, patient nothing of eleven months of effort.\nShe thought about Tunde''s door not opening. The fraying backpack strap. Mama Chidi''s voice: something is wrong with him.\nShe pressed share.\nThe caption came fast, the way words come when something underneath them has already made a decision. This happened in my compound. I know exactly who she is describing. Women are not safe anywhere, not even behind their own locked doors. We have to protect each other.\nShe put the phone down.\nShe picked it back up.\nThe notifications arrived in under two minutes. Strangers she had never reached before, agreeing, amplifying, tagging other strangers into the thread. Her own followers responding with a heat she had never felt directed at her before. Three people asked for the compound address. Someone called for the man to be named publicly. Someone else posted a long thread about the behavioral patterns of men who isolate themselves from their neighbors.\nBy twelve forty, her share alone had been reshared twenty-two times.\nShe sat in the middle of it and felt something she had no previous name for. Not the hollow feeling of midnight scrolling. Not the small, patient ache of forty-two likes. Something larger and warmer and faster, something that felt, in the breathless logic of that hour, like finally mattering. Like being the person in the room who had stood first when standing was needed.\nShe posted a second caption beneath her original share. To every woman reading this. I see you. We all see you.\nThe response came immediately, warm and wide and more than she had ever received.\nAt some point she stopped reading individual comments because there were simply too many. She watched the numbers instead. She watched her follower count move upward in the quick, clean jumps she had spent nearly a year trying to produce. She lay back against her pillow with the phone resting on her chest and the screen still glowing and felt the compound outside her window differently than she had felt it an hour ago.\nShe was part of something.\nShe mattered inside it.\nSleep came slowly, satisfied.\nShe did not notice, and no one thought to tell her, that the light behind the curtains of Flat 9 had been on since eleven.\nIt was still on past midnight. Still on at one. Still on past two, long after the last sound had left Compound 14 and the whole of Awolowo Close had gone dark and still.\nTunde was at his desk.\nHe was not on social media. He did not know yet what was sitting in the feeds of everyone around him.\nHe was just working.','\n',char(10)),834,1,1,NULL,'2026-04-17T04:54:02.530Z','2026-04-17 04:54:02','2026-04-17 04:54:02','2026-04-17T05:00:00.000Z',1,NULL);
INSERT INTO "chapters" ("id","novel_id","chapter_number","title","content","word_count","is_premium","is_published","audio_url","published_at","created_at","updated_at","scheduled_release_at","part_number","season_id") VALUES(444,57,5,' The Compound Decides',replace('Ngozi knew something had shifted before she opened her door.\nShe heard it first. Voices in the courtyard below, low and clustered, the kind of talking that was not really conversation but the sound people make when they are building something together and have not yet decided what. She checked her phone. Seven forty-three in the morning. Compound 14 was not a place that gathered before nine.\nShe pulled her wrapper tighter and stepped onto the corridor balcony.\nFour women stood near the back stairwell. Mama Chidi was among them, no groundnuts, no plastic chair, just her arms folded across her chest and her face arranged into the expression she reserved for things she had already judged and sentenced. The wife from the top floor was there. Two other women Ngozi recognized by face but not by name. They were speaking in the direction of the ground floor.\nIn the direction of Flat 9.\nNgozi looked down at the door. It was closed. The curtains behind the window were drawn the same as always. But someone, at some point between last night and this morning, had written a word on the wall directly beside it. One word, sprayed in red paint, uneven letters, the kind of thing written in a hurry by someone who wanted the statement more than the craftsmanship.\nShe read it from the balcony and felt something move through her that she did not immediately examine.\nBy eight thirty the landlord had arrived. Mr. Fashola was a compact man in his sixties who wore the same style of embroidered kaftan regardless of the occasion and spoke in the measured tone of someone who had decided long ago that raising his voice was beneath him. He stood outside Flat 9 with his hands clasped behind his back and knocked once.\nNo answer.\nHe knocked again and spoke toward the door. "Tunde. I know you are inside. We will need to discuss your tenancy pending this investigation. I am giving you until end of week."\nSilence from inside. Just the faint, familiar hum of equipment.\nMr. Fashola turned and walked back across the courtyard without looking at anyone. The women near the stairwell watched him go. Mama Chidi nodded slowly, satisfied, as though the morning had delivered exactly what she had ordered.\nNgozi went back inside and sat on her bed.\nHer phone was warm from being held so long. She had checked it four times since waking up. The numbers were still moving. Her follower count had cleared four hundred overnight. The comments on her share had passed one hundred and twenty. Someone had tagged a journalist. Someone else had tagged a women''s rights organization with a blue tick and eighty thousand followers.\nShe put the phone face down and told herself she would not check it again for one hour.\nShe checked it after eleven minutes.\nAt midday, a food delivery arrived at the compound gate. The rider was young, helmet still on, scanning the address on his phone. Ngozi was back on the balcony, her textbook open on the ledge beside her, unread.\nShe watched Baba Risi point the rider toward Flat 9. Watched the rider walk across the courtyard, slow down as he got closer, read the word on the wall, and stop. He stood there holding the paper bag, looking at the door, looking at the wall, looking at the door again.\nThen he set the bag down on the ground outside the door, turned around, and walked back to his bike.\nHe did not knock.\nNgozi watched the bag sitting on the floor outside Flat 9. Steam would be leaving it already. Whatever was inside was going cold.\nSomething moved through her again, the same feeling as before, and this time she stayed with it long enough to almost recognize it before Sade''s voice note arrived and pulled her back.\n"Ngozi. I saw your share. Are you okay? Is it really the guy in your compound? Everyone in my area is talking about it now."\nShe typed back quickly. I am fine. Yes, it is him. Nobody is safe, you know how these things are.\nShe sent it and watched the ticks turn blue.\nFrom below, the door to Flat 9 did not open. The paper bag sat on the floor outside it. The word on the wall dried in the afternoon sun.\nNgozi told herself the feeling in her chest was just the weight of a serious situation. That it was normal to feel heavy when something like this happened close to home. That discomfort was not the same as doubt.\nShe picked up her phone and opened Uloma''s original post.\nThe share count had a comma in it now.\nForty-seven thousand.','\n',char(10)),790,1,1,NULL,'2026-04-17T04:55:08.112Z','2026-04-17 04:55:08','2026-04-17 04:55:08','2026-04-17T05:00:00.000Z',1,NULL);
INSERT INTO "chapters" ("id","novel_id","chapter_number","title","content","word_count","is_premium","is_published","audio_url","published_at","created_at","updated_at","scheduled_release_at","part_number","season_id") VALUES(445,57,6,' Main Character',replace('By Wednesday, Ngozi had six hundred and eleven followers.\nShe knew the exact number because she had checked it fourteen times before noon. Six hundred and eleven people who had not existed in her notifications four days ago, who had found her through the share, through the comments, through the particular momentum of a story that kept moving even after you put your phone down.\nShe sat at her desk and tried to study. She read the same paragraph three times and retained nothing. Her phone buzzed. She checked it. A women''s rights organization with a blue tick had reposted Uloma''s original accusation with a caption about the epidemic of unsafe housing for Nigerian women. In the repost, they had quoted Ngozi''s share directly, her exact words, her name attached.\nShe read her own words on a page with eighty thousand followers and felt something bright and strange move through her.\nShe opened her camera.\nShe had not planned a video. She had not arranged the background the way Uloma had taught her, no ring light, no considered framing, just her face and the wall behind her and the afternoon coming through the curtain. But she pressed record and spoke, and the words came out clean and certain the way words do when you have been thinking something for long enough that saying it feels like relief.\n"I want to talk about what it means to believe survivors," she said. "Not just online. Not just when it is trending. In your compound. On your street. When it is uncomfortable and close and the person is someone you have seen at the gate."\nShe spoke for two minutes and forty seconds. She did not edit it. She posted it with a caption that said simply: We must believe and protect survivors. Full stop.\nThen she set her phone face down and opened her textbook.\nShe lasted four minutes.\nThe video moved faster than anything she had ever made. The blue tick organization shared it within the hour. Then a second account, then a third. The comments were warm and urgent and full of people tagging other people, building a chain she could follow all the way out to strangers who had never heard of Awolowo Close but were now saying her name in their own captions.\nThree thousand likes by evening.\nShe sat with that number and turned it over slowly, the way you handle something valuable and slightly unreal.\nUloma knocked on her door at six. She came in already talking, animated in a way Ngozi had not seen from her before, a loose, electric energy that was different from her usual controlled warmth.\n"A journalist from an online publication wants a comment," Uloma said, sitting on the edge of the bed. "And the organization that reposted, they want to feature the story in their newsletter." She looked at Ngozi. "You are blowing up."\n"You are the one they want to feature."\n"They want both of us." Uloma smiled. "I told you. Proximity to things people care about."\nNgozi smiled back. She almost said something about the food bag that had sat outside Flat 9 until Baba Risi quietly picked it up and set it inside the gate. She almost said something about the word on the wall that no one had cleaned off yet. But the moment was warm and the numbers were good and Uloma was looking at her like she had finally arrived somewhere, so she said nothing and let the moment stay the way it was.\nThe compound landline rang at eight forty-five that night.\nIt was mounted on the wall near the stairwell, an old thing in a faded cream casing that mostly received calls for tenants who could not be reached on mobile. Ngozi heard it from her room, two floors up, through the window she had left open for the evening air.\nIt rang seven times.\nNobody picked up. Baba Risi had gone home for the night. The tenants who might have passed it were already inside. The ringing moved through the compound and found no one.\nWhat Ngozi did not know, and would only learn much later, was who was on the other end of that call. A young woman in Osun State, sitting in a room lit by a single bulb, redialing a number she had found on an old receipt her brother had sent her months ago. She had been calling since morning. She had seen things online, fragments and threads and a share that described a neighbor in a compound in Lagos who did not talk to people, and something had settled cold in her stomach.\nShe just wanted to know if her brother was okay.\nThe line rang out again. She sat with the phone in her hand and tried his mobile for the eleventh time. It went to voicemail. She did not leave a message. She did not know what message to leave.\nAt nine thirty, Ngozi posted a second video. Shorter this time, more direct, filmed with the ring light she had borrowed from Uloma.\nIt got four hundred likes in the first hour.\nShe watched the numbers climb and felt the same bright, clean feeling as before.\nShe did not mention the ringing phone.\nShe had not heard it.','\n',char(10)),884,1,1,NULL,'2026-04-17T04:56:13.062Z','2026-04-17 04:56:13','2026-04-17 04:56:13','2026-04-17T05:00:00.000Z',1,NULL);
INSERT INTO "chapters" ("id","novel_id","chapter_number","title","content","word_count","is_premium","is_published","audio_url","published_at","created_at","updated_at","scheduled_release_at","part_number","season_id") VALUES(446,57,7,' Where Is the Report?',replace('\nThree weeks was long enough for a hashtag to develop a layer of dust.\nNgozi noticed it the way you notice a sound that has slowly stopped. The notifications had thinned from a flood to a trickle to the occasional comment from someone who had found the post late and was just now catching up to an outrage that everyone else had already moved through. The women''s rights organization had not posted about it in eleven days. The journalist who had slid into Uloma''s messages had not followed up. The thread that had once been building its own momentum had quieted the way threads do when the next story arrives and the crowd turns to face it.\nLife in Compound 14 had not returned to normal exactly, but it had returned to routine. Mama Chidi was back in her chair with her groundnuts. The word on the wall outside Flat 9 had faded in the rain to something illegible. Mr. Fashola had not followed through on the eviction notice, at least not yet, though he had also not retracted it. Tunde''s curtains remained closed. His door remained shut. The compound moved around his silence the way water moves around a stone, without acknowledging it.\nNgozi had eight hundred and forty followers now. She posted twice a week. The content had shifted slightly, less about the specific story and more about safety and belief and the general subject of women navigating the world. It got decent engagement. Not the numbers from the first week, but steady.\nShe was on her way down to buy water sachets when she saw the comment thread on Uloma''s page.\nSomeone had typed, plainly and without aggression, a question that other people had immediately begun liking: It has been three weeks. Is there a police report? Has he been arrested?\nBelow it, more questions. Different voices, same direction. Why has his name not been released? What is the update? Is there any progress on the case?\nThe comments were not hostile toward Uloma. They were the questions of people who had invested belief and wanted to see it honored with action. The tone was careful, supportive even, but the questions were real and they were accumulating.\nUloma had posted a response that morning. Not a full post, just a story, a soft-focus photo of her window with the caption layered over it in clean white text.\nHealing is not linear. Recovery does not follow the timeline the internet wants. Please give me space to move through this at my own pace. Your support means more than you know.\nThe responses to the story were warm and immediate. People saying they were sorry for pushing. People saying she owed no one an explanation. People reminding each other that survivors set their own timelines.\nNgozi read all of it standing in the corridor with the water sachet money folded in her hand.\nShe put her phone away and went downstairs.\nShe might not have seen the reel at all if Sade had not sent it to her.\nIt arrived on Thursday evening with no caption, just a link. The kind of thing Sade sent when she wanted Ngozi to see something and had decided to let her arrive at her own reaction without being guided there.\nNgozi tapped it.\nIt was a reel from an account she did not follow. A rooftop gathering somewhere on the island, the kind of Lagos evening that existed in one tax bracket and photographed well in all of them. String lights strung between poles. People in good outfits laughing at things that were clearly funnier in person. The account owner panning the camera across the group.\nUloma appeared at the four second mark.\nShe was in a yellow dress, a cold drink in her hand, her head thrown back in the particular way of someone laughing at something genuinely funny. Not performing. Just laughing. Completely at ease. The timestamp in the reel''s caption said Tuesday evening, two nights ago.\nNgozi watched it once. Then she watched it again.\nShe put her thumb on the screen and held it. Screenshot.\nShe sat on the edge of her bed and looked at the frozen image. Uloma mid-laugh, drink raised, surrounded by people having an ordinary good time on a Tuesday night in Lagos.\nThere was nothing wrong with it. People who had been through difficult things were still allowed to laugh at rooftop parties. Recovery was not linear, as the story had said. You could be hurting privately and still appear in someone''s reel.\nNgozi knew all of that. She assembled each piece of it carefully in her mind.\nAnd yet she kept looking at the screenshot.\nShe did not send it to anyone. She did not post about it. She did not knock on Uloma''s door.\nShe set her phone face down on the mattress and sat in the quiet of her room, listening to the compound sounds she had memorized over eleven months, the gate, the television, the generator two streets over.\nFrom below, nothing moved behind the curtains of Flat 9.\nShe picked up the phone and looked at the screenshot one more time.\nThen she locked the screen and lay down in the dark.','\n',char(10)),874,1,1,NULL,'2026-04-17T04:57:06.293Z','2026-04-17 04:57:06','2026-04-17 04:57:06','2026-04-17T05:00:00.000Z',1,NULL);
INSERT INTO "chapters" ("id","novel_id","chapter_number","title","content","word_count","is_premium","is_published","audio_url","published_at","created_at","updated_at","scheduled_release_at","part_number","season_id") VALUES(447,57,8,' The Numbers Don''t Add Up',replace('It started as something she was not doing deliberately.\nNgozi had gone back to Uloma''s original post to find a comment she half-remembered, something a follower had said in the first hour that she had meant to screenshot and never did. She was not investigating anything. She was not looking for anything. She was just scrolling back through a thread she had already read, the way you reread a page when your mind was somewhere else the first time.\nShe found the comment. She screenshotted it. She was about to close the app when her eyes snagged on the timestamp in the original post.\n11:47pm. A Thursday night.\nShe read the post again. Not the comments this time. The post itself, the way she had read it the first night, carefully, sentence by sentence. The language was specific in the way she had originally taken as evidence of truth. The detail about the corridor light being out. The detail about the window latch that did not catch properly. The description of a neighbor who kept to himself and used that to move through spaces unnoticed.\nShe read it a third time.\nThen she opened a different app and searched Uloma''s older posts. She was not sure what she was looking for, she told herself that clearly, she was not sure, she was just looking the way you look when something is sitting at the edge of your thinking and will not move off.\nShe scrolled back six weeks. Eight weeks. The posts were consistent with the Uloma she knew, sharp captions, good framing, the careful performance of a life that looked both real and worth watching. Then she went to the location tags.\nThree months ago, Uloma had checked in to a hotel in Abuja. The caption was brief. Change of scenery. The work follows you everywhere. A photograph of a desk near a window, a laptop open, the particular beige of a hotel room in the background.\nNgozi looked at the date.\nShe looked at it again.\nShe went back to the original post. Re-read the opening line. Three nights ago. The post had gone live on a Thursday. Three nights ago from a Thursday was a Monday.\nThe hotel check-in was a Monday.\nThe same Monday.\nShe set the phone face down on her thigh and sat very still. The ceiling fan moved the warm air in slow rotations above her. Outside, a car horn sounded twice and went quiet.\nShe picked the phone back up and looked at both screens again, toggling between them slowly, as if the numbers might rearrange themselves into something she had simply misread.\nThey did not.\nShe called Sade that evening and kept her voice easy.\n"Can I ask you something strange?"\n"When have you ever asked me something normal," Sade said.\n"That night Uloma posted. You saw it, right. You messaged me the next morning."\n"Yes."\n"Did she not say somewhere, that week, that she was traveling? I feel like I heard something about Abuja."\nSade was quiet for a moment, thinking. "I don''t know. I don''t really follow her like that. Why?"\n"I am just trying to remember the timeline. I think I mixed something up."\n"Ngozi." Sade''s voice shifted, just slightly. "What are you looking for?"\n"Nothing. I told you. I just mixed up a timeline."\nSade let it sit for a moment. "Okay," she said finally, in the tone she used when she was not convinced but had decided not to push.\nThey talked about other things after that. An exam result. A cousin''s upcoming introduction. Ngozi contributed the right words at the right moments and her mind was not in the conversation at all.\nAfter she hung up she sat on the floor with her back against the bed and opened both posts again. She looked at them for a long time. She thought about what it would mean if what she was seeing was what she was seeing. She thought about eight hundred and forty followers. She thought about her own video, her own voice saying we must believe and protect survivors, full stop. She thought about the blue tick organization that had quoted her words on a page with eighty thousand followers.\nShe thought about the word on the wall outside Flat 9, faded now but not gone.\nShe thought about a paper bag going cold on a concrete floor.\nShe put her phone face down on the mattress and stood up. She needed water. She needed air. She needed to be somewhere other than the four walls of her own thinking.\nShe went downstairs.\nThe courtyard was empty in the early evening quiet. She crossed it toward the back tap without looking at Flat 9. She was not looking at Flat 9. She was getting water.\nBut as she passed the door, she heard it.\nTyping. Fast, steady, uninterrupted. The particular sound of someone deep inside a task, unaware of anything outside it. Alive and working in there, in the room that the compound had decided to fear.\nShe stood outside the door for just a moment, water forgotten, hand loose at her side.\nThen she walked back upstairs and did not look at her phone for the rest of the night.','\n',char(10)),878,1,1,NULL,'2026-04-17T04:58:06.699Z','2026-04-17 04:58:06','2026-04-17 04:58:06','2026-04-17T05:00:00.000Z',1,NULL);
INSERT INTO "chapters" ("id","novel_id","chapter_number","title","content","word_count","is_premium","is_published","audio_url","published_at","created_at","updated_at","scheduled_release_at","part_number","season_id") VALUES(448,57,9,' What Staying Silent Costs',replace('She heard about the quit notice from Mama Chidi, which meant the entire compound had heard about it first.\nNgozi was coming down the back stairwell on a Saturday morning when Mama Chidi''s voice rose up to meet her, carrying the way it always carried, unhurried and absolute, the voice of a woman who had long understood that information was its own kind of currency.\n"Mr. Fashola delivered the letter himself on Friday," Mama Chidi was saying to the woman from the top floor. "End of month. He has until end of month to find somewhere else."\nNgozi slowed her steps without stopping.\n"And his family?" the woman from the top floor asked.\n"Nobody has come for him. He is in there alone." Mama Chidi paused. "A boy with no family and no community. That is how you know the character."\nNgozi reached the bottom of the stairs and walked past them with a quiet good morning. Neither woman broke their conversation. She crossed the courtyard to the back tap and turned it on and let the water run over her hands longer than she needed.\nEnd of month was eleven days away.\nShe learned about the clients from Baba Risi, which surprised her, because Baba Risi rarely volunteered information.\nHe mentioned it the way he mentioned most things, sideways, while doing something else, oiling hinges or adjusting the padlock chain, his eyes on his hands and not on her.\n"The deliveries have stopped," he said, on a Tuesday afternoon when she was leaving for the pharmacy.\nShe paused. "What deliveries?"\n"He used to receive things. Equipment, packages. Small courier bags. Once or twice a week." Baba Risi kept his eyes on the padlock chain. "Last one came five weeks ago. Before all the noise."\nNgozi stood at the gate and understood what he was not quite saying. The packages were work. Whatever Tunde did inside Flat 9, the courier bags were part of it. And they had stopped arriving at the same time the compound had decided what kind of person he was.\nShe thanked Baba Risi for nothing in particular and went to the pharmacy and came back and went upstairs and sat on her bed for a long time.\nThe thing about his sister she heard by accident, which was the worst way to hear it.\nShe was on the balcony on Wednesday evening when she caught pieces of a conversation between two women in the courtyard below, voices low but not low enough, the way people speak when they are being discreet only as a formality.\nA young woman had come to the gate ten days ago, on a day Ngozi had been out most of the afternoon. She had asked for Tunde by name. Baba Risi had told her the situation, or enough of it, and the young woman had stood at the gate for a while without going in. She had cried quietly. Not loudly, not dramatically, the crying of someone who was not doing it for anyone else. Then she had asked to use the compound landline. The call had not connected. She had stood there a while longer and then she had left.\nShe had not been let through the gate.\nNobody had gone to knock on Flat 9 to tell Tunde his sister was outside.\nNgozi gripped the balcony railing and looked out over the courtyard. The evening light was going amber across the rooftops. A neighbor''s radio played something with a slow, heavy bassline two buildings over. Everything in Compound 14 was completely ordinary.\nShe thought about the girl in Osun State she did not know existed, redialing a number from an old receipt. She had no way to connect that imagined figure to this one, the young woman crying quietly at the gate. But something in her chest connected them anyway, without her permission, the way bodies know things before minds catch up.\nShe went inside. She sat at her desk. She opened her phone and scrolled through her own page, the videos, the captions, the careful architecture of a person who noticed things and said so.\nHer last post was four days ago. The comments had been decent. Nothing like the early numbers, but steady.\nShe opened the wider feed. There were three new stories trending, none of them connected to anything she recognized. The crowd had moved entirely. The particular urgency that had once filled her notifications like weather had passed through and left no mark on the people who had carried it.\nA girl in a university hostel. A policy announcement. A celebrity photograph taken out of context. The feed was full and moving and completely indifferent to Awolowo Close.\nShe put her phone down and went to the window.\nFlat 9 was directly below and to the left, partially visible from this angle. She had never seen those curtains open. In nine months of watching, not once.\nThey were open now.\nJust slightly, just enough. The evening light catching the edge of the fabric where it had been pulled a few centimeters to one side. And behind the gap, barely visible, a face. Tunde, standing at his own window, looking out at the compound he had lived inside for the better part of a year and barely touched.\nHe was looking at the courtyard. At the gate. At nothing in particular.\nHe did not look up at her window.\nShe stood very still and watched him look for something she could not name, in a compound that had already decided it did not want to find him.','\n',char(10)),932,1,1,NULL,'2026-04-17T04:59:08.952Z','2026-04-17 04:59:09','2026-04-17 04:59:09','2026-04-17T05:00:00.000Z',1,NULL);
INSERT INTO "chapters" ("id","novel_id","chapter_number","title","content","word_count","is_premium","is_published","audio_url","published_at","created_at","updated_at","scheduled_release_at","part_number","season_id") VALUES(449,57,10,' Uloma Logs Off',replace('Ngozi found out the way most people found out about most things now, through a screenshot someone else had already assembled.\nSade sent it at half past ten on a Thursday morning with the same no-caption approach she used when she wanted the thing to speak for itself. Ngozi opened it, still in bed, still in the thick half-awareness of early morning, and sat up slowly as her eyes adjusted to what she was reading.\nIt was a compiled thread. Someone had done the work, gone back through posts and timestamps and location tags and testimony from two people who had been in Abuja that Monday, and laid it all out in the clean, numbered format that threads used when they wanted to be taken seriously. Eleven posts long. Each one building on the last.\nThe hotel check-in was post number four.\nNgozi''s own screenshot, the one she had taken and shown to no one, was post number seven. Someone else had found it independently.\nShe read the whole thread twice. Then she opened Uloma''s page.\nThe account was private.\nShe refreshed it. Still private. She checked the handle to make sure she had the right one, confirmed it, refreshed again. The follower count was still visible in the preview. Eleven thousand, four hundred and twelve.\nShe put the phone face down and stared at the ceiling.\nBy noon, the account was gone entirely.\nNot private. Gone. The handle returned nothing. The profile photo returned nothing. The eleven thousand, four hundred and twelve followers were following an empty space where a person had been.\nThe thread, however, was still moving. It had been shared two hundred times by noon. Three hundred by one o''clock. The same crowd that had amplified the original accusation was now amplifying the unraveling of it, with the same velocity and the same heat, just pointed in a different direction.\nNgozi watched it from her bed, where she had not moved in three hours.\nHer own share was still live. Her own caption was still attached to it. This happened in my compound. I know exactly who she is describing. Her name. Her face in the video still visible on her own page, her voice saying we must believe and protect survivors, full stop.\nThe first person tagged her at twelve forty.\nBy two o''clock there were eleven tags. By three there were too many to count separately. They arrived in clusters, groups of strangers pulling her into a conversation that had turned and was now facing her. Some of the voices were measured, asking questions. Some were not measured at all.\nShe locked her account at three fifteen.\nShe sat on the rooftop because she could not stay in her room and she did not know where else to go. The afternoon sun was flat and direct and she had come up without sunscreen or a book or any of the things she usually carried. She sat on the low concrete ledge with her back against the water tank, the same position she had occupied the evening Uloma had called up to her from the floor below, and looked at nothing.\nThe compound below was ordinary. Mama Chidi in her chair. A child from the top floor kicking a ball against the back wall. Baba Risi threading a new rope through the gate pulley. The usual sounds, the usual movements, the usual shape of an afternoon in Awolowo Close.\nShe looked at the wall beside the door of Flat 9. The word that had been sprayed in red paint in the first hot hours after the post had faded over the weeks of weather into a pale stain. You could still read it if you were looking for it.\nHer phone buzzed continuously in her pocket. She stopped taking it out.\nAt some point she heard Mama Chidi''s voice float up from below, talking to someone Ngozi could not see. "I always said something was not right about that Uloma. You cannot trust a person who does not greet neighbors. Her and that boy she accused, both the same."\nNgozi closed her eyes.\nThe afternoon moved. The sun shifted. The child downstairs stopped kicking the ball and went inside. The compound went through its evening rhythms without requiring anything from her.\nWhen she finally took her phone out, the screen was full. She did not read the notifications. She went directly to her messages, a reflex without a clear destination, and stopped.\nThere was a message she did not recognize. A number not saved in her contacts, sent three hours ago, still unread.\nShe opened it.\nHi. You don''t know me. My name is Adaeze. Tunde is my brother. I saw your name in the thread. I think we need to talk.','\n',char(10)),797,1,1,NULL,'2026-04-17T05:00:18.098Z','2026-04-17 05:00:18','2026-04-17 05:00:18','2026-04-17T05:05:00.000Z',1,NULL);
INSERT INTO "chapters" ("id","novel_id","chapter_number","title","content","word_count","is_premium","is_published","audio_url","published_at","created_at","updated_at","scheduled_release_at","part_number","season_id") VALUES(450,57,11,' Flat 9',replace('She replied to Adaeze at seven in the morning, before she had talked herself out of it.\nShe had drafted the message four times the night before and deleted each one. The first was too apologetic. The second explained too much. The third was so careful it said almost nothing. The fourth she deleted without finishing because she realized she was writing to make herself feel better and not to actually meet the person on the other side of the screen.\nThe fifth one said: I am in the compound. I can meet you wherever is easiest for you.\nAdaeze replied in under three minutes. She was already in Lagos. She had come down two days ago and was staying with a cousin in Surulere. She could be at a cafe near Awolowo Close by ten.\nThe cafe was the kind of small, quiet place that existed in the gaps between bigger things, six tables, a ceiling fan that worked, a woman at the counter who did not look up when you entered. Ngozi arrived first and chose a corner table and ordered nothing and waited.\nAdaeze was younger than she had imagined. Twenty at most, slight, wearing a blue ankara blouse and carrying a bag that was slightly too large for her frame, the bag of someone who had packed in a hurry and brought more than she needed because she did not know what she would need. She scanned the room and found Ngozi''s eyes and came over without smiling.\nShe sat down. She folded her hands on the table.\n"Thank you for coming," she said.\n"Thank you for reaching out," Ngozi said.\nThey looked at each other for a moment, two people at a table with a very specific thing between them that neither had yet touched.\nAdaeze touched it first.\nShe spoke for close to forty minutes. She did not raise her voice. She did not cry, though twice she paused in a way that suggested she was managing the possibility of it. She spoke the way someone speaks when they have been carrying a thing for so long that the telling of it has become its own kind of exhaustion.\nShe told Ngozi about the first call she had placed to the compound landline the morning after the post went live. About the eleven unanswered calls to Tunde''s mobile across three days. About his voice when he finally picked up, quiet in a way that was different from his usual quiet, flattened, like something underneath it had been pressed down and was staying down.\nShe told her about the clients. Two of them, both small businesses that had found Tunde''s name connected to the story through the comment threads, one in Abuja, one in Port Harcourt, both of whom had sent polite, brief messages ending their contracts. She pulled out her phone and showed Ngozi the screenshots Tunde had forwarded her without comment. Two short emails. Professional language doing an unprofessional thing.\nShe told her about the food. How he had stopped ordering delivery after the rider left the bag on the floor. How she had sent him money through a transfer app and he had not touched it for a week. How their mother in Osun had been calling and he had been answering just enough to stop her from making the trip to Lagos.\nShe told her about coming to the gate. About standing outside and crying in a way she was embarrassed about and asking to use the compound phone and the line not connecting. About not being let through.\nShe said all of it without cruelty. She laid each thing down on the table between them like evidence, not like a weapon. When she finished she picked up the cup of tea that had arrived at some point and held it with both hands and looked at Ngozi steadily.\n"I am not angry at you specifically," Adaeze said. "I just need you to understand what happened."\nNgozi looked at the table. "I understand," she said. It came out smaller than she intended.\n"He did not do anything," Adaeze said. "He has never done anything to anyone. He just lives quietly and does his work and tries to stay out of people''s way." She paused. "That is not a crime."\n"I know," Ngozi said.\n"Okay," Adaeze said softly. "Okay."\nShe walked back to Compound 14 alone.\nThe afternoon was loud in the way Lagos afternoons were loud, generators, horns, a woman selling something from a tray on her head calling out in a voice that carried half a street. Ngozi moved through all of it and heard none of it.\nShe crossed the courtyard. She looked at the pale stain on the wall beside the door. She stood outside Flat 9 and raised her hand and knocked before the part of her that was afraid could make an argument.\nA pause. Longer than usual.\nThen the sound of the lock.\nThe door opened and Tunde stood in it, and she had been in the same compound as this person for eleven months and this was the first time she had seen him this close in full light. He looked the way Adaeze had prepared her for without preparing her. Tired in a deep, settled way. Thinner. His eyes moved to her face and waited without expression.\nShe had planned what to say. The words were gone.\n"I am sorry," she said. Just that. Just the two words, with nothing attached to soften them or explain them away.\nTunde looked at her.\nHe did not speak for a long time. The courtyard behind her went about its business. The ceiling fan inside his room turned slowly in the silence between them.\nThen he stepped back from the door. Not closing it. Just making room.\nWord count: 943','\n',char(10)),974,1,1,NULL,'2026-04-17T05:01:23.258Z','2026-04-17 05:01:23','2026-04-17 05:01:23','2026-04-17T05:05:00.000Z',1,NULL);
INSERT INTO "chapters" ("id","novel_id","chapter_number","title","content","word_count","is_premium","is_published","audio_url","published_at","created_at","updated_at","scheduled_release_at","part_number","season_id") VALUES(451,57,12,' The Quiet Next Door',replace('She did not sleep well the night before Tunde left.\nShe knew he was leaving because Adaeze had messaged her two days earlier, brief and factual the way her messages tended to be. He got a short-term room in Yaba. Moving Saturday. I think it is better for him to start somewhere new. Ngozi had read it three times and replied with a single word. Okay.\nSaturday arrived the way difficult days arrive, looking exactly like any other day until you are inside it.\nShe was on the balcony when she saw Adaeze come through the gate at nine in the morning. She was dressed simply, the same large bag from the cafe, a pair of flat sandals. She knocked on the door of Flat 9 and it opened immediately, as though Tunde had been standing on the other side of it waiting.\nNgozi went downstairs.\nShe did not plan to help. She simply found herself in the courtyard as Tunde came through his door carrying a box, the first time she had seen him move through this compound without the earphones, without the downward gaze, without the whole apparatus of a person trying to take up no space. He moved slowly now, with a different kind of quietness, not the hunted quiet of before but something flatter, something that had been through a process and come out the other side of it without recovering all of what it had lost.\nShe held the gate open.\nHe looked at her. She looked at him. The courtyard was behind them and Awolowo Close was ahead and between them was everything that did not have a clean shape yet.\n"I can take that," she said, nodding at the box.\nHe handed it over without a word. It was heavier than it looked. Equipment, she realized. The work that had kept a light on in Flat 9 at two in the morning while the compound slept and did not know him.\nThey walked to the waiting Keke at the roadside. Adaeze came behind with a second bag. Three trips in total. Not much for eleven months of a life. Ngozi did not count the trips. She just carried what she was given.\nWhen the last bag was loaded, Tunde stood on the pavement outside the gate and looked back once at Compound 14. She could not read what was in his face when he looked at it. She was not sure she was meant to.\n"Where in Yaba?" she asked. She did not know why she asked. She was not going to visit.\nHe named a street. She did not know it.\n"Will you be okay?" she said.\nHe considered the question the way he seemed to consider most things, fully, without hurry. "I don''t know yet," he said.\nIt was the most honest answer anyone had given her in months.\nAdaeze came out of the gate and put a hand briefly on Ngozi''s arm. No words. The Keke engine started. The two of them climbed in and the compound swallowed the sound of it slowly as it rounded the corner and was gone.\nShe went upstairs.\nShe sat at her desk for a long time without opening her phone. The compound moved through its Saturday morning below her window. Mama Chidi''s voice. The gate. The five note whistle. All of it exactly as it had always been.\nShe opened her camera.\nThe room behind her was not arranged. No ring light. No borrowed aesthetics. Just the ordinary wall and the ordinary light coming through the curtain she had never thought to consider as a character. She pressed record and looked at herself in the small rectangle of the screen for a moment before she spoke.\nShe told it plainly. Not a survivor story. Not a call to action. Just what had happened, what she had done, what it had cost someone real. She said Tunde''s name. She said she had shared something without knowing whether it was true and that people had built a fire from what she gave them and she had watched it burn and felt good about herself while it was burning. She said she was not posting this for reach. She said she did not know if anyone would see it or believe it or if it would change anything for him, whose name was already attached to a story he had never written.\nShe said she was leaving it up.\nTwo minutes and eighteen seconds. She posted it without a caption.\nThen she put her phone face down and went to the rooftop.\nThe city spread out from Awolowo Close the way it always had, loud and layered and entirely indifferent to the specific grief of specific people moving through it. She sat on the low concrete ledge with her back against the water tank and let the afternoon do what it did.\nBy evening, the post had twelve comments. Not three thousand. Not forty-seven thousand. Twelve people, some of whom she knew and most of whom she did not, who had watched a girl sit with what she had done and not look away from it.\nShe left it up.\nBelow, the curtains of Flat 9 were open for the first time in eleven months.\nThe room behind them was empty.','\n',char(10)),885,1,1,NULL,'2026-04-17T05:02:55.318Z','2026-04-17 05:02:55','2026-04-17 05:02:55','2026-04-17T05:05:00.000Z',1,NULL);
INSERT INTO "chapters" ("id","novel_id","chapter_number","title","content","word_count","is_premium","is_published","audio_url","published_at","created_at","updated_at","scheduled_release_at","part_number","season_id") VALUES(452,21,7,'Other People',replace('Kemi''s mother noticed on Sunday morning, which was predictable. Her mother noticed everything eventually and only pretended otherwise when she was giving Kemi time to arrive at the truth on her own terms.\nThe tell was in the questions. Normally she asked about school generally, the broad parental sweep of "how was your week" delivered while managing three other things at once. This time she was at the kitchen table with both hands around her mug and nothing else in front of her. She asked about revision. About the teachers. About whether Kemi was eating properly during exam season, which was a new addition to the standard list. Then she said, "You seem lighter."\nKemi was pouring cereal and used the action as cover. "Exam stress. Maybe it''s lifting."\n"Maybe," her mother said, in the tone that filed something without closing the folder.\nKemi ate at the counter and looked through the kitchen window at the neighbourhood doing its Sunday work: a boy directing a man reversing a car into a compound gate, a generator running two buildings away, a woman on the far balcony taking down laundry that moved in the morning air like loose pages. She thought about Tobenna and the cat and Saturday afternoon, and then about Canada in the same breath, because those two things were now attached, the way a shadow arrives with the object that casts it.\nHer mother turned a page. The refrigerator hummed against the wall.\n"Kemi." Her mother did not look up. "Whatever it is, it is allowed."\nShe rinsed her bowl and went to her room before the conversation could become something she had to carry all day.\nAt school on Monday, Adaeze was waiting.\nNot in the obvious way. She was on the bench outside the arts block with a container of rice and a look of complete patience, which was more alarming than urgency would have been. Kemi sat. "Tobenna Okafor," Adaeze said, opening her container.\n"Good morning."\n"I have given you the appropriate window. The window is closed." She ate with the composure of someone who had planned this and had no intention of rushing it. "He walked you to the gate on Friday. You were fifteen minutes leaving school. Chisom saw you on Adeleke Street on Saturday afternoon." A pause. "I am your best friend. I am not asking out of interest. I am asking out of jurisdiction."\nKemi looked at the corridor wall. A motivational poster near the water fountain had developed a curl at the corner, the bottom half drooping away from the paint and bowing outward. THE FUTURE BELONGS TO, it read, and then the rest was folded inward, out of sight.\n"It''s something," Kemi said. "I don''t know yet what to call it."\n"Does he know it''s something?"\n"Yes."\n"Does he know about Canada?"\n"Yes."\n"And you know about Kano."\n"Yes."\nAdaeze set down her container and was quiet in the deliberate way that meant she had a full opinion and was choosing what portion to release.\n"I think you are either very brave or mildly foolish," she said. "I have known you long enough to believe both are possible at once." She picked up the container again. "What I will say is that you have been practising leaving since January. And I think this has made you better at being present." A pause. "Which is maybe the whole point."\nKemi looked at her. Adaeze ate rice with complete composure.\n"Thank you," Kemi said.\n"Don''t. I''m going to worry anyway."\nTobenna''s version was less gentle.\nHe told her at the library on Tuesday, arriving slightly late and sitting down without his usual deliberateness, carrying the quality of someone who had not fully set down the previous hour. His friend Emeka had asked him directly after Further Maths. Emeka had known Tobenna since JS1 and had an older-brother authority he had not fully earned but had worn long enough that most people had stopped examining it. He had pulled Tobenna aside and conducted something closer to interrogation than conversation.\n"He asked what I thought would happen," Tobenna said. His pen was in his hand but his notebook stayed closed. "Not in a careful way."\n"What did you say?"\n"That I wasn''t calculating outcomes. That I was spending time with someone I wanted to spend time with."\n"He didn''t find that convincing."\n"He used the word foolish." Tobenna said it without particular emphasis. "He said I was building something with a demolition date already set."\nThe phrase settled between them. It was not wrong. It was the same logic Kemi had run herself, the clean well-structured case for not beginning, and it was not wrong, it simply was not the whole truth of what this was. She had stopped needing it to be wrong in order to continue.\nShe was forming a response when his phone buzzed on the table between them.\nHe looked at the screen. Something moved across his face quickly, a tight and managed thing that she caught only the edge of before it was gone.\n"My father," he said. "There''s a meeting in Kano this weekend. He wants me to come. To see the new school."\nThe library fan turned overhead in slow arcs. Across the room, a junior student reshelved books with the inattentive rhythm of a task being done mostly to be finished. She watched Tobenna look at the phone with an expression that lived somewhere between resignation and something younger than resignation.\n"When?" she said.\n"Saturday."\nSaturday. Their Saturday, the one they had not named because naming it would have made it a thing that could be taken. She turned this over carefully, the way you hold something you have not yet decided how to carry.\n"Okay," she said, because it was. Because it had to be.\nHe nodded and opened his notebook. But he did not write, and she did not either, and in the particular quality of the silence that followed she registered something new: the first faint suggestion, quiet but legible, that 81 days was not only a countdown but a resource, and resources could be spent before you finished deciding how to use them.','\n',char(10)),1031,1,1,NULL,'2026-04-24 03:00:40','2026-04-17 07:18:36','2026-04-24 03:00:40','2026-04-17T06:30:00.000Z',1,NULL);
INSERT INTO "chapters" ("id","novel_id","chapter_number","title","content","word_count","is_premium","is_published","audio_url","published_at","created_at","updated_at","scheduled_release_at","part_number","season_id") VALUES(453,21,8,'Fault Lines',replace('He came back from Kano on Monday and Kemi knew before he said a word.\nIt was not one thing she could point to. It was something in the geometry of how he moved through Tuesday morning: present in every technical sense, asking the right questions in Economics, nodding at the right moments when Chisom ran the study group. But there was a quarter-inch of distance in everything he did, the specific quality of someone who had made a small internal adjustment and was hoping it would not show.\nIt showed.\nShe waited. She gave it Tuesday and Wednesday, which she considered generous. She told herself the Kano trip was big and deserved processing time, that she of all people understood needing space to hold something new before speaking about it. She believed this for thirty-six hours and then stopped believing it.\nOn Wednesday after school she caught him at the back stairwell, the one that led down to the sports field. He was by the water point, filling his bottle, and he looked up when she came around the corner and his expression did the thing she had come to know, the clearing, the layered arrival of whatever he was about to present as his response to her. She waited for it to settle and then said, "Tell me about Kano."\nHe capped his bottle. "It was fine."\n"Tobenna."\n"It was a school. Good building. Bigger than here." He looked at the water point rather than at her. "My father was pleased with it."\n"What did you think of it?"\nA pause that was half a second too long. "It was fine."\nShe felt something tighten in her chest. Not hurt yet. Something preceding hurt, the recognition that she was being managed. He was speaking to her with the careful measured language he used for people he was protecting himself from, and she was not supposed to be that person.\n"You''ve been different since Monday," she said.\n"Exam stress. We''re all different."\n"That''s not what this is."\nHe looked at her then, and she read something in his face that she hadn''t expected: not coldness but exhaustion, the specific exhaustion of someone who had been holding something at arm''s length and was tired of the effort.\n"I stood in the assembly hall of that school," he said, "and I heard the echo. I heard what it was going to sound like in September with students in it. My name on a roll. A locker with a number." He stopped. "It stopped being abstract."\n"I understand that."\n"Do you?" It came out sharper than she expected, sharper than he expected too, she could see him register it. But he didn''t pull it back. "You''ve had months to get used to it. You told me yourself, you''ve been half gone since January. This is new for me. I''m allowed to need a day."\n"I gave you two days."\n"You timed it."\n"I noticed it. There''s a difference."\nHe set his bottle on the ledge of the water point and the plastic knock of it against concrete was loud in the empty stairwell. Below them the sports field ran out to the back fence, the dry-season grass worn to pale yellow in the rectangle where the boys played football every Thursday. The goal posts at the far end had lost their nets. She had never noticed that before.\n"I''m not pulling away," he said. "I''m adjusting."\n"It looks the same from here."\n"Then maybe you''re looking for problems."\nShe was quiet for a moment because she needed to be sure of what she said next. "I''m looking at what''s actually in front of me. Which is you deciding that the way to handle something hard is to turn a few degrees in the opposite direction and hope I don''t notice."\n"And what do you want me to do instead? Pretend seeing that school changed nothing?"\n"No. Talk to me. Tell me what it changed. That is different from going quiet and calibrated and treating me like someone you have to manage."\nSomething moved across his face. A flash of recognition, and underneath it, the brief flicker of someone who knows they have been accurately seen and does not like the timing of it.\n"You want honesty?" he said. "Fine. I stood in that hall and I thought about September and then I thought about this, whatever this is, and I thought about the fact that we are making it harder for ourselves every single week. That every conversation, every Saturday, every hour in the library is another thing we are going to have to subtract later." He was not raising his voice. That almost made it worse. "I thought maybe Emeka was right. Not because I want him to be. Because I was standing in an assembly hall in Kano and I could already feel what July is going to cost and I was afraid."\nThe word landed in the stairwell and stayed there.\nShe looked at him. He was standing with his back to the window, the pale field behind him, and he looked the way people look when they have said the true thing rather than the ready thing and are not certain it was the right time.\nShe wanted to say something that held all of it: that she understood the fear, that she had carried a version of it since January, that none of this was foolishness or miscalculation but simply what it cost to be present in something real. She had the shape of all of it.\nBut he had called it whatever this is.\nAfter everything, in the same breath as admitting fear, he had looked at what they were and called it whatever this is, and that was the thing that found the fault line and ran along it.\n"I know what this is," she said. She picked up her bag. "Let me know when you do."\nShe took the stairs down, not fast, not slow.','\n',char(10)),1001,1,1,NULL,'2026-04-24 03:01:52','2026-04-17 07:19:56','2026-04-24 03:01:52','2026-04-17T06:30:00.000Z',1,NULL);
INSERT INTO "chapters" ("id","novel_id","chapter_number","title","content","word_count","is_premium","is_published","audio_url","published_at","created_at","updated_at","scheduled_release_at","part_number","season_id") VALUES(454,21,9,'What I Meant Was',replace('Three days of careful nothing was apparently his limit.\nKemi was eating lunch alone on Thursday at the far end of the corridor outside the library, a place she had chosen specifically because it was inconvenient to reach, when Tobenna came around the corner with his bag over one shoulder and the expression of someone who had rehearsed the first sentence and was already doubtful about it.\nShe looked at him. He stopped two feet away and did not use the sentence he had prepared.\n"I''m sorry," he said instead. "Not a managed apology. An actual one."\nShe moved her bag off the bench beside her and said nothing, which he accepted as the invitation it was. He sat. Below them, three floors down, the lunch crowd moved through the school compound in its usual patterns. She could hear the tuck shop queue from here, the specific friction of thirty people in a space meant for fifteen.\n"Whatever this is," he said. "I''ve been thinking about those three words since Wednesday."\nShe waited.\n"I used them because I was afraid of the alternative. Of saying what it actually is and having that be a real thing I have said, that exists, that I then have to carry into July." He set his bag on the ground by his feet. "That was cowardice. I want to say it correctly now, if that is still something you''ll hear."\nShe looked at the wall opposite them. Someone had taped a revision timetable to the notice board at the corridor''s end and one corner had come loose, curling forward in the hot air from the stairwell. She watched it move slightly, then still.\n"Say it correctly," she said.\n"This is the most real thing in my life right now. Not despite the deadline. Not in spite of Kano or Canada or the mathematics of it." He was not looking at her but she could hear the effort in his voice, the effort of someone pulling a thing into the light that has been kept carefully indoors. "You are the most honest thing I have encountered in four years of this school and possibly longer, and calling it whatever feels like I''m protecting myself at your expense, and you didn''t deserve that."\nThe corridor fan above them turned. She kept her eyes on the timetable corner, watching it lift and fall with the movement of air.\n"Why Wednesday?" she said.\n"Emeka found me in the library Tuesday night. He said he''d heard things were bad between us and that this was probably for the best. That I should focus on Kano, get ahead of it mentally." He paused. "I sat with that opinion for about twenty minutes before I realised that the reason it made me angry was not because he was interfering. It was because the idea of this being over was the first thing in weeks to make me feel genuinely afraid. Not Kano-afraid. Not July-afraid. Just afraid."\nShe turned and looked at him then, and he was looking at her with the face she knew best, not the controlled expression, not the layered arrival of a managed response, simply his face.\n"I said whatever this is and I hurt you," he said. "I want to know how."\nShe considered not saying it. She had a version of it already formed, a shorter less exposed version that would satisfy the shape of a conversation without giving him the actual thing. She decided against it.\n"I have known what this is since the stairwell," she said. "Since the eighty-three days. I have been sitting with a name for it for two weeks and not saying it because naming it meant it was real, and real things end, and I am already acquainted with enough endings this year." She stopped. "So when you stood there afraid and called it whatever, I heard: she is not worth the precision. After all of this, still unnamed."\nHe was very still.\n"That''s what it sounded like to me," she said. "I''m not saying that''s what you meant. I''m saying that is what it found."\n"It''s not what I meant," he said. "What I meant was: I love this so much I don''t have a word big enough and small words feel like a betrayal of it." He paused. "Which I understand is not better. I understand that is still me failing to find the language. But I want you to know what was underneath it."\nShe looked at the timetable corner lifting again in the stale corridor air. Below them, someone on the ground floor laughed at full volume, a burst of it carrying upward, and then it was gone.\n"There are fifty-nine days," she said.\n"I know."\n"I don''t want to spend them managing what this is. I want to spend them inside it."\n"So do I." His voice was quiet and direct and without performance. "I want to get it right for fifty-nine days. I want it to be a thing I did well. Not something I protected myself through."\nShe thought about January, about the long months of practising distance, of keeping everything at arm''s length to avoid the cost of caring about a place she was leaving. She thought about the library and the darkness and the one phone torch and the thing that had cracked open in three hours of honest conversation. She thought about everything she had learned in the weeks since that she had not known before, about herself, about what she wanted, about the distance between having feelings and being willing to claim them.\n"I named it on the stairwell," she said. "When you showed me the number. I just didn''t say it out loud."\nHe turned toward her slightly on the bench. The corridor stretched behind them both, empty and long.\n"Say it now," he said.\nThe timetable corner lifted one last time in the hot still air of the corridor, and held.','\n',char(10)),994,1,1,NULL,'2026-04-24 03:03:27','2026-04-17 07:21:02','2026-04-24 03:03:27','2026-04-17T06:30:00.000Z',1,NULL);
INSERT INTO "chapters" ("id","novel_id","chapter_number","title","content","word_count","is_premium","is_published","audio_url","published_at","created_at","updated_at","scheduled_release_at","part_number","season_id") VALUES(455,21,10,'Fewer Weeks',replace('The valedictory notice went up on the SS3 board on Monday morning, and Kemi stood in front of it long enough to be late for first lesson.\nIt was not complicated information. Date, time, dress code, a note about the collection of leaving certificates after the ceremony. The school produced this notice every year. Somewhere in the archive was probably a version from the year Kemi was in JS1, presiding over girls she had not yet known, who were now scattered across universities and cities she could not picture. It was a routine document. She photographed it and kept walking.\nShe sent the photo to Tobenna without a message. He replied: June 28th. She typed yes. He typed four weeks. She locked her phone and went to Biology.\nIn Chemistry, Mrs. Obiageli returned their last graded practicals with the small speech she gave every year about the importance of results. Kemi had heard it enough times to anticipate it by sentence. She took her report, folded it into her textbook, and understood it was the last one.\nThe thing about the final weeks of a school year was that the building did it to you from every direction. The JS1 students were louder than usual in the corridors, running on the restored energy of people who had survived their first full year and were not yet accustomed to it. The notice board outside the principal''s office had been cleared for end of term certificates. The Economics teacher was already talking about next session in the distracted way of someone mentally reorganising for new students. The school was processing its own ending with complete institutional efficiency, and Kemi moved through it like someone in a building that was folding quietly behind her. Everything that had seemed permanent was suddenly made of paper.\nShe found Tobenna at the water point near the east stairwell at lunch. He was turning something small in his hand and held it out when she arrived. A bottle cap. Pale green, bent slightly along one edge.\n"From where?" she said.\n"My Kano school uniform arrived this morning. My mother washed it before I came downstairs. This was in the basin with it, from a button on the breast pocket. Sprite, apparently. I have no idea how it got there." He looked at it in her hand. "I don''t know why I brought it to school."\nShe turned it over. The bent edge caught the stairwell light in a thin line. The object was so small and so inconsequential that carrying it across two bus stops and three stairwell flights said something he had not said in words.\n"I found my winter coat this morning," she said. "My mother ordered it months ago without telling me. It was boxed in her room with my name written on the lid in her own handwriting. Not a label. Her actual handwriting, careful, the way you write on something you don''t want lost." She returned the cap to him. "The coat is built for somewhere that is not here. Wrong in every direction in this heat and completely necessary in six weeks."\nHe closed his hand around the cap. She watched him, holding something that was not the thing it stood for but had come bearing it.\nThey went out to the back field, which sat empty at midday, the pavilion quiet and the pale dry grass stretching all the way to the fence where a row of casuarina trees grew too close together, their thin branches interlocked into a single continuous canopy. The groundskeeper had left a rake propped against the pavilion wall. It cast a long thin shadow across the concrete steps.\nKemi sat on the low pavilion step. Tobenna sat beside her. A pigeon moved along the top of the fence with great purpose and then stopped and stood with complete vacancy. The midday heat pressed down without wind.\n"What happens after?" she said. "Not the logistics. I mean to us. Do we say we''ll stay in touch and then spend the next year finding out what that actually costs at a time difference of six hours?"\nHe was quiet for a moment that was thought rather than avoidance.\n"I don''t want to make promises in July that I haven''t tested," he said. "I know that''s not the comfortable answer."\n"It''s the honest one. More useful." She looked at the interlocked tree line. "I just want us to be accurate. Not inflated. Not minimised."\n"It is the best thing that has happened to me in this school." He said it without decoration. "I want to say that plainly before July makes it harder. This is not a manageable amount of feeling to compress into messages across a time difference. If we try to hold it exactly as it is, I think we end up grieving something we cannot keep. But if we let it become what it actually becomes, honestly, without forcing the shape, I think something real survives."\nShe thought about her mother''s handwriting on the box lid. About a Kano school uniform dripping in a basin that morning. The way things became real before you had finished deciding how to hold them.\n"I think so too," she said.\nThe groundskeeper came around the far end of the field, retrieved the rake from the pavilion wall without looking at them, and walked back the way he had come. They watched until the path turned and he was gone.\n"I want to do something next Saturday," Tobenna said. "Somewhere neither of us has been. Something I can remember when I think about this time. Not school, not revision, not a goodbye. Just a day that belongs to itself."\nShe thought about the suya courtyard, the cold Fanta, the afternoon that had held everything without asking for more. Three Saturdays left after this one.\n"Where?" she said.\n"I don''t know yet." He turned the bottle cap once in his palm and pocketed it. "I''ll find somewhere good."','\n',char(10)),998,1,1,NULL,'2026-04-24 03:04:30','2026-04-17 07:23:05','2026-04-24 03:04:30','2026-04-17T06:30:00.000Z',1,NULL);
INSERT INTO "chapters" ("id","novel_id","chapter_number","title","content","word_count","is_premium","is_published","audio_url","published_at","created_at","updated_at","scheduled_release_at","part_number","season_id") VALUES(456,21,11,'The Last Real Day',replace('Tobenna arrived at her gate at nine in the morning with two sachets of pure water and the expression of someone who had spent the week preparing something and was ready to find out if it had been worth the planning.\n"Where are we going?"\n"You''ll see."\nShe had trusted him further and over longer distances than this. She went.\nThe danfo to Lekki moved through Saturday morning with the particular rhythm of Lagos traffic before the heat found its full weight: not smooth but sustained. They sat near the back, window open, the morning air coming in warm and direct. Beside Kemi, a woman held a carton of eggs across her knees with the focused calm of someone whose entire day depended on them arriving whole. Tobenna''s shoulder was close enough that its warmth was specific against the general heat of the bus. She did not adjust away. There was no reason left to.\nShe saw the Conservation Centre sign through the window and understood.\n"You''ve never been," Tobenna said. He was watching her face.\n"I''ve passed it a hundred times."\n"That''s exactly why."\nThe ticket booth had a hand-painted wooden awning, the green fresh and even. A note in a glass case beside the trail map read: PLEASE DO NOT FEED THE MONITOR LIZARDS. She considered this for a moment and decided it improved the day.\nHe paid. She noted this and said nothing, which was itself a kind of sentence in the language they had built between them.\nThe lower forest path ran above dark water on a narrow boardwalk, the mangrove roots rising below in angled formations, each one reaching upward with the patient effort of something working against a slow and constant pull. The light arrived here in pieces rather than whole, filtered green through layered canopy. The air was cooler and still. Above them, birds moved in small certain arcs through the upper branches.\nThen the walkway.\nIt appeared at the end of the forest path: a straight run of mesh and wooden planking rising into the upper canopy and curving out of sight in a long slow arc. At the first step, the planks gave with a subtle and responsive shift, and the entire structure moved with the quiet awareness of something suspended. Not instability. Awareness.\nThe walkway was not wide enough for two people to walk fully side by side without contact. She was fairly certain he had known this.\nThey stopped at the midpoint viewing platform, a widened section with a low wooden railing, and she looked out across the top of the canopy. Through breaks in the trees, the Lagos skyline was visible in the middle distance, pale and specific against the morning.\n"I had a plan for this year," Tobenna said. He was beside her, both forearms on the railing, looking outward. "Prefect. Strong results. A clear and recognizable shape in that school."\n"And instead?"\n"Instead I found out that mattering to a place and mattering to a person are entirely different skills. The second is harder and the one I was actually missing." He paused. "I would have made it to July without knowing that. I think I would have graduated and moved and never asked the question at all."\nShe watched an egret move across the upper treeline in a long white arc, deliberate and unhurried.\n"I came back to school in January already practising being gone," she said. "Holding everything at a distance so the leaving would cost less." She turned toward him. "I nearly finished the year without being inside it."\n"But you were in it," he said. "The library was dark and you were completely in it."\nShe looked at his face in the green filtered light. Open and direct, no layered arrival, no managed expression. Simply Tobenna, standing somewhere neither of them had stood before, giving her the accurate version of himself.\nThey walked the rest of the walkway to the far platform and back, talking in the easy way that had become its own kind of ordinary. He maintained a considered position on the monitor lizard note and its philosophical implications for the broader question of instructions nobody expected to need. She told him about a junior student she had watched on Thursday arranging stationery by height with grave precision, and the private kinship she had felt. He said his mother had already sourced a new doormat for the Kano house, which had unsettled him in ways he was still working through. She laughed and the walkway registered it, and she did not stop.\nOn the danfo back, she sat with the window open and the afternoon moving through it. Tobenna was quiet beside her. Not the managed quiet of the Kano week. The quiet of someone who had said what he needed to say and was now simply present inside what remained.\nThe day was already becoming past tense. Not unhappily. The way things that were good become memory without needing to be mourned first.\nAt her gate the sky had gone the deep amber of a Lagos Saturday evening. Tobenna reached into his pocket and held out the bottle cap, the green one, bent at one edge.\n"Keep it," he said. "You have a coat with your name on the box. I have a uniform I haven''t worn yet. This came from outside all of that."\nIt sat in her palm, small and bent and specific.\nShe closed her fingers around it. The things she could have said were either too large or too small for the gate and the evening and the way he was looking at her, with the face she had learned better than she had planned to.\n"Tomorrow," he said.\n"Tomorrow," she said.\nShe went inside.','\n',char(10)),960,1,1,NULL,'2026-04-24 03:06:03','2026-04-17 07:24:54','2026-04-24 03:06:03','2026-04-17T06:30:00.000Z',1,NULL);
INSERT INTO "chapters" ("id","novel_id","chapter_number","title","content","word_count","is_premium","is_published","audio_url","published_at","created_at","updated_at","scheduled_release_at","part_number","season_id") VALUES(457,21,12,'Same Uniform',replace('The valedictory ceremony ran for two hours and twenty minutes, and at no point during it did Kemi cry, which surprised her.\nShe had prepared for it. The tissue was in her blazer pocket from the morning and she had given herself permission to need it. But as the principal moved through his address with careful measured cadence, and the choir performed with the earnest precision they reserved for an audience that included parents, and names were called one by one across the stage, nothing arrived that required the tissue. Only a clean and specific calm, the kind that settles when something you have been moving toward for a long time is finally directly beneath your feet.\nShe received her leaving certificate in its blue folder and shook the principal''s hand and descended the stage steps and as she did she looked across the hall and found him.\nTobenna was in the third row from the left, which was where he always sat, three rows from wherever she was. He caught her eye as her foot found the last step. He did not smile yet. He only looked at her with the expression she had learned to read the way you learn a language by living inside it: the steady layered attention that meant he was paying complete account to what he saw.\nShe walked back to her seat and the ceremony continued.\nAfter, the compound became its own particular event. Parents moved through the crowd with phones raised. Students clustered in configurations for photographs that would circulate for the rest of the week. Near the admin block, a group of girls were crying together with the generous volume of people who had collectively decided this was the moment and were honouring it fully. The principal stood near the gate shaking hands with the satisfied expression of a man who had successfully closed an annual account.\nAdaeze found her first. She came through the crowd with her own certificate and her composure at full capacity, which was how Adaeze handled strong feeling: not suppressed but organised. They sat on the low wall near the water fountain. Adaeze said, in order and without allowing interruption: that she was proud of Kemi in the specific way you were proud of someone who had grown toward rather than away from themselves. That she would visit Canada within two years, not as aspiration but as commitment. That the Tobenna situation had turned out to be brave after all, and she was willing to revise her earlier assessment accordingly. Kemi listened and then said she was going to miss Adaeze precisely and specifically, not as a general statement about school but as a fact about that particular person. Adaeze nodded, stood, straightened her uniform, and walked back into the crowd without ceremony because that was exactly who she was.\nTobenna found her at the east stairwell, the one that opened to the sports field. She had gone there for a few minutes of space and he had done the same, which said something about how well they had learned each other. They stood at the bottom of the steps, the field beyond the door stretching out in pale dry grass to the casuarina fence line, the branches interlocked above the posts into a single continuous shade.\nShe was still holding the blue folder.\n"How are you?" he said.\n"I don''t know yet. You?"\n"The same." He looked at the field. "I was thinking during the ceremony about SS1. First week. I was in this uniform and I had no idea where anything was. I asked three people for directions to the library."\n"What did they tell you?"\n"Two wrong answers and one correct. I didn''t know which was which so I tried all three."\n"Did you find it?"\n"Eventually." Something settled in his expression, simple and without performance. "It turned out to be worth knowing where."\nShe held the two meanings of that without separating them.\nThe noise of the compound filtered down from above: voices, camera sounds, a car reversing under instruction. The field held its quiet against all of it.\n"I''m going to remember you as someone who told me the truth," she said. "Every time. Even when it was the complicated version."\n"That''s a good thing to be remembered as."\n"It''s the best thing." She paused. "I''m going to remember all of it. The library. The stairwell. The suya courtyard. The walkway. Every piece."\n"So will I." He stood with his weight even, blazer open, the ceremony folder in one hand. "I''m going to remember you as the person who taught me to ask better questions about myself." He stopped. "That sounds like a speech."\n"It sounds like the truth."\n"Then I''ll keep it."\nThey stood in the stairwell, the compound above and the field below and twelve weeks between the library and here. She reached out and straightened his collar, which did not require straightening. He let her. She withdrew her hand.\n"Take care of yourself in Kano."\n"Take care of yourself in Canada."\nOne of them would send the first message. She did not yet know who. She thought it would be him, arriving at a strange hour because of the time difference, and that she would already be awake.\nShe went up the stairs and back into the noise.\nAt home by four, she laid the uniform on her bed: the white collar, the navy fabric, the school crest she had worn since JS1. She pressed the fold flat with both hands.\nShe thought about September. The girl who had put this uniform on then had already been practising being gone, holding everything at a careful distance, moving through the year like someone in a building she was preparing to leave. Then a power cut. Three hours. One phone torch between them.\nShe had not predicted any of what followed. She would not have subtracted a day of it.\nThe bottle cap was in her blazer pocket. She set it on the windowsill, where it would catch the morning when she packed.\nShe left the uniform on the bed and went to find her mother.','\n',char(10)),1026,1,1,NULL,'2026-04-24 03:09:14','2026-04-17 07:26:45','2026-04-24 03:09:14','2026-04-17T06:30:00.000Z',1,NULL);
INSERT INTO "chapters" ("id","novel_id","chapter_number","title","content","word_count","is_premium","is_published","audio_url","published_at","created_at","updated_at","scheduled_release_at","part_number","season_id") VALUES(458,30,7,' Danfo Don''t Stop',replace('The deadline passed at midnight and Seun slept through it without meaning to, which was not the defiant choice he had imagined making but was perhaps more honest. He woke at five in the morning to the sound of his mother already moving in the kitchen, the low clank of a pot, the smell of something being reheated, and he lay on his back in the dark and made the decision he had been standing at the edge of for six days.\nHe was going to work the route.\nNot Ruka''s route. Not the union''s route. His route, the one he had learned from the inside out, the one that had his rhythm and his knowledge baked into every passenger interaction and every traffic pattern. The plan needed three more weeks of solid collection to hit the school fees number. Three weeks was not forever. He would work quietly, no confrontation, just a conductor doing his job, and he would see how long the space held before something filled it.\nHe told himself this was strategy.\nHe knew it was also stubbornness. He was sixteen and his back was against a wall and sometimes when your back is against a wall the only move that feels like yours is the one that pushes forward.\nHe was at the park by six-fifteen. Earlier than usual. He wanted to be settled in the bay before the morning rush built, before Olamide''s bus arrived, before anyone had cause to notice him as anything other than a conductor starting his day.\nUncle Femi was already there, standing beside the bus with a toothpick in his mouth, watching Seun approach with an expression that said he had expected this and had not decided yet what to do about it.\n"You know what today is," Uncle Femi said.\n"I know."\nThe old man removed the toothpick. He looked at it, then at Seun. "I can''t stop you boarding my bus. But I want you to understand that if trouble comes, I have a vehicle I need to protect. You understand what I''m telling you."\nSeun understood. Uncle Femi was not abandoning him. He was being honest about the limits of his loyalty, which was more than most people offered. "I understand."\n"Don''t do anything that makes a scene."\n"I won''t."\n"Just collect fares and keep your head down."\n"Yes sir."\nUncle Femi looked at him one more time with that same expression, then put the toothpick back in his mouth and climbed into the driver''s seat. Seun swung onto the door frame.\nThe first two runs were clean.\nThe morning rush was thick and the passengers came in the usual flow and Seun worked them with the quiet efficiency of someone who needed nothing to go wrong. He called fares without his full voice, softer than usual, and made change fast and kept his eyes moving across the park the way they always did. He saw Olamide''s bus in the bay. He did not look at it longer than necessary.\nThe third run was where it changed.\nThey were loading passengers for the return from Ojota when Seun saw them. Two young men moving through the park with the specific purposeful looseness of people who were not there to catch a bus. They were not boys exactly, early twenties maybe, wearing plain clothes that were plain in the way a choice was plain, deliberately unremarkable. One of them was chewing something. Both of them were looking at Uncle Femi''s bus.\nSeun kept his face neutral and his hands moving, taking fares, counting change, because the moment you showed that you had noticed was the moment the thing that was about to happen arrived faster.\nThey reached the bus as Uncle Femi was pulling out of the bay. The one who wasn''t chewing put his hand on the door frame, just above Seun''s hand, and looked up at him with a mild expression.\n"Step off," he said quietly. Not loud. Conversational.\nSeun looked at him. The park moved around them. People loading other buses. Hawkers passing. The full indifferent machinery of Oshodi morning.\n"I''m working," Seun said, equally quiet.\n"You''re not registered." The man''s voice had no heat in it. That was the thing that made it serious. "Step off the bus and we won''t have a problem."\nUncle Femi had stopped the bus. Seun could see the old man''s eyes in the rearview mirror, still and watchful, a man calculating his vehicle''s safety in real time.\nThe passengers inside the bus had gone quiet the way passengers went quiet when something was happening that they wanted no part of.\nSeun stepped off the bus.\nHe stepped off because he had done the calculation in the two seconds available to him and the calculation said that a scene on the bus involved Uncle Femi''s livelihood and the passengers who had nothing to do with any of this. He stepped off but he did not step back. He stood on the ground and looked at the man who had told him to and waited.\nThe second man, the one who had been chewing, moved around the front of the bus and came to stand slightly behind Seun''s left shoulder. Not touching. Just there. The geometry of it was clear enough.\n"You work when you''re registered," the first man said. Still quiet. Still mild. "Those are the rules of this park."\n"I''ve been working this route for two years."\n"Then you know the rules better than most." He tilted his head slightly. "Go home. Sort your papers. Come back correct."\nBehind Seun, the second man shifted his weight and the shift made a small sound and Seun felt it in his spine before he heard it.\nHe did not turn around.\nHe stood there on the Oshodi tarmac with the morning sun beginning to find its heat and the park noise filling the space around this small quiet confrontation that nobody nearby was looking at directly but everyone could feel. He thought about the notebook. He thought about three more weeks. He thought about a plan that was supposed to be solid and the specific texture of the wall it had run into.\nThen Uncle Femi''s voice came from the window, low and careful. "Seun."\nJust his name. But the way the old man said it carried everything that needed to be said. It carried the bus and the passengers and twenty years of working a route and knowing when a line existed that you did not cross in front of witnesses.\nSeun stepped back from the door.\nThe first man looked at him without triumph, which was almost worse than triumph would have been. He lifted his chin in something that was not quite a nod and then both of them turned and moved back into the park the way they had come, unhurried, their job done.\nUncle Femi pulled the bus out of the bay.\nSeun stood on the tarmac and watched it go. Around him the park resumed itself fully, the noise and motion snapping back into place like nothing had parted it. A hawker brushed past him with a tray of chilled drinks. Two conductors argued about something near the union office. The sun pressed down on the top of his head with the flat certainty of a hand.\nHe had worked the route for one morning.\nHe had three weeks of collection to make and zero days left to make it the way he had planned.\nAcross the park, Olamide''s bus was pulling out of the Ojota bay, full of passengers, and Seun watched it until it turned the corner and was gone.\nHe put his hands in his pockets and found them empty.','\n',char(10)),1290,1,1,NULL,'2026-04-17T07:40:27.252Z','2026-04-17 07:40:27','2026-04-17 07:40:27','2026-04-17T08:00:00.000Z',1,NULL);
INSERT INTO "chapters" ("id","novel_id","chapter_number","title","content","word_count","is_premium","is_published","audio_url","published_at","created_at","updated_at","scheduled_release_at","part_number","season_id") VALUES(459,30,8,'What the Money Is For (Rewrite)',replace('The notebook had forty-three pages.\nSeun had bought it from a stationery kiosk near his school the same week he stopped attending, a small irony he had noticed at the time and set aside without examining. It was the cheap kind, the cover thin cardboard, the pages slightly translucent. He had made it hold everything important anyway.\nThe first page was a single number written large in the center, the way you wrote a name you were afraid of forgetting.\n14,000.\nJSS3 resumption fees, one full term, Community Secondary School Mushin. He had gotten the figure from his form teacher, Mr. Adeyemi, on the last day he attended, standing in the corridor with his school bag on one shoulder and the specific shame of a boy who already knew what was coming.\n"Your mother knows?" Mr. Adeyemi had asked.\n"She knows I''m taking a break," Seun had said.\nMr. Adeyemi had handed him the fee schedule without another word. That was four months ago.\nSeun sat now in the narrow strip of shade between the backwall of the house and the fence, the one spot that caught a cross-breeze in the afternoon, the notebook open in his lap. He ran his finger down the income log without needing the numbers. He knew them already. Average net per day, two thousand three hundred naira on a good week. Six months of this, managed carefully, had produced eleven thousand two hundred naira.\nTwo thousand eight hundred left to close the gap.\nHe turned to the page he had never shown anyone, titled at the top in small letters: after school.\nThe plan was not complicated but it was specific, because he had learned early that vagueness was where plans went to die. Two years of conducting after his certificate. Then a partnership with a driver he trusted. One bus. Year one conservative, numbers that accounted for breakdowns and bad weeks. Year two better. Year three was the year the word fleet became possible to write without feeling like a joke.\nHe turned pages slowly.\nThere was a page with the names of three drivers he had assessed informally over the past year, observations they didn''t know about, how they treated their conductors, whether they padded running costs to skim from their conductor''s cut. Uncle Femi did not do this. Most others did.\nThere was a page with route analysis. Four corridors beyond his own, passenger volumes estimated by time of day, places where gaps existed between what was being offered and what passengers actually needed.\nThen a half-page that was not numbers.\nIt was a list that began with one word.\nMama.\nBelow it, three things. Rent paid without her having to mention it. A sewing machine that actually worked, not the one currently held together by a wire on the left tension arm. School fees for Tokunbo.\nTokunbo was eight. She was in primary three and asked questions the way other children breathed, constant and precise. She asked why the power went out at the same time every day. She asked what the difference was between a road and a street. She was gathering data for answers she intended to have eventually.\nHis mother worked as a seamstress from the front room, taking in alterations from neighbors. She was skilled in the way people who learned a thing out of necessity were skilled, thoroughly and without sentiment. She did not love sewing. She was good at it.\nShe had wanted to be a teacher. Seun had learned this not from her but from an aunt who mentioned it once in passing, not realizing she was handing him something he would turn over for years. His mother had the marks for the College of Education at nineteen. Then his grandmother got sick and the fees became impossible and the place was deferred and then it was just gone.\nShe sewed because it was what was available.\nThe practicality was what made her hard to argue with. When she said Seun should be in school she was not speaking from naivety about money. She had concluded from a full understanding of how the world worked that the street was a ceiling you hit sooner than you expected.\nShe was not wrong.\nThe part she didn''t have information to understand was that Seun already knew the street was a ceiling. He was not trying to live on it. He was using it as a floor, a temporary floor to stand on while he built the staircase.\nHe had tried to explain this once. They were eating together, the three of them, and his mother had said something quiet and sideways about a neighbor''s son who had just started university. He had put his spoon down and said carefully that the route was not the destination but the vehicle.\nHis mother looked at him for a long moment.\n"A danfo," she said, "is not a vehicle for going somewhere better. It is a vehicle for going in circles."\nTokunbo had looked between them with her data-gathering eyes. Seun picked his spoon back up and said nothing, which his mother understood correctly as the thing it was.\nHe closed the notebook now and listened to the compound sounds around him. A radio from the next flat. The distant complaint of a generator down the street. He got up and went inside because Tokunbo had asked him yesterday to help with her homework and he had said yes, and of all the things currently pulling at him, being the person who showed up when his eight-year-old sister asked him to was the one thing that still felt completely simple.\nShe was at the table with her arithmetic book open and a pencil held upright in her fist like a flag.\n"You''re late," she said.\n"I know."\n"I already did three by myself."\n"Show me."\nShe showed him. They were all correct. He told her so and she nodded as though this confirmed something she had already suspected.\nFor the next forty minutes he did not think about the route or the levy or Olamide. He sat with his sister and worked through problems that had clean answers, and the cleanness of it was a thing he hadn''t known he needed until he was inside it.\nOutside, the generator coughed and steadied and the lights came on, and his mother moved in the front room with the sound of the sewing machine starting up, and Seun stayed at the table until all the problems were done.','\n',char(10)),1088,1,1,NULL,'2026-04-17T07:44:44.680Z','2026-04-17 07:44:44','2026-04-17 07:44:44','2026-04-17T08:00:00.000Z',1,NULL);
INSERT INTO "chapters" ("id","novel_id","chapter_number","title","content","word_count","is_premium","is_published","audio_url","published_at","created_at","updated_at","scheduled_release_at","part_number","season_id") VALUES(460,30,9,'The Boss''s Boy',replace('Seun was not looking for Olamide when he found him.\nHe had come to the park to talk to Chukwu about a possibility he had been turning over since the previous night, a informal arrangement with a driver who operated outside Ruka''s corridor, further east, routes that had not yet been absorbed into the union''s geography. It was a thin possibility, the kind that required three things to go right simultaneously, but thin was what he had.\nChukwu was not at his usual spot.\nOlamide was.\nHe was sitting on the low concrete block where Chukwu normally ate his groundnuts, and he was not alone. There was a boy beside him, small, maybe nine or ten, wearing a school uniform that had been washed so many times the color had made a decision to become something other than what it started as. The boy was asleep against Olamide''s arm with the complete physical trust of a child who had fallen asleep in this exact position before and expected to be held.\nOlamide looked up when Seun approached. He did not look surprised. He looked like a man who had been waiting for something and had stopped being particular about what form it arrived in.\n"Sit down," Olamide said.\nSeun sat. He looked at the boy. "Yours?"\n"My brother." Olamide adjusted his arm slightly, settling the boy''s weight without waking him. "Emeka. He''s nine."\n"He should be in school."\n"His school is on break this week." A pause. "And next week probably. The fees are behind."\nSeun said nothing. He watched Olamide''s face, which was doing the careful thing it always did now, managing its own expression, but around the edges of it something had loosened.\n"How far behind?" Seun asked.\n"Two terms."\nThe number sat there.\nSeun thought about his own notebook. His own fourteen thousand. The way the number had lived in his chest for four months like a second heartbeat. He thought about what two terms meant, not as money but as time. Two terms of a child in a uniform that had lost its color going to a school that was running out of patience.\n"My mother had a stroke in January," Olamide said. He said it the way people said things they had said many times, to doctors, to relatives, to themselves at odd hours. The rawness was not gone but it had been handled enough to be portable. "Left side. She recovered most of her speech but her left hand doesn''t work the way it did. She can''t do the plaiting anymore."\nHis mother had been a hair braider. Good enough that women came from two streets away. It had been the household''s main income for as long as Seun had known them. He remembered the sound of it from childhood, visiting Olamide''s house, the low voices of women talking while Mama Olamide worked, the specific intimacy of that front room.\n"The uncle in Bariga," Seun said slowly. "He''s not helping?"\nOlamide made a sound that was not a laugh. "The uncle in Bariga has his own four children and his own three problems. He let us stay in his compound. That''s where his help ends."\n"So you''re the income."\n"I''ve been the income since February." He looked down at Emeka, who had shifted slightly in sleep, one small fist closing around nothing. "I was on a bad route before this. You know the Bariga to Ikorodu run? The driver was skimming. I was taking home less than eight hundred naira on good days. I reported it to the local transport chairman. The chairman and the driver are cousins." He paused. "I had no work for three weeks after that."\nSeun was quiet.\n"Then a man came to me. Said he had a placement on a strong corridor. Good driver, clean bus, union backing from day one. He knew my situation somehow, the hospital bills, Emeka''s fees, my mother''s hand. He knew all of it." Olamide''s jaw tightened briefly. "He mentioned your name. Said the route was currently occupied by someone who hadn''t sorted his union papers. He said it like that. Occupied. Like you were temporary."\n"And you needed the work."\n"I needed the work," Olamide said. "But I also need you to know I told him I would think about it. I went home. I looked at my mother''s hand on the table. I looked at Emeka''s uniform." He stopped. "I called the man back the same evening."\nThe park moved around them. A danfo nosed through the gap between two parked buses and a conductor shouted something cheerful at the driver. Somewhere nearby a phone was playing music too loudly and then wasn''t.\n"Why are you telling me this?" Seun asked.\n"Because you deserve the whole truth. Not just the shape of it."\n"The whole truth is that you knew it was my route."\n"Yes."\n"And you came anyway."\n"Yes."\n"And you let them use you to push me off."\nOlamide held his brother closer, a small unconscious motion. "Yes."\nSeun looked at the sleeping boy. He looked at the uniform. He thought about Tokunbo at the arithmetic table with her pencil held up like a flag and the three problems she had already solved by herself. He thought about how he would feel standing where Olamide was standing, looking at what Olamide was looking at, and a man somewhere offering a phone number to call back.\nHe thought about this carefully because it was important to think about it carefully.\nUnderstanding it did not make it acceptable. That was the thing he needed to hold onto. Because the pull of the story, the mother''s hand and the washed-out uniform and the boy asleep with his fist closed around nothing, was real and it had weight and it worked on Seun the way it was probably designed to work on him by the man who had chosen Olamide specifically. The man knew that Seun would eventually find out the truth. He had sent someone whose truth would be hard to be angry at cleanly.\nThat was the move. That was why it was Olamide and not a stranger.\n"I''m not going to tell you it''s fine," Seun said.\n"I''m not asking you to."\n"What you did put my school fees, my sister''s future, my mother''s rent directly at risk. You knew that and you did it anyway."\nOlamide nodded. No argument. No negotiation.\n"And I understand why," Seun said. "That''s what I hate most about this. That I understand why."\nEmeka stirred, made a small sound, settled again. His uniform collar had twisted and Olamide reached up with his free hand and straightened it with the automatic precision of someone who had done this many times, before school, after sleep, whenever the world needed to see the boy looking cared for even when the care was running on fumes.\nSeun stood.\n"Is he using you for anything else?" Seun asked. "Ruka. Is there more to your arrangement than the route?"\nOlamide looked up. "What do you mean?"\n"I mean are you only a conductor or are you also a set of eyes. Someone who reports back on what I do, who I talk to, whether I''m looking for angles."\nThe pause before Olamide answered was short but it was there.\n"I was asked to keep him informed," Olamide said quietly.\nSeun nodded slowly. There it was. The full architecture of it, finally visible. Not just a body on his route. An instrument. Tuned specifically to the frequency of someone Seun would not immediately close a door against.\n"When you go back and tell him about this conversation," Seun said, keeping his voice even, "tell him the money is still coming. I haven''t decided how yet. But I''m not done."\nHe walked away from the concrete block before Olamide could respond. He moved through the park without looking back, and this time the feeling on his back was different from the last time he had walked away. Less like weight. More like clarity.\nHe understood the whole board now. Every piece and what it was for.\nWhat he did with that understanding was still the question.','\n',char(10)),1363,1,1,NULL,'2026-04-17T07:46:23.357Z','2026-04-17 07:46:23','2026-04-17 07:46:23','2026-04-17T08:00:00.000Z',1,NULL);
INSERT INTO "chapters" ("id","novel_id","chapter_number","title","content","word_count","is_premium","is_published","audio_url","published_at","created_at","updated_at","scheduled_release_at","part_number","season_id") VALUES(461,30,10,'Burn It or Bend',replace('The floorboard came up the way it always did, the left corner first, then the right, then the whole section lifting cleanly because Seun had practiced it enough times that his hands knew the motion without instruction. The envelope was there. It was always there. He had checked it enough times in the last three weeks that the checking had become its own kind of problem, the way you pressed a bruise not because you expected it to stop hurting but because you needed confirmation that it still did.\nHe sat on the floor of his room and opened the envelope and counted the money.\nEleven thousand two hundred naira.\nHe counted it again. The notes were soft from handling, the older ones beginning to separate at the folds. He laid them flat on the floor in front of him and looked at them in the early morning light, and something in him that had been holding a particular shape for four months began, quietly and without drama, to come apart.\nHe had done everything correctly. That was the specific cruelty of it. He had not been careless or lazy or naive in the way his mother feared he was being naive. He had built something real from nothing, with his own hands and his own knowledge, and it had been targeted and dismantled not because it was weak but because it was working. Because a short wide man in a tea-colored kaftan had looked at a sixteen-year-old boy running a clean independent operation and decided that independence itself was the problem.\nHe sat with the money on the floor for a long time.\nThen he put it back in the envelope. He put the envelope back under the floorboard. He pressed the board down until it sat flush and stood up and looked at the wall of his room, which had a calendar on it that his mother had put there, the kind with a different Bible verse for each month, and the verse for this month said something about paths being made straight, and Seun looked at it without feeling anything about it either way.\nHe made a decision.\nNot the one he had been building toward for weeks. Not the careful angled decision of a boy working a notebook, finding routes around obstacles, managing variables. Something different. Simpler and more dangerous and the kind of decision that arrived not from calculation but from the place that existed past calculation, where you had run out of road and the only thing left was to find out what you were made of.\nHe was going to see Alhaji Ruka.\nThe union office was not impressive up close. It was a two-room structure behind the main park with a corrugated iron roof and a wooden door that had warped slightly in its frame, the kind of building that held authority not because of what it looked like but because of what happened inside it. Seun had walked past it hundreds of times. He had never had reason to go in.\nHe went in at half past eight, before the park reached full morning volume, because earlier meant fewer witnesses and fewer witnesses meant fewer versions of this story circulating by afternoon.\nA young man at a small table looked up. "Union business?"\n"I''m here to see Alhaji Ruka."\n"He''s not available."\n"I''ll wait."\nThe young man looked at him the way gatekeepers looked at people who did not have appointments and did not appear to understand why appointments existed. "Your name?"\n"Seun Adeyemi. I work the Oshodi to Ojota corridor. He knows who I am."\nSomething shifted in the young man''s face, barely perceptible, the small recalibration of someone who had just heard a name that carried context. He stood and went through the inner door without further comment. Seun sat in the plastic chair beside the table and put his hands on his knees and breathed carefully.\nHe was not afraid exactly. He was something more precise than afraid, a state of high alertness where everything felt very clear and very close and slightly too bright.\nThe young man came back. "Five minutes."\nAlhaji Ruka was sitting behind a desk that was too large for the room, a broad wooden thing covered in papers that were organized in a way that suggested they were handled often. He was eating kolanut, breaking pieces off with the deliberate patience of a man who ate slowly because he had decided that eating slowly was one of the ways you communicated that your time was your own.\nHe looked at Seun without surprise and without particular interest. The permanent boredom. Up close it was even more complete.\n"The conductor," he said.\n"Yes sir."\n"Sit."\nSeun sat. He had prepared words on the walk over, organized them into an approach, a proposition framed around mutual benefit in the way that Chukwu had once told him was the only language men like Ruka understood. He had the words ready.\nHe did not use them.\n"I can''t pay five thousand naira monthly," he said. "Not now. My savings are committed to school fees and I won''t touch them. But I know the Oshodi to Ojota corridor better than anyone currently working it. Passenger patterns, peak hours, the three pick-up points between the official stops where volume is high but no bus currently serves them consistently. I know which days the checkpoint moves and which mornings the Ketu junction needs an alternate approach. I have two years of operational knowledge about that route that your current registered conductors don''t have."\nRuka broke another piece of kolanut. He did not speak.\n"I''m not asking you to waive the levy," Seun continued. "I''m asking for ninety days. Ninety days to complete my school fees savings while working the route under provisional registration. After ninety days I pay the full monthly levy, same as everyone else. What you get in return is the route running at the efficiency it''s been running at for two years, plus whatever value you place on what I know."\nHe stopped talking.\nThe room was quiet except for the sound of the park outside and Alhaji Ruka eating kolanut with the patience of geography.\nRuka looked at him for a long moment. The boredom in his face did not shift, but something underneath it adjusted slightly, the way deep water moved without showing it on the surface.\n"You came here alone," Ruka said.\n"Yes sir."\n"No driver. No senior conductor. No one to speak for you."\n"No sir."\nRuka nodded slowly, as if this confirmed something he had been evaluating. He set the kolanut down and folded his hands on the desk. "You know why most boys your age don''t come to this office?"\n"Because they''re afraid of you."\n"Because they send someone else. A father. An uncle. Somebody who has standing." He looked at Seun with the first expression that was not boredom, something harder to name. "You have nobody to send."\n"I have myself."\nRuka was quiet for a moment. Then he said, "Sixty days. Not ninety. Sixty days provisional. You work the route under a temporary registration that my office holds. If your collection numbers for those sixty days average above the corridor benchmark, the levy for the first month after provisional period is halved. After that it is full rate." He picked up the kolanut again. "The conductor currently on your bay stays. You work alongside him until the provisional period ends. Then we review."\nAlongside Olamide. Seun absorbed this.\n"And if I miss the benchmark?"\n"Then you pay the levy at full rate starting from day one of the sixty days, retroactively." Ruka looked at him with the mild expression of a man offering terms he had already decided were favorable to himself. "You are a good conductor or you are not. The sixty days will tell us which."\nSeun thought about the notebook. He thought about the numbers he knew without opening it. He thought about walking in here alone with no leverage except information and the willingness to be present.\n"Agreed," he said.\nRuka nodded and reached for a form from the organized papers. He began writing without looking up. "You surprised me," he said, almost to himself. "Most people your age burn the thing or walk away from it. They don''t come and sit down."\nSeun said nothing.\n"That is either very smart or very foolish." Ruka looked up briefly. "We will see which."\nHe slid the form across the desk.\nSeun picked up the pen.\nHis hand was steady.','\n',char(10)),1433,1,1,NULL,'2026-04-17T07:48:10.570Z','2026-04-17 07:48:10','2026-04-17 07:48:10','2026-04-17T08:00:00.000Z',1,NULL);
INSERT INTO "chapters" ("id","novel_id","chapter_number","title","content","word_count","is_premium","is_published","audio_url","published_at","created_at","updated_at","scheduled_release_at","part_number","season_id") VALUES(462,30,11,'Oshodi Reckoning (Rewrite)',replace('The first morning Seun worked alongside Olamide, nobody said anything about it.\nNot Uncle Femi, who moved his bus into the bay and began the day with the focused quiet of a man who had decided not to have opinions about things he couldn''t change. Not Razor, who looked between them with an expression that wanted badly to become a comment and didn''t quite get there. Not the regular passengers, who distributed themselves between the two buses with the pure pragmatism of people whose only concern was getting where they were going.\nOlamide nodded when Seun arrived. Seun nodded back. They worked the bay from opposite ends, two people who knew each other''s rhythms well enough to not collide even without speaking.\nSeun focused on the numbers.\nThe benchmark Ruka had specified was the corridor daily average, net of running costs. It was a number Seun had been exceeding consistently for eight months before the levy crisis. Sixty days was winnable if nothing else went wrong.\nHe was on day eleven when something else went wrong.\nIt started with a passenger named Mr. Fashola. A regular, a civil servant in his late forties, always sat by the window, always paid exact change. On day eleven he climbed into Uncle Femi''s bus, sat down, then climbed back out forty seconds later and walked to Olamide''s bus.\nSeun watched this without expression.\nHe had seen it in smaller increments across eleven days, two or three passengers per run drifting toward the newer bus, not because Olamide was doing anything wrong but because newer felt like better and feeling like better was enough for most people most of the time. Not a flood. A leak. The kind that didn''t look like a problem until you checked the numbers.\nOn day fourteen his daily average was six percent below benchmark.\nHe adjusted his approach. Started meeting buses at the stop before the main bay to load passengers before they reached the point of choosing. It worked for three days. Then Olamide began doing the same thing, not aggressively, just a conductor doing his job well, which was the specific thing that had always made Olamide impossible to be cleanly angry at.\nOn day nineteen Seun came home, opened the notebook, and sat with it for a long time.\nHe needed to do something about Olamide.\nHe found him at the midday lull on day twenty-one, eating jollof rice from a paper plate near the Ojota bay.\n"Your numbers are taking mine," Seun said.\nOlamide looked up. He did not pretend not to understand. "I know."\n"I need to hit the benchmark or the arrangement collapses and I''m back to owing full retroactive levy I don''t have."\n"I know that too."\n"Load from the far end of the bay. Give me the closer position."\n"That''s not how bays are allocated."\n"I''m not talking about allocation. I''m talking about you and me making an arrangement."\nOlamide was quiet.\n"I did something for you three years ago," Seun said. It came out before he had decided to say it, rising from the place he had kept sealed since the day Olamide appeared on his route. "You remember the Adekunle situation."\nSomething moved across Olamide''s face. The Adekunle situation was a thing from when they were thirteen. An older boy. An escalation Olamide couldn''t handle alone. Seun had stepped in and taken a cut on his forearm that was now a thin scar he no longer thought about. It had entered the unspoken ledger between them, the kind of debt that didn''t need naming because both people could feel its weight.\nSeun had never intended to use it.\nHe heard himself using it now and felt something shift in his chest that he didn''t fully like.\nOlamide''s jaw tightened. "You''re calling that in."\n"I''m asking for the far end of the bay. Forty days."\nThe silence between them had a different quality now. Not the heavy silence of two people carrying unsaid things. Something thinner and more final, like a surface that had been under pressure for too long and had just developed its first visible crack.\n"I''ll take the far end," Olamide said quietly.\n"Thank you."\n"Don''t." The word landed with a flatness that was not anger but was what lived on the other side of anger after anger had finished burning. "Just don''t."\nSeun stood there a moment longer, reaching for something to say, an acknowledgment of what it had cost him to use the debt and what it was costing Olamide to honor it. He couldn''t find the shape of it. Every version was either too small for the moment or asked for something he had no right to ask.\nHe walked back to Uncle Femi''s bus.\nThe old man was sitting forward with his eyes fixed ahead, having witnessed the entire exchange with the stillness of someone who knew when to be invisible.\n"You got what you needed?" Uncle Femi asked without looking at him.\n"Yes."\nThe old man started the engine. "There are things that win you the day and cost you more than the day was worth." He pulled out of the bay. "I''m not saying you were wrong. I''m saying know what you paid."\nOver the next nineteen days Seun hit the benchmark.\nNot easily. There were bad days folded into the good ones, days where something in his chest felt like it was running on the wrong kind of fuel. But the closer bay position made the difference at the margins and the margins were where this had always been going to be decided.\nOn day forty his average cleared the benchmark by four percent.\nHe walked out of the union office into the Oshodi morning with a stamped form and a first month levy at fifty percent, as agreed. Still a number that required adjustment in the notebook. But a number he could work with.\nOlamide was crossing the park from the direction of the Ojota bay. He stopped when he saw Seun. They stood fifteen feet apart in the full noise of the park, neither of them moving.\nSeun crossed the distance.\n"The provisional period is done," he said. "Work the bay however you want."\nOlamide looked at him. "How did the numbers come out?"\n"I made it."\nSomething moved through Olamide''s face, complicated and quick. He nodded once.\n"Good," he said. One word, quietly meant, carrying in it everything else that neither of them was going to say standing in the middle of Oshodi motor park on a Wednesday morning.\nSeun nodded back and turned toward Uncle Femi''s bus.\nThe weight on his back had not gone. But it had changed its character, become less like something pressing him down and more like something he was learning to carry without bending.\nWhether the bending had happened earlier, in the moment with the paper plate and the old debt called in, he didn''t let himself decide yet.\nThere was still the last episode.\nThere was still the last thing.','\n',char(10)),1171,1,1,NULL,'2026-04-17T07:50:12.611Z','2026-04-17 07:50:12','2026-04-17 07:50:12','2026-04-17T08:00:00.000Z',1,NULL);
INSERT INTO "chapters" ("id","novel_id","chapter_number","title","content","word_count","is_premium","is_published","audio_url","published_at","created_at","updated_at","scheduled_release_at","part_number","season_id") VALUES(463,30,12,'Yellow Danfo',replace('The school fees were paid on a Tuesday.\nSeun stood at the counter of Community Secondary School Mushin with an envelope that had lived under a floorboard for four months, and he counted out fourteen thousand naira while the school secretary wrote a receipt, and the receipt was a small unremarkable piece of paper that Seun folded carefully and put in his back pocket and did not look at again until he was outside.\nThen he stood on the pavement in front of the school and looked at it.\nHis name. The amount. The date. The school stamp in faded blue ink. He had carried the number this paper represented for so long that having it converted into something physical and official and done felt strange, like a sound you had been hearing so long that the silence where it used to be was louder than the sound was.\nHe put the receipt back in his pocket and went to work.\nHe told his mother that evening.\nNot about all of it. Not Ruka or the levy or the sixty days or Olamide and the debt he had called in and the specific flavor of that moment he was still digesting. Not the men in plain clothes who had stood behind his left shoulder on a morning that felt much further away than six weeks. Not the notebook or the after school page or her name written at the top of a list she had never seen.\nHe told her he had paid the fees. That he was resuming next term. That the break was over.\nShe was at the sewing machine when he said it, hemming something in a dark fabric that required close attention. She did not stop sewing. She finished the seam she was on, which took perhaps forty seconds, and Seun stood in the doorway of the front room and waited.\nThen she stopped.\nShe turned on the chair and looked at him, and her face did the thing it sometimes did where it held too many things at once and none of them came out separately. She looked at him for a long moment.\n"Sit down," she said.\nHe sat in the plastic chair across from the machine.\n"You did this yourself," she said. It was not a question.\n"Yes ma."\nShe was quiet. Outside a car passed. The generator down the street was running, filling the neighborhood with its low continuous sound.\n"I said things about the route," she said.\n"You weren''t wrong."\n"I wasn''t complete either." She looked at her hands in her lap, then back at him. "I saw the route and I thought I was seeing the destination. I didn''t see what you were using it for."\nHe had waited a long time for some version of this. Now that it was here he found he didn''t need it the way he had thought he would. The needing had quietly resolved itself somewhere in the last six weeks, replaced by something quieter and less hungry.\n"I should have explained it better," he said.\nShe shook her head. "You shouldn''t have had to explain it at all. You''re sixteen. You should be bringing me problems, not solving them and keeping the solving to yourself so I don''t worry." She said it plainly, without accusation. "That''s my job. The worrying."\nTokunbo appeared in the hallway behind Seun in her nightclothes, having heard voices and decided this constituted permission to be present.\n"Is something happening?" she asked.\n"Seun is going back to school," his mother said.\nTokunbo processed this. "Which school?"\n"The same one," Seun said.\nShe considered this further. "Did you save enough money?"\n"Yes."\nShe nodded with the satisfied expression of someone whose data had just been confirmed. "I knew you would," she said, and disappeared back down the hallway as abruptly as she had arrived.\nHis mother looked at the empty hallway for a moment and then something in her face let go of whatever it had been holding and she almost smiled.\nHe saw Olamide the next morning.\nThey had been working the bay together for three weeks since the provisional period ended, a returned to parallel operation without the cold geometry of the sixty days, something that was not friendship yet but was no longer its opposite. They spoke when they needed to. They did not avoid each other. It was the fragile thing that came after something broke, not the original object but not nothing either.\nOlamide was loading passengers when Seun arrived. He looked up and said, "Early today."\n"Fees are paid," Seun said. "New term starts in two weeks. I''m building the next number."\nOlamide looked at him. Something moved in his face, genuine and unguarded, one of the first expressions in weeks that had not been managed. "You made it."\n"I made it."\nOlamide was quiet for a moment. Then he said, "Emeka''s school sorted out a payment arrangement. Two terms by the end of the year." He said it the way people reported good news they were still getting used to, carefully, like they weren''t sure yet if they were allowed to be relieved.\n"Good," Seun said.\n"It''s not fixed. But it''s a direction."\n"That''s enough."\nThey loaded their respective buses and the morning began to build around them, the park filling with its familiar noise and motion, conductors calling fares and drivers navigating the tight spaces between vehicles and hawkers moving through with practiced efficiency, the entire complex functioning machine of Oshodi doing what it had always done, indifferent and relentless and somehow, from inside it, almost like a kind of order.\nUncle Femi pulled the bus up and looked at Seun in the rearview mirror with the expression of a man who had watched the last few months from close range and had formed conclusions he was keeping to himself.\nSeun swung onto the door frame.\nHe felt the bus under him, the familiar vibration of it, the door frame under his hand, the morning air beginning to carry its first heat. Below him Oshodi was fully awake and loud, the yellow buses moving in their rows, the whole route stretching away toward Ojota the way it always had.\nThe plan had changed shape. It had been broken into and bent and reassembled with parts he hadn''t budgeted for, and the version sitting in the notebook now was different from the one he had started with in ways that were still becoming clear to him. But it was still there. That was the thing. He had walked through six weeks that were designed to end it and it was still there.\n"Ojota!" he called, his voice going out full into the morning. "Ojota direct! Enter with your change o!"\nThree passengers moved toward the bus.\nHe counted them before they reached him.\nHe was already working.\n\n\nEnd of Yellow Danfo.','\n',char(10)),1148,1,1,NULL,'2026-04-17T07:51:55.624Z','2026-04-17 07:51:55','2026-04-17 07:51:55','2026-04-17T08:00:00.000Z',1,NULL);
INSERT INTO "chapters" ("id","novel_id","chapter_number","title","content","word_count","is_premium","is_published","audio_url","published_at","created_at","updated_at","scheduled_release_at","part_number","season_id") VALUES(470,58,1,' Last Routes',replace('The checkpoint appeared at the Ugbowo junction before sunrise, which meant the bad news had already spread by the time Osaro heard it. Three officials, a laminated order, and the particular silence of a street that has decided to hold its breath.\nHe turned the bike around without a word.\nThe crackdown had been working its way south for six weeks. It started in Lagos, then Ibadan, then like a sickness that does not hurry but does not stop, it arrived in Benin City with clipboards and barrier tape and men who stood in the road like they had been personally offended by motorcycles. Osaro had been watching the news on his uncle''s old television with the sound turned low, tracking the closed routes on a map he had drawn himself, folded and kept inside his left boot.\nHe was seventeen. He could not afford to be surprised.\n"Ugbowo is gone," he said when he got back to the yard.\nIdemudia was crouched beside the second bike, the older one, working something loose near the chain guard with a thin screwdriver. He looked up but did not stop working. He was twenty three and had the kind of face that processed bad news slowly, not because he was slow, but because he was always checking it against something only he could see.\n"Ugbowo," he repeated.\n"The junction. Full checkpoint. They have paper."\nIdemudia set down the screwdriver. He wiped his hands on a cloth that was not clean enough for any wiping and stood. He was taller than Osaro by nearly a full head, broader in the shoulders, with a scar on his left forearm from something he had never fully explained.\n"That leaves us Aduwawa and the back way through Ikpoba Slope," he said.\n"The Slope gets muddy from Tuesday. You know that."\n"I know that."\nThey stood in the yard behind Uncle Ehigie''s compound, where the gate had been broken since February and the two bikes lived under a zinc sheet that leaked in one corner. A rooster that belonged to nobody in particular moved between them without concern.\nUncle Ehigie had owned three bikes once. The third was gone now, sold to cover hospital costs during a bad month that nobody spoke about directly anymore. What remained were these two, a 2009 and a 2011, both kept running through the kind of mechanical loyalty that is really just stubbornness with a wrench.\nOsaro had been riding for his uncle since he was fifteen, first as a learner sitting behind Idemudia, then alone. He kept a notebook. Every fare, every route, every cost of fuel written in careful columns. He had been doing the math for two years, adding the numbers slowly and patiently, like a person building a wall one stone at a time. The figure he was building toward was the cost of a year at Auchi Polytechnic, engineering programme. He had the brochure. He had read it so many times the fold lines had gone soft.\nHe needed four more months of clean riding. Four months without a lost bike, without a bad week, without a checkpoint eating his routes alive.\nIdemudia had no brochure. Idemudia had opinions about brochures.\n"School no be the only door," he had said once, not unkindly, when Osaro mentioned Auchi for the third time in one week. "Some doors, you build them yourself."\nOsaro had not argued. There was no argument that would land. Idemudia had been in this city six years longer, had tried three different angles on life and found them all narrow, and had arrived at a philosophy that was hard to argue against because it had been paid for in actual pain. You did not debate that kind of knowledge. You just made sure it did not become your own.\nThey divided the remaining routes. Idemudia took Aduwawa, which had more stops but rougher road. Osaro took Ikpoba Slope, longer but cleaner, with market traffic picking up in the afternoons.\nBy midday he had done nine runs. Not enough.\nBy three in the afternoon, Osaro was sitting on the low wall outside the Slope market, eating groundnuts from a paper cone and staring at his notebook, when a man came and sat beside him. The man wore a collared shirt on a hot afternoon. He had a briefcase across his knees, the solid kind with two clasps, and he set it down carefully, the way a person sets something down when what is inside carries a value that is not written anywhere.\nHe did not look at Osaro immediately. He bought his own groundnuts from the same seller, ate three, then turned.\n"You are one of Ehigie''s boys," the man said. It was not a question.\nOsaro looked at him.\n"The bikes," the man said. "I know those bikes."\nWord count: 879','\n',char(10)),807,0,1,NULL,'2026-04-18T06:18:50.873Z','2026-04-18 06:18:50','2026-04-18 06:18:50','2026-04-18T06:30:00.000Z',1,41);
INSERT INTO "chapters" ("id","novel_id","chapter_number","title","content","word_count","is_premium","is_published","audio_url","published_at","created_at","updated_at","scheduled_release_at","part_number","season_id") VALUES(471,58,2,'Uncle''s Burden',replace('Uncle Ehigie''s right hand had not closed properly in three years. He could hold a cup, turn a key, button his shirt with patience, but the grip was gone, the real grip, the kind a man uses when he means something with his hands. He never explained what happened. The family had their versions and he had his silence, and everyone had agreed without discussion that the silence was final.\nWhat he had instead of that grip was the compound, the gate that nobody had fixed, the rooster that belonged to nobody, and the two bikes.\nOsaro had come home later than usual that evening. He sat with his uncle on the narrow concrete step outside the main door, where Ehigie liked to be in the early evening with his radio playing something low. The light was going soft and orange across the yard. Ehigie was drinking tea from a tin cup, holding it the careful way he always did now, both hands around the base.\n"Ugbowo junction is closed," Osaro said.\n"I heard." Ehigie lifted his cup. "Tunde from the front street was chased off there by seven this morning."\n"That leaves us Aduwawa and Ikpoba Slope."\n"I know what it leaves us."\nHe said it without sharpness, just the flat weight of a man who has already done the arithmetic and does not need it read back to him. Ehigie was fifty one years old and looked like a man who had been in a long negotiation with life and had stopped expecting a good settlement. His hair had gone grey at the sides in patches, and he wore the same brown slippers every evening because they were the only ones that did not aggravate the swelling in his left ankle.\nThe bikes had come from a period that felt distant now, when Ehigie had a small transport business with four riders working under him. That version of his life lasted three years before it collapsed, not dramatically, but in the slow way things collapse when money and bad luck work together without hurrying. The fourth bike went first, sold to cover a debt. Then the third, for the hospital. Now there were two, and they were not really a business anymore. They were a rope that the family was holding with both hands above something Osaro could not see the bottom of.\n"A man spoke to me today," Osaro said. "At the Slope market."\nEhigie looked at him sideways.\n"He knew the bikes. He knew your name."\n"What kind of man."\n"Collared shirt. Briefcase. He did not say much. He said he knew Ehigie''s boys and then he stopped, like he was waiting for me to ask him something."\nHis uncle was quiet for long enough that the radio filled the space between them, a man talking about roads in a voice too calm for the subject.\n"Did you ask him?"\n"No. I left."\nEhigie nodded slowly. He turned the tin cup in his hands.\n"There are men in this city," he said, "who find people when the road is getting narrow. They wait for the right pressure. When they show up with money, they are not doing you a favour. They are doing a calculation."\nHe did not look at Osaro while he said it. He said it the way a man delivers something he has been carrying and is now setting down carefully at someone else''s feet.\n"I have made mistakes," Ehigie said. "With this hand and before this hand. Some of them I made because a man appeared at the right time with the right number. I thought I was making a decision. I was only choosing between two things that both belonged to someone else."\nThe rooster moved past them in the failing light, untroubled.\n"Where is Idemudia?" Ehigie asked.\n"Not back yet."\nSomething moved across his uncle''s face that was not quite worry and not quite something else. It sat between the two things, heavy and familiar, like a feeling he had carried long enough that it had stopped having a clean name.\nThe truth about the bikes, the thing that Osaro understood and Idemudia chose not to speak about directly, was that they were not just transport. They were what stood between Ehigie and a particular kind of defeat. As long as the bikes moved, the old man had something that was still his, something that still produced, still justified the compound and the gate and the daily effort of getting up.\nIf the bikes stopped, something in Ehigie would stop with them. Osaro believed this the way he believed in the columns in his notebook, quietly and completely, without needing anyone to confirm it.\nHe heard the gate move. Idemudia''s footsteps crossed the yard in the dark, unhurried.\nEhigie did not turn around.\n"He came to you too," he said quietly to Osaro. Not a question. A man recognising the shape of something that has happened before.','\n',char(10)),827,0,1,NULL,'2026-04-18T06:20:13.129Z','2026-04-18 06:20:13','2026-04-18 06:20:13','2026-04-18T06:30:00.000Z',1,41);
INSERT INTO "chapters" ("id","novel_id","chapter_number","title","content","word_count","is_premium","is_published","audio_url","published_at","created_at","updated_at","scheduled_release_at","part_number","season_id") VALUES(472,58,3,'A Man with a Briefcase',replace('Idemudia had met him on a Wednesday.\nHe told Osaro this the following morning while they were checking tyre pressure in the yard, speaking in the flat, careful tone he used when he was deciding how much of a thing to give and how much to hold back. He said a man had stopped him near the Aduwawa roundabout, asked him by name if he was one of Ehigie''s riders, and then said he had work that paid differently from the usual kind.\n"He said it like that?" Osaro asked. "Differently?"\n"That was his word. Differently."\nOsaro crouched beside the rear tyre of the older bike and said nothing. The morning was already hot and the zinc sheet above them was ticking as it expanded in the heat.\n"You did not tell Uncle," Osaro said.\n"You did not tell him everything either."\nThat was true enough to close the conversation.\nThe man found them together on Friday afternoon, which Osaro later understood was not an accident. He was already at the Slope market wall when they arrived, sitting the same way he had sat before, briefcase flat across his knees, buying nothing, watching the road with the patience of someone who has learned that waiting is a skill and not a waste.\nHe was perhaps forty, perhaps older. His collared shirt was a deep blue, clean in a way that felt deliberate in the dust and heat of that road. He had a face that did not give much away, not unkind, not warm, the kind of face that had been trained over years to remain useful without becoming readable. His shoes were leather and had been recently polished.\nHe nodded at them as they pulled up, like he had made an appointment and they had arrived on time.\n"Idemudia," he said. Then, "Osaro."\nThe fact of their names in his mouth sat wrong.\nThey did not sit. Idemudia leaned against his bike and crossed his arms. Osaro stood a half step back, which was not something he had planned but which his body decided on its own.\nThe man did not perform an introduction. He opened the conversation the way a person opens a ledger, directly and without decoration.\n"The two of you run the Aduwawa corridor and Ikpoba Slope," he said. "Before the Ugbowo closure you also ran the junction road. You are losing income every week the crackdown holds. The crackdown will not lift before the end of the quarter. I have been watching the policy cycle for four years and it follows the same pattern. The pressure comes from the top, it moves south, it holds for ninety days, and then it relaxes just enough to feel like relief."\nHe let that sit.\n"I have a delivery," he said. "One trip. Point to point, inside the city. The item travels in a bag. You do not open the bag. You do not ask about the bag. You deliver it to a gate I will show you on a map and you collect your money from the man at the gate."\n"What is the rate?" Idemudia asked.\nThe man said a number.\nOsaro looked at his cousin. Idemudia''s face did not move but something behind it shifted, the way light shifts under water.\nThe number was three times what a full day of clean runs would produce on the Slope. For one trip. Inside the city.\n"Both of us?" Osaro asked.\n"One bike. One rider. The second can follow if it makes you comfortable. But only one person carries the bag."\n"And if we are stopped," Idemudia said. "Checkpoint. Officials."\n"You will not be stopped. The route I give you does not have checkpoints on a Friday evening. I know the rotation."\n"You know the rotation," Idemudia repeated.\n"I know many rotations," the man said simply, without pride, the way someone states a professional qualification.\nOsaro studied the briefcase across the man''s knees. The clasps were brass. There were no markings, no stickers, no scratches that suggested age or heavy use. It was the briefcase of a man who treated his tools carefully because they were important to him.\n"We need to talk," Osaro said.\n"Of course," the man said. He reached into his shirt pocket and produced a card, plain white with a single phone number, no name. He placed it on the wall between them and rested two fingers on it briefly before withdrawing his hand. "I need an answer before Sunday morning. If the answer is no, I respect that and we do not see each other again. If the answer is yes, call that number Friday night and I will send the map."\nHe stood, lifted his briefcase by the handle, and walked back toward the road. He did not look back. He crossed between two danfos and was gone the way water goes, without drama and without a trace.\nThe card sat on the wall between them.\nIdemudia looked at it. Osaro looked at Idemudia.\nThe number on that card was three months of Osaro''s careful columns. Three months, one trip, one bag he was not allowed to ask about.\nThe market continued around them as if nothing had been offered.','\n',char(10)),869,0,1,NULL,'2026-04-18T06:21:16.493Z','2026-04-18 06:21:16','2026-04-18 06:21:16','2026-04-18T06:30:00.000Z',1,41);
INSERT INTO "chapters" ("id","novel_id","chapter_number","title","content","word_count","is_premium","is_published","audio_url","published_at","created_at","updated_at","scheduled_release_at","part_number","season_id") VALUES(473,58,4,' What Idemudia Said',replace('The card was in Idemudia''s pocket before they left the market wall, which told Osaro everything about how the next conversation was going to go.\nThey rode back through Ikpoba Slope in the late afternoon traffic, single file, Osaro behind. He watched his cousin''s back the whole way, the straight spine, the unhurried hands on the bars, and thought about how a person could know someone for seventeen years and still not be able to read the exact shape of a decision forming inside them.\nThey ate at the compound. Rice and stew that their uncle''s neighbour, Mama Osakue, had sent over in a covered pot the way she did on Fridays. Ehigie ate and went inside early. His ankle was bad in the evenings. The cousins sat in the yard after, the light from the kitchen window making a yellow square on the ground between them.\nIdemudia spoke first.\n"Three times the rate," he said. "One run."\n"I heard the man."\n"That is six weeks of what we are pulling now. In one evening."\nOsaro looked at the yellow square of light. A moth was working the edges of it, committed and stupid.\n"We do not know what is in the bag," Osaro said.\n"He told us not to ask."\n"That is the same as knowing."\nIdemudia leaned back in his chair and looked at the sky. There were no stars visible yet, just a deep blue going darker at the edges.\n"Osaro," he said, and the way he said the name had a tiredness in it that was not about the day''s riding. "How long have you been saving?"\n"Two years. Close to."\n"Two years. And where are you?"\n"Four months from the number I need."\n"Four months," Idemudia said. "And that is if nothing goes wrong. No bad week, no bike trouble, no crackdown eating another route. Four months of perfect." He paused. "When was the last time this road gave you four perfect months?"\nOsaro did not answer because the answer was not useful to either of them.\n"The polytechnic," Idemudia continued, not unkindly, leaning forward now with his elbows on his knees. "I am not saying it is a bad dream. I am saying the road between here and that dream has more checkpoints than Ugbowo junction and none of them are on your map."\n"So we take the man''s job instead."\n"I am saying we look at it honestly."\n"I am looking at it honestly. A man we do not know wants us to carry something we cannot ask about and he knows the security rotation and carries a briefcase that has never been used for anything ordinary. That is what I am looking at honestly."\nIdemudia was quiet for a moment.\n"You know what your problem is," he said finally. "You think the careful road is safe because it is slow. But slow and safe are not the same thing. This city will take your two years of savings and your four months of patience and your Auchi brochure and it will not feel bad about any of it."\nThe brochure. Osaro had not told him about the brochure. Which meant he had been in the room when Osaro was reading it and had said nothing until now.\n"I know what the brochure costs," Osaro said quietly.\n"I know you know. I am telling you I have watched three men in this compound plan their way out of this street. Your father was one of them." He stopped. Let that land. "I am not saying it to wound you. I am saying it because I watched. Planning did not fail those men. The ground failed them. The ground here is not level, it was never level, and a man who keeps believing in his calculations while the ground is moving is not careful. He is just slow to see what is happening."\nOsaro stood up. Not from anger exactly, but from the feeling that if he stayed sitting the words would settle into him in a way he could not undo.\n"Idemudia. If you take that job and something goes wrong, it is not only you. It is Uncle''s bikes. It is this compound. It is everything holding the old man up."\n"And if I do not take it," Idemudia said, "and next week they close Aduwawa, what is holding him up then?"\nThey looked at each other across the yellow square of light.\nThis was the argument they had never had out loud, the one that had been living under every conversation about money and routes and the future for two years. It was not about the briefcase. It was about whether Osaro''s road was real or whether it was just a story a seventeen year old was telling himself to get through the difficulty of being seventeen in Benin City with no father and two bikes and a crumbling gate.\nIdemudia pulled the white card from his pocket and set it on the ground between them.\n"I am not deciding tonight," he said. "But I am not throwing it away."\nHe went inside.\nOsaro looked at the card on the ground for a long time. Then he picked it up.','\n',char(10)),869,1,1,NULL,'2026-04-18T06:22:15.302Z','2026-04-18 06:22:15','2026-04-18 06:22:15','2026-04-18T06:30:00.000Z',1,41);
INSERT INTO "chapters" ("id","novel_id","chapter_number","title","content","word_count","is_premium","is_published","audio_url","published_at","created_at","updated_at","scheduled_release_at","part_number","season_id") VALUES(474,58,5,'The First Delivery',replace('Idemudia called the number on Saturday night.\nOsaro was in the room when he did it, sitting on the edge of his mattress with his notebook open to a page of numbers he was not reading. He heard his cousin''s voice through the thin wall, low and brief, three sentences at most, and then silence. No argument had been resolved between them. Osaro had simply decided that if Idemudia was going, he was going too, and Idemudia had accepted this without discussion, which was its own kind of answer.\nThe map came as a voice note. A man, different from the quiet man at the market, read out the route in a flat unhurried voice. Aduwawa junction, left before the overhead bridge, through the unpaved road behind the depot, then a long straight road Osaro did not recognise by name but knew by the water tower that sat at its far end like a grey thumb against the sky.\nFriday evening. Seven o clock. One bag. One gate.\nThe bag was delivered to the compound on Friday at four, left outside the broken gate by someone neither of them saw. It was a black canvas bag, medium sized, with two zips and a combination lock threaded through both zipper pulls. It weighed enough to be serious. It made no sound when Idemudia lifted it and turned it once in his hands.\nHe strapped it across his body and did not look at Osaro when he did it.\nThey left the compound at six thirty. The evening light was the colour of old copper and the city had that particular Friday feeling, loud and loose, like a belt that had been undone one notch. Traffic was thick on the main road but it moved. Osaro rode behind Idemudia the way he had since he was fifteen, watching his cousin read the road, watching the slight adjustments of his shoulders when he was making a decision.\nThe first part of the route was ordinary. Aduwawa junction was the same junction it always was, the same yellow buses and hawkers and the man who sold phone cables from a board propped against the traffic light pole. Osaro kept his eyes moving, scanning for uniforms, for checkpoints, for anything that sat wrong in the pattern of the road.\nNothing sat wrong. That was the first thing that felt wrong in a quiet way.\nThe left turn before the overhead bridge took them onto a road that was narrower and less lit. The depot road. The surface was uneven and the occasional streetlight worked only in the sense that it was present. There were fewer people here. A woman with a bucket walking quickly. Two boys on a stationary bike at a junction, watching them pass with no particular expression.\nIdemudia did not slow down or speed up. He rode the way the quiet man had presumably intended them to ride, like two young men going somewhere ordinary on a Friday evening.\nOsaro''s chest had been doing something since they left the compound that he did not have a clean name for. It was not fear exactly, or not only fear. It was the physical sensation of knowing that a decision had been made and that the time for unmmaking it was now behind him, somewhere back on that main road with the yellow buses and the cable seller.\nThey reached the long straight road at six fifty two. Osaro knew the time because he checked. He had been checking every few minutes the way a person checks a wound they are trying not to think about.\nThe water tower appeared at the far end exactly where the voice note had said it would be. On the left side of the road, set back behind a low concrete wall, was a gate. Green painted metal, double width, the kind that suggested a compound rather than a house. A single bulb burned above it on an iron arm.\nIdemudia stopped ten metres short and looked back at Osaro once.\nOsaro nodded.\nIdemudia rode to the gate and stopped. Before he could do anything, the gate opened from inside, just enough for a man to appear in the gap. Not the quiet man from the market. Someone younger, shorter, wearing a plain tee shirt and moving with the careful economy of someone who was paid to be unhurried and alert.\nHe looked at Idemudia. He looked at Osaro. His gaze stayed on Osaro one second longer than felt like nothing.\nIdemudia unstrapped the bag and held it out. The man at the gate took it, unthreaded the combination lock with four quick turns, opened the top zip three inches and looked inside. He zipped it closed. He produced an envelope from his back pocket and held it toward Idemudia.\nIdemudia took it.\nThe gate closed.\nThe whole exchange lasted less than ninety seconds.\nThey rode back through the depot road without speaking. The city received them the same way it had sent them out, indifferent and continuing, full of its own Friday noise.\nIt was only when they reached the compound and Idemudia counted the money under the kitchen light that Osaro noticed his cousin''s hands were completely steady.\nHis own were not.','\n',char(10)),876,1,1,NULL,'2026-04-18T06:23:04.787Z','2026-04-18 06:23:04','2026-04-18 06:23:04','2026-04-18T06:30:00.000Z',1,41);
INSERT INTO "chapters" ("id","novel_id","chapter_number","title","content","word_count","is_premium","is_published","audio_url","published_at","created_at","updated_at","scheduled_release_at","part_number","season_id") VALUES(475,58,6,'The People at the Gate',replace('The envelope held enough to matter and not enough to explain.\nIdemudia split it the way he split everything, two thirds for himself because he had carried the bag, one third for Osaro because he had come. Osaro accepted his share without argument and put it in his notebook between two pages of columns, which was the closest he could come to an honest record of what it had cost to earn it.\nThey did not speak about it for three days. Life resumed its ordinary shape. Aduwawa in the mornings, Ikpoba Slope in the afternoons, the uncle on his step in the evenings with his tea and his radio. The crackdown had not lifted. Two more corridors had been quietly closed off and the remaining routes were thickening with displaced riders pulling the same shrinking pool of fares.\nOn the third day Idemudia said the quiet man had called him.\nHe said it while they were eating, the same way he said most things that required courage to say, in the middle of something ordinary, so the weight of it had somewhere to land besides silence.\n"He wants to meet," Idemudia said. "Not a job. A meeting."\n"Why."\n"He said there is something he wants us to understand."\nOsaro looked at his food.\n"He said both of us," Idemudia added.\nThe meeting was not at the market wall. It was at a compound on Reservation Road, the kind of address that carried its own information. The houses there were set back behind walls and the walls had razor wire at the top, not the aggressive kind that announces danger, but the quiet kind that says this property has already decided about you.\nA different gate opened for them. A woman led them through a short passage into a sitting room that was cool and dim, with leather chairs and a ceiling fan moving slowly and a side table with two bottles of water already placed as if their arrival had been counted on. The woman left without speaking.\nThey sat.\nThe quiet man came in two minutes later, still in a collared shirt, this one the colour of dry sand. He sat across from them and leaned back and looked at them both with the same unhurried attention he had given them at the market wall, the look of a man taking a measurement.\n"You did well on Friday," he said.\nNeither of them responded.\n"The man at the gate said the second rider stayed back at a respectful distance. That showed judgment." He looked at Osaro when he said this.\n"What is this meeting for," Idemudia said.\nThe quiet man placed both hands flat on his knees. "I want you to know enough to be useful and not enough to be dangerous. That is the honest version of what I am about to tell you, and I am telling you the honest version because I think you are both smart enough to know the difference."\nHe explained it plainly. He moved money, documents, and occasionally objects between parties in Benin City who could not be seen moving these things themselves. He was not the origin and not the destination. He was the road. His clients paid for discretion, for timing, and for riders who understood that the value of the job was in the silence around it.\n"The bag on Friday," Idemudia said. "What was in it."\n"Documents," the man said. "Land documents, specifically. A title that one party needed to reach another party before a filing deadline on Monday morning. The combination lock was to ensure the contents were not interfered with in transit."\nThe answer was clean and specific and Osaro did not believe all of it and did not disbelieve all of it, which was the most unsettling position to be in.\n"The man at the gate," Osaro said. "He looked at us."\n"He looks at everyone."\n"He looked at me longer."\nThe quiet man considered this. "He noted that there were two riders. I had arranged for one. He was confirming nothing else had changed about the job."\nIt was the kind of answer that explained exactly as much as it chose to.\n"I have three more deliveries before the end of the month," the man said. "Different routes, different recipients. Same terms, same rate. I am offering them to you because Friday demonstrated that you can hold your nerve on a road and keep your questions for afterward."\nHe looked at them both and waited.\nOsaro looked around the room slowly. The leather chairs, the ceiling fan, the two bottles of water on the side table. The woman who had led them in without speaking. The razor wire on the outer wall that did not announce itself. Every detail in this room had been arranged by someone who understood that comfort was a tool as much as any other.\nHis portion of Friday''s envelope was still inside his notebook.\nThree more jobs at that rate was a number that rearranged his columns in a way that made Auchi feel close in a way it had never felt before.\nThat was the thing that frightened him most.\nNot the bag. Not the gate. Not the man at the gate who had looked at him one second too long.\nThe money making sense. That was the part that frightened him.','\n',char(10)),895,1,1,NULL,'2026-04-18T06:23:56.335Z','2026-04-18 06:23:56','2026-04-18 06:23:56','2026-04-18T06:30:00.000Z',1,41);
INSERT INTO "chapters" ("id","novel_id","chapter_number","title","content","word_count","is_premium","is_published","audio_url","published_at","created_at","updated_at","scheduled_release_at","part_number","season_id") VALUES(476,58,7,'Different Math',replace('Osaro opened a new page in his notebook that night.\nHe did not plan to. He was sitting on his mattress with the notebook in his lap the way he always sat after a long day, and his hand turned to a clean page before his mind had decided anything, the way a body sometimes knows what it is going to do before the person inside it catches up.\nHe wrote two columns.\nOn the left side he wrote what the money was. Three more jobs at the same rate, added to what remained in his careful running total, minus what he still owed toward the polytechnic figure. He did the calculation three times because the first time he did not trust it and the second time he still did not trust it, but by the third time the number was just a number and it meant he was looking at six weeks, not four months.\nSix weeks. If everything held.\nOn the right side he wrote what the money cost. He sat with the pen above that column for a long time. A motorcycle ticked as it cooled outside in the yard. The radio in his uncle''s room played something he could not make out. He wrote three things in the right column and then stopped because the fourth thing he wanted to write was not something he had a word for yet.\nThe three things he wrote were: the bag, the gate, the man who looked too long.\nThe fourth thing was something closer to what happened to a person when they began to be comfortable in a room they should not be comfortable in. He had felt it in those leather chairs, in the way the cool air and the slow ceiling fan had arranged themselves around him while the quiet man talked. He had felt himself settling into the chair. That settling was the fourth thing and he did not have a word for it but he knew it was the most expensive item in the right column.\nHe closed the notebook.\nIdemudia was in the yard when Osaro came out, sitting in the same chair as always, but there was something different about his posture tonight. A looseness that had not been there before the first delivery. He was eating chin chin from a small bag and looking at the broken gate with the expression of a man who has stopped seeing the broken part.\n"I have been thinking," Osaro said.\n"About the jobs."\n"About the jobs."\nIdemudia offered him the chin chin. Osaro took a few pieces and sat.\n"Three more," Idemudia said. "Clean runs, in and out. By the time we are done the crackdown might be lifting anyway and we go back to normal with something solid behind us."\n"That is one way to see it."\nIdemudia looked at him. "What is the other way."\nOsaro chose his words the way he chose routes on a bad day, carefully and with an awareness of what was on either side.\n"The other way is that we have been inside that man''s house. We have sat in his chairs. We know the road to his gate and the rotation of his contacts and we are three jobs deeper into something we entered because it was one job." He paused. "Each job is not the same job. Each one is a step that makes the next one easier to agree to."\nIdemudia was quiet for a moment. Then he said, "That is a very complicated way of saying you are afraid."\n"I am not saying I am afraid. I am saying the math has two sides."\n"Your math," Idemudia said, and his voice had something in it now, not cruelty but a kind of impatience, the sound of a person who has been in a conversation longer than they find useful. "Osaro, I have been in this city since I was seventeen. I have done the straight math, the careful math, the patient math. You know what patient math bought me? Three years of watching this compound get smaller. A hand I have watched go wrong on a man who deserved better. A gate nobody fixes because nobody can afford to." He stopped. "Your polytechnic math is beautiful. I am not saying it is not beautiful. I am saying it has been beautiful for two years and you are still here."\nThe words did not land like an attack. They landed like something heavier, an accounting.\n"And if something goes wrong on one of these runs," Osaro said quietly. "If the thing in the bag is not documents. If the man at the gate is not just careful but is the kind of careful that ends with bikes confiscated and boys in a cell. What does that math look like."\nIdemudia looked at him for a long moment.\n"Then we do not let something go wrong," he said.\nThat was the moment Osaro understood they had stopped speaking the same language. They were using the same words, money, risk, the future, the compound, and they were meaning completely different things by all of them. The gap between those meanings was not new. It had been there for years, patient and quiet, the same way the broken gate had been there, something everyone could see and nobody was fixing.\nIdemudia finished his chin chin and folded the bag into a small square.\n"I am calling him tomorrow," he said. "You can come or you can not come. But I am calling."\nHe went inside.\nOsaro sat alone in the yard with the broken gate in front of him and his notebook on his knee and the fourth thing in the right column still without a name.','\n',char(10)),960,1,1,NULL,'2026-04-18T06:24:46.647Z','2026-04-18 06:24:46','2026-04-18 06:24:46','2026-04-18T06:30:00.000Z',1,41);
INSERT INTO "chapters" ("id","novel_id","chapter_number","title","content","word_count","is_premium","is_published","audio_url","published_at","created_at","updated_at","scheduled_release_at","part_number","season_id") VALUES(477,58,8,'The Second Offer',replace('The quiet man did not make them come to Reservation Road this time.\nHe came to them.\nOsaro was on the Slope at half past two when Idemudia called and said the man was at the yard, sitting outside the broken gate on a plastic chair that belonged to the compound next door, waiting. Osaro finished his current fare, did not take another, and rode back in the kind of focused silence that was not calm but looked like it from the outside.\nThe quiet man stood when he heard the bikes. He was dressed the same way he was always dressed, collared shirt, leather shoes, briefcase held at his side. He had brought the plastic chair back to its correct compound and was standing where it had been, which was a small thing but the kind of small thing that told Osaro this man understood that details were the difference between a person who was trusted and a person who was tolerated.\n"I would have come to you," Idemudia said.\n"I was in the area," the quiet man said, which was almost certainly untrue and said with enough ease that it did not matter either way.\nThey stood in the street outside the gate because Ehigie was inside and none of them needed that conversation. The afternoon traffic moved past them and nobody who passed looked twice at three people talking near a compound, which was the point of choosing this over a sitting room on Reservation Road. Here they were just the road.\n"I have a job that is different from the previous ones," the quiet man said. "I want to be direct with you about the difference because I think you have both earned that."\n"Say it," Idemudia said.\n"The previous bag was documents. I told you that and it was true. This bag will not be documents." He let that settle without filling the space around it. "I will not tell you what it is. That is still a condition. But I will not pretend it is something smaller than it is."\nOsaro looked at the briefcase at the man''s side. "Then why would we take it."\nThe quiet man looked at him with something that was close to respect.\n"Because the rate is different also." He said a number.\nThe number was not triple. It was five times the daily rate, split between them, for a single run. It sat in the air between the three of them and rearranged the space around it the way a large object rearranges a small room just by being placed inside it.\nOsaro did not look at Idemudia. He did not need to. He could feel his cousin''s attention shift the way you feel a change in weather before it arrives.\n"The route is longer," the quiet man continued. "Out of the central corridor, through the Oba market road and down to a compound in Oregbeni. There are two handoffs instead of one. The second person you deliver to will ask you a question and you will give them an answer I will tell you before you leave. That is all."\n"A password," Idemudia said.\n"A confirmation," the quiet man said, which was the same thing dressed differently.\nOsaro spoke carefully. "The first job was documents. You told us. The second and third were also things you named. Now you are telling us you will not name it and the number goes up by this much." He paused. "The number going up is because the risk is going up."\n"Yes," the quiet man said.\nThe honesty landed strangely. Osaro had prepared himself for a reassurance, for another clean explanation that explained exactly as much as it chose to. The straight yes sat differently in his chest, heavier but in some way more manageable than a careful lie would have been.\n"We need time," Osaro said.\n"You have until tomorrow evening."\n"We need more than that."\nThe quiet man considered him. "You have until Saturday morning. After Saturday morning I find another arrangement and we conclude our relationship respectfully."\nHe picked up his briefcase, which he had set down at some point without Osaro noticing, and nodded at them both the way he always did, like a man completing a transaction that had gone according to his expectations.\nHe walked to a car parked twenty metres down the road. Not a flashy car. A clean, middle aged saloon the colour of charcoal that had been chosen for exactly the same reason as everything else this man owned and wore and said: to be present without being seen.\nThe car pulled into traffic and was gone.\nIdemudia turned to Osaro. His eyes were doing the thing they did when a decision was already forming and he was deciding how much of that to show.\n"Five times," he said.\n"I heard him."\n"Osaro. Five times in one run."\n"I heard him the first time, Idemudia."\nIdemudia looked down the road where the charcoal car had disappeared. "He was honest with us. He did not dress it up."\n"He was honest because the size of the number needed the honesty to land properly. That is not the same as him looking out for us."\nIdemudia looked at him then, and something in his face shifted. Not anger. Something older than anger, the look of a man who has decided that a conversation has reached the limit of what it can produce and is now simply waiting for the other person to arrive at the same conclusion.\n"I am going to take it," Idemudia said quietly. "With or without you."\nThe three words at the end of that sentence were the ones that stayed with Osaro long after his cousin had gone inside.\nWith or without you.\nIt was the first time Idemudia had said them out loud. But it was not the first time Osaro had heard them.','\n',char(10)),986,1,1,NULL,'2026-04-18T06:25:43.627Z','2026-04-18 06:25:43','2026-04-18 06:25:43','2026-04-18T06:30:00.000Z',1,41);
INSERT INTO "chapters" ("id","novel_id","chapter_number","title","content","word_count","is_premium","is_published","audio_url","published_at","created_at","updated_at","scheduled_release_at","part_number","season_id") VALUES(478,58,9,' What Cousins Don''t Say',replace('It started over something small, the way the real arguments always do.\nOsaro moved the white card from the ground where Idemudia had left it in Episode 4. Wait, I need to just write the episode fresh without referencing episode numbers.\nSeason 1, Episode 9: What Cousins Don''t Say\nIt started over the notebook.\nIdemudia picked it up from the table where Osaro had left it, not to read it, just moved it to set down his cup, and something about the casual handling of it, the way his cousin''s hand moved it aside like it was any object, cracked something open in Osaro that had been sealed for a long time.\n"Don''t," Osaro said.\nIdemudia set the cup down and looked at him. "I was moving it."\n"I know what you were doing."\nThe words came out with more edge than Osaro had planned and they both felt it, the specific sharpness of something that had been waiting behind ordinary speech for longer than either of them had admitted.\nIdemudia straightened slowly. He did not raise his voice. He was not a man who raised his voice, which sometimes made things worse.\n"Say what you actually want to say," he said.\nOsaro looked at the notebook on the table. His two years were in that notebook, his columns, his calculations, every fare and fuel cost and careful subtraction. The brochure from Auchi was folded inside the back cover.\n"You have never believed in this," Osaro said. "Not once. Not from the beginning. You ride beside me every day and you think it is a child''s plan and you have thought that since I started the columns."\n"I never said it was a child''s plan."\n"You did not need to say it."\nIdemudia crossed his arms. Outside the broken gate a motorcycle passed and the sound of it moved through the yard and faded.\n"What I believe," Idemudia said carefully, "is that this city does not owe you the ending you have written for yourself. That is not the same as thinking you are a child."\n"It is the same as thinking my plan is one."\n"Osaro."\n"My father had a plan too." Osaro''s voice stayed level but the steadiness of it cost him something. "You said that to me. You put it in front of me like a fact and walked inside. You have been carrying that comparison for two years and you dropped it on me like it was nothing."\nIdemudia was quiet.\n"What happened to my father," Osaro continued, "was not because he planned wrong or dreamed wrong. What happened to him happened because he was in the wrong place at the wrong time with the wrong people. And you know that. You were there for the last part of it. You were seventeen and you were there and you know it was not his plan that failed him."\nThe silence that followed was the kind that had weight and texture. The radio in Ehigie''s room had gone off. The yard held nothing but the two of them and the space between them that had been accumulating for years.\nSomething moved across Idemudia''s face. Not guilt exactly. Something more complicated, the expression of a man confronting a truth he has been managing rather than holding directly.\n"You are right," he said quietly. "That was not a fair thing to say to you."\nThe admission did not make Osaro feel better. It made him feel the sadness underneath the anger, which was worse.\n"Then why," Osaro said. "Why are you pulling toward this man and his bags and his gate on Oregbeni. Why, when you know what happens when people get tangled in things they cannot name."\nIdemudia sat down. For a long moment he looked at his hands, at the scar on his left forearm that he had never fully explained.\n"Because I am tired," he said. "That is the honest answer. I am tired of the small road. I am tired of watching the routes close one by one and doing the same calculation every morning and arriving at the same number every night. I am twenty three years old and I feel like a man who has been running on the same road for so long he has forgotten there are other roads."\n"The man''s road leads somewhere you cannot come back from."\n"Maybe," Idemudia said. "Maybe not. But Osaro." He looked up. "I have watched you build something real. I have watched you hold it together with both hands for two years and I have never told you that, so I am telling you now. What you are building is real." He paused. "But I cannot build it with you. That is what I have been trying to say badly for weeks. I am not trying to take your plan from you. I am telling you mine is different."\nOsaro stood with that for a long moment.\n"If you take the Oregbeni job," he said finally, "and something happens to you, Uncle does not survive it. You know that."\n"I know that."\n"And you are still going."\nIdemudia did not answer immediately. The answer, when it came, was not a word. It was the way he sat in the chair, the set of his shoulders, the steadiness of a man who has arrived at a decision through enough pain that the decision has become its own kind of peace.\nOsaro picked up his notebook from the table. He held it for a moment, then set it back down.\n"Then I am coming with you," he said. "On the Oregbeni run. I am coming and I am watching your back and when it is done we are done with this man forever."\nIdemudia looked at him.\n"That is not your choice to make," he said.\n"I just made it," Osaro said.','\n',char(10)),976,1,1,NULL,'2026-04-18T06:26:52.684Z','2026-04-18 06:26:52','2026-04-18 06:26:52','2026-04-18T06:30:00.000Z',1,41);
INSERT INTO "chapters" ("id","novel_id","chapter_number","title","content","word_count","is_premium","is_published","audio_url","published_at","created_at","updated_at","scheduled_release_at","part_number","season_id") VALUES(479,58,10,'Osaro Says No',replace('The Oregbeni run changed Osaro in a way he did not have words for until three days after it happened.\nEverything had gone the way the quiet man said it would. The route through Oba market road, the two handoffs, the confirmation word spoken to a man behind a second gate who received it without expression and closed the door like it had never opened. No checkpoints. No complications. The money arrived in an envelope thicker than the first and Osaro rode back through Benin City at nine in the evening feeling like a person who had walked through a door and heard it lock behind him.\nHe put his share in his notebook and did not open the notebook again for three days.\nOn the fourth day the quiet man called Idemudia with the third job.\nOsaro said no at the compound table, with his notebook closed in front of him and Ehigie in the next room and the evening settling around the yard in the way it always did, ordinary and indifferent to whatever was happening inside it.\nHe said it once, clearly, without building a case around it.\nIdemudia looked at him across the table. He was turning his phone over in his hand, the slow rotation he did when he was thinking about more things than the conversation in front of him.\n"The number is the same as Oregbeni," Idemudia said.\n"I know."\n"You know what that adds to your total."\n"I know what it adds."\nIdemudia set the phone down. "Then what changed."\nOsaro thought about how to answer that honestly. He thought about the second gate on the Oregbeni run, about the man who received the confirmation word, about the half second before the door closed when Osaro had seen past the man''s shoulder into the compound behind him. He had seen two other men seated at a table in the open air, and a generator cable running from somewhere out of sight, and the particular quality of attention those two men had paid to the gate opening, the way people pay attention when what is happening at a gate is the most important thing happening anywhere.\nHe had not told Idemudia what he saw. He had carried it for three days and now it was the clearest thing in his chest.\n"I saw enough on the last run," he said. "I know enough now to know I do not want to know more."\n"That is the same fear talking."\n"No," Osaro said. "Fear is what you feel before you understand something. What I have now is understanding. I understand what we are riding for, Idemudia. Not documents. Not land titles. I understand it and I am not doing it again."\nIdemudia looked at him for a long moment. The phone screen lit up with a notification and went dark again.\n"I will go alone then," Idemudia said.\n"I know you will."\n"You are not going to argue."\n"I have argued. I have done every version of the argument. I am done with arguing." Osaro looked at his cousin directly. "I am asking you. Not arguing, not warning. I am asking you as someone who has known you since I was three years old. Do not take this job."\nIdemudia picked up his phone.\n"I will be back before midnight," he said.\nOsaro nodded. He had known this was how it would go and the knowing did not make it easier, just more exact.\nHe sat at the table after Idemudia left and listened to the bike start in the yard and the sound of it moving through the broken gate and down the street. He listened until the sound was gone and what replaced it was the ordinary night noise of the compound, the radio, the rooster settling somewhere, the distant grammar of the city going about its Friday business.\nEhigie appeared in the kitchen doorway. He had his tin cup and his brown slippers and the careful hands. He looked at the empty chair across from Osaro and then at Osaro.\nHe did not ask where Idemudia had gone. The question was already in the room and they both knew it and asking it out loud would only have made it louder.\nHe sat in Idemudia''s chair and set his cup on the table and looked at the notebook in front of Osaro.\n"How close are you," he said.\n"To the polytechnic number?"\n"Yes."\nOsaro opened the notebook to the last page with writing on it. He turned it so his uncle could see the final figure at the bottom of the column.\nEhigie looked at it for a long time. His right hand was around the base of his cup, the careful grip.\n"Your father would have been very proud of those numbers," he said.\nOsaro closed the notebook.\nThey sat together in the kitchen while the night continued around them, uncle and nephew, the tin cup going slowly cold between them, both of them listening to a sound that was no longer there, waiting for it to return.\nEleven o clock came.\nEleven thirty.\nAt twelve fifteen Osaro''s phone lit the table in the dark.\nIt was not Idemudia''s number. It was a number he did not recognise, and when he answered it a voice he had never heard said his name once, then told him in three sentences what had happened on the road to Oregbeni.\nHe sat very still for a moment after the call ended.\nThen he stood, took his jacket from the hook by the door, and walked out through the broken gate into the dark.','\n',char(10)),940,1,1,NULL,'2026-04-18T06:27:46.052Z','2026-04-18 06:27:46','2026-04-18 06:27:46','2026-04-18T06:30:00.000Z',1,41);
INSERT INTO "chapters" ("id","novel_id","chapter_number","title","content","word_count","is_premium","is_published","audio_url","published_at","created_at","updated_at","scheduled_release_at","part_number","season_id") VALUES(480,58,11,'What the Road Took',replace('The address the voice had given him was not Oregbeni.\nIt was a street off the Sapele Road corridor, the kind of street that did not have a proper name on any map Osaro knew, only a description, third turning after the filling station with the broken sign. He rode there with his phone in his jacket pocket and the city moving past him in its late night configuration, fewer people, longer shadows, the particular emptiness of roads that have finished their useful hours and are waiting for morning.\nHe found the bike first.\nIt was on its side in the red dirt at the edge of the road, ten metres from a low concrete wall. The older bike, the 2009, the one with the scratch along the left panel from a scrape at Aduwawa junction four months ago. Osaro recognised it before he was fully stopped. He put down his own bike and crouched beside it and his hands moved over it the way his uncle''s hands moved over things he needed to read by touch, checking without deciding yet what he was checking for.\nThe bike was not badly damaged. A broken mirror. Dirt on the fuel tank. The engine had been cut, not stalled, someone had turned the key.\nThere was no bag.\nHe stood and looked at the wall and at the road in both directions. Two men were standing twenty metres away near a gutter, watching him without pretending not to. He did not know them. They did not move toward him and they did not move away.\nHe called Idemudia''s number.\nIt rang. It rang the full length and went to a recorded voice and he called again and it rang again and on the third call it did not ring at all, just went directly to the recorded voice, which meant the phone had been turned off or had died or had been taken by someone who knew to turn it off.\nOsaro stood on that road for a long moment with the phone at his side and the older bike on the ground in front of him and the two men watching from their twenty metres of distance.\nThen he called the quiet man''s number.\nIt rang twice. The quiet man answered on the third ring, which meant he was awake and had been waiting for a call, just not necessarily this one.\n"Where is my cousin," Osaro said.\nA pause. Not long. The length of a man deciding how much of a thing to give.\n"There was a complication on the route," the quiet man said.\n"That is not what I asked you."\n"Idemudia is not harmed. I want you to know that first."\nThe relief and the anger arrived at the same moment and occupied the same space in Osaro''s chest in a way that made it difficult to separate them.\n"Where is he."\n"He is being held. Not by police. By the people on the other side of the delivery. There was a disagreement about the contents of the bag and Idemudia was present when the disagreement became physical. He is unhurt but he is not free to leave until the disagreement is resolved."\n"What disagreement."\nAnother pause. This one had a different quality, the pause of a man who has arrived at the edge of what he planned to reveal and is deciding whether to step over it.\n"The contents of the bag were contested," the quiet man said. "What was inside was not what the recipients were told would be inside. That is not your cousin''s fault and it is not my intention that he bear the consequence of it."\nOsaro turned away from the two watching men and lowered his voice.\n"You sent him out with a bag and you did not know what was in it."\nSilence.\n"You do not own the bags," Osaro said slowly. The understanding arriving the way cold water arrives, completely and all at once. "You are not the one filling them. You are the road, that is what you told us. But someone is using your road and they are not telling you everything about what they are moving."\nThe quiet man said nothing and his silence was its own kind of answer.\nEverything Osaro thought he understood about this man reshuffled itself in the space of ten seconds. The Reservation Road compound, the leather chairs, the slow ceiling fan, the careful shoes, none of it was the picture of a man in control. It was the picture of a man who was very good at appearing to be in control, which was not the same thing and had never been the same thing.\n"I want my cousin back tonight," Osaro said.\n"I am working on that."\n"That is not enough."\n"It is what I have right now." The quiet man''s voice had changed. The unhurried quality was still there but underneath it was something Osaro had not heard before, a tightness, the sound of a man who is also waiting and also does not know how the night ends.\n"I will call you when there is movement," the quiet man said. "Go home, Osaro. There is nothing on that road that you can fix tonight by being on it."\nThe call ended.\nOsaro stood on the unnamed street with the 2009 lying in the dirt and the city quiet around him and the two men still watching from their twenty metres, patient and still, like men who had been placed there and told to wait and were good at waiting.\nHe looked at them. They looked at him.\nHe righted the older bike. He checked the engine, turned the key, and it started on the second try. He rode it slowly, his own bike following on the road in his mind, back through the late night city toward the compound.\nThe broken gate was open the way he had left it.\nEhigie was on the step with no tea and no radio, just sitting in the dark in his brown slippers with his careful hands on his knees, looking at the gate like a man who has spent a long time looking at the specific space a person leaves behind them when they go.\nOsaro stopped the bike in the yard.\nHis uncle looked at the older bike. He looked at Osaro. He looked at the space behind Osaro where the second rider was not.\nHe did not ask.\nOsaro sat on the step beside him and they stayed there together in the dark, and the city went on around them the way cities do, without pausing, without knowing, without caring what any one road had taken from any one person on any one night.','\n',char(10)),1126,1,1,NULL,'2026-04-18T06:28:37.703Z','2026-04-18 06:28:37','2026-04-18 06:28:37','2026-04-18T06:30:00.000Z',1,41);
INSERT INTO "chapters" ("id","novel_id","chapter_number","title","content","word_count","is_premium","is_published","audio_url","published_at","created_at","updated_at","scheduled_release_at","part_number","season_id") VALUES(481,59,1,' The Morning After',replace('Ehigie was already awake when the light came.\nOsaro had not slept. He knew this not because he had been watching the hours but because the night had passed through him like weather, present and continuous, without the break that sleep makes in a person''s experience of time. He had been on the step and then inside and then on the step again, and at some point his uncle had gone to bed without a word and the yard had held only Osaro and the two bikes and the particular silence of a compound waiting for someone who had not come back.\nThe morning arrived the way Benin City mornings always did, gradually and then all at once, the light finding the zinc sheet above the bikes first, then the broken gate, then the rooster moving out from wherever it slept, unconcerned.\nEhigie came out with two cups of tea and sat beside Osaro on the step. He handed one over with his careful grip and they drank without speaking. The tea was strong and too hot and Osaro was grateful for both things.\n"Tell me," his uncle said finally.\nOsaro told him. Not everything, not the full shape of the quiet man and the deliveries and the notebook page with two columns that he had filled and then stared at for three days. He told him the part that was tonight''s business. The call, the road off Sapele corridor, the bike on its side, the quiet man''s voice with the tightness underneath it.\nEhigie held his cup and listened without interrupting.\nWhen Osaro finished, his uncle was quiet long enough that a danfo passed on the street outside and its noise came and went completely before either of them spoke.\n"How many runs," Ehigie said.\nOsaro looked at the gate. "Three."\nHis uncle nodded slowly, not with surprise, with the particular acknowledgment of a man receiving information that confirms something he already knew the shape of.\n"I moved the card from outside the gate," Osaro said. "The first night. I should have thrown it into the gutter."\n"Yes," Ehigie said simply. No cruelty in it. Just agreement, the way an older person agrees when they have lived long enough to know that most disasters have a moment that small somewhere near their beginning.\nThe street outside was waking up. Osaro could hear it, the gradual accumulation of sound that meant the city was resuming itself, motorcycles and generators and someone with a broom working a concrete yard nearby. Benin City did not mark the night any differently from the day. It simply continued, layer after layer, indifferent to what any particular person had lost between sunset and sunrise.\nThat indifference felt different to Osaro this morning.\nHe had grown up in this city. He knew its corridors and its crackdowns and its particular way of making a person feel both seen and invisible depending on which road they were on and what they were carrying. He had always understood the city as a thing to be navigated, mapped, calculated against. His notebook was evidence of that understanding.\nBut sitting on the step now with his uncle''s tea going cool in his hands, the city felt less like a thing to be navigated and more like a thing that did not know he existed and would not notice if he solved or failed to solve anything that was currently happening to him and the people he loved.\nHe opened his phone and looked at it. No messages. No calls from the unknown number. No calls from Idemudia''s number.\nHe called Idemudia again. Straight to the recorded voice.\n"The people holding him," Osaro said. "I need to know who they are."\nEhigie looked at him.\n"If the quiet man cannot resolve it by tonight I cannot just sit here and wait."\n"Osaro."\n"I know what you are going to say."\n"Then let me say it anyway." His uncle turned to face him directly, which he did not always do, usually preferring to speak looking outward at the yard. "The moment you go looking for those people without knowing what you are walking into, you become the second problem. And a man who is trying to solve one problem while being a second problem cannot solve anything."\nOsaro looked at the older bike leaning against the compound wall where he had parked it last night. The broken mirror caught a piece of the morning light and threw it sideways.\n"He is your blood too," Osaro said.\n"He is my blood and he is also a grown man who made a choice. Both of those things are true at the same time." Ehigie''s voice did not waver. "And you are also my blood, and you are seventeen, and I will not watch the road take two of you in the same night."\nThe rooster passed between them without ceremony.\nOsaro drank the rest of his tea. It had gone from too hot to exactly the temperature of a decision he was not ready to make, bearable but not comfortable.\nHis phone lit the space between his knees.\nThe number was not Idemudia''s. It was not the quiet man''s. It was the same unknown number that had called him last night, the voice that had given him the address and the three sentences and nothing else.\nHe answered it before the second ring finished.\nThe voice was different this time. Younger. And what it said was not three sentences. It was one, and it changed the shape of the morning completely.','\n',char(10)),927,0,1,NULL,'2026-04-18T06:33:35.821Z','2026-04-18 06:33:35','2026-04-18 06:33:35','2026-04-18T07:00:00.000Z',2,42);
INSERT INTO "chapters" ("id","novel_id","chapter_number","title","content","word_count","is_premium","is_published","audio_url","published_at","created_at","updated_at","scheduled_release_at","part_number","season_id") VALUES(482,59,2,'The Quiet Man Has a Name',replace('The voice on the phone belonged to a boy.\nNot a child, but young enough that Osaro registered it immediately, the particular unfinished quality of a voice that had not yet settled into what it was going to be. Seventeen, maybe eighteen. He spoke Edo with a Benin City accent and his words had the careful precision of someone who had rehearsed what he was going to say and was now saying it exactly.\n"My name is Enobakhare," he said. "You do not know me. I know you because I know your cousin and I know the man you have been working for and I am calling because there are things you need to understand before you make your next move."\nOsaro stood up from the step. "Where is Idemudia."\n"He is in a compound off Ugbor Road. He is not injured. He has been there since eleven last night and the people keeping him are waiting for a man named Coker to make a decision."\n"Who is Coker."\n"That is the beginning of what I need to tell you."\nOsaro walked to the far end of the yard, away from his uncle''s hearing. The rooster moved out of his path.\n"Talk," he said.\nEnobakhare talked.\nThe quiet man''s name was Festus Agbonlahor. He had been operating inside Benin City for eleven years, moving between the transport business and other arrangements the way some men move between a legitimate occupation and its shadow, comfortably and without visible seam. He had started as a driver, become a coordinator, and was now what Enobakhare called a connector, a man whose value was not in what he owned but in who he knew and what he could be trusted to move between them.\nHe was not the top of anything. That was the important part.\nAbove Agbonlahor was a network that Enobakhare described not as an organisation but as an arrangement, a word he used deliberately, a loose structure of businessmen, transport operators, and two politicians whose names he did not give, who used the city''s movement economy the way you use a river, not by owning it but by knowing where to put things in and where to take them out.\nThe bags Osaro and Idemudia had carried were part of this arrangement. Not all of them were documents. Not all of them were the same kind of wrong.\n"The Oregbeni bag," Osaro said.\n"Was supposed to contain a specific item that had already been paid for by the people at the gate. What it actually contained was something different. Someone between Agbonlahor and the origin of the bag made a substitution. Agbonlahor did not know. The people at the gate opened the bag, found the wrong thing, and decided the rider was the safest person to hold until the situation was corrected."\n"Idemudia had nothing to do with any substitution."\n"I know that. The people holding him know that. But Coker, the man who makes decisions for that compound, he is waiting for Agbonlahor to produce the correct item before he releases anyone."\n"And Agbonlahor."\n"Is trying to locate the person who made the substitution. Which is taking time he does not have."\nOsaro leaned against the compound wall and looked at the sky above the zinc sheet. It was the uncomplicated blue of a morning that had no interest in the events happening beneath it.\n"How do you know all of this," he said.\nA brief pause. "I work for Agbonlahor. I have been working for him for eight months. I run messages, not bags. I know the shape of the network because it is my job to know which door to knock on and in what order." Another pause, shorter. "I am telling you this because Idemudia taught me to ride when I was fifteen and I owe him something and this is what I have to give."\nOsaro absorbed this. The network was finding its edges in his mind, the way a map finds its edges when you add enough detail. Agbonlahor at the centre, the politicians and businessmen above, the connectors and message runners and riders below, all of it structured around the principle that the city''s movement could be used, that roads were not just roads.\n"Coker," Osaro said. "Is he the kind of man you can reason with."\n"He is the kind of man who responds to correct information delivered correctly. He is not cruel but he is not patient. He gave Agbonlahor until tonight."\n"Tonight."\n"Six o clock. If the item is not produced or its equivalent value is not provided, the situation changes in a direction I cannot predict and neither can Agbonlahor."\nOsaro looked at the time on his phone. It was seven forty in the morning. He had ten hours.\n"What is the equivalent value," he said.\nEnobakhare told him.\nThe figure was large. Not impossible large, not the kind of large that closed the conversation immediately, but large enough that Osaro''s notebook columns rearranged themselves in his head the moment he heard it. Large enough that the number he had been building toward for two years and the number that would satisfy Coker by six o clock occupied roughly the same space.\nHe stood very still against the compound wall.\n"I am going to need to see Agbonlahor," he said.\n"I thought you would say that. He is expecting your call."\n"He is expecting my call."\n"He told me this morning that Osaro would call. Not Idemudia''s uncle. Not anyone else. Osaro." Enobakhare''s voice had something in it now, not quite warning, the tone of a person passing on information whose full weight they want the receiver to feel. "He knows how you think. He has been watching both of you since before the market wall."\nThe morning continued around the compound, ordinary and indifferent. Somewhere down the street a woman was calling a child''s name with the specific persistence of a parent who has called it several times already.\nOsaro looked at the older bike against the wall. At the broken mirror throwing its piece of light.\nAgbonlahor had known them both before the market wall. Which meant the quiet man sitting with his groundnuts and his careful briefcase had not been an accident of proximity or a businessman looking for available riders.\nHe had chosen them.\nThe question that remained was why, and Osaro understood now that the answer to that question was not going to make the morning easier.','\n',char(10)),1082,0,1,NULL,'2026-04-18T06:34:50.843Z','2026-04-18 06:34:50','2026-04-18 06:34:50','2026-04-18T07:00:00.000Z',2,42);
INSERT INTO "chapters" ("id","novel_id","chapter_number","title","content","word_count","is_premium","is_published","audio_url","published_at","created_at","updated_at","scheduled_release_at","part_number","season_id") VALUES(483,59,3,' What Uncle Knows',replace('Osaro came back inside and stood in the kitchen doorway and looked at his uncle and understood, in the particular way you understand something that has been true for a long time before you knew it, that this conversation had been waiting since before the market wall.\nEhigie was at the table with his second cup of tea. He had not gone back to bed and he had not turned on the radio and he was sitting in the specific stillness of a man who is not resting but holding.\nOsaro sat across from him.\n"Festus Agbonlahor," he said.\nHis uncle''s hands tightened around the base of the cup. Just slightly. Just enough.\n"You know that name," Osaro said.\nEhigie looked at his tea. The morning light was coming through the kitchen window now in a long flat angle that put half the table in brightness and half in shade.\n"Where did you hear it," his uncle said.\n"Someone called me. Someone who knows the network and knows Idemudia and knows that the man at the market wall was not sitting there by accident." Osaro kept his voice level because the alternative would not help either of them. "He chose us, Uncle. He did not find us. He chose us and he had been watching before he sat down beside me at that wall. So I need to know what you know."\nThe silence was long.\nEhigie set his cup down with the careful placement he gave everything, not from delicacy but from necessity, and folded his hands on the table.\n"I knew Festus Agbonlahor," he said, "when he was a driver and I was running four bikes and neither of us was what we have become. He worked a route that connected with mine on the Sapele corridor. We were not partners. We were two men in the same economy who understood each other''s value." He paused. "That was ten years ago."\n"What happened."\n"I expanded. I took on work I should not have taken on because the money was the right size at the wrong time. Festus was the one who brought me the work. He did not tell me everything about what I was moving and I did not ask everything I should have asked because I was a man who had four bikes and a growing business and I had decided I deserved what was coming to me."\nOsaro sat very still.\n"The business did not collapse on its own," Ehigie said. "There was a night, a specific night on the Sapele corridor, when one of my riders was stopped with something he did not know he was carrying. The rider was released because he genuinely did not know. But the bike was confiscated and the business was connected in a record somewhere with a name it should not have been connected with." He looked at his hands. "After that the business came apart the way things come apart when the ground under them has been moved. Slowly at first. Then completely."\n"The third bike," Osaro said.\n"Was not sold for hospital costs." His uncle said it plainly, without self-protection. "It was taken. Different people, same network. Payment for a debt I had accumulated without fully understanding I was accumulating it."\nOsaro looked at the window, at the flat morning light dividing the table.\n"Your hand," he said quietly.\nHis uncle did not answer immediately. The silence confirmed what the silence always confirms.\n"Not the network directly," Ehigie said finally. "A man connected to the edges of it. A disagreement about what I owed and what I had already given. It was handled in the particular way those disagreements were handled in that world." He turned his right hand over on the table slowly, looking at it with the expression of a man regarding a document he did not choose to sign but signed anyway. "I left that world after. Completely. Or I believed I had left it completely."\n"But Agbonlahor found us through you."\n"I do not know that for certain."\n"Uncle."\nEhigie looked at him. In his uncle''s eyes was something Osaro had not seen there before, not in all the evenings on the step with the radio playing, not in all the careful cups of tea. It was the look of a man carrying a weight he had convinced himself he was carrying privately, and finding out that the weight had been visible the whole time to the person standing closest.\n"I should have spoken when you told me about the man at the wall," his uncle said. "I told myself I did not know for certain that it was connected. That is not entirely a lie. But it is also not the whole truth."\nOsaro nodded slowly. He was not angry. The anger would have required a version of his uncle that did not include everything Ehigie had just put on the table, the ten years, the corridor, the hand, the gate and the document signed without understanding. You could not be simply angry at the full weight of a person''s history.\n"Agbonlahor has Idemudia because of a substitution in the bag," Osaro said. "Someone in the network swapped what was being moved and Idemudia was holding it when the recipients opened it. A man named Coker is holding him until six o clock tonight."\nEhigie closed his eyes briefly.\n"The person who can resolve it is Agbonlahor. But I need to go to him knowing what I am walking into." Osaro leaned forward. "Is there anything else. Anything at all that you have not said."\nHis uncle opened his eyes. He looked at his nephew across the divided table, half light, half shade, and what moved across his face was not evasion but the expression of a man who has decided, late and at cost, to put down something he has been carrying in the wrong direction for a long time.\n"Agbonlahor lost something to the same people who took the third bike," he said. "Something more important to him than a bike or a business. I do not know the details. But I know he has been rebuilding his position in that network for years and I know a man rebuilding from loss does not always choose his methods carefully."\nHe picked up his cup.\n"When you see him," he said, "do not let him make you feel that you owe him something. That is how he begins. That is how he began with me."','\n',char(10)),1085,0,1,NULL,'2026-04-18T06:35:59.022Z','2026-04-18 06:35:59','2026-04-18 06:35:59','2026-04-18T07:00:00.000Z',2,42);
INSERT INTO "chapters" ("id","novel_id","chapter_number","title","content","word_count","is_premium","is_published","audio_url","published_at","created_at","updated_at","scheduled_release_at","part_number","season_id") VALUES(484,59,4,'Inside the Network',replace('Agbonlahor answered on the first ring.\nHe said an address and a time, eleven o clock, and nothing else, and the call lasted nine seconds, which told Osaro that the quiet man had been waiting with the phone in his hand and had already decided what the conversation would contain before it happened.\nThe address was not Reservation Road.\nIt was a compound on Ugbor Road, closer to the centre of the city, the kind of address that did not announce itself. No razor wire on the outer wall. No green painted gate. Just a brown metal door set into a concrete wall, the paint on it the particular faded quality of something that had been chosen to look ordinary and had succeeded.\nEnobakhare was outside when Osaro arrived. He was shorter than his voice had suggested, compact, with close cut hair and the alert stillness of someone who had learned early that awareness was a form of safety. He was wearing a plain shirt and holding a phone he was not looking at.\nHe nodded at Osaro once and pushed the brown door open.\nInside was a courtyard and beyond the courtyard a low building with three doors, all closed. Two men were seated on a bench along the left wall. They looked at Osaro with the specific quality of attention that is professional rather than personal, the look of men who notice everything and decide afterward what to do about what they have noticed.\nOsaro kept his pace even and his hands visible.\nEnobakhare led him through the middle door.\nThe room was not like the Reservation Road sitting room. No leather chairs, no ceiling fan, no bottled water arranged for comfort. It was a working room, a table, four chairs, a window with a curtain that had been pulled three quarters of the way across. Maps on one wall, not tourist maps but hand drawn ones with routes marked in two colours, red and blue, that Osaro understood immediately were the active corridors of the network laid out in plain sight because everyone in this room already knew what they were.\nAgbonlahor was at the table.\nHe looked different here than he had at the market wall or in the Reservation Road compound. He was wearing a plain tee shirt and his briefcase was nowhere visible and without the collared shirt and the leather shoes the performance of composure was reduced to just the man underneath it. He looked like what he was, a man in the middle of a serious problem, working with the time he had been given to solve it.\nHe did not stand when Osaro entered.\n"Sit," he said.\nOsaro sat.\nEnobakhare remained standing near the door.\n"I know what Enobakhare told you this morning," Agbonlahor said. "I told him to tell you. So we can skip the part of the conversation where you are deciding how much I know and go directly to the part that helps your cousin."\n"Then go directly," Osaro said.\nAgbonlahor put both hands flat on the table. It was the same gesture he had used in the Reservation Road sitting room and Osaro recognised it as the man''s way of beginning something he intended to say completely.\n"The substitution in the Oregbeni bag was made by a man named Danladi who coordinates the origin point of several items I move for the upper level of this network. He substituted the original item for something smaller in value and kept the difference. He has done this before. I did not know the extent of it until last night."\n"Where is Danladi now."\n"I know where he is. Getting to him and recovering what he took or its equivalent is a problem of access and time, and the time is shorter than the access allows." Agbonlahor looked at Osaro steadily. "But there is another way to satisfy Coker before six o clock."\nOsaro looked at the maps on the wall. The red corridors and the blue ones crossing and diverging across a hand drawn version of the city he had ridden every day for two years.\n"There is a delivery," Agbonlahor said, "that I have been holding for three days because I do not have a rider I trust to move it. The recipient is in Aduwawa. The item is clean. Not documents but clean, nothing that touches Coker''s world or Danladi''s substitution. The recipient owes me a favour of sufficient size that completing this delivery tonight, before six o clock, would allow me to call that favour in and have him speak to Coker directly."\n"You want me to ride for you," Osaro said. "After everything."\n"I want you to understand the situation completely and then make your own decision."\n"You chose us," Osaro said. "From before the market wall. You watched us and you selected us and you used my uncle''s history with you to find your way to us. And now you are sitting in this room telling me you need my help."\nAgbonlahor did not flinch. "Yes."\n"Why us. From the beginning. Why Ehigie''s boys."\nThe quiet man was quiet for a moment. The curtain moved slightly in a draft from somewhere.\n"Because your uncle is the most honest man I have ever done dishonest business with," Agbonlahor said. "And I believed that quality had passed to at least one of you." He paused. "I was right about one and wrong about the direction. I thought it would be Idemudia. He is older, more experienced. I did not expect it to be the seventeen year old with the notebook."\nOsaro looked at the maps again. The red corridors and the blue ones.\nHe thought about Idemudia in a compound off Ugbor Road with a man named Coker counting down to six o clock. He thought about his uncle on the step in the dark with no radio and no tea. He thought about the notebook in his jacket pocket, the columns, the figure at the bottom that he had been building toward for two years.\nHe thought about what it meant that he was sitting in this room and the room had not surprised him as much as it should have.\n"Show me the route," he said.\nAgbonlahor turned one of the hand drawn maps to face him. His finger traced a line from the centre of the city to Aduwawa, a route Osaro knew better than his own name.\nEnobakhare moved from the door to the table and sat down. He placed a bag on the table between them, canvas, medium sized, no combination lock.\nOsaro looked at it.\n"Open it," Agbonlahor said.\nOsaro opened it. Inside was a sealed envelope and a mobile phone still in its original packaging and nothing else.\nHe closed it.\n"What time," he said.','\n',char(10)),1136,1,1,NULL,'2026-04-18T06:37:07.601Z','2026-04-18 06:37:07','2026-04-18 06:37:07','2026-04-18T07:00:00.000Z',2,42);
INSERT INTO "chapters" ("id","novel_id","chapter_number","title","content","word_count","is_premium","is_published","audio_url","published_at","created_at","updated_at","scheduled_release_at","part_number","season_id") VALUES(485,59,5,'Two Versions of Loyalty',replace('The delivery took forty minutes.\nOsaro rode the Aduwawa route the way he had ridden it a thousand times, with the particular attention of a person who knows a road so well that the knowing has become the body''s work rather than the mind''s. He did not think about the bag. He thought about the time, four seventeen when he left the Ugbor Road compound, and about the specific quality of the afternoon traffic on the approach to Aduwawa, which was thicker on Saturdays and required patience at two junctions that had no patience to give on a weekday.\nThe recipient was a man at a provision store who took the bag without ceremony, looked inside, nodded once, and gave Osaro an envelope in return. Not money. A folded note with a name and a phone number and three words written beneath them in careful handwriting.\nTell him tonight.\nOsaro photographed it and sent the image to Agbonlahor before he had left the store''s frontage. Agbonlahor''s response was a single word. Good.\nHe called Enobakhare from the road.\n"It is done," he said. "Where is the compound."\nEnobakhare gave him the address. It was not the same compound off Ugbor Road where Agbonlahor worked. It was further east, a residential street that began ordinarily and became quieter the deeper you went into it, the houses set further back, the walls higher, the sound of the main road fading behind you like a conversation you have walked away from.\nThe gate was blue. A man opened it before Osaro knocked, which meant he had been watched from the street, and led him through a compound that was larger than its outer wall suggested, with a generator running somewhere at the back and two vehicles parked side by side under a corrugated shelter.\nCoker was not what Osaro had built in his mind during the night.\nHe was perhaps fifty, heavyset, with a close trimmed beard going grey and the expression of a man who had long ago stopped being surprised by the things people did for money. He was seated in a covered area at the side of the main building, eating from a plate of rice with the unhurried manner of someone who had decided that whatever was about to happen could wait until he had finished eating.\nHe looked at Osaro. He looked at the phone Agbonlahor had called him on twenty minutes earlier, now sitting face up on the table beside his plate.\n"You are the younger one," he said.\n"Yes."\n"Sit."\nOsaro sat.\nCoker ate two more forkfuls of rice. He was not performing. He was simply finishing his food.\n"Your man called me," he said. "The favour is accepted. Your cousin can go." He picked up the phone and turned it face down. "I want you to understand that I do not hold boys responsible for what men above them put in bags. Your cousin was in the wrong place because someone above him was dishonest. That is not his sin."\n"I understand."\n"Good." Coker picked up his fork again. "He is in the room at the end of the passage. He knows he is free. He has known for the last fifteen minutes."\nOsaro stood and walked to the passage.\nThe room at the end was small, a cot, a window with a metal grille, a plastic chair. Idemudia was on the cot with his back against the wall and his long legs stretched out in front of him. He was eating chin chin from a bag. He looked, physically, completely unharmed, which was the first thing Osaro checked and the only thing that prevented the next several seconds from going differently.\nIdemudia looked at him.\n"You did a run for Agbonlahor," he said.\n"How do you know that."\n"Because you are here and I am free and there is no other way that happens before six o clock." He put a piece of chin chin in his mouth. "Sit down, Osaro."\nThere was only the plastic chair. Osaro sat in it.\n"Are you hurt," Osaro said.\n"No."\n"Did anyone touch you."\n"No. They fed me twice and left me alone." Idemudia looked at the grilled window. "Coker is not the kind of man I expected. He apologised to me this morning. Said the situation was above my level and he was sorry I had been caught in it."\nOsaro looked at his cousin. At the familiar set of his shoulders and the scar on his left forearm and the particular quality of stillness that Idemudia had when he had made a decision and the decision had settled completely into him.\n"You are not coming home," Osaro said.\nIt was not a question. He had felt it from the doorway.\nIdemudia looked at him directly. "Not tonight."\n"Idemudia."\n"Listen to me." He sat forward. "I have been in this room for sixteen hours and I have had nothing to do but think and what I have thought is this. I was angry about being held. I was not frightened. That is information about myself that I cannot ignore." He paused. "I understand this world, Osaro. I understand how it moves and how the people in it think. I am not saying it is a good world. I am saying I fit inside it in a way I have never fit inside the other one."\n"The other one is the one that does not end with you in a room with a grille on the window."\n"The other one ended with our fathers," Idemudia said quietly. "Both of them. Doing everything right and ending up with nothing and dying before they could explain why."\nThe word fathers sat between them in the small room.\n"I am not our fathers," Osaro said.\n"I know that."\n"Then come home."\nIdemudia looked at him with an expression that contained everything they had ever been to each other and everything they were no longer going to be in the same way, the love and the divergence occupying the same space in his face without contradiction.\n"I am going to talk to Agbonlahor," he said. "Properly. As someone who understands the network and what went wrong with Danladi and what needs to happen to fix it. Not as a rider. As someone with a different value."\n"You are going to work for him."\n"I am going to work with him. There is a difference."\nOsaro stood. The plastic chair scraped the floor.\n"You told me once," he said, "that the straight road was not safe just because it was slow. You told me slow and safe are not the same thing." He looked at his cousin. "I am telling you now that fast and safe are not the same thing either."\nIdemudia nodded. "I know."\n"And you are still staying."\n"For now."\nOsaro stood in the doorway of the small room and looked at his cousin on the cot with his chin chin and his long legs and his decision that had the particular solidity of something that had been made in full understanding of its cost.\n"I will tell Uncle you are safe," he said.\n"Tell him I am sorry."\nOsaro walked back through the passage into the compound where the generator ran and the two vehicles sat under their shelter and the late afternoon light was going the colour of old copper across the walls.\nHe did not look back.','\n',char(10)),1241,1,1,NULL,'2026-04-18T06:38:21.961Z','2026-04-18 06:38:22','2026-04-18 06:38:22','2026-04-18T07:00:00.000Z',2,42);
INSERT INTO "chapters" ("id","novel_id","chapter_number","title","content","word_count","is_premium","is_published","audio_url","published_at","created_at","updated_at","scheduled_release_at","part_number","season_id") VALUES(486,59,6,'The Third Bike',replace('Ehigie was not on the step when Osaro got back.\nHe was in the yard, standing beside the two bikes under the zinc sheet, doing something Osaro had not seen him do in a long time. He was checking them. Not the careful mechanical inspection they did before a riding day, but the slower kind, the kind where a person moves their hands over a thing they value and the moving is not really about the thing but about the need to be in contact with something that is still present and still theirs.\nOsaro stood at the broken gate and watched him for a moment before coming in.\n"Idemudia is safe," he said.\nHis uncle straightened slowly. He turned and looked at Osaro with the specific attention of a man receiving the most important piece of information in a long and difficult day.\n"Unharmed," Osaro said. "He was fed. Nobody touched him."\nEhigie let out a breath that seemed to have been inside him since midnight. He put one hand on the seat of the older bike and stood that way for a moment, not speaking.\n"He is not coming back tonight," Osaro said. "He is talking to Agbonlahor. He has decided on a direction and I cannot change it."\nHis uncle nodded once. The nod of a man who already knew the shape of this outcome and had been waiting only to have its details confirmed.\nThey went inside. Ehigie made food, the simple kind, rice and a thin stew that needed more time than they gave it, but neither of them said anything about that. They ate at the kitchen table in the ordinary way and the ordinariness of it was its own kind of relief.\nAfter, Osaro took his notebook to the table.\nHe had not opened it since the night Idemudia left for Oregbeni. It felt different in his hands now, lighter in a way that had nothing to do with its physical weight. He opened it to the last written page and looked at the columns.\nThe numbers were still there. Two years of careful fares and fuel costs and patient subtractions. The figure at the bottom of the right column was the same figure it had been when he last looked at it, before the deliveries, before Reservation Road and Ugbor Road and Aduwawa this afternoon.\nBut the money from the three deliveries was also in the notebook, folded between pages. His share of two runs and the payment for this afternoon''s job, which Agbonlahor had sent to his phone before he left the blue gate compound, the correct amount, without being asked.\nHe had not touched that money since he put it in the notebook. He had not touched it because counting it felt like deciding something before he was ready to decide it.\nHe counted it now.\nAdded to his running total it brought him to within a single month of the polytechnic number. One month of clean ordinary riding on the two remaining routes, no more briefcases, no more blue gates. Four weeks. The number was right there, close enough to see its face.\nHe sat with that for a long time.\nThe price had changed shape. That was the accurate thing to say about it. The money was real, the polytechnic was real, the four weeks were real. But between the figure at the bottom of his column and the brochure in the back of the notebook there was now a history that had not been there when he started the columns at fifteen. The deliveries. The rooms. The maps with red corridors and blue ones. Idemudia on a cot with his chin chin and his made decision.\nYou could not unlearn the shape of a network once you had seen it drawn on a wall in two colours.\nEhigie came in from the yard and sat across from him. He looked at the open notebook without reading it.\n"I want to show you something," his uncle said.\nHe went to his room and came back with a small key, old, the kind that opened a padlock rather than a door. He set it on the table between them.\n"There is a storage room at Mama Osakue''s compound next door," he said. "Third door from the back. I have been paying the rent on it for two years."\nOsaro looked at the key. "What is inside."\n"Parts. A frame. A 2015 engine that needs work but is sound." Ehigie folded his hands on the table. "I have been collecting it piece by piece. When I could. From sales I did not mention and savings I kept separate." He looked at the key. "I was going to tell you when you reached your number. I did not want it to be a reason you lowered your guard."\nOsaro understood what he was being told.\nThere was a third bike.\nNot whole yet, not rideable, but present. Assembled in pieces in a room next door, built quietly by a man with a damaged hand over two years of small decisions, the way some people build things, without announcement, with patience, with the particular faith of someone who cannot afford to stop believing in the value of what they are making.\nHe looked at his uncle across the table.\nEhigie met his eyes. "The number you are carrying," he said, "was never only yours to carry."\nOsaro closed the notebook.\nHe picked up the key and held it in his hand and said nothing, because some things do not need language. They only need to be held.','\n',char(10)),935,1,1,NULL,'2026-04-18T06:39:40.018Z','2026-04-18 06:39:40','2026-04-18 06:39:40','2026-04-18T07:00:00.000Z',2,42);
INSERT INTO "chapters" ("id","novel_id","chapter_number","title","content","word_count","is_premium","is_published","audio_url","published_at","created_at","updated_at","scheduled_release_at","part_number","season_id") VALUES(487,59,7,'Someone Talks',replace('The first sign was a different kind of silence on the Slope.\nOsaro noticed it on Tuesday morning, three days after the blue gate compound and the third bike key and the notebook closed on its new number. He noticed it the way you notice something that is defined by absence rather than presence, the hawker who usually worked the Slope entrance was not there, the two boys who parked their bike at the lower junction had moved it, and the woman who sold akara from a tray near the market wall was packing up two hours earlier than usual.\nNot one of these things alone meant anything. Together they had a texture he recognised.\nThe street was adjusting itself around something it knew that he did not.\nHe finished his fares and went home earlier than usual and did not mention it to Ehigie.\nOn Wednesday Enobakhare called.\n"Someone talked," he said, without greeting, without preamble, in the voice of a person delivering information that has a shelf life. "About the deliveries. About you and Idemudia specifically. The source is someone inside the network, not Agbonlahor''s level but connected enough to know names and routes and the shape of what happened at Oregbeni."\n"Who did they talk to," Osaro said.\n"An investigator. Not uniformed police. Someone working a private brief, which means someone on the other side of the network paid him to find the loose end of the Oregbeni situation and pull it."\nOsaro sat down on the step. The rooster was near his feet, moving in its usual small circles.\n"Why would someone on the other side pay for that."\n"Because Danladi''s substitution embarrassed people above Agbonlahor. People who do not like being embarrassed and who want the full chain of the mistake documented and held. You and Idemudia are part of that chain."\n"We were riders. We did not know what we were carrying."\n"I know that. You know that. The investigator is not looking for guilt. He is building a picture. Everyone in the picture becomes useful to whoever commissioned the picture." Enobakhare paused. "He has your name. He has your usual routes. He has the compound address."\nOsaro looked at the broken gate.\n"Agbonlahor," he said.\n"Is aware. He is managing it from his end. But there is a version of this where his management does not cover you fast enough and you are approached before he can get in front of it."\n"Approached how."\n"Questions. Documentation. The private kind that becomes official quickly if the person asking decides it should." Enobakhare''s voice was careful and precise, each word placed where it would land clearly. "You need to be less visible on the routes for a few days. Not invisible. Not running. Just less present."\nThe call ended.\nOsaro sat on the step and looked at the yard and thought about what less visible cost in a week where he was one month from his number. Four weeks had now become three and a half and three and a half was a count he could feel in the way a person feels a distance they have been walking for a long time.\nHe told Ehigie that evening.\nHis uncle listened with the same stillness he brought to all difficult information, receiving it completely before responding.\n"How serious," Ehigie said.\n"Serious enough that someone paid for it."\n"Do you know who."\n"No. Someone above Agbonlahor who wants the Oregbeni mess documented."\nEhigie was quiet. Then he said, "This is the cost of the deliveries finding you. Not the doing of them. The existing of them."\nOsaro nodded.\n"The investigator," Ehigie said. "Private brief. That kind of man works from what he has been given. If what he has been given is names and routes, he will come to the routes." He looked at the two bikes under the zinc sheet through the kitchen window. "Do not be on the routes for three days."\n"Three days is money."\n"Three days is also the time it takes for a private investigator to decide a subject has moved on and redirect his attention." Ehigie looked at him. "I have experience with this kind of attention. Three days of patience is cheaper than one day of being found."\nThe next morning Osaro did not ride.\nHe went instead to Mama Osakue''s compound and unlocked the third door from the back and stood in the small storage room with the key in his hand and looked at what his uncle had been building.\nThe frame was a good one, solid, the kind that lasted. The engine sat beside it wrapped in cloth, oil stained but intact. Beside the engine were two cartons of parts, sorted and labelled in his uncle''s handwriting, small paper tags tied to each component with a date and a source note. A man with a damaged hand had done this sorting. Had tied each small tag with careful fingers and a patience that had no audience.\nOsaro crouched beside the engine and put his hand on it.\nOn the second day a man came to the compound.\nOsaro saw him through the gap in the broken gate before the man knocked. Plain clothes, a notebook in his shirt pocket, the particular way of standing on an unfamiliar street that belongs to someone who has come with a specific purpose. He knocked twice. Waited. Knocked again.\nEhigie answered.\nOsaro watched from inside the kitchen doorway. He could not hear the full conversation but he could see his uncle''s posture and the way his uncle''s hands stayed at his sides, open, unhurried, the body language of a man who has spoken to this kind of visitor before and knows that the performance of having nothing to hide is itself a skill.\nThe conversation lasted four minutes.\nThe man wrote something in his notebook, nodded, and left.\nEhigie came inside and closed the door and stood in the kitchen with his back against it.\n"He asked about my riders," he said. "I told him I had one current rider, my nephew, seventeen, studying for polytechnic entrance. I told him my other rider, a relative, had gone to stay with family in Edo North three days ago for a personal matter."\nOsaro looked at his uncle.\n"Is that true," he said. "About Idemudia. Edo North."\nEhigie looked at him steadily. "It is true that I do not know where Idemudia is sleeping. Edo North is as accurate as anywhere else I could have said."\nOsaro understood. His uncle had not lied. He had arranged the truth.\n"Did he believe you," Osaro said.\n"He believed that I was an old man with a bad hand and two bikes and a nephew who was going to polytechnic." Ehigie moved to the table and sat. "Which is exactly what I am."\nOn the third day nothing happened, which was its own kind of answer.\nOsaro rode on the fourth morning. The Slope was back to its ordinary configuration, the akara seller, the boys at the junction, the sound of a street that has resumed itself after holding its breath.\nHe did seven fares before noon.\n','\n',char(10)),1192,1,1,NULL,'2026-04-18T06:40:37.781Z','2026-04-18 06:40:37','2026-04-18 06:40:37','2026-04-18T07:00:00.000Z',2,42);
INSERT INTO "chapters" ("id","novel_id","chapter_number","title","content","word_count","is_premium","is_published","audio_url","published_at","created_at","updated_at","scheduled_release_at","part_number","season_id") VALUES(488,59,8,' Choosing Yourself',replace('Agbonlahor called on a Thursday.\nOsaro was on the Slope, between fares, sitting on the low wall where the quiet man had first sat beside him with his groundnuts and his briefcase and his careful patience. Osaro had not thought about the symmetry of this until the phone rang and he saw the name and looked up and understood where he was sitting.\nHe answered.\n"I need a conversation," Agbonlahor said. "Not a job. A conversation."\n"We can have it now."\n"In person."\nOsaro looked at the wall beneath him. At the market continuing around him, the same stalls and the same noise and the same ordinary motion of a city that did not know or care what had happened to two cousins on its roads over the past several weeks.\n"Ugbor Road," he said. "One hour."\nHe called Enobakhare first. He had started doing this, calling Enobakhare before any meeting with Agbonlahor the way you check a road before you commit to it. Enobakhare told him the investigator situation had been managed, that the person who commissioned the brief had been satisfied with the documentation and had closed the inquiry. He said it the way he said most things, precisely and without decoration.\n"Is Idemudia with Agbonlahor," Osaro asked.\nA pause. "Yes."\nOsaro sat with that for a moment, then thanked him and ended the call.\nAgbonlahor was at the table when Osaro arrived, the hand drawn maps still on the wall, the curtain pulled three quarters across. Idemudia was in the chair to his right.\nThey looked at each other, the cousins. It had been eight days. Idemudia looked the same, same scar, same broad shoulders, same quality of stillness. Something in his eyes had settled further in a direction Osaro recognised as permanent.\nOsaro sat.\nAgbonlahor spoke first.\n"I want to offer you a position," he said. "Not riding. Coordination. You understand routes, timing, the pressure points in the city''s movement economy. I have watched you think for two months and I am telling you that the way you think is worth more than what you are currently doing with it."\nHe said a monthly figure.\nThe figure was not what the deliveries had paid. It was steadier, structured, the kind of number that belonged to an arrangement rather than a single job. It was also, calculated across twelve months, enough to cover the polytechnic cost and leave something behind.\nOsaro looked at the maps on the wall.\n"You would not ride," Agbonlahor continued. "You would plan. Routes, timing, contingencies. Think of it as applied mathematics." He said this last part with the specific quality of a man who has researched his offer before making it. He had known about the notebook. He had probably always known.\nOsaro looked at Idemudia.\nHis cousin met his eyes and said nothing. He was not pushing. He was not the argument for the room or the proof that the arrangement worked. He was simply sitting there the way he had always sat, steady and already decided, and whatever he felt about what Osaro was about to say was held somewhere Osaro could not reach.\n"Can I ask you something," Osaro said to Agbonlahor.\n"Yes."\n"The network above you. The politicians, the businessmen. The arrangement that uses the city''s movement without owning it." He paused. "Does a coordinator become part of that arrangement. Over time. Does the work stay at your level or does it move upward toward theirs."\nAgbonlahor looked at him for a long moment.\n"It depends on the person," he said.\n"That is not an answer."\n"It is the only honest one."\nOsaro nodded slowly. He looked at the maps one more time, at the red corridors and the blue ones, at the hand drawn version of the city he had ridden every day for two years, all its routes and pressure points laid out in two colours on a wall in a room with a curtain pulled three quarters across.\nHe thought about the notebook in his jacket. The columns. The figure at the bottom that was now three weeks from completion if he rode cleanly and kept his head down and did not let anything pull him off the road he had been building since he was fifteen.\nHe thought about the storage room at Mama Osakue''s compound and the engine wrapped in cloth and the paper tags in his uncle''s handwriting and what it meant that a man with a damaged hand had tied each one.\nHe thought about what Idemudia had said in the yard the night the arguments were still fresh. Your polytechnic math is beautiful. Said without cruelty. Said as a true thing that was not enough.\nIt was enough. That was what Idemudia had never understood and what Osaro could not explain because it was not an argument but a conviction, the kind that lives below language in the place where a person keeps the things they are made of.\n"No," he said.\nThe word was clean. No building and no case around it, no apology underneath it. Just the word, placed in the room the way his uncle placed his cup, with care and finality.\nAgbonlahor looked at him. Something moved in the man''s face that was not disappointment exactly. It was closer to recognition.\n"I respect that," he said quietly.\nOsaro stood. He looked at his cousin.\nIdemudia looked back. His expression did not ask Osaro to change his answer. It did not grieve it. It simply held it, the way you hold something that belongs to someone else, carefully and without possession.\n"Take care of yourself," Osaro said.\n"You too," Idemudia said.\nOsaro walked out of the room, through the courtyard, past the two men on the bench, through the brown door into the Benin City street.\nHe stood on the pavement for a moment in the afternoon heat.\nThen he got on his bike and rode back to the Slope.','\n',char(10)),993,1,1,NULL,'2026-04-18T06:41:54.740Z','2026-04-18 06:41:54','2026-04-18 06:41:54','2026-04-18T07:00:00.000Z',2,42);
INSERT INTO "chapters" ("id","novel_id","chapter_number","title","content","word_count","is_premium","is_published","audio_url","published_at","created_at","updated_at","scheduled_release_at","part_number","season_id") VALUES(489,59,9,' Idemudia''s Last Run',replace('The city looked different at five in the morning.\nIdemudia had always known this and had never had anyone to tell it to, because the people in his life who would have understood it were not awake at five in the morning, and the people who were awake at five in the morning did not talk about what the city looked like. They just moved through it, which was its own kind of understanding.\nHe was riding the Sapele corridor before the sun had fully committed to the day, carrying nothing, going nowhere specific, which was the kind of riding he did now when he needed to think. Agbonlahor had given him this, among other things. Time. The freedom to move without a destination, which sounds like nothing until you have spent years moving only toward something and discover that the absence of a fixed point is not emptiness but space.\nHe thought about Osaro.\nHe had been thinking about Osaro since Thursday, since his cousin had sat across from Agbonlahor and said no with the clean simplicity of a person who has located themselves so completely that the word requires no support structure. Idemudia had watched it happen and had felt two things simultaneously, pride and grief, which he had since understood were not contradictory but were the two sides of loving someone whose road has diverged from yours.\nHe turned off the Sapele corridor onto the depot road, the same road they had ridden together on the first delivery, and let the bike find its own pace on the uneven surface.\nThat night felt distant and close at the same time. He remembered Osaro behind him, the weight of his cousin''s attention on his back, the particular quality of presence that Osaro had always had, watchful and steady, the kind of person who sees everything and processes it quietly and does not speak until the speaking will be useful. He had ridden that road with Osaro behind him and had felt, underneath the nerves and the calculation, something that he recognised now as the last version of a thing before it changed.\nThe last ride where they were still going the same direction.\nHe did not regret the direction he had taken. That was the truth he had been sitting with since the room with the grille and the cot and the sixteen hours of thinking. He had regret about specific moments, the way he had put Osaro''s father in front of him that night in the yard, that had been a wound dressed as an argument and he knew it and he was ashamed of it. He had regret about the Oregbeni run, not for taking it but for the way his certainty had closed its ears to everything Osaro had said that was actually correct.\nBut the direction itself. The choice of this road. He did not regret it.\nHe turned onto the long straight road with the water tower at its end, grey and familiar in the early light. He slowed and stopped where they had stopped before Idemudia rode to the green gate. The gate was closed now and the single bulb above it was off and the road was empty in both directions.\nHe sat on the idling bike and looked at it.\nWhat Osaro had never fully understood, or perhaps had understood and chosen not to accept, was that Idemudia''s road was not the absence of a plan. It was a different plan. Built from different materials and aimed at a different kind of arrival, but a plan, held with the same seriousness that Osaro held his columns and his brochure and his four weeks of clean riding.\nHe had watched his uncle''s hand. He had watched what happened to men who built carefully in a city that did not care about careful. And he had decided, not impulsively but over years of quiet observation, that the only way to be safe in a city like this was to understand its actual structure, not the surface of it, the roads and the fares and the route maps, but the deeper structure, the arrangement beneath, the way power actually moved and who actually held it.\nAgbonlahor was not the end. Agbonlahor was the door.\nAnd Osaro, with his beautiful math and his honest notebook, was going to polytechnic.\nBoth of these things were true. That was the part he had needed sixteen hours on a cot to fully hold. He had spent two years believing that one of them being right meant the other was wrong, and that belief had bent every conversation they had about the future into an argument. But sitting in the small room with the grille on the window, he had understood that Osaro''s road being real did not make his own road false. They were just roads. Going different places.\nHe turned the bike around on the long straight road and began riding back toward the city.\nThe sun was properly up now and Benin was becoming itself, layer by layer, the generators and the voices and the particular noise of a city returning to its daily life. He rode through it with the attention he always gave the road and the something extra underneath that attention that had always been his, the feeling of a man in his element, moving through the world in the way the world was built for him to move through it.\nHe thought about the broken gate.\nHe thought about going to fix it, not announcing it, just arriving one morning with the right tools and the time to do it properly. A thing Ehigie would wake up and find done. He would do it soon. Before Osaro left for Auchi. Before the compound changed its shape into whatever it was going to be after.\nHe owed his uncle a fixed gate. He owed Osaro nothing, which was the deepest form of what they were to each other.\nHe accelerated onto the main road and let the city receive him the way it always had, without ceremony, without condition, as one of its own.','\n',char(10)),1022,1,1,NULL,'2026-04-18 06:49:01','2026-04-18 06:43:12','2026-04-18 06:49:01','2026-04-18T07:00:00.000Z',2,42);
INSERT INTO "chapters" ("id","novel_id","chapter_number","title","content","word_count","is_premium","is_published","audio_url","published_at","created_at","updated_at","scheduled_release_at","part_number","season_id") VALUES(490,59,10,'Season 2, Episode 10: Benin, After',replace('The letter from Auchi Polytechnic arrived on a Wednesday.\nEhigie brought it inside from the gate without opening it and set it on the kitchen table and went back to his tea, which was either faith or the particular patience of a man who has learned that the outcome of a thing does not change based on how quickly you look at it.\nOsaro stood at the table for a moment with the envelope in front of him. Then he sat down and opened it with the same steadiness his uncle brought to everything, both hands, no tearing.\nHe read it twice.\n"Well," Ehigie said.\n"Yes," Osaro said.\nHis uncle nodded and drank his tea.\nOutside in the yard the two bikes were under their zinc sheet and the rooster was doing its morning work and the broken gate was no longer broken. It had been fixed three weeks ago, on a Tuesday before anyone was awake, with new hinges and a coat of black paint that was still the freshest thing in the compound. Nobody had mentioned it and nobody needed to. The gate simply worked now, opening and closing cleanly, the way things do when someone who understands them has given them the right attention.\nOsaro folded the letter and put it in the back of his notebook, behind the Auchi brochure whose fold lines had gone soft from handling.\nHe did not stop riding the day the letter arrived. There were still two weeks before the reporting date and two weeks was two weeks and the columns in the notebook had not stopped mattering just because the number had been reached. He rode the Slope in the morning and Aduwawa in the afternoon and came home in the evenings with his fares recorded and his fuel costs subtracted and the notebook balanced against the day.\nHe had not heard from Idemudia directly since the Ugbor Road compound. He heard about him the way you hear about someone whose life has moved into a register you do not have full access to, in small pieces, from Enobakhare mostly, who called occasionally with the careful brevity of a person managing the distance between two worlds he inhabited simultaneously. Idemudia was well. Idemudia was working. Idemudia had moved to a different part of the city.\nIt was enough and it was not enough and Osaro had made his peace with both of those things being true at once.\nOn the last Friday before he left he rode every route he knew.\nNot for fares. He went out at six in the morning before the traffic had built and he rode the Slope from end to end and then Aduwawa and then the depot road and the long straight road with the water tower and then back through the city''s main corridors, all the streets he had mapped in his notebook and in his body over two years of daily riding. He rode them the way you read something for the last time before returning it, with full attention, taking nothing for granted.\nThe city received him the way it always had. Without acknowledgment, without ceremony, with the complete indifference of a place that contains too much living to mark the passage of any single person through it.\nHe had loved it for that, once. The indifference. The feeling of being one of many, anonymous in the best way, a person on a road who knew his road and needed nothing beyond that.\nHe still loved it. He just understood it differently now.\nHe was at the Slope market wall at half past nine, sitting where he had sat a hundred times, when he heard a motorcycle stop behind him and felt the quality of the silence that followed it.\nHe did not turn around immediately. He ate the last of his groundnuts from their paper cone and folded the cone into a small square the way Idemudia folded things and then he turned.\nIdemudia was on a bike Osaro did not recognise, newer than either of Ehigie''s, with the particular shine of something recently and deliberately purchased. He was wearing his same jacket and his same expression and the scar on his left forearm caught the morning light the way it always had.\nHe looked at Osaro. Osaro looked at him.\n"I heard about Auchi," Idemudia said.\n"Enobakhare."\n"Enobakhare." He almost smiled. "I fixed the gate."\n"I know."\nIdemudia looked at the market around them, the stalls and the noise and the ordinary motion of the morning.\n"I am going to come and see you off," he said. "When you leave. If that is acceptable."\n"It is acceptable," Osaro said.\nIdemudia nodded. He turned the bike in the road with the easy authority of a man entirely at home on his machine and rode back into the city without looking back.\nOsaro sat on the wall for another minute.\nThen he got on his bike and rode home to the compound with the fixed gate and the uncle and the two bikes and the third one almost ready in the room next door. He rode without a destination because he was already where he was going. He rode because the road was still the road, the same road it had always been, and where it took you depended entirely on who you were when you got on it.\nHe parked in the yard.\nHe went inside.','\n',char(10)),906,1,1,NULL,'2026-04-18T06:44:37.913Z','2026-04-18 06:44:37','2026-04-18 06:44:37','2026-04-18T07:00:00.000Z',2,42);
INSERT INTO "chapters" ("id","novel_id","chapter_number","title","content","word_count","is_premium","is_published","audio_url","published_at","created_at","updated_at","scheduled_release_at","part_number","season_id") VALUES(491,60,1,'The Last Row',replace('The back row of SS2B had three qualities that every student at Goldcrest Academy privately acknowledged: the ceiling fan above it had not worked since the previous academic year, the window beside it admitted noise without breeze, and no one who possessed any social standing whatsoever ever chose to sit there.\nThat last point was the one that mattered.\nKachi occupied the far left seat because the wall was there and the wall required nothing from him. He had a novel balanced on his lap below the desk edge, not because any rule prohibited it but because explaining what he was reading reliably produced conversations he had no desire to sustain. He had been attempting the same paragraph for eleven minutes. Emeka was talking again.\nTwo seats away, Emeka had tilted his chair back to the exact angle that still technically qualified as sitting. He was in the middle of a story about a night guard, a missing generator, and something that may or may not have been a goat, and the two boys in the row ahead were laughing hard enough to vibrate their chairs. Emeka had a particular quality. He entered a silent room and the silence became something else before anyone could stop it. His parents found this exhausting. Most teachers found this exhausting. Emeka found it entirely practical.\nThe unoccupied seat between him and Nasiru was not accidental. Nasiru had placed his bag there in the first week of term and no one had questioned it. He sat with his back straight, wrote in clean horizontal lines, and watched things. Not people precisely. Things. The shift in a room''s temperature that came just before a teacher lost patience. The small change in posture that arrived just before a lie finished forming. He had attended Goldcrest since JSS1 and had eaten lunch without company for four years. Not from lack of options. From a deliberate assessment of the available options and a conclusion that none of them were worth the negotiation.\nAt the right end of the row the two girls had arrived at their seating arrangement through something closer to mutual indifference than any conscious decision. Adun sat nearest the window because the natural light was better and her notes were not something she approached without intention. Organized by subject, separated by color, not a margin wasted. The product of six consecutive terms at the top of SS2B, a record she carried the way certain people carry a family name: quietly, and without apology.\nYewa sat at the final seat against the wall. She was the youngest student in the class by nearly a full year, a fact she acknowledged only by never acknowledging it. When people raised it she regarded them with the patient expression of someone waiting for an unusually slow sentence to find its end. She was drawing in the margin of her chemistry notebook when Mr. Chukwu walked in, and she did not look up because Mr. Chukwu always came in alone, top collar button undone, usually four minutes past the hour.\nHis button was done up today.\nVP Amaechi was behind him.\nYewa put her pen down.\nVP Amaechi did not visit classrooms. He appeared at assemblies, at disciplinary proceedings, and at the particular category of school moment that ended up recorded in red ink. His presence in a doorway had a specific effect. Conversation stopped in reverse order, back row to front, like a tide pulling away from shore. Even Emeka stopped.\nMr. Chukwu set his things down without looking at the class. This was wrong. He always looked first, found someone to greet or someone to correct. Today his eyes went to the desk and stayed there.\nVP Amaechi walked to the front and let the silence sit for one beat longer than comfort allowed.\n"I will need the following students to stand."\nHe read from a sheet of paper. He did not look up from it once.\n"Onyekachi Okafor."\nThe novel slid from Kachi''s lap to the floor. He left it there.\n"Chukwuemeka Dike."\nEmeka''s chair returned to all four legs. His mouth, for once, did not open.\n"Adunola Bankole."\nAdun set her pen down with the steadiness of someone who needed to be performing some small act of control.\n"Yewande Adesanya."\nThe pen stayed in Yewa''s hand. She was not drawing.\n"Nasiru Lawal."\nFive students stood. Thirty-one others turned to look, and the looking carried something heavier than curiosity. It was recognition. The back row. The dead fan and the useless window and the seats nobody ever fought for. Naturally it was the back row.\n"These five students," VP Amaechi said to the class, his eyes still on the sheet, "are being questioned in connection with the leak of the SS2 mid-term biology examination paper."\nThe sound that moved through the room was not quite a gasp. It was the class releasing something it had been holding from the moment he walked in.\n"You will come with me now."\nHe turned and walked out. Mr. Chukwu stepped aside and looked at the window.\nKachi picked his novel up from the floor, closed it, and put it in his bag. He could not have explained why. Some part of him was still performing ordinary life even as ordinary life quietly stopped being true.\nThey filed out into the corridor. The door swung shut behind them, and through it, immediately, came the sound of thirty-one voices deciding what all of this meant.','\n',char(10)),913,0,1,NULL,'2026-04-18T19:13:37.021Z','2026-04-18 19:13:37','2026-04-18 19:13:37','2026-04-18T19:30:00.000Z',1,NULL);
INSERT INTO "chapters" ("id","novel_id","chapter_number","title","content","word_count","is_premium","is_published","audio_url","published_at","created_at","updated_at","scheduled_release_at","part_number","season_id") VALUES(492,60,2,'Office of Shame',replace('The corridor outside VP Amaechi''s office had one bench.\nIt seated three people if nobody had a bag. They had bags. Kachi sat at one end, Nasiru at the other, and the space between them contained Emeka, Adun, and Yewa in an arrangement that satisfied nobody. The corridor smelled of floor wax and the particular anxiety that old institutions absorb into their walls over decades. A secretary typed behind a frosted glass partition and did not look at them once, which told them everything they needed to know about how this was already being regarded.\nVP Amaechi called Adun first.\nShe went in with her back straight and her folder held against her chest and came out seven minutes later with her back still straight and her folder still held the same way. She sat back down and looked at the wall opposite and said nothing. Emeka opened his mouth. She turned her eyes to him with an expression that closed the question before it formed.\nEmeka went in second, which surprised nobody. VP Amaechi probably calculated that separating Adun and Emeka was the sensible order of operations. He came out after nine minutes looking for the first time since the classroom like a person who was not entirely certain what to do with his hands. He sat, put both hands on his knees, and studied them with focused attention.\nNasiru went third. Six minutes. He came out and returned to his end of the bench and resumed the posture he had maintained before going in, which was the posture of someone who had not just spent six minutes in a room with VP Amaechi.\nYewa went fourth. She came out after eight minutes and sat and took her phone from her pocket and stared at the screen without unlocking it.\nKachi went last. VP Amaechi gestured to the chair across from his desk and waited for it to be occupied before he said anything. The office had the same portrait of the school''s founder on every wall that every office in Goldcrest had. Four different angles of the same man, watching.\n"You sit in the back row," VP Amaechi said. It was not a question.\n"Yes sir."\n"By choice?"\nKachi considered the question longer than was probably useful. "Yes sir."\nVP Amaechi made a note. The notepad was positioned so that its contents were not visible, a detail Kachi registered and filed away.\n"The biology paper for the mid-term examination was removed from the administration block three nights ago between the hours of eight and ten pm. Your name has been provided to this office in connection with that removal." He looked up. "What do you have to say?"\n"I wasn''t there sir."\n"Where were you?"\n"At home."\n"Anyone who can confirm that?"\n"My mother. Our gateman."\nAnother note. VP Amaechi put his pen down and looked at Kachi with the expression of a man who had already done the paperwork and was now simply completing the formality of the conversation.\n"You will all return to your classes for now. The five of you will present yourselves here on Friday morning together. If the matter is not resolved satisfactorily before then, it goes to the board at the end of ten days. The board''s involvement will have consequences for your academic records that this office will not be in a position to reverse." He picked his pen back up. "You may go."\nKachi went.\nWhen he came out all four of them were still on the bench. The secretary was still typing. Nobody had moved anywhere. He stood in front of them for a moment, uncertain whether to return to his end or remain standing, and the problem solved itself when Adun stood up and walked to the end of the corridor without saying anything. They followed. It seemed to be what was required.\nThey stood in a loose cluster where the corridor met the stairwell. From here they could see the quad below, students moving across it with the ordinary velocity of people who had not just been named in front of their class. Someone was laughing loudly near the tuck shop.\n"Ten days," Adun said. She was not talking to any of them specifically.\n"He''s already decided." This was Yewa. Her voice was flat. "Did you see how he was writing before we even answered anything. He had the pen ready."\n"That''s how they always do it in this school." Emeka''s voice came out smaller than usual and he seemed to notice this because he cleared his throat and looked away. "Ask the questions after the conclusion."\nNasiru had not said anything since he came out of the office. He said something now, quietly, directed at no particular person.\n"Someone gave them our names."\nThe corridor absorbed this. Below in the quad the laughing near the tuck shop continued.\n"That''s what he said," Kachi said carefully. "That a name was provided."\n"Five names," Nasiru said. "Specifically us. Not four. Not six."\nNobody answered this because the answer it was pointing toward was one that required standing still for a moment before approaching it. Someone had not simply stolen an exam paper. Someone had also decided, with some deliberateness, whose names to attach to it.\nYewa was looking at Nasiru now. Then at Kachi. Then back at the wall.\nAdun picked up her folder.\n"Friday," she said. "Same time."\nShe walked toward the stairwell. Yewa followed. Emeka pushed off the wall and went after them.\nKachi and Nasiru stood for a moment longer.\n"Same row?" Kachi asked.\nNasiru picked up his bag. "Same row."','\n',char(10)),936,0,1,NULL,'2026-04-18T19:14:43.829Z','2026-04-18 19:14:43','2026-04-18 19:14:43','2026-04-18T19:30:00.000Z',1,NULL);
INSERT INTO "chapters" ("id","novel_id","chapter_number","title","content","word_count","is_premium","is_published","audio_url","published_at","created_at","updated_at","scheduled_release_at","part_number","season_id") VALUES(493,60,3,'The Deal',replace('Adun chose the library because the library had rules.\nNo raised voices. No food. Sign in at the desk, sign out at the desk, and Mrs. Obi watched both transactions with the attentiveness of someone who understood that a library''s value was precisely its inconvenience to people who did not take things seriously. Adun had calculated that a room with those properties would keep a certain energy out of the conversation before it arrived.\nShe had underestimated Emeka.\n"So we''re forming a gang," he said, dropping into the chair across from her. "Fantastic. Do we get a name or do we just go with The Back Row Five. I feel like The Back Row Five has something."\n"Keep your voice down."\n"I''m whispering."\n"You are not whispering."\nNasiru came in and signed the register and sat at the far end of the table. Yewa arrived two minutes later and took the seat beside Adun without being directed to it, which Adun noted and appreciated without saying so. Kachi was last. He sat, put his bag on the floor, and looked at Adun in a way that indicated he was prepared to listen before deciding anything.\nAdun opened her notebook.\n"We have ten days. The board meets on a Friday. If we go in there with nothing except our word against whoever gave our names to VP Amaechi, we lose. This school will write five letters to five sets of parents and we will all carry an academic misconduct record into SS3 and beyond." She looked around the table. "I don''t intend for that to happen."\n"So what exactly are you proposing," Yewa said. It was not entirely a question.\n"We investigate. Properly. We find out who actually took that paper and we build something concrete enough that the board cannot ignore it."\nEmeka leaned back. "And we do this how exactly. We''re sixteen. We don''t have a laboratory or police contacts or whatever."\n"We have something better than police contacts," Adun said. "We have access. We''re students in this school. We move through it every day. People talk in front of us because they don''t think we''re paying attention."\nEmeka looked at Kachi. Kachi looked at his bag.\n"I''m in," Yewa said.\n"Naturally," Emeka said.\nYewa turned to him slowly. "What does that mean."\n"It means you''re both in because you''re already in the same corner. No offense."\n"It''s offensive."\n"It wasn''t meant to be."\n"Then work on your phrasing."\nEmeka opened his mouth and Nasiru spoke.\n"Someone studied us," Nasiru said. The table went quiet. He had the quality, when he chose to speak, of a person who had finished thinking before anyone else had started. "They didn''t put random names on that paper. They looked at the five of us and decided we were the ones least likely to be believed. That means they know this school. They know how it works and who it protects. Which means they are still here, moving through it the same way we are, and they are watching to see what we do next."\nThe library''s ceiling fan rotated slowly above them.\n"So we have to be careful," Kachi said quietly.\n"We have to be faster than careful," Nasiru said.\nEmeka was no longer leaning back. He had both elbows on the table and an expression that had not been on his face since the whole thing started, something behind the jokes that was paying full attention. He looked at Adun.\n"Fine," he said. "What''s the plan."\nAdun had divided the work into four areas before she arrived. Physical access: who could have gotten into the admin block and how. Timeline: mapping exactly what happened the night the paper disappeared. School records: any previous misconduct cases that followed this same pattern. And the source of the accusation itself, meaning whose name or names had actually been given to VP Amaechi and how.\nThe division of labor lasted nine minutes before it began collapsing.\nAdun assigned herself and Yewa the records and timeline. She assigned Emeka and Kachi the physical access investigation, meaning talking to the security staff and examining the admin block entry points. She assigned Nasiru the source question.\n"Why does he get the most important one alone," Emeka said.\n"Because he will actually do it," Adun said.\n"I will also actually do it."\n"You will do it and then report everything you found to four other people before the day ends."\nEmeka looked at Kachi again. Kachi, with the expression of a person choosing not to have an opinion, looked at the table.\n"I don''t need a partner," Nasiru said.\n"Nobody said you did," Adun said.\n"I''m just noting it."\n"Noted."\nYewa was watching this exchange with the focused expression she applied to chemistry problems. Emeka pushed his chair back and stood and announced that he had a class and left, which was true, though the class had started four minutes ago.\nKachi packed his bag slowly. He left without speaking, which was consistent with his general practice.\nAdun was writing the task divisions into her notebook when the library door opened and a senior student leaned in. Adun recognized him vaguely, SS3, one of the faces that appeared at inter-house sports. He was looking for Emeka.\n"He just left," Yewa said.\nThe senior student looked at them both for a moment with an expression that was not unfriendly and was also not friendly.\n"Tell him Segun said to leave it alone," he said. "He''ll understand."\nHe left.\nAdun and Yewa looked at each other across the notebook.\n"Leave what alone," Yewa said.\nAdun wrote the name Segun in the margin of her notebook and drew a small box around it.\n"That," she said, "is an excellent question."','\n',char(10)),958,0,1,NULL,'2026-04-18T19:15:55.172Z','2026-04-18 19:15:55','2026-04-18 19:15:55','2026-04-18T19:30:00.000Z',1,NULL);
INSERT INTO "chapters" ("id","novel_id","chapter_number","title","content","word_count","is_premium","is_published","audio_url","published_at","created_at","updated_at","scheduled_release_at","part_number","season_id") VALUES(494,60,4,'What Kachi Saw',replace('The timeline, written out in Adun''s handwriting on two pages of graph paper, looked more manageable than it actually was.\nShe had taped it to the inside cover of her investigative notebook, a designation she had given the notebook privately and would deny publicly. Three nights ago. Administration block. Biology paper. The exam was scheduled for that Thursday. The paper had been printed and sealed in the VP''s office the previous Monday, signed for by Mr. Chukwu and one other staff member whose name Adun had not yet confirmed. Between Monday and Wednesday night, something happened to it.\nThey met at the back row during the long break because the library required signing in and signing in created a record. Kachi had mapped the admin block from memory, a clean pencil drawing on a sheet from his notebook. The level of detail made Emeka look at him with new attention.\n"You drew this from memory," Emeka said.\n"I pay attention to buildings," Kachi said.\n"That''s a thing people do?"\n"I do."\nAdun took the drawing and oriented it against her timeline. The admin block had two entry points. The main door facing the assembly ground, which the security staff locked at six pm. And the side corridor door connecting to the staff room block, which was not always locked because the staff room block was not always empty in the evenings.\n"So whoever went in," Yewa said, "most likely went through the side corridor."\n"Or had a key to the main door," Nasiru said.\n"Students don''t have keys to the main door," Adun said.\n"Students aren''t supposed to have keys to the main door," Nasiru said.\nThis distinction settled over the group and was accepted.\nEmeka had spoken to the daytime security man, a conversation he had managed by pretending to look for a lost calculus textbook with the kind of helpless energy that adult men found either amusing or pitiable, both of which were useful. The security man confirmed that he locked the main door at six and checked the side corridor door at six thirty. He had not checked it again after that.\n"So there''s a window," Adun said. "Six thirty to whenever the staff room block empties."\n"On Wednesday nights the debate club uses the staff room block," Kachi said. "They usually finish around eight."\nEveryone looked at him.\n"I told you. I pay attention."\n"Debate club," Adun said, writing it down. "Who runs debate club."\n"Mr. Adaobi. But the student who organizes it is Ifeanyi Obi."\nThe name entered the conversation the way a stone enters still water, with an initial impact and then a spreading. Ifeanyi Obi was one of those students a school like Goldcrest produced every few years, the kind whose name appeared in every positive sentence a teacher constructed publicly. Senior prefect. Inter-school debate champion. The student VP Amaechi cited in assemblies when he needed an example of what Goldcrest students were capable of being. He was not unpleasant. That was almost the problem. He was perfectly calibrated.\nAdun was writing his name when she noticed Kachi.\nHe had gone still in a way that was different from his ordinary stillness. His ordinary stillness was active, the focused quiet of a person listening. This was something else. His pencil was down. His hands were flat on the desk. He was looking at Adun''s notebook and not at anything in it.\nShe kept writing. She noted it and kept writing.\nThey divided the next steps. Emeka would find out who attended debate club on Wednesday. Yewa would confirm the staff room block''s schedule with a JSS3 student she knew who did drama practice in the adjoining room. Nasiru would look into Ifeanyi''s prefect responsibilities and which of them gave him administrative access.\nKachi said he would check the biology department''s record of who had been given advance sight of the exam format, a legitimate process through which prefects sometimes received structural information for revision purposes.\n"Does Ifeanyi have a reason to need the actual paper," Yewa asked. "He''s clearly not struggling academically."\n"People who don''t need things still take them," Nasiru said. "Sometimes more than anyone."\nThe bell rang. They scattered with the ordinary urgency of students who were already late and for whom being late now carried an additional layer of risk.\nAdun waited.\nShe packed her notebook slowly. Repositioned her bag. Checked something in her folder that did not need checking. When the room had emptied she walked out and positioned herself at the bottom of the stairwell where the path to the car park passed. She was looking at her phone when Kachi came down.\n"Walk with me," she said.\nHe fell into step beside her.\n"You''ve met Ifeanyi Obi before," she said. "Not just as a name. Actually met him."\nA pause that lasted two steps too long.\n"He''s a prefect. Everyone has met him."\n"That''s not what I mean and you know it."\nAnother pause. They were at the edge of the car park now. The afternoon drivers were beginning to arrive, gleaming cars pulling through the gate with the unhurried certainty of money.\n"I don''t have anything to tell you," Kachi said.\n"That is genuinely the worst lie I have heard this week," Adun said. "And I spent this morning in VP Amaechi''s office."\nKachi looked at the approaching cars.\n"I don''t have anything to tell you yet," he said. "That''s different."\nAdun studied him for a moment. She recognized the distinction he was drawing and she also recognized that pushing past it today would close the door entirely.\n"Yet has an expiry date," she said. "This investigation does not have the luxury of waiting for you to be ready."\nShe walked toward her mother''s car, which had just pulled through the gate.\nKachi stood at the edge of the car park and watched it leave and said nothing, which was what he always did, and which today felt entirely different from every other time.','\n',char(10)),998,1,1,NULL,'2026-04-18T19:17:09.912Z','2026-04-18 19:17:09','2026-04-18 19:17:09','2026-04-18T19:30:00.000Z',1,NULL);
INSERT INTO "chapters" ("id","novel_id","chapter_number","title","content","word_count","is_premium","is_published","audio_url","published_at","created_at","updated_at","scheduled_release_at","part_number","season_id") VALUES(495,60,5,'Adun''s Problem',replace('The rumour arrived the way rumours at Goldcrest always arrived: through no single identifiable mouth, from no traceable origin, fully formed and moving fast.\nBy the time Adun walked into SS2B on Thursday morning it had already been there for twenty minutes. She knew because of the way Chisom Eze stopped talking when she passed her desk. Chisom Eze had never in four terms stopped talking for anything short of a teacher''s entrance. Adun registered this, filed it, and sat down and opened her notebook to the day''s first page.\nEmeka leaned across from the back row during Mr. Adaobi''s government class and placed a small folded note on her desk with the precision of someone who had done this many times and considered it a technical skill. She unfolded it below the desk edge.\nChief Bankole is your uncle. People are saying you planned all of this.\nShe refolded it. Put it in her notebook. Continued writing.\nBy the long break the version circulating had acquired detail and momentum. Chief Bankole sat on the board of governors. His niece was in SS2. His niece sat in the back row. The back row was where the leaked paper came from. These four facts, arranged in a sequence, produced a conclusion that the class found satisfying in the way that conclusions requiring no further investigation are always satisfying.\nThe version with the most circulation included an additional element: Adun had recruited four other students to sit in the back row with her so that when the leak was discovered the blame would distribute across five people instead of landing on one. This version had no evidence behind it and traveled faster than any of the others.\nShe found out about this version when she walked to the tuck shop and a JSS2 student she had never spoken to looked at her with the bright, uncertain expression of someone who had recently learned something about a person they were now looking at directly.\nShe bought a bottle of water and walked back.\nThe back row meeting that afternoon was supposed to be about Emeka''s debate club findings and Yewa''s drama room confirmation. What it became was something else entirely.\n"You should have told us," Yewa said. Her voice was not unkind. That was almost worse.\n"Told you what exactly," Adun said.\n"That your family has a seat on the board. That whatever happens at that meeting, your family is in the room."\n"My uncle''s presence on the board has no bearing on this investigation."\n"It has a bearing on how this looks," Emeka said. "Which at this moment is not great."\nAdun looked at him.\n"I want to be precise about what you''re suggesting," she said. "Because I want to make sure I''m hearing it correctly before I respond to it."\n"Nobody is suggesting anything," Kachi said. It was the first thing he had said since they sat down.\n"He''s suggesting something," Adun said. "He can say it plainly or not say it at all."\nEmeka put both hands on the desk. "I''m saying that if this investigation falls apart and the board meeting happens and your uncle is sitting there, you walk away from this cleaner than the rest of us. That''s not an accusation. That''s mathematics."\nThe silence that followed was the kind that has weight.\n"My uncle," Adun said, "has called my father twice since yesterday. Both times to advise that the cleanest outcome for the family name is for me to accept a quiet administrative warning, express remorse to VP Amaechi, and allow the matter to be closed without a board hearing." She picked up her pen. "I have not returned either call."\nNobody spoke.\n"Chief Bankole does not help me in that boardroom. He complicates me. He gives the school a reason to make this disappear quietly in a way that protects his reputation and leaves four other people''s records untouched." She looked around the table steadily. "I am aware of exactly what my uncle''s involvement means for this group. I chose not to raise it because it changes nothing about what we are doing and everything about how you would look at me."\nShe looked at Emeka specifically on the last sentence.\nEmeka had the expression of someone locating a response and discarding it twice before settling.\n"The note from Segun," Yewa said suddenly. "Leave it alone. That was directed at Emeka." She looked at Emeka. "What is it that you''re supposed to leave alone."\nThe temperature of the conversation shifted. Emeka straightened.\n"That''s not relevant right now."\n"It became relevant the moment you started asking questions about who in this group has something to hide," Yewa said.\n"That''s a different thing."\n"It is exactly the same thing," Adun said. Her voice was even and precise and contained no heat whatsoever, which was more effective than heat would have been.\nEmeka looked at Kachi. Kachi was looking at his notebook.\n"Debate club," Nasiru said.\nEveryone turned to him. He had been sitting at the end of the table through the entire exchange with the stillness of someone letting a storm move past before speaking.\n"Emeka found something at debate club. That is why we are here. We can continue the other conversation afterward or we can do the work." He looked at Emeka. "What did you find."\nA long moment. Emeka breathed out through his nose and opened his own notebook, a thing none of them had seen him use before today.\n"Ifeanyi ran debate club on Wednesday. Finished at seven forty five. Staff room block." He paused. "He signed out of the main gate at nine fifteen."\nAdun''s pen stopped moving.\n"That''s an hour and a half," Kachi said quietly.\n"Yes," Emeka said. "It is."\nOutside the window, the afternoon drivers were beginning to arrive. Adun looked at her notebook and added the time to her timeline with the careful handwriting of someone who understood that what she was writing mattered.\nNobody moved seats.','\n',char(10)),999,1,1,NULL,'2026-04-18T19:18:22.119Z','2026-04-18 19:18:22','2026-04-18 19:18:22','2026-04-18T19:30:00.000Z',1,NULL);
INSERT INTO "chapters" ("id","novel_id","chapter_number","title","content","word_count","is_premium","is_published","audio_url","published_at","created_at","updated_at","scheduled_release_at","part_number","season_id") VALUES(496,60,6,'North of Here',replace('The first note appeared on Monday morning inside Nasiru''s locker, folded into quarters and placed on top of his chemistry textbook with the deliberateness of something meant to be found immediately.\nHe read it once, refolded it along its original creases, and put it in the front pocket of his bag. He took out his chemistry textbook and walked to class. He did not change his pace in the corridor. He did not look around to see if anyone was watching to see how he received it, though someone almost certainly was.\nThe note said: You don''t belong here. You never did.\nThe second one appeared under his desk during the lunch break, meaning someone had come into an empty SS2B and placed it there specifically, which required a level of intention that the first note''s locker placement had not fully communicated. This one was shorter.\nGo back to where you came from.\nHe folded this one and put it with the first.\nHe said nothing to the group on Monday. They had enough moving pieces and he had assessed, with the methodical honesty he applied to most things, that sharing the notes would produce one of two outcomes. Either the group would redirect energy toward protecting him, which was energy the investigation could not afford, or the group would treat it as additional evidence of the pattern they were already mapping, which was true but not yet useful enough to act on.\nOn Tuesday the third note appeared folded into his biology textbook between pages forty and forty one. He found it during Mr. Chukwu''s class when he turned to the day''s topic, and he pressed it flat with one hand, read it without lifting the page from the desk, and continued taking notes with the other hand.\nThis one was different.\nAsk your Hausa friend what he''s been telling people. Ask him what he knows. Ask him why he''s still here.\nNasiru read this sentence three times. Then he closed the textbook with the note inside it and looked at the board and copied down everything Mr. Chukwu wrote for the next forty minutes without processing a single word of it.\nAfter school he sat in the back row alone. The classroom emptied around him with the daily velocity of students whose drivers were waiting, whose afternoons held other obligations, whose lives outside Goldcrest''s gate resumed the moment the last bell rang. He waited until the room was fully empty and then he took out his phone.\nThe contact was saved under a name that would mean nothing to anyone who picked up his phone. D.A. He had not needed to use it since the beginning of term. He typed carefully.\nSomeone inside knows we''re looking. Notes in my locker, my desk, my textbook. Third one mentions you indirectly. Says to ask what you''ve been telling people. Are you careful?\nHe sent it and put his phone face down on the desk and looked at the window.\nDayo Abiodun had left Goldcrest Academy fourteen months ago under circumstances the school recorded as voluntary withdrawal and that were not voluntary in any meaningful sense of the word. He was eighteen now, in his first year at a university in Enugu, and he had reasons to know things about Goldcrest that current students did not, reasons that Nasiru had understood from their first conversation three months ago when Dayo had reached out through a mutual contact with the careful, specific energy of someone who had been waiting for the right moment to say something to the right person.\nThe phone vibrated.\nI''m careful. They''re watching you because you''re the easiest target. Don''t let them make you small. I''m working on something. Give me until Thursday.\nNasiru read this twice and put the phone away.\nHe was still sitting there when Adun came back.\nShe had left her chemistry notes, she said, holding them up as evidence. She stopped when she saw his face. Not the content of it, because Nasiru''s face was not a document that gave itself up easily. But the quality of his stillness was different from its ordinary version in a way she had learned, over four weeks of sitting two seats away, to read as a register of something being contained.\nShe sat down. Not beside him. At her own seat, two down, where she always sat.\n"You don''t have to tell me," she said. "But you should tell someone."\nA long moment.\nHe reached into the front pocket of his bag and put three folded pieces of paper on the desk between them. She looked at them without touching them.\n"How long," she said.\n"Since Monday."\nShe looked at him then with an expression that was not pity. Pity would have been easier to dismiss. It was something more precise. The recognition of a person who understood what it cost to carry something alone and had made a different calculation about what that cost was worth.\n"This is the same person," she said. "The notes to you and the rumour about my uncle and the warning to Emeka. One source."\n"Yes."\n"Which means we are closer than we think we are."\n"Or they are more frightened than we expected," Nasiru said. "Which is the same thing from a different angle."\nAdun picked up her chemistry notes and stood.\n"Thursday," she said. "Full group. Everything on the table. No more managing what we tell each other."\nShe walked out.\nNasiru sat for another moment. Outside the window the last of the afternoon drivers were pulling away from the gate, carrying other people''s children back into lives that waited for them. He looked at the three folded notes on the desk.\nHe picked them up and put them back in his bag and walked out of the empty classroom into the corridor and did not look back, because looking back was a habit he had decided, a long time before this week, was not one he could afford.','\n',char(10)),1001,1,1,NULL,'2026-04-18T19:19:27.181Z','2026-04-18 19:19:27','2026-04-18 19:19:27','2026-04-18T19:30:00.000Z',1,NULL);
INSERT INTO "chapters" ("id","novel_id","chapter_number","title","content","word_count","is_premium","is_published","audio_url","published_at","created_at","updated_at","scheduled_release_at","part_number","season_id") VALUES(497,60,7,'The Side Business',replace('The piece of paper fell from Emeka''s bag on Wednesday morning when he swung it off his shoulder to get his government textbook, and the way it fell, face up, in the narrow space between his chair and Yewa''s, was the kind of accident that could not have been engineered with more precision if someone had tried.\nYewa picked it up.\nShe did not intend to read it. She was reaching for it the way a person reaches for anything that falls near them, with the automatic courtesy of returning it before the moment becomes a thing. Then her eyes caught the column structure and her hand stopped moving and she read it without entirely deciding to.\nIt was a list. Names on the left side, amounts on the right. Some names had check marks. Some had small notations she did not immediately understand. The amounts ranged from two thousand naira to eight thousand. There were fourteen names on the list and she recognized six of them as SS3 students.\nShe looked up at Emeka, who had found his textbook and was about to sit down.\nHe saw her face first. Then he looked at what was in her hand. Something moved behind his eyes, a rapid sequence of calculations, and then his hand came out.\n"That''s mine."\nShe pulled it back slightly. Not dramatically. Just enough.\n"What is this," she said.\n"It''s mine. Give it back."\n"Emeka. What is this list."\nHe took it from her hand with a firmness that was not quite a snatch and pushed it into his bag and sat down and opened his textbook to the day''s page with the focused attention of someone who had decided a conversation was not happening.\nIt happened at the back row meeting that afternoon.\nYewa described what she had seen with the precision of someone who had been thinking about how to describe it since morning. Column structure. Names she recognized. Amounts. Check marks. She did not editorialize. She laid it out the way Adun had taught the group, without the conclusion attached, and let the conclusion arrive on its own.\nIt arrived.\n"Test notes," Adun said. She was looking at Emeka with the expression of someone who had suspected a room had a particular smell and had now confirmed it. "You''ve been selling senior students'' test notes. That''s what Segun''s warning was about. Leave it alone means leave the investigation alone because an investigation means someone looks at your operation."\n"It''s not an operation," Emeka said.\n"What would you call it."\n"A service. Senior students want organized notes from the previous year''s set. I provide them. Nobody fails, nobody gets hurt, everybody goes home."\n"Except," Yewa said, "that you have been running a paid service inside this school that involves handling academic materials and you are currently under investigation for stealing an academic paper."\nThe sentence landed in the room and stayed there.\nEmeka looked at the desk. A muscle in his jaw moved.\n"That''s not the same thing," he said.\n"It looks like the same thing," Adun said.\n"It is not the same thing."\n"Emeka." Adun''s voice dropped to the register she used when she wanted someone to understand she was being precise and not theatrical. "Did you take the biology paper."\nThe room went very still.\n"No," Emeka said.\n"But you can see why we are asking."\n"I can see why you are asking," he said. "I cannot see why you are asking like that."\n"Like what."\n"Like you''ve already decided and you''re just waiting for my mouth to confirm it." His voice had risen. He registered this and did not correct it. "I have been in this investigation from the beginning. I talked to the security man. I got the debate club timing. I have done everything that was asked of me and now because of a piece of paper with some names on it you''re all sitting there looking at me like I''m the one who did this."\n"Nobody said you did this," Kachi said. It was the first thing he had said. His voice was quiet and even.\n"She asked me directly."\n"She asked a question the evidence made necessary," Kachi said. "That''s not the same as an accusation."\nEmeka looked at him for a long moment.\n"You''re defending her."\n"I''m describing what happened."\nNasiru spoke.\n"The notes you sell," he said. "Have you ever sold anything from the current academic year."\nOne sentence. Precisely placed. The room turned to Emeka and waited.\nThe silence that followed was a different kind from the ones before it. It was the silence of a specific question that required a specific answer and would not accept movement in either direction without that answer being given first.\n"No," Emeka said finally. "Old materials only. Nothing current."\n"Then you need to write that down," Nasiru said. "Every transaction. Every name. Dates. Amounts. Because if this investigation reaches the point where your side business surfaces publicly, you need a record that shows the pattern clearly. Old materials. Completed academic years. Nothing that could be confused with what we are being accused of."\nEmeka stared at him.\n"You''re telling me to document my own illegal business."\n"I''m telling you to build your own defense before someone else builds a version of it for you."\nThe logic of this settled over the table slowly. Adun looked at Nasiru with something that was not quite surprise and not quite admiration but lived in the space between them. Yewa had stopped looking at Emeka with the expression from earlier and was now looking at the table.\nEmeka sat back.\nThe loudness had gone out of him the way it sometimes did, not gradually but at once, like a switch, and what it left behind was quieter and harder to read and significantly more unsettling than anything that had come before it.\n"Fine," he said.\nHe opened his notebook and began to write.','\n',char(10)),991,1,1,NULL,'2026-04-18T19:20:37.180Z','2026-04-18 19:20:37','2026-04-18 19:20:37','2026-04-18T19:30:00.000Z',1,NULL);
INSERT INTO "chapters" ("id","novel_id","chapter_number","title","content","word_count","is_premium","is_published","audio_url","published_at","created_at","updated_at","scheduled_release_at","part_number","season_id") VALUES(498,60,8,'Yewa''s Night',replace('It was Adun who pushed too far.\nNot with cruelty. With the particular precision that was her specific variety of too far, the kind that arrived dressed as logic and landed like something else entirely. They were reviewing the timeline for the fourth time, mapping Ifeanyi''s ninety minute window against the admin block entry points, and Yewa had said something about the side corridor door that Adun had already noted and Adun said, without looking up from her notebook, that it would help if everyone contributed information they actually had rather than information that had already been established.\nThe room went still in the way it did when something had been said that could not be unsaid.\nYewa looked at Adun.\n"What does that mean," she said.\n"It means we are running out of time and we need to be useful."\n"I have been useful."\n"You confirmed the drama room schedule. That was day three." Adun turned a page. "Since then you have been present and quiet and I don''t know what that means but I know we cannot afford it."\nYewa''s expression did something complicated. The others were watching without appearing to watch, the specific skill of people who had learned that looking directly at a live wire was inadvisable.\n"Adun," Kachi said.\n"I''m being honest."\n"You''re being precise," Nasiru said. "That''s not always the same thing."\nAdun looked up from her notebook. She opened her mouth and then she saw Yewa''s face clearly for the first time in the exchange and she closed it.\nYewa was not angry.\nShe looked like someone who had been carrying something at a distance for a very long time and had just calculated that the distance was no longer manageable.\n"I was there," Yewa said.\nNobody moved.\n"Wednesday night. The admin block." She looked at the table. "I was there."\nThe silence had a different quality from every other silence the group had produced. It was the silence of five people recalibrating simultaneously.\n"How long," Emeka said.\n"I got in through the side corridor at seven twenty. I left before eight." She folded her hands on the desk. "I did not take the biology paper. I did not touch anything on VP Amaechi''s desk or in the filing cabinet beside it. I went for one reason and that reason had nothing to do with any examination."\n"Then what was the reason," Adun said. Her voice had changed. The precision was still there but the edge under it was gone.\nYewa reached into the front section of her bag and removed her phone. She opened the gallery, scrolled with the focused efficiency of someone who had looked at a particular image many times, and placed the phone face up in the center of the table.\nThey leaned in.\nIt was a photograph of a document page, slightly angled, taken in low light with the flash off. The image quality was careful rather than accidental. She had taken her time with it. The document was a contractor payment schedule, the school''s letterhead visible at the top edge, a column of company names on the left and payment amounts on the right. The amounts ran into millions.\nEmeka''s finger moved toward the screen.\n"Don''t touch it," Yewa said. Not sharply. Just clearly.\n"Third from the bottom," Kachi said quietly.\nThey all looked at it at the same time.\nAdesanya Integrated Services Ltd. Consultancy and Facilities Management. 4,750,000 naira.\nYewa took the phone back.\n"My father''s company," she said. "I know every contract his company has held in the last three years because he talks about them at dinner. Pipeline maintenance in Rivers State. A road resurfacing job outside Owerri. A security consultancy in Abuja." She put the phone back in her bag. "Goldcrest Academy is not on that list. It has never been on that list. I have never heard that name in my house in connection with this school."\n"Consultancy and facilities management," Adun said. "For a school."\n"This school has not built anything new since the science block three years ago and that was funded by a parent donation. There is no facilities management contract of that scale that I have seen any evidence of." Yewa looked around the table. "Four million seven hundred and fifty thousand naira paid to my father''s company for a service that I cannot find any physical evidence of anywhere on these premises."\n"When was the payment made," Nasiru said.\n"The document was dated eight months ago. There were three payments. That was the third."\n"So it''s been running for at least a year," Kachi said.\n"At least."\nEmeka sat back and looked at the ceiling. He exhaled slowly through his mouth.\n"The exam paper," Adun said. She was thinking aloud now, her pen moving without producing words. "What if it was never about the exam paper."\n"Explain," Nasiru said.\n"The back row was chosen. We established that. Five students who would not be believed. But if someone is running payments through contractor accounts that don''t match real services, they need the school''s administration focused on something internal. A disciplinary matter. An investigation into students." She looked at Yewa. "Your father''s company name in that file means someone at this school is either paying for something that doesn''t exist or paying your father for his silence about something that does."\nThe word silence sat in the room and expanded.\n"My father doesn''t know I have that photograph," Yewa said. It was the first thing she had said that sounded like the age she actually was.\n"Does he know you went to the admin block," Kachi asked.\n"No."\n"Does anyone know," Nasiru asked.\nShe looked at him steadily.\n"You do," she said. "Now."\nOutside the window the afternoon had gone orange and long. The back row held five students who had started the week as strangers performing cooperation and were now something else, not friends precisely, but people who had given each other something that could not be taken back.\nAdun opened her notebook to a fresh page.\n"Start from the beginning," she said to Yewa. "Everything you saw."','\n',char(10)),1020,1,1,NULL,'2026-04-18T19:21:50.631Z','2026-04-18 19:21:50','2026-04-18 19:21:50','2026-04-18T19:30:00.000Z',1,NULL);
INSERT INTO "chapters" ("id","novel_id","chapter_number","title","content","word_count","is_premium","is_published","audio_url","published_at","created_at","updated_at","scheduled_release_at","part_number","season_id") VALUES(499,60,9,'The Shape of It',replace('Adun drew a circle in the center of a fresh page.\nInside it she wrote one word: paper. Then she drew five lines outward from the circle, one for each of them, and at the end of each line she wrote a name. She pushed the notebook to the center of the table and put her pen down and sat back, and for the first time in nine days nobody reached for something to do with their hands.\n"Walk me through it," she said. "Each line. What they knew about each of us specifically."\nKachi spoke first, which surprised everyone including him.\n"Me. I sit in the back row because I want to be left alone. I don''t have close friends in this school. No one who would speak for me without hesitation if it came to that." He looked at the notebook. "I''m easy to isolate. Easy to disbelieve. And I have a specific history with Ifeanyi Obi that someone knew about and calculated I would not raise publicly."\n"What history," Emeka said.\n"I''ll get to it."\nEmeka accepted this and moved on with the speed of someone who had learned which hills to stop on.\n"Me," he said. "The side business. Whoever built this knew that the moment an investigation started, the first thing it would find on me is a pattern of handling academic materials for money. That''s not a coincidence. Someone either knew about the business directly or found out the same way Yewa did, which means they were watching us before any of this started."\n"Segun''s warning," Yewa said.\n"Segun knew to warn me the same day our names were read out. He didn''t wait to see how things developed. He already knew what an investigation would surface." Emeka''s voice carried no humor at all. It was an unfamiliar register and the group received it accordingly. "Someone told him. Which means someone connected to the SS3 block is connected to whoever built this."\nAdun wrote Segun at the edge of the page and drew a line to Emeka''s spoke.\n"Me," Adun said. "My uncle''s position on the board makes me a liability to the group from the outside and gives the school a quiet exit route if they need one. Chief Bankole''s instinct is always to protect the family name first. Whoever chose me knew that his involvement would either make the group distrust me or make the school confident they could pressure me into a quiet resolution." She paused. "They understood my family better than I am comfortable with."\nYewa was next. She looked at the photograph on her phone screen for a moment before speaking.\n"My father''s company in that file means two things. Either my father is complicit in whatever financial arrangement the school is running, which means I have a reason to stay quiet to protect him. Or my father is being used without his knowledge, which means I have a reason to be frightened." She put the phone down. "Either way I am compromised before I open my mouth. Someone knew the file was there and knew I would eventually find it or find a reason to look."\n"But you weren''t supposed to photograph it," Nasiru said.\n"No," Yewa said. "I don''t think that was part of the plan."\nEveryone looked at Nasiru.\nHe took a moment.\n"I am the only northern student in this school. I have been for four years. The anonymous notes used tribal language because whoever sent them understood that the most efficient way to remove me from an investigation is to make the investigation feel like one more place I am not welcome." He looked at the table. "They were not wrong about the calculation. They were wrong about the conclusion it would produce."\nAdun wrote something at the end of each spoke.\nIsolated. Compromised. Pressured. Frightened. Targeted.\nShe looked at it.\n"They did not pick us because we were convenient," she said. "They picked us because each of us, for a specific reason, would be difficult to believe and easy to silence. Five different reasons. Five different pressure points. Someone sat down and thought about this school and looked at the back row and built a list."\nThe ceiling fan rotated above them. Somewhere down the corridor a door closed.\n"Ifeanyi," Kachi said.\nThe name dropped into the conversation and everything reorganized around it.\n"He runs debate club in the staff room block. He had an hour and a half on Wednesday night. He has prefect access that gets him closer to administrative spaces than any other student." Kachi''s voice was steady and effortful in equal measure. "And last term, in week seven, I stayed late to return a book to Mr. Chukwu''s office. The corridor was empty. I saw Ifeanyi coming out of VP Amaechi''s office at six forty with a folder under his arm. VP Amaechi had left at six. I know because I saw him leave."\nThe table was completely still.\n"You saw him in the VP''s office after hours," Emeka said slowly. "With a folder."\n"Yes."\n"And you said nothing."\nKachi looked at his hands.\n"Three days later Ifeanyi stopped a group of SS3 boys from doing something to my bag during break. Publicly. Made a point of it." He stopped. "I told myself it wasn''t connected."\n"Kachi," Yewa said.\n"I know," he said. "I know what it was."\nAdun looked at him without judgment, which required something from her.\n"He bought your silence before he needed it," Nasiru said. One sentence. Precise and terrible.\nKachi said nothing. Outside the window the sky had gone the deep orange of late afternoon in Umuahia, the light that arrived just before everything went dark.\n"Now we know the shape of it," Adun said quietly. "All of it."\nShe drew one final line from the center circle and at the end of it wrote a single name.\nIfeanyi Obi.','\n',char(10)),986,1,1,NULL,'2026-04-18T19:22:58.018Z','2026-04-18 19:22:58','2026-04-18 19:22:58','2026-04-18T19:30:00.000Z',1,NULL);
INSERT INTO "chapters" ("id","novel_id","chapter_number","title","content","word_count","is_premium","is_published","audio_url","published_at","created_at","updated_at","scheduled_release_at","part_number","season_id") VALUES(500,60,10,'The One They Trust',replace('They found him at the notice board outside the staff room.\nNot confronting him. Not yet. Just looking. Adun had suggested they observe him for one full day before the next meeting, the way you look at a structure before deciding where to apply pressure. So they looked, separately, at different points in the day, and reported back what ordinary life looked like on Ifeanyi Obi when he did not know he was being watched.\nWhat it looked like was this: easy.\nHe moved through Goldcrest with the particular ease of a person who had never once walked into a room and calculated the odds of being believed. He greeted teachers by name and they brightened when they saw him. He arbitrated a dispute between two JSS2 boys during the morning break with the patient authority of someone twice his age and the boys thanked him. At afternoon assembly VP Amaechi referenced, without naming him directly, a student whose academic conduct represented the school''s founding values, and half the assembly turned to look at Ifeanyi anyway because the description had only one address.\nHe accepted this without visible discomfort.\nThat was the thing Emeka reported back at the meeting, the detail that sat differently from all the others.\n"He''s not nervous," Emeka said. "Not even a little. We have been visibly investigating something for nine days and he walks around this school like the weather."\n"Because he''s not afraid of the outcome," Nasiru said. "Whatever happens, he''s calculated that his version of events survives it."\n"His word against five students from the back row," Yewa said.\n"Against five students who each have a reason to lie," Adun said. "That''s what he built. It''s not just that we''re unbelievable. It''s that he gave us all specific reasons to be unbelievable."\nKachi had said nothing since the meeting started. He was sitting in his usual position, back straight, hands on the desk, looking at the center of the table with the expression of someone who had arrived at a destination they had been avoiding for a long time and found it exactly as difficult as expected.\n"Tell us properly," Adun said to him. "Everything. From the beginning."\nA moment.\n"Week seven, last term," Kachi said. "I stayed late to return Mr. Chukwu''s annotated copy of the government textbook. He''d lent it to me in week four and I kept forgetting." He paused. "The main corridor was empty. VP Amaechi''s office light was off from the outside, meaning the overhead light was off, but there was the smaller desk lamp. The one he uses when he''s doing paperwork he doesn''t want to look like official hours."\nThe group was quiet.\n"The door was not fully closed. I was going to knock and then I heard voices. VP Amaechi and Ifeanyi. I could not hear the full conversation from the corridor. But I heard VP Amaechi say that the revised figures needed to be kept inside the administration file only and not entered into the school''s main accounts system. And Ifeanyi said he understood." Kachi looked up. "Then VP Amaechi said, you have been a great help to this school, Ifeanyi, and I will not forget it."\nNobody moved.\n"I heard footsteps moving toward the door and I stepped back against the wall and VP Amaechi came out and walked toward the senior staff exit without looking back. Ifeanyi came out thirty seconds later with the folder. He walked in my direction and then he stopped."\nKachi''s hands pressed flat against the desk.\n"He looked at me. Directly. He knew I had been standing there. I don''t know for how long he knew. He looked at me for a moment and then he smiled and said, you''re Kachi, right, from SS2B. Good student. And he walked past me."\n"The folder," Emeka said quietly. "What was in it."\n"I don''t know. I didn''t see inside it."\n"But he saw you," Yewa said. "He saw you and he knew what you had heard and he chose not to address it directly."\n"Three days later he stopped the SS3 boys from touching my bag. He did it publicly. Made sure I saw him do it." Kachi''s voice was even and without inflection and entirely devastating. "I understood what it was. I understood it was a transaction. And I accepted it. Because I was afraid and because it was easier than the alternative." He looked at the table. "And then when our names were read out I understood that the transaction had not protected me the way I thought it had. It had just given him something to rely on."\nThe ceiling fan turned above them.\nIfeanyi Obi was seventeen years old. He was ranked second in SS2 academically. He had represented Goldcrest in three inter-school competitions and won two of them. He was not cruel in the visible ways that made people easy to identify as dangerous. He held doors open. He knew the names of the JSS1 students. He had looked at a frightened boy in a corridor and offered him something small and useful and then filed the debt away for later.\n"VP Amaechi," Nasiru said. "The revised figures. The accounts system."\n"Yewa''s photograph," Adun said.\nThey looked at each other.\n"It''s not just Ifeanyi," Yewa said. "It was never just a student."\n"Ifeanyi didn''t build this alone," Nasiru said. "He''s seventeen. He built the part a seventeen year old could build. Someone older built the rest and needed him on the inside."\n"VP Amaechi needed a student he trusted with the financial irregularities," Adun said. "A student he had enough of a hold on to keep quiet. And then when the files became a risk, when someone started looking at the contractor accounts, he needed a problem that would keep the school looking inward." She stopped. "We were never the target. We were the distraction."\nEmeka looked at the ceiling for a long moment.\n"So we''re not just clearing our names," he said. "We''re walking into something much larger than an exam paper in front of a board that includes your uncle and is run by the man at the center of it."\nHe did not say this dramatically. He said it the way a person states a fact they wish were not a fact.\nAdun picked up her pen.\n"Yes," she said. "We are."','\n',char(10)),1061,1,1,NULL,'2026-04-18T19:24:06.028Z','2026-04-18 19:24:06','2026-04-18 19:24:06','2026-04-18T19:30:00.000Z',1,NULL);
INSERT INTO "chapters" ("id","novel_id","chapter_number","title","content","word_count","is_premium","is_published","audio_url","published_at","created_at","updated_at","scheduled_release_at","part_number","season_id") VALUES(501,60,11,'Evidence',replace('The problem with the truth was that it required a container.\nAdun had spent Thursday night at her desk reducing everything they had into a single document. Kachi''s testimony. Emeka''s transaction records. Yewa''s photograph. Nasiru''s notes. The timeline. The ninety minute window. The folder in the corridor. The contractor payments that matched no physical service. VP Amaechi''s voice saying revised figures to a student in an office with the desk lamp on and the overhead light off.\nSeparately, each piece was dismissible.\nA quiet boy who thought he heard something in a corridor seven months ago. A girl who photographed a document she had no business being near. A note-seller with a convenient reason to reframe his own exposure. A student whose uncle sat on the board presenting evidence against that board''s administrator. A northern boy who had been receiving anonymous threats and had been in contact with a former student nobody in authority had reason to trust.\nShe looked at the document for a long time.\nThen she wrote at the top of a new page: What does the board see when we walk in.\nShe wrote the answer underneath it and did not sleep well after that.\nFriday morning. Last row. Two days before the board meeting.\nShe put the document in the center of the table and let them read it. Nobody spoke while they read. Emeka reached the last page first and put it down and looked at the window. Yewa read every line twice. Nasiru finished and looked at Adun and gave her the particular look he reserved for things he considered accurate and did not enjoy.\nKachi read it slowly and put it down and said: "You wrote it the way they''ll hear it."\n"Yes," Adun said.\n"It sounds like five students with personal grievances constructing a story."\n"Yes."\n"So what do we do," Yewa said.\n"We give them something they cannot reframe," Adun said. "Something that exists independently of our word. Yewa''s photograph is close but the board can question how she obtained it and the answer to that question damages her." She looked around the table. "We need at least two of us to go into that room having already made public what we were hiding. Not to the board first. Before the board. So that when we walk in, the secrets are already out and they cannot be used against us in the room."\nEmeka understood before the others. She watched him understand it.\n"You want us to burn ourselves first," he said.\n"I want us to choose what burns and what survives."\n"Who," Kachi said.\n"That is what we need to decide together."\nThe vote was Adun''s idea and she regretted proposing it approximately four minutes after proposing it. Not because it was wrong. Because voting required each of them to look at the others and make a calculation about whose exposure cost the least, and that calculation, done in the open, was one of the more uncomfortable things the back row had yet produced.\nEmeka nominated himself first.\n"My side business is already half out," he said. "Segun knows. Whoever sent him knows. If I go to Mr. Chukwu before the board meeting and disclose the note-selling myself, I control the narrative. I''m not hiding it from the board, I''m the one who brought it forward." He paused. "It ends the business permanently and my parents will be a specific kind of unhappy about it. But it''s mine to burn."\n"That''s one," Adun said.\nA silence.\n"Kachi," Nasiru said.\nKachi looked at him.\n"Your testimony about VP Amaechi and Ifeanyi is the center of this. Without it the photograph is circumstantial and the timeline is incomplete. But your testimony only holds if the board cannot say you invented it after the fact." Nasiru''s voice was measured and not unkind. "If you go to Mr. Chukwu today and state on record that you witnessed that conversation last term and were afraid to report it, you establish a prior knowledge that predates this investigation."\n"It also establishes that I stayed silent for seven months," Kachi said.\n"Yes. It does."\nThe room held this.\n"They''ll ask why," Kachi said.\n"You tell them why," Yewa said quietly. "That Ifeanyi knew you had heard and that three days later he did something public that you understood as a warning and a trade. You tell them exactly what it felt like to be fifteen years old in a corridor with a prefect who had just decided your silence was useful." She stopped. "That''s not a weakness in your testimony. That''s the testimony."\nKachi looked at the table.\n"All right," he said.\nIt was two words and they cost something visible.\nAdun wrote both names down.\nThen Yewa said: "I''ll show the photograph to my father tonight. Before the meeting. He deserves to know before a room full of strangers sees it."\nNobody had asked this of her.\n"Yewa," Emeka said.\n"It''s fine."\nIt was not fine. Anyone at the table could see that it was not fine and that Yewa knew it was not fine and had decided to carry it anyway. Her jaw was set in the way it got when she had finished thinking about something and was no longer available for further discussion on the matter.\nThe silence that followed was not empty. It was the specific fullness of four people watching a fifth carry something heavy and understanding that the only respectful response to that was to not look away.\nEmeka was looking at the desk when Adun noticed his eyes were bright.\nHe turned to the window before anyone could register it directly.\nNobody mentioned it afterward.\n','\n',char(10)),947,1,1,NULL,'2026-04-18T19:25:52.492Z','2026-04-18 19:25:52','2026-04-18 19:25:52','2026-04-18T19:30:00.000Z',1,NULL);
INSERT INTO "chapters" ("id","novel_id","chapter_number","title","content","word_count","is_premium","is_published","audio_url","published_at","created_at","updated_at","scheduled_release_at","part_number","season_id") VALUES(502,60,12,'Believed',replace('The boardroom was on the second floor of the administration block, a room that existed separately from the rest of the school the way certain rooms in certain institutions exist to remind everyone else of the distance between decisions and the people they affect.\nThey arrived together. This was deliberate. Adun had said the night before that they would walk in as a group or not at all, and nobody had argued with it. They wore their uniforms with the specific care of people who understood that appearance was not vanity in a room like this one but a form of language. Shoes polished. Shirts tucked. The ordinary armour of students who had been told since JSS1 that presentation communicated seriousness.\nKachi held the door.\nThe room had a long table. Eight chairs on the far side, five on theirs. The board members were already seated and the first thing Adun saw when she walked in was her uncle''s face, Chief Bankole at the far left end, a large careful man with her father''s forehead and a quality of watchful neutrality that she had seen applied to difficult family dinners and apparently to this as well.\nThe second thing she saw was a man she did not recognize seated two chairs from VP Amaechi at the center. Late forties. Dark suit. The particular stillness of someone who had sat in rooms like this many times and understood their geometry.\nNasiru leaned close to her ear as they sat.\n"Ifeanyi''s father," he said.\nShe looked again. The resemblance was architectural rather than immediate. The same economy of expression. The same quality of waiting.\nVP Amaechi opened the meeting with the procedural efficiency of a man who had done nothing wrong and had the patience of institutional certainty behind him. He outlined the allegation. He outlined the timeline. He outlined the five students'' connection to the back row, to the administration block, to the examination paper. He did not raise his voice once.\nHe did not look at any of them directly.\nThe board chair, a woman named Dr. Obiageli whose reading glasses were pushed up onto her forehead, asked the five students to present their account.\nAdun stood.\nShe had prepared for twenty two minutes but she used eleven. She was precise. She did not editorialize. She presented the timeline, the ninety minute window, the debate club schedule, the side corridor access, Kachi''s written statement delivered to Mr. Chukwu the previous morning, and Emeka''s voluntary disclosure of his note-selling operation alongside the full transaction record demonstrating no current academic materials had ever been involved.\nThe room listened.\nIt listened the way certain rooms listen to young people presenting things adults have not yet decided to take seriously, with the surface attention of courtesy and the deeper reserve of people who have already had a prior conversation before the meeting began.\nChief Bankole had not looked at Adun once.\nShe sat down.\nDr. Obiageli asked several questions. They were reasonable questions asked in a reasonable tone and they landed like stones in water, producing ripples that closed over immediately. VP Amaechi responded to two of them before the students could, which was a technique Adun recognized and had no immediate instrument to counter.\nIfeanyi''s father spoke once. His voice was the same register as his son''s, low and precisely calibrated.\n"These are serious allegations against a student with an exemplary record," he said. "Allegations from students who are themselves under investigation. I would want the board to weigh that carefully."\nHe said it without looking at any of them. He said it to the center of the table.\nKachi''s hands were flat on his knees beneath the table. Adun could see this from where she sat. She could also see the line of his jaw and the quality of effort it represented.\nDr. Obiageli was preparing to move the discussion toward deliberation. Adun could feel it in the room''s shift, the gathering of papers, the straightening of postures. The particular choreography of a room preparing to conclude.\nYewa put the photograph on the table.\nShe slid her phone to the center, screen up, image visible to the full length of the board side. She did not stand. She did not perform it. She simply placed it there with the steadiness of someone who had sat across from her father the previous night and said everything that needed saying and had come through that conversation still intact.\n"This is a page from the school''s contractor payment schedule," she said. "Photographed in the administration block on the night in question. Adesanya Integrated Services Limited. Consultancy and facilities management. Four million seven hundred and fifty thousand naira. Third of three payments." She paused. "My father''s company holds no contract with this school. He confirmed this to me last night. He also confirmed that he has received no payment from Goldcrest Academy in any amount at any time."\nThe room changed.\nNot dramatically. Not with the clean shift of a scene in a film where faces recompose themselves into legible expressions. It changed the way pressure changes a sealed room, invisibly and entirely, in a way that everyone present felt simultaneously in different parts of their body.\nVP Amaechi looked at the photograph.\nIfeanyi''s father looked at VP Amaechi.\nChief Bankole looked at his niece for the first time since she walked in. She did not look back.\nDr. Obiageli picked up the phone with both hands and looked at the image for a long time. Then she set it down and looked at VP Amaechi with an expression that had moved past neutrality into something with an edge under it.\n"I think," she said carefully, "that we will need to take this into private deliberation."\nShe looked at the five students.\n"You will wait outside."\nThey stood. They filed out. Kachi held the door again on the way out. The door closed behind them with the soft institutional sound of a room sealing itself off from the people most affected by what it was about to decide.\nThe corridor bench seated three.\nThey stood.\nNobody spoke for a long time.\nThen Emeka said, very quietly, to nobody in particular: "She looked at him. Did you see that. Dr. Obiageli looked straight at him."\n"Yes," Nasiru said.\n"That means something."\n"It means something," Nasiru said. "We''ll find out tonight what it means."\nThe corridor held them. The ceiling fan above the bench turned slowly. Somewhere inside the sealed room, eight people were deciding what to do with the truth that five students from the back row had carried all the way to the second floor of the administration block and placed on a table in front of people who had not expected them to get this far.\nYewa was looking at the wall.\nKachi was looking at the floor.\nAdun closed her notebook and held it against her chest the way she had held it on the first morning outside VP Amaechi''s office, ten days ago, when they were five people with nothing in common except a bench too small to hold them.\nThey waited.','\n',char(10)),1189,1,1,NULL,'2026-04-18T19:27:14.721Z','2026-04-18 19:27:14','2026-04-18 19:27:14','2026-04-18T19:30:00.000Z',1,NULL);
INSERT INTO "chapters" ("id","novel_id","chapter_number","title","content","word_count","is_premium","is_published","audio_url","published_at","created_at","updated_at","scheduled_release_at","part_number","season_id") VALUES(503,60,13,'The Last Row',replace('The letter arrived in five separate envelopes on Monday morning.\nNot delivered by hand. Not read aloud in class. Slipped into five separate lockers before first period with the quiet efficiency of an institution that had decided the cleanest resolution was one that made the least noise. Adun found hers between her chemistry textbook and her spare notebook. She read it standing at her locker with her bag still on her shoulder.\nDear Miss Adunola Bankole, following a review of the matter raised on Friday the 14th, the disciplinary board has determined that the allegations against you are without sufficient foundation. Your academic record remains unaffected. The school considers this matter closed.\nEleven lines. No apology. No acknowledgment of the ten days. No reference to what had been placed on the table in that room or what it had cost to place it there.\nThe school considers this matter closed.\nShe put the letter in her bag and walked to class.\nEmeka read his at the gate, leaning against the wall with one foot up, and folded it twice when he finished and put it in his back pocket and stood there for a moment looking at the assembly ground with an expression that people passing him likely read as nothing in particular.\nKachi read his in the corridor and then read it again and then folded it carefully along precise lines and placed it in the front section of his bag, beside the three anonymous notes Nasiru had given him to hold after the board meeting, because Nasiru had said he did not want them in his own bag anymore and Kachi had said nothing and taken them without being asked twice.\nYewa did not open hers until break.\nShe sat on the low wall beside the biology block with the envelope in her hands for a full five minutes before she opened it. Her father had called her that morning before school. The call had lasted four minutes and covered two things: that he was engaging a lawyer to investigate the contractor file, and that he was proud of her, which he said once, at the end, in the specific way he said things he meant deeply and was not practiced at expressing. She had said okay and hung up and sat on the edge of her bed for a while before getting dressed.\nThe letter said what the others said. She folded it and put it in her pocket and looked at the assembly ground.\nNasiru''s envelope was already open when he found it, which told him someone had read it before him and resealed it imprecisely. He read it and noted the imprecision and filed it and walked to class.\nIfeanyi Obi was not in school on Monday.\nHe was not in school on Tuesday either. By Wednesday the explanation circulating was that he had taken a brief medical leave. By Thursday the word was that he had been moved to a school in Port Harcourt, a transfer arranged with the quiet speed that money and institutional goodwill could produce when applied together without friction. His name was not mentioned in any assembly. His prefect position was not officially vacated, simply unoccupied, the way a chair is unoccupied when no one has decided yet what to do about the fact of its emptiness.\nVP Amaechi was present all week. He took morning assembly on Tuesday and referenced the school''s founding values with the steady delivery of a man who had survived something and intended to continue surviving it. He did not look at the back row during assembly. The back row noticed.\nThe class did not celebrate the five. There was no moment of public acknowledgment, no assembly announcement, no teacher who paused a lesson to say that what had happened was unjust and was now corrected. The rumour about Adun''s uncle had not been publicly retracted. The assumption that the back row had done something even if not the specific thing had not been formally dissolved. The school moved on as schools move on, which is to say that it moved forward and called that the same thing.\nChisom Eze said something to Adun on Wednesday that was approximately an apology if you tilted it at the right angle. Adun thanked her without warmth and opened her notebook.\nOn Thursday Emeka arrived at SS2B to find a JSS3 student waiting outside with the specific energy of someone who wanted to quietly resume a prior arrangement. Emeka looked at him for a moment and then said, clearly and without drama, that the service was closed, and walked into class. The JSS3 student stood in the corridor for a moment, recalibrating, and then walked away.\nFriday morning. Second week after the board meeting. SS2B filled with the ordinary noise of a class settling into the day, bags dropping, chairs scraping, the particular register of thirty one teenagers transitioning from the outside world into the inside one.\nFive students walked in at different intervals across four minutes. Not together. Not coordinated. Kachi first, as always. Then Nasiru. Then Emeka, who was technically late but only by ninety seconds. Then Yewa. Then Adun, who was never late and was not late today.\nThey passed the front rows. The middle rows. The row three from the back where Chisom sat. The row two from the back where the debate club boys had started sitting since Ifeanyi left.\nThey sat in the last row.\nNot because the letter had been sent. Not because the board had deliberated. Not because Ifeanyi was in Port Harcourt or because the school had quietly confirmed what they already knew. They sat there because the last row was theirs now in a way it had not been three weeks ago, earned not by being believed but by choosing each other in a room where the easier choice was to let each other fall.\nThe ceiling fan above them was still broken.\nNobody mentioned it.\nYewa took out her chemistry notebook and opened it to the day''s page. Her phone was in her bag. The photograph was still in her gallery, timestamped, undeleted. Her father''s lawyer had called yesterday. The file had more pages than the one she had photographed. The investigation had not ended. It had simply moved to a room she was not in.\nThat was not nothing. It was also not everything.\nMr. Chukwu walked in, top button undone, three minutes past the hour.\nHe looked at the class the way he always did, a quick scan from front to back. When his eyes reached the last row they stayed there for a moment, not long, not with any particular expression that could be named or held to account.\nThen he opened his textbook and began.','\n',char(10)),1132,1,1,NULL,'2026-04-18T19:28:51.787Z','2026-04-18 19:28:51','2026-04-18 19:28:51','2026-04-18T19:30:00.000Z',1,NULL);
INSERT INTO "chapters" ("id","novel_id","chapter_number","title","content","word_count","is_premium","is_published","audio_url","published_at","created_at","updated_at","scheduled_release_at","part_number","season_id") VALUES(504,64,1,' Three Evenings a Week',replace('The chair his mother set out for the new teacher was the good chair, the one nobody sat in unless company had come. Chukwudi stood in the doorway of Room 4 and understood, without being told, that this evening was being treated as an occasion.\nHis mother had rearranged the side table too. The old newspapers were gone. In their place she had set a small bowl of chin-chin covered with a cloth, and a bottle of water with an actual glass beside it, not a cup. Chukwudi took a mental note of all of this and said nothing. Saying things was rarely worth the energy it cost in this house.\nHe sat down at the lesson table, the plastic foldout one his father had bought years ago for visiting relatives who never stayed long, and opened his Integrated Science textbook to a random page. He was not reading it. He was waiting.\nShe arrived at six fifteen, fifteen minutes later than his mother had told him to expect. He heard the knock before anyone else in the house responded, heard his mother call out from the kitchen, heard the scrape of the front door. Then footsteps across the corridor tiles. Then she walked in.\nShe was not what he had been picturing, though he could not have said what he had been picturing. She was small, maybe twenty, maybe a little older. Her NYSC uniform was the shade of green that always looked slightly wrong against every complexion, but she wore it like she had stopped thinking about it a long time ago. She had a tote bag over one shoulder with the spine of a book sticking out of the top, and she was already scanning the room as she entered, the way people did when they were forming opinions quickly and preferred not to be caught doing it.\nHis mother came in behind her, wiping her hands on a kitchen towel and using her warmest voice, the one reserved for church and landlords.\n"Chukwudi. This is Corper Amanda. She will be teaching you Monday, Wednesday, Friday."\nChukwudi rose the way he had been raised to rise when adults entered a room. Automatic. Muscle memory built by repetition.\n"Good evening, ma."\nThe corper looked at him. Not through him, not past him, not at the general space where a boy of fourteen was standing. Directly at him, with the kind of attention that did not feel like inspection.\n"Good evening," she said. "You can call me Amanda."\nHis mother made a sound that was not quite objection and not quite agreement and found her way back to the kitchen.\nThey sat down across from each other. Amanda pulled a notepad from her bag, uncapped a pen, and looked at him again.\n"So," she said. "What are you struggling with?"\nIt was a simple question and it took him a moment to understand she was waiting for a real answer. Most teachers, in his experience, asked that question the way adults asked how are you, as ritual, not inquiry. They did not wait. They opened the textbook and began, and struggling was something you demonstrated through wrong answers, not something you were expected to put into words.\nChukwudi looked down at his Integrated Science textbook and then back at her.\n"Mathematics," he said. "And English. My teacher says I overcomplicate things."\n"Overcomplicate how?"\n"He says I use too many ideas when one idea is enough."\nAmanda wrote something in her notepad. He could not read it from where he was sitting.\n"What do you think?" she said.\nHe opened his mouth. Closed it. The question had landed somewhere he was not prepared for.\n"I think," he began, slowly, "that one idea is sometimes not enough. Especially when the thing you are writing about is not a simple thing."\nShe looked at him for a moment longer than people usually did after he said something. Then she nodded, once, like she was storing the information in the right place.\n"Show me your last English assignment," she said.\nHe found it in his bag, the one his teacher had returned with a red six out of ten and two words in the margin: too much. He slid it across the table with the expression he used when he needed people to believe he did not care about something he cared about completely.\nShe read it. All of it. Without sighing, without letting her eyes skip ahead, without making the face adults made when they were waiting for a child to stop wasting their time. She read the whole thing, and when she looked up, her expression was different from what it had been.\n"Your teacher is not wrong that it is long," she said. "But he is wrong about the ideas. They are good. You just need to learn how to carry them so other people can follow."\nChukwudi said nothing. There was nothing in him that could come out as words right now.\n"We will work on structure," she said. "Same ideas, better container. Okay?"\nHe nodded.\nThe lesson ran for an hour and twenty minutes. When his mother appeared in the doorway to say the hour was getting late, Chukwudi looked up and felt the particular surprise of someone who had lost track of time without noticing. That had not happened to him in a lesson before. Not once in his entire school life.\nAfter Amanda left, he remained in the plastic chair and looked at the covered chin-chin bowl on the side table, untouched through the whole evening.\nThere was something sitting in his chest that he did not have a name for.\nHe told himself it was nothing, and almost believed it.','\n',char(10)),955,0,1,NULL,'2026-04-19T14:56:41.857Z','2026-04-19 14:56:41','2026-04-19 14:56:41','2026-04-19T15:05:00.000Z',1,NULL);
INSERT INTO "chapters" ("id","novel_id","chapter_number","title","content","word_count","is_premium","is_published","audio_url","published_at","created_at","updated_at","scheduled_release_at","part_number","season_id") VALUES(505,64,2,'What Do You Think?',replace('The second lesson was a Wednesday, and Chukwudi had spent Monday and all of Tuesday pretending he had not been thinking about it.\nHe had done his homework twice. The first version he threw away because it felt lazy, which was a word he had never used to describe his own work before in his life. The second version he read over three times, crossed out two sentences, rewrote them, and then put the paper face down on his desk so he would stop reading it.\nHe was in his seat in Room 4 by five fifty. Their lesson did not begin until six.\nAmanda arrived at six on the mark, which told him she had been late the first time on purpose, or by ordinary human accident, and that this was who she actually was, someone who kept time. She dropped her tote bag on the chair beside her, pulled out her notepad, and looked at him with the same full attention that had unsettled him three days ago and that he had not stopped thinking about since.\n"How was school?" she said.\n"Fine," he said. Automatic. The answer his mouth gave before his brain arrived.\nShe waited.\nHe shifted in his chair. "My Civic teacher gave us a test we did not know about. I think I did okay. He marks hard."\n"What was the test on?"\n"Nigerian federalism. The structure of government."\n"Do you find it interesting?"\nNobody had ever asked him that either. Interesting. Like the subject was something you could have a personal relationship with, rather than a thing to absorb and reproduce on demand.\n"Sometimes," he said carefully. "When it connects to something real. When it explains why things are the way they are."\nAmanda was writing in her notepad again. He wanted badly to know what she kept recording.\nThey moved into the English session. She had asked him, at the end of the first lesson, to write one paragraph, not an assignment, not something to be graded, just one paragraph about anything he actually cared about. No audience. No teacher. Just him and the page.\nHe pulled the paper from his bag and held it for a second before passing it across.\nShe read it.\nHe had written about the oil spills in Ogoniland. He had written about the way the creeks looked in photographs he had seen, the black slick across water that was supposed to be green, the fish that came up belly-side, the farmland that could not grow anything anymore. He had written about Ken Saro-Wiwa, whose name his father had said once at the dinner table in a voice that asked no questions. He had written about what it meant that all of this had happened, and was still happening, and that most people in Lagos and Abuja discussed it the way you discussed weather, with brief attention and no intention of doing anything.\nIt was too long for one paragraph. He knew that when he handed it over.\nAmanda read it slowly. He watched her face the way he watched teachers'' faces when they marked his work, looking for the moment the expression shifted into correction mode. It did not shift. She read all the way to the end, and then she went back and read something in the middle again, and then she put the paper down on the table between them.\n"Chukwudi," she said. "This is the best thing I have read from someone your age."\nThe sentence entered him and did not know where to go.\n"It is too long," he said. The first defense available.\n"Yes. But that is a technical problem. What is inside it is not a technical problem. What is inside it is real thinking." She tapped the paper once, lightly. "Where did this come from?"\n"I read about it in a magazine. My uncle left it here. And I looked for more after."\n"On your own."\n"Yes."\n"Because you wanted to."\n"Yes."\nShe looked at him again with that particular quality of attention that made him feel like the room had gotten slightly smaller, not in a bad way but in the way rooms got smaller when the thing happening inside them was important.\n"What do you think should happen?" she said. "About Ogoniland. Not what the textbook says. What do you, Chukwudi, actually think."\nAnd here was the question again. The one she kept asking and then waiting for, waiting the way nobody waited, like she had no other place to be and no preferred answer she was hoping to steer him toward.\nHe thought about his father and the voice his father used to close conversations about things that could not be fixed. He thought about his Civic teacher, who marked hard and did not ask what you thought about anything.\nThen he answered. Slowly at first, then with more confidence than he had planned. He talked about accountability and documentation and the specific cruelty of forgetting. He talked for almost four minutes without stopping. He knew it was four minutes because the clock on the wall was directly in his line of sight.\nWhen he finished, Amanda did not immediately speak.\n"You should keep writing," she said finally. "Not for school. For yourself. You have something to say."\nHe nodded as though this were ordinary information, received calmly by an ordinary person.\nInside his chest something had cracked open, clean and irreversible, the way a door opened that had never had a key before.\nHe did not know what to do with it. He gathered his papers, straightened them against the table, and told himself it was just a lesson. A good lesson. Nothing more than that.\nOutside, a generator two houses down kicked into life and flooded the street with its familiar noise.\nChukwudi sat in it and felt, for the first time in a long time, completely awake.','\n',char(10)),984,0,1,NULL,'2026-04-19T14:57:55.231Z','2026-04-19 14:57:55','2026-04-19 14:57:55','2026-04-19T15:05:00.000Z',1,NULL);
INSERT INTO "chapters" ("id","novel_id","chapter_number","title","content","word_count","is_premium","is_published","audio_url","published_at","created_at","updated_at","scheduled_release_at","part_number","season_id") VALUES(506,64,3,'Chin-Chin',replace('She had mentioned it on Wednesday, in the middle of a conversation that was not supposed to be a conversation.\nThey had been reviewing his paragraph structure, the Ogoniland piece cut down and reorganized, when Amanda reached into her tote bag for her pen and pulled out a small nylon of chin-chin by accident, the kind sold at the front of provision stores in tiny tied bags for twenty naira. She looked at it the way people looked at things they had forgotten they were carrying, then set it on the corner of the table and said, more to herself than to him, "I have been walking around with this since Monday."\nChukwudi had noted this. He had noted it the way he noted everything in Room 4, completely and without appearing to.\n"You like chin-chin?" he said.\n"My mother used to make it." She uncapped her pen without elaborating. "The ones from the store are never the same but I keep buying them anyway. Bad habit." She moved on to his paragraph without pause. He moved with her.\nThat was all. Twelve seconds of conversation, maybe less. By any reasonable measure, nothing.\nBy Friday evening, Chukwudi was standing in front of the provision store on Azikiwe Close with his pocket money and a problem he could not explain to himself.\nHe had two hundred naira. His mother gave him two hundred every week, which was enough for a meat pie on Thursday and a Capri-Sun on whatever day he felt he had earned it. The system was consistent and he had never spent it differently.\nHe bought four nylons of chin-chin. Eighty naira. The woman behind the counter put them in a black nylon bag without interest and handed him his change. He walked home with the bag hanging from his fingers and the full awareness that he was being foolish pressing down on the back of his neck.\nHe was not foolish. He knew he was not foolish. He was the boy who had read three books on the Niger Delta on his own initiative, who had rewritten a paragraph seven times to make it right, who understood things about the structure of Nigerian government that his Civic teacher had not taught him. He was not the kind of person who spent pocket money on snacks for a reason he could not explain.\nHe was also holding eighty naira worth of chin-chin.\nHe told himself it was gratitude. A simple, appropriate expression of gratitude toward someone who was helping him. Teachers received gifts. That was a known, normal thing. His primary school teachers had received New Yam Festival parcels from parents without anyone treating it as unusual. This was not different from that.\nHe arranged the four nylons on the lesson table when he got home, evenly spaced, and then stood back and looked at them and put two of them in his bag.\nFour was too many. Four said something he did not want to say.\nTwo was reasonable. Two was a boy who had been raised with manners.\nAmanda arrived at six, on time as she always was now. She greeted his mother in the corridor, set her tote bag down, and pulled out her notepad. Then she saw the two nylons on the table.\nShe looked at them. Then at him.\n"I passed the store," Chukwudi said. The sentence came out sounding exactly as rehearsed as it was.\nSomething moved through Amanda''s expression, brief and unreadable, gone before he could study it.\n"Thank you," she said simply, and moved her notepad to the center of the table. That was all. She did not make a production of it. She did not ask questions. She opened one of the nylons during the lesson and ate from it while she read his latest work, the way people ate things they actually liked, without ceremony.\nHe did not look at her while she was eating. He kept his eyes on the paper in front of him and moved his pen and told himself his pulse was elevated because of the upcoming JS3 mock examination, which was a reasonable biological explanation and had nothing to do with anything else.\nThe lesson was on comprehension passages. She made him read aloud, then argue with the author of the passage, then defend the author''s position even though he disagreed with it. By the end of it his brain was working the way it worked when he had been running, loose and hot and thoroughly occupied. He was grateful for the occupation.\nWhen the lesson ended and Amanda was packing her bag, she paused and held up the second nylon of chin-chin. "Can I take this? For the walk home."\n"Yes," he said. Too quickly. He adjusted. "Yes, of course."\nShe dropped it into her tote bag beside the spine of whatever book she was currently carrying, said good evening to him and then to his mother who had appeared in the corridor, and left.\nChukwudi remained in the plastic chair.\nThe remaining eighty naira in his pocket suddenly felt like a small, private embarrassment. Not because he had spent it wrong. Because he now understood, with the particular clarity that came only after the decision was made and could not be unmade, that he would probably do it again next week.\nHe would tell himself the same story about gratitude and manners and it would be just as thin and just as unconvincing and he would bring them anyway.\nThe generator outside clicked on. Four hours of light. He pulled his Mathematics textbook toward him and opened it to a page he had already understood and stared at the numbers until they stopped meaning anything.\nIt was nothing.\nHe was fourteen years old and it was absolutely nothing and he knew, in the same part of him that rewrote assignments until they were right, that this was not true at all.','\n',char(10)),990,0,1,NULL,'2026-04-19T14:59:02.175Z','2026-04-19 14:59:02','2026-04-19 14:59:02','2026-04-19T15:05:00.000Z',1,NULL);
INSERT INTO "chapters" ("id","novel_id","chapter_number","title","content","word_count","is_premium","is_published","audio_url","published_at","created_at","updated_at","scheduled_release_at","part_number","season_id") VALUES(507,64,4,' Soft Boys',replace('His father came home on Friday evening while the lesson was still running.\nChukwudi heard the car first, the particular sound of the engine that always gave the house about ninety seconds of preparation time. He watched Amanda glance toward the window without stopping her sentence, registering the sound the way visitors registered things in other people''s houses, carefully and without comment.\nHis mother moved through the corridor. The front door opened. His father''s voice filled the house the way it always did, not loudly but with a quality of mass, like furniture being rearranged.\nHe appeared in the doorway of Room 4 still holding his car keys.\nEngr. Obiora Okonkwo was not a large man but he occupied space with the confidence of someone who had decided a long time ago that every room he entered was his. He looked at Amanda first, assessing without apology, then at his son, then at the table between them.\n"Good evening, sir." Amanda rose slightly, the automatic courtesy of someone NYSC had trained to defer to civilians.\n"Evening." His father''s eyes moved to the notepad, the textbooks, the arrangement of the table. "NYSC?"\n"Yes, sir. Corper Amanda. I am posted to Graceland Primary just down the road."\nHis father made the sound he made when information was acceptable but not interesting. He looked at Chukwudi. "How is it going?"\n"Fine, sir," Chukwudi said.\nHis father nodded once, said something to his mother that Chukwudi could not fully hear, and moved away from the doorway. The room exhaled.\nAmanda sat back down. She looked at Chukwudi with an expression that asked, without asking, whether he was alright. He picked up his pen to tell her he was.\nThe trouble came after the lesson.\nHis father was in the sitting room with the television on when Chukwudi passed through, his bag over one shoulder and a notebook in his hand, the one he had started keeping after Amanda told him to write for himself. He had been carrying it between his room and Room 4 all week, adding to it in the spaces between homework and sleep.\n"What is that?"\nChukwudi stopped. "A notebook, sir."\n"I can see it is a notebook. What are you using it for?"\nA pause, small but present. "Writing, sir. The lesson teacher said it would help my English."\nHis father muted the television. This was a gesture that meant the conversation had just changed categories.\n"Writing what? Your assignments?"\n"Not exactly. Just, writing. Thoughts. Arguments. She said it helps with structure."\nHis father looked at him the way he looked at invoices that did not add up. Not angry. Calculating.\n"Sit down."\nChukwudi sat.\nHis father was quiet for a moment, which was always more difficult to read than noise. Then: "Your mother showed me your last result. You improved."\n"Yes, sir."\n"That is what the lessons are for. That is the purpose." He picked up the remote, turned it over in his hand without looking at it. "You are not in JS3 to find yourself. You are there to build a foundation. Science subjects. Mathematics. The things that carry a man somewhere. You understand?"\n"Yes, sir."\n"This country does not reward boys who sit and write their feelings in notebooks. It rewards engineers, doctors, men who can solve problems with their hands and their heads. I am not saying this to be hard on you. I am saying it because I know what I am talking about." He set the remote down. "Your uncle Nnamdi, you know what people called him in school? The professor. Always reading, always with an opinion, always writing letters to newspapers. You know what Nnamdi is doing today?"\nChukwudi said nothing. He knew what Nnamdi was doing. His father did not actually want an answer.\n"He is in Aba trying to run a business that does not work, borrowing money from people who used to respect him." His father looked at him fully. "Softness is a thing that happens slowly. It starts with notebooks and opinions and before you see it, a man has nothing left but things to say about it."\nThe television came back on.\nChukwudi went to his room.\nHe sat on his bed with the notebook in his hands and did not open it. He looked at the wall, which had a nail hole in it from a calendar that had fallen years ago and been replaced with nothing. He looked at the nail hole for a long time.\nHis father was not a cruel man. Chukwudi had understood this early. His father was a man built by specific circumstances, which had produced specific conclusions, which had calcified into specific rules. He applied those rules with the thoroughness of someone who had tested them and found them reliable. He was not wrong about Nnamdi. He was not wrong about this country. He was not wrong about most of the things he said in rooms with the television muted.\nChukwudi opened the notebook.\nHe did not write anything about his father. He did not write anything about the conversation or the feeling sitting inside his ribs like something swallowed too fast. He wrote three sentences about the nail hole in the wall and why spaces left by things that had fallen were sometimes more present than the things themselves.\nThen he stopped, read the three sentences, and thought about Amanda reading them.\nHe thought about what she would say. What question she would ask and then wait for the real answer to.\nHe closed the notebook and put it under his pillow. Not because he was hiding it. Because it was his, and because some things needed to be kept close until you understood what they were worth.\nOutside, the generator had not come on yet. The room was the specific darkness of a neighborhood that was used to waiting.\nChukwudi lay back and stared at the ceiling and felt the cost of wanting things his father did not have a word for.','\n',char(10)),1004,1,1,NULL,'2026-04-19T15:00:06.841Z','2026-04-19 15:00:06','2026-04-19 15:00:06','2026-04-19T15:05:00.000Z',1,NULL);
INSERT INTO "chapters" ("id","novel_id","chapter_number","title","content","word_count","is_premium","is_published","audio_url","published_at","created_at","updated_at","scheduled_release_at","part_number","season_id") VALUES(508,64,5,'Fourth Draft',replace('The assignment was one page on any Nigerian historical event of his choosing, due Monday. Chukwudi finished the first draft on Saturday morning before breakfast.\nHe read it back, put it face down on his desk, ate his eba, washed his hands, and came back and read it again. By noon it was in the bin.\nThe problem was not the facts. The facts were correct and properly sequenced and his teacher would have accepted them without complaint and given him a seven, maybe seven and a half, and written adequate in the margin and moved on. The problem was that he could hear, underneath every sentence, the sound of a boy performing competence rather than actually thinking. He had read enough of his own work now, with Amanda''s attention sharpening his eye, to know the difference. The first draft was a student answering a question. It was not Chukwudi saying something.\nHe started the second draft after lunch.\nHe wrote about the Aba Women''s Riots of 1929, which he had chosen because it was the one event from their history syllabus that had made him stop and sit with it when he first encountered it. Women who had no formal power walking into the offices of colonial administrators and refusing to move. The sheer mass of refusal. Something about it had stayed with him in a way that the dates and names in his textbook had not fully explained, and he thought that maybe writing about it would help him understand why.\nThe second draft was better. It had an argument inside it, not just a sequence. He could feel the difference, the way a sentence with a real idea in it had a different weight from a sentence that was only doing its grammatical duty. He read it twice and found three places where he had explained what the reader could simply feel if he trusted them more, which was a thing Amanda had said about his work once, you over-explain where you should trust, and he had written it in the inside cover of his notebook because it had sounded true in a way that stayed.\nHe cut those three places. The draft became sharper but also shorter, and now the ending felt unfinished. He looked at the ending for a long time. Then he put the paper down and went to read something else for an hour, which was a trick he had figured out on his own, that distance changed what you could see.\nBy Sunday evening he was on the fourth draft.\nHis mother found him at the desk at nine o''clock, which was past the hour she preferred the house to begin settling. She appeared in his doorway with the particular quiet she used when she was not sure what she was walking into.\n"Chukwudi. You have not eaten supper."\n"I will eat in a minute, Ma."\nShe did not leave. He could feel her in the doorway, reading the room the way mothers read rooms, not the objects but the atmosphere.\n"What are you writing?"\n"An assignment."\nA pause. "The same one you were writing this morning?"\nHe looked up then. His mother was leaning against the doorframe with her arms folded loosely, not in the way she folded them when she was displeased but in the other way, the way she held herself when she was paying attention to something she did not yet understand.\n"It is a difficult one," he said.\nShe looked at the desk. Three sheets of paper in the bin beside it, which she could see from where she stood and which he had not thought to cover because he had not expected an audience. Her eyes moved from the bin to the current page in front of him, then to his face.\n"The corper," she said. "She is pushing you."\nIt was not a question. He answered it anyway.\n"She says I have something to say. She says I just need to learn how to carry it."\nHis mother was quiet for a moment. She had a particular quality of quiet that was different from his father''s. His father''s silence calculated. His mother''s silence felt, turned things over gently, set them back down.\n"You like her lessons," she said. Also not a question.\n"They are useful," Chukwudi said. The word was careful and true and not the whole truth, and he thought, watching his mother''s face, that she might know it was not the whole truth, and that she was choosing not to open that door.\nShe unfolded her arms and pushed off the doorframe. "Finish by ten. There is stew on the cooker."\nShe left. He listened to her footsteps down the corridor and waited until the sound had moved fully away before he exhaled.\nHe looked at the fourth draft.\nThe ending was still not right. He could feel the place where it lost its nerve, where he had backed away from the thing he actually meant because saying the actual thing felt presumptuous for a JS3 assignment. He picked up his pen. He crossed out the last two sentences and wrote in their place: The 1929 women did not wait to be given the language to describe what was being done to them. They used the only language that could not be ignored. That is what makes them worth remembering.\nHe put the pen down.\nRead it once.\nIt was right. Not perfect but right, which was its own separate category and the better one to aim for, Amanda had said, because perfect was a reason to never finish anything.\nHe gathered the pages, tapped them straight, and put them inside his English notebook. Then he went to the kitchen for supper, stepping quietly past his parents'' room where the television murmured and the light came thin under the door.\nThe fourth draft sat in his notebook.\nMonday was still eleven hours away and already he was thinking about her face when she read it.\n','\n',char(10)),1002,1,1,NULL,'2026-04-19T15:01:07.398Z','2026-04-19 15:01:07','2026-04-19 15:01:07','2026-04-19T15:05:00.000Z',1,NULL);
INSERT INTO "chapters" ("id","novel_id","chapter_number","title","content","word_count","is_premium","is_published","audio_url","published_at","created_at","updated_at","scheduled_release_at","part_number","season_id") VALUES(509,64,6,' A Girl from Owerri',replace('He saw her before she saw him, which gave him approximately four seconds to decide what to do with his face.\nShe was standing outside the gates of Graceland Primary, half in the shade of the compound wall, her NYSC cap pushed back on her head at an angle that suggested she had forgotten it was there. She was on a phone call. She was laughing.\nChukwudi had been sent to buy groundnut oil from the store on the next street, and he had taken the longer route without thinking about why, which he was now thinking about. He slowed without stopping, the way you slowed when you were trying not to look like you were slowing, and kept walking.\nIt was the laugh that did something to him. He had heard her amused before, the dry, precise amusement she expressed when he said something sharp during a lesson. This was different. This was a full laugh, head tilting back slightly, shoulders moving. Whoever was on the other end of the call had said something genuinely funny and she had responded to it with her whole body.\nHe had not, until this moment, thought about the fact that she had people who made her laugh like that.\nHe bought the groundnut oil and walked home by the shorter route.\nThat evening she arrived at six with a book under her arm that was not her usual notepad. She set it on the table between them and he looked at the cover before he could stop himself. A collection of short stories, the spine cracked from repeated opening, the kind of crack that meant a book had been read the way books deserved to be read.\n"I want to try something different tonight," she said. "Before we do your assignment review."\nShe opened the book to a page she had marked with a folded receipt and slid it across to him. "Read that. Take your time."\nHe read it. It was a short story, not more than four pages, about a girl walking through a market in Onitsha looking for her mother who had been missing for three days. The writing was close and specific, the kind that made you feel the heat and the noise and the particular dread of searching a crowd for a face you needed to find. When he looked up his chest felt slightly compressed, the way it felt after something had reached inside and rearranged things.\n"Who wrote this?" he said.\n"A woman from Delta State. She was twenty-four when she wrote it. She had never published anything before."\nHe looked at the page again. "How did you find it?"\n"My roommate in Owerri had the book. I borrowed it and never gave it back." A small pause. "I have been carrying it around since my first week of service. Some days it is the only thing that makes the posting feel worth it."\nHe looked at her. She was not performing the confession, not offering it as a lesson point. She said it the way you said true things when you had momentarily stopped managing them.\n"Is it hard?" he said. "The posting."\nShe considered this with the seriousness she gave all real questions. "The school is underresourced. The pupils are bright but there are too many of them and not enough of anything else. Some mornings I stand in front of forty-three primary four children and I think about everything I cannot give them and it sits on me for the whole day." She paused. "But then one of them reads a sentence correctly for the first time and their face does something, this specific thing, and I remember why it matters."\nChukwudi was quiet. He was learning to be quiet in a way that invited people to continue.\n"I wanted to be a writer," she said. "Before I wanted to be a teacher. Or maybe at the same time. I have not decided which one won yet." She pulled the book back across the table and looked at the cover with an expression he did not have a word for. "That is why I keep pushing you. Because you can already do the thing I spent years learning to do, which is to mean what you write."\nThe room was very still.\nHe wanted to say something adequate and could not locate anything adequate and so he said: "You should keep writing too. Not just teaching it."\nIt came out quieter than he intended. She looked at him, and there was a moment, brief and complete, where they were simply two people who cared about the same things looking at each other across a plastic table.\nThen she opened her notepad.\n"Let me see the fourth draft you mentioned on Wednesday," she said, and the lesson resumed, the professional frame settling back into place.\nHe passed her the pages. She read, made small marks in the margin, asked him three questions about his argument that made him think harder than the essay itself had. By the end of the hour he had a fifth draft mapped out in his head and his hand was cramped from writing notes.\nAfter she left, he stayed in the chair.\nHe thought about her standing outside the school gates, laughing at something he had not heard. He thought about the forty-three primary four children and the specific thing their faces did. He thought about a girl from Owerri who had borrowed a book and never returned it, who carried it through her service year because some days it was the only thing that helped.\nHe thought about the fact that she had a whole life that existed entirely outside Room 4.\nHe did not know why this made him feel the way it made him feel. Fuller somehow, and lonelier at the same time.\nHe opened his notebook and tried to write it down before it moved out of reach.','\n',char(10)),994,1,1,NULL,'2026-04-19T15:02:07.415Z','2026-04-19 15:02:07','2026-04-19 15:02:07','2026-04-19T15:05:00.000Z',1,NULL);
INSERT INTO "chapters" ("id","novel_id","chapter_number","title","content","word_count","is_premium","is_published","audio_url","published_at","created_at","updated_at","scheduled_release_at","part_number","season_id") VALUES(510,64,7,' Someone Her Own Age',replace('It was not what he expected and it was not dramatic and that was the thing that made it so difficult to put down afterward.\nHe had gone with his mother to the Thursday market on Lagos Bus Stop Road, which he did not usually do but had agreed to because his mother had asked in the voice she used when she genuinely wanted company rather than help carrying things. They moved through the stalls in the way they moved through markets together, his mother stopping to examine and negotiate, Chukwudi walking at her pace and holding whatever she handed him.\nThey were near the back row, where the provisions stalls gave way to household goods, when he heard her voice.\nHe recognized it before he located her. The particular clarity of it, the way it arrived in a crowd without effort. He turned and she was three stalls away, standing beside a young man in a white kaftan, both of them looking at a display of printed fabric. The young man was pointing at something and Amanda was shaking her head, laughing, and the young man leaned closer to say something directly into her ear that made her laugh again.\nHe was tall. He had the ease of someone who had been comfortable in his own body for a long time. He touched the fabric, held a corner of it toward Amanda, and she took the corner and held it against her wrist to check the color. The gesture between them was unhurried and familiar, the gesture of people who had stood beside each other in many places before this one.\nChukwudi''s mother said something about onions. He answered her without knowing what he said.\nHe did not stare. He moved with his mother down the row and kept his eyes on the stalls and carried what he was handed and did not look back. He was aware of the exact coordinates of Amanda''s position relative to his for the full seven minutes they remained in the same market, in the way you were aware of a sound that had stopped but whose frequency your body still expected.\nIn the car going home, his mother talked about the price of tomatoes, which had risen again in a way that she took personally. He responded where responses were needed and watched Port Harcourt move past the window.\nHe was fine. He was completely fine and he was fourteen years old and he was aware that he was supposed to be fine and he was monitoring himself for the specific humiliation of not being fine and finding, underneath the monitoring, something that did not feel like fine at all.\nThe lesson that evening was English comprehension and his performance was the worst it had been in weeks. He lost the thread of an argument midway, gave an answer he knew was shallow without being able to access anything deeper, sat in his own brain and felt it working at reduced capacity the way the house worked when NEPA had taken light and only the generator''s four hours stood between them and full darkness.\nAmanda looked at him at one point with her head slightly tilted.\n"Where are you today?" she said.\n"I am here," he said.\nShe let it pass. She moved to the next question, gave him a moment to reset, and he managed the rest of the lesson at something close to his usual standard. But he could feel the effort of it, the conscious maintenance of normal, and he did not think she had fully let the question go.\nNear the end, while she was reviewing his notes, he said it without planning to.\n"Who was the person at the market? The one in the white kaftan."\nShe looked up. Her expression did not change dramatically but something in it located him with precision.\n"His name is Emeka. He is a corper too, posted to the government secondary school on Aba Road." She paused. "We met during orientation. We have been friends since then."\nFriends. The word arrived and he turned it over and examined it the way he examined words in comprehension passages, looking for what they carried beyond their face value.\n"Okay," he said.\n"We grew up in the same area in Owerri," she added. "Different streets but the same parish."\nHe nodded. He was performing a version of himself that found this information straightforwardly acceptable, and he thought he was performing it adequately.\nAmanda closed her notepad. She looked at him for a moment with the particular quality of attention that had started all of this, the attention that saw rather than looked, and he felt the specific terror of being seen right now, at this moment, when what was inside him was something he had not chosen and could not explain and did not want anyone to identify.\nShe said: "You are one of the most perceptive students I have taught, Chukwudi. And one of the most honest, when you let yourself be." She picked up her bag. "Whatever you are working through, write it. Do not perform your way around it. Write it."\nHe did not answer.\nAfter she left he sat in Room 4 for a long time in the particular silence of a room that had held something and now held only the after of it.\nHe was not jealous. He told himself clearly and with some firmness that jealousy was not the thing he was feeling, because jealousy required a claim and he had no claim. He was fourteen and she was twenty-two and she was his lesson teacher and there was a young man in a white kaftan who had grown up two streets from her and knew what made her laugh and stood beside her in markets with the ease of someone who belonged there.\nHe understood all of this. He understood it the way he understood complex things, completely and without comfort.\nHe opened his notebook.\nHe wrote one sentence.\nSome gaps do not announce themselves. They simply appear, and then you have to decide what to do with all the ground that used to feel solid.\nHe stared at it for a long time.\nThen he kept writing.','\n',char(10)),1042,1,1,NULL,'2026-04-19T15:03:10.361Z','2026-04-19 15:03:10','2026-04-19 15:03:10','2026-04-19T15:07:00.000Z',1,NULL);
INSERT INTO "chapters" ("id","novel_id","chapter_number","title","content","word_count","is_premium","is_published","audio_url","published_at","created_at","updated_at","scheduled_release_at","part_number","season_id") VALUES(511,64,8,' After Friday',replace('She told him at the beginning of the lesson, which was the right thing to do and also the worst possible way for him to receive it.\nHe had arrived in Room 4 at five fifty-five, five minutes earlier than usual, because it was Friday and Friday lessons had become the fixed point around which the rest of his week quietly organized itself, a fact he had not examined too closely. He had his notebook, his English text, the draft he had worked on since Wednesday. He was ready.\nAmanda arrived at six. She set her bag down, and she did not open it. She sat across from him and placed both hands flat on the table, a gesture he had not seen her make before. It made him pay attention in a different way.\n"I need to tell you something before we start," she said.\nHe waited. He was good at waiting.\n"I have been reposted. A primary school in Rumuola needs a corper and the local government selected me for the transfer. It is further away." She paused. "I will not be able to continue coming here after today."\nThe room did not change. The light was the same, the table was the same, the plastic chair held his weight exactly as it had every Monday and Wednesday and Friday for the past weeks. Everything was identical and something inside it had shifted completely.\n"Okay," he said.\nAmanda looked at him. "I wanted to tell you at the start so we could still have the full lesson. I did not want to leave it until the end."\n"That makes sense," he said.\nHis voice was level. He could hear that it was level and he was holding it there with something that was not quite effort but was also not natural, the way you held a glass of water completely still not by gripping it harder but by becoming very deliberate about your own stillness.\n"Your mother knows," Amanda said. "I called her yesterday. She is looking into another corper, someone who lives closer."\nHe nodded.\nShe studied him for a moment with the attention that had always seen past what he presented. He looked back at her steadily and showed her nothing he was not prepared to show.\n"Shall we start?" he said.\nSomething moved through her expression. Not pity. Closer to recognition. She opened her bag and took out her notepad.\nThey worked through the lesson with the full concentration of two people who had decided, without discussing it, that the work deserved the same seriousness it had always been given. She reviewed his draft, the one on the 1929 women, and it was the fifth version, lean and argued and honest in the way she had been teaching him to be honest on the page. She made two small marks and no large ones. She asked him four questions and his answers were good. He knew they were good. He could feel the quality of his own thinking and today the thinking was sharp in the specific way things were sharp when something behind them was pressing.\nAt one point she handed him her cracked-spine book of short stories, the one from the girl in Delta State, and asked him to read the last paragraph of the first story aloud. He read it. His voice held.\n"What is it doing?" she said. "That last paragraph."\n"It is not resolving anything," he said. "It is just telling the truth about how the thing felt. Without explaining why the feeling matters. It trusts that the reader already knows why it matters."\nAmanda looked at him steadily. "Yes," she said. "Exactly that."\nThe lesson ran its full hour and twenty minutes. At the end she stacked his papers, added her notes in the margin of the draft, and slid it back to him. She took a separate sheet from her notepad and wrote something on it, tore it out, and placed it on top of the stack.\n"That is the name of a writing competition. It is open to secondary school students in Rivers State. The submission deadline is in March." She tapped the paper once. "You should enter the Ogoniland essay. Revise it one more time, tighten the ending, and send it."\nHe looked at the paper. Her handwriting was small and precise.\n"Okay," he said.\nShe zipped her bag. She stood. She looked at him the way she had been looking at him since the first evening, directly and with full attention, the way that had started everything.\n"You are going to be fine, Chukwudi," she said. "Not because things will be easy. Because you have the thing inside you that makes difficult things useful. You know how to turn what happens to you into something you can think with. That is not common. Do not let anyone tell you it makes you soft."\nHe absorbed this without moving.\n"Thank you," he said. "For the lessons."\nShe smiled, brief and real, and said good evening to him, and then called out the same to his mother who was somewhere in the back of the house, and then the front door opened and closed and her footsteps moved down the compound path and disappeared into the noise of the street outside.\nChukwudi sat in the plastic chair.\nThe good chair was still in its corner. The side table was bare, no chin-chin bowl, no covered cloth. The generator next door had not come on yet and the room held the specific quality of evening light that existed only in the twenty minutes before darkness arrived to replace it.\nHe sat in it.\nHe did not move and he did not make a sound and he held himself completely still the way the story''s last paragraph had held itself, without resolving anything, without explaining why the feeling mattered, trusting that somewhere underneath all of it, the part of him that had learned to write would eventually know what to do.\nFriday became evening.\nEvening became dark.\nHe sat in it.','\n',char(10)),1012,1,1,NULL,'2026-04-19T15:04:14.013Z','2026-04-19 15:04:14','2026-04-19 15:04:14','2026-04-19T15:05:00.000Z',1,NULL);
INSERT INTO "chapters" ("id","novel_id","chapter_number","title","content","word_count","is_premium","is_published","audio_url","published_at","created_at","updated_at","scheduled_release_at","part_number","season_id") VALUES(512,64,9,'Room 4 on a Tuesday',replace('The new teacher did not come until the following Wednesday.\nHis mother had found her quickly, a final year university student named Blessing who lived four streets away and charged less than Amanda had and arrived with a printed lesson plan in a plastic folder and a bright, efficient manner that filled the room with forward motion. She was good. Chukwudi could see that she was good. He answered her questions correctly and took his notes and thanked her at the end of the hour and felt, throughout all of it, like a person watching himself from a slight distance.\nBut that was Wednesday.\nTuesday was the day nobody had planned for.\nTuesday was the day that used to be empty, the gap between Monday and Wednesday that had always been an ordinary nothing, homework and supper and the generator''s four hours and sleep. It had not occurred to him that Tuesday would be the day that cost him the most, because Tuesday had never been a lesson day. Tuesday had no reason to feel like loss.\nHe sat in Room 4 at six o''clock on a Tuesday evening with no particular explanation for why he was there.\nHe had come in to get a textbook he had left on the shelf. That was true. He had gotten the textbook, and then he had sat down, and the sitting had become staying in the way that sometimes happened when the body made a decision the mind had not finished making yet.\nThe room was exactly as it had always been. The plastic foldout table. The good chair in its corner with no occasion to justify moving it. The shelf with his textbooks leaning against each other in the order he had arranged them. The single window that looked onto the side passage between their compound and the next, where the neighbor''s breadfruit tree dropped leaves that nobody raked.\nHe looked at the chair across from where he sat.\nIt was a green plastic chair with a faint crack along the left armrest that Amanda had never seemed to notice or had chosen not to mention. He had noticed it on the second lesson and had thought, briefly, about whether it would hold, and it always had. The crack was still there. The chair was still there. It was the same chair it had always been and it was also now the most present absence in the room.\nHe was not someone who cried easily. He had not cried when he was eight and fell off the compound wall and broke two fingers. He had not cried at his grandmother''s funeral, though he had wanted to, because his father was standing beside him and his father''s stillness had seemed like instruction. He had a high threshold for the kind of pain that produced tears, which he had always thought of as a practical quality rather than an emotional one.\nHe was not crying now. He was sitting in a plastic chair in a room that smelled of dust and old textbook paper and looking at another plastic chair and feeling something that did not have a clean name.\nIt was not sadness exactly. Sadness, in his experience, was about something that had been bad. This was about something that had been good. The specific weight of this was different, heavier in a different place, pressing not on the chest but somewhere lower, in the part of the body that registered permanence.\nShe was still in Port Harcourt. That was the unreasonable part. She had not gone back to Owerri. She was twenty minutes away in Rumuola, teaching forty or fifty children in a school he could find on a map if he chose to. She existed in the same city, under the same load-shedding schedule, buying chin-chin from provision stores and carrying her cracked-spine book in her tote bag. She was not gone.\nShe was just not here.\nAnd here, he was discovering, was the specific location of everything that mattered.\nHe thought about the first evening, his mother''s good chair moved and the covered chin-chin bowl and the way he had sat at the table with his Integrated Science textbook open to a page he was not reading, waiting. He had not known then what he was at the beginning of. You never knew that. You only knew it from the other side, once the thing had already happened to you and left its shape.\nHe thought about her handwriting, small and precise, on the torn sheet with the writing competition details. The sheet was in his notebook now, folded between the pages. He had not looked at it since Friday. He had been aware of it in there, the way you were aware of something in a room even when your back was turned to it.\nHis mother appeared in the doorway.\nShe looked at him sitting alone at the lesson table with no books open and no pen in his hand and the room dim around him, and she did not ask what he was doing there. She looked at him with the quiet that felt, rather than calculated, and he looked back at her and for a moment the house held its breath.\n"Come and eat," she said.\nHe got up. He carried his textbook. He followed her down the corridor toward the kitchen where supper was waiting and the small radio on the counter was playing something low and the ordinary evening was arranged around them, patient and continuous.\nAt the table he ate without tasting. His father discussed a contract dispute at work and his mother made the right sounds and the generator came on at eight and the lights steadied and the fan resumed its turning. Life, which had not paused for any of this, continued in its reliable way.\nHe washed his plate and said good night and went to his room and sat on his bed in the dark for a while before remembering to turn on the light.\nThe notebook was on his desk where he had left it.\nHe did not open it. Not yet. He was not ready to open it yet, which he knew was true because he had learned, over these weeks, the difference between writing because you were ready and writing because you were running. He was still too close to whatever this was. The words would come out unformed and he would have to throw them away, which would feel like losing it twice.\nHe lay down instead and looked at the ceiling and waited.\nTomorrow was Wednesday.\nBlessing would arrive at six with her printed lesson plan and her efficient brightness and the work would continue, because the work was what continued, because Amanda had taught him that the work was what you held onto when everything else became difficult to hold.\nHe knew this. He believed it. It sat in him alongside the weight of the empty chair in Room 4, and neither one cancelled out the other.\nBoth things were true at the same time.\nHe was beginning to understand that this was what growing up mostly felt like.','\n',char(10)),1197,1,1,NULL,'2026-04-19T15:05:10.076Z','2026-04-19 15:05:10','2026-04-19 15:05:10','2026-04-19T15:07:00.000Z',1,NULL);
INSERT INTO "chapters" ("id","novel_id","chapter_number","title","content","word_count","is_premium","is_published","audio_url","published_at","created_at","updated_at","scheduled_release_at","part_number","season_id") VALUES(513,64,10,'The Essay He Did Not Hand In',replace('He started it on a Thursday night three weeks after the last lesson, which was not a decision so much as the moment his hand finally moved before his doubt could stop it.\nHe had tried twice before. The first time he wrote two sentences, read them, and closed the notebook because they were performing grief rather than telling the truth about it, which was a distinction Amanda had made about a student essay once, without knowing she was teaching him something that would matter for reasons beyond English class. The second time he wrote a full paragraph and it was better but it was still aimed at an imagined reader, still shaped for effect, still doing the thing he had learned to stop doing. He threw it away.\nThe third time he did not think about who would read it.\nHe wrote: I am trying to understand what happened to me this term and I do not have a clean way to start so I am starting here, in the middle of not knowing.\nHe read it back. It was not elegant. It did not open with a strong image or a declarative statement. His English teacher would have returned it with a red mark and a direction to begin again. He left it and kept going.\nHe wrote about the first evening. The good chair moved from its corner. The covered chin-chin bowl that nobody touched. The way she had walked into Room 4 and scanned it quickly and he had understood, without being told, that she was someone who formed opinions fast and kept them. He wrote about the question she asked and then waited for, which was the first thing, the thing that had started everything. She waited like the answer was actually the point. I did not know adults did that.\nHe wrote about the Ogoniland essay and what it had felt like to hand over something true and have someone receive it without flinching. He had been handing people his work for years and they had marked it and returned it and he had accepted the marks and moved on. This was different. This was someone reading him, not his sentences, and saying: this is real, keep going. He had not known he was hungry for that until it was given to him.\nHe wrote about the chin-chin and stopped and looked at the ceiling for a moment, and then wrote about it honestly, including the part where he bought four nylons and put two back because four said something he was not ready to say. He wrote: I told myself it was gratitude. It was gratitude. It was also something else I did not have a word for and I think I was scared of the word so I kept using gratitude until it wore thin.\nHe wrote about his father and the notebook and the nail hole in the wall and the specific loneliness of wanting things that the people who loved you did not have language for. He wrote about this carefully, not to indict his father, but because it was true and leaving it out would make the whole thing dishonest. He had learned that omission was its own kind of lie.\nHe wrote about the market and the young man in the white kaftan and the seven minutes of knowing exactly where she was in the crowd without looking. He wrote about going home and sitting in the car while his mother talked about tomatoes and feeling the ground shift beneath something he had been standing on without knowing it was there. He wrote: I understood then that she had a whole life I was not part of and I had known this in theory the entire time and theory turned out to be nothing. The actual knowing was a different thing entirely.\nHe wrote about the last lesson. The way she placed her hands flat on the table before she spoke. The way he had held his voice level and felt himself holding it, the specific muscular quality of keeping still when stillness cost something. He wrote about her saying do not let anyone tell you it makes you soft and the way those words had entered him and stayed in a place where his father''s words about softness had also been living, and how the two things sat beside each other now without canceling out, two true things from two people who both meant him well and saw different versions of what well meant.\nHe wrote about Room 4 on a Tuesday and his mother in the doorway and coming to eat and the generator and the fan and life continuing in its reliable way around a boy who was carrying something that life had not paused to acknowledge.\nThen he stopped and read from the beginning.\nIt was long. It had no proper structure, no clear argument, no thesis his Civic teacher could assess or his English teacher could mark with a number. It moved the way thought moved, forward and back and sideways, following the truth rather than a predetermined shape. By every measure he had been taught to apply to written work, it was not an essay.\nIt was also the most honest thing he had ever written.\nHe sat with that for a while.\nThen he wrote the last part, which arrived not as a conclusion but as an understanding he had reached by the act of writing itself, which was the thing she had been telling him writing could do and which he had believed intellectually and now knew in his body.\nI think I loved her the way you love the first person who shows you what you are capable of. Not because of who she was to me, because she was never mine to begin with and I understood that even when it hurt to understand it. But because of what happened to me in that room. I started writing. I started meaning what I said. I started being the person who rewrote things four times until they were right, not because a teacher was watching but because I could not stand to produce something less than what I actually thought.\nShe did not give me that. She made it impossible for me to keep hiding it from myself.\nThat is what I lost when she left. That is what I kept.\nHe closed the notebook.\nOutside the window Port Harcourt was doing what it always did, generators and traffic and the specific nighttime noise of a city that did not fully sleep. The fan turned. The light held.\nChukwudi sat at his desk and felt, for the first time in weeks, like himself. Not the managed version. Not the performance. The actual thing underneath.\nHe picked up his pen and opened to a new page.\nHe had more to say.','\n',char(10)),1151,1,1,NULL,'2026-04-19T15:06:16.581Z','2026-04-19 15:06:16','2026-04-19 15:06:16','2026-04-19T15:07:00.000Z',1,NULL);
INSERT INTO "chapters" ("id","novel_id","chapter_number","title","content","word_count","is_premium","is_published","audio_url","published_at","created_at","updated_at","scheduled_release_at","part_number","season_id") VALUES(514,65,1,'The Transfer',replace('The day Temi Adeyinka walked into Federal Government College Lokoja, she was carrying a box of textbooks that weighed more than her pride and a Lagos attitude she had absolutely no intention of apologizing for.\nHer mother had said it plainly at the bus park in Ojota, three days before, while paying the fare and refusing to look emotional about it: "This is not punishment. This is opportunity." Temi had nodded because arguing with her mother at a bus park, surrounded by conductors and loud horns, was not the kind of battle she chose anymore. But she had spent the entire four hour road from Lagos in her window seat, watching the landscape shift from highway concrete to red laterite earth, thinking about everything she was leaving behind. Her school. Her position. Three years of carefully constructed reputation as the girl who never seemed to try and still finished first.\nFederal Government College Lokoja was not what she had imagined. She had expected the crumbling grandness she had read about, the kind of federal school that looked like it once mattered and was now held together by tradition and willpower. But the school was functional in a way that surprised her quietly. Red dust paths cutting between long classroom blocks. A wide quadrangle where a group of students in white shirts sat under a neem tree during break. Classrooms with actual glass in the windows and bulletin boards covered in academic results posted in neat columns. It was not Lagos. But it was not a ruin either.\nThe vice principal''s secretary walked her to SS1B without conversation and knocked once on the door before opening it without waiting for a response.\nThe class was in the middle of a lesson. Government. The teacher, a thin man with fingers pale from chalk dust, stopped halfway through a sentence and regarded Temi the way adults regard inconveniences that must be managed but cannot be postponed.\n"New student," the secretary said, handing the teacher a folder and turning to leave before the door had fully closed behind her.\nThirty two faces turned. Temi had been stared at enough times in her life to understand the different categories. The bored stare. The curious one. The immediately calculating stare from whoever considered themselves the social authority of any given room, already measuring whether she was a threat or a prop. She catalogued them all in the first five seconds. Average threat level. Nothing she had not handled before.\n"Adeyinka Temi," the teacher said, reading from the folder. "From Lagos. Previous school, Corona Secondary. Impressive academic record." He said the last part in a tone that made impressive sound like a word under review. "Find a seat."\nThere were two empty seats. One at the back, beside a girl already smiling at Temi with the open warmth of someone who collected people on instinct. One closer to the middle of the room, beside a boy who had not turned around when everyone else did.\nTemi noticed that. The not turning.\nShe took the seat near the back. The smiling girl shifted her bag immediately to make room.\n"I''m Funke," the girl whispered. "Ignore how Mr. Adesanya said that. He uses that voice with every transfer student. He used it on Bello last term and now Bello is his favorite person in this class."\nTemi nodded once. She was still watching the boy who had not turned.\nHe was writing in his notebook. Not copying from the board because Mr. Adesanya had not resumed yet. Something else entirely. From where Temi sat, his handwriting looked small and deliberate, the kind of handwriting that suggested someone who made considered choices about most things.\n"Who is that?" she asked Funke.\nFunke glanced over, then back at Temi, and made a short sound that landed somewhere between amusement and a warning. "That is Dayo Okonkwo," she said. "First position, three consecutive terms. Do not ask about him in that voice before you know what it means."\nTemi opened her mouth to say she had no particular voice.\nDayo Okonkwo turned around.\nNot fully. Just enough. A partial turn, his eyes finding Temi across the rows of desks with a directness that was not rude and not friendly and was something she did not have a name for yet. He looked at her the exact way she imagined someone looked at a new variable in an equation they were already close to solving. One steady second. Then he turned back to his notebook without any change in expression.\nMr. Adesanya resumed the lesson.\nTemi opened her own notebook and wrote the date at the top of a fresh page. Her handwriting was not small. It was even and confident and took up its full space on the line. She was aware, in a way she could not entirely account for, that her pulse had done something briefly irregular in the last thirty seconds.\nShe decided it was the journey. Four hours on a road with too many potholes would do that to a person.\nBefore the lesson ended, Mr. Adesanya threw two questions to the class. Temi answered one without waiting to be called on. A small ripple moved through the room. Dayo answered the other, also without being called on. Mr. Adesanya looked between them with the expression of a man who could already see the shape of something coming and was very tired.\nAfter the bell, Funke fell into step beside her on the path toward the dining hall and offered, cheerfully and without any prompting: "For what it is worth, you are the first person to walk into this school and make Dayo Okonkwo turn around."\nTemi said nothing.\nShe had noticed. She had absolutely noticed.','\n',char(10)),958,0,1,NULL,'2026-04-20T02:22:55.699Z','2026-04-20 02:22:55','2026-04-20 02:22:55','2026-04-20T02:35:00.000Z',1,NULL);
INSERT INTO "chapters" ("id","novel_id","chapter_number","title","content","word_count","is_premium","is_published","audio_url","published_at","created_at","updated_at","scheduled_release_at","part_number","season_id") VALUES(515,65,2,'First Position',replace('The results were always read on Friday mornings.\nTemi learned this on Wednesday from Funke, who delivered the information with the gravity of someone briefing a new soldier on terrain before a known ambush. "Mr. Adesanya reads them himself," Funke said. "Full names. Scores. Position. Out loud. In front of everyone." She paused. "Some people cry. Not in front of him, but after."\nTemi had been at Federal Government College Lokoja for six days. In those six days she had located the one shower in the hostel that had reliable water pressure, memorized the dining hall schedule well enough to avoid the worst of the vegetable soup, and mapped the precise social geography of SS1B with the efficiency of someone who understood that information was always the first resource worth gathering.\nShe had also, without deciding to, catalogued almost everything she knew about Dayo Okonkwo.\nHe arrived to class before the teacher. Every time. He sat in the second row, not the first, which she found interesting because first row was where people sat to be seen working hard, and Dayo did not appear to need that kind of confirmation. He did not raise his hand much but when he spoke it was without the performance some of the other students wrapped their answers in. No lengthy preamble. No eye contact with the class. Just the answer, clean and exact, and then silence. Three different teachers had called on him when they were stuck, not because he had raised his hand, but because they seemed to already know where the answer lived.\nHe had turned around twice more since that first day. Both times, Temi had been speaking. Both times, he had not looked impressed. He had looked interested, which she was beginning to understand was worse.\nFriday arrived the way Fridays arrived at federal schools, slow until it was not, the morning assembly running long, the walk to the first lesson carrying the specific energy of people pretending they were not anxious.\nMr. Adesanya came in with the folder.\nThe class stilled.\nHe sat down, opened the folder, and read from it without any ceremony. That was somehow more severe than if he had made an occasion of it.\n"I will read positions one through ten. The rest of you will collect your individual result slips after class." He adjusted his glasses. "Third term, continuous assessment combined with the mid-session test. Thirty students. These are your rankings."\nHe began.\nPosition ten. Position nine. Each name pulled someone out of anonymity for exactly three seconds before the next name erased them. Temi watched the room rather than the teacher. She could read more from faces than from any announcement. The girl at position seven who exhaled like she had been holding her breath for a week. The boy at position four who nodded once, satisfied, and wrote something in his notebook immediately, as if recording evidence.\n"Position three." Mr. Adesanya looked up briefly, then back down. "Adekoya Funke. Seventy one out of eighty."\nFunke, beside Temi, made a sound that was quiet and private and sounded like relief converted into something manageable. Temi touched her arm once, briefly.\n"Position two."\nThe room did something. Not a sound exactly. More like a collective adjustment, thirty bodies all remembering to breathe properly.\n"Adeyinka Temi. Seventy four out of eighty."\nTemi had known. She had done the calculations herself after the test, honest about what she had gotten wrong, so the number was not a surprise. But hearing her name in this room, at this position, at this school where she had existed for less than two weeks, landed differently than she expected. It landed like an arrival. Like she was real here now in a way she had not been before the sentence.\nShe kept her face even. She had learned early that the expression you wore when your name was called in public was itself a kind of answer to a question everyone was asking.\n"Position one."\nThe room adjusted again.\n"Okonkwo Dayo. Seventy six out of eighty."\nDayo did not move. He did not write anything down. He sat in his second row seat with his hands flat on the desk and his eyes forward, and Temi could only see the back of him, but the stillness had a quality to it that she recognized because she had practiced the same stillness herself. It was the stillness of someone who felt something and had made a deliberate choice about whether to show it.\nTwo marks.\nShe turned the number over. Not in distress. In the precise and focused way she turned over any problem worth solving.\nTwo marks between her and a boy who had been first in this room for three consecutive terms, and she had arrived six days ago, and the test had been taken four days ago, which meant she had written it on day two with no knowledge of the syllabus structure, no sense of the teacher''s preferred format, no time at all.\nTwo marks. With all of those disadvantages built in.\nDayo turned around.\nNot the partial turn from that first day. He turned fully this time, enough that she could see his expression clearly across the rows of desks. It was not smug. It was not a smile.\nIt was the look of someone who had just received information they had been half expecting and found it, against their own preferences, genuinely interesting.\nTemi held his gaze for one full second and then opened her notebook and wrote the date at the top of a new page. Unhurried. Deliberate. Every movement measured.\nShe heard Funke make a sound beside her that was trying very hard not to be laughter.\nShe ignored it. She was already thinking about the next test.','\n',char(10)),966,0,1,NULL,'2026-04-20T02:24:10.905Z','2026-04-20 02:24:10','2026-04-20 02:24:10','2026-04-20T02:35:00.000Z',1,NULL);
INSERT INTO "chapters" ("id","novel_id","chapter_number","title","content","word_count","is_premium","is_published","audio_url","published_at","created_at","updated_at","scheduled_release_at","part_number","season_id") VALUES(516,65,3,'Spectator Sport',replace('\nIt started with Bello.\nBello was the kind of boy who treated other people''s business like a public service, which meant that by Monday morning, the story of Friday''s rankings had been retold, annotated, and distributed across SS1B with the efficiency of a school notice. His version had details Temi was certain no one could have observed from across a classroom. The held gaze. The notebook. The timing of it all. Bello had constructed a narrative from the raw material of two people sitting twelve feet apart, and he had done it with the confidence of someone who believed he was simply reporting facts.\n"He is not wrong though," Funke said, when Temi pointed this out on the way to Monday''s first lesson. "Something happened. I was sitting right there."\n"Nothing happened," Temi said.\nFunke looked at her with the patient expression of someone who had decided not to argue because time would do it for her.\nBy Tuesday, it had a shape. Not a rumor exactly. More like a shared observation that the class had agreed to find entertaining. The two new terms for it, which Temi overheard from a group near the tuck shop, were The Rivalry and, less formally, The Temi and Dayo Situation. She had stopped walking for one full second when she heard that second one. Then she had continued, because stopping was data she refused to give anyone.\nThe thing was, she could feel it. That was the part she could not dismiss as easily as she dismissed Bello''s commentary. There was something different about the air in SS1B now when she and Dayo were both in it. The class paid attention in a particular way, the kind of attention that was less about the lesson and more about the two people at the edge of it, circling each other through answers and silences.\nOn Tuesday, during Literature, Mrs. Ojo asked the class to identify the central tension in the extract they had read the night before. Three hands went up. Temi''s was one of them. Dayo did not raise his hand but Mrs. Ojo called on him anyway, the way she sometimes did, like she had a private arrangement with him about participation.\nTemi answered first. She spoke for forty seconds, precise and structured, building her point the way she always did, from foundation to conclusion without unnecessary decoration.\nThere was a pause.\nThen Dayo said, simply, "She is right about the technique. The conclusion is incomplete though."\nTemi turned to look at him. "Incomplete how."\nIt was not a question. It was an invitation to be specific.\nHe was specific. Two sentences. Clean. They extended her point in a direction she had not taken it, and the direction was correct, and she knew it was correct, which was the most inconvenient part.\n"Fair," she said.\nThe class made a sound. Not loud. More like a collective exhale that had been held for the duration of that exchange and was now, carefully, being released.\nMrs. Ojo moved on. But Temi caught Bello turning to the boy beside him and mouthing something she did not need to lip read to understand.\nThe sides formed without a formal announcement. This was also Bello''s doing, partly, though Temi suspected it would have happened regardless. On one side: the people who had decided, early and loudly, that Temi was going to close the two mark gap by next term and that this was the most interesting academic development in the form''s recent history. Funke was in this group, though she maintained a diplomatic position she described as "supportive of Temi personally and neutral on the conflict professionally." On the other side: Dayo''s people, who were fewer but quieter, and who expressed their loyalty less through enthusiasm than through a settled confidence that suggested they had seen challengers arrive before.\nDayo''s closest friend was a boy named Chukwuemeka, who everyone called Emeka, who was at position six in the rankings and appeared entirely unbothered by this. Emeka watched the whole situation the way a person watched weather, interested but not invested, occasionally providing commentary that Temi overheard and found, against her preference, quite funny.\nOn Wednesday, Emeka passed Funke in the corridor and said, without stopping, "Tell your person to stop timing how long it takes Dayo to write his notes. It is making everyone uncomfortable."\nFunke relayed this to Temi at lunch.\n"I was not timing him," Temi said.\n"I know," Funke said. "But you were watching, and watching with that face you make is basically the same thing."\n"What face."\nFunke demonstrated it. Temi looked at her for a long moment.\n"I do not make that face," she said.\n"You are making it right now," Funke said, and turned her attention back to her food.\nThe performance, which Temi refused to call a performance, continued through the week. The pointed remarks in class debates. The way they both angled slightly toward each other when a discussion got interesting, instinctive and immediate, like two instruments tuning to the same note without deciding to. The class narrated all of it. Bello had started adding what he called analysis, delivered at break time to whoever would listen.\nBy Thursday, someone had begun keeping a casual tally on the inside cover of a notebook. Temi had heard about it third hand and had refused to ask whose notebook it was because asking would mean she cared and she was committed, deeply and specifically, to not caring.\nAfter the bell, Funke fell into step beside her on the path toward the dining hall and offered, cheerfully and without any prompting: "For what it is worth, you are the first person to walk into this school and make Dayo Okonkwo turn around." Temi said nothing. She was thinking about something else entirely, something she had only just registered, which was that in every class since Monday, across four different subjects and four different classrooms, Dayo Okonkwo had never sat more than two desks away from her. And he always arrived after she did.','\n',char(10)),1011,0,1,NULL,'2026-04-28 15:23:10','2026-04-20 02:25:23','2026-04-28 15:23:10','2026-04-20T01:35:00.000Z',1,NULL);
INSERT INTO "chapters" ("id","novel_id","chapter_number","title","content","word_count","is_premium","is_published","audio_url","published_at","created_at","updated_at","scheduled_release_at","part_number","season_id") VALUES(517,65,4,'He Sits Here On Purpose',replace('Temi noticed the pattern on the eighth day.\nShe had not been looking for it. That was the part that bothered her most, that it had not required looking. It had simply accumulated, the way certain truths accumulated, quietly and without permission, until they were too obvious to reroute around.\nDayo Okonkwo sat near her in every class that did not have assigned seating.\nNot beside her. He was never obvious enough for beside. But near. Within a desk or two. Close enough that she was aware of him in her peripheral vision the way you were aware of a light left on in a room you were trying to sleep in. Present. Unignorable. Apparently unbothered by being either.\nShe tested it on a Thursday.\nShe arrived to Government class early, which she never did, and sat at the far left end of the third row, a seat she had never occupied before. It had no strategic value. The board angle was slightly wrong and the ceiling fan overhead was broken and tilted at a degree that suggested it had lost an argument with the wall. There was no reason to sit there except that it was as far from Dayo''s usual coordinates as the room allowed.\nHe came in four minutes later, scanned the room in the way he always did, which was brief and gave nothing away, and sat down two seats to her right.\nTemi looked at the broken fan for a moment.\nThen she opened her notebook and wrote the date.\nShe did not say anything. She was building evidence, not a case. Not yet.\nBy Friday she had enough. Four subjects. Four separate classrooms. The distance between them never more than two desks, never less than one. Always slightly behind her when they entered separately, which meant he was adjusting for where she sat rather than sitting first and letting her adjust. This was deliberate. The deliberateness was the point. Dayo was not careless about anything she had observed, which meant this was not carelessness either.\nShe told Funke at Saturday morning prep, low enough that the girls at the next table could not hear.\nFunke put her pen down. "I know," she said.\nTemi stared at her. "You know."\n"The whole class knows," Funke said, with the careful tone of someone delivering a diagnosis they had been holding for a while. "Temi. Bello made a chart."\nTemi thought about several things she could say. She said none of them. She picked up her pen and looked at her Economics notes and decided that the correct response to this information was to say absolutely nothing and think extremely carefully.\nOn Monday she changed her approach.\nIf he wanted proximity, she would give him proximity. She would give him so much proximity that it became a problem for him rather than a variable he controlled. She arrived to Biology, their first lesson, and sat in the second row, one seat from the aisle. His row. She had never sat in the second row. She arranged her books with the ease of someone who had always sat here and had no particular feelings about it.\nDayo came in, saw her, and sat down one seat away.\nHis expression did not change. This was the part she had been prepared for least: his absolute refusal to react visibly to anything she did. She had expected something. A pause. A question in his eyes. Even the slight recalibration of someone whose plan had been interrupted. She got none of it. He opened his Biology textbook to the correct page before Mr. Fashola had even closed the door, like the seating arrangement was already old news.\nTemi looked at her own textbook.\nFine.\nIn the lesson, Mr. Fashola asked the class to explain the mechanism of osmosis without using the word pressure. It was the kind of question designed to find out who understood the concept versus who had memorized the definition. Four students attempted it. Two of them used the word pressure anyway, which Temi noted with private judgment. She raised her hand.\nShe explained it in five sentences. Clean, accurate, using water potential and concentration gradients in a way that answered the question and slightly exceeded it.\n"Correct," Mr. Fashola said.\nShe was still writing her own notes when she heard Dayo say, beside her, to no one in particular and quietly enough that it was not a class contribution: "You could have made it three sentences."\nShe did not look up. "I could have," she said, equally quiet. "I chose five."\n"Why."\n"Because three would have answered the question. Five answered it and closed every follow up question he might have asked." She turned a page. "Different objectives."\nA pause. Short.\n"That is actually smart," he said. It did not sound like a compliment arranged for effect. It sounded like an assessment he had arrived at and reported without decoration.\nTemi looked up then, because she had not expected honesty and honesty required acknowledgment.\n"I know," she said.\nDayo looked at her for one second with the expression she still had no proper name for, the one that was not a smile but lived in the same neighborhood, and turned back to his notes.\nFunke, three seats away, was looking in the opposite direction with the studied innocence of someone who had heard every word and was choosing, generously, not to comment until later.\nShe would comment later. Temi was already prepared for it.\nWhat she was not prepared for, and would not have admitted to anyone in that room or any other, was the specific feeling of having said something sharp and having it land on someone whose mind was fast enough to catch it cleanly.\nShe wrote her notes. The broken fan in third row suddenly felt very far away.','\n',char(10)),975,1,1,NULL,'2026-04-20T02:26:27.858Z','2026-04-20 02:26:27','2026-04-20 02:26:27','2026-04-20T02:35:00.000Z',1,NULL);
INSERT INTO "chapters" ("id","novel_id","chapter_number","title","content","word_count","is_premium","is_published","audio_url","published_at","created_at","updated_at","scheduled_release_at","part_number","season_id") VALUES(518,65,5,'Forty Minutes',replace('The generator died at 8:47 PM.\nTemi knew the time because she had checked her watch four minutes earlier, calculating how much of prep remained before lights out, and the number 8:47 was still in her head when the fluorescent strips overhead gave one stuttering protest and the whole block went dark.\nFor a moment nobody moved. Then the noise started, the scraping of chairs, someone''s torch cutting a thin beam across the ceiling, the prefect at the front door telling everyone to stay seated in the voice of a person who knew the instruction would be partially ignored. Three students left anyway. The rest stayed, settling into the particular patience of boarding school teenagers who had learned that most inconveniences resolved themselves if you waited long enough and did not expend energy on them.\nTemi''s torch was in her locker. She had not brought it to prep because the generator had not failed on any of the eighteen evenings she had been at this school, and she was practical about probability.\nShe sat in the near dark and waited.\n"Your torch is in your locker," Dayo said, beside her.\n"Yes," she said.\n"Mine too."\n"I know. I saw you come in without it."\nA pause. Outside, something that might have been a frog started up near the drainage channel. The partial light from a distant security lamp came through the louvred windows at a low angle and divided the room into shadow and less shadow. Temi could see the outline of him, his arm on the desk, the angle of his shoulder.\n"You notice a lot of things," he said. Not accusatory. Just observational.\n"So do you," she said.\nThis was true and they both knew it and acknowledging it openly felt different from the way they usually acknowledged things, which was sideways, through class answers and notebook angles and the deliberate performance of not reacting.\nThe silence that followed was not uncomfortable. That was the first strange thing. They had sat near each other for weeks and the silences between them had always had texture, the particular texture of two people engaged in something unspoken. This one was just quiet.\n"Why did you come here," Dayo said. "Mid session."\nTemi considered the version of this answer she usually gave, which was clean and brief and closed the subject. Then she thought about the fact that it was dark and she could not see his expression and he could not see hers, and the usual reasons for the clean brief version did not feel as necessary.\n"My parents separated," she said. "My mother got a posting to Lokoja. I came with her." She paused. "The school in Lokoja she liked most was this one."\nHe did not say sorry. She appreciated that. Sorry was what people said when they did not know what else to offer and she had received enough of it in the last two months to last her considerably longer.\n"Did you want to come," he asked.\n"No," she said. "I wanted to stay in Lagos and finish secondary school in the same place I started it and not be the new person who had to prove herself in a school where everyone already knew everyone else."\nShe had not said that out loud before. Not in that order, not that completely.\n"But you are good at it," he said. "Proving yourself."\n"That is not the same as wanting to do it."\nHe was quiet for a moment. The frog outside had acquired a second frog.\n"I came because my father went here," Dayo said. "And his father before him. It was not really a question in our house. This was just where you went." A brief pause. "I did not mind. I like it here. But I have thought sometimes about what it would mean to have chosen it."\n"Does it matter, if the outcome is the same?"\n"It matters to the person who had to decide," he said.\nTemi turned that over. It was the kind of answer that did not argue with you but moved the whole frame of the question somewhere more honest.\n"You think differently than the way you talk in class," she said.\n"So do you," he said.\nShe almost smiled. She was grateful for the dark.\n"What do you actually like," she said. "Not the subjects. Not the academic part. What do you actually like."\nHe thought about it. She noticed he did not rush.\n"Maps," he said. "Old ones, specifically. Before borders were finalized. The kind where you can see what people thought the world looked like before they had been everywhere." He paused like he was checking if this sounded strange. "And arguments. Not fighting. Actual arguments, where both people are trying to get closer to something true."\nTemi sat with that for a moment.\n"I like bus journeys," she said. "Long ones. The window seat. The way the landscape changes when you have been moving for long enough that you cannot remember exactly what the starting point looked like." She paused. "And I like being right. I know that is not an attractive thing to admit."\n"I like being right too," he said.\n"I know," she said. "It is actually one of the least annoying things about you."\nThe lights came back.\nSudden and total and without warning, the fluorescent strips restarting with the same mechanical indifference with which they had left. The room reassembled itself around them, the other students, the prefect, the scattered textbooks and prep notes, all of it rushing back into existence.\nTemi looked at her notebook. The page was blank. She had not written a single thing in forty minutes.\nAcross the room, someone was complaining about lost work. Chairs scraped. Normal sounds, ordinary sounds, the sounds of a prep session resuming.\nShe did not look at Dayo.\nHe did not look at her.\nBut the air between them had rearranged itself into something neither of them had a prepared response for, and they both knew it, and neither of them said so, and the not saying was its own kind of answer.','\n',char(10)),1022,1,1,NULL,'2026-04-20T02:27:46.334Z','2026-04-20 02:27:46','2026-04-20 02:27:46','2026-04-20T02:35:00.000Z',1,NULL);
INSERT INTO "chapters" ("id","novel_id","chapter_number","title","content","word_count","is_premium","is_published","audio_url","published_at","created_at","updated_at","scheduled_release_at","part_number","season_id") VALUES(519,65,6,'Nothing Happened',replace('Temi woke up at five thirteen and stared at the ceiling of the hostel for eleven minutes before admitting she was not going back to sleep.\nThis was new. She was a reliable sleeper. It was one of the things she considered a personal discipline, the ability to close the day completely at lights out and not carry it past the threshold of consciousness into the next morning. She had managed this through her parents'' separation, through the announcement of the transfer, through the first disorienting week at this school. Eleven minutes on the ceiling was not a crisis. But she noted it the way she noted anything that deviated from an established pattern.\nShe got up, found her soap and towel in the dark, and went to the shower before the queue formed.\nThe water was cold. She had expected it. Cold water at five in the morning was not something she wasted energy resisting anymore. She stood under it and thought, with great deliberateness, about Economics. The next topic was elasticity of demand. She had read ahead. She ran through the formula, the worked examples, the type of question Mr. Bello, their Economics teacher, seemed to favor based on three weeks of observation.\nShe did not think about anything else.\nShe was completely successful at this for approximately four minutes, which was how long the shower lasted.\nFunke was awake when she returned, sitting on her bunk with the focused expression of someone who had prepared a question and was waiting for the correct moment to deploy it.\n"Good morning," Temi said.\n"What happened at prep last night," Funke said.\n"Nothing," Temi said. She hung her towel on the rail beside her locker. "Generator went out. We waited. It came back."\n"Bello said you and Dayo were talking."\n"Bello," Temi said, "was on the other side of a dark room."\n"Bello has exceptional hearing. He considers it a spiritual gift." Funke paused. "Were you talking?"\n"People talk during blackouts," Temi said. "It is a normal human response to having nothing else to do."\nFunke looked at her for a long moment with the expression she reserved for situations where she had decided arguing was unnecessary because the evidence would argue for her eventually.\n"Okay," Funke said.\n"Okay," Temi agreed.\nNeither of them said anything else about it. Temi found her uniform and began to dress with the efficiency of someone whose morning routine was already fully optimized and required no additional thought at all.\nShe saw him at breakfast.\nThis was not unusual. She saw him at breakfast every morning. The dining hall had a loose seating logic that had organized itself naturally over the term, and his table and her table were diagonal from each other, which meant she was aware of him the way you were aware of anything that sat consistently in your peripheral vision. She had categorized this awareness weeks ago and moved on.\nThis morning her eyes found his table before she had consciously directed them there.\nHe was already seated. He was talking to Emeka, leaning slightly forward over his tray, and he had the expression he wore when he was making a point he considered well supported. She knew this expression. She had been on the receiving end of it enough times to have developed a detailed internal taxonomy of his expressions, which she noted, briefly, was a strange thing to have done.\nShe looked at her tray.\nThe bread was the same bread. The tea was the same tea. Nothing about this morning was different from any other morning at this school.\nShe was almost completely convinced of this.\nHe glanced over.\nIt was brief. A fraction of a second, the kind of glance that could be accidental, that could be the result of general visual sweeping of a crowded room rather than any directional intention. Temi had done enough people watching in enough rooms to know the difference between accidental and aimed.\nShe looked at her tea.\nFunke, across from her, said nothing. This was more alarming than if she had said something, because Funke''s silence on subjects she had opinions about required active restraint, and active restraint meant she was being careful, and being careful meant she thought the situation was delicate.\nTemi drank her tea.\nFirst lesson was Chemistry.\nShe arrived, sat down, opened her notebook. Standard. She wrote the date. She reviewed the previous lesson''s notes while waiting for the teacher, which she always did.\nDayo came in. He went to his seat in the second row. He opened his textbook to the correct page.\nNormal. Entirely normal. Two students in a classroom before a lesson. Nothing specific about it.\nExcept that when Mrs. Adamu asked the class to name the factors affecting reaction rates, and Temi answered, and the answer was thorough and correct, Dayo did not follow it with a quiet addition the way he sometimes did. He wrote in his notebook and said nothing.\nShe did not know why she noticed the absence of something that was not even a guaranteed occurrence.\nShe looked at her own notes and kept writing.\nIn the second half of the lesson, Mrs. Adamu posed a problem question and asked them to work through it individually. The room went quiet with the specific industry of students performing effort. Temi worked through the question in seven minutes, checked it twice, and sat back.\nDayo finished around the same time. She knew because the particular rhythm of his pen stopped.\nHe did not lean slightly toward her the way he sometimes did when they finished simultaneously, that small unconscious movement she had noticed and filed away. He looked at the board.\nTemi looked at the board too.\nNothing had shifted. That was the correct reading. The generator had gone out and come back and they had talked the way two people talked when there was nothing else to do and the dark made the usual rules temporarily irrelevant. It meant nothing that she had told him about her parents. It was dark. People said things in the dark.\nShe wrote a note to herself in the margin of her Chemistry notebook. It was not about Chemistry.\nShe looked at it for one second, then drew a line through it.','\n',char(10)),1050,1,1,NULL,'2026-04-20T02:28:50.753Z','2026-04-20 02:28:50','2026-04-20 02:28:50','2026-04-20T02:35:00.000Z',1,NULL);
INSERT INTO "chapters" ("id","novel_id","chapter_number","title","content","word_count","is_premium","is_published","audio_url","published_at","created_at","updated_at","scheduled_release_at","part_number","season_id") VALUES(520,65,7,' Group Work',replace('The inter-house academic quiz was announced on a Wednesday, which gave them nine days.\nThe notice went up on the SS1B bulletin board between a reminder about dining hall conduct and a faded photocopy of last term''s punctuality rankings. Temi read it on her way out of class, standing close enough to take in the full details without stopping, which was a habit she had developed for information she did not want anyone to see her visibly interested in.\nFour houses. Two representatives per house per category. Categories: Science, Humanities, Mathematics, General Knowledge. House assignments were not self selected. They were what they had always been, inherited at registration and carrying the particular weight of things you did not choose but were expected to perform for anyway.\nShe and Dayo were both in Confluence House.\nShe found this out the same way she found out most things at this school, through Funke, who appeared at her elbow at lunch with her tray and the expression of someone arriving with news they found personally delightful.\n"Confluence House academic team," Funke said, sitting down. "Mr. Adesanya is selecting. He posted the shortlist this morning."\n"I saw the notice," Temi said.\n"Did you see the shortlist."\nTemi looked at her.\n"You and Dayo," Funke said, "are both on it. Science and Mathematics respectively. Mr. Adesanya is picking one per category from the shortlist based on last term''s scores." She paused for effect. "Your scores are the highest in both categories. Combined."\nTemi picked up her fork. "So we will both be selected."\n"So you will both be selected," Funke confirmed. "And then you will have to work together. Prepare together. Sit at the same table during the quiz and confer and pass notes and generally behave like people who are on the same side." She took a long drink of water. "I think it is wonderful."\n"You think it is entertaining," Temi said.\n"Those are not mutually exclusive," Funke said.\nMr. Adesanya confirmed the selections on Thursday. He read the full Confluence House team in front of the class with the same ceremony with which he read everything, which was no ceremony at all, just names delivered plainly and an instruction to report to the prep hall on Saturday morning for the first practice session.\nDayo received the news the same way he received most news, without visible reaction and with the immediate pivot to whatever came next. Temi watched him write something in his planner and thought, not for the first time, that his composure was either deeply genuine or deeply practiced, and she had not yet determined which.\nShe was beginning to suspect it was both.\nSaturday prep hall. Eight fifteen in the morning.\nThe full Confluence House team was six students. Two of them were seniors who regarded the SS1 representatives with the mild tolerance of people who had done this before and had opinions about it. One was a quiet JS3 boy who had apparently placed first in his set in Mathematics for two consecutive terms and now sat with the stillness of someone waiting to be underestimated. The other was a girl from SS2 named Adaeze who was, according to Funke''s intelligence, the previous year''s highest scorer in Humanities and took that distinction with considerable seriousness.\nTemi and Dayo sat at opposite ends of the same table. This was not a decision either of them appeared to make consciously. It was simply what happened when two people arrived at a table from different directions and sat down.\nThe SS3 team captain, a broad shouldered boy named Rotimi, distributed past quiz papers and explained the format. Buzzer rounds. Bonus questions. Conferral periods of thirty seconds maximum. Penalties for incorrect answers after conferral. He spoke quickly and with the authority of someone who had organized this before and had specific opinions about time wasting.\n"Science and Mathematics will confer together for the quantitative rounds," Rotimi said. "That means you two." He looked at Temi and Dayo without any awareness that this designation carried any particular weight.\nTemi looked at the past paper in front of her.\nDayo looked at his.\nThey worked through the first practice round individually, which was how Rotimi wanted it, establishing a baseline. The questions were harder than Temi had expected, not in content but in format, the kind of questions that required fast retrieval rather than careful construction, which was a different skill from classroom answering and one she took note of immediately.\nShe got nine out of twelve.\nDayo got ten out of twelve.\nRotimi called the conferral practice next. "Same questions. Different set. You have thirty seconds. Talk to each other."\nThe paper went down between them. Temi read the first question and had the answer in four seconds. She said it quietly.\nDayo shook his head, equally quiet. "That is the expected answer. The question is asking for the exception. Read the last clause."\nShe read the last clause. He was right.\nShe noted what it felt like to have someone catch the part she had moved past too quickly. It felt, unexpectedly, like something she could use.\n"Second question," she said.\nThey moved through the set in twenty two seconds. Eight out of eight.\nRotimi looked at his answer sheet, then at them, with the expression of someone revising an assumption he had not known he was making. "Again," he said.\nThey did it again. Seven seconds faster.\nThe thing about arguing with someone for three weeks across classroom debates and test scores was that you developed, without deciding to, an accurate model of how their mind moved. She knew how he approached problems. He knew how she did. Put on the same side, this was not rivalry. It was something closer to architecture, each of them filling the space the other left open, the answers coming together faster than either of them would have managed alone.\nShe did not say this out loud.\nAfter the session, walking back across the quadrangle, he said: "You read too fast on the first pass."\n"You second guess confirmed answers," she said.\nA pause.\n"Good session," he said.\n"Yes," she said.\nThey parted at the path that split toward their separate hostels. Temi walked the rest of the way without looking back, which required, she realized, a small and specific effort.\nShe thought about the thirty seconds. How it had not felt like thirty seconds.','\n',char(10)),1071,1,1,NULL,'2026-04-20T02:30:10.832Z','2026-04-20 02:30:10','2026-04-20 02:30:10','2026-04-20T02:35:00.000Z',1,NULL);
INSERT INTO "chapters" ("id","novel_id","chapter_number","title","content","word_count","is_premium","is_published","audio_url","published_at","created_at","updated_at","scheduled_release_at","part_number","season_id") VALUES(521,65,8,' What He Said',replace('The quiz was eleven days away and Confluence House had settled into a practice rhythm that Rotimi enforced with the dedication of someone who took inter-house competitions personally.\nMonday, Wednesday, Saturday. Prep hall. Eight fifteen sharp. Past papers, timed rounds, conferral practice. The SS3 members ran the sessions with brisk authority and the JS3 boy, whose name was Ifeanyi, had turned out to be quietly devastating at Mathematics in a way that made Temi recalibrate her initial assessment of him entirely. She respected the recalibration. It meant she was paying attention.\nShe and Dayo had found a working rhythm by the third session. Not a comfortable one exactly. Comfortable suggested ease and ease suggested the absence of pressure and what they had was almost the opposite of that. It was productive tension. The specific friction of two people who thought at similar speeds but arrived from different angles, and had learned, through nine days of thirty second windows, to use the difference rather than argue about it.\nShe read fast and caught the broad structure. He read slower and caught the clause she moved past. Together their accuracy rate was ninety one percent. Separately, in the baseline rounds Rotimi still ran at the start of each session, she averaged eighty three and Dayo averaged eighty five. The gap between their combined score and their individual scores was the clearest argument for collaboration Temi had ever encountered and she was someone who required clear arguments before she conceded anything.\nShe had not told him about the ninety one percent. She suspected he had calculated it himself.\nIt happened on Wednesday, after practice.\nThe session had run long because Rotimi had introduced a new format, rapid fire singles, one representative answering alone while the partner held their notes and could not assist. It was designed, Rotimi explained, for the rounds where conferral was not permitted. Temi found it harder than the conferral rounds, not because the questions exceeded her knowledge but because the silence beside her during those rounds had its own particular quality now, a held attention she was aware of even when she was focused on something else.\nShe got six out of eight in the rapid fire round. One wrong answer was a genuine gap in her knowledge, a history question that fell outside her preparation. The other was a calculation she had rushed.\nDayo got seven out of eight. His missed answer was one she had known. She said nothing about this. There were rules, in the rapid fire round, and she respected rules even when they were inconvenient.\nAfter Rotimi dismissed them, the team dispersed in the direction of various obligations. Temi stayed to collect the practice papers she had borrowed, stacking them in order by topic the way she always did before returning them to the folder.\nDayo was also still there, writing something in his planner, which he appeared to use as a combined calendar, notebook, and thinking record in a way she had started to find oddly legible.\n"The history question," she said, because she was thinking about it and thinking about things without addressing them was a habit she was trying to improve. "The one about the regional government system. Was that a gap or a rush?"\n"A gap," he said. He did not sound bothered by admitting it. "I have not done enough on the First Republic period. It is on my list."\n"It is on the likely question list for this quiz. Rotimi mentioned it in the first session."\n"I know." He finished what he was writing. "What was your second miss."\n"Arithmetic rush," she said. "I calculated the percentage wrong. I knew the method."\nHe nodded once. "You do that when you are slightly ahead of yourself. You confirm the method and move before you finish running it."\nTemi looked at him. "You have noticed that."\n"It has happened four times across three sessions," he said. It was not a criticism. It was the same register he used when he was being accurate, flat and clean, like a measurement rather than a judgment.\nShe picked up the folder. Something about the flatness of it, the absence of any edge in it, was what made the next part land differently than it might have otherwise.\n"You would have caught it," he said. "In a conferral round. You always check yourself when there is a second person."\nHe was already closing his planner when he said it. His attention was moving toward the door and the rest of his day, the comment delivered in passing, not constructed for effect, not timed for impact. Just a thing he had observed and reported, the way he reported most things he observed.\nTemi stood with the folder in her hands.\nShe was trying to identify what was strange about the last twenty seconds and then she understood it. He had not said: you are careless under pressure, or: you should slow down, or: that is a problem you need to fix. He had said: you always check yourself when there is a second person, which was not a criticism at all. It was something closer to: you are better when someone is with you, delivered without any apparent awareness of what that sentence contained.\nShe was fairly certain he had meant it technically. A note about quiz performance and conferral strategy and the mechanics of how she worked under timed conditions.\nShe was also fairly certain that she was going to be thinking about it for considerably longer than the topic warranted.\n"Good session," she said, the way she always said it.\n"Yes," he said, the way he always said it.\nShe walked back to the hostel through the red dust path with the folder under her arm and the afternoon light coming in low and orange across the quadrangle.\nFunke was on her bunk reading when Temi came in. She looked up, read something in Temi''s face that Temi had not intended to leave there, and put her book down.\n"What happened," she said.\n"Nothing happened," Temi said. "Practice ran long."\nFunke looked at her for a long moment.\n"You have that face again," she said.\n"I do not have a face," Temi said.\nBut she sat down on her own bunk and looked at the wall for a moment before reaching for her Economics notes, and the pause was long enough that Funke, wisely, picked her book back up and said nothing at all.','\n',char(10)),1081,1,1,NULL,'2026-04-20T02:31:07.110Z','2026-04-20 02:31:07','2026-04-20 02:31:07','2026-04-20T02:35:00.000Z',1,NULL);
INSERT INTO "chapters" ("id","novel_id","chapter_number","title","content","word_count","is_premium","is_published","audio_url","published_at","created_at","updated_at","scheduled_release_at","part_number","season_id") VALUES(522,65,9,' The Other Boy',replace('His name was Tunde Adeola and he was from SS1A and he was, by any reasonable measure, exactly the kind of boy Temi would have noticed under normal circumstances.\nHe was tall in the easy way, not self conscious about it. He had a quality that some boys at this age performed and others simply had, a settled comfort in rooms, like he had already made peace with where he stood in them. He was funny, specifically the kind of funny that did not require an audience, the low quiet humor that surfaced in passing and did not wait around to be appreciated. Temi had encountered him three times before he introduced himself, once at the library, once near the tuck shop, once during the inter-house athletics meeting that all SS1 students were required to attend regardless of sporting interest.\nThe fourth time, he sat beside her at the library on a Thursday afternoon and said, without preamble: "You are the transfer student who nearly caught Okonkwo on the first test."\n"Nearly is doing a lot of work in that sentence," Temi said, without looking up from her Government textbook.\n"Two marks," he said. "After six days. I would not say nearly."\nShe looked up then. He was already smiling, not the wide smile of someone performing charm but the smaller one of someone who had said what they meant and was comfortable waiting to see how it landed.\nHis name was Tunde. He was studying for the same Government exam. They worked at the same table for an hour and a half without it becoming a thing, which Temi noted as a point in his favor. He did not make conversation out of every silence. He asked one question about her notes, she answered it, he nodded and went back to his own work. Straightforward. Uncomplicated. Easy in a way that most interactions at this school, for reasons she was not examining directly, had not been.\nWhen they were leaving he said, "Same time Saturday?" and she said, "I have quiz practice Saturday morning," and he said, "After, then," and she said, "Possibly," which was not a no.\nShe told Funke about it that evening with the deliberate neutrality of someone reporting logistical information.\nFunke listened to the full account and then said, "He is very nice looking."\n"That is not relevant," Temi said.\n"It is slightly relevant," Funke said. "It is not the most relevant thing. But it is not nothing."\nTemi opened her Literature notes. "It was a library session. We studied."\n"He asked to see you again."\n"He suggested studying again."\n"Temi."\n"Funke."\nFunke smiled and picked up her own book and let the subject settle. But Temi noticed she was still smiling three pages later.\nSaturday practice ran until half ten. Rotimi pushed the rapid fire rounds twice, then ran a full mock quiz with Adaeze keeping time and Ifeanyi recording scores with the seriousness of someone who had been asked to do one thing and intended to do it completely.\nTemi and Dayo''s combined score was their highest yet. Ninety three percent. She allowed herself a private moment of satisfaction about this and then began stacking the papers.\nTunde appeared at the prep hall entrance at ten forty, which was exactly when she had told him practice would finish, which meant he had remembered exactly.\nHe was carrying two small bottles of cold Fanta from the tuck shop. He held one out to her when she reached the door and said, "You look like someone who just won something."\n"Practice," she said, taking it. "We are ready."\n"I never doubted it," he said, which was a simple thing to say and he said it simply and it was fine. He was fine. Everything about this was uncomplicated and fine.\nShe became aware, in the way you became aware of a sound that had been present for a while before you consciously registered it, that Dayo had not left yet.\nHe was behind her, slightly, still in the prep hall doorway, his planner in his hand. She did not turn around. She knew his stillness well enough by now to feel the particular quality of it without looking.\nTunde, who did not know anything about any of this, smiled past her and said, "Okonkwo. Good practice?"\n"Yes," Dayo said. His voice was its usual register, even and unhurried.\n"Quiz is in four days," Tunde said pleasantly. "Confluence going to take it?"\n"Yes," Dayo said, again.\nThere was a pause that lasted less than three seconds and contained, in Temi''s assessment, considerably more information than three seconds should be able to hold.\n"We are going to the library," Temi said, to no one in particular. "Government exam prep."\n"Right," Dayo said.\nShe walked with Tunde toward the library path. She did not look back. This was a principle she had applied consistently for nine weeks at this school and she applied it now.\nShe heard Dayo''s footsteps go in the opposite direction toward the hostel.\nShe focused on what Tunde was saying, which was something about the Government examiner''s known preference for essay structure over content volume, which was genuinely useful information she should be paying full attention to.\nShe paid full attention to it.\nLater, in the library, she reached into her bag for her Government textbook and found, tucked inside the front cover, one of the practice quiz papers from the session. She had not put it there. She recognized the handwriting in the margin immediately, small and deliberate: First Republic. Pages 44 to 61. The questions come from here.\nNo name. He had not signed it.\nHe had also, she realized, not needed to.\nShe sat with the paper for a moment. Tunde was reading beside her, unbothered, present, easy.\nShe opened the textbook to page forty four.','\n',char(10)),975,1,1,NULL,'2026-04-20T02:32:04.407Z','2026-04-20 02:32:04','2026-04-20 02:32:04','2026-04-20T02:35:00.000Z',1,NULL);
INSERT INTO "chapters" ("id","novel_id","chapter_number","title","content","word_count","is_premium","is_published","audio_url","published_at","created_at","updated_at","scheduled_release_at","part_number","season_id") VALUES(523,65,10,' Too Far',replace('The wound came on a Tuesday, dressed as an argument about literature.\nMrs. Ojo had assigned an essay the week before. The prompt was direct: Analyze how a character''s background shapes their ability to succeed. One page, minimum. Cited evidence from the set text. She had told them she would select two essays to be read aloud and discussed in class, which was either an incentive or a threat depending on your relationship with public evaluation.\nShe selected Temi''s and Dayo''s.\nThis surprised no one, including Temi, who had written her essay with the awareness that it was the kind of prompt Mrs. Ojo found meaningful, the intersection of circumstance and character, and had structured her argument accordingly. She had been thorough. She had also been, in places, more personal than she usually allowed herself to be in academic writing. Not obviously. Not in a way that announced itself. But the argument had come from somewhere real and that gave it a quality that purely technical writing did not have.\nMrs. Ojo read them both aloud without identifying which belonged to whom, which was her method. Then she asked the class to respond.\nThe discussion ran well for the first ten minutes. Several students contributed. The arguments were the usual mixture of careful and approximate, the kind Temi could map and anticipate. She said two things, both measured, both well received. Dayo said one thing that reframed the central question in a way that pushed the discussion somewhere more interesting. This was the normal shape of things.\nThen Bello, who had no reliable filter between thought and speech, said: "But does background actually limit you? Or do people use it as a reason not to try as hard?"\nIt was the kind of question that was not really a question. It was a position dressed in a question''s clothing, the rhetorical move of someone who wanted to say something and had chosen a form that made it harder to argue with directly.\nTemi felt the shift in the room. The particular alertness of thirty students recognizing that something with an edge had just entered the conversation.\nShe should have let it pass. She was aware of this later with the clarity that only arrived after the moment for it had gone. She should have responded to Bello''s not-question with the clean academic rebuttal it deserved and moved on.\nInstead she said, "Background is not an excuse. It is a variable. People who have not had to navigate certain variables sometimes struggle to understand why those variables are real."\nA pause.\nBello said, "Like what variables."\n"Like arriving somewhere mid session," Temi said, "with no context, no prior knowledge of the curriculum structure, no social footing, and being expected to perform at the same level as people who have had the full term to prepare. That is a real variable. Closing the gap under those conditions is not the same as starting from the same point."\nShe had not meant it as a declaration. She had meant it as an example. But the room had gone quiet in the specific way it went quiet when something personal had surfaced through an academic argument, and she could feel it landing as more than an example.\nDayo said, from his seat in the second row: "Some people choose their variables."\nIt was quiet. Even by his standards, it was quiet.\nTemi looked at him.\nHe was not looking at her. He was looking at the front of the room, his pen resting on his notebook, his expression doing the thing it did when he was being measured. But there was something underneath the measure that she had not seen before, something that had slipped through, and because she knew his face better now than she had any reason to, she could see it.\n"Some people choose their variables," he said again, still not looking at her, "and some people have their variables chosen for them. But the ones who were given their starting position do not usually get to decide which category deserves more credit."\nThe room understood that sentence. Temi understood it faster than anyone.\nHe knew about her parents. He knew about the transfer, about Lokoja, about the posting and the separation and everything she had told him in forty minutes of darkness that she had not told anyone else at this school. And he had taken that information, which she had offered without armor because it was dark and she had trusted the dark, and he had laid it on the table in front of thirty people as a point in an argument.\nNot deliberately. She believed that even in the moment. He had not constructed it as an attack. It had come from somewhere reactive, somewhere that surprised her because he was not reactive, and that meant she had gotten under something she had not known she was beneath.\nNone of that changed what it felt like.\nShe looked at her essay on the desk in front of her. The argument she had built from somewhere real, the argument Mrs. Ojo had chosen to read aloud, the argument that had just been used against her by the only person in this school she had been honest with.\nShe said nothing for the rest of the lesson. Not one word. Not when Mrs. Ojo asked a direct question that she knew the answer to, not when the discussion circled back to the essay and she had three clear contributions she could have made.\nThe bell rang. The class moved.\nShe put her essay in her bag and walked out.\nFunke caught up to her on the path and said nothing, which was the right call, because Temi''s face had closed in a way that did not invite entry. Funke walked beside her in silence all the way to the dining hall and put food on a tray in front of her and sat down across from her and that was enough.\nBehind them, through the dining hall entrance, Temi heard Emeka say something to Dayo in a low voice.\nDayo did not respond.\nShe did not turn around.','\n',char(10)),1028,1,1,NULL,'2026-04-20T02:33:03.013Z','2026-04-20 02:33:03','2026-04-20 02:33:03','2026-04-20T02:35:00.000Z',1,NULL);
INSERT INTO "chapters" ("id","novel_id","chapter_number","title","content","word_count","is_premium","is_published","audio_url","published_at","created_at","updated_at","scheduled_release_at","part_number","season_id") VALUES(524,65,11,' The Quiet',replace('The first day, the class thought it was a mood.\nTemi came to SS1B on Wednesday morning, sat in her usual seat, opened her notebook, and did not look at the second row. This was not new behavior exactly. She had always managed her attention deliberately, and there had been days before when the rivalry had a cooler temperature than others. One day was nothing. One day was weather.\nBut she also did not answer when Mrs. Ojo opened the Literature discussion and the question was precisely the kind she always took. She let Bello answer it. Bello''s answer was approximate in two places and she sat with her pen still and said nothing. Funke glanced at her once and then looked forward.\nDayo answered the follow up question. Temi wrote a note in the margin of her notebook.\nShe did not look up.\nThe second day, Bello noticed.\nHe arrived to Government class with the alert expression of someone who had been tracking data and was now prepared to share his findings. He said nothing directly. He was smarter than that when it mattered. But Temi observed him watching the second row and then watching her and then watching the distance between them with the concentration of a boy who had built a chart on the inside of a notebook and was now watching its subject matter behave in ways the chart had not predicted.\nAt break, she heard him say to the boy beside him: "Something happened."\nShe kept walking.\nIn class, the shape of the absence was becoming visible. The pointed remarks that had sharpened every discussion for three weeks were not there. The angle Temi and Dayo both took when a debate got interesting, that instinctive lean toward the same point from different directions, was not there. The electricity that the class had been treating as entertainment, the thing that made SS1B''s discussions feel like they had higher stakes than the curriculum required, had gone somewhere, and the room felt its absence the way a room felt a dropped temperature, not dramatically, but in the specific way that made you aware of what had been providing the warmth.\nMrs. Ojo asked a question that would normally have produced the particular dynamic the class had come to expect, two voices arriving at the answer from different angles, sharpening each other without conceding anything. She got one answer, from a girl named Sade, which was correct and sufficient and landed in the room like a coin dropped on carpet.\nMrs. Ojo looked between the second row and the back of the class with the expression of a woman who noticed everything and had decided not to comment. She moved on.\nTemi was not performing the silence. That was the thing she needed to be clear about with herself, because she was honest with herself about most things even when she was not honest with other people. She was not doing it for effect. She was not engineering an absence to see what it produced. She was simply not ready, and readiness was something she had always respected in herself and in others, the understanding that some things required a particular interior condition before they could be approached and that forcing them before that condition arrived made them worse.\nWhat he had said had not been malicious. She had turned this over many times in the days since Tuesday and arrived at the same place each time. He was reactive in the moment, which was new for him, and reactive people reached for whatever was near, and what was near was what she had told him, and he had not thought about what it meant to use it before he used it.\nShe understood this.\nShe was still not ready.\nShe also understood, without wanting to, that his reaction meant something. You did not become reactive about things that did not matter to you. She had watched him for ten weeks and he was not a reactive person, which meant something specific had made him reactive, which meant she had gotten under something she had not been trying to get under, and the knowledge of that sat in her chest with a weight she did not have a clean category for.\nShe opened her Government textbook and read the same paragraph three times.\nBy Friday, it had become the only thing SS1B was interested in.\nEmeka said something to Funke at the tuck shop on Thursday afternoon, which Funke relayed that evening with careful neutrality. "He said Dayo has rewritten his Government essay twice since Tuesday. He does not usually rewrite things." Funke paused. "I am not editorializing. I am reporting."\n"Thank you," Temi said.\n"I am also slightly editorializing," Funke said. "Not much. Just a small amount."\nTemi lay on her bunk and looked at the ceiling. The hostel was loud around her, the specific end of week noise of girls who had reached their limit with structure and were releasing it in overlapping conversations and someone''s radio playing low near the window.\nShe thought about what Dayo had said in the generator dark, three weeks ago, about arguments. About how he liked actual arguments, where both people were trying to get closer to something true. She had understood that exactly when he said it because it was the same thing she liked and had never articulated, the specific pleasure of a mind that would meet yours and push back and not collapse under pressure, and she had recognized it in him from the first week even as she was busy treating it as competition.\nShe was tired of treating it as competition.\nShe was also not ready for what came after that.\nFriday last lesson. Mathematics.\nMr. Okafor wrote a proof on the board and asked the class to identify the error in the third step. It was the kind of question that required patience more than brilliance, the willingness to go back to the foundation rather than accept the established working.\nTemi found it in forty seconds. She did not raise her hand.\nDayo found it around the same time. She could tell by the way his pen stopped.\nHe did not raise his hand either.\nThey sat in the same room with the same answer and the same silence and outside the window the red dust quadrangle was bright with late afternoon light and somewhere across the school someone was ringing the prep bell early and getting it wrong.\nMr. Okafor waited.\nNobody answered.\nHe looked at the second row. He looked at the back of the class. His expression moved through mild confusion into something that was almost, briefly, concern.\nThe bell rang for real.\nTemi packed her bag. The answer she had not given sat in her chest alongside everything else she was not ready for yet, and she walked out of the classroom into the orange afternoon and thought: not today.\nBut soon.','\n',char(10)),1161,1,1,NULL,'2026-04-20T02:33:57.536Z','2026-04-20 02:33:57','2026-04-20 02:33:57','2026-04-20T02:35:00.000Z',1,NULL);
INSERT INTO "chapters" ("id","novel_id","chapter_number","title","content","word_count","is_premium","is_published","audio_url","published_at","created_at","updated_at","scheduled_release_at","part_number","season_id") VALUES(525,65,12,'By First Name',replace('The inter-house academic quiz happened on a Saturday and Confluence House won it.\nThis was not a surprise to anyone who had watched the practice sessions, but winning still produced its own particular feeling, the kind that arrived not as noise but as a quiet settling, like something that had been held at tension finally finding its resting position. Rotimi shook both their hands after the final scores were read, with the solemnity of someone completing a ritual, and Ifeanyi wrote the final score in his notebook even though it was already on the board, because he was exactly that kind of person and Temi had come to find it entirely reasonable.\nThe team dispersed into the general celebration of house members who had been watching from the hall benches. Someone produced a bag of chin chin from somewhere. The SS3 girls were loud in a way that suggested the win mattered to them for reasons beyond academics.\nTemi stood at the edge of it and felt the afternoon settle around her.\nShe had not spoken to Dayo outside of quiz necessity for eleven days. During the quiz itself they had functioned as they always functioned in conferral, efficient and accurate and assembled from the same material, the thirty second windows doing what they always did, which was collapse the distance between them into pure utility. She had felt him beside her during the final round with the specific awareness she had stopped pretending was ordinary. She had answered four questions. He had answered three. They had conferred on two and been right on both.\nAfter, in the general movement of the hall emptying, she had looked for a moment to say something and not found it, or not taken it, and now she was standing at the edge of a celebration with chin chin she was not eating and the afternoon light coming in through the high windows and the thing she was not ready for sitting closer than it had been on Friday.\nShe went outside.\nThe quadrangle was mostly empty. A few junior students crossing from the hostel direction. The neem tree throwing its long late afternoon shadow across the red dust. The smell of the school in the early evening, something like iron and chalk and the specific green smell of the compound after the groundsmen had cut the grass that morning.\nShe sat on the low wall beside the main classroom block and looked at nothing in particular.\nShe heard him before she saw him. His footsteps on the concrete path were recognizable to her now and she noted this without judgment, the way she noted most things about herself that had moved past the point of arguing with.\nHe sat on the wall. Not beside her. A small distance, the same instinctive calibration he had always applied, except that today it felt less like strategy and more like consideration.\nThey sat in the kind of quiet that had its own texture now, specific to them, built from eleven weeks of everything that had passed between them and everything that had not.\n"I should not have said what I said," he said.\nHe was not looking at her. He was looking at the neem tree, his hands on the wall on either side of him, his voice at its usual register but with something underneath it that was not usual.\n"No," she said. "You should not have."\n"I knew it when I said it," he said. "I said it anyway."\nShe considered what she wanted to do with that honesty. She could receive it as an apology and close the subject. That was the efficient option. She had always preferred efficiency.\n"Why," she said instead.\nA pause. The kind he took when he was not performing the answer but actually finding it.\n"Because you mentioned Tunde," he said. "And I was already in the middle of saying something before I understood why I was saying it."\nThe quadrangle was very quiet.\nTemi looked at the neem tree. A single bird had landed in its upper branches and was doing nothing visible except existing there, small and unremarkable against the early evening sky.\n"That is a very honest answer," she said.\n"You asked an honest question," he said.\nShe turned to look at him then. He turned at the same moment, and for the first time in eleven days they were looking directly at each other without a quiz paper or a classroom between them, and his expression was the one she had never had a name for, except that she had a name for it now and had probably had it for longer than she was willing to account for.\n"I told you things in the dark," she said. "That I have not told other people here."\n"I know," he said.\n"That meant something," she said. "The telling."\n"I know," he said again, and his voice was different on the second one, quieter, carrying the specific weight of someone who understood exactly what they had been given and what they had done with it and was not minimizing either.\nShe looked at the bird in the neem tree.\n"Dayo," she said.\nIt was the first time. In eleven weeks of sitting near each other and arguing in classroom voices and forty minutes in the dark and everything after, she had not once used his first name. They had called each other by surname the way you called a worthy opponent by surname, with the formality of people who had agreed, without discussing it, to keep a particular distance.\nHe went still beside her.\n"I am not good at this," she said. "The part that comes after the argument. The part where you stop using the argument as a reason not to say the actual thing."\n"Neither am I," he said.\n"I know," she said. "It is actually one of the least annoying things about you."\nShe heard him exhale. Not quite a laugh. Something that lived beside a laugh and was warmer.\n"Temi," he said.\nHer name. Plain and direct and without any distance in it at all.\nShe looked at him. He looked at her. The neem tree shadow stretched long across the quadrangle and somewhere behind them the chin chin celebration was still producing noise and across the compound the prep bell was thirty minutes from ringing and none of it was the thing that mattered right now.\n"Good quiz," she said.\n"Yes," he said. "Good quiz."\nNeither of them moved. Neither of them needed to. Something had been said that could not be unsaid, and it sat between them in the late afternoon light, uncomplicated and true, the kind of thing that did not require a next sentence immediately.\nThey sat on the wall until the prep bell rang.\nThen they walked, not together exactly, but not apart, back into the school.','\n',char(10)),1150,1,1,NULL,'2026-04-20T02:35:20.352Z','2026-04-20 02:35:20','2026-04-20 02:35:20','2026-04-20T02:37:00.000Z',1,NULL);
INSERT INTO "chapters" ("id","novel_id","chapter_number","title","content","word_count","is_premium","is_published","audio_url","published_at","created_at","updated_at","scheduled_release_at","part_number","season_id") VALUES(526,66,1,' Glass and Chrome',replace('The pool at Meridian Academy caught the morning light and threw it back at you, and every girl who had ever swum there knew this and dressed accordingly. Adanna Obi had been dressing accordingly since JSS1.\nShe stood at the top of the corridor that ran along the upper wing, blazer hanging off one shoulder the way Vice Principal Chukwu specifically hated, watching Sochi and Temi down on the pool terrace. Sochi had her head thrown back at something on her phone, braids catching the light like they had been arranged for a photograph. Temi was applying lip gloss with the focused energy of someone who took this seriously, because Temi took all of it seriously. They were waiting for Adanna. They were always waiting for Adanna.\nShe let them wait thirty more seconds before she started moving.\nThis was how things worked at Meridian. There was a current to the place, invisible but completely real, and certain girls rode it and certain girls fought it and the ones who fought it were always slightly breathless from the effort. Adanna did not fight and she did not ride. She simply was. She had arrived at Meridian in JSS1 with her father''s name, a confidence that did not announce itself, and the easy posture of a girl who had never once been made to feel that a room was not hers. The rest had arranged itself around her the way things arrange themselves around a settled center.\n"You''re late," Sochi said, not looking up from her phone.\n"I''m exactly on time," Adanna said. "You came early."\n"It is the same thing."\n"It is absolutely not the same thing."\nTemi capped her lip gloss and looked between them. "Double English in eleven minutes."\nThey walked. The daily procession, the three of them down the corridor alongside the pool, blazers straight, voices low and warm. This was a school where things worked. The air conditioning worked. The projectors worked. The library had new books in it, not the kind donated from dead people''s estates, cracked along the spine and carrying the particular weight of someone else''s abandoned life. Adanna did not think about any of this because she had never been without it. Water does not think about being wet.\nMrs. Adeyemi took them through a comprehension passage that three quarters of the class had actually read. Adanna had read it twice. Not from anxiety but from preference. She liked knowing the answer before she was asked. There was a difference between studying hard and simply being prepared. Studying hard was nervous. Prepared was just sensible.\nA folded note arrived on her desk halfway through the lesson. She opened it low under the table.\nTokunbo is doing something Saturday. Island Club rooftop. Can your dad''s driver bring us?\nShe wrote back: Yes. Folded it. Passed it without looking up.\nEmmanuel would come in the black Range Rover, cold inside, quiet underfoot, and Emmanuel never asked where they were going or noticed when they came back carrying the residue of someone else''s party. He was better than a parent for these purposes.\nAfter dismissal they claimed the terrace by the pool, because this was also ritual. The SS2 girls treated this terrace the way adults treated a sitting room, a place to decompress, to say the things that could not be said inside a classroom. A junior girl had sat at their usual table once, early in the term. She had been corrected, quietly and completely, and it had not happened again.\nSochi announced that the Island Club rooftop was tired and had been tired since they were fourteen.\nTemi said: "You say that because you have no better suggestion."\n"I say it because it is true. I am allowed to state true things."\n"State them somewhere else. We are going."\nAdanna listened and watched the pool. The light was falling orange now, the surface still, everything underneath it suspended and quiet. She looked at it for a while. It looked like something that would always be there.\nEmmanuel collected her at five fifteen. She settled into the back seat and watched Lagos Island move past the glass in its evening state, the yellow buses cutting lanes, the hawkers threading between cars at the junction on Awolowo Road, men in agbadas stepping out of the bank with their briefcases and their serious faces. Everything out there, nothing in here. The glass between them felt permanent and correct.\nHer mother was in the sitting room when she got in. A phone call ended a beat too quickly when she heard the door.\n"Welcome."\n"Good evening, Mummy."\n"How was school?"\n"Fine."\nHer mother nodded and looked at the far wall in the particular way that meant she was calculating something she had decided not to share. Adanna noticed it and left it alone. There were textures to her parents'' life together that she had learned early not to reach for. Families like theirs ran on a polished surface, and the surface held because everyone agreed to maintain it.\nShe went upstairs, showered, and opened her reading for tomorrow.\nDinner was laid for eight. Three plates. The good china.\nAt eight fifteen, her mother told the housekeeper to go ahead and serve.\nAdanna looked at her father''s chair. Empty. Her mother was cutting her chicken with quiet precision, eyes on her plate, not on the chair, not on Adanna.\n"Where is Daddy?"\nHer mother took one slow breath. "He has a meeting."\nThe answer was correct. Her father had meetings all the time. But the way her mother said it, without looking up, without the usual footnote about when he would return, made the word feel thin. Like a piece of fabric laid over something it was not quite large enough to cover.\nAdanna ate her dinner. She did not ask again.','\n',char(10)),975,0,1,NULL,'2026-04-20 10:56:02','2026-04-20 10:53:04','2026-04-20 10:56:02','2026-04-20T10:10:00.000Z',1,43);
INSERT INTO "chapters" ("id","novel_id","chapter_number","title","content","word_count","is_premium","is_published","audio_url","published_at","created_at","updated_at","scheduled_release_at","part_number","season_id") VALUES(527,66,2,'What the Driver Knows',replace('Chibunna asked about Emmanuel on Monday, the way she asked about everything, directly and in front of people.\nThey were in the tuck shop queue, four of them, Adanna and Sochi and Temi and Chibunna who was not exactly in their group but moved near its edges with the confidence of someone who had decided that was close enough. The question arrived between the moment of receiving a meat pie and the moment of paying for it: "Your driver didn''t bring you today. Is he sick?"\nAdanna took her meat pie. "He has something to sort out."\n"Since last week?"\nShe looked at Chibunna with the particular steadiness she had spent four years developing, the one that said: this line of inquiry is not welcome and I am being pleasant about it. "He''ll be back," she said, and turned to Sochi with a comment about something else entirely, and Sochi, who could always read the redirect, followed it without pause, and the conversation moved on.\nChibunna was not cruel. That was what made it worse. She was simply a girl who noticed things and said them, and what she had noticed was that Adanna had arrived by a different method two mornings running. In a school like Meridian, this kind of noticing was the first instrument of social change. It was not gossip yet. It was data.\nAdanna ate her meat pie and talked about what Sochi wanted to talk about and let the morning arrange itself. The performance was good. She had always been good at this.\nWhat she was less good at, she was discovering, was the performance she could not see she was giving.\nHer father had been at the breakfast table that morning for the first time in a week. She had come downstairs to find him with a cup of tea he was not drinking, his phone face down beside it, still in yesterday''s clothes. She had not seen him in yesterday''s clothes before. He was a man who was always dressed before the house woke, who was suited and ready by six as a daily act of discipline, as if the day were a meeting he intended to win. He had looked up when she came in and asked about her exam timetable and she had answered and he had listened and when her mother came in with the car keys he had kissed her on the cheek and said be safe, and the whole exchange had been correct.\nShe had watched him through the window as they reversed out of the compound. He was still at the table. He had not moved.\nIn double English, Mrs. Adeyemi paired the class for comprehension. Adanna was paired with Nkechi, who wore her socks at exactly the same height every day and had opinions about everything and expressed them with full commitment. Nkechi read the passage twice, set it down, and said: "The author is wrong. You can see it in the third paragraph."\n"You can''t say the author is wrong," Adanna said.\n"I just said it."\n"The author has a position. You can disagree with the position."\n"That is exactly the same as wrong."\nThey went back and forth for four minutes and Adanna felt herself actually inside the argument, not managing it from the surface but present in it, and it was the first time all morning she had forgotten to maintain anything because there was nothing to maintain. She was just there, with her whole attention, pushing against an idea because the idea deserved to be pushed against.\nNkechi said after class: "You''re good at arguing."\n"Thank you."\n"I mean it as a compliment."\n"I know," Adanna said. And she did.\nWalking to the last period she passed the car park at the school''s front entrance. The black Range Rover was not there. She had not thought about it until she was already looking at the space where it was not. Emmanuel had always been there before the last lesson began, parked at the same angle with a newspaper on the steering wheel.\nShe had never thought about what he did while he waited. He had been waiting for her for four years and she had never once thought about it. She did not know his last name.\nShe thought about this, in the way you think about a thing you cannot change and are only beginning to see.\nHer mother collected her at four. They drove home mostly in silence. At a red light on Awolowo Road her mother looked at her hands on the steering wheel for a long moment, then looked up.\n"Your father is sorting things out," she said. "It will take some time."\n"How much time?"\nThe light changed. Her mother drove.\n"Mummy."\n"I don''t know exactly," her mother said. Not the careful version of I don''t know. The honest one. The version that did not have a shape around it yet.\nAdanna looked out at the road, the evening hawkers and the buses and the men with briefcases and the city going about its complete indifference to private difficulty, and sat with the honest version, which took up more space than the careful one.\nAt home her father was in the library with the door not fully closed. She could see him at the desk, papers spread in front of him, not reading them. Sitting with them the way you sit with something you have read too many times to read again.\nShe went upstairs. She finished her homework. She ate dinner with her mother, just the two of them, at the table set for three.\nThe chair at the end of the table held its shape in the room all evening. Neither of them named it. Neither of them moved it. They ate around it with the practiced quiet of people who had agreed, without saying so, that some things are not made more bearable by being spoken.','\n',char(10)),992,0,1,NULL,'2026-04-26 12:12:48','2026-04-20 10:54:08','2026-04-26 12:12:48',NULL,1,43);
INSERT INTO "chapters" ("id","novel_id","chapter_number","title","content","word_count","is_premium","is_published","audio_url","published_at","created_at","updated_at","scheduled_release_at","part_number","season_id") VALUES(528,66,3,'The Crash',replace('The school knew on Wednesday.\nAdanna found out the school knew on Wednesday because of the way Chisom Eze-Williams looked at her in the corridor outside the chemistry lab, a look that arrived and then disappeared too fast, like a hand pulled back from something hot.\nShe almost stopped walking. She did not stop walking.\nShe filed into chemistry and took her seat and arranged her notebook and did not look at Chisom, who sat two rows forward and to the left, and did not look at anyone else who might be looking at her. The teacher wrote equilibrium reactions on the board. Adanna copied them down in her cleanest handwriting, each symbol placed with the kind of deliberate care that had nothing to do with chemistry.\nBy break time something had changed in the quality of the air around her. It was not dramatic. It was the social equivalent of a barometric shift, the kind you feel in your ears before you understand what it means. Conversations that paused a half second too long when she passed. The table under the overhang where Sochi and Temi were already seated when she arrived, heads bent together, which straightened and brightened in a way that was not quite natural.\n"You''re quiet," Temi said.\n"I''m fine," Adanna said.\nSochi offered chinchin. They talked about the drama rehearsal. The surface held.\nBut at lunch, while Sochi was at the counter, Temi leaned across the table and said quietly: "My mummy said something last night." She stopped. Looked at her tray. "I just wanted you to know. Before."\n"Before what?"\nTemi looked up. Her face was carrying something she did not want to be carrying. "I don''t know exactly. Just. Before."\nAdanna said: "My father is handling some business." The sentence arrived from nowhere, already formed, already polished. "It is a temporary thing."\nTemi nodded. Looked at her tray again. Sochi returned with two Fantas and the conversation moved on.\nThe call came at two seventeen.\nAdanna was in the middle of a group reading in English when the Vice Principal appeared at the classroom door and spoke quietly to Mrs. Adeyemi, who looked at Adanna once and said, "Adanna, please step outside." The class did not make noise. The class was very quiet.\nHer mother was in the Vice Principal''s office, sitting upright in the chair across from the desk, still in her work blouse, her handbag in her lap. She looked like a woman performing composure for an audience. When Adanna walked in, something in her mother''s face shifted, and then resettled.\n"We are going home," her mother said.\n"What happened?"\n"We will talk at home."\nThe Vice Principal made a sound of polite concern. Her mother thanked her. They walked to the car.\nHer father''s company had its accounts suspended. That was what her mother said, in the car, on the Ozumba Mbadiwe road, looking straight ahead. The government agency responsible had moved without warning. There were allegations, her mother said, and then stopped, and then said: "It is not permanent. He is working to resolve it." Her voice was a woman reading from a script she did not fully believe.\nAdanna sat with the words and felt them settle, heavy and strangely without edges, the way very large news often arrives before the mind knows how to give it shape.\n"What about school?" she said.\n"I said he is working to resolve it."\n"Mummy."\n"We will discuss everything at home."\nAt home meant the sitting room. At the sitting room meant her father was there, seated, not in his usual posture, and the sight of him sitting like that in his own house, slightly reduced from his usual size, was more frightening than anything either parent had said. He told her what happened in the direct, clipped version. Accounts frozen, operations suspended, everything under review. He said review the way people say a word they have decided not to believe.\nAdanna sat across from them both and listened and nodded when nodding was required.\nThat evening her mother''s phone rang and she answered it in the kitchen with her voice deliberately low. Adanna was three rooms away. She did not try to hear.\nBut she heard the quality of the call. How it ended. Her mother came back to the sitting room and placed the phone face down and sat.\n"Who was that?"\n"Nobody."\n"Mummy."\n"It was Folake." Sochi''s mother. A pause. "She will call back later."\nShe did not call back later. Adanna checked her own phone after nine. Sochi had not messaged since the brief one after school, which had read ok hope ur good and nothing after that. The full stop at the end of it sat there like a small closed door.\nHer father came to say goodnight at ten. He stood at the doorway of her room in the way that meant he was not coming in, just checking. He said: "This will not swallow us." Like the statement was also a question.\nAdanna said: "I know, Daddy."\nShe turned back to her textbook. She heard him go down the hall. She heard the door of the master bedroom close.\nShe looked at the page in front of her. She had read the same paragraph six times now, and each time the words went in and left nothing behind, like water poured over sealed ground.\nShe closed the book. She sat in the light and let the silence of the house fill in around her.\nHer phone lit up on the desk.\nA message from Temi. Two words, no punctuation, the kind sent quickly, before the sender could reconsider: They know.\nShe looked at it for a long time without touching it, and the question she could not answer, the one that sat at the base of everything, was not what Temi meant. It was who else did.','\n',char(10)),983,0,1,NULL,'2026-04-28 13:26:20','2026-04-20 10:55:35','2026-04-28 13:26:20','2026-04-20T10:10:00.000Z',1,43);
INSERT INTO "chapters" ("id","novel_id","chapter_number","title","content","word_count","is_premium","is_published","audio_url","published_at","created_at","updated_at","scheduled_release_at","part_number","season_id") VALUES(529,66,4,'How Fast They Move',replace('Sochi stopped sitting with her on Thursday.\nIt was not announced. It never was. Sochi simply arrived at the table under the overhang with Chisom Eze-Williams and a girl from the other SS2 arm whose name Adanna had never needed to learn, and the three of them arranged themselves with the ease of people who had been doing this for a long time. Sochi looked at Adanna once, a look that said nothing and everything, and then looked away.\nAdanna sat down anyway. She opened her lunch. She ate it.\nThis was the first lesson in how it worked. The abandonment did not come with confrontation because confrontation required acknowledging that something was being taken. What was being taken here was proximity. The right to sit, to be included in the casual warmth of people who chose you. And when it was removed this way, quietly, with no words to push back against, there was nothing to do but sit with your food and let the space around you announce itself.\nShe sat with it for four minutes. Then she picked up her bag and went to the library.\nBy Friday the table under the overhang belonged to someone else entirely.\nTemi was the one she had believed in. This was important because Adanna did not believe easily, and she had collected evidence of Temi''s difference over three years. Temi was the one who had said, in JSS3, that she did not like how the class had treated the new girl from Imo State, had said it out loud at the table while everyone else was still laughing. Temi was the one who sent long voice notes when you were sick, who remembered the specific details of things you had told her in passing. Adanna had decided, based on this evidence, that Temi was made of different material.\nTemi called on Friday evening.\nAdanna picked up on the second ring.\n"How are you?" Temi said.\n"I''m fine."\nA pause. "My mummy said I shouldn''t talk about your family''s situation."\nAdanna said nothing.\n"She said it''s not our business and we should give your family space."\nThe word space. The way people use it as a container for the thing they mean but will not say.\n"I''m not asking you to talk about it," Adanna said.\n"I know. I just. I wanted to explain." Another pause, longer. "I''m not going anywhere, okay? I just have to be careful about what I say at school. You understand."\n"I understand," Adanna said.\nAnd she did understand. That was the particular cruelty of it. She understood exactly what Temi was doing, which was constructing a version of abandonment that she could live with, a story where she remained a good person in her own accounting. I''m not going anywhere. What that sentence meant, in the language of surfaces they had all learned together, was: I am going somewhere but I need you not to say so.\n"Talk soon," Temi said.\n"Talk soon," Adanna said.\nShe put the phone on her desk and sat with the ceiling for a long time.\nThe week that followed had a rhythm she had not been taught for. The school day arranged itself around her absence from the group with a speed that was almost impressive. The table under the overhang was fully reconstituted, its dynamics reset, as if the three years she had spent at its center had happened to a different school. Girls who had greeted her every morning now achieved a careful nearness to her that was not quite acknowledgment. She had become inconvenient, and the social body was doing what it always did with inconvenience, which was to smoothly close the wound.\nShe moved through it. Library at break. A corner of the upper corridor at lunch where the SSS3 girls used to go before they graduated. She had her books. She had her notes. She was still the girl who knew the answers. The classroom had not been taken from her, and she held it.\nHer father was home less. The phone calls in the kitchen continued, her mother''s voice dropping to a register Adanna had learned not to follow. She stopped trying to read her parents'' faces and started reading the house instead. The housekeeper came three days now instead of five. The freezer was not as full.\nShe noted each thing. She did not speak any of them aloud.\nOn Friday of the second week, Temi messaged. A meme, the kind sent to groups, forwarded without context. Adanna looked at it for a long moment. She put her phone face down.\nTemi sent a follow-up. lol and then a second meme.\nAdanna did not reply.\nTwo days later she understood why Temi had messaged. She saw the photo on Temi''s story. The Island Club rooftop. Tokunbo''s birthday. Sochi and Temi and Chisom and six other girls from their year, someone''s driver visible in the background, all of them dressed in the language of the life they still had. Temi was laughing with her head thrown back, braids catching the light.\nShe had sent the memes because she knew the photo would go up. She had sent them to soften the landing.\nAdanna closed the app.\nShe sat with the knowledge of it, slow and complete, the way you sit when you have just learned something you already knew. She thought about what Temi had said in the car to Obalende once, in JSS3, about the girl from Imo State. I don''t like how they treated her. It says something about who they actually are.\nYes, Adanna thought now.\nIt does say something.\nShe picked up her book.\nOutside, the Lagos evening was going gold.\nShe read until the light changed.','\n',char(10)),958,1,1,NULL,'2026-04-20T10:57:04.925Z','2026-04-20 10:57:05','2026-04-20 10:57:05','2026-04-20T11:10:00.000Z',1,43);
INSERT INTO "chapters" ("id","novel_id","chapter_number","title","content","word_count","is_premium","is_published","audio_url","published_at","created_at","updated_at","scheduled_release_at","part_number","season_id") VALUES(530,66,5,' Inventory',replace('\n\nThe boxes arrived on a Tuesday, flat and stacked against the wall of the entrance corridor, and Adanna stepped around them for two days without looking directly at them, the way you do not look directly at something you are not ready to make real.\nOn Thursday her mother started folding.\nAdanna stood in the doorway of the master bedroom and watched. Her mother worked with the methodical quiet of someone who had decided that the only way through a thing was to treat it like a task. She had a system. Clothes first, by season and weight. Then the smaller items from the dressing table. She did not cry. She did not speak. She lifted and folded and placed with the careful attention of a woman who had decided that feeling it would have to wait until the work was done.\n"You can come in," her mother said, without turning.\nAdanna came in. She sat on the edge of the bed, on the side her father slept on, which was bare now, the small table beside it already cleared of his reading glasses and his devotional and the phone charger that was always there, always coiled in the same corner.\n"I can help," Adanna said.\n"You can pass me that stack."\nShe passed the stack. She watched her mother work.\nWhat she was actually doing, while her hands were useful, was counting. It was the same counting she had been doing all week, the private inventory she had been keeping without deciding to keep it. Every item that moved from its place to a box was an item she was cataloging. Not as loss exactly. As record.\nThe photograph from their trip to Accra in JSS1, the one where her father is laughing so hard his eyes are closed and Adanna is looking at him like he is the funniest thing she has ever seen and she is right. Into a box.\nThe perfume bottles lined along the dresser''s edge, seven of them in ascending height, which her mother had arranged that way when they moved in and never rearranged because she liked the order of it. Wrapped in cloth. Into a box.\nThe curtains in the sitting room were not theirs to take. Adanna had not thought about this before. The curtains came with the house, which was a rented house, which she had always known and had never once thought about. The way you do not think about the walls unless someone tells you the walls are not yours.\nShe went from room to room slowly, over the hours of that afternoon, while her mother packed. She was not packing herself. She was walking. Looking.\nThe pool in the center courtyard, which she had never swum in because it was decorative, her mother''s word, but which had been beautiful to look at in the morning when the light hit it from the east. The tiles around it would stay.\nThe kitchen with the double oven, which Celestine the housekeeper had operated with the authority of someone who understood the equipment. Celestine had not come this week. Her mother had not said why. Adanna had not asked.\nThe library, which was what her father called it though it was a small room with shelves along one wall and a reading chair in the corner. Her father''s books were already boxed, labelled in his handwriting, stacked by the door. Adanna ran one hand along the spines of the ones still shelved. A history of Biafra. Three Chinua Achebe novels. A thick book on corporate law whose spine was broken from use. These were his. They would go.\nHer own room she saved for last.\nShe stood in it and looked at it the way you look at something before a journey, trying to take in enough of it to carry. The light was different here at this hour, falling through the window at the angle that turned the wall above her desk the color of warm sand. She had never tried to describe this before. She tried now.\nShe sat at her desk. In the drawer was the usual accumulation: pens, a broken earring she had kept meaning to fix, an old timetable from JSS3, notes from Temi written on folded paper. She opened one of the notes. Temi''s handwriting, round and deliberate. You looked amazing today. I''m not even saying that. She folded it and put it back.\nShe opened her wardrobe. She owned too many clothes. She had never thought of this as a fact but it was a fact. She ran the rail through, item by item, and tried to see them clearly. The blazer for parties. The two matching sets she had bought with Sochi at the boutique in VI after a whole afternoon of trying things on, the afternoon when the shop girl had called them sisters and they had laughed about it for weeks. She took both sets out and laid them on the bed.\nShe sat beside them for a long time.\nThe girl who wore them knew certain things. She knew which table to sit at. She knew the register that opened rooms. She knew the precise weight of being looked at and found correct. She had built her days around knowing these things, had arranged herself around them the way her mother had arranged the perfume bottles, by order, by height, by the satisfaction of a thing that held its shape.\nAll of that was going into boxes now.\nNot the clothes. The clothes were just cloth.\nBut the version of herself that had lived inside them, that had moved through the world with the particular ease of someone who had never once been made to feel unwelcome in her own life, that girl was being packed up too. Without ceremony. Without acknowledgment. The way you pack something you do not know how to name.\nHer mother appeared in the doorway with a roll of tape.\n"Adanna. Come and eat."\n"Coming," she said.\nShe looked at the clothes on the bed one more time. She picked them up carefully and began to fold.','\n',char(10)),1023,1,1,NULL,'2026-04-20T10:58:05.588Z','2026-04-20 10:58:05','2026-04-20 10:58:05','2026-04-20T11:10:00.000Z',1,43);
INSERT INTO "chapters" ("id","novel_id","chapter_number","title","content","word_count","is_premium","is_published","audio_url","published_at","created_at","updated_at","scheduled_release_at","part_number","season_id") VALUES(531,66,6,'The Island Leaves You',replace('The truck came at seven.\nTwo men, efficient and incurious, the kind of men who had moved other people''s lives often enough that they no longer looked at what they were carrying. They worked from the ground floor up, filling the truck with the logic of weight and space rather than sentiment, and Adanna stood in the entrance corridor with her school bag and a box of books and watched her family''s compound become a series of rectangular problems to be solved.\nHer father directed from the courtyard. He had a clipboard, which she had never seen him use before, and he moved between the men and the rooms with a focused energy that looked, from a certain angle, like purpose. She had seen this before, this ability her father had of converting difficulty into motion. She understood it and she did not comfort her with it.\nHer mother was in the kitchen. The last room. The one she had packed herself.\nBy nine the truck was loaded. The compound stood open around them, each room reduced to its bones, curtains still on the windows because the curtains were not theirs, walls still holding the faint squares where pictures had hung. The pool caught the morning light the same way it always had, indifferent to the occasion.\nAdanna walked through each room once. She did not know why. Her feet decided and she followed them, room to room, the way you do a thing when you know it is the last time even if you have not said so aloud.\nShe stood in her room for one minute exactly. The wall above the desk was warm sand in the morning light, the same as always. She looked at it. She turned and left.\nHer father locked the compound gate at nine forty. The sound of it was very clean and final.\nThey drove in convoy, her mother''s Camry behind the truck, her father''s car behind the Camry. Adanna was in the back seat of the Camry with a bag at her feet and a box on her lap and nothing to look at but what was passing outside the glass. Lagos Island moved past her the way it always had, except now she was moving past it too.\nShe watched it without trying to memorize it. She had passed all of these corners ten thousand times. Her body remembered them the way bodies remember routes they have run long enough. The junction on Awolowo Road. The petrol station with the faded sign outside Falomo. The stretch along the lagoon where the water appeared between the buildings if you were in the right seat at the right moment.\nShe was in the right seat.\nShe looked at the water.\nThen the Carter Bridge, and beneath it the lagoon wide and grey and moving, and above it the sky in its Lagos morning state, white and already bright. She had crossed this bridge in both directions more times than she could count. She had never once thought about which direction was which.\nShe thought about it now.\nMushin arrived without announcement. That was the thing she had not expected. She had imagined a moment of crossing, a visible threshold between one kind of Lagos and another. There was none. The city simply continued and then they were in it, in the press of it, the streets narrower and louder, generators running at the road''s edge, shops open and stacked, a woman selling ogi with a wrapper tied around her waist and a child on her back, keke napep navigating the intersections with the physics of things that should not work but do. The scale of everything was different. Not smaller. Just closer.\nShe did not look away.\nHer mother navigated from a note on her phone. Two turns after a church. Right at the blue building. A street whose name was on a sign so faded the letters had become suggestions.\nThe house was the middle unit in a compound of three. Two floors. A gate that opened inward with a sound that needed oil. A small concrete yard where the landlord''s potted plants stood in a row along the wall, which meant the landlord was the type who kept potted plants, which was something.\nA woman appeared from the first unit and greeted her mother warmly. A neighbor who had been told they were coming. Her mother smiled and responded and accepted a glass of water and this small exchange, this ordinary Lagos introduction, was the first human warmth of the entire morning.\nHer room was on the second floor. She found it herself while her parents directed the men with the boxes. It was smaller than her old room by a measure she tried not to calculate. A window that faced the yard. Walls in a white that had gone slightly towards yellow from age. A ceiling fan instead of air conditioning.\nShe put her bag on the floor. She put her box of books against the wall. She stood in the center of the room.\nThrough the window she could hear the compound''s sounds. The neighbor''s television. A radio from the street. A child somewhere saying the same word three times, urgent about something. Real and layered and continuous, the sound of people living at close range without apology.\nIn the old compound there had been a quality of managed silence. Noise had been kept at the right distance by the gate, by the generator, by the simple fact of space. She had not known she was used to that distance until it was gone.\nShe sat on the floor, back against the wall, knees up.\nShe was not crying. She noted this without pride or judgment, the way you note the weather.\nShe was simply here. In this room. In this new arithmetic of her life, smaller by most of the measurements she had been taught to use.\nBehind the bridge was the compound with the pool, the school with the air conditioning, Temi''s voice on a folded note. The girl who had lived inside all of that.\nHere was a ceiling fan. A window. A city that did not know her name.\nShe sat with it.\nOutside, Lagos continued without pause.','\n',char(10)),1044,1,1,NULL,'2026-04-20T10:59:19.224Z','2026-04-20 10:59:19','2026-04-20 10:59:19','2026-04-20T11:10:00.000Z',1,43);
INSERT INTO "chapters" ("id","novel_id","chapter_number","title","content","word_count","is_premium","is_published","audio_url","published_at","created_at","updated_at","scheduled_release_at","part_number","season_id") VALUES(532,67,1,' New Uniform',replace('The uniform was the first problem.\nNot because it was ugly, though it was plain, a pale blue on white that had clearly been chosen by someone with no strong feelings about either color. The problem was the fit. Her mother had bought it two days before from a woman at the market who measured with her eyes and approximate confidence, and the result was a blouse that sat correctly across the shoulders but gave her too much room everywhere else, fabric that did not know her body, that moved independently of her when she walked. At Meridian her uniforms had been made by a tailor in Lekki who kept her measurements in a book and called her mother when the new term''s fabric arrived. She had never once thought about this.\nShe thought about it now, standing in front of the small mirror in her room, trying to decide if there was anything to be done.\nThere was nothing to be done. She picked up her bag.\nHer mother drove her. The school was twelve minutes away by the route that avoided the market, seventeen if you went through it. They went through it this time, which meant the car moved at the pace of the street, which moved at the pace of everything else on it, which was slow and loud and completely without urgency. Adanna sat in the passenger seat and watched a man push a cart of yam through a gap in traffic that should not have accommodated a cart of yam.\n"They are expecting you," her mother said. "I spoke to the vice principal yesterday. Her name is Mrs. Okoro."\n"Okay."\n"She said the teachers are good."\nAdanna said nothing.\n"Adanna."\n"I heard you, Mummy."\nHer mother looked at her once and then returned to the road.\nThe school appeared between a printing shop and a block of flats, announced by a blue metal gate with the name painted above it in yellow letters, the yellow slightly newer than the blue, suggesting the name had been corrected at some point in the gate''s history. A security man in a plastic chair. A concrete path beyond the gate where students were moving in both directions with the comfortable disorganization of people who knew exactly where they were going.\nShe was not one of those people.\nShe got out of the car with her bag and her new uniform and stood at the gate while her mother completed a three-point turn in the narrow street, and then the car was gone and there was just the noise and the movement and the gate and the security man looking at her with the mild curiosity of someone who had seen first days before.\nInside was louder than she had prepared herself for. At Meridian the corridors had a managed volume, not from any formal rule but from the self-regulation of girls who understood that noise was not the register of people like them. Here the corridors were full in both senses, with students and with sound, voices layered over each other, someone laughing from a window above, a teacher shouting a name from somewhere she could not locate. The classrooms she passed had their doors open, which Meridian classrooms did not.\nEverything was slightly different in scale from what she knew. The lockers smaller. The staircase narrower. The space between things compressed, as if the architect had worked from the same blueprint but with a shorter margin.\nMrs. Okoro''s office was at the end of the ground floor corridor. She was a wide woman with close-cropped hair and reading glasses pushed up on her forehead that she never once brought down to her eyes in the entire time Adanna was in her office. She looked at Adanna in the direct, assessing way of someone who did not have time for the preliminary version of anything.\n"SS2," she said. "Your records came. Your grades are good." She said this without warmth but also without suspicion, simply as fact. "You will be in SS2B. I will have someone show you around before your first class."\n"Thank you, ma."\n"Do you have any questions?"\nAdanna had many questions, none of which were the kind you asked. "No, ma."\n"Good." Mrs. Okoro wrote something on a notepad, tore it off, handed it across the desk. "Give that to your form teacher. Mr. Adebayo. Second floor, third door."\nShe stood in the corridor outside the office for a moment, the note in her hand. Around her the school moved without adjusting for her. A boy in her peripheral vision was eating something from a cellophane bag with the focused joy of someone who had been waiting for this moment since morning. Two girls passed arguing cheerfully about a debt of two hundred naira, one of them making her case with complete bodily commitment. Someone''s phone was playing Afrobeats from a bag that had not been fully zipped.\nShe understood that she was visible in the wrong way. Not the way she had been visible at Meridian, where visibility was the natural result of being known. This was the visibility of a wrong note, of a thing that did not yet speak the room''s language, and the room was not hostile about it but it was completely obvious.\nShe found the second floor. Third door. Mr. Adebayo was a lean man in a checked shirt who read the note and looked at her and looked at the note again.\n"Adanna Obi." He said it as a confirmation, not a greeting. "Okay. Find a seat."\nShe found one near the window. The girl beside her glanced at her once, not unfriendly, not particularly interested.\n"You''re new," the girl said.\n"Yes."\n"Where from?"\n"Lagos Island."\nThe girl considered this, nodded once, the way people acknowledge information they have filed away.\nBefore first period, Mr. Adebayo stopped at a desk near the front of the class and said something to a boy seated there, too low for Adanna to hear. The boy turned and looked at her with the direct, uncomplicated curiosity of someone who had not yet decided what he thought.\n"Chinedu," Mr. Adebayo said, louder now. "Show her around at break."\nThe boy nodded. He looked at Adanna one more time, not performing anything, not unkind. Just looking.\nShe looked back.\nThe first class began.','\n',char(10)),1060,0,1,NULL,'2026-04-26 12:26:26','2026-04-20 11:00:55','2026-04-26 12:26:26','2026-04-20T10:10:00.000Z',2,44);
INSERT INTO "chapters" ("id","novel_id","chapter_number","title","content","word_count","is_premium","is_published","audio_url","published_at","created_at","updated_at","scheduled_release_at","part_number","season_id") VALUES(533,67,2,'Chinedu',replace('He was waiting outside the classroom at break with the unbothered posture of someone who had agreed to a task and intended to complete it without drama.\nShe had spent the first two periods watching him without meaning to. He sat three rows ahead and one desk left, which put him in her sightline whenever she looked at the board, and she had gathered the following information without trying: he answered when called and not otherwise, his handwriting was fast and economical, he shared a textbook with the boy beside him and never once looked irritated about it, and when the teacher made a joke that was only partially funny he laughed at the part that was actually funny and left the rest alone. She did not know what to do with any of this data except that it did not match the version of this school she had been building in her head since the drive through the market.\nShe collected her bag and walked out to where he was standing.\n"Ready?" he said.\n"You don''t have to do this if you don''t want to," she said. It came out the way she had not intended, like a door held open with one foot already out of it.\nHe looked at her with the same direct uncomplicated expression he had used when Mr. Adebayo pointed at her. "I don''t do things I don''t want to do," he said. Not as a challenge. Just as information.\nShe followed him.\nHe showed her the school the way someone shows you a place they know well and have no anxiety about. The tuck shop at the back of the block, which sold meat pie and pure water and a fried doughnut he called puff puff with a confidence that suggested no other name was acceptable. The second staircase that was faster than the first if your next class was on the third floor. The staff room, the counselor''s office, the room with the one functioning computer that everyone called the ICT lab with a collective tone of optimism. He named things and moved on. He did not embellish.\n"The library?" she said.\nHe paused. "We have one."\n"I know you have one. I''m asking where it is."\nHe looked at her for a moment. "Follow."\nThe library was a room on the first floor with two ceiling fans and shelves along three walls and a table in the center surrounded by chairs with uneven legs. The books were old, some of them very old, but there were more of them than she had expected and they were organized. Someone took care of this room. She could tell by the arrangement, by the fact that the table was clean, by the feeling of deliberateness in it.\n"It''s better than it looks from the door," Chinedu said.\n"I wasn''t going to say anything."\n"You were about to."\nShe had been about to. She turned to look at the shelves instead.\nOutside again she fell into step beside him, back toward the main block. The compound at break was fully alive around them, groups assembled in the patterns groups always assembled in, the particular democratic chaos of a school that did not organize itself around a hierarchy she could read. She was aware that some people looked at her as she passed. New girl. The too-big uniform. The way she walked, which she could not adjust because she did not know what was wrong with it, only that it was marking her as something.\nChinedu appeared not to notice any of this.\n"How long have you been here?" she asked.\n"Since JSS1."\n"Do you like it?"\nHe considered this with a seriousness that surprised her. "It''s my school," he said.\nShe waited for more. More did not come.\nShe stopped walking. "That''s not an answer."\nHe stopped too and looked at her with the patient expression she was already finding difficult. "What answer were you looking for?"\nShe did not know. She started walking again.\nAt the tuck shop he bought two puff puffs and held one out to her. She looked at it. It was in his open palm, in the way you offer something without ceremony, no transaction, just a thing being shared.\nShe thought of several ways to decline and did not say any of them. She took it.\nIt was warm and slightly sweet and genuinely very good, which irritated her for reasons she could not fully explain.\n"What part of the Island?" he said.\n"Victoria Island. Near Falomo."\nHe nodded, like he was mapping this.\n"You know it?" she said.\n"I know where it is." A pause. "It is different from here."\nThe understatement was so complete she almost laughed. "Yes," she said. "It is."\n"Are you going back?"\nThe question arrived without cushion. She looked at him. He was not asking to be cruel. He was asking because he wanted to know, with the simple directness of someone who had never learned to dress questions in social fabric before releasing them.\n"I don''t know," she said.\nHe nodded. Accepted this. Ate the last of his puff puff.\n"You ask a lot of direct questions," she said.\n"Is that bad?"\n"It is unusual."\n"Unusual for who?"\nShe opened her mouth and closed it. The answer was: for the people I know. But he was not the people she knew, and the sentence, applied here, landed badly even in her own head.\nHe watched her not answer with that same curious patience, like a person observing a process that interested them, and the quality of it, the way he looked at her without judgment but also without any desire to make her comfortable, was the most disorienting thing about him.\nShe had been looked at her whole life. Assessed, admired, measured. She knew all the registers of being seen.\nThis was not any of them.\n"Break is almost finished," she said.\n"Yes," he agreed, and they walked back, and he did not fill the silence and she did not fill it either, and when they reached the classroom door he stopped and said: "I go that way," gesturing down the corridor.\n"Thank you," she said, and meant it less warmly than the words suggested.\n"Sure," he said, and walked away without looking back, like a person who had done a thing and was finished with it.\nShe stood at the door for one moment.\nShe had expected many things from this school. Chinedu was not any of them.\nShe went inside.','\n',char(10)),1090,0,1,NULL,'2026-04-26 12:26:38','2026-04-20 11:02:02','2026-04-26 12:26:38','2026-04-20T10:10:00.000Z',2,44);
INSERT INTO "chapters" ("id","novel_id","chapter_number","title","content","word_count","is_premium","is_published","audio_url","published_at","created_at","updated_at","scheduled_release_at","part_number","season_id") VALUES(534,67,3,'Proximity',replace('The road home was forty minutes on foot.\nShe discovered this on the third day when her mother called to say the car was with the mechanic and there was no money for keke every day so she should learn the road because she would be walking it. Her mother said this in the careful voice she now used for sentences that contained the word money, which was a voice that did not invite response.\nAdanna stood at the school gate with her bag and looked at the street.\nShe had walked for five minutes, past the printing shop and a row of provision stores and a woman selling pepper from a wide enamel tray, before she heard footsteps that matched her pace and then Chinedu was beside her, bag over one shoulder, completely unsurprised, as if they had arranged this.\n"You walk?" she said.\n"Every day," he said.\nShe waited for him to offer to show her the way or ask if she knew the road. He did neither. He simply walked, at her pace, looking ahead.\nShe kept her eyes forward too and let the road come.\nIt was not a quiet road. Nothing in this part of Lagos was quiet in the late afternoon, the heat settling into the concrete and everything on the street pushing against it, the generator noise and the radio noise and the particular percussion of a busy area folding the day into evening. She passed a compound where a woman was frying akara at the entrance, the oil sound and the smell arriving together. She passed two boys her age conducting a very serious argument about a football match with their whole bodies. She passed a tailor''s shop with fabrics hanging in the doorway, ankara in orange and green catching the light.\nShe was looking at everything and she knew she was looking at everything and she knew Chinedu knew she was looking at everything.\n"First time walking this way?" he said.\n"I walked it yesterday."\n"You looked at everything yesterday too."\nShe turned to look at him. He was not smiling exactly but there was something around his eyes. "Is that strange?" she said.\n"No," he said. "Most people stop looking after a while. The road becomes just a road."\nShe considered this. "Does it? For you?"\nHe thought about it in the way she was learning he thought about things, actually and without performance. "Sometimes," he said. "Not always."\nThey walked.\nThe textbook situation declared itself on Thursday. Mr. Fashola distributed the new literature texts and came up four copies short, which he announced without apology as a temporary situation and resolved by pairing students. He paired Adanna with Chinedu in the way of a man who had already been pairing them in his head since the new girl arrived and saw no reason to be subtle about it.\nThe textbook lived with Chinedu because he had a shelf at home, which he told her in the straightforward way he told her most things. He brought it each morning. In class they shared the desk''s surface, the book centered between them, and this created a proximity that had not existed before, his arm on the desk alongside hers when he turned the pages, his handwriting in the margin that she read without meaning to.\nHis notes were not what she expected. Not transcription. He wrote questions to himself in the margin. Why does Soyinka do this here. What is the thing he is not saying. Observations, not records. She read one on Tuesday and looked at him.\n"You write in borrowed books?" she said.\n"It''s not borrowed. We share it."\n"That is the definition of borrowed."\n"Borrowed means it goes back to the original owner," he said. "This one belongs to both of us now."\nShe wanted to argue the logic and could not find the correct entry point.\nShe started writing her own notes in the margin. Small ones, to the right of his, with a deliberate gap between their handwriting so the book could tell them apart. He read her notes the same way she read his, she could see him doing it from the corner of her eye, and he never commented, which was correct but also somehow unsatisfying.\nOne afternoon he tapped the margin where she had written a question about a passage. "This one," he said.\n"What about it?"\n"I was thinking the same thing." He paused. "Three chapters back."\nShe looked at where his finger rested. Then at him. "Why didn''t you write it there?"\n"I wasn''t sure enough."\n"So you waited."\n"Yes."\nShe looked at the margin note. Her handwriting, her uncertainty made visible in ink. She had written it without thinking, which was something she did not usually do. The habit at Meridian had been to present conclusions, not questions. Questions implied that the answer was missing, and missing things were not the register of girls like her.\n"It''s okay to not be sure," he said. Not as advice. As a statement of his own operating principle.\nShe turned the page. "I know that," she said.\nShe did not know that. She was beginning to understand that she did not know that.\nThe road home on Friday she asked him a question she had been turning over since Tuesday. "The way you asked me if I was going back. On the second day."\nHe looked at her. "Yes."\n"Why did you want to know?"\nHe walked for a moment before answering. "Because it changes how you move," he said. "If you think somewhere is temporary you don''t settle into it. You stay at the surface." A pause. "I wanted to know which one you were doing."\nShe looked at the road ahead. The street narrowed here, a keke squeezing past a parked truck on the left, a food cart on the right. The city compressing and releasing, breathing in its Lagos way.\n"Which one am I doing?" she said.\n"I''m still watching," he said.\nShe did not answer. She did not have one that was ready.\nThey reached the junction where their roads separated and he said later and she said later and she walked the remaining eight minutes alone, feeling the question he had handed back to her the way you feel a weight after you''ve been carrying it long enough to forget it''s there.\nShe turned it over all evening.\nShe did not reach an answer.','\n',char(10)),1076,0,1,NULL,'2026-04-26 12:26:50','2026-04-20 11:03:46','2026-04-26 12:26:50','2026-04-20T10:10:00.000Z',2,44);
INSERT INTO "chapters" ("id","novel_id","chapter_number","title","content","word_count","is_premium","is_published","audio_url","published_at","created_at","updated_at","scheduled_release_at","part_number","season_id") VALUES(535,67,4,'The Performance Fails',replace('It started with the literature class and a question that should have been simple.\nMr. Fashola was working through the second act of the play, moving between desks with the loose energy of a teacher who genuinely liked his subject, asking questions in the way of someone who wanted thinking rather than answers. He stopped at the front third of the class and asked what the playwright was doing with silence in the scene they had read the night before.\nThree hands went up slowly, uncertainly.\nAdanna knew the answer. She had known it since the first reading, had in fact written a note about it in the margin of the shared textbook three days ago. She also knew something else, which was that she was tired of sitting in this class like someone waiting to be noticed. At Meridian she had been the girl teachers referenced when making a point, the one whose answer arrived before the question was fully formed. She had been sitting in SS2B for two weeks now, correct and contained, and it was beginning to feel like disappearing.\nShe put her hand up.\nMr. Fashola nodded at her.\nShe gave the answer. It was a good answer, complete and precise, the kind that did not leave gaps for follow-up questions because all the follow-up questions were already inside it. At Meridian it would have earned a particular quality of pause from the teacher, a brief silence that acknowledged that something worth hearing had just been said. She knew that pause. She had been collecting it for years.\nMr. Fashola nodded again, once. "Good," he said, and moved to the next question.\nGood. One word. And then the class continued.\nShe sat with this. Something in her chest had prepared itself for the pause and received the word good instead, and the adjustment took a moment.\nThe second thing happened at lunch.\nShe had been eating alone most days at a table near the back wall of the canteen, which she had chosen for its position and its relative quiet. That day Rolake and Gbemi, two girls from SS2A who had been running a slow orbit around her since the first week, settled across from her with their trays. She had observed them already. They were the type who collected interesting things, and she had apparently become interesting.\nRolake asked where she had gone to school before.\nShe said Meridian Academy.\nBoth girls received this with the blank politeness of people who have been given information in a currency they do not use. They knew the name the way you know the name of a place you have never needed to go. It registered and produced nothing.\n"It''s a private school," she said. "On the Island."\n"Oh," Gbemi said, with the tone of someone completing a transaction. "Is it nice?"\nShe looked at Gbemi. Nice. The question sat there with its complete innocence and its complete inadequacy, and she understood in that moment that the entire architecture she had been standing on for three years, the school, the blazer, the table under the overhang, the particular register of being the girl whose name meant something, all of it was a language that meant nothing here. Not negatively. Not with hostility. It simply did not translate. The school had its own language, its own hierarchies, its own centers of gravity, and she was not in any of them and could not purchase entry with the currency she had arrived holding.\n"Yes," she said. "It was nice."\nThey ate lunch and talked about other things and the girls were perfectly pleasant and she participated with the correct surface responses, and it was the most hollow thirty minutes she had spent since arriving.\nIn the afternoon she made the third mistake.\nIt was a small thing. The kind of small thing that is in fact not small at all. A boy in the corridor, moving too fast, caught her bag with his elbow and kept walking with only a half-glance back. At Meridian this would have produced an apology of a particular quality, the specific social adjustment of someone who knew that certain people required acknowledgment. She had received this her whole life and had never thought about it.\nShe said, to the boy''s retreating back, in a voice that came from the wrong place: "Excuse me."\nHe turned. Looked at her with calm, uncomplicated confusion.\n"You hit my bag," she said.\nThe boy looked at her. Looked at the bag. Looked at the corridor around them, which was full of people moving, the ordinary contact of a busy school going about its afternoon. His face said, quietly and without malice: this is just the corridor.\nHe said: "Sorry na," with the easy brevity of someone offering what was asked and finding the whole thing slightly puzzling, and walked on.\nTwo girls nearby had watched this. They did not laugh. They returned to their conversation with the practiced generosity of people who had decided not to make something of it. This was somehow worse than if they had laughed.\nShe walked to class.\nChinedu was at his desk when she came in. He had been somewhere else at lunch, she did not know where, and she was aware of having wanted him there and being annoyed at wanting him there. He looked at her when she sat down, the way he always looked, that direct unhurried attention.\nShe opened her notebook.\n"How was lunch?" he said.\n"Fine."\nHe looked at her for one more moment and then opened his own notebook, and she felt the full weight of what that look contained, which was that he had seen the corridor. He had been at the staircase end, she realized now. He had seen the boy, the bag, the two-word apology, the girls who had been kind enough not to laugh.\nHe said nothing about it. He did not offer her sympathy or rescue or a gentle reframing of what had happened.\nHe simply did not laugh.\nAnd she sat with the particular indignity of being witnessed without being rescued, which was a thing she had never experienced before and did not have a name for yet.\nThe class began. She wrote her notes and the words went down correctly but somewhere in the second period she stopped performing even the note-taking and simply let the class happen around her without managing her participation in it. She did not raise her hand. She did not position herself. She sat and listened and let the lesson reach her at whatever distance it chose.\nThis was not defeat. It was something else. Something without a name yet that felt like the first honest thing she had done all day.\nAfter school she went to the library. She did not plan to. Her feet went there and she followed them.\nChinedu was at the table with a book that was not the literature text, something thicker, and he was writing margin notes in the way he wrote them, actual questions to himself rather than records of what the page said. He looked up when she came in.\nShe sat across from him. Not beside him. Across.\nShe opened her literature text and read. He returned to his book and his pen moved.\nHe did not ask about the corridor. He did not offer anything to cover the afternoon or smooth it into something easier to carry. He simply read, and she read, and the library held them both in its particular quiet, the ceiling fans turning, the old books on their careful shelves.\nShe had come here, she understood slowly, because it was the one place in the school that charged no admission. That asked nothing of her except that she sit and be present. She had come because he was here and he was not looking at her in any of the ways she had been looked at today. Not with the half-attention of Mr. Fashola. Not with the polite blankness of the girls at lunch. Not with the mild confusion of the boy in the corridor.\nHe was just reading.\nShe read too. Outside the window the afternoon went from white to gold. The fan turned. The pages turned. Neither of them said anything, and it was the least performed thing that had happened to her since she arrived.','\n',char(10)),1398,1,1,NULL,'2026-04-26 12:27:10','2026-04-20 11:04:49','2026-04-26 12:27:10','2026-04-20T09:10:00.000Z',2,44);
INSERT INTO "chapters" ("id","novel_id","chapter_number","title","content","word_count","is_premium","is_published","audio_url","published_at","created_at","updated_at","scheduled_release_at","part_number","season_id") VALUES(536,67,5,' The First Real Thing',replace('It started with Wole Soyinka and escalated from there.\nThey were on the road home, Tuesday, the week after the corridor incident, and she had been carrying the shared textbook because Chinedu had a bag strap that had been threatening to give way since Monday and she had said, without thinking about it, that she would carry it. This was the kind of small transaction that had become ordinary between them in a way she had not decided to allow but had apparently allowed.\nShe was reading a passage as she walked, which was a habit she had developed at Meridian on the drive home in the back seat of the Range Rover, the smooth ride making it possible. Walking and reading was not the same but she was managing.\n"You''re going to miss the gutter," Chinedu said.\nShe stepped over the gutter without looking up.\nHe made a sound that was almost a laugh.\nShe read another line. Stopped walking. "He does it again here."\n"Does what?"\n"This thing where the character speaks and the stage direction contradicts what he just said. He did it in the second act too. The man says one thing and the playwright tells you to believe another." She looked up. "It''s deliberate."\nChinedu looked at the page from beside her. He was close enough that she could see where his finger was tracking, two lines above where she had stopped. "I read that as the character not knowing himself," he said. "Not the playwright commenting."\n"They''re the same thing."\n"They''re not the same thing."\nShe turned to face him properly. "If the playwright writes a character who doesn''t know himself, the playwright is the one making that observation. The character doesn''t know. The playwright does. They cannot be separated."\n"The character exists outside the playwright once the play is performed," Chinedu said, with the calm of someone who had thought about this before and was not threatened by disagreement. "What the character does on stage is its own thing. The intention and the act are different."\n"That is not how authorship works."\n"That is exactly how authorship works. Have you seen a play performed?"\n"Of course I''ve seen a play performed."\n"Did the performance match exactly what you imagined when you read it?"\nShe opened her mouth. Closed it. "That''s not the point."\n"It is completely the point."\nThey had stopped walking. She was holding the textbook open at the page and he was looking at her with the expression she had come to know, steady and interested, except that now it had a different quality to it, a slight forward lean, the look of someone who was not just observing but actually in the thing.\n"The text is the authority," she said, but with slightly less certainty than she had begun with.\n"The text is a starting point," he said. "Not the same as authority."\n"You''re saying a bad production can override the writer''s intention."\n"I''m saying the writer''s intention is one voice in a conversation. Not the last word."\nShe looked at the page. She looked at him. Something about the argument had shifted in the last sixty seconds from a disagreement about Soyinka to something she could not name, something that required her to hold two ideas at once and test them against each other honestly, and she was doing it, which was the part she had not planned for.\n"That means the interpretation is unstable," she said. "Anyone can decide the text means anything."\n"No. It means the meaning is made in the exchange. Between the text and the person reading it." He paused. "Or watching it."\nShe stood on the road in the late afternoon light and felt the argument complete itself inside her head and arrive at a place that was not quite his position and not quite hers but somewhere that had been made by the two of them pushing against each other. She had not thought about Soyinka this way before. She had answered questions about Soyinka correctly for three years without once thinking about him this way.\nShe laughed.\nIt came out before she knew it was coming, not a polite laugh or a social laugh but the real kind, sudden and unguarded, and it was out in the air between them before she could measure it or decide whether to release it. She laughed because the argument was genuinely good and because she had lost a part of it and because losing a part of it had given her something she did not have before, and all of that arrived at once as laughter.\nChinedu looked at her. For one moment, the first time she had seen this, he looked surprised. Like she had done something he had not predicted.\nThen he smiled, and it was not the careful expression he usually wore, the observant patience, but something that came from the same unguarded place as her laugh. Quick and real and briefly, completely undefended.\nShe saw it.\nShe felt the quality of the moment, the way you feel a change in temperature, and what she felt was that something had passed between them without the usual layer over it, without the glass she had been maintaining since the first day in his school, and the absence of the glass was both lighter than she expected and more frightening.\nShe looked back at the road. Started walking.\n"The interpretation still has to be grounded in the text," she said. Her voice was slightly different, slightly more careful, because she was rebuilding something with it.\nHe fell into step beside her. "Agreed," he said.\n"So I wasn''t entirely wrong."\n"You weren''t entirely wrong," he said.\nShe nodded, as if this had been the point all along. As if the laugh had not happened. As if the moment before the laugh had not happened either.\nHe did not call her back to it. He let her rebuild without comment, which was either kindness or its own kind of understanding, and she was not ready to decide which.\nThey walked. The road did its Lagos thing around them, loud and layered and ongoing. A woman called a name from a window above. A radio played something she half recognized.\nAt the junction she said later without looking at him.\nHe said later and went his way.\nShe walked the last eight minutes alone, faster than usual, and when she reached the compound gate she stopped and stood for a moment outside it.\nThe laugh was still there. She could feel its shape, the specific texture of a thing that had escaped her before she could decide whether to let it go. She did not laugh like that with people she was maintaining distance from. That was the problem. That was the specific problem.\nShe had been careful for five weeks. Not from dishonesty. From the correct understanding that proximity was a direction and she had not decided to travel in it.\nThe laugh was a direction.\nShe opened the gate and went inside.\nUpstairs, she set the textbook on her desk and looked at it for a moment. His questions in the margin on the left. Her questions on the right. The small gap between them that she had maintained with deliberate care.\nShe sat down and opened to a new page and began her notes for tomorrow.\nShe wrote in the center of the margin.\nShe noticed this and moved her pen back to the right side.\nShe sat with the page for a long time before she wrote anything at all.','\n',char(10)),1267,1,1,NULL,'2026-04-26 12:27:24','2026-04-20 11:05:54','2026-04-26 12:27:24','2026-04-20T10:10:00.000Z',2,44);
INSERT INTO "chapters" ("id","novel_id","chapter_number","title","content","word_count","is_premium","is_published","audio_url","published_at","created_at","updated_at","scheduled_release_at","part_number","season_id") VALUES(537,67,6,'His World',replace('She did not plan to see where he lived. The rain planned it for her.\nIt came the way Lagos rain comes in the middle of the school term, without negotiation, arriving in the last period as a sound on the roof that started as a suggestion and became, within four minutes, a declaration. By dismissal the compound was running water and the street beyond the gate was a different kind of road from the one they walked each afternoon, brown and moving and completely indifferent to the needs of people who had forty minutes to cover on foot.\nShe was standing under the overhang by the gate with her bag held against her chest when Chinedu appeared beside her.\n"It won''t stop," he said, looking at the sky with the authority of someone who had read this particular sky many times.\n"I''ll wait."\n"It won''t stop before dark."\nShe looked at the street. A keke pushed through, its passengers pressed together under the canopy, water sheeting off the sides. A woman walked past with a plastic basin on her head repurposed as shelter, her wrapper soaked from the knee down, moving with the complete pragmatic dignity of a person who had decided that rain was weather and not a crisis.\n"My house is ten minutes," Chinedu said. "You can wait it out there."\nShe looked at the rain. She looked at him. He had made the offer the same way he made most things, without pressure or performance, as a simple option on a menu of options, take it or don''t.\n"Ten minutes in this," she said.\nHe reached into his bag and produced a wide rubber covering, the kind market traders used, folded into a square. He shook it open. It was large enough for two people if they did not mind being close.\nThey did not discuss this. They went.\nThe ten minutes in the rain were not ten minutes. They were closer to fifteen, through streets she had not taken before, past a compound where a man was pulling a motorcycle under an awning with the focused urgency of someone protecting something that mattered. The rubber covering kept most of the water off. She was aware of the closeness required to stay under it, the adjustment of pace and direction two people make when they are sharing a single shelter, and she managed this by keeping her eyes on the road.\nThe compound was on a street with three other compounds, mid-terraced, a low wall in front with a gate that opened easily. His father''s okada was just inside the gate, covered with a tarp weighted at the corners with stones. Someone had done this before the rain came, which meant someone had read the sky this morning.\nInside, the sitting room arrived before she was ready for it.\nShe did not know what she had been expecting. Something sparse, perhaps, from the logic she had been using without examining it, the calculus she had been doing with his okada-rider father and his seamstress mother and the way he had once said my house has a shelf as if this were a notable feature. She had built a room from these details and it was not this room.\nThe room was full of fabric.\nNot cluttered. Full, which was different. Bolts of ankara and aso-oke arranged along the far wall in a column that reached the ceiling, organized by color in a way that was clearly intentional, the warm tones together, the cool tones together, the patterns that defied category in their own section at the end. A sewing machine sat against the window with a half-finished garment on it, pinned at the shoulder, the pins in a line so straight they looked measured. A table along the side wall held spools of thread in colors that corresponded to the fabrics, and above this a hand-drawn chart with measurements and dates and a client column in handwriting that was not Chinedu''s.\nThe room had the quality of a place where serious work was done. It was organized the way the library at school was organized, by someone who understood their materials and respected them.\n"My mother is at a fitting," Chinedu said. "My father won''t be back until evening."\nHe put his bag down and went to the kitchen. She stood in the sitting room.\nShe looked at the fabrics. She looked at the sewing machine, at the pinned garment, at the thread spools. She looked at the chart on the wall and read the names in the client column without meaning to. Seven names. Three marked delivered. Four with dates still ahead.\nA shelf beside the door held books and other things, a small radio, a Bible with a cracked spine, a folded newspaper, and on the top shelf two trophies, the small kind from school competitions, their gold paint slightly worn. She stepped closer. One said Mathematics, SS1. One said Essay Competition, JSS3. Both had Chinedu Okafor on the plate.\nShe had not known his last name until this moment.\nHe came back with two cups of Milo, handed her one. She took it without thinking.\n"You won these," she said.\nHe looked at the shelf. "Yes."\n"You didn''t say you were good at mathematics."\n"You didn''t ask."\nShe turned from the shelf. He was watching her look at his house with the same patient attention he brought to everything, except that here, in this room, there was something else in it, something she recognized after a moment as protectiveness. Not defensiveness. Protectiveness, the way you stand slightly differently in a space that matters to you.\nShe looked at the fabric wall again. "Your mother does all of this herself?"\n"My sister helps on Saturdays. When there is plenty work."\n"How long has she been sewing?"\n"Before I was born." He sat in the chair near the sewing machine with the ease of someone settling into a place that knew him. "She learned from her own mother. My grandmother still sews. Her eyes are not good now but she still cuts."\nAdanna sat on the low couch across from him. Outside the rain continued. The room held them inside its warmth and its bolts of color and its evidence of a life built by careful hands over a long time.\nShe thought about a word she had been using privately since she arrived in Mushin, the word ordinary, the way she had been applying it to this school and this neighborhood and by implication to Chinedu himself. A container word. A word that meant: smaller than what I had.\nShe looked at the fabric wall. She looked at the trophies. She looked at the chart with seven client names and the thread spools arranged by color and the sewing machine with the pinned garment waiting to be finished.\nNothing in this room was small. It had just been built from different materials than the rooms she knew.\n"Thank you for the Milo," she said.\n"It''s okay."\nThe rain did not stop for another hour. They sat with the textbook between them and worked through the next passage in the literature text, and the argument was quieter this time, more like thinking aloud than sparring, and at one point his mother came in from the back and greeted Adanna with a warmth so uncomplicated that Adanna said good evening three times before she realized she had said it twice already.\nHis mother''s hands, she noticed, had the particular quality of hands that worked constantly, careful and strong, with a scar along the left thumb from a blade or a pin, and she moved through the room with the confidence of someone in complete possession of her space.\nAdanna watched her adjust the garment on the sewing machine without disrupting their reading, humming something low under the rain sound.\nShe had told herself a story about Chinedu. About what his life looked like, what it meant, what category it belonged to. She had used that story to manage the distance between them.\nThe story had not survived this room.\nShe did not know yet what to put in its place. But she felt the old version loosening, the way fabric loosens at a seam when the thread has been pulled from the wrong end, and she sat with the textbook open and the rain on the roof and Chinedu''s mother humming in the background and understood that something she had been holding had shifted, and she had not given it permission to.','\n',char(10)),1426,1,1,NULL,'2026-04-26 12:27:39','2026-04-20 11:07:18','2026-04-26 12:27:39','2026-04-20T10:10:00.000Z',2,44);
INSERT INTO "chapters" ("id","novel_id","chapter_number","title","content","word_count","is_premium","is_published","audio_url","published_at","created_at","updated_at","scheduled_release_at","part_number","season_id") VALUES(538,67,7,' Old Number',replace('Tokunbo''s message arrived in two parts on a Friday evening.\nThe first was just her name on the screen, which Adanna had not seen there since October. The second, arriving thirty seconds later, was a voice note she played with her thumb hovering over the stop button the whole time. Tokunbo''s voice, warm and familiar and carrying the register of someone who had rehearsed: Chidera''s birthday, Island Club rooftop, Saturday evening, everyone would be there, it would be good to see her, she had been meaning to call.\nShe put the phone face down.\nShe picked it up and replied: I''ll try to come.\nShe did not examine this decision for long. Examining it would mean admitting how much she still wanted it to mean something, and she was not ready to be that honest about the Island yet.\nShe spent Saturday morning with the cream set from the boutique in VI. Her mother helped with her hair without asking questions, which was its own kind of care. In the small mirror she looked correct, looked like the version of herself that understood these gatherings, and she took one long look and went.\nThe Island received her the way it always had, as if she had never left. Roads wider. Compounds set back from the street. The quality of the light different, arriving in longer stretches between the buildings. She took a keke from the bridge and sat with her bag on her lap and let the Island reassemble itself around her, and what surprised her was that it felt like arriving rather than returning. A place she was visiting.\nShe had not expected that distinction.\nThe rooftop was warm and arranged perfectly. Chidera''s mother had done the decorations, which meant everything was expensive and tasteful and color-coordinated in a way that left no room for accident. The music was right. The food table was right. Forty people moving through the space with the ease of people who had grown up speaking the same language and never needed another.\nTokunbo found her immediately and the hug was genuine, genuinely warm, the uncomplicated warmth of someone who had actually missed her. Adanna received it and did not dismiss it. She had decided on the keke that she was going to be honest about this evening, at least with herself. If there was good in it she would let it be good.\nThere was good in it.\nShe talked to people she had not spoken to in months and found some of those conversations real, carrying actual warmth and actual history worth something. A girl from her old chemistry class said something funny about Mrs. Adeyemi and she laughed, and the laugh was not performed. She stood at the railing and let the Island spread below in its nighttime arrangement and felt, genuinely, a pull toward it. This had been her world. She had been happy in it. Both things were allowed to be true at once.\nShe was in the middle of a real conversation with Tokunbo when Tokunbo said something she had not prepared for.\n"You seem different," Tokunbo said.\n"Different how?"\nTokunbo tilted her head, trying to locate it. "Like you''re not trying."\nAdanna went still.\n"That''s a compliment," Tokunbo said quickly. "It''s actually nice. You were always a bit." She stopped, laughing slightly at herself. "You made everything feel like an exam we were all taking."\nThe sentence arrived and sat there between them.\nAdanna looked at Tokunbo''s face, which was open and slightly uncertain and without any malice in it. This was not cruelty. This was Tokunbo saying, in the direct way Tokunbo had always said difficult things, that the girl at this party right now was easier to be near than the girl who used to come to parties like this one.\nAnd the thing was, Adanna knew exactly which girl she meant.\nThe girl who was not trying was not the Island girl. The Island girl had tried continuously, had run the full performance at capacity every single day. The girl who was not trying was the one learning to exist without the performance, on a road in Mushin, over a shared textbook, in a room full of her mother''s fabric. That girl had come to this party inside the cream set and the correct hair and Tokunbo, who had known her for three years, had recognized her immediately.\nShe had not left that girl behind in Mushin.\nShe had brought herself with her.\n"I''ll take that," Adanna said.\nShe stayed another hour. She said happy birthday to Chidera and meant it. She found Tokunbo at the end of the evening and hugged her again, and this time the hug carried something more precise, a gratitude she did not try to explain.\nOn the keke back to the bridge she sat with what the evening had given her, which was not what she had gone looking for. She had dressed for a test and found instead an answer she had not thought to ask for: the self she had been building in Mushin was not a lesser version of the old one. It was simply the real one. It had walked onto the Island rooftop and Tokunbo had seen it before Adanna announced it.\nThe bridge. Below it the lagoon, wide and dark and moving.\nShe crossed over. Mushin rose to meet her on the other side, loud and layered and completely itself.\nShe was not hollow. She had never been hollow. She was in the middle of becoming something, and tonight was evidence that it was working.','\n',char(10)),933,1,1,NULL,'2026-04-26 12:27:52','2026-04-20 11:08:51','2026-04-26 12:27:52',NULL,2,44);
INSERT INTO "chapters" ("id","novel_id","chapter_number","title","content","word_count","is_premium","is_published","audio_url","published_at","created_at","updated_at","scheduled_release_at","part_number","season_id") VALUES(539,67,8,'The Space He Leaves',replace('The textbook was on her desk when she arrived Monday morning.\nChinedu had placed it at the corner nearest her and was already in his seat with his notebook open, pen moving, and she stood by the desk and looked at the book and understood, without needing to examine it, that something had changed over the weekend. She sat down. She put the book in her bag. She opened her notes and did not look across at him.\nThe morning passed in its established shape. He answered when called. His handwriting moved fast across the page the way it always did. At one point Mr. Fashola asked about the third act and Chinedu answered in the precise, undecorated way he answered things, two words where another person would use six, and two people nodded and the class moved on. All of it was correct. All of it was exactly as it had always been.\nWhat was different had no visible location.\nAt break she went to the library and sat in the chair with the uneven leg and did not look at the door. She read the same page four times and on the fourth gave up and looked at the ceiling fan turning slowly above the table. She thought about the last several weeks, which had been warm and argumentative and alive with the thing the two of them made when they were both fully present. She had not named that thing. She had been careful not to name it. She was beginning to understand that carefulness had a cost she had not calculated.\nOn the road home he was beside her, same as always. They talked about a mathematics problem from the afternoon, a proof he had solved two ways and was working toward a third. She asked questions and he answered them and the conversation was correct and had a beginning and an end and no moment in between where it left the stated subject and arrived somewhere neither of them had aimed for. She had not known she was relying on those moments until they stopped arriving.\nAt the junction he said later. She said later. He went his way.\nWhat she had not told him was that she had heard something at the tuck shop on Friday. She had been around the corner, not visible, when Emeka, who sat behind Chinedu and had known him since primary school and carried the easy authority of that long history, said something in a low voice that was not meant to carry.\n"That Island girl. She''s going back eventually. You know that, right?"\nShe had not heard Chinedu''s response. She had moved away before it came.\nShe had thought about it across the whole weekend. Not the words, which were not new information. The fact of someone saying them to Chinedu''s face. And what it would mean to be him, to have watched her arrive with her performed distance and her old-life currency and her careful glass, and to genuinely not know, after eleven weeks, which version of herself she was going to choose.\nShe had given him no clear reason to know.\nShe had been so occupied with reading the change in him that she had not stopped to think about what he was managing. He had never needed anyone''s assessment to determine how he moved. But Emeka''s question was not an assessment of Chinedu. It was a question about her, and it touched the one real uncertainty that even Chinedu, with all his steadiness, could not answer from the outside.\nShe was the only one who could answer it. She had been keeping the answer somewhere private, drawing on the warmth of his presence as if it came without conditions. It was not without conditions. He had simply been too careful to say so.\nTuesday she arrived before the first bell. He was already there, alone in the classroom, working through a margin note, and the morning light was coming through the window at the angle that reached his desk. She put her bag down. She sat.\n"The question you asked me in the third week," she said. "About whether I was settling in or staying at the surface."\nHe looked up from the notebook.\n"I have been staying at the surface," she said. "Not because this isn''t real. Because I was afraid of what it would mean if it was."\nHe was quiet for a moment. Outside in the corridor the school was beginning to assemble, bags dropped, voices layering over each other, the morning building its usual noise.\n"I know," he said.\n"I know you know," she said. "I wanted to say it to your face."\nHe looked at her for a long moment and the full version of his attention came back into the room, not the reduced version of the past week, but the one she had been learning since the first day he showed her the school, the one that asked real questions and waited for real answers without filling the silence with easier things.\n"Okay," he said. Quietly. Like a door opening rather than closing.\nHe returned to his notes. She opened her own. When the other students began to come in and Mr. Adebayo arrived and told them to open to page forty-three, Chinedu slid the textbook to the center of the desk without being asked.\nShe moved her notebook to make room.\nThe margin gap was still there, his handwriting on the left, hers on the right. But for the first time since she had established it, it did not feel like a boundary she was maintaining. It felt like space between two people who were, slowly and without announcement, choosing to move across it.','\n',char(10)),957,1,1,NULL,'2026-04-26 12:28:12','2026-04-20 11:09:57','2026-04-26 12:28:12','2026-04-20T08:15:00.000Z',2,44);
INSERT INTO "chapters" ("id","novel_id","chapter_number","title","content","word_count","is_premium","is_published","audio_url","published_at","created_at","updated_at","scheduled_release_at","part_number","season_id") VALUES(540,67,9,' Grief, Finally',replace('It was the uniform that did it.\nShe had washed it herself on Friday evening because her mother was at a catering job that ran late and the uniform needed to be ready for Monday and this was simply the reality of how things worked now. She washed it in the bucket the way her mother had shown her, working the collar and the cuffs where the fabric held the week, and she hung it on the line in the yard in the last of the evening light.\nSaturday morning she brought it in.\nShe was unpegging it from the line, the pale blue cotton still slightly cool from the night air, when she looked at it. Really looked at it. The fabric that did not know her body, that she had stopped noticing because the body learns to stop noticing things it cannot change. The small repair her mother had made to the left cuff with a thread that was almost the right color but not exactly. The way the collar had softened from washing, losing the stiffness it had arrived with.\nShe had worn this uniform for eleven weeks.\nShe stood in the yard with the uniform in her hands and felt something arrive in her chest that was different from all the other things that had arrived there since October. Not the sharp specific pain of Temi''s story going up, or the hollow feeling of the Island Club rooftop, or the slow ache of four days without Chinedu''s full attention. Those had been pains with addresses, pains she could locate and name.\nThis had no address. This was older than all of it.\nShe sat down on the low concrete step at the yard''s edge, the uniform across her lap, and the thing that arrived was not dramatic, she did not sob, she did not make any sound at all for a long time. It was more like a structure giving way. The way a building does not always fall loudly. Sometimes the internal load-bearing things simply stop holding and the building comes down into itself, quietly, with a kind of dignity.\nShe let it come.\nShe thought about the pool at the old compound, decorative and perfectly still in the morning light, and how she had looked at it the day they left and thought it looked like something that would always be there. She let herself feel how much she had loved that light.\nShe thought about Emmanuel and his particular quality of silence, which had been a professional silence, the discretion of a man paid to be invisible, and how she had never once said good morning to him in three years. She had never thought about him as a person with a morning.\nShe thought about the library at Meridian, the new books with their unbroken spines, and how she had moved through that room with the complete ease of someone who believed that rooms like that were simply part of what life was.\nShe thought about Sochi throwing her head back laughing on the pool terrace, braids catching the light, and how that image still carried warmth even now even after everything, because it had been real, the warmth had been real even if the loyalty had not been and the two things could both be true at once.\nShe thought about the girl who had stood at the top of the corridor with her blazer hanging off one shoulder the way Vice Principal Chukwu specifically hated. The girl who had known which table to sit at and which register opened rooms and how to enter a space so that the space reorganized itself around her. The girl who had never once in her sixteen years been made to feel that a room was not hers.\nShe sat with that girl for a long time.\nShe sat with everything that girl had been given and everything she had not known she was given and everything she had not known to be grateful for because gratitude requires awareness of the alternative and the alternative had not been visible from where she stood.\nShe sat with the cruelty that girl had not known was cruelty, the particular damage of someone operating from an unexamined height, the way she had made the junior girl find another table, the way she had received Temi''s small confidences and Sochi''s loyalty and Emmanuel''s invisible labor and her father''s money and her mother''s management and all of it, all of it, and had moved through it with the breezy unconsciousness of someone who had never been asked to notice.\nShe was not that girl anymore. She understood this completely, sitting on the step with the uniform in her hands, for the first time without the pain of it overriding the understanding. She was not that girl and she could not go back and the going back, even if it were possible, would mean returning to the not-knowing, and she did not want to not-know again. She did not want to be the girl who did not say good morning to Emmanuel. She did not want to be the girl who could not see the value in a room because it had been built from materials she had not learned to read.\nBut she had loved that girl. That was the thing she had not allowed herself yet, the thing that had been waiting under all the other things. She had loved her. The confidence and the clean handwriting and the way she could walk into a room and simply be. There had been real things inside her, real generosity, real sharpness, real warmth, and they had been wrapped in a life that taught her those things had a price tag, that they were earned by proximity to the right address and the right table and the right friends.\nThey did not have a price tag. She knew that now. She had learned it on a road in Mushin, in a library with uneven chairs, over a shared textbook with margin notes growing on both sides.\nShe let herself feel the love for the old girl. She let herself grieve her.\nShe sat on the step and the morning moved around her, the compound waking up, the neighbor''s radio through the wall, a child on the street saying something with great urgency that was almost certainly not urgent. Lagos, doing what it always did, which was continue without waiting.\nHer mother came out through the back door with a bucket she was taking to the tap, and stopped.\nShe looked at Adanna on the step. Adanna looked back. The moment held itself between them, the bucket in her mother''s hand, the uniform across Adanna''s lap, the morning light coming over the compound wall at an angle that reached both of them.\nHer mother put the bucket down. She sat on the step, not beside Adanna but with a small space between them, because her mother was not the type to collapse a distance without permission. She sat with her back against the wall and her hands in her lap and looked at the compound yard for a long time.\n"I had a dress," she said.\nAdanna waited.\n"Aso-ebi, from your aunty Ngozi''s wedding. I spent six months paying the tailor. I wore it once." A pause. "I thought about it every day when we were packing."\nShe had not said this before. In all the careful months of managing, she had not said this.\n"Did you bring it?" Adanna said.\n"I brought it." Her mother looked at her hands. "I don''t know where I will ever wear it now." A breath. "I brought it anyway."\nThe yard was quiet. Somewhere in the eaves above them a bird moved once and settled.\nHer mother reached over, not to cover Adanna''s hand but to touch the hem of the uniform, briefly, the way you acknowledge something without making a speech of it. Then she stood, picked up the bucket, and went to the tap.\nAdanna sat for a while longer, listening to the water run.\nThen she stood too, and the standing felt like something. Like a direction.\n"I''m okay," she told her mother''s back.\nHer mother turned off the tap. Turned around. Looked at her face with the careful attention of a woman who had spent sixteen years learning to read it.\n"I know," her mother said.','\n',char(10)),1406,1,1,NULL,'2026-04-26 12:28:22','2026-04-20 11:11:05','2026-04-26 12:28:22',NULL,2,44);
INSERT INTO "chapters" ("id","novel_id","chapter_number","title","content","word_count","is_premium","is_published","audio_url","published_at","created_at","updated_at","scheduled_release_at","part_number","season_id") VALUES(541,67,10,'What Holds',replace('She did not plan it. That was the thing she wanted to be clear about, at least to herself. She did not rehearse it or decide it the way she had decided things before, with the careful calculation of someone managing outcomes. She was walking the road home on a Thursday afternoon, three days after the step in the yard, and she was not performing anything and not maintaining any distance, and when she reached the junction where their roads separated she did not turn.\nShe kept walking. His direction.\nHe noticed after four steps. She could tell by the slight adjustment in his pace, the way he looked at her once from the side without turning his head fully.\n"You passed your junction," he said.\n"I know."\nHe did not say anything else. He walked and she walked and the road did what the road did, loud and layered and ongoing, a woman frying plantain at a compound entrance, two boys on a bicycle that was only built for one, a radio from somewhere above playing something slow and golden from another decade.\nShe had been thinking about what to say since Tuesday and had arrived at nothing prepared, which was correct, because prepared was the old way and the old way was what she was leaving behind.\n"I went to the Island last month," she said. "Chidera''s birthday."\n"I know. You told me."\n"I didn''t tell you how it was."\nHe looked at her. "How was it?"\nShe thought about the rooftop and the warm lights and the forty people performing the grammar they all knew and her own flawless performance and the complete hollowness of it. She thought about standing at the railing looking at the lights below and thinking about his mother''s fabric wall.\n"It was like reading a book I had already finished," she said. "All the words in the right places. Nothing left to find."\nHe walked with this for a moment. "And here?"\nShe looked at the road ahead, at Mushin going about its loud honest afternoon, at the city that had not known her name when she arrived and now knew it, not the way the Island had known it, not as currency, but as a person''s name, the thing you call someone when you see them.\n"Here is where the finding is happening," she said.\nHe stopped walking.\nShe stopped too and turned to face him. He was looking at her with the full version of his attention, not the half-degree reduction of the last difficult weeks, not the careful patience he had maintained since the first day in Mr. Adebayo''s class. This was the unguarded version, the one she had seen for one brief moment on the road after the Soyinka argument, and it was not small.\n"I owe you something," she said.\n"You don''t owe me anything."\n"I was awful to you. In the beginning."\nHe considered this with the honesty she had learned to expect from him. "You were," he said. "But I understood what it was."\n"That doesn''t make it acceptable."\n"No," he agreed. "It doesn''t. I''m just telling you I understood it."\nShe looked at him. This was the thing about Chinedu that she had not had language for until now, standing on the road with the plantain smoke reaching them from half a block back. He did not perform patience the way she had first read it, as superiority, as a man waiting for you to catch up. It was something else entirely. It was the ease of someone who had always known what he was worth, who had never needed her to confirm it, and who had therefore been free to simply watch her find her own way without requiring her to perform the finding for his benefit.\nShe had not known that kind of person existed. She had not known she needed to know one.\n"The margin notes," she said.\nHe looked at her, waiting.\n"You wrote your questions on the left. I wrote mine on the right. I moved to the center once and then moved back." She paused. "I don''t want to keep moving back."\nHe was quiet for a moment. Around them the road continued, a keke horn, someone calling a name from a window, the city''s unceasing conversation with itself. And then Chinedu, who had never in her experience reached for anything he was not certain of, reached over and took the textbook from her hands, the one she had been carrying all day, and put it in his bag.\nHe had a new bag strap. She noticed this now. It had been replaced sometime in the last week.\n"Walk," he said.\nThey walked.\nPast the junction where she should have turned. Past the compound with the potted plants. Past the tailor''s shop with the ankara in orange and green. The road unwinding ahead of them, familiar now, her body knowing it the way bodies know routes they have run long enough.\nShe did not talk and he did not talk and the silence between them was the new kind, not the managed quiet of two people maintaining distance but the settled kind, the kind that does not need to be filled because it is already full.\nAt his compound gate he stopped. His father''s okada was outside, not yet covered, which meant his father was newly returned.\n"You should come inside," he said. "My mother asked about you last week."\nThe simplicity of it. His mother had asked about her. He was telling her. He was opening a door without theater, without declaration, in the exact same way he offered puff puff from an open palm, without ceremony, as if her receiving it was already understood.\nShe thought about everything that had brought her to this gate. The compound on the Island in its final days, the boxes and the curtains that were not theirs to take. The drive across the bridge, the lagoon wide and grey below. The first day in the too-big uniform at the gate of this school. The road home with the man and his cart of yam. The library with the uneven chairs. The argument about Soyinka that had broken something open. The fabric wall and the trophies with worn gold paint. The Island rooftop and its hollow perfection. The step in the yard with the uniform in her hands and her mother''s hand over hers.\nAll of it, every piece of it, had been necessary. She understood this in the way you understand things after you have lived them rather than before.\nShe had not come to Chinedu because she had nothing else. She had other things now, real things she had built from the rubble of the old life and from this new one, her own honesty, her mother''s resilience, the school that had not asked her to be anything except present. She had come because she knew the difference now, clearly and completely, between what had been borrowed and what held.\nHe was what held.\n"Okay," she said.\nHe opened the gate. The yard was warm in the late afternoon, the light coming over the wall at the angle that turned everything amber, the potted plants casting small shadows on the concrete.\nHis mother''s voice came from inside, talking to someone, laughing at something, her particular laugh that filled a room without effort.\nAdanna stepped through the gate.\nThe city continued around them, outside the wall, loud and layered and alive, this enormous relentless Lagos that had taken everything from her and given her, in return, the only things that turned out to matter.\nShe was sixteen and she did not have the pool or the blazer or the table under the overhang. She had a too-big uniform and a second-floor room with a ceiling fan and a road she had walked until it knew her feet.\nShe had this.\nIt was enough. It was more than enough.\nIt was real.','\n',char(10)),1331,1,1,NULL,'2026-04-26 12:28:37','2026-04-20 11:12:35','2026-04-26 12:28:37','2026-04-20T10:15:00.000Z',2,44);
INSERT INTO "chapters" ("id","novel_id","chapter_number","title","content","word_count","is_premium","is_published","audio_url","published_at","created_at","updated_at","scheduled_release_at","part_number","season_id") VALUES(542,61,1,'The Bottom Bunk',replace('The gate of Queen''s Hallmark Secondary School looked like it had been painted once and then forgotten. Chiamaka stood outside it with two bags and a trunk box, watching a security man scratch his arm with a pen and not look up at her.\n"I''m a new student," she said. "SS2."\nHe looked up then. Looked at her bags. Looked at her face. Then he pointed toward a cluster of buildings to the left and went back to his arm.\nThis was not Greenfield Academy. At Greenfield, the administration block had glass doors and a receptionist who offered water. There was a koi pond. Chiamaka had walked past that koi pond every morning for three years without once thinking about how strange it was to have fish at a school. She thought about it now.\nShe dragged her trunk box across uneven concrete, the wheels catching on every crack.\nThe housemother''s name was Aunty Remilekun, and she spoke in the specific way of women who had long stopped finding children interesting. She read Chiamaka''s name from a form, mispronounced it once, did not try again, and handed her a key on a numbered tag.\n"Room Six, Hostel B. Top floor. Lights out is nine o''clock. Morning prep is five-thirty. You missed two weeks of term already so I don''t want to hear about catching up. Catch up."\nShe turned back to her desk. The conversation was over.\nRoom Six was at the end of a corridor that smelled of cement and hair grease and the particular density of six girls sharing one space. Chiamaka stood outside the door for a moment. She could hear voices inside. She knocked.\nNobody answered. She pushed the door open.\nFive of the six bunks were already claimed. She could tell from the fabrics, the photos tucked into bed frames, the provisions boxes stacked near lockers. A girl with thick box braids was sitting on the top bunk nearest the window, reading a novel with the cover facing down. She did not look up when Chiamaka entered.\nA shorter girl with a kind face looked up from where she was arranging something in a locker. "Ah, you''re the new girl. Chiamaka, abi?"\n"Yes." Chiamaka tried to smile. "Hi."\n"I''m Ngozi." She pointed around the room with easy confidence. "That''s Funke, that''s Blessing, Sade is in the bathroom. And that''s Temi."\nTemi was the girl with the box braids on the top bunk. She turned a page without looking up.\n"Your bunk is there." Ngozi pointed to the bottom bunk directly beneath Temi. "We already put the mattress."\nChiamaka looked at the bunk. The mattress was thin in a way that her eyes registered before her brain could stop them from registering it. She was used to a bed with a headboard and a mattress thick enough to sink into. She stood there one second too long.\n"Is something wrong with it?" Funke asked. She was seventeen, Chiamaka would learn, and had a way of watching people that felt less like interest and more like calculation.\n"No," Chiamaka said. "Nothing."\nShe put her bags down and started to unpack, and it was while she was kneeling beside her trunk box that she felt it. The specific feeling of being watched. She looked up.\nTemi was looking at her.\nNot the way Ngozi looked at her, which was warm and easy. Not the way Funke looked at her, which was measuring. Temi was looking at her the way you look at something you already have an opinion about. Her eyes moved from Chiamaka''s face to her bags to the small initialled luggage tag on her trunk box. Then she turned back to her book.\nChiamaka felt heat climb the back of her neck. She did not know what she had done. She had been in the room for four minutes.\nShe finished unpacking, sat on the edge of her new mattress, and looked at the ceiling. It was Temi''s bunk above her. She could hear the faint rustle of pages turning.\nHer mother had cried at the bus park in Lagos. Her father had not come. He was dealing with things, her mother said, in a voice that had learned to make large disasters sound like minor scheduling conflicts. Chiamaka had not cried at the bus park. She had looked out the window the whole four hours and thought about nothing, which was its own kind of work.\nShe looked around the room. Funke was now talking to Blessing in a low voice about something that made Blessing laugh. Ngozi had gone back to her locker. Sade had come out of the bathroom and was oiling her scalp in front of a small mirror without looking up. These girls had rhythms already. Three weeks into term, they had become a small world, and Chiamaka was standing at the border of it with her Lagos accent and her initialled trunk box and whatever it was that Temi had read in her face in that single look.\nShe had been at the top of every room she had ever walked into. That was just the truth of her life. She was not performing when she walked into Greenfield every morning. She was just being herself, and herself had always been enough, and more than enough, and now she was sitting on a thin mattress in Ibadan listening to other girls laugh at a joke she had not heard.\nAbove her, Temi turned another page.\nThe bottom bunk had never been something Chiamaka imagined for herself. She was beginning to understand that this was not the only thing she had been wrong about.','\n',char(10)),943,0,1,NULL,'2026-04-20T12:11:17.094Z','2026-04-20 12:11:17','2026-04-20 12:11:17',NULL,1,45);
INSERT INTO "chapters" ("id","novel_id","chapter_number","title","content","word_count","is_premium","is_published","audio_url","published_at","created_at","updated_at","scheduled_release_at","part_number","season_id") VALUES(543,61,2,'Provision Check',replace('Sunday morning in Hostel B started with noise.\nNot the structured noise of prep bell or assembly, but the loose, happy noise of girls who knew something good was coming. Chiamaka heard it before she opened her eyes: locker doors, the slide of boxes across the floor, someone down the corridor singing an Asake song badly and at full volume.\nShe lay still on her thin mattress and listened, and for four seconds she did not remember where she was. Then the springs above her creaked as Temi climbed down, and she remembered everything.\nSunday was provision day. She knew this because Ngozi had mentioned it the night before with the quiet excitement of someone who had been thinking about it since Thursday.\n"Your people are sending something, abi?" Ngozi had asked, not unkindly.\n"Yes," Chiamaka had said, because it was easier than the truth.\nThe truth was that her mother had packed the box herself while Chiamaka watched, and the watching had been its own kind of pain. Her mother''s hands moving carefully over the things she had gathered: one tin of Milo, one packet of cabin biscuits, a small bag of garri, a tin of groundnut, three sachets of sugar. She had added a bottle of Fanta at the last moment like a full stop, and Chiamaka had looked away from her mother''s face because she had not wanted to see what was on it.\nAt Greenfield, the provision boxes had been different. Chiamaka''s had always had a cooler bag inside it. Roasted chicken from the good place in Lekki. Chin-chin from the aunty in Surulere whose chin-chin was famous enough to be currency. A full carton of Capri-Sonne juice packs, not the small sachets but the ones with the foil pouches. Her mother had packed it every third Sunday like an act of love that also said: we are doing fine, we are doing well, look at how we are doing.\nShe sat up.\nThe room had transformed. Funke had pulled her box out and opened it like a small market. There were packs of noodles, three different sizes of biscuits, a tin of sardines, cooked meat wrapped in foil that Chiamaka could not help noticing, a bag of chin-chin, two cans of malt. Funke was inventorying it with the satisfied expression of someone confirming good news they already knew.\nBlessing was quieter about it, her smaller box open just enough to put a few things into her locker. Sade had a cooler. Ngozi had a rubber bag from which she was pulling wrapped parcels of home-cooked food, and the smell that came out of it made the room feel briefly like a Saturday afternoon in someone''s mother''s kitchen.\nChiamaka opened her own box.\nShe did it without rushing, because rushing would look like nervousness, and she was not going to be nervous about a box in front of girls she had known for two days. She lifted the lid. The Milo tin. The cabin biscuits. The garri. The groundnut. The sugar sachets. The Fanta.\nShe could feel the shape of the room''s attention even though nobody was looking at her directly. That was the thing about six girls in a small space: peripheral vision became a social language.\nShe put the things in her locker with the same deliberate calm she had used at Greenfield when she wanted to communicate that whatever was happening was beneath her. The locker door closed. She sat back on her bunk.\nTemi was back on the top bunk with a pack of plantain chips and what appeared to be an entire cooler that her mother had sent from Ibadan, twenty minutes away. The closeness of home and the fullness of that box were not things Temi seemed to find worth commenting on. She just ate.\nFunke looked up from her own box. "Your people sent small thing this time," she said. Not viciously. The way she said it was almost neutral, which was somehow worse.\n"It''s enough," Chiamaka said.\nFunke shrugged and bit into a piece of cooked meat.\nNgozi, from across the room, met Chiamaka''s eyes for a brief moment. There was something in her face that was not pity, exactly, but was close enough to pity that Chiamaka looked away from it.\nLunch was rice from the school kitchen. Chiamaka ate it without her provision and told herself that she was not hungry, that the rice was fine, that she had eaten basic meals before and this was not suffering. She had the internal conversation with herself all the way through lunch, and she almost won it. Almost.\nIt was in the evening, when Funke was eating her chin-chin and the smell of Ngozi''s jollof from home was spreading warmly through the room, that her stomach made a sound that she could not explain away.\nTemi looked down from her bunk.\nTheir eyes met. Chiamaka held her face still, the way she had practised in front of mirrors in Lagos after the news first broke, when relatives started coming around with the particular gentleness that people reserve for those they feel sorry for.\nTemi did not say anything. She reached into her cooler, pulled out a short bread biscuit, and placed it at the edge of her bunk. Then she turned back to her book.\nIt sat there on the edge of the bunk like a question Chiamaka did not know how to answer. She did not touch it for a long time. She stared at the ceiling and listened to the room and thought about pride and about hunger and about how sometimes they were the same feeling, just wearing different faces.\nThe biscuit was still there when lights out came.','\n',char(10)),954,0,1,NULL,'2026-04-20T12:12:07.637Z','2026-04-20 12:12:07','2026-04-20 12:12:07',NULL,1,45);
INSERT INTO "chapters" ("id","novel_id","chapter_number","title","content","word_count","is_premium","is_published","audio_url","published_at","created_at","updated_at","scheduled_release_at","part_number","season_id") VALUES(544,61,3,' Lagos Accent',replace('She said "excuse me" to a girl blocking the corridor doorway on Monday morning, and the girl turned around and stared at her like she had spoken in a foreign language.\n"You''re the Lagos girl," the girl said. It was not a question.\nBy the time Chiamaka reached her SS2 classroom, four people had already heard about her before she arrived. She could tell from the way heads turned when she entered, the way conversations dipped briefly and then resumed. She found an empty seat near the middle row and sat down and felt the room reorient slightly around her presence the way a body of water adjusts around something dropped into it.\nHer accent was the problem. Or maybe the problem was that it was not a problem to her, which made it a problem to everyone else.\nAt Greenfield, everyone had sounded like her. The particular flatness of certain vowels, the upward lilt at the end of sentences, the way Lagos compressed some words and stretched others. It was just how people talked. Here, the sound of it was a flag she carried into every room without choosing to.\n"Read from paragraph three," the English teacher said, and pointed at Chiamaka because she was new and teachers always did that to new students, used them as proof that the class was still paying attention.\nChiamaka read. She read well. She had always read well. When she finished, the teacher nodded and the class was quiet for a moment that felt longer than it was.\n"Lagos," a boy''s voice said from the corridor window. Just the word, like an identification tag. A few people in the class laughed before catching themselves.\nAfter school, in the hostel common room, a senior girl named Biola stopped Chiamaka on her way past and asked her to repeat the phrase "how far" just to hear how it sounded. Biola''s friends found this worth laughing about. Chiamaka stood there and let them hear it and smiled with her teeth and felt something harden in her chest like cooling wax.\nThat night she lay on her thin mattress and thought about it. The way the word Lagos had followed her from the gate to the classroom to the common room like a label ironed into the collar of everything she wore. She had heard people use the word before, in Lagos itself, but there it meant something uncomplicated. Here it meant: you are from somewhere else, you think you are better, let us see you figure out that you are not.\nShe thought about what to do with it.\nBy Wednesday, she had made a decision. If Lagos was going to follow her everywhere, she was going to walk faster than it.\nIt started small. In class, when the teacher asked about the economic implications of oil production for a comprehension passage, Chiamaka answered with the full Lagos fluency she usually modulated in new spaces. She let the accent land the way it wanted to land. She referenced things she had seen in Lagos, places she had been, the kind of details that established geography and class simultaneously. The teacher was impressed. She could see it. A few classmates looked at her differently.\nIn the dining hall, when a girl asked where she had bought her school sandals, Chiamaka named the specific store in Victoria Island where her mother had bought them two terms ago. She watched recognition move across the girl''s face. That specific store meant something. She filed that away.\nShe started talking more. Louder, in some contexts. She let the Lagos sit in her mouth like something she was proud of instead of something she was managing. She talked about Greenfield the way she used to talk about it before Greenfield became a thing she had to leave. She talked about her father''s car, the old one, the good one, before. She talked in the present tense about things that were past tense, and she did it with the smooth ease of someone who had decided that the difference between a lie and a performance was mostly a question of confidence.\nFunke watched her do it one afternoon in the common room with the expression of someone watching a card game they already know the ending of.\n"You''re getting loud," Funke said, when the other girls had moved away.\n"I''m just talking," Chiamaka said.\n"You''re performing." Funke said it simply, without cruelty, the way she said most things. "It''s fine. Just know the difference."\nChiamaka did not answer her.\nThat evening, back in the room, she was in the middle of a story about a restaurant in Ikoyi, something that had happened at a birthday party last year, and she was telling it well, she knew she was telling it well, and Ngozi was listening with genuine interest, and even Sade had looked up from her textbook. Chiamaka was in the middle of the best part of the story when she noticed Temi.\nTemi was lying on the top bunk, face toward the wall, not reading, not sleeping. Just still. And something in the stillness was different from indifference. It was more deliberate than that. Like a door closed from the inside.\nChiamaka finished the story. The girls laughed. Ngozi said "chai" in that warm way of hers. The moment passed.\nBut she kept thinking about Temi''s back. The specific quality of that silence. As if the story had not been nothing to Temi but had been something, something that required effort to be still against.\nShe did not know what that meant. She lay in the dark after lights out and turned it over in her mind, that careful, deliberate stillness, and underneath all the Lagos noise she had been manufacturing all week, she felt something she did not have a word for yet.\nIt felt like being seen and not wanting to be.','\n',char(10)),983,0,1,NULL,'2026-04-20T12:12:56.717Z','2026-04-20 12:12:56','2026-04-20 12:12:56',NULL,1,45);
INSERT INTO "chapters" ("id","novel_id","chapter_number","title","content","word_count","is_premium","is_published","audio_url","published_at","created_at","updated_at","scheduled_release_at","part_number","season_id") VALUES(545,61,4,' Senior Girls Don''t Beg',replace('The thing about hunger was that it had a rhythm, and by Thursday Chiamaka had learned to anticipate it the way you anticipate a difficult person: brace before it arrives, manage it while it is there, recover quietly after.\nBreakfast was tea and bread. Lunch was whatever the school kitchen decided the afternoon deserved, which on Thursdays was a watery stew over rice that Chiamaka ate completely and told herself she had not. Dinner was the same stew''s older, thicker cousin, and she ate that too, and by nine o''clock, two hours after dinner, she was lying on her mattress listening to her own stomach with the specific frustration of someone losing an argument with their own body.\nThe room had its evening rhythms. Funke was eating noodles she had cooked in the kitchen down the hall, the smell of seasoning cube sharp and warm in the small space. Blessing was reading. Sade was on her phone under her blanket, the glow visible at the edges. Ngozi had a small container of groundnut she kept on the ledge beside her locker and was eating them one by one, slowly, the way you eat something when you want it to last.\nChiamaka looked at the ceiling.\nShe had two cabin biscuits left in her locker. She was saving them for tomorrow morning because the school''s tea was not enough on its own and she had learned that the hard way on Tuesday when her concentration had slipped during a maths class and she had looked at the chalkboard and understood nothing for a full ten minutes. Two cabin biscuits. She was not going to eat them tonight.\nAbove her, Temi was quiet. She had been quiet since she came back from the bathroom. Chiamaka could tell from the stillness of the mattress springs that she was not asleep.\nFunke looked up from her noodles. "Chiamaka, you want?"\nThe question was easy. Funke''s tone was easy. There was nothing complicated in the offering.\n"I''m fine," Chiamaka said.\nFunke looked at her for one second, then went back to her noodles.\nThis was the problem with pride. It did not announce itself. It just answered before you could think, and then you had to live inside the answer.\nShe was not fine. Her stomach knew it. The room probably knew it. But senior girls did not beg, and she was not begging, and asking was a kind of begging if the person you asked could see the reason for the asking. That was the logic she was living inside, and she knew even as she was living inside it that it was the logic of someone performing for an audience that was not watching.\nFriday arrived with a geography test she had not fully prepared for and a morning tea that was more hot water than tea, and by the time she walked into the classroom she was running on two cabin biscuits and the specific sharpness that came from not eating enough.\nShe passed the test. She knew she passed it because geography had always come easily to her, names and places and the logic of how the earth organized itself, but sitting in that classroom with her pen moving across the paper she felt thin in a way that had nothing to do with her weight. Like a battery that was answering every call but showing one bar.\nAfter school there was a small chop bar near the back of the school premises where a woman sold fried yam and akara from a low table. Chiamaka had walked past it twice that week without stopping. The smell followed her, rich and familiar, and she had kept walking both times.\nToday she stopped.\nShe counted the money in the small purse in her bag. She had been counting it all week without meaning to, the way you keep checking a wound. There was enough for fried yam. Enough for three pieces if she chose the smaller ones. She stood in front of the woman''s table and made herself breathe.\n"Two pieces," she said. "Medium."\nShe sat on the low bench nearby and ate quickly and did not look around to see who was watching, because looking around to see who was watching was the thing that would make it a moment, and she did not want it to be a moment.\nIt was Temi who walked past.\nTemi coming from the direction of the classrooms, bag over one shoulder, and she slowed briefly when she saw Chiamaka, and for one terrible second Chiamaka felt her jaw stop moving. Then she made herself keep chewing, slow and deliberate, the way she ate in the dining hall when she was eating a meal that had nothing to apologize for.\nTemi looked at her. Not the hostile, measuring look from that first day. Something flatter than that. Something closer to recognition.\nShe walked on without saying anything.\nChiamaka finished the yam. She licked the oil from her thumb and gathered herself from the inside out the way she had been doing all week, collecting her composure from wherever it scattered to and organizing it back into the shape of a girl who was handling things. She stood up. She walked back toward Hostel B.\nBut in the stairwell, between the first and second floor, she stopped. She stood with her hand on the rail and her eyes on the wall and she let herself feel it for thirty seconds exactly. The yam she had needed. The money getting smaller. Her father''s car and the koi pond and the cooler bag with the Lekki chicken inside it.\nShe counted to thirty and then she climbed the stairs.\nThe room was empty when she got back. She sat on her bunk in the quiet and looked at her locker and felt the shape of what was happening to her settle more firmly around her, the way a garment settles when you finally stop pretending it does not fit.','\n',char(10)),1001,1,1,NULL,'2026-04-20 12:16:49','2026-04-20 12:13:56','2026-04-20 12:16:49',NULL,1,45);
INSERT INTO "chapters" ("id","novel_id","chapter_number","title","content","word_count","is_premium","is_published","audio_url","published_at","created_at","updated_at","scheduled_release_at","part_number","season_id") VALUES(546,61,5,' Ngozi''s Offer',replace('It was a Saturday, which meant no classes and nowhere to be, which meant the room had no schedule to hold it together and everyone settled into their own version of the afternoon.\nFunke left early with a group of SS2 girls Chiamaka recognized from the corridor but had not spoken to. Sade spent the morning washing clothes at the back of the hostel and came back with her arms tired and her mood quiet. Blessing read. Temi was gone before Chiamaka woke up and did not come back until after two.\nChiamaka sat on her bunk and read a textbook she had borrowed from the class shelf, not because she was studying but because having a textbook open in front of her felt like doing something, and doing something felt better than being still with her own thoughts.\nHer phone was almost out of data. She had been rationing it the way she rationed the cabin biscuits, opening only what was necessary, keeping conversations short. Her mother had sent a message that morning: How are you coping? Eating well? Chiamaka had typed back Yes fine and closed the app before she could read whatever came after.\nThe afternoon moved slowly. Outside the hostel window, she could hear girls playing something in the compound below, a ball game from the sound of it, feet on concrete and voices rising and falling. She watched a gecko cross the wall above Temi''s locker. A thread on Sade''s blanket caught the light when the curtain moved.\nShe was very hungry.\nThe school kitchen served lunch at one, and she had eaten all of hers and mopped the plate with the last of the school bread, and now it was past three and the hunger had come back and was making itself comfortable. She looked at her locker. She had the garri her mother had packed and a tin of groundnut and the sugar sachets. She had not touched the garri because making garri required hot water and a bowl and a quietness of spirit she had not found the energy to perform in front of the room.\nShe heard Ngozi come in behind her.\nNgozi moved through the room the way she always did, without announcing herself, setting her things down and opening her locker with the casual ease of someone who found the room genuinely comfortable. She pulled out a bag of garri and a cup and went to the kettle on the small table by the window and Chiamaka went back to her textbook.\nFive minutes later Ngozi was at her bunk.\n"Come," Ngozi said.\nChiamaka looked up from the textbook.\nNgozi was holding a bowl with both hands. The garri was already made, thick and yellow-white, with groundnut oil floating in rings at the top. There was groundnut on the side and two cubes of sugar already dissolving at the edges. She had made it the proper way, not the hurried way. The steam coming off it was very gentle.\n"I made enough for two," Ngozi said simply. Like it was information rather than an offer.\nChiamaka looked at the bowl. Then at Ngozi''s face, which was open and patient in a way that did not carry pity in it, or at least was trying very hard not to. The difference was small but Chiamaka''s eyes had been trained all week to find it.\nThe word no shaped itself in her mouth.\nShe felt it sitting there, the same word that had answered Funke without consulting her. The familiar armoring that happened before she could choose it. No thank you. I was about to make mine. The words were right there, easy and ready and perfectly shaped to keep her exactly where she was.\nShe looked at the bowl again.\nNgozi had used the good groundnut, the kind with the papery skin peeled off. She had used the right amount of water. The sugar was dissolving in the way that meant she had learned from someone who made garri properly, probably a mother or a grandmother, someone who understood that the point was not just calories but something else, something that lived in the warmth of the thing.\n"Okay," Chiamaka said. The word came out smaller than she intended.\nNgozi sat on the edge of the lower bunk across from her, her own cup between her palms, and handed the bowl across without ceremony. Chiamaka took it and turned it once in her hands and then she ate.\nShe ate slowly at first, the way you eat when someone is watching and you are trying not to show how much you needed what they gave you. Then hunger made its own decision and she stopped performing for an audience that was not watching anyway and just ate.\nThey were quiet together. Outside, the ball game continued. Sade came back in and went to her locker without noticing them or pretending not to. Blessing turned a page.\n"You don''t have to tell me anything," Ngozi said, after a while.\nChiamaka stopped with the spoon halfway to her mouth.\n"I just mean," Ngozi continued, looking at her cup, "you don''t have to explain. We all have a term we didn''t expect. Mine was JSS2." She paused. "My father changed his job and everything changed with it. The provisions changed. The phone changed. Everything."\nShe said it without drama. The way you say a thing you have already finished being ashamed of.\nChiamaka looked at her. Fifteen years old, this girl, and she held her history like it was just a fact about herself, like it was no heavier than her name.\n"Thank you," Chiamaka said. "For the garri."\nNgozi smiled and lifted her cup in a small toast. "Next week make your own and give me."\nChiamaka almost laughed. It came out as something smaller, a breath with a shape to it, but it was real, and it surprised her, and for a moment the room felt like somewhere she might eventually learn to live.','\n',char(10)),1003,1,1,NULL,'2026-04-20T12:14:46.325Z','2026-04-20 12:14:46','2026-04-20 12:14:46',NULL,1,45);
INSERT INTO "chapters" ("id","novel_id","chapter_number","title","content","word_count","is_premium","is_published","audio_url","published_at","created_at","updated_at","scheduled_release_at","part_number","season_id") VALUES(547,61,6,'What Temi Knows',replace('The comment happened on a Tuesday, in the middle of an argument about nothing, the way the most important things usually happen.\nIt had started with the fan. The room''s ceiling fan had one speed, which was loud, and one direction, which was toward Temi''s side of the bunk, and Chiamaka had reached up that evening and angled the head of it slightly toward the center of the room without asking. Temi had reached down from the top bunk and angled it back. Chiamaka had moved it again. Temi had moved it again. Nobody said anything during any of this. It was the kind of argument that lived entirely in actions until it did not.\n"Can we just share the air," Chiamaka said, "like reasonable people."\n"Can you ask before you touch things that are not yours," Temi said.\n"The fan belongs to the school."\n"The position of the fan is mine. I was here first."\n"That logic would give the whole country to whoever was born earliest."\nFunke, from her bunk, made a sound that was not quite a laugh.\n"You people should rest," Sade said, without looking up.\nTemi came down from the bunk. She did it in the particular way she did everything, economical and unbothered, and she went to her locker and opened it and took out a textbook and that should have been the end of it. The fan argument was over. These things ended. The room had a short memory for small conflicts because it could not afford a long one.\nBut then Temi said, still facing her locker, "At least I have a reason to be here."\nThe room changed temperature.\nChiamaka turned to look at her. "What does that mean?"\nTemi turned around. Her face was even, the way it usually was, but there was something deliberate in the evenness, something being held in place by effort. "It means some of us chose this school. We didn''t land here because our fathers ran out of options."\nThe silence was total. Even Funke was still.\nChiamaka felt the words enter her the way cold water enters when you are not expecting it. Chest first. Then spreading.\n"You don''t know anything about my father," she said.\n"Obi Construction," Temi said. "The contract scandal. It was in the Punch in August." She said it quietly, without pleasure, which was almost worse than if she had said it with pleasure. "My uncle works at the ministry. He talked about it at a family dinner. I didn''t know it was your father until I saw your trunk box. The initials."\nThe initials. C.N.O. on a luggage tag. Chiamaka had not thought about what those three letters could tell someone who was already looking.\n"That''s my family''s business," Chiamaka said. Her voice was level. She had learned to keep it level. "Not yours."\n"I know," Temi said. And then, unexpectedly, she looked away first. Not in the way of someone who felt she had won but in the way of someone who had gone further than she intended and was now standing somewhere she had not planned to be. "I''m just saying you''re here now. Like the rest of us."\nShe took her textbook to her bunk and climbed up and that was it.\nThe room gradually returned to its sounds. Blessing turned a page. Ngozi exhaled softly from across the room. Funke stretched and reached for her phone with the careful neutrality of someone who had decided not to have witnessed what she had witnessed.\nChiamaka sat on her bunk. She looked at her hands in her lap, at the small scar on her left index finger from a cooking accident at eleven, at the silver ring on her right hand that her father had bought her for her last birthday at a shop in Ikeja that she had thought was not expensive enough at the time and had barely thanked him for.\nThe Punch. August. Her father''s name in a newspaper article while she was still at Greenfield, still walking past the koi pond, still eating chicken from the good place in Lekki. The world had already been shifting underneath her before she knew it was shifting. Temi had read about it at a family dinner and filed it away, and then a girl with the matching initials had walked into Room Six two weeks ago and Temi had looked at that trunk box and known.\nAll that hostility. From the very first day. It had not been general. It had been specific.\nKnowing that did not make it better. It made it stranger, more complicated, like a shape she had been feeling in the dark that turned out to be something she recognized.\nShe lay back on her mattress and looked up at the underside of Temi''s bunk and thought about her father. Not the version of him from the newspapers or from the hushed phone calls she had overheard all August, but the one from before. The one who drove too fast on the third mainland bridge with the windows down and the radio up. The one who called her my chairman when she brought home a good report card. That man and the man in the Punch article were supposed to be the same person and she still had not figured out how to hold them together.\nAbove her, Temi shifted. The mattress springs spoke briefly and went quiet.\nChiamaka thought about what Temi had said. You''re here now. Like the rest of us.\nIt was not kindness. She did not think Temi had meant it as kindness. But it was something. An acknowledgment of a shared condition, the way you might acknowledge someone standing next to you in a queue neither of you chose.\nShe was not sure whether to be angry about what Temi had done or grateful for what Temi had said. She suspected the answer was both, and that living inside both at the same time was exactly where this term intended to keep her.','\n',char(10)),1006,1,1,NULL,'2026-04-20T12:15:34.705Z','2026-04-20 12:15:34','2026-04-20 12:15:34',NULL,1,45);
INSERT INTO "chapters" ("id","novel_id","chapter_number","title","content","word_count","is_premium","is_published","audio_url","published_at","created_at","updated_at","scheduled_release_at","part_number","season_id") VALUES(548,61,7,'The Test',replace('The exam timetable went up on the notice board on a Wednesday, and by Thursday morning the entire hostel had reorganized itself around it.\nChiamaka read it once, standing in the corridor with her tray from breakfast, and then she read it again. Three weeks. Chemistry, Mathematics, English Language, Literature, Geography, Economics, Biology. Seven papers across five days in the third week of the month. She had known exams were coming, the way you know rain is coming when the sky changes, but seeing the dates printed in the vice principal''s neat block letters made it a different kind of real.\nShe went back to her room and sat on her bunk and opened her chemistry textbook to the current chapter marker and stared at a diagram of electron configurations for a long time.\nAt Greenfield, the curriculum had been British-leaning, structured around Cambridge standards, the kind of syllabus that had its own logic and internal consistency. Here the scheme of work was WAEC-focused in a way that was not better or worse but was genuinely different, and she had been three weeks behind it before she even arrived, and she had been telling herself since week one that she was catching up but the truth, sitting here with this diagram, was that she had been performing catching up more than she had been doing it.\nShe closed the textbook.\nShe opened it again.\n"What chapter are you on?" Ngozi asked from across the room, not looking up from her own notes.\n"Atomic structure," Chiamaka said.\nNgozi looked up. "We finished that in week two. We''re on chemical bonding now. Test starts from bonding."\nChiamaka kept her face still. "I know."\nShe did not know.\nShe waited until the room emptied for morning prep before she sat with both textbooks open, the Greenfield chemistry notes she had brought in her bag and the borrowed scheme of work she had finally asked a classmate for that morning. She put them side by side and looked at the distance between where she was and where she needed to be. It was not impossible. She had three weeks. She was not a weak student. But three weeks of real work, which was different from three weeks of performing the idea of work in between managing hunger and hostel politics and the daily effort of not falling apart in front of people she barely knew.\nShe made a list. Chemistry: two chapters behind. Mathematics: the class had covered a statistics unit she had not touched since JSS3. Literature: they were on a text she had not read. Geography: she was actually fine. Economics: close enough. Biology: manageable.\nShe stared at the list.\nThen she did something she had not done since she arrived. She went to find her class teacher.\nMrs. Adeyinka taught Economics and had the patient, well-organized manner of someone who had taught for long enough to distinguish between students who were struggling and students who were wasting her time. She looked at Chiamaka''s list across her desk without expression and then looked at Chiamaka.\n"You should have come three weeks ago," she said.\n"Yes ma," Chiamaka said.\n"But you''re here now." Mrs. Adeyinka pulled out a copy of the scheme of work and circled four topics. "These are the highest-weighted areas. If you understand these, the others follow. Do you have someone in your class you can study with?"\nChiamaka thought about it. There was a girl called Remi who sat two rows ahead and always had her notes colour-coded and visible. She had not spoken to Remi beyond greetings. "I''ll find someone," she said.\nShe went back to the hostel and studied until dinner and then after dinner and then after lights-out with a torch under her blanket until Temi''s voice came down from above her, flat and unbothered: "You''re keeping me awake."\n"Sorry," Chiamaka said, and turned the torch off, and lay in the dark reconstructing the chemical bonding diagrams in her mind until she fell asleep.\nThe first practice test was in class on Friday. Mrs. Obiora, the chemistry teacher, put it on the board as a diagnostic, she said, which meant it counted for nothing officially but meant everything to Chiamaka because it was information.\nShe sat with the questions in front of her and answered what she knew and left spaces for what she did not, and when the papers were exchanged for marking she sat with her pen and marked someone else''s work and kept her breathing even. When she got her paper back, the score was written in red in the top corner.\nFifty-one out of a hundred.\nShe looked at it. The number had a flatness to it, a neutrality that was worse than if it had been lower. Fifty-one meant she was in the middle of something, not at the bottom where the situation was clear and the only direction was up, but in a complicated middle where the result of effort was uncertain.\nShe folded the paper and put it in her bag.\nWalking back to the hostel she passed the small chop bar and kept walking. She passed the notice board with the timetable on it and looked at the dates again and kept walking. She climbed the stairs to the top floor and went into Room Six and sat on her bunk and looked at her hands.\nPride had kept her from coming to this point properly. She could see that clearly now, the way you see clearly after you have been looking at something too close for too long. She had spent three weeks performing the shape of a girl who was managing when she could have been becoming a girl who actually was.\nShe opened her chemistry textbook to the bonding chapter. She pressed her pen to the first blank page of her notebook.\nShe started from the beginning.','\n',char(10)),982,1,1,NULL,'2026-04-20T12:16:33.651Z','2026-04-20 12:16:33','2026-04-20 12:16:33',NULL,1,45);
INSERT INTO "chapters" ("id","novel_id","chapter_number","title","content","word_count","is_premium","is_published","audio_url","published_at","created_at","updated_at","scheduled_release_at","part_number","season_id") VALUES(549,61,8,'Night Talk',replace('The light went out at exactly nine o''clock and Funke said, into the sudden dark, "If I fail Economics I''m going to become a pastor."\nNobody laughed immediately. Then Sade did, and then it spread.\nIt had been a long week. Two weeks to the exam now, and the room had been carrying that weight in different ways. Funke with her loud, deliberate unbotheredness. Blessing with a silence that had grown denser and more textured. Ngozi studying in careful, unhurried blocks like someone who had learned not to panic about things she could not control. Sade snapping at small things and then apologizing. Temi unreachable, as always, but with a stillness that felt recently acquired, like a decision rather than a default.\nChiamaka had been studying. Really studying, not the performance of it. She had found Remi from her class and they had sat together twice that week and Remi''s colour-coded notes were, she admitted to no one, some of the most useful things she had encountered since arriving.\n"Pastor of what kind of church though," Ngozi said, from across the dark room.\n"The kind where they don''t ask questions," Funke said. "You just come, you give your tithe, you go home."\n"That''s every church," Sade said.\n"Then I''m already qualified."\nChiamaka was lying on her back with her hands folded on her stomach, looking at the dark where the ceiling was. She could hear the compound outside, distant voices from a lower floor, a generator somewhere on the school grounds that had been running since eight.\n"What would you do," Blessing said, "if you couldn''t do school?"\nThe question settled into the room like something dropped into still water.\n"Blessing." Funke''s voice had a smile in it. "It''s nine-fifteen. Why are you doing this."\n"I''m just asking."\n"Hair," Sade said, after a moment. "I''d do hair. I''ve been doing my aunt''s hair since I was eleven and people always ask who did it."\n"I knew it," Ngozi said. "You have the hands for it."\n"What does that mean."\n"It means your hands look like they know what they''re doing."\nA small silence. Then Sade said, "Thank you. I think."\n"I''d write," Ngozi said. "I know it doesn''t make money. I know that. But you asked what I''d do and that''s what I''d do. I''ve been writing since JSS1. Stories, mostly. I have four notebooks."\n"Four notebooks," Funke repeated. "Ngozi. You''ve been holding this from us?"\n"You never asked."\n"What kind of stories?" Chiamaka asked.\n"The kind where things go wrong and then better," Ngozi said. "Not easy better. Real better. The kind that costs something."\nThe room absorbed this.\n"I''d go home," Blessing said quietly. It was the answer to her own question, the one nobody had turned back on her yet. "I''d go back to Makurdi and help my mother with the shop. It wouldn''t be nothing. It would be something real."\nNobody said anything to that, because there was nothing to say that would be better than letting it sit there.\n"Temi," Funke said. "You''ve been very quiet up there."\n"I''m sleeping," Temi said.\n"You are not sleeping. You answered too fast."\nA pause. Then Temi said, "Architecture. I''ve wanted to do it since I was nine. I used to draw floor plans for the houses on our street. My mother thought I was strange."\n"Floor plans," Sade said. "Like, for buildings?"\n"What other kind of floor plan is there, Sade."\n"I''m just confirming."\n"Yes. For buildings." A beat. "I got into Federal Government College, Warri. JS1. My parents couldn''t afford the transport and the setup costs at the same time, so I came here instead. It''s a good school. I''m not complaining."\nShe said the last sentence in the specific tone of someone who had practised saying it until it sounded like the truth.\nChiamaka stared at the dark ceiling. Federal Government College, Warri. A national merit admission, the kind that required real scores, real ability. And Temi had been here instead, for three years, building something out of what was available.\n"Chiamaka," Ngozi said.\nEveryone waited.\nShe had not expected to be in this conversation. She had been lying in the dark listening, which was its own kind of participation, and now the room was waiting and the dark made certain things easier to say than they would have been in the light.\n"I don''t know," she said. "I used to know. I had a whole answer. Law, like my father. Or business. Something with a title." She paused. "But I think I was just saying what fit the picture. The picture of everything. School and house and car and what people expected." She stopped. "The picture is different now. I don''t have a new answer yet."\nNobody rushed to fill the space after that.\n"That''s honest," Ngozi said.\n"It''s terrifying is what it is," Chiamaka said.\n"Those are the same thing sometimes," Ngozi said.\nFunke made a sound that might have been agreement or might have been her settling into her pillow. Sade yawned. Blessing had gone quiet again but it was a softer quiet than usual, the quiet of someone who had said a thing and felt lighter for having said it.\nChiamaka looked at the dark and felt the room differently than she had felt it since she arrived. Not comfortable, not yet, but something adjacent to it. Six girls breathing in the same space, all of them carrying something, none of them putting it down but some of them, just for tonight, showing the weight of it.\nAbove her, just before sleep came for the room, Temi''s voice came down once more. Low and unprompted and not directed at anyone in particular.\n"You''d be good at whatever you chose," Temi said. "You''re too stubborn not to be."\nChiamaka opened her mouth. Closed it. The silence stretched and then settled.\nShe did not sleep for another hour.','\n',char(10)),985,1,1,NULL,'2026-04-20T12:18:02.973Z','2026-04-20 12:18:03','2026-04-20 12:18:03',NULL,1,45);
INSERT INTO "chapters" ("id","novel_id","chapter_number","title","content","word_count","is_premium","is_published","audio_url","published_at","created_at","updated_at","scheduled_release_at","part_number","season_id") VALUES(550,61,9,' Funke''s Deal',replace('Funke made her offer on a Sunday afternoon, which Chiamaka would later think was deliberate. Sunday was when the room was emptiest, when people were at fellowship or the tuck shop or the laundry lines out back, and Funke had a precise sense of when a conversation needed an audience and when it did not.\nShe came and sat on the edge of Chiamaka''s bunk without asking, which was typical Funke, and she had two chin-chin in her hand and offered one across, which Chiamaka took because she had learned, since the garri, to take things when they were offered and deal with what that meant separately.\n"You''ve been here almost a month," Funke said.\n"Twenty-six days," Chiamaka said.\nFunke looked at her. "You''ve been counting."\n"I notice things."\n"I know." Funke ate her chin-chin and looked at the wall with the particular expression she wore when she was building toward a point. "You''ve been quiet. Outside this room, I mean. In school you talk, in class you answer, but you haven''t placed yourself yet."\nChiamaka waited.\n"There''s a hierarchy," Funke continued. "You know there is. You came from a school where you understood it. Here you''re still reading the room, which is smart, but you''re running out of time. By the end of term people will have decided what you are and that decision is harder to change than to make."\nThis was true. Chiamaka had seen it operating around her for weeks, the invisible sorting that happened in every secondary school, who sat where at assembly, who got greeted in corridors, who was consulted versus who was informed. She had been watching it the way you watch a card game you have not yet been invited to join.\n"What are you offering," Chiamaka said.\nFunke smiled. Not the wide, performing smile she used in groups but the smaller, realer one. "I know everyone. Three years in this school, one extra, I know every senior girl worth knowing and every connection worth having. You need someone to place you properly before people place you without you. I can do that."\n"And what do you need."\nFunke turned the last piece of chin-chin in her fingers. "Economics. I''m failing it and you''re not. Mrs. Adeyinka likes you already, I can see it. You think clearly and you write fast. I need someone to sit with me three times a week before the exam and make the content make sense." She paused. "Not to write my exam for me. I''m not asking that. I just need a person who understands it to talk it through with me until I understand it too."\nChiamaka looked at her. Funke''s face was even, serious in the way she was rarely serious in public. This was a real ask. The calculation was visible and Funke was not hiding it, which meant she was also not pretending the offer was anything other than what it was.\n"Why not Ngozi? Ngozi is good at Economics."\n"Ngozi explains things the way she sees them, which is not always the way I see them. You explain things the way someone sees them when they had to figure it out themselves. That''s more useful to me."\nChiamaka thought about that. She thought about what Funke was offering. Social placement, which she had been trying to build herself for four weeks with limited success because she had been doing it with Lagos performance instead of actual presence. And she thought about what it would mean to have Funke''s network. Funke knew the senior girls who controlled hostel resources, the SS3 students who could make a junior girl''s term comfortable or miserable by degrees. She knew who to ask about missing provisions and who to avoid at the back of the dining hall on Fridays.\nShe also thought about Temi.\nIt was not a complete thought. Just a shape of one. The awareness that accepting Funke''s offer would shift her position in the room in a way that would be visible, and Temi noticed visible things and had opinions about them that she did not always keep to herself.\n"I want something else," Chiamaka said.\nFunke raised an eyebrow.\n"The tuck shop. Mrs. Bello lets certain students get things on credit until their parents send money. I''ve seen it. I need to be on that list."\nA pause. Funke looked at her steadily and Chiamaka held the look without flinching, because she had made a decision somewhere between Ngozi''s garri and the fifty-one on the chemistry paper that she was done performing comfort she did not have. This was a negotiation. She was going to negotiate.\n"That''s Mrs. Bello''s decision," Funke said.\n"But you know her daughter. I''ve seen you talking to her. Senior Kemi."\nFunke was quiet for a moment. Then she did something unexpected: she looked at Chiamaka with what appeared to be genuine respect. The rare, transactional kind. "Three weeks. Economics, Mondays, Wednesdays, Fridays. After dinner."\n"Agreed," Chiamaka said.\nThey did not shake hands. It was not that kind of thing.\nAfter Funke left, Chiamaka sat with it. She turned the arrangement over in her mind and examined it from different angles the way she had learned to examine things since arriving, looking for what was solid and what would shift under pressure. Funke was practical more than she was loyal, which meant the arrangement would hold exactly as long as it was useful and not one day longer. That was fine. Chiamaka understood practical. Practical she could work with.\nWhat she could not entirely quiet was a different feeling, smaller and sitting lower. Not guilt, exactly. More like the awareness of a door opening that she had not seen in the wall before. She was not certain yet what was on the other side of it.\nShe opened her Economics textbook and started preparing Monday''s session.\nAbove her bunk, the springs were still. Temi had not come back yet.','\n',char(10)),991,1,1,NULL,'2026-04-20T12:18:58.236Z','2026-04-20 12:18:58','2026-04-20 12:18:58',NULL,1,45);
INSERT INTO "chapters" ("id","novel_id","chapter_number","title","content","word_count","is_premium","is_published","audio_url","published_at","created_at","updated_at","scheduled_release_at","part_number","season_id") VALUES(551,61,10,'What She Sold',replace('The senior girls gathered on Saturday evenings in SS3 Hostel A, Room Two, which everyone called the Parlour because someone three sets ago had draped a piece of ankara fabric over the window and the name had stayed. Funke had been bringing Chiamaka into that orbit for two weeks now, slow and deliberate, the way you introduce a new element into an existing system and watch to see how it settles.\nChiamaka had been settling well, she thought. She had learned the names and the dynamics. Senior Kemi, Funke''s contact, who was measured and watchful and whose approval moved through the group like a current. Senior Bisi, who was loud and generous and forgave things quickly. Senior Amaka, who remembered everything and forgave nothing. Three other girls whose names and functions she had filed carefully.\nThe tuck shop credit had come through on Wednesday. Mrs. Bello''s daughter had mentioned it to Mrs. Bello and Mrs. Bello had added Chiamaka''s name to a small notebook under the counter without ceremony. Chiamaka had bought a sachet of milk and a packet of cabin biscuits and walked back to the hostel feeling something she recognized as relief and something else she was less comfortable naming.\nTonight Funke had brought her to the Parlour for the third time, and it was going well. Chiamaka had positioned herself at the edge of the conversation the way she had learned to position herself in rooms, present enough to be noticed, contained enough to seem worth knowing. Senior Kemi had asked her twice about Lagos, genuine questions rather than the mocking ones from her first week, and Chiamaka had answered cleanly, without performing, and felt the room warm slightly toward her.\nThen Senior Amaka said, "Your roommate. The one with the braids. Temi."\nChiamaka looked at her. "What about her?"\n"She''s been walking around here like she has somewhere better to be since JSS1." Senior Amaka''s tone was not hostile exactly, but it had weight in it. "I''ve never understood that girl. Where does she think she''s going."\nThe room waited. This was a test, Chiamaka understood. Not a formal one, but the kind that happened constantly in rooms like this, the small measurements of loyalty and alignment that determined where you stood.\nShe should have said nothing. She knew that, in the part of herself that had been watching and learning since she arrived. She should have smiled and moved the conversation elsewhere the way Funke sometimes did, elegant and unreadable.\nInstead she said, "She got into Federal Government College, Warri. JS1. Her parents couldn''t manage the setup costs so she came here instead."\nThe room shifted. Senior Bisi made a sound of surprise. Senior Amaka sat back slightly, recalibrating.\n"FGC Warri," Senior Kemi repeated. "Merit entry?"\n"That''s what she said." Chiamaka heard her own voice delivering it and felt, even as she delivered it, the exact texture of what she was doing. The information had come out of a dark room at nine-fifteen at night, from a girl lying in her bunk talking to the ceiling, not to Chiamaka specifically but to the air, to the shared dark that made things sayable. It had not been given to her. She had just been in the room when it was released.\nAnd she had just spent it.\nThe conversation moved on. Senior Amaka looked at Chiamaka differently after that, with something that was closer to acknowledgment than anything she had given her before. Senior Kemi asked about her Economics exam preparation. The evening continued. Funke, beside her, said nothing, but Chiamaka felt the quality of Funke''s silence as something specific, a commentary without words.\nWalking back to Hostel B, Funke said, "You didn''t need to do that."\n"I know."\n"You were already in the room. You were already fine."\n"I know," Chiamaka said again.\nFunke looked at her sideways. "Amaka will use it. She uses everything. By Monday that story will have traveled."\nChiamaka did not answer. The night was warm and the compound was mostly quiet and she walked with her arms crossed over her chest not because she was cold but because she needed to hold something.\nRoom Six was half-asleep when she got back. Blessing''s breathing was already slow and even. Sade had her phone face-down on the pillow. Ngozi looked up when Chiamaka came in, registered her face, and looked back at her book without asking.\nTemi was awake. Chiamaka could tell from the quality of the stillness above her. Not the loose stillness of sleep but the held stillness of someone who was not ready to stop thinking.\nChiamaka changed into her night clothes and lay down and looked at the ceiling and felt the shape of what she had done sit in her chest like something swallowed wrong. It was not a large thing. In the architecture of secondary school social politics it was a small brick, the kind that moved in and out of girls'' conversations and lost meaning by the end of the week. She told herself that.\nThe problem was that it had come from the dark. It had come from a girl talking to the ceiling at nine-fifteen about a door that had closed before she was ready, and Chiamaka had taken it into a lit room full of people and put it on the table like it was hers to spend.\nShe pressed her eyes closed.\nAbove her, Temi turned over once and went still again.\nChiamaka lay there and thought about currency. About what you reached for when belonging felt like it was slipping. About the difference between surviving a room and deserving to be in it, and how she had spent four weeks confusing the two.\nSleep did not come easily. When it came, it was not kind.','\n',char(10)),965,1,1,NULL,'2026-04-20T12:19:48.155Z','2026-04-20 12:19:48','2026-04-20 12:19:48',NULL,1,45);
INSERT INTO "chapters" ("id","novel_id","chapter_number","title","content","word_count","is_premium","is_published","audio_url","published_at","created_at","updated_at","scheduled_release_at","part_number","season_id") VALUES(552,61,11,' The Letter',replace('The letter came on a Wednesday, which was an ordinary day in every other way.\nChiamaka saw it in the administrative block pigeonhole when she went to collect a form for Mrs. Adeyinka. Her name in her mother''s handwriting, the specific cursive her mother had been writing since before Chiamaka was born, looped and slightly rightward-leaning, the kind of handwriting that belonged to a person who had learned it carefully and never changed. She stood in the corridor and looked at the envelope for a moment before she picked it up, the way you pause before opening a door when you are not sure what is on the other side.\nShe put it in her bag and carried it through double period mathematics and through lunch and through the first half of afternoon prep, and at no point did she open it.\nNgozi noticed it at dinner. Not the letter itself but the quality of Chiamaka''s attention, the way she ate without tasting and answered questions half a beat late. "You okay?" Ngozi asked, quietly, under the dining hall noise.\n"Fine," Chiamaka said. Her default answer. It came out before she could choose something more honest.\nShe opened the letter after dinner, sitting on her bunk while the room was in its post-dinner looseness, Funke on the phone, Sade and Blessing both at their desks. She had waited until the room was occupied with itself so that she could read without being watched.\nThe letter was two pages in her mother''s handwriting. Her mother had not sent a message in four days, which Chiamaka had noticed and chosen not to examine. Now she understood the four days.\nShe read the first page slowly. The house in Lekki was going. Her mother used the word relinquished, which was a word from legal documents rather than from conversations between a mother and her daughter, and Chiamaka read it twice and understood that her mother had borrowed it from something she had been reading, some official process that had its own language. They were moving. An uncle in Surulere had a flat, two bedrooms, and they would be there by the end of the month.\nShe turned to the second page. Her father. He was not being charged, the letter said, or not yet, and the not yet was doing a great deal of work in that sentence. The business was finished. The investigation was ongoing. Her school fees for the second term were uncertain. Her mother had written the word uncertain and then written three more lines about it that made it mean something more definite than uncertain.\nThe second term fees were not coming.\nShe folded the letter on the first crease and then the second and put it back in the envelope and held the envelope in both hands and looked at her locker door.\nShe was not going to cry. She had not cried in front of this room since she arrived and she was not going to start tonight because crying was the thing that would make this moment into a story that the room carried forward, and she had watched what happened to stories that the room carried forward.\nShe breathed in through her nose. She breathed out.\nThe house in Lekki had a compound with a mango tree that dropped fruit in March. She had complained about the fruit on the driveway every March for as long as she could remember, the soft impact of it on the concrete, the ants that followed. She thought about the mango tree and the compound and then she thought about a two-bedroom flat in Surulere and her parents moving their things into it and she stopped breathing correctly.\nThe tears came without noise. That was the only mercy. She was not a loud crier, had never been, and so when it happened it was just her sitting on the bunk with the envelope in her hands and her face doing something she could not stop it from doing, quietly, in the middle of a room full of people who were looking at other things.\nShe did not know Temi had come down until she was there.\nNot close. Temi had come off the bunk and was standing at her own locker, which was on the same side as Chiamaka''s bunk, her back turned, taking a long time to find whatever she had come down to find. She did not look at Chiamaka. She opened the locker and closed it and opened it again and her back remained turned with the deliberate quality that Chiamaka recognized from the fan argument and the night talk and every other moment Temi had chosen a particular posture toward her.\nOn the desk in front of Funke, her phone screen lit up with a notification and Funke laughed at something and the sound of it covered the next thirty seconds of the room.\nBy the time Funke''s laugh faded, Chiamaka had the back of her hand against her face and was breathing again, slow and even, the practised rhythm of someone returning from somewhere they had not intended to go.\nTemi closed her locker and turned around. Her eyes moved to Chiamaka''s face for one brief moment and then she climbed back up to the top bunk and that was all.\nBut in the moment before she turned away, she put something on the small ledge of the bed frame. A travel-size pack of tissues. The blue and white kind. Placed without ceremony, without announcement, without any of the vocabulary of comfort that would have made Chiamaka need to respond to it.\nJust there.\nChiamaka looked at it for a long time. Outside the window the compound had its night sounds, the generator and the distant voices and a moth hitting the fluorescent light in the corridor. She picked up the tissues. She held them and did not open them and did not say anything and above her Temi was already still, already turned toward the wall.\nThe letter sat in her lap. The flat in Surulere waited at the end of the month. Her father''s name sat in a Punch article from August.\nShe had thought she had already hit the bottom of it. She was learning that the bottom kept moving.','\n',char(10)),1049,1,1,NULL,'2026-04-20T12:21:27.747Z','2026-04-20 12:21:27','2026-04-20 12:21:27',NULL,1,45);
INSERT INTO "chapters" ("id","novel_id","chapter_number","title","content","word_count","is_premium","is_published","audio_url","published_at","created_at","updated_at","scheduled_release_at","part_number","season_id") VALUES(553,61,12,'Room Six Fracture',replace('It started with Senior Amaka.\nChiamaka heard it from Ngozi, who had heard it from a girl in the next room, who had heard it in the dining hall on Monday morning. Senior Amaka had told the story at an SS3 gathering over the weekend, the story of Temi and FGC Warri, told the way Senior Amaka told everything, with precision and a particular relish for detail. By Monday afternoon it had traveled the full length of the hostel and folded back on itself and arrived at Room Six wearing the shape of common knowledge.\nChiamaka knew it was coming before Temi walked in.\nShe knew from the way Ngozi looked at her when she came back from class, a look that was gentle and worried in equal measure. She knew from the way Blessing closed her book and sat very still, the posture of someone who had decided to be present for something difficult. She knew from her own body, the specific tightening across her shoulders that had started Sunday night and had not left.\nTemi came in at four-fifteen.\nShe put her bag on the bunk. She stood with her back to the room for a moment. When she turned around her face was the even, controlled face she wore when she was managing something large, and Chiamaka recognized it because she had been wearing a version of that face for six weeks.\n"Who told them," Temi said. Not loud. The quietness was worse than loudness would have been.\nNobody spoke.\n"I''m asking a direct question," Temi said. "The FGC story. It was in this room. Six people. Who told it outside this room."\nChiamaka opened her mouth.\n"It was me," she said.\nThe room absorbed it. Funke looked at the wall. Blessing looked at her hands. Ngozi closed her eyes briefly, one small wince of pain for all of them.\nTemi looked at Chiamaka for a long moment. Something moved through her face that was not the hostility of the first day and was not the careful neutrality of the fan argument and was not the complicated thing from the night of the letter. It was something rawer than all of those, something that had not been processed into a posture yet.\n"Why," Temi said.\nChiamaka had been asking herself the same question for two weeks. She had answers, small ones. The room. Senior Amaka''s eyes. The need to have something to put on the table. But the answers were explanations and Temi was not asking for an explanation. She was asking for the truth beneath it.\n"I was trying to be in the room," Chiamaka said. "The senior girls'' room. I wanted them to see me differently and I used it. I shouldn''t have." She paused. "I''m sorry."\nTemi laughed. It was a short, sharp sound with nothing warm in it. "You''re sorry." She crossed her arms. "I''ve been in this school three years. Three years I''ve been the girl who goes home for Christmas and comes back and doesn''t talk about what home looks like. Three years I''ve managed what people know about me." Her voice was level but the levelness was costing her something visible. "And you''ve been here six weeks and you went into a room of seniors and handed them the one thing I didn''t hand anyone."\n"I know," Chiamaka said.\n"You don''t know." Temi''s voice finally cracked at the edge. Not breaking, just showing the seam. "You came here with your Lagos accent and your monogrammed box and your whole performance of a life you don''t even have anymore, and the one time I said something real in this room, in the dark, to no one, you picked it up and spent it like it was yours."\nThe words landed the way true things land, with a weight that didn''t scatter but settled.\n"That''s not fair," Funke said, and her voice was careful. "Chiamaka said she was wrong."\n"I''m not talking to you, Funke."\n"I know. I''m talking to the room."\nSade stood up. "Everyone should just calm down."\n"I am calm," Temi said. She said it like a door closing. She picked up her textbook from the bunk and walked out of the room and the door shut behind her, not slammed, just closed, which was its own kind of statement.\nThe room sat in the silence she left.\nAfter a moment Sade went after her, because Sade was Sade and she could not help it. Blessing gathered her book and followed, the quiet solidarity of someone who had learned that sometimes presence was the only useful thing. Funke stood and stretched and looked at Chiamaka once, without judgment but without comfort either, and went to her locker and took out her provisions and left.\nNgozi was the last one in the room.\nShe sat across from Chiamaka for a moment and looked at her with the honest, undecorated look she had been giving since the garri. "You know what you did," Ngozi said.\n"Yes."\n"Then you know what it costs."\n"Yes."\nNgozi nodded. She picked up her reading and moved to the doorway, then stopped. "The thing about this room," she said, "is that it always has to come back to itself. Six people, one space, one term. It comes back." She paused. "But it takes time. And it costs the person who broke it."\nShe left.\nChiamaka sat alone in Room Six. The evening light came through the window at its low angle and moved across the floor the way it did every evening, and the room was full of the ordinary things of six girls, the textbooks and fabric and scattered sandals, and she sat in the middle of all of it and felt the precise weight of what she had done.\nShe had arrived six weeks ago with a trunk box and a Lagos accent and the practised poise of a girl who had always been at the top of every room she had walked into.\nShe looked at the room. Empty. Silent. The accusation still in the air like a frequency that had not finished sounding.\nShe had wanted to belong here. That was the truth under everything, under the performing and the dealing and the careful social arithmetic. She had wanted to belong somewhere after the world she belonged to stopped existing.\nInstead she had broken the first real thing she''d been given.','\n',char(10)),1069,1,1,NULL,'2026-04-20T12:22:18.727Z','2026-04-20 12:22:18','2026-04-20 12:22:18',NULL,1,45);
INSERT INTO "chapters" ("id","novel_id","chapter_number","title","content","word_count","is_premium","is_published","audio_url","published_at","created_at","updated_at","scheduled_release_at","part_number","season_id") VALUES(554,62,1,'After the Silence',replace('The generator cut at six in the morning and the room woke up in stages.\nSade''s alarm first, the tinny default sound she had never bothered to change, and then the soft movements of girls finding their bearings in the early light. The routine of it was familiar by now. Six weeks had made it familiar. Sandals on the floor, the creak of lockers, someone at the small mirror adjusting something before the five-thirty bell finished its work.\nChiamaka was already awake. She had been awake since four.\nShe lay on her bunk and listened to the room assemble itself around her and did not move. Above her, Temi''s mattress shifted once, the particular creak that meant she was sitting up, and then went quiet. Across the room Ngozi moved with her usual unhurried ease. Blessing dressed with her back to everyone, as always. Nobody spoke.\nThe silence was not the comfortable silence of the night talk, the shared dark where things were said because the darkness made room for them. This silence had a shape to it. It was the shape of something that had happened and not been resolved, and everyone in the room knew its dimensions exactly because they had all been present for its making.\nChiamaka sat up.\nShe sat on the edge of her bunk with her feet on the floor and looked at the room and made herself look at it without flinching. Temi was at her locker, her back turned. Ngozi glanced at Chiamaka briefly with a look that was not warm and not cold but held. Funke was pulling her hair into a bun with the focused neutrality of someone who had decided this morning was not her business. Sade and Blessing moved around each other in the small space of the room''s center without speaking.\nShe picked up her towel and her soap and went to the bathroom.\nThe bathrooms in Hostel B were four stalls for the whole floor and in the morning they were a queue and a negotiation, but at this hour she was early enough for the second stall and she stood under the cold water and thought very clearly about one thing.\nShe had broken something. Ngozi had named it exactly. Breaking it had been her own action, her own reaching for something at the expense of someone else, and the apology she had given Temi in the room last night was true but it was not enough. An apology was a word. It was what you said when you had done the damage and were standing in it. What came after the apology was different. That was the part that either meant something or did not.\nShe stood under the cold water and made a decision.\nNot a dramatic one. She had been making dramatic decisions since she arrived and most of them had been about managing the way she appeared. This was smaller and more specific. She was going to stop. Not stop being who she was, not perform a new version of herself for the room''s benefit, but stop the architecture of it. The daily construction of an acceptable Chiamaka, the Lagos accent deployed at the right volume, the social arithmetic with Funke, the careful navigation of what she let people see. She was going to stop building the scaffold and see what was underneath.\nShe did not know what was underneath. That was the frightening part. But she was more afraid, she decided under the cold water, of spending the rest of this term in the same loop she had been in since the first day.\nShe dried off and went back to the room.\nTemi was still there, sitting on the lower bunk now with a textbook open, which was unusual because Temi usually went straight to the dining hall after dressing. Chiamaka noticed this and did not comment on it. She went to her locker and found her uniform and started to dress.\nWhen she was done she took the small package from the back of her locker. She had bought it two days ago at the tuck shop, before the fracture, before Monday''s dining hall and Senior Amaka''s story, when she had still been in the middle of doing the thing she had now undone. A packet of the plantain chips she had seen Temi eating in that first week. The kind in the yellow packet. She had bought it without a plan for it, some instinct she had not examined at the time.\nShe put it on Temi''s textbook.\nNot with a speech. Not with the apology again, which she had already given and which Temi had heard. Just placed it there and stepped back and went to get her school bag from under the bunk.\nTemi looked at it. Then at Chiamaka''s back. Then at the packet again.\nChiamaka zipped her bag and straightened and found Ngozi watching her from across the room. Ngozi''s expression had shifted by some small degree, enough to register, not enough to announce.\nAt breakfast she ate her bread and tea and sat with Ngozi and Blessing and did not fill the silence with anything. She did not perform being fine. She did not tell a Lagos story. She sat in the early morning noise of the dining hall and ate what was in front of her and thought about what the term had left.\nForty days. Approximately. Enough time for something to be built if she started now and stopped wasting material.\nShe looked at her bread and thought about her father driving too fast on the third mainland bridge, the radio up and the windows down, and how she had sat in the passenger seat then thinking the speed was the whole point and understanding now, six weeks into a Hostel B bunk in Ibadan, that the point had been the windows and the air and her father''s hand on the wheel and none of it had needed to go as fast as it did.\nShe ate her breakfast. The dining hall was loud around her. The day began.','\n',char(10)),1019,0,1,NULL,'2026-04-20 12:25:25','2026-04-20 12:23:40','2026-04-20 12:25:25',NULL,2,46);
INSERT INTO "chapters" ("id","novel_id","chapter_number","title","content","word_count","is_premium","is_published","audio_url","published_at","created_at","updated_at","scheduled_release_at","part_number","season_id") VALUES(555,62,2,'Akunna Arrives',replace('She heard the name before she saw the face.\nIt came from the corridor on a Thursday morning, carried by a JSS2 girl who was delivering a message to the class prefect, and the name moved through Chiamaka''s chest the way a familiar song moves through you when you hear it in an unfamiliar place. Akunna Eze. New transfer. SS2. Arriving Thursday afternoon.\nChiamaka sat with the information through double period Literature and did not read a single line of the text in front of her.\nAkunna Eze had been at Greenfield since JSS1. Her father ran an import business out of Apapa and her mother was a consultant for something Chiamaka had never fully understood but that required her mother to travel frequently and return with things from other countries. Akunna had been in Chiamaka''s orbit for three years, not her closest person but close enough. They had shared birthday parties and study groups and a particular brand of Lagos girlhood that involved certain shops and certain conversations and a shared understanding of how the world was organized and where they both sat inside it.\nShe had not spoken to Akunna since March, when everything began to change and Chiamaka had started managing her phone carefully, keeping conversations light, volunteering nothing.\nAfter school she went back to the hostel and sat on her bunk and waited.\nAkunna arrived at four with two bags and a box that was larger than Chiamaka''s had been and an expression of controlled displeasure that Chiamaka recognized as the Greenfield face, the one they all wore when confronted with circumstances that did not meet expectations. A housemother showed her to a room down the corridor. Not Room Six. Chiamaka noted this and did not know whether she was relieved or not.\nShe found Chiamaka before dinner.\nShe appeared in the doorway of Room Six and her face when she saw Chiamaka did a rapid sequence of things, surprise and recognition and something more complicated that resolved, on the surface, into warmth. "Chiamaka." She came in and hugged her with the easy physicality of girls who had known each other for years. She smelled like the same body spray she had been wearing since JS2. "I didn''t know you were here. Why didn''t you tell me?"\n"I didn''t know you were coming," Chiamaka said.\n"My parents pulled me from Greenfield. My father says the fees structure changed and it''s not worth it anymore." She said it lightly, the way you say things you have decided not to be affected by. She sat on the edge of Ngozi''s bunk without asking, which Chiamaka noticed, and looked around the room. "This is cozy," she said, in the tone that meant the opposite.\nNgozi was at her locker. Blessing was reading. Temi had not come back from wherever Temi went after school. Funke was on her phone.\n"Your roommates?" Akunna asked.\n"Yes," Chiamaka said.\nAkunna smiled at the room with the Greenfield smile, the social reflex that was not unkind but assumed a certain hierarchy of looking and being looked at. Funke returned it with the steady, measuring expression she gave everything new. Ngozi said a polite hello. Blessing looked up and looked back down.\nAkunna turned back to Chiamaka and her voice dropped into the frequency of Lagos familiarity. "Okay, tell me everything. Where is the best way to get internet? I''m already dying. And is the food actually as bad as it looks in these kinds of places or is there a system?"\nChiamaka looked at her.\nShe was watching herself from a slight distance, which was something she had been doing since the morning after the fracture. Watching the shape of what she was about to do before she did it. And what she was about to do, the version of herself that was assembling at the back of her throat, was the Lagos Chiamaka. The one who knew the systems and the shortcuts and could orient a new person by speaking a language they both understood.\nIt would have been easy. It was still her language. She had not stopped speaking it.\nBut Ngozi was at the locker. Ngozi who had made garri for her on a Saturday and asked nothing in return. Blessing who had said in the dark that she would go back to Makurdi and help her mother and had said it without shame. Temi, whose story she had spent in a room full of senior girls and who had put a pack of tissues on the bed frame and climbed back up without asking for anything.\n"The food has a system," Chiamaka said to Akunna. "I''ll show you. But not tonight."\nAkunna blinked. "Why not tonight?"\n"Because tonight I have Economics prep."\nAkunna looked at her for a moment, recalibrating. Something moved across her face, a brief confusion about who she was talking to. The Chiamaka she had known would have moved the Economics prep. Would have said yes immediately and rearranged everything around the social priority of a familiar face in an unfamiliar place.\n"Tomorrow then," Akunna said. "First thing."\n"Tomorrow after school," Chiamaka said. "Come find me here."\nAfter Akunna left, Funke put her phone down and looked at Chiamaka with the direct, specific attention she reserved for things that interested her. She did not say anything. She just looked, and the looking had the quality of someone updating a file they had been keeping.\nTemi came in at five-thirty. She moved through her evening routine without looking at Chiamaka, but the hostility that had defined the room''s temperature for six weeks was different now, not gone but rearranged, like furniture that had been moved in the dark.\nChiamaka opened her Economics notes.\nOutside the window, the compound was doing its evening things. Somewhere down the corridor, a girl was playing music too loudly and someone else was asking her to stop. The ordinary life of the hostel, moving around her, and she was in it, not performing it.\nThat was the difference. Small as a pin. Real as the thin mattress under her.','\n',char(10)),1016,0,1,NULL,'2026-04-20T12:24:54.912Z','2026-04-20 12:24:54','2026-04-20 12:24:54',NULL,2,46);
INSERT INTO "chapters" ("id","novel_id","chapter_number","title","content","word_count","is_premium","is_published","audio_url","published_at","created_at","updated_at","scheduled_release_at","part_number","season_id") VALUES(556,62,3,' Blessing Speaks',replace('Blessing had a way of being in a room that made you forget she was in it.\nNot because she was small, though she was, or because she was quiet, though she was that too. It was more specific than either of those things. She had perfected the art of existing at the exact frequency that rooms were tuned to ignore, and Chiamaka, who had spent six weeks being too loud in every sense, had only recently begun to notice how much Blessing saw from that frequency.\nShe saw it first on Friday, in the dining hall.\nAkunna had found Chiamaka after school as agreed and Chiamaka had taken her through the system, the tuck shop credit arrangement, the chop bar woman behind the main block, the senior girls whose goodwill was worth cultivating and the ones whose attention was better avoided. She had done it cleanly, without the Lagos performance, just information given person to person. Akunna had taken it with a slightly puzzled gratitude, still recalibrating around this version of Chiamaka.\nAt dinner they sat together and Akunna talked about Lagos the way Chiamaka used to talk about it, present tense and detailed, and Chiamaka listened and found that she could do that now, listen to it without needing to add to it or match it. At some point she looked up and Blessing was across the dining hall, two tables over, watching the interaction with a thoughtful expression that she did not hide when Chiamaka caught her eye. She just held the look for a moment and turned back to her food.\nBack in the room that evening, Chiamaka was at her desk working through a literature question when Blessing came to sit beside her.\nThis had not happened before. In seven weeks Blessing had not initiated a conversation with Chiamaka directly, not once. She had spoken in groups, answered when addressed, existed in the shared space of the room with her characteristic careful presence. But she had never come to sit beside her.\nShe had a notebook with her. She put it on the desk, not open, just placed it there as if it needed to be present for what she was about to say.\n"You''re doing it differently," Blessing said.\nChiamaka looked at her. Up close, Blessing had the particular attentiveness of someone who spent a great deal of time listening, the quality of attention that went deeper than surface interest. "What do you mean?"\n"Since last week. You''re not constructing anymore." She said it without judgment, the way she said everything, as observation rather than verdict. "You were before. When you first arrived. Building something every time you walked into a room." She paused. "Most people who come from what you came from, they either collapse or they build harder. You stopped building. I''ve been watching to see what that means."\nChiamaka put her pen down. "And what does it mean?"\n"I don''t know yet," Blessing said honestly. "That''s why I''m talking to you."\nOutside the window the nine o''clock bell was approaching. Funke was on her phone. Temi was up on her bunk. Ngozi was writing something in one of her four notebooks.\n"Your friend," Blessing said. "Akunna."\n"She''s not exactly a friend. She''s familiar."\nBlessing nodded as if this distinction was important to her. "She''s going to want you to be what you were. Not because she''s unkind. Just because that''s the version of you she knows and it''s easier for her if you stay in that shape."\nChiamaka looked at the notebook Blessing had brought to the desk. "What''s in that?"\nBlessing opened it.\nIt was a record. Not a diary, not exactly. More like a log. Dates down the left margin and beside each date a few sentences, sometimes less. Chiamaka scanned without meaning to and caught fragments. New girl from Lagos. Monogrammed box. Temi clocked it immediately. And further down: She didn''t eat the biscuit Temi left. She kept it on the ledge until morning. And later: Told Temi''s FGC story to seniors. Room fracture. She apologized without being asked.\nShe looked at Blessing.\n"You''ve been writing about me."\n"About the room," Blessing said. "You''re in the room."\n"Does everyone know you do this?"\n"No."\nChiamaka thought about how she should feel about this and found that she was not sure. There was a version of this that was an intrusion, a girl quietly cataloguing people without their knowledge. But the entries she had seen were not unkind or sensationalizing. They were just precise, the record of someone paying close attention because paying attention was how she understood the world.\n"Why are you showing me?" Chiamaka asked.\nBlessing considered this. "Because you''re at the part where you could go either way. Back to what you were or forward to what you haven''t figured out yet." She turned a page. Near the bottom was a line from two days ago: She chose Economics prep over Akunna. Something has shifted.\n"Ngozi writes stories," Blessing said. "I write observations. It''s the same thing, I think. Trying to understand people by recording them."\n"And what have you understood about me?"\nBlessing closed the notebook. She held it in both hands and looked at Chiamaka with the clear, uncomplicated directness that was, Chiamaka was beginning to understand, simply how Blessing''s face worked when she had decided to say something real.\n"That you''re braver than you think," Blessing said. "And that you keep waiting for someone to confirm it before you act like it''s true."\nThe nine o''clock bell rang. The room began its lights-out preparations. Blessing picked up her notebook and returned to her bunk and opened a textbook and was, within two minutes, exactly what she always appeared to be: quiet, contained, easy to overlook.\nBut the shape of the room had changed. Chiamaka sat at her desk after the light went out and felt it, the way you feel a shift in temperature, small enough to question but real enough to stay with you.\nBlessing had been watching all along. And what she had seen was not what Chiamaka had been trying to show.\nIt was something better.','\n',char(10)),1026,0,1,NULL,'2026-04-20T12:26:18.954Z','2026-04-20 12:26:19','2026-04-20 12:26:19',NULL,2,46);
INSERT INTO "chapters" ("id","novel_id","chapter_number","title","content","word_count","is_premium","is_published","audio_url","published_at","created_at","updated_at","scheduled_release_at","part_number","season_id") VALUES(557,62,4,'Temi''s Story',replace('The version Chiamaka heard first came from a girl in SS2B named Dolapo, who had been at the school since JSS1 and knew the history of every room in every hostel the way some people knew scripture, by heart and with feeling.\nIt was a Wednesday, two days after Blessing had opened her notebook, and Chiamaka was at the tuck shop queue when Dolapo came to stand beside her and started talking about Room Six the way people talked about rooms with histories, with the particular relish of someone who understood that a story gains something in the passing.\nShe listened without asking questions, because asking questions would have told Dolapo how little she knew and she was not ready to advertise that.\nThe version Dolapo told went like this.\nTemi had come to Queen''s Hallmark three years ago from a primary school that everyone agreed was too good for this neighborhood, the kind of school that produced children with precise diction and the ability to sit still for long periods. She had been eleven. She had come with the Federal Government College admission in her bag and the specific confidence of a child who had been told, accurately, that she was exceptional. Her parents had explained the situation on the drive from their house. The FGC setup costs had arrived the same week as her father''s salary cut. They had looked at the numbers from every angle. This school was closer. This school was manageable. This school would still get her where she needed to go.\nTemi had not argued. She was eleven and she did not argue.\nWhat she had done, Dolapo said, was arrive at Queen''s Hallmark and immediately become the best student in her class. Not gradually, not after settling in, but from the first week. Mathematics, especially. The kind of mathematics that made teachers stop mid-lesson and write to the vice principal. By the end of JSS1 she had the highest aggregate in her year. By JSS2 a teacher had submitted her name for a state-level science competition and she had placed second, which the school celebrated with an announcement at assembly.\n"So what happened?" Chiamaka asked, and then regretted asking because it confirmed that she had been listening carefully.\nDolapo looked pleased. "JSS3. The scholarship."\nThere was a federal scholarship for science students in public secondary schools. Competitive, national, the kind that covered university fees and came with a stipend. Temi had applied in JSS3. She had made it through the first round and the second and then the third, which was an interview in Abuja that her father had saved for three months to fund the travel for.\nShe had not gotten it.\nNot because her scores were insufficient. Dolapo''s voice took on the specific tone that people used when the injustice of a story was the point of telling it. There had been a quota consideration, a regional distribution clause, something administrative that had nothing to do with the numbers. The girl who received the scholarship from Ogun State had lower scores. This was known. It had been discussed. A teacher had written a letter. Nothing had changed.\nTemi had come back from Abuja and returned to class the following Monday and nobody had known what to say so mostly people had said nothing.\nChiamaka stood with her tuck shop items in her hands and looked at the wall.\n"She doesn''t talk about it," Dolapo said. "She never has. But that''s when she got the way she is. That quietness. Like she''s keeping everything inside a container."\nAfter Dolapo left, Chiamaka walked back to the hostel slowly. The afternoon was warm and the compound had its post-school looseness, girls in small groups, someone kicking a stone along the path ahead of her. She walked through all of it and thought about what she had heard and tried to place it against everything she knew about Temi.\nThe hostility from that first day. She had thought it was class resentment, the general kind, and it was that but it was also more specific. A girl who had been told she was exceptional, whose exceptional-ness had been confirmed by numbers and competitions and a federal process, and who had then watched a system ignore the numbers in favour of something else. And then a girl from Lagos had walked into her room with a monogrammed trunk box and the entire vocabulary of the life that Temi had been working toward in spite of that system.\nNot just working toward. Temi had been working toward it from a position of real loss. She had given up FGC Warri at eleven. She had watched a scholarship go to someone else at fifteen. And she was still here, still reading floor plan books, still at the top of her class, still building something out of what was available.\nWhat Chiamaka had arrived carrying was not just privilege. It was the specific shape of the thing Temi had been denied.\nShe sat on her bunk and looked at the ceiling. The underside of Temi''s mattress was directly above her, and she had been looking at it for seven weeks without understanding what it meant to be below it.\nShe thought about her father driving too fast on the third mainland bridge and how she had been sitting in the passenger seat with no awareness of how many people were on foot on the road below and how fast the world was moving for them.\nShe had not been cruel in her life. She did not think she had been cruel. But she was beginning to understand that you did not have to be cruel to cause the specific kind of damage that came from simply not knowing what other people were carrying and not thinking to ask.\nThe room was empty. She sat in it alone and let the story settle into her, not as information this time but as something that required her to reconfigure. A shape she had been feeling in the dark since that first day, finally showing her what it was.\nShe had been resenting Temi''s hostility for seven weeks.\nShe had been resenting the wrong thing entirely.','\n',char(10)),1034,1,1,NULL,'2026-04-20T12:27:20.304Z','2026-04-20 12:27:20','2026-04-20 12:27:20',NULL,2,46);
INSERT INTO "chapters" ("id","novel_id","chapter_number","title","content","word_count","is_premium","is_published","audio_url","published_at","created_at","updated_at","scheduled_release_at","part_number","season_id") VALUES(558,62,5,' The Trade-Back',replace('She went to Senior Amaka on a Thursday.\nShe had been thinking about how to do it since Wednesday, since sitting alone in Room Six with Temi''s story reorganized inside her chest like furniture that had finally been moved to where it always should have been. She had thought about it through dinner and through lights-out and through the early morning and she had arrived at the same conclusion each time. There was no clean way. There was only the direct way, which was the only kind that would mean anything.\nSenior Amaka was in the Parlour after school with two other SS3 girls, doing what senior girls did on Thursday afternoons, which was very little, performed with great authority. She looked up when Chiamaka appeared in the doorway and her expression did the small recalibration it always did when Chiamaka appeared, the acknowledgment of someone she had found useful.\n"Chiamaka." She said it with the particular warmth of girls who had decided you were worth knowing. "Come and sit."\n"I won''t stay," Chiamaka said. "I just need to say something."\nSenior Amaka waited.\n"The story I told you. About my roommate. The FGC admission." Chiamaka kept her voice even because even was the only register that would be heard in this room as something other than weakness or aggression. "I need you to let it stop."\nThe warmth in Senior Amaka''s expression became something more careful. "Stop how?"\n"Stop traveling. You know how these things move. I''m asking you to move this one back."\nA silence. One of the other girls shifted. Senior Amaka looked at Chiamaka with the clear, measuring look she had been giving since the first time Funke brought her to this room, the look that calculated value and leverage simultaneously.\n"That story is already out," Senior Amaka said.\n"I know."\n"You can''t unstory something."\n"I know that too. I''m not asking you to erase it. I''m asking you not to keep adding to it. Not to bring it to new rooms. Let it get old."\nSenior Amaka tilted her head. "You''re asking me to do something for nothing."\n"I''m asking you to do something because it''s the right thing." Chiamaka heard how that sounded in this room, idealistic and slightly naive, and she held it there anyway because retreating from it would mean she had not meant it. "I know that''s not how this works. But it''s what I''m asking."\nThe other girls were quiet. Senior Amaka looked at her for a long moment with something that was not softness but was adjacent to consideration.\n"What changed?" Senior Amaka asked.\n"I found out the whole story," Chiamaka said. "I gave you a piece of it and kept the rest without knowing I was keeping it. The rest changes what the piece means."\n"Then tell me the rest."\nChiamaka shook her head. "That''s not mine to tell either."\nAnother silence. Senior Amaka looked at her with an expression that Chiamaka could not fully read, something between respect and irritation, the look of someone who appreciated a well-made argument and resented it simultaneously.\n"I''ll think about it," Senior Amaka said finally.\nIt was not a yes. Chiamaka had not expected a yes. She nodded and left the Parlour and walked back across the compound and understood, in the walking, what Ngozi had meant when she said fixing something cost more than breaking it.\nBreaking it had cost her nothing in the moment. She had sat in a warm room and put a story on a table and received acknowledgment in return and walked out feeling like she had gained ground. The full cost had come later, in the fracture, in Temi''s voice saying you picked it up and spent it like it was yours.\nThe trade-back had cost her Senior Amaka''s goodwill, or at least a portion of it, the warmth specifically, which was the part she had been using. She had walked into that room with the social capital she had built over three weeks and she had spent it on a maybe. On Senior Amaka saying she would think about it, which in this school''s economy meant something between probably not and possibly, depending on mood and circumstances.\nFunke was in the corridor when she came back to Hostel B. She looked at Chiamaka''s face and understood something from it before Chiamaka said anything, which was typical Funke.\n"You went to Amaka," Funke said.\n"Yes."\n"What did she say?"\n"She''ll think about it."\nFunke leaned against the wall and looked at the ceiling briefly. "That cost you."\n"Yes."\n"Was it worth it?"\nChiamaka thought about Temi in Abuja at fifteen, sitting in a room with her scores in front of her and a decision that had nothing to do with her scores coming back against her. She thought about Temi returning to class the following Monday with nothing to say about it and nobody saying anything back.\n"Yes," she said.\nFunke looked at her with the expression she had given her in the tuck shop corridor, the one that updated a file. Then she pushed off the wall and fell into step beside her toward the staircase.\n"Amaka respects things that cost people something," Funke said, not looking at her. "She won''t say that. But she does. You going there and asking directly, without offering anything, that registered." She paused. "She''ll let the story get old."\nChiamaka looked at her. "How do you know?"\n"Because I know Amaka." Funke shrugged. "And because you asked the right way. Not begging. Not bargaining. Just asking and explaining. She respects that more than currency."\nThey climbed the stairs in silence. At the top floor, before they reached the room, Funke stopped.\n"You''re different," Funke said. "From when you came."\n"I know," Chiamaka said.\n"I''m not sure I helped with that. Some of the ways."\nIt was the closest thing to an apology that Funke''s particular constitution allowed. Chiamaka recognized it for what it was.\n"We helped each other figure things out," Chiamaka said. "I think that''s what this term has been."\nFunke considered this and then made a small sound of agreement and pushed the corridor door open and they walked into the ordinary Thursday evening of Hostel B, which was loud and warm and full of girls who did not know or care about the conversation that had just happened, and that was fine.\nSome things did not need an audience to be real.','\n',char(10)),1077,1,1,NULL,'2026-04-20T12:28:15.701Z','2026-04-20 12:28:15','2026-04-20 12:28:15',NULL,2,46);
INSERT INTO "chapters" ("id","novel_id","chapter_number","title","content","word_count","is_premium","is_published","audio_url","published_at","created_at","updated_at","scheduled_release_at","part_number","season_id") VALUES(559,62,6,'Aunty Remi''s Kitchen',replace('The punishment was for missing lights-out.\nIt was a Friday and Chiamaka had been in the library finishing a literature essay that was due Monday, and she had looked up from the text at what she thought was eight-forty and turned out to be nine-twenty, and by the time she reached Hostel B the corridor lights were already dimmed and Aunty Remilekun was standing at the top of the staircase with the specific stillness of a woman who had been waiting and had opinions about the waiting.\n"Name," Aunty Remi said, even though she knew the name.\n"Chiamaka Obi. SS2."\n"Library."\n"Yes ma. I was finishing a literature essay."\nAunty Remi looked at her for a long moment with the expression she wore for everything, which was the expression of someone who had heard every possible explanation and had stopped finding any of them interesting. "Saturday morning. Six o''clock. My kitchen. You''ll help Mama Ngozi with the weekend cooking prep."\nShe turned and walked back to her office and that was it.\nThe kitchen attached to the housemother''s quarters was not the school kitchen, which was an industrial space behind the dining hall that smelled of stock fish and old cooking oil. This was a smaller room at the back of Aunty Remi''s flat, with a window that looked out onto the side of the hostel building and caught the morning light in a particular way that made the whole space feel warmer than the rest of the school''s architecture.\nMama Ngozi, who was not Ngozi''s mother but a woman who had worked in this kitchen for eleven years and had received the name from some earlier generation of students, was already there when Chiamaka arrived at six. She was a broad, unhurried woman who assigned tasks without preamble. She put Chiamaka to work washing beans and then told her to start sorting rice and Chiamaka did both without complaint because complaint was not an available option and also because there was something about the kitchen at six in the morning, the light and the quiet activity, that asked for a particular kind of presence.\nAunty Remi appeared at seven.\nShe came in through the inner door in a house dress and flat slippers, which was a different Aunty Remi from the corridor Aunty Remi, and she poured herself tea from a flask on the counter and sat at the small table by the window and looked at Chiamaka sorting rice with the calm of someone observing something that did not require her commentary.\nThey were quiet for several minutes. Mama Ngozi moved between the cooker and the counter. Outside, the hostel was beginning its Saturday sounds, distant and unhurried.\n"Lagos girl," Aunty Remi said finally. Not unkindly.\n"Yes ma."\n"Mid-term transfer."\n"Yes ma."\nAunty Remi drank her tea. "I''ve been at this school nineteen years. I was here before the new classroom block, before the second hostel, before the current principal." She said it without pride, just as a statement of duration. "I''ve watched a lot of girls come into this place from places that did not prepare them for this place."\nChiamaka kept her hands moving through the rice, feeling for stones, the way Mama Ngozi had shown her.\n"Some of them fight it the whole term," Aunty Remi continued. "Fight the food, fight the schedule, fight the other girls. Use all their energy fighting the fact that they are here instead of somewhere else." She paused. "Some of them learn something. Not many, but some."\n"Which am I?" Chiamaka asked, and then wondered if the question was too direct for this kitchen, for this hour.\nAunty Remi looked at her over the rim of her cup. "You''re somewhere in the middle still. You were fighting at the beginning. Something changed recently." She tilted her head. "What changed?"\nChiamaka thought about how to answer. She had been answering versions of this question since the morning after the fracture, from Funke, from Blessing, from herself in the mirror above the bathroom sink. She had different answers depending on who was asking.\n"I found out I was wrong about some things," she said. "Not small wrong. The kind of wrong that means you have to go back to the beginning and look at everything again."\nAunty Remi nodded slowly. "Your father."\nChiamaka''s hands stilled in the rice.\n"I don''t read newspapers," Aunty Remi said. "But people talk. And I''ve been watching you since you arrived and I know the shape of a girl who is managing a story that is bigger than school." She was not gentle about it exactly, but she was not harsh either. She was precise in the way of people who had no patience for softening truths but understood that truth had weight. "The question I ask every girl who comes here carrying something like that is this. What are you going to do with it."\n"I don''t know yet," Chiamaka said.\n"That''s the right answer," Aunty Remi said. "The wrong answer is the one I usually get, which is the name of a plan that is really just the old life with different packaging." She set down her cup. "Your father made his choices. You are not your father''s choices. You are also not your father''s advantages. Both of those things are true at the same time and most people only accept one of them."\nMama Ngozi put a pot on the cooker and the room filled briefly with the sound of water and heat.\nChiamaka looked at the rice in the bowl in front of her. All those small grains, sorted from the stones, made ready. She had been doing it for forty minutes without thinking about it as anything more than the task at hand and now she was thinking about it differently, the patience of it, the willingness to go through everything piece by piece and remove what should not be there.\n"My mother is in Surulere now," Chiamaka said. "They moved last month."\n"I know," Aunty Remi said.\n"I haven''t told anyone here. Except it came out with my roommates because of a letter." She paused. "I think I was ashamed of it."\n"And now?"\nChiamaka thought about Ngozi''s four notebooks and Blessing''s story about Makurdi and Temi''s floor plans for houses on her street. About how each of them had something they carried and none of them had let the carrying define the ceiling.\n"Now I think shame is expensive," she said. "And I''ve been spending things I can''t afford."\nAunty Remi was quiet for a moment. Then she made a sound that was not quite a laugh but was the closest thing to warmth her face had produced in Chiamaka''s presence. "Finish the rice," she said. "Then you can go."\nChiamaka finished the rice. She washed her hands at the small sink and dried them on the cloth Mama Ngozi handed her and turned to leave and then stopped.\n"Aunty."\nAunty Remi looked up from the table.\n"Thank you," Chiamaka said. "For the punishment."\nAunty Remi picked up her cup and looked out the window at the morning light on the hostel wall and said nothing, which was its own kind of answer.\nChiamaka walked back through the corridor and up the stairs and into the Saturday morning of Hostel B, and the walk felt different from the walk down, not lighter exactly but more deliberate, like someone who had been given directions to a place they had been trying to find without a map.','\n',char(10)),1256,1,1,NULL,'2026-04-20T12:29:06.043Z','2026-04-20 12:29:06','2026-04-20 12:29:06',NULL,2,46);
INSERT INTO "chapters" ("id","novel_id","chapter_number","title","content","word_count","is_premium","is_published","audio_url","published_at","created_at","updated_at","scheduled_release_at","part_number","season_id") VALUES(560,62,7,'Funke Falls',replace('The results went up on a Tuesday and Funke did not go to look at them.\nThis was unusual enough that Chiamaka noticed it before she noticed anything else. Every other SS2 student had made the trip to the notice board outside the vice principal''s office by ten o''clock. The first-term exam results had been promised for this week and their arrival had changed the atmosphere of the school the way pressure changes before rain, everyone alert and moving toward the same point.\nFunke stayed in the room during morning break with a textbook open in front of her that she had not turned a page of in twenty minutes.\nChiamaka looked at her from across the room and then looked away and then made a decision.\n"I''ll walk with you," she said.\nFunke did not look up. "I''m reading."\n"You haven''t turned that page since I came in."\nA pause. Funke closed the textbook with the careful deliberateness of someone who had been found out and had decided the dignified response was to stop pretending. She stood up and straightened her uniform and Chiamaka fell into step beside her and they walked to the notice board without discussing it.\nThe list was posted in the format the school always used, class positions and raw scores side by side, public in the specific way of schools that believed visibility was its own kind of motivation. Chiamaka found her name and kept her face neutral. She had done better than the fifty-one. Much better. The studying had been real and the results were real and she filed that away for later.\nThen she looked for Funke''s name.\nFunke was looking at it too. Chiamaka could see the moment she found it from the quality of the stillness that came over her face, a particular kind of stillness that was not the composed, strategic stillness Funke usually wore but something rawer, the stillness of a person absorbing a number they had been afraid of.\nSeventeenth out of twenty-three. Economics specifically, which Chiamaka saw on the subject breakdown sheet pinned beside the main list, a score that sat below the pass mark in a subject Funke needed for the commercial track she had told Chiamaka about once, briefly, on a Wednesday evening after their third Economics session, the track that led to the accounting degree her mother had been referencing since Funke was twelve.\nThey stood there for a moment. Around them, girls came and went, exclamations and the particular compressed sounds of people receiving news they had hoped would be different.\nFunke turned and walked back toward the hostel and Chiamaka walked beside her and said nothing because there was nothing to say that Funke''s dignity would be able to receive right now, in this corridor, in front of everyone.\nBack in the room, Funke sat on her bunk and put her hands in her lap and looked at them. It was such an unFunke posture, that stillness without strategy, that Chiamaka found it more affecting than tears would have been.\n"I thought the sessions helped," Funke said. Her voice was even but thin.\n"They did help," Chiamaka said. "You were at forty-one before we started."\nFunke laughed once, without warmth. "Forty-one to fifty-three. Still below pass."\n"Three weeks of sessions against a full term of being behind. The sessions were real work, Funke. The problem was the term, not the three weeks."\n"That''s a nice thing to say."\n"It''s a true thing."\nFunke was quiet. Outside the window the bell rang for the end of break and feet moved along the corridor and the room absorbed the sound and went quiet again.\n"My mother is going to call on Friday," Funke said. "She calls every Friday. She''s going to ask about Economics because she always asks about Economics." She paused. "I''ve been telling her it was going fine."\nChiamaka sat on the edge of her own bunk, across from Funke, at the same level. Not standing over her. Not at a distance. Just present in the space.\n"You can tell her the truth," Chiamaka said.\n"You don''t know my mother."\n"No. But I know about telling people things are fine when they are not." She held Funke''s look. "It''s exhausting. And it doesn''t protect them. It just moves the conversation to a place where the truth is harder to say when it finally has to come out."\nFunke looked at her for a long moment. Something shifted in her face, the composed surface of it giving way briefly to the thing underneath, which was the face of a seventeen-year-old girl who had been running a room and managing a reputation and holding herself together with performance for longer than anyone in that room had probably understood.\n"She wanted better for me than she had," Funke said. "That''s the thing. She worked for the fees every term and she never complained and she has this idea of who I''m going to become." She stopped. "I didn''t want to be the thing that disappointed the idea."\n"You''re not the idea," Chiamaka said quietly. "You''re the person. The person can fail an exam and sit with her mother on the phone on Friday and say it didn''t go well and still become something real. The idea can''t do any of that."\nThe room was very still.\nFunke looked at her with an expression Chiamaka had not seen on her before. Not the measuring look or the strategic warmth or the composed neutrality. Something genuinely unguarded, the look of someone who had been seen more clearly than they expected and was not sure whether to retreat from it.\nShe did not retreat.\n"Will you sit with me on Friday," Funke said. "When I call her."\n"Yes," Chiamaka said.\nFunke nodded. She reached into her locker and took out her Economics notes and put them on the bed in front of her, the full set, every session, and she opened the first page.\n"Show me what I missed," she said. "Not to pass the supplementary. I want to actually understand it."\nChiamaka pulled her own notes from under her mattress. She moved to sit beside Funke on the bunk and opened to the first unit and started from the beginning, and the room held them both in its ordinary afternoon light while they worked through the thing that had not been finished the first time.','\n',char(10)),1069,1,1,NULL,'2026-04-20T12:30:01.083Z','2026-04-20 12:30:01','2026-04-20 12:30:01',NULL,2,46);
INSERT INTO "chapters" ("id","novel_id","chapter_number","title","content","word_count","is_premium","is_published","audio_url","published_at","created_at","updated_at","scheduled_release_at","part_number","season_id") VALUES(561,62,8,'Temi and the Rain',replace('The rain came on a Wednesday afternoon without the usual warning.\nNo gathering of clouds that morning, no shift in the air that Chiamaka had learned to read over the weeks, just the sky going suddenly and completely serious at two-fifteen and opening. By the time the last period ended it was a full rain, the kind that had opinions about where you were going and when.\nHalf the school sheltered in the classroom blocks waiting it out. Chiamaka had stayed back to return a borrowed textbook to the class shelf and was standing under the narrow overhang outside the SS2 block watching the compound turn to running water when she realized Temi was standing six feet to her left doing the same thing.\nThey had not been alone together since the fracture.\nIn the room there was always the buffer of other people, the ordinary activity of six girls that gave them both something to look at besides each other. In class they sat in different rows. In the dining hall there was always noise and movement. But here the rain had built a temporary wall around this particular overhang and there was nowhere else to look.\nChiamaka looked at the rain.\nTemi looked at the rain.\nA minute passed. The water coming off the overhang edge was a solid curtain. Somewhere across the compound a girl made a decision and ran for it, her uniform immediately dark with water, and she disappeared into the hostel block shrieking.\n"She''s going to regret that in about four minutes," Temi said.\nIt was not directed at Chiamaka exactly. It was said to the rain, to the general air. But it was said.\n"Her mattress will be wet for two days," Chiamaka said.\nA pause. The rain intensified briefly and then settled into itself.\n"You got the highest score in SS2 for the mock," Temi said.\nChiamaka turned to look at her. Temi was still watching the compound.\n"How do you know?"\n"Mrs. Obiora told my row as an example. She didn''t say your name but she described you." A beat. "New student, mid-term entry, significant improvement from diagnostic to mock. There''s only one person that is."\nChiamaka looked back at the rain. "I worked for it."\n"I know." Temi said it simply. "I could hear you studying. Most nights I was awake when you finally turned the torch off."\nThis information rearranged something. All those nights under the blanket with the torch, the quadratic equations and the bonding diagrams and the literature annotations, she had thought she was doing it in private. The person above her had been awake the whole time, listening to the sound of her working.\n"The chemistry," Temi said. "The bonding section. You were on it for four nights straight. I could hear you writing."\n"I was failing it," Chiamaka said. "I needed to understand it from the base up."\n"Did you?"\n"Eventually. It clicked on the fourth night. Around midnight."\nTemi was quiet for a moment. Then she said, almost to herself, "It always happens like that. Not gradually. Just one moment where the whole thing makes sense at once."\nChiamaka looked at her profile, the box braids pulled back the way she wore them for school, the particular angle of her chin when she was thinking. She had been looking at this profile from the bottom bunk for eight weeks and she had spent most of that time reading hostility into it and she was understanding now that hostility had been only one layer.\n"I''m sorry," Chiamaka said. "For the FGC story. I''ve said it before and I know saying it again doesn''t change what happened but I want to say it again without the fracture around it. Without the room. Just directly."\nTemi did not answer immediately. The rain ran along the overhang edge.\n"Dolapo told you the rest of it," Temi said. It was not a question.\n"Yes."\n"She tells everyone eventually. She can''t help it. She loves a complete story." There was no bitterness in it, just the recognition of a fact. "So you know about Abuja."\n"Yes."\nTemi pressed her lips together briefly. "The worst part was not the scholarship. The worst part was that I had already imagined the university. I had a whole picture of it. The department, the studio spaces, the kind of work I was going to do." She stopped. "You make pictures like that and then someone removes the ground from under them and the pictures just float there with nowhere to land."\nChiamaka thought about a koi pond and a cooler bag and a third mainland bridge with the windows down. About the pictures she had been carrying that no longer had ground under them.\n"I know that feeling," she said.\nTemi turned and looked at her. A full look, not the measuring look from week one, not the controlled look from the fracture. Just a direct look from one person to another who had said something true.\n"I know you do," Temi said.\nThe rain began to ease. Not stop, just pull back from its intensity into something lighter and more manageable. Across the compound the compound revealed itself again in pieces, the path to the hostel, the chop bar woman dragging her table back under cover, a palm tree with its fronds still running water.\nThey did not say anything else. There was no resolution offered and no resolution taken. But the silence that came after was different from every silence they had shared in eight weeks. It had no hostility in it. It had no performance. It was just two girls standing under a narrow overhang in Ibadan while the rain finished saying what it had come to say.\nWhen the rain softened enough, Temi stepped out first. Chiamaka followed. They walked back to the hostel on the same path, not together exactly, but no longer apart.','\n',char(10)),985,1,1,NULL,'2026-04-20T12:31:17.502Z','2026-04-20 12:31:17','2026-04-20 12:31:17',NULL,2,46);
INSERT INTO "chapters" ("id","novel_id","chapter_number","title","content","word_count","is_premium","is_published","audio_url","published_at","created_at","updated_at","scheduled_release_at","part_number","season_id") VALUES(562,62,9,' End of Term Prep',replace('The end of term announced itself in small ways before it arrived officially.\nProvision boxes began to empty without being restocked. Girls started making calculations about what to finish and what to carry home, the specific arithmetic of leaving. The laundry lines behind Hostel B had a different quality on Saturday morning, fewer items, things being washed and folded for packing rather than for another week of wearing. The notice board outside the vice principal''s office had a new sheet with the closing ceremony program and the bus departure schedule, and girls clustered around it in twos and threes and made plans in the particular way of people who could already see the end of something.\nChiamaka read the departure schedule on a Monday and felt the information land differently than she had expected.\nFive days.\nShe had been counting toward the end of term since the first week, when it had seemed impossibly far away. She had counted through hunger and the fracture and the rain with Temi and Funke''s Friday phone call, which had happened and been difficult and then been okay, Funke''s mother''s voice coming through the phone in pieces while Chiamaka sat beside her on the bunk and said nothing but was there. She had been counting toward this week like it was a destination.\nNow it was here and she understood that she did not know what it meant.\nHome was a two-bedroom flat in Surulere she had never seen. Her mother had sent a photo in November, a WhatsApp image of the sitting room with afternoon light coming through a window, everything arranged carefully, her mother''s hand visible at the edge of the frame adjusting a curtain. Chiamaka had looked at the photo for a long time and written back it looks nice and her mother had sent a heart emoji and that had been the whole conversation.\nHer father was in the photo too. Not visible, but present in the things that were missing. The large television from the Lekki house. The particular armchair he had owned since before Chiamaka was born. The side table with the glass top where he had kept his newspapers. None of those things in the Surulere sitting room. Her mother had arranged what there was carefully and it looked like someone''s home but not yet like her parents'' home.\nShe thought about all of this standing at the notice board on Monday and then went back to class.\nThe room that evening was different. Everyone was packing in stages, not completely, but beginning the mental process of dismantling the term. Sade had taken down the photos from her bed frame and was stacking them with rubber bands. Akunna, who had started spending evenings in Room Six more often, was sorting things into piles on the extra bunk with quiet efficiency. Ngozi was at her desk but her notebooks were stacked and ordered instead of spread, the posture of someone finishing rather than working.\n"What is everyone going home to?" Funke asked from her bunk, in the tone she sometimes used now, the new one that was still Funke but without the performance underneath it.\nIt was the kind of question that could have been deflected. A few weeks ago in this room it would have been deflected, laughed past or redirected toward something safer. But the room had changed. They all knew it had changed. Eight people in a space long enough will either harden against each other or soften toward something more honest, and Room Six had taken the second path, slowly, at great cost, one episode at a time.\n"My grandmother''s house in Ibadan," Ngozi said. "Same as always. I love it. She cooks for three days straight when I arrive."\n"Benin," Blessing said. "My mother expanded the shop. She wants me to see it."\n"Lagos," Sade said simply, and smiled the way people smile when a word is enough.\n"Lagos," Akunna said.\n"Ibadan," Temi said from her bunk. "Twenty minutes away and I haven''t been since resumption. My mother is already making a list of things she wants me to bring back next term."\nEveryone looked at Chiamaka.\n"Surulere," she said.\nShe had not said it out loud before, not to the room, not in the easy social way. She had said Lekki all term, the word sitting in her mouth like the address of a place that still existed in the sense that mattered. But Lekki was where she had come from. Surulere was where she was going.\n"My parents moved this term," she said. "I haven''t seen the new place yet."\nThe room received this without drama. Ngozi nodded. Blessing looked up and looked back down. Funke said nothing but the quality of her silence was kind.\n"Is that okay?" Ngozi asked. Not loudly. Just placing the question in the room for whoever needed to answer it.\nChiamaka thought about it with the honesty she had been practising since the morning after the fracture, the willingness to look at the actual shape of things rather than the shape she preferred them to have.\n"I don''t know," she said. "I think it will be. But I don''t know yet because I haven''t been there and I haven''t been there because I don''t know how to walk into it." She paused. "Which is the same problem I had at the start of this term, now that I say it out loud."\n"Except you''re better at walking into things now," Temi said from above her.\nIt was so direct and so clean that the room went briefly quiet with it.\nChiamaka looked at the ceiling. She felt the weight of Temi''s mattress above her, familiar as her own breathing by now, and she thought about five days and a bus and a Surulere flat with afternoon light through a curtain.\n"Yes," she said. "I think I am."','\n',char(10)),982,1,1,NULL,'2026-04-20T12:32:06.118Z','2026-04-20 12:32:06','2026-04-20 12:32:06',NULL,2,46);
INSERT INTO "chapters" ("id","novel_id","chapter_number","title","content","word_count","is_premium","is_published","audio_url","published_at","created_at","updated_at","scheduled_release_at","part_number","season_id") VALUES(563,62,10,'Season 2, Episode 10 — What Ngozi Knew',replace('It came out on a Wednesday evening, three days before closing ceremony, the way confessions come out at the end of things, when the weight of carrying them finally exceeds the weight of saying them.\nThey were doing what the room had been doing all week in small increments, packing and sorting and dismantling the careful arrangements of a full term. Ngozi was going through her locker with the methodical attention she brought to everything, wrapping things in cloth, stacking her four notebooks at the bottom of her bag with a care that was not precious but was deliberate.\nChiamaka was folding her uniforms on her bunk. The trunk box was open beside her. She had been thinking about what it meant to pack it going back, how different the objects felt from when she had arrived, the same tin of Milo, almost finished now, the same garri bag her mother had packed, long empty. The box was lighter. She was not sure yet whether she was lighter too or just differently weighted.\n"I need to tell you something," Ngozi said.\nShe said it to her locker, still facing away, which told Chiamaka before anything else that it was going to be something real.\n"Okay," Chiamaka said.\nNgozi turned around and sat on her own bunk with her hands on her knees, the posture of someone who had decided. The room was quiet. Funke was down the corridor. Temi had gone to return library books. Sade and Blessing were at the bathroom. It was the two of them, which Chiamaka understood was not accidental. Ngozi had waited for this.\n"I knew about your family before I offered you the garri," Ngozi said.\nChiamaka went still with a folded uniform in her hands.\n"My mother told me before resumption. She heard it from a woman in her prayer group whose husband knows people at the ministry. The Obi Construction contract. Your father." Ngozi looked at her steadily. "She mentioned it because she said there might be a girl from that family at this school and I should be kind to her without making her feel pitied."\nThe room held this.\n"So from the first day," Chiamaka said.\n"From the first day."\nChiamaka looked at the uniform in her hands. She put it down slowly on the bunk and thought about the first Sunday, the provision boxes, the way Ngozi had stood at her locker with her back turned while Chiamaka arranged five items into a space built for much more. All those weeks of carefully not watching. The garri on a Saturday afternoon, made properly, with the good groundnut and the right amount of water.\n"The way you didn''t look," Chiamaka said. "When I was opening my box. I thought you were being polite."\n"I was being polite," Ngozi said. "But not accidentally. I knew what I was doing."\n"And the garri."\n"I made enough for two on purpose. I watched you that first week and I could see you weren''t going to ask. You were going to manage it into the ground before you asked." A small pause. "I knew someone like that once. A girl at my primary school. She was hungry for a month before anyone noticed because she was so good at performing not-hungry. I never forgot that."\nChiamaka looked at her. Fifteen years old and she had been moving through this term with that kind of attentiveness, the specific watchfulness of someone who had learned that the people who needed help most were often the ones performing needing nothing.\n"Why are you telling me now?" Chiamaka asked.\nNgozi considered this. Outside the window the early evening light was doing what it did in this last week of term, falling differently, the specific quality of late light in a place you are about to leave.\n"Because you spent this whole term thinking you were navigating alone," Ngozi said. "Figuring things out by yourself, making mistakes by yourself, fixing them by yourself. And some of that was real and it matters that you did it." She paused. "But I want you to know that you were also being looked out for from the beginning. Not in a way that took anything from you. Just a bowl of garri. Just someone making sure you didn''t disappear."\nChiamaka felt something move through her chest. Not the sharp feeling of the fracture or the cold feeling of the letter or the complicated feeling of Temi''s story. Something slower and warmer than all of those. The feeling of understanding that you have been held somewhere you thought you were falling.\n"I was so awful in the beginning," Chiamaka said. "The Lagos performance. The dealing with Funke. What I did with Temi''s story."\n"Yes," Ngozi said simply. Not dismissing it and not dwelling on it. Just yes.\n"And you just kept giving me garri."\nNgozi smiled. The full, warm smile that she had been giving since week one, the one that Chiamaka had initially read as naivety and had slowly understood was something much more considered. "I''m a writer," Ngozi said. "I told you. I write stories where things go wrong and then better. The kind that costs something." She tilted her head. "I suppose I wanted to see yours go better."\n"That''s a terrible reason to help someone."\n"It worked though."\nChiamaka laughed. A real one, unguarded, the kind she had not heard from herself in so long that the sound of it in the room surprised her.\nNgozi reached under her mattress and pulled out one of her four notebooks. She held it out across the space between the bunks.\nChiamaka took it. She looked at the cover, a plain blue exercise book, and then at Ngozi.\n"It''s the room," Ngozi said. "This term. I''ve been writing it since week one." She paused. "You don''t have to read it now. But I want you to have it. So that when you''re in Surulere and it''s different from what you expected, you can remember that you did something real this term. Even the bad parts. It all happened and it all counts."\nChiamaka held the notebook in both hands. The weight of it was slight, just paper and ink, but it felt like something that required two hands.\n"You know you''re extraordinary," Chiamaka said quietly.\nNgozi shook her head. "I''m just paying attention." She stood up and went back to her locker and resumed packing with her usual unhurried ease, as if she had just said something small rather than something that had rearranged the entire shape of the term.\nChiamaka sat with the notebook in her lap and looked at the room. Her trunk box open. The thin mattress that had become, somewhere between week one and now, simply her mattress. The underside of Temi''s bunk above her, which she knew the way you know any ceiling you have spent a term looking at.\nShe put the notebook carefully at the bottom of her trunk box, beneath the folded uniforms, and went back to packing.','\n',char(10)),1174,1,1,NULL,'2026-04-20T12:32:58.340Z','2026-04-20 12:32:58','2026-04-20 12:32:58',NULL,2,46);
INSERT INTO "chapters" ("id","novel_id","chapter_number","title","content","word_count","is_premium","is_published","audio_url","published_at","created_at","updated_at","scheduled_release_at","part_number","season_id") VALUES(564,62,11,'Six Girls',replace('Nobody planned it.\nThat was the thing about the best conversations in Room Six. They did not begin with intention. They began with one person saying a small thing into the air and the room deciding, collectively and without announcement, to take it somewhere.\nIt started with Sade.\nShe was lying on her bunk at nine-fifteen, the term''s last lights-out, and she said, to no one in particular, "I failed Mathematics."\nThe room had known. The results had been up for two weeks. But she had not said it out loud until now, in the dark, the night before the buses came, and the saying of it changed its weight.\n"I know," Funke said from across the room. "I saw."\n"My father is going to take my phone for a month," Sade said. Not with self-pity, just with the flat accuracy of someone reporting a weather forecast. "He has a system. One week per failed subject. Mathematics counts as four because he is an engineer and he takes it personally."\n"That''s not a system," Blessing said. "That''s a sentence."\n"Same thing in my house."\nA brief silence, not uncomfortable. Outside the window the compound had its last-night sounds, girls in other rooms doing what this room was doing, the particular noise of an ending.\n"I cried the first week," Blessing said. "I didn''t tell anyone. I went to the bathroom at five-thirty every morning for the first five days and I stood under the water and cried because I was so sure I had made a mistake. Taking the scholarship. Leaving Makurdi. All of it."\n"And then?" Ngozi asked.\n"And then I decided that if I had made a mistake I would make it all the way and see where it went." A pause. "It didn''t go badly."\n"You topped Biology," Temi said from the top bunk. "You didn''t just pass. You topped it."\n"I know," Blessing said quietly. "My mother is going to put it on the shop wall. She told me already."\n"That''s embarrassing," Funke said.\n"I know," Blessing said. "I''m going to let her."\nAnother silence, warmer this time.\n"I almost didn''t come back," Funke said.\nThe room waited.\n"After the results. First term results. Two years ago. I was seventeenth then too, and my mother and I had a conversation and I thought about asking to leave. Going to a school in Lagos closer to home where I could catch up." She paused. "I didn''t because I was too proud to admit I was struggling. The same pride that kept me from asking for help early enough this term." She exhaled. "Interesting how the same thing can keep you in a place and keep you from being honest about why you''re there."\nChiamaka listened to this and thought about the word pride and everything she had spent it on since September.\n"Ngozi," Sade said. "Tell us something true."\nNgozi was quiet for a moment. Chiamaka could picture her lying on her back the way she often did in the dark, hands folded, looking at the ceiling with the particular calm of someone who was always thinking something considered.\n"I am afraid," Ngozi said, "that the stories I write are the best thing about me and that everything else is ordinary." A beat. "And I''m afraid that when I finally show someone the stories they will agree."\n"That''s not going to happen," Blessing said immediately.\n"You don''t know that."\n"I know the four notebooks. I''ve seen you write. Ngozi." Blessing''s voice had the precision of someone saying something they had been holding for a while. "You are going to be read by people who don''t know you. Real people who picked up a book because it was on a shelf and had no reason to love you first. And they are going to love what you made."\nThe room received this with the specific silence of people who knew they had just heard something that was exactly true.\n"Temi," Funke said, after a while.\nThe springs above Chiamaka shifted slightly.\n"I''m going to get the architecture scholarship," Temi said. "The federal one. There''s a second window in university application. I''ve been reading about it since October. The qualification criteria changed this year. I qualify." Another pause, smaller. "I found out two weeks ago and I haven''t told anyone because I didn''t want to want it out loud before I knew if I could have it."\n"You can have it," Chiamaka said.\n"You don''t know that either," Temi said. But the way she said it was not the way she said things in September, not the closed-door flatness of the first weeks. It had room in it. Space for the possibility that someone saying a thing might mean it.\n"You''re right," Chiamaka said. "But I know your scores. I''ve been in the same class as you for one term and I''ve seen every result on that board and I know what your scores say about what you can do." She paused. "Want it out loud. You''ve earned wanting it out loud."\nThe room held this.\n"Chiamaka," Ngozi said softly.\nThe whole room knew it was her turn. Even the dark seemed to settle differently, the way it did when something had been building for a long time and the building was finally done.\nShe thought about what was true. Not what was manageable or presentable or safe to say at the end of a term in a room where she had to come back next year. What was actually true.\n"I came here thinking this school was something that had happened to me," she said. "A punishment. A consequence of something my father did that I didn''t choose and didn''t deserve." She stopped. "And it was the best thing that happened to me. Not because it was easy. Because it was honest. Because I could not perform my way through it the way I had performed through everything before and so I had to find out who I actually was without the performance."\nShe felt the room breathing around her.\n"I don''t know who that is yet. Fully. But I know she''s braver than the girl who came off that bus in September. And I know she knows what a real room feels like. Not a room you''ve conquered or managed or navigated. A room that held you even when you didn''t deserve it."\nNobody spoke for a long time.\nThen Sade said, quietly: "This is the best room I''ve ever been in."\nAnd nobody argued with that, because there was nothing to argue with. It was true in the simple, complete way that the best true things were. Six girls in one space, one term, everything it had cost and everything it had given, and none of them the same as when they had arrived.\nAbove Chiamaka, Temi''s hand appeared at the edge of the top bunk. Not reaching down, just resting there at the border between the two bunks, open and still.\nChiamaka looked at it in the dark. Then she reached up and touched it once, briefly, two fingers against a palm.\nTemi did not move her hand away.\nThe room went quiet. The compound outside settled into its deep night sounds. One by one the girls'' breathing slowed and deepened, finding the rhythm of sleep, and Room Six held them all in its ordinary walls that had become, over one full term, something none of them had the right word for but all of them would spend the rest of their lives recognizing when they felt it again.','\n',char(10)),1264,1,1,NULL,'2026-04-20T12:34:06.932Z','2026-04-20 12:34:07','2026-04-20 12:34:07',NULL,2,46);
INSERT INTO "chapters" ("id","novel_id","chapter_number","title","content","word_count","is_premium","is_published","audio_url","published_at","created_at","updated_at","scheduled_release_at","part_number","season_id") VALUES(565,62,12,'Her Side',replace('The buses were at eight.\nChiamaka woke at five without an alarm, which had been happening since the third week of term, her body having quietly adopted the school''s schedule without asking her permission. She lay still for a moment in the familiar dark and listened to the room breathe.\nEveryone was still asleep. Temi above her, the known weight of her. Ngozi across the room with her four notebooks already packed and her bag zipped at the foot of her bunk. Funke on her side, one arm hanging off the edge the way she always slept. Blessing small and still. Sade with her phone face-down on the pillow even in sleep, even on the last morning.\nShe sat up slowly and looked at the room in the early light.\nThe walls were the same walls. The floor was the same floor. The ceiling fan turned at its one speed in its one direction. Six months ago this room had been the end of everything she understood about her life and she had stood in the doorway of it with her monogrammed trunk box and felt the ground shift under her in a way that she had not yet had language for.\nShe had language for it now.\nShe got up quietly and went to the window and looked out at the compound. The morning was doing what Ibadan mornings did in December, cool and clear, the kind of air that felt like it had been rinsed. The mango tree at the edge of the compound caught the early light in its upper branches. She had not noticed that tree until the sixth week. She noticed everything now.\nShe turned back to her trunk box.\nShe had packed most of it the night before, after the conversation, after the room went quiet and sleep came slowly and Temi''s hand had rested at the edge of the bunk until Chiamaka had heard the change in her breathing that meant she was finally asleep. What was left out were the things she had needed this morning. Her soap and towel from the bathroom. Her uniform, which she would wear for the bus. The blue notebook Ngozi had given her, which she had put back out from the bottom of the trunk because she wanted to carry it in her school bag, close.\nShe packed the soap. She folded the towel.\nWhat she had arrived with: two bags, a trunk box, a monogrammed luggage tag, a Lagos accent deployed like a weapon, a father''s name that meant one thing and then another, the complete performance of a girl who had never needed to be anything other than what the world had always told her she was.\nWhat she was leaving with: the same bags, the same trunk box. The luggage tag with its three initials, which meant something different now, not the name of the life she had come from but just her name. C.N.O. Chiamaka Ngozi Obi. The middle name her mother had given her, which she had not thought about in years and which she had been thinking about since Ngozi made garri for her on a Saturday afternoon and asked for nothing except that she give some back next week.\nShe was leaving with a chemistry result that had started at fifty-one and finished at eighty-three. With the knowledge of how to sort rice from stones with patience. With a conversation in a kitchen at six in the morning and an understanding of the difference between her father''s choices and her own. With the memory of standing under a narrow overhang in the rain while Temi talked about pictures that had lost their ground.\nWith Ngozi''s notebook at the bottom of her school bag.\nWith the understanding that belonging was not a room you conquered. It was a room that told you the truth about yourself and held you while you figured out what to do with it.\nShe closed the trunk box.\nAround her the room was beginning to stir. Funke first, always Funke, sitting up with her hair pressed on one side and her eyes already calculating. Then Sade reaching for her phone before she was fully awake. Blessing sitting up straight the way she always did, fully present inside three seconds. Ngozi opening her eyes and looking at the ceiling with the expression of someone composing a first line.\nAbove her, Temi was still.\nThen the springs moved and Temi appeared over the edge of the bunk, looking down, her box braids loose around her face in the way she only wore them before she put them up for the day. She looked at Chiamaka and the packed box and the school bag sitting ready by the door.\n"You''re up early," Temi said.\n"Couldn''t sleep past five," Chiamaka said. "Your fault. I''ve been on school time since October."\nSomething moved across Temi''s face. Not quite a smile. Something adjacent to it, the thing that lived in the same neighborhood as a smile and was sometimes worth more.\n"Next term," Temi said. "The architecture scholarship application opens in February. I''m going to need the bonding chapter."\nChiamaka looked up at her. "The chemistry bonding chapter."\n"The process. How you learned it. You said it clicked on the fourth night. I need to understand how to make things click. For the technical drawing component." She paused, and it was a very Temi pause, the kind that carried everything she was not saying alongside the thing she was. "If you''re willing."\n"I''m willing," Chiamaka said.\nTemi nodded. She pulled herself back up to her bunk and the springs settled and the room went about its final morning, the sounds of girls gathering themselves and their things, the specific energy of a last day that was also a beginning.\nChiamaka picked up her school bag and felt the weight of Ngozi''s notebook inside it. She looked at the bottom bunk one last time, the thin mattress with the familiar depression in the center, the small ledge of the bed frame where a travel pack of tissues had once appeared without explanation.\nThe buses were at eight.\nShe was ready.','\n',char(10)),1028,1,1,NULL,'2026-04-20T12:46:22.769Z','2026-04-20 12:46:22','2026-04-20 12:46:22',NULL,2,46);
INSERT INTO "chapters" ("id","novel_id","chapter_number","title","content","word_count","is_premium","is_published","audio_url","published_at","created_at","updated_at","scheduled_release_at","part_number","season_id") VALUES(572,70,1,'The Night Before the Machines',replace('The truck arrived on a Tuesday, which was wrong, because everyone in Agulu knew you did not bring machines near the lake on a market day. Nobody said this to the men in the orange vests. Nobody said much of anything.\nOby watched from the top of the compound wall, her legs dangling, her chin resting on her hands. Below her, along the road that curved past the eastern edge of the lake, three flatbed trucks had parked in a line. The excavator on the last truck was still strapped down, yellow and enormous, its claw folded against its body like something pretending to sleep. Workers in matching vests moved around it with clipboards and phones, speaking in a language that was partly Igbo and mostly money.\nHer neighbour Auntie Chisom stood at her gate with her wrapper tied tight and her arms folded, watching. Two boys from the next street had climbed a guava tree for a better view. Even Bisco, the compound dog who barked at everything, sat completely still.\nThe project had been talked about for four months. A road, they said. A proper one, with asphalt and drainage, cutting through the eastern wetlands and shaving forty minutes off the route to Awka. The community had argued about it in church, at the market, at naming ceremonies where people were supposed to be celebrating. Half of Agulu wanted the road. The other half wanted the company gone. The company had not waited to find out which half was larger.\nOby''s mother appeared at the doorway below. "Obiageli. Come down from there."\n"I''m just looking."\n"I said come down."\nThere was something in her mother''s voice that was not the usual tired-after-work flatness. It was tighter. Pressed. Oby dropped from the wall and followed her inside without arguing, which she would later think about. She almost never did that.\nDinner was quiet. Her mother had made ofe onugbu with enough cocoyam to last three days, but she ate almost none of it. She kept glancing at the window as if she expected someone to knock. Nobody knocked. Outside, the sound of the trucks slowly faded as the workers drove back toward whatever hotel the company had booked in Awka. The lake, as always, said nothing.\nOby washed the plates. She did her reading for school. She lay on her back on the narrow mattress she had slept on for sixteen years, in the room whose ceiling she knew like a map, and she waited for sleep the way she always did, counting the water stains above her into shapes.\nShe did not expect anything.\nShe had lived beside Agulu Lake her entire life. She had watched it in every season. She had seen it silver in harmattan and dark green in the rains. She had watched the crocodiles surface and sink without fear, because fear was for people who did not grow up here, people who came from the city and stood at the edge with their phones out, daring each other to lean closer. The lake was simply the lake. It had always been there. It would always be there.\nShe believed this right up until she closed her eyes.\nThe dream did not begin slowly. It arrived the way cold water arrives when someone tips a bucket over your head while you are not looking. One moment there was ceiling. The next there was water, everywhere, but she was not drowning. She was standing in it, on it, inside it. The water was the colour of old bronze and it moved around her like something breathing.\nShe knew she was at the lake. She knew it the way you know your own house in the dark, by weight and texture and the particular quality of its silence.\nSomething was below her.\nNot something dangerous. Not yet. But large. Patient. The kind of patient that does not come from waiting a few years. The kind that comes from waiting so long that time itself has become irrelevant.\nIt rose.\nThe crocodile was bigger than any she had seen. Its eyes were open and they were not the flat gold of an animal''s eyes. They held something that looked, in the bronze water, almost like recognition.\nIt stopped just below the surface. It looked at her. It did not open its mouth. It did not move. It simply regarded her with the total attention of something that had been waiting for a specific person to arrive.\nOby opened her mouth to speak and heard, instead, a voice that came from inside her own chest. It was not her voice. It was older than her voice by a distance she could not calculate. And it said, in Igbo so clean it felt like water on stone:\nThey are here. You already know what is buried. You have always known. You simply have not been asked to remember.\nOby woke up.\nThe ceiling was above her. The room was dark. Outside, the lake was quiet.\nBut her hands were pressed flat against her mattress and her heart was a drum and she was already sitting up because somewhere inside her, beneath every ordinary thing she had ever believed about herself, something had just turned over like a stone.\nAnd underneath it, something moved.','\n',char(10)),883,0,1,NULL,'2026-04-20T20:18:32.893Z','2026-04-20 20:18:32','2026-04-20 20:18:32','2026-04-20T21:00:00.000Z',1,48);
INSERT INTO "chapters" ("id","novel_id","chapter_number","title","content","word_count","is_premium","is_published","audio_url","published_at","created_at","updated_at","scheduled_release_at","part_number","season_id") VALUES(573,70,2,'What She Woke Up Knowing',replace('The knowledge was there before she was fully awake. That was the part that frightened her most.\nNot the dream itself. The dream she could argue with, could fold into the category of strange night things that dissolve by morning. What she could not argue with was the information sitting inside her head like it had always lived there, calm and arranged, waiting for her to notice it.\nShe knew, for instance, that the lake had a depth at its northern edge that no surveyor had ever correctly measured. She knew the number. She could not have said where the number came from.\nShe knew that the crocodiles were oldest near the centre. That the large ones did not simply grow. That they accumulated.\nShe knew that her grandmother''s grandmother had a name that was not the one written in any church record.\nOby sat on the edge of her mattress and pressed her palms against her eyes. Outside, birds were doing their early morning argument in the guava tree. The compound smelled like the neighbour''s firewood. Everything was ordinary. She was not ordinary. Something had shifted in the night and she did not know how to shift it back.\nShe tried telling herself it was just a dream.\nBy the time she had brushed her teeth, she had stopped trying.\nHer mother was already in the kitchen, moving with the particular efficiency of someone who had not slept well but intended to behave as if she had. She had her work bag on the counter, her phone propped against the kerosene lamp, reading something on the screen with a face that gave nothing away.\n"Sit," her mother said. "Food is on the stove."\nOby sat. She watched her mother''s back. The straight spine, the set of the shoulders, the way she always seemed to be bracing for something.\n"Mama."\n"Mm."\n"Did your grandmother have another name? Before her Christian name?"\nHer mother''s hand stopped moving. It was a small pause, barely a second, and then she continued stirring. "Eat your food, Oby."\n"I am asking a question."\n"I heard you." She turned from the stove and set a plate down with a firmness that was not quite slamming it. "Eat."\nThere was a wall behind her mother''s eyes that Oby recognised. She had spent sixteen years occasionally throwing herself against it and getting nowhere. She ate. She did not ask again. But she watched her mother''s hands for the rest of breakfast and noticed they were not entirely steady.\nSchool was a separate problem.\nShe sat through her first two classes and understood that the words her teachers were saying were reaching her, but something else kept pulling her attention sideways. During civic education she found herself drawing the outline of the lake on the margin of her notebook without meaning to. The shape came out accurate in a way it should not have been accurate. She had never studied the lake''s exact shape. She had simply lived beside it.\nAt break time she walked to the back fence of the school compound, which faced the direction of the lake, and stood there with her hands in her pockets.\nAdaeze found her. Adaeze always found her.\n"You look like someone told you a very long story and you are still deciding if you believe it," Adaeze said, coming to stand beside her with a meat pie she had clearly bought from the tuck shop.\n"Something like that."\n"The construction thing?" Adaeze took a bite. "My father says the road will be good for business. My mother says the lake will swallow every one of those workers before the month is out." She paused. "I don''t know what I think."\nOby said nothing. She was looking at the distance, at the faint glitter she could not actually see from here but knew was there because she always knew where the lake was, the same way she always knew where her own hands were.\n"Oby."\n"I had a dream last night."\nAdaeze waited.\n"Something spoke to me. From the lake. And when I woke up I knew things. Things I was not told." She stopped. She could hear how it sounded. "I know how that sounds."\nAdaeze was quiet for a moment. "What kind of things?"\n"Things about the lake. About my family." She turned to face her. "Adaeze, I knew a number. A measurement. For the depth of the lake at the northern edge. I don''t know how I know it. But I know that it is correct."\nAdaeze looked at her for a long time. She was not the kind of person who dismissed things quickly. She was also not the kind of person who accepted them without pressure.\n"How would you verify it?"\nOby had not thought about that. And then, before she finished the thought, she realised she already knew how to verify it, and who would have the records, and where those records were kept.\nShe had not known any of that thirty seconds ago.\nThe bell rang. Adaeze touched her arm once and went back inside.\nOby stood at the fence for another moment. The afternoon light was flat and white and normal. A hawker passed on the road outside calling out pure water.\nShe looked toward where the lake was and understood, with a cold clarity that had nothing dreamlike about it, that the knowing was not finished. It was only starting. And it was going to keep arriving whether she was ready or not.','\n',char(10)),921,0,1,NULL,'2026-04-20 20:35:33','2026-04-20 20:19:55','2026-04-20 20:35:33','2026-04-20T21:00:00.000Z',1,48);
INSERT INTO "chapters" ("id","novel_id","chapter_number","title","content","word_count","is_premium","is_published","audio_url","published_at","created_at","updated_at","scheduled_release_at","part_number","season_id") VALUES(574,70,3,'The Oldest Name in Her Family',replace('The records office behind St. Joseph''s Parish had not been properly organized since 1987, and the man who kept it, Papa Ikenna, treated every visitor like a personal inconvenience sent to ruin his afternoon.\nOby knew this. She came anyway, after school, with her uniform still on because she had calculated that adults were less suspicious of girls in school uniforms carrying notebooks. She knocked on the low wooden door and waited with her hands clasped in front of her and her most responsible expression arranged on her face.\nPapa Ikenna opened the door, looked at her, and sighed the sigh of a man who had been sighing at young people for forty years.\n"I am looking for old baptismal records," Oby said. "For a family history project."\nHe let her in.\nThe room was narrow and cool and smelled of paper that had been rained on too many times. Shelves ran from floor to ceiling on both sides, crowded with bound registers, loose folders, and cardboard boxes labeled in fading ink. A ceiling fan turned slowly overhead, moving the air without cooling it.\nPapa Ikenna pointed her to the section covering 1890 to 1940 and returned to his chair and his radio.\nOby worked steadily. She knew what she was looking for, which was the strange part, the part she had stopped questioning. She knew the approximate decade. She knew the name would appear as a secondary entry, a native name recorded in brackets beside the Christian one, the way the early missionaries sometimes documented them before the practice was abandoned entirely.\nShe found it in the third register.\nAdaora Nkechi Eze (Nnedimma-Iyi). Baptized 1902. Daughter of Chukwuemeka Eze. Born Agulu.\nOby read it twice.\nNnedimma-Iyi. The name from the dream. Not a stranger. Not a figure from general community history. A name attached to her own family line, bracketed and half-hidden and recorded only because one particular missionary had been more thorough than was strictly required.\nShe wrote it down in her notebook. Her handwriting was not as steady as she would have liked.\nShe kept searching. There were two more. A generation earlier, another woman in her line had the same secondary name structure. And one generation before that, the name appeared not in brackets but as the primary entry, no Christian name beside it at all.\nJust Nnedimma-Iyi. Nothing else needed.\nOby closed the register carefully and thanked Papa Ikenna on her way out. He did not look up from his radio.\nOutside, the late afternoon had turned the road to orange dust and long shadows. She walked home the long way, past the eastern edge of the lake, because she needed to see it. The water was dark in the fading light and completely still. A single crocodile lay on the far bank with its mouth open, the way they did when they were regulating heat. It looked ancient and unhurried and utterly unbothered by the survey stakes the construction company had driven into the ground thirty metres from where it rested.\nOby stopped walking.\nThe crocodile turned its head.\nNot toward the water. Not toward some sound in the bush. Toward her. Directly, precisely, the way a person turns when their name is called across a room.\nShe stood completely still.\nIt held her gaze for a long moment, then turned back and slid, without any urgency, into the water.\nShe exhaled.\nAt home, her mother was on the phone in the parlour, speaking in the low careful tone she used when she did not want to be overheard. She stopped when Oby came in and said, into the phone, "She just got back, let me call you later," and hung up with a speed that answered several questions Oby had not yet asked out loud.\n"Sit down," her mother said. She said it the way she said everything lately, like she was reading from a script she had written to get through a specific period of time.\nOby sat. She put her notebook on the table between them, opened to the page where she had written the names.\nHer mother looked at the page. Something moved across her face, too fast to name, and then the wall came up and it was gone.\n"Where did you get this?"\n"Parish records. St. Joseph''s."\nHer mother closed the notebook. Slid it back across the table. "You need to stop pulling at this."\n"Mama. Nnedimma-Iyi is in our family line. Three generations. It doesn''t stop at great-grandmother. It goes further back than the records do." She leaned forward. "And I know that name. It spoke to me in a dream the night the construction trucks arrived."\n"Dreams are just dreams."\n"You didn''t sleep last night."\nSilence.\n"You didn''t sleep," Oby said again, more quietly, "because you know they are not."\nHer mother stood up. She was not angry, which was almost worse than anger. She was something more controlled than that, something that had been practiced over years.\n"Your grandmother told me to let it pass to you when it was time," she said, her back to Oby, her hand on the kitchen doorframe. "She said I would know when. I have spent your entire life deciding it was never time."\nShe went into the kitchen.\nThe fan turned overhead. Outside, darkness was fully settling now, and the lake was invisible beyond the trees, but Oby could feel it the way she always felt it, steady and enormous and extraordinarily patient.\nFor the first time in her life, that patience felt like a message aimed specifically at her.','\n',char(10)),932,0,1,NULL,'2026-04-20 20:33:36','2026-04-20 20:21:07','2026-04-20 20:33:36','2026-04-20T21:00:00.000Z',1,48);
INSERT INTO "chapters" ("id","novel_id","chapter_number","title","content","word_count","is_premium","is_published","audio_url","published_at","created_at","updated_at","scheduled_release_at","part_number","season_id") VALUES(575,70,4,' The Crocodile That Follows',replace('It was at the school gate on Wednesday morning.\nNot close. Not threatening. Sitting at the edge of the drainage gutter on the opposite side of the road with the stillness that crocodiles had perfected over millions of years, the kind of stillness that made them look like objects until they didn''t. It was facing the gate. Facing, specifically, the direction Oby was walking from.\nShe stopped. A motorcycle taxi swerved around her and the rider shouted something she did not hear.\nThe crocodile was not large by Agulu standards, maybe a metre and a half, with a ridge along its back that caught the early morning light. Its eyes were open. They found her immediately, the way they had found her at the lake two days ago, with that same unsettling directness.\nA woman passing with a tray of tomatoes on her head glanced at it, sucked her teeth, and kept walking. Two boys on the other side of the road pointed and laughed. Nobody else stopped. Nobody else seemed to find the direction of its attention particularly notable.\nOby crossed the road slowly and stood three metres from it.\n"I see you," she said quietly, feeling only slightly foolish.\nIt blinked once, the slow sideways blink of a reptile, and then it turned and moved toward the gutter with a speed that was over before she could properly register it and was gone.\nShe went to school. She could not have told anyone what was taught that day.\nIt was at the market on Thursday.\nShe had gone for her mother, a list in her hand, tomatoes and Cameroon pepper and a tin of sardines. The Agulu market was narrow and loud and wonderful, a press of colour and voices and the specific smell of fresh red oil that she had loved since she was small enough to be carried through it on her mother''s back. She was weighing tomatoes with Mama Tochukwu when she felt the particular quality of attention on her that she was beginning to recognize.\nShe turned.\nAcross the aisle, between a stall selling plastic buckets and another selling secondhand clothing, the crocodile sat in the gap between two wooden tables like it was the most natural thing in the world. Market goers moved around it with the casual avoidance of people who had grown up beside the lake and found crocodiles manageable as long as you did not provoke them.\nBut they were not looking at it the way it was looking at her.\nMama Tochukwu followed her gaze. "Agulu crocodiles are everywhere these days," she said, dropping tomatoes into Oby''s bag. "Since those construction people started their work at the eastern edge. The animals are disturbed." She lowered her voice. "Which is what we told the community heads. But who listens?"\nOby paid and left without looking back. She did not need to look back. She could feel it watching her all the way to the end of the aisle.\nThat night she sat at the edge of the lake for the first time since the dreams started.\nShe had done this her whole life, sitting at the flat rock near the northern bank where the ground was solid and the reeds grew tall on either side and you could see the full open face of the water. She had done homework here. She had cried here after her father left, seven years ago, when she was nine and still believed that crying somewhere peaceful would make the feeling go somewhere peaceful too. It hadn''t, but the rock had never judged her for trying.\nShe sat now with her knees pulled up and waited.\nThe lake was silver in the moonlight. Something moved below the surface near the centre, a long slow displacement of water, unhurried.\nIt surfaced fifteen minutes later, close to the bank, close to her, much closer than a crocodile had ever come to her before. The large one. She recognised it by the ridge pattern along its back, the same one from the dream, the same one from the school gate and the market. Her heart climbed her throat and she held herself very still even though every instinct she had was arguing loudly for movement.\nIt stopped at the waterline. Its head was raised slightly. The eyes were that colour again, not flat gold but something layered, something deep in the way that the lake itself was deep.\nOby breathed.\n"You were in my dream," she said. Her voice came out steadier than she felt. "And you have been following me."\nThe crocodile did not move.\n"I don''t know what you need me to do yet." She kept her voice low and even, the way she spoke to frightened small children when she helped at Sunday school. "But I am listening."\nThe water around it shifted. Not from movement. From something below it, pressing gently upward, the way heat moves through a surface. The bronze colour from her dream bled briefly into the silver of the moonlit water directly beneath the crocodile''s body and then faded.\nA warmth moved through Oby''s chest. Not threatening. The opposite of threatening. Like being recognised by something very old after a very long time apart.\nThen, from the direction of the construction site, a generator coughed to life. Floodlights cut across the eastern tree line. Voices carried over the water. Night work. They were doing night work now.\nThe crocodile turned its head toward the sound. Something changed in its stillness. The patience shifted into something with an edge to it.\nIt looked back at Oby once, and then submerged without a sound, leaving only a ring of disturbed water that spread outward and outward until it reached the bank and dissolved against the rock where she sat.\nShe stayed until the ring was gone. Then she walked home in the dark, one hand pressed flat against her sternum where the warmth had been, her mind running ahead of her toward a question she had not yet figured out how to ask.\nWhatever was buried under the lake was running out of time.\nAnd somehow, impossibly, she already knew exactly how much time was left.','\n',char(10)),1034,1,1,NULL,'2026-04-20 20:34:16','2026-04-20 20:22:31','2026-04-20 20:34:16','2026-04-20T21:00:00.000Z',1,48);
INSERT INTO "chapters" ("id","novel_id","chapter_number","title","content","word_count","is_premium","is_published","audio_url","published_at","created_at","updated_at","scheduled_release_at","part_number","season_id") VALUES(576,70,5,'What the Elders Won''t Say',replace('The Council of Elders met on Friday evenings in the community hall behind the town clock, and they did not invite sixteen-year-old girls.\nOby knew this. She had known it her whole life the way she knew other fixed things, the way school fees were due in January, the way harmattan arrived without asking. The council was seven men and two women whose combined age was somewhere above six hundred years and whose combined patience for disruption was somewhere near zero.\nShe went anyway.\nShe arrived early enough to take a position outside the louvred window before anyone could tell her to leave. The hall was already warm with bodies and the particular formality of old people conducting serious business. She could see through the slats: Chief Odumegwu at the head of the table, massive and white-haired; Lolo Adaku beside him, her wrapper immaculate, her expression giving nothing away; six others arranged in order of age or pride, she had never been sure which.\nThey were already arguing.\n"The company has the state government approval," one of the men said. She recognised his voice. Engineer Okafor, who had built his house with government contract money and believed that government approval settled most questions. "We cannot fight Abuja with tradition."\n"We are not fighting Abuja," Lolo Adaku said. "We are asking for a proper heritage assessment before ground is broken at the northern edge. That is a legal right."\n"They are not touching the northern edge."\n"Not yet."\nChief Odumegwu cleared his throat and the room quieted. "The question before us is not whether we value the lake. Every person in this hall values the lake. The question is what tools we have available and how we use them."\n"The question," said an older woman Oby did not recognise, sitting at the far end, "is whether any of you are going to say what you actually know or whether we will spend another Friday evening speaking around it."\nSilence. A different kind of silence than before.\nChief Odumegwu looked at the old woman. "Mama Uzo."\n"Do not Mama Uzo me, Chukwudi. Some of us are old enough to remember what your own father told us about that lake." She set both hands flat on the table. "The stones. Are we going to talk about the stones or are we going to continue pretending we are simply concerned citizens?"\nThe air in the hall changed. Oby pressed herself closer to the window.\n"That is not a matter for open council," Engineer Okafor said quickly.\n"Then when is it a matter? When the machines reach the northern bed?"\n"We do not know for certain that the stones are where—"\n"My father mapped it," Chief Odumegwu said quietly. The room went still again. "In 1961. When the last development proposal came through and was eventually abandoned. He mapped the location and documented it and then he locked the document away and told me never to produce it unless the lake was in direct threat." He paused. "He also told me the mapping would not matter in the end. That when it was necessary, the lake would produce its own evidence."\n"Through the bloodline," Mama Uzo said.\nAnother silence.\n"There has been no one in that line for a generation," Lolo Adaku said carefully.\n"Adaora''s daughter has a child," Mama Uzo said. "She is sixteen. And unless I am wrong, she has been visited."\nOby stopped breathing.\n"We do not know that."\n"Her mother knows that. Why do you think Ngozi has not slept this week?"\nOby''s mother''s name in that sentence landed on her like something physical.\nShe must have moved, or made a sound, because Chief Odumegwu turned suddenly toward the window. She pulled back against the outer wall, her heart enormous in her chest, and waited.\nFootsteps. The side door opened.\nIt was Lolo Adaku who came out, not the chief, which surprised her. The old woman looked at her without surprise, without anger, with an expression that Oby could only describe as tired recognition.\n"How long have you been out here?"\n"Long enough," Oby said. She decided there was no point in any other answer.\nLolo Adaku studied her for a moment. "You have your great-grandmother''s posture," she said, not warmly, not coldly, simply as a fact being recorded. "Come."\nShe did not take her inside. She took her to the bench at the side of the building, under the overhead light that the moths had found, and sat down with the careful arrangement of a woman whose knees had opinions.\n"Ask what you came to ask."\n"The stones," Oby said. "The Covenant Stones. They are real and they are in the lake and the elders know where. And something happens if the construction reaches them."\nLolo Adaku did not confirm or deny this. She looked at her hands.\n"I want to know what the council knows and is not saying publicly."\n"What the council knows," the old woman said slowly, "is enough to frighten people who have lived long lives and seen many things. It is not something you hand to a sixteen-year-old girl and walk away."\n"It has already been handed to me," Oby said. "By the lake itself. I did not ask for it and I cannot put it back." She kept her voice level. "So the choice is not between telling me and protecting me. It is between telling me and leaving me to figure it out without you."\nLolo Adaku looked at her then, fully, the way people rarely looked at her, the way people looked at other people whose weight they were just beginning to correctly estimate.\nShe was quiet for a long moment.\n"Come to me on Sunday morning," she said finally. "Not the council. Me." She stood, smoothing her wrapper. "Come alone. Come early. And do not tell your mother I said so."\nShe went back inside.\nOby sat alone under the light and the moths and thought about the fact that the elders had been sitting on a documented location for sixty years, waiting for a bloodline to reactivate, and had said nothing to her mother, nothing to her, nothing to anyone.\nThe lake had been patient.\nThe elders had been patient.\nEveryone, it seemed, had been waiting for Oby.\nNobody had thought to ask if Oby was ready.','\n',char(10)),1057,1,1,NULL,'2026-04-20T20:24:35.926Z','2026-04-20 20:24:35','2026-04-20 20:24:35','2026-04-20T21:00:00.000Z',1,48);
INSERT INTO "chapters" ("id","novel_id","chapter_number","title","content","word_count","is_premium","is_published","audio_url","published_at","created_at","updated_at","scheduled_release_at","part_number","season_id") VALUES(577,70,6,'The First Warning',replace('By Saturday morning, the fish were gone.\nNot reduced. Not moved to another section of the lake. Gone. Every fisherman who had set traps the night before pulled them up empty, which had not happened in living memory, not during drought, not during the floods of 2012, not during any of the disruptions that Agulu Lake had absorbed over the decades without changing its fundamental generosity toward the people beside it.\nOby heard about it from Adaeze, who had heard it from her father, who had come back from the water at dawn with a face like a man who had seen something he needed time to categorize.\nShe went to the bank herself.\nThe fishermen were gathered in a loose cluster near the main landing, their traps piled beside them, talking in the low urgent register of people trying to stay calm about something that was not calm. The water was normal in colour, normal in level, undisturbed on the surface. But the quality of the quiet above it was different. The birds that usually worked the shallows in the morning were absent. The reeds were still. Even the light on the water seemed to sit differently, heavier, like the surface of something holding its breath.\nOld Ikechukwu, who had fished this lake for fifty years and whose opinion on its moods was treated as weather forecasting, was standing apart from the others with his arms folded and his eyes moving slowly across the water.\n"Nna," Oby said, coming to stand beside him. "What happened?"\n"The lake swallowed itself," he said, not looking at her. "That is what happened."\nShe waited for more. He did not offer more.\nThe company site manager arrived at nine o''clock. His name was Mr. Salau and he had the specific energy of a man who had been hired to solve problems and had been told that hesitation was a problem. He came with two other men in matching company polo shirts and a woman with a laptop who appeared to be documenting things.\nHe looked at the empty traps. He looked at the fishermen. He said, with the careful patience of someone who had prepared for local resistance, that disruption to fish patterns during early-stage construction was a documented and temporary phenomenon, that his company''s environmental assessment had anticipated it, and that normalcy would be restored within two to three weeks once the water table adjusted.\nNobody said anything for a moment.\nThen Ikechukwu turned from the water and looked at Mr. Salau with an expression that was not hostility and was not grief but was something that sat exactly between them. "This lake has never been empty," he said. "Not in fifty years. Not in any account I have been told by any person who fished before me. What your assessment anticipated was a different lake."\nMr. Salau made a note on his phone. "I understand your concern. We will monitor the situation."\n"You will monitor," Ikechukwu said, and turned back to the water.\nOby watched Mr. Salau work his way through the cluster of fishermen, absorbing complaints with the smooth efficiency of a company representative who had been trained not to absorb them too visibly. The woman with the laptop typed steadily. One of the polo-shirt men took photographs of the empty traps, which Oby found strange, the way you photograph evidence rather than the way you photograph a problem you intend to solve.\nShe walked the bank east, away from the gathering, toward the section where the construction markers were thickest, the orange stakes driven into the ground every ten metres with survey tape strung between them. The machines had not moved to this section yet, but the ground had been cleared of brush and the earth had a raw, opened quality that felt wrong beside water that old.\nShe stopped at the last marker before the reeds thickened.\nThe water here was darker than the main body. Deeper. She knew this without measuring it. She stood at the edge and looked down and the surface gave back her own reflection, sharp and complete, the way mirrors work but lake water rarely does.\nExcept behind her reflection, there was something else.\nNot a shape. Not a figure. A colour. The bronze from the dream, rising from below her reflection and spreading outward in a slow pulse, like a heartbeat made visible, moving out to the edges of what she could see and then fading and then rising again.\nShe crouched down and held her hand an inch above the surface.\nThe warmth she had felt on the rock two nights ago moved up her palm and into her wrist and settled in the same place in her chest, pressing steadily, not urgently but with the particular insistence of something trying to make a point before time ran out.\nBehind her she heard Mr. Salau''s voice, closer now, talking to the woman with the laptop. "Eastern section is on schedule for Monday. I want the drainage survey completed before the excavator moves in."\nMonday.\nOby stood up. The bronze had faded from the water. Her reflection looked back at her, alone again.\nShe turned around. Mr. Salau was walking past with his phone raised, checking signal. He glanced at her the way adults glanced at teenagers near work sites, assessingly, deciding if she required management.\n"This section of the bank," Oby said clearly. "How deep does your survey say the lake bed is here?"\nHe stopped. The assessment in his eyes shifted slightly. "Approximately twelve metres. Why?"\nShe held his gaze. "It is twenty-seven metres. Your equipment was wrong, or your assessment did not try very hard."\nShe walked away before he could respond, back toward the fishermen, back toward the cluster of empty traps and the grey-faced men who already knew what she was just learning to name: that the lake had issued its first statement, and the people with the clipboards and laptops had looked directly at it and seen a temporary inconvenience in need of monitoring.\nThe warning had been given.\nIt would not be repeated in the same language.','\n',char(10)),1022,1,1,NULL,'2026-04-20T20:26:22.840Z','2026-04-20 20:26:22','2026-04-20 20:26:22','2026-04-20T21:00:00.000Z',1,48);
INSERT INTO "chapters" ("id","novel_id","chapter_number","title","content","word_count","is_premium","is_published","audio_url","published_at","created_at","updated_at","scheduled_release_at","part_number","season_id") VALUES(578,70,7,' Her Mother''s Silence',replace('Her mother was burning things.\nNot dramatically. Not with the energy of someone making a statement. She was crouched beside the small concrete drainage channel behind their compound, feeding papers into a tin can fire with the focused attention of someone completing a task they had delayed too long. The smoke was thin and white and smelled faintly of old paper.\nOby stood at the back door and watched for a full minute before her mother sensed her and looked up.\nNeither of them spoke.\nHer mother fed the last paper into the can, watched it catch, and stood slowly, pressing one hand against her knee the way she did when it had been aching. She picked up the can lid and covered the flame without hurrying. Then she turned and walked back toward the house, and Oby stepped aside to let her pass.\n"Sit down," her mother said, moving to the kitchen.\n"What were you burning?"\n"Sit down, Obiageli."\nShe sat at the parlour table. Her mother came back with two cups of tea she had clearly not just made, lukewarm and over-steeped, the kind of tea you prepared earlier when you were anticipating a conversation. She set one in front of Oby and wrapped both hands around her own cup and remained standing.\n"Lolo Adaku called me," she said.\nOby absorbed this. "What did she say?"\n"That you were outside the council window on Friday." She looked at her steadily. "And that she spoke to you afterward."\n"She told me to come to her on Sunday. Alone."\n"I know."\n"Are you going to tell me not to go?"\nHer mother looked at her for a long moment, and something moved behind her eyes, a slow internal rearrangement, the look of someone releasing a position they had held for a very long time and feeling the specific ache of the muscles that had been holding it.\nShe sat down.\n"Your grandmother," she began, and stopped. Started again. "My mother was the most extraordinary person I have known in my life. She knew things. The way you know things now." She did not phrase it as a question. "She knew them from the time she was small, and she carried it quietly, the way you carry something you have accepted but not chosen."\nOby held her cup and said nothing.\n"She told me when I was twelve that the inheritance passed through the women of our line. That it had skipped her mother, who refused it, and come back to her doubled. She said it would come to me or to my daughter, depending on what the lake needed and when." Her mother''s voice was controlled in the way of someone reading from a document they have memorized to avoid feeling it. "And then she died. And I was seventeen. And I waited for the thing to come to me and it did not come. And after enough years I decided it had skipped me entirely and would go no further."\n"You decided that," Oby said quietly. "Or you hoped for it."\nThe cup in her mother''s hands shifted. "Both."\n"What were you burning?"\nA pause. Long enough to have its own weather.\n"Letters," her mother said. "From my mother to me. Written before she died, meant to be given to me when the inheritance arrived." She looked at the window. "She left them with Lolo Adaku. Adaku gave them to me seven years ago, when your father left and the lake started appearing in your drawings and your sleep talking, and I decided—" She stopped.\n"You decided it was grief. That I was drawing the lake because I was sad."\n"You were sad."\n"I was also being called." Oby said it without anger, which surprised her. "And you knew. Seven years ago you knew and you burned the letters before I could read them."\n"I burned the letters tonight," her mother said. "Seven years ago I read them and then I put them in a box and I have been deciding ever since." She finally met Oby''s eyes fully. "I was trying to protect you."\n"From what?"\n"From being what she was. From being what I watched her be." Her voice cracked along one edge and she pressed it back together immediately. "You know what it cost her? To carry that? She had no life that was only hers. Every decision she made ran through the lake first. Every relationship, every plan. She loved us but we were always second. The lake was always first."\nOby sat with that.\nOutside, the night was settled and still, and the lake was out there in the darkness doing what it always did, simply existing with its enormous patience and its buried stones and its waiting crocodile.\n"What did the letters say?" Oby asked. "Before you burned them."\nHer mother was quiet so long that Oby thought she would not answer.\n"She said the inheritance was not a burden. She said I had been taught to see it as one because the colonial church spent a century teaching our family that the lake was primitive and the bloodline was superstition." She exhaled slowly. "She said the truth was the opposite. That the women of our line were not trapped by the lake." She paused. "They were trusted by it."\nThe word landed in the room and stayed there.\nTrusted.\nOby felt it settle into the warmth in her chest, into the space where the knowledge lived, and something she had not known was tense released slowly.\nHer mother reached across the table and covered Oby''s hand with her own. Her palm was warm. Her grip was tight in the way of someone holding on, not holding back.\n"Go to Lolo Adaku on Sunday," she said. "I should have sent you months ago."','\n',char(10)),970,1,1,NULL,'2026-04-20T20:27:32.722Z','2026-04-20 20:27:32','2026-04-20 20:27:32','2026-04-20T21:00:00.000Z',1,48);
INSERT INTO "chapters" ("id","novel_id","chapter_number","title","content","word_count","is_premium","is_published","audio_url","published_at","created_at","updated_at","scheduled_release_at","part_number","season_id") VALUES(579,70,8,'What''s Buried',replace('Lolo Adaku lived alone in a house that had been old when she moved into it as a young bride and had continued aging around her with what appeared to be mutual respect. The compound walls were thick and cool. The parlour had no television, only chairs and a shelf of books and a ceramic pot in the corner that Oby had never seen anyone use and had never asked about.\nShe arrived Sunday morning as the church bells from St. Joseph''s were finishing their first call. The old woman was already seated outside on a low bench with a cup of something steaming, as if she had been there for hours.\n"You came," Lolo Adaku said.\n"You told me to."\n"Many people are told things." She gestured to the bench beside her. "Sit."\nOby sat. The morning was cool and the compound was full of the sound of birds and somewhere down the road a generator was running its early shift.\nLolo Adaku spoke for forty minutes without being asked questions. She spoke about the history of the lake the way a person speaks who has been composing a specific account in their mind for a long time and is finally delivering it. She spoke about the original covenant, about a dibia named Nnedimma who had formalised in stone what the community had always understood informally, that the lake was not simply a body of water but a living record, a keeper, a presence with memory longer than any human institution. She spoke about the British arrival and the compromised elder who signed papers he should not have signed and the deliberate erasure of the lake''s sacred status from colonial administrative records.\nShe spoke about the stones. Seven of them. Nsibidi script. Submerged at the northern bed.\nWhen she finished, Oby said, "I know all of this."\nLolo Adaku looked at her. "Yes. I suspected you did." She picked up her cup. "I wanted you to hear it from a human mouth before you went further. So that you would know the knowing inside you is accurate."\n"How do I go further?"\nThe old woman studied her. "You sleep beside the lake."\nThat night, her mother did not argue. She helped Oby carry a mat and a wrapper to the flat rock on the northern bank and stood at the edge of the compound watching as Oby settled herself with the calm deliberateness of someone who had made a decision and was following it through. Then she went back inside without a word, and the lights in the parlour stayed on.\nOby lay on her back. The sky above Agulu was thick with stars the way it only was when the power was out across the whole street, and the power was out. The lake moved with its slow breathing. The reeds said small things to each other in the night breeze. Somewhere to the east, the construction site was silent for once, the generators off, the workers gone to their hotel beds.\nShe did not try to sleep. Sleep came for her.\nThe bronze arrived first. She recognised it now, the specific warmth of it, the way it moved up from below into the colour of the dream, turning the ordinary dark behind her closed eyes into that ancient amber light. Then the water, everywhere and breathable. Then the depth below her, immense and layered, the way the earth is layered when you understand that rock is only time made solid.\nAnd then, for the first time, the figure.\nShe was standing in the water twenty metres away. Not floating. Standing, as though the lake bed were a floor and she had always known where to put her feet. She was tall, her wrapper a deep indigo that moved in the water like smoke, her head shaved close, her neck carrying three strands of white beads that caught the bronze light and returned it doubled.\nHer face was Oby''s face. Not identical, not a mirror, but belonging to the same original design the way different generations of a river belong to the same watershed.\nShe did not smile. She looked at Oby with an expression that contained too many things to read quickly.\n"Nnedimma," Oby said.\nThe woman inclined her head. When she spoke, her voice was the one from the first dream, the one that lived inside Oby''s chest. "You took a long time," she said. Not as accusation. As fact.\n"I didn''t know I was coming."\n"Your line never does." Something shifted in her expression. "Come."\nShe turned and walked deeper, and Oby followed because in this place following felt as natural as breathing, and because she understood that what she was being led to was the thing she had known about since the first night, the thing the knowledge inside her had been circling.\nNnedimma stopped and pointed downward.\nBelow them, through the clear bronze water, the lake bed was visible. And arranged on it, half-sedimented, half-emerged, worn smooth by more than a century of water, were seven flat stones in a loose arc. The Nsibidi markings on them were luminous. They pulsed with the same rhythm as the warmth in Oby''s chest, slow and steady, like a second heartbeat she had carried her whole life without noticing.\n"They are here," Oby said.\n"They have always been here. Now you have seen them." Nnedimma looked at her steadily. "When the machines reach the northern bed, and they will reach it if nothing changes, two of the outer stones will be displaced. The seal will fracture." She paused. "I need you to understand what that means before I tell you what it means."\nOby looked up from the stones. "Tell me."\nBut the bronze was already fading. The dream was ending with the particular cruelty of important dreams.\nShe woke up gasping, flat on her back on the rock, the lake silver around her and the stars still thick above, and the knowledge of exactly where the stones were burning in her chest like a coordinate she would never lose.','\n',char(10)),1014,1,1,NULL,'2026-04-20T20:28:38.628Z','2026-04-20 20:28:38','2026-04-20 20:28:38','2026-04-20T21:00:00.000Z',1,48);
INSERT INTO "chapters" ("id","novel_id","chapter_number","title","content","word_count","is_premium","is_published","audio_url","published_at","created_at","updated_at","scheduled_release_at","part_number","season_id") VALUES(580,70,9,'The Vote',replace('The town hall was full in a way Oby had never seen it.\nNot the polite fullness of naming ceremonies or the obligatory fullness of community clean-up announcements. This was the fullness of people who had been arguing in kitchens and on roadsides and across market stalls for weeks and had finally arrived at the place where the argument would be settled, or at least formalized. Every bench was taken. People stood three deep along the walls. Children sat on the windowsills because there was nowhere else and their parents were too distracted to move them.\nThe company had sent Mr. Salau and two senior representatives in suits that announced money quietly. They sat at a table at the front with printed documents and water bottles and the composed patience of people who believed the outcome was already determined.\nThe council sat beside them. Chief Odumegwu at the centre, Lolo Adaku three seats down, the others arranged in their familiar order. Mama Uzo was not at the council table. She was in the front row of the public seating, upright and small and paying attention to everything.\nOby sat near the back with her mother, who had come without being asked and had not spoken on the walk over. She sat with her hands flat on her thighs and her eyes forward, and Oby understood this was the posture of a woman who had decided something and was carrying it quietly until the moment it was needed.\nThe proceedings opened with formality and dissolved into noise within fifteen minutes. Mr. Salau presented the project in careful language, road infrastructure, economic development, state government partnership, temporary environmental impact. He used the word temporary four times. He showed slides on a projector screen. The road would reduce travel time, improve market access, bring contracts and employment to Agulu tradesmen.\nHalf the room nodded. The other half did not.\nThe objections came in waves. Old Ikechukwu stood and talked about the empty fish traps and was told the disruption was documented and manageable. A woman named Mrs. Okonkwo stood and talked about what the lake meant to her children and was told the project respected cultural significance. A younger man near the front stood and said the road would bring his brother''s transport business back from Awka, and several people clapped, and several other people turned to look at them with undisguised feeling.\nChief Odumegwu called for order repeatedly. The hall obeyed in short intervals and then resumed.\nLolo Adaku spoke once, carefully, requesting a heritage assessment of the northern lake bed before any further ground was broken. Mr. Salau said the environmental assessment already conducted was comprehensive. She said an environmental assessment and a heritage assessment were different instruments. He said he would take the request under advisement. She looked at him with an expression that had seen seventy years of things being taken under advisement.\nThe vote was structured as a show of hands. Support the project as planned, or request a formal suspension pending independent review.\nOby watched the council member who was supposed to call the vote arrange his papers, and she felt the knowledge in her chest pressing upward, not the warmth this time but something more insistent, the way water presses against a door it needs opened.\nShe stood up.\nSeveral people turned. Her mother''s hand moved toward her arm and then stopped, withdrew, settled back on her thigh.\n"I would like to speak," Oby said.\nThe murmur in the hall shifted in quality. Chief Odumegwu looked at her over the heads of the crowd. "This is an adult community proceeding."\n"I live in this community. I live beside that lake." She kept her voice level and clear, the way Lolo Adaku''s voice was always level and clear. "And I have information the council does not have on record."\nMr. Salau leaned over to one of his colleagues and said something quietly.\n"Speak," Mama Uzo said from the front row, loudly, looking not at Oby but at Chief Odumegwu. "Let her speak."\nThe chief looked at Mama Uzo. He looked at Oby. He gestured with one hand.\nOby walked to the front of the hall. She stood where she could see the whole room.\n"The depth of the northern lake bed is twenty-seven metres," she said. "Not twelve, as the company''s survey recorded. The survey equipment was either poorly calibrated or the assessment was not thorough. At twenty-seven metres, at the northern bed, there are physical objects. Not rocks. Not natural sediment. Artifacts. Specifically, the Covenant Stones of Nnedimma, placed there in the mid-1800s and recorded in the parish documents at St. Joseph''s under the baptismal name of my ancestor Adaora Nkechi Eze." She paused. "What the company is planning to excavate is a heritage site. What is buried there is not symbolic. It is physical, it is documented in our own community records, and it changes the legal standing of this project entirely."\nThe hall was very quiet.\nMr. Salau''s composed expression had developed a careful quality, the look of someone recalculating.\n"How do you know the depth measurement?" the council member with the papers asked.\nOby looked at him steadily. "The lake told me."\nThe noise that followed was large and mixed and she stood in the middle of it without moving.\nWhen the vote was finally called, the hands for suspension were more than the council had expected and fewer than Oby had hoped. The project was approved to continue. The request for independent review was noted and deferred.\nShe walked back to her seat. Her mother said nothing. She took Oby''s hand under the table and held it with both of hers, and Oby stared at the front of the hall where Mr. Salau was already shaking hands with Chief Odumegwu, and she thought about twenty-seven metres of water and seven stones and a woman in an indigo wrapper who had been waiting more than a century.\nNot for a vote.\nFor what came after one.','\n',char(10)),1003,1,1,NULL,'2026-04-20T20:29:54.466Z','2026-04-20 20:29:54','2026-04-20 20:29:54','2026-04-20T21:00:00.000Z',1,48);
INSERT INTO "chapters" ("id","novel_id","chapter_number","title","content","word_count","is_premium","is_published","audio_url","published_at","created_at","updated_at","scheduled_release_at","part_number","season_id") VALUES(581,70,10,'The Machines Move Anyway',replace('She did not sleep.\nNot because she was afraid, though she was. Not because the knowledge in her chest was loud, though it was louder than it had ever been, a pressure now rather than a warmth, something that had shifted from patient to urgent the moment the vote was formalised and Mr. Salau shook Chief Odumegwu''s hand.\nShe did not sleep because she had decided that if the excavator was going to move at dawn, she was going to be awake when it did. She was going to see it. She was going to be a witness, because some things needed a witness, and she was the only one the lake had asked.\nShe sat at the flat rock on the northern bank from midnight and watched the water.\nThe lake was not bronze tonight. It was dark and completely still, the stillness of something that has finished speaking and is now waiting for events to confirm what it already knows. The crocodile surfaced once around two in the morning, the large one, her one, and floated near the bank for nearly an hour without moving. She sat with it in the dark the way you sit with someone in a hospital corridor, not because there is anything useful to say but because presence is the only thing that remains when everything else has been tried.\nAround three, her mother arrived with a wrapper and a flask of tea and sat down beside her without a word. She poured two cups. They drank in the dark beside the still water and the floating crocodile and said nothing because nothing was the right size for what they were both feeling.\nAt four-thirty, the generator at the construction site coughed on.\nAt five, the floodlights came up along the eastern clearing and spread their flat white light across the tree line.\nAt dawn, the excavator moved.\nShe heard it before she saw it, the deep mechanical grind of something enormous shifting its weight, the sound of the engine climbing to working pitch. Then it appeared through the trees at the eastern edge, its yellow body catching the early light, its claw rising and falling in a slow test motion as the operator settled into the controls.\nIt was not heading for the northern bed. Not yet. It was beginning at the eastern drainage section, as planned. She knew this. She had known the sequencing since Mr. Salau''s slide presentation. The northern bed was weeks away.\nBut the ground broke anyway.\nShe felt it the moment the claw hit earth. Not metaphorically. Physically, in her sternum, a sharp reverberation like a tuning fork struck against bone. She pressed her hand to her chest and her mother turned to look at her and Oby shook her head, she was fine, or she was not fine but she was not in danger, she simply felt it.\nThe lake felt it too.\nThe stillness broke. Not violently. The surface shifted, a slow deep movement that came from below rather than from wind, a rolling that moved outward from the centre the way a breath moves through a body, ribs expanding, surface rising. The crocodile submerged without a sound. The reeds flattened briefly and came back up.\nThen the colour came.\nNot bronze. Not the warm amber of the dreams. The water at the northern bank where she sat turned a deep red, the colour of laterite soil, the colour of old iron, spreading from the centre outward in a slow pulse and fading before it reached the banks, then rising again, then fading. A heartbeat. A distressed heartbeat, irregular and urgent, nothing like the steady rhythm of the stones she had seen in the dream.\nHer mother made a sound beside her. A small sound, involuntary, the sound of a person seeing something they were told about as a child and discovering that being told does not prepare you for the reality.\n"Mama," Oby said.\n"I see it." Her mother''s voice was steady with effort. "I see it."\nAcross the lake, on the eastern bank, two of the construction workers had stopped to look at the water. One of them was pointing. Mr. Salau appeared at the edge of the site in his hard hat and looked for thirty seconds and then said something to the pointing worker and the worker turned back to his task.\nThey were going to continue.\nOby stood up from the rock. The red was still pulsing in the water below her, slower now, as if exhausted, and the knowledge in her chest was not a pressure anymore but a clarity, cold and absolute, the kind of knowing that stops being frightening because it has become too complete for fear to find purchase.\nShe knew what would happen if they reached the northern bed.\nShe knew what Nnedimma had been waiting to tell her at the end of the dream, the part that had dissolved before it was spoken. She knew it the way she knew the depth of the water and the names in the parish register, fully and without doubt.\nIf the stones were displaced, the seal would fracture. What Nnedimma had locked beneath the covenant would not stay locked. And whatever it consumed first, it would not stop at Agulu.\nShe looked at her mother. Her mother looked back at her. Seven years of silence and one night of tea on a rock and the gap between them had collapsed into something that felt, for the first time, like it could bear weight.\n"I have to go back into the dream," Oby said. "I have to let her finish."\n"I know," her mother said.\n"And I need to find the stones before the machines do."\nHer mother reached out and straightened the wrapper around Oby''s shoulders, smoothing it flat with both palms, the gesture precise and deliberate, the gesture of a woman who had finally stopped burning things.\n"Then we find the stones," she said.\nIn the water below them, the red pulsed once more.\nAnd went still.','\n',char(10)),1011,1,1,NULL,'2026-04-20 20:31:36','2026-04-20 20:31:10','2026-04-20 20:31:36','2026-04-20T21:00:00.000Z',1,48);
INSERT INTO "chapters" ("id","novel_id","chapter_number","title","content","word_count","is_premium","is_published","audio_url","published_at","created_at","updated_at","scheduled_release_at","part_number","season_id") VALUES(582,73,1,'The Corner',replace('The 7:42 danfo from Iyana-Ipaja was always late, which meant the men who rode it were always anxious, which meant they never stopped walking when they reached the underpass. Jidenna had learned, in two years of working this corner, that an anxious man will pay ten naira extra just to avoid the USSD code.\nHe was standing at the edge of the underpass when the bus pulled in, its yellow body patched in three places with mismatched paint. He did not move toward the passengers. Uncle Remi had taught him that in the first week: never move toward them like you are chasing. Stand still. Let your stillness be the thing that catches their eye. A running boy looks desperate. A still boy looks like he has something worth stopping for.\n"Omo, give me one gig."\nThe man was already reaching into his pocket before he finished the sentence. He wore a shirt with short sleeves and an ID card bouncing against his chest, carrying the kind of hurry that had nothing to do with the time and everything to do with a boss somewhere waiting.\nJidenna unlocked his itel phone with his thumb. The screen had a crack across the top right corner that had been there since March and had not spread, which he took as a sign that the phone had accepted its condition and decided to move on. He opened the reseller app, typed in the man''s number from memory, confirmed the bundle, and held up the screen.\n"Done."\nThe man handed him three hundred naira and was gone before the notification landed. Jidenna folded the notes and slid them into the left pocket, which was for cash received this morning. The right pocket was for change. He kept them separate because mixing them was how you lost track, and losing track was how you lost money, and losing money was not something Jidenna had any patience for.\nHe did not write things down. He had tried once, a small notebook with a plastic cover, but the ink ran in the rain and he lost a week of records. After that he moved everything into his head and found it more reliable than any notebook. He remembered phone numbers the way other people remembered song lyrics, not by trying, just by having heard them enough times. He remembered what each customer bought, and when, and whether they had been slow to pay. He remembered which ones would round up and which ones would ask for change.\nHis mental ledger had forty one active customers. He had given them no names inside his head, only numbers. This was not coldness. It was precision. His mother always said the Igbo man who cannot count is the Igbo man who goes hungry, and though she said it lightly, the way you say things that are too true to carry heavy, Jidenna had taken it in and kept it.\nThe morning moved the way good mornings moved, steadily and without drama. A woman who ran a provision store near the overhead bridge texted him before she arrived, which she always did, and he had her two gigabyte bundle ready before she stepped off the bus. A secondary school student bought the cheapest plan on the menu and apologized for it, which Jidenna found unnecessary. Money was money. Small money spent consistently was more reliable than big money spent once.\nAt half past nine the rush thinned. Jidenna counted what the left pocket held and moved the notes to his waistband pouch, which was where money went once it had graduated from morning money to real money. He bought a meat pie from the woman three stalls down, not because he was very hungry but because he was hungry enough, and because she gave him a small discount that had started as a gesture eight months ago and had since become an arrangement neither of them had ever mentioned aloud.\nHe ate standing up. Around him Oshodi continued at its usual volume. A man argued with a bus conductor about change that both of them knew did not exist. Two boys younger than Jidenna wove between parked buses selling phone chargers in transparent packaging. A radio somewhere played a song Jidenna recognised but could not name.\nHe had a Commerce class at ten. He knew this the way he knew everything about school, accurately and without urgency. He would go if the corner stayed slow. If a late rush came, which sometimes happened when a bus broke down and rerouted passengers from further up the road, he would stay.\nHe stayed.\nBy noon he had served nineteen customers and his waistband pouch was satisfyingly thick. He sat on the low concrete ledge behind the stalls and opened the itel to check his reseller app. The wholesale balance was holding. He had spent the last two weeks being careful, not because business was bad but because there was a number living at the back of his mind that he was building toward, slowly, the way you build toward something when you cannot afford to rush it and will not allow yourself to stop.\nHe did not tell people about the number. Not his mother, who would worry in ways that would make him feel responsible for her worry. Not Uncle Remi, who had taught him the business and whom Jidenna respected and who had, Jidenna had quietly decided, stopped dreaming at some point without noticing.\nThe number was his. It was specific. It was close enough now that he could feel the edge of it when he counted.\nHe put the phone away and watched a new danfo push through the underpass, horn working hard.\nTomorrow, he thought. Tomorrow the corner would be the same and he would be one day closer.\nHe was still watching when the bus stopped and a woman stepped off with her phone already out, already looking for someone selling data.\nJidenna stood up.','\n',char(10)),997,0,1,NULL,'2026-04-21T14:56:07.888Z','2026-04-21 14:56:07','2026-04-21 14:56:07','2026-04-21T15:10:00.000Z',1,NULL);
INSERT INTO "chapters" ("id","novel_id","chapter_number","title","content","word_count","is_premium","is_published","audio_url","published_at","created_at","updated_at","scheduled_release_at","part_number","season_id") VALUES(583,73,2,' The Kiosk',replace('The canopy went up on a Tuesday, which was the kind of day that had no business changing anything.\nJidenna saw the van first. It was white and clean in the way that things are clean when they have never had to survive Oshodi, no dust in the wheel arches, no scratch along the side panel, no dent from a danfo that had misjudged its own width. It parked at the mouth of the underpass with a confidence that said whoever sent it had not asked permission from anyone on this street.\nHe watched from his corner without moving.\nTwo men stepped out in matching polo shirts, the kind with a network logo embroidered on the chest in the company''s exact brand color. They opened the back of the van and began pulling out equipment with the ease of people who had done this in twelve other locations before this one. A folding table. A branded canopy in red and white. A small generator the size of a school bag. A display board with laminated pricing.\nTwenty meters. That was the distance between where they set up and where Jidenna stood every morning.\nHe counted it with his eyes because counting things was how he processed them.\nA small crowd gathered the way crowds always gather in Oshodi, not by anyone deciding to gather, but by everyone slowing down slightly at the same time until slowness became stillness became a cluster of people craning to see. One of the uniformed men smiled at the crowd and began talking in the smooth, rehearsed voice of someone trained to sound friendly while selling something. He was explaining data packages. He was pointing at the laminated board. He was using the words "affordable" and "official" and "no hidden charges" in the same sentence, which Jidenna noted was a specific choice.\nNo hidden charges. As if the alternative was a boy with hidden charges.\nJidenna turned back to his corner. A regular customer, a tailor who operated from a shop three streets over and bought data every two days without fail, was walking toward him with his phone already out.\n"You see that thing they set up?" the tailor said, tilting his head toward the canopy without breaking stride.\n"I see it," Jidenna said.\n"You worried?"\nJidenna opened the reseller app and typed in the number. "One gig or two?"\nThe tailor looked at him for a moment, then laughed the short laugh of a man who had just received an answer he did not expect. "Two," he said. "And add my wife''s number this time. Same bundle."\nJidenna processed both transactions and collected the cash. The tailor left. Jide put the notes in his left pocket and looked back at the canopy.\nThe two uniformed agents were now fully set up. One of them was handling a customer already, a woman in a wrapper who had her phone pressed against her ear with one hand and was pointing at the price board with the other. The transaction took longer than it should have. The agent typed slowly, confirmed twice, showed the woman her screen, waited for her nod. Professional. Careful. Slow.\nJidenna served three more customers before that single transaction finished.\nHe spent the rest of the morning watching the kiosk the way he watched everything he needed to understand, without staring, without showing that he was watching, filing what he saw into the part of his mind that sorted information by usefulness. He noticed that the agents took a lunch break at the same time, both stepping away from the table together, leaving a handwritten sign that said Back in 15 minutes in English that not everyone passing through Oshodi would read. He noticed they did not know their customers. Every person who approached the table was a stranger to them. They asked for phone numbers rather than already knowing them. They confirmed spellings of names for registration forms.\nHe noticed that the pricing on the laminated board was lower than his on the entry level packages. Not by much. But enough.\nBy three o''clock he had counted seven customers he recognised who had walked past his corner and stopped at the canopy instead. He did not let his face say anything about this. He served the customers who came to him and he thought about the seven.\nAt a quarter to five one of the agents began folding the display board. By five they were loading the generator back into the van. By ten past five the canopy was down and the white van was threading its way out of the underpass with the same clean confidence it had arrived with.\nJidenna was still on his corner.\nHe served two more customers after the van left, men coming from the direction of the bus stop with the loosened energy of people who were finally, after a long day, going home. He knew both their numbers. He had their bundles processed before they finished saying hello.\nHe counted his earnings while he walked to the bus stop. The number was lower than Monday. Lower than last Friday. He had expected this and decided in advance that expecting it would keep it from meaning more than it meant, which was that today was a difficult day, not that all days going forward would be.\nThe white van would come back tomorrow. He knew this.\nHe also knew something the men in the matching polo shirts did not know, something that had nothing to do with pricing or canopies or laminated boards.\nHe knew this street.\nHe had been learning it since he was fourteen and it had been teaching him every single day since, and no company van that had never once sat in an Oshodi go slow was going to read it faster than he could.\nHe kept walking. The number at the back of his mind held steady.','\n',char(10)),987,0,1,NULL,'2026-04-21T14:56:58.038Z','2026-04-21 14:56:58','2026-04-21 14:56:58','2026-04-21T15:10:00.000Z',1,NULL);
INSERT INTO "chapters" ("id","novel_id","chapter_number","title","content","word_count","is_premium","is_published","audio_url","published_at","created_at","updated_at","scheduled_release_at","part_number","season_id") VALUES(584,73,3,'Margin',replace('Mr. Fashola wrote two numbers on the board and underlined them both.\n"Same product," he said, turning to face the class. "Two sellers. Different prices. What happens?"\nThe classroom had survived many years of use and showed every one of them, desks with carved initials, a ceiling fan that worked on one speed only, windows that let in more noise than light. Jidenna sat in the third row, far enough from the front to think and close enough to the board to read without effort. He had his notebook open. He had written the two numbers down before Mr. Fashola finished underlining them, because writing things down was a habit and habits did not pause for context.\nA girl in the front row raised her hand. "The cheaper one gets more customers."\n"Correct," Mr. Fashola said. "And what happens to the seller with the higher price?"\nNobody answered immediately. Jidenna looked at the two numbers on the board. The gap between them was small. Fifty naira. He thought about the laminated pricing board at the kiosk and the seven customers who had walked past him yesterday, and he felt something move in his chest that was not quite worry and not quite anger. It was closer to clarity. He had a name for the thing happening to his corner now. He had a textbook definition for it and a teacher drawing it on a board in blue chalk and a class full of students treating it like an abstract exercise.\nIt was not abstract. It was Tuesday morning and his numbers were down.\n"He loses customers," a boy from the back offered.\n"He loses customers," Mr. Fashola agreed. "This is price competition. When a new seller enters a market with a lower price, existing sellers face a choice. Match the price, find another advantage, or lose the customer." He paused. "Write that down."\nJidenna wrote it down, though he already knew it. He had known it since before it had a name.\nBy the time he reached the corner at half past eleven the canopy was already up and one of the agents was in conversation with a woman Jidenna recognised immediately. She lived in his mental ledger as 0803, a fabric trader who bought one gigabyte every three days and always paid in exact change because she kept her money sorted by denomination in a purse with separate compartments. She had been his customer for fourteen months.\nHe watched her complete her transaction at the kiosk. She did not look in his direction.\nHe set up at his corner and unlocked the itel. Three messages had come in while he was at school, customers sending their numbers ahead of arrival. He prepared their bundles in advance and waited.\nTwo of the three came. The third did not.\nAt noon a bus driver who bought data every market day came through the underpass, saw the kiosk, slowed, and stopped. Jidenna watched him read the laminated board. The driver was a practical man who made decisions the way practical men do, quickly and without ceremony. He stepped up to the kiosk table.\nThat was three defections in one morning.\nJidenna served a woman who was new to his corner, a recommendation from Mama Titi two stalls down, and he was pleasant with her because she deserved pleasantness and because the quality of his service was not something he would allow a canopy and two polo shirts to affect.\nBut he was counting. He was always counting.\nHe thought about what Mr. Fashola had written on the board. Match the price. Find another advantage. Lose the customer. Three options, and only one of them was not a version of surrender.\nThe kiosk''s entry level price was forty naira below his on the smallest bundle. To match it he would have to compress his margin to a point that made the day''s work barely worth the standing. He had done the calculation twice since Tuesday and it came out the same way both times. Matching the price was not a strategy. It was a slow way of closing a business while telling yourself you were fighting to save it.\nWhich left the second option.\nHe spent the afternoon thinking about advantage the way Mr. Fashola had not quite explained it, not as an abstract term in a textbook but as a specific and practical thing that existed in the gap between what the kiosk could do and what it could not. He had already started this list in his head two days ago. He returned to it now and added to it carefully.\nThe kiosk did not know anyone. Every customer was a new face, a new number typed in slowly, a new transaction that began from zero. Jidenna knew forty one people by number and by habit and by the particular way each of them related to money. That was not nothing. That was two years of daily work that could not be printed on a laminated board and assembled under a canopy in forty minutes.\nThe kiosk closed at five. He had confirmed this on Tuesday and confirmed it again today when the agents began packing at ten to five with the efficiency of people following a schedule written by someone who had never stood in Oshodi heat for a full working day.\nJidenna stayed until half past six and served four customers in that window. Small sales. But they were his.\nHe was walking to the bus stop when his phone buzzed. A message from 0803. It said: Their network was slow. I go still come your side tomorrow.\nHe read it once and felt the small warmth of it and allowed himself that much.\nThen he looked up.\nAcross the underpass, one of the kiosk agents was on a phone call, turned slightly away from the street, nodding at whatever was being said on the other end. In his free hand was a notepad, and he was writing something down with the focused attention of a man receiving instructions rather than giving them. Jidenna watched him tear the top sheet off, fold it once, and slide it into his shirt pocket.\nThe agent ended the call. He looked at the underpass for a moment, the way a person looks at a place they are measuring rather than seeing. Then he looked directly at Jidenna''s corner.\nJidenna did not look away.\nHe did not know what had just been decided in that phone call.\nHe knew that something had.','\n',char(10)),1089,0,1,NULL,'2026-04-28 13:15:12','2026-04-21 14:58:29','2026-04-28 13:15:12',NULL,1,NULL);
INSERT INTO "chapters" ("id","novel_id","chapter_number","title","content","word_count","is_premium","is_published","audio_url","published_at","created_at","updated_at","scheduled_release_at","part_number","season_id") VALUES(585,73,4,' What They Cannot Do',replace('Jidenna started the list on Thursday morning, in the back of his Commerce notebook, on a page three sections away from Mr. Fashola''s notes so nobody glancing over his shoulder would connect the two things.\nHe drew a line down the middle of the page. On the left side he wrote: What they have. On the right side he wrote: What they cannot do.\nThe left side filled quickly. Official network backing. Laminated pricing. A generator that meant no interruptions when NEPA took light. A branded canopy that made customers feel they were dealing with something real and registered and unlikely to disappear. Two agents who wore the same shirt and therefore looked like a system rather than a person.\nHe stared at the right side for a moment, then began.\nThey could not remember a face. He had tested this on Wednesday, watching from his corner as a woman he recognised from the underpass approached the kiosk for the second time. The agent had asked for her number as if she had never stood at that table before, because to him she had not. There was no memory there. No recognition. No "your usual?" The transaction was clean and correct and completely without texture.\nThey could not extend credit. This was structural, not personal. An agent working on behalf of a company could not look a customer in the eye and say, pay me Friday, because Friday was not his problem to manage. Accountability flowed upward in that arrangement, not outward. The kiosk could only take money it already had in front of it.\nThey could not move. The table was where the table was. The canopy was where the canopy was. If your shop was three streets over and you ran out of data at midday, the kiosk required you to come to it. Jidenna could come to you.\nHe looked at the right side of the page. Three things. He tapped the pen against the notebook and thought about which one to test first.\nUncle Remi called at two o''clock, which was unusual. He was not a man who called in the middle of a work day without reason.\n"How the corner dey?" he said, in the particular mix of Yoruba inflection and Lagos street Jidenna had heard from him since childhood.\n"E dey move," Jidenna said.\n"I hear say one of the networks set up kiosk for that area."\nJidenna was quiet for a moment. He was not surprised that Uncle Remi knew. The man had been in the data business since before Jidenna was in secondary school. He had a network of information that operated the same way his business did, quietly, through relationships built over years.\n"They set up Tuesday," Jidenna said.\n"How your numbers?"\n"Down a little."\nUncle Remi made a sound that was not quite a hiss and not quite a sigh. "Jide, my brother, just hold steady. These kiosk things, they come and they go. Head office will send them somewhere else in two, three months. Just keep your head down, keep your price where it is, and wait them out."\nJidenna listened. He always listened to Uncle Remi, not because he agreed with everything the man said but because disagreement was something you did inside your head, quietly, after the conversation, when you had time to sort what was useful from what was not.\n"Yes sir," he said.\n"Good boy. Come and see me this weekend."\nHe filed it away after the call ended. Hold steady. Wait them out. He understood where the advice came from. Uncle Remi had been on his own corner, metaphorically speaking, for seventeen years, and holding steady had kept him there for all seventeen. It was not wrong advice. It was just advice built for a different ambition.\nJidenna was not trying to stay on the corner. He was trying to leave it as something larger than he found it.\nHe tested the third item on the list that same afternoon.\nMama Titi''s provision store was a ten minute walk from the underpass, tucked into a row of stalls near the main market. Jidenna had been to the store twice before, both times to deliver bundles she had ordered by text. Today he went without being called.\nShe looked up from her counter when he came in. "Jidenna. You bring data?"\n"I come check on you," he said. "Your bundle dey expire tomorrow morning. You go need top up before you open."\nShe studied him for a moment with the careful eyes of a woman who had been in business long enough to know that people who came without being called usually wanted something. Then she saw that he did not have the posture of someone wanting something. He had the posture of someone delivering something.\n"Top me up now then," she said, reaching for her purse. "Two gig. And check my husband''s number, e been dey complain say his own dey finish fast."\nJidenna topped up both numbers and added the husband''s to his mental ledger. He did not charge for the extra trip. The trip was not a service he was billing for. It was a fact he was establishing, which was that he was the kind of seller who came to you, who knew when your bundle was expiring before you did, who moved.\nThat was not on any laminated board in Oshodi.\nHe walked back to the corner as the afternoon began its slow lean toward evening, and he thought about the right side of the page in his Commerce notebook.\nThree things the kiosk could not do.\nHe had tested one. It had worked exactly as he expected.\nHe allowed himself a small, private satisfaction, the kind that did not show on his face.','\n',char(10)),964,1,1,NULL,'2026-04-21T14:59:43.930Z','2026-04-21 14:59:43','2026-04-21 14:59:43','2026-04-21T15:10:00.000Z',1,NULL);
INSERT INTO "chapters" ("id","novel_id","chapter_number","title","content","word_count","is_premium","is_published","audio_url","published_at","created_at","updated_at","scheduled_release_at","part_number","season_id") VALUES(586,73,5,'Credit',replace('The idea came to him on Friday morning while he was watching the kiosk.\nOne of the agents was turning away a woman Jidenna recognised, a pepper seller who set up every weekday near the entrance of the underpass market. She was a small woman who moved with the permanent urgency of someone who had too many things to do and not enough hours to do them in. She had her phone out and was pointing at the data packages on the laminated board, but her other hand was empty. No cash. She said something to the agent, gesturing toward the market, and the agent shook his head in the polite, practised way of someone who had a policy to enforce and no authority to bend it.\nNo cash, no data. That was the policy.\nJidenna watched the pepper seller walk away from the kiosk with her phone still in her hand and her problem still unsolved. Then he stepped away from his corner and walked toward her.\n"Mama, which bundle you want?"\nShe looked at him with the particular suspicion of someone who had just been disappointed and was not ready to be offered something else. "I no get cash on me now. My customer go pay me by ten."\n"I go sort you," Jidenna said. "Pay me when your customer pay you."\nShe looked at him for a long moment. He held her gaze without filling the silence, because filling the silence would have made it sound like a sales pitch, and it was not a sales pitch. It was a proposition between two people who had been operating in the same space long enough to have established something, even if neither of them had ever named it.\n"One gig," she said finally.\nHe processed the bundle and she walked back to her stall with data on her phone. He walked back to his corner with nothing in his pocket but the knowledge of what she owed him, which he entered into his mental ledger the way he entered everything, accurately and permanently.\nBy ten fifteen she appeared at his corner with exact change and an additional fifty naira she pressed into his hand without explanation. He did not question it. He understood what it was.\nHe extended credit two more times that day. The first was to a young man who worked at one of the phone repair stalls and whose payment had been delayed by a difficult customer who was arguing about a screen replacement job. The second was to a woman whose name he did not know but whose number had been in his ledger for eleven months, a reliable customer whose history of payment was so consistent it functioned as its own kind of guarantee.\nBoth paid before the end of the day.\nOn Saturday he called Mama Titi.\n"I wan start something," he told her. "For my regular customers. Data now, pay later. But only people I know well."\nMama Titi was quiet for a moment. When she spoke her voice had the particular quality it got when she was weighing something seriously. "How you go protect yourself? Person fit collect data and disappear."\n"Only people with history," Jidenna said. "If you don buy from me minimum three months, consistent, then I go extend you credit. Not everybody. Specific people."\nShe considered this. "You go need to know who is who."\n"I already know," he said.\nHe heard the smile in her pause before she spoke again. "Jide, you get sense. Do it."\nHe did not extend credit to everyone. He went through his mental ledger with the same precision he applied to everything and identified nine customers whose payment history was solid enough to qualify. He contacted each of them individually, not with a broadcast message but with a personal text that used their name and referenced their usual bundle, because the point was not to announce a policy. The point was to make each person feel that they had been specifically chosen, which they had.\nEight of the nine responded well.\nThe ninth was a man Jidenna had been serving for seven months, a trader who bought two gigabytes every few days and had never once been late. Jidenna had extended him credit on Monday morning without hesitation, four hundred and fifty naira worth of data on the understanding that payment would come by Wednesday.\nWednesday came. No payment.\nHe sent a message on Wednesday evening. Polite. Direct. No threat in it because there was no threat available to him, which was a fact he had accepted before he started.\nThursday passed.\nFriday morning the man walked past the corner without stopping, his eyes going to the kiosk instead. Jidenna watched him complete his transaction there and walk on, and he felt the specific coldness of a person who has just understood something about another person that they had not wanted to know.\nHe did not chase. He did not send another message. He opened his mental ledger and moved the man''s number from the active column to a place he thought of as closed, a category with no drama attached to it, only clarity. The four hundred and fifty naira was the cost of the lesson. He calculated it as a business expense, the way you calculated any cost that produced useful information, and he moved on.\nThat evening Mama Titi appeared at his corner before he packed up. She pressed five hundred naira into his hand and said nothing else.\nHe looked at her.\n"For the sense you get," she said, and walked back to her stall.\nHe stood with the note in his hand for a moment, long enough to understand that she had somehow heard about the man, the way Oshodi heard about everything eventually, and had decided in her own way to balance the account.\nHe put the money in his waistband pouch. The ledger in his head updated itself.\nNine customers. Eight successes. One lesson. One unexpected addition.\nThe corner, he thought, was still teaching him.','\n',char(10)),1011,1,1,NULL,'2026-04-21T15:00:43.613Z','2026-04-21 15:00:43','2026-04-21 15:00:43','2026-04-21T15:10:00.000Z',1,NULL);
INSERT INTO "chapters" ("id","novel_id","chapter_number","title","content","word_count","is_premium","is_published","audio_url","published_at","created_at","updated_at","scheduled_release_at","part_number","season_id") VALUES(587,73,6,' House Calls',replace('He mapped the route on Sunday, in his head, the way he mapped everything.\nFourteen customers within a twenty minute radius of the underpass. Not walking distance from the kiosk, but walking distance from Jidenna, because Jidenna was not fixed to a table. He had a phone, a reseller app, and two legs that had been carrying him across Oshodi since he was fourteen years old. The kiosk could not follow a customer home. Jidenna could show up before the customer remembered they needed him.\nHe started Monday morning before the corner got busy.\nHis first stop was a woman who ran a small chop house on a street behind the main market. She bought data every Monday without fail but always came to him between noon and one, during the window when her morning rush was done and her afternoon prep had not yet started. Jidenna arrived at her shop at eight thirty with her usual bundle already prepared.\nShe looked up from the pot she was stirring and stared at him with the particular expression of someone trying to decide if they were surprised or not.\n"I come before you come to me," Jidenna said simply.\nShe laughed, wiped her hand on her wrapper, and reached for her purse. "You too much," she said, and paid him and went back to her pot.\nHe was back at his corner by nine fifteen with three transactions already completed, three customers served before the kiosk agents had finished setting up their canopy for the day.\nHe spent the rest of the week building the route properly, learning which customers preferred morning visits and which ones found it easier to pay at midday when their first sales had come in. He learned which streets had gates that required him to call ahead and which stalls he could walk into without announcement. He learned that showing up in person, consistently and without being summoned, did something to a customer relationship that no text message could replicate. It said: I have thought about you specifically, before you thought about yourself.\nThree new customers came to him that week through referrals from the house call route. People talked. That was also something the kiosk could not engineer.\nHe saw Mr. Balogun on Thursday afternoon.\nThe man was standing outside a phone accessories shop two streets from the underpass, talking to the shop owner with the relaxed posture of someone who had nowhere urgent to be. He was older than Jidenna remembered, heavier in the face, with grey working its way into the hair above his ears. But the laugh was the same, the big Yoruba laugh that filled a space and expected the space to receive it.\nJidenna had last seen him four years ago, at a function his mother had taken him to, one of those gatherings of people who knew each other from a long time before and whose connections Jidenna had never fully mapped. His mother had pointed Mr. Balogun out across the room and said quietly, that one knew your father well. She had said it the way she said anything about his father, with a flatness that was not quite sadness and not quite anger, just the voice of a woman who had decided that certain things would not take up more space than they were owed.\nMr. Balogun saw him before Jidenna could decide to cross the street.\n"Ha. Is this not Adaeze''s son?" He said it with the warmth of a man who was genuinely pleased, spreading his hands slightly as if Jidenna''s appearance in this street was a gift delivered at the right time. "You don grow, my brother. What are you doing in this area?"\n"I work around here," Jidenna said.\n"Work? Which kind work?" He looked at Jidenna the way adults looked at teenagers they had last seen as children, measuring the distance between memory and reality.\n"Data business," Jidenna said. He kept his voice even and his face pleasant, the specific pleasantness that required a little effort to hold and gave nothing away.\nMr. Balogun laughed the big laugh. "Serious? Your papa used to do small business too, you know. Before he" He paused, adjusted, moved on. "He was always one to find an angle, your father. You take after him."\nJidenna held the pleasantness in place.\n"How is your mama?" Mr. Balogun said.\n"She is fine, sir. Thank you."\n"Tell her Balogun asked after her. We go see. She has my number?"\n"I am not sure, sir."\nMr. Balogun reached into his shirt pocket and produced a card, the kind printed on slightly too thick paper by someone who took his own importance seriously. Jidenna took it with both hands the way he had been raised to receive things from elders and put it in his pocket.\n"Good boy," Mr. Balogun said, and turned back to the shop owner as if the conversation had reached its natural end.\nJidenna walked back toward the underpass at the same pace he had arrived with. He passed three stalls and a man selling groundnuts from a tray balanced on his head and a group of boys arguing over a phone screen. He kept his face neutral and his hands steady.\nHe did not take the card out of his pocket again. He knew he would not give it to his mother. He knew she would not want it. And he knew that whatever his father had been, angle finder or abandoner or both at once, it was not the inheritance Jidenna was building toward.\nThe number at the back of his mind was his own. He had counted every naira of it himself.\nHe got back to his corner and served the next customer waiting there, and the one after that, and did not think about Mr. Balogun again for the rest of the day.\nAlmost.','\n',char(10)),981,1,1,NULL,'2026-04-21T15:01:52.150Z','2026-04-21 15:01:52','2026-04-21 15:01:52','2026-04-21T15:10:00.000Z',1,NULL);
INSERT INTO "chapters" ("id","novel_id","chapter_number","title","content","word_count","is_premium","is_published","audio_url","published_at","created_at","updated_at","scheduled_release_at","part_number","season_id") VALUES(588,73,7,' The Network',replace('The boy had been watching him for three days before he said anything.\nJidenna had noticed him the way he noticed everything on this street, peripherally, without making it obvious. He was young, eleven or twelve years old at most, with the particular alertness of a child who had learned early that paying attention was a survival skill. He sold pure water from a plastic crate he dragged between the bus stop and the underpass entrance, but his eyes followed Jidenna''s transactions with an interest that had nothing to do with water.\nOn Thursday the boy appeared at his corner during the mid morning lull, crate parked behind him, hands clasped in front of him in the careful posture of someone who had rehearsed this moment.\n"Oga," he said.\nJidenna looked at him. "You dey sell water and you dey call me oga?"\nThe boy''s mouth moved toward a smile and then steadied itself. He was taking this seriously and did not want the seriousness undermined. "I wan learn the data business," he said. "I go work for you. I go carry the customers come, I go help you when rush plenty. I no go collect salary for now. Just teach me."\nJidenna studied him for a moment. The boy held his gaze with the effort of someone who knew that looking away first would cost him something.\n"What is your name?"\n"Tunde."\n"How old are you, Tunde?"\n"Twelve."\nJidenna looked at the water crate. "That one na your business or your madam own?"\n"My madam own. She go collect the money when I return."\n"So you dey hustle for another person."\nTunde nodded, and something in the nod said he understood exactly what that meant and had been understanding it for some time.\nJidenna did not answer immediately. He served two customers who came in quick succession, processing both transactions without breaking his thinking, which was something he had trained himself to do over two years of running a business and attending school and managing a mental ledger all at the same time.\nHe thought about the day he had gone to Uncle Remi.\nHe had been fourteen, not twelve, but the posture had been the same. The clasped hands. The rehearsed opening sentence. The decision to take himself seriously before anyone else had agreed to. Uncle Remi had looked at him for a long moment and then said, come back Saturday, I go show you the app. Just those words. No ceremony. No long speech about responsibility and hard work. Just a door opened at the right width.\nHe thought about what it had meant to have that door opened.\n"I cannot take you as a worker," Jidenna said.\nTunde''s face did not collapse but it tightened, the way faces tighten when they are preparing to absorb a disappointment they had told themselves not to expect.\n"But I go teach you," Jidenna continued. "Different thing."\nThe tightness released slowly, replaced by something more careful than excitement.\n"Every day you dey here, during the slow periods, come and stand with me. Watch the transactions. Ask me anything you want to ask. I go answer. But you must finish your water work first. You no go shortchange your madam because you wan learn from me. You understand?"\n"Yes," Tunde said.\n"And school. You dey go school?"\n"Morning session."\n"Good. Keep going."\nTunde nodded with the full seriousness of someone signing an agreement.\nJidenna turned back to the underpass and said nothing else, because nothing else was needed. The boy retrieved his water crate and went back to work, but Jidenna noticed that his route now kept him within sight of the corner, close enough to observe without abandoning his own business.\nSmart, Jidenna thought. The boy had already understood something about proximity.\nBy afternoon Tunde had completed three rounds of water sales and returned to the corner during each rest period, standing quietly to the side and watching without interrupting. When a customer came he stepped back automatically to give the transaction room. When the customer left he stepped forward again.\nOn his third return Jidenna asked him a question.\n"That woman wey just buy from me. She always buy the same bundle at the same time every day. Why you think she do that?"\nTunde thought about it. "Because she always need the same thing?"\n"Yes. What that tell you about how to serve her?"\nA pause. "Have am ready before she ask."\nJidenna looked at him. "You go far," he said simply.\nTunde''s face did something that was not quite a smile, something more private than that, the expression of a person who has just received the specific confirmation they did not know they were waiting for.\nBy late afternoon Mama Titi had appeared at the edge of the corner, as she sometimes did when business was slow, to exchange the particular kind of conversation that was less talking and more two people thinking aloud near each other. She watched Tunde for a moment.\n"He yours?" she asked Jidenna quietly.\n"I am teaching him," Jidenna said.\nMama Titi was quiet for a moment. Then she said, "You know say na exactly how your uncle start with you."\nJidenna knew. He had been thinking about it since morning, about the chain of it, the way useful knowledge either stopped with a person or moved through them. Uncle Remi had opened a door and Jidenna had walked through it and built something larger than what he had been shown. Now a twelve year old boy was standing at a corner with clasped hands and a rehearsed sentence, and the door was Jidenna''s to open or close.\nHe watched Tunde drag his water crate toward the bus stop for the last round of the day, moving with the quick efficiency of a boy who had decided that everything he did from now on was preparation for something else.\nThe door, Jidenna had already decided, was open.','\n',char(10)),995,1,1,NULL,'2026-04-21T15:03:15.051Z','2026-04-21 15:03:15','2026-04-21 15:03:15','2026-04-21T15:10:00.000Z',1,NULL);
INSERT INTO "chapters" ("id","novel_id","chapter_number","title","content","word_count","is_premium","is_published","audio_url","published_at","created_at","updated_at","scheduled_release_at","part_number","season_id") VALUES(589,73,8,'The Kiosk Closes Early',replace('It started as a pattern so small Jidenna almost filed it away as nothing.\nThe first time the kiosk closed at ten to five he thought it was a personal matter, one of the agents needing to leave, some arrangement made between them and their supervisor that had nothing to do with the schedule. He noted it without attaching meaning to it and went on serving his own customers until the light began to change color over the underpass.\nThe second time was a Thursday. Quarter to five. One agent folding the display board while the other loaded the generator with the unhurried ease of a man who knew exactly when his workday ended and had no intention of extending it by a single minute.\nThe third time Jidenna checked his phone when the packing started. Four forty two.\nHe stood at his corner and watched the white van reverse out of the underpass and he thought about what the pattern meant, which was not complicated. It meant that somewhere in an office building far from Oshodi, a person who had never stood in this heat was deciding when the agents'' workday ended. It meant that the kiosk was not a living thing that responded to the street. It was a scheduled thing. It arrived when it was told to arrive and it left when it was told to leave and in the space between those two instructions it had no ability to improvise.\nJidenna stayed until six thirty and served eleven customers in the gap.\nBy the third week he had begun to call it the window, in his head, that stretch of time between the van''s departure and full dark when the street was still busy but the only data seller operating was him. Workers coming off late shifts. Traders finishing final transactions. Bus conductors and drivers running low on data after a full day of calls. All of them arriving at the underpass after five with a need and, now, only one option.\nHe did not raise his prices in the window. He had considered it once and rejected it immediately. The point was not to extract maximum naira from the gap. The point was to establish himself as the consistent presence, the one that was always there, so that when any of those after five customers thought about data, the thought and his face arrived at the same time.\nTunde had started timing his last water round to end at five so he could watch the window. He stood at the edge of the corner without being asked, not interfering, just observing with the focused attention of someone who understood that what he was watching was instruction.\n"Why you no charge more when they go?" Tunde asked one evening, tilting his head toward the space where the canopy had been.\nJidenna looked at him. "Because I want them back tomorrow."\nTunde turned this over in his mind. "If they go come back anyway, why you need low price?"\n"Because tomorrow they go have a choice again. I want the choice to already be made before they reach the underpass."\nThe boy nodded slowly, and Jidenna could see the idea finding its shape inside him.\nOn a Wednesday evening three weeks after he had first noticed the pattern, something happened that Jidenna had not planned for.\nA man in a company shirt, not one of the kiosk agents but someone older, with a senior employee identification card around his neck, stopped at the underpass at twenty past five. He looked at the spot where the canopy had been, already gone for twenty minutes, then looked around and found Jidenna.\nHe walked over without hesitation.\n"You sell data?"\n"Yes sir."\nThe man named a package and Jidenna processed it. The transaction took forty seconds. The man checked his phone, nodded with the satisfaction of someone whose problem had been efficiently solved, and walked on.\nHe came back the following Tuesday. And the Thursday after that.\nJidenna added him to the mental ledger.\nBy the end of the month the window had given him sixteen new recurring customers. Not all of them had come specifically because the kiosk was closed. Some had simply been walking past and seen him and decided that now was as good a time as any. But they had stayed, and they were returning, and that was the thing that mattered.\nMama Titi stopped by on a Friday evening as he was packing up, later than usual because the window had been busy.\n"You look different," she said, studying him with the direct attention she applied to everything.\n"I am the same," Jidenna said.\nShe shook her head. "No. Three weeks ago you were reacting. Now you are deciding." She said it the way she said true things, without decoration, without waiting to see if it landed. Then she went back to her stall.\nHe thought about the word on his way to the bus stop. Reacting. Deciding. She had put a boundary between two phases of the last few weeks and named exactly where the boundary was, which was around the time he had stopped watching the kiosk for what it was doing to him and started watching it for what it was showing him.\nThe canopy arrived every morning and left every evening at a time that had been decided by people who were not here.\nJidenna arrived every morning and left when the work was done.\nThat difference, quiet as it was, had changed the corner. Not dramatically. Not in a way anyone would write down or photograph. But the traders knew it. The regular customers knew it. Tunde knew it.\nThe corner was his again, and this time he had not taken it back by fighting.\nHe had simply stayed.','\n',char(10)),969,1,1,NULL,'2026-04-21T15:04:21.750Z','2026-04-21 15:04:21','2026-04-21 15:04:21','2026-04-21T15:10:00.000Z',1,NULL);
INSERT INTO "chapters" ("id","novel_id","chapter_number","title","content","word_count","is_premium","is_published","audio_url","published_at","created_at","updated_at","scheduled_release_at","part_number","season_id") VALUES(590,73,9,'The Number',replace('LHe counted it on a Sunday morning, alone in the room he shared with nobody because his mother had gone to church and the apartment was quiet in the particular way it was only quiet one morning a week.\nHe emptied the waistband pouch onto the bed. Then the secondary pouch he kept inside his school bag, the one his mother did not know about, not because he was hiding it from her but because some things needed to exist without the weight of another person''s hope pressing down on them. Then the small envelope at the back of his Commerce notebook where he kept the overflow when the pouches got full.\nHe sorted the notes by denomination the way Mama Titi had taught him without meaning to, the way you absorb a practice from someone you spend enough time watching. Thousands together. Five hundreds together. Two hundreds in their own pile. The smaller notes at the bottom because they were the oldest, the ones that had been sitting longest, and there was something in him that wanted to acknowledge that, the patience of small money accumulating into something larger than itself.\nThen he counted.\nThe first count gave him a number. He put the notes down, looked at the ceiling for a moment, and counted again from the beginning, not because he distrusted himself but because a number this close to real deserved to be confirmed twice. Same number both times. He sat with it for a while, feeling the shape of it, the specific texture of something that had lived in his head as an idea for two years and was now a fact lying on a bedsheet in the morning light.\nForty three thousand, eight hundred naira.\nThe number he needed was forty seven thousand.\nThree thousand, two hundred naira away.\nHe stayed sitting on the edge of the bed with the sorted notes in front of him and thought about two years. He thought about the first week on the corner when his hands shook slightly every time a customer walked away without buying, when he recounted his wholesale balance three times a day because he could not yet trust that the business was real. He thought about the itel phone and the cracked screen and the forty one customers who existed as numbers in his head, each one a relationship built naira by naira over months of showing up. He thought about the kiosk arriving and the seven defections and the list in the back of his Commerce notebook and the pepper seller who had paid him back with an extra fifty naira pressed silently into his hand.\nAll of it had been moving toward this number. Every early morning and late window and house call and credit arrangement had been feeding it, quietly, the way a river feeds from sources so small you would never think to trace them.\nThree thousand, two hundred naira.\nOne good week.\nHe called Uncle Remi that afternoon. Not because he had decided to tell him but because he had been sitting with the gap for five hours and needed to say the number out loud to someone, needed to hear it leave his mouth and exist in a space outside his own head.\nUncle Remi listened without interrupting, which was not his usual way. It told Jidenna the man understood this was not a casual conversation.\nWhen Jidenna finished explaining, the CAC registration, the authorized sub dealer status, the minimum first stock purchase, the certificate that would make him a legal operator inside the network''s own system, Uncle Remi was quiet for a long moment.\nThen he said: "Jide. You want to put forty seven thousand naira into a registration? That is the money you have been saving all this time? For paper?"\n"Not just paper," Jidenna said. "Authorization. Official dealership. The network cannot remove an authorized dealer the way they can remove me now. Right now I am operating in a grey space. This closes the grey."\n"They can still pressure you. You go still be one boy on a corner with a certificate."\n"I go be one boy on a corner with a certificate that says I am operating legally inside their own system. They set up a kiosk to compete with people like me. I am about to become the kind of person their kiosk cannot compete with."\nUncle Remi exhaled slowly. "This na serious risk. What if the sub dealer program changes? What if the network restructures their reseller tiers? You go don spend forty seven thousand on something wey don expire."\n"Then I go adapt," Jidenna said. "Same way I adapted when the kiosk came."\nThe silence on the line had a particular quality, not the silence of a man thinking but the silence of a man who has recognised something and is deciding how to carry it. When Uncle Remi spoke again his voice was quieter.\n"You don already decide," he said. It was not a question.\n"I called to tell you, sir. Not to ask."\nAnother silence. Then Uncle Remi said, "Your father used to do that too. Call people after he had decided, not before." He said it without weight, without the complicated history the comparison could have carried. He said it like a man leaving a fact on a table and walking away from it.\nJidenna said nothing.\n"Be careful," Uncle Remi said finally. "Build the cushion after the registration. Do not spend the certificate money and leave yourself nothing."\n"Yes sir."\nAfter the call he sat with the phone in his hand and thought about Uncle Remi, seventeen years on the same corner, the ceiling that had been mistaken for a floor. The man was not wrong about the risk. The program could change. The model could shift. But Jidenna had watched a corporate kiosk arrive and adapted. Had built a credit system that produced eight loyal customers and one useful lesson. Had mapped a house call route that turned proximity into relationship. Every disruption had made him larger than itself.\nHe could manage a risk he had studied this carefully.\nHe opened his Commerce notebook and turned to the page with the line down the middle. Below the three things the kiosk could not do he wrote a fourth line.\nThey cannot become me.\nHe closed the notebook. Then he opened his reseller app and looked at the week ahead and began, quietly and without ceremony, to plan how to close three thousand, two hundred naira in six days.\nBy Sunday evening he knew exactly how.','\n',char(10)),1099,1,1,NULL,'2026-04-21 15:11:52','2026-04-21 15:06:03','2026-04-21 15:11:52',NULL,1,NULL);
INSERT INTO "chapters" ("id","novel_id","chapter_number","title","content","word_count","is_premium","is_published","audio_url","published_at","created_at","updated_at","scheduled_release_at","part_number","season_id") VALUES(591,73,10,'What Markets Are',replace('He closed the gap in six days.\nNot through anything dramatic. Through the application of everything the corner had taught him over two years, applied at full concentration for one week. He extended his window hours by forty five minutes on both ends of the day. He activated four dormant customer numbers from the back of his mental ledger, people who had bought once or twice and disappeared, reaching out with a personal message that referenced their last purchase. Three of the four responded. He asked Tunde to take his water route through two streets Jidenna had not yet covered on the house call map and to mention, naturally, that there was a data seller on the underpass corner who came to you.\nTwo new customers arrived by Wednesday with Tunde''s name in their mouths.\nOn Saturday morning he counted again. Forty seven thousand, three hundred and fifty naira.\nHe sat with it for a long time. Not celebrating. Just sitting, the way you sit with something that has taken two years to become real and deserves more than a quick acknowledgment before you move on to the next thing.\nThen he got up and got dressed and went to do what needed to be done.\nThe CAC office visit took most of the morning, which he had anticipated. He had prepared his documents the night before, spread on the bed in the order they would be needed, and he arrived early enough to be in the first group processed. He filled the forms with the careful handwriting of someone who understood that the quality of your paperwork said something about the quality of your seriousness. He paid the fees at the designated counter and received his acknowledgment slip and was told the certificate processing timeline.\nHe walked out of the building into the afternoon heat with a slip of paper in his hand that was not yet a certificate but was already a fact.\nOn his way back to Oshodi he stopped at his school because Mr. Fashola had asked him twice that week to come in during the weekend for a brief conversation about his Commerce results, which had improved in the last assessment in ways the teacher apparently wanted to discuss.\nMr. Fashola was in the staff room, marking exercise books with the focused attention of a man who took the work seriously. He looked up when Jidenna appeared at the door.\n"Sit down, Jidenna."\nHe sat.\nMr. Fashola put down his pen. "Your last assessment. The question on market entry and competitive response. You wrote about price competition, service differentiation, mobility advantage, and customer relationship as sequential strategies." He paused. "Where did you learn to structure an argument like that?"\nJidenna considered the question. "I have been reading, sir."\nMr. Fashola studied him. "What you described in that answer was not from our textbook. It was applied theory. Someone who has watched markets respond in real time." Another pause. "Are you running a business, Jidenna?"\nJidenna reached into his bag and placed the CAC acknowledgment slip on the desk.\nMr. Fashola picked it up. Read it. Put it down carefully, the way you put down something that has changed the nature of a conversation. He looked at Jidenna for a long moment.\n"This is correct procedure," he said. "This is exactly right." He said it quietly, without performance, the way a man speaks when he is genuinely struck by something. "You registered a business."\n"Authorized sub dealership," Jidenna said. "Network certified. Within the system."\nMr. Fashola sat back in his chair. Something moved across his face that was not quite surprise, more like the expression of a man who has been teaching a subject for many years and has just seen it lived at a level his syllabus had not accounted for.\n"How long have you been operating?"\n"Two years, sir."\nA silence settled between them that was not uncomfortable. Then Mr. Fashola said, "Bring your ledger next week. The mental one, written down. I want to show you how to turn it into a formal accounting record."\nJidenna nodded.\nHe walked back to the underpass in the late afternoon, the acknowledgment slip folded carefully in his bag. The kiosk agents were already gone, the space they used smooth and unmarked as if the canopy had never been there.\nHe stood at his corner and looked at the street. Tunde appeared from the direction of the bus stop, water crate empty, day done, moving with the quick walk of a boy who was always trying to be somewhere useful.\nHe stopped beside Jidenna. "How the registration go?"\n"It go well," Jidenna said.\nTunde nodded with the gravity of someone for whom this mattered personally. Then he looked at Jidenna''s phone. "You go upgrade that itel now?"\nJidenna looked at the phone. The crack across the top right corner was still there, exactly as it had been since March. The phone had processed thousands of transactions and survived rain and one accidental drop from the concrete ledge and had not once failed him at a moment that mattered.\n"Not yet," he said.\nTunde looked surprised. "You get money now."\n"I know," Jidenna said. "But I do not upgrade tools until the tools fail. That one has not failed."\nHe put the phone in his pocket and looked back at the street, at the underpass still busy with the particular evening energy of a place that never fully stopped, at Mama Titi''s stall where a light had just come on, at the spot twenty meters away that had held a canopy for weeks and now held nothing.\nThe corner was not the end. It was never the end. It was where he had learned what he needed to learn, and what he had learned was that survival intelligence, when given room and direction and two years of compounding work, became something that looked a great deal like a future.\nHe was sixteen years old and he had a registered business and a teacher who wanted to see his ledger and a twelve year old boy beside him who was watching everything.\nThe number was real now.\nHe stood on his corner and he let that be enough for today.','\n',char(10)),1041,1,1,NULL,'2026-04-21T15:07:40.605Z','2026-04-21 15:07:40','2026-04-21 15:07:40','2026-04-21T15:10:00.000Z',1,NULL);
INSERT INTO "chapters" ("id","novel_id","chapter_number","title","content","word_count","is_premium","is_published","audio_url","published_at","created_at","updated_at","scheduled_release_at","part_number","season_id") VALUES(592,71,1,' What Breaks When You Break the Ground',replace('The well in Mama Uzo''s compound ran dry at exactly seven-fourteen in the morning.\nOby knew the time because Mama Uzo''s granddaughter had been drawing water for the morning bath when the bucket came up empty and the girl screamed, and the scream woke the man in the next compound who checked his phone before going to investigate. He told the story eleven times that day. He always mentioned the time.\nBy eight o''clock, four other wells along the northern road had done the same thing. Not running low. Not clouded or changed in taste or smell. Empty. The way a cup is empty. As if the water had simply decided to be elsewhere.\nOby was at Mama Uzo''s compound when the fifth report came in. She had gone there at first light because after her mother''s words at the lake she needed someone who had been holding knowledge longer than she had been alive. Mama Uzo had opened her door without surprise and put water on the stove and they had been sitting in the small parlour when the granddaughter screamed.\nNow they stood at the open well and looked down into darkness that should not have been there.\n"The aquifer," Oby said.\nMama Uzo nodded slowly. "The lake and the underground water are the same system. Whatever lives in the lake runs beneath our feet also. When you disturb one end—" She did not finish the sentence. She did not need to.\nOby had felt the excavator''s first contact with the earth in her sternum. This was the consequence of that contact made visible. The lake was not just responding. It was demonstrating. Showing, precisely and efficiently, what connection meant, what it meant to break ground in a place where everything was joined to everything else below the surface.\nShe pulled out her phone and called Adaeze.\n"I need you," she said when Adaeze picked up.\n"I am eating breakfast."\n"Bring it. Come to Mama Uzo''s compound on the northern road. And come the back way, not past the construction site."\nA pause. "How bad?"\n"Five wells. So far."\nAdaeze came within twenty minutes, still holding a piece of bread, and stood at the empty well with an expression that moved through disbelief and arrived at something more serious.\n"This is connected to the digging," she said. It was not a question.\n"Yes."\n"Can you prove that connection to anyone who needs convincing?"\nIt was exactly the right question. It was why Oby had called her. Adaeze thought in evidence, in demonstration, in the gap between what was true and what could be shown to be true. It was not a quality Oby had always appreciated. Today it was exactly the quality she needed.\n"Not yet," Oby said. "But the company ran a water table survey before they started. If their survey showed a healthy aquifer under the northern road and the aquifer is now dry, that is either their incompetence or evidence of direct impact."\n"Either way it is their problem."\n"Either way it is leverage."\nMama Uzo, who had been listening from her doorway, made a sound of quiet approval.\nBy mid-morning the well failures had reached seven. A water tanker appeared on the northern road, sent by the construction company before anyone had formally complained to them, which meant they had monitoring equipment on site and the monitoring equipment had already told them what was happening.\nOby watched the tanker from the road and thought about that.\nThey knew. The moment the ground broke they had instruments that registered the aquifer response. Someone in that company had looked at a readout this morning and made a decision about whether to tell the community or to manage the situation quietly with water deliveries.\nThey had chosen the water deliveries.\nAt noon the lake changed again.\nShe was at the northern bank when it happened, had been there since the tanker arrived, sitting at the flat rock with her notebook, writing down every well address, every time, every detail she could gather. The water had been its strange still self all morning, the red pulse from dawn faded, the surface giving back clouds and a blank sky.\nThen a sound came from the centre. Not loud. Not dramatic. A low resonance, felt more in the chest than heard with the ears, like the lowest note of an instrument with no name, sustained and patient and final.\nThe surface of the entire lake shivered.\nNot a wave. Not a ripple from wind. Every point of the surface moved simultaneously, a single shudder, as if the lake were a living skin responding to something that had passed through it.\nThe birds left.\nEvery bird along both banks lifted at once in a single unanimous decision and flew, not in their usual random scatter but together, in one direction, away from the eastern site, away from the sound of the excavator. The sky above the lake emptied in under ten seconds.\nAdaeze grabbed Oby''s arm. "What was that?"\n"The second warning," Oby said.\n"You said the fish leaving was the first warning."\n"Yes."\nAdaeze looked at the empty sky, at the still water, at the eastern tree line where the excavator''s engine was a low continuous pressure against the afternoon. Her jaw was set. She was doing what Oby had watched her do since primary school, sorting information, arranging it into something she could act on.\n"Then we do not have the luxury of waiting for a third," she said. "What do you need? Tell me specifically and I will tell you if I can do it."\nOby looked at her, at this girl who had brought her bread to an emergency and asked the right questions and was now standing at the edge of something she only partly understood and offering herself to it anyway.\n"I need the company''s water table survey documents," Oby said. "And I need to know if there is anyone inside that site who is uncomfortable with what they saw on their instruments this morning."\nAdaeze nodded once. "Give me two days."\nBehind them, the lake was still and silent and waiting, as it had waited for more than a century, with the specific patience of something that has learned that the people it loves always take longer than they should.','\n',char(10)),1056,0,1,NULL,'2026-04-21 20:24:21','2026-04-21 20:13:33','2026-04-21 20:24:21','2026-04-21T19:30:00.000Z',2,49);
INSERT INTO "chapters" ("id","novel_id","chapter_number","title","content","word_count","is_premium","is_published","audio_url","published_at","created_at","updated_at","scheduled_release_at","part_number","season_id") VALUES(593,71,2,'The Crocodile Speaks in Full',replace('The dream did not wait for her to sleep.\nShe was sitting at the northern bank at dusk, notebook open, watching the last light leave the water, when the bronze came up through the rock beneath her and moved into her hands and she was simply there, between one breath and the next, standing in the amber water with the lake bed visible below and Nnedimma already waiting.\nNo transition. No slow arrival. The lake was done with gentleness.\nNnedimma stood where she always stood, indigo wrapper moving in water that had no current, white beads catching light that had no source. Her face was composed in the way of someone who has rehearsed a difficult conversation and has decided to deliver it without softening.\n"You were going to finish telling me," Oby said. "The night the machines moved. You were cut off."\n"I was not cut off," Nnedimma said. "You were not ready. There is a difference." She looked at Oby steadily. "You are ready now."\n"Tell me about the seal."\nNnedimma turned and moved toward the stones. Oby followed. Below them the seven flat stones lay in their arc, their Nsibidi markings pulsing with a rhythm that was slower than before, more laboured, the way breathing sounds when something has been running.\n"When I made the covenant," Nnedimma said, "I did not only record an agreement between this community and the lake. I bound something." She crouched beside the outermost stone and held her hand above it without touching. "The lake''s power is a living thing. It has a nature that gives and a nature that consumes. For most of what it is, those two natures are balanced. But there is a concentration of the consuming nature, old, much older than this covenant, much older than this community, that had no balance. It had been drawing from the water table, from the soil, from the people who lived beside it, for longer than any oral account reaches."\nOby crouched beside her. "You sealed it."\n"I bound it beneath the covenant. The stones are not only a record. They are a lock." She looked at the outermost stone. "The construction has already disturbed the aquifer. You have seen that. What you have not seen is what that disturbance does to the lock." She paused. "Each fracture in the water table weakens one stone. There are seven stones. The excavator has been working for one day."\n"How many are weakened?"\nNnedimma looked at her. "Two."\nThe number landed in Oby''s chest with physical weight.\n"If all seven are compromised," Nnedimma continued, "the binding dissolves. What I locked beneath will surface. Not into the lake. Into the water table. Into every well, every stream, every body of water connected to this system." She stood. "It will not announce itself. It will simply begin consuming. Quietly, gradually, the way drought begins, until the land around Agulu cannot support what lives on it."\nOby stood too. "How far does the water table reach?"\n"From here to the Niger River."\nThe scale of it moved through her slowly, too large for immediate feeling, the way news of a death sometimes takes hours to become grief.\n"What stops it once it surfaces?"\n"Nothing stops it. It can only be resealed." Nnedimma turned to face her directly. "Which requires the stones to be intact, in place, and reactivated."\n"Reactivated how?"\n"By the bloodline. By you." She did not look away. "You would need to bring all seven stones to the surface, carry them to the centre of the lake, and return them to the bed with the covenant renewed. Spoken aloud, in full, in the language in which it was first made."\n"You would need to teach me that language."\n"I have been teaching you since the first dream. You already know more of it than you understand." She moved closer. "But Obiageli. You need to hear the full consequence before you decide anything."\nOby held her gaze. "Tell me."\n"The renewal requires the one who performs it to remain in contact with the stones until the binding sets. Underwater. At the northern bed." She paused with the precision of someone who has learned that silence is the clearest frame for difficult truth. "It took me three days. I did not surface. I have not surfaced since."\nThe understanding arrived completely and immediately.\n"You are still there," Oby said. "You have been there since you sealed it. You are not a spirit. You are not a memory. You are held."\n"I made a choice," Nnedimma said. "I am telling you so that you make yours with full knowledge, not with the incomplete picture that has been handed to the women of our line across generations to make the choosing easier." Something shifted in her expression, not softness exactly, but the closest thing to it she appeared to carry. "I do not regret my choice. But it was mine to make with open eyes, and this one is yours."\nOby looked at the stones. At the laboured pulse of their markings. At the outermost two, their light dimmer than the others, their edges less defined.\n"The machines need to stop before they reach the northern bed," she said.\n"Yes."\n"And if I cannot stop them in time, someone has to go down and renew the covenant before the seventh stone fails."\n"Yes."\n"And that person stays."\nNnedimma said nothing. Which was its own answer.\nThe bronze began fading at the edges. The dream was closing. But this time Oby felt it coming and held herself inside it one moment longer.\n"I am not going to let it reach that point," she said.\nNnedimma looked at her with those ancient eyes that held everything the lake had witnessed since before anyone alive was born.\n"I know," she said. "That is why I chose your line."','\n',char(10)),977,0,1,NULL,'2026-04-21T20:14:32.632Z','2026-04-21 20:14:32','2026-04-21 20:14:32','2026-04-21T20:30:00.000Z',2,49);
INSERT INTO "chapters" ("id","novel_id","chapter_number","title","content","word_count","is_premium","is_published","audio_url","published_at","created_at","updated_at","scheduled_release_at","part_number","season_id") VALUES(594,71,3,' Allies',replace('Adaeze came back in one day, not two.\nShe arrived at Oby''s compound at six in the morning with a folded paper in her hand and the specific expression she wore when she had done something she was proud of and was rationing how proud she allowed herself to look.\n"The water table survey," she said, holding it out.\nOby took it. "How?"\n"The company posted a community notice board copy outside the eastern site entrance. Required by the state environmental guidelines." She sat down on the compound bench. "Nobody read it because it was printed in twelve-point font on A4 paper inside a plastic sleeve at ankle height." She paused. "I read it."\nOby unfolded the document. It was four pages of figures and technical language and one map. The map showed the aquifer system beneath the northern road and the lake bed. The depth figures were clearly marked. The survey had recorded the aquifer as active, healthy, and carrying significant volume. The date on the document was three weeks ago.\nThe aquifer was now dry in seven wells.\n"Three weeks ago versus this morning," Adaeze said, reading Oby''s face. "That is your before and after. That is your direct impact evidence."\n"This alone is not enough to stop them legally."\n"No. But it is enough to make noise with. And noise buys time." She leaned forward. "Who do we make noise to?"\nThis was the question Oby had been turning over since the morning of the empty wells. The community vote had failed. The council was compromised by the half that wanted the road. The company had state government backing. Conventional routes had been tried and absorbed.\nWhat she needed was unconventional weight.\n"Arinze Eze," Oby said.\nAdaeze''s expression shifted. "The disgraced one."\n"He is not disgraced. He retired."\n"He was removed from the state heritage commission for filing too many objections to development projects. That is a kind of disgraced."\n"That is exactly why I need him." Oby folded the survey document. "He knows heritage law. He knows how to file the kind of objection that cannot be absorbed in a community vote. And he has been waiting for a case that gives him grounds." She stood. "He lives on the road past the Catholic school. Come."\nArinze Eze opened his door in a wrapper and reading glasses and looked at them with the wariness of a man who had been visited by young people bringing problems before and had not always found the experience worthwhile.\nOby put the survey document in his hand and said, "The company''s own pre-construction survey recorded a healthy aquifer. Seven wells along the northern road are now dry after one day of excavation. And at twenty-seven metres under the northern lake bed there are physical artifacts from the mid-1800s that were never declared to the heritage commission because a colonial administrative filing in the 1890s deliberately removed the lake''s sacred status from the record."\nArinze Eze looked at her over his glasses.\n"I have the parish record with my ancestor''s name and the secondary notation Nnedimma-Iyi," she continued. "I have the survey document. I have the testimony of seven households with empty wells. And I have a council elder who will speak to the existence of a location map drawn by Chief Odumegwu''s father in 1961 documenting the stones."\nHe was quiet for a long moment.\n"Come in," he said.\nThey spent two hours at his table. He asked hard questions and she answered them and when she did not have an answer she said so and he made a note and said he would look for it himself. He was not warm. He was rigorous, which was better. By the end he had a list of seven items that could constitute the foundation of an emergency heritage injunction and a separate list of three items that needed to be sourced before any filing was credible.\n"Give me four days," he said.\n"We may not have four days."\nHe looked at her steadily. "Then I will work faster."\nThe third ally arrived without being recruited.\nHis name was Tobenna and he was twenty-two years old and he had been working as a site surveyor''s assistant for the construction company for six weeks. Oby did not know him. He came to her compound that evening having heard, through the specific efficiency of a small town''s information network, that a girl from the northern road had stood up in the community meeting and given a depth measurement that contradicted the company survey.\nHe was thin and serious and he held his hard hat in both hands in front of him like he was not sure where else to put it.\n"The depth reading," he said at the gate. "The twenty-seven metres."\n"Yes."\n"Our equipment registered it." He glanced down the road, then back at her. "On day one of site setup. The lead surveyor filed a corrected figure internally but the number in the official documentation was not updated." He pressed his lips together. "I asked why. I was told the original assessment figure stood for regulatory purposes and to leave it."\nOby looked at him steadily. "You are telling me the company knows the correct depth."\n"I am telling you someone in the company knows." He met her eyes. "I still have my site access card. I have not been assigned to the northern section. But I know where the internal survey logs are stored." He paused. "I don''t know what is under that lake. But I know what it means when a company corrects a number privately and leaves the wrong one in the public record."\nOby opened the gate.\n"Come in," she said. "There are people you need to meet."','\n',char(10)),960,0,1,NULL,'2026-04-21T20:16:04.579Z','2026-04-21 20:16:04','2026-04-21 20:16:04','2026-04-21T20:30:00.000Z',2,49);
INSERT INTO "chapters" ("id","novel_id","chapter_number","title","content","word_count","is_premium","is_published","audio_url","published_at","created_at","updated_at","scheduled_release_at","part_number","season_id") VALUES(595,71,4,' The Document Trail',replace('Arinze Eze called on the second day, not the fourth.\nOby was at the lake when her phone rang, sitting at the flat rock with her notebook, watching the water for the colour changes she had learned to read like a second language. The lake had been restless since dawn, not dramatically, just unsettled in the way of something that is aware of a clock running.\n"Come to my house," Arinze said. "Bring whoever is working with you. And come through the back road, not past the site."\nHe said nothing else and ended the call.\nShe collected Adaeze from her compound and sent a message to Tobenna, and the three of them arrived at Arinze''s house within the hour to find him at his table with three folders open and a look on his face that she was beginning to recognise as his version of urgency, contained, precise, all the feeling folded into the tightness around his eyes.\n"Sit," he said.\nThey sat.\nHe opened the first folder. "The state government approval for this project was processed through the Ministry of Infrastructure using a land classification document that designates the eastern lakeshore and northern wetlands as general agricultural land." He turned the folder to face them. "This classification originates from a survey conducted in 1963, which itself referenced an earlier British colonial administrative filing from 1897."\nHe opened the second folder and placed it beside the first.\n"The 1897 filing," he said, "was submitted by a District Officer named H.C. Brentwood, who was stationed in this area during the early consolidation period. The filing reclassified several sites across what is now Anambra State from their previous designations. Agulu Lake, in the original traditional land records, was classified as ihe nsọ. Sacred property. Not ownable, not alienable, not subject to government acquisition."\n"And Brentwood changed that," Adaeze said.\n"Brentwood changed that." Arinze placed one finger on a line of text in the second folder. "He reclassified it as communal agricultural water reserve. Removing the sacred designation. Removing the protection." He paused. "There is a witness signature on the document. A community representative who attested that the reclassification was accepted."\nOby leaned forward and looked at the name.\nShe did not recognise it. But beneath the signature, in small neat colonial handwriting, was the signatory''s role. Elder-Representative, Agulu Settlement.\n"One person," she said. "One compromised elder signed away the sacred status of the entire lake."\n"That is how it was done across the region," Arinze said, without heat, with the flatness of someone who has spent a career looking at documents that made him angry and has learned to keep the anger out of his voice so it does not cloud his thinking. "Find one cooperative local figure, have him sign, file the document, and the reclassification becomes the legal record. Everything built on top of it, every subsequent filing, every land survey, every development approval, goes back to that single document as its foundation."\nHe opened the third folder.\n"Which means," he continued, "that if the 1897 filing can be successfully challenged as a coerced or fraudulent reclassification, every approval that rests on it becomes unstable. Including the current construction permit."\nThe room was quiet.\nTobenna leaned forward. "Can it be challenged? After this long?"\n"Normally, the time window for challenging colonial-era land reclassifications is complicated and often closed." Arinze looked at Oby. "But there is a specific provision under the 2004 National Heritage Act that allows for emergency review of land classifications when physical heritage artifacts are demonstrated to exist on or under the contested site." He paused. "Physical artifacts that were present at the time of the original classification and were not disclosed or assessed."\n"The Covenant Stones," Oby said.\n"The Covenant Stones." He tapped the folder. "If we can demonstrate that the stones exist and that they constituted an undisclosed heritage site at the time Brentwood filed his reclassification, we have grounds for an emergency heritage review that would automatically suspend the construction permit pending investigation."\n"Demonstrate how?" Adaeze asked. "We cannot exactly bring them to the surface as evidence."\n"We do not need to bring them to the surface. We need to demonstrate their existence through documented evidence." He looked at Oby. "The parish record you found. Your ancestor''s name with the Nnedimma-Iyi notation. Do you have it?"\n"I have a copy."\n"Good. I also need the 1961 location map that Chief Odumegwu''s father made. The chief mentioned it at the council meeting. Whether he will produce it is a different question."\nOby thought about Chief Odumegwu shaking Mr. Salau''s hand.\n"He will not produce it willingly," she said.\n"Then we need someone who has seen it and will testify to its existence." He looked at her steadily. "Lolo Adaku."\n"She knows about the map."\n"She needs to go on record. Sworn testimony, not a community meeting statement." He closed the third folder. "And we need the company''s internal survey log showing the corrected depth figure." He looked at Tobenna. "That is yours."\nTobenna nodded once, tightly.\n"How long?" Oby asked.\n"The emergency heritage review application can be filed within forty-eight hours if we have all the documents." He looked at each of them in turn. "Once filed, the construction company receives formal notice and has seventy-two hours to respond before a mandatory review period begins. During that review period, excavation in the designated contested zone must legally stop."\nFive days. If everything went correctly, five days to a legal suspension.\nOby thought about the two weakened stones. About the aquifer. About what Nnedimma had told her regarding the pace of the damage.\n"The company will challenge it immediately," Adaeze said.\n"Yes," Arinze said. "Which is why the documentation must be complete and clean before we file. We get one shot at this. If they find a gap in the evidence they will move to dismiss and the application fails and the permit stands." He looked at Oby. "No gaps."\nShe thought about a document filed in 1897 by a man named Brentwood who had never stood at the northern bank at midnight and felt the lake breathe beneath him. A man who had looked at something ancient and sacred and written general agricultural water reserve and moved on to his next assignment.\nOne document. One compromised signature. One hundred and twenty-nine years of damage building quietly on top of it.\n"No gaps," she said.','\n',char(10)),1069,1,1,NULL,'2026-04-21T20:17:03.443Z','2026-04-21 20:17:03','2026-04-21 20:17:03','2026-04-21T20:30:00.000Z',2,49);
INSERT INTO "chapters" ("id","novel_id","chapter_number","title","content","word_count","is_premium","is_published","audio_url","published_at","created_at","updated_at","scheduled_release_at","part_number","season_id") VALUES(596,71,5,'Her Mother Confesses',replace('Her mother was waiting up.\nNot pretending to do something else while waiting, not busy with dishes or her phone. Actually waiting, sitting at the parlour table with her hands folded and the lamp on and the particular stillness of someone who has decided that tonight is the night and has arranged themselves accordingly.\nOby came in from Arinze''s house and stopped in the doorway and read her mother''s face and sat down.\n"You already know something happened," Oby said.\n"Lolo Adaku called me after you left her compound this morning." Her mother looked at her steadily. "She told me Arinze is building the heritage case. She told me he needs my testimony about the location map." She paused. "And she told me it was time I stopped making you piece this together from other people''s accounts."\nOby said nothing. She waited.\nHer mother unfolded her hands and placed them flat on the table and looked at them as if reading something written there.\n"I was twelve when my mother first told me about the bloodline," she began. "Not everything. The outline. That the women of our line carried a connection to the lake, that it was real and not superstition, that it would come to me when it was time." She exhaled slowly. "I was twelve and I thought it was the most extraordinary thing I had ever heard. I was proud. I spent three years waiting for it to arrive."\n"But it didn''t come."\n"It did not come." Her voice was even. "I was fifteen, sixteen, seventeen. Nothing. My mother watched me and said nothing helpful except that the lake chose its timing and I should be patient." She pressed her lips together briefly. "When I was nineteen, my mother sat me down and told me the full truth of why."\nOby leaned forward slightly.\n"She had refused it," her mother said. "When she was young and the inheritance first moved toward her, she was frightened. She had watched her own mother carry it and understood what it cost. The sleepless nights. The dreams that were not rest but work. The way the lake''s needs moved ahead of everything personal." She looked up from her hands. "So she refused. She told the lake no in the only way available to her. She married your grandfather and moved away from Agulu for eleven years."\n"You can refuse it?"\n"You can delay it. Distance weakens the connection. If you go far enough, for long enough, the inheritance recedes." Her mother''s voice carried something complicated. "It does not disappear. It waits. And when she came back to Agulu after your grandfather died, it came back to her too. Stronger, for having been refused. But by then she was too old for what it needed from her. The lake does not choose carelessly. It needed someone young enough to act."\n"So it skipped your generation entirely."\n"Because of me." The words came out quietly, without drama, which somehow made them heavier. "My mother told me that her refusal had consequences. That the inheritance had to wait out her lifetime before it could pass cleanly. That her decision had cost our line thirty years." She looked at Oby directly. "Those thirty years are why the lake is in the position it is in now. If the inheritance had passed in the normal order, you would have been prepared from childhood. The community would have had an active keeper. The construction project would never have gotten this far before someone with the full knowledge was in place to stop it."\nThe room held that information without moving.\nOby thought about Nnedimma beneath the water, waiting for more than a century. She thought about the weakened stones, about the dry wells, about everything that was now urgent that might have been manageable with thirty more years of preparation.\n"Mama," she said carefully. "Why did my grandmother tell you this?"\nHer mother was quiet for a moment.\n"Because when she told me that the inheritance had passed me and was waiting for my daughter, I was angry," she said. "I was twenty-one and I was angry in the way you can only be angry when someone tells you that your life was shaped by a decision you did not make. I told her it was unfair. That she had no right to make a choice that fell on my child." She paused. "She agreed with me."\nOby had not expected that.\n"She said I was correct. She said she had been selfish and that the cost of her fear had compounded across the years and landed on people who had not chosen it. She said she was sorry in the way of someone who had lived long enough to understand that some sorries arrive too late to change anything but still need to be said." Her mother''s voice had developed a faint roughness along one edge. "And then she gave me the letters to hold for you and she told me that when the time came, I should not do what she had done. I should not make the same choice from the same fear."\n"And then she died."\n"And then she died. And you were small. And the letters sat in a box and I told myself I was protecting you and I was, partly. But I was also afraid of the same thing she had been afraid of." She met Oby''s eyes. "Of watching my child become someone whose first responsibility was never me."\nThe lamp flickered once. Outside, the night was deep and still.\nOby thought about what Nnedimma had said. That the women of their line were not trapped by the lake. They were trusted by it.\nShe thought about the difference between those two things and how long it had taken one family to learn it.\n"I need your testimony for Arinze''s filing," she said gently. "About the location map. About what Lolo Adaku told you."\n"I know." Her mother reached across the table and covered her hand. "I will go to him tomorrow." She held on. "I should have gone a long time ago."\nOutside, the lake was quiet.\nFor the first time, that quietness felt less like patience and more like relief.','\n',char(10)),1043,1,1,NULL,'2026-04-21T20:17:57.168Z','2026-04-21 20:17:57','2026-04-21 20:17:57','2026-04-21T20:30:00.000Z',2,49);
INSERT INTO "chapters" ("id","novel_id","chapter_number","title","content","word_count","is_premium","is_published","audio_url","published_at","created_at","updated_at","scheduled_release_at","part_number","season_id") VALUES(597,71,6,'The Lake Rises',replace('The water crossed the bank at four in the morning.\nNot flooding. Not the violent overflow of heavy rain or a broken dam. The lake simply expanded, slowly and deliberately, the way a sleeping person shifts their weight, and when the sun came up the flat rock where Oby had spent so many nights was underwater and the reeds along the northern bank were submerged to their midpoints and the construction company''s survey markers at the eastern edge were standing in six inches of water.\nOby stood at the new waterline in her slippers and looked at where her rock used to be.\nThe water was calm. Completely, unusually calm, considering it had moved. No current, no churn, no evidence of the physical process that should have accompanied a rise of this scale overnight. It had simply decided to occupy more space, and it had done so with the total authority of something that had always owned the ground it was now covering.\nHer mother came to stand beside her without speaking and they looked at it together in the early light.\nBy seven, the northern road had a thin sheet of water across its lowest section. Nothing impassable, but enough that the women who walked it to the morning market were lifting their wrappers and the children were delighted and the older residents were standing at their gates with expressions that ranged from worried to deeply unsurprised.\nBy nine, Mr. Salau was on site with three additional people Oby had not seen before, all of them moving with the energy of people who had received early morning phone calls they had not wanted to receive. They had equipment. They were taking measurements. Their faces said the measurements were not matching their projections.\nOby watched from the road.\nTobenna appeared beside her, having come from inside the site. He had his hard hat on and his eyes forward, speaking from the side of his mouth in the way of someone maintaining the appearance of simply passing by.\n"Their water level sensors registered the rise at three forty-seven," he said quietly. "It is eighteen centimetres above baseline at the northern edge. Thirty-one centimetres at the eastern section near the excavation."\n"Thirty-one at the excavation point."\n"The lead engineer is saying it is seasonal groundwater rebound. That the excavation disturbed a subsurface pressure system and the lake is equalising." He paused. "He is saying this loudly and repeatedly."\n"Is he saying it to convince others or himself?"\nTobenna said nothing, which was its own answer.\nShe left him and walked the perimeter of the new waterline, all the way around the northern bank and down the eastern side, stepping over the survey tape that was now half submerged. The water that had crossed the bank was not murky the way flood water was murky. It was clear and dark and it moved over the red laterite soil without mixing into it, maintaining its own colour, its own quality, the way it knew what it was and had no interest in becoming something else.\nAt the point closest to the excavation site, the water had stopped advancing. It had come right to the edge of the broken ground and no further, as if it had drawn itself a line. The cleared earth on the company''s side was dry. The lake''s new territory was on the other side.\nA boundary. Deliberate and visible and completely impossible to explain with seasonal groundwater rebound.\nShe crouched at the line and pressed her palm to the wet ground.\nThe warmth came immediately, stronger than it had ever been outside the dream, moving up her arm with an urgency that was close to pain. And with it, images, not the slow symbolic language of the dream-space but something faster, compressed, the way information arrives when time is short.\nShe saw the stones. Two of the outer ones were dark, their markings gone entirely. Not dimmed. Gone. The binding in those two was no longer weakened. It was broken.\nShe pulled her hand back and stood up.\nTwo stones failed. Five remaining. And the excavator had been working for less than a week.\nShe called Arinze from the road.\n"How close are we?" she said when he picked up.\n"I am waiting for Tobenna''s document and your mother''s signed statement. Everything else is ready."\n"I need it filed today."\nA pause. "Tobenna''s document—"\n"Today, Arinze." She looked at the water standing calmly over the ground it had reclaimed. "Two of the seven stones have already failed. I do not have the luxury of a clean filing if the alternative is an incomplete lake."\nAnother pause, longer. "I will call your mother now. If Tobenna gets me the internal survey log before noon I can file by evening."\nShe hung up and sent Tobenna a message with one word. Today.\nHis reply came in under a minute. Understood.\nShe stood at the boundary line between the lake''s new territory and the broken earth for a long time, looking at the water. The clarity of it. The intention of it. The way it had moved precisely as far as it needed to move to make its statement without destroying anything, without harming anyone, using the minimum force available to it.\nShe thought about Nnedimma making the same calculation in 1897. Watching the colonial administration arrive. Assessing what was available to her. Choosing the most complete action she could take with the tools her time allowed her.\nThe lake had been making the same calculation ever since.\nEverything it had done, the empty fish traps, the dry wells, the shudder, the rising, had been calibrated. Warning, then demonstration, then boundary. It was not acting from desperation. It was escalating deliberately, the way a person escalates who has tried every smaller option first.\nIt had not yet shown what it would do if the smaller options failed.\nOby did not want to find out.\nShe turned from the water and walked fast toward Arinze''s house, moving with the particular urgency of someone who has just understood that the situation is ahead of them and has decided to stop letting it lead.\nBehind her, the lake held its new boundary and waited, as it had always waited, with a patience that was no longer comfortable.','\n',char(10)),1051,1,1,NULL,'2026-04-21T20:18:52.940Z','2026-04-21 20:18:53','2026-04-21 20:18:53','2026-04-21T20:30:00.000Z',2,49);
INSERT INTO "chapters" ("id","novel_id","chapter_number","title","content","word_count","is_premium","is_published","audio_url","published_at","created_at","updated_at","scheduled_release_at","part_number","season_id") VALUES(598,71,7,' The Company Pushes Back',replace('The filing went in at seven-forty in the evening.\nArinze sent her a message with two words: It''s done. She read it sitting on the floor of her room with her back against the bed and her knees pulled up and felt something that was not quite relief because relief implied the danger had passed and the danger had not passed. It was more like the feeling of having thrown something and now watching to see where it landed.\nThe company received formal notice by eight.\nShe knew this because Tobenna, who was still inside the site accommodation, sent her a voice note at eight-seventeen that was mostly ambient sound and one sentence spoken very quietly: Their lawyer just arrived by car from Abuja.\nA lawyer from Abuja. Same night. Within the hour.\nAdaeze, sitting cross-legged on Oby''s bed reading the message over her shoulder, said, "They were prepared for this."\n"They were prepared for something," Oby said. "Maybe not exactly this."\nThey found out what the company''s response looked like the next morning, when Oby''s mother handed her a phone showing a post on the community Facebook group that had gone up at midnight. It was long and formally written, bearing the company''s logo at the top, addressed to the Agulu community.\nShe read it standing in the kitchen.\nIt was careful. That was the first thing she noticed. It did not attack directly. It expressed deep respect for community concerns and cultural heritage. It noted the company''s commitment to environmental responsibility and transparent operations. And then, in the fourth paragraph, it pivoted.\nIt stated that the emergency heritage filing had been submitted by a minor, aged sixteen, acting without legal standing, on the basis of claims that included a self-reported dream experience and an unverified family oral tradition. It noted that no qualified archaeologist, historian, or heritage professional had assessed the site. It noted that the depth measurement the minor had cited publicly contradicted the findings of a certified environmental survey firm. It expressed concern that the filing represented an orchestrated attempt to delay legitimate infrastructure development by parties with undisclosed interests, and called on community leaders to consider the source of the disruption carefully before allowing it to derail a project that would benefit every household in Agulu.\nThe last paragraph mentioned Oby by name.\nShe read that paragraph twice. Her mother watched her face.\n"They are trying to make you the story," her mother said. "Instead of the lake."\n"I know." She put the phone down. "It will work on some people."\nIt worked by noon.\nShe went to the market for her mother and three separate women looked at her with the careful blankness of people who had formed an opinion and were deciding whether to share it. One of them, a woman she had known since childhood, said without meeting her eyes that it was a shame young people these days were being used by politicians and NGOs to cause confusion in the community.\nOby said nothing and bought her tomatoes and left.\nOn the road home she passed two men she did not know who were talking near a parked okada and one of them said her name in the middle of a sentence she was not meant to hear, and the other one laughed.\nBy afternoon the post had been shared forty-seven times.\nShe called Arinze.\n"They have no legal grounds to challenge the filing on the basis of my age," she said. "Arinze filed it. He has standing. My name is supporting evidence, not the applicant."\n"Correct. The legal challenge will be different, filed formally in the next seventy-two hours, almost certainly on the grounds of insufficient evidence to constitute a heritage claim." He paused. "The community post is not legal strategy. It is social strategy. They want to isolate you before the review period begins so that no one in a position to support the case will risk being associated with it."\n"And the council?"\n"Chief Odumegwu called me this morning requesting a meeting." His voice was neutral. "I am attending this afternoon."\n"He is going to ask you to withdraw."\n"He is going to try." Another pause. "The social pressure will increase before it decreases, Oby. I want you to be ready for that."\nShe was ready for it in the way that you are ready for rain when you can see the clouds but have no roof available.\nIt came from three directions at once.\nA community leader she had never spoken to directly appeared at their compound gate that evening and asked to speak to her mother. Oby sat in the parlour and listened through the wall to a twenty-minute conversation that was entirely about community harmony and the importance of young people channeling their energy constructively and the observation that the lake had been there for generations and would continue to be there after this road was built and it was not healthy for a young girl to become obsessed with things beyond her understanding.\nHer mother''s voice stayed level throughout. At the end she said, clearly enough to be heard through walls, that she would pass the message along.\nThe community leader left.\nHer mother came into the parlour and sat down and said nothing for a moment.\n"He was sent," Oby said.\n"Obviously." She looked at Oby. "He also said that the company is prepared to offer a community development fund of four million naira if the heritage filing is withdrawn within forty-eight hours."\nThe number sat in the air between them.\n"That is a significant amount of money," Oby said carefully.\n"It is." Her mother held her gaze. "It is also a number that tells you exactly how much they do not want that review to happen." She reached across and straightened the collar of Oby''s shirt, the precise deliberate gesture she used when she was making a point through her hands rather than her words. "Which tells you exactly how real everything you have been telling me actually is."\nAdaeze arrived an hour later with her laptop and the expression of someone who had been productive and needed to report it.\n"The community Facebook post," she said, opening the laptop. "Twenty-three of the forty-seven shares are from accounts created in the last month. No profile photos. No prior community activity." She turned the screen. "This campaign was prepared in advance."\nOby looked at the screen.\nThey had been ready for the filing. They had built the counter-narrative before the filing happened. Which meant someone had been watching the lake, watching the community, watching her, long before the excavator moved.\nShe thought about that.\nThen she thought about a company lawyer arriving from Abuja within an hour of notification.\nThen she thought about a colonial administrator named Brentwood who had filed one careful document in 1897 and built a legal structure on top of it that had survived a hundred and twenty-nine years.\nDifferent century. Same method. Find the right document, control the narrative, isolate the opposition, move fast.\nShe closed Adaeze''s laptop.\n"Post the water table comparison," she said. "The company''s survey document against Tobenna''s internal log. No commentary. No claims. Just the two documents side by side and one sentence: the company corrected this number privately and left the wrong one in the public record."\nAdaeze was already opening the laptop again.\n"Let them respond to that," Oby said.','\n',char(10)),1238,1,1,NULL,'2026-04-21T20:19:47.156Z','2026-04-21 20:19:47','2026-04-21 20:19:47','2026-04-21T20:30:00.000Z',2,49);
INSERT INTO "chapters" ("id","novel_id","chapter_number","title","content","word_count","is_premium","is_published","audio_url","published_at","created_at","updated_at","scheduled_release_at","part_number","season_id") VALUES(599,71,8,'What the Crocodiles Guard',replace('The crocodiles came ashore the night the documents went public.\nNot one. Not three. All of them.\nOby counted seventeen from the northern bank before she stopped counting, their bodies arranged along both sides of the lake in the particular stillness that she now understood was not animal passivity but attention. They were not basking. The night was cool and they had no heat to regulate. They were simply present, in a line, facing the construction site with the unified quality of a thing that has made a collective decision.\nBy morning half of Agulu had seen them. By noon the photographs were everywhere. By afternoon the company had issued a statement that crocodile movement patterns were a known environmental response to water level changes and posed no threat to site workers, who had been briefed on safety protocols.\nNobody in Agulu believed the statement. But they took different things from their disbelief. Some took fear. Some took confirmation. Some took the particular stubbornness of people who had already decided and did not want the crocodiles complicating their position.\nOby''s phone had not stopped since Adaeze posted the documents. The comparison image had been shared three hundred times by morning. A journalist from a Lagos-based news platform had sent a message requesting an interview. Two heritage academics from the University of Nigeria Nsukka had contacted Arinze directly.\nThe company''s legal challenge had been filed at nine in the morning, exactly as Arinze had predicted, contesting the evidentiary basis of the heritage claim.\nNone of this was the dream.\nThe dream came at noon, while she was awake.\nShe had been pacing the northern bank watching the crocodiles when it simply arrived, faster and harder than it had ever come, the bronze slamming up through the ground into her feet and she was standing in the water with Nnedimma before she had finished drawing a breath.\nSomething was different. Nnedimma''s composure, always total, had developed a crack along one edge, not fear, something more disciplined than fear, the look of a general who has held a position for a very long time and is watching the perimeter compress.\n"You need to see it," Nnedimma said, without greeting. "Now. Before the hearing."\n"See what?"\n"What is beneath the stones."\nShe had told Oby about it. The shadow. The consuming nature of the lake''s power, concentrated and sealed. But she had not shown it. Oby understood now that showing it had required something from Nnedimma that she had been conserving, some reserve of whatever held the dream-space open, and she was spending it now because the timeline had moved beyond the point where withholding was protective.\nThey descended.\nIt was not like the other dreams where the lake bed was a floor you stood on. This was a descent through layers, water becoming something denser than water, the amber light thinning, the seven stones appearing below them in their arc, five still lit, two completely dark.\nBelow the stones, the darkness was different.\nNot the natural darkness of deep water. Something with texture. Something that moved the way shadows move when the light source shifts, except there was no light source here, the movement was internal, slow and searching, the movement of something that was aware of the boundaries around it and spent its existence testing them.\n"What is it?" Oby asked.\n"A hunger," Nnedimma said. "As old as water. Before people named things, before the lake had a community beside it, this existed in the water table of this region. It does not want. It does not intend. It only consumes. Quietly, persistently, without malice, the way fire has no malice." She kept her eyes on it. "The Iyi-Ọcha, the water memory that powers the covenant, that speaks through the crocodiles, that moves through our line, it is the counterbalance. Same water. Opposite nature. They have always coexisted because the lake is deep enough to hold both."\n"But the seal keeps them separated."\n"The seal keeps the consuming nature below the stones and the living nature above. If the seal breaks, the separation breaks. The consuming nature enters the water table freely." She turned to Oby. "It does not destroy quickly. It depletes. Soil fertility first, then well water, then the health of whatever lives near the water. Over years, not days. Quietly, the way the region simply becomes less, the way crops fail without obvious cause, the way communities shrink and no one can say exactly why."\nOby stared at the moving dark below the stones.\n"The crocodiles," she said.\n"The crocodiles are the living nature made physical. They carry the Iyi-Ọcha in their bodies. They are not guardians in the way of soldiers. They are guardians in the way of a living seal, their presence above the water reinforcing the boundary below it." Nnedimma paused. "When they came ashore tonight, they were not performing. They were concentrating above the point of greatest weakness. Three of the remaining five stones are failing."\nThree. Yesterday it was two lost and five remaining. Now three of the five were failing.\n"How long?" Oby asked.\n"At the current rate of excavation, the remaining stones fail in four days." She looked at Oby with an expression that carried the full weight of more than a century of waiting. "The heritage review takes longer than four days."\n"Then we need to stop the excavation before the review concludes."\n"Yes."\n"The documents alone will not do that in time."\n"No."\nOby stared at the darkness below the stones. The slow, searching movement of it. Patient in the way of something that has never needed to hurry because it has always known the boundary would eventually give.\nShe thought about Brentwood''s document. About the company''s lawyer arriving within the hour. About every layer of protection that had been systematically removed since 1897.\n"I need to go down there," she said. "Before the stones fail completely. I need to be at the northern bed."\nNnedimma said nothing.\n"If I renew the covenant before the seal breaks completely, the remaining stones stabilise. The lake stops escalating. The evidence holds. The review succeeds." She looked at her ancestor. "It does not have to end the way it ended for you."\nNnedimma''s expression did not change. But her eyes held something that was not quite agreement and not quite its opposite.\n"Come back tonight," she said. "I will begin teaching you the full language of the covenant."\nThe bronze dissolved.\nOby was standing on the northern bank in the noon heat with the crocodiles in their line and the sound of the excavator carrying across the water, and four days in her chest like a stone of its own.','\n',char(10)),1117,1,1,NULL,'2026-04-21T20:20:44.706Z','2026-04-21 20:20:44','2026-04-21 20:20:44','2026-04-21T20:30:00.000Z',2,49);
INSERT INTO "chapters" ("id","novel_id","chapter_number","title","content","word_count","is_premium","is_published","audio_url","published_at","created_at","updated_at","scheduled_release_at","part_number","season_id") VALUES(600,71,9,' Fracture',replace('Tobenna came to her compound at seven in the morning with his hard hat in his hands and something already decided in his eyes.\nShe knew before he spoke.\n"They know it was me," he said. He did not sit down. He stood at the compound entrance with the posture of someone who had rehearsed leaving and needed to complete it quickly before the rehearsal lost its hold. "The internal survey log. They audited the access records last night after the documents went public. My site card was the last one used in that storage system before the file disappeared."\n"Have they confronted you directly?"\n"The site manager called me into his office at six this morning and asked me to explain the access." He looked at the ground briefly then back at her. "I told him I had been misfiled into the wrong storage category and was correcting it. He said he would be reviewing my contract." He pressed his lips together. "My contract pays for my mother''s dialysis, Oby."\nThe silence between them had its own weight.\nShe wanted to say something that would hold him in place without being the kind of thing that asked someone to sacrifice their mother''s health for a principle. She could not find that thing because it did not exist.\n"I understand," she said.\n"I am sorry."\n"You gave us the document. It is already posted. It is already being seen." She meant it. "You did what mattered."\nHe nodded once, tightly, and left without looking back. She watched him go and then went inside and sat at the table and gave herself three minutes to feel the specific cold of watching something you built develop its first crack.\nThen she called Arinze.\nHe answered on the first ring. "I heard about the boy."\n"Word travels."\n"In Agulu it travels before the event has finished happening." He paused. "The legal challenge hearing has been scheduled for day after tomorrow. The review board received our filing and the company''s counter-filing and they are moving quickly, which is either a good sign or a sign that someone has applied pressure to move it toward dismissal."\n"Which do you think it is?"\n"I think it is both, depending on which member of the board you are asking." He was quiet for a moment. "There is something else. Chief Odumegwu has submitted a statement to the review board on behalf of the community council. Supporting the company''s position."\nShe absorbed this. "He submitted it formally? On record?"\n"This morning. He cited the community vote, the approved state permit, and expressed concern about what he called unsubstantiated mythological claims being used to obstruct legitimate development." A pause. "He did not mention the 1961 map. He did not mention his father''s documentation. He buried it."\nShe thought about Chief Odumegwu shaking Mr. Salau''s hand the night of the vote. She thought about how long that handshake might have been in preparation.\n"Does it damage the filing?"\n"It complicates it. A formal community council statement supporting the company undermines our claim to be representing community interests." His voice was careful. "I need Lolo Adaku at the hearing, Oby. In person, on record, as a counter to the council statement. Without her testimony the board has one elder speaking for the community and it is not speaking for us."\n"I will talk to her."\nShe found Adaeze next, at her family compound, and knew within thirty seconds of seeing her face that something had shifted there too. Adaeze met her at the gate and they walked to the end of the road before either of them spoke, the way they had always done when what needed saying required distance from other ears.\n"My father spoke to me last night," Adaeze said. She kept her eyes forward. "He is one of the community members the company approached about the development fund. The four million naira." She paused. "He said he is not against what we are doing. But he said the road will be built regardless, that we cannot stop Abuja, and that I am going to damage my name in this community before I am old enough to understand what that costs."\n"What did you tell him?"\n"I told him I understood his concern." She stopped walking. "Oby, I am not leaving. I want to be clear about that. But my father has asked me not to attend the hearing. Not to be publicly associated with the filing at the stage where it could be dismissed." She finally looked at her. "I can still work. I can research, I can find things, I can be everything I have been. But from behind. Not in front."\nOby looked at her friend, at the particular misery of someone who was trying to honour two things that were pulling in opposite directions and had found the only position that let her hold both.\n"Behind is still in," Oby said.\nAdaeze exhaled. "Yes. Behind is still in."\nThey walked back. At the compound gate Adaeze squeezed her arm once and went inside and Oby stood on the road alone in the morning heat and took a full accounting of where she was.\nTobenna was out. Adaeze was behind the line. Chief Odumegwu was actively working against them. The hearing was in two days. The stones had three days at most.\nShe walked to Lolo Adaku''s compound.\nThe old woman was in her garden, moving between plants with a slowness that was not frailty but consideration, the way she did everything. She looked up when Oby came through the gate and read her face in one pass.\n"Sit," she said, pointing to the bench.\nOby sat and laid out everything, plainly, without softening any of it. The withdrawn testimony, Adaeze''s position, the chief''s statement, the timeline on the stones, the hearing date. She said it all in the flat clear way she had learned from Arinze, keeping the feeling out of her voice so it did not cloud the information.\nWhen she finished, Lolo Adaku was quiet for a long time.\n"The chief''s father told him about the stones when he was young," she said finally. "He grew up knowing. He has spent his adult life deciding that knowing was a burden he could set down." She looked at her hands. "Fear makes people choose the smaller life. It is the oldest story we have."\n"Will you testify?"\nThe old woman looked at her steadily. "I have been waiting to testify since 1989," she said. "I was only waiting for someone to build a case worth testifying in."\nShe stood and went inside, and Oby sat alone in the garden with the birds and the sound of the road and the knowledge that she was down to three people, herself and an old woman and a man who had spent his retirement building toward exactly this, and four days on a clock that the review board did not know was running.\nShe pulled out her notebook. She wrote down everything she still had. The parish records. The survey comparison. Lolo Adaku''s testimony. Arinze''s filing. The photographs of seventeen crocodiles ashore. The water level data. The failed wells.\nIt was not nothing.\nIt was not enough to feel comfortable.\nBut she had stopped needing to feel comfortable somewhere around the time the lake stopped being just a lake, and she had not missed it as much as she would have expected.','\n',char(10)),1245,1,1,NULL,'2026-04-21T20:21:50.007Z','2026-04-21 20:21:50','2026-04-21 20:21:50','2026-04-21T20:30:00.000Z',2,49);
INSERT INTO "chapters" ("id","novel_id","chapter_number","title","content","word_count","is_premium","is_published","audio_url","published_at","created_at","updated_at","scheduled_release_at","part_number","season_id") VALUES(601,71,10,'The Descent',replace('The hearing lasted four hours and ended without a ruling.\nOby sat through it in Arinze''s car outside the state heritage board office in Awka, because minors were not admitted to formal review proceedings and she had known this and come anyway, needing to be close to the room where the thing she had built was either going to hold or not hold.\nArinze came out at three in the afternoon with Lolo Adaku moving carefully beside him, and Oby read his face before he reached the car.\nNot dismissed. Not ruled in their favour. Deferred.\n"The board chair said the evidence was substantial enough to warrant full review," he said, getting into the driver''s seat. "They are not dismissing the filing."\n"But they are not suspending the construction."\n"They have requested an independent assessment of the northern lake bed before any ruling. A qualified marine archaeologist. The earliest available appointment is in eleven days."\nEleven days.\nShe said nothing on the drive back. Lolo Adaku sat beside her in the back seat and did not offer comfort, which was the most respectful thing she could have done. The old woman understood that some gaps could not be filled with words and had the dignity not to try.\nThree days on the stones. Eleven days for the assessment.\nThe math was simple and it was catastrophic.\nHer mother was at the gate when they arrived. She looked at Oby''s face and stepped aside and let her pass without speaking. Oby went through the compound and out the back and down the path to the lake and sat at the flat rock, which was no longer flat but a slight rise in the extended waterline, the water coming to the edges of it now on both sides.\nThe lake was dark in the late afternoon. The crocodiles were still ashore, seventeen of them, unmoving, and she had stopped finding this remarkable because remarkable had stopped being a useful category three weeks ago.\nShe sat there until the sun was gone.\nShe sat there while her mother came to the path edge and stood for a moment and went back inside. She sat there while Adaeze sent a message she did not open. She sat there while the night settled over the lake and the stars came out and the construction site across the water went quiet for its night hours.\nShe sat there until midnight.\nThen she opened the message from Adaeze, because Adaeze did not send anything that was not worth reading.\nThe marine archaeologist the board appointed. I looked her up. She published a paper in 2019 on Nsibidi artifacts in the Niger Delta. She knows what she is looking for. She will find the stones if they are there.\nIf they are there.\nOby looked at the water.\nThree days. The stones had three days before the remaining five failed entirely. The assessment was in eleven. By the time the archaeologist arrived there would be nothing left to find, nothing to confirm, nothing to show the board. The company''s legal team would move to dismiss on the grounds of insufficient evidence and the filing would collapse and the construction would continue and whatever lived in the dark below the covenant would surface into the water table and begin its quiet work.\nShe thought about Nnedimma. About the choice she had made with open eyes. About what she had said: This one is yours.\nShe thought about her mother burning letters for seven years out of love that expressed itself as fear.\nShe thought about Tobenna''s mother and Adaeze''s father and Chief Odumegwu choosing the smaller life. All of them making their choices from the materials available to them, from the fear available to them, doing the best calculation they could manage with the information they were willing to hold.\nShe had more information than any of them.\nShe stood up.\nShe took off her shoes and placed them beside the rock. She placed her phone beside them, screen up, and opened her contacts to her mother''s name without calling. A marker. A trail.\nThe water was cold at her ankles. She had expected this and it did not slow her.\nShe waded in to her knees and the cold moved up her legs and the lake floor was soft beneath her feet, soft and familiar, the way the floor of your own room is familiar in the dark. The crocodiles on the banks did not move. They watched her the way they had always watched her, with that total attention that had stopped being frightening because it was the most honest thing anyone had shown her throughout all of this.\nHer crocodile surfaced three metres ahead of her. The large one. The ridge along its back catching the starlight.\n"I know," she said to it. "I know what I am doing."\nIt turned and moved deeper and she followed.\nThe water reached her waist. Her chest. The cold was complete and she breathed through it. The bronze was rising from below, warming the water around her, guiding her the way it had guided her since the first dream, patient and certain, a light that lived inside the dark rather than above it.\nHer chin reached the waterline.\nBehind her, from the direction of the house, she heard the back door open. Her mother''s voice, sharp and frightened, calling her name across the water.\nShe turned and looked back once.\nHer mother was standing at the path edge, one hand pressed against her mouth.\nOby held her gaze across the dark water for one long moment.\nThen she took a breath, full and deliberate, the way you breathe before something that requires everything you have.\nAnd she went under.','\n',char(10)),960,1,1,NULL,'2026-04-21T20:22:55.283Z','2026-04-21 20:22:55','2026-04-21 20:22:55','2026-04-21T20:30:00.000Z',2,49);
INSERT INTO "chapters" ("id","novel_id","chapter_number","title","content","word_count","is_premium","is_published","audio_url","published_at","created_at","updated_at","scheduled_release_at","part_number","season_id") VALUES(602,72,1,'Under',replace('The cold stopped at the surface.\nBelow it, the water was warm, the specific warmth of the bronze that had been finding her since the first night, and she understood now that it had never been a dream temperature. It had always been this. The dream had been the preparation and this was the thing itself, the real water, the real depth, the real weight of twenty-seven metres pressing around her with the gentleness of something that had been expecting her.\nShe could breathe.\nNot the way you breathe air. Something slower and more complete, as if the water itself was what her lungs had always been designed for and the sixteen years of breathing above the surface had been the approximation. She did not question this. There was no part of her that was available for questioning. Every part of her was for this.\nThe crocodile moved ahead of her, its body a dark shape in the bronze light, unhurried, its tail moving in long slow sweeps. She followed its movement the way she had followed it in every dream, with the trust that had been building in her since the first night it turned its head and looked at her across the road.\nThe lake deepened around her.\nShe passed through layers. The upper water, still and warm. A cooler band where two temperatures met and held their boundary. A darker zone where the light came only from below, amber rising through the dark like dawn seen from the wrong direction. She watched the surface above her recede until it was a faint silver memory and then it was gone and there was only depth and the crocodile and the light from below.\nThe stones appeared first as a glow.\nThen as shapes. Then as themselves, seven flat stones in their arc on the lake bed, and from above they were more real than the dream had made them, worn and dark and ancient, their Nsibidi markings burning in the bronze light, the ones that still held burning brightest.\nShe counted. Two fully dark. Three others with markings that were thin and flickering, burning the way a flame burns when the fuel is nearly gone. Two still strong, their patterns clear and complete, pulsing with the steady rhythm she recognised from the first dream.\nShe landed on the lake bed softly, the silt rising in small clouds around her feet and settling back, and crouched beside the nearest failing stone and held her hand above it without touching.\nThe warmth that came up was not the full warmth of the living stones. It was a warmth with an edge of something else in it, the faint cold of the dark below pressing up through the fractures, testing, patient, the way it had always been patient.\n"You came."\nNnedimma was there.\nNot standing this time. Seated, cross-legged, between two of the central stones, her indigo wrapper perfectly still in the water around her, her white beads luminous. She looked exactly as she had in every dream and also completely different, because in the dreams Oby had been visiting, and now Oby was here, and there was a difference between those two things that changed the quality of everything.\n"How long have you been sitting like that?" Oby asked.\nSomething moved across Nnedimma''s face that was the closest thing to humour she had ever shown. "Since 1897."\nOby sat down across from her, between two of the outer stones. The lake bed was solid beneath her. Above them the water rose and rose toward a surface she could no longer see.\n"The two dark ones," Oby said. "Can they be restored?"\n"If the covenant is renewed before the remaining five fail, yes. The binding resets from the moment of renewal. What is dark reactivates from the covenant''s energy, not from the stone itself." She looked at the failing three. "But it must be complete. All seven must be touched in sequence, the covenant spoken over each one, and the final sealing done at the centre of the arc before the last strong stone dims."\n"Teach me the sequence."\n"I have been teaching you since the first dream." Nnedimma held her gaze. "Put your hand on the outermost stone. The dark one."\nOby turned to the stone on her left and placed her palm flat against it.\nThe cold came up immediately, sharp and searching, and beneath the cold the faint residue of the binding that had once lived there, the ghost of it, the shape of what had been carved and sealed and held for more than a century. She did not pull back from the cold. She let it come and sat with it the way you sit with something difficult until you understand it well enough to work with it.\nThen something moved in her chest, the warmth, her warmth, the thing she had been born carrying without knowing it, and it came down her arm and into her palm and met the cold in the stone and the language arrived.\nNot learned. Remembered.\nIt came up from below conscious thought, from the same place the lake''s knowledge had always lived in her, full and certain and perfectly formed, each syllable of it weighted the way the Nsibidi markings were weighted, not decoration but function, not symbol but mechanism.\nShe heard herself speaking it and did not know how she knew it and understood that knowing how she knew it was not the point.\nThe stone warmed under her palm.\nA single marking relit. Faint, tentative, but present.\nNnedimma exhaled, long and slow, the breath of someone who has been holding something very heavy for a very long time and has just felt the weight begin to shift.\n"Yes," she said quietly. "Exactly like that."\nAbove them, the lake held its breath.\nBelow them, in the dark beneath the stones, something that had been pressing at the boundaries for a hundred and twenty-nine years felt the pressure change and went still.\nListening.','\n',char(10)),1004,0,1,NULL,'2026-04-21T20:27:44.560Z','2026-04-21 20:27:44','2026-04-21 20:27:44','2026-04-21T21:00:00.000Z',3,NULL);
INSERT INTO "chapters" ("id","novel_id","chapter_number","title","content","word_count","is_premium","is_published","audio_url","published_at","created_at","updated_at","scheduled_release_at","part_number","season_id") VALUES(603,72,2,'The Original Covenant',replace('Nnedimma did not begin at the beginning.\nShe began the way all true things begin, in the middle, where the weight was, and worked outward from there. Oby sat with her palm still warm from the stone and listened the way she had learned to listen at the bottom of a lake, with her whole body, not just her ears.\n"Before Agulu was a community," Nnedimma said, "before the first family built beside this water, the lake existed as two things inhabiting one body. Iyi-Ọcha above. The hunger below." She gestured at the water around them, at the bronze light and the dark beneath it. "They did not fight. They did not negotiate. They simply coexisted because water large enough holds everything."\n"But the hunger grew," Oby said.\n"The hunger was always the same size. What changed was the presence of people." Nnedimma looked at the stones. "The living nature, Iyi-Ọcha, responded to human presence the way all living things respond to proximity. It became interested. It began to remember. The people beside the lake began to dream, to receive knowledge, to feel the connection between their health and the health of the water." She paused. "The consuming nature does not respond to human presence. It simply continues consuming. But people living beside water drink it. They farm in its soil. They give their dead to its margins. And so the consuming nature began accessing what it had not previously reached."\n"The crops," Oby said. "The soil."\n"Slowly. Over two generations. The elders of that time knew something was wrong but not what. The harvests were thinner. The water tasted different in the dry season. Children who swam in the eastern shallows came out tired in ways they had not been tired before." She held Oby''s gaze. "Then Iyi-Ọcha showed them. Through the women of the line it had always spoken through. My grandmother''s grandmother received the first dream. My grandmother received the full understanding. And it came to me with a task attached."\n"The covenant."\n"The covenant." She looked at her hands, these hands that had carved seven stones and spoken words over each one and chosen the deepest floor of a lake as the place where she would spend the rest of forever. "I was thirty-one years old. I had three children and a husband and a compound full of life." She said it plainly, without performance. "I understood what the task required before I accepted it. Iyi-Ọcha does not deceive. It showed me exactly what sealing the covenant would mean."\nOby waited.\n"The binding required a living anchor. The stones hold the covenant''s language. But language requires a speaker to remain active. A sealed covenant with no keeper degrades. The Nsibidi fades. The hunger tests the margins and finds them softening and pushes." She looked at the water above them. "I could have sealed it for a generation. Two, perhaps. Without an anchor it would have needed renewal every fifty years by whoever held the bloodline."\n"But you made it permanent."\n"I made it as permanent as one life could make it." She looked at Oby directly. "I chose to remain because in 1897 the British administration had already begun its work on the land records. I had seen what was coming. Communities losing legal standing over their sacred sites one document at a time. I knew that fifty years later there might be no one in the bloodline who had been prepared, who understood what the renewal required, who would not be too frightened or too assimilated to do it." She paused. "I was not wrong."\nOby thought about her grandmother refusing the inheritance. About her mother''s box of unread letters. About thirty years lost to fear.\n"Tell me about the original agreement," she said. "What Iyi-Ọcha promised and what the community promised."\nNnedimma settled herself slightly, the posture of someone moving from personal account to formal record.\n"Iyi-Ọcha offered three things. Clean water through every dry season regardless of rainfall. Fertile soil within walking distance of the lake for as long as the community maintained it. And guardianship of the dead, the lake as a passage point for those who died within its community, their memory held in the water rather than lost." She looked at Oby. "You understand what that third one means?"\nOby thought about it. About the depth of the lake as memory. About the crocodiles carrying something in their bodies that was older than the community itself.\n"The people who have died here," she said slowly. "They are in the lake."\n"Their memory is. Their knowledge. Everything they knew and loved and built. The lake holds it the way written records hold language. Permanently." Nnedimma''s expression carried something that was not grief exactly but lived in the same neighbourhood. "Every generation of Agulu that has kept the covenant has added to what the lake knows. That is why the lake knows everything it knows. It has been paying attention since before the first church was built."\nThe weight of this moved through Oby slowly.\n"And what did the community promise?"\n"Three things equally. To protect the water from contamination or diversion. To maintain the sacred designation of the lake in all dealings with outside authorities. And to keep the bloodline aware, each generation preparing the next so that the covenant could be renewed when needed without crisis." She looked at Oby with something that might have been the gentlest form of irony. "You see how that went."\n"One compromised elder in 1897."\n"One compromised elder and one hundred and twenty-nine years of accumulated negligence built on top of his signature." She did not say it with bitterness. She said it the way you state a mathematical result. "This is why the hunger has been reaching the margins for decades. The soil loss in the farms nearest the lake began in the 1960s. The fish patterns changed in the 1980s. The community noticed and called it climate, called it development, called it many things that were easier than what it actually was."\nOby sat with everything she had just been given, feeling the full architecture of it settle into her understanding alongside the knowledge she had been carrying since the first dream.\n"If I renew the covenant," she said, "what does it require from this generation? From the community above?"\n"What it has always required. The sacred designation restored. The lake protected in law the way it was always protected in practice." She paused. "And a keeper who is prepared."\n"Me."\n"You are already prepared. You have been preparing for three weeks at a pace that took my grandmother''s grandmother three years." Something in her expression opened slightly, like a door that had been shut a long time coming ajar. "You are the most prepared keeper this line has produced since me. Partly necessity. Partly who you are."\nAbove them the water was dark and still and holding everything it had ever been told.\n"Then show me the full sequence," Oby said. "All seven stones. Everything I need to say and do and hold." She met Nnedimma''s eyes. "I am not going to stay at the bottom of this lake. But I am going to finish what you started."\nNnedimma looked at her for a long moment.\nThen she moved to the first stone and placed her hand beside Oby''s hand and began.','\n',char(10)),1231,0,1,NULL,'2026-04-21T20:28:52.906Z','2026-04-21 20:28:52','2026-04-21 20:28:52','2026-04-21T21:00:00.000Z',3,50);
INSERT INTO "chapters" ("id","novel_id","chapter_number","title","content","word_count","is_premium","is_published","audio_url","published_at","created_at","updated_at","scheduled_release_at","part_number","season_id") VALUES(604,72,3,'Surface',replace('She came up at dawn.\nNot gasping. Not struggling. She rose through the layers of the lake the way the bronze light rose, steadily, from below, with the unhurried quality of something that had completed what it went down to do and was now returning on its own terms. The cold band between the temperatures. The lighter water above it. The silver underside of the surface coming toward her until she broke through it into the early morning air of Agulu and the world above the lake received her back without ceremony.\nShe stood chest-deep in the water and breathed.\nThe air tasted different. Not because it had changed. Because she had.\nHer mother was on the bank.\nShe had been there all night. Oby could see it in the way she was sitting, on the ground rather than the rock, her wrapper pulled around her, her back against a tree with the particular collapsed quality of a body that had been holding itself rigid for hours and had finally given up on rigid without giving up on watching. She was awake. She had not slept. Her eyes found Oby the moment Oby surfaced and something in her face broke open and then immediately reassembled itself into something that was trying very hard to be calm.\nOby waded to the bank.\nShe did not speak until she was on solid ground. She stood dripping on the red laterite soil and her mother stood too and they looked at each other across the two metres between them.\nHer mother crossed it.\nShe pulled Oby against her with both arms and held on with the grip of someone who had spent the night making calculations about loss and was revising them in real time. Oby felt her shaking, finely, the way people shake when they have been frightened for a long time and the frightening is over and the body has not received the message yet.\n"I am here," Oby said into her mother''s shoulder. "I am here."\nThey stood like that until the shaking stopped.\nHer mother pulled back and held her face in both hands and looked at her with the searching attention of a person checking for damage. What she found instead made her go still. Her eyes moved across Oby''s face slowly.\n"You are different," she said.\n"Yes."\n"Are you still mine?"\nThe question was so plainly itself, so unguarded, that Oby felt it land somewhere that the whole lake journey had not touched.\n"I am completely yours," she said. "And I am completely the lake''s. Those two things are not fighting each other."\nHer mother exhaled. She pressed her forehead briefly against Oby''s and then stepped back and straightened herself and became again the composed woman who had carried everything alone for sixteen years, except that now the composure had a different quality. Less like a wall. More like a choice.\n"Come inside," she said. "You need food and dry clothes and then you need to tell me everything."\nWord of Oby''s emergence moved through Agulu the way all significant things moved through Agulu, faster than it should have been possible and shaped differently by every mouth that passed it along.\nBy mid-morning the accounts varied considerably.\nSome said she had walked into the lake and stayed under for eight hours, which was impossible, and therefore either a lie or something that required a new category. Some said the crocodiles had formed a circle around the place where she went under. Some said the lake had glowed. Some said they had seen nothing unusual and the whole thing was the invention of a community that had been agitated beyond reason by a teenager and an old man with a grudge against development.\nBut the people who lived on the northern road, the ones who had been watching the lake for three weeks, who had seen the fish leave and the wells dry and the water rise and seventeen crocodiles come ashore in a line, those people looked at the accounts differently. They looked at them the way you look at a pattern when you have enough data points to see the shape.\nOby walked through the market at noon because she needed to and because retreating felt like the wrong signal to send to herself.\nThe difference in how people looked at her was immediate and difficult to describe precisely. It was not fear, though fear was present in some faces. It was not reverence, though there was something adjacent to it in others. It was closer to the feeling in a room when someone enters who has clearly just come from somewhere significant and the room has not decided yet what to do with that.\nOld Ikechukwu saw her from his stall and stood up. He did not say anything. He simply stood, the way you stand for something that deserves standing.\nShe nodded at him. He nodded back.\nMrs. Okonkwo touched her arm as she passed and said, very quietly, "The wells on the northern road. Two of them have water again this morning."\nOby stopped. "How much?"\n"Not full. A beginning." She searched Oby''s face. "Did you do that?"\n"I began something," Oby said carefully. "It is not finished."\nShe found Adaeze at the fabric stall where she sometimes helped her aunt on Saturdays. Adaeze looked at her the way she looked at things she was assessing, direct and thorough, and then her expression settled into something that was not quite relief but was the emotion that comes directly before relief when the situation is not yet resolved.\n"You went in," Adaeze said.\n"I went in."\n"And?"\n"I know the full sequence now. I know what to say over each stone and in what order and how to complete the sealing." She kept her voice low. "But I cannot do it alone. I need the hearing to succeed. I need the construction stopped before I complete the renewal, or the excavation will just fracture it again."\nAdaeze was already thinking. Oby could see it, the particular stillness behind her eyes that meant she was moving pieces.\n"The archaeologist," Adaeze said. "The one the board appointed."\n"She is eleven days away."\n"Nine now. And she published on Nsibidi artifacts." She met Oby''s eyes. "What if she did not need to wait eleven days? What if someone sent her what she was going to find before she arrived?"\nOby looked at her. "The stone markings."\n"You have been down there. You have seen them up close. You know the Nsibidi on each stone, what it says, what sequence it follows." She paused. "Write it down. All of it. Everything you saw. I will find her institutional email."\nA preliminary report from the appointed archaeologist, submitted to the heritage board before the scheduled site visit, carrying specific Nsibidi descriptions that could only come from direct observation of artifacts that the company claimed did not exist.\n"That accelerates the timeline," Oby said.\n"That collapses the timeline," Adaeze said.\nBehind them, across the market''s noise and colour, the lake was visible in the distance, dark and silver and holding everything it knew, waiting for Oby to come back down and finish what one hundred and twenty-nine years of patience had been building toward.\nShe took out her notebook.\nShe began to write.','\n',char(10)),1223,0,1,NULL,'2026-04-21T20:30:13.062Z','2026-04-21 20:30:13','2026-04-21 20:30:13','2026-04-21T21:00:00.000Z',3,50);
INSERT INTO "chapters" ("id","novel_id","chapter_number","title","content","word_count","is_premium","is_published","audio_url","published_at","created_at","updated_at","scheduled_release_at","part_number","season_id") VALUES(605,72,4,'The Evidence',replace('Dr. Amara Osei replied within six hours.\nOby had not expected that. She had sent the email through Adaeze, fourteen pages of detailed Nsibidi descriptions, stone dimensions estimated by memory, the arc arrangement mapped onto a hand-drawn diagram, the sequence of the markings and their functions as Nnedimma had taught her, attached to a single paragraph of context that was precise and unembellished. She had not expected a response before morning. She had prepared herself for the particular silence of institutional email addresses that are checked twice a week.\nInstead, at nine-fourteen in the evening, Adaeze''s phone lit up.\nThey read the reply together on Adaeze''s screen, standing in the compound under the overhead light.\nDr. Osei wrote in the clipped, energised tone of an academic who had been handed something that contradicted her expectation of what the day would contain. She wrote that the Nsibidi sequence described was consistent with binding covenant documentation from the mid-nineteenth century Niger Delta and Igbo transitional period, that the seven-stone arc formation was a known but extraordinarily rare configuration used specifically for covenants requiring permanent spiritual anchorage, and that if the physical artifacts matched the descriptions provided, this would constitute one of the most significant undisturbed heritage finds in the southeast region in forty years.\nShe wrote that she was moving her site visit from eleven days to four.\nShe also wrote that she was forwarding the descriptions to the heritage board chair tonight, with a preliminary assessment letter recommending an immediate precautionary suspension of excavation activity within fifty metres of the northern lake bed pending physical verification.\nAdaeze made a sound that was not quite a word.\nOby read the email a second time, then a third, with the careful attention of someone who needed to be certain they were reading what they thought they were reading and not what they needed to read.\n"Four days," she said.\n"Four days," Adaeze confirmed. "And a precautionary suspension recommendation going to the board tonight."\n"The board has to act on the recommendation."\n"They do not have to. But if they receive a written preliminary assessment from their own appointed archaeologist recommending suspension and they choose to ignore it, that decision goes on record." Adaeze looked at her. "Which means if anything happens to the northern bed during those four days, the liability lands directly on them."\nOby thought about the three failing stones. About the timeline she had been carrying in her chest since Nnedimma told her.\nThree days on the stones when she descended. She had spent one night below. Two days remaining on the weakest ones. Four days until Dr. Osei arrived.\nThe gap was two days.\nShe called Arinze.\nHe answered on the second ring despite the hour, which told her he had been waiting. She gave him the email summary in three sentences. He was quiet for a moment and then he said, in the voice of a man who had been building cases for thirty years and could recognise a turning point by its weight, "I will call the board chair at seven tomorrow morning. With the preliminary assessment letter and a formal request for emergency suspension pending the site visit. If the letter is as strong as you are describing, he cannot reasonably refuse."\n"And if he refuses?"\n"Then we file an emergency injunction in the federal court by noon citing the board''s failure to act on its own appointed expert''s recommendation." He paused. "That filing takes four hours to process. The injunction is automatic pending a hearing. Construction stops the moment it is filed."\nLegal suspension by noon tomorrow. One way or another.\nShe told her mother at the kitchen table, laying it out the same way she had laid out everything to Arinze, plainly and in sequence. Her mother listened without interrupting, which was how she listened when the information was moving faster than her emotional responses could organise themselves.\nWhen Oby finished her mother said, "The two days before Dr. Osei arrives."\n"Yes."\n"The stones."\n"The three weakest ones." She held her mother''s gaze. "If the construction stops tomorrow and the stones hold for two more days, the site visit happens before the seal breaks completely."\n"And after the site visit?"\n"After Dr. Osei confirms the artifacts, the heritage board issues a full suspension. The construction permit is suspended pending legal review. That review, given Arinze''s colonial document challenge, could take months." She paused. "Long enough for me to complete the renewal properly. With time. With preparation."\nHer mother was quiet. Outside, the lake was doing its night breathing, steady and enormous.\n"You are not going back down until it is safe," her mother said.\n"I am not going back down until it is time," Oby said, which was not the same thing, and they both knew it, and her mother accepted the difference with the specific grace of a woman who had been burning letters for seven years and had decided she was done choosing the smaller thing.\nThe board chair called Arinze at eight the following morning.\nOby sat at the kitchen table and watched her mother''s face while Arinze''s voice came through the phone on speaker, and she read the news in the slight release around her mother''s eyes before the words arrived.\nPrecautionary suspension. Effective immediately. Fifty metres from the northern lake bed. All excavation activity in the designated zone to cease pending Dr. Osei''s site visit and preliminary physical verification.\nThe excavator reached the eastern drainage section at eight-thirty, continuing its permitted work outside the suspended zone. But the survey team that had been advancing markers toward the northern section packed their equipment into the company truck and drove away, and when Mr. Salau appeared at the northern perimeter at nine o''clock and stood looking at the new boundary markers the board''s officer had placed before dawn, his face carried the precise expression of a man whose calculations had just been revised by someone else''s arithmetic.\nOby watched him from the northern road.\nHe looked up and saw her.\nThey held each other''s gaze across the survey tape and the distance and the four weeks of accumulated consequence between them. He did not look at her with anger. He looked at her with the complicated expression of someone who had underestimated something and was still in the process of understanding exactly what.\nThen he turned and went back to his site.\nOby turned and went back to the lake.\nShe sat at the waterline and pressed her palm to the surface and felt the stones below her, all seven, the two dark ones and the three failing ones and the two still strong. She held the warmth of the intact ones and sent it down the same way she had sent it down in the first tentative touch at the bottom of the lake.\nShe felt the failing stones respond. Faintly. The way a fire responds to breath, catching slightly, stabilising slightly, not recovering but not diminishing either.\nHolding.\nShe kept her palm in the water for an hour.\nTwo days. The stones needed to hold for two days.\nShe would sit here every hour of those two days if that was what it took.\nBelow her, Nnedimma was waiting with the patience of someone who had learned that patience was not the absence of urgency but urgency expressed as endurance, and above her the sky was wide and blue over Agulu and the lake was the lake, ancient and certain and completely, finally, on the edge of being protected.','\n',char(10)),1260,1,1,NULL,'2026-04-21T20:31:25.058Z','2026-04-21 20:31:25','2026-04-21 20:31:25','2026-04-21T21:00:00.000Z',3,50);
INSERT INTO "chapters" ("id","novel_id","chapter_number","title","content","word_count","is_premium","is_published","audio_url","published_at","created_at","updated_at","scheduled_release_at","part_number","season_id") VALUES(606,72,5,'Confrontation at the Lake',replace('Dr. Osei arrived on the third day, not the fourth.\nShe came in a university vehicle with two research assistants and equipment cases and the particular energy of someone who had rearranged several other people''s schedules to be here and did not regret it. She was small and precise and she shook Oby''s hand at the northern bank with the directness of a person who had decided before arriving that the sixteen-year-old who wrote fourteen pages of Nsibidi descriptions from memory deserved to be treated as a peer.\n"Show me where," she said.\nOby showed her.\nShe stood at the waterline and described the arc formation, the stone dimensions, the sequence of the markings, the depth. Dr. Osei''s two assistants set up underwater imaging equipment while she listened, asking sharp questions, making notes, her expression moving through professional assessment into something that was trying to stay professional but kept bumping against the sheer weight of what it was being asked to process.\nThey were twenty minutes into the site assessment when the company vehicles arrived.\nThree of them. Mr. Salau and the Abuja lawyer and two men Oby had not seen before, large and quiet and positioned in the way of people whose function was presence rather than conversation. Behind them, arriving separately in his council car, Chief Odumegwu.\nArinze appeared at Oby''s shoulder from the direction of the road, having been watching for exactly this. Lolo Adaku came from the other direction, slower, with her wrapper immaculate and her face arranged in the expression she wore when she had decided something before she left the house.\nMr. Salau walked directly to Dr. Osei.\n"The precautionary suspension applies to excavation activity," he said, pleasantly, with the precision of someone who had spent two days with a lawyer reviewing exact language. "It does not restrict the company''s access to its permitted site area. We have a right to be present during any assessment on land covered by our permit."\nDr. Osei looked at him with the calm of someone who had done fieldwork in complicated locations and had developed a comprehensive immunity to men arriving to manage her. "You are welcome to observe," she said, and turned back to her equipment.\nThe Abuja lawyer produced a document and handed it to Arinze. "Emergency counter-filing. Contesting the basis of the precautionary suspension on the grounds that the preliminary assessment constitutes hearsay evidence provided by an unqualified source." He said it without looking at Oby.\n"The source described artifacts consistent with documented mid-century Niger Delta heritage formations," Arinze said, not opening the document. "That description will be verified or disproven by Dr. Osei''s physical assessment in the next two hours. Filing a counter-injunction before the assessment is complete tells the court your client is more concerned with preventing verification than with legal accuracy."\nThe lawyer looked at him steadily. "File what you like."\nChief Odumegwu had not spoken. He stood apart from the company men, which Oby noticed. He was looking at the lake with an expression she had not seen on him before, something private, something that did not belong to the version of himself he deployed at council meetings.\nShe walked to him.\nHe did not move when she approached, did not rearrange his expression or produce the council-meeting version of himself. He simply stood looking at the water with the face of a man in the middle of something.\n"Your father mapped the stones in 1961," she said quietly. "You have known their location your entire adult life."\n"Yes." He said it without deflection.\n"You submitted a statement supporting the company."\n"Yes."\nShe waited.\n"My father told me about the stones the year before he died," he said, still looking at the water. "He told me what they meant, what they held, what would happen if they were disturbed. He told me the bloodline would know when it was time and I would know it by watching the women of Adaora''s line." He paused. "When you stood up in the community meeting and gave that depth measurement, I knew."\n"And you still filed the statement."\n"I have held this town''s infrastructure decisions for twenty-two years," he said. "This road brings contracts, employment, access. Half this community has been waiting for it." He turned and looked at her directly. "I told myself the heritage claim would fail anyway. That the stones were too deep, too old, too unverifiable. That it was better to let it fail than to put myself against the project and lose influence and have nothing left to protect the community with."\n"You were protecting your position."\nHe held her gaze. "Yes." He said it with the particular dignity of a man who has stopped lying to himself. "I was also afraid."\nBehind them, Dr. Osei''s assistant surfaced from the first dive, pulling off his mask, and said something to her in a rapid undertone. Dr. Osei looked at her recording equipment and then at the bank with an expression that had moved completely beyond professional neutrality into something unguarded.\nShe looked at Oby.\n"They are there," she said. "Exactly where you described. All seven."\nThe words moved through the people assembled on the bank differently. Arinze absorbed them into his legal calculations visibly. Lolo Adaku closed her eyes briefly, the expression of someone receiving news they have waited decades to receive. Mr. Salau''s lawyer was already on his phone. Mr. Salau himself looked at his lawyer and something passed between them.\nThe two large quiet men stepped back.\nThe crocodiles surfaced.\nNot one. All seventeen, appearing simultaneously across the full width of the lake, their ridged backs breaking the surface in a line, their heads raised and facing the bank where the company men stood. The water around them was bronze in the afternoon light, the whole surface of it, every point, as if the lake had turned its full attention upward.\nNobody on the bank spoke.\nEven the lawyer stopped typing on his phone.\nChief Odumegwu looked at the crocodiles, at the bronze water, at the assessment equipment on the bank, and at Oby. Something finished moving through his face and settled.\n"I will withdraw the council statement," he said. "Today. By written submission to the board."\nHe said it to Oby. Not to Arinze. Not to Lolo Adaku. To her.\nShe held his gaze. "The location map your father made. The 1961 document."\nHe reached into his jacket and produced an envelope and held it out.\nShe took it.','\n',char(10)),1084,1,1,NULL,'2026-04-21T20:32:47.101Z','2026-04-21 20:32:47','2026-04-21 20:32:47','2026-04-21T21:00:00.000Z',3,50);
INSERT INTO "chapters" ("id","novel_id","chapter_number","title","content","word_count","is_premium","is_published","audio_url","published_at","created_at","updated_at","scheduled_release_at","part_number","season_id") VALUES(607,72,6,'What Her Mother Chooses',replace('Her mother was at the bank when Oby returned from the confrontation.\nNot waiting in the anxious way of the night Oby went under. Standing, arms at her sides, looking at the lake with the open expression of someone who has removed a structure they had been maintaining for a long time and is feeling the unfamiliar air on the place where it used to be.\nOby came to stand beside her. She held out the envelope. Her mother took it, opened it, unfolded the paper inside. She looked at it for a long time. The hand-drawn map, the measurements, the careful handwriting of Chief Odumegwu''s father documenting in 1961 what he had known his whole life and trusted to paper because some knowledge is too important to exist only in one person''s memory.\nHer mother refolded it slowly.\n"He gave it to you," she said.\n"He gave it to me."\nHer mother looked at the water. "When I was seventeen and my mother had just died, I went to Lolo Adaku. I told her I did not want it. The inheritance. Any of it." She said it without apology, as information. "Adaku told me the lake did not deal in want. She said it would come when it was ready and I could either be prepared or be surprised." A pause. "I chose to be surprised. And then I chose to be surprised for so long that you were the one who had to manage the surprise."\n"Mama."\n"I am not asking for forgiveness. I am giving you the accurate account." She folded the envelope and held it with both hands. "What do you need for the renewal? The full one. Tell me specifically."\nOby looked at her. "You want to help."\n"I am asking what you need."\n"The renewal requires someone on the surface while I am below. Someone holding the connection between the upper lake and the lower, keeping the water memory active above while I work the stones beneath." She paused. "Nnedimma did it alone because there was no one to hold the surface for her. She had to anchor from below. That is why she could not come back up." She held her mother''s gaze. "With someone on the surface holding the upper connection, the person below does not need to remain. The anchor becomes shared."\nHer mother absorbed this. The specific quality of her stillness shifted.\n"You are telling me that if I had been prepared," she said carefully. "If any woman of this line had been prepared and present when this needed doing. Nnedimma would not have had to stay."\n"Yes."\nThe word landed between them and stayed there with everything it contained. Not accusation. Fact. The cost of the accumulated refusals calculated clearly at last.\nHer mother was quiet for a long time. The lake breathed around them. Somewhere to the east the construction site was silent, the suspension holding, the machines resting.\n"Show me what to do," her mother said.\n"You need to be in the water. Not deep. At the northern shallows where the stones are closest to the surface." Oby turned to face her fully. "You place your palms on the surface and you hold. You do not speak the covenant language. I do that below. Your part is presence and intention. The lake already knows you. It has always known you." She paused. "You just have to stop telling it no."\nSomething crossed her mother''s face that was too large and too private to name from the outside. She looked at the lake, this water she had lived beside for forty-one years and treated as scenery and refused as inheritance and feared as obligation and finally, standing on this bank with her daughter on one side and everything she had postponed on the other, was being asked to simply enter.\nShe took off her shoes.\nShe handed the envelope to Oby. She unwrapped her outer wrapper and folded it on the flat rock and stood in her blouse and underskirt and walked into the shallows.\nThe water received her without ceremony. She walked in to her knees and stopped and stood with her shoulders rising and falling and her face doing something that Oby could not fully see from the bank.\nThen she lowered herself until the water was at her waist and she placed both palms on the surface.\nThe bronze came up immediately.\nNot the faint warmth Oby coaxed from it with effort. Full and immediate, the way it came when the lake had been waiting for something and the something finally arrived. It spread from her mother''s palms outward across the surface in a slow pulse and the water around her lit amber and her mother made a sound that was not pain and was not surprise but was the sound of a person receiving something at full strength that they have been receiving at a fraction their entire life and only now understand the difference.\nOby entered the water beside her.\nShe stood next to her mother in the shallows and felt the connection running between them, between the surface warmth her mother was holding and the deeper warmth below, the stones responding from the lake bed, the whole system recognising itself in a way it had not been able to recognise for two generations.\nHer mother turned and looked at her. Her eyes were wet and the bronze light was on her face and she looked like herself and also like every woman behind her in the line, all the way back to the one who had worn indigo and carved seven stones and loved this water enough to stay in it forever.\n"I should have done this when I was seventeen," she said.\n"You are doing it now," Oby said.\nHer mother nodded once. She turned back to the lake and pressed her palms deeper and held.\nBelow them, at twenty-seven metres, Nnedimma waited.\nBut not alone.\nNot anymore.','\n',char(10)),997,1,1,NULL,'2026-04-21T20:33:57.516Z','2026-04-21 20:33:57','2026-04-21 20:33:57','2026-04-21T21:00:00.000Z',3,50);
INSERT INTO "chapters" ("id","novel_id","chapter_number","title","content","word_count","is_premium","is_published","audio_url","published_at","created_at","updated_at","scheduled_release_at","part_number","season_id") VALUES(608,72,7,'The Road That Cannot Be Built',replace('Dr. Osei''s formal site assessment report was forty-three pages.\nArinze called Oby the morning it was submitted to the heritage board and read her the executive summary over the phone, slowly, the way he read things he wanted to make sure were correctly received. His voice had the particular quality it carried when something he had worked toward for a long time was arriving and he was making himself receive it calmly rather than the other way.\nThe report confirmed seven submerged stone artifacts at the northern lake bed. It confirmed the Nsibidi script as consistent with mid-nineteenth century binding covenant documentation. It confirmed the arc formation as a protected configuration under Section 14 of the National Heritage Act. It noted that the artifacts showed evidence of recent stress fractures consistent with seismic disturbance from nearby excavation activity. And it classified the entire northern lake bed within a forty-metre radius as a Category One heritage site requiring immediate and permanent protection.\nCategory One. The highest designation available under Nigerian heritage law.\n"What does that mean for the permit?" Oby asked.\n"It means the construction permit is void," Arinze said. "Not suspended. Not under review. Void, because it was issued on the basis of a land classification that is now legally incompatible with the heritage designation." He paused. "The 1897 Brentwood reclassification, combined with the Chief''s 1961 documentation and the colonial suppression evidence, gives the heritage commission grounds to formally reverse the original land status. Ihe nsọ. Sacred property. Reinstated."\nThe word moved through her the way the bronze moved through water.\n"When?" she asked.\n"The board chair is convening an emergency session this afternoon. He has the report, the colonial document evidence, and the withdrawn council statement. The company''s lawyers are already in Awka." He was quiet for a moment. "They know. They have known since Dr. Osei surfaced with her recording equipment yesterday. The filing of the counter-injunction was withdrawn at seven this morning."\nShe stood at the northern bank after the call and looked at the lake and thought about the specific shape of things ending.\nThe company broke camp on a Thursday.\nNot dramatically. Not the way endings looked in the stories she had grown up reading, where the villains departed in noise and disruption and left behind visible damage that the community then gathered to repair. They simply began, over the course of a single day, to reverse the process of their arrival.\nThe survey markers came out of the ground first, the orange stakes pulled up in pairs by two workers moving efficiently along the perimeter, the yellow survey tape rolled onto spools. The equipment cases came out of the site office. The generator went onto a truck. The portable structures that had housed the site management were collapsed and loaded with the practiced speed of people who had done this before.\nMr. Salau walked the site once in the afternoon, alone, before the final vehicles loaded. He did not come to the lake. He stood at the eastern clearing where the excavator had worked and looked at the opened ground for several minutes and then turned and got into his car and did not look back.\nThe excavator was the last thing to leave. It went on the same flatbed truck that had brought it, its claw folded against its body, moving back through the road it had arrived on four weeks earlier while the late afternoon light made it look, for a moment, like something sleeping rather than something defeated.\nOby watched from the compound wall, her legs dangling, her chin on her hands. The same position she had been in when they arrived.\nAdaeze came to stand in the road below and looked up at her. "How does it feel?"\nOby thought about the question honestly. "Incomplete," she said. "The project collapsed. The permit is void. But the stones are still fractured. The seal is still compromised. The work is not done."\n"The legal work is done."\n"The other work is not."\nAdaeze nodded slowly. "When?"\n"Soon." She looked at the lake, at the late light on its surface. "I need three days. Nnedimma has been teaching me since I went under the first time. The sequence is complete. I know every word." She paused. "I just needed the construction to stop so that what I do below holds without being undone above."\n"It has stopped."\n"It has stopped."\nShe climbed down from the wall.\nThere was one more thing.\nShe went to the site of the opened ground, the eastern section where the excavator had worked, and stood at its edge. The earth was raw and red, the way broken ground always was, the soil exposed and rearranged. Around the edges of it the grass had already begun its slow return, the thin green of new shoots pressing through the disturbed soil at the boundary, doing what living things did, finding the edges of damage and beginning there.\nShe crouched and pressed her palm to the opened earth.\nThe warmth came up faintly, thinner here than at the waterline but present, the Iyi-Ọcha moving through the soil the way it moved through the water, present in everything connected to the lake''s system. She held her hand there and felt the ground, its disruption, its underlying continuity, the way the damage sat above something that had not been reached.\nShe thought about Brentwood''s document. One careful filing, one corrupted signature, one hundred and twenty-nine years of a false record standing as the foundation of every subsequent decision. She thought about what it meant to build on a lie, how the structure could stand for a long time, could look solid, could pass inspection after inspection, and still rest on something that was never true.\nIt did not require drama to fall. It required only the right evidence, placed correctly, in the hands of people willing to look at it.\nShe stood up.\nThe road that could not be built would not be built here. Not on this ground, not through this water, not above these stones. Other roads would come, other proposals, other documents filed by other men with clipboards. She did not imagine this was the last of it. She was not that young.\nBut this one had ended.\nAnd the reason it had ended was not protest, not emotion, not tradition deployed as sentiment. It had ended because of a fourteen-page email and a colonial archive and a 1961 hand-drawn map and a lawyer who had been waiting thirty years for a case worth filing and a girl who had listened when a lake decided it was time to speak.\nEvidence. The oldest magic there was.\nShe walked back toward the northern bank, toward the water and the waiting stones and the work that was still ahead, and the sun went down over Agulu and the lake turned the colour of everything the evening had left in the sky.','\n',char(10)),1159,1,1,NULL,'2026-04-21T20:35:06.954Z','2026-04-21 20:35:07','2026-04-21 20:35:07','2026-04-21T21:00:00.000Z',3,50);
INSERT INTO "chapters" ("id","novel_id","chapter_number","title","content","word_count","is_premium","is_published","audio_url","published_at","created_at","updated_at","scheduled_release_at","part_number","season_id") VALUES(609,72,8,' What Agulu Remembers',replace('The wells filled on a Friday.\nNot the two that had trickled back during the partial renewal. All of them, the full seven that had run dry on the morning after the first excavation, filling overnight with the unhurried completeness of water that has decided to return rather than water that has been restored. By dawn the women who had been walking to the tanker point every morning were drawing from their own compounds again, and the news moved through the northern road before breakfast was finished.\nOby heard about it from three separate people before she reached the market.\nWhat she noticed was not the relief in their voices, though the relief was real and large. What she noticed was what came underneath the relief, a quieter thing, more complicated, the thing that arrives when a community looks at what it nearly did and has to find a way to hold that knowledge going forward.\nShe saw it in how people spoke about the lake now.\nNot with the comfortable familiarity of before, the casual ownership of something that had always been there and would always be there regardless of what was done beside it. That version was gone. In its place was something more careful, more considered, the way you speak about a person after you have understood for the first time that they can leave.\nMrs. Okonkwo stopped her at the pepper stall. "The fish are back," she said. "Ikechukwu went out this morning. Full traps." She looked at Oby with the directness of someone who had decided to stop being indirect. "We almost let them drain that section. Half of us stood at that community meeting and raised our hands."\n"A road is a reasonable thing to want," Oby said.\n"We wanted the road more than we wanted to ask what the road would cost." She set down her pepper. "That is different."\nIt was. Oby did not say so. She did not need to.\nThe community gathering was not officially called by anyone.\nIt assembled itself on Saturday morning at the northern bank, the way certain things assembled themselves in Agulu, through the wordless collective agreement of people who understood that something significant had concluded and needed witnessing. By nine o''clock there were more than a hundred people at the waterline. Fishermen and traders and schoolchildren and elders and the woman who had told Oby she was being used by politicians and the man who had laughed at her name on the road.\nAll of them at the lake.\nChief Odumegwu came and stood at the edge of the gathering without his council formality, without his car or his attendants, in a plain wrapper and slippers, the clothes of a man who had decided to attend as himself rather than his title. He did not seek the front. He stood in the middle of the crowd like everyone else.\nLolo Adaku sat on a chair that someone had carried for her, at the waterline, her face turned toward the water with the expression of a woman who had been waiting for this specific morning for most of her adult life and was receiving it without performance.\nOby stood at the bank and did not make a speech.\nShe had thought about whether to speak and had decided that what the moment needed was not her voice. The lake was present. The crocodiles were visible, the large one at the surface near the northern shallows, the others further out, their ridges breaking the water in a line. The filled wells and the returning fish and the bronze that had been in the water since the construction stopped were doing the work that words would only approximate.\nWhat she did instead was walk to Mama Uzo.\nThe old woman was seated near Lolo Adaku, her small hands folded in her lap, her eyes on the water. Oby crouched beside her.\n"You said his name at the council meeting," Oby said quietly. "When you said the elders needed to stop talking around what they knew. You made them say the stones out loud."\nMama Uzo looked at her. "Someone had to."\n"Why didn''t they listen to you back then? Before it got this far?"\nThe old woman was quiet for a moment. "Because I was old and a woman and my late husband had been on the wrong side of a land dispute with Chief Odumegwu''s father in 1974 and these things have long memories in small communities." She said it without bitterness, as geological fact. "Also I had no proof. Only knowing." She looked at Oby steadily. "You had proof. That is what changed."\nProof and knowing together. That was what had been required. One without the other had failed for a hundred and twenty-nine years.\nAdaeze found her in the crowd and stood beside her without needing to say anything. They watched the lake together, the water and the crocodiles and the hundred people gathered at the bank doing what people had always done when they did not have the words for what they were feeling and needed to be near the thing itself.\nAfter a time, Engineer Okafor, who had spoken in favour of the project at every meeting, who had said government approval settled most questions, came and stood near Oby with his hands in his pockets. He looked at the water for a long moment.\n"I have a grandchild," he said finally. "Eight months old." He kept his eyes on the lake. "I want her to swim in this water."\nOby looked at him. "Then help us protect it. Not from emotion. From the legal side. You have connections in the infrastructure ministry." She paused. "The heritage designation needs to be enforced, not just filed. That requires people who understand how ministry decisions get made and unmade."\nHe looked at her with the expression of a man receiving a task he had not expected and finding it smaller than his guilt, which made it manageable.\n"Come to me next week," he said. "With Arinze."\nHe walked away.\nAdaeze made a quiet sound of appreciation beside her.\nThe gathering stayed until noon, when the sun drove people back to their compounds and their meals and their ordinary Saturday errands, and they went with the particular quality of people who have stood together at something significant and are carrying it home in their bodies, not as burden but as belonging.\nThe lake was still as they left.\nThe water held the light.\nIt had held so much longer than any of them had understood, and it would hold longer still.','\n',char(10)),1105,1,1,NULL,'2026-04-21T20:36:04.588Z','2026-04-21 20:36:04','2026-04-21 20:36:04','2026-04-21T21:00:00.000Z',3,50);
INSERT INTO "chapters" ("id","novel_id","chapter_number","title","content","word_count","is_premium","is_published","audio_url","published_at","created_at","updated_at","scheduled_release_at","part_number","season_id") VALUES(610,72,9,' The New Keeper',replace('She went down on a Sunday.\nNot at midnight. Not in crisis. In the late morning, with the sun high and the water warm at the surface and her mother standing in the northern shallows with both palms on the water and her face arranged in the concentrated stillness she had been practicing every morning since the day she first entered the lake and felt what she had been refusing for twenty-four years.\nOby stood at the waterline and looked at the lake and took a complete account of herself.\nShe was sixteen years old. She had a school examination in three weeks that she had not finished preparing for. She had a best friend who researched things at midnight and asked the right questions and had spent the last month working from behind a line she had not chosen and had stayed anyway. She had a mother who had burned letters out of love and walked into water out of the same love and was standing in it now, holding something ancient with her bare hands, getting better at it every day.\nShe had a life. It was hers. It was full of specific and ordinary things she was not willing to release.\nShe also had seven stones at twenty-seven metres and a covenant that needed completing and an ancestor who had been waiting in the deep since 1897 for someone in their line to come back down and share the weight.\nBoth of these things were true. She had spent the last two weeks understanding that they were not in opposition.\nShe walked into the water.\nHer mother did not look at her. She kept her palms on the surface and her eyes forward and her presence steady, the surface connection holding the way Nnedimma had said it would hold, the way it had always been designed to hold, by two women instead of one, the burden distributed across the line rather than collapsed into a single point.\nOby went under.\nThe bronze received her like a homecoming.\nNot the urgent homecoming of the first descent, the dark and the emergency and the failing stones. This was something quieter. The warmth moved around her as she descended and the lake bed appeared below her and the stones were as she had left them, two dark, three dim, two still bright, the whole arc waiting with the patience it had always had.\nNnedimma was standing.\nNot seated between the stones in the posture of someone conserving what they had left. Standing, upright, her indigo wrapper moving in the current, her white beads luminous. She looked at Oby descending and her face held an expression Oby had not seen on it before.\nNot the composure of a general. Not the precision of a teacher. Something that had been kept underneath both of those things for a very long time, something that was simply a person, a woman of thirty-one who had made a choice with open eyes and had been keeping the consequences of it alone for more than a century.\nRelief.\nOby landed on the lake bed and stood before her.\nNeither of them spoke for a moment.\n"My mother is on the surface," Oby said.\n"I know." Nnedimma looked upward briefly. "I felt her enter the water the first time." Something moved across her face. "She has her grandmother''s hands."\n"She is learning."\n"She is more than learning." She looked at Oby. "She found it quickly when she stopped running from it. That is the thing about this inheritance. It does not diminish with refusal. It waits, and what it finds when the refusal ends is everything that was refused, returned at once."\nOby looked at the stones. "I am ready."\n"I know you are."\n"I want to be clear about something first." She held Nnedimma''s gaze. "I am completing the renewal. I am accepting the role of keeper. But I am not accepting the terms you accepted." She said it directly, without apology. "I am not staying below. I am not anchoring from the deep. My mother holds the surface and I hold the covenant and between us the binding does not require a single point of permanent sacrifice."\nNnedimma looked at her for a long moment.\n"The covenant language allows for it," she said. "A surface keeper changes the architecture of the anchor. I chose the deep because there was no one to hold the surface. I did not choose it because it was the only way." She paused. "I may have allowed the women of the line to believe it was the only way."\n"Why?"\n"Because I was afraid," she said, and saying it out loud after more than a century carried a weight that was visible on her face. "I was afraid that if they understood the surface option was available, they would choose it without understanding what it required of the person below. That they would put someone down here unprepared and the seal would fail." She held Oby''s eyes. "I was protecting the covenant. I was also protecting something in myself that needed the sacrifice to have been the only choice."\nThe honesty of it moved through the water between them.\n"It was the only choice available to you," Oby said. "In 1897, with no one prepared, with the administration already filing documents above your head. What you did was not wrong. It was what the moment required."\nNnedimma said nothing.\n"But this moment requires something different," Oby continued. "And I am going to meet this moment with what it actually needs, not with what the last one needed."\nShe moved to the first stone. The outermost dark one. She placed her palm flat against it and felt the cold and the residue of the binding and above her, at twenty-seven metres, she felt her mother''s palms on the surface, the connection running between them like a rope between two points, taut and warm and certain.\nShe spoke the first words of the covenant.\nThe language came without effort, without searching, the way her own name came when someone asked for it. Full and weighted and precisely formed, each syllable landing on the stone and sinking in the way water sinks into dry earth, finding the channels that had always been there.\nThe marking lit. One line. Then two. Then the full pattern, running across the stone''s face in amber light, the Nsibidi burning back to life with the particular brightness of something that has been dark for a long time and remembers what light is for.\nShe moved to the second stone.\nThen the third. Then the fourth and fifth, the dim ones responding with less resistance than she had expected, as if they had been holding themselves near the surface of dead waiting for exactly this touch. The sixth. The seventh, the strong ones confirming what the weaker ones had recovered, the whole arc burning in sequence, the covenant reinstated from its outermost points to its centre.\nShe stood at the centre of the arc.\nAbove her, the surface connection pulsed with her mother''s presence, steady and warm, the upper covenant held with two hands and a lifetime of delayed inheritance finally delivered.\nBelow her, the darkness that Nnedimma had sealed was still. Contained. The pressure of it was present but bounded, the way it had always been bounded when the stones were whole, the hunger held below the covenant exactly as it had been held since 1897.\nShe spoke the sealing words.\nAll of them, the full final passage, the commitment of the keeper to the covenant and the covenant''s commitment to the community and the lake''s promise to remember and hold and sustain, everything that Nnedimma had first spoken into these stones in the year the British arrived with their documents and their reclassifications and their careful erasures of what they did not want to acknowledge.\nThe arc pulsed once, all seven stones simultaneously, a single beat of amber light that moved outward through the water and upward through twenty-seven metres and broke the surface in a ring that Oby could not see but knew was there from the way her mother''s connection strengthened in the same moment, recognition passing between surface and deep.\nDone.\nShe looked at Nnedimma.\nThe dibia was watching her with the expression of someone who has waited longer than patience should require for something they loved, and has finally received it.\n"You are free," Oby said. "The surface keeper holds the upper anchor. You do not need to hold from below anymore."\nNnedimma looked at the stones, burning complete and whole in their arc on the lake bed, and something in her face changed so slowly it was like watching the light change at the end of the dry season, gradual and total and transforming everything it touched.\n"A hundred and twenty-eight years," she said quietly.\n"Come up," Oby said.\nShe held out her hand.\nNnedimma looked at it, at this hand of a girl of sixteen who shared her face and her bloodline and her refusal to accept the terms of the previous era as the permanent terms of all eras, and she reached out and took it.\nThey rose together through the bronze water, through the layers, through the warmth and the cold and the warmth again, upward through twenty-seven metres of memory and history and everything the lake had been holding since before the first church bell rang in Agulu.\nThe surface received them both.','\n',char(10)),1585,1,1,NULL,'2026-04-21T20:37:08.982Z','2026-04-21 20:37:09','2026-04-21 20:37:09','2026-04-21T21:00:00.000Z',3,50);
INSERT INTO "chapters" ("id","novel_id","chapter_number","title","content","word_count","is_premium","is_published","audio_url","published_at","created_at","updated_at","scheduled_release_at","part_number","season_id") VALUES(611,72,10,'What the Lake Knows Now',replace('Three months after the covenant was renewed, the rainy season came early.\nNot the tentative early rains that arrived in March like a question, testing whether the dry season was truly finished. The full rains, generous and certain, arriving in the second week of March as if the sky had consulted something below and received confirmation that the ground was ready. The farmers along the northern road stood in their doorways and looked at it and said nothing for a while, the way people receive good news that arrived after they had stopped expecting it.\nThe lake rose to its proper level and stopped there. Not the crisis rising of the months before, the deliberate expansion of a body asserting its boundaries. The natural level, the one the oldest residents remembered from their childhoods, before decades of drought cycles and water table stress had gradually reduced it. It simply returned to what it had always been, quietly and without announcement, the way right things settled when the conditions for rightness were restored.\nThe fish came back fully in the fourth week.\nIkechukwu went out on a Tuesday and came back with his boat sitting lower in the water than it had in eleven years, and he pulled his traps up at the landing and stood looking at them for a long time without moving, and when Oby passed on her way from school he looked up at her with the face of a man who had several things to say and had decided that none of them were adequate.\nHe said nothing.\nShe said nothing.\nThey understood each other completely.\nNnedimma did not disappear when she surfaced.\nThis was the thing Oby had not anticipated, had not thought to ask Nnedimma about in all their hours of conversation at the lake bed, and which Nnedimma had not volunteered, perhaps because she had not known herself what release would look like after a hundred and twenty-eight years.\nWhat it looked like was this: she was present in the water. Not visible, not a figure standing in the shallows. Present the way a memory is present when the right thing calls it forward, in warmth, in the specific quality of the bronze light when it appeared, in the weight of knowledge that moved through Oby''s hands when she touched the surface.\nNot trapped. Not departed. Simply part of it now.\nThe lake had been holding the memory of everyone it loved since the original covenant. It held Nnedimma the same way, but differently. The others were held as record. Nnedimma was held as something closer to voice. When Oby sat at the waterline and pressed her palm to the surface and asked a question she could not answer alone, the response that came back had a quality she recognised.\nShe mentioned this to her mother one evening.\nHer mother looked at the water for a moment. "Is she well?"\nOby considered this. "I think she is more herself than she has been since 1897."\nHer mother nodded slowly, the nod of a woman who had learned to hold large things without requiring them to be smaller.\nThe heritage designation was gazetted in June.\nIhe nsọ. Sacred property. Agulu Lake restored to its original legal status in the official record, the 1897 Brentwood reclassification formally struck and annotated as a coerced colonial instrument. Arinze received the gazette notification at his house and called Oby and read her the precise legal language in full without abbreviating a word, and when he finished there was a silence on the line that was not emptiness but fullness, the silence of something that had been correctly resolved and did not require additional commentary.\nHe said, "Your great-great-great-grandmother would have known what this document means."\n"She does know," Oby said. "The lake told her."\nHe was quiet for another moment. "I am going to pretend I understood that."\n"That is fine," she said. "Thank you, Arinze. For everything."\nHe made a sound that was not quite acknowledgment and not quite deflection and was exactly the sound of a man who had spent his retirement building toward a case worth winning and had won it and did not know what to do with the feeling of that yet.\nTobenna came back in August.\nHis contract with the company had ended when the project collapsed, which he had anticipated, and he had spent the intervening months doing survey work with a firm in Enugu. He arrived at Oby''s compound on a Saturday with his hard hat no longer in his hands and a quietness about him that was different from the tight careful quietness of the man who had stood at her gate with information that could cost him something.\nThis was the quietness of someone who had paid the cost and found it was payable.\nThey sat in the compound and drank palm wine from a flask he had brought and talked about what was next. He was applying to study environmental geology. He wanted to understand what the instruments measured and what they missed.\n"That depth reading," he said. "The one our equipment got wrong. I keep thinking about that."\n"What about it?"\n"There is a whole category of things that instruments measure incorrectly," he said. "Not because the instruments are faulty. Because they are designed to measure what the people who built them decided was worth measuring." He looked at the lake in the distance. "And everything else just registers as noise."\nOby looked at him.\n"Study well," she said.\nOn the first of September she sat her examinations.\nShe sat them at the same desk she had always sat at, in the same hall, with the same invigilator who always fell asleep at the two-hour mark and woke with a start at the three-hour bell. She answered every question with the focused attention of a person who had learned over the preceding months that preparation and presence were the same skill applied to different surfaces.\nShe passed. Well. Not perfectly, which she had not expected. But with the solid confidence of a person who had been doing something genuinely difficult all year and whose mind had grown in the doing of it.\nAdaeze passed better, which Oby mentioned to her with complete sincerity. Adaeze received the compliment with the same sincerity and they walked home from the results board together through the afternoon heat, taking the long way past the lake, the way they always did now, not from obligation but from the simple fact that the lake was the most themselves either of them felt when they stood beside it.\nShe went to the waterline on the evening of her seventeenth birthday.\nHer mother had made ofe onugbu, the same pot she made every year, with cocoyam and enough for three days. They had eaten together at the table with the lamp on and Oby had felt the specific completeness of ordinary life fully inhabited, the joy of sitting across from your mother on your birthday with no emergency running underneath it.\nNow she sat at the northern bank alone in the blue dark.\nThe crocodile surfaced after a few minutes. Her crocodile, the large one, the ridge along its back silver in the moonlight. It floated near the bank and regarded her with those eyes that had stopped being remarkable because they had become simply how things were, the most honest gaze available in Agulu.\nShe pressed her palm to the water.\nThe warmth came up, steady and full, the covenant burning clean below her at twenty-seven metres, the seven stones complete and luminous and holding everything they had always held. The dark beneath them was still. The seal was whole.\nShe felt her mother''s presence in the upper connection, faint at this distance but present, the way the surface keeper''s anchor worked, always available, always held.\nShe felt Nnedimma in the water. Not speaking. Simply there. A warmth within the warmth, the quality of a person who has set down something very heavy and is learning, slowly and with great attention, what it feels like to have empty hands.\nThe lake was still around her and it was full, full of everything it had collected since before the first name was spoken beside it, full of every season and every person and every agreement kept and broken and repaired, full of the particular memory of a community that had almost lost itself and had turned back from the edge and would spend the rest of its long life deciding what to do with what it had almost done.\nIt knew all of this.\nIt had always known.\nNow it had a keeper who knew it too.\nThe crocodile blinked once, slow and deliberate, and submerged without a sound.\nOby sat at the edge of the water that was hers to protect, on the bank of the community that was hers to serve, under the sky of the country that was still learning what it owed its oldest things, and she was seventeen years old and completely, quietly, entirely herself.\nThe lake breathed around her.\nThe night held.\nAnd the water remembered.','\n',char(10)),1528,1,1,NULL,'2026-04-21T20:38:48.680Z','2026-04-21 20:38:48','2026-04-21 20:38:48','2026-04-21T21:00:00.000Z',3,50);
INSERT INTO "chapters" ("id","novel_id","chapter_number","title","content","word_count","is_premium","is_published","audio_url","published_at","created_at","updated_at","scheduled_release_at","part_number","season_id") VALUES(612,75,1,'The Car Nobody Could Read',replace('\nThe car rolled in on a Tuesday just after two, and the first thing Jideofor noticed was that nobody moved toward it.\nThat was unusual. Under Carter Bridge, every vehicle that entered the cluster was claimed within seconds. Someone calling out to the driver, someone already reaching for a rag, someone crouching to look at the tyres before the engine had stopped. Cars meant money. Money meant everything moved. But this car, a grey Volvo XC90 with European plates still on it and barely any dust on the bodywork, sat at the entrance while the whole workshop went still.\nUncle Okonkwo stepped out from under the Camry he''d been working on. He straightened slowly, wiped his hands on the side of his trousers, and walked toward the Volvo the way he walked toward things he respected: deliberately, without rushing.\nThe driver''s window came down. A man in a blue agbada, phone pressed to his ear, gestured impatiently without looking at Uncle Okonkwo.\n"Electrical," he said. "Everything has gone off. AC, dashboard, the whole thing. I am already late."\nUncle Okonkwo looked at the car for a moment. He opened the driver''s door, leaned in, turned the key. The dashboard lit, then flickered, then died in a pattern Jideofor had never seen before. Not a complete shutdown. A collapse and recovery, collapse and recovery, like the car was breathing wrong.\nJideofor set down the wire stripper he''d been holding and watched.\nUncle Okonkwo called Chukwuebuka first. Chukwuebuka had been doing auto electrical work since before Jideofor was born. He came, looked, tried three things in sequence, and shook his head. Then Uncle Okonkwo called Rasaki, who handled European cars and charged double. Rasaki sat in the driver''s seat for four full minutes, said something in Yoruba that Jideofor didn''t catch, and got out.\nThe driver was off his phone now. His impatience had changed shape. It was still impatience, but underneath it something close to worry had appeared.\n"What is the problem?" he asked.\n"We are checking," Uncle Okonkwo said.\nJideofor picked up his wire stripper again and went back to the Honda Civic he''d been rewiring. He kept his eyes down. He had learned early that curiosity in a workshop had to look like something else, or it became a liability. You watched by not watching. You listened by being quiet.\nWhat he was hearing was this: the car was running a CAN bus system. He knew this because the collapsing and recovering pattern on the dashboard was not a battery problem and not a simple relay fault. It was a communication failure. Somewhere in the network of microcontrollers the car used to make all its components talk to each other, something had gone silent. The other components were still trying to reach it. That was the flickering. That was the car not dying but asking.\nHe had read about CAN bus systems six months ago in a PDF someone had shared in a Telegram group for electrical engineering students. He had read it on Mr. Eze''s phone during a lunch break, standing by the water drum, eating rice with one hand and scrolling with the other.\nHe finished the Honda''s wiring, cleaned up his section, and waited.\nAt half past three, Uncle Okonkwo sat on an upturned paint bucket near the Volvo with the look on his face that meant he was calculating how to return money he had already spent in his mind.\nJideofor walked over.\n"Uncle."\n"Not now, Jide."\n"I think it''s the CAN bus."\nUncle Okonkwo looked at him.\nJideofor kept his voice level. "The way the dash is behaving. It is not losing power completely. The modules are losing each other. One node is down and the others are still polling. There should be a diagnostic port, the OBD socket, and if someone has a scanner that reads live CAN data we can locate the dead node directly."\n"Where did you learn this?"\n"I read it."\nHis uncle was quiet for a moment. Then: "Mr. Eze. Give Jide your phone."\nMr. Eze, who was patching a tyre nearby and had been pretending not to listen, handed over his phone without argument.\nJideofor found the PDF in forty seconds. He had bookmarked it without telling anyone. He pulled up the section on fault isolation, read the diagnostic sequence, and looked up.\n"I need the scanner. The German one in the back cabinet."\nNobody laughed. That was how he knew they were taking him seriously.\nIt took him just over twenty minutes. He found the fault in the body control module. A corrupted firmware update that the previous mechanic abroad had not completed. The module was stuck partway through the update, alive enough to cause damage, dead enough to do nothing useful. Jideofor documented what he found on a piece of brown paper, wrote out the fix in two steps, and handed it to his uncle.\nUncle Okonkwo read it twice. He looked at Jideofor. He looked at the car.\nHe didn''t say anything about being proud. He didn''t say anything about being surprised. He folded the paper, put it in his chest pocket, and went to speak to the driver.\nJideofor returned to the Honda.\nHis hands were steady. They were always steady. It was the thing inside his chest that had no name yet. Something had shifted slightly, something that had heard itself and recognized the sound, that he didn''t know what to do with.\nHe picked up the wire stripper and got back to work.','\n',char(10)),921,0,1,NULL,'2026-04-22 09:31:22','2026-04-22 07:34:27','2026-04-22 09:31:22',NULL,1,NULL);
INSERT INTO "chapters" ("id","novel_id","chapter_number","title","content","word_count","is_premium","is_published","audio_url","published_at","created_at","updated_at","scheduled_release_at","part_number","season_id") VALUES(613,75,2,'Who Did This?',replace('She came on Thursday.\nJideofor was inside the engine bay of a Toyota Hiace, tracing a short circuit through the ignition system, when he heard the workshop change. Not a sound exactly — more like the quality of the noise shifting, the way it does when someone enters a space who doesn''t belong to it.\nHe straightened and looked over the Hiace''s bonnet.\nThe Volvo was back, and this time the driver''s seat was empty. A woman stood beside it. She was wearing a plain dark blouse and trousers, reading glasses pushed up on her head, and she was looking around the workshop with the steady attention of someone conducting an assessment rather than a visit.\nUncle Okonkwo was at her side within moments, talking, gesturing toward the car. The woman nodded once, twice, then said something that made Uncle Okonkwo pause and look across the workshop.\nAt Jideofor.\nHe came out from behind the Hiace slowly, cleaning his hands on a rag. The woman watched him cross the floor. She did not smile in welcome or make her face available in any way. She just watched him arrive.\n"You are the one who found the fault," she said. It was not a question.\n"Yes, ma."\nShe looked at him for a moment. Not up and down — that would have been dismissive. She looked at his face, which was somehow more uncomfortable.\n"How old are you?"\n"Seventeen."\nShe glanced at Uncle Okonkwo briefly, then back. "Your uncle says you read about CAN bus systems on a phone."\n"Yes, ma. I found a PDF. Bosch technical manual, third edition."\n"You found it, or someone shared it with you?"\n"I found the group. The PDF was in the group."\nShe nodded slowly, like she was filing this information somewhere specific. "What school are you in?"\nJideofor felt Uncle Okonkwo''s presence at the edge of the conversation without looking at him. "Surulere Grammar. SS3."\n"You intend to finish?"\n"Yes, ma."\n"And after SS3?"\nThe question was neutral. Her voice gave him nothing — no warmth, no trap he could identify, just the question sitting there requiring an answer.\n"I''ll work here," he said. "Build the electrical side. My uncle wants to expand it."\nIt was not a lie. He had thought about it genuinely, had even sketched out in his head what a proper auto-electrical unit under the bridge would look like, what equipment it would need, what kind of jobs it could take. The sketch was real. It was just not the whole picture.\nThe woman looked at him.\n"That''s what you want," she said. "Or that''s what makes sense to say right now?"\nThe workshop noise continued around them — hammering from Chukwuebuka''s corner, a radio playing Afrobeats faintly from somewhere near the vulcanizers — but Jideofor had the sudden sensation of the space around him and this woman going quiet.\nHe opened his mouth.\nHe closed it.\nHe said: "It''s what I want."\nShe let that sit for three full seconds. Then she said: "The fault you found — explain it to me. Not what the manual said. What you understood."\nThis he could do. He walked her through it: the CAN bus network, the body control module, the incomplete firmware update creating a loop that disrupted communication across the system''s nodes. He used the correct terms without reaching for them — they came the way tools came when you''d handled them enough.\nShe listened without interrupting. When he finished, she said: "The previous mechanic who started that firmware update — what do you think happened?"\n"He probably didn''t know what he was doing. Or was interrupted and tried to recover it without the right equipment."\n"Or?"\nJideofor looked at her. "Or he knew exactly what he was doing and rushed it because someone was standing over him telling him to finish."\nSomething shifted in her face — not warmth, but recognition. The difference between a teacher finding what they expected and finding something better.\n"My name is Dr. Adaeze Obi," she said. "I teach in the Electrical Engineering department at UNILAG."\nJideofor said nothing. He wasn''t sure what he was supposed to say.\n"The car is my husband''s," she continued. "He brought it from Germany two years ago. The mechanic in Abuja who tried to update the module was, as you guessed, rushed." She paused. "Who taught you to read a system before you touch it?"\n"Nobody. I just — I don''t like to touch something I don''t understand."\n"Why not?"\n"Because a wrong touch in a wiring system doesn''t fix itself. It compounds."\nShe took off her glasses from her head and held them in one hand, looking at him.\n"I''m going to ask you something," Dr. Obi said. "And I want you to think before you answer."\nHe waited.\n"If someone offered you a full scholarship to study Electrical Engineering — starting next year, everything paid — would you take it?"\nThe hammering continued. The radio continued. Somewhere behind Jideofor, Mr. Eze was arguing with a customer about a bill. The bridge overhead held its permanent shadow over the whole compound, and through the gaps in the corrugated roofing the Lagos sky was its usual white.\nJideofor looked at this woman who had driven herself here on a Thursday morning to find out who had read a PDF and understood it.\nHe said: "Yes."\nThen he said: "No."\nThen he said nothing, because he had answered and both answers were true and he could not find the sentence that held them together.\nDr. Obi put her glasses back on her head.\n"Thursday next week," she said. "I''ll come back. Think about why you said both."\nShe turned and spoke briefly to Uncle Okonkwo, thanked him for the repair, and walked back to the Volvo.\nJideofor stood where she had left him.\nAbove the bridge, a danfo honked twice and the whole structure shuddered lightly, the way it always did, the way nobody who worked here noticed anymore.\nHe noticed today.','\n',char(10)),1004,0,1,NULL,'2026-04-22T07:36:34.306Z','2026-04-22 07:36:34','2026-04-22 07:36:34','2026-04-22T08:30:00.000Z',1,NULL);
INSERT INTO "chapters" ("id","novel_id","chapter_number","title","content","word_count","is_premium","is_published","audio_url","published_at","created_at","updated_at","scheduled_release_at","part_number","season_id") VALUES(614,75,3,'She Comes Back',replace('She arrived before the workshop was fully awake, when only Jideofor and Mr. Eze were present and the concrete pillars of the bridge still held the night''s coolness in them.\nJideofor was sorting cables by gauge on the workbench when he heard a car and looked up and saw the Volvo. He set down the cables. She parked at the same spot as Thursday and got out carrying nothing except her keys, which she dropped into her pocket without looking.\n"You thought about it," she said when she reached him. Also not a question.\n"Yes, ma."\n"And?"\nHe had spent six days turning the question over, setting it down, picking it back up. Yes and no had not resolved into anything cleaner. But he had found, somewhere in the middle of the week, what the yes and the no were each protecting.\n"The yes is for the knowledge," he said. "The no is because I don''t think you need a university to have it."\nDr. Obi looked at him steadily. "Explain that."\n"Everything I know about auto electrical, I learned here. Not in a classroom. The CAN bus fault — I found that in a PDF, not a textbook. The system works. I work."\n"You diagnosed one fault correctly," she said. "On one car. Using documentation written by engineers who spent four years in university before they were allowed near a design floor."\nJideofor said nothing.\n"The PDF you read," she continued. "Who wrote it?"\n"Bosch engineers."\n"Trained where?"\nHe understood what she was doing. He kept his voice even. "Trained in universities. But they also had workshop time. Practical time."\n"After the theory," Dr. Obi said. "Not instead of it."\n"Some of the best mechanics under this bridge have no certificates. They can hear a fault. They can feel it."\n"Yes. And they also have a ceiling." She said it without cruelty, which made it worse. "There is a class of problem they cannot solve because they do not have the mathematics for it. Not because they are not intelligent. Because intelligence without structure has a ceiling, Jideofor. You are going to hit it."\nHe felt something sharpen in him, not anger exactly, but its cleaner version.\n"You''re saying the workshop is a dead end."\n"I am saying it is a foundation that was built to hold one floor."\n"And university adds the other floors."\n"Yes."\n"But the foundation is mine," Jideofor said. "I built it. Nobody handed it to me. And you''re standing here telling me it can only hold so much, like the building on top is something separate from what''s below it." He paused. "It''s not separate. The floors and the foundation are the same building."\nDr. Obi tilted her head slightly.\n"So your position," she said, "is that formal training and what you have learned here are continuous. Not two different things."\n"Yes."\n"Then why do you behave as though choosing one means losing the other?"\nThe question landed differently from the others. He felt it find something in him and press.\n"Who said I''m behaving that way?"\n"You said yes and then no when I asked about the scholarship. That is not someone who sees continuity. That is someone who sees a wall."\nMr. Eze had arrived quietly at some point and was working near the far end of the bench, his back turned with the careful neutrality of a man who was absolutely listening.\nJideofor looked at the ground for a moment. The oil on the concrete had formed dark territories over years, one spill layered on another until the floor had its own geography. He had walked it so many times he no longer saw it. He saw it now.\n"I said both," he said, "because both are true. I want the knowledge a degree gives. I also don''t want to stand in front of my uncle and tell him everything he built here was not enough for me."\n"Those are not the same statement."\n"They feel the same."\n"Feelings are not arguments, Jideofor."\n"With respect, ma," he said, and he meant the respect, he was not using it as a blade, "feelings are the reason arguments matter at all. If I walk away from this workshop to go and study and my uncle watches me go and believes I think he wasted his life teaching me, then I have gained knowledge and I have broken something that cannot be fixed with a certificate. That is not a feeling. That is a consequence."\nDr. Obi was quiet for the first time since she had arrived.\nAbove them, the bridge carried its morning traffic. Lorries and buses vibrated through the concrete overhead and the vibration came down through the pillars in a low continuous hum that everyone under Carter Bridge had long since stopped hearing. It was the sound of the place existing. Of Lagos moving on top of them.\n"You are not wrong," she said finally.\nJideofor looked at her.\n"I did not say you were wrong," she repeated. "I said feelings are not arguments. I was testing whether you would abandon yours when pressed. You didn''t." Something in her face shifted, not warmth yet, but the space where warmth could eventually be. "That is the more important thing."\nHe did not know what to do with that so he did what he always did when the situation outpaced him.\nHe picked up the cables he had been sorting and asked: "Same time next Thursday, ma?"\nShe almost smiled.\n"I''ll come when I come," she said.','\n',char(10)),924,0,1,NULL,'2026-04-22T07:37:41.360Z','2026-04-22 07:37:41','2026-04-22 07:37:41','2026-04-22T08:30:00.000Z',1,NULL);
INSERT INTO "chapters" ("id","novel_id","chapter_number","title","content","word_count","is_premium","is_published","audio_url","published_at","created_at","updated_at","scheduled_release_at","part_number","season_id") VALUES(615,75,4,' What She Actually Said',replace('She had been gone four hours before Jideofor understood what she actually said.\nNot what he heard in the moment, which had felt like a verdict arriving in polite language. What she actually said, under the parts he had been busy defending against.\nHe was elbow deep in a Peugeot 406''s dashboard, chasing a wiring fault behind the instrument cluster, when the first piece of it came back to him clearly. Not feelings are not arguments. The line after it. I was testing whether you would abandon yours when pressed.\nHe stopped moving for a second.\nChukwuebuka noticed. "You find it?"\n"Not yet."\nHe went back to the wiring. His fingers found the harness connector and he began checking pins by feel, the way his uncle had taught him before he could name a single component. You learn the shape of a thing before you learn its name, Uncle Okonkwo always said. The name is just how you talk about it to someone else.\nThe Peugeot''s problem turned out to be a corroded ground connection behind the cluster, simple enough, embarrassingly simple for the amount of time it had been sitting. He cleaned the terminal, reconnected it, watched the instrument panel come back to full life. The driver, a thin man in a bus conductor''s uniform who had been sitting on a plastic chair since noon, stood up.\nJideofor cleaned his hands and let Chukwuebuka handle the payment.\nHe was thinking about the ceiling.\nThat was the part he had pushed against hardest, standing in front of her that morning. Intelligence without structure has a ceiling. He had felt it as an attack and answered it as one. But now, in the afternoon heat with the workshop noise around him and his hands still carrying the memory of that corroded ground terminal, he sat with it differently.\nHe thought about Sunday. Sunday was fifty, had been under Carter Bridge for twenty years, and could diagnose a fuel injection problem by sound alone. There was nobody faster with a Japanese car. But three months ago, a customer had brought in a Mercedes with an adaptive suspension fault, a new system, fully electronic, and Sunday had stood looking at it for an hour before quietly telling the customer to take it somewhere with a computer system. He had said it without embarrassment. He was a man who knew his edges.\nBut he had known his edges because he had reached them.\nJideofor had not reached his yet. That was the thing Dr. Obi had seen and said, and he had been too busy defending the workshop to hear it cleanly.\nShe was not saying the foundation was worthless. She had said it could hold one floor. One floor was not nothing. One floor was twenty years of Sunday''s livelihood, his uncle''s expanding reputation, the entire breathing economy of this space under the bridge. But one floor was also not the building she was pointing at when she spoke about design floors and mathematics and the class of problem that required more than feel.\nHe thought: she is right about that.\nThen he thought: but she was also not entirely right.\nHe walked to the back of the workshop where the spare parts were stored, not because he needed anything, but because he needed to move while he thought. He stood looking at shelves his uncle had built from old scaffold planks and angle iron, labeled in his uncle''s handwriting, each label written in the same careful capitals Uncle Okonkwo used for everything.\nDr. Obi had spoken about the university as though entering it was simple. As though the only thing standing between Jideofor and four years of Electrical Engineering at UNILAG was a decision. She had not asked about the cost. She had not asked about what Uncle Okonkwo had put into him since JS3, not as debt but as investment in a particular future. She had not asked about what it meant to leave a workshop that ran partly on his presence and come back to it four years later as something different.\nShe had said: feelings are not arguments.\nHe wanted to tell her: the things I am talking about are not feelings. They are logistics. They are what happens to real people in real time when a decision gets made. You can believe in continuity and still understand that a gap exists between this floor and the next one, and that someone pays for the scaffolding to cross it.\nBut he had not said that. He had talked about his uncle''s feelings, which had let her call it a feeling and move past it.\nThat was his mistake.\nHe had given her emotion when he had an actual argument. He had the argument now. It had taken four hours of workshop noise and a corroded ground terminal to find it, but it was here, it was solid, and it was not made of hurt.\nHe came back to the main floor. Rasaki was arguing with a customer near the entrance. Chukwuebuka was under a new car. Mr. Eze was eating rice from a takeaway pack, watching the argument with quiet enjoyment. The bridge sat over all of it, heavy with Lagos, leaking evening light through its gaps.\nShe had said she would come when she came.\nJideofor picked up the notepad he used for wiring diagrams and wrote one line at the bottom of a page already full of circuits.\nThe scaffolding. Who pays for it.\nHe closed the notepad.\nNext time, he would be ready.','\n',char(10)),927,1,1,NULL,'2026-04-22T07:38:55.876Z','2026-04-22 07:38:55','2026-04-22 07:38:55','2026-04-22T08:30:00.000Z',1,NULL);
INSERT INTO "chapters" ("id","novel_id","chapter_number","title","content","word_count","is_premium","is_published","audio_url","published_at","created_at","updated_at","scheduled_release_at","part_number","season_id") VALUES(616,75,5,'The Notebook',replace('Chukwuebuka found the bag on a Friday, which was the worst possible day because Friday afternoons under the bridge were slow and slow meant everyone was paying attention to everything.\nJideofor saw it happen from across the workshop. Chukwuebuka had gone behind the parts shelf looking for a fuse box and knocked over the old knapsack Jideofor kept there, and the bag fell open, and the JAMB practice booklet slid out across the concrete floor with its green cover facing up and the word MATHEMATICS printed on it large enough to read from where Jideofor was standing.\nHe crossed the workshop in eight steps.\n"That''s mine," he said, crouching to pick it up before Chukwuebuka had fully turned around.\nChukwuebuka looked at the booklet, then at him. "Mathematics?"\nJideofor held it loosely, without hiding it, the way you hold something that has no weight. "School assignment. SS3 project. We''re doing calculations for a wiring load project." He met Chukwuebuka''s eyes straight. "Mrs. Okafor likes us to show workings in a separate booklet."\nChukwuebuka''s face showed nothing particular. He was not a suspicious man by nature. "Okay," he said, found the fuse box he had come for, and went back to his car.\nJideofor put the booklet back into the bag and fastened the zip this time, both clasps, and returned to the alternator he had been testing.\nThe lie had been good. It had been so good it had come out before he decided to say it, fully formed, with a teacher''s name and a specific detail about showing workings, the kind of detail that made a lie feel like memory rather than invention. He had not stumbled. He had not looked away.\nThat was the thing he sat with for the rest of the afternoon.\nThe JAMB booklet was one of four. He had the Mathematics, the Physics, the Use of English, and the thin one on Current Affairs that he barely touched. He studied them in pieces, in the gaps the workshop allowed. During lunch if he could get to the back early. On Mr. Eze''s phone during slow periods, cross-referencing topics the booklets raised that he wanted to understand more fully. He had told nobody. He had meant to tell nobody until the JAMB form was submitted and the result was back and the thing was real enough to be a fact rather than a plan.\nBut the form was already submitted. The thing was already real.\nHe just had not updated the lie.\nHe thought about his uncle, who was out pricing generator parts in Ladipo today and would not be back until evening. Uncle Okonkwo moved through the workshop with an authority that did not come from being loud. He never needed to raise his voice. He knew where everything was and what it cost and what it could do, and he applied that knowledge with the quiet precision of a man who had built something and understood every part of what he had built.\nIncluding, Jideofor knew, every part of his nephew.\nOnce, in JSS2, Jideofor had told Uncle Okonkwo that he had finished oiling the generator when he had not. Not a serious lie, a lazy one. His uncle had gone to the generator, laid a hand on it, and said nothing. He had simply looked at Jideofor until Jideofor went and oiled it. That was all. But Jideofor had understood something that day about the cost of being known by someone — that when a person knows you completely, a lie is not just a lie. It is a small destruction of the thing between you.\nHe was not telling his uncle lazy lies now.\nHe was telling the workshop careful ones, and they were working, and that was its own kind of information.\nHe had written one line in his notepad this week: the scaffolding, who pays for it. He had been planning it as an argument for Dr. Obi, something to say when she came back. But the line had another meaning now, sitting in the same week as a lie that had come too easily.\nEverything had a cost and someone was always paying it. The question was whether the person paying knew they were.\nChukwuebuka knew nothing. Mr. Eze knew nothing. The workshop continued around Jideofor exactly as it always had, smelling of grease and hot metal and the exhaust that drifted in from the road, the radio playing, someone arguing cheerfully near the entrance, the bridge doing what the bridge always did.\nHe had protected the secret. The secret was safe because he was good at this now, because the lie had arrived already shaped, because he had apparently been practicing without noticing he was practicing.\nHe did not feel relieved.\nHe had expected to feel relieved. Instead there was something sitting in the centre of his chest that he did not have an exact word for. Not guilt, it was not guilt. Guilt came from doing something wrong and he was not sure he had done something wrong. It was more like the feeling of hearing a sound from a machine that the machine was not supposed to make. Not a breakdown. Just a new noise, and you did not yet know what it meant, but you knew you should not ignore it.\nHe filed it the way he filed things he did not yet understand.\nRasaki walked over to borrow his wire stripper and Jideofor handed it over.\n"Your head is somewhere," Rasaki said.\n"I''m calculating," Jideofor said.\nRasaki accepted this and walked away.\nAlso not a lie, Jideofor thought. Also not entirely the truth.\nThe two of them were starting to look the same, and he was not sure when that had happened.','\n',char(10)),959,1,1,NULL,'2026-04-22T07:40:06.963Z','2026-04-22 07:40:07','2026-04-22 07:40:07','2026-04-22T08:30:00.000Z',1,NULL);
INSERT INTO "chapters" ("id","novel_id","chapter_number","title","content","word_count","is_premium","is_published","audio_url","published_at","created_at","updated_at","scheduled_release_at","part_number","season_id") VALUES(617,75,6,'His Uncle''s Hands',replace('Uncle Okonkwo did not know he was being watched, or he knew and did not mind.\nIt was a Saturday, quiet by the workshop''s standards, the kind of afternoon when the serious customers had come and gone and what remained were a few lingering jobs and the particular stillness that settled over Carter Bridge when Lagos briefly stopped pressing. Jideofor had finished his last task an hour ago and had found a reason to stay close to his uncle''s bay rather than go home.\nUncle Okonkwo was rewiring a generator set. Old work, the kind that didn''t need concentration anymore, just patience. His hands moved through the harness with a slowness that was not uncertainty but precision of a different order, the way a man moves when he is no longer proving anything to anyone.\nJideofor watched the hands.\nThey were thick through the palm, his uncle''s hands, and the knuckles had the permanent darkness that no amount of washing fully removed, the record of thirty years of honest contact with machines. But what Jideofor was watching was not the history in them. It was the authority. The way his uncle''s left hand held a connector while the right located the corresponding socket without looking, the way he stripped wire to exactly the right length the first time, every time, without measuring.\n"You are counting something," Uncle Okonkwo said without looking up.\n"I''m just watching."\n"You watch the way you count." He separated two wires and compared them to the diagram on the bench beside him. "What is the question?"\nJideofor considered. "Where did you learn to work like that? The way your hands know before you look."\nHis uncle was quiet for a moment. He seated a connector, checked it with a light pull, moved to the next one. "Your grandfather," he said. "Not here. We did not have a workshop. We had a yard behind the house in Nnewi and whatever broke in the neighborhood came to that yard." He paused. "Generators mostly. Some vehicles. Your grandfather could not read the manuals but he could take a thing apart and reassemble it and find the problem in the taking apart. He said a machine tells you everything when it is open. You only have to be quiet enough to listen."\n"You learned that from him."\n"I learned the work from him. The manuals I learned myself." His uncle glanced up briefly. "He thought manuals were for people who did not trust their hands. I thought hands without manuals were for people who did not trust their eyes." He returned to the wiring. "We argued about it for years."\nJideofor looked at a spot on the bench where the wood had been worn smooth by decades of elbows and tools. "Who was right?"\n"We were both right in different directions. A hand that has never read a manual reaches its edge faster. A manual that has never been held by a working hand stays flat on paper." His uncle set down the wire he was holding and picked up a small screwdriver with the casual certainty of a man reaching for something he knows will be exactly where he put it. "What your grandfather gave me was the beginning. What I added was the next part. That is how it works. Each generation adds the next part."\n"And you think I''ll add the next part."\n"I know you will." No hesitation. Not a compliment either, just a statement of understood fact. "You already have. The CAN bus business. I had not heard of it. Now I have." He tightened a terminal. "That is how it works."\nAbove them, the underside of Carter Bridge was mapped with water stains and old paint and the marks left by cables that had been run and rerouted over many years, the whole ceiling of the workshop a kind of record of every problem that had ever been solved here. Jideofor had never looked at it properly before. He looked at it now.\n"What if the next part," he said carefully, "was something bigger than you expected?"\nUncle Okonkwo did not answer immediately. He finished the terminal, tested the connection, sat back slightly on his stool.\n"My father expected me to repair small appliances," he said. "Fans, pressing irons. He thought cars were too complicated for someone who did not grow up near them." He picked up the diagram and studied it. "I disappointed his expectations. He died proud of me." He set the diagram down. "What he expected and what made him proud were not the same thing."\nThe generator''s rewired section gleamed faintly in the low Saturday light. Outside, a bus conductor''s whistle sounded twice, sharp and distant, and then traffic swallowed it.\nJideofor looked at his uncle''s hands resting on the bench.\nThirty years of work in them. The beginning his grandfather had given, the next part his uncle had added, and underneath this conversation, like a wire running through a wall, the part that had not yet been named.\n"Uncle," he said.\n"Go home, Jide," his uncle said, not unkindly. "Come back with your full head tomorrow."\nJideofor stood, picked up his bag, and walked out into the late afternoon light, and behind him the sound of his uncle returning to the generator followed him all the way to the road.','\n',char(10)),891,1,1,NULL,'2026-04-22T07:41:31.878Z','2026-04-22 07:41:31','2026-04-22 07:41:31','2026-04-22T08:30:00.000Z',1,NULL);
INSERT INTO "chapters" ("id","novel_id","chapter_number","title","content","word_count","is_premium","is_published","audio_url","published_at","created_at","updated_at","scheduled_release_at","part_number","season_id") VALUES(618,75,7,' The Registration',replace('The JAMB registration center on Broad Street smelled like generator exhaust and printer ink and the specific anxiety of people making decisions they could not unmake.\nJideofor took a number and sat on a plastic chair against the wall and looked at the room. Forty, maybe fifty people. Mostly his age, mostly in school uniforms still carrying the morning''s sweat, a few older candidates who had the focused quiet of people attempting something for the second or third time. Two harassed women behind a counter managed three queues simultaneously, calling numbers in a voice that had given up on warmth hours ago.\nHe had told his uncle he was going to price inverter batteries in the Mile 2 market.\nHe sat with that for a moment, then put it down. There would be a time for the truth. This was not it, and he had decided that clearly, and he would not spend the next two hours quietly punishing himself for a decision he had already made.\nHis number was called forty minutes later. The woman at the counter had a blue headwrap and reading glasses on a cord around her neck and she handled his documents with the speed of someone who had looked at ten thousand sets of documents and found them all broadly identical.\n"Course?" she said without looking up.\n"Electrical Engineering."\n"Institution?"\n"UNILAG. First choice. FUTA second."\nShe typed. Her nails were very long and she typed with the sides of her fingers, an adjustment so practiced it had become its own technique. Jideofor found himself watching it with professional attention, the way he watched any adaptation a person had made to do work efficiently.\n"Date of birth?"\nHe gave it. She typed. She asked three more questions and he answered them and then she turned the screen toward him and said "Confirm your details" and he read through everything slowly even though everything was correct because this was not a moment for speed.\nHis name. His school. Electrical Engineering. UNILAG.\nHe pressed confirm.\nThe printer beside her produced a slip. She handed it across with the automatic efficiency of a woman who had handed across ten thousand slips.\n"Keep that," she said, already looking past him.\nHe kept it.\nHe stood outside the building on Broad Street with the confirmation slip folded once and held in both hands, and Lagos did what Lagos always did, which was continue entirely without reference to him. A yellow bus discharged passengers at the corner. A woman sold cold water from a polystyrene cooler, calling out in a voice designed to carry over traffic. Two men argued over a parking space with the cheerful aggression of people who did not actually intend for the argument to go anywhere serious.\nThe something that settled was this: the decision had a reference number now. It existed in a government database. Whatever happened next, this moment had occurred, was recorded, could not be untaken. He had wanted to study Electrical Engineering since SS1 when his physics teacher had explained how a transformer worked and Jideofor had looked at the diagram and felt the clean satisfaction of a system that obeyed itself completely, input and output in permanent honest relation. That want was now a document. It had weight.\nHe stood with that for a moment and let it be what it was.\nThe something that did not settle was harder to locate.\nHe walked toward the bus stop, slip in his bag now, hands free. Broad Street ran down toward the water and if you stood at the right angle you could see a strip of the lagoon between buildings, flat and bright under the afternoon sun, and he stood at that angle for a moment and looked at it.\nHe thought about Rasaki. Rasaki had been under Carter Bridge for eleven years and had built a reputation for European cars that brought customers from Ikoyi and Victoria Island, serious money, repeat money. Rasaki had once told Jideofor that the secret was simple: you showed up every day and you got better every day and eventually people heard your name before they saw your face. That was it. That was the whole system.\nJideofor did not think Rasaki was wrong.\nHe also thought about the woman at the counter and her adapted typing technique, the long nails requiring a completely rebuilt relationship with the keyboard, and how she had done it so long it no longer looked like adaptation, it looked like method.\nHe was not choosing between the workshop and a degree.\nHe was adding a floor, the way his uncle had said each generation added a floor, except he had not said this to his uncle yet, had not shown his uncle the confirmation slip, had not said the name of the course or the institution out loud to anyone who mattered.\nThe decision was real and documented and it was also still entirely secret, which meant it was real in the way a foundation was real when there was nothing yet built on top of it. You could not see it. You had to know it was there.\nA danfo slowed beside him, the conductor leaning out with a destination he didn''t need.\n"Mile 2," Jideofor said.\nHe got in.\nHe had inverter batteries to price, and after that he had a workshop to return to, and in his bag was a slip of paper that changed everything and currently changed nothing, and he looked out the window at the city moving past and felt both of those things sitting in him at the same distance, neither one closer than the other.','\n',char(10)),943,1,1,NULL,'2026-04-22T07:43:15.225Z','2026-04-22 07:43:15','2026-04-22 07:43:15','2026-04-22T08:30:00.000Z',1,NULL);
INSERT INTO "chapters" ("id","novel_id","chapter_number","title","content","word_count","is_premium","is_published","audio_url","published_at","created_at","updated_at","scheduled_release_at","part_number","season_id") VALUES(619,75,8,'Under the Bridge Talks',replace('Rasaki started it, which surprised nobody, because Rasaki''s other skill beside European cars was information.\nHe had heard it from the driver of the Volvo, who had heard it from the owner herself, apparently, and what he reported to the workshop on Monday morning was this: the woman who owned the car was a lecturer at UNILAG, she had come back twice specifically to speak to Jideofor, and she had told her husband that the boy under the bridge understood the CAN bus fault better than the Abuja mechanic who had caused it.\nJideofor was not present for this report. He was at the back of the workshop replacing a starter motor and he heard it through the open partition the way he heard most things, at a distance that gave him time to arrange his face.\nWhat followed was not a single reaction. It was the workshop processing something through all its different parts simultaneously, and each part had its own response.\nSunday, who had been coiling cable near the entrance, came and stood in the doorway of Jideofor''s section. Sunday was a compact man who communicated mostly through proximity, and his standing there meant he had something to say that he was deciding whether to say.\n"The UNILAG woman," he said finally. "She is coming back?"\n"She said she would come when she came."\nSunday nodded slowly. He was quiet for a moment, watching Jideofor''s hands on the starter motor. "When I was your age," he said, "a man from NNPC came to look at my father''s generator repair work. My father sent me away before the man arrived." He paused. "He thought I would say something that complicated the conversation." He picked up the cable he had set down. "Your uncle did not send you away."\nHe went back to his coiling without explaining what he meant by that, and Jideofor turned it over while he worked.\nChukwuebuka''s reaction was different. He came at midday, during the lunch pause, when most of the workshop was eating or resting, and he sat on the empty bench beside Jideofor''s section with the deliberate posture of a man who had been thinking about something and had arrived at a position.\n"These UNILAG people," he said. "They like to find somebody and make them a project." He said it without malice, but without warmth either. "I have seen it. They come, they are interested, they talk. Then the semester starts and they are gone and the person they found is standing there with big ideas and an empty hand."\nJideofor looked at him. In two years of working alongside Chukwuebuka he had learned that the man''s skepticism was not laziness. It had a history he did not discuss but which showed occasionally, like this, in the specific shape of a warning.\n"You know someone it happened to," Jideofor said.\nChukwuebuka ate his rice. "My brother. Different situation. But the pattern is the same." He stood, took his food, looked at Jideofor once more. "I am not saying don''t listen to her. I am saying know the difference between someone who finds you interesting and someone who is actually useful to you. They are not always the same person."\nHe left.\nThe afternoon brought Mr. Eze, who handled it the way Mr. Eze handled everything significant, by pretending it was funny. He walked past Jideofor twice making a gesture of touching a cap he wasn''t wearing, a mock salute, before Jideofor told him to stop and he stopped, but he was still grinning while he stopped, which meant he was proud and didn''t know how to say that without it costing him something.\nRasaki himself said nothing directly to Jideofor. But Jideofor noticed that Rasaki had moved his stool to face the workshop differently, and twice during the afternoon Jideofor looked up and found Rasaki watching him with an expression he had not seen on Rasaki''s face before. Not jealousy, not quite. Something more like recalculation. The way a man looks when he has held a particular map of a place for a long time and has just been shown a feature on it he did not know was there.\nUncle Okonkwo said nothing at all about any of it.\nHe moved through the day exactly as he always moved through it, checking work, pricing a job, spending forty minutes on a phone call about a generator contract that could bring serious money before the rains came. If he had heard Rasaki''s report, and he must have heard it, he gave it no surface that Jideofor could read.\nAt four o''clock, Jideofor was cleaning up his section. The afternoon light was coming through the gaps in the roofing at a low angle that turned the oil on the floor into something almost iridescent, colors that had no business being that beautiful in a workshop. He had never noticed it at this hour. It happened every day at this hour and he had simply always been too occupied to see it.\nHe thought about what Chukwuebuka had said. Interesting versus useful. He thought about Sunday''s father sending him away. He thought about Rasaki''s recalculating eyes.\nEach of them had handed him something. None of it was the same thing. The workshop had more opinions about his life than he had understood, and most of those opinions had been sitting quietly in the bodies of the men around him, waiting for a reason to surface.\nThe UNILAG woman had given them a reason.\nHe picked up his bag and checked that the zip was fastened, both clasps.','\n',char(10)),933,1,1,NULL,'2026-04-22T07:44:28.757Z','2026-04-22 07:44:28','2026-04-22 07:44:28','2026-04-22T08:30:00.000Z',1,NULL);
INSERT INTO "chapters" ("id","novel_id","chapter_number","title","content","word_count","is_premium","is_published","audio_url","published_at","created_at","updated_at","scheduled_release_at","part_number","season_id") VALUES(620,75,9,' The Uncle Finds Out',replace('It was not Chukwuebuka. It was not Rasaki, or Mr. Eze, or anyone in the workshop.\nIt was the confirmation slip, which Jideofor had moved from his bag to the inside cover of his Physics practice booklet, and which fell out on a Wednesday evening when Uncle Okonkwo picked up the booklet from the kitchen table because he wanted to see what his nephew was studying.\nJideofor was in the bathroom. He heard nothing. He came out toweling his face and his uncle was sitting at the table with the slip open in front of him, reading glasses on, and the quality of his stillness was different from his ordinary stillness. His ordinary stillness was a working stillness, a man at rest between efforts. This was the stillness of someone who had stopped completely.\nJideofor sat down across from him.\nUncle Okonkwo read the slip once more, though he had clearly already read it. Then he folded it along the original crease and set it on the table between them and took off his glasses and looked at his nephew.\n"Electrical Engineering," he said.\n"Yes, Uncle."\n"UNILAG."\n"Yes."\nHis uncle looked at the slip rather than at him for a moment. The kitchen was small and the evening light through the window was the pale orange that came just before it failed entirely, and the generator from the compound next door was running, its sound filling the silence between sentences the way it always did.\n"When did you submit this?"\n"Three weeks ago."\nHis uncle nodded once. Not in acceptance. In the way a person nods when they are cataloguing information, placing it in sequence, understanding the shape of what has been withheld and for how long.\n"The JAMB booklets," his uncle said. "In the bag behind the parts shelf."\nJideofor felt the floor shift slightly under him. "You knew."\n"I have been in that workshop for thirty years. I know what is in it." He paused. "I wanted to see if you would tell me."\nThe generator next door coughed once and recovered. Somewhere in the compound a child was being called inside for dinner, the mother''s voice patient, then less patient, then patient again.\n"I was going to tell you," Jideofor said.\n"When the result came?"\n"Yes."\n"So that it would already be a fact."\nIt was not a question and Jideofor did not answer it as one. He looked at his uncle''s hands flat on the table, either side of the folded slip, and he understood that he had been calculating even this moment, placing the truth at the point where it would have the least power to be stopped. He had not fully admitted that to himself until now.\nHis uncle was quiet for a long time.\n"You told me you wanted the workshop," he said finally.\n"I do want it."\n"And this." He touched the slip lightly, one finger.\n"And this."\nUncle Okonkwo stood and went to the window. He stood with his back to the room, looking out at the compound where the last of the light was going. His hands were in his pockets. He was not a man who put his hands in his pockets often, and the gesture made him look briefly like someone younger, like a man still deciding something about his life rather than a man who had long since decided.\n"Your father," he said to the window. "You know he wanted to study."\nJideofor had not known this. He said nothing.\n"Architecture. He had the ability for it. He could draw anything he looked at, exactly as it was." His uncle paused. "He did not have the money, and I was still building the workshop, and our mother was sick that year. He stayed. He helped. By the time things were better he had a family." He turned from the window. "He never said he regretted it. But I knew. A man who has put something down always knows where he put it, even when he stops going back to look."\nJideofor felt something move in his chest, slow and heavy.\n"I am not stopping you," Uncle Okonkwo said. His voice was level and it cost him something to keep it level and they both knew that. "I want to be clear about that. I am not stopping you."\n"Uncle."\n"Let me finish." He came back to the table but did not sit. "What I am is not stopping you. What I also am is a man who has spent four years teaching you this work, who has told his customers his nephew will take the electrical side, who has made plans that had your name in them." He looked at his nephew steadily. "I am allowed to be sitting with that tonight. I am not angry at you. I am allowed to be sitting with it."\nJideofor looked at his uncle and saw all three things clearly, the anger that was not quite anger, the pride that had no clean way to arrive, and underneath both of them something older and more private that had to do with a brother who could draw anything he saw and had put that down and not gone back to look at it.\n"I should have told you earlier," Jideofor said.\nHis uncle picked up the slip and held it out. "Keep this somewhere it will not fall out."\nJideofor took it.\nHis uncle went to the kitchen counter, filled a glass of water, and drank it standing up.\n"Come early tomorrow," he said. "Sunday is out and we have three jobs."\n"Yes, Uncle."\nThe light outside was gone now. The generator ran on. His uncle set the glass down and left the kitchen and Jideofor sat at the table with the confirmation slip in his hand and the full weight of being known by someone resting on him like a second skin.','\n',char(10)),982,1,1,NULL,'2026-04-22T07:45:33.203Z','2026-04-22 07:45:33','2026-04-22 07:45:33','2026-04-22T08:30:00.000Z',1,NULL);
INSERT INTO "chapters" ("id","novel_id","chapter_number","title","content","word_count","is_premium","is_published","audio_url","published_at","created_at","updated_at","scheduled_release_at","part_number","season_id") VALUES(621,75,10,'The Real Argument',replace('It started over a customer, which was not what it was about.\nThe customer was a man named Biodun who brought his Lexus in on Friday and asked specifically for Jideofor, because word had continued to travel since the Volvo, and Jideofor had handled two of Biodun''s previous visits and done the work cleanly. Biodun was the kind of customer the workshop needed more of, Ikoyi address, European cars, willing to pay correctly if the work was correct.\nUncle Okonkwo told Biodun that Jideofor would not always be available.\nHe said it pleasantly, in the middle of writing up the job. Biodun had already moved away toward his car and probably did not hear the full weight of it. Jideofor, standing at his bench with a terminal crimper in his hand, heard every word.\nHe waited until Biodun left.\n"What does that mean," he said. Not loudly.\nHis uncle was already walking toward the Lexus. "It means what it says. He should not build a habit on one person."\n"You said it like I was leaving next week."\nUncle Okonkwo opened the Lexus door and leaned in to check the dashboard. "You are in SS3. JAMB results come out. Then what? You are here until September at least. Maybe longer if admission takes time." He straightened. "I said it because it is true, not to make a point."\n"It felt like a point."\nHis uncle looked at him then, fully, the way he looked at a wiring fault he had decided to stop ignoring.\n"Come," he said.\nThey went to the back office, which was not really an office, just a section of the workshop partitioned by a half-wall where Uncle Okonkwo kept the ledger and the safe and a chair nobody else sat in. His uncle sat. Jideofor stood.\n"Say what you want to say," his uncle said.\n"I want to know if you''re angry."\n"I told you I am not angry."\n"You told me you were sitting with it. That was four days ago. I want to know where you have landed."\nHis uncle was quiet for a moment. Outside, Rasaki''s radio was playing and someone was testing an engine in short revs. The workshop sounds came through the partition wall in full, and standing in this small space with them all around felt to Jideofor like standing inside the workshop''s chest.\n"I have landed," his uncle said carefully, "on the question of what you think this place is."\n"I think it is where I learned everything I know."\n"And what else?"\nJideofor looked at him. "Say what you mean, Uncle."\n"I think you see this place as the thing you are leaving behind. Even if you do not say that. Even if you believe the other version. When you walk into that UNILAG gate in September, this," he gestured at the walls around them, "becomes the thing you came from. Not the thing you are going to. And I want to know if you understand what that means for the people who are staying."\nThe words landed and Jideofor felt them and did not step back from them.\n"With respect," he said, "that is your fear telling you a story about my intention."\nHis uncle''s eyes sharpened.\n"I have never once thought of this workshop as something to leave behind. I think of it as the first floor of a building. You said it yourself, each generation adds the next floor. I am adding a floor. That is not leaving. That is building on top of what you gave me." He paused. "But you are treating it like I am pulling the foundation out."\n"I am treating it," his uncle said, and his voice had the controlled heat of a man choosing his words from a much larger fire, "like someone who made plans with my name in them found out through a piece of paper falling out of a book. Not a conversation. A piece of paper."\nJideofor felt that land too.\n"You are right about that," he said.\n"I know I am."\n"I should have told you when I submitted the form. I did not because I was afraid that the plan would stop being a plan if it was spoken. I was protecting it."\n"From me."\n"From the conversation. From the moment becoming bigger than I could handle." He looked at his uncle directly. "Not from you. I do not think of you as someone trying to stop me. I think of you as someone who has given me everything and whom I do not want to disappoint. Those are not the same thing, but they feel the same at four in the morning."\nSomething shifted in the room.\nHis uncle leaned forward, elbows on his knees, and looked at the floor the way a man looks at something only he can see. The controlled heat in his voice had changed to something slower, something that had been waiting longer.\n"Your father could draw anything," he said. "I told you that."\n"Yes."\n"What I did not tell you is that I asked him to stay. I told him the workshop needed him, that our mother needed him, that there would be another time." He looked up. "There was not another time. And I have carried that every day I have stood in this workshop, because I built something real and I built it on a thing I should not have asked him to put down." His voice was steady and it was the steadiest and most difficult thing Jideofor had ever heard him say. "I am not doing that to you. I want to be very clear. I am not asking you to stay."\n"Uncle."\n"What I am asking," he said, "is that you do not make me invisible while you go. That you do not decide that what we have here is the story of how you almost got stuck. Because it is not that story. It is the story of how you learned to work. And those are not the same building."\nJideofor stood in the partition office with the workshop sounds around him and his uncle''s face in front of him and the theme of the last four months arriving not as a lesson but as a collision, and what he understood in that collision was this: ambition had never been the problem. Silence had been the problem. He had protected the dream so carefully he had nearly made his uncle a stranger to it.\n"It is the same building," Jideofor said quietly. "I promise you it is the same building."\nHis uncle stood. He picked up the ledger and held it in one hand and looked at his nephew for a long moment with all three things still present in his face, but arranged differently now, the anger gone smallest, the pride gone largest, and the old private grief about his brother sitting where it had always sat, not healed but acknowledged, which was the closest some things ever got.\n"The Lexus," he said. "Electrical fault on the rear sensors. Go and look at it."\nJideofor went.','\n',char(10)),1187,1,1,NULL,'2026-04-22T07:46:22.530Z','2026-04-22 07:46:22','2026-04-22 07:46:22','2026-04-22T08:30:00.000Z',1,NULL);
INSERT INTO "chapters" ("id","novel_id","chapter_number","title","content","word_count","is_premium","is_published","audio_url","published_at","created_at","updated_at","scheduled_release_at","part_number","season_id") VALUES(622,75,11,'Carter Bridge, 6 A.M.',replace('He was there before the gate was unlocked, which meant he was there before Mallam Sule, who had opened the compound gate every morning for eleven years and had never once found anyone waiting on the other side of it.\nMallam Sule looked at him with the mild suspicion of a man whose routine has been interrupted. "Your uncle is not here yet."\n"I know," Jideofor said. "I have the spare key."\nHe let himself into the workshop and did not turn on the overhead light. The fluorescent strip took three pulls to start and this morning he did not want the work interrupted by the pulling. He used the work lamp clipped to his bench, a single directed beam, and in that beam he set down the things he had carried from home in the old knapsack: a ruler, two pens, the wiring load calculation notebook, and the folder he had assembled last night at the kitchen table while his uncle slept.\nThe folder was not impressive to look at. It was a manila envelope with a clip, the kind used for school submissions. Inside it were six pages in his own handwriting.\nHe had been building the document in his head since SS2, adding to it the way you add to something you cannot yet show anyone. The proper auto-electrical unit he had sketched mentally a hundred times: what equipment it needed, what the bench configuration should be, which categories of job the workshop was currently turning away because it lacked the diagnostic range to handle them. Computers. Software licenses. A second oscilloscope. A trained second hand who could manage the bay while Jideofor was at lectures.\nHe had written it out last night in full, costed it roughly, and organized it in the sequence his uncle used for all serious proposals: problem, solution, what it needs, what it returns. He had used Uncle Okonkwo''s own format because it was his uncle''s workshop and his uncle''s language, and he was not presenting a foreign idea. He was presenting the next floor in the vocabulary of the man who had built the one beneath it.\nHe spent the first hour checking the work. He found two calculation errors in the equipment costing and corrected them. He rewrote one section that had read like an argument and should have read like information. At half past six the rest of Carter Bridge began to wake around him, the vulcanizers arriving first as always, then the panel beaters, and the compound filling gradually with the sounds of a working day assembling itself.\nHe was replacing a cracked terminal block on a Kia when he heard his uncle''s car.\nUncle Okonkwo came through the workshop gate with his keys in one hand and stopped when he saw the lamp on and Jideofor at the bench.\n"You slept here?"\n"I came early." Jideofor set down the terminal block. "I have something for you."\nHe picked up the manila folder and held it out.\nHis uncle took it, looked at the front, looked at Jideofor. He opened the clip and read the first page standing. Then he pulled up the spare stool and read the rest sitting down.\nHe was a slow and thorough reader and he read the way he did everything, without rushing, without performing reaction. Jideofor went back to the Kia and replaced the terminal block and did not watch his uncle''s face.\nHe heard pages turning. He heard his uncle go back to a page, then forward again. He heard the stool shift.\n"The oscilloscope," his uncle said.\n"Second hand. There is a dealer in Alaba. Reliable stock."\n"The software license. This is annual?"\n"Yes. But it covers unlimited vehicles for the license period. The cost per job comes down after the sixth car."\nHis uncle read again. The workshop was filling properly now, Rasaki arriving, Mr. Eze greeting someone at the gate, the radio going on somewhere in the middle distance.\n"The second hand you mention," Uncle Okonkwo said. "You have someone in mind?"\n"Sunday''s nephew is finishing his auto-electrical apprenticeship in Apapa in March. Sunday says he is serious."\nHis uncle turned back to the first page. He was looking at the heading Jideofor had written at the top: Okonkwo Auto-Electrical Unit, Proposed Expansion. His uncle''s name at the top. Not Jideofor''s.\nUncle Okonkwo closed the folder.\nHe held it with both hands and looked at the compound, the morning light now fully arrived, the bridge overhead carrying its first serious traffic, the whole ecosystem of the place doing what it always did, which was work.\nHe stood, tucked the folder under his arm, and looked at his nephew.\nHe did not say that it was good work. He did not say that it was exactly what he had been thinking. He did not say that the heading with his name on it had done something to him that he was not going to discuss in the middle of the workshop at six forty-five in the morning with Rasaki within earshot.\nWhat he said was: "The Kia needs a full electrical check after the terminal. Don''t just do the presenting fault."\n"I know," Jideofor said.\nHis uncle walked to his bay.\nJideofor turned back to the Kia and saw that his hands were steady, as they always were, and that the thing inside his chest that had shifted in Episode 1 when he first heard himself and recognized the sound had shifted again, further this time, into something that had a shape now.\nNot resolved. Not finished. But committed, the way a foundation was committed once the concrete had set. The building would still have to be built. That was the work ahead.\nHe picked up his diagnostic scanner and got started.','\n',char(10)),963,1,1,NULL,'2026-04-22T07:47:21.443Z','2026-04-22 07:47:21','2026-04-22 07:47:21','2026-04-22T08:30:00.000Z',1,NULL);
INSERT INTO "chapters" ("id","novel_id","chapter_number","title","content","word_count","is_premium","is_published","audio_url","published_at","created_at","updated_at","scheduled_release_at","part_number","season_id") VALUES(623,75,12,' Both Hands',replace('The alarm went off at five and Jideofor was already awake.\nHe had been awake since four, not from anxiety exactly, but from the particular alertness of a body that understands something significant is about to happen and has decided sleep is no longer the point. He lay on his back looking at the ceiling until the alarm confirmed what he already knew, then he turned it off and got up.\nHe dressed in the dark. School uniform was wrong for today so he wore the plain white shirt his uncle had bought him for his aunt''s burial three years ago, the one that still fit, and dark trousers and his good shoes. He looked at himself in the small mirror above the sink and saw someone who was going somewhere and was dressed accordingly.\nHis uncle was in the kitchen.\nThis was unexpected. It was five twenty and Uncle Okonkwo was sitting at the table with tea, fully dressed, not in workshop clothes but in the ankara shirt he wore for serious occasions. He had not mentioned doing this. He had said nothing yesterday evening beyond the ordinary things, the ordinary goodnights.\nHe pushed a covered plate across the table without speaking.\nJideofor sat and ate. Fried eggs and bread, which his uncle almost never cooked. They ate without conversation and the silence was not uncomfortable. It was the silence of two people who had already said the important things and were now simply present with each other before the day took its course.\nAt five fifty his uncle said: "Your calculator."\n"In the bag."\n"Spare pencils."\n"Yes."\n"The center is Yaba. You know the road."\n"I know the road."\nHis uncle drank the last of his tea and set the cup down. He looked at his nephew across the small kitchen table and Jideofor looked back at him.\n"Go and do it well," Uncle Okonkwo said.\nJideofor picked up his bag and went.\nThe road to Yaba at six in the morning had its own character, different from the road at any other hour. The buses were filling but not yet full. The sellers were arranging but not yet calling. Lagos in the act of becoming itself, not yet arrived at the full noise of the day. He stood in it and felt it around him and thought about nothing in particular, which was its own kind of preparation.\nThe examination center was a secondary school on a side street, its gate already open, a registration desk staffed by two JAMB officials with lanyards and printed candidate lists. He joined the queue. Around him were other candidates, some talking in pairs, some quiet, some performing a confidence that was doing visible work to hold itself together. He recognized the type. He had been that type for months.\nHe was not that type this morning.\nHis name was on the list. He was directed to Hall C. He found his seat, a desk near the window with a view of the school''s open compound, a neem tree at the center of it, its branches wide and unhurried, unbothered by the morning''s business.\nHe placed his calculator and pencils on the desk and waited.\nWhen the papers came he read the first Mathematics question and felt the same thing he felt when a wiring diagram resolved into sense: the system was knowable, the path was findable, the work was simply work. He picked up his pencil.\nHe thought briefly of the Bosch PDF on Mr. Eze''s phone. He thought of the corroded ground terminal in the Peugeot 406, the instruments coming back to life. He thought of his uncle''s hands moving through a wiring harness at a slowness that was not uncertainty but a different kind of precision. He thought of the manila folder with his uncle''s name at the top, now sitting in the safe behind the half-wall partition, costed and organized and waiting for the building to catch up with it.\nHe thought of his father, who could draw anything he looked at and had put that down and not gone back.\nHe was not putting anything down.\nHe wrote the first answer and moved to the second.\nTwo hours and forty minutes later he walked out of Hall C into the compound, the neem tree still there, still unbothered, the morning now fully itself. He stood in the compound and took stock: Mathematics had gone well. Physics had gone well. The English paper had asked him to write a composition about ambition, which had felt for a moment like the examination was being operated by someone with a specific sense of humor.\nHe had written the truth. Not the version he would have written in SS1, which would have been about success and achievement, the words that teenagers use when they have not yet felt the actual weight of wanting something. He had written about a workshop under a bridge and a man whose hands knew things before his brain caught up, and about how the desire to learn more was not a verdict on what had already been learned. How a foundation and the floors above it were the same building. How the word ambition, when people used it against you, usually meant they were afraid you were leaving, and how the answer to that fear was not to go quietly but to take the whole place with you when you went, the smell of it, the sound of it, the specific knowledge of what it meant to make something work with your hands and your mind together.\nHe did not know if the examiner would understand it. He had written it anyway.\nHe sent his uncle one message: Done. Coming to the workshop.\nThree minutes later his uncle replied with nothing except: Biodun''s Lexus is back. Rear sensors again.\nJideofor looked at this message for a moment and then he smiled, fully, in the school compound with the neem tree and the emptying crowd of candidates around him, because the message meant exactly what it said and also everything else, which was that the workshop was there, as it had always been, his foundation and his first floor and the name at the top of a proposal in a manila folder, and it was not behind him.\nHe put his phone in his pocket and walked toward the gate.\nBoth hands, he thought. All along, it had always been both hands.','\n',char(10)),1076,1,1,NULL,'2026-04-22T07:48:38.738Z','2026-04-22 07:48:38','2026-04-22 07:48:38','2026-04-22T08:30:00.000Z',1,NULL);
INSERT INTO "chapters" ("id","novel_id","chapter_number","title","content","word_count","is_premium","is_published","audio_url","published_at","created_at","updated_at","scheduled_release_at","part_number","season_id") VALUES(624,74,1,'The Notebook',replace('By four o''clock on Saturdays, Folake could tell which customers were serious and which ones were wasting her time. Two years at Madam Bisi''s pepper stall had given her that, if nothing else.\nThe serious ones walked in straight lines. They moved through Bodija Market the way people moved through things they had done a hundred times before, not fast but without hesitation, already knowing what they needed and trusting that she would weigh it correctly. They did not argue unless she gave them a reason.\nThe others were a different study. They touched everything. They held a tomato up to the light as though checking for something hidden inside. They asked questions that were really complaints. How come tatashe is this price? Is the pepper fresh? Folake had learned to meet all of it with the flat patience Madam Bisi had drilled into her from the very first Saturday. Not rude, not warm. Just sufficient. Sufficient was its own kind of skill.\nIt was late afternoon, the heat easing slightly but refusing to apologize for the day it had caused. The market had come down from its midday noise into something slower and more worn. Women moved through the aisles doing final rounds, trays carried on their heads, unhurried in the way of people who had learned that the last sale always came to those who waited. The shade cloth over the pepper stall had been patched twice on the left side and still let through a thin stripe of light that fell across the table at the same angle every afternoon. Folake had noticed it on her third Saturday working here and had noticed it every Saturday since. She noticed things without meaning to.\nShe was restocking the tatashe row, working from the back forward so the older stock stayed visible at the front, when the woman arrived.\nA woman in her forties in office clothes, a bag clamped under her arm that told a short story. Not a regular trader, not a housewife on her usual market circuit. Someone who had turned off her route home to stop here quickly, with the manner of a person who had three more things to do before the day released her. Folake had read all of it before the woman finished approaching the table.\n"Pepper, tatashe, onion," the woman said, eyes moving across the arrangement. "The full set."\nFolake began to measure. The woman watched with the compressed impatience of someone whose day had already been too long. She checked her phone twice. She moved her bag from one arm to the other and then back again.\n"They should really make this easier, you know," the woman said, to no one in particular, to the market, to the frustration she had been carrying since morning. "You buy pepper from one place, tomato somewhere else, by the time you have ground everything yourself and gotten it on the fire, it is already midnight before the soup is ready."\nFolake knotted the bag and said the price.\nThe woman paid and left.\nFolake set the money in the till and stood still for a beat longer than the transaction needed.\nShe had heard that complaint before. She had heard some version of it from this stall, in this market, across two years of working here. What''s fresh today? Do you have already blended? Why must I buy everything separately? She had always filed those words in the part of her mind reserved for things she had not yet figured out what to do with. Customer preference. Observed, noted, set aside.\nBut the word midnight landed differently this time.\nWhy not already blended, actually? Why not here?\nShe already knew the answer to the second question. She had walked every row of Bodija Market more times than she could count. There were women with grinding machines who would process your ingredients for a small fee. But prepackaged, ready to open and use, portioned for one pot? Nothing. Not a single stall in this entire market sold that.\nShe served another customer. She counted change without looking at her hands. She swept under the weighing scale, where pepper dust collected fastest. She helped a girl from the next stall carry a sack of onions to the back storage. She did everything she was supposed to do, and she did it correctly, without losing the thread pulling tight at the back of her mind.\nAt quarter past five, when the market crowd had thinned to its tired evening pace, Folake reached into her school bag and took out the notebook.\nGreen cover, fifty naira from the stationers near her school, the corner beginning to fray from how often she opened it. She had bought it herself in JS2, after she realized that prices in Bodija did not move randomly. They moved in patterns. Tatashe climbed two weeks before Christmas without fail. Onion prices rose whenever news came that the northern trucks had been held up. She had tracked all of it across three stalls, one column each, every Saturday morning before her shift started. Eight months of data that no one had requested and no one knew existed.\nShe found a clean page and wrote:\nAlready blended mix. Small sachets. Working women. Time problem.\nBelow that, she wrote: Does anyone in this market sell this?\nShe drew a box around the question.\nMadam Bisi appeared at the entrance of the stall, looked at the table for a long moment, and then looked at Folake.\n"You have been standing there doing nothing," Madam Bisi said.\n"I was thinking," Folake said.\n"The tatashe in front is older than the tatashe at the back."\nFolake put the notebook away and fixed the tatashe.\nBut the box she had drawn around that question did not close with the notebook. It stayed through the packing up, through the low evening noise of the market, through the bus ride home, through dinner and homework and the moment she finally lay down in the dark. She turned it over one more time before sleep came, and she still could not find a single reason why the answer had to be no.','\n',char(10)),1029,0,1,NULL,'2026-04-22T21:14:35.232Z','2026-04-22 21:14:35','2026-04-22 21:14:35','2026-04-23T08:00:00.000Z',1,NULL);
INSERT INTO "chapters" ("id","novel_id","chapter_number","title","content","word_count","is_premium","is_published","audio_url","published_at","created_at","updated_at","scheduled_release_at","part_number","season_id") VALUES(625,74,2,'What Women Buy',replace('The first thing she needed was a system.\nFolake had learned from eight months of price tracking that a hunch without evidence was just a feeling, and feelings did not survive argument. If she was going to build anything real from the question she had boxed in her notebook, she needed to confirm it properly. Not assumed real. Not hoped. Real the way a price shift was real: observable across different days, different people, different corners of the same market.\nShe gave herself two weeks.\nThe research did not look like research from the outside, and that was intentional. She kept doing everything she always did at the stall: weighing, pricing, restocking, making change, managing the Saturday lunch rush when Bodija swelled with women doing their weekly shopping. But she adjusted her listening. Not for what customers said to her directly, because people rarely gave you the honest thing when they knew a seller was on the receiving end. She listened for what they said to each other, in the small unguarded moments between transactions.\nThe food court at the center of Bodija was where she started. On her break the first Wednesday, she walked to where Mama Tunde sold eba and egusi at a long table covered in blue plastic cloth, the kind that had been washed so many times the pattern was almost gone. Women who ate there always talked while they ate. That was the particular truth about a place where food happened: people released whatever they had been carrying and said the things the day had not given them room to say elsewhere. Folake bought a small portion, found a stool at the far end of the bench, and listened without appearing to.\nIn forty minutes, she heard some version of it three times.\nA woman in a yellow cotton wrapper complained to her companion about coming home from work to an empty pot. Her companion asked if she had ground pepper that morning. The first woman laughed in a way that was not really laughter. "Since when do I have time to grind pepper on a Wednesday?"\nA younger woman counting change for her plate muttered to herself about stopping at the grinding machine before she could even start her soup. A third woman, speaking across the table to someone Folake could not see clearly, described a packaged pepper mix she had found in a shop in Lagos: small sachet, everything already blended and measured. She said there was nothing like it here in Ibadan and she did not understand why every useful thing arrived in Lagos first.\nFolake ate her eba slowly and let all three conversations settle. She noticed that in the whole of that forty minutes she had not heard a single person say they would not want a ready solution. The objection, when it came at all, was always price or availability. Never the thing itself. That was important.\nBy the end of the first week she had moved through the fabric row, the provision stores near the main gate, and twice through the open section where women sold fresh tomatoes from low tables pushed close together, their red arrangement visible from the far entrance. She did not ask anyone directly about preblended mixes. She asked sideways, the way she had learned to approach difficult things with Madam Bisi: carefully, without showing where she was actually going. She asked a woman sorting tomatoes whether customers ever asked for ingredients already combined. The woman gave her a long look and said: "Everybody wants that. Nobody is selling it because people will say the price is too much." She asked a young man at a provision stall near the northern side whether he had ever considered stocking packaged pepper paste. He said his supplier did not carry anything like that and that it would expire too fast for a small operation anyway.\nShe wrote all of it down. Not in the green notebook, which she kept strictly for price patterns. She had started a second one: blue cover, fifty naira, same stationer near school. The green notebook held numbers. The blue one held people.\nIn the second week she returned to a stall she had noticed before without ever studying closely. Near the eastern entrance, where the morning light caught the concrete wall at a low angle before the heat of the day shifted everything, a woman named Iya Gbemisola sold ground crayfish and locust beans from a small wooden counter. She was the only trader in the whole of Bodija selling a product that was already processed: not raw ingredients to be taken home, but finished, ready to open and use. Her stall had a steady flow every morning. Women came, bought quickly, left. Nobody stood there negotiating the price. Nobody asked why the crayfish was not sold raw.\nFolake watched for twenty minutes before she bought two scoops she did not need. Those women were not buying crayfish. They were buying back the part of the evening they would otherwise have spent grinding it themselves.\nShe walked back to the pepper stall and wrote across the top of a clean page in the blue notebook, in letters large enough that she could not look past them: THE PRODUCT IS TIME.\nThe final confirmation came four days later from a regular: a civil servant who bought tatashe every Friday on her way from the secretariat, always in a hurry, always exact with her money. The woman mentioned that she had once found a sachet pepper mix at a supermarket near Ring Road and it had saved her entire week. The supermarket had been out of stock for three weeks and she had not found it anywhere else. Folake asked, as lightly as she could manage, whether she would buy it here in Bodija if it were available.\nThe woman stopped. She turned and considered the stall with the careful attention of someone making an honest calculation.\n"Here?" she said. "I would buy ten."','\n',char(10)),1001,0,1,NULL,'2026-04-22T21:15:51.647Z','2026-04-22 21:15:51','2026-04-22 21:15:51','2026-04-23T08:00:00.000Z',1,NULL);
INSERT INTO "chapters" ("id","novel_id","chapter_number","title","content","word_count","is_premium","is_published","audio_url","published_at","created_at","updated_at","scheduled_release_at","part_number","season_id") VALUES(626,74,3,'Minimum Order',replace('The question was not where to find sachets. The question was who to ask without showing her hand.\nFolake had spent one full week of lunch breaks tracing the answer backward. She started with what she could see: the small transparent sachets that groundnut sellers used, the flat sealed packets from provision stores, the hard plastic sachets holding palm oil near the main gate. Somebody was supplying all of it. All those containers did not arrive in Bodija by accident.\nShe asked Mama Tunde first, not directly but during the natural pause at the end of a slow lunch hour when the older woman was stacking plates and her guard was down. Did she know where traders got their packaging? The flat sachets? Mama Tunde gave her a considering look and pointed left. "Ask Alhaji Rauf. He comes Tuesday and Friday mornings. He supplies the provision side."\nFolake thanked her and went back to the stall.\nShe could not come on Tuesday. School. She planned for Friday and spent the days between pricing the rest of the problem in her head. How many sachets to start? How much pepper and tomato per sachet? What weight made the price right without making the margin wrong? She worked the numbers the way she worked the price columns in her green notebook: without rushing, returning to them across different days to see if they held under pressure. By Thursday evening she had a starting figure she trusted. Two hundred sachets for a first run. That was testable. That was real without being reckless.\nFriday morning, she told Madam Bisi she needed five minutes before her shift started and walked toward the provision section.\nAlhaji Rauf was not what she had pictured. She had constructed someone older and slower, the kind of trader who sat behind a table and waited for the world to come to him. The man she found was compact and precise in his movements, loading small cartons from a handcart onto a shelf with the quick efficiency of someone who had been doing it for years and had other stops waiting. He wore a white kaftan with a small stain near the pocket that he clearly had not noticed. He looked up when she arrived and did not stop working.\n"Good morning, sir."\nHe nodded. "What do you need?"\nShe had rehearsed this. She said she was looking for transparent flat sachets suitable for food product, the heat seal kind. She described the dimensions she had measured off similar packaging at the provision stall: roughly ten centimeters by seven, thick enough to hold a hundred grams without splitting, food safe.\nHe stopped loading. He looked at her properly for the first time. She was fifteen, in school uniform, standing at the edge of a business she clearly had not entered before. She watched him read all of it.\n"What are you packaging?" he asked.\n"Pepper and tomato mix," she said.\nHe resumed moving cartons. "Minimum order is one thousand units. That is the smallest I supply."\nThe number landed in the center of her chest and stayed there.\nShe did not let it reach her face. Two years at Madam Bisi''s stall had taught her that a visible reaction was a concession you had not agreed to give. She kept her expression level while the arithmetic settled.\n"How much per unit at minimum order?" she asked.\nHe told her.\nOne thousand units at that price came to close to fourteen thousand naira. Her savings, collected carefully across two years of Saturday pay, birthday money she had not spent, the two hundred and five hundred naira she had pressed into the back of the blue notebook over months, totaled slightly under three thousand naira. She had come here needing two hundred sachets. The smallest available quantity was nearly five times her entire savings.\n"Can I get a number?" she asked. "In case my budget changes."\nHe tilted his head at the provision stall owner beside him, who wrote a number on a scrap of paper and handed it across without expression. Folake thanked both of them and walked back toward the main aisle at the same pace she had arrived.\nShe stopped in the narrow back passage behind the fabric row, a concrete corridor she cut through most mornings because it shaved two minutes off the walk. A single bulb hung from a wire overhead, the kind of pale yellow light that made everything look slightly older than it was. Against the far wall, cartons of unsold goods were stacked unevenly, and somewhere above the roofing sheets a bird was moving without urgency. There was nobody else in the passage.\nShe did the numbers again from the beginning, carefully, in case she had made an error.\nShe had not made an error.\nThree thousand against fourteen thousand. She was short by eleven thousand naira. She could save toward it, but her stall income was steady and small: useful, not enough to close an eleven thousand gap in any time that left the idea still alive. Four months, maybe five, before she reached the minimum. By then the civil servant from the secretariat would still be buying elsewhere. The woman at Mama Tunde''s bench who had not found the Lagos sachet mix in three weeks would still be waiting for something that had not yet arrived in Bodija.\nShe had expected the first wall to come later. After a test batch, after something she could hold up. Instead it was here at the start, standing across the path like it had always known she was coming.\nShe folded the scrap of paper into the blue notebook and looked at the far end of the passage, where the main market noise continued without her.\nThere was only one person in Bodija Market who could hear the words "pepper sachet mix" and understand everything those words were trying to become.\nFolake was not ready for that conversation. But eleven thousand naira had just told her she could not afford to keep waiting until she was.','\n',char(10)),1011,0,1,NULL,'2026-04-23 03:58:59','2026-04-23 03:58:40','2026-04-23 03:58:59','2026-04-23T07:00:00.000Z',1,NULL);
INSERT INTO "chapters" ("id","novel_id","chapter_number","title","content","word_count","is_premium","is_published","audio_url","published_at","created_at","updated_at","scheduled_release_at","part_number","season_id") VALUES(627,74,4,'The Ask',replace('She had rehearsed it forty times and the rehearsal had not helped.\nThe problem with preparing to say a difficult thing to someone who was sharp was that sharpness did not behave the way scripts expected. Madam Bisi had a particular way of listening that rearranged whatever you had planned to say before you finished the first sentence. Folake had watched it happen to customers, to the girl from the next stall who had once tried to borrow the weighing scale for a weekend, to a distributor who had arrived with a fixed price and left having agreed to something different. The woman did not interrupt. She listened with the kind of attention that made you hear your own words differently, and then she asked one question that changed the shape of the whole conversation. Folake had rehearsed for that question. The problem was she had no idea which question it would be.\nShe had two weeks of evidence in the blue notebook, a supplier''s number on a scrap of paper, and the memory of a civil servant saying she would buy ten. She had worked the figures until they held. She knew what she was asking for: kitchen access on Saturday mornings before the market opened, use of the grinding machine in Madam Bisi''s back storeroom, and space to keep a first batch of sachets until they moved. Two hundred sachets as a starting number. Manageable. Testable. Real enough to argue for. She had gone over the numbers the night before until she stopped finding errors in them.\nShe had not yet solved the minimum order problem. She would present it the way it was: a gap she was aware of, not one she was hiding.\nSaturday came with the dry harmattan light that settled over Ibadan in November, pale and flat, the kind of morning where everything looked as though it had been left out too long. Folake arrived at the stall forty minutes early. The neighboring provision store was just opening, its owner rolling up the metal shutter with a sound that rang down the aisle in both directions. The man who sold dried fish two stalls across was stacking his display from a wide enamel basin balanced on one shoulder, the silver arrangement catching what little light there was. A boy pushed a cart of empty crates past the entrance, the wheels catching on the uneven concrete with a rhythmic skip. The market had not yet decided to be loud.\nFolake restocked what did not need restocking and arranged what did not need arranging. She repositioned the plastic scoop twice before she recognized what she was doing and put it down.\nMadam Bisi arrived at her usual time. She surveyed the table, noted the arrangement without comment, set her bag on the wooden stool behind the counter, and began her opening routine: checking the remaining stock weight against Friday''s close, moving a crate from the front of the storage shelf to the back, making a sound in her throat that meant she was calculating something and had not finished yet.\nFolake waited until the routine was complete. She had learned that Madam Bisi did not receive anything well while her hands were still in the middle of something else.\n"Ma," she said.\n"Mm."\n"I have something I want to ask you."\nMadam Bisi straightened and turned. Not with surprise. More like someone who had been expecting a knock at the door and was now opening it.\n"Talk," she said.\nFolake talked. She had decided on the walk over to lead with the research, because the research was the solid ground and she needed them both standing on it before the ask. She laid it out clearly and without rushing: the two weeks of observation across the market, Iya Gbemisola''s stall and the specific thing it was actually selling, the civil servant from the secretariat, the woman from the food court who had found the Lagos sachet mix and been unable to replace it in Ibadan for three weeks. She named the gap precisely and described the customer it left unserved: working women, time poor, already paying the grinding machine, already wanting something no one was providing.\nThen she said what she needed. The kitchen. The grinding machine. Storage space for a first batch. She gave the starting figure clearly: two hundred sachets, contingent on resolving the minimum order problem, which she named directly rather than leaving for Madam Bisi to find.\nWhen she finished, the market had settled into its morning rhythm. A woman moved through the aisle with a tray of chin chin on her head, calling her price in a voice that reached three rows over. From the fabric section, a radio carried something with a talking drum underneath it, steady and low.\nMadam Bisi had not moved once during all of it.\nThe silence that followed was not uncomfortable. It was the silence of a person doing serious work. Folake had learned to leave that kind of silence alone. She waited.\n"How long," Madam Bisi said, "have you been tracking prices in this market?"\n"Eight months, ma."\nSomething moved across the older woman''s face. Not surprise. Not quite approval. Something between the two that Folake did not yet have a word for.\n"The minimum order problem," Madam Bisi said. "How much are you short?"\n"Eleven thousand naira."\nMadam Bisi turned back to the storage shelf and adjusted the crate she had already moved, a small unnecessary gesture, the kind that meant the visible part of a conversation was finished and the real part had moved somewhere else.\n"Come back at closing," she said. "We will talk."\nNot yes. Not no. But Folake, who had spent two years learning what this woman''s measured silences carried, understood that she had just been taken seriously in a way that changed the shape of the morning.\nShe picked up the plastic scoop and started her day.','\n',char(10)),989,1,1,NULL,'2026-04-23T04:01:49.692Z','2026-04-23 04:01:49','2026-04-23 04:01:49','2026-04-23T08:00:00.000Z',1,NULL);
INSERT INTO "chapters" ("id","novel_id","chapter_number","title","content","word_count","is_premium","is_published","audio_url","published_at","created_at","updated_at","scheduled_release_at","part_number","season_id") VALUES(629,74,5,'Madam Bisi''s Hands',replace('\nThe kitchen was smaller than Folake had imagined, and Madam Bisi moved through it like someone who had never needed it to be larger.\nIt was the Saturday after the closing conversation, early enough that the market''s outer aisles were still mostly quiet. Madam Bisi had unlocked the back storeroom before Folake arrived and left the door open without comment, which was instruction enough. The room connected through a short corridor to a small cooking space: a gas cooker against the left wall, a grinding machine bolted to a wooden counter beside it, shelves of sorted containers on the right, and a window at the far end that let in the pale morning without enthusiasm. Everything had a position. Nothing was decorative.\nFolake set her bag down and waited to be told where to begin.\n"Wash the tomatoes," Madam Bisi said, already moving.\nFolake washed the tomatoes.\nWhat followed was not a lesson in the formal sense. Madam Bisi did not explain what she was doing as she did it. She simply worked, and Folake, trained by two years of watching the woman manage a stall with the efficiency of someone who had identified the shortest path between every task, understood that watching was the instruction. She paid attention the way she had learned to pay attention in this market: without announcing it.\nThe first thing she noticed was the ratios.\nMadam Bisi measured nothing with a scale and nothing with a cup. She worked in handfuls and proportions, adjusting as she went with the assurance of someone reading a result before it was finished. Three parts tomato to one part tatashe to a calculated handful of the scotch bonnet, adjusted down for the heat level that a mixed customer base could tolerate. Folake had not told her what the target customer looked like. Madam Bisi had arrived at this formulation on her own, from reasoning Folake had not heard aloud. Working women. Time poor. Cooking for families, not restaurants. The heat needed to be real but forgiving.\nFolake stood at the grinding machine when it was her turn and fed the ingredients through the way she was shown: in portions, not all at once, so the texture came out smooth without losing body. Madam Bisi stood beside her the first time and said nothing. Watched the output, made a sound in her throat, and told Folake to adjust the feed speed. Folake adjusted it. The second batch came out differently and the sound Madam Bisi made was different too.\nThey moved through the first test quantity together in just under an hour. The kitchen had warmed with the gas and the morning both, and outside the window the market was beginning to find its voice, traders arriving and setting up with the particular percussion of stalls opening: crates, shutters, greetings called across aisles.\nIt was when they were filling the test sachets, twelve of them, the ones Madam Bisi had sourced from a contact Folake had not asked about yet, that Folake saw the second thing she had not planned to see.\nMadam Bisi sealed each sachet with a flat iron heated on the gas, working along the top edge in one smooth press, checking the seal with two fingers before setting it down. She did it with the concentrated attention of someone who understood that the seal was the product''s first promise to the customer. Not the ingredients, not the price. The integrity of what was closed inside. A sachet that split in a customer''s bag destroyed more than one sale. It destroyed the credibility of everything the product was trying to be.\n"You press from the center," Madam Bisi said, without looking up. "Not from the side. Center gives you even pressure both ways."\nFolake tried it. Madam Bisi looked at the result and nodded once.\nThey lined the twelve sachets on the counter. A row of flat, sealed, identical packages that had not existed two hours ago. Folake looked at them for a moment. They were real in a way that the blue notebook and the price columns and the figure in her head had not quite been.\n"Turn one over," Madam Bisi said.\nFolake turned one over.\n"The label goes here," Madam Bisi said, and she placed her thumb in the center of the back face, precise as a stamp. "Name, weight, and a preparation line. Not instructions. One line. Women buying this know how to cook. You are not teaching them. You are reminding them that whoever made this also knows."\nFolake was quiet.\nShe had thought about the product. She had thought about the gap and the customer and the minimum order and the capital problem. She had not thought about the label. She had not thought about the sentence on the label that told the customer what kind of intelligence had made the thing they were holding.\n"How did you know to think about that?" Folake asked.\nMadam Bisi set the iron down and looked at the row of sachets with an expression Folake had not catalogued before. It was not pride and it was not distance. It was closer to the particular attention of someone recognizing a version of something they had carried a long time.\n"Because," she said, "I have been in this market for thirty years. And I have watched people sell the same correct product badly, more times than I can tell you."\nThe market outside had reached its full morning noise. Somewhere in the fabric row, a woman was laughing at something in long generous waves that carried over the rooftops. A generator started two stalls over, its sound settling into the background texture of the day.\nFolake looked at the twelve sealed sachets and understood, for the first time, that Madam Bisi had not simply agreed to help her make a product.\nShe had been building this alongside her from the moment Folake had said eleven thousand naira.','\n',char(10)),992,1,1,NULL,'2026-04-23T04:07:27.501Z','2026-04-23 04:07:27','2026-04-23 04:07:27','2026-04-23T08:00:00.000Z',1,NULL);
INSERT INTO "chapters" ("id","novel_id","chapter_number","title","content","word_count","is_premium","is_published","audio_url","published_at","created_at","updated_at","scheduled_release_at","part_number","season_id") VALUES(630,74,6,'Market Price',replace('The numbers worked. She had checked them four times across three evenings and they had held every time.\nFolake had built the price from the floor up, the way the green notebook had trained her: begin with what is fixed, account for what changes, leave a margin that can absorb a surprise without the whole structure collapsing. She itemized every cost across the twelve test sachets. Packaging per unit. Ingredients per unit. Grinding time, which was paid in fuel and labor even if the labor was her own. Sealing time. A small loss allowance for failed seals and overfill. She laid the total against what a working woman already paid at the grinding machine per visit, the cost she absorbed every week without complaint, and arrived at a figure that served both sides without dishonesty. She wrote it in the blue notebook with a circle around it, not a box. A box was for something she was still inside. A circle meant she was ready to move it into the world.\nTwo hundred naira per sachet.\nShe tested it against herself first, the way she tested everything before she trusted it. Would she, standing in the civil servant''s shoes, arriving home tired on a Wednesday evening with one hour before the family expected dinner, pay two hundred naira for something that handed that hour back? She held the question carefully and gave it an honest answer. Yes. She would pay it and consider the trade fair. She wrote yes beside the circle, underlined it once, and closed the notebook.\nShe brought the number to Bodija on a Thursday afternoon after school, not to sell anything but to take the temperature. She found Alhaja Muinat at the provisions stall near the northern entrance, a woman whose opinion traveled through this market the way harmattan moved through a street: entering everywhere, leaving traces without being seen. Folake bought a tin of tomato paste she had no use for and introduced the sachet project the way she had learned to introduce things she needed honest responses to, lightly, without pressure, as though she herself was still in the thinking stage.\nAlhaja Muinat heard the price and set her tin opener down.\n"Two hundred naira?"\n"Yes, ma."\nThe woman regarded her with the particular attention of someone deciding how direct to be. "Who is selling this?"\n"I am. With Madam Bisi''s kitchen."\nA pause that was doing real work. "You are fifteen."\n"Yes, ma."\n"Two hundred naira is a Lagos price." Alhaja Muinat returned to her work with the settled finality of someone who had said the necessary thing. "In this market, people will not say your product is wrong. They will say you are too young to be charging that."\nFolake thanked her and walked on.\nShe heard the same opinion twice more before the afternoon light began to flatten. An older woman in the vegetable section had arranged garden eggs in careful graduated rows along a low wooden board, the pale green and white ovals sorted by size with a deliberateness most people would not notice. She told Folake that a girl her age setting that price would collect suspicion before she collected customers. A man at the far provision stall, one of the ones who had seen the test sachets through Madam Bisi''s contact, said the market floor for a product like this from a secondary school student was one hundred and fifty naira. Anything above that would draw the wrong kind of noise.\nNeither of them said the product was wrong.\nFolake registered this and kept it separate from the rest of what she had heard. Not one person across three conversations had questioned the gap she had identified, the product itself, the ingredients, or the customer she was targeting. The resistance had landed at the same point every time and it was not the number. It was the person attached to the number. The market was not telling her the price was too high. It was telling her it did not yet have a name for her.\nShe took the back entrance out to the narrow ledge running along the outer market wall, a low concrete shelf above an open drainage channel carrying a slow thread of water toward the main road. A woman had set out bottles of zobo here in two rows on a wooden board balanced across bricks, the deep red of the drink visible through the glass. The afternoon light had thinned to something gentler, the harshest part of the day already spent. The bus stop sat thirty meters to the left, and the foot traffic between the market and the road moved past in a steady, unremarkable stream. Folake had walked past this spot dozens of times and never sat. Now she sat and watched.\nEvery trader who moved through that junction carried the particular ease of people whose right to be in this market was not currently under question. It was not arrogance. It was the physical fact of accumulated credibility, the kind a body absorbs across years of being here, of proving something, of having the market register it and move on. She was fifteen with two years at a stall and eight months of price data and a product with no competition in this entire space. None of that was written in any language the market had learned to read at a glance.\nThe number was right. She had tested it from every angle and it had held every time. What she was missing was not inside the circle. It was attached to the outside of it, and she was beginning to understand what it looked like.\nShe was still sitting with this when the zobo woman looked up from her bottles.\n"Madam Bisi''s girl, abi?"\n"Yes, ma."\nThe woman gave one slow nod, as though this confirmed something she had already concluded, and returned to her arrangement.\nFolake opened the blue notebook to the circled number. She wrote two words beneath it, underlined them once, and put the notebook away. Then she stood and walked back into the market.','\n',char(10)),1019,1,1,NULL,'2026-04-23T04:09:48.139Z','2026-04-23 04:09:48','2026-04-23 04:09:48','2026-04-23T08:00:00.000Z',1,NULL);
INSERT INTO "chapters" ("id","novel_id","chapter_number","title","content","word_count","is_premium","is_published","audio_url","published_at","created_at","updated_at","scheduled_release_at","part_number","season_id") VALUES(631,74,7,'First Saturday',replace('She almost did not put them out.\nThat was the part she had not predicted: that after two weeks of research and one test batch and four evenings of pricing and all the conversations she had carried home and turned over in the dark, the actual moment of placing the sachets on the table would arrive with a reluctance so physical it felt like weather. She stood at the stall at seven forty that Saturday morning, the twelve sachets in a flat row inside a small woven tray Madam Bisi had produced from the storeroom without explanation, and her hands did not move.\nMadam Bisi was behind her, arranging the week''s fresh stock with the unhurried precision of someone who had already decided not to watch.\nFolake set the tray on the left corner of the table.\nShe positioned it twice. She adjusted the angle once. Then she stepped back and began the actual work of the morning: weighing, pricing, making change, managing the first wave of customers who arrived early because they had somewhere else to be after.\nThe sachets sat. The first hour passed without a single person stopping for them. Folake served six pepper customers and noticed, without meaning to, that two of them looked at the tray and looked away without asking. The look was not hostile. It was the look of something unfamiliar in a familiar space, registered and set aside for someone else to investigate first.\nBy nine o''clock the main Saturday crowd had filled the aisle, and the stall was moving. Folake worked with the focused efficiency she had built over two years, not fast enough to invite errors and not slow enough to lose the rhythm of the rush. She kept her peripheral attention on the tray without making it the center of anything.\nThe first sachet sold at nine seventeen to a woman in a printed ankara blouse who had bought tatashe from the stall before and picked up a sachet the way a person picks up something that has already answered the question they were about to ask. She turned it over, read the single line on the back label, and said the price like she was confirming it rather than questioning it.\n"Two hundred?"\n"Yes, ma."\nShe counted two notes from a folded money held flat in her palm and moved on.\nSachets two and three went together to a woman who asked one question about preparation and then bought both without negotiating. Folake answered the question briefly, without over explaining, the way Madam Bisi had taught her to answer questions about stall products: enough information to close the uncertainty, not so much that you sounded like you were selling something you were not sure of yourself.\nBy eleven the tray held four sachets.\nThe morning traffic shifted. The rush settled into the midday pace that was looser and less directed, the kind of market hour where browsers moved beside buyers and the difference was not always immediately clear. Folake continued working the pepper stock and let the remaining sachets sit in the tray without attention. She had learned from watching Iya Gbemisola that a product displayed with desperation transmitted that desperation to the customer before any word was spoken.\nThe civil servant arrived at eleven forty.\nFolake recognized the ankle length skirt first, then the bag clamped under the arm. The woman had arrived earlier than her usual Friday route, appearing on a Saturday for the first time that Folake could remember, which meant something had changed in her week and she had reorganized around it. She came to the stall and bought her regular tatashe order without looking at the tray. Folake weighed it, named the price. The woman paid.\nThen she stopped.\nHer eyes had found the tray on the corner of the table.\nShe set her bag down on the surface, an unusual thing that meant she was no longer in transit, and picked up a sachet. She read the back label slowly. She turned it to check the seal. She looked up at Folake.\n"Is this the one?" she asked.\n"Yes, ma."\nThe woman was quiet for a moment that had real weight. She set the sachet down and stood with the expression of someone doing an honest calculation rather than a polite one. Folake waited and let her.\n"You actually did it," the woman said.\nNot to Folake exactly. Not to the market. To something in the air between the two of them that the previous conversation had left open, the one about stopping at a supermarket near Ring Road, about waiting three weeks, about buying ten if it were available here.\nShe bought three.\nThe last sachet went mid afternoon to a woman Folake had never seen before at the stall, who had not come for pepper at all but had noticed the tray from the aisle and entered sideways with the particular movement of someone who had not planned to stop. She asked no questions. She paid exactly and left without a bag for her single sachet, simply sliding it into the wide pocket of her wrapper as though she had always known it would fit there.\nEight sachets sold. Four remained.\nMadam Bisi came to the front of the stall in the slow hour before closing, looked at the tray, and looked at Folake. She said nothing.\nBut Alhaja Muinat arrived at ten past four.\nThe same woman who had set down her tin opener and told Folake that two hundred naira was a Lagos price. She approached the table directly, as though she had decided something at a point in the day before this one. She picked up a sachet, checked it for the same three seconds she gave everything before she bought it, placed two hundred naira flat on the counter, and tucked the sachet inside her blouse pocket.\nShe did not look at Folake again.\nShe turned and walked back into the market the way she had come, her footsteps steady and unhurried on the warm concrete, until the afternoon crowd closed behind her like water.','\n',char(10)),1019,1,1,NULL,'2026-04-24T13:11:23.094Z','2026-04-24 13:11:23','2026-04-24 13:11:23',NULL,1,NULL);
INSERT INTO "chapters" ("id","novel_id","chapter_number","title","content","word_count","is_premium","is_published","audio_url","published_at","created_at","updated_at","scheduled_release_at","part_number","season_id") VALUES(632,74,8,'Stockout',replace('The second batch went in four hours.\nFolake had made twenty sachets this time, working with Madam Bisi in the kitchen on the Friday evening before, moving through the process with the efficiency of people who had already done it once and found the places where the work wanted to go faster. They finished in just over forty minutes. She lined the sachets in the woven tray that Saturday morning with a steadiness she had not felt the first time, the particular calm of someone whose theory had already cleared one test and was now running a second. Twenty was enough to confirm something. It was not enough to build anything.\nBy noon, the tray was empty.\nShe had not even moved all twenty from the back arrangement to the front display before the first three sold. The civil servant had come again and this time brought a colleague, a woman in a pale blue dress who inspected the sachet with the specific attention of someone who had been told about it beforehand and was now checking whether the description was accurate. She bought two. She asked about larger quantities and Folake said she would have them soon, which was not a lie but was not yet a confirmed truth either.\nTwo of the Saturday regulars from the previous week returned. That was the detail that caught in Folake''s attention and stayed: not the new customers, but the returning ones. The woman who had slid the sachet into her wrapper pocket without asking a question came back before eleven with her sister and bought one each. The woman in the ankara blouse arrived, found the tray already depleted to four, and took two. A young woman Folake had not seen before spent three full minutes at the tray, turning a sachet over, reading the label, then bought one, then stopped at the end of the aisle and came back for a second.\nAt twenty past twelve, Folake turned the empty tray face down on the corner of the table, which was the arrangement she and Madam Bisi had agreed would signal sold out to any passing attention. The woven base of the tray faced the aisle like a small apology.\nShe served pepper customers for the rest of the afternoon and counted the sachet money separately in the tin she had brought for that purpose. Four thousand naira exactly. Four thousand naira from twenty sachets across four hours, with a customer list that had included returning buyers before noon.\nOn the bus home she opened the blue notebook across her knees and worked the problem from the beginning, not because she had not worked it before but because the numbers were different now and she needed to see what the difference revealed.\nTwenty sachets per Saturday at two hundred naira was four thousand naira revenue. Cost of ingredients and fuel per batch of twenty was roughly six hundred and fifty naira. Clear return per Saturday: three thousand three hundred and fifty naira. She ran that forward across eight Saturdays and the figure that came out was real and promising and beside the point. Because the problem was not the return on twenty sachets. The problem was the ceiling.\nShe could not scale above what the kitchen could produce in a Friday evening session, and she could not use Madam Bisi''s kitchen beyond what Madam Bisi had silently agreed to without a conversation that had not yet happened. More immediately, the sachets themselves were borrowed: Madam Bisi''s contact had supplied the first two batches from existing stock, a bridge arrangement that had always been temporary. The next step was the supplier. The minimum order was still one thousand units. The cost was still fourteen thousand naira. Her savings had grown by three thousand three hundred and fifty naira across the two Saturdays, which brought her total to somewhere just above six thousand naira.\nSix thousand against fourteen thousand. The gap had narrowed and was still a gap.\nShe turned to a clean page and drew a single column. At the top she wrote: what I have. Below it she listed everything: savings, this Saturday''s return, the next two Saturdays at projected rate, assuming demand held. She arrived at a figure she could realistically hold by the end of the month. It was nine thousand and some. It did not reach the minimum. It did not reach the minimum even if she stretched the savings projections and held every expense where it was and had no Saturdays where the product moved slower than today.\nThe bus crossed the Dugbe junction, the evening traffic backing up at the intersection where the road narrowed beside the row of phone repair stalls. A woman on the seat in front was reading a newspaper folded into quarters. A child two rows back was arguing cheerfully with someone through a phone pressed to one ear. The window beside Folake showed Ibadan in the particular light it wore at this hour: buildings low and stacked, the sky behind them carrying the last color before dark, the city doing what cities did in the early evening, which was continue.\nShe looked at the column in the notebook.\nThe only solution that closed the gap in time that kept the product alive was capital she did not have. The only route to that capital, without a bank she could not enter and without borrowing from family in a way that changed the nature of the project, was the one she had been circling since she stood in the back passage and looked at the first figure Alhaji Rauf had handed her. She had known it then. She had known it through two Saturdays of sales and a growing return and a tray she was turning face down before noon.\nShe was not short of a supplier. She was not short of a product or a gap or customers who came back.\nShe was short of a conversation she had been building toward since episode one of her own notebook, and she had run out of numbers to put between herself and it.\nShe closed the blue notebook.\nThrough the dusty window, the last color left the Ibadan sky and the streetlights came on, first one and then several and then all at once, the city deciding without ceremony that it was night.','\n',char(10)),1062,1,1,NULL,'2026-04-24T13:12:27.229Z','2026-04-24 13:12:27','2026-04-24 13:12:27',NULL,1,NULL);
INSERT INTO "chapters" ("id","novel_id","chapter_number","title","content","word_count","is_premium","is_published","audio_url","published_at","created_at","updated_at","scheduled_release_at","part_number","season_id") VALUES(633,74,9,'The Offer',replace('Madam Bisi closed the stall at four and did not ask Folake to stay. She simply did not tell her to go.\nThat was a language Folake had learned to read. She stacked the remaining stock, covered the table, and followed the older woman through the short corridor into the storeroom without being invited, because an invitation was not what this was. The market outside was doing what Bodija did at this hour: releasing the day slowly, the noise descending from its afternoon peak into something lower and more tired, traders calling across closing stalls, the particular scrape of wooden shutters being pulled and locked.\nMadam Bisi sat on the wooden bench against the far wall and set both hands flat on her knees. She looked at Folake with the attention of someone who had been waiting for the right moment and had now decided this was it.\n"Sit," she said.\nFolake sat on the low stool across from her.\nThe storeroom held the day''s warmth along its concrete walls and smelled of nothing particular, just the closed air of a space that had been worked in. A single fluorescent tube above them made everything very clear. There was no softening of the light and no way to be imprecise in it.\n"The sachets," Madam Bisi began. "You sold out in four hours last Saturday."\n"Yes, ma."\n"And the Saturday before that."\n"Yes."\n"And you cannot scale past the capital problem."\nFolake said nothing. It was not a question.\nMadam Bisi looked at the far wall for a moment, as though reading something written there that she was deciding how to translate. When she turned back her expression was the one Folake had begun to recognize across the last few weeks: not the exacting stall face, the one calibrated for customers and distributors. The other one. The one that had appeared first in the kitchen over a row of sealed sachets and a thumb placed with the precision of a stamp.\n"I will cover the capital gap," Madam Bisi said. "The full minimum order. Packaging, ingredients to start, grinding fuel. You will have access to this kitchen every Friday evening and Saturday morning for as long as the product runs. I will manage the supplier directly, because I have history with Alhaji Rauf that you do not have and it will get you better pricing than you can negotiate yourself at fifteen."\nShe paused. The fluorescent tube above them held its even light without variation.\n"In exchange," she said, "I take forty percent of what the sachet business earns. The product carries both names on the label. Not below yours. Beside it."\nFolake held very still.\n"You keep sixty percent," Madam Bisi continued, with the measured precision of someone who had structured this before presenting it and was now presenting it exactly as structured. "You run the production and the sales. I do not interfere with how you manage the table or the customer. You continue at the stall on your regular arrangement. The sachet business is separate from your stall pay. Everything is separate."\nShe stopped.\nThe offer sat in the room between them, fully formed, every edge accounted for. Folake understood, with the part of her that had spent eight months building the green notebook and two more weeks building the blue one, that the structure was sound. Forty percent for capital, kitchen access, equipment, supplier relationships, and the accumulated weight of thirty years in this market, was not exploitation. She had run numbers enough to know what exploitation looked like. This was not it. By any measure she had learned to apply in this storeroom and outside it, the offer was fair.\nThat was the first thing she understood.\nThe second thing came slower, the way the complicated things always did.\nMadam Bisi had sourced the sachets for the first two batches herself. She had arrived in the kitchen with a formulation already calibrated for the customer Folake had described, without being told the description. She had placed her thumb on the back of the label and said not instructions, one line, and she had known what that line needed to communicate before Folake had thought to ask. She had watched two Saturdays of sellout without once asking about the numbers.\nShe had not been waiting for Folake to come to her.\nShe had known Folake would come to her. She had known it from the evening Folake had stood at this stall and said eleven thousand naira, and possibly from before that, possibly from some earlier moment Folake could not locate. The question that had kept the offer off the table until now was not whether Madam Bisi believed in the product. She had believed in it, quietly and with absolute certainty, from before the first sachet was sealed.\nThe question had been when Folake would run out of alternatives.\nAnd she had, across two Saturdays and a column of numbers on a bus, run out of alternatives.\nThe offer was fair. It was also the offer of someone who had understood the entire map and waited at the only exit.\nFolake looked at the woman across the small bright room. Madam Bisi looked back without apology and without cruelty, with the steady gaze of a person who had built something over thirty years in a loud and demanding market and had never once confused fairness with softness.\n"I need to think," Folake said.\nMadam Bisi nodded once. "Come back when you have thought."\nFolake stood. Her legs were steady. She picked up her school bag from beside the stool and settled it on her shoulder, and at the entrance of the storeroom she stopped without turning around.\n"Ma," she said. "Did you know you were going to make this offer before I made the ask?"\nThe silence behind her was three seconds long.\n"Go home, Folake," Madam Bisi said.','\n',char(10)),984,1,1,NULL,'2026-04-24T13:13:38.755Z','2026-04-24 13:13:38','2026-04-24 13:13:38',NULL,1,NULL);
INSERT INTO "chapters" ("id","novel_id","chapter_number","title","content","word_count","is_premium","is_published","audio_url","published_at","created_at","updated_at","scheduled_release_at","part_number","season_id") VALUES(634,74,10,'Her Mother''s Daughter',replace('She got home before her mother finished cooking, which meant she sat at the kitchen table and watched her mother work instead of arriving to a plate already set.\nHer mother noted this without turning from the pot. "You are quiet."\n"I am thinking."\n"You are always thinking. Tonight you are quiet."\nThe kitchen on Akinola Street had a window that faced the compound wall of the neighbor''s house, close enough that the two buildings shared shade in the afternoon. A row of enamel cups hung from hooks on the crossbeam above the sink, blue and white and one red that had arrived in the house from somewhere no one remembered clearly anymore. The linoleum beside the cooker had lifted at the corner and been pressed back so many times it no longer fully held. On the shelf above the gas cylinder, a line of spice tins stood in the order her mother had established before Folake was old enough to reach them. These were details of the kitchen Folake had stopped registering years ago. She was registering them tonight because she needed something to do with her eyes while her mind worked the problem from the inside.\nHer mother was making egusi. The wooden spoon moved in its particular direction, neither strictly clockwise nor counter, the private rotation her mother had been making for as long as Folake could place. She had asked about it once in primary school. Her mother had said: my mother taught me this way, and I have not yet found a reason to change it.\nThey ate without talking for most of the meal. That was a comfortable silence, the kind their house had plenty of. Her younger brother had gone to a neighbor''s and the compound outside was quiet except for the sound of the generator two houses down, and the occasional call between children whose day had not ended yet.\nFolake washed her plate and stood at the sink looking through the window at the compound wall. The concrete was stained at the base from years of rain runoff, a dark tide mark no higher than a low fence, and above it the wall was the pale color of old paint still deciding what to do next.\n"Why Madam Bisi?" she asked. Her voice came out steadier than she had expected.\nHer mother looked up from the table where she was picking through dried crayfish with the unhurried attention of someone with nowhere to be. "What do you mean?"\n"When you decided I should work. Why her stall? There were other places."\nHer mother set down what she was holding and considered the question the way she considered most things: without rushing and without performing the consideration. Outside, the generator changed pitch briefly and then returned to its note.\n"I knew Bisi before she had that stall," her mother said. "Before she had anything in that market. She came in with a table, no shade cloth, no supplier she could count on. She built everything from what she earned inside it. Year by year. Nobody handed it to her."\nFolake dried her hands on the cloth beside the sink.\n"I sent you to her because she is the kind of woman who does not let what she has built make her forget what it cost to build it. She will not be careless with you." Her mother paused. "She will also not be careless about what she decides is worth her time."\nThe generator outside settled back into its steady note.\n"She is the kind of woman," her mother said, after a pause that was doing specific work, "who sees clearly when something is worth holding. And does not pretend she does not see it."\nFolake looked at her mother.\nHer mother picked up the crayfish again and returned to her sorting, the small dry sounds of it filling the kitchen with a patience that was not indifferent. She had said what she had said the way she said most true things: without editorial, without softening. Here it is. Decide what to do with it.\nFolake went to her room.\nShe sat on the edge of her bed for a moment before she opened the notebook. The room was small and ordered in the way of someone who had made peace with its dimensions and arranged everything accordingly. A calendar on the wall showed a month that had already passed. She had not replaced it because the picture at the top, a coastal road with no particular significance, was one she found easy to look at.\nShe opened the blue notebook and ran the numbers again. The column was the same column it had been on the bus: her savings, the projected Saturdays, the gap that remained. She added the last two Saturdays'' returns and ran the projection forward at sustained demand. She arrived at the same ceiling she had always arrived at. The ceiling had not moved.\nShe turned to a clean page and ran a different calculation. Sixty percent of what the sachets could earn at proper scale, not Friday evening batches but a real supply arrangement, not twelve and then twenty but a hundred, then two hundred, then however many the demand could hold. She ran it forward at three months and then six. The figure she arrived at was larger than she had let herself write down before, because writing it down before had felt like wanting something she had not yet earned.\nShe looked at the figure for a long time.\nThen she wrote beside it, in the small careful hand she used when something mattered: not what I am giving up. What I am starting with.\nShe closed the notebook. Through the window, the compound had gone mostly quiet. The generator two houses down was still running, its sound steady and even and without opinion, the noise of something built to continue past the point where the original light had failed.\nShe knew what she was going to do. What she did not yet know was exactly how she was going to say it.','\n',char(10)),1018,1,1,NULL,'2026-04-24T13:14:38.805Z','2026-04-24 13:14:38','2026-04-24 13:14:38',NULL,1,NULL);
INSERT INTO "chapters" ("id","novel_id","chapter_number","title","content","word_count","is_premium","is_published","audio_url","published_at","created_at","updated_at","scheduled_release_at","part_number","season_id") VALUES(635,74,11,'Counter',replace('She had written her terms on a single page torn from the blue notebook, and she had written them three times before she was satisfied with the wording.\nThe first draft had been too long. She had explained too much, and explanation in a negotiation was a form of apology she had not decided to make. The second draft had overcorrected: four bare lines that read as aggression she did not intend. The third draft found the right weight. Seven points, each one stated without apology and without performance, the way the green notebook stated prices. Here is the number. Here is what it means.\nShe came on Tuesday after school, still in uniform, which she had considered changing and then decided against. She was fifteen. The uniform was a fact of her, and dressing around it was a concession she had already decided not to make.\nMadam Bisi was with a customer when she arrived. Folake waited at the edge of the stall rather than behind the counter. She had thought about that too: where to stand, what it communicated. Outside the counter meant she had arrived as something other than the stall girl. Madam Bisi registered her position without remarking on it and finished with her customer at the same pace she used for everything.\nWhen the customer left, the older woman looked at her.\n"You have thought," Madam Bisi said.\n"I have."\n"Come."\nThey went to the storeroom. The same fluorescent light, the same bench and stool, the same plain air of a space where precision was the only available mode. Folake sat without being invited this time. She set the page on the low surface between them and turned it so the writing faced Madam Bisi.\n"Read it first," she said. "Then I will explain anything that needs explaining."\nMadam Bisi read it.\nSeven points, in the order Folake had determined mattered most.\nOne: thirty percent to Madam Bisi, seventy to Folake. The capital was a loan with a structured return, not permanent equity. Folake proposed a repayment mechanism from the first four months of earnings at scale, after which the share reverted to twenty and eighty.\nTwo: the product name was Folake''s to determine. The label carried both names, but the product name belonged to the person who had identified the gap.\nThree: kitchen access for twelve months, with renegotiation at the end of that period decided jointly, not at Madam Bisi''s discretion alone.\nFour: supplier relationship shared from the second meeting onward. Folake attended every meeting that followed.\nFive: production schedule set by Folake, within agreed kitchen hours, with no changes without her agreement.\nSix: if the product expanded beyond Bodija, other markets, other distribution, Folake held first right of decision on every move.\nSeven: written agreement. Not because she did not trust the woman across from her. Because this was a business.\nMadam Bisi finished reading. She set the page down and looked at it, both hands flat on her knees.\n"The repayment timeline," she said. "Four months is tight if demand shifts."\n"I used the last two Saturdays as my baseline and discounted it by thirty percent for variance," Folake said. "If the numbers do not hold at month three, we extend by thirty days at a time. That extension goes in writing too."\nA pause. Not discomfort. The pause of someone updating a calculation.\n"Point four," Madam Bisi said. "Second supplier meeting, not the first."\n"Why?"\n"Because the first meeting I am repairing a price I negotiated before this conversation existed. You do not need to be in the room for that. From the second meeting, you are there for everything."\nFolake looked at her. The reason was specific and honest. It was not a retention of control for its own sake. She held it for the three seconds it deserved.\n"Agreed," she said.\n"Point seven," Madam Bisi said.\n"Yes, ma."\n"I have not signed a written agreement in this market in thirty years."\n"I know," Folake said. "This is not the market. This is a business."\nThe fluorescent tube above them made its faint electric sound. Outside, the market was doing its Tuesday afternoon work, consistent and unhurried, the sound of the place continuing without requiring their attention.\nMadam Bisi looked at the page for a long moment. Then she looked at Folake with the expression that had first appeared over a row of sealed sachets on a kitchen counter and had not fully left since.\n"Points one, three, five, and six," she said. "Accepted as written."\n"And point seven?"\nThe older woman was quiet for four full seconds, which was a long time in a room with nothing soft to land on.\n"You will need someone to draft it correctly," she said.\n"I will find someone."\nMadam Bisi nodded, a single deliberate movement carrying the weight of someone who had just agreed to something they had not fully anticipated being asked for.\n"Then we have something," she said.\nFolake picked up the page and folded it once along the center. She looked across the small bright room at the woman who had given her the first three years of understanding what real work felt like and what real work cost.\n"Thank you, ma," she said. "For the original offer. It was a fair one."\nMadam Bisi held her gaze evenly. "But not fair enough."\n"No," Folake said. "Not quite."\nShe tucked the page into her school bag and walked back out through the short corridor into the noise of the stall and the aisle and the market beyond it, which had not stopped for any of this and did not start now.','\n',char(10)),943,1,1,NULL,'2026-04-26T03:54:59.661Z','2026-04-26 03:54:59','2026-04-26 03:54:59',NULL,1,NULL);
INSERT INTO "chapters" ("id","novel_id","chapter_number","title","content","word_count","is_premium","is_published","audio_url","published_at","created_at","updated_at","scheduled_release_at","part_number","season_id") VALUES(636,74,12,'Madam Bisi''s Girl',replace('The agreement took eleven days to exist properly on paper.\nFolake had found the right person through her mother, who knew a woman on Akinola Street whose son had studied law at the University of Ibadan and now practiced at a firm near Dugbe. He was young enough to be curious about the structure and experienced enough to ask the questions that mattered, and his questions were better than Folake had anticipated, which meant she had to think harder about what she was protecting than she had already thought. She answered every question carefully. He drafted two pages. She read them across three sittings and sent back four specific comments. He revised. She read again. On the eleventh day she had a document that said exactly what both parties had agreed in the storeroom under the fluorescent light, nothing added, nothing softened.\nShe brought it to the stall on a Wednesday afternoon.\nMadam Bisi read it standing at the counter, which was unusual. She read without expression, which was not. She asked one question about the repayment structure and Folake answered it precisely, and then Madam Bisi removed the pen from the front pocket of her wrapper and signed on the line without ceremony. The pen moved, the page carried a signature, and she handed the document back.\nFolake signed beneath it and placed it flat inside the blue notebook.\nThe first full production run came that Friday evening. Alhaji Rauf had delivered the minimum order on Thursday: one thousand sachets stacked in two cardboard boxes that now occupied the left corner of the storeroom with the particular presence of things that had been a long time arriving. Folake and Madam Bisi worked the kitchen for just under two hours, a production line that had found its rhythm across the test batches and now moved through the larger quantity with the ease of something that had decided to become a process. By the time the gas cooker cooled, one hundred and twenty sachets stood in four flat rows on the wooden counter, each one sealed from the center and checked between two fingers before stacking.\nSaturday morning arrived with the kind of clear Ibadan sky that felt like a decision. Folake arranged the woven tray on the corner of the stall table with the unhurried certainty of someone who had done this before and now understood the full weight of what she was doing. Thirty sachets in the tray. Ninety in reserve. A label on each one that carried both names and a single line beneath them in the small careful hand she used for things that mattered: made in Bodija, for the woman who knows what her time is worth.\nBy ten o''clock, sixteen had sold.\nShe was weighing tatashe for a customer near eleven when Alhaja Muinat appeared at the front of the stall, not at the tray this time but at the table itself, standing directly before Folake with the manner of someone who had made a decision at some earlier point in the week and had now arrived to act on it.\n"I want twelve sachets," Alhaja Muinat said. "For my shop. I take them on margin. Thirty percent return to you per sachet sold."\nFolake finished the tatashe. She gave the customer change. She looked up.\n"Fifty percent," she said. "And I restock every Thursday."\nAlhaja Muinat held her gaze with the measuring attention she gave everything before committing to it. A truck reversed somewhere in the main aisle, its horn carrying over the rooftops in three flat notes.\n"Thursday," Alhaja Muinat said.\nShe counted the advance on twelve sachets in flat notes on the counter. Folake packaged them without rushing. The woman picked up the bag and paused in the way of someone who had one more thing that was not strictly business.\n"You are serious," she said. Not a question. Not a compliment. An observation, the kind that confirmed something the speaker had been tracking quietly for longer than this conversation.\nFolake handed her the bag.\nThe afternoon moved through its closing hour the way Bodija always did: the noise coming down from its peak into something tired and deliberate, shutters beginning their rounds, women doing final calculations before the day released them. Folake worked the tatashe and the tomatoes and the closing stock count with the same efficiency she had brought to this table across three years of Saturdays, and at the end of it she sat with the sachet tin and counted what the day had produced.\nThirty eight sachets across two channels. She wrote the figure in the blue notebook, and for the first time in the months she had been keeping it, she did not draw a shape around the number. She did not need to. It was no longer a question.\nShe looked up to find Madam Bisi watching her from the rear of the stall, arms folded, wearing the expression that had no name in any catalogue Folake had built across three years of close attention.\n"You are staying?" Madam Bisi asked.\nFolake understood the question entirely. It was not about tonight and they both knew it. It was about the stall, the Saturdays, the whole architecture of what this had been and what it was now that the table had changed shape.\nShe looked at the counter she had learned to weigh pepper behind. The patched shade cloth. The space that had taught her to read a customer from thirty meters and seal a sachet from the center and negotiate with a woman who had thirty years on her without blinking.\n"I am staying," Folake said. "But I am renegotiating my Saturday pay."\nMadam Bisi looked at her for one full second.\nAnd then something moved across the older woman''s face that Folake had never once seen in three years of standing inside this stall. It was not approval, exactly. It was not pride. It was the specific expression of someone who had built something carefully over a long time and had just watched it produce exactly the thing it was always meant to.\nMadam Bisi smiled.','\n',char(10)),1021,1,1,NULL,'2026-04-26T03:58:58.226Z','2026-04-26 03:58:58','2026-04-26 03:58:58',NULL,1,NULL);
INSERT INTO "chapters" ("id","novel_id","chapter_number","title","content","word_count","is_premium","is_published","audio_url","published_at","created_at","updated_at","scheduled_release_at","part_number","season_id") VALUES(637,32,1,' The Boy Who Came Quietly',replace('The new boy arrived on a Tuesday, which was already wrong. Nobody transferred to Federal Government College Abuja in the middle of second term. It simply did not happen.\nDamilola noticed him before the morning assembly bell finished ringing. He was standing at the edge of the quadrangle with a blue backpack that looked too new and a face that looked too careful. Not nervous careful. Calculated careful. Like someone who had already decided exactly how much of himself he was willing to show.\nShe pulled out her notepad. Old habit.\nHis name came through the grapevine by second period. Ibrahim Suleiman. SS2. Transferred from King''s Academy in Kaduna. The story that traveled with his name was thin. Family reasons. That was it. Two words to explain why a student would abandon a school three weeks into the term, leave his classmates behind, and start over in a city that did not know him.\nDamilola wrote family reasons and underlined it twice.\nHer editor at The Eagle Press, Mrs. Adaora, always said that the thinnest stories had the heaviest skeletons. Damilola had spent two years writing about cafeteria food protests, annual sports competition drama, and a minor scandal involving the JS1 block toilet renovation fund. Nothing that ever required underlining.\nIbrahim sat directly in front of her in Mathematics. Mr. Okafor had barely finished writing the equation on the board when Ibrahim''s hand went up.\n"Sir. There is an error in line three."\nThe class went quiet in that specific way it does when someone new does something that could be courage or foolishness and nobody is sure which one yet.\nMr. Okafor looked at the board. Looked at Ibrahim. Looked at the board again.\n"Correct," he said. Then, quieter: "Good eye."\nNobody clapped. But three people turned to stare at Ibrahim, and two of them were already smiling. That was faster than Damilola expected. New students usually spent at least a week being invisible. Ibrahim had used forty seconds.\nShe wrote: math. confident. not performing it. actually it.\nAfter class, she fell into step beside him in the corridor. She did it the way she always did when she needed something from someone: casually, like it was an accident.\n"You are Ibrahim, right?"\nHe glanced at her sideways. "Yes."\n"Damilola. Everyone calls me Lola." She gestured vaguely toward the general direction of the school building. "You settling in okay?"\n"Getting there."\n"Where are you staying? The hostel or..."\n"Hostel." He shifted his backpack strap. "Block C."\nShe nodded as though this was new information and not something she had already collected from Amara in the registration office that morning. "King''s Academy is a solid school. What made you leave?"\nHe stopped walking.\nIt was only for a second, the smallest pause between one step and the next, but Damilola caught it the way she caught everything: completely.\n"Family reasons," he said. Then he turned into the stairwell and was gone.\nShe stood in the corridor and wrote: reacts to King''s Academy. Immediate redirect. Practiced.\nThe first incident happened six days after Ibrahim arrived.\nDamilola heard about it the way most students did: in fragments, between classes, with everyone''s voice turned a little lower than usual. The school exam results database had been accessed without authorization. No results had been changed. Nothing was deleted. Whoever had gotten in had only looked.\nVice Principal Eze called it a routine security review in the official notice posted outside the staffroom. The word "hacked" spread through the student body anyway, because students always used the honest word.\nDamilola went to the computer lab during free period and found Chukwuemeka, the SS3 student who managed the school''s tech systems under Mr. Bello''s loose supervision. Emeka was pacing.\n"Can you tell me what happened?"\n"I can tell you what I know," he said. "Which is basically nothing useful. The access point was inside the school network. Whoever did it understood the system."\n"How well did they understand it?"\nHe looked at her for a moment before answering. "Well enough that it took me four hours to notice anything had changed."\nShe wrote that down. "Is there a record of who was in here that afternoon?"\n"The sheet by the door." He pointed at the clipboard hanging from a nail. "But that only shows students who signed in through the official register. If someone came in with a friend during a class period, they would not appear on it."\nDamilola photographed the sheet with her phone and left.\nThat night in her hostel room, she went through it by torchlight so she would not wake her roommates. Sixteen names. She recognized fourteen of them immediately.\nThe fifteenth was a teacher. One she knew well but would not have expected to find in the computer lab on a Thursday afternoon.\nThe sixteenth name was Ibrahim Suleiman. Recorded arrival at 2:47pm. Recorded departure at 3:15pm. 28 minutes. The breach, according to Emeka, had occurred somewhere between 3:00 and 3:30pm.\nDamilola sat with that for a long moment.\nThen she looked at the fifteenth name again. The teacher. Recorded arrival at 2:30pm. No departure time recorded at all.\nShe lowered the sheet. In the dark of the room, with the soft breathing of her roommates around her, she opened a clean page in her notepad and wrote two names at the top. Then she drew a straight line down the center.\nShe did not yet know which side was the real story and which side was the distraction. But Mrs. Adaora had taught her one thing above all others: when two things look equally suspicious at exactly the same time, it usually means something is directing your gaze.\nShe was being aimed.\nShe just did not know yet by whom.','\n',char(10)),961,0,1,NULL,'2026-04-26 08:55:20','2026-04-26 08:42:54','2026-04-26 08:55:20','2026-04-26T09:00:00.000Z',1,NULL);
INSERT INTO "chapters" ("id","novel_id","chapter_number","title","content","word_count","is_premium","is_published","audio_url","published_at","created_at","updated_at","scheduled_release_at","part_number","season_id") VALUES(638,32,2,' Three Things, One Week Apart',replace('The second incident happened exactly seven days after the first, and that was what broke Damilola''s sleep at 2am on a Wednesday.\nNot the incident itself. The interval.\nShe sat up in her bunk and counted backward on her fingers in the dark. The database breach: Thursday, Week 1. Mr. Adeniyi''s car, the silver Camry in the staff parking lot, keyed from bonnet to boot with something sharp enough to cut through paint and into metal: Thursday, Week 2. She had heard about the car that morning, walking back from the dining hall, and had spent six hours telling herself it was coincidence before her body refused to believe it anymore and woke her up at 2am to deal with it properly.\nShe reached for her notepad.\nSeven days. Exact.\nShe drew a horizontal line across the page. Marked the first Thursday with a small circle. Marked the second with another. The line between them was exactly the length of one week. If the pattern continued, something would happen again in seven days. Another Thursday.\nShe stared at the page until her eyes adjusted fully to the dark. Then she wrote one question underneath both circles: same person, or same schedule?\nBecause those were two different things entirely.\nIn the morning she found Ibrahim at the back of the library during the first free period, working through a past questions booklet with a pencil and no eraser. She had noticed that about him. He never erased. Whatever he wrote the first time, he committed to it.\nShe set her bag down across the table without asking.\n"I need to ask you something," she said, keeping her voice low enough to stay under the librarian''s radar.\nIbrahim looked up. He did not look surprised to see her. She was not sure he was capable of looking surprised.\n"You were in the computer lab last Thursday," she said. "During the window when the database was accessed."\nHe held her gaze without blinking. "Yes."\n"What were you doing there?"\n"Past questions. The school archive has WAEC materials going back twelve years. I needed the 2019 maths paper." He tapped the booklet in front of him. "I can show you the login record for the archive access if the lab still stores it."\n"Do you know they can retrieve it?"\n"I know because I asked Emeka to pull it for me on Friday before the story got around." He paused. "I assumed someone would come asking."\nShe studied him. He had been waiting for this conversation. Not with dread. With preparation. There was a difference.\n"Do you know about the car?" she asked.\nSomething shifted behind his eyes. Brief and controlled, but there. "Mr. Adeniyi''s Camry. Yes. I heard."\n"Where were you Thursday afternoon? Yesterday."\n"Classroom. Extra lesson with Mr. Okafor. I stayed an extra forty minutes after because he offered to walk me through the June 2023 Further Maths paper." He tilted his head slightly. "You can ask him."\nShe wrote nothing down. Not in front of him. "I will," she said.\nShe picked up her bag and left him there with his pencil and his commitment to never erasing anything.\nMr. Okafor confirmed the extra lesson without hesitation. Forty-five minutes. Ibrahim had left at 5:10pm. The car, according to the report circulating among the junior prefects, had been found at 4:30pm.\nSo Ibrahim had not done it.\nDamilola stood outside the staffroom and felt the ground shift slightly under the logic she had been building.\nShe pulled out her notepad and looked at the two circles on the horizontal line. If Ibrahim was not the thread connecting both incidents, then something else was. Something or someone else had been present on both Thursdays, and she had been so fixed on the new face in the room that she had almost missed the older presence hiding behind it.\nShe flipped back to the lab sign-in photograph on her phone. The fifteenth name again. The teacher with no recorded departure time.\nMr. Eze-Nwosu. Vice Principal of Academics. The man who had written the official notice calling the hack a "routine security review." The man who had, in effect, named the tone of the entire story before any student could form their own opinion of it.\nShe thought about that for a long time.\nThursday came exactly on schedule.\nDamilola spent the morning in class and the afternoon moving. She was not sure what she was looking for, only that the pattern demanded she look. She checked the staff car park at 3pm. She walked past the admin block twice. She sat on the wall near the school gate pretending to read a novel for forty minutes.\nAt 4:17pm, she saw the school secretary step out of the admin office and tape a notice to the board outside it. Damilola crossed the courtyard and read it before three other students had gathered.\nIt was brief. Clinical. Formal in the way that official notices always are when they are trying to dilute something.\nThe office of the Deputy Principal hereby confirms receipt of an anonymous letter. Contents of the letter are currently under review. Students are advised to disregard unverified information circulating on social media.\nDamilola read it twice.\nAn anonymous letter. Week 3. Thursday.\nShe took a photograph of the notice. Her hand was completely steady because she had trained herself years ago not to let her hands show what her chest was doing.\nBehind her, a voice said: "I heard it mentions a student. Someone who transferred in recently."\nShe turned. It was Amara from the registration office, arms folded, watching her with an expression that was half gossip and half something more deliberate.\n"Where did you hear that?" Damilola asked.\nAmara shrugged. "Everyone is saying it."\n"Everyone." Damilola looked back at the notice. "Or someone?"\nAmara did not answer. When Damilola turned around again, she was already walking away.','\n',char(10)),986,0,1,NULL,'2026-04-26 08:55:35','2026-04-26 08:44:24','2026-04-26 08:55:35','2026-04-26T09:00:00.000Z',1,NULL);
INSERT INTO "chapters" ("id","novel_id","chapter_number","title","content","word_count","is_premium","is_published","audio_url","published_at","created_at","updated_at","scheduled_release_at","part_number","season_id") VALUES(639,32,3,' What the Database Knew',replace('The anonymous letter had named Ibrahim Suleiman by full name, and that changed everything about the story Damilola was trying to tell.\nNot because it made him guilty. Because it made him useful to someone.\nShe spent Friday morning thinking about the difference. An anonymous letter did not arrive by accident. Someone had written it, sealed it, delivered it to the deputy principal''s office, and walked away clean. That required timing. That required knowledge of how this school processed information and how fast a name could travel once the administration touched it. Whoever sent the letter understood Federal Government College Abuja the way you only understood a place after years inside it.\nIbrahim had been here for two weeks.\nShe went back to Emeka after school.\nHe was in the computer lab again, which was no longer surprising. Since the breach, he had been spending every free period auditing the system in layers, the way someone rebuilds a wall after discovering the foundation was not where they thought it was. He looked tired in the specific way that people look when they have been solving the same problem for too long without finding the answer.\n"I need to understand the database better," Damilola said. "Not who accessed it. What they accessed."\nEmeka swiveled his chair to face her. "The system logs the access points. Not the specific files viewed within a session."\n"So we know someone was inside but not what they were looking at."\n"Correct."\n"What is stored in the results database? Walk me through it."\nHe thought for a moment. "Student academic records. End of term grades going back six years. Internal assessment scores. Teacher evaluation notes attached to student profiles. And a separate restricted folder for disciplinary records. That one requires a second-level password."\nDamilola looked up from her notepad. "Disciplinary records."\n"Yes."\n"Would those records include transfers? Students who left under difficult circumstances?"\nEmeka''s expression shifted. Not much. Just enough. "They would include any formal incident that went through the school administration."\nShe let that settle. "Has anyone else asked you about this? Since the breach?"\n"Vice Principal Eze-Nwosu came in on Friday afternoon," Emeka said. "He asked me to hold off on filing the full incident report until Monday. Said he wanted to review it personally first."\n"And you agreed?"\n"He is the vice principal."\nDamilola wrote that down and underlined it once. "What time did he come in?"\n"Around 4pm." Emeka paused. "He stayed until almost 5:30. I left before him."\nShe kept her voice level. "So he was alone in the lab for some time after you left."\nEmeka said nothing. But his jaw tightened in a way that meant he had already thought about that and had not known what to do with it.\nShe found Ibrahim on the football field after the final bell, not playing but sitting on the concrete edge of the stands with his Further Maths textbook open on his knees. The late afternoon light was flat and bright and it made everything on the field look exposed. There was nowhere to have a private conversation out there, which she suspected was exactly why he had chosen it.\nShe sat beside him without preamble. "The letter mentioned something specific about King''s Academy."\nHe did not look up from the book. "I know."\n"What happened there?"\nHe was quiet for long enough that she thought he had decided not to answer. Then he closed the textbook slowly, keeping his finger in the page like he intended to return to it very soon.\n"A student''s internal scores were altered," he said. "Someone accessed the academic database and changed three scores. The student moved from a failing position to a pass. It was discovered two weeks before end of term exams."\nDamilola kept very still. "And they thought it was you."\n"The school investigated. They found no evidence connecting me to it." He finally looked at her. "I was cleared. Officially. The letter your deputy principal received is either incomplete or deliberately selective about that part."\n"Why would someone send it here? Why now?"\n"Because I transferred." He looked back at the field. "Whoever sent it knew that a cleared name sounds almost as suspicious as a guilty one when it arrives attached to a fresh incident. They were betting on context doing the work for them."\nShe thought about what Emeka had told her. The disciplinary records folder. The second-level password. The fact that a disciplinary record from King''s Academy would only appear in this school''s system if someone had requested it through official channels. And the only person with the access level to request inter-school disciplinary records was a member of senior administration.\nShe kept that thought sealed behind her expression.\n"Why didn''t you defend yourself when the letter spread?" she asked. "When students started talking, you went quiet."\n"I went quiet before the letter," he said. "Going loud would not have changed anything. It never does. People believe the story that arrived first."\nShe stood and pulled her bag onto her shoulder. "One more question. At King''s Academy, before the investigation was closed. Was there anyone on staff who pushed particularly hard to keep the case open? Someone who seemed to want it to remain unresolved?"\nIbrahim''s stillness changed quality. Something behind his eyes cooled and focused at the same time.\n"There was a visiting administrator," he said slowly. "He came in during the investigation. External review, they called it. I never learned which school he came from."\nDamilola kept her voice very steady. "What did he look like?"\nIbrahim reached into his backpack and produced his phone. He opened a photograph and held it out to her without a word.\nShe looked at the image for three full seconds. The man in it was standing in a school corridor, talking to someone off-camera, relaxed and authoritative in the way that people are when they have been in charge of something for a very long time.\nShe had seen that face every day for three years.\nHe was standing outside the staffroom in the photograph. But she knew exactly which office he occupied in this building.','\n',char(10)),1028,0,1,NULL,'2026-04-26 08:55:52','2026-04-26 08:45:49','2026-04-26 08:55:52','2026-04-26T09:00:00.000Z',1,NULL);
INSERT INTO "chapters" ("id","novel_id","chapter_number","title","content","word_count","is_premium","is_published","audio_url","published_at","created_at","updated_at","scheduled_release_at","part_number","season_id") VALUES(640,32,4,' The Letter',replace('By Saturday morning the letter was no longer anonymous. It was a story, and the school was telling it the way teenagers tell every story: loudly, incompletely, and with total confidence.\nDamilola heard three different versions before breakfast. In the first, Ibrahim had hacked two schools before this one and King''s Academy had covered it up for money. In the second, he had been expelled and his family had bribed someone in the federal ministry to get him a clean transfer. In the third, which was the most creative and therefore the most widely believed, he had changed his own grades, then changed the grades of four other students to hide the trail, and a teacher had died of stress complications shortly after discovering it.\nShe sat down across from her roommate Simi in the dining hall and watched the story move through the room. It was traveling in the way that the worst stories always did: not from person to person but from table to table, growing a little with each crossing, shedding whatever nuance it had started with.\nIbrahim was not at breakfast. She noted that.\nSimi leaned forward. "You heard about the transfer boy?"\n"I have heard several things about the transfer boy," Damilola said carefully.\n"They are saying he did the same thing here. The database thing."\n"Who is they?"\nSimi blinked. "Everyone."\nDamilola picked up her fork. There was that word again. Everyone. A word that meant no one had to take responsibility for being the origin of anything.\nShe found Ibrahim''s hostel block at 9am under the pretense of returning a textbook to a student in Block C. She did not need a pretense. It was Saturday and movement between blocks was unrestricted, but she had learned a long time ago that visible reasons kept people from asking invisible questions.\nIbrahim was sitting on the steps outside the block entrance. He had the textbook open again but he was not reading it. He was watching the courtyard.\n"You did not go to breakfast," she said.\n"I was not hungry."\nShe sat beside him on the step. The morning was loud with the usual Saturday noise: music from an upper window, two boys arguing about a football match, the sound of someone dragging a bucket across concrete. Normal sounds. Except that twice in the time it took her to sit down, a group of students had walked past and slowed their pace, turning to look at Ibrahim with the particular expression of people who have decided something about someone and are checking their decision against the physical evidence.\nIbrahim had noticed. He noticed everything. He simply refused to show that he had.\n"The letter is spreading," she said.\n"I know."\n"The version traveling around the hostel is not accurate."\n"It never is." He turned a page he had not read. "What version are you carrying, Lola?"\nShe looked at him directly. "The one where you were investigated at King''s Academy, cleared officially, and someone has followed you here with a selectively edited version of that record specifically designed to make cleared sound like guilty."\nHe was quiet for a moment. "That is a very precise version."\n"I talked to Emeka again. The disciplinary records folder in the database requires a second-level password. Standard students cannot access it. Teachers with general clearance cannot access it. Only senior administration can request inter-school records through official channels." She kept her voice low and steady. "The person who sent that letter had access to your King''s Academy disciplinary file. Which means the person is not a student."\nIbrahim set the textbook flat on his knees. The gesture was small but it meant he was no longer pretending to read.\n"You identified the man in the photograph," he said.\n"Yes."\n"And?"\n"I am not going to say the name outside four walls," she said. "Not yet. Not until I have something that cannot be explained away."\nHe nodded slowly. She could see him recalibrating, revising whatever calculation he had been running about how much to tell her and how fast.\n"He was at King''s Academy for four days," Ibrahim said. "He told the investigating panel that the evidence against me was stronger than the official record showed. The panel disagreed. He did not accept that quietly."\n"What did he do?"\n"He filed a separate note. A personal assessment, they called it. It was attached to my record as a dissenting observation. Not binding. But there." He paused. "It would be the first thing anyone read if they pulled my file."\nDamilola thought about that. A dissenting observation. Not enough to override a cleared verdict but enough to seed doubt in anyone who came after. A slow-release mechanism. A story waiting for the right moment to be activated.\nShe looked across the courtyard. Three junior students were standing near the water point, watching Ibrahim the way people watch something they have been told to be afraid of.\n"They are going to make your life here very difficult," she said.\n"They already are."\n"I need more time. To build what I have into something solid enough that it cannot be dismissed." She turned to face him fully. "I need you to do something uncomfortable."\n"What?"\n"Nothing. For now. Do not defend yourself publicly. Do not confront anyone. Do not give them a reaction to photograph and circulate."\nHis jaw worked. "You are asking me to let it happen."\n"I am asking you to let me work." She held his gaze. "Can you do that?"\nHe looked at her for a long moment. Then he picked up the textbook again.\n"You have one week," he said. "After that, I handle it my own way."\nShe stood and shouldered her bag. She had taken four steps toward the block entrance when his voice reached her, quieter than before.\n"Lola. Be careful about who knows what you are doing."\nShe turned.\n"Someone sent that letter knowing exactly when to send it and exactly whose desk it would land on." His eyes were steady. "That means they know how this school works from the inside. And if they are watching me, they are also watching anyone who gets close to me."\nThe door to Block C opened behind her. Vice Principal Eze-Nwosu stepped out, paused when he saw her, and smiled the particular smile of someone who has never been questioned about anything in their life.\n"Damilola," he said warmly. "What brings you to the boys'' block?"','\n',char(10)),1081,1,1,NULL,'2026-04-26 08:56:10','2026-04-26 08:47:17','2026-04-26 08:56:10','2026-04-26T09:00:00.000Z',1,NULL);
INSERT INTO "chapters" ("id","novel_id","chapter_number","title","content","word_count","is_premium","is_published","audio_url","published_at","created_at","updated_at","scheduled_release_at","part_number","season_id") VALUES(641,32,5,'His Side',replace('Vice Principal Eze-Nwosu had a gift for making ordinary things feel like transactions.\nHe stood in the doorway of Block C with his hands clasped in front of him and asked about her welfare, her studies, her mother who had once served on the PTA three years ago. He remembered her mother''s name. He used it twice. And the whole time he was speaking, his eyes were doing something his mouth was not, moving between her and Ibrahim with a precision that felt nothing like casual.\nDamilola told him she had been returning a textbook. She even produced it from her bag, a Further Maths collection she had borrowed from the library the previous evening specifically so she would have something to produce if she needed it. He looked at the book. He looked at her. He smiled in the way that certain adults smile when they are not surprised by anything you have said but want you to feel as though they are granting you something by accepting it.\n"Good girl," he said. "Enjoy your Saturday."\nHe went back inside.\nShe walked away from the block at a pace that was normal and unhurried, and she did not write anything in her notepad until she had turned the corner behind the language block and was fully out of sight.\nThen she wrote: he was not coming out. he was already there. how long had he been standing behind that door?\nShe spent the afternoon going backward.\nNot through her notes about the incidents. Through her notes about herself. Every journalist had them, the record of how a story started. Mrs. Adaora had insisted on it from the first day of Press Club. Always know where your instinct came from, she used to say. Because sometimes it is not instinct. Sometimes it is a nudge someone gave you so gently you mistook it for your own idea.\nDamilola opened the first page of the notebook she had started the day Ibrahim arrived.\nShe read it slowly.\nShe had written down his name during assembly. She remembered that. But she had not gotten his name from the assembly. She had gotten it from a conversation during first period. She had written name from grapevine in the margin and moved on without examining that further because grapevines were background noise. They were always present. They did not require sourcing.\nBut now she sat with that.\nWho had said his name first? She replayed the morning of Ibrahim''s arrival. The corridor outside the SS2 classroom. The group near the noticeboard. Someone talking in that specific tone that people use when they want the information they are spreading to feel accidental.\nShe could not pull the face.\nThat bothered her more than anything had bothered her in weeks.\nShe went back to Ibrahim at 5pm. He was still on the steps. He had moved through half the textbook in her absence, and she knew by now that this was not performance. The mathematics was actual comfort.\nShe sat down without a greeting. "I need to ask you something different."\nHe waited.\n"The morning you arrived. Did anyone introduce themselves to you before assembly? Anyone who seemed particularly interested in making sure you were seen? Noticed?"\nIbrahim looked at her with a new quality of attention. "What are you actually asking?"\n"I am asking whether someone made sure I was looking at you before I decided to look at you myself."\nThe silence between them changed texture. He closed the textbook.\n"There was someone," he said. "A prefect. He came to the hostel the night I arrived. Welcomed me, helped me find the dining hall schedule, pointed out which teachers to watch out for. Very warm. Very helpful." He paused. "He mentioned your name. Said the school journalist was thorough and that new students sometimes found themselves in her articles whether they cooperated or not."\nDamilola''s pen stopped moving.\n"He said it lightly," Ibrahim continued. "The way you say something true so that it does not sound like a warning. But I noticed it because I have learned to notice when someone is pre-explaining something." He looked at her steadily. "I think someone told you to look at me, Lola. And I think they did it the same way they did everything else in this sequence. Early enough that by the time the incident happened, your eye was already trained on me."\nShe did not respond immediately. She was thinking about the three versions of the letter story she had heard at breakfast. She was thinking about Amara from the registration office, who had appeared at exactly the right moment outside the admin board. She was thinking about how, in every step of this investigation, information had arrived slightly ahead of her. Not behind her. Never behind her. Always arriving just in time to keep her moving in a specific direction.\nShe had thought she was following a trail.\nShe was beginning to understand that the trail had been following her.\n"Who is the prefect?" she asked.\n"Daniel Osagie," Ibrahim said. "SS3. Head of the Mathematics Club."\nShe knew Daniel. Everyone knew Daniel. He was one of those students who existed in every teacher''s good books simultaneously, the kind of reliable, warm, consistent presence that schools held up as evidence that they were doing something right. He had been at Federal Government College Abuja since JSS1. He had helped paint the school mural in JS2 and his photograph was still on the wall outside the principal''s office.\nHe had also, she now recalled, been the person standing nearest to her the morning she first wrote Ibrahim''s name in her notepad.\nShe looked down at the page in front of her. Two names at the top. The line down the center. She had drawn it in episode one thinking she was separating two suspects.\nShe saw now that the line had been separating something else entirely.\nThe investigation she thought she was running. And the one she had actually been placed inside.','\n',char(10)),1006,1,1,NULL,'2026-04-26 08:56:48','2026-04-26 08:48:25','2026-04-26 08:56:48','2026-04-26T09:00:00.000Z',1,NULL);
INSERT INTO "chapters" ("id","novel_id","chapter_number","title","content","word_count","is_premium","is_published","audio_url","published_at","created_at","updated_at","scheduled_release_at","part_number","season_id") VALUES(642,32,6,'Old School',replace('Getting a phone number for King''s Academy Kaduna took Damilola forty minutes and three lies.\nThe first lie was to Amara in the registration office, where she said she was following up on a transfer documentation error for a class assignment on school administrative systems. Amara gave her the number for the King''s Academy administrative block without blinking, which told Damilola two things: that Amara was either genuinely helpful or carefully so, and that the number was not difficult to obtain, which meant whoever had pulled Ibrahim''s file had not needed Amara to do it.\nThe second lie was to the woman who answered the King''s Academy phone, to whom she introduced herself as a student welfare officer conducting a routine inter-school check. The woman put her on hold for six minutes.\nThe third lie was to herself, when she told herself she was not nervous.\nThe person who eventually came to the phone was a man with a voice that sounded like it had been worn smooth by decades of administrative patience. He identified himself as Mr. Lawal, assistant registrar.\n"I am calling about a former student," Damilola said. "Ibrahim Suleiman. He transferred to our school recently and we are trying to complete his file."\nA pause. Brief but textured. "What specifically do you need?"\n"His academic standing at the time of departure. And whether there were any unresolved conduct matters."\nAnother pause, longer this time. She heard the sound of something moving, papers or a keyboard, and then Mr. Lawal said: "Ibrahim Suleiman was among our top three students in SS2. His academic record is clean. He was investigated regarding an internal database incident last term and formally cleared. The case is closed."\n"Closed completely?"\n"Completely. No conditions attached. The investigation found no evidence of his involvement."\nShe wrote that down even though she already knew it. Hearing it confirmed by a voice from the source still mattered. "Was there anything attached to his file afterward? A personal assessment or a dissenting note from any external reviewer?"\nThe silence this time was different. Careful rather than searching.\n"Where did you say you were calling from?" Mr. Lawal asked.\nShe repeated the lie about the welfare office.\n"I see." He did not sound convinced. "There was a note attached, yes. Filed by a visiting administrator who sat in on the final review panel. It was not binding and the panel did not adopt its conclusions."\n"Can you tell me the name of the visiting administrator?"\n"That information is internal."\n"I understand. Can you tell me which school he represented?"\nA long pause. Then: "Federal Government College Abuja."\nDamilola pressed the pen so hard into the notepad that the next three pages carried the impression of what she wrote. She kept her voice completely even. "Thank you, Mr. Lawal. You have been very helpful."\nShe ended the call and sat on the edge of her bunk for three minutes without moving.\nIt was confirmed now. Eze-Nwosu had been at King''s Academy during the investigation. He had filed a dissenting note against a cleared verdict. He had returned to Abuja and at some point, whether through official channels or through the access he held in this school''s own system, he had obtained a copy of Ibrahim''s disciplinary record. And then Ibrahim had transferred here, and the incidents had begun, and an anonymous letter had arrived on the desk of the deputy principal, a letter citing a record that only someone with Eze-Nwosu''s clearance could have retrieved.\nThe shape of it was clear now. But clear shapes were not evidence. They were arguments, and arguments could be dismantled.\nShe needed something that could not be dismantled.\nShe found Mrs. Adaora in the Press Club room on Sunday afternoon, which was the only place the journalism teacher spent her Sunday afternoons. She was marking scripts from the junior correspondents and she looked up when Damilola came in with the specific expression she reserved for students who were about to complicate her weekend.\n"Sit," she said, without being asked whether she had time.\nDamilola sat. She did not open her notepad. What she was about to ask required a conversation, not documentation.\n"If a senior administrator at a school filed a note against a cleared investigation verdict at a different school, and then that same administrator appeared to have obtained the cleared student''s disciplinary record through official channels and used it to damage the student at a new school," she said carefully, "what would you call that?"\nMrs. Adaora set her red pen down. "I would call it several things. Professionally I would call it a misuse of inter-school administrative access. Legally I would call it a matter for the ministry''s school oversight board." She looked at Damilola steadily. "Personally I would call it the kind of story that ends careers. And the kind of story that gets young journalists hurt if they move on it without enough protection."\n"What counts as enough protection?"\n"At minimum? A second source confirming the connection between the administrator and the document. Physical or digital evidence of the access. And an editor old enough to take the heat if the story is challenged." She paused. "You are missing at least two of those three things. Am I wrong?"\nDamilola said nothing.\n"I thought so." Mrs. Adaora picked up her pen. "You are close to something real. I can see it in how tightly you are holding that notepad. But close is where people make the mistakes that undo everything that came before." She looked back at her marking. "Come back when you have the second source."\nDamilola stood. She was at the door when Mrs. Adaora spoke again without looking up.\n"Damilola. Whatever you have found, stop keeping it only in that notepad."\nShe turned. "What do you mean?"\n"I mean that paper can be taken. Photographs can be deleted." The teacher''s pen moved across the page. "Make copies. Put them somewhere that is not your room and not your bag and not anywhere a person who knows your routine would think to look first."\nDamilola stood in the doorway for a moment.\nThen she heard footsteps in the corridor outside, slow and deliberate, pausing just before they reached the Press Club door.','\n',char(10)),1045,1,1,NULL,'2026-04-26 08:57:05','2026-04-26 08:50:06','2026-04-26 08:57:05','2026-04-26T09:00:00.000Z',1,NULL);
INSERT INTO "chapters" ("id","novel_id","chapter_number","title","content","word_count","is_premium","is_published","audio_url","published_at","created_at","updated_at","scheduled_release_at","part_number","season_id") VALUES(643,32,7,'The Wrong Witness',replace('The footsteps in the corridor had belonged to a JS3 student looking for the bathroom, which was either the truth or the most useful lie available, and Damilola had spent Sunday night deciding which one it was.\nBy Monday morning she had decided it did not matter. What mattered was that Mrs. Adaora was right about the notepad, and she had spent Sunday night photographing every page and uploading the files to an email draft she would never send, sitting in an account with a username that meant nothing and a password she had never written down anywhere.\nThe witness''s name was Precious Okoro.\nDamilola had not known about her until Monday second period, when Simi mentioned, with the casualness of someone reporting weather, that the JS2 girl who had told the hostel prefects she saw Ibrahim near the staff car park on the Thursday of the vandalism had apparently stopped telling that story.\n"What do you mean stopped?" Damilola asked.\n"I mean she is saying she was confused. That she mixed up the day." Simi shrugged and turned a page of her textbook. "Her senior sister told my bunkmate."\nDamilola was out of her seat before the bell rang.\nPrecious Okoro was twelve years old and small for it, the kind of student who sat at the front of class not from eagerness but from a long habit of making herself easy to overlook. Damilola found her behind the Home Economics block during the short break, eating a meat pie alone and reading a novel with the focused intensity of someone who had found a good hiding spot and intended to protect it.\nShe looked up when Damilola approached and her expression did something complicated. Not guilt. Not fear exactly. The look of someone who had recently been given instructions they were not sure they could follow convincingly.\nDamilola sat on the low wall beside her. "I am not here to pressure you," she said, and meant it.\nPrecious said nothing.\n"I heard you changed your account about what you saw on Thursday two weeks ago. I just want to understand what happened."\n"I was confused," Precious said. The words were flat and rehearsed and she seemed to know they were flat and rehearsed, which was worse than if she had delivered them with confidence.\n"Confused about the day or about what you saw?"\nA pause. "Both."\nDamilola looked at the half-eaten meat pie in the girl''s hand. Then at the novel. Then at the careful way Precious was holding herself, shoulders slightly turned inward, the posture of someone who had been told that what they said could cause problems for people larger than themselves.\n"Did someone talk to you about this?" Damilola asked quietly. "Before you changed your account?"\nPrecious peeled a strip of pastry from the edge of the meat pie and did not eat it. "My house mistress called me in Saturday evening. She said students should not be spreading unverified information about other students because it could constitute a conduct violation."\n"Your house mistress."\n"Yes."\n"Did your house mistress suggest that what you had said was unverified?"\nPrecious looked at her for the first time directly. She was twelve and trying hard to look younger than that, and it was not working. "She said I should think carefully about whether I was certain of what I saw before I kept repeating it."\nDamilola kept her face neutral. "And are you certain?"\nThe girl looked away again. Down at the meat pie. Across at the wall. Anywhere that was not Damilola''s face. Then, very quietly, so that the words barely cleared the space between them: "I saw what I saw."\nDamilola did not write it down. She did not reach for her notepad. She simply sat with it.\n"Thank you," she said. She stood up to leave.\n"It was not the boy," Precious said suddenly. The words came out faster than she had planned them, slightly too loud for the space. She caught herself and dropped her voice. "I saw him near the car park, yes. But he was walking away from it. He came from the direction of the classroom block and he was walking toward the hostel. He did not stop at the cars. He did not even look at them."\nDamilola sat back down.\n"There was someone else," Precious continued. The meat pie had gone completely forgotten in her hand. "Standing between the cars. I noticed because they were standing very still, which people usually do not do in a car park unless they are waiting for something. I thought they were waiting for a staff member." She paused. "I could not see them clearly. The angle was wrong."\n"Man or woman?"\n"Man. I think. The build."\n"Staff or student?"\n"The way they were standing." Precious stopped. Something crossed her face, a calculation running beneath the surface of it. "Like someone who was used to being in charge of things."\nDamilola looked at the girl carefully. "Why did you not say this the first time? When you told the hostel prefects?"\nPrecious was quiet for a moment. "Because the first time I thought I was helping by saying I had seen the transfer boy near the cars. Everyone was already saying it was him. I thought I was confirming something that was already decided." She folded the uneaten pastry strip carefully in her palm. "I did not understand until later that confirming something already decided is not the same as telling the truth."\nThe bell rang for the end of short break. Around the corner, the sound of three hundred students beginning to move filled the air.\nPrecious stood, tucked her novel under her arm, and looked at Damilola with an expression that was twelve years old and also somehow much older than that. "Please do not put my name in anything," she said.\nShe walked away before Damilola could answer.\nDamilola sat on the wall alone and thought about a man standing very still between cars, in a car park he had every institutional right to be in, waiting for something he had arranged to happen.','\n',char(10)),1024,1,1,NULL,'2026-04-26 08:57:39','2026-04-26 08:51:12','2026-04-26 08:57:39','2026-04-26T09:00:00.000Z',1,NULL);
INSERT INTO "chapters" ("id","novel_id","chapter_number","title","content","word_count","is_premium","is_published","audio_url","published_at","created_at","updated_at","scheduled_release_at","part_number","season_id") VALUES(644,32,8,' Someone Is Reading My Notes',replace('The email draft was gone.\nNot the account. Not the other files sitting in the inbox from three years of Press Club correspondence. Just the draft. The one with no recipient, no subject line, and photographs of every page of her notepad attached to it in sequence.\nDamilola sat in the computer lab on Tuesday evening and read the empty drafts folder three times as though the files might reappear if she looked with enough patience. They did not. She checked the trash folder. She checked the sent folder. She logged out and logged back in and checked again.\nGone.\nShe sat back in the chair and looked at the ceiling and breathed through the specific feeling of realizing that something you believed was invisible had been seen completely.\nThe account had no connection to her name. She had created it two years ago during a project on digital security for the Press Club, using a school desktop during a free period, and she had never accessed it from her personal phone or from any device that carried her identity. She had typed the username and password from memory every time, never written them down, never saved them to a browser.\nShe thought about all of that very carefully.\nThen she thought about the fact that she was currently sitting in the same computer lab where the original breach had occurred.\nShe logged out, cleared the browser history, wiped the session, and left.\nShe did not go to Emeka. Not yet. Emeka was useful and she trusted him to a point, but trust had a geography now, a map with borders she was drawing and redrawing daily. Instead she went to the one place in the school where she could think without anyone finding her presence remarkable.\nThe Press Club room was empty at 6pm. She had a key from Mrs. Adaora and she used it, locking the door behind her and sitting on the floor with her back against the wall beneath the window so that she was below the sight line of anyone passing outside.\nShe opened her notepad and started from the beginning.\nSomeone had accessed a draft email account with a username that existed nowhere in writing and a password she had never recorded. There were two ways that was possible. One: they had watched her type it. Which meant physical proximity during one of the three times she had logged in. Two: they had access to something she did not know she had left behind. A session cookie. A browser cache she had not cleared thoroughly enough. A keylogger on one of the school computers.\nShe thought about the computer lab sign-in sheet. She had photographed it the first week. She had been inside the lab four times since then, always during periods when other students were present. She had logged into the draft account from the lab twice and from the library terminal once.\nShe turned to a clean page and wrote out the timeline of every lab and library visit. Then she wrote, beside each one, who else had been present.\nOne name appeared in proximity to all three visits.\nNot Eze-Nwosu. Not Daniel Osagie. Someone she had noticed without cataloguing, the way you noticed furniture, a permanent and unremarkable feature of a room you passed through regularly.\nKelechi Nwankwo. SS3. He was always in the computer lab. Everyone knew Kelechi was always in the computer lab. He was one of those students whose omnipresence in a specific location had become so consistent that it had become invisible, which was a very useful quality if you were trying to watch things without being seen watching them.\nShe thought about Emeka saying a keylogger would require someone with enough system knowledge to install it without leaving obvious traces. She thought about Kelechi, who sat in the back row of the lab during every free period, who had offered twice to help her when she looked confused at a terminal, whose offers she had politely declined.\nShe wrote his name. Then she drew a line connecting it to Daniel Osagie, who ran the Mathematics Club, of which Kelechi was the secretary.\nThen she drew a line from Daniel Osagie to Eze-Nwosu, who had been the staff patron of the Mathematics Club for four consecutive years.\nShe stared at the diagram for a long time.\nShe had been thinking about this as one person working alone. A senior administrator with access and motive, moving pieces from above. But access at every level of this operation required more than one set of hands. The keylogger required someone inside the lab system. The witness required someone with the standing to speak to a house mistress. The stories at breakfast required someone close enough to student networks to seed a narrative overnight.\nEze-Nwosu had not been doing this alone. He had been doing it through people who owed him things, people he had cultivated over years, people who were so woven into the fabric of the school that pulling on any one of them would feel, to most observers, like pulling on the school itself.\nShe thought about what Ibrahim had said on the football field. They are watching me. And then: They are also watching anyone who gets close to me.\nShe had interpreted that as a warning about being seen with Ibrahim. She understood now it was more specific than that. They had not just been watching. They had been inside her investigation. Reading her notes. Tracking her movements. And they had let it run long enough to map exactly how much she knew.\nThe question she could not answer yet was why.\nWhy let her get this far? Why not shut it down earlier, scare her off with something small, make the story less interesting before it became dangerous? Unless letting her run was itself the strategy. Unless she was still being aimed, even now, in a direction she had not yet identified.\nShe looked at her diagram again. The three lines meeting at Eze-Nwosu''s name at the center.\nThen she looked at the space above his name. The space she had left blank because she had assumed, from the beginning, that he was the top of the structure.\nShe picked up her pen slowly.\nWho does Eze-Nwosu owe?\nThe door handle turned.\nSomeone was trying to get in.','\n',char(10)),1063,1,1,NULL,'2026-04-26 08:58:00','2026-04-26 08:52:27','2026-04-26 08:58:00','2026-04-26T09:00:00.000Z',1,NULL);
INSERT INTO "chapters" ("id","novel_id","chapter_number","title","content","word_count","is_premium","is_published","audio_url","published_at","created_at","updated_at","scheduled_release_at","part_number","season_id") VALUES(645,32,9,'The Closest One',replace('The door opened and it was Simi, holding a bag of chin-chin and looking mildly offended at finding the room locked.\n"Why are you sitting on the floor in the dark?" she asked.\nDamilola closed the notepad. "Thinking."\n"You are always thinking." Simi dropped into the nearest chair and offered the bag across. "Come and eat something. Your thinking is making you look like a person who has not slept."\nDamilola took one piece of chin-chin and chewed it without tasting it. She watched Simi settle in, comfortable and unbothered, and felt the particular loneliness of carrying a weight that could not be shared yet. Not because she did not trust Simi. Because trusting the wrong person at the wrong moment in this particular story had already cost Precious Okoro a witness statement and cost Damilola an email draft she could not recover.\n"I am fine," she said. "Go ahead. I will follow you."\nShe waited until Simi''s footsteps faded down the corridor. Then she turned back to the diagram and the blank space above Eze-Nwosu''s name.\nWho does Eze-Nwosu owe?\nShe had been asking the wrong version of the question. Owing implied debt, and debt implied a transaction. But the structure she was looking at had not been built on debt. It had been built on trust. Daniel Osagie trusted Eze-Nwosu because Eze-Nwosu had nurtured his academic career since JSS2. Kelechi trusted him because Eze-Nwosu had recommended him for a national mathematics competition two years ago. Trust was cleaner than debt. It did not need to be repaid because it felt like loyalty.\nSo the question was not who Eze-Nwosu owed. The question was who, above him, he was loyal to.\nShe thought about every interaction she had reported to Mrs. Adaora. Every piece of the story she had walked into that room and laid on the table. She had gone to her teacher for guidance and she had received it, specific and useful and perfectly calibrated to keep the investigation moving at exactly the pace it was moving. Come back when you have a second source. Make copies. Put them somewhere safe.\nShe had followed every instruction.\nShe opened her phone and went back through three weeks of Press Club notices. Mrs. Adaora sent them every Friday through the school''s internal mail system. Damilola had read them the way she read all routine correspondence, present but not suspicious. She scrolled back to the week of Ibrahim''s arrival.\nThe Friday notice that week had contained one unusual item. A reminder that all student press investigations required faculty sign-off before publication, and that journalists should keep their supervising teacher informed of any story in development. Standard policy. She had read it as bureaucratic maintenance and forgotten it.\nShe sat with it now.\nThe notice had gone out on Friday. Ibrahim had arrived on Tuesday. The database breach had occurred the following Thursday. The notice had told every student journalist in the school to report their investigations upward before publishing. It had arrived, she now understood, not as routine policy but as a mechanism. A guarantee that whatever Damilola found, she would carry it to the one place where it would be seen before it became a story.\nShe turned to a new page and wrote Mrs. Adaora''s name at the top.\nThen she stopped. Because writing a teacher''s name on a list of suspects was the kind of thing that could not be undone, and she needed to be more certain than she currently was before she committed it to paper.\nShe went to the filing cabinet in the corner of the Press Club room. Mrs. Adaora kept physical copies of everything, past issues, correspondence, competition entries, staff communications going back eight years. Damilola had filed half of them herself during her JSS2 induction year. She knew the system by heart.\nShe found the staff correspondence folder for the current academic year and worked backwards through it. Meeting minutes. Inter-department memos. Three letters from the principal regarding the school''s ranking in the national press club competition.\nAnd then, between a budget approval form and a maintenance request, a single sheet of paper that had been placed there recently enough that it was still flat, not yet carrying the soft crease of a document that had been filed for any length of time.\nIt was a printed email. Sent six days before Ibrahim''s arrival.\nThe sender was Eze-Nwosu. The recipient was Mrs. Adaora. The subject line read: Re: Transfer student — situation update.\nThe body of the email was four sentences. She read them twice to make sure she was reading them correctly.\nHe has confirmed the placement. The boy arrives Tuesday. The timetable will run as discussed. Ensure the journalist stays on the visible trail until we need her elsewhere.\nDamilola looked at that last sentence for a long time.\nEnsure the journalist stays on the visible trail.\nShe was the journalist. She had always been the journalist. And the visible trail was the one she had been running along for three weeks, moving through every breadcrumb that had been set out for her, reporting back to the woman who had placed them.\nShe thought about JSS1. The first day she had walked into the Press Club room and found Mrs. Adaora sitting exactly where she always sat, red pen in hand, looking at Damilola with an expression she had always read as recognition. The expression of a teacher who saw something worth developing.\nShe looked at it differently now. She thought about what it meant to identify a useful person early. To cultivate them carefully. To give them just enough skill and just enough confidence and just enough independence that by the time you needed them, they would run toward the story you had built without ever feeling the leash.\nHer pen was still in her hand. She looked down at the new page in her notepad.\nShe wrote Mrs. Adaora''s name. Then she drew a line connecting it to Eze-Nwosu. Then she sat in the dark room alone and understood, fully, what it meant to be the closest secret to someone who had never once looked like a secret at all.','\n',char(10)),1033,1,1,NULL,'2026-04-26 08:58:20','2026-04-26 08:53:50','2026-04-26 08:58:20','2026-04-26T09:00:00.000Z',1,NULL);
INSERT INTO "chapters" ("id","novel_id","chapter_number","title","content","word_count","is_premium","is_published","audio_url","published_at","created_at","updated_at","scheduled_release_at","part_number","season_id") VALUES(646,32,10,'The Story She Can''t Print',replace('Damilola left the Press Club room at 7:43pm, walked to the dining hall, ate jollof rice she could not taste, and went to bed at 9pm without speaking to anyone.\nShe lay in the dark and ran the story from the beginning.\nMrs. Adaora and Eze-Nwosu had known Ibrahim was coming before he arrived. They had a timetable. Three incidents, spaced exactly one week apart, designed not to frame Ibrahim permanently but to generate enough suspicion around him that any formal investigation would be muddy and slow. The anonymous letter had not been the conclusion of the plan. It had been the acceleration of it. Something had shifted in the third week. Something had made them move faster than the original schedule required.\nShe thought about what had changed in week three.\nShe had called King''s Academy.\nShe did not know how they had found out. She had used the office phone in the admin block on a Saturday morning, signing the outgoing call register with a name she had borrowed from a JS1 student two corridors over. But someone had been watching. Someone was always watching. And when she had called Kaduna and asked about a visiting administrator and inter-school disciplinary records, she had told them, without knowing she was telling them, exactly how close she was.\nThe letter had arrived the following Thursday. Designed to flood the school with noise at the precise moment she was getting near enough to hear something quiet.\nShe stared at the ceiling until it was 1am. Then she got up, took the notepad from under her mattress, and added one line at the bottom of the last page.\nHe has confirmed the placement.\nShe had been reading that sentence as Eze-Nwosu confirming Ibrahim''s school placement. Transfer arranged. Student incoming. But Ibrahim''s transfer had not been arranged by Eze-Nwosu. Ibrahim had transferred because of genuine family circumstances, which King''s Academy had confirmed, which Damilola had confirmed through Ibrahim himself.\nSo what placement had been confirmed?\nShe wrote the question and sat with it for twenty minutes. Then she picked up the pen again.\nHe. Not the school. Not the ministry. He.\nSomeone above both of them had confirmed something. Someone who had the authority to move pieces that even a vice principal and a journalism teacher could not move alone. Someone with reach into King''s Academy''s review process, into this school''s administrative channels, into the infrastructure that governed how student records traveled between institutions.\nThe blank space above Eze-Nwosu''s name was not empty because she had run out of evidence. It was empty because whatever was above him operated at a level she had no access to. Not yet.\nShe found Ibrahim at the library gate before first period. He took one look at her face and held the door open without being asked.\nThey sat at the back table. She placed the printed email in front of him without explanation and watched him read it.\nHe read it twice. Then he set it down and folded his hands on the table with the careful steadiness of someone managing something large in a small space.\n"How long have you known?" he asked.\n"Since last night."\n"The placement they are referring to," he said quietly. "I think I know what it is." He looked at the email again. "My father submitted a formal complaint to the federal education ministry three months ago. Against King''s Academy''s handling of the investigation. He had documentation. Correspondence between the school and an external administrator who, we believed, had interfered with the review process." He paused. "The ministry opened a preliminary inquiry. It was assigned to a committee."\nDamilola felt the shape of it arrive before he finished speaking.\n"Eze-Nwosu is on the committee," she said.\n"He chairs it," Ibrahim said. "I found out four days ago. I did not know how to tell you without sounding like I was adding fuel to a story that was already burning."\nShe looked at the email. He has confirmed the placement. Not a transfer. An assignment. Eze-Nwosu had been placed on the inquiry committee by someone with the authority to put him there, someone who needed the complaint buried, and with Ibrahim now in Eze-Nwosu''s own school, the complaint could be dismantled quietly, discredited by association with a student who had been made to look guilty enough that his father''s testimony would carry the weight of a compromised source.\nThe entire operation had never been about Ibrahim. It had been about his father''s complaint. Ibrahim had simply been the most efficient way to destroy it.\nShe sat back in her chair.\n"This is bigger than the school," she said.\n"Yes."\n"I cannot print what I have." She said it plainly, without grief. "Not yet. The email proves a connection between Adaora and Eze-Nwosu, but it proves nothing about the ministry. Without the top of the structure, printing the bottom only warns the top and gives them time to clean everything below it."\nIbrahim looked at her. "So what do you do?"\nShe thought about Mrs. Adaora. Three years of red pen corrections and after-school conversations and the particular warmth of being seen by someone you respected. She thought about how the best lies were constructed from genuine things. Mrs. Adaora had actually developed her. The skill was real. The training was real. The care had probably even been real, at some point, before it became useful.\nThat was the part that sat in her chest like a stone she could not swallow.\n"I protect what I have," she said. "I find the top. And I wait until I can print all of it at once."\nShe reached across the table and took the email back. She folded it carefully and put it in the inside pocket of her bag, against the lining, where it would not move.\nHer phone lit up on the table between them. A message from an unsaved number, seven words, no punctuation.\nWe know you were in the press room.\nShe read it once. Then she turned the phone face down and looked at Ibrahim across the table.\nHe had seen it. His jaw was tight and his eyes were steady and he looked exactly the way he had looked the first morning she had seen him in the quadrangle, calculated careful, the look of someone who had already decided how much of himself he was willing to lose.\n"Lola," he said.\n"I know," she said.\nOutside the library window, across the courtyard, Vice Principal Eze-Nwosu was walking toward the admin block with his hands clasped behind his back, unhurried, moving through the school the way a person moves through a place that has always been theirs.\nHe stopped at the edge of the courtyard. Turned his head toward the library window.\nAnd looked directly at her.','\n',char(10)),1140,1,1,NULL,'2026-04-26 08:58:35','2026-04-26 08:54:54','2026-04-26 08:58:35','2026-04-26T09:00:00.000Z',1,NULL);
INSERT INTO "chapters" ("id","novel_id","chapter_number","title","content","word_count","is_premium","is_published","audio_url","published_at","created_at","updated_at","scheduled_release_at","part_number","season_id") VALUES(647,76,1,' 6:45',replace('The danfo arrives at 6:43, which means Simi has exactly two minutes to get on before it fills and she loses her seat. She knows this the way she knows everything about her mornings: precisely, quietly, without anyone asking her to.\nShe is the fourth person in line at the Ojuelegba stop. She counts. She always counts. The conductor''s assistant, a boy of about twelve with a torn Arsenal jersey and the volume of someone twice his size, hangs off the open door and calls the route before the bus even stops moving. "Yaba! Yaba! Enter, enter!" She enters.\nHer usual seat, third row from the back on the left, is taken. She moves to the right side instead, middle position. She does not mind. From here she has a clean view of the aisle, which is actually better.\nHe boards at the second stop.\nSimi is not watching for him. She is looking at her phone, specifically at a history note she should have reviewed last night, the one about the constitutional conferences that Mr. Lawal has already told them twice will be on the exam. But she registers the shift in the bus anyway, the way three women readjust their bags, the way the conductor''s assistant calls "Move inside!" with new energy, and she looks up at the right moment the way she always does, without planning to.\nShe does not know his name. Not his real one. She knows other things.\nShe knows he takes the window seat four rows from the front on the right side. She knows the window beside it doesn''t open fully, and she has worked out that this is why he takes the aisle seat instead, because it is November and this is Lagos and a broken window on a danfo is a problem, not an aesthetic choice. She worked this out on a morning four weeks ago when the heat was particularly unreasonable and she watched him glance at the window, register the gap, and readjust without frustration. He is not the kind of person who wastes energy being annoyed about small things. She has noted this.\nShe knows his shoes. Adidas slides, white socks, always very clean in a way that shouldn''t be possible given that this is Ojuelegba at 6:45 in the morning. She had catalogued them the first Tuesday he almost stepped on her foot during boarding, when she looked down and then kept looking because something about the combination interested her. Size forty-two. She is confident in this.\nShe knows he reads. Not the same book every week. Last week, something with a cracked spine and a plain black cover, the kind of book that has been read so many times it has stopped trying to present itself. This week the cover is orange. She cannot read the title from here without being obvious about it.\nIt is not a crush. A crush involves wanting something from a person. Simi does not want anything from him. She simply notices him, the same way she notices that this danfo''s engine skips every third Tuesday, the way she notices that the chin-chin seller at Ojuelegba wears the same style of green head tie every morning but has four of them because the pattern is the same and the fabric is not. Simi notices things. It is a habit she has never been able to explain and has never needed to.\nHe mouths words.\nNot to anyone. He is looking out at the road and his lips are moving to something private, some song that lives in his left earphone and apparently also in his chest, because his shoulders move with it slightly. His right ear is always free. She noticed this in her third week on this route. Left ear in, right ear out. For the city, probably.\nThe danfo lurches.\nNot the usual kind of lurch, the one that means the driver has decided his vehicle has priority over the Keke Napep in his way and is acting accordingly. This is different. It comes from below and it travels through the floor and up through Simi''s seat, and the engine makes a sound she has never heard from this particular vehicle in four months of mornings, and she knows without anyone telling her that the sound is not good.\nThe driver speaks in Yoruba. The conductor''s assistant repeats it, louder. The bus slows, and then it stops, and Simi looks out the window and sees Carter Bridge.\nShe checks the time. 7:09.\nThe school gates close at 7:45. Mrs. Adebayo, the vice principal, signs the late register herself because she trusts no one with this task, and Simi has two lates already this term. Three means a call home.\nShe is going to be late.\nShe gathers her bag and joins the stream of passengers stepping off the bus onto the bridge. The sun is already very serious. Around her, people are calculating new routes, sucking their teeth at the driver, who stands at the front of the bus with his hands raised in the universal position of a man explaining that nothing is his fault.\n"You''re from St. Catherine''s."\nShe turns.\nHe is standing directly behind her. Danfo boy. Adidas slides. White socks. Up close, he is taller than she had estimated, and he is looking at her with the uncomplicated directness of someone who does not know he is standing inside a private world she has been building around him for four months.\n"The crest," he says, nodding at her bag. "I''m at Igbobi. I think we''re walking to the same junction."\nSimi opens her mouth.\nShe has known this person existed for four months. She knows his shoe size and his reading habits and that he lip-syncs to music with his left ear in and his right ear out. None of that prepared her for this.\nShe has no idea what to say to him.','\n',char(10)),990,0,1,NULL,'2026-04-29T02:29:41.631Z','2026-04-29 02:29:41','2026-04-29 02:29:41','2026-04-29T06:00:00.000Z',1,51);
INSERT INTO "chapters" ("id","novel_id","chapter_number","title","content","word_count","is_premium","is_published","audio_url","published_at","created_at","updated_at","scheduled_release_at","part_number","season_id") VALUES(648,76,2,' The Queue',replace('He is still waiting for her to answer, and behind them a woman with a baby strapped to her back is trying to get past, and Simi steps aside and says, "Yes. St. Catherine''s," and that is how she gets through the first four words she has ever spoken to him.\nHis name is Femi. She knows this because six weeks ago a girl had shouted it from the opposite side of the Ojuelegba stop, a short girl in a gray uniform who waved at him from across the traffic, and he had waved back, and Simi had filed it away in the part of her mind that keeps information it was never asked to keep. She has never done anything with this information because there was nothing to do with it. He was a stranger. Strangers do not need you to know their names.\nHe falls into step beside her on the bridge, which means they are walking together, which means this is happening.\n"You''ve been on that route for a while," he says. It is not a question.\n"Since September."\n"Yeah, I started August." He shifts his bag to his other shoulder. "The driver always makes it to Yaba except on Tuesdays. I don''t know what it is about Tuesdays."\nSimi does know what it is about Tuesdays. She has a theory involving the connector belt and the age of the engine, but she is not going to say this because she cannot explain knowing it without explaining the four months of quiet, systematic attention that produced it, and she has known this boy for approximately three minutes.\n"Hm," she says instead.\nThe junction is busy in the particular way Lagos junctions are busy at 7:15 on a Monday, which is to say it is loud and bright and everyone is going somewhere urgently and nobody is happy about the traffic between them and that somewhere. They join the bus queue for Yaba at the same time, Simi on the left, Femi on the right, and a danfo heading their direction pulls up before either of them has to decide whether the conversation is continuing.\nShe checks her phone on the bus. 7:31. The gates close in fourteen minutes.\nThey don''t make it.\nSimi sees the closed gates from across the street and feels the specific, sinking weight of something she cannot fix. She crosses anyway, because the alternative is standing on the pavement processing her feelings about this, and she does not have time for that. Femi crosses with her. She does not look at him but she registers the sound of his slides on the asphalt, which tells her approximately how far behind her he is, which is information she did not ask for and could not stop collecting.\nThe late register is on a table outside Mrs. Adebayo''s office, monitored by a prefect with the energy of someone who has been waiting for exactly this opportunity. Simi adds her name below seven others. Her handwriting is neat even now. She cannot help it.\n"You have nice handwriting," Femi says.\nShe gives him a flat look. He looks back at her with a mild, unashamed expression, the same way she has watched him absorb unexpected things on the danfo, a sudden stop, a phone call taken on speaker by the man beside him, the time a woman''s wig shifted and she fixed it without breaking her conversation. He does not react; he simply adjusts. It is one of the things she has noted. It is bothering her considerably right now.\n"Thank you," she says.\nThe bench outside the office seats five. There are four other students already waiting, three girls and a boy from SS2 that Simi recognizes by sight but not name. She sits at the end. Femi sits on the floor across from the bench, his back against the wall and his bag between his knees, and opens his orange book.\nSimi reads her history note.\nThis is not reading. This is holding a phone and looking at text while being aware that she is sitting three meters from a person she has observed for four months and has now spoken to. The constitutional conferences of 1953 do not stand a chance against this.\nMrs. Adebayo calls students in one at a time. The process is slow. By the time Simi is fourth in line, she has read the same sentence about the Lyttleton Constitution eleven times and retained nothing. The SS2 boy leaves the office with the look of someone who has survived something.\n"Is she bad?" Femi asks, not looking up from his book.\n"She''s thorough," Simi says.\nHe closes the book on his thumb to mark the page. It is a habit she has watched him do on the danfo, but up close she can see the thumb is careful, deliberate, like he minds the spine. "What''s your name?" he says.\nHere is the thing about being asked your name by someone whose name you already know. There is a clean version of this and a complicated version. In the clean version you say your name and they say theirs and the information is exchanged evenly and that is the end of it. She takes a breath and says, "Simi."\n"Femi," he says.\nThe silence that follows is not long. It is four seconds, maybe five. But something happens inside it, something that sits in the space between what is being said and what is not, and Simi feels it the way you feel a shift in pressure before rain. She keeps her face level. She is very good at keeping her face level.\nWhat she is not good at is what comes out of her mouth next.\n"I know," she says.','\n',char(10)),961,0,1,NULL,'2026-04-29T02:31:01.011Z','2026-04-29 02:31:01','2026-04-29 02:31:01','2026-04-29T06:00:00.000Z',1,51);
INSERT INTO "chapters" ("id","novel_id","chapter_number","title","content","word_count","is_premium","is_published","audio_url","published_at","created_at","updated_at","scheduled_release_at","part_number","season_id") VALUES(649,76,3,'Shoe Size',replace('\nThe door opens at the wrong moment, which means it opens exactly when Femi''s face is beginning to do something Simi cannot read, and Mrs. Adebayo says her name from the doorway and she has no choice but to stand and go inside and leave the two words sitting there, I know, on the bench between them like something she dropped and cannot stop to pick up.\nMrs. Adebayo''s office carries the smell of old paper and a specific kind of authority that does not need to announce itself. The vice principal does not shout. She is more efficient than that. She sits behind her desk and looks at Simi over her reading glasses and asks three questions in the measured tone of someone who already knows the answers: where was she this morning, why was she late, and does she understand that two prior lates this term means this cannot become a pattern. Simi answers each one. Mrs. Adebayo writes in her register, slides a pink late slip across the desk, and says she may go. Simi thanks her, opens the door, and steps out.\nThe bench is empty. Femi is gone. The orange book is gone. The bag he had between his knees is gone.\nShe looks at the space for two seconds and then she walks to class.\nThe rest of Monday is long in the way days are long when you have said something you cannot take back and are also not sure yet how much damage it did. In Literature, Mrs. Okafor reads a passage from Purple Hibiscus aloud and pauses at a sentence about silence and looks up at the class with the expression of a woman expecting recognition. Simi copies the sentence into her notebook because her hands need something to do.\nAt lunch, Tola sets her tray down across from her and says, "You look like someone who studied for an exam and failed it anyway."\n"I''m fine."\n"You''re saying fine the way people say fine when they are very much not fine."\nTola has been Simi''s closest friend since JSS2. She has a talent, inconvenient and accurate, for identifying the specific moments when Simi is performing composure rather than having it. She opens her Fanta and does not press. She waits. She has always been good at waiting.\n"I was late this morning," Simi says. "Mrs. Adebayo. Third late."\n"Your face isn''t about Mrs. Adebayo."\nShe moves her fork through her rice. "I said something to someone without thinking."\n"What kind of something?"\n"The kind that would take a lot of context to explain."\nTola looks at her across the table. "Context that''s hard to explain usually means you know more about the person than they know you know."\nSimi keeps her eyes on her food.\n"Simi."\n"I said I''m fine, Tola."\nTola lets it go, which means she files it for later, which means it is not gone at all. Simi finishes her rice and spends the rest of the afternoon reminding herself she is not thinking about Femi''s face in the half second before the office door opened. She is not very successful.\nTuesday morning she sets her alarm for 6:25. The extra ten minutes are entirely about punctuality, she tells herself, nothing to do with arriving at the stop before him and not having to board behind him, not having to feel that again. She tells herself this twice and then gets up and makes tea and stands at the window while the street below does its early things: the gateman from the compound next door sweeping the gate with slow, tired strokes, a woman moving past with a tray of bread balanced on her head without looking up, two okada riders arguing about something she cannot hear. She watches all of it instead of thinking about what I know must have sounded like to someone who had never spoken to her before.\nShe is second in line at 6:41. The danfo comes. She boards, sets her bag between her feet, and takes her seat: third row from the back on the left. She opens the history note and reads the first sentence of the Lyttleton Constitution section, which she has now attempted seven times across two days and one restless hour last night.\nHe boards at the second stop.\nShe does not look up. Not the casual kind of not looking up. The deliberate kind, the kind that takes effort, the kind she has been rehearsing since yesterday. She hears the shift in the bus that signals a new boarder and she keeps her eyes on the screen.\nThe footsteps do not continue to the fourth row.\nThey stop.\nShe counts without moving her head. One row from the back. Two. Three.\nHe sits down beside her. Not one row ahead. Not across the aisle. Directly beside her, and his bag clips the armrest when he sets it down and she feels the small shift in the seat, and she can see from the corner of her eye that the orange book is in his left hand. He opens it to the marked page. His thumb holds the spine the way she has watched him do it across a dozen mornings: careful, like it is something worth keeping.\nHe does not say anything. She does not say anything. Outside, Lagos moves past the window, already fully itself, already loud and bright and indifferent to whatever is happening inside this particular danfo.\nFrom the edge of her vision, she can see his shoe. The white Adidas slide. The clean white sock. Forty-two, she thinks, and immediately after: you knew his shoe size before you knew what his voice sounded like.\nShe hears the soft sound of the orange book closing.\nNot because he has finished it. She knows his pace; he has four chapters left, she estimated Friday, and this is Tuesday. He closes it the way she has watched him close it across a dozen mornings: when the book is no longer the point. She is looking at her phone. She is not reading anything on it. Beside her, he has set the book down, and the bus is still moving, and he has not said a word yet, and the silence has changed shape entirely.','\n',char(10)),1049,0,1,NULL,'2026-04-29 07:27:27','2026-04-29 02:31:55','2026-04-29 07:27:27','2026-04-29T05:00:00.000Z',1,51);
INSERT INTO "chapters" ("id","novel_id","chapter_number","title","content","word_count","is_premium","is_published","audio_url","published_at","created_at","updated_at","scheduled_release_at","part_number","season_id") VALUES(650,76,4,'Words to Songs',replace('He sits beside her on Wednesday too. And Thursday. By Friday she has stopped counting it as a surprise and started counting it as a fact, which is different, which is worse in ways she has not fully worked out yet.\nThey do not speak on these mornings. This is not awkward, exactly. It is more like an arrangement neither of them made out loud. He opens his book. She opens her notes or her phone or the paragraph of a novel she has been moving through a page at a time for three weeks. The danfo does what the danfo does. Lagos does what Lagos does. They ride from Ojuelegba to Yaba in a silence that is, Simi decides, the most companionable silence she has had with another human being this entire year, and she cannot explain why without sounding strange, so she does not try.\nWhat she does instead is keep her eyes forward. This is the rule she has given herself, private and non-negotiable. She can see him in her peripheral vision. She does not need to look directly. She knows his habits well enough that the peripheral version is sufficient: the shape of him settling into the seat, the angle at which he holds his book, the left earbud in and the right one out, always, the way his hand moves to the page with the same deliberate care he has always used.\nMonday comes around again and the danfo is more crowded than usual, the kind of crowded that happens after a public holiday when the whole city is trying to get back to itself. She boards third. He boards at the second stop and she hears the assistant''s "move inside" and she shifts fractionally, not enough for anyone to notice, just enough to leave the edge of the seat accessible, which is not an invitation, she decides, it is logistics.\nHe sits down. His shoulder is close enough to hers that she can feel the slight pressure when the bus rocks at the Aguda junction. He puts the left earbud in.\nShe reads. Three pages, four pages. Outside, the traffic on Western Avenue is beginning its slow argument with itself, a contest of horns and patience in which patience has never won.\nHe is mouthing something.\nShe sees it from the edge of her vision first. The slight movement in her peripheral frame that draws her eye the way movement always does. She does not mean to look fully. She means to glance and return, glance and return, the way she has done for four months from a safe four rows away. But the distance is different now. He is right here. And the thing he is mouthing is not random, she can see the shape of it, the repetition, a chorus, something he knows so well it is in his chest before it reaches his lips.\nShe watches for three seconds longer than a glance.\nHe turns.\nThe eye contact is immediate and clean, no buffer of distance to hide in, no four rows to blur the direction of her gaze. She looks directly at him and he looks directly at her and she knows, with a certainty that is almost physical, that he has seen her watching.\nShe has three seconds. She knows this because the brain, when it is working very quickly, turns time into intervals, and hers is working very quickly. Three seconds to decide what her face is doing, what her mouth is going to produce, whether she looks away or holds or speaks. She ran this calculation once before, on Carter Bridge, and the outcome was I know, and she is still recovering from that one.\nOne.\nShe looks at his lips. Not romantically. Analytically. The way she would look at evidence. The shape is there, still, a reflex his face has not finished completing, and she reads it the way you read a page mid-sentence: something, something, never let you go.\nTwo.\nShe knows that song. It is not a famous song. It is the kind of song that lives in certain playlists and in people who find music before it finds everyone else, and she knows it because she found it the same way, in a slow hour on a Friday night six months before she started this route, and she has never met another person who knew it.\nThree.\n"That''s Odeal," she says.\nHe blinks. Not a flinch, not a recoil, but the specific blink of a person recalibrating. His right earbud is out, so she knows he heard her, and what he does with what he heard is this: he looks at her for one full second before anything else moves on his face. Then something at the corner of his mouth shifts.\n"How do you know Odeal?"\n"I found it on a playlist," she says. "The B-sides one. The one that only has three hundred followers."\nHe stares at her. "That playlist has three hundred followers because I am one of them and my friend Dare is one of them and the person who made it is one of them and I can account for everyone else."\nShe meets his stare and says nothing.\n"Simi." It is the first time he has said her name and she registers it somewhere in her chest in a way she would prefer not to. "How do you know that playlist?"\nThe bus stops for a red light. Around them, the danfo fills with the sound it always fills with at a stop, conversation resuming, a child asking a question, the driver consulting someone on the phone about something that turns the air a little tense. The light will change in thirty seconds. She has ridden this route long enough to know.\nShe has been holding a version of this conversation in her chest for four months and now it is in front of her and she only has thirty seconds and she does not know yet how much of it she is ready to say.\n"Same way I know your shoe size," she says.\nThe light changes.','\n',char(10)),1021,1,1,NULL,'2026-04-29T02:32:56.967Z','2026-04-29 02:32:57','2026-04-29 02:32:57','2026-04-29T06:00:00.000Z',1,51);
INSERT INTO "chapters" ("id","novel_id","chapter_number","title","content","word_count","is_premium","is_published","audio_url","published_at","created_at","updated_at","scheduled_release_at","part_number","season_id") VALUES(651,76,5,'What She Knows',replace('\nThe bus moves and neither of them speaks and Simi looks at her phone and sees nothing on the screen that enters her brain. Beside her, Femi has closed the orange book. She notices this without looking directly. She notices everything without looking directly; that is the whole problem.\nAt the Yaba junction he stands before the bus finishes stopping, which is a danfo thing, a Lagos thing, the understanding that the bus will not fully stop and you must be ready to meet the ground. She stands a second after him. They step off into the morning crowd and the bus moves away and they are on the pavement and he turns to look at her with an expression she cannot file cleanly into any category.\n"What does that mean?" he says. "Same way you know my shoe size."\nShe adjusts her bag strap. "It means I''m observant."\n"Observant." He says the word back to her, not unkindly, the way you say a word to test how much weight it holds. He looks at her for another second. Around them the junction moves: conductors calling routes, a woman navigating a cart of sachet water through the crowd, two men in suits consulting a phone together. Femi says, "Okay," and they walk in the same direction toward the school road, and he does not press, and this is somehow worse than if he had.\nThey split at the junction by the filling station, different uniforms, different directions, and Simi spends the four-minute walk to St. Catherine''s gates doing the arithmetic on the last twelve minutes of her life. She reaches the gate one minute before it closes. She signs in. She goes to class.\nShe texts Tola during the first period: I need to talk to you at lunch.\nTola replies: I knew the fine thing would return.\nWhat fine thing.\nThe not-fine face. It came back this morning. I saw you by the lockers.\nSimi puts her phone away. Mr. Lawal is writing a constitutional conference date on the board and underlining it twice, which means he will ask about it directly and she needs to be ready. She copies the date. She underlines it twice. She does not think about the word okay and how Femi said it.\nTola is at the corner table before Simi arrives at lunch, which is typical. Tola is always early to things she is interested in and late to things she is not and she operates at this frequency without apology. She has a meat pie and a bottle of water and she is watching Simi cross the canteen with the look of someone waiting for a performance to begin.\nSimi sits down. She opens her own lunch, a container of rice from home that her mother packs every morning with the exact same ratio of tomato to pepper, a consistency Simi has always found privately comforting. She eats two forks of rice.\n"Tola," she says.\n"Yes."\n"If I tell you something you''re going to make it a bigger thing than it is."\n"I can''t promise anything," Tola says, "but I''ll try."\nThis is the most honest answer she could have given, so Simi accepts it. She takes a breath and says, "There''s a boy. He goes to Igbobi. We''ve been on the same danfo every morning since September."\nTola''s face does not move. She is containing herself. This is visible.\n"I know things about him," Simi continues. "Not from talking to him. From being on the same bus. I know he takes the window seat four rows from the front because the window on that side doesn''t open properly. I know his shoes, Adidas slides, size forty-two, he keeps them very clean. I know he reads and that he takes care of his books. I know he mouths the words to songs with his left earbud in and his right ear free." She pauses. "I know what playlist he uses. We both found the same Odeal B-sides playlist, the one with three hundred followers. I told him I found it the same way I know his shoe size."\nTola puts the meat pie down.\n"I have been watching this person for four months," Simi says, "and he didn''t know I existed until we were both late to school last Monday and he introduced himself at the junction on Carter Bridge."\nThe canteen does its canteen things around them. Plates, voices, a bench scraping. Tola is quiet for a moment in the way she is quiet when she is building a response rather than reacting.\n"You''ve been cataloguing him," Tola says.\n"I notice things. It''s not a—"\n"You know his shoe size, Simi."\n"I notice things about everyone."\n"Tell me one thing you''ve noticed about me this week."\nThe answer comes before she has time to decide whether to give it. "You''ve been sleeping badly. You''ve had the same pen cap in your mouth during class since Thursday, which you only do when you''re anxious, and you changed your hair twice in four days, which you only do when something feels out of your control. I haven''t asked because you haven''t brought it up." She stops. "I notice things."\nTola picks up the meat pie again. She is quiet for a moment. Then she says, "That''s different."\n"Why?"\n"Because you love me. Noticing someone because you love them is different." She takes a bite, chews, looks at Simi with the precise steadiness she has always had. "What have you been telling yourself this is, if it''s not that?"\nSimi looks down at her rice. She moves her fork through it, finding the bottom of the container, the way you look for something you already know is not there.\nOutside the canteen window, someone crosses the courtyard in a gray Igbobi uniform. Her head comes up.\nIt is not him. She knows it is not him before she fully looks, the build is wrong, the walk is wrong, but the speed of the reaction is already there, already out of her hands, and Tola is watching her with an expression that does not need to say anything at all.','\n',char(10)),1026,1,1,NULL,'2026-04-29T02:33:50.977Z','2026-04-29 02:33:51','2026-04-29 02:33:51','2026-04-29T06:00:00.000Z',1,51);
INSERT INTO "chapters" ("id","novel_id","chapter_number","title","content","word_count","is_premium","is_published","audio_url","published_at","created_at","updated_at","scheduled_release_at","part_number","season_id") VALUES(652,76,6,'Not a Crush',replace('She makes the list on Tuesday night, in the back of her Chemistry notebook where Mr. Fashola will never reach because he marks only the front sections and she knows this from three terms of careful observation.\nThe list has a heading: Reasons This Is Not What Tola Thinks It Is.\nShe writes:\n1. I don''t know him. I know facts about him. These are different.\n2. Noticing someone is not the same as wanting something from them. Wanting is when you''d be diminished without it. I would not be diminished.\n3. He sat beside me because of Carter Bridge. It was a convenience that became a habit. Habits don''t mean anything.\n4. The playlist is a coincidence. Lagos has twenty million people. Some of them listen to the same music. Probability.\nShe reads the list back. It is logical. It is correct. She closes the notebook and goes to sleep.\nIn the morning she wakes up and the first thing that enters her head is not her alarm or the history exam Friday or the sound her mother is making in the kitchen below. It is the word okay and the specific weight Femi put in it when he said it on Monday morning, like he was filing something away. Like she was a question he had decided to come back to.\nShe gets up. She does not think about this. She makes tea.\nOn the danfo he is already in the seat beside hers when she boards, which has not happened before. She is used to boarding before the second stop. She is used to his arrival. She is not used to arriving to find him already there, already settled, book open to a new page, orange cover replaced now with a slim gray paperback that she clocks in her peripheral vision and cannot identify by spine alone. He has finished the orange one. She had four chapters left, at her reading pace, before she estimated he''d be done.\nShe was two days off.\nShe sits down. He glances up and back to the page in one motion, not rude, just reading. She puts her earphones in, both of them, which she never does because she prefers to stay aware of the bus, but right now she needs something between her and the air that is suddenly very full.\nThe music does not help. She pulls up the Odeal B-sides playlist, which she should not do, and the first track is not the one he was mouthing but it is from the same album and it sits in her chest in a way that makes the notebook list feel thin.\nShe pulls the earphones out at Surulere.\nHe says, without looking up, "You usually only put one in."\nShe turns her head. He is still reading. His eyes are on the page.\n"I notice things," he says, mildly, and turns a page.\nSimi looks forward. Outside the window a billboard for a new estate in Lekki slides past, smiling people in front of a gate that leads to a render of a house that does not exist yet. She breathes through her nose.\n"That''s not fair," she says.\n"I know." He says it without apology, but also without edge. Just a fact. The same way she said I know in the principal''s queue, and she understands now, hearing it from the other side, that it is not a cruel thing to say. It is just an honest one.\nShe does not say anything else. The bus moves. At Ojuelegba market, where the road narrows and the driver slows to navigate around a truck unloading crates, the bus rocks and his shoulder presses briefly against hers and neither of them adjusts away.\nShe opens her phone. She re-reads the list in her head, point by point, because the notebook is in her bag and she has memorized it already. Noticing someone is not the same as wanting something from them. She has believed this for four months. She needs it to still be true.\nAt lunch Tola slides into the seat across from her before Simi has unwrapped her food and says, "You have the Chemistry notebook."\n"We have Chemistry tomorrow."\n"You take Chemistry notes on your phone. You''ve used that notebook three times this year." Tola unfolds her own lunch, a wrap from the woman outside the gate that Simi has never trusted because the woman reuses the foil, which is not a hygiene issue but is an organizational one. "What''s in the back pages?"\n"Notes."\n"What kind."\n"The private kind."\nTola accepts this, which means she does not accept it but will approach it differently. She eats. Simi eats. The canteen conversation around them is a Tuesday kind of conversation, lower than Monday, louder than Wednesday, the week finding its rhythm. Somebody at the table behind them is retelling a story with increasing volume, the story getting better each time, the way Lagos stories do.\n"I don''t think you''re confused about what it is," Tola says, without looking up from her wrap. "I think you''re confused about what to do with it."\n"I''m not confused about anything."\n"Simi. You made a list."\nShe looks up. Tola is watching her with the steady, unhurried patience of someone who does not need to win immediately because she is confident in the eventual outcome. She has always been like this. It is one of the reasons Simi has trusted her since JSS2 and also one of the reasons Simi finds her, at specific moments, genuinely difficult.\n"A list doesn''t mean anything," Simi says.\n"You make lists when you''re trying to convince yourself of something." Tola finishes the last of her wrap and folds the foil. "The list is not the argument. The list is evidence that you already know the argument isn''t working."\nSimi opens her mouth.\nHer phone buzzes on the table between them. An unknown number. She flips it over, reads the screen, and her mouth stays open without producing anything.\nThis is Femi. Is this Simi? Dare got your number from someone at St. Catherine''s. I have a question.','\n',char(10)),1022,1,1,NULL,'2026-04-29T02:35:07.347Z','2026-04-29 02:35:07','2026-04-29 02:35:07','2026-04-29T06:00:00.000Z',1,51);
INSERT INTO "chapters" ("id","novel_id","chapter_number","title","content","word_count","is_premium","is_published","audio_url","published_at","created_at","updated_at","scheduled_release_at","part_number","season_id") VALUES(653,76,7,'The Long Way',replace('She stares at the message for forty seconds. She knows because she times it, a reflex, the same part of her brain that clocks danfo arrivals and exam countdowns turning itself on the one situation where she genuinely does not want to be precise.\nTola is watching her from across the table.\nSimi puts the phone face down. She finishes her rice. She does not tell Tola what the message says because Tola will make a face that is worse than words and Simi does not have the resources for that right now. She gets through the rest of Tuesday on the understanding that she will think about it tonight, properly, with the notebook closed and no list.\nThe question is: How long?\nJust that. Two words, after the introduction. This is Femi. Is this Simi? Dare got your number from someone at St. Catherine''s. I have a question. How long?\nShe knows what he means. He is not asking about the route. He is not asking about the playlist. He is asking about the shoe size and the reading habits and all the quiet, accumulated weight of four months of paying attention. He is asking how far back it goes.\nShe types four different answers between Tuesday night and Wednesday morning. She deletes all of them. The problem is not that she does not know what to say. The problem is that every honest answer sounds like more than she is ready to hand over.\nShe sends: Since September.\nHe replies nine minutes later: Okay.\nThat word again. She puts the phone down and does not pick it up for an hour.\nOn Wednesday morning she is at the Ojuelegba stop at 6:38, earlier than usual, and she is there because she is punctual and not for any other reason. She is in line, she is ready, she is watching the road for the danfo. What she is not doing is replaying the text exchange, which she has already replayed eleven times and does not need to replay again.\n6:45 comes and the danfo does not.\nShe checks the road. She checks her phone. She looks at the other people in the queue: the woman with the baby who is always here, two men in the same company polo shirt, a student from a school she doesn''t recognize eating bread straight from the loaf. None of them appear concerned. Lagos bus delays are not events. They are conditions.\n7:03, she hears footsteps she recognizes, a specific rhythm and weight, and she is angry with herself for recognizing it before she turns around.\nFemi stops beside her in the queue. He looks at the empty road. He looks at his phone. He says, without looking at her, "How long has it been late?"\n"Eighteen minutes."\nHe nods. He shifts his bag. He is wearing the gray school shirt with the sleeves pushed to the elbows, which she has seen him do before on warmer mornings, and she moves her eyes back to the road and keeps them there.\n"We should walk to Ojuelegba market and catch one there," he says.\nShe considers the time. 7:04. The market stop is twelve minutes on foot, enough to intercept a Yaba-bound bus before the school gates close. It is the correct logistical decision. "Okay," she says.\nThey walk.\nThe morning is already doing its full Lagos thing, the road loud and bright, a man arguing with a fuel station attendant over something involving change, the smell of agege bread from a cart near the bus stop corner. Simi keeps her pace even. Femi walks without hurrying, the same way he absorbs everything, like the city is something he is reading rather than moving through.\n"September," he says, after a minute.\n"Yes."\n"That''s four months."\n"I know how long four months is."\nThe corner of his mouth moves. She sees it from the side. "I''m not correcting you," he says. "I''m just." He pauses. "That''s a long time to know someone''s shoe size without knowing their name."\n"I told you. I notice things."\n"You notice things," he says, in the tone of someone who has been turning a phrase over since Monday and has not finished with it. "What else?"\nThis is the question she deleted four answers to last night. She looks forward, at the road, at the row of shops just opening their steel shutters with the particular grinding sound that belongs to every Lagos morning. She could redirect. She is good at redirecting.\nBut there is something about walking that is different from sitting. On the danfo, there is always the window, the route, the forward momentum to look at instead of each other. Here there is just the pavement and the twelve minutes between them and the market stop.\n"You started the gray one yesterday," she says. "The book. The one that replaced the orange cover. You''re a fast reader. You''ll be done by Friday." She glances at him briefly. "You check your watch at the Aguda junction every morning, not because you''re late, just because you need to know. You gave your seat to a woman with bags last Thursday without looking up from your page, you just moved, and then you kept reading." She pauses. "The right earbud stays out because you like to hear where you are."\nHe is quiet for a moment. The market is ahead, the noise of it reaching them before the crowd does.\n"I like to hear where I am," he repeats, slowly, like he is reading something true about himself that he did not write.\nShe does not say anything. Around them the market swallows the road whole, the stalls and the voices and the weight of the morning compressing into a single moving thing. A bus heading Yaba pulls into the stop ten meters ahead.\nThey run for it.\nThey make it, and they board, and they find two seats and the bus moves, and she is looking forward and he is looking forward and there is something sitting between them now, not silence, not conversation, something that has no name yet but has definite, specific weight.\nHe opens the gray book. After a moment, he tilts it slightly in her direction, not handing it over, just enough that she can read the spine.\nShe reads the title. She knows it. Of course she knows it.\nThis time, she doesn''t say so.','\n',char(10)),1071,1,1,NULL,'2026-04-29T02:36:07.482Z','2026-04-29 02:36:07','2026-04-29 02:36:07','2026-04-29T06:00:00.000Z',1,51);
INSERT INTO "chapters" ("id","novel_id","chapter_number","title","content","word_count","is_premium","is_published","audio_url","published_at","created_at","updated_at","scheduled_release_at","part_number","season_id") VALUES(654,76,8,' Six Weeks',replace('Six weeks after Carter Bridge, Simi knows three new things about Femi that she did not learn from the danfo.\nShe knows he takes his tea without sugar because he mentioned it once on the long way to the market stop, offhandedly, in the middle of a sentence about something else, the way people mention things they do not realize they are mentioning. She knows he has a younger sister because the sister called during the Wednesday walk two weeks ago and he answered with the particular patience of an older sibling who is also genuinely fond of the person calling. He stepped slightly ahead to take it and she slowed down without discussing it, and when he came back he said sorry and she said for what and that was the end of it. She knows he finished the gray book on Thursday, as she predicted, and started something new on Friday that he has not yet tilted in her direction.\nThese are small things. She is aware that she is still collecting them. The difference now is that she is less certain what the collection is for.\nIt is a Friday morning in December, cool enough that Lagos has consented to be slightly less than itself, and the danfo is on time for once, and they are in their seats, which are now permanently their seats in the way that things become permanent without any formal announcement. Left side, third row from the back. She has the window because he gave it to her on a Tuesday three weeks ago without explanation and she has had it since.\n"What time does your last paper end today?" he says.\nShe looks up from her phone. "Twelve-thirty. You?"\n"One." He flips a page. "My mother is picking me up. First time this term she''s been free at the same time as me."\nShe considers this. "Where does she usually pick you up?"\n"The junction by the filling station." He pauses. "Same one we split at every morning."\nShe has walked past that junction every school day for three months. She has never thought about what it looks like when he reaches it from the other direction. She thinks about it now briefly, unwillingly, and looks back at her phone.\n"Simi," he says.\nSomething in the way he says it makes her look up immediately, before she has time to decide whether to. He has closed the book, which he only does when the conversation has his full attention, and he is looking at her with the expression she has catalogued more carefully than any other over the past six weeks: direct, unhurried, the expression of someone who has thought about something long enough to have arrived somewhere.\n"Can I tell you something?"\nThe bus rocks at Aguda. She checks her watch, which she does every morning at this junction, and then stops herself and looks at him. "Yes."\n"August," he says. "Not September. I''ve been on this route since August."\nShe waits.\n"You board at Ojuelegba. You''re always fourth or fifth in line, early enough to get your seat. You sit third row from the back on the left, except the one time someone took it and you moved to the right side instead and got a better view of the aisle, and I could tell from how you settled that you knew that immediately." He is not reading from anything. He is looking at her and the words are level and deliberate, the way his words always are when they matter. "You count the queue. Not obviously, but you do. You put your bag between your feet, not on your lap, not on the seat. You eat breakfast before you board, not after, because there''s never food in your hand but there''s always a slight deliberateness about your first few minutes on the bus, like someone who has already handled the morning and is now moving through the easy part."\nShe is very still.\n"You read on your phone, not a book. You use one earbud. You always know exactly how long the journey has left without checking the window, which means you''ve internalized the stops." He pauses. "The first time the danfo was late and you were standing in the queue and I came up beside you, you already knew how long it had been. Eighteen minutes. You didn''t check your phone when I asked. You just knew."\nThe bus is moving. Outside, Yaba is assembling itself, the junction rising ahead through the windscreen, the school road turning off to the left. Four minutes.\n"August," she says. Her voice is level. She is proud of this.\n"August," he confirms.\nShe does the arithmetic she cannot stop herself from doing. He has been on this route a month longer than her. He was there first. Everything she thought she had been doing quietly, carefully, in the private space of four rows of distance, she was doing in front of someone who was already paying attention.\n"Carter Bridge," she says.\n"Yes."\n"You introduced yourself."\n"Yes."\n"On Carter Bridge." She hears her own voice working something out in real time. "You introduced yourself."\nHe does not look away. "The danfo breaking down seemed like a reasonable opening."\nThe bus slows for the Yaba junction and the conductor''s assistant begins his exit announcement and around them bags are being gathered and people are standing and the ordinary machinery of arrival is turning, and Simi is sitting in her seat with four months of careful, private attention reframing itself in real time, every morning rearranging into a different shape, and Femi is watching her do it with the specific patience of someone who has been waiting six weeks to see what her face would do when she found out.\nShe stands. She collects her bag. She moves into the aisle.\nAt the door of the danfo, stepping down into the Yaba morning, she glances back at him once.\nHe is already looking at her.','\n',char(10)),1001,1,1,NULL,'2026-04-29T02:37:19.613Z','2026-04-29 02:37:19','2026-04-29 02:37:19','2026-04-29T06:00:00.000Z',1,51);
INSERT INTO "chapters" ("id","novel_id","chapter_number","title","content","word_count","is_premium","is_published","audio_url","published_at","created_at","updated_at","scheduled_release_at","part_number","season_id") VALUES(655,77,1,'Season 2, Episode 1 — New Seat',replace('The new term starts on a Wednesday, which feels wrong the way all Wednesdays feel when they are pretending to be Mondays, and Simi is at the Ojuelegba stop at 6:41 for the first time in three weeks. The December break was long enough to make her doubt her own rhythms, the precise calibration of her mornings, and she had spent the last Sunday night recalibrating: alarm at 6:25, tea, window, gate.\nShe is fourth in line. Of course she is.\nThe danfo arrives at 6:44, one minute late, which she adjusts for without thinking. The conductor''s assistant is a different boy today, younger than the one with the Arsenal jersey, quieter, still learning the volume the job requires. She boards. She takes her seat. She puts her bag between her feet.\nThird row from the back, left side.\nShe is aware, before she consciously registers it, that she is also aware of what the seat beside hers looks like empty.\nShe opens her phone. The history exam results from last term are supposed to be posted in the first week. She navigates to the school portal and the portal is down, which it always is at the beginning of term, which she knew, which means she is looking at the portal not because she expected it to work but because she needed something to do with her eyes.\nHe boards at the second stop.\nShe hears the shift. She hears the assistant''s enter enter and the specific change in the bus''s weight distribution and she does not look up, which takes a quantity of effort she refuses to measure.\nThe footsteps stop at the third row from the back.\nBut not at the seat beside her.\nShe looks up. He is standing in the aisle, one row ahead of their usual row, looking at the seat to his right with the expression of a person doing a calculation. It is a window seat. The window beside it, she notices now, opens fully, both panels, clean in their tracks. Somebody fixed it over the break.\nHe sits down. One row ahead and one seat to the right.\nSimi looks at this new arrangement for two seconds and then looks back at her phone. The portal is still down. She opens the Odeal playlist and puts her right earbud in, which she never does, and then realizes what she has done and takes it out again and puts the left one in instead and stares at the screen.\nThe woman with the baby, who takes the second row every morning with the reliability of a landmark, turns around. She looks at Simi''s empty seat beside Simi. She looks at Femi one row ahead. She looks at Simi again.\nSimi looks at her phone.\nThe woman faces forward, makes a sound between her teeth that is not quite a word, and readjusts the baby on her back.\nAt the Aguda junction, without turning his head, Femi says, "Happy new year."\n"Happy new year," Simi says, to the back of his seat.\n"How was break?"\n"Fine." A pause. "Yours?"\n"Good. My aunt came from Ibadan. We cooked for three days."\nShe tries to imagine his kitchen, his family, his three days of cooking, and the trying feels different from all the previous months of imagining because now the information is coming from the source rather than from the careful arithmetic of observation, and she does not quite know what to do with the difference. She says, "What did you cook?"\nHe turns slightly. Not fully, just the angle that means he is speaking to the aisle rather than the window. "Egusi, pounded yam, jollof, small chops on the second day because my aunt believes every gathering requires small chops regardless of size." A pause. "She and my mother argued about the pepper for forty minutes."\n"Who won?"\n"My aunt," he says. "She always wins. My mother knows this and still argues every time." He faces forward again. "I think it''s their actual language."\nSomething loosens in Simi''s chest, small and involuntary. She breathes through it.\nA man in the fourth row, heavyset, with a briefcase balanced across his knees, has been listening to this exchange with the unconcealed interest of someone who takes this danfo every day and considers its regular passengers his personal business. He is looking between Simi and the back of Femi''s head with an expression that says he has a theory and is satisfied to see it confirmed. He catches Simi''s eye.\nShe looks away.\nHe does not. He says, in Yoruba, This one has finally moved closer, and the woman with the baby turns around again and says, also in Yoruba, He moved closer but not close enough, and the man makes a sound of agreement and they both look at Simi.\nSimi''s Yoruba is conversational rather than fluent, but she is a person who notices things, which means she understood every word.\nShe says, in English, "I can hear you."\nThe man replies, in English, with the serenity of someone completely unbothered: "We know."\nThe woman with the baby says something else in Yoruba that makes the man laugh, a full laugh, and the student in the front row turns around to see what is happening, and Simi is looking at the back of Femi''s head and she can tell, from the angle of his shoulders, from the precise stillness of someone trying not to be visible, that he has heard every word and is making the same effort she is.\nHis shoulders lose the battle first.\nThey shake, just once, and she sees it, and something she did not budget for rises in her chest and she turns back to her phone before it reaches her face.\nThe bus moves toward Yaba and the man with the briefcase settles back into his seat with the satisfaction of someone who has done a good morning''s work.\nHer phone buzzes. An unknown number, except it is not unknown anymore.\nWas that Baba Briefcase?\nShe stares at the message. She looks at the back of Femi''s head. He is looking at his phone, one row ahead and one seat to the right, and he is still trying not to smile.\nShe types: He has a name?\nHe told me in October. He tells everyone eventually.\nShe reads this twice. October. He was speaking to the danfo passengers in October while she was watching from four rows away and assembling a private world, and the world was apparently more populated than she knew.\nShe looks up. The woman with the baby is watching her again, calm and patient and completely unashamed.\nHow much do they know? Simi types.\nThree dots appear. Disappear. Appear again.','\n',char(10)),1124,0,1,NULL,'2026-04-29T02:45:32.909Z','2026-04-29 02:45:32','2026-04-29 02:45:32','2026-04-29T06:00:00.000Z',2,52);
INSERT INTO "chapters" ("id","novel_id","chapter_number","title","content","word_count","is_premium","is_published","audio_url","published_at","created_at","updated_at","scheduled_release_at","part_number","season_id") VALUES(656,77,2,'Outside',replace('The three dots disappear without a message, which is an answer of its own kind, and Simi spends the last four minutes of the journey looking at her phone with the focused expression of someone reading very important information that is not there.\nAt the Yaba junction they step off into the January morning, which is cold enough by Lagos standards that people have made decisions about their jackets, and they fall into step beside each other without discussing it, the way they have fallen into things since Carter Bridge, without announcement, without formal agreement, the way water finds level. At the filling station junction she slows. He slows too.\n"They know," he says, answering the question from the bus, "that I take the danfo every morning. That I finish books quickly. That I moved to the seat beside you in October and then inexplicably moved away from it in January." He looks at the junction, not at her. "Baba Briefcase has opinions about the last one."\n"What kind of opinions?"\n"The kind that come with a full explanation and no invitation." He shifts his bag. "He asked me in December if I had done something wrong."\nShe looks at him. "Had you?"\nThe corner of his mouth moves. "I moved one row forward. I''m still deciding if that counts."\nShe does not know what to do with that so she looks at the road. A keke navigates around a pothole with the focused energy of a small vehicle that has learned all the city''s bad patches by heart. She watches it until it turns the corner.\n"I have to go," she says.\n"I know." He is already facing the Igbobi direction. "Saturday."\nShe looks back at him. "Saturday what?"\n"Jhalobia. The recreational park, off Bode Thomas." He says it in the tone of someone completing a sentence he began some time ago. "My friend Dare is having a small thing. Not a party. Just people. You could come."\nShe processes this. Not the danfo, not the school road, not the twelve-minute walk to the market stop. Somewhere that belongs to neither of their routines, with no route to focus on and no bell to end things. A place where they would simply be people standing in space without the structure of a moving vehicle organizing the distance between them.\n"What time?" she says.\n"Four."\nShe says okay, which is his word, and walks to St. Catherine''s without looking back, and spends the rest of Friday thinking about the fact that she said it before she finished deciding.\nShe tells Tola on Saturday morning, over the phone, while standing at her wardrobe in a way that is not about the wardrobe. Tola is quiet for three seconds and then says, "Do you want advice or do you want to talk?"\n"I want to get dressed."\n"Wear the green one," Tola says immediately. "The one with the small buttons. It''s the one where you look like yourself."\n"I look like myself in everything."\n"You look like yourself performing composure in most things," Tola says. "The green one is different. Wear it."\nShe wears it.\nJhalobia is fifteen minutes from her house by keke, close enough that she has passed it dozens of times without going in. Inside the gate it opens into something gentler than the city outside: low trees, paths, the sound of water from somewhere she cannot immediately locate. There are people scattered in loose clusters, some at the tables near the entrance, some further in along the path. She scans the space with the efficiency of someone who scans all spaces on entry.\nShe finds Femi before he finds her.\nHe is standing by a low tree near the middle path, talking to a boy she does not know, tall, with the relaxed posture of someone very comfortable wherever they are standing. Femi has his hands in his pockets. He is wearing a plain white shirt and dark trousers and he looks, she registers without intending to, completely himself, the same way he always looks on the danfo, the same way he looks everywhere apparently, like he does not adjust for location. It unsettles her slightly. She was counting on something being different.\nHe sees her before she covers the distance. He lifts one hand. She lifts one back.\n"You came," he says, when she reaches them.\n"I said I would."\n"People say they will." He says it without accusation, as a fact about people. "Simi, this is Dare."\nDare looks at her with the specific interest of someone who has been given information in advance. He says, "Oh," and then, to Femi, in a tone that is doing considerable work to be casual, "This is the one from the danfo."\n"Dare," Femi says.\n"I''m just saying." Dare turns back to her with a generous, unrepentant smile. "He talked about the danfo every day for four months and somehow you were never the subject but always in the sentence. I''m Dare. I got your number. I apologize for that."\nSimi looks at Femi. He is looking at the tree.\n"He talks about the danfo?" she says.\n"He talks about the route," Dare says, helpfully. "The traffic patterns. The passengers. Baba Briefcase specifically. The reading conditions." He pauses. "The girl who always knows exactly how late the bus is."\nFemi looks at the sky now. It is a clear Saturday sky, January-bright, the kind that makes Lagos look temporary and beautiful. He is not going to rescue himself from this and they both know it.\nSimi files the information away: four months, both directions, both of them constructing something in parallel from four rows apart, and neither of them with a name for it.\nShe says, to Dare, "The reading conditions?"\n"The light through the left-side window is better than the right," Dare says solemnly. "Apparently."\nShe turns to look at the left side of anything and finds she is looking at Femi, who has given up on the sky and is now looking back at her with the expression of a person who has decided that composure is no longer available to him and has accepted this.\n"The light," she says.\n"The light," he agrees, quietly, and she hears in it everything Dare was not quite saying, and the park moves around them, easy and green and unhurried, and this is nothing like the danfo.\nThat is the problem. That is exactly the problem.','\n',char(10)),1076,0,1,NULL,'2026-04-29T02:46:34.537Z','2026-04-29 02:46:34','2026-04-29 02:46:34','2026-04-29T06:00:00.000Z',2,52);
INSERT INTO "chapters" ("id","novel_id","chapter_number","title","content","word_count","is_premium","is_published","audio_url","published_at","created_at","updated_at","scheduled_release_at","part_number","season_id") VALUES(657,77,3,' His Side',replace('Dare disappears with the diplomatic efficiency of someone who created an opening and knows when to leave it alone. He says he is getting drinks and walks toward the tables near the water and does not come back for a long time, which Simi suspects is the point.\nThey walk. Not toward anything specific. The path curves away from the entrance into a quieter part of the park, where the trees are older and the noise from the road outside becomes theoretical rather than actual. Femi walks with his hands out of his pockets now, at his sides, and she notices the change without commenting on it.\n"The reading conditions," she says again, because she has decided she is not letting that go.\nHe looks at the path. "I needed something to tell Dare."\n"You could have told him the truth."\n"I was working up to the truth." A pause. "I spent four months working up to the truth. Carter Bridge moved the timeline."\nShe considers this. The path narrows slightly and they walk closer together by necessity, not by choice, which she is aware is becoming a recurring feature of her interactions with this person. Proximity as logistics. Proximity as something she has stopped fully believing in as an excuse.\n"What was the truth?" she says.\nHe is quiet for long enough that she thinks he is redirecting. Then he says, "In August, the second week I was on the route, I was reading and I looked up at the Aguda junction, which I do every morning because there''s a particular corner where the bus angle changes and the light comes differently." He pauses. "You were writing something. In a small notebook, not your phone. You were writing fast, the kind of fast that means the thought is going somewhere and you need to keep up with it. And then the traffic moved and the light changed and you stopped, and you read what you''d written, and your face did something."\nShe looks at him. "What did my face do?"\n"It went very still," he says. "Like you''d found something you hadn''t expected to find." He glances at her briefly. "I thought, that person is someone who thinks like that, in private, without performing it, and they''re doing it on a danfo at 7am in the middle of Lagos. I wanted to know what they''d written."\nShe has no memory of this specific morning. She has used that notebook for years, small black cover, fills one every three months or so, she is on her fifth since secondary school began. She cannot locate the August morning he is describing. It bothers her, slightly, that he has a memory of her that she does not have of herself.\n"You never asked," she says.\n"You didn''t know I existed." He says it without weight. "It seemed like information I wasn''t supposed to have yet."\nYet. She catches the word and holds it.\nThe path opens into a small clearing with a wooden bench facing a narrow stretch of water, a channel really, more intention than river, but it catches the afternoon light and holds it in a way that makes the clearing feel separate from everything outside the park. She sits on the bench because her legs have made the decision before her head has. He sits beside her.\n"When did it change?" she says. "From noticing to."\nShe doesn''t finish. He doesn''t make her.\n"October," he says. "There was a morning you were reading something on your phone and you made a sound. Not a word. Just a sound, the kind that comes out when something lands in a book and you weren''t ready for it." He is looking at the water. "I was four rows away and I heard it. I''d been moving closer by one row every few weeks because I wanted to hear what you were reading and I thought if I was gradual enough it wouldn''t be a thing."\nShe stares at him. "You were moving closer deliberately."\n"One row every two weeks."\n"Femi."\n"I know."\nShe looks at the water because she needs something to look at that is not his face, which is doing the unhurried, direct thing it always does, the thing that makes her feel like someone has removed a layer of insulation she didn''t know she was wearing. The light on the water moves.\n"What were you going to do?" she says. "If Carter Bridge hadn''t happened."\nHe is quiet for a moment. A bird lands on the near edge of the water, decides against whatever it was considering, and leaves. "I had a plan," he says. "I was going to ask you about your notebook."\n"That''s the plan?"\n"It''s a good opening." He says it with complete seriousness. "People always want to talk about the thing they were just thinking. If I caught you right after you''d been writing, while the thought was still warm, you''d answer."\nShe turns to look at him, this boy who has been conducting his own quiet study of her from four rows away, who moved closer one row at a time across weeks, who has a theory about notebook timing and the temperature of recent thoughts. She has spent four months believing she was the one paying attention.\n"You planned it," she says.\n"You memorized my shoe size," he says.\nNeither of them has a response to this.\nThe water moves. Somewhere behind them, in the direction Dare disappeared, there is the sound of a group finding a joke funny all at once, the brief warm noise of it reaching them and passing over.\nShe looks down at her hands in her lap. Small black notebook, fifth one, she has been carrying it in her bag every day for three years, and one August morning the light came through a danfo window at the Aguda junction and a boy four rows away saw her face do something she didn''t know it was doing.\n"What did you think I''d written?" she says. "In August. What did you imagine?"\nHe looks at her. The afternoon is in his face and he doesn''t look away and he says, "Something true. I thought it was something true that surprised you."\nShe holds that for a moment, turning it over.\n"Was I right?" he says.','\n',char(10)),1056,0,1,NULL,'2026-04-29T02:47:39.324Z','2026-04-29 02:47:39','2026-04-29 02:47:39','2026-04-29T06:00:00.000Z',2,52);
INSERT INTO "chapters" ("id","novel_id","chapter_number","title","content","word_count","is_premium","is_published","audio_url","published_at","created_at","updated_at","scheduled_release_at","part_number","season_id") VALUES(658,77,4,' Her House',replace('\nShe an expertswers him on the walk back to the entrance, when Dare has rejoined them and the conversation has moved to other things, and she answers him not with words but by taking the small black notebook from her bag and holding it out.\nHe looks at it. He does not take it.\n"I''m not asking to read it," he says.\n"I know." She holds it a moment longer and then puts it back. "Yes," she says. "You were right."\nDare, to his credit, says nothing. He eats his chin-chin and watches a group of children argue over a bicycle near the entrance and pretends he is not tracking every word. She has decided she likes Dare.\nShe is home by six-thirty.\nThe compound is a two-storey on a residential street in Surulere, and the generator is running when she enters, which means NEPA has taken light, which means her mother is in the kitchen where the gas cooker works regardless and the kitchen light runs off a separate line. Simi knows the specific acoustics of this: the generator''s low hum beneath the sound of a pot, her mother moving between the cooker and the counter with the efficient rhythm of a woman who has organized a kitchen the way Simi organizes mornings, precisely, without wasted motion.\n"You''re back," her mother says, without turning.\n"Yes, ma."\n"Food is almost ready. Go and change."\nSimi goes upstairs, changes out of the green dress and hangs it carefully, and sits on the edge of her bed for two minutes before going back down. The two minutes are not about anything she would name out loud.\nHer mother''s name is Mrs. Adeyemi-Soyinka, which is how she is addressed by everyone including, on careful occasions, Simi''s father. Her parents separated when Simi was eleven, cleanly and without visible drama, her father moving to Port Harcourt for work and then staying for reasons that were never fully explained and eventually stopped needing to be. He calls every Sunday. The calls are warm, brief, and informative, the kind of calls where love is present and expressed through the reliable structure of the call itself rather than its content. Simi has understood this since she was thirteen and has never said so.\nHer mother serves the food, egusi with eba, and they sit across from each other at the kitchen table in the way they have sat across from each other at the kitchen table for six years, and her mother asks three questions in the order she always asks them: how was it today, what did you eat, and is there anything due next week.\n"Fine," Simi says. "I ate at Tola''s." The notebook-holding and the yes, you were right go into the part of her that files things away from this table.\n"And school?"\n"No exam until third week."\nHer mother nods, satisfied, and eats. She is a compact woman who does not fill silences out of discomfort. She is a biology teacher at a secondary school four streets away, and she approaches most things the way she approaches a lesson plan: identify the objective, establish the method, evaluate the result. Simi inherited this. She has always known she inherited this. The knowing does not make it simpler.\n"Your cousin called today," her mother says.\n"Bisi?"\n"She passed her JAMB." Her mother''s voice carries a specific weight on this, not unkind, just present. "Two hundred and seventy-four."\nSimi eats.\n"I told her I was happy for her." Her mother refills her own water. "I told her you would call to congratulate her."\n"I will."\n"Simi." Her mother looks at her across the table. Not with the reading glasses expression, not with the school-corridor authority she sometimes brings home without noticing. Just looking. "You have four months to your JAMB. Are you where you need to be?"\n"Yes, ma."\n"I''m not asking what you think I want to hear."\nSimi sets her fork down. "I know, ma. Yes. I''m where I need to be."\nHer mother holds the look for one more second and then nods, the nod that means the subject is filed under monitored rather than closed, and they finish dinner in the quiet that has always been the primary language of this house. Not cold. Just exact. Her mother has always been a woman who knows the value of space between words, who reserves fullness for things that earn it, and Simi has grown up calibrating herself to this, learning to take up the right amount of room and no more.\nShe washes the plates. Her mother goes to mark exercise books at the dining table, the red pen moving with the same efficiency as everything else. Simi dries her hands and stands at the kitchen window looking at the compound below, the generator, the neighbor''s car, the guava tree at the far wall that has been there since before she was born.\nShe thinks about August. The light through the danfo window. Her face doing something she did not know it was doing.\nShe has spent a long time in this house being watched by no one who saw her the way he described. Her mother loves her, she knows this the way she knows useful, important things, completely and without needing to verify it. But love in this house is a responsible thing, a structural thing, expressed through packed lunches with the right pepper ratio and JAMB countdowns and the reliable Sunday calls from Port Harcourt. Not the kind that notices a face going still when a thought surprises itself.\nShe gets her phone from her bag. She opens the conversation with Femi. The last message is his, from this afternoon after she left the park, two words:\nGet home safe.\nShe reads it three times in the kitchen light and then opens a new message.\nWhat did the notebook say, she types, that August morning. What do you think you would have found.\nShe sends it before she can file it away. Behind her, the red pen moves across the dining table, steady and regular, and her mother turns a page.\nHer phone lights up. She looks down.\nShe does not read the message before her mother says her name.','\n',char(10)),1041,1,1,NULL,'2026-04-29T02:49:29.601Z','2026-04-29 02:49:29','2026-04-29 02:49:29','2026-04-29T06:00:00.000Z',2,52);
INSERT INTO "chapters" ("id","novel_id","chapter_number","title","content","word_count","is_premium","is_published","audio_url","published_at","created_at","updated_at","scheduled_release_at","part_number","season_id") VALUES(659,77,5,' The Wrong Word',replace('\nHer mother wants to know if she has called Bisi yet.\nShe has not called Bisi yet. She puts her phone in her pocket and goes to the dining table and listens to four minutes of how family celebrates together and how Bisi''s mother, Aunty Ngozi, always remembers to call when Simi does well, and she nods through all of it with the practiced attention she brings to things she must survive without reacting to. Then she goes upstairs, calls Bisi, says the right things, and lies on her bed for ten minutes looking at the ceiling before she picks up her phone.\nFemi''s message is still there.\nThe notebook. I think you found a sentence that was more honest than you meant to be. The kind that comes out when you''re not editing yet. I think you read it back and weren''t sure if it was brave or just true.\nShe reads it three times. Then she types: What''s the difference.\nHe replies: Brave means you chose it. True means it chose you.\nShe does not answer this immediately because she cannot answer it immediately. She puts the phone down and picks up her Chemistry notebook and opens it to the list in the back pages. Reasons This Is Not What Tola Thinks It Is. She reads it once. Then she closes the notebook and does not open it again.\nShe texts him back the next morning on the danfo, sitting one row behind him with the new arrangement that she has almost stopped finding strange. I think most of my true things come out before I''ve decided whether I want them to.\nThat''s not a problem, he replies.\nIt is if you''re me, she sends, and immediately second-guesses it, and then decides to leave it.\nHe turns slightly in his seat, not all the way, just enough to be visible. She is looking at her phone. He faces forward.\nWhat does that mean, he types, if you''re you.\nShe watches Lagos move past the window, a Tuesday morning assembling itself in the usual way, a woman ironing clothes outside a shop, a man reversing a truck with the confidence of someone who has made peace with small disasters. She thinks about how to answer and then types the honest version without letting herself revise it: It means I spend a lot of energy making sure what comes out is what I chose. And sometimes the unchosen things feel like a loss of something.\nControl, he types.\nYes.\nA pause. Then: Is that what the notebook is for. The unchosen things.\nShe considers this. Something like that. It''s where I put things before I''ve decided what they are.\nThe bus slows at a junction and around them the familiar reordering of a stop happens, a woman gathering her bags, a man standing before the bus is fully still, the conductor''s assistant calling forward movement. Femi''s message arrives while the bus is still rocking.\nSo when I said I wanted to know what you''d written. That August morning. I was asking to see the place where you put things before you''ve decided.\nShe reads it. She reads it again.\nYes, she types, because it is true, because he has named something she did not have the shape of.\nHis next message comes quickly, and she can tell, from the rhythm of it, that he typed it before hers arrived: That makes sense. You''re very careful with what you let out. I think you''ve been that way for a long time.\nShe looks at the screen. The message is not wrong. It is accurate, precise, the same quality of attention he brings to everything, the careful-spine book and the right earbud out for the city and the one row every two weeks. It is something she would have agreed with on the danfo six months ago, something she would have filed under correctly observed.\nBut she is not on the danfo six months ago. She is here, in the new seat arrangement, with a green dress hanging in her wardrobe and a notebook she held out and took back, and the message lands in a way she did not expect. Like a categorization. Like a specimen correctly identified.\nShe does not reply.\nHe sends one more: I don''t mean that as a bad thing.\nShe knows he doesn''t. She knows this the way she knows his shoe size and his reading pace and that he moves one row at a time. The knowing does not change the feeling, which is small and specific, the feeling of being seen so accurately that the seeing outpaces the choosing, and she is back to the same place she has been circling for months: the distance between being noticed and being known.\nAt the Yaba junction they step off and she is a half-step ahead, already adjusting her bag, and he falls into step beside her and says, "I shouldn''t have said it like that."\nShe looks at the road. "You weren''t wrong."\n"That''s not what I asked."\nShe stops walking. They are at the narrow part of the pavement near the filling station, where the keke traffic forces pedestrians into a single file, and people move around them on both sides. He is standing in front of her and she is looking at his collarbone because that is where her eyes landed and she has not moved them.\n"I know you didn''t mean it badly," she says. "I just." She stops. Starts again. "I don''t want to be a thing you''ve worked out."\nThe silence that follows is not long. But it has weight, the specific weight of something said that cannot be unsaid, not because it is destructive but because it is true, and truth heard for the first time changes the air.\nHe doesn''t answer before a keke cuts close to the pavement and they both step back and the moment folds in on itself and she says she has to go and she goes.\nShe does not look back. She knows he is watching.','\n',char(10)),1013,1,1,NULL,'2026-04-29T02:50:30.894Z','2026-04-29 02:50:30','2026-04-29 02:50:30','2026-04-29T06:00:00.000Z',2,52);
INSERT INTO "chapters" ("id","novel_id","chapter_number","title","content","word_count","is_premium","is_published","audio_url","published_at","created_at","updated_at","scheduled_release_at","part_number","season_id") VALUES(660,77,6,'Silent Route',replace('Wednesday she is fourth in line at 6:41 and the danfo comes at 6:44 and she boards and sits down and puts her bag between her feet and opens her phone and does not look up when he boards at the second stop.\nHe sits one row ahead. She hears it. She does not mark it.\nThis is the shape of it now.\nShe reads three pages of a novel she started on Sunday, a story about a girl navigating her grandmother''s compound in Kano, spare and specific in the way good writing is specific, each detail doing two things at once. She has been reading it in fifteen-minute intervals for three days and it is the first book in weeks that has asked her full attention. She gives it that now, deliberately, the way you make yourself useful to something to keep from being idle.\nAt Aguda she does not check her watch.\nThe conductor''s assistant, the quiet young one who has slowly been finding his volume, calls out the stops with growing confidence this week, his voice still cracking at the top of the call but landing more solidly than Monday. She has noticed the improvement. She notices it now and says nothing to no one because there is no one beside her to say it to.\nShe keeps reading. The grandmother in the novel is teaching the girl how to read kola nut patterns. The girl thinks it is superstition. The grandmother does not argue. She just keeps teaching, patient as water.\nBaba Briefcase boards at the Ojuelegba market extension stop, which he only does when he misses the earlier bus, and settles into the fourth row with the expression of a man who has had a morning and is not finished having it. He opens his briefcase, removes a newspaper, and holds it in front of him with the force of someone using print as a boundary.\nHe does not look at her. He does not look one row ahead.\nShe registers this as a change.\nFor three weeks, since the new year and the new seating arrangement, Baba Briefcase has been running a low commentary, nothing loud, nothing directed, just the ambient warmth of a man who has decided he is personally invested in two young people''s ability to close a four-row gap. He had said, last Thursday, something in Yoruba to the woman with the baby about patience having a limit. The woman had laughed. Simi had looked at her phone.\nToday he has his newspaper and his boundary and he is, she understands, being tactful. The thought is unexpectedly moving. She looks back at the novel.\nOutside, Lagos moves through its Wednesday version of itself. Past Alaka, past the bridge where the road briefly opens, past the row of mechanics whose shops appear every morning with the same parts arranged in the same order, a precision that has always struck her as a quiet form of optimism, the belief that the day will bring the kind of problem you are already prepared for. She has thought this before, on other mornings, and pointed it out to nobody.\nThat is the thing about the silence. It is not empty. It is full of every small observation she has made this week that collected in the place where she would have sent them and did not. Three things on Monday, two on Tuesday, four today already and it is only Aguda.\nThe conductor is getting better.\nThe mechanic on the left rearranged his brake pads overnight.\nThe grandmother in the book is right and the girl will understand it too late.\nShe holds them. They go nowhere.\nOne row ahead, Femi is reading. She knows this from the angle of his shoulders, the slight forward lean that means the page has him. She does not know what he is reading. He did not tilt the cover in her direction this week. This is a small withdrawal that she understands the logic of and finds, nonetheless, a specific kind of loss.\nShe thinks about I don''t want to be a thing you''ve worked out. She has thought about it every morning since Tuesday, not with regret exactly, more like you think about a door after you''ve opened it and felt the cold on the other side: fully understanding what you''ve done, unable to undo the understanding.\nShe was not wrong. She knows she was not wrong. The problem is that being right about something does not make the space after it less wide.\nThe bus slows on the approach to Yaba. Around her the boarding-preparations begin, the subtle gathering-of-self that every regular passenger performs at this point, the muscle memory of arrival. Baba Briefcase folds his newspaper with the unhurried method of a man who intends to finish it at the office. The quiet conductor calls the stop.\nShe stands. She moves into the aisle.\nHe is ahead of her. At the door, stepping down, he lands and moves left along the pavement and she lands and moves left and they are walking the same direction in the way they always walk the same direction because they are going to the same junction and the junction has not moved.\nHe does not slow. She does not slow. They move at the same pace with two feet of pavement between them, and she is aware of every mechanic''s shop, every keke and okada negotiating the road beside them, every detail of a morning she would have narrated in a message and did not, and the two feet of pavement is not angry space, not cold space, it is just space, and space, she is learning, has its own weight.\nAt the junction by the filling station they stop.\nHe faces the Igbobi direction. She faces hers.\nHe does not say see you tomorrow. He does not say anything. He shifts his bag and she sees his profile, the angle of his face toward his road, and then she turns toward hers.\nBehind her, she hears his footsteps start. She counts them without meaning to. At seven, they stop.\nShe keeps walking.','\n',char(10)),1024,1,1,NULL,'2026-04-29T02:51:45.052Z','2026-04-29 02:51:45','2026-04-29 02:51:45','2026-04-29T06:00:00.000Z',2,52);
INSERT INTO "chapters" ("id","novel_id","chapter_number","title","content","word_count","is_premium","is_published","audio_url","published_at","created_at","updated_at","scheduled_release_at","part_number","season_id") VALUES(661,77,7,'First',replace('He is at the Ojuelegba stop on Thursday morning, which is not where he is supposed to be.\nSimi sees him from fifteen meters away and her feet do not stop moving because stopping would be a thing, and she has decided this morning, as she has decided every morning this week, that she is going to the stop and she is going to board the danfo and she is going to read her novel and the grandmother and the kola nut patterns will be enough to fill the space between Ojuelegba and Yaba. She has not accounted for him being at the first stop.\nHe is third in the queue. She joins behind him. He does not turn around, which means he heard her join and is deciding the same thing she is deciding, which is whether this is a thing. She looks at the road. He looks at the road. The queue grows behind her.\nThe danfo comes at 6:44.\nThey board one after the other, and the logic of the queue puts them moving toward the same row, and she takes the third row from the back on the left and he takes the seat beside her, not one row ahead, not one row back, directly beside her, and she has her bag between her feet before she has finished deciding how she feels about this.\nHe does not open a book. She opens her phone.\nThe grandmother is teaching the girl about the kola nut again. The girl is arguing this time. She has a point, technically, the girl always has a point technically, but she is missing the thing the grandmother is actually teaching, which is not about kola nuts at all. Simi reads four pages without absorbing a sentence. She knows the shape of each sentence. She cannot find what is inside them.\nAt Aguda she almost checks her watch. She stops herself. She reads the same paragraph for the third time.\nOutside, the row of mechanics passes, the brake pads arranged in their careful optimistic order, and she thinks, without choosing to: same formation as yesterday. The thought completes itself and lands in the usual place and stays there.\nThe quiet conductor calls the approach to Yaba with his new confidence, the crack still there at the top but smaller now, almost gone. She has been tracking this all week. She has said nothing about it to anyone because there has been no one to say it to, and the thought has sat in the collecting place where the messages didn''t go, and she is suddenly, sharply tired of that place. Tired of the weight of small true things with nowhere to land.\nShe closes her novel.\nShe looks at her phone screen, dark now, and in it a faint reflection of the window and the moving city and the edge of his shoulder. She looks at the reflection for a moment. Then she says, quietly, to the phone: "The conductor''s getting better."\nA pause. Around them the bus does its arrival preparations. Bags gathered, people shifting.\n"Thursday of last week he dropped the stop name entirely," Femi says. His voice is careful, the way you are careful with a thing you were afraid was broken. "I wondered if he''d quit."\n"He didn''t quit."\n"No," he says. "He didn''t."\nThe bus stops. They stand. They step off into the Thursday morning, which is bright and smells of bread from somewhere on the Yaba side, and they walk the filling station road in a silence that is different from the week''s silences. Not empty. Not full of the weight of what wasn''t said. Just two people walking at the same pace with the city around them and the junction ahead.\nShe slows before she reaches it.\nHe slows with her.\nShe is looking at the junction and she says, without turning: "Seven."\nHe waits.\n"On Wednesday. Your footsteps. I counted seven before you stopped." She looks at the road. "I don''t know why I''m telling you that."\nHe is quiet for long enough that a keke negotiates the junction entirely and a man crosses behind them before Femi says, "I stopped because I couldn''t think of what to say."\n"You didn''t have to say anything."\n"I know." A pause. "I didn''t want to leave it like that. Tuesday. I kept thinking I''d said the wrong thing but I couldn''t find the right thing." He is looking at the junction too, not at her. "I''m not always careful with words. I''m careful with everything else but words move faster than I mean them to sometimes."\nShe thinks about brave means you chose it, true means it chose you. She thinks about the word careful and all the things she has been careful with for a long time.\n"You weren''t wrong," she says. "That''s the problem. You weren''t wrong about me."\n"I know I wasn''t wrong," he says. "I just." He stops. He tries again. "I wasn''t watching you to work you out. That August morning, the notebook, I didn''t want to solve you. I wanted to." He pauses on the edge of the word for a second. "I wanted to be surprised. By what you thought. By what you found when you weren''t editing yet." He is looking at her now and she can feel it without turning her head. "That''s different from working someone out."\nShe turns.\nHe is looking at her with the direct, unhurried expression she has catalogued more carefully than any other thing on this route, and underneath it, for the first time, she can see the thing it costs him. The specific expenditure of a person who is also careful, who has also been holding something without a name for a long time and has just handed it across.\n"Surprised," she says.\n"Yes."\nThe junction moves around them and the school roads wait in their separate directions and she looks at him, this boy she knew by shoe size before she knew his voice, and she says, carefully, choosing it:\n"I have the notebook in my bag."','\n',char(10)),1017,1,1,NULL,'2026-04-29T02:52:45.428Z','2026-04-29 02:52:45','2026-04-29 02:52:45','2026-04-29T06:00:00.000Z',2,52);
INSERT INTO "chapters" ("id","novel_id","chapter_number","title","content","word_count","is_premium","is_published","audio_url","published_at","created_at","updated_at","scheduled_release_at","part_number","season_id") VALUES(662,77,8,'Same Queue, Different Reason',replace('He does not ask to read it.\nThis is the first thing she notices, standing at the filling station junction with the notebook in her hand and the Thursday morning moving around them. He looks at it the way he looked at it in Jhalobia, with the careful attention of someone who understands what is being offered and does not want to take more than is given.\n"You don''t have to," he says.\n"I know." She holds it a moment longer. Then she opens it, not to August, not to the first page, but to three weeks ago, a Sunday night entry, four lines she wrote after Jhalobia when she could not sleep. She holds the open page toward him.\nHe reads it. She watches his face the way she has watched his face for seven months, but close now, without four rows of distance, without peripheral vision and careful angles. She watches it directly and she sees the moment the words land: the slight stillness, the thing that moves at the corner of his mouth, the expression she has catalogued more carefully than any other shifting into something she has not seen before and does not have a name for yet.\nHe looks up.\n"When did you write this?" he says.\n"After Jhalobia." She takes the notebook back and closes it. "That Saturday."\nHe is quiet. Around them the junction negotiates itself, a keke and a danfo and a man on a bicycle all attempting the same narrow space with the mutual tolerance of people who have made this calculation every morning for years. She watches the junction and he watches her and neither of them says anything until the road clears.\n"Simi," he says.\nShe looks at him.\n"I''ve been trying to find the right opening since August." He says it plainly, without drama, the way he says things that matter to him. "I had the notebook plan and I had about seven other plans that Dare has opinions about and I used none of them because every morning you were already doing the thing, already thinking something I wanted to know, already yourself in the specific way you''re yourself, and I couldn''t find a version of hello that was large enough."\nShe thinks about seven months of mornings. Both of them on the same bus, four rows apart, constructing parallel worlds out of the same raw material: the Aguda junction light, the conductor''s improving voice, the brake pads arranged in their careful hopeful line.\n"Carter Bridge was large enough," she says.\nSomething breaks open in his face, unhurried and complete, and she understands that this is what Dare meant when he said Femi talked about the route every day for four months and somehow she was never the subject but always in the sentence. You cannot name the centre of a thing every time without eventually naming it.\n"Carter Bridge was an accident," he says.\n"The best ones are," she says, and means it.\nHe looks at her for a long moment. Then he says, "I need to tell you something."\nShe waits.\n"The principal''s office. St. Catherine''s." He meets her eyes. "Last Monday. I was late on purpose."\nShe goes still.\n"There was a notice on the gate," he says. "A collaboration thing. St. Catherine''s and Igbobi, joint debate preparation, they needed students from both schools to submit interest. I saw it three weeks ago and I told my form teacher on Friday that I would come Monday morning to sign the form in person." He pauses. "The form was inside. The gates were closed when I arrived because I timed it wrong. And you were in the queue."\nShe stares at him. "You were late on purpose."\n"I was going to the office anyway. The lateness was a miscalculation."\n"You were at a different stop."\n"I was coming from the school side. I''d already been to the gate."\nShe processes this, the whole architecture of the thing, Carter Bridge and the queue and he introduced himself and the seven weeks before it. She processes it the way she processes everything, carefully, completely, and at the end of the processing she starts to laugh. Not a polite laugh. A real one, the kind that comes before you''ve decided whether it''s appropriate, the unchosen kind. It comes out of her and she cannot help it and she does not try.\nHe watches her laugh with an expression of profound relief.\n"The notebook plan was better," she says, when she can.\n"The notebook plan took four months and still didn''t happen," he says. "I had to let Lagos solve it."\nShe wipes her eyes. Around them the junction carries on, indifferent and eternal, and the school roads wait in their separate directions, and above them the January sky is doing the thing it does on clear Lagos mornings, enormous and specific and briefly beautiful.\n"The debate preparation," she says.\n"Three sessions. Starts next week."\n"Where?"\n"St. Catherine''s library." He looks at her steadily. "Same queue. Different reason."\nShe looks back at him, this boy she knew by shoe size before she knew his voice, who moved one row every two weeks and had seven plans and let a broken danfo on Carter Bridge do the work instead, and she reaches into her bag and takes out the notebook and holds it out properly this time, no hesitation, no halfway.\nHe takes it. He holds it with the same care he holds his books, the careful-spine hold, like it is something worth keeping.\n"Start from August," she says. "I want to know which morning."\nHe finds it. She watches his face find it, the specific stillness of recognition, and she thinks: this is what it looks like when someone arrives at the thing they''ve been moving toward for a long time.\nShe knows that look. She is wearing it too.','\n',char(10)),981,1,1,NULL,'2026-04-29T02:54:17.023Z','2026-04-29 02:54:17','2026-04-29 02:54:17','2026-04-29T06:00:00.000Z',2,52);
INSERT INTO "chapters" ("id","novel_id","chapter_number","title","content","word_count","is_premium","is_published","audio_url","published_at","created_at","updated_at","scheduled_release_at","part_number","season_id") VALUES(663,50,5,'Broken Glass',replace('Nobody moved for a long time.\nThe truth sat on the centre table beside the white cloth and the untouched glass of water and the bowl of chin chin and it was heavier than all of them. Papa Okon Ekpo had both hands on his walking stick and his eyes on the middle distance. Edem''s uncle had removed his reading glasses from his forehead and was holding them in his hands, turning them slowly. On Emem''s side of the room Auntie Remi had gone completely quiet, which was the most unsettling thing that had happened all morning.\nOutside a car horn sounded twice on the street and faded.\nEdem was still looking at the phone on the table. He had set it down carefully after Emem finished speaking, the way a person set down something they needed to stop holding in order to think clearly. His face had not collapsed. It had gone somewhere else instead. Somewhere interior and very still.\nAfiong was looking at her hands.\n\nPapa Okon Ekpo spoke first.\nHe did not speak loudly. He had never needed to speak loudly. He said that what the room had heard was this: a young girl had seen something she did not understand and had carried it in silence and then delivered it badly. He said the account on that phone had belonged to another man entirely. He said these were facts now and the room had to sit with them.\nHe paused.\nHe said there was something else the room also had to sit with.\nHe looked at Afiong.\nWhat followed was not for the room. Emem understood that immediately. Papa Okon Ekpo spoke to Afiong in the direct way elders spoke when they had decided that kindness and truth were the same thing. He said a woman who received information, however wrong, however incomplete, had choices available to her. She could confront. She could ask. She could wait. She could pray if prayer was her inclination.\nHe said the choice Afiong had made was not among those.\nAfiong did not raise her eyes from her hands.\n\nThen Edem stood up.\nHe did not stand the way he had stood earlier when he addressed the room. He stood the way a person stood when they were done with the formal version of a thing and needed to say the real version.\nHe looked at Afiong.\nThe room went very still.\nHe said her name once. She looked up.\nHe said he had spent three months reaching for a woman who had already decided what he was without asking him a single question. He said he had made her tea in the yellow cup and fixed the cabinet hinge and come home every evening to a face that had already judged and convicted him. He said he had done all of this without knowing why, which was the part that would stay with him the longest.\nHis voice did not shake. It was the voice of a man who had finished grieving something privately and was now simply stating what remained.\nHe turned and looked at Emem.\nShe held his gaze. It was the hardest thing she had done in this room and she had done several hard things already.\nHe said: "What you did started this."\nHe said it without anger. As a fact. A stone placed on the table beside the other stones.\nThen he looked back at Afiong.\nHe said: "But it doesn''t change what you did."\nThe room received it.\nAfiong pressed both hands flat against her knees. Her jaw moved once. She looked at him the way a person looked at something they had broken and could not repair and had already made peace with not repairing. There was no performance in it. No tears arrived. She had used her tears in other rooms on other nights and had none left for this one.\nShe said: "I know."\nTwo words. The same weight as his.\nEdem looked at her for a long moment. Then he picked up his jacket from the back of his chair and sat back down and said nothing further.\n\nPapa Okon Ekpo tried.\nHe was an elder and it was his function to try and he tried with the full dignity of his office. He spoke about the history of marriage in their people. He spoke about what was repairable and what was not. He asked Edem directly whether he would consider what the family was asking him to consider.\nEdem listened to every word.\nThen he said no.\nHe said it quietly and completely and the finality of it moved through the room like a change in weather. Auntie Remi opened her mouth. Edem''s uncle shook his head once in her direction and she closed it.\nPapa Okon Ekpo sat back in his chair.\nHe looked at the room. He looked at the two sides of the family facing each other across the narrow center. He looked at the phone on the white cloth and the untouched glass of water and the bowl of chin chin. He looked at the young girl at the edge of the left side who had been sitting in the same position since the beginning with her hands folded and her head slightly bowed.\nHe closed his eyes briefly.\nThen he said that the clan had gathered and the clan had heard everything and some things were beyond the gathering''s power to fix.\nHe said it the way a man said the hardest true thing he knew.\nThe room accepted it.','\n',char(10)),927,0,1,NULL,'2026-04-30T14:19:58.785Z','2026-04-30 14:19:58','2026-04-30 14:19:58',NULL,2,33);
INSERT INTO "chapters" ("id","novel_id","chapter_number","title","content","word_count","is_premium","is_published","audio_url","published_at","created_at","updated_at","scheduled_release_at","part_number","season_id") VALUES(665,68,1,'Pen Pal','<h3></h3><p>Chisom had a voice that surprised people. Not because it was beautiful, it was ordinary, slightly low for a girl her age, but because of what came out of it when no one was watching her face.</p><p>That was the condition. She needed the not-watching. The announcement came on a Tuesday. Mrs. Okafor stood at the front of the class with the particular posture she reserved for news she considered a gift. Chin up. Papers held at chest level. Waiting for the room to notice her before she spoke.</p><p>Chisom noticed. She always noticed things like that. She just rarely said so out loud.</p><p>"Federal Government Inter-School Exchange," Mrs. Okafor said. "Voice correspondence. You will be paired with a student from a partner school in Abuja. One voice note per week, minimum. The program runs for one term."</p><p>Someone in the third row said, "Voice notes? Like WhatsApp?"</p><p>"Like structured communication," Mrs. Okafor said, which meant yes.</p><p>Chisom looked down at her notebook. She had already written the word <em>Abuja</em> in the margin, small and careful, without deciding to.</p><p>The pairings came two days later, printed on a list that got passed around during break. Chisom found her name halfway down the page.</p><p><em>Chisom Eze. Khalil Bello. Unity Secondary School, Abuja.</em></p><p>She folded the paper. Put it in the front pocket of her bag. Took it out again. Looked at his name. <em>Khalil.</em> It sat in her mouth strangely, not quite like a Yoruba name and not quite like a Hausa one either. She put the paper away for the last time and went to class. The instructions said first notes should be brief. Introduce yourself. Share one fact about where you live. Ask one question.</p><p>Chisom sat on the edge of her bed that evening, phone in hand, and recorded eleven attempts.</p><p>The first one started with "Hi, my name is" and she deleted it before she finished the sentence.</p><p>The fourth was actually good for about thirty seconds before she said the word <em>actually</em> four times in a row and had to stop.</p><p>The ninth was forty-five seconds long and ended with her laughing at herself, which she deleted immediately because that felt like too much to give a stranger.</p><p>The eleventh one she sent before she could listen back to it.</p><p><em>Hi. I''m Chisom, from Enugu. I''m in SS2. I don''t really know what to say in these things. I don''t think anyone does, at the beginning. One fact about where I live: there is a woman on my street who sells akara every morning at exactly 6:15 and I have never once seen her arrive or set up. She is just always already there. My question is: what does Abuja actually feel like? Not the government part. The regular part. You don''t have to answer that if it''s a strange question.</em></p><p>She put her phone on the mattress and stared at the ceiling. Outside, Enugu was doing its evening things. Generators kicking on. The neighbor''s TV loud through the wall. The sound of her mother''s slippers on the kitchen floor.</p><p>Her phone buzzed twenty minutes later. His note was forty-three seconds.</p><p>She could tell immediately that he was comfortable with his own voice in a way she was not comfortable with hers. Not arrogant about it. Just at home in it. Like he had never spent a Tuesday evening recording himself eleven times.</p><p><em>Hey, Chisom. I''m Khalil. Abuja, SS2, Unity. Okay so your akara woman is actually — I need you to know this is a real phenomenon here too. There''s a guy near my house who sells suya and no one has ever seen him set up his grill. We think he just exists. Like he came with the neighborhood.</em></p><p>A pause.</p><p><em>Your question isn''t strange. What Abuja actually feels like. It feels like a city that''s always in a meeting. Like everyone is on the way to something or from something and the city itself doesn''t live anywhere, it just commutes. That''s the honest answer. What does Enugu feel like?</em></p><p>He said her name correctly on the first try. Not <em>Chee-som</em> the way teachers from outside the southeast always said it. Just Chisom, easy, like it fit in his mouth without effort.</p><p>She noticed that. She put the phone down and noticed that she had noticed it, and then she opened her notebook and wrote nothing for a full minute. She sent her reply the next morning, before school, standing at the gate while the akara woman moved behind her folding table with the calm of someone who had been there since the beginning of time.</p><p><em>Enugu feels like it remembers things. Like the hills are keeping records. I don''t know how to explain it better than that.</em></p><p>She pressed send. Adjusted her bag strap. Walked through the gate.</p><p>The exchange was done for the week. Polite. Brief. Exactly what the instructions asked for. Nothing in it that would make either of them look twice if a teacher decided to review it.</p><p>She did not think about it again until Thursday, when she realized she had answered his question about Enugu but he had not yet answered her follow-up about the suya man, and somehow the unanswered thing was sitting in the back of her mind like a tab left open on a browser she kept meaning to close.</p><p>She did not send another note. That was not the rules.</p><p>But she thought about it.</p><p>The suya man. The city that commutes. The voice that had said her name like it already knew where the syllables went.</p><p>She thought about it for the rest of the week and told herself it was nothing, which was the kind of thing you only told yourself about something that was already, quietly, becoming something.</p><p></p>',936,0,1,NULL,'2026-05-30 09:03:38','2026-05-30 08:58:28','2026-05-30 09:03:38',NULL,1,47);
INSERT INTO "chapters" ("id","novel_id","chapter_number","title","content","word_count","is_premium","is_published","audio_url","published_at","created_at","updated_at","scheduled_release_at","part_number","season_id") VALUES(666,68,2,'Your Voice Sounds Like','<h3></h3><p>The second note arrived on a Wednesday, which meant he had sent it three days early, which meant nothing, probably. Chisom told herself it meant nothing as she sat on the edge of the bathtub with the door locked and her rice going cold on the dining table. Her mother had been talking about Aunty Ngozi''s wedding when the notification came. Chisom had said "mm" at the appropriate intervals, pushed her chair back with the explanation that she needed the bathroom, and been gone before the next sentence.</p><p>This was not waiting. She had not been waiting. She had simply noticed, sometime around Monday, that she was curious how he would answer the follow-up question about the suya man. That was a different thing entirely.</p><p>She pressed play.</p><p><em>Hey. Okay so I lied by omission last week. My question about what Enugu feels like, I actually already had an answer in my head before I asked. I just wanted to hear if yours matched. It didn''t, but yours was better. Mine was going to be something about the weather.</em></p><p>A pause. Not an awkward pause. A thinking one. She could hear the difference already, and she had only forty-three seconds of him to compare against.</p><p><em>The suya man. His name is Mallam Sule, I found out. He''s been on that street for eleven years. I asked my uncle. Eleven years and I didn''t know his name until this week because of you, so. There''s that.</em></p><p>He stopped. Like he was not sure what to do with the end of the sentence. Then:</p><p><em>Your turn. What''s a thing you know about your street that you''ve never told anyone?</em></p><p>Forty-one seconds total. Two seconds shorter than the first one.</p><p>Chisom played it again. Not the whole thing. Just the part where he said <em>because of you, so</em> and then did not know where to put his hands, voice-wise. The unfinished trailing of it. She played that part three times, not because she was trying to memorize it, but because she was trying to understand what she was hearing in it. She was late recording her reply. Not because she had nothing to say but because she had too much, which was a new problem. The old problem was finding words. The new one was choosing between them.</p><p>In the end she sent this:</p><p><em>There''s a boy on my street, maybe nine years old, who walks home from school every afternoon counting the concrete blocks in the fence along Obiagu Road. Not touching them. Just counting out loud. I have never seen him reach the end. I don''t know if the fence ends before he gets home or if he just starts over at some point. I''ve thought about asking him but I think I don''t actually want to know. Some things are better as questions.</em></p><p>She almost deleted the last two sentences. They felt too much like herself. She sent it anyway, before the feeling could settle into a decision. The thing she was noticing, she wrote in her notebook that night, was this: Khalil had a way of ending sentences like he was leaving a door open. Not every sentence. But the ones that mattered. He would say a thing and then not close it all the way, and the space he left was shaped exactly like a question even when it was not phrased as one.</p><p>She had a friend, Adaeze, who talked in the opposite direction. Everything Adaeze said came with a period at the end, sometimes two. She was funny and certain and Chisom loved her. But you never felt, after a conversation with Adaeze, that there was more to find. You felt finished.</p><p>Khalil''s voice left you unfinished. She was still thinking about the suya man. About <em>because of you, so.</em> About eleven years and not knowing a name.</p><p>She wrote: <em>His voice sounds like a sentence that keeps going after the audio ends.</em></p><p>Then she closed the notebook because that was embarrassing to have written. But she did not cross it out. His reply came the next morning, before she was out of bed.</p><p><em>Okay "some things are better as questions" is going to live in my head for a long time. I want to argue with it and I can''t. That''s the worst kind of sentence.</em></p><p>Then, after a beat:</p><p><em>Do you always talk like that or is this a voice note thing?</em></p><p>Fifteen seconds. The shortest note yet. But she lay in the grey early morning of her room, the ceiling fan making its slow rounds above her, and she felt the question settle into her chest the way important questions do. Not loudly.</p><p>She had never been asked that before. Not like that. Most people who noticed the way she talked did not ask about it. They either used the word <em>serious</em> or the word <em>quiet</em> and moved on, as though she were a weather condition. Something to be noted and then navigated around.</p><p>Khalil asked like he actually wanted the coordinates.</p><p>She did not record a reply that morning. She got up and went to school and sat through double mathematics and ate her lunch in the usual spot and listened to Adaeze talk about the new chemistry teacher. She did all of it with his question sitting open somewhere beneath her sternum, patient as the counting-blocks boy at the start of the fence.</p><p><em>Do you always talk like that or is this a voice note thing?</em></p><p>By the time she got home, the afternoon light coming through her bedroom window at its familiar angle, laying its usual stripe across the floor, she thought she might have the beginning of an answer.</p><p>Not the full answer. Just the first floor of it.</p><p>She picked up her phone. Pressed record.</p><p>And for the first time since the program began, she did not record a second version.</p>',955,0,1,NULL,'2026-05-30T09:00:55.155Z','2026-05-30 09:00:55','2026-05-30 09:00:55',NULL,1,NULL);
INSERT INTO "chapters" ("id","novel_id","chapter_number","title","content","word_count","is_premium","is_published","audio_url","published_at","created_at","updated_at","scheduled_release_at","part_number","season_id") VALUES(667,68,3,'The Fifth One','<p></p><h3></h3><p>She answered his question on a Thursday evening, sitting on the back step of her house with her shoes still on, which was something she never did. <em>It''s a voice note thing. But I think the voice note thing is just the regular thing with the lights off. Does that make sense? Like I''m still me. I just can''t see you seeing me, so I stop editing.</em></p><p>She sent it before she finished deciding to. Twelve seconds. The shortest she had ever sent.</p><p>His reply came back in four minutes.</p><p><em>That makes complete sense. That''s actually one of the more honest things anyone has said to me. I''m keeping that.</em></p><p>And then, before she could reply:</p><p><em>Okay here''s my version. I talk a lot in real life. Like, a lot a lot. My friends call it a condition. But I notice, with you, I keep stopping to think. Which I don''t usually do. So maybe this is also my lights-off thing.</em></p><p>She read the notification preview and then opened the app and played it twice. She was doing that more now, the playing-twice. Not because she missed something the first time. Because the first time she was listening and the second time she was hearing. The fifth exchange happened on a Saturday.</p><p>There was no rule against weekend notes. The program said one per week minimum, which in practice meant they had each been sending two or three. Nobody had discussed this. It had simply become the pattern, the way patterns do, quietly, before you notice they are patterns.</p><p>Chisom was at the dining table pretending to read her literature textbook when she opened the app and started recording without planning to.</p><p><em>I''ve been trying to figure out why it''s easier to talk to you than to most people I know in person. I think it''s because you ask questions that have room in them. Like they''re not trying to catch me anywhere. I don''t know if that''s a skill or just who you are.</em></p><p>She sent it. Stared at the table. Got up and poured herself water she did not drink.</p><p>His reply was eleven minutes later, and it was different. Not the content. The texture of his voice. Like something had shifted one degree, the way a window shifts when you open it just enough to change the air in the room without changing the room itself.</p><p><em>Nobody has ever said that to me before. I''ve been sitting with it for a few minutes because I wanted to answer it properly.</em></p><p>A pause. Longer than his usual pauses.</p><p><em>I think it''s just you. I think you make it easy to ask that way because I can feel that you''ll actually answer. Most people want to be asked things so they can perform the answer. You don''t perform. I noticed that in your first note. The akara woman. You gave me something real when you didn''t have to.</em></p><p>Fifty-eight seconds. His longest yet.</p><p>Chisom sat very still with her phone in her hand.</p><p>She was seventeen years old and she had known this boy, if known was even the word, for exactly five exchanges. She did not have a word for what was happening. She looked for one the way you look for something you are not sure you packed, and came up empty.</p><p>She wrote in her notebook: <em>The fifth one was different. I don''t know how to say what changed. </em>She called Adaeze that evening. Not to talk about Khalil. Or not directly.</p><p>"Do you ever feel like," she started, "you talk differently depending on who''s listening?"</p><p>Adaeze said, "What do you mean?"</p><p>"Like you are the same person but you''re different amounts of yourself."</p><p>"Chisom," Adaeze said, in the voice she used when Chisom was being too Chisom, "are you okay?"</p><p>"I''m fine. I''m just thinking."</p><p>"Think less," Adaeze said. "Come to Adanna''s thing on Sunday."</p><p>"Maybe," Chisom said.</p><p>She did not go to Adanna''s thing on Sunday. She sat with her notebook and wrote nothing useful and thought about the phrase <em>different amounts of yourself</em> and how, in five exchanges, she had sent Khalil more of herself than she had given most people in three years of sitting beside them in classrooms.</p><p>This did not frighten her. That was the thing that frightened her. She sent him a note on Sunday evening. Short.</p><p><em>Do you think you''re the same in person as you are in these?</em></p><p>He replied an hour later.</p><p><em>Honestly? I think I''m better in these. Which is either a good thing or something I should probably think about.</em></p><p>Then:</p><p><em>What about you?</em></p><p>She looked at the question for a long time. Outside, the evening was cooling into night, the neighborhood settling into its familiar sounds. She could hear a generator cycling on down the street. She had started hearing that sound as a landmark, the way she had started thinking of the akara woman as a landmark, ordinary things that had taken on new weight because she had tried to describe them to someone who could not see them.</p><p>She typed back, voice note already recording:</p><p><em>I think in person I''m a rough draft. In these I''m closer to the final thing.</em></p><p>She sent it. Put her phone down.</p><p>Neither of them said anything else that night. But the silence after felt different from the silences before. Fuller, somehow. Like it was holding something neither of them had named yet, turning it over in the dark between two phones, two cities, two people who were only five exchanges in and already standing somewhere neither of them had planned to be.</p><p>She closed her notebook. Turned off her light.</p><p>The ceiling fan turned its slow circles.</p><p>She lay in the dark and did not try to name it. Not yet. Some things you let exist before you made them into words. She had learned that from the counting-blocks boy. Some things were better as questions.</p><p>For now she let it be a question.</p>',959,0,1,NULL,'2026-05-30 09:04:08','2026-05-30 09:03:00','2026-05-30 09:04:08',NULL,1,47);
INSERT INTO "chapters" ("id","novel_id","chapter_number","title","content","word_count","is_premium","is_published","audio_url","published_at","created_at","updated_at","scheduled_release_at","part_number","season_id") VALUES(668,68,4,'Things We Don''t Say','<p></p><h3></h3><p>The disclosure did not happen the way Chisom expected. She had not been planning to say anything real. She had been planning to talk about school. It was a Tuesday, the kind Enugu produced in the middle of term, humid and grey and slow. Double biology in the morning, then the long afternoon the school calendar called "independent study" and everyone else called sleeping. Chisom spent it in the library, not sleeping, reading the same paragraph of her government textbook four times without absorbing it.</p><p>She recorded the note on her walk home, which she had started doing. Moving made it easier. Something about the forward motion let her voice find its rhythm without her having to stand somewhere and wait for it.</p><p><em>So there''s a girl in my class, Nneka, who got the highest score in our mock WAEC and Mrs. Okafor announced it in front of everyone. And I watched Nneka''s face while it was being announced and she looked not happy. Like she was waiting for it to be over. And I understood that completely and I don''t know what that says about me.</em></p><p>She had not planned to say Nneka''s name. Or the part about understanding it.</p><p>She sent it anyway. His reply came that evening while she was helping her mother shell ọgbọnọ seeds at the kitchen table. She felt the buzz against her thigh and waited until her mother got up to check the pot before she slipped one earphone in and pressed play.</p><p><em>Okay I need you to say more about that. Because I think I know what you mean but I want to make sure I know what you mean.</em></p><p>She put the phone back in her pocket. Finished the ọgbọnọ. Ate dinner. Washed her hands.</p><p>Later, in her room, door closed, she sat on the floor with her back against the bed and thought about how much to give.</p><p>The thing she had not said yet, the thing sitting behind the Nneka observation, was this: Chisom was good at school in the way that had become its own trap. Not the best, not visibly brilliant, but consistently, quietly good. Good enough that teachers expected it, which meant it stopped being an achievement and became a debt. Every grade was just proof she had not failed yet. She had never said this out loud. She had barely let herself think it, because thinking it felt ungrateful, and ungrateful was one of the words that had teeth.</p><p>She pressed record.</p><p><em>What I mean is there''s a kind of being good at something that stops feeling like yours. Like other people''s expectations move into the thing you used to do just because you loved it, and then it belongs to them more than you. And you''re still doing it. You''re doing it fine. But you''re doing it for a different reason now and you''re not totally sure when that happened.</em></p><p>She breathed.</p><p><em>I used to love reading. Like actually love it, not in the way you say it in an essay. I read under the covers with my phone torch until 2am. I read during church. I read my way through my father''s entire shelf before I was thirteen. And now I read because literature is on the WAEC syllabus and I need the marks and I look at the books I used to love and I feel nothing. And I''m scared that''s permanent.</em></p><p>Forty-nine seconds. She pressed send and stood up immediately and went to drink water from the kitchen tap, cold and direct, because she needed something plain. He took three hours to reply.</p><p>Not because he was being careless. She knew this by then, the way you learn the rhythms of a person. Three hours from Khalil meant he was thinking. One minute meant something light. Immediate meant something had caught him off guard.</p><p>Three hours meant she had given him something he was taking seriously.</p><p><em>Chisom.</em></p><p>Just her name, at the start, the way someone says a name when they are making sure you know they heard you.</p><p><em>What you just said about reading. I''ve felt that about football. I played from when I was seven. My father''s idea first, and then mine, and then at some point I couldn''t tell the difference between those two things anymore. I quit in JS3. Told everyone my knee was bad. My knee was fine.</em></p><p>A pause.</p><p><em>I think what you''re describing is what happens when something you own gets turned into something you owe. And I think that''s one of the loneliest feelings there is because from the outside it looks like success.</em></p><p>Chisom sat with the phone in her hands for a long time after that.</p><p><em>From the outside it looks like success.</em></p><p>She had never heard it named that way. She had the words, she always had the words, but she had not assembled them into that particular shape. He had done it in one sentence, in the voice of someone who had lived the same thing from a different angle.</p><p>She wrote it in her notebook. Then she sat and thought about the fact that there was a boy in Abuja who had quit football in JS3 and told everyone his knee was bad, and that she was probably the only person in the world who knew his knee was fine.</p><p>That was not a small thing to be. She sent one more note before she slept.</p><p><em>Thank you for the knee. I mean for telling me. I know what it costs to say the real version.</em></p><p>His reply was quick this time. Under a minute.</p><p><em>Yeah. I know you do.</em></p><p>Four words. But she heard everything inside them. The acknowledgment. The quiet recognition. Two people on either side of the same window, realizing at the same moment that the glass was thinner than they thought and the view from both sides was the same.</p><p>She closed the app. Lay back in the dark.</p><p>The ceiling fan turned. Enugu settled into its night sounds. And somewhere in Abuja, a boy she had never seen knew something about her that Adaeze did not.</p><p>She held that thought carefully.</p><p>It did not feel like a small thing to hold.</p>',1005,1,1,NULL,'2026-05-30 09:06:51','2026-05-30 09:06:26','2026-05-30 09:06:51',NULL,1,47);
INSERT INTO "chapters" ("id","novel_id","chapter_number","title","content","word_count","is_premium","is_published","audio_url","published_at","created_at","updated_at","scheduled_release_at","part_number","season_id") VALUES(669,68,5,'His Laugh ','<p></p><h3></h3><p>It happened because of a goat.</p><p>Not metaphorically. An actual goat, on the actual street outside his house in Abuja, which had apparently escaped from somewhere and was now standing in front of a man''s brand new car, refusing, on principle, to move. Khalil had been telling her about his day, which was something they had started doing without deciding to, and the goat came up the way details come up when someone is talking to you properly, not performing a story but actually recounting one. He described the standoff. The man in the car, who was dressed for something important and was therefore losing his dignity by degrees in front of his own neighbors. The goat, which had the posture, Khalil said, of someone who owned property in the area.</p><p>Chisom was sitting on her bed, back against the headboard, textbook open across her knees and long abandoned. She was smiling already, the way his details always made her smile, when he said the next part.</p><p><em>And then the man, okay he stepped out of the car right, and he was clearly trying to be calm, and he just looked at the goat, and the goat looked at him, and then the goat sneezed. Directly in his face. And the man just stood there. Receiving it.</em></p><p>And then Khalil laughed.</p><p>Chisom had heard him laugh before. Small laughs, polite ones, the kind you produce when something is mildly funny and you want the other person to know you noticed. She had catalogued those. They were pleasant. They told her nothing.</p><p>This was not that.</p><p>This was the laugh that happened when something caught him completely off guard, when his body reacted before his composure could intervene. It started somewhere in his chest and it broke in the middle, like it was too big to come out in one piece, and there was a wheeze at the end of it, brief and undignified, that he clearly did not intend to send to anyone.</p><p>It lasted maybe five seconds.</p><p>Chisom sat very still on her bed.</p><p>The textbook slid off her knees. She did not pick it up. She played the note again. She told herself she was going back for the full story, for the part about the man receiving the sneeze with such helpless dignity. She listened to all of it. But she already knew that the part she was actually going back for was the laugh. The specific way it broke in the middle. The wheeze.</p><p>She sat there a bit longer than she needed to.</p><p>Then she got up and went to the kitchen for water she did not want and stood at the counter looking at the wall tiles, the ones with the small blue pattern her mother had chosen in 2018, and had a quiet conversation with herself.</p><p>The conversation went: <em>This is fine.</em></p><p>And then: <em>You have never met this person.</em></p><p>And then: <em>You don''t even know what he looks like.</em></p><p>And then, because she was honest with herself even when it was inconvenient: <em>It does not matter what he looks like.</em></p><p>She put her glass down and went back to her room. She recorded her reply standing up, which was new.</p><p><em>Okay the goat. The goat is everything. The goat understood the assignment which was to humble that man specifically on that day. I need you to know I have been having a deeply average Tuesday and that story fixed something in me.</em></p><p>She paused. Decided to say the rest.</p><p><em>Also. That laugh. I''m just going to say it. I have never heard you actually laugh before, like your real one, and now I understand why you keep it tucked away. Because if you just gave that to everyone they would all be in serious trouble.</em></p><p>She pressed send before she could pull the last part back.</p><p>Then she sat on the floor, back against the wardrobe, and looked at the ceiling and thought about what she had just done. His reply was twenty-two minutes later. She counted.</p><p><em>First of all I did not intend to send that. The laugh. That was an accident and I would like it struck from the record.</em></p><p>A pause.</p><p><em>Second.</em></p><p>Another pause. Longer.</p><p><em>You said "they would all be in serious trouble." Not "we would all." They.</em></p><p>One more pause, the thinking kind, the one she had learned to read like a language inside the language.</p><p><em>I noticed that.</em></p><p>Thirty seconds total. She read the words from the notification preview three times before she opened the app and played it. And hearing it was different from reading it. In his voice the observation landed with a softness that made it more precise, not less. Like he was handing her something carefully, making sure she understood he knew what he was holding.</p><p>She had said <em>they</em> on purpose. She had not known she was doing it on purpose until he named it.</p><p>She wrote in her notebook that night: <em>He listens to the parts I don''t say.</em></p><p>And below that, after a long pause of her own: <em>I''m already in trouble. </em>She did not reply that evening. Not because she had nothing to say but because anything she sent now would say everything, and she was not ready for that yet. She needed one more night of it just being almost.</p><p>She lay in the dark and listened to Enugu doing its late sounds. A dog somewhere down the street. A generator cycling off. Her father''s late news program coming faintly through the wall. All the familiar sounds of a life that had been exactly itself for seventeen years.</p><p>Something was different in it now. She could not have said what, exactly. Only that the room felt slightly rearranged without any furniture having moved, the way a room changes when a window is opened and the air shifts and you cannot point to one specific thing that is different and yet everything is.</p><p>She closed her eyes.</p><p>Somewhere in Abuja, a boy was probably also awake, having also noticed something, and also not sending a note about it.</p><p>The silence between two phones, she was learning, could be its own kind of conversation.</p>',997,1,1,NULL,'2026-05-30T09:10:49.358Z','2026-05-30 09:10:49','2026-05-30 09:10:49',NULL,1,47);
INSERT INTO "chapters" ("id","novel_id","chapter_number","title","content","word_count","is_premium","is_published","audio_url","published_at","created_at","updated_at","scheduled_release_at","part_number","season_id") VALUES(670,68,6,'Our Grammar','<p></p><h3></h3><p>The moment it became real was not a moment she could have predicted. It happened inside an argument about nothing, which is where most true things happen. It started with Adaeze.</p><p>They were walking back from the school canteen on a Thursday, the long way because the short way had construction that smelled like wet concrete and ambition, and Adaeze was in the middle of a story about her uncle''s new car, the one he had bought to impress a woman who had not yet agreed to be impressed by it, when Chisom said, without planning to:</p><p>"He''s receiving it."</p><p>Adaeze stopped walking. "He''s what?"</p><p>"Receiving it. The situation. Like he has no choice but to just stand there while life sneezes in his face."</p><p>Adaeze looked at her with the expression she reserved for Chisom''s more opaque observations. "I don''t know what that means."</p><p>"It means he''s in the situation and he can''t get out of it with dignity so he''s just there. Receiving it."</p><p>"That''s what I said. He bought the car and she still hasn''t called him back."</p><p>"Right. He''s receiving it."</p><p>Adaeze started walking again. "You''ve been saying strange things lately. Last week you said our chemistry teacher had goat energy and I''ve been thinking about it ever since and I still don''t know if I agree."</p><p>Chisom opened her mouth to explain goat energy and then stopped.</p><p>Because she could not explain it. Not fully. Not without explaining Khalil and the man in the car and Mallam Sule and the entire architecture of a language that had been building for six weeks between two phones. She could not extract one piece of it and hand it to Adaeze because the pieces only made sense inside the whole. The whole only existed between two people, and Adaeze was not one of them.</p><p>She closed her mouth.</p><p>"Never mind," she said.</p><p>Adaeze gave her a look and moved on. But Chisom carried the moment with her for the rest of the afternoon, turning it over quietly, pressing on it the way you press on something to find out where the weight is. She told Khalil about it that evening. Not as a confession. As an observation she needed somewhere to go.</p><p><em>I tried to explain goat energy to my friend today,</em> she said. <em>And I couldn''t. And I don''t mean I couldn''t find the words. I always find words. I mean the words exist but they only work inside a specific context and the context is us and I couldn''t hand her the context.</em></p><p>She paused.</p><p><em>I didn''t know that was possible. A language you can''t translate. I didn''t know we''d made one until I tried to give a piece of it to someone else and it just stopped working.</em></p><p>She sent it. Sat on the back step in the cooling evening and waited.</p><p>His reply came in eleven minutes, thinking-pause length, and when it came she could hear in the first second that he had been sitting with something similar, the texture of a person who had been inside a realization and was just now finding the door out.</p><p><em>Something happened today as well. Emeka asked me why I said "receiving it" when our maths teacher gave us the extra assignment. I told him it was something I''d seen online. And then I spent the rest of the lesson thinking about the fact that I lied. Not a big lie. But I covered it. I protected it.</em></p><p>A pause.</p><p><em>I think I protected it because it isn''t mine to give. It''s ours. And I''ve never had an "ours" before that I needed to protect from someone I actually like.</em></p><p>She sat with that. The evening was going gently around her, the compound wall holding the last of the light, the street settling into its after-six register.</p><p><em>I''ve never had an ours before either,</em> she said, recording her reply slowly. <em>I have an us with Adaeze. She''s my person. But an ours is different. An ours is something you build together. Something that doesn''t exist in either direction alone.</em></p><p>She stopped. Then:</p><p><em>We built a thing. I don''t think I understood until today that it was a thing. I thought it was just talking. But you can''t translate a thing. A thing has its own walls. </em>His reply was longer than she expected, which meant it had been building.</p><p><em>Can I tell you what it looks like from my side? What the thing is?</em></p><p><em>Yes,</em> she sent immediately.</p><p><em>There''s a moment in every conversation I have with people where I can feel the shape of what''s allowed. What this person can hold, what they''ll understand, what will land and what will fall. I''m always calibrating. You know I do this. It''s my thing.</em></p><p>A pause.</p><p><em>With you I stopped calibrating around the fourth or fifth exchange. I don''t know exactly when. But at some point I was just talking. Not performing the talk. Not checking the shape. Just going. And the thing we built is what grew in that space. The space where I stopped checking.</em></p><p>She played that twice.</p><p><em>The space where I stopped checking.</em> She wrote it in her notebook in the good pen, the one she saved for things that needed to last.</p><p>Below it she wrote: <em>I stopped editing. He stopped checking. And in the space between those two things something grew that neither of us could have made alone.</em></p><p>She closed the notebook. Above the compound wall the sky had gone fully dark, the first stars appearing with their indifferent consistency.</p><p>She pressed record one last time.</p><p><em>We made a place,</em> she said simply. <em>Not a language. A place. And only two people have the address.</em></p><p>She heard his reply before she slept. Short, the way he went short when something had landed completely.</p><p><em>Only two people,</em> he said. <em>Yeah.</em></p><p>She put her phone down. Let the night settle around her.</p><p>In the morning she passed Adaeze on the way to assembly and Adaeze said something about her uncle''s car and Chisom smiled at the right moment and said nothing about goats or receiving or the address of a place that existed between two phones.</p><p>Some things you kept. Not because you were hiding them.</p><p>Because they only survived whole.</p>',1005,1,1,NULL,'2026-05-30T09:14:27.677Z','2026-05-30 09:14:27','2026-05-30 09:14:27',NULL,1,47);
INSERT INTO "chapters" ("id","novel_id","chapter_number","title","content","word_count","is_premium","is_published","audio_url","published_at","created_at","updated_at","scheduled_release_at","part_number","season_id") VALUES(671,68,7,'Night Notes','<p></p><h3></h3><p>It started because neither of them could sleep.</p><p>She found out later that was his reason too. But at 11:47pm on a Wednesday, when Chisom sent the first note, she thought she was sending into a void, expected nothing back until morning, and sent it anyway because the thought had been sitting on her chest for two hours and needed somewhere to go. <em>I''ve been thinking about the future. Not in the WAEC prep way. In the actual way. Like who am I going to be? And I can''t see it. I can see the steps. I can see university applications and the course I''m supposed to want. But I can''t see the person on the other side of all that. Is that normal or is something wrong with me.</em></p><p>She put her phone on the mattress. Listened to the house sleep around her, her father''s faint snoring through the wall, the night settling into itself. She had not turned her light on. She was speaking from the dark.</p><p>His reply came in four minutes.</p><p>Four minutes at 11:51pm.</p><p><em>You''re awake.</em></p><p><em>So are you,</em> she sent back.</p><p><em>I''ve been awake since ten. My brain won''t stop.</em> A pause. <em>What did you mean you can see the steps but not the person?</em></p><p>She picked up her phone. Sat up against her headboard. What followed was not one exchange. It was many, quick and unplanned, the notes getting shorter as the night went on, the way conversation gets when two people stop performing it and start just talking.</p><p>She said: <em>I mean I''m going to do all the right things and I''m scared I''ll get to the end and not recognize myself there.</em></p><p>He said: <em>I think about that with architecture. My father wants me to do law. I want to design things. Not because I''m romantic about it. Because when I look at a building I see the decisions inside it. Every angle is someone choosing. I want to be someone who chooses like that.</em></p><p>She had not known he wanted to do architecture. She played that part three times, not for the content but for the texture of his voice saying it. Certain in a way he was not always certain. Like this was a room he had already lived in alone for a long time.</p><p>She said: <em>Tell me something about a building you love.</em></p><p>He said: <em>There''s a church near my grandmother''s house in Kaduna. Old, colonial, the kind with very thick walls. And inside it is always cold, not from AC, just from the stone, and when I was small I used to press my whole palm against the wall just to feel it. Someone made the decision to build it thick enough that it would hold cool air a hundred years later. That person is dead and I am still feeling their decision. I don''t know. That gets me every time.</em></p><p>Chisom sat in her dark room and felt something move through her that was not quite sadness and not quite joy and was something in the family of both.</p><p>She said: <em>I''m writing that down.</em></p><p>He said: <em>The church or the thing about decisions?</em></p><p>She said: <em>Both. All of it. </em>By 1am they had covered his grandmother''s house, the time Chisom had won a writing prize in JS2 and hidden the certificate because she could not explain the winning to herself, the specific sound Enugu made at 3am which she attempted to describe and he attempted to imagine, the question of whether the person you were at seventeen was a real person or a rehearsal.</p><p>He said: <em>I think it''s a real person who is also a rehearsal. Like it counts and it also doesn''t fully count yet. Both things.</em></p><p>She said: <em>That''s the most useful thing anyone has said to me about being seventeen.</em></p><p>He said: <em>How many people have said things to you about being seventeen.</em></p><p>She laughed. Sent the laugh. He sent back his laugh, the real one, brief and unguarded, and even through the phone and the dark and the distance she felt it land somewhere in her chest with a warmth that she was no longer pretending to examine objectively. At 1:24am he sent: <em>Can I ask you something I''ve been sitting on for a while.</em></p><p>She said: <em>Yes.</em></p><p>He said: <em>Do you find it easier to be honest in these because you can''t see my reaction? Like does the not-seeing help?</em></p><p>She thought about it for longer than she usually let herself think before answering.</p><p><em>Yes,</em> she said. <em>But I think it''s more than that. I think you''ve never seen me be awkward in a room. You have no version of me that isn''t this version. So when I talk to you I''m not correcting for a wrong impression. I''m just here.</em></p><p>A long pause.</p><p><em>Nobody has just their best version,</em> he said finally. <em>In real life I mean. There''s always the room.</em></p><p><em>I know,</em> she said.</p><p><em>I''m glad we got the notes first,</em> he said. <em>Before the room.</em></p><p>She sat with that for a long time.</p><p><em>Me too,</em> she sent back. <em>Me too. </em>The last note of the night was hers. 1:51am. Her voice was quiet, the way voices get when the night has gone on long enough to soften them.</p><p><em>I can see the person on the other side now. A little bit. I think she still loves reading. I think she chooses like that architect. I think she knows what her real laugh sounds like.</em></p><p>She paused.</p><p><em>I think you helped with that. Tonight.</em></p><p>His reply came right before she finally slept, so close to sleep that she heard it halfway between states, his voice coming through her earphone warm and unhurried, the way certain things arrived when you had stopped bracing for them.</p><p><em>Good,</em> he said. <em>Sleep, Chisom.</em></p><p>She slept.</p>',938,1,1,NULL,'2026-05-30T09:19:08.294Z','2026-05-30 09:19:08','2026-05-30 09:19:08',NULL,1,47);
INSERT INTO "chapters" ("id","novel_id","chapter_number","title","content","word_count","is_premium","is_published","audio_url","published_at","created_at","updated_at","scheduled_release_at","part_number","season_id") VALUES(672,68,8,'What I Haven''t Told Anyone','<p></p><h3></h3><p>She did not plan to tell him about her father. It came out sideways, the way true things do, through a door she had opened for something else entirely. It started with a question he asked on a Sunday afternoon, casual in tone, the kind of question that does not announce what it is carrying.</p><p><em>What does your house feel like? Not describe it. Feel like.</em></p><p>She was at her desk, the window open, the smell of her mother''s cooking moving through the house in slow waves. She picked up her phone and started talking before she had decided what to say, which was becoming her normal way with him.</p><p><em>It feels like a house that is very good at keeping things inside it. Like the walls have an agreement. Everyone is fine in this house. That is the first rule.</em></p><p>She paused. The cooking smell moved through again. Palm oil and something else, something older.</p><p><em>My father is not well. Not physically. He is fine, technically. He goes to work. He comes home. He eats. But about two years ago something changed in him and no one has named it. My mother manages around it. I manage around it. My younger brother is too small to manage, so he just lives inside it without knowing it is something. And we are all in this house together being fine.</em></p><p>She stopped. Her own voice had surprised her.</p><p>She sent it before she could reclassify it as too much. His reply was slow. Forty minutes, which was his longest thinking pause, which meant he was taking it seriously in the way she had learned to trust.</p><p><em>Chisom. Thank you for that.</em></p><p>A pause.</p><p><em>I''m going to tell you something I have not told anyone. Not Emeka, not my cousins, not anyone in my family who doesn''t already know.</em></p><p>His voice shifted. Not weaker, exactly. More precise. The way a person sounds when they are choosing each word from a specific shelf.</p><p><em>My parents separated last year. Not divorce. They don''t call it anything. My father lives in the flat, my mother lives in the main house, and they speak to each other at dinner in complete, polite sentences about practical things. My father passes the salt when she needs it. My mother asks about his work. I sit between them twice a week and eat jollof rice inside a silence that is dressed up as normalcy and I have never said that sentence out loud until this moment.</em></p><p>A breath.</p><p><em>The thing nobody tells you about that kind of quiet is how loud it is. It is the loudest thing I have ever been inside.</em></p><p>Sixty-three seconds. His longest note yet.</p><p>Chisom sat very still. She read the transcript her mind was already making, turned it over, felt the weight of what he had just handed her. The jollof rice. The complete sentences. The salt.</p><p>She understood the salt completely. She recorded her reply on the back step, shoes on, which was her outdoor-thinking posture now, the one she had developed without noticing.</p><p><em>The loudest thing I have ever been inside.</em> She said it back to him first, so he would know she had heard it. <em>I know that sound. I know it in a different shape but I know it.</em></p><p>She watched a lizard move across the compound wall in short, decisive bursts.</p><p><em>My father used to read to me. Every night, from when I was four until I was maybe nine or ten. Not children''s books, actual books from his shelf, things I barely understood. I used to fall asleep to the sound of sentences I couldn''t parse and wake up somehow understanding them better. I think that''s where the reading came from. The real love of it.</em></p><p>She paused.</p><p><em>He stopped around the time something changed in him. He still reads. I see him with books. But the reading out loud stopped and then slowly other things stopped and now he is someone who is present but not available. And I am seventeen years old and I miss my father while he is sitting in the same room as me and I have never said that to my mother or to Adaeze or to anyone.</em></p><p>Her voice did something at the end of that sentence. She heard it. She did not re-record.</p><p><em>I think you''re the first person I''ve trusted with the real version of my house. </em>He replied in the evening. She was doing homework she was not doing, pen moving without intent across the margin of her notebook, when the notification came.</p><p><em>Can I tell you what I do with it? The dinner. My coping mechanism, which is embarrassing but I''m telling you anyway.</em></p><p><em>Yes,</em> she sent immediately.</p><p><em>I design the house. In my head. While they''re being polite at me. I look at the ceiling, the angles, the way the light comes through the window above the sink, and I redesign it. I give it better light. I move the walls. I make it a house where people can breathe. I have redesigned that dining room maybe forty times.</em></p><p>A pause.</p><p><em>Architecture is not just about buildings for me. I think I want to design spaces where people don''t have to be fine. Where the walls don''t have an agreement. I didn''t know that was why until just now.</em></p><p>Chisom read that twice. Then she opened her notebook and wrote it down, not the words but the idea inside them, the thing he had discovered about himself out loud, in a voice note, because she had told him about her father''s silence and he had trusted her with his dinner table.</p><p>This was what it was, she thought. This specific thing. Not the jokes or the grammar or the laugh, though it was all of those too. It was this. The way they had become the place where the real version lived. She sent the last note of the night late, after her parents had gone to bed, the house settled into its loud quiet.</p><p><em>I want to say something and I need you to just receive it without making it into a thing.</em></p><p>She waited. He sent back: <em>Okay.</em></p><p><em>I think you might be the person I have been most honest with in my entire life. More than my diary. More than Adaeze. More than myself, sometimes. And you live in Abuja and I have never seen your face and I don''t fully know what to do with that. I just needed to say it somewhere real.</em></p><p>His reply came twelve minutes later. Not the thinking pause. Something else. Something she did not have a name for yet, a quality she had not heard before in the eleven seconds it took to play it, like a door opening in a room she had thought she already knew the shape of.</p><p><em>I was going to say the same thing,</em> he said. <em>I''ve been trying to figure out how to say it for three weeks.</em></p><p>A pause that she felt in her whole chest.</p><p><em>You are the realest conversation I have ever been in, Chisom.</em></p><p>She closed the app. Put her phone on the nightstand. Lay in the dark of her room, in her house that was good at keeping things inside it, and felt something bloom quietly in the center of her chest, something that had no name yet but was already large.</p><p>She did not try to name it.</p><p>She just let it be there.</p>',1210,1,1,NULL,'2026-05-30T09:25:45.589Z','2026-05-30 09:25:45','2026-05-30 09:25:45',NULL,1,47);
INSERT INTO "chapters" ("id","novel_id","chapter_number","title","content","word_count","is_premium","is_published","audio_url","published_at","created_at","updated_at","scheduled_release_at","part_number","season_id") VALUES(673,68,9,'I Think About You Differently Now','<p></p><h3></h3><p>She did not tell herself the truth all at once. She told it to herself in installments, the way you approach something bright, in glances, from angles that do not require you to look directly. The first installment came on a Monday.</p><p>She was in the middle of a practice essay, something about the themes of loyalty in <em>Things Fall Apart</em>, pen moving steadily across the page, when she realized she had been composing a voice note in her head for twenty minutes. Not the essay. A voice note. To Khalil. About the essay, about what Okonkwo''s fear of becoming his father actually was beneath the surface reading, what it cost a person to spend their whole life running from one thing and arriving at exactly that thing from a different direction.</p><p>She had not been aware of doing it. She had simply been thinking, and her thinking had organized itself into something she wanted to send him.</p><p>She put her pen down. Looked at the half-finished essay.</p><p><em>This is a thing that is happening,</em> she thought carefully.</p><p>She picked the pen back up and finished the essay. But she noted it. The way you mark a page. The second installment came two days later, through Adaeze.</p><p>They were at lunch, the usual spot by the water tank, and Adaeze was recounting something her cousin had said at the weekend, a story that was funny in the way Adaeze''s stories were always funny, structured and committed, landing exactly where she aimed. Chisom laughed at the right places. She was present.</p><p>But somewhere at the back of her mind she was also doing the thing where she tracked how Adaeze told stories versus how Khalil told stories, the way Adaeze built toward a punchline and Khalil built toward a truth, and both were valid, both were their own kind of intelligence, but they were different instruments and she had spent enough time listening to both to know the difference now by sound alone.</p><p>The observation arrived gently and then sat there, not going anywhere.</p><p>She looked at Adaeze, mid-story, gesturing with a piece of fried plantain. Chisom loved Adaeze. She had loved Adaeze since JS1 when Adaeze had lent her a pen during an exam without being asked, which was the kind of kindness that told you everything about a person in one gesture.</p><p>Khalil had never lent her a pen. Khalil was a voice through a phone from a city she had visited once at age eleven and barely remembered. He had no face she could picture, no height, no way of sitting in a room, no handwriting.</p><p>And yet.</p><p>She filed it. Second installment. The third one was harder.</p><p>She was playing back an old note, not a recent one, one from maybe the fifth or sixth week, before they had gone deep, back when the grammar was just forming. She was not sure why she had gone back to it. She had told herself she was looking for something he had said about Kaduna, a detail she wanted to revisit.</p><p>She played forward through four notes looking for the detail. Found it. Kept playing anyway.</p><p>She listened to his early voice, the one that was already comfortable but not yet open, the voice before the fifth one and before the night notes and before the things they had not told anyone. She listened to the moment, in the note about Mallam Sule, where he had said <em>because of you, so</em> and then not known where to put the end of the sentence.</p><p>She remembered what she had felt then. The curiosity. The leaning toward.</p><p>She compared it to what she felt now, listening to the same recording.</p><p>They were not the same feeling. The current one was bigger and had weight to it and lived somewhere below her ribs, not just in her chest. It had been growing and she had been watching it grow and calling it by smaller names, <em>interesting, comfortable, important,</em> the way you call a thing by the wrong name while you work up to the right one.</p><p>She put her phone down.</p><p>Sat in her room for a long moment.</p><p><em>You know what this is,</em> she told herself quietly.</p><p>She did not answer immediately. She looked at her hands, then at the ceiling fan, then at the small photograph on her desk of her and Adaeze at the JSS3 prize-giving, both of them squinting into the sun. Then she looked at her phone.</p><p><em>You know what this is.</em></p><p>She knew what this was. She did not send him a note that evening. Or the next morning. Not because she had nothing to say but because she needed to walk around inside the truth for a day before she decided what to do with it.</p><p>The truth was simple and enormous in the way simple things can be when they are also true. She had fallen for a voice. For a thinking pause and a real laugh and the specific way a sentence left a door open. For someone who heard the parts she did not say. For someone who had told her about his knee and his dining room table and forty imaginary redesigns of a house where people could not breathe.</p><p>She had fallen for a person she had never seen.</p><p>And the falling was real. That was the part she turned over the most. There was nothing hypothetical about it. It was not a crush on a concept. She knew him. Not the way you knew someone''s face or posture or the specific way they entered a room. But she knew what he was afraid of. She knew what he had not told Emeka. She knew the church in Kaduna with the thick walls and the cool stone and the decision some dead architect had made that Khalil still felt in his palm.</p><p>She knew things about Khalil that Khalil had not told anyone.</p><p>And he knew things about her.</p><p><em>That is not nothing,</em> she wrote in her notebook. <em>That is not a small thing to build something on.</em></p><p>Then below it, after a pause: <em>But what are we building?</em></p><p>She had no answer. Not yet. She sent him a note on the third day. Kept it on the surface, asked about his week, mentioned something funny Adaeze had said. He replied in kind, warm and attentive, the way he always was, and they had a normal exchange, the easy kind, their private grammar moving through it naturally.</p><p>But she felt the thing she now knew sitting underneath every word she said, like a second conversation happening in the same room, quiet but present, waiting with the patience of something that understood it did not need to announce itself to be real.</p><p>She wondered if he felt it too. She thought, from certain pauses, that he might.</p><p>She was not ready to ask.</p><p>But she was done pretending she did not know what it was.</p><p>The ceiling fan turned its slow circles above her. Outside, Enugu was doing its evening things, the hills keeping their records, the street filling with its familiar sounds, all of it exactly as it had always been.</p><p>She sat inside it differently now.</p><p>That was the only thing that had changed.</p><p>That was the only thing that needed to.</p>',1183,1,1,NULL,'2026-05-30T09:29:11.727Z','2026-05-30 09:29:11','2026-05-30 09:29:11',NULL,1,47);
INSERT INTO "chapters" ("id","novel_id","chapter_number","title","content","word_count","is_premium","is_published","audio_url","published_at","created_at","updated_at","scheduled_release_at","part_number","season_id") VALUES(674,68,10,'The Announcement','<p></p><h3></h3><p>The week before it happened, Chisom had been feeling something she could only describe as a careful happiness. Not the loud kind. The kind you carried gently, with both hands, because you knew it was the sort of thing that could spill. Things had shifted between them without either of them naming the shift. Not dramatically. There was no moment of declaration, no note where either of them said the thing that was sitting underneath all the other things. But the texture had changed. His notes arrived faster now. Hers were less edited. The silence between exchanges was different, not empty but patient, the kind of silence that knew something was coming and was not afraid of it.</p><p>She had told her notebook things she had not told him yet. She was working up to them in the way she worked up to all true things, from angles, in installments.</p><p>On Wednesday she had recorded a note and deleted it. Not because it was bad. Because it was too accurate.</p><p>On Thursday she had sent a shorter version and he had replied with something that made her sit very still for a long time afterward. A note about how he had started noticing Enugu references in things, a song lyric, a news headline, a word, and how each one landed like something that now belonged to a specific part of his mind that had her name on it.</p><p>She had not replied to that one immediately. She had carried it through Thursday evening and most of Friday morning, warm and unwieldy, like something she did not have a bag large enough for.</p><p>Friday was the day Mrs. Okafor came back into the classroom with her chin-up posture. Chisom saw it first. The posture. The papers at chest level. The particular quality of waiting that meant the room was about to receive something Mrs. Okafor considered a gift.</p><p>She wrote <em>Abuja behavior</em> in the margin of her notebook before she knew why.</p><p>She did not yet know why.</p><p>"The Federal Government Inter-School Exchange Program," Mrs. Okafor began, and Chisom''s pen went still, "has announced a physical visit component for all participating pairs."</p><p>The room did not react with the weight the words deserved. Someone in the back said something to someone else. A chair scraped. The ordinary sounds of an announcement that meant nothing particular to people for whom it meant nothing particular.</p><p>"Abuja students will visit Enugu in six weeks. A full day program. Cultural exchange, shared activities, formal introduction of pen pal pairs."</p><p>Mrs. Okafor said some other things after that. Chisom heard the sounds of them without processing the content. She was looking at the word she had written in her notebook margin. <em>Abuja behavior.</em> She looked at it for a long time.</p><p>Six weeks. She did not record a note on Friday. Or Friday evening. She moved through the afternoon the way you moved through water, slower than usual, the air thicker than it had been that morning.</p><p>Her mother asked if she was well at dinner and she said yes.</p><p>Her brother asked if she wanted to watch something and she said maybe later.</p><p>She sat on the back step in the dark for forty minutes and watched the compound wall and did not think about anything in particular and thought about everything.</p><p>The thing was this: she had built something in the dark. Deliberately and carefully and with more of herself than she had given anything in recent memory. She had built it specifically in the conditions that allowed her to build it. The not-watching. The voice without the face. The room without the room. She had given Khalil the final version of herself because the conditions made the final version possible.</p><p>In six weeks there would be a room.</p><p>She would be in it.</p><p>He would be in it.</p><p>And all of it, every note and every laugh and every thing they had not told anyone, would have to survive being in a room.</p><p>She had not considered this. She understood now that she had been not-considering it carefully, around the edges of it, in the way you avoided thinking about something by thinking about everything adjacent to it instead. She recorded the note on Saturday morning, early, before the house was fully awake. She sat at her desk with the grey light coming in through the curtains and her voice came out quieter than usual.</p><p><em>I don''t know how to start this one so I''m just going to start. They announced the visit yesterday. Six weeks. Abuja comes to Enugu. I''ve been sitting with it since then and I want to be someone who says that''s fine, that''s great, I''m looking forward to it. And part of me is. A real part.</em></p><p>She paused.</p><p><em>But there''s another part that is, I don''t have a word that isn''t dramatic. Afraid is dramatic. But something in that family. Because what we have exists in a specific place and I don''t know what happens to it when it has to exist somewhere else. In a room. With faces.</em></p><p>Her voice did the thing it sometimes did at the bottom of a true thing, the slight unevenness that she no longer re-recorded.</p><p><em>I think you''re the most important conversation I''ve ever been in. I said something like that before but I mean it more now than I meant it then. And I think that''s exactly why six weeks feels like something I need to stand very still and look at.</em></p><p>She stopped. Then, quietly:</p><p><em>What if the room changes things?</em></p><p>She sent it. Put her phone face down on the desk. Watched the curtains move in the early morning air.</p><p>The house was still quiet. Her father''s room was silent. Outside, somewhere down the street, she could hear the small sounds of the akara woman arriving to her spot, or already there, having always been there, the way she always was.</p><p>Some things held. Some things simply held, across all conditions, without being asked to prove themselves, without needing a room to survive in. They just existed, steady and consistent, the way the akara woman existed, the way the hills existed, the way certain true things existed once they had decided to be true.</p><p>She picked her phone back up. Looked at it. Put it down again.</p><p>She would wait for his reply with both hands, carefully, the way you carried something you were not ready to spill.</p><p>Outside, Enugu was waking up. It was doing the thing it always did, remembering itself into the morning, the hills keeping their records, the street filling with its daily sounds, all of it exactly as it had always been.</p><p>Chisom sat inside all of it.</p><p>And waited.</p>',1092,1,1,NULL,'2026-05-30T09:31:48.761Z','2026-05-30 09:31:48','2026-05-30 09:31:48',NULL,1,47);
INSERT INTO "chapters" ("id","novel_id","chapter_number","title","content","word_count","is_premium","is_published","audio_url","published_at","created_at","updated_at","scheduled_release_at","part_number","season_id") VALUES(675,69,1,'What Are We','<p></p><h3></h3><p>His reply came on Saturday afternoon, six hours after she sent her note. Not the thinking pause. Something longer than that. Something she did not yet have a name for but felt in the quality of the wait itself, heavier than usual, like the air before rain that takes its time arriving. She had cleaned her room while she waited. Not because it needed cleaning. Because her hands needed something to do that her brain didn''t have to supervise. She reorganized her bookshelf twice, first by color, then by the original system, author alphabetically, which she should have kept in the first place. She wiped down her desk. She sharpened four pencils she did not need sharpened.</p><p>Her mother passed the doorway, looked in, said nothing. Her mother had a gift for reading a room and leaving it intact.</p><p>When the notification finally came she was sitting on the floor with her back against the wardrobe, which had become, without her officially deciding it, her most honest posture. The place she sat when she was not managing herself.</p><p>She pressed play. He did not start with her name the way he did when something was important. He started with a breath. Just audible, just long enough to be deliberate, and then:</p><p><em>Okay. So I''ve been sitting with your note since this morning and I''ve been trying to figure out what the honest answer is versus what the comfortable answer is. Because the comfortable answer is it''ll be fine, we''ll be fine, what we have is real and rooms don''t change real things. And I believe that. I do.</em></p><p>A pause.</p><p><em>But I also sat in my room this morning and tried to imagine it. Meeting you. Actually meeting you. And I couldn''t hold the image still. Every time I tried to picture it my brain just skipped. Like a scratch on a record. And I don''t know what that means but I''m telling you because you asked the real question and you deserve the real answer.</em></p><p>His voice did something then, a slight drop in register, the way it went when he was at the bottom of something true.</p><p><em>What if I''m different in person than I am in these? Not worse. Just different. What if the version of me you know only exists in this specific place and the person who shows up in Enugu in six weeks is someone you have to meet from the beginning?</em></p><p>Forty-four seconds. She played it twice.</p><p>The second time she listened specifically to the word <em>Enugu.</em> The way it sounded in his mouth, not like a destination but like something that already had weight. Like he had been saying it privately for a while. She did not reply immediately either. She understood now that the six-hour wait had not been avoidance. It had been the same thing she was doing now, sitting inside the size of the question, making sure she brought him the real answer and not the comfortable one.</p><p>She moved to the back step. Shoes on. Evening coming in slowly over the compound wall, the sky going from pale to the deep orange that Enugu did better than anywhere she had ever been.</p><p>She pressed record.</p><p><em>I''ve been thinking about your question all day without knowing it was your question. What if you''re different in person. And I want to say that''s not what scares me, but I''d be lying.</em></p><p>She watched a bird cross the strip of orange sky above the compound wall, fast and direct, knowing exactly where it was going.</p><p><em>What scares me is something smaller and also bigger. It''s we built this in specific conditions. The not-watching. The voice without the face. And those conditions made it possible for me to be the version of me that you know. And I keep thinking about whether she shows up in a room. Whether I show up. Or whether I walk in there and become the rough draft again and you meet her instead and have to recalculate everything.</em></p><p>A pause.</p><p><em>You said what if the person who comes to Enugu is someone I have to meet from the beginning. And I heard that and I thought but what if the person who shows up to meet you is someone even I don''t fully recognize.</em></p><p>She breathed.</p><p><em>That''s my real answer. That''s what the room means to me.</em></p><p>She sent it. Stayed on the step until the orange was gone and the sky had made up its mind about being night. His reply came while she was eating dinner. She felt the buzz and left the phone in her pocket and finished her food and helped clear the table and told her mother the stew was good, which it was. Then she went to her room and sat in her honest posture and played it.</p><p><em>Chisom.</em> Her name first. She knew what that meant.</p><p><em>Can I ask you something directly. Not around it.</em></p><p>She sent back: <em>Yes.</em></p><p>His next note came in under two minutes.</p><p><em>What are we? I''ve been not asking that for a while now. I''ve been living inside whatever this is and calling it the program and calling it our notes and calling it a lot of things that are technically accurate. But I think the honest question, the one underneath all the other questions, is that one. What are we. And I think you''ve been not asking it too.</em></p><p>A pause that had a different quality from all his other pauses. Not thinking. Waiting.</p><p><em>You don''t have to answer it now. I just needed to ask it in a place where it was real.</em></p><p>Twenty-eight seconds.</p><p>She sat with her phone in her hand and felt the question rearrange something in the room. Not dramatically. The way furniture rearranges a space simply by being moved two inches. The same room. Different weight distribution.</p><p>She had been not asking it for nine weeks. She knew the answer. She had known it since Episode nine of her own internal series, since the installments, since the notebook entry she had written and not crossed out.</p><p>She opened her mouth to record a reply and closed it again.</p><p>Not because she didn''t know what to say. Because she wanted to say it once, properly, from the right posture, with the right voice. Not the managed one. The one that came out when nobody was watching her face.</p><p>She looked at the ceiling fan. The room. The bookshelf reorganized twice for no reason.</p><p>Six weeks, she thought. There were two things to do in six weeks. Answer that question. And then survive the answer becoming real.</p><p>She pressed record.</p>',1076,0,1,NULL,'2026-05-30 09:45:58','2026-05-30 09:39:35','2026-05-30 09:45:58',NULL,2,53);
INSERT INTO "chapters" ("id","novel_id","chapter_number","title","content","word_count","is_premium","is_published","audio_url","published_at","created_at","updated_at","scheduled_release_at","part_number","season_id") VALUES(676,69,2,'The Version of Me You Know','<p></p><h3></h3><p>She answered his question on a Sunday evening, twelve hours after he asked it. Not because she spent twelve hours finding the answer. She had the answer within minutes. She spent twelve hours finding the courage to say it in the right order. The order mattered. She had learned this about herself through nine weeks of notes, that she was not afraid of honesty but she was afraid of honesty arriving before its scaffolding, the way a building looks wrong when the walls go up before the structure underneath is ready. She needed to build toward the true thing properly or it came out misshapen.</p><p>She spent Sunday doing ordinary things with the answer sitting in her chest. She read forty pages of a novel she had recently started loving again, slowly and for real, the way she used to before the WAEC had colonized everything. She ate groundnuts on the back step and watched a neighborhood cat conduct a very serious investigation of the compound wall. She helped her mother portion rice into the cooler for the week, both of them working in the comfortable quiet they had always been good at, her mother humming something churchward and low.</p><p>By evening she was ready. She sat at her desk. Not the wardrobe posture, not the back step. Her desk, where she did her best constructed thinking, where the words came out most organized. She pressed record.</p><p><em>I''m going to answer both questions. The one you asked last night and the one underneath it. And I need you to let me finish before you reply because I''ve been building this in a specific order and if you interrupt the order I''ll lose it.</em></p><p>She paused.</p><p><em>What are we. I think we are the realest thing I have in my life right now. I think we are two people who found a specific frequency and have been living on it for nine weeks and built something on it that I don''t have a word for that fits inside the program guidelines. I think you know that. I think I know that. So that''s the answer to that question.</em></p><p>She breathed carefully.</p><p><em>Now the underneath one. The one I actually want to talk about.</em></p><p>She looked at her bookshelf. The reorganized one. Authors alphabetical, the right system, the one that held.</p><p><em>You asked what are we and I heard it as two questions. What are we right now, which I just answered. And what are we going to be when you walk into a room in Enugu in six weeks. And that second question is the one I''ve been carrying since Friday and I want to tell you exactly what it contains. The version of me you know,</em> she said, <em>was made possible by specific conditions. I''ve said this before, the not-watching, the voice without the face, but I don''t think I''ve said the full version of what I mean. So here it is.</em></p><p>She had rehearsed this part least. She had decided, deliberately, to let this section come without preparation, because prepared honesty sometimes arrived wearing the wrong clothes.</p><p><em>I am not good in rooms. I want you to understand that as a factual statement and not as self-pity. I am articulate and quick and I can hold a thought precisely and I have all of that available to me when I am here, in my room, talking to you without you watching my face. In a room I become someone who edits. I edit for the expression I see, for the energy I read, for the space between what I want to say and what I think will land without making things strange. I lose approximately half of myself to that editing process and what comes out the other side is a girl who is fine, who is decent company, who says mostly the right things, but who is a rough draft of what you have been hearing for nine weeks.</em></p><p>Her voice stayed even. She had promised herself it would stay even.</p><p><em>You have the final version. You have the version that knows what it thinks before it speaks and says it without checking your face for permission. You have the version that told you about her father and the reading and the 2am feels and the thing about being different amounts of yourself. That version lives here. In these notes. In this specific dark.</em></p><p>A long pause.</p><p><em>And I am terrified, Khalil. I am genuinely terrified that you are going to walk into that room in six weeks and meet the editing version and spend the whole day quietly recalculating. Deciding that the notes were better. That the voice was better. That you built something with a person who does not fully exist outside a phone screen.</em></p><p>She stopped. Felt the words settle.</p><p><em>That is my fear. The full version. I needed you to have it because you asked me what are we and I think the honest answer is we are something that is about to be tested in a way that I don''t know how to prepare for. And I trust you enough to say I''m scared of the test. </em>She sent it and immediately stood up and went to the kitchen and drank water and came back and did not pick up her phone.</p><p>She gave him time. She sat on her bed and read three more pages of her novel and understood none of them and sat with the open book on her lap and waited.</p><p>His reply came in twenty-five minutes.</p><p>Not the longest thinking pause. But weighted. She could feel the weight of it before she pressed play, the way you can sometimes feel the temperature of a room before you open the door.</p><p><em>Chisom.</em></p><p>Her name. Both hands.</p><p><em>Thank you for building it in the right order. I heard every floor of it.</em></p><p>A pause.</p><p><em>I need to tell you something now. About the version of me you know. Because I think you gave me the full version of your fear and the only right thing to do with that is give you mine.</em></p><p>He stopped.</p><p><em>Can I do that tomorrow? Not because I''m avoiding. Because you gave me something real and I want to come back with something equally real and I need to build it in the right order too.</em></p><p>She read the notification twice. Then played it. Then sat with it.</p><p>He had heard every floor.</p><p>She closed her novel. Put it on the nightstand. Lay back and looked at the ceiling fan making its slow rounds and felt something loosen slightly in her chest, not the fear leaving, but the fear being held by someone else for a moment, shared across two states, made slightly lighter by the fact of being known.</p><p><em>Okay,</em> she sent back. <em>Tomorrow.</em></p><p>She turned off her light. </p>',1114,0,1,NULL,'2026-05-30 09:46:13','2026-05-30 09:42:21','2026-05-30 09:46:13',NULL,2,53);
INSERT INTO "chapters" ("id","novel_id","chapter_number","title","content","word_count","is_premium","is_published","audio_url","published_at","created_at","updated_at","scheduled_release_at","part_number","season_id") VALUES(677,69,3,'The Version of Me You Don''t','<p></p><h3></h3><p>He sent it Monday after school, which meant he had carried it through a full day of classes before releasing it. She thought about that while it was playing. Him sitting through lessons with this thing built and ready inside him, waiting for the right moment to send it into the world. She was on the back step when it came. Shoes on. The compound wall doing its usual holding of the evening sky. She had been waiting without performing the waiting, going about her afternoon with the knowledge of his promised note sitting quietly beneath everything, a low frequency hum she had stopped trying not to hear.</p><p>She pressed play.</p><p><em>Okay. I built it. Here it is.</em></p><p>A breath. Not the deliberate one from Saturday. A shorter one, like he was stepping off something.</p><p><em>You said the version of you I know was made possible by specific conditions. And I heard that and I understood it completely and I also heard something underneath it that I don''t think you intended to put there. The assumption that the conditions only helped you. That I''m the one who shows up intact regardless of the room.</em></p><p>A pause.</p><p><em>I want to tell you about the version of me you don''t know. Because I think you deserve it and because I think I''ve been letting you believe in a steadiness I don''t entirely have. </em>She pulled one knee to her chest. Above the compound wall the sky was doing its early evening shift, pale going slowly golden. She kept the phone at her ear and stayed very still.</p><p><em>You know I talk. You know that about me, my friends call it a condition, I told you that in like the second week. What I didn''t tell you is what the talking is for. Because it''s not just personality. It''s not just who I am. It is also, I am going to say this out loud for possibly the first time, a way of controlling a room before the room can do something I don''t expect.</em></p><p>His voice stayed level. She recognized the effort that required.</p><p><em>If I''m talking I know where the energy is. I know what people are paying attention to. I can see the shape of things and adjust while I''m in motion. It''s actually a skill. People think it''s just charm or confidence but it is a skill I developed because I did not always know how to be in a room without managing it.</em></p><p>A pause that felt like he was looking at something.</p><p><em>At home, you know what my house sounds like. The dinners. The politeness. I grew up in a house where the real things happened in the silences between the managed things and I learned very early to watch silences more carefully than words. And the way I protected myself from being caught off guard by a silence was to fill space. Talk first. Move first. Name the thing in the room before the room named me. </em>She was not breathing in her usual way. She noticed this and did not adjust it.</p><p><em>So here is the version of me you don''t know, Chisom. I am excellent in rooms because I have spent years learning how not to be ambushed by them. I walk in, I read it, I calibrate, and I perform a version of myself that is likeable and easy and makes people comfortable. And it is not fake. I want to be clear about that. It is genuinely me. But it is the managed me. The me that is always slightly ahead of the room, always with one hand on the controls.</em></p><p>A breath.</p><p><em>In these notes I do not have the controls. There is no room to read. There is no energy to calibrate. There is just you, asking real questions in a real voice, and me answering from somewhere underneath the performance. And I think you have had that version of me, the underneath one, for nine weeks, and I am not sure that version knows how to exist in a room yet. I am not sure I know how to be unmanaged in person.</em></p><p>His voice dropped slightly on the last sentence. Not breaking. Dropping. The way a note drops on a piano when the weight behind it is real. <em>There''s something else.</em></p><p>She tightened her hand around her phone.</p><p><em>I have thought about meeting you. Not in the skipping-record way I described on Saturday. I mean before that. Before the announcement. I have thought about it more than I told you and in more detail than is probably reasonable for someone who has never seen your face. I know your back step exists. I know the akara woman''s corner. I know the strip of sky above your compound wall from the way you describe it. I have a map of your Enugu that is made entirely of your voice and I have walked through it more times than I am comfortable admitting.</em></p><p>A pause.</p><p><em>And that is the part that scares me most. Not that I''ll be different in person. But that I have wanted this too much and wanting things too much is how I have gotten hurt before. My father wanted my mother to be someone she wasn''t anymore and he wanted it so completely that he couldn''t see what she actually was until it was already quiet at the dinner table. I watched that happen from across the jollof rice for three years.</em></p><p>His voice was very quiet now. Below the performance, below the management, below all of it.</p><p><em>I am terrified of wanting you to be exactly what you are in these notes and meeting you and needing you to be that so badly that I can''t see who you actually are standing in front of me.</em></p><p>He stopped. Several seconds of silence, not the thinking kind. The arrived kind.</p><p><em>That is the version of me you don''t know. The one that wants things too much and has learned to manage it by managing everything else. I''m giving you him because you gave me you. Because that''s the only fair exchange.</em></p><p>Sixty-one seconds total. His longest note since the night notes. She sat on the back step for a long time after it ended. The evening had made its full transition while she was listening, the golden gone, the sky now the deep settled navy of Enugu at dusk. Somewhere down the street a generator came on. The neighborhood shifting into its nighttime self.</p><p>She had thought she knew the shape of his fear. She had thought it was the same shape as hers, different city, same architecture. But his was not the same shape. His was older and had parents and sat across a dinner table and had learned, young, that wanting something completely was a way of losing it.</p><p>She wrote in her notebook, slowly: <em>He is afraid of wanting me too much. I am afraid of being too little. We are afraid of the same visit from opposite directions.</em></p><p>She looked at what she had written.</p><p>Then below it: <em>I think I love him. I think I have for a while. I think saying it here, in my notebook, is me finally looking directly at the thing.</em></p><p>She closed the notebook.</p><p>Went inside.</p><p>Sat at her desk and pressed record with her hands very steady.</p><p><em>Khalil. I heard every floor of that too. And I need you to know something. The version of me that shows up in that room in five weeks and six days, rough draft and all, she already knows who you are underneath the management. She has been listening to the underneath version for nine weeks. She is not going to need you to perform.</em></p><p>She paused.</p><p><em>And the version of you that wants things too much? I think that version and I are going to get along just fine.</em></p><p>She sent it. Put her phone down.</p><p>Looked at her closed notebook.</p><p>At the ceiling.</p><p>At her hands.</p><p>Five weeks and six days.</p>',1306,0,1,NULL,'2026-05-30T09:49:41.542Z','2026-05-30 09:49:41','2026-05-30 09:49:41',NULL,2,53);
INSERT INTO "chapters" ("id","novel_id","chapter_number","title","content","word_count","is_premium","is_published","audio_url","published_at","created_at","updated_at","scheduled_release_at","part_number","season_id") VALUES(678,69,4,'Don''t Change','<p></p><h3></h3><p>The week after they gave each other their fears was quieter than she expected. Not distant. Quieter. Like two people who had said the large thing and were now sitting with it, not needing to fill the space it had left behind. The notes still came. But they were different in register, softer at the edges, less about building toward something and more about simply being in it. She noticed she was sending more observations and fewer questions. Small things. The counting-blocks boy had made it past the section of fence she had never seen him reach before, which felt significant in a way she could not fully explain. A teacher at school had worn the same shoes three days running and Chisom had developed a theory about it that had no stakes and gave her genuine pleasure to construct.</p><p>He sent her a voice note about a building he had walked past on his way home, an old one, mid-century, with a detail above the third-floor window that someone had carved by hand, a small repeating pattern that would have taken weeks and that no one standing at street level would ever fully see. He had stopped and looked at it for a long time. He had been late getting home.</p><p><em>Somebody made that for the building,</em> he said. <em>Not for anyone who would look at it. Just because it should be there. I think about what kind of person does that.</em></p><p>She played that note three times. Not for any reason she needed to analyze. On Wednesday she sent him something she had been holding for a few days, since before the fears, since somewhere in the middle of the shift.</p><p><em>I want to ask you something and I want you to know it''s not pressure. It''s just a real thing I''ve been thinking.</em></p><p>She paused.</p><p><em>When the visit is done. When whatever happens happens. I don''t want to lose this. The notes. The grammar. The specific place this is. I know we don''t know yet what the room does to things. But whatever it does, even if it''s good, even if it''s everything, I want us to keep sending them. I want this to stay.</em></p><p>She had been afraid to say that. It felt like asking the thing to promise to stay, which was the kind of asking that sometimes frightened things away. But she had promised herself after Episode eight of her own internal series that she would stop managing what she gave him, and so she sent it and sat with the sending.</p><p>His reply came in thirty minutes.</p><p><em>I was going to say that to you this week,</em> he said. <em>I was building up to it.</em></p><p>A pause.</p><p><em>Don''t change. That''s what I keep thinking. Whatever happens in Enugu. Don''t let us change this part. Keep sending them. Keep picking up.</em></p><p>She heard something in those three words that was not just about the notes. <em>Don''t change.</em> The way he said it landed in two directions at once, the practical meaning and the underneath one, the one about her, about who she was in this specific place, the version he had been given.</p><p>She understood both directions. She felt both of them. She told Adaeze on Thursday. Not everything. The important shape of it.</p><p>They were in their usual spot, the low wall outside the admin block, the afternoon going slowly around them. Chisom had been carrying it long enough that it needed somewhere else to live for a moment.</p><p>"His name is Khalil," she said. "The pen pal."</p><p>Adaeze looked at her with the expression of someone who had been waiting for exactly this sentence. "I know his name. You''ve mentioned it approximately nine hundred times."</p><p>"I haven''t."</p><p>"Chisom. Last week you said <em>Khalil says</em> in the middle of a conversation about the canteen menu."</p><p>Chisom looked at the middle distance. "That''s possible."</p><p>"So." Adaeze ate a chin-chin. Patient. Waiting.</p><p>"So he''s coming here. In five weeks. With the visit."</p><p>Adaeze was quiet for a moment, which was not her usual mode, which meant she understood the weight of it. "Are you scared?"</p><p>"Yes."</p><p>"Of what specifically."</p><p>Chisom thought about how to say it in a way that fit into a conversation rather than a voice note. "Of being less in person than I am in the notes."</p><p>Adaeze looked at her for a long time. Not unkindly. With the specific focus she used when she was going to say something true.</p><p>"Chisom," she said. "I have known you since JS1. I know the in-person version." She paused. "She is not less. She is just quieter about what she is. Those are not the same thing."</p><p>Chisom had no answer for that. She ate some of Adaeze''s chin-chin and felt something loosen slightly, not the fear, but the isolation of it. That evening she told Khalil about the conversation without naming Adaeze''s last words directly. She described it around the edges instead, the way she sometimes approached the true thing.</p><p><em>My friend reminded me today that quiet and less are not the same thing. I''m still thinking about it.</em></p><p>His reply came quickly.</p><p><em>She''s right. And I want to add something to that.</em></p><p>A pause.</p><p><em>I have never once, in nine weeks, heard you be less. I''ve heard you be careful. I''ve heard you edit. But the thing underneath the editing, the thing that comes through anyway, is not small. It has never been small. I need you to know that I know the difference.</em></p><p>She sat at her desk and read the notification before playing it, and then played it, and then sat quietly for a while.</p><p><em>The thing that comes through anyway.</em></p><p>She wrote that in her notebook. She had a section now, not officially designated but effectively real, where she kept the things he said that she needed to return to. This went there. Before she slept she sent one last note. Short. The kind that didn''t need building toward.</p><p><em>Five weeks.</em></p><p>He replied in under a minute.</p><p><em>Five weeks.</em></p><p>Then, after a beat, quietly:</p><p><em>Don''t change, Chisom. Between now and then. Don''t let the waiting change you. Come as you are.</em></p><p>She turned off her light.</p><p>Outside, Enugu was settling into its night sounds, the generator down the street, the dog, the distant TV. All the sounds that had been the same her whole life, that had been there before Khalil and would be there after everything.</p><p>But they felt different now. Inhabited differently. Like she was listening to them from inside something rather than just inside a room.</p><p><em>Come as you are.</em></p><p>She held it carefully. Both hands.</p>',1064,1,1,NULL,'2026-05-30T09:52:08.589Z','2026-05-30 09:52:08','2026-05-30 09:52:08',NULL,2,53);
INSERT INTO "chapters" ("id","novel_id","chapter_number","title","content","word_count","is_premium","is_published","audio_url","published_at","created_at","updated_at","scheduled_release_at","part_number","season_id") VALUES(679,69,5,'Six Days','<p></p><h3></h3><p>The countdown had been happening in the background for weeks, a quiet subtraction she was aware of without looking at directly. But somewhere between five weeks and six days the subtraction became loud. She could not explain why six days was the number that made it real. It simply was. She woke up on Monday and knew immediately. Not from checking the calendar. From the quality of the morning itself, the way the light came through the curtains with a different weight, the way her first conscious thought was not about school or the day''s schedule but about a boy in Abuja who was six days away from being in the same city as her.</p><p>She lay still for several minutes. The ceiling fan turned. Her brother moved through the corridor outside. The house began its usual morning assembly of sounds.</p><p>Six days. School was difficult in a way that had nothing to do with school. She sat through classes with the countdown running beneath everything, a low persistent hum that she could manage in the foreground while it continued in the background, patient and indifferent to what she needed from it.</p><p>In literature, they discussed the ending of the novel they had been studying all term. Whether the resolution was earned. Whether the characters had done enough internal work to deserve what the ending gave them. Chisom had three things to say about it and said none of them, which was unusual enough that her literature teacher looked at her twice during the discussion.</p><p>She was thinking about earned endings. She was thinking about whether nine weeks of voice notes was enough internal work. She was thinking about the specific mechanics of a moment she could not yet picture, a door, a room, a face she had never seen attached to a voice she knew better than most of the voices in her daily life.</p><p>She wrote in the margin of her literature notebook: <em>What does it mean to earn something.</em></p><p>Then below it, smaller: <em>What if you''ve done everything right and it still doesn''t hold. </em>Khalil sent a note during her lunch break. She felt the buzz against her leg and waited until she was away from the main canteen noise, sitting on the low wall with her back to the school building, before she played it.</p><p><em>Six days,</em> he said. Just that, at the start. Like he had woken up knowing it too.</p><p><em>I did something this morning that I''m going to tell you about because we said real answers only. I looked up Unity Secondary School Enugu on the internet. Not for information. Just to look at it. I looked at the gate. The buildings. The compound. I was trying to picture where you are when you send me notes from school.</em></p><p>A pause.</p><p><em>I found it. I looked at it for maybe three minutes. And then I closed it because it felt like I was doing something out of order. Like reading the last page before you''ve earned it.</em></p><p>She sat with that. The image of him at his phone, looking at her school gate, closing it deliberately. The restraint in that. The respect for sequence.</p><p><em>I keep thinking about what you said weeks ago,</em> he continued. <em>About being glad we got the notes before the room. I am glad. I want you to know I am still glad. Whatever happens in six days I am glad for all of this before it.</em></p><p>He stopped.</p><p><em>I''m also not going to pretend I''m not terrified. Because I am. I''m managing it, which you now know is my thing, but underneath the managing I am genuinely terrified and I think you should know that so you don''t walk in there thinking I''m fine and you''re the only one whose hands might be shaking.</em></p><p>Forty-nine seconds. She played it twice.</p><p><em>His hands might be shaking.</em> She wrote it in her notebook when she got back to class, not in the margin this time but on a full line. She did not fully understand why it helped. But it did. The knowledge that the fear was distributed. That she was not carrying it alone across two states.  She replied that evening from her desk, the organized one, the structured-thinking posture.</p><p><em>I looked up Unity Secondary Abuja three weeks ago,</em> she said. <em>I''m only telling you now because you told me. I also closed it before I finished looking. I didn''t feel ready.</em></p><p>A pause.</p><p><em>Six days is doing something to time. The days feel longer and also like they''re disappearing too fast simultaneously, which should be impossible but here we are. I went through all of Monday and it was the longest Monday I''ve had since exam season and also somehow it''s already evening and I''ve lost it.</em></p><p>She shifted in her chair.</p><p><em>I want to tell you something I haven''t let myself say out loud yet. I''m excited. Underneath the terror, underneath all the things we''ve said about rooms and rough drafts and versions of ourselves, there is something else that has been sitting there the whole time that I haven''t named because naming it felt like too much pressure to put on a day that hasn''t happened yet.</em></p><p>She breathed.</p><p><em>But six days feels like the time to say it. I want to meet you, Khalil. I want to meet you for real. I want to hear your laugh from the same room. I want to see what your thinking pause looks like on your face. I want to know if the church in Kaduna sounds different when you talk about it in person or if it sounds exactly the same. I want all of it. I''m scared of all of it and I want all of it at the same time and I think that''s the most honest thing I''ve said in six weeks.</em></p><p>She sent it without the usual pause before sending. His reply came an hour later.</p><p><em>Chisom.</em></p><p>Both hands.</p><p><em>I want to meet you too. I have wanted to for a long time and I''ve been managing the wanting because that''s what I do. But six days. I''m done managing it.</em></p><p>A pause. Then, with a quietness that had nothing soft about it, that was instead very precise:</p><p><em>I have a map of your Enugu made of your voice. I have heard you at 2am and after hard days and in the middle of ordinary Tuesdays. I know what your real laugh sounds like and what your voice does at the bottom of a true thing. I know your back step and the akara woman and the hills that remember things.</em></p><p>He stopped briefly.</p><p><em>In six days that map gets a person standing in it. And I am terrified and I am not managing it right now and I am also,</em> a breath, <em>I am also so ready, Chisom. I am so ready.</em></p><p>She sat at her desk for a long time after that. Not writing. Not thinking in any directed way. Just sitting inside the fullness of the moment, the fear and the want occupying the same space without canceling each other out, which she had not known was possible until recently.</p><p>Six days.</p><p>She looked at her bookshelf. Authors alphabetical. The right system. The one that held.</p><p>She looked at her notebook, closed on the desk beside her phone. Everything she had written in it over nine weeks, the installments, the maps, the things too full for words that she had found words for anyway.</p><p>She opened it to a fresh page.</p><p>Wrote the date.</p><p>Below it: <em>Six days. Come as you are.</em></p><p>Then she closed it and went to tell the ceiling fan goodnight, which was not something she had ever done before and which she would never admit to anyone.</p><p>But the room felt like it deserved a goodnight.</p><p>So she gave it one.</p>',1274,1,1,NULL,'2026-05-30T09:54:31.626Z','2026-05-30 09:54:31','2026-05-30 09:54:31',NULL,2,53);
INSERT INTO "chapters" ("id","novel_id","chapter_number","title","content","word_count","is_premium","is_published","audio_url","published_at","created_at","updated_at","scheduled_release_at","part_number","season_id") VALUES(680,69,6,'The Night Before','<p></p><h3></h3><p>She had thought about this note for six days. What she would say. How she would say it. Whether she would build it in the right order or let it come out the way the night notes had come out, unplanned and honest and slightly too large for the container.</p><p>By 9pm she still had not recorded it. She had opened the app four times and closed it. The evening had been ordinary in all the ways that felt surreal given what was underneath it. Dinner with her family. Her brother asking about the visit program with the mild curiosity of someone for whom it meant a free period and possibly a chance to see students from another school. Her mother asking practical questions, what time, where on the compound, should she prepare anything. Her father passing the salt without being asked, the way he sometimes did, and Chisom watching his hand and feeling the complicated thing she always felt watching his hand.</p><p>She had packed her bag. Checked it twice. Put it by the door.</p><p>She had stood in her room afterward looking at the space beside the door where the bag was sitting and tried to understand that tomorrow it would carry her to the same compound as Khalil and she could not make the fact feel real. It kept sliding off. Like trying to hold water in an open palm. She called Adaeze at eight. Not for advice. Just for the sound of a familiar voice while she worked up to the real one.</p><p>Adaeze answered with: "Is it tomorrow?"</p><p>"It''s tomorrow."</p><p>"Okay." A pause. "How are you?"</p><p>"I don''t have a word for it."</p><p>"That''s actually a good sign," Adaeze said. "When you have a word for everything it means you''ve been managing it. No word means it''s real."</p><p>Chisom sat on her bed and thought about that. "Did you come up with that just now?"</p><p>"Yes. Is it good?"</p><p>"It''s very good."</p><p>"I know." A comfortable silence. Then: "Chisom. You''ve been talking to this person for nine weeks. You know him. You actually know him. Just go in knowing him."</p><p>She held the phone and let that settle.</p><p>"I''m scared of who he meets," she said. The true version, bare and quick.</p><p>"I know," Adaeze said. "But you can''t be anyone else. So go be you and trust what you built."</p><p>They talked for twenty more minutes about nothing in particular, the chemistry test next week, something Adaeze''s cousin had said, the comfortable texture of a friendship that did not need everything to be significant. By the time they said goodnight something in Chisom had settled, not the fear, but the loneliness of it. At nine-thirty she sat on the back step. Shoes on. The compound wall holding its usual patch of sky above her, the stars doing what they always did, indifferent and consistent and somehow comforting in their indifference.</p><p>She pressed record.</p><p><em>I''ve been trying to start this for three hours. I had a whole structure. An order. I was going to build it properly, the way I build everything. And I''m sitting on my back step and it''s the night before and I think I''m just going to talk.</em></p><p>She looked at the sky.</p><p><em>Tomorrow is going to happen. I''ve understood that intellectually for six weeks and I''ve understood it in my chest for six days and tonight, right now, I understand it in my hands. They''re not shaking. I want you to know that. I told you they might be shaking and they''re not. They''re just very awake.</em></p><p>She breathed.</p><p><em>I want to say some things before tomorrow. While we''re still here. In this place. Because this is the last note from before, and I think before deserves its own goodbye. Nine weeks ago Mrs. Okafor stood up with her papers and her chin-up posture and announced a program I was going to hate. I was going to be polite about it and professional and send the minimum one note per week and satisfy the requirement and feel nothing about it. You were going to be a name on a list.</em></p><p>She paused.</p><p><em>You were a name on a list for approximately four days. And then you knew about Mallam Sule and I knew about the akara woman and something started that I genuinely did not have the architecture for. I didn''t know what to do with you. I kept not knowing what to do with you while you went from a voice I was curious about to a voice I knew, while the exchanges went from stilted to an hour long, while we built a grammar that belongs to nobody else on earth.</em></p><p>She felt her voice doing the thing at the bottom of a true thing. She did not re-record.</p><p><em>You are the best conversation I have ever been in. I need to say that tonight, in the before, while it''s still just this. Before the room and the face and whatever tomorrow finds. You gave me back the version of myself I thought I''d given away to WAEC prep and performance and the managing of other people''s expectations of me. You asked real questions and waited for real answers and you kept the things I gave you carefully. I felt that. Every time. The carefulness.</em></p><p>She stopped for a moment.</p><p><em>I don''t know what tomorrow looks like. I''ve tried to picture it more times than is reasonable and it keeps sliding off. But I know what I''m bringing into it. I''m bringing nine weeks of the final version of myself. I''m bringing the girl who talks on back steps and reads with a phone torch and has a map of your Abuja made entirely of your voice. I''m bringing her, rough draft edges and all, into that room.</em></p><p>A breath. Then quietly, from the bottom of it:</p><p><em>Come as you are, Khalil. Come as the underneath version. Come as the person who redesigns rooms where people can''t breathe and sees decisions in building angles and wanted to meet me enough to look up my school and then close it because you respected the sequence. Come as the person who told me about his knee and his dinner table and his hands that might be shaking. I know that person. I have known him for nine weeks. He does not need to manage anything tomorrow. Not with me.</em></p><p>She sat in the silence after the words. The night was deep now, the street quieter, the generator down the road cycling steadily. Enugu at its most itself, unhurried and sure.</p><p><em>Whatever tomorrow finds,</em> she said finally. <em>I''m glad we had the before. I will always be glad for the before.</em></p><p>She sent it. Put her phone on the step beside her.</p><p>Sat with the sky for a long time, the stars doing their consistent thing above the compound wall, the night holding her in its usual way without asking anything from her.</p><p>Her phone buzzed twenty minutes later. She had known he would be awake. She had known the way you know the things you know without having to check.</p><p>She picked it up and played it.</p><p>His voice was quieter than she had ever heard it. Below the management, below everything, at the very floor of him.</p><p><em>I''ve been sitting at my desk since eight trying to write this in the right order. I kept deleting it. So I''m just going to say the thing.</em></p><p>A pause that had the weight of nine weeks in it.</p><p><em>I think I''ve been in love with your voice since the fifth exchange. I think I''ve been in love with you since the night notes. I have been managing that information for a long time because I was afraid of wanting something too completely. You know that about me. You know why.</em></p><p>He breathed.</p><p><em>I''m done managing it. It''s the night before and you deserve the real version.</em></p><p>He stopped. Then, very simply:</p><p><em>I''ll see you tomorrow, Chisom. I''ll finally see you.</em></p><p>She sat on the back step of her house in Enugu, on the last night of the before, and let the words move through her like water through something that had been waiting a long time to be filled.</p><p>She did not send another note.</p><p>Some things you just receive.</p>',1342,1,1,NULL,'2026-05-30T09:56:43.229Z','2026-05-30 09:56:43','2026-05-30 09:56:43',NULL,2,53);
INSERT INTO "chapters" ("id","novel_id","chapter_number","title","content","word_count","is_premium","is_published","audio_url","published_at","created_at","updated_at","scheduled_release_at","part_number","season_id") VALUES(681,69,7,'Enugu Meets Abuja','<p></p><h3></h3><p>She was early. She had not planned to be early but she had also, if she was honest, planned exactly to be early, had built extra time into her morning without acknowledging why, and so she was standing in the school compound at 8:14am while the Abuja bus was not due until 9:00, with her bag over one shoulder and the rest of her arranged as calmly as she could manage. The morning had the quality of mornings that know they are significant. Or she was giving it that quality. She could not tell the difference and had stopped trying. She had eaten breakfast without tasting it, said goodbye to her mother who had looked at her with the knowing expression she sometimes deployed without comment, walked to school through streets that were doing their ordinary things with an ordinariness that felt almost aggressive given what was underneath the day.</p><p>The akara woman was at her spot. Of course she was. Already there, as always, having always been there. Chisom had slowed as she passed and looked at her properly for the first time in weeks, this woman who had started everything, whose existence at 6:15am on an ordinary Tuesday had become the first real thing she had given Khalil, the first brick of everything that came after.</p><p>She almost said something to her. She didn''t. Some things stayed in the register where they belonged. Adaeze found her at 8:30, standing near the main gate with the careful stillness of someone not performing stillness.</p><p>"You''re going to wear a hole in the ground standing like that," Adaeze said.</p><p>"I''m fine."</p><p>"Your bag strap," Adaeze said, "has been adjusted four times since I walked over here."</p><p>Chisom put her hand down. "I''m fine."</p><p>Adaeze stood beside her. Did not say anything further. This was one of the things Chisom loved most about her, the understanding of when presence was the entire gift.</p><p>They stood together and watched the gate and the street beyond it, the ordinary Saturday morning traffic of the neighborhood, okadas and pedestrians and a man pushing a cart with a loose wheel that complained rhythmically against the tarmac.</p><p>At 8:52 a bus appeared at the end of the street.</p><p>Chisom''s hands went very awake. The bus pulled through the gate slowly. It was a white bus, the kind schools rented for inter-state trips, slightly dusty from the road. It parked near the main block and the engine cut and for a moment it just sat there, still, before the doors opened.</p><p>Students came out in the ordinary way that students come out of buses after long trips, stretching, talking, adjusting bags, carrying the slightly rumpled quality of people who have been sitting for three hours. Teachers from both schools moved toward each other with the particular purposefulness of adults organizing things.</p><p>Chisom watched the door.</p><p>She had no picture of him. She had, deliberately, never asked for one. She had felt strongly, from early in the notes, that she wanted to find him the way she had come to know him, through something other than an image. She had held to this even in the weeks of countdown when the not-knowing felt almost physically difficult.</p><p>She watched the door and understood that she was about to find out what nine weeks of a voice looked like. He came out third from last.</p><p>She knew him before she understood how she knew him. It was not one thing. It was the way he came out of the bus already looking, not at the compound or the building or the general scene, but scanning, the focused attention of someone with a specific purpose. It was the way he paused at the bottom of the bus steps for exactly one beat, not long, barely noticeable, the way someone pauses before a room to read it before entering.</p><p>She knew that pause.</p><p>He was taller than she had assembled in her head, which had never had a height to work with. He was wearing a navy shirt and carrying his bag with one strap, the easy posture of someone comfortable in their own body, and his face, the face she had been unable to picture steadily for six weeks, was the face of someone who was very good in rooms and was currently using none of that skill because he was looking, scanning, and then</p><p>he found her. It lasted less than a second before both of them looked away. Not from discomfort. From the sheer size of the moment, the need to let it happen in stages rather than all at once.</p><p>She looked at Adaeze. Adaeze was looking at the middle distance with the expression of someone who had decided to give a person privacy while standing directly beside them. Chisom loved her completely.</p><p>She looked back.</p><p>He was walking toward her. Not quickly. At the pace of someone who understood that the approach was part of it, that this moment had been nine weeks in the making and deserved to be walked toward properly.</p><p>She stayed where she was. Her hands were very awake and not shaking.</p><p>When he was close enough that she would have had to raise her voice to project across the distance, he stopped. Looked at her with the direct, open attention she had heard in his voice a hundred times but was now seeing and it was the same. That was the thing she registered first, clearly and with something that moved through her like relief. It was the same. The eyes had the same quality as the thinking pause. The same quality as <em>I noticed that.</em></p><p>"Chisom," he said.</p><p>He said her name the way he had always said it. Easy. Like it fit without effort.</p><p>"Khalil," she said.</p><p>Her voice came out steady. The final version, showing up. They stood for a moment in the ordinary noise of the compound, teachers organizing, students meeting, the general managed chaos of a program beginning. All of it happening around them at a slight remove, like weather in a different part of the sky.</p><p>"You''re taller than I thought," he said.</p><p>"You''re also taller than I thought."</p><p>"I didn''t give you a height."</p><p>"I assembled one," she said. "From inference."</p><p>Something crossed his face at that. Not a smile exactly. The thing that happened right before the real laugh, the precursor she had learned to hear and was now, for the first time, seeing. It looked exactly like it sounded.</p><p>"Your inference was wrong," he said.</p><p>"My inference was wrong," she agreed.</p><p>He looked at her for a moment. Steady. The room-reading skill entirely offline.</p><p>"Is it strange?" he asked. "Seeing me."</p><p>She thought about it honestly, the way she did everything with him.</p><p>"It''s strange," she said, "the way all real things are a little strange when you look directly at them."</p><p>She had said that to him once before. Months ago. He heard it and she watched him hear it, watched the recognition move across his face, their grammar landing in the space between them in a compound in Enugu on a Saturday morning with nine weeks behind it and whatever came next ahead.</p><p>"Like that," he said quietly.</p><p>"Like that," she said.</p><p>Somewhere nearby Adaeze made a small sound that could have been anything. Chisom did not look over.</p><p>The morning was doing what mornings do, moving forward without asking anyone''s permission. The program would begin soon. There would be structured activities and teachers redirecting and the whole apparatus of an inter-school visit assembling itself around them.</p><p>But for this moment they were just two people standing in the compound, looking at each other properly for the first time, and the looking was not destroying anything.</p><p>It was adding something.</p><p>She did not yet have the word for what it was adding.</p><p>She thought she might, by the end of the day, have the beginning of one.</p>',1278,1,1,NULL,'2026-05-30T09:59:13.653Z','2026-05-30 09:59:13','2026-05-30 09:59:13',NULL,2,53);
INSERT INTO "chapters" ("id","novel_id","chapter_number","title","content","word_count","is_premium","is_published","audio_url","published_at","created_at","updated_at","scheduled_release_at","part_number","season_id") VALUES(682,69,8,'What the Body Knows','<p></p><h3></h3><p>The program had a schedule. She knew this because a laminated copy had been handed to every student at the start and she had folded hers into her pocket without reading it, which was not like her, which told her something about the kind of day this was. The morning moved through its official shapes. Introductions in the hall, a cultural exchange activity that involved both schools presenting something about their city, a group exercise that paired students randomly and was clearly designed to manufacture connection through proximity. Chisom participated in all of it with the functional part of herself while the rest of her was doing something quieter and more important.</p><p>She was learning how he existed in a room.</p><p>It was different from what she had imagined and also exactly what she should have expected. He was good in rooms, she had known that, but watching it was different from knowing it. He moved through the space with the easy fluency of someone who had learned early to make people comfortable, and people responded to it, leaning toward him, laughing at the right moments, the teachers included. She watched a girl from her own class orient toward him within four minutes of introduction, the way people oriented toward warmth.</p><p>She noticed it without the feeling she had expected to feel. Not jealousy exactly. Something more like recognition. <em>This is the managed version. I know what is underneath it.</em></p><p>Across the room he caught her watching and something shifted in his face, a slight softening, a step back from the performance, there and gone in a second. Only for her. She understood that immediately and completely.</p><p>Their private grammar, surviving the room. The afternoon session gave them unstructured time. Forty minutes for the pairs to talk, officially. The program''s concession to the actual point of itself.</p><p>They found each other without coordinating it, a bench near the side wall of the main block, slightly removed from the main activity, the afternoon sun cutting a warm angle across the compound. Adaeze drifted tactfully in another direction. Chisom noted this with gratitude she would express later.</p><p>They sat. Not close enough to be remarkable. Close enough.</p><p>For a moment neither of them said anything. Not the awkward kind of silence. The kind that had a specific quality they both recognized, the arrived kind, the kind that came after something had been building for a long time and had now arrived and needed a moment to settle.</p><p>"How is it?" he asked. "The room."</p><p>She considered it properly.</p><p>"Better than the rough draft version," she said. "The one I was afraid of sending."</p><p>He looked at the compound, the students moving through the afternoon in their various configurations. "You''re the same," he said. "I want you to know that. The version I know. She''s here."</p><p>She felt that land and stayed with it.</p><p>"You''re different," she said.</p><p>He turned to look at her.</p><p>"Not worse," she said quickly, the way he had said it once about himself. "Just. You have a body. You take up space. You have a way of sitting that I didn''t know." She paused. "I''m still making the map. I have to add things."</p><p>He was quiet for a moment. Then: "What things."</p><p>She looked at him directly, the way she had been learning to do across the day, in the careful stages the morning had required.</p><p>"Your thinking pause is longer on your face than in your voice," she said. "There''s a line here." She indicated her own brow, not touching her face, just the location. "It does something when you''re actually thinking. I''ve been hearing it for nine weeks and now I can see it and they match. That''s." She stopped. "That''s a strange thing to feel. The matching."</p><p>He looked at her with the thinking pause, the line doing the thing she had described, and she watched it in real time and felt the matching move through her like something resolving.</p><p>"Can I tell you what I''ve been doing all morning?" he said.</p><p>"Yes."</p><p>"Listening to you talk. To actual you, in this compound, in this air, with this voice that I know and also don''t know because I''ve never heard it without a phone between us." He paused. "It''s lower in person. Your voice. Not different. Just. More of itself. Like when you remove a filter from something and you realize the filter was taking something away."</p><p>She sat with that. The afternoon was warm and unhurried. Around them the visit program continued its official business, pairs talking, a group activity starting up near the assembly hall. The day moving forward without asking permission.</p><p>"The filter was the phone," she said.</p><p>"Yes."</p><p>"And without it?"</p><p>He looked at her steadily. "Without it you''re still the best conversation I''ve ever been in. Just louder. Just more real. Just here." They talked for the full forty minutes and then beyond it, into the edge of the next scheduled activity, which they both pretended not to notice until a teacher moved past and the schedule reasserted itself. They talked the way they had always talked, building toward true things, leaving doors open, their grammar moving through the conversation like a current beneath the surface.</p><p>She told him the akara woman had been at her spot that morning. He said of course she had. They both understood what that meant and neither explained it.</p><p>He told her the compound looked like her voice had described it. She asked what that meant. He said it felt like a place that remembered things. She looked at the hills beyond the school fence, Enugu doing its usual holding of everything, and felt something in her chest that was too large and too right to fit inside a single word.</p><p>At one point he laughed at something she said. The real one. Unguarded, breaking in the middle, the wheeze at the end of it, undignified and entirely genuine. She heard it in the open air of the compound without a phone between them and it was the same laugh, the exact same laugh, and she sat inside the sameness of it and felt something complete. The bus was leaving at four.</p><p>She knew this from the schedule she had never read, announced by a teacher at 3:45 with the practiced authority of someone accustomed to ending things that people did not want to end.</p><p>They stood near the gate with ten minutes remaining. The compound had the quality of a day concluding, students gathering bags, the Enugu students standing with their counterparts in the easy way of people who had spent a day together and were now slightly different from how they had arrived.</p><p>"I''m going to send you a note tonight," he said. "When I get back."</p><p>"I know," she said. "I''m going to send one too."</p><p>"Will it be different? The notes. After today."</p><p>She thought about it honestly, the way she had thought about everything with him.</p><p>"The grammar will be the same," she said. "But there will be more in it. The body things. The matching. The way your face does the thinking pause." She paused. "I''ll know what I''m talking to now. Not just the voice. The whole thing."</p><p>He nodded slowly. The thinking line doing its work.</p><p>"I was afraid," he said, "that the room would take something away. That seeing each other would make the notes smaller somehow. Like the thing we built could only survive in the dark."</p><p>"And?"</p><p>He looked at her. Steady. The management entirely offline.</p><p>"And the dark was never the point," he said. "We were the point. The dark was just where we found out."</p><p>She felt that move through her the way the best true things moved, not loudly, not with announcement, just with the quiet certainty of something that had always been true and had now been said.</p><p>The teacher called a five-minute warning.</p><p>Neither of them moved immediately.</p><p>"Khalil," she said.</p><p>"Yes."</p><p>"Come back." She said it simply, the way simple things needed to be said. "Not for the program. There''s no more program after this. Just come back."</p><p>He looked at her for a long moment. And then he smiled, not the room-management smile, not the polite one, not even the precursor to the real laugh. Something quieter and more permanent. The smile that did not need a performance because it was not for a room.</p><p>It was for her.</p><p>"I''ll come back," he said.</p><p>The bus started its engine.</p><p>She stepped back. He adjusted his bag. Between them the afternoon sat, warm and specific and already becoming something they would return to for a long time, in notes and in memory and in all the future conversations that had this day underneath them.</p><p>She watched the bus until it turned out of the gate and the street folded it out of sight.</p><p>Then she stood in the compound for a moment, just standing, feeling the particular quality of an ending that was not an ending, the kind that opened into something rather than closing.</p><p>The hills held the late afternoon light. Enugu kept its records. The compound settled into itself.</p><p>She took out her phone.</p><p>Pressed record.</p><p><em>I know what I built,</em> she said quietly, to a voice note that was already on its way to Abuja before the bus had reached the highway. <em>I know what it is. I know what it survived. And I know what it''s walking toward now.</em></p><p>She paused.</p><p><em>It''s walking toward more. That''s all. Just more.</em></p><p>She sent it.</p><p>Walked through the gate.</p><p>The akara woman''s spot was empty now, the evening too late for akara, but the space held its familiar shape, the small geography of an ordinary corner that had started everything, that had been the first real thing she had given him, the first brick.</p><p>She walked past it and toward home.</p><p>The street was doing its evening things. The hills were keeping their records. And somewhere on a road between Enugu and Abuja, a boy was sitting on a bus with his phone already in his hand, waiting for the note she had just sent, ready to send one back.</p><p>The silence between two phones.</p><p>Still a conversation.</p><p>Still theirs.</p>',1645,1,1,NULL,'2026-05-30T10:01:40.430Z','2026-05-30 10:01:40','2026-05-30 10:01:40',NULL,2,53);
