INSERT INTO "competition_submissions" ("id","user_id","full_name","email","phone","school_name","class_year","age","story_title","genre","synopsis","story_content","word_count","is_original_work","referral_source","has_written_before","status","admin_notes","created_at","updated_at","story_2_title","story_2_synopsis","story_2_content","story_2_word_count","story_3_title","story_3_synopsis","story_3_content","story_3_word_count","novel_1_id","novel_1_summary","novel_2_id","novel_2_summary","novel_3_id","novel_3_summary","follows_facebook","follows_instagram","follows_tiktok","follows_youtube","follows_whatsapp") VALUES(1,'sample-user-1','Adaeze Okonkwo','adaeze@example.com','+234 801 234 5678','University of Lagos','Year 3',21,'The Last Masquerade','Cultural Fantasy','A young woman discovers she is the last in a line of masquerade dancers who can communicate with ancestral spirits.','The drums began at midnight, as they always did during the festival of the ancestors. Chidinma pressed her palms against the red earth, feeling the vibrations travel through her bones like whispered secrets from the other side...',2847,1,'Instagram',1,'pending',NULL,'2025-01-15 10:30:00','2025-01-15 10:30:00',NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,0,0,0,0,0);
