INSERT INTO "competition_submissions" ("id","user_id","full_name","email","phone","school_name","class_year","age","story_title","genre","synopsis","story_content","word_count","is_original_work","referral_source","has_written_before","status","admin_notes","created_at","updated_at","story_2_title","story_2_synopsis","story_2_content","story_2_word_count","story_3_title","story_3_synopsis","story_3_content","story_3_word_count","novel_1_id","novel_1_summary","novel_2_id","novel_2_summary","novel_3_id","novel_3_summary","follows_facebook","follows_instagram","follows_tiktok","follows_youtube","follows_whatsapp") VALUES(3,'sample-user-3','Fatima Ibrahim','fatima@example.com','+234 802 345 6789','Ahmadu Bello University','Year 2',20,'Threads of Silk and Sand','Historical Fiction','During the ancient trans-Saharan trade routes, a young merchant''s daughter uncovers a conspiracy that could topple kingdoms.','The caravan stretched across the dunes like a serpent made of gold and spices. Amina adjusted her veil against the biting sand, her eyes fixed on the distant city of Timbuktu, where secrets older than the desert itself awaited...',4102,1,'Twitter',0,'shortlisted',NULL,'2025-01-12 08:15:00','2025-01-17 11:30:00',NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,0,0,0,0,0);
