INSERT INTO "competition_submissions" ("id","user_id","full_name","email","phone","school_name","class_year","age","story_title","genre","synopsis","story_content","word_count","is_original_work","referral_source","has_written_before","status","admin_notes","created_at","updated_at","story_2_title","story_2_synopsis","story_2_content","story_2_word_count","story_3_title","story_3_synopsis","story_3_content","story_3_word_count","novel_1_id","novel_1_summary","novel_2_id","novel_2_summary","novel_3_id","novel_3_summary","follows_facebook","follows_instagram","follows_tiktok","follows_youtube","follows_whatsapp") VALUES(6,'sample-user-6','Tendai Moyo','tendai@example.com','+263 77 234 5678','University of Zimbabwe','Year 4',24,'Stone Kingdom','Historical Fantasy','In the shadow of Great Zimbabwe, a young stonemason discovers he can see the spirits that built the ancient walls.','The stones spoke to Tendai in voices older than memory. Each granite block in the great wall hummed with the energy of those who had placed it there, centuries before the white men came with their questions and their cameras...',3890,1,'Online search',1,'shortlisted',NULL,'2025-01-11 12:30:00','2025-01-17 16:45:00',NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,0,0,0,0,0);
