updated_at DATETIME DEFAULT CURRENT_TIMESTAMP
, favorite_genres TEXT, referral_source TEXT, is_newsletter_subscribed BOOLEAN DEFAULT 0, has_completed_onboarding BOOLEAN DEFAULT 0, is_age_verified BOOLEAN DEFAULT 0, email TEXT, referral_code TEXT, referred_by_code TEXT, is_chapter_notifications_enabled BOOLEAN DEFAULT 1, age_range TEXT, birth_date DATE, trial_started_at DATETIME, referral_bonus_days INTEGER DEFAULT 0, has_early_access BOOLEAN DEFAULT 0, total_referral_days_earned INTEGER DEFAULT 0, successful_referrals_count INTEGER DEFAULT 0);
